export const SEED_JUTSUS: IJutsuV1Dto[] = [
  { _id: "f644fa8f44ec197b9e8d0059", name: "CHAKRA HANDS", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "1 Chakra", components: "CM", duration: "1 minute", description: "A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it as an action. The hand vanishes if it is ever more than 30 feet away from you or if you dismiss the jutsu. You can use your action to control the hand. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. You can move the hand up to 30 feet each time you use it. The hand can’t attack, activate chakra items, or carry more than 10 pounds.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "10b8d04ffda71b477f3ae1fd", name: "CHAKRA MOVEMENT", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "1 Chakra", components: "HS", duration: "Instant", description: "You transfer chakra to the bottom of your feet, creating a strong repulsive force upon release of this jutsu, increasing your movement speed momentarily. Increase your movement speed by 10 until the end of your next turn.", at_higher_ranks: "This Jutsu’s movement speed boost increases by 5ft at 5th level (15ft), 11th level (20ft), 17th level (25ft)", created_at: NOW, updated_at: NOW },
  { _id: "e5ab1de4a0b8621c466a752a", name: "CHAKRA PULSE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "2 Chakra", components: "HS", duration: "Instant", description: "You create a forceful pulse of chakra that erupts from your body. Each creature within 5 feet of you, other than you, must make a Strength saving throw or take 2d4 force damage and are forced prone.", at_higher_ranks: "This Jutsu’s effectiveness increases by 2d4 at 5th level (4d4), 11th level (6d4), 17th level (8d4)", created_at: NOW, updated_at: NOW },
  { _id: "d5a7f4ec0a025f4b4c5a6603", name: "CHAKRA BLOW", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "2 Chakra", components: "HS, CM, W(any)", duration: "1 round", description: "As part of the action used to cast this ninjutsu, you must make a weapon attack against one creature within the Jutsu's range, otherwise the jutsu fails. On a hit, the target suffers the attacks normal effects and takes an additional 1d6 damage.", at_higher_ranks: "This Jutsu’s effectiveness increases by 1d6 at 5th level (2d6), 11th level (3d6), 17th level (4d6)", created_at: NOW, updated_at: NOW },
  { _id: "ee6c73b621e651f0f8bbb801", name: "ENHANCED DEFENSE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "2 Chakra", components: "HS", duration: "Instant", description: "You focus chakra into the top layer of your skin, providing your resistance to Bludgeoning, Piercing, and slashing damage until the start of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "74e2c815118fbf2efa42c800", name: "ENHANCED RESISTANCE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you fail a saving throw", range: "Self", chakra_cost: "2 Chakra", components: "HS", duration: "1 Round", description: "You focus chakra throughout your body reinforcing it to attacks. You gain a +1 bonus to the next saving throw of your choice.", at_higher_ranks: "This Jutsu’s body reinforcement increases as you increase in level. Gain an additional +1 bonus at 5th Level (+2), 11th level (+3) and 17th level (+4). 4", created_at: NOW, updated_at: NOW },
  { _id: "78777cfab69f339aa92bb90e", name: "ENHANCED SKILL", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you fail a skill check", range: "Self", chakra_cost: "2 Chakra", components: "HS", duration: "1 Round.", description: "You focus chakra toward different parts of your body to enhance your ability to complete different tasks. When you fail a skill check using a physical ability score (Strength, Dexterity or Constitution), you can add+2 to that failed check, potentially turning a failure, into a success. Once you cast this jutsu, you cannot do so again for 10 minutes.", at_higher_ranks: "This Jutsu's skill reinforcement increases as you increase in level. This bonus increases by +2 at 5th Level (+4), 11th level (+6), 17th level (+8)", created_at: NOW, updated_at: NOW },
  { _id: "395399726ffe24ab83584a04", name: "ESCAPE TECHNIQUE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "2 Chakra", components: "HS", duration: "Instant", description: "You use chakra to feel the knots of ropes chains, and other tools used to bind and restrain you. This helps you figure out the best course of escape while trapped. While restrained or grappled, you can roll Sleight of Hand in place of the normally required skill check or saving throw at advantage. On a success, you are able to slip out of the grapple or restrained position, freeing yourself.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "995cebf4ba5ccf3471b7a297", name: "FINGER CARVING SEAL", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "1 Chakra", components: "CM, CS", duration: "Permanent", description: "You focus chakra into the tip of your finger and use the accumulated heat and energy to apply worlds, letters and shapes of your choice, no longer than 20 words per action taken. These words can be applied to structures and constructs and deal no damage. These words can be applied to a willing creature, leaving a permanent scar in their skin with your writings.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ba1a007f6354f793e8fa5153", name: "FIRECRACKER FLASH", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "2 Chakra", components: "NT", duration: "Instant", description: "You take a bundle of flash firecrackers, and use your chakra to light the wicks of each one before throwing them in an arc in front of you. Creatures standing in front of you in a 15-foot-wide space must make a Wisdom Save, giving you advantage on your next attack against them and disadvantage on their next attack on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2608b7d6a0bac64cda10f7b4", name: "INVISIBILITY CLOAK", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "1 Chakra", components: "NT", duration: "Instant", description: "You quickly pull a chameleon cloak over yourself while against a wall or other standing surface. Roll a stealth check with a 1d4+1 bonus to the check. If a creature would attempt to make a perception check in an attempt to find you, they make their check with a 1d4+1 penalty to their check. This penalty lasts until you move more than 10 feet from your current location.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4a32d94b9f7f09019570f84f", name: "LIGHT", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "1 Chakra", components: "CM", duration: "1 Hour", description: "You touch one object that is no larger than 10 feet in any dimension. Until the jutsu ends, the object sheds bright light in a 10-foot radius and dim light for an additional 10 feet, the light is a soft blue/ Completely covering the object with something opaque blocks the light. The jutsu ends if you cast it again or dismiss it as an action. If you target an object held or worn by a hostile creature, that creature can must make a Dexterity saving throw to avoid the jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "203c85cf15a305da3b1368a9", name: "MENDING", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Minute", range: "Touch", chakra_cost: "1 Chakra", components: "CM", duration: "Instant", description: "This jutsu repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot, you mend it, leaving no trace of the former damage. 5 SEALING ART:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "261a033dd6c7b58f25c28a08", name: "STRING LIGHT FORMATION", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "2 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You use your chakra to create a sealing formation stretching from yourself to a target creature you can see within range, in a straight line. The target creature must make a Charisma saving throw, reducing both your and the target’s movement speed to 0 on a failed save. This can be used with others targeting the same creature, increasing the Save DC by +1 for each additional user. At the end of the target creatures turn, they remake their save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3a9f4348e23154425a262965", name: "VIRTUE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "1 Chakra", components: "HS, CM", duration: "1 Round", description: "You touch one willing creature, imbuing it with vitality. If the target has at least 1 hit point, it gains a number of temporary hit points equal to 1d4 + you ninjutsu ability modifier. The temporary hit points are lost at the end of the creatures next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4be2e6d063289cc544f22d47", name: "ADVANCED TRANSFORMATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Concentration, Up to 10 minutes", description: "An advanced form of the transformation technique. When cast you transform your body into a physical object such as a weapon or object of Small or Medium size. While transformed into an object you take on its physical properties and function as this object. If transformed into a weapon you also take on its weapon properties. Others can wield and use you as a weapon so long as you maintain concentration on this jutsu. You cannot transform into any object that separates into multiple pieces, disconnects or has multiple moving mechanical parts, such as an electric fan or a Safe. If you do, these additional pieces or functions do not work or cannot be moved by any means. While transformed you cannot move or act or speak. You are aware of your immediate surroundings and can hear as normal, but are unable to cast jutsu or make attacks of any kind while transformed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When Cast at B-Rank you can transform into large or smaller objects.", created_at: NOW, updated_at: NOW },
  { _id: "15900fe9fe381c74fcdd9de5", name: "ALARMING TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "30 Feet Cube", chakra_cost: "5 Chakra", components: "HS, CS", duration: "8 Hours", description: "You set a chakra seal that expands 30 feet across the ground or surface it is placed on and it releases a very faint and mostly undetectable aura of chakra in a 30- foot cube. Until the Jutsu ends, an alarm alerts you whenever a creature touches or enters the Seals area. When you set the seal, you can designate creatures that don’t set off the alarm. You can also choose to make the alarm mental or audible.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "17178f5539eaedf2e71a19f6", name: "ARMS OF BUDDHA", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "10ft", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You focus your chakra throughout your body, culminating in a golden buddha forming around you and making multiple strikes with its 100 arms. Make a Melee Ninjutsu Attack against a creature within range, on a hit the target creature takes 4d6 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "8dbdf21cff11e6f350ed1ac4", name: "BAT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Instant", description: "You inscribe into your scroll the image of a bat to blind you enemies. Make a ranged ninjutsu attack against a medium or smaller sized creature. On hit the creature becomes blinded as the bat latches onto their face blocking vision. As an action on the creatures turn, they can attempt to pull the bat off by making a Strength saving throw ending the blinded condition on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and this number of attacks this jutsu can make by +1. However, each additional attack must target a different creature.", created_at: NOW, updated_at: NOW },
  { _id: "b2c9283a345da8c827574fda", name: "DEER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Instant", description: "You draw an image of a herd of deer that charge from your scroll towards your chosen target. Make a ranged ninjutsu attack. On a success, the target creature takes 2d8 in Bludgeoning damage and must make a Strength saving throw, being knocked prone on a failed save. If this jutsu is cast targeting a prone Creature, you do not roll disadvantage, instead rolling advantage and dealing an additional 2d6 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "34b756908905afddec4a3494", name: "LIZARD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, Up to 1 minute", description: "You summon an inky lizard in a space you can see within range that can hold it. The lizard is a construct with the following statistics; • AC 12, 5d6 (20) Hit points. The lizard immediately after being summoned, screeches a menacing sound to those around it. All creatures who begin their turn within 10 feet of the lizard excluding you, must make a Wisdom saving throw. On a failed save they gain 1 rank of Fear. So long as a creature has ranks of fear gained as a result of this jutsu they cannot willingly approach the Lizard.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range of the lizards Screech by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "487b35a04189c9895e00e4e7", name: "PIDGEON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "Up to 10 Minute", range: "Self", chakra_cost: "3 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "24 Hours", description: "You write in your scroll a message of any length that you can conceivably write within a 10 minute or less time span. Once complete, the writings manifest into the form of a bird of your description and now carry themselves. You can also cast this jutsu targeting a message already written of 25 words or less. The bird you create has 1 hp and an AC of 15. You then specify a location that you have previously visited and a recipient who matches a general description. You can also then give the bird a letter, scroll, tag, or similarly small object to deliver to this creature. The construct travels for the duration of the jutsu towards the location, covering no more than 50 miles per 24 hours. When the bird arrives, it turns back into the message when provided a scroll to be placed on and delivers any packages to the creature you described. The bird will only release the object to the creature you specified or if killed. The creature dissipates into non-staining ink when the message is delivered or it is killed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and duration increases by 24 hours. When casting this jutsu at B-Rank or Higher, the bird becomes large in size and is capable of carrying two medium size creatures on its back.", created_at: NOW, updated_at: NOW },
  { _id: "1e6b9b820849dd09455ef450", name: "RATS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Minute", range: "1 Mile Radius", chakra_cost: "5 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "10 Minutes", description: "When you cast this jutsu you draw a horde of rats into your scroll. After 1 minute the picture is finished and the rats come to life scattering around. After a 10-minute delay, you can make a Ninshou check. Based on your level of success, you become aware of a variety of things within a 1-mile radius. • DC 10: You become aware of structures that are not hidden within range. This does not inform you of their specific location or size, only their general direction. • DC 15: You become aware of any non-hidden creatures within range. This does not inform you of their specific location or even the type of creature they are, only their general direction. • DC 20: You become aware of hidden structures within range. • DC 25: You become aware of the size of Structures and the types of creatures within range. • DC 30: You become aware of hidden creatures.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the range of this jutsu to 2 miles. If this jutsu is cast at S-Rank, increase the range of this jutsu to 3 miles.", created_at: NOW, updated_at: NOW },
  { _id: "7c0ac7f4ce47e4e52b3f2330", name: "RETRIEVAL HAWK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "3 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, up to 1 minute", description: "You hurriedly draw an image of a hawk to retrieve something for you. The hawk breaks out of your scroll and attempts to retrieve an object no more than 10 pounds and bring it to a destination of your choosing within range. The hawk has a fly speed of 45ft, AC of 15 and 1 hp. The hawk must stay within the range of this jutsu from the caster at all times and does not require the caster's actions to command aside from its initial creation. The destination of delivery can be changed as a bonus action on the casters turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the hawks speed by 10 feet, the weight it can carry by 10 pounds and this jutsu’s range by 30 feet. BEAST IMITATING ART:", created_at: NOW, updated_at: NOW },
  { _id: "34d04e65c39035a30f004e79", name: "SNAKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Instant", description: "When you cast this jutsu you draw an image of two snakes into your scroll infusing chakra into it making it come to life. You command the pair of snakes to wrap around your enemies. Target up to two creatures within range. Each creature must make a Strength saving throw. If any of the creatures are within 5 feet of each other they each make the save at disadvantage. On a failed save, they are restrained by the snakes as they wrap around them. A creature restrained by this jutsu, may as an action on their turn attempt another Strength save to end this condition. If affect creatures are within 5 feet of each other, when one creature succeeds all creatures within 5 feet of them, restrained conditions ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets by +1.", created_at: NOW, updated_at: NOW },
  { _id: "a9c492a12e4edf202bc81c7b", name: "BODY CAMOUFLAGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS", duration: "1 minute", description: "You coat your body in chakra and begin to imitate the color and texture of the area around you blending in like a chameleon. For the duration, roll an additional +4 adding the result to your stealth checks.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and you can target one additional creature for each rank and they gain the benefits of this jutsu as well.", created_at: NOW, updated_at: NOW },
  { _id: "e03d61851bc7f4795f1e8dbf", name: "BODY FLICKER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "3 Chakra", components: "HS, M", duration: "1 Round", description: "You gain a mastery of movement, allowing you to cover much greater distance in a shorter amount of time. Until the end of your next turn, increase your speed by 30 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3a81d5da92b167c574e24f2a", name: "CALLING ON TEARS TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30 Foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest chakra around your tongue and throat as you use it to vibrate and magnify all sound escaping your mouth. You then release a stunning scream in an attempt to incapacitate all that hear it. All creatures in a 30-foot cone originating from you must make a Wisdom saving throw, being Deafened and Dazed until the end of their next turn on a failed save. Additionally, any traps such as explosives, trap doors or pressure plates that are within this jutsu’s range are triggered.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "21f33b477ffc99b4e6e710e1", name: "CATAPULT TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 action", range: "90 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "Choose one object weighing no more than 1 bulk within range, that isn’t being worn or carried. The object flies in a straight line up to 90 feet in a direction you choose before falling to the ground, stopping early if it impacts a solid surface. If the object would strike a creature that creature must make a Dexterity saving throw. On a failed save, the object strikes the target and stops moving. In either case, both the object and the creature or solid surface takes 3d8 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the maximum bulk of the objects that this jutsu can use increases by 1 bulk, and the maximum distance by 10ft. This jutsu’s damage also changes depending on the affected object’s bulk: 1 Bulk or less: 3d8. 2 Bulk: 4d8 3 Bulk: 5d8 4 Bulk: 6d8 5 Bulk: 7d8", created_at: NOW, updated_at: NOW },
  { _id: "dbc74a2341f190e8c4a92038", name: "CHAKRA BOLT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a 4-inch sphere of pure chakra at a creature you can see within range. Make a ranged ninjutsu attack. On a hit, the target takes 3d6 damage. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. Additionally, you gain one of the following benefits based on the Damage type of this jutsu. • Earth: The target must make a Strength saving throw being Bruised on a failed Save. • Wind: The target must make a Strength saving throw being pushed back 15 feet and being knocked prone on a failed save. • Fire: Each creature within a 5-foot radius sphere of the target creature must make a Dexterity saving throw, being burned on a failed save. • Cold: Each creature within a 5-foot radius sphere of the target creature must make a Constitution saving throw, being chilled on a failed save. • Lightning: The target must make a Constitution saving throw, being shocked until the end of their next turn. • Force: Changed damage die to d8. The target must make a Dexterity saving throw being Dazed.", created_at: NOW, updated_at: NOW },
  { _id: "56a77ab55b9c6ce04b8433be", name: "CHAKRA LEAPING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "3 Chakra", components: "HS, M", duration: "Instant", description: "You focus chakra into your legs, increasing your jumping Strength astronomically. Until the end of this turn, Double your jumping height.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, the duration of this jutsu becomes 1 minute. If this jutsu is cast at S-Rank, the duration becomes 1 hour.", created_at: NOW, updated_at: NOW },
  { _id: "47f4972ebcda1adb29c19f73", name: "CHAKRA MARK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "Special", range: "Touch", chakra_cost: "5 Chakra", components: "CS", duration: "10 Minute", description: "You create a chakra seal and attempt to place it on a creature, structure or construct you are able to touch. When you score a hit with a melee attack or a ranged attack, you are able to mark a creature. This does not work if another creature, construct or structure intercepts the attacks damage. While a creature, construct or structure is marked with this jutsu and is within 1 mile of you, you become aware of the existence of this seal, but not its immediate location. You gain a +4 bonus to all checks made to find or track the marked creature. Additionally, if you can teleport you can choose to teleport to a marked creature, construct or structure so long as they are within 1 mile of you. Once you teleport in this way, the mark vanishes, ending this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. At C- Rank This jutsu’s Duration becomes 1 Hour. 8 Hours at B- Rank, 24 Hours at A-Rank, Permanent at S-Rank.", created_at: NOW, updated_at: NOW },
  { _id: "602767c9d40d2ab25441bbd1", name: "CHAKRA SHIELD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Reaction, which you take when you take damage", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a swirling barrier of chakra around you protecting you from the triggering attack. You gain 12 Temporary Hit points. If you have a nature release, this jutsu gains a single nature release keyword that you can cast, and additional effects base on the Nature release. Your shield gains one of the following benefits based on the chosen nature release. If you do not have a nature release this shield instead has 16 temporary hit points. • Earth: This jutsu gains the Construct keyword. Your shield has resistance to Cold damage, vulnerability to lightning Damage and once cast leaves behind an Quake Shard in a 5ft cube within 5ft of you. • Wind: Your shield has resistance to Lightning Damage, vulnerability to Fire Damage and once cast all creatures of your choice within 5 feet of you gains 1 rank of bleed. • Fire: Your shield has resistance to Wind Damage, Vulnerability to Cold Damage and all creatures within 10 feet of you takes fire damage equal to your Ninjutsu ability modifier. • Water: Your shield has resistance to fire damage, vulnerability to earth damage and if this jutsu is cast near a sufficient source of water, reduce the cost of this jutsu by -2. • Lightning: Your shield has resistance to Earth damage, vulnerability to wind damage and you gain a +2 to Dexterity saving throws until the beginning of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points you gain by +6.", created_at: NOW, updated_at: NOW },
  { _id: "db89b84ce84902da9cc79744", name: "CHAKRA SKIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Until Short Rest", description: "You coat yourself in a Protective aura of chakra, protecting you from damage. When you cast this jutsu, you lose the benefits of any Armor you are wearing, utilizing this Jutsu’s AC calculation for its duration. Your AC becomes 13 + your Intelligence Modifier + Half of your proficiency Bonus. This jutsu ends if you dismiss it as a Bonus action.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank or higher, you gain Temporary hit points equal to your Ninjutsu ability modifier. As a Bonus action on your turn, you can replenish these Temporary hit points for 5 Chakra. If this jutsu is cast at B-Rank or higher, increase the AC this Jutsu grants by +1. If this jutsu is cast at A-Rank or higher, the Temporary hit points gained, is instead equal to half of the casters Ninjutsu ability score. If this jutsu is cast at S-Rank or higher, increase the AC this Jutsu grants by +2, instead of +1.", created_at: NOW, updated_at: NOW },
  { _id: "543f4db498ad02d07a21a9d7", name: "DARKVISION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has Darkvision out to a range of 60 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can affect with this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "c8e57fb162d069924b818700", name: "ENHANCED REACTIONS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "3 Chakra", components: "HS", duration: "8 Hours", description: "You store chakra in pockets behind your eyes and joints in preparation to move with a burst of speed at any moment. The first time you would roll initiative for the duration, you may add 1d4+1 to your roll. This jutsu then ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "549b712e5cd17ba497f0a91e", name: "HOLLOW STARS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You force your palms together before pointing them towards the sky, shooting our four bursts of chakra that take the shape of small stars before falling to the ground in four different spaces of your choice within range, dealing damage to objects, creatures and structures occupying the space. Objects, creatures and structures in the selected spaces each take 1d4+1 damage. A creature, object or structure in the area of more than one star, takes the damage of each of these stars. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. A creature can only ever be affected by the following effects twice per casting. • Earth: You create a 10-foot cube of difficult terrain, centering on each space selected. This space remains difficult terrain until cleared. • Wind: Each creature within 5 feet of the selected space makes a Strength saving throw. On a failed save they are thrown back 5 feet from the target space and falling prone. • Fire: Each creature within 5 feet of the selected space makes a Dexterity saving throw. On a failed save they takes damage equal to the damage dealt to the target space. • Cold: Each creature within a 10-foot radius sphere of the target space must make a Constitution saving throw, being chilled on a failed save. • Lightning: If two or more selected spaces are within 15 feet of each other, lightning arcs between them in a straight line so long as there are no obstructions. Creatures in the Arcs path must make a Constitution saving throw, being shocked on a failed save • Force: Damage die increases to a d8. Also, creatures occupying select spaces are bruised.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of stars made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "ecfccde651084d85560729b1", name: "INK CLONE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS, NT (Vial of Ink)", duration: "1 Minute", description: "You infuse chakra into the ink as you then infuse a chakra seal into it. You conjure a clone of yourself made of ink. They look, sound and act as your describe. The cost of these clones cannot be reduced below half. An Ink clone has 1 Hit point and can be no farther than 90 feet from you. It can walk, talk and interact with things but it cannot declare an attack. This clone acts at the end of your turn. As a bonus action you can command the clone to attack. When you do it pretends to weave hand seals to cast a jutsu targeting a single creature within 60 feet of it. The target creature makes a Wisdom (Insight) Check vs your Ninjutsu Save DC. On a failure, they become distracted by the clones antics. A creature distracted in this manner grants the next attack targeting it advantage and they are treated as surprised against this attack.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "968f8e9e27a47e10a5598eba", name: "LOCK/RELEASE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "3 Chakra", components: "HS, CS", duration: "Until dispelled", description: "You place a chakra seal on a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and creatures you designate when the jutsu is used can open the object normally. You can also set a password that when spoken within 5 feet of the object releases the jutsu for 1 minute. This jutsu also works inversely allowing you to attempt to lock pick using your chakra alone. Make an Intelligence (Chakra Control) check vs the Locks DC as if you are picking a lock using a Security kit. Creatures attempting to open the object you have locked with this jutsu must make an Athletics check vs your Ninjutsu save DC to force open the object.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "58895c38799de4948a5e5964", name: "ACID ARMOR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You manifest acidic chakra in the form of a highly dangerous aura of chakra that intercepts attacks for you and harms those who would try to touch you. You gain 14 temporary hit points. Creatures who would deal damage with a melee attack take 6 acid damage each time they would deal damage, while you have temporary hit points granted by this jutsu. A creature who would strike you with a weapon attack or unarmed strike whose rank is equal to or less than the rank this jutsu was cast at has their weapon suffer a permanent -1 penalty until fixed by the Mending ninjutsu. An unarmed attack such as your fists or legs can be fixed with any jutsu with the medical keyword that restores hit points or removes conditions. A weapon or limb which has reached a -5 penalty breaks, being destroyed by all of the acid covering it.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points by 7 and the acid damage by 3.", created_at: NOW, updated_at: NOW },
  { _id: "59f2495c785503d43a635218", name: "ACID BEAM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (60-Foot line)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest acidic chakra in the form of a powerful beam meant to melt through everything in its path. All creatures in a 60-foot long, 5-foot-wide line originating from you must make a Dexterity saving throw. On a failed save, you deal 3d6 acid damage and at the beginning of an affected creature’s next turn, they take 3d4 acid damage. Constructs and structures made of earth, metal or wood take double damage as the acid eats through them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "4e80ff5ca5cb4d5e67773505", name: "ACID STRING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (20-foot cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You manifest acidic chakra in the form of barbed wires, enough to fill a 20-foot cube originating from you. For the duration, creatures, excluding you, who would begin their turn or enter for the first time on their turn, the affected area, they take 7 acid damage and an additional 7 acid damage for every 5 feet they would move through the affected area. A creature cannot take damage from the same 5 by 5-foot square more than once per round.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the affected area by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "e18a1f1ff27884e3848ad938", name: "ACID TAIL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest acidic chakra in the form of a beast’s tail, be it a massive dragon tail, or large lions tail. Make one melee ninjutsu attack. Compare the result of your attack against all creatures in a 15-foot cone, originating from you. For each success, you deal 2d6 + 1d6 acid damage, for each additional creature hit after the first. Additionally, all creatures you deal damage to must make a Strength Saving throw. On a failed save, creatures are knocked prone and gain 1 rank of corroded.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d8152c2469cfe87175aa6f3f", name: "ACID WHIPS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You manifest acidic chakra in the form of two whips of acid designed to grapple and melt into your foes. Make two ranged ninjutsu attack, dealing 2d6 acid damage on a hit. Additionally, creature you hit must make a Strength saving throw. On a failed save, they become grappled by you and your acid whips for the duration. A creature grappled by your acid whips takes 1d6 acid damage at the beginning of each of their turns.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of attacks you make by +1.", created_at: NOW, updated_at: NOW },
  { _id: "cbe60a3b5a7d78487bbf7e0e", name: "ACIDIC CLEANSE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (15 feet)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Special", description: "You learn to bend acidic substances to your will, molding and manipulating them like puppets on a string. All creatures within 15 feet of you who are under the effects of the corroded condition has their condition ended, as you collect all of the left-over acid into a ball above your head. The ball floats for up to 1 minute or until used. The next time you would cast a jutsu that would deal acid damage you can spend the ball of acid, upcasting the jutsu by 1 rank at no cost, ignoring upcasting limitations.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c5aa6f0f3f3ae60ce682b219", name: "BROKEN BODY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate a surge of twisted medical release chakra designed to shatter the bones and splinter the muscles of your target. A creature you can reach must make a Strength saving throw. On a failed save their bones twist and their muscles spasm as they take 4d8 necrotic damage and they cannot use their arms to hold a weapon until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "b74f8741607d2e9fd8efdc93", name: "CORRUPT MISSILE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You begin to generate a mass of twisted medical release chakra designed to be fired like a missile, bolt or beam. Make a ranged ninjutsu attack targeting one creature you can see in range. On a hit you deal 2d8 + your ninjutsu ability modifier necrotic damage. Additionally, the next time the affected creature would regain chakra within the next minute, they regain half of the listed amount", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "cde68d694ff81e10f6fa7dfc", name: "CORRUPTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute.", description: "You begin to generate a surge of twisted medical release chakra designed spread like a curse, draining all creatures in range. Select a space you can see within range. You manifest a 5- foot radius field of corruption. At the beginning of each of your turns for the duration, the size of the field grows by 5 feet. All creature who begins their turns within the affected area or first enter the affected area on their turns, must make a Charisma saving throw. On a failed save creatures take 3d12 necrotic damage and no damage on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "20a5b9c136d37dd9a2b5dbf6", name: "DETECT POISON AND DISEASE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 minute", description: "For the duration, you can sense the presence and location of poisons, poisonous creatures and diseases within 30 feet of you. This jutsu can penetrate most barriers, but is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ae84b25a52c6de147c7d0070", name: "ENSNARING STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "CM, M", duration: "1 Round", description: "The next time you hit a creature with a melee or ranged weapon or unarmed attack before this jutsu ends, you inject chakra into your enemy’s muscles attempting to restrict their movements. The target must make a Strength saving throw or be restrained until the end of their next turn. A large or larger creature has advantage on the saving throw. While restrained by this jutsu, the target takes 1d8 poison damage at the start of each of its turns.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8", created_at: NOW, updated_at: NOW },
  { _id: "cc949ddb8ae0050c8c1b68fd", name: "GOODBERRY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, M", duration: "Instant", description: "With fine chakra control, you can touch up to 5 fruits or nuts that are then infused with medical release chakra for the duration. A creature can use its action to eat any of the 5 affected food items. Eating a food infused with this jutsu restores 1 hit point and provides enough nourishment to sustain a creature for one day. A creature cannot benefit from this jutsu more than twice per long rest. The infused food loses its potency if they have not been consumed within 24 hours of casting this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a0da65199388587ea8c09fb6", name: "GRIM MASK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra, 1 Hit Die", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You weave summoning seals together and infuse them with medical release chakra manifesting the mask of the Reaper of death. The mask siphons a small fraction of your life force to don it, but it grants you a great deal of power in return. You cannot lose concentration of this jutsu as a result of damage. Attacks you make deal an additional 1d4 necrotic damage for the duration. If an attack you make or jutsu you cast would deal necrotic damage as a part of its casting or through its lingering effects, the additional damage instead becomes a 1d8. Additionally, an attack you make that scores a critical hit or one where you roll the maximum damage possible on the die, if your target is classified as a player character, it loses 1 hit die. If your target is classified as an Adversary, it loses 1 Tenacity die.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e76569cf8c6196cea48d79c2", name: "GRIM SIPHON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra, 1 Hit Die", components: "HS, CM, CS", duration: "Instant", description: "You weave summoning seals together and infuse them with medical release chakra manifesting the hand of the Reaper of death. The hand siphons a small fraction of your life force to summon it, but it grants you a great deal of power in return. Select one creature you can see within range, that creature must make a Charisma saving throw, taking 2d8 + your ninjutsu ability modifier necrotic damage, and depending on the targets classification different effects would be applied to them. If the target is classified as a player character, they lose 1 hit die on a failed save or half as much damage and no hit die loss on a success. Another creature of your choice that it within 20 feet of your target regains hit points equal to the damage dealt. If the target is classified as an Adversary, they lose 1 Tenacity die, and you gain it for 1 minute, able to use it as a bonus to one ability check, skill check or saving throw.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "cee20865a6091a6a477dc7eb", name: "GRIM WEAPON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM, W (Any)", duration: "Concentration, up to 1 minute", description: "You weave summoning seals together, infusing them into your weapon and medical release chakra that manifests as an echo of reaping black chakra enhances the weapon you touch. You cannot lose concentration of this jutsu as a result of damage. For the duration, the weapon you affected by this jutsu is enhanced by the reaper’s black necrotic chakra. Enhanced weapons deal an additional 1d6 Necrotic damage twice per turn. If the affected creature has regained hit points prior in this initiative roll, this damage is increased to 1d12. Once per round, creatures who take necrotic damage from this enhanced weapon reduces the number of hit points they regain by half.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the damage this jutsu deals by 1d6 or 1d12 respectively. If this jutsu is cast at S-Rank, creatures who take necrotic damage from this enhanced weapon cannot regain hit points for the duration of this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "89f2d29a92500a1b4a6085f2", name: "HEALING ELIXIR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Minute", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, NT (Medical Kit, 1 Charge)", duration: "1 Hour", description: "You use your medical kit to assist in creating a healing elixir which is contained in a simple vial that appears in your hand. The elixir retains its potency for the duration or until its consumed. As an action, a creature can drink the elixir or administer it to another creature. The drinker regains 4d6+6 hit points and immediately removes 2 ranks of the Bleeding or envenomed condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When you cast this Jutsu at B-Rank, the drinker instead regains 4d8+12 Hit points and immediately ends the Poisoned, Dazed or Weakened conditions or removes 4 ranks of the Bleeding condition. When cast at S-Rank, the drinker regains 4d12+24 and ends any single condition excluding Exhaustion, Prone, or Invisible.", created_at: NOW, updated_at: NOW },
  { _id: "a987af5fd7cf1c2cdecbcda5", name: "HEALING ADEPT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "Special", range: "Special", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You cover your hands in chakra that glows with a warm green hue, reactivating a creature's cells reproductive process closing their wounds. This jutsu is unique unto itself in that it can be cast in one of three variations with each taking more time to cast than the last. This jutsu has no effect on Undead or constructs. • 1 Action: When cast, this Jutsu's range becomes Touch and an affected creature regains a number of hit points equal to 3d8. • 1 Bonus Action: When cast, this jutsu range becomes Self (15-f00t radius) and all creatures of your choice in range regains 8 hit points. • 1 Full-Turn Action: When cast, this jutsu’s range becomes Self (30-f00t radius) and all creatures of your choice in range regains 3d8+5 hit points", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and healing by +1 dice. If you do not roll dice for healing when casting this jutsu, you instead increase the healing by +4. 14", created_at: NOW, updated_at: NOW },
  { _id: "042b1be96decf9ecc00ed57d", name: "HONEY BEE TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You summon a large swarm of bees made of poisonous medical release chakra that swarm and sting a single target that you can see within range. Make a ranged ninjutsu attack. On a hit, you deal 2d6 Poison damage and the target must make a Constitution saving throw. On a failed save the targets joints begin to seize up for the next minute. At the beginning of the target creatures turn they roll 1d12. On a roll of 1 or 2 the pain keeps them from moving Stunning them until the end of their turn. The target remakes the Constitution save at the end of each of their turns ending this on a success. A Jutsu or effect that ends the poison condition can also end this condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the number of targets by +1.", created_at: NOW, updated_at: NOW },
  { _id: "9660ca9c173272c20115f434", name: "NECROSIS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You infused Medical Chakra on your hands as you putrefy it. Make a melee ninjutsu attack against a creature you can reach. On a hit, the target takes 2d12 Necrotic damage. Plants take double damage. Additionally, the creature must make a Constitution saving throw. On a failed save they gain 1 rank of Envenomed as their body begins to open long closed wounds.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "e440e04969b7e1650c10bdfa", name: "POISON BULLET", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You inhale air, as your saliva begins to build while pumping medical release chakra into it, putrefying the liquid until it becomes a poisonous substance that you can eject from your mouth like bullets. Make a ranged ninjutsu attack, dealing 3d6 poison damage. On a hit a creature damaged by this jutsu suffers a 1d4 penalty to their next attack roll or skill check until the end of their next turn. This penalty does not stack.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, the number of attacks you make by +1. If this jutsu is cast at S-Rank, the number of attacks you make by +2", created_at: NOW, updated_at: NOW },
  { _id: "c62d725aba074973ec77b93e", name: "POISON STINGER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM, W (any thrown)", duration: "Instant", description: "You infused Medical Chakra on a thrown weapon as you putrefy it. Make a ranged ninjutsu attack against a creature within range. On a hit, the target takes your weapons damage + 2d6 Poison damage and must make a Constitution saving throw. On a failed save they are poisoned for 1 minute.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "24c44fb3c758023eb25b949c", name: "POISONOUS BLAST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You mold medical release chakra in your belly to imitate the heat and power of the fire release nature transformation, before releasing it as a blast of sickly green or dark purple chakra from your hands or mouth. All creatures in a 10-foot radius sphere centered on a point you can see within range, must make a Dexterity saving throw. On a failed save, creatures take 2d8 poison damage and gain the envenomed condition. On a successful save, creatures take half damage and no further effects.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and the radius of the sphere by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "f150a60dffdcce108a1e56db", name: "TOXIC EXTRACTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You can manipulate any substance comprised of toxic materials or poisonous components, much like a water release master, bending water to their whims. As an action on your turn, a creature you touch can have the poison, toxins or venoms drawn out of them through their skin. The substance coalesces into a mote of poison which you can choose to place into a vial, retaining it for later use, or dispersing it harmlessly. The extracted poison retains its potency for the next 10 minutes and can be applied to a weapon or used as a component for another jutsu that requires it or a Poisoners kit.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dec7950ac5a49d52f991e81a", name: "TOXIC FANGS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charge)", duration: "Concentration, up to 1 minute.", description: "You coat your hands in a poisonous liquid and use your medical release chakra to maintain its viscosity and lethality. For the duration, your hands, feet or teeth are coated in a heavily poisonous substance, ready to be used as striking instruments. For the duration, you can spend your action to make a melee ninjutsu attack. On a hit you deal 3d4 poison damage and once per turn, you can force the target creature to make a Constitution saving throw. On a failed save, the target gains 1 rank of envenomed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d4. If this jutsu is cast at B-Rank the number of attacks you can make becomes two. If this jutsu is cast at S-Rank, the number of attacks you can make becomes three.", created_at: NOW, updated_at: NOW },
  { _id: "bd611202fd4f317654d0e1d9", name: "TWISTED HEALING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Reaction, which you take when you see a creature regain hit points", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate a surge of twisted medical release chakra designed to reverse the effects of healing, even making it detrimental to do so. When you see a creature begin to mend their wounds, or have their wounds mended by another within range, you can swiftly prevent it. Roll 4d6, you reduce the amount of hit points regained by the result.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of targets by +1, and the healing prevented by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "560928405e5ba83078d399de", name: "VENOM SHOCK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant.", description: "You generate a surge of medical release chakra and imitate the violent and un controllable currents of lightning release nature transformations. Select one creature you can see within range. The target creature must make a Constitution saving throw. On a failed save, they take 3d8 poison damage and gain the envenomed condition or half as much on a successful save and no further effect. A creature envenomed as a result of this jutsu suffers a -1 penalty to Strength saving throws for each rank of envenomed they have.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8 MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "d267caa95eea9d942a6b93f8", name: "VENOMOUS SHARDS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (15-foot cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You mold medical release chakra in your hands to imitate the substance and structure of the earth release nature transformation, before releasing it as a quake of sickly green or dark purple crystalline structures from the ground itself. All creatures in a 15-foot cube originating from you, must make a Constitution saving throw. On a failed save, creatures take 2d12 poison damage and have their movement speed reduced by 10 feet for the next minute. On a successful save a creature takes half damage and no further effect. A jutsu or effect that would end the poisoned condition, can also remove this effect.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d12 and the size of the cube by 5 feet. If this jutsu is cast at B-Rank and above on a failed save this jutsu also inflicts the envenomed condition. If this jutsu is cast at A-Rank and above, on a failed save this jutsu also leaves the affected area as difficult terrain. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2daf76bedc4d5685bd08f56a", name: "WITHER AND BLOOM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 feet (10-foot radius sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate a surge of twisted medical release chakra designed to invoke life and death. All creature of your choice in a 10-foot radius sphere centered on a point you can see within range, must make a Constitution saving throw. On a failed save they take 3d6 necrotic damage. Additionally, one creature of your choice within the chosen area regains 3d6 hit points.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the hit points regained by 1d6. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e1fdf03d3b1148bad891799a", name: "WOUNDS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate a surge of twisted medical release chakra designed to tear open wounds and rend the flesh. Make a range ninjutsu attack against a creature you can see. On a hit, you deal 3d10 necrotic damage. A creature who currently has ranks of bleeding, has one rank of bleeding evolve into one rank of laceration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d10. 16", created_at: NOW, updated_at: NOW },
  { _id: "2f7f6f85eb56348b1a609af7", name: "OPPRESSIVE AURA", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "10 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You begin to exert chakra into an oppressive aura around yourself with enough intensity to be seen by the naked eye and even move loose materials such as dirt, leaves, and water droplets. Creatures who are within 10 feet of you upon activation of this jutsu must make a Strength saving throw to not be pushed to their knees and become prone for the duration, becoming unable to stand while inside the aura. Creatures knocked prone by this jutsu remakes their saving throw at the beginning of their turn to end the effect. If a you, or an affected creature moves outside of the aura, the jutsu’s effect ends on them immediately. A creature affected by this jutsu, who ends or escapes its effects, cannot be affected again until the end of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2da4266c10cd015c5d221293", name: "BIND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You infuse chakra into a chakra seal as you attempt to mark a person with the seal of binding. A creature within range, must make a Charisma saving throw. On a failed save the target creature is Restrained for the duration and gains 1 rank of Sealed. A creature restrained by this jutsu remakes their save at the end of each of their turns.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets by +1. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "391ae4363a809037606e303e", name: "BLOCK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction, which you make when you or a  willing creature you can see are targeted or would make a  saving throw against a jutsu with the Fuinjutsu keyword", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "1 Round", description: "You infuse chakra into a chakra seal as you attempt to manifest a seal of protection. When you or a willing creature would be the target of, or would make a saving throw or skill check against, any jutsu with the Fuinjutsu keyword you enact a defensive ward meant to protect until the beginning of your next turn. They gain a +2 bonus to their AC, saving throws, and ninshou checks against jutsu with the Fuinjutsu keyword.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase your AC and saving throw bonus to +3. If this jutsu is cast at S-Rank or higher, increase your AC and saving throw bonus to +4. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "afdf63cb572df17b940106c0", name: "FRACTURE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You infuse chakra into a chakra seal as you attempt to mark a person with the seal of descension and then shatter it causing a fracture in their internal balance of Yin and Yang. A creature you can see within range, must make a Charisma saving throw. On a failed save the target creature takes 3d8 Force damage and gains 1 rank of Sealed. A creature with 3 or more ranks of Sealed makes this saving throw at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. If this jutsu is cast at B-Rank or higher, increase the ranks of Sealed inflicted to 2. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "b9d35e0df231707916d2b002", name: "LOCK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "3 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You infuse chakra into a chakra seal as you attempt to mark an object with a seal of objection. You must select either an unattended object or a creature you can see within range who is holding an item. If an unattended item it is instantly bound to the surface it is currently resting on. If a creature holding an object, that creature must make a Strength saving throw. On a failed save the object the target is holding is sealed and bound to the nearest surface within range; be it the floor, a wall, or ceiling. For the jutsu’s duration the item remains bound to that surface unable to be moved by any means. A creature within 5 feet of the sealed object may attempt to remove the seal by making an Intelligence (Ninshou) check vs your Ninjutsu save DC. On a successful save they break the seal freeing the item.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range by 30 feet.", created_at: NOW, updated_at: NOW },
  { _id: "bd6e0a13a8b42a6f86da3a66", name: "REVERBERATE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, CS, W (Any)", duration: "Concentration, up to 1 minute", description: "You infuse chakra into a chakra seal as you mark a weapon you touch with a seal of veneration. For the duration, this [Weapons Damage] die is increased by +1. If the weapon already rolls more than one die when it deals damage, you instead increase the damage die by one step. (d4>d6>d8>d10>d12) This weapon cannot be targeted with another jutsu or effect that would change its damage type, die, add additional damage die, or augment it further by any means. If it is the target of such a jutsu or effect, it shatters. If this weapon scores a critical hit the seal shatters and you reroll any 1’s taking the second result. This jutsu then immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e1a2bc974ca9e254311b3686", name: "SENSING TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "Special", range: "Self", chakra_cost: "5 Chakra", components: "HS", duration: "10 minutes", description: "You are able to knead chakra in such a way that you can begin to sense other creatures chakra signatures clearly when you try. You can only cast this jutsu on your turn, and casting it does not cost action economy. When this jutsu is cast, for the duration, you gain access to a unique special action called Sense Chakra. This special action can be gained and used in addition to other special actions you gain and use. This special action counts as a Skill-Action and both a Constitution and Wisdom based skill. Sense Chakra. As a Bonus action, you can make a Perception check using either Constitution or Wisdom vs the Passive Chakra control (Chakra control bonus + 10) of all creatures within 30 feet of you. On a success, you gain the benefit of the Chakra Sensing special sense against them for the duration until they either have 0 chakra or they make and succeed their Suppress Chakra skill action.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range of the Sense Chakra skill action by 30ft.", created_at: NOW, updated_at: NOW },
  { _id: "70032fdf669183edbc59c5d0", name: "SHADOW SNAKE BITE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "15 Feet", chakra_cost: "4 Chakra", components: "HS, CS", duration: "Instant", description: "You summon a snake formed from chakra that originates from a location of your body, that reaches out and attacks the target creature in range. Make a Ninjutsu attack. Target creature takes 2d8 Poison damage and must make a Strength saving throw on a Hit. On a failed Strength save, the target creature is restrained by the snake. As an action on a restrained creatures turn, they can attempt another Strength saving throw to end this condition on themselves.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets this jutsu affects by +1.", created_at: NOW, updated_at: NOW },
  { _id: "8d154682fbb93bad8e2c33f6", name: "SUBSTITUTION TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "Self", chakra_cost: "5 Chakra", components: "HS, M", duration: "Instant", description: "You quickly replace yourself with an object, allowing you a swifter escape with smaller margins for error. When you would take damage you may increase your AC by +3 until the beginning of your next turn. If this bonus would cause the triggering attack to miss, you may move up to half of your movement away. If you activate this jutsu as a result of making a saving throw, you must still make the saving throw even if your movement would move you to the outside of its range.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1ff40eb6f7749655d5605a7b", name: "SUMMONING TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "Full Turn Action", range: "10 Feet", chakra_cost: "Special (See Summoning Section for Jutsu", components: "HS, CS, CM", duration: "Instant", description: "You must have formed a Blood Contract with a Sage Tribe, such as one found in the Summoning Jutsu section found at the end of the Ninjutsu chapter in order to successfully cast this jutsu. If a creature refuses or cannot be summoned, You spend chakra according to the rank this jutsu was cast. It appears where the user designates and can act as a Bonus Action on the user's turn, on the user's initiative order. You can communicate with the creature and it will listen to you and only you in combat. You can direct it to perform the following actions: Attack (Unarmed, Weapon, or Jutsu), Dodge, and Help. The creature can perform an Action and Move. The summoned creature must remain within 120 feet of the summoner. All sage creatures can speak common.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, you summon a corresponding creature equal in level and rank to the Rank used upon activation. 18", created_at: NOW, updated_at: NOW },
  { _id: "f7bed87e7188d69d54f88bf3", name: "THUNDEROUS SCREECH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You create a focused high-pitched screech that affects creatures in the direct path of the sound waves. Creatures in the target area must make a Constitution saving throw. On a failed save their body is rocked by the thunderous shockwave of sound. They gain 1 rank of Concussed and lose concentration on any one Jutsu of equal rank or lower they were concentrating on. On a successful save they suffer no effects.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the cone size by +5ft. C-RANK: BEAST IMITATING ART:", created_at: NOW, updated_at: NOW },
  { _id: "6f6aa27b1a5df1c5fa5a3c5d", name: "BEAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, Up to 1 minute", description: "You draw a picture of a bear. Infusing chakra into it as it exits your scroll and standing next to you. You summon a construct Ink bear. The construct bear has the following Statistics; You may command the Ink Bear as a bonus action on your turn. The Ink bear may take an appropriate reaction if able, such as attack of opportunity. The Ink Bear uses your Ninjutsu Attack bonus and Save for all of its attacks and effect save DC’s", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Ink Bears Hit points by 2d10+6. BEAST IMITATING ART:", created_at: NOW, updated_at: NOW },
  { _id: "d88b06a2111586ffa3c01238", name: "LION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, Up to 1 minute", description: "You draw a picture of a lion. Infusing chakra into it as it exits your scroll and standing next to you. You summon a construct Ink Lion. The construct Lion has the following Statistics; You may command the Ink Lion as a bonus action on your turn. The Ink Lion may take an appropriate bonus action if able. The Ink Lion uses your Ninjutsu Attack bonus for all of its attacks.", at_higher_ranks: "At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Ink Lions Hit points by 2d8+2.", created_at: NOW, updated_at: NOW },
  { _id: "a56516f3f8d704d7057a893c", name: "BEAST SENSES", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "6 Chakra", components: "HS, CM, CS", duration: "1 Hour", description: "You touch a willing beast. For the duration of the jutsu, you can use your action to temporarily gain the special senses or sensory features of the beast you touch for up to 1 hour. After which this jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the length of time you retain the special senses by 1 hour.", created_at: NOW, updated_at: NOW },
  { _id: "b556bd736cb5188916ed48c2", name: "CHAKRA SPHERE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet.", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create a 5-foot diameter floating sphere of dense chakra in an unoccupied space you can see within range. As a bonus action on your turn, you can command the sphere to move up to 30 feet and make a single melee ninjutsu attack against a creature within 5 feet of it. On a success, the target takes 2d8 damage. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. • Earth: As an action on your turn or when the jutsu ends, you can cause one or more spheres to explode. Each creature within 15-feet of the spheres space(s) must make a Strength saving throw. On a failed save the creature takes gains 1 bruised and concussed. • Wind: Each creature hit by a sphere must make a Strength saving throw being knocked back 20 feet on a failed save. • Fire: Each creature who begins their turns within 5 feet of the sphere must make a Constitution saving throw, being burned on a failed save. • Water: Your sphere can move through allied spaces. When it does, roll its damage die, granting the creature(s) who’s space it moved through temporary hit points equal to the result. A creature can only gain temporary hit points this way once per turn. • Lightning: Each creature hit by a sphere must make a Constitution saving throw, being shocked. • Force: The damage die becomes a d10.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 the damage by 1d8 and the number of spheres created by +1, controlling each sphere independently with the same action. A creature can only be affected by two spheres each turn. Additionally, you can change the Nature Release and corresponding Damage type to one you currently know.", created_at: NOW, updated_at: NOW },
  { _id: "a5fd9049cebfb70c02847779", name: "CHAKRA TENTACLES", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "90 feet.", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create squirming tentacles of chakra that fill a 20-foot cube on a surface that you can see within range. When a creature enters the affected area for the first time or starts its turn there, they must make a Strength saving throw. On a failed save they take 3d6 bludgeoning damage and are restrained for the duration. A creature restrained by this jutsu takes 3d6 bludgeoning damage at the beginning of each of its turns. A creature restrained by this jutsu can use its action to remake it’s saving throw. On a success, it free’s itself.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 the damage by 1d6 and the cube size by 5ft. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "e369a16c97b49b460cf6af82", name: "DARKNESS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 minutes.", description: "You imbue your chakra seal to conjure a field of darkness. You throw your seal at a point you choose within range. The chakra-based darkness spreads from the seal, to fill a 15-foot radius sphere for the duration. The darkness spreads around corners. A creature with Darkvision or Chakra Sight can’t see through this darkness, and light created using an effect or jutsu of C-Rank or lower cannot illuminate it. If the point you choose is on an object you are holding or one that isn’t being worn or carried, the darkness emanates from it and moves with it. If any of this jutsu’s area overlaps with an area of light created by a jutsu of B-Rank or higher this darkness is dispelled.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "98f634f99909ebc59c07abe6", name: "HAIR BINDING TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "Using chakra, you activate the roots of your hair and begin to manipulate it freely. Because of the malleability of this hair, the user can attempt to grapple creatures completely immobilizing them. Select one creature within range. Make a melee ninjutsu attack. On a hit, the target is grappled by you. Creatures grappled by this jutsu cannot use Chakra Seals (CS). At the end of a restrained creatures turn, they make a Strength saving throw, escaping on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 the number of creatures you can target by +1. 20", created_at: NOW, updated_at: NOW },
  { _id: "116917754eed20f11bb6c47b", name: "HIDING IN SHADOW TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "10 Minutes", description: "As a part of the requirements to cast and maintain this jutsu a creature or object within range must be casting a shadow. You select a creature, structure or objects shadow within range. Stealthily slipping inside of it, and gaining total concealment for this jutsu’s duration. For the duration of this jutsu, you can see and hear from the shadow but cannot act, speak, or move. When the creatures shadow moves, you move along with it. You may end this jutsu early as a bonus action expelling yourself from the shadow appearing in the closest space near the target that can hold you. If the target would lose their shadow by any means, this jutsu immediately ends as you appear in the closes space near the target that can hold you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e547d0d48b3deef81dbc8e76", name: "LIVING WEAPON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 bonus action", range: "Touch (60 feet)", chakra_cost: "8 Chakra", components: "CM", duration: "Concentration, up to 1 Minute", description: "You touch a weapon an imbue it with your chakra and it begins to float within range and does so for the duration or until you dismiss this jutsu. When you cast this jutsu you can move the weapon 30 feet an make a melee ninjutsu attack against a creature within 5 feet of the weapon. On a hit, the target takes the 2d8 + your ninjutsu ability modifier of your weapon’s damage type. As a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack against a creature within 5 feet of it.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c122c8a3664b8d254145b3b6", name: "ACID SPRAY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30 Foot Line)", chakra_cost: "6 Chakra", components: "HS, NT", duration: "Instant", description: "You take a vial of poison ingesting and using your fine control of chakra, blend it with your stomach acid that you spray out like a jet in a straight line. Creatures in range must make a Dexterity saving throw. On a failed save, affected creatures take 6d4 Acid Damage and gain 1 rank of Corroded and they take another 2d4 Acid damage at the start of their next turn. On a success the target takes half as much damage and suffer no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the initial and delayed damage by 2d4. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2064ba961b170cc974e62d31", name: "ACIDIC BLAST", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot-cone)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate acidic medical chakra and release it into a spray of boiling acid. All creatures in range must make a Dexterity saving throw, taking 6d6 acid damage on a failed save and half as much on a successful save. A creature who fails their saving throw gains 1 rank of the corroded condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4b0660ff482c330801db59b6", name: "ACIDIC BLOOD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Reaction, which you take when a creature other than yourself, within range would take Bludgeoning, piercing or slashing damage from an attack.", range: "60 Feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 Round", description: "You begin to generate acidic medical chakra and infuse it into a willing creature within range. When a willing creature would take bludgeoning, piercing or slashing damage before the beginning of their next turn, their body reacts by ejecting acidic blood. All creatures within 5 feet of the affected creature takes 9 acid damage, and must make a Constitution saving throw being corroded on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 3. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "a969037b64e21187d1f68cf6", name: "ACIDIC BOLT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate acidic medical chakra and mold it into an arrow, lance or bullet. Make a ranged ninjutsu attack against a creature in range. On a hit you deal 4d6 acid damage. All creatures in a 15-foot cone originating from the target much make a Dexterity saving throw, being corroded on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by 1. 21 MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9b1ff82c56a1b0ae38ea8062", name: "AID", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "1 Hour", description: "You imbue a chakra seal with medical release chakra before placing it on up to three creatures within range. Each target’s Maximum Hit Points increase by 15 for the duration and they regain 15 Hit Points.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and a target’s Maximum Hit Point increase and healing done by an additional 10. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "bd2b729be6d97c34e0828ff6", name: "AURA OF LIFE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You infuse medical chakra into yourself as you release it as an aura of supporting energy. For this jutsu’s duration, anytime you or a non- hostile creature in this jutsu’s radius would take damage from a hostile creature, they immediately regain 8 Hit Points. A creature can only be healed by this jutsu 5 times per casting, after which this jutsu no longer affects them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the maximum number of times a creature can be healed by this jutsu by +2. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "a0bb916f0cc9c757d6ccda2a", name: "AURA OF PURITY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You infuse medical chakra into yourself as you release it as an aura of cleansing energy. You release a potent wave of medical release chakra. All creatures within range who are currently under the effects of a Mental or Sensory conditions as a result of a jutsu of equal rank or lower, has all stacks (if any) of their condition removed, cleansing them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. Listed conditions inflicted by jutsu of equal rank or lower are removed. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0edb4b129b71955a2afaebd8", name: "CHAKRA NEEDLES", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "7 Chakra", components: "HS, W", duration: "Instant", description: "You create needles formed from your chakra and launch them at a creature you can see within range. Make a Ranged Ninjutsu check. Target creature takes 6d6 Necrotic damage on a hit and must make a Constitution saving throw, losing 10 movement speed until the end of their next turn on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, damage by 1d6 and reduce target movement by 5. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "92f7d408c25ddc01e4f1cd68", name: "CHAKRA TRANSFER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "Special", components: "CM", duration: "Instant", description: "You place your hand on a creature and share your chakra with them, transferring it to them. Spend a number of Chakra die up to your proficiency bonus. When you do roll the spent die, recording the result and adding your Constitution modifier. Transfer the result to a willing creature. Chakra die spent in this way cannot be regained until you complete a long rest. If the creature is affected by a Genjutsu, they gain advantage on their next saving throw.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "de47450086be062c2047fd07", name: "CORRUPT WAVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate corrupted medical chakra and release it as a destructive wave of desecrating energy. All creatures in a 30-foot long, 10-foot-wide line originating from you, must make a Constitution saving throw, taking 6d4 necrotic damage or half as much on a success. Creatures who failed, take 4d4 necrotic damage at the beginning of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the initial damage by 1d4. 22 MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "87a71a447c02f925c5cb8cf5", name: "ENCROACHING ENTROPY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You weave necrotic and decaying medical release chakra together and manifest it into a point you can see within range. The point expands until it is occupying a 20-foot radius sphere, forcing all creatures within its radius to make a Constitution saving throw. On a failed save creatures take 3d8 necrotic damage and have their maximum hit points reduced by the same amount. On a successful save they take half damage and suffer no further effects. A creature who’s hit point maximum is reduced as a result of this jutsu, must make a Constitution saving throw at the beginning of each of its turns, taking an additional 2d8 necrotic damage and having their maximum hit points reduced by the same value, taking only no damage on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and both instances of damage by 1d8. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "454a042f48272f8b8fba60ee", name: "GRIM BLADE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "9 Chakra, 1 Hit Die", components: "HS, CM, CS", duration: "Instant", description: "You weave summoning seals together and infuse them with medical release chakra manifesting two hands of the Reaper of death. His hands reach into you and draw out a fragment of your spirit turning it into a temporary blade of necrotic power. The reaper makes a melee ninjutsu attack at a creature of your choice within range, even if you cannot see them, ignoring cover. If the target you select whom you cannot see, is not in range, the reaper instead randomly picks a creature itself from all available creatures in range. On a hit the reaper deals 10d4 necrotic damage and depending on the type of creature it hits, the following happens. A creature affected by this jutsu cannot be affected by it again, until the end of this casters next turn; • If the target is considered a player character, it reduces the number of hit die it has by 1d4. If a creature affected by this jutsu has 0 Hit die, they take additional necrotic damage equal to your level on a hit. • If the target is considered an adversary, it loses 1 Tenacity die.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 chakra. If this jutsu is cast at A-Rank, you spend 1 additional hit die and increase the damage by 4d4, and the number of hit die lost to 1d6. If this jutsu is Cast at S-Rank, you spend 1 additional hit die and increase the damage by 6d4, and the number of Tenacity die reduced to 2. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9ed448b93e48e6c59dcb76f6", name: "GRIM LEGION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "9 Chakra, 1 Hit Die", components: "HS, CM, CS", duration: "Concentration, up to 1 minute.", description: "You weave summoning seals together and infuse them with medical release chakra and a portion of your spirit, manifesting a summoning tag that you throw into a space you can see within range. From the chakra seal an echoing call of shadowy figures of your choice begin to manifest filling a 10-foot cube, which counts as difficult terrain. The creatures resemble once living entities you once knew. Whenever a creature starts its turn inside the cube, or within 5 feet of it, or enters the cube for the first time on its turn, the conjured shadows all strike. Affected creatures make a Strength saving throw, taking 4d10 necrotic damage and dragging them 5 feet towards the center of the cube and depending on the type of creature that fails the save, the following happens. A creature affected by either of the following effects cannot be affected by it again, until the end of this casters next turn; • If the creature is considered a player character, it reduces the number of hit die it has by 1d4. If a creature affected by this jutsu has 0 Hit die, they take additional necrotic damage equal to your level on a hit. • If the creature is considered an adversary, it loses 1 Tenacity die.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 chakra and the size of the cube by 5 feet. If this jutsu is cast at A-Rank, you spend 1 additional chakra die, increase the damage by 2d10 and affected creatures are knocked prone prior to being dragged in closer. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e2a3147d56b78d0d1b0277a9", name: "MEDICAL AURA", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Life preserving Medical Chakra radiates from you in an aura with a 30-foot radius. Until this jutsu ends, the aura moves with you, centered on you. Each non-hostile creature in the aura, (including you) has resistance to necrotic and poison damage and becomes immune to the bleeding and envenomed conditions. A creature’s hit point maximum while within the aura cannot be reduced by hostile effects. Additionally, creatures roll at advantage when making saving throws to resist an Elemental condition. Lastly, a non-hostile, living creature regains 1 hit point when it starts its turn in the aura with 0 hit points. A creature can only regain hit points this way a number of times equal to its Constitution modifier per long rest (Min 1.)", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "07dd754f7b51316663547cf5", name: "METALLIC RUST", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate acidic medical chakra and attempt to press it onto a creature, object or item of your choice. Make a melee ninjutsu attack against a creature you can reach. On a hit, you deal 6d4 acid damage and the target becomes covered in acid becoming corroded. A creature wearing armor suffers a permanent -1 penalty to its AC bonus on a failed save. An Armor whose AC bonus is reduced to 0 is destroyed. Armor whose AC is suffering a penalty can be fixed by casting the Mending jutsu on it, removing all penalties or with 1 hour of work with an Armorsmith kit.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d4. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2ba3a2747107510b894b5661", name: "PLAY DEAD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "6 Chakra", components: "HS, CM", duration: "1 Hour", description: "You touch a willing creature putting it into a cataleptic state that is indistinguishable from death. For the jutsu’s duration, or until you use an action to touch the target and dismiss this jutsu, the target appears dead to all outward inspection and to jutsu used to determine the targets status. The target is blinded and incapacitated, and its speed drops to 0. The target has Resistance to all damage. If the target is diseased or poisoned when you case this jutsu, or becomes diseased or poisoned while under this Jutsu's effect, the disease and poison have no effect until this jutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "288ebef56e53e752f4188b3b", name: "POISON MIST TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 Feet (30 Foot Cloud)", chakra_cost: "9 Chakra", components: "HS, NT", duration: "1 minute", description: "You ingest a vial of poison, and exhale it as a thick cloud of purple smoke that obscures vision up to 60 feet away that expands into a 15-foot radius sphere that spreads around corners. It lasts for the Duration. When a creature enters the area for the first time on a turn or starts its turn there, the creature must make a Constitution saving throw taking 3d10 poison damage and gaining the poisoned condition on a failed save and half as much on a successful one. Creatures are affected even if they hold their breath and don’t need to breathe.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c99ada48504dde84c2a3da97", name: "POISON WEAPON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM, W (Any)", duration: "Concentration, up to 1 Minute", description: "You touch a weapon, coating it in a vile green glowing poison and enhancing its potency. Weapon and Taijutsu attacks made with this weapon deals an additional 2d4 Poison damage twice per turn. You cannot lose concentration of this jutsu as a result of damage. Once per turn, when you would deal Poison damage with this jutsu, the affected creature must make a Constitution save, gaining 1 rank of Envenomed on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or Higher, increase the number of ranks of Envenomed this jutsu inflicts by +1. If this jutsu is cast at A- Rank or Higher, increase the damage by 1d4. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4dcc75e7fd96e8415f0a40a6", name: "RAY OF SICKNESS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You collect medical release chakra into your hands and fire a ray of sickening energy that lash out towards a creature within range. Make a ranged ninjutsu attack against a target within range, on a hit the target takes 3d8 poison damage and must make a Constitution saving throw. On a failed save it is also poisoned for the next minute.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "d01299ab979ea38d6b852945", name: "RESTORATIVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "Your hands glow with a warm blue hue as you touch a willing creature filtering out impurities and fixing debilitating conditions, they are suffering from with precise chakra control. Creatures suffering from an Elemental, Physical, Mental or Sensory condition from the use of a jutsu or effect of a rank, equal to or lower than what this jutsu was cast, are healed of one of those conditions, removing all ranks, if any.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. The number of conditions with a different name removed increases by +1. 24 MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0c63720902010f80d969a0cd", name: "SPORE CALLER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (15 Feet)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You begin to generate poisonous medical chakra and release it like an aura permeating from your skin. All creatures, excluding the caster, who would begin their turns in or first enter your, poisonous aura of spores, must make a Constitution saving throw taking 4d6 poison damage and having the spores nest in their eyes blinding them until the end of their next turn. A creature who would be blinded by this jutsu while already blinded has the duration of the blinded condition extended by 1 round.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "85217dada02194ffc8e19e54", name: "STINKING CLOUD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "8 Chakra", components: "HS, CM, W", duration: "1 minute", description: "You create a 10-foot radius sphere of yellow nauseating gas centered on a point within range. The cloud spreads around corners, and its area is heavily obscured. The cloud lingers in the air for the duration. Each creature within the cloud at the start of its turn must make a Constitution saving throw. On a failed save the creature spends it action that turn retching and reeling. Creatures that don’t need to breathe or are immune to poison automatically succeed on this saving throw. A moderate wind (at least 10 miles per hour) disperses the cloud after 4 rounds. A strong wind (at least 20 miles per hour) disperses it after 1 round.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "28d78319a9a3b06fc0379a65", name: "TRANSFER OF LIFE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Full Turn Action", range: "Touch", chakra_cost: "Special", components: "HS, CM, CS", duration: "Instant", description: "You sacrifice your life for another. Select one creature who has been dead for no longer than 10 Minutes whom you can reach. This jutsu cannot be used by Clones, Constructs or Undead. When you do, you begin transferring all of your life energy into them. The creature regains all of its hit points equal to your current hit points. A creature revived as a result of this jutsu has all ranks of Exhaustion removed from them. Reduce your Maximum hit points to 0, which cannot be increased by any means.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1e3c4b5c28031c27cbf37131", name: "VAMPIRIC TOUCH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Your hands glow with a shadowy aura of chakra. Make a melee ninjutsu attack against a creature within your reach. On a hit, the target takes 4d10 necrotic damage and you regain hit points equal to half the amount of necrotic damage dealt. Until the jutsu ends, you can make the attack again on each of your turns as an action.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "dbc92793f5c3e83589b91113", name: "VENOMOUS HAZE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30 Foot cube)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You begin to generate poisonous medical chakra and release it, creating a poisonous haze, enough to fill a 30-foot cube originating from you. All creatures within the haze who would suffer damage of varying types also suffer additional effects based on the damage taken. Bludgeoning Damage. Once per turn, must make a Constitution saving throw, gaining the poisoned condition as they inhale a large breath of poison. Piercing Damage. Once per turn, must make a Constitution saving throw, gaining the envenomed condition as poison is injected into them with each strike. Slashing Damage. They take an additional 1d6 poison damage once per turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu cast at A-Rank, increase the size of the cube by 15 feet. 25 MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "14a62c489ca0b7adaec22504", name: "VENOMOUS REFLUX", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant.", description: "You begin to generate poisonous medical chakra and release it, causing it to erupt under a creature you can see within range. Select one creature you can see within range. The target creature must make a Constitution saving throw as poison erupts around them. On a failed save, they take 3d8 poison damage and cannot take reactions until the end of their next turn as they are coughing and hacking the poisonous gas back up trying to eject it from their bodies. On a successful save they take half damage and no further effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "239901758873b9e0f1756c6d", name: "WALL OF BEE’S", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute.", description: "You weave together a mixture of summoning seals and summon forth a wall of angry, irrational and non-compromising bees. The wall is 5 feet thick, 15 feet high and up to 30 feet long. The wall must be continuous and at least 5 feet thick along its entire length. You select where the wall of bees appear and the entire length must be within your line of sight and within this jutsu’s range from you. A creature that starts within the bee’s wall or that gets within 5 feet of the wall of bees agitates the insects and are swarmed by them and must make a Constitution saving throw against their assault. On a failed save they take 5d6 poison damage and are incapacitated until the end of the current turn. On a successful save they take half damage and suffer no additional effects.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1d4ec3d78f8e0a41f0fa525a", name: "NEEDLE JIZO", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You activate the roots of your hair causing your hair to grow at a heightened rate, while you control it to wrap around your body and harden with spiked, needle like hair protruding from it., For the duration, your movement speed is reduced to 0, each time a creature makes a melee attack against you while within 10 feet of you, they take 3d6 piercing damage, this includes the triggering attack.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "cca5c41e1cb45e6304bf81ce", name: "RASENGAN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "8 Chakra", components: "CM", duration: "Concentration, up to 1 Minute", description: "You collect chakra into your hand generating a powerful sphere of spiraling chakra to strike an enemy with. You do not spend chakra to maintain concentration on this jutsu. Beginning at the start of your next turn, you can spend your action to make a melee ninjutsu attack against a creature within range. On a hit, you deal 5d8 force damage and the target makes a Strength saving throw. On a failed save they are knocked back 30ft becoming Dazed and Concussed. This jutsu only ends on a successful hit. If a creature knocked back by this jutsu collides with a structure or construct, their movement stops, taking damage as if they had fallen an equal distance.", at_higher_ranks: "For each rank above C-Rank, increase the cost by 3 and the damage by 3d8 and the knock back distance by 10 feet. If this Jutsu is cast at B-Rank or higher, you can make the melee ninjutsu attack the turn you cast it. You may also add a nature release keyword, changing this jutsu’s damage type to match the nature release you currently can use. You gain the following benefits depending on the Nature Release chosen: • Earth: The target takes earth damage is bruised & gains the weakened condition until the end of their next turn. • Wind: The Rasengan gains a range of 60 Feet and you can instead make a ranged ninjutsu attack targeting a creature within that range. On a hit, the target takes wind damage and the Rasengan expands. All Creatures, except the original target, in a 15-foot radius sphere centered on the original target must make a Dexterity saving throw, taking the damage of this jutsu as well on a failed save. • Fire: The target takes fire damage and 1 rank of burned, and all creatures in a 30-foot cone behind the target creature must make a Constitution saving throw, gaining the burned condition on a failed save. • Water: Target creature takes cold damage and makes their saving throw at disadvantage. On a failed save, they are knocked back twice the distance, taking falling damage if they hit a solid surface. • Lightning: The attack made has advantage and on a hit, the target creature takes lightning damage and gains the Shocked condition.", created_at: NOW, updated_at: NOW },
  { _id: "facb945452032c47e7153af6", name: "SPLINTER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "7 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You infuse chakra into a chakra seal as you attempt to mark a person with the seal of prevention and then shatter it causing a fracture in their internal balance of Yin and Yang. A creature you can see within range, must make a Charisma saving throw. On a failed save the target creature takes 5d8 Chakra damage, gains 1 rank of Sealed and is unable to make Hand Signs (HS) until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. If this jutsu is cast at A-Rank, increase the ranks of sealed to 2. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "e184aec0f8835f61c7ac3e7d", name: "CHAKRA DISPEL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You infuse chakra into a chakra seal as you attempt to end a jutsu with the seal of Dispis. Choose any creature, object, or chakra-based effect you can see as you mark it with your chakra seal. You then attempt to end any Ninjutsu or Genjutsu currently affecting it of a rank less than the rank this jutsu was cast at. If the Jutsu is of a rank equal to this jutsu, you instead must make an ability check, using your ninjutsu ability modifier. The DC equals (13 +the rank of the Jutsu, D-Rank: 1, C-Rank: 2, B-Rank: 3, A-Rank: 4, S-Rank: 5). If the jutsu is of a rank higher than this jutsu, you make the ability check at disadvantage, unable to add dice-based bonuses to your check.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3.", created_at: NOW, updated_at: NOW },
  { _id: "58fcc2a3d677946672bcc719", name: "CIRCLE OF DEFIANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You infuse chakra into a chakra seal as you attempt to end a jutsu with the seal of resistance. For this jutsu’s duration, as a Bonus Action you may select one willing creature within range. That creature gains Temporary hit points equal to 2d8 + Your Ninjutsu ability Modifier, until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the amount of temporary hit points by 1d8 and the number of creatures you can target by +1. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "ff8e77dbd7115d572c567971", name: "CURSE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 10 minutes", description: "You infuse chakra into a chakra seal as you attempt to mark a creature you can touch with the seal of pestilence. You do not need to spend chakra to maintain Concentration on this jutsu. You touch a creature, and that creature must make a Charisma saving throw or become cursed for the duration of the jutsu. When you cast this jutsu, choose the nature of the curse from the following options: • Choose one Ability Score. While cursed, the target has disadvantage on ability checks, skill checks and saving throws made with that ability score. • While cursed, the target has disadvantage on attack rolls against you. • While cursed, the target must make a Wisdom saving throw at the start of each of its turns. If it fails, it wastes its action that turn doing nothing. • While cursed, your attacks and jutsu deal an extra 1d8 necrotic damage to the target. • While cursed, the target cannot regain hit points. • While cursed, the target loses all special senses it has. • While cursed, reduce the targets movement speed by half. • While cursed, the target must speak all of their thoughts verbally as loud as possible. • While cursed, the target gains 1 rank of Demoralized while it is within 20 feet of a specific object or structure of the casters choice. • At the GM option, you may choose an alternative curse effect, but it should be no more powerful than those described above. The DM has final say on such a curses effect.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If casted at B-Rank or higher, increase its duration to 8 hours but does not cost chakra to maintain concentration. If casted at A-Rank or higher this jutsu no longer requires concentration & has a duration of 24 hours. If Cast at S-Rank This jutsu has a duration of Permanent (Until dispelled). 27 SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "e49c6da32f5dc41ac8c9bf0e", name: "INANIMATE PUPPET", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Hour", range: "Touch", chakra_cost: "10 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You infuse chakra into a chakra seal as you attempt to mark an object you can see with the seal of false life. This jutsu creates false life. A creature from nothingness. A servant formed from the world around you. Choose a pile of rocks, dried bones, leaves, wood or any other inanimate objects that you can reach while casting this jutsu. Temporarily reduce your Maximum Chakra by 10 for each puppet you create. You cannot reduce the cost of this jutsu by more than half. For each puppet that dies, or you lose control of, you increase your maximum chakra by 10, up to your original maximum. You place a seal on the objects as they conjoin to form a mimicry of life, raising a construct creature. The creature becomes a construct with the following statistics (When a feature or ability asks for Rank of jutsu use the following; C-Rank: 2, B-Rank: 3, A-Rank: 4, S-Rank: 5) On each of your turns, you can use a bonus action to mentally command any creature you’ve created with this jutsu if the creature is within 60 feet of you. You can control up to 4 Creatures at a time this way. (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete. The creature is under your control for 24 hours, after which it stops obeying any command you’ve given it. To maintain the control of the creature for another 24 hours, you must cast this jutsu on the creature again before the current 24-hour period ends. The use of the jutsu reasserts your control over up to four creatures you have animated with this spell, rather than animating a new one. Recasting the jutsu in this way on an already summoned construct does not reduce your maximum chakra a second time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number hit points your construct has by 10. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "8bad590386014c67236e132d", name: "MARK OF FINDING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Minute", range: "Self (1 Mile Radius)", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 Hour", description: "You infuse chakra into a chakra seal as you attempt to mark yourself with the seal of clairvoyance. You do not need to spend chakra to maintain Concentration on this jutsu. When you cast this jutsu select one creature or location that you have seen or can clearly describe. When you do for the duration of this jutsu, you know the General direction of this creature or location so long as it is within your Jutsu’s radius. This seal does not give you absolute knowledge on the creatures or locations, coordinates, but only what direction they are in relation to you.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the radius of this jutsu by 1 Mile SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "f3e190a3347323b897443430", name: "MOBILITY RESTRICTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction, which you take when you see a creature cast a Taijutsu or Bukijutsu.", range: "30 feet", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You infuse chakra into a chakra seal as you attempt to mark a creature you can see with the seal of patience. This counts as Interrupting a jutsu’s casting. A creature who you can see within range, who cast a Taijutsu or Bukijutsu, must first make a Charisma saving throw. On a failed save the target creatures speed is reduced to 0 until the end of the current turn and gain 1 rank of Sealed. Medium Construct, unaligned Armor Class 13 + The Rank of the Jutsu. (Natural Armor) Hit Points 20 + 10 for each rank above C-Rank. Speed 30 ft. STR DEX CON INT WIS CHA 18 (+4) 12 (+1) 16 (+3) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Necrotic, Poison Damage Resistances Bludgeoning Damage Vulnerabilities Lightning Condition Immunities Charmed, Exhaustion, frightened, stunned, poisoned. Senses passive Perception 10 Unnatural Fortitude. The Inanimate Puppet makes Constitution saving throws at advantage. Multiattack. The Inanimate Puppet can attack a number of times equal to the jutsu’s rank with their slam attack. Slam. Melee Weapon Attack: + (5 + The Rank of the jutsu) to hit, reach 5 ft., one creature. Hit: 1d8 + 4 Bludgeoning damage. SMASH (Recharge 11-12): The Inanimate Puppet slams the ground. All creatures within 10 feet of it must make a DC (12 + The Rank of the Jutsu.) Dexterity Saving throw. On a failed save, they take 3d8 bludgeoning damage, are knocked prone and Dazed until the end of their next turn. 28", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "30910746a706e4b195a8602f", name: "SHADOW CLONE TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "dc2837c0a3446d09da7edaf6"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (6 Chakra)", components: "HS, CM", duration: "1 Minute", description: "An Advanced Version of the Clone Genjutsu that creates a solid clone out of thin air using only chakra called a Shadow Clone. When a Shadow Clone is killed, it sends its most recent experiences within the last minute as thoughts and images to its Summoner. A Shadow Clone presents itself as its own person. A creature looking at a Shadow Clone with chakra sight cannot tell that it is not a real person unless otherwise specified. This jutsu’s caster can further enhance its casting. By doing this the caster can create up to 4 Shadow Clones at once, each clone after the first costing 3 chakra. All Shadow Clones act at once and attempt to perform the same command given. If commanded to perform the help action, they can only help the Summoner. Shadow Clones do not have Reactions and each clone has basic versions of your melee or ranged weapons. Weapons your Shadow Clone is summoned with that has the ammunition property cannot be given to anyone. Shadow Clones can only cast jutsu of C-Rank or lower. If multiple shadow clones attack the same creature, you do not make multiple attack rolls. You instead choose a lead clone and it gains a +1d4 bonus to its damage roll(s), for each additional clone that is aiding it.", at_higher_ranks: "If this jutsu is cast at B-Rank or higher, increase the number of clones you can create with this jutsu by 2. If this jutsu is cast at A-Rank, Shadow Clones you summon can cast jutsu of B-Rank or lower.", created_at: NOW, updated_at: NOW },
  { _id: "b4e4daafa3eec08fa27b25e9", name: "SHADOW SHURIKEN TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot Cone)", chakra_cost: "8 Chakra", components: "HS, CM, W (Thrown)", duration: "Instant", description: "You throw a single weapon, when you do, you quickly multiply it five-fold, creating multiple copies of it while in transit. Creatures within this jutsu’s range must make a Dexterity saving throw taking 5dX + your Dexterity modifier on a failed save, or half as much on a success. (X equals the original Damage die of the thrown weapon d4, d6, d8, d10, d12).", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2dX.", created_at: NOW, updated_at: NOW },
  { _id: "e96be821e992c2ebb1fd2501", name: "SHATTER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You place your hands on a solid surface within range before your hand vibrates and releases a massive surge of chakra creating a sudden loud ringing noise, that erupts from a point of your choice within range. Each creature excluding you, in a 15-foot radius sphere centered on the point of your choice within range must make a Constitution saving throw, taking 4d6 bludgeoning damage and being dazed on a failed save and half as much on a successful one. Constructs have disadvantage on the saving throw, takes double damage and cannot be resistant or immune to this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. 29 B-RANK: BEAST IMITATING ART:", created_at: NOW, updated_at: NOW },
  { _id: "f1c20537176d59d844e710df", name: "TIGER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, Up to 1 minute", description: "You draw a picture of a Tiger. Infusing chakra into it as it exits your scroll and standing next to you. You summon a construct Ink Tiger. The construct Tiger has the following Statistics, using your Ninjutsu attack bonus and Save DC for anything that requires an attack or saving throw. You may command the Ink Tiger as a bonus action on your turn. The Ink Tiger may take an appropriate bonus action if able.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the Ink Tiger Hit points by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "96433d76a867ba4091b9cc74", name: "BESTIAL ART: LYCANTHROPE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You infuse chakra into a chakra seal as you attempt to mark yourself with the seal of wolves. Your voice, figure, and temperament becomes bestial in nature. You grow fur of any color of your choice covering your arms, and your hands become large claws with iron like nails. For this jutsu’s duration, you gain the following benefits; • Your Strength becomes 19 if it is not already 19 or higher. If it is 19 or higher already, you instead increase your Strength Score by +2. • Your unarmed damage is now 2d8. You do not add your ability score modifier to these damage rolls. • You gain a +20 bonus to movement speed. • Attacks of Opportunity you make are at advantage. • When you take the attack action, you can make two attacks instead of one, if you cannot already.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4432a8a6a972f30f3648105a", name: "EXPLOSIVE SUBSTITUTION TECHNIQUE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "Self (30-foot radius sphere)", chakra_cost: "13 Chakra", components: "HS, NT (Explosive Tools)", duration: "Instant", description: "An advanced version of the Substitution Technique, where in addition to avoiding damage, you leave behind an explosive surprise. When you would take damage, from an attack you may increase your AC by +5 against the triggering attack. Regardless if this would cause the attack to miss or not, you move without provoking attacks of opportunity up to your full movement +10 away. You then leave behind a decoy with an Explosive tool attached to it, which immediately explodes, catching all creatures in a 30- foot radius sphere, centered on your location, before you moved as a result of this jutsu. Each of these creatures must make a Dexterity saving throw. On a failed save, they suffer the effects of the explosive tool you left behind, or half as much on a success. This does spend a use of the explosive tool used. Large Construct, unaligned Armor Class 13 + Your Ninjutsu Ability Modifier Hit Points 76 (8d10 + 32) Speed 45 ft. STR DEX CON INT WIS CHA 18 (+4) 18 (+4) 18 (+4) 1 (-5) 10 (+0) 1 (-5) Condition Immunities Charmed, Chilled, Exhaustion, frightened, stunned, poisoned. Senses Darkvision 30 ft., passive Perception 10 Immutable Form. The Ink Tiger is immune to any Jutsu or effect that would alter its form. Inky Weapons. The Ink Tiger attacks are chakra enhanced. Multiattack. The Ink Tiger can attack twice with their claws. Claw. Melee Weapon Attack: reach 5 ft., one creature. Hit: 3d6 + 4 Slashing damage. A creature who takes damage from this attack must make a Constitution saving throw, gaining 2 ranks of the bleeding condition. Roar (Recharge 5-6). The Ink Tiger as a bonus action, may roar. All creatures of your choice within 20 feet of it must make a Charisma saving throw. On a failed save, they gain 3 ranks of Fear for the duration. At the end of a frightened creatures turn, they remake the Charisma save to end the Fear condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0536e5fa391804f0477c69e8", name: "KAGURA’S MIND EYE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You force open your minds 3rd Eye greatly increasing your perceptive abilities almost 10-fold. This jutsu does not cost chakra to maintain concentration. When this jutsu is cast, for the duration, you gain access to a unique special action called Third Eye Opening. This special action can be gained and used in addition to other special actions you gain and use. This special action counts as a Skill-Action and both a Constitution and Wisdom based skill. Third Eye Opening. As a Bonus action, you open your metaphorical third eye gaining 120ft of Chakra sight and Chakra Sensing. While gaining the benefit of these senses as a result of this jutsu, you gain the following benefits; You can identify if a creature, object or structure has been affected by a jutsu within the last 24 hours, gain advantage on checks made to see if a creature is lying, and can see the echoes of chakra usage within the past 24 hours, while also being able to identify creatures and jutsu based on these echo’s if you have sensed them before. These echoes can be used to help track creatures exclusively by their chakra alone.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the range of Third Eye Opening’s special senses to 1-Mile and the duration of this jutsu becomes Concentration, up to 10 minutes. If this jutsu is cast at S-Rank, it no longer requires concentration.", created_at: NOW, updated_at: NOW },
  { _id: "c1244ed315aa0990ad2a8387", name: "LIFE TRANSFERENCE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You sacrifice some of your health to mend other creatures’ injuries. Roll any number of d8s up to 6d8, you take that much in Necrotic Damage which can’t be Reduced or Resisted or be made Immune to in any way, and one creature you can reach regains a number of Hit Points equal to twice the Necrotic Damage you take.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the maximum number of d8s you can roll by 2. 31", created_at: NOW, updated_at: NOW },
  { _id: "f40f0860eb958b1b9e038455", name: "LION MANE: HUNTING PREDATOR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You activate the roots of your hair causing your hair to grow at a heightened rate and granting you full control over your hairs movements. For the duration of this jutsu you gain additional actions which you can take using your hair. For this jutsu’s duration, when you would cast Needle Jizo, you may reduce Needle Jizo’s Cost by -5 or Lion Mane: Needle Hell, reducing its cost by -10. (Both Jutsu to a minimum of 1) 1 Action. • Attack: You command your hair to lash out attacking a creature you can see within 90 feet of you. Make a melee ninjutsu attack. On a success you deal 3d10 piercing and 3d10 bludgeoning damage as your hair sharpens and slams into them. • Wrap: You command your hair to lash out grabbing a creature you can see within 90 feet of you. Make a melee ninjutsu attack. On a success, you grapple and restrain them. A grappled creature makes a Strength (Athletics) or Dexterity (Acrobatics) check vs your Ninjutsu save DC to escape. On a failed check, they remain grappled and restrained by your hair. You can then move the grappled creature anywhere within 90 feet of you as if you were dragging them. • Crush and Tear: You command your hair to crush and tear into a creature currently grappled by it. A creature grappled by your hair takes 12d6 slashing damage as it attempts to tear them apart. A grappled creature immediately gets to attempt their checks to escape after taking damage as a result of this action.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1714c068ad88470a078ad189", name: "ACIDIC BLADE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "11 Chakra", components: "HS, CM, W (Any)", duration: "Concentration, up to 1 minute", description: "You draw out acidic chakra and coat it over a weapon you can reach. When you do, for the duration, twice per turn when a successful attack is made with the weapon, it deals an additional 2d8 acid damage. You cannot lose concentration of this jutsu as a result of damage. Once per turn, creatures who take acid damage as a result of this jutsu, make a Constitution saving throw. On a failed save, they gain 1 rank of the Corroded Condition.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at S-Rank, increase the damage this jutsu deals by 1d8. MEDICAL RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "449926d3d3e404bfed56824e", name: "BLOOD ROT CURSE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra, X Hit die. (You decide)", components: "CM, CS", duration: "Instant", description: "You weave necrotic chakra into a special wavelength, invisible to even creatures with Chakra sight. When you cast this jutsu roll all spent hit die. Recording the result. You touch a creature who’s hit points are not full and bestow a curse. The cursed target must make a Charisma saving throw. You can attempt to bestow the curse in a concealed manner not revealing your intentions by making a Stealth check vs the targets passive insight. On a success, the target is unaware of the curse you placed on them. The curse takes effect immediately, for a number of days, equal to half result of your spent hit die, the target cannot regain hit points except as a result of long and full rests, if and when they would take Acid, Poison or Necrotic damage, they take 2d4 additional damage of that same type. Additionally, if a creature is poisoned or envenomed, they make whatever skill checks, or saving throws to remove the chosen condition at disadvantage. Finally, this jutsu’s effect can only be removed by a Ninjutsu with the Fuinjutsu keyword of B-Rank or higher that dispels jutsu based effects. MEDICAL RELEASE: BODY PATHWAY", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a5f97979d3adf54cd80061e6", name: "BODY PATHWAY DERANGEMENT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "HS, CM, M", duration: "Up to 1 minute", description: "You coat your fingertips in chakra and attempt to strike an opponent at the nape of their neck sending a surge of chakra through their central nervous system mixing up signals from their brain to the rest of their bodies. Make a Melee Ninjutsu Attack. On a hit, the target creature must make a Constitution saving throw. On a failed save, the target creature's speed is halved, it takes a -2 Penalty to AC, automatically fails Dexterity saving throws and cannot use reactions. On its turn, it can either use an action or bonus action, not both. Regardless of the creature's abilities or jutsu descriptions, it can’t make more than one attack during its turn. If the creature wants to use an action to make an ability save to end this effect, they must instead roll an Intelligence save. 32 MEDICAL RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "05937b9287668951fe60158c", name: "CONTAGION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "HS, CM", duration: "1 Week", description: "You infuse putrefied Medical Chakra onto your hand as you become able to inflict disease from touch alone. Make a Melee ninjutsu attack against a creature within your reach. On a hit the target is poisoned. At the end of each of the poisoned creatures turns, the target must make a Constitution saving throw. If the target succeeds on three of these saves, it is no longer poisoned and the jutsu ends. If the targets fails three of these saves, the target is no longer poisoned, but choose one of the diseases below. The target is subjected to the chosen disease for the Jutsu’s duration. Since this jutsu induces a natural disease in its target, any effect that removes a disease or otherwise ameliorates a diseases effects apply to it. • Blinding Sickness. Pain grips the creature’s mind, and its eyes turn milky white. The creature has disadvantage on Wisdom checks and Wisdom saving throws and is blinded. • Filth Fever. A raging fever sweeps through the creature’s body. The creature has disadvantage on Strength checks, Strength saving throws, and attack rolls that use Strength. • Flesh Rot. The creature’s flesh decays. The creature has disadvantage on Charisma checks and vulnerability to all damage. • Mindfire. The creature’s mind becomes feverish. The creature has disadvantage on Intelligence checks and Intelligence saving throws, and the creature becomes Berserked for the duration. • Seizure. The creature is overcome with shaking. The creature has disadvantage on Dexterity checks, Dexterity saving throws, and attack rolls that use Dexterity. • Slimy Doom. The creature begins to bleed uncontrollably. The creature has disadvantage on Constitution checks and Constitution saving throws. In addition, whenever the creature takes damage, it is stunned until the end of its next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b87b490075743ce24299a2d4", name: "DEAD HEARTBEAT TECHNIQUE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Day", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Special", description: "When casting this jutsu, you must have fully intact corpse of a humanoid creature. You perform a type of surgery designed to induce a false heartbeat. At the conclusion of this jutsu’s casting, the corpse begins to move at your behest. You must stay within 90 feet of the corpse while facilitating its temporary revival. All wounds, and damage the corpse had prior to this jutsu’s casting remains. The corpse you use this on only retains their memories. They can regain their personalities if you instead extend this jutsu's casting time to 1 Week. The corpse cannot disobey you, and must not act in any way that would bring you harm. The corpse has 1 Hit points and calculates its AC as normal. It cannot cast jutsu, or use features by any means. The corpse remains active until you dismiss this jutsu as a bonus action or begin concentrating on any other jutsu or feature. A corpse can only be temporarily be brought back this way once ever using this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0b58c41e86ccbe9049f630a5", name: "DEATH WARD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Until it triggers.", description: "You draw your chakra seal onto a talesman or scroll and place it onto a creature granting it a measure of protection from death. The first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the jutsu ends. If the jutsu is still in effect when the target is subjected to a hostile effect that would kill it instantly without dealing damage (Except Exhaustion), that effect is instead negated against the target, and the jutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "50dacf33b1753139b7fa85e7", name: "GRIM CALLING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self (30 feet)", chakra_cost: "14 Chakra, 2 Hit Die", components: "HS, CM, CS", duration: "Instant", description: "You weave summoning seals together and infuse them with medical release chakra manifesting the head of the Reaper of death. His fangs bite into you and draw out a fragment of your spirit turning it into a temporary source of necrotic power. It screeches a spectral wail that penetrates to the souls of most creatures, calling and pulling on their spiritual selves. All creatures within range must make a Charisma saving throw. On a failed save, creatures take 6d8 necrotic damage and depending on the classification of the affected creature, alternative effects take place. If the target is classified as a player character, it loses 1d6 of its hits die. If a creature affected by this jutsu has 0 Hit die, they take additional necrotic damage equal to your level on a failure. If the target is classified as an Adversary, it loses 2 Tenacity die. If the affected Adversary has 0 Tenacity die, they take additional necrotic damage equal to your level on a failure.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 chakra. If this jutsu is cast at S-Rank, you spend 1 additional hit die and increase the damage by 2d8, and the number of hit die lost to 1d8 or the number of Tenacity die lost to 4.", created_at: NOW, updated_at: NOW },
  { _id: "f1d7ccd34e3b93c0a015cd5c", name: "INVESTITURE OF ACID", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You draw out acidic chakra and infuse it into yourself, coating your entire body like armor. The acid does not harm you. You cannot lose concentration on this jutsu as a result of damage. For the duration, you gain the following benefits; • You are immune to Acid, Poison, and Cold Damage. • You have resistance to Bludgeoning, Piercing and Slashing damage from weapons and Bukijutsu that use weapons as a component. • You have vulnerability to Earth and Fire damage. • You can move across difficult terrain on solid ground without spending any extra movement, as you melt the obstructions in your path. • The ground in a 10-foot radius around you is covered in acid, counts as difficult terrain for creatures other than you, and moves with you. • You can use your action to blast a 15-foot cone of acid from you in a direction you choose. Each creature in the cone must make a Constitution saving throw. A creature takes 4d8 Acid damage and gains 1 rank of the corroded condition on a failed save or half as much and no further effects on a successful one. MEDICAL RELEASE: RECONSTRUCTIVE", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6e4aedf5c1997c578c434a7a", name: "RECONSTRUCTIVE HAND", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You coat your hand in cell manipulating Medical chakra. You can attempt to manipulate the cellular integrity of a creatures cells. As an action on your turn, you can touch a willing creature you can reach. When you do, you can jumpstart their cellular regenerative process. The creature regains hit points equal to 3d8 + Your ninjutsu ability Modifier. Afterwards, for the next minute, the creature regains 5 hit points at the beginning of each of their turns. Alternatively, as an action you can attempt to touch a hostile creature you can reach. Make a melee ninjutsu attack. On a successful hit, they take 5d10 Necrotic Damage and become compromised. A compromised creature must make a Constitution saving throw at the beginning of each of their turns for the next minute. Any jutsu or affect that would remove conditions can end the compromised condition on a creature. A compromised creature who succeeds three saving throws first, ends this condition. A compromised creature who fails three saving throws first, has their cells begin to fail and rupture. They permanently gain two ranks of Exhaustion and the Weakened, and Dazed conditions. A creature who gains these conditions this way can have them removed only be a casting of; Restorative at A-Rank, Regenerate, Medical Aura and remain within the Aura for no less than 1 week straight, Medical Release: Heal or Reconstructive Hand on them no less than 3 times in an 8-hour period.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c41b1d2d865dcb3405f0eded", name: "REVIVAL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You send a surge of healing chakra through a creature that has been dead for no more than 1 minute that didn’t die of old age, isn’t undead, and not missing its head. You make a Medicine skill Check vs DC (20 + 1 for every round the target has been dead.) The target returns to life with 1 Hit Point. Missing body parts are not returned. Internal organs are healed and regenerated. This jutsu cures all normal diseases affecting the creature when it dies. This jutsu does not remove ranks of Exhaustion a creature has accumulated prior to death. Once a creature has been revived in this way, they cannot be revived again in the same way for 30 days, as their body simply cannot handle the strain of being forced back from the dead in such a fashion.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d52305af3a3da12a9d43c165", name: "SPORES OF RUIN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate poisonous medical chakra and release it, creating a massive wave of infectious spores of your design. All creatures of your choice within range must make a Constitution saving throw. On a failed save creatures take 5d8 poison damage, becomes poisoned, and gains 1 rank of envenomed. On a successful save creatures take half damage and suffer no further effect. Additionally, creatures who failed their save begin to exhibit bouts of a terrifying disease of your making. Black fungus begins to grow from their skin. Black ooze begins to leak from their eyes, mouth and ears. Creatures who would touch the affected creature also becomes exposed to this disease making a Constitution saving throw, suffering the effects of this jutsu as normal. At the beginning and end of an envenomed creatures turn they suffer the effects of the envenomed condition. Finally, a jutsu with the medical keyword that removes conditions of B-Rank or higher can end this effect. If the caster must touch or be in contact with the patient to cast the jutsu, then the caster must make a saving throw as they become exposed to the effects of this jutsu as well.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "b19abbbb4986bf33c2c881f9", name: "STRENGTH OF 100", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "14 Chakra", components: "CM", duration: "Concentration, Up to 1 Minute", description: "You use finely controlled chakra across your body, granting you Strength of over 100 people. Your Strength becomes 20 for the Duration. Your jump height and distance are doubled. You gain Advantage on Strength & Constitution based ability checks, skill checks, and saves. When you make an unarmed attack, you deal 3d10 Bludgeoning damage. After you end this jutsu, you suffer the consequences of pushing your body to its limit. Your movement speed is halved, you gain disadvantage on Strength & Constitution ability and skill checks. These lasts until you take a short rest.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "ad5813d1674d9ab9c551a573", name: "VENOM SHOWER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "10 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to generate poisonous medical chakra and release it, creating a rain of poisonous needles. Select a space in the air that you can see. You create a poisonous gas cloud that begins to rain down poisonous needles filling a 20-foot radius, 50-foot-high cylinder. Each creature in the cylinder must make a Dexterity saving throw. A creature takes 6d6 poison damage on a failed save and half as much on a successful save. The ground this area affects generates poisonous thorns on the ground that lasts for 1 minute. Creatures who that enter the area of poisonous thorns takes 4d4 poison damage for each 5 feet they move through the affected area. Once a space has been moved through, the thorns break becoming inert.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "00049a976bb96acd0097267e", name: "VITRIOLIC SPHERE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "150 feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Instant", description: "You point at a place within range, and conjure a glowing 1-foot ball of bubbling acid that streaks to the chosen location and explodes in a 15-foot radius sphere. Each creature in that area must make a Dexterity saving throw taking 10d4 Acid damage and 5d4 Acid damage at the end of its next turn and gains 1 rank of corrosion. On a successful save, a creature takes half the initial damage and suffer no further effects.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the initial damage by 2d4 and the lingering damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "7c72d1ec2c794a38633d5169", name: "WATER TO ACID", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You draw out acidic chakra and infuse it into a body of water that you can see. You convert a 15- foot cubes worth of water, into pure acid for the duration. Jutsu with the Water release keyword that would require a source of water, cannot use this pool of acid. If you would convert a pool of water into acid and there is water outside of this jutsu’s area of effect, then creatures can still use water release ninjutsu that requires sources of water. Any creature that is in contact with the water when it turns to acid such as stand on top of it with the water walking technique immediately sinks down into it. Creatures who would begin their turn submerged in the acid takes 7d4 acid damage and must make a Constitution saving throw, being blinded and gaining the corroded condition on a failed save. When this jutsu would end, the acid turns back into normal water.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the size of the acid conversion doubles. (15>30>60)", created_at: NOW, updated_at: NOW },
  { _id: "a2b7b6d8c88e38c037464e37", name: "NON-DETECTION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "CM", duration: "Concentration, up to 8 hours.", description: "For the duration, you suppress a creatures chakra which lowers their presence and hides them from all manner of sensory jutsu. The target can be a willing creature or an object. The target can’t be sensed or seen by the Chakra Sight or Chakra Sensing special sense as a result of jutsu cast at an equal rank or lower. If a creature would gain either of these senses as a result of a feature or trait, this jutsu only works on creatures who is of a level equal or lower than the casters.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, this jutsu can now affect structures and small locations no larger than 30 feet by 30 feet. If this jutsu is cast at S-Rank, it can affect locations no larger than 100 feet by 100 feet.", created_at: NOW, updated_at: NOW },
  { _id: "b8b73851b4b184d3eb03df70", name: "BANISHING SEAL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You infuse chakra into a chakra seal as you attempt to send them away with the seal of banishment. Choose one creature you can see within range as you force them to make a Charisma saving throw or be sent to a pocket dimension of your creation. On a failed save they are banished to this pocket dimension. While banished, they are incapacitated and are unaware of any actions or happenings in the dimension they were just banished from. When this jutsu ends, they are summoned back into the same space they were originally banished from and gain 2 ranks of Sealed.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "a5f5a1c67163c658a83c4313", name: "CIRCLE OF AUTHORITY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "13 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 Minute", description: "You infuse chakra into a chakra seal as you attempt to mark yourself with the seal of domination. You then exude a 30-foot radius sphere of authority that other creatures must abide by. This radius follows you. For this jutsu’s duration, anytime a hostile creature in this jutsu’s radius would make a saving throw against a jutsu you or an allied creature cast, they immediately take a -2 Penalty to their roll.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "ded468a398e1836e3e16b467", name: "COMMUNE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "HS, CM, CS", duration: "1 Minute", description: "You infuse chakra into a chakra seal as you attempt to mark yourself with the seal of relation. You reach out into the void. Calling upon the spirit of a single deceased spirit, with whom you have a connection with, be it ancestral, legacy, ideals, historical, or antagonistic. The DM allow other forms of relation as well. You summon the spirit to the material plane and ask it three questions that can be answered with a yes or no. You must ask your questions before the jutsu ends. You the most correct answer possible from to the spirits knowledge. The spirit is not omniscient, so you may receive unclear or uncertain answers, if a question lies beyond the spirits knowledge. In a case where a one-word answer could be misleading or contrary to the spirits interests, the DM may offer a short phrase as an answer instead. A spirit cannot be summoned this way more than once per month.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bd9344f728bfe33e0e147b22", name: "CURSE OF THE PREY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You attempt to impose the qualities of a single weak bestial creature. Select one creature within your reach. The target must make a Charisma saving throw. On a failed save, they gain one of the following bestial qualities. Swallows Endurance: The creatures bones begin to feel hollow and brittle as their heart begins to beat furiously as their blood begins to thin. For the duration, they have a -3 penalty on all Constitution saving throws, skill checks and ability checks. Additionally, they cannot take the Dash Action and cannot gain additional speed by any means. Mites Strength: The creatures muscles begin to grow weak and unable to carry weight. They gain a -4 Penalty to their Strength ability score and disadvantage on Strength saving throws and attacks made with Strength. Sloth’s Grace: The creatures reflexes are shot as they become unable to move gracefully or even carry themselves correctly. They gain a -4 penalty to their Dexterity ability score and disadvantage on Dexterity saving throws and ability checks. They also take double damage from falling, and they spend their full movement trying to stand from Prone. Rhinoceros Splendor: The creatures vision, auditory perception and sense of smell becomes dull and weak as they gain a -4 Penalty to their Wisdom ability score and disadvantage on Wisdom ability checks. Their visual range is cut in half and they cannot hear things more than 30 feet away from them. Turkey’s Cunning: The creatures ability to think through complex matters and concepts becomes muddled. They find it hard to remember simple handsigns, colors and even their left from their right. They gain a -4 Penalty to their intelligence ability score and disadvantage on intelligence saving throws and ability checks. They cannot concentrate on more than 1 Jutsu, and the Base Concentration check DC becomes 17. Turtles Hubris: The creatures ability to exert is fore of will is hindered. They gain a -3 penalty on all charisma saving throws, skill checks and ability checks. Additionally, their Deception, Intimidation and Persuasion bonuses are reduced to 0. 36 SEALING ART:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c157fed047019a79cb056b1b", name: "DIMENSIONAL POCKET", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Month", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Permanent", description: "You infuse chakra into a chakra seal as you attempt to tear open a rift in the fabric of reality, marking out a small space in the void for yourself with the seal of distortion. As a part of the casting of this jutsu, you must mark a representative space no larger than a 20-foot cube with chakra seals, doing this dictates the exact size of your pocket dimension. If this jutsu casting time is interrupted, the jutsu ends and you must restart the process from scratch. After successfully casting this jutsu, you create a room in the void, unable to accessed without jutsu that can traverse through dimensions or teleport ignoring space all together. This room is one of your design and can look however you describe it. While inside this dimension, you are no longer on the material plane. You are unaware of what’s going on, on the material plane. You cannot communicate with or locate people on the material plane. If you exit your room, stepping into the void, you are instantly shunted to a random location on the material plane. This can be anywhere from another country, to the bottom of the ocean, or even 10,000 feet in the sky. This room produces no sound and cannot be found by normal means. You can freely access your room, by spending 10 minutes weaving handseals and materializing a gate which takes you directly to this room. The room has 4 walls, and can only ever be 1 floor. It has a single door, which cannot be locked by normal means, which leads to a short bridge feeding into a chakra gate which takes you back to the material plane from the exact location you entered to your room from originally.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ee29d2586d53641263448012", name: "DISPLACEMENT SEALING TRAP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Minute", range: "10 feet", chakra_cost: "14 Chakra", components: "HS, CS", duration: "Instant", description: "You draw a circle up to a 10-foot diameter circle on the ground inscribed with shinobi sigils that link your location to another location of which you’ve been too or know its exact coordinates. Only you or a trigger you set can trigger this sealing circle. Once activated all creatures in the circle are immediately teleported to the exact location within 10 feet of its exact coordinates.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "360ae44100dc5652bb2b4645", name: "DIVINATION TECHNIQUE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You infuse chakra into a chakra seal as you attempt to peer through the fabric of time, diving future events with the seal of perception. You must ask a single question concerning a specific goal, event or activity to occur within 7 days. The DM offers as truthful a reply as possible. The reply might be a short phrase, a cryptic rhyme or an omen. You hear the aforementioned in your own voice as if you are speaking to a future version of yourself. This jutsu doesn’t take into account any possible circumstances that might change the outcome, such as the casting of certain jutsu, or the loss or gain of a companion. You cannot peer into the future this way more than once per week.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "33cc24d23e7220d5c1926d03", name: "GIFT OF THE APEX", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute.", description: "You begin to gain qualities of a single bestial creature. Granting you chakra projections that enhance your physical traits. Select one of the following beasts to gain traits from. Bears Endurance: You gain a +4 Bonus to your Constitution ability score and advantage on Constitution saving throws. Bull’s Strength: You gain a +4 Bonus to your Strength ability score and advantage on Strength saving throws. You grow horns made of chakra. As an action you can attempt to gore an enemy. Make a melee attack against a creature within 5 feet of you dealing 2d12 + Strength piercing damage and knocking them prone. Cat’s Grace: You gain a +4 Bonus to your Dexterity ability score and advantage on Dexterity saving throws. You grow cat like claws and can make melee attacks using Dexterity instead of Strength for attack and damage rolls. You gain natural weapon claw attacks that deals 2d8 + Dexterity slashing damage. You can make two attacks using this natural weapon. Eagle’s Splendor: You gain a +4 Bonus to your Wisdom ability score and advantage on Wisdom saving throws. Fox’s Cunning: You gain a +4 Bonus to your intelligence ability score and advantage on intelligence saving throws. You can concentrate on up to 3 Jutsu at once. Lions Presence: You gain a +4 Bonus to your Charisma ability score and advantage on charisma saving throws. You cannot gain ranks of Charm, Demoralized or Berserk.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fde5bb1156f9b8dcbec17f5a", name: "WARDING SEAL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Instant", description: "When you cast this jutsu, you inscribe a harmful seal either on a surface (such as a section of floor, a wall, or a table) or within an object that can be closed to conceal the seal (such as a book, a scroll, or a treasure chest). If you choose a surface, the seal can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; if the object is moved more than 10 feet from where you cast this jutsu, the seal is broken and this jutsu ends without being triggered. The seal is nearly invisible, requiring an Investigation or Ninshou check vs your ninjutsu save DC to find it. You decide what triggers the seal when you cast the jutsu. For seals inscribed on a surface, the most typical triggers include touching or stepping on the seal, removing another object covering it, approaching within a certain distance of it, or manipulating the object that holds it. A creature cannot trigger more than one Warding Seal or Seal of Discord per turn. You can further refine the trigger so the jutsu is activated only under certain circumstances or according to a creature’s physical characteristics (such as height or weight). You can also specify creatures that don’t trigger the seal, such as those who say a certain password. When you inscribe the seal, you can store a Ninjutsu or Genjutsu of B-Rank or lower in the seal by casting it as part of creating the seal. The jutsu must target a single creature or an area. The jutsu being stored has no immediate effect when cast in this way. When the seal is triggered, the stored jutsu is cast. If the jutsu has a target, it targets the creature that triggered the seal. If the jutsu affects an area, the area is centered on that creature. If the jutsu summons hostile creatures or creates harmful objects or traps, they appear as close as possible to the intrude and attack it. If the jutsu requires concentration, it lasts until the end of its full duration.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the rank of a Sealed Jutsu by 1. (B>A>S)", created_at: NOW, updated_at: NOW },
  { _id: "bd0a1e63fe2f47005ba26424", name: "SUMMONING: RASHOMON", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Reaction, which you take when you or an allied creature would take damage or make a saving throw.", range: "30 Feet", chakra_cost: "12 Chakra", components: "HS, CS", duration: "Instant", description: "You bite your finger drawing blood before using it as a catalyst to summon Rashomon, a 60 feet tall, 30 feet wide, and 5 feet thick gate made of iron, brick, chakra and other materials. This wall is erected standing straight upward. If you are in an area that cannot fit Rashomon, this jutsu will fail. Rashomon has 100 Hit Points. The Rashomon unsummons itself after 1 minute, or if this Jutsu is cast again, whichever comes first. The Rashomon regains all of its Hit Points over the course of a Long Rest. If the Rashomon is summoned before its caster takes a Long Rest, it remains in the same condition it was in when it was unsummoned.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and Rashomon’s Hit points by +25.", created_at: NOW, updated_at: NOW },
  { _id: "6b8ae6561fa8c220e01369ab", name: "THOUSAND-ARMED MURDER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "An Advanced version of the “Arms of Buddha” Ninjutsu. This advanced version keeps the Golden Buddha materialized out of golden chakra. This Buddha stands behind its user with a calm and peaceful face, however whenever the user gets angry or intends to attack, the spirit turns red and grows fangs and its appearance becomes akin to a demon and attacks its users’ enemies with its 1000 hands or protects its user when attacked. As a Bonus action, make a Melee Ninjutsu Attack against a creature you have already made an attack against this turn, no more than 10 feet away. On a hit, the target creature takes 8d8 Bludgeoning Damage. Alternatively, as a Reaction, when you are hit by an attack. Roll 2d12 + Ninjutsu ability modifier, reduce the incoming damage you take by the result.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. Increase the damage by 2d8 and the reaction roll by 2d12.", created_at: NOW, updated_at: NOW },
  { _id: "4653d9d62bf55657873ce997", name: "TOBIRAMA’S PRIVATE SANCTUM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Minute", range: "120 feet", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "24 Hours", description: "You make an area within range secure. This area is a cube that can be as small as 5 feet to as large as 100 feet on each side. This jutsu lasts for the duration, or until you use an action to dismiss it. When you cast this jutsu, you decide what sort of security it provides, choosing no more than 2 of the following; • Sound can’t pass through the barrier at the edge of the warded area. • The barrier of the warded area appears dark and foggy, preventing vision (including Darkvision) through it. • Sensors created by Jutsu with the Sensory Keyword can’t appear inside the protected area or pass through the barrier at its perimeter. • Nothing can teleport into or out of the warded area. • Dimensional travel is blocked within the warded area.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "38631d8e82d85ff09113477c", name: "ANIMATE OBJECTS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minutes", description: "Objects come to life at your command. Choose up to ten objects within range that are not being worn or carried. Tiny targets count as one object, medium targets count as two, large targets count as four, huge targets count as ten. You can’t animate any object larger than Huge. Each target animates and becomes a creature under your control until the jutsu ends or until reduced to 0 hit points. As a bonus action, you can mentally command any creature you made with this jutsu if the creature is within 500 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete. ANIMATED OBJECT STATISTICS An animated object is a construct with AC, hit points, attacks, DR (Damage reduction), and damage determine by its size. Its speed is 30 feet; if the objects lack legs or other appendages it can use for locomotion, it instead has a flying speed of 30 feet and can hover. If the object is securely attached to a surface or larger object, such as a chain bolted to a wall, its speed is 0. It has blindsight with a radius of 30 feet and is blind beyond that distance. When the animated object drops to 0 hit points, it reverts to its original object form, and any remaining damage carries over to its original object form. If you command an object to attack, it can make a single melee attack against a creature within 5 feet of it. It makes a slam attack with an attack bonus and bludgeoning damage determine by its size. The DM might rule that a specific object inflicts slashing or piercing damage based on its form.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3030fe94dbf21ea81577244a", name: "ONI TWINS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, Up to 1 minute", description: "You draw a picture of two Oni, Demons of your description. Infusing chakra into it as it exits your scroll and standing next to you. You summon two construct Ink Oni’s. The Ink Oni’s has the following Statistics using your Ninjutsu attack bonus and Save DC for anything that requires an attack or saving throw; You may command both Ink Oni’s as a bonus action on your turn. Each Ink Oni may be commanded to perform different actions. The Ink Oni’s may take an appropriate bonus actions or reactions if able.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the number of Oni’s you summon by +1.", created_at: NOW, updated_at: NOW },
  { _id: "5b0761be0f77bbae7ad75617", name: "BESTIAL ART: PREDATOR", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "18 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You infuse chakra into a chakra seal as you attempt to mark yourself with the seal of Predation. You cannot reduce the cost of this jutsu by any means. Your eyes become beast like with your iris looking more feline than human. Your muscles grow stronger and leaner, as you encompass a wolves physicality. Your senses grow sharper as you can tell the exact distribution of water in the air if you so choose. For this jutsu’s duration, you gain the following benefits; • Your Strength, Dexterity and Wisdom becomes 19 if it is not already 19 or higher. If a score is 19 or higher already, you instead increase it by +2. • You cannot be seen with Chakra sight. • You gain a bonus to movement speed equal to 10 times your Strength Modifier. • Your jump distance and height are doubled. • Your unarmed damage is now 2d6 + strength + dexterity piercing or slashing damage. • Attacks of Opportunity you make are at advantage. • When you take the attack action, you can make two attacks instead of one, if you cannot already. If you already can, then you instead make one additional unarmed attack", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "414374814b1a2e88b39624bf", name: "CROWN OF STARS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You Create 8 Globes of light, that split into groups of 4 as they circle your wrists or ankles. You can use a Bonus Action to send one of the globes streaking toward one creature or object within 60 Feet of you. When you do, make a ranged Ninjutsu attack. On a hit the target takes 4d12 Force Damage. Whether you hit or miss you spend one globe and it vanishes after use. The Jutsu ends early if you expend the last globe or fall unconscious. If you have 4 or more globes, they shed a bright light in a 30-foot radius and dim light for an additional 30 feet. If you have less than 4, the remaining globes shed dim light in a 30-foot radius.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the motes’ damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "9f86bf3d581e7fe5a90c9c53", name: "EXCELLENT CHAKRA SPEARS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (60-foot cone)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You create eight spears of highly condensed chakra that you then launch simultaneously. All creatures in a 60-foot cone originating from you, must make a Dexterity Saving throw, taking 10d6 damage on a failed save or half as much on a successful one. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. All effects imparted by the different nature releases can only be removed by a Jutsu that removes conditions of B-Rank or higher. • Force: The damage die increases to a d10. • Earth: On a failed save, a creature gains 2 ranks of Bruised. • Wind: On a failed save, a creature gains 2 rank of Lacerated. • Fire: On a failed save, a creature gains 2 ranks of Burned. • Water: On a failed save, a creature gains 2 ranks of chilled. • Lightning: On a failed save, a creature gains 2 ranks of shocked.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "813d5029d3e551ac22558b8f", name: "FISSION TECHNIQUE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "CM", duration: "1 Minute", description: "The Fission Technique is a highly advanced ninjutsu which allows you to split your own body into two identical — yet entirely independent — duplicates of yourself. You cannot reduce the cost of this jutsu by any means. Unlike clone techniques that only appear to be similar, the ability is instead a physical separation and so does not require hand seals to activate, making it faster in comparison as a result. You may make an exact copy of yourself, you cut your current and maximum hit and chakra points in half and your clone gains that much, this clone is an exact copy of yourself being able to use your Class and Clan features & jutsu. If you have an expendable feature such as combo points or superiority die the clone gains half the amount you had when you casted this jutsu. The clone acts at the end of your turn. At the end of this jutsu’s duration you fuse back together, regaining any hit and chakra points the clone had, restoring your maximum hit and chakra points back to normal, and gaining any conditions, poisons or diseases the clone may have had. If the clones body is destroyed, not whole, transformed (such as petrified) or not on the same plane of existence before refusing back together with you, you do not regain any hit or chakra points and your maximum hit and chakra points are permanently cut in half. If you can find your clones body and recast this jutsu while touching it, you refuse with it as normal.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "281baa6989a9b5cb0bcda618", name: "FLYING THUNDER GOD", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "Special", range: "1 mile", chakra_cost: "Special", components: "HS, CM, CS, NT, W", duration: "Special", description: "Using a Chakra Seal you are able to imprint a personally made seal upon any weapon, surface, or object. This process takes 1 hour. Spending this time allows you to mark as many objects, weapons, or surfaces within 30 feet of you. Alternatively, as an action, you may make a ninjutsu attack. On a hit, target creature is marked. Attempting to mark creatures in this way costs 5 chakra regardless if you hit or miss. You can have up to 10 markings active at once. If you make a 11th mark then one of the previous seals vanish. As a Bonus Action on your turn, you are able to spend 5 chakra to teleport yourself and up to one creature within 5 feet of you, up to 1 mile from your current position towards either a Chakra seal made by this jutsu or the Chakra Mark ninjutsu, appearing within 5 feet of your selected seal in a space that can hold you. If you appear within 5 feet of a hostile creature, you have advantage on the next attack roll made against the creature until the end of your next turn. A seal created by this jutsu can only be teleported to up to 5 times before the seal is eroded forcing you to redo the sealing process. Others who have this jutsu, with whom you share this jutsu’s network with, can use your seal to teleport to other marked locations that you made that bear your seal so long as they know the location of the target seal's destination and you have opened your next work to them.", at_higher_ranks: "When you would upcast this jutsu, Beginning at S-Rank; You are able to mark a single object, surface, or a weapon within 5 feet as a bonus action at the cost of 10 chakra. You also multiply your teleportation distance by 10 by increasing the cost to teleport by 10.", created_at: NOW, updated_at: NOW },
  { _id: "0498808fbaa58540e4cf78f7", name: "LION MANE: NEEDLE HELL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you are targeted for an attack or Jutsu.", range: "Self", chakra_cost: "15 Chakra", components: "HS, CM", duration: "1 Round", description: "An advanced version of the “Needle Jizo” Ninjutsu. You create a much thicker and much denser shield of hair that covers your entire body that also shoots your hair like needles outwards in a 360-degree area around you with enough force to tear boulders apart. You gain +4 AC for the duration of this jutsu and all creatures in a 15 Foot-radius sphere centered on you, must make a Dexterity saving throw, taking 8d8 Piercing damage on a failed save, or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d8", created_at: NOW, updated_at: NOW },
  { _id: "d116d6541f8fe763129cb478", name: "AURA OF POWER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Intense chakra lashes out from you and coalesces in a soft radiance of blue light in a 30-foot radius around you. Allied creatures of your choice in the radius when you cast this jutsu have advantage on all saving throws against Ninjutsu. Hostile creatures within this radius have disadvantage on saving throws against Ninjutsu cast from within this jutsu’s radius. Also, when an affected hostile creature hits an affected allied creature with a melee attack, The attacker must make a Strength saving throw or be incapacitated until the end of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "332cc8f4ceb1262df912432c", name: "CASUALTY PUPPET", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Minute", range: "Touch", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "10 Minutes", description: "As a part of the casting of this jutsu, you must have a creature who has been dead no longer than 10 minutes available to you. You place a chakra seal onto the corpses body. When you do you perform a ritual absorbing its memories fully into the seal, then placing the chakra seal on yourself. For this jutsu’s duration, you gain access to all of the memories and Jutsu, that the creature knew. While you have the chakra seal attached to you, you cannot end this jutsu early. Your mind begins to feel hazy and clouded. At the beginning of each of your turns while in combat, or every minute while not in combat. You must make a Charisma saving throw vs a DC (Original Creatures Level + Their Proficiency Bonus). On a failed save, you act as they would until the end of their turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c49c1bf824a729d02e658e36", name: "CORROSIVE PLUME", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You mold acidic chakra into the shape of flower on a point that you can see within range. This flower then begins to grow and bloom at a violent rate. All creatures within 30 feet of the flower when it blooms must make a Dexterity saving throw, taking 12d6 acid damage and gaining 2 ranks of the corroded condition. A creature who fails their saving throw, who has 5 ranks of corroded has vulnerability to acid damage from this jutsu. Armor, weapons and items that are not being held are immediately dissolved if they do not have a seal, or chakra- based effect of A-Rank or higher cast upon it or infused into it. Creatures reduced to 0 hit points as a result of this jutsu are dissolved into a mass of acidic goop, unable to be revived.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5b74d44a49c62a12331318d6", name: "GRIM REALITY", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (20 Chakra), 5 Hit Die", components: "HS, CM, CS", duration: "Concentration, up to 1 Minute", description: "You weave summoning seals together and infuse them with medical release chakra manifesting the cloak, weapon and presence of the Reaper of death. He demands a large payment for you borrowing his power, so he takes it by stripping you of a large portion of your life force. You cannot lose concentration on this jutsu as a result of damage and you cannot end concentration of this jutsu on other creatures turn, instead only being able to end it, at the end of one of your own turns. Additionally, this jutsu cannot be dispelled or interrupted by another creatures jutsu, by any means, except by a jutsu of S-Rank. At the beginning of each of your turns, instead of spending chakra to maintain concentration, you must spend a Hit die. You don the cloak, and blade of the reaper. The Cloak of the reaper grants you an AC equal to your Ninjutsu save DC if your current AC is lower. The blade of the reaper is a construct weapon, in the form of either a tanto or scythe, which you choose when you cast this jutsu. If tanto, the weapon deals 2d6 + Ninjutsu ability modifier necrotic damage, and scores a critical hit on a roll of 18~20. If scythe, the weapon deals 2d8 +Ninjutsu ability modifier necrotic damage, has reach 2, Deadly, and Two-Handed. Regardless of the weapon chosen, as an action, you can make two melee ninjutsu attacks using the construct weapons. Finally, if you would cast another jutsu with the Medical keyword, that has the Grim pre-fix, you can spend 1 Chakra die in place of hit dice as a part of their cost, additionally, if you would force a creature to lose hit dice or Tenacity die, you regain one hit die for each creature who lost hit dice or tenacity die.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "294261a239fdbe017707e0b8", name: "HEALING WAVE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "30 Feet radius sphere", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You clasp your hands releasing a shockwave of healing energy in a 30-foot radius sphere centering on you. You heal up to 8 creatures a total of 200 hit points being split evenly between them while also gaining advantage on saving throws and resistance to the next instance of damage they take, until the end of your next turn. If you would target less than 3 creatures with this jutsu, they can only recover up to 40 hit points each this way.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "00f12a5b0eb46a9ab746daad", name: "NEGATIVE EMOTION SENSING", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "100 feet", chakra_cost: "16 Chakra", components: "HS, CM", duration: "Concentration, up to 1 hour.", description: "You are able to knead chakra in such a way that you can begin to sense other creatures chakra signatures clearly when you try. You can only cast this jutsu on your turn, and casting it does not cost action economy. When this jutsu is cast, for the duration, you gain access to a unique special action called Sense Chakra. This special action can be gained and used in addition to other special actions you gain and use. This special action counts as a Skill-Action and both a Constitution and Wisdom based skill. Sense Chakra. As a Bonus action, you can make a Perception check using either Constitution or Wisdom vs the Passive Chakra control (Chakra control bonus + 10) of all creatures within 30 feet of you. On a success, you gain the benefit of the Chakra Sensing special sense against them for the duration until they either have 0 chakra or they make and succeed their Suppress Chakra skill action.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f6c8ffac3d4fca3bc5494134", name: "REGENERATE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "18 Chakra", components: "HS, CM", duration: "1 hour", description: "You touch a creature and stimulate its natural healing ability. The target regains 4d8+15 hit points. For the duration of the jutsu, the target regains 1 hit point at the start of each of its turns (10 hit points per minute). The targets severed body members (fingers, legs, tails, and so on), if any, are restored after 2 minutes. If you have the severed part and hold it to the stump, the jutsu instantly causes the limb to knit to the stump.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cf4d2c3a7e4f462073b19886", name: "SCORPIONS STING", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "17 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You mold poisonous chakra into the shape of a scorpion stinger dripping with poison, and fully under your control. The tail has a reach of 15 feet and scores a critical hit on a roll of 19~20. For the duration, as an action you can make two melee ninjutsu attacks, dealing 4d8 + your ninjutsu ability modifier poison damage on a hit. Once per turn, a creature who takes damage from this jutsu must make a Constitution saving throw, gaining 2 ranks of envenomed on a failed save. A creature you target, who has 5 ranks of envenomed has vulnerability to poison damage from this jutsu’s attacks for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "15518dbfa14861e1b695cf65", name: "WILT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (45-Foot cube)", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You infuse necrotic chakra into a surge of medical chakra, designed to suck the life from a target creature. You draw the life force of all creatures of your choice within range, that you can see. Each creature in the area must make a Constitution Saving throw. Construct and undead aren’t affected. Plants, Celestials, and Demons make this saving throw at disadvantage. A creature takes 10d8 Necrotic Damage and are marked with the seal of extraction for the next minute, or half as much damage and no additional effects on a successful save. A creature marked with the seal of extraction takes 5 additional Necrotic damage each time they would take damage from any source for the duration. Plants, Celestials, and Demons instead take 10 additional Necrotic damage each time they would take damage from any source for the duration. A creature marked with the seal of extraction can as an action attempt to remove the seal by making an Intelligence (Ninshou) check vs your Ninjutsu save DC, removing it early on a success. Plants, Celestials, and Demons make this skill check at disadvantage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2e4c2ceb49e2861f38003b08", name: "REVERSE SEAL SUMMONING", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You mark up to 6 willing Creatures with a chakra seal, marking them with your personal seal formation. With this seal, you can, as a bonus action, teleport creatures marked with your seal, to you, from up to 1 mile away. You may also Inversely teleport to them, as a bonus action, from up to 300 Feet away, occupying a space within 5 feet of them that can hold you. Creatures marked can resist being summoned causing this jutsu to fail, if they resist you do not spend chakra.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and multiply the range by 10.", created_at: NOW, updated_at: NOW },
  { _id: "fdf5d018033dd18d106f50c9", name: "FORCECAGE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "100 feet", chakra_cost: "19 Chakra", components: "HS, CM, CS", duration: "1 hour", description: "You impart a scroll with your chakra seal, which conjures an immobile, glowing blue, cube shaped prison composed of chakra, springs into existence around an area you choose within range. The prison can be a cage or a solid box as you choose. 43 A prison in the shape of a cage can be up to 20 feet on a side. A prison in the shape of a box can be up to 10 feet on a side, creating a solid barrier of chakra that prevents any matter from passing through it and blocking any jutsu cast into or out of the area. Both the cage and box shaped barriers have 200 Hit Points. When you can the jutsu, any creature that is completely inside this Jutsu’s area is trapped. Creatures only partially within the area, or those too large to fit inside the area, are pushed away from the center of the area until they are completely outside the area. A creature inside the Forcecage can’t leave it by non- teleportation means. If the creature tries to use teleportation to leave the Forcecage, it must first make a Charisma saving throw, on a success the creature can use that jutsu or feature to exit the Forceage. On a failure the creature can’t exit the Forcecage and wastes the use of the jutsu or effect.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e63f4247ffcf3c7e9e6b4266", name: "SEAL OF DISCORD", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "10 Minutes", range: "Touch", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Until dispelled or triggered.", description: "When you cast this jutsu, you inscribe a harmful seal either on a surface (such as a section of floor, a wall, or a table) or within an object that can be closed to conceal the seal (such as a book, a scroll, or a treasure chest). If you choose a surface, the seal can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; If the object is moved more than 10 feet from where you cast this jutsu, the seal is broken and this jutsu ends without being triggered. The seal is nearly invisible requiring an Intelligence (Investigation) or (Ninshou) check vs your ninjutsu save DC to find it. You decide what triggers the seal when you cast the jutsu such as touching or stepping on the seal, removing another object covering it, approaching within a certain distance of it or manipulating the object that holds it. You can further refine the trigger so the seal is activated only under certain circumstances or according to a creature’s physical characteristics (such as height or weight). You can also specify creatures that don’t trigger the seal, such as those who say a certain password. A creature cannot trigger more than one Warding Seal or Seal of Discord per turn. When you inscribe the seal, choose one of the options below for its effect. Once triggered, the seal glows, filling a 30-foot radius sphere with dim light for 10 minutes, after which time the jutsu ends. Each creature in the sphere when the seal activates is targeted by its effect, as is a creature that enters the sphere for the first time or ends its turn there. Death. Each creature makes a Charisma saving throw, taking 10d10 necrotic damage on a failed save or half as much on a successful one. Hopelessness. Each target must make a charisma saving throw. On a failed save, the target is overwhelmed with despair for 1 minute. During this time, it can’t attack or target any creature with harmful abilities, jutsu or attacks. Stunning. Each target must make a Charisma saving throw and becomes stunned for 1 minute on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6d38121da1ca2656ab7242f6", name: "SHINING STARS, SOARING STRIKE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "The next time you hit a creature with a melee or ranged weapon or unarmed attack before this jutsu ends, you inject chakra into your enemy’s muscles attempting to restrict their movements. The target must make a Strength saving throw or be restrained until the end of their next turn. A large or larger creature has advantage on the saving throw. While restrained by this jutsu, the target takes 1d8 poison damage at the start of each of its turns.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the number of star shaped objects made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "1e439c080bc436dd19448afa", name: "TETHERED ESSENCE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "1 Hour", description: "You infuse chakra into a chakra seal as you attempt to mark two creatures (excluding yourself) with the seal of mirrors. Select two creature you can see within range. Each creature must make a Charisma Saving throw. They make this save at disadvantage if they are within 30 feet of each other. Either creature can willingly fail the save. If either creature saves, the jutsu has no effect. If both saves fail, the creatures are linked for the duration, regardless of the distance between them. When damage is dealt to one of them, the same damage is dealt to the other one. If hit points are restored to one of them, the same number of hit points are restored to the other one. If either of the tethered creatures is reduced to 0 hit points, the jutsu ends on both. If the jutsu ends on one creature, it ends on both.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "85d2d210d8002040897b27c5", name: "TOBIRAMA’S SWORD", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "17 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a sword-shaped place of spacial distortion that hovers within range. It lasts for the duration. When the sword appears, you make a melee ninjutsu attack against a target of your choice within 5 feet of the sword. On a hit, the target takes 5d10 force damage and gains 1 rank of Sealed. Until the jutsu ends, you can use a bonus action on each of your turns to move the sword up to 60 feet to a spot you can see and repeat this attack against the same target or a different one. If this jutsu scores a critical hit, the target instead gains 5 ranks of Sealed.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the amount of attacks the sword can make by 1 per round.", created_at: NOW, updated_at: NOW },
  { _id: "29f2dc24ae64ceeab3b76f32", name: "TOUCH OF DEATH", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "20 Chakra", components: "CM", duration: "Instant", description: "You come close and begin to touch a willing creature you can reach. This touch can be in the form of a grab, kiss, or hug. When you do, you immediately become aware of all nature affinities the creature has if any. The target creature loses 10d6 Hit Points and you recover the same amount. If the creature has any Temporary Hit Points, they lose them and you gain the same amount. Temporary Hit Points you gain as a result of this Jutsu last for a minute before disappearing. If you attempt to cast this jutsu on an unwilling creature, you make a melee Ninjutsu Attack. On a hit, this Jutsu’s effects trigger as normal. Additionally, if you reduce a creatures Hit Points to 0 as a result of this jutsu, you are temporarily able to steal their nature release from them, if they have any. Until you complete a Long Rest, you randomly gain one of the target creature’s’ nature releases and one random Jutsu of C-Rank or lower, that requires that nature release that they knew. You cannot learn additional Jutsu of the stolen nature release unless you already have the chosen nature affinity. If you would gain another nature release as a result of this jutsu, you instead replace the previous nature release and jutsu known.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "409fe8b635302969d202f3f8", name: "CHAKRA DISTORTION FIELD", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (10 foot-Radius sphere)", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "A 10-foot radius invisible sphere of chakra distortion. This area is divorced from chakra that makes up the world. Within the sphere, Ninjutsu or Genjutsu can’t be cast, and chakra items become mundane. Until the jutsu ends, the sphere moves with you, centered on you. Jutsu and other chakra-based effects except those created by an S-Ranked Artifact or Class Mods are suppressed in the sphere and can’t protrude into it. Chakra spent to cast a suppressed jutsu is lost. While an effect is suppressed, it doesn’t function, but the time it spends suppressed counts against its duration. Targeted Effects. Jutsu and other chakra effects such as Flame bolt or Doubled Pain, that target a creature or an object in the sphere have no effect on that target. Areas of Chakra. The area of another jutsu or chakra effect such as Fireball, can’t extend into the sphere. If the sphere overlaps an area of chakra, the part of the area that is covered by the sphere is suppressed. For example, the winds created by Wall of wind are suppressed within the sphere, creating a gap in the wall if the overlap is large enough. Jutsu. Any active jutsu or other chakra effect on a creature or an object in the sphere is suppressed while the creature or object is in it. Chakra items. The properties and abilities of chakra items are suppressed in the sphere. For example, a +1 Katana in the sphere functions as a non-chakra enhanced katana. A Chakra weapons properties and powers are suppressed if it is used against a target in the sphere or wielded by an attacker in the sphere. If a chakra weapon or piece of chakra enhanced ammunition fully leaves the sphere.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b818b519a45466a03b732617", name: "STRENGTH OF 1000", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "As a prerequisite for learning this jutsu you must know the “Strength of 100 Technique” Jutsu. You have mastered the “Strength of 100 Technique” perfecting the chakra control needed and finding the most efficient way to enhance your physical Strength by over 1000 times. For the duration, your Strength score Double. Your jump distance is multiplied by 4, your movement speed is tripled, you gain advantage on Strength, Dexterity and Constitution saving throws, and you regenerate hit points equal to 2d12+ your Constitution modifier at the start of each of your turns. When you make an unarmed attack, you deal an additional 3d10 Bludgeoning damage. When this jutsu ends or you deactivate this jutsu, your body experiences a massive shock. You gain 10 ranks of Exhaustion which cannot be removed or healed by any means. You must complete at least 4 weeks of Recouperation during Downtime to remove them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5a2c76103466c91eef9930de", name: "DEMIPLANE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 action", range: "30 feet", chakra_cost: "35 Chakra", components: "HS, CM, CS", duration: "1 hour", description: "When you cast this jutsu, you inscribe a transportation seal either on a surface (such as a section of floor, a wall, or a table) or within an object that can be closed to conceal the seal (such as a book, a scroll, or a treasure chest). If you choose a surface, the seal can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; if the object is moved more than 10 feet from where you cast this jutsu, the seal is broken and this jutsu ends without being triggered. The seal glows as a shadowy door forms on a flat solid surface that is attached to the surface the seal is placed on. The door is large enough to allow medium creatures to pass through unhindered. When opened, the door leads to a Demiplane that appears to be an empty room 30 feet in each dimension, made of wood or stone. When the jutsu ends, the door disappears, and any creature or objects inside the Demiplane remain trapped there, as the door also disappears from the other side. Each time you cast this jutsu, you can create a new Demiplane, or have the shadowy door connect to a Demiplane you created with a previous casting of this jutsu. Additionally, if you know the nature and contents of a Demiplane created by a casting of this jutsu by another creature, you can have the shadowy door connect to its Demiplane instead.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1b9fe372fc08da77ed9b3ce7", name: "FLYING THUNDER GOD: GUIDING THUNDER", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction to another creature's Move, Attack, or Cast a Jutsu Action", range: "30 Feet", chakra_cost: "22 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You bend space and time by making a sealing formation in midair up to 30 feet away from you in a space you can see that you decide. Creatures, objects or Jutsu that cross through this space are immediately teleported to a location that you have previously marked with any Chakra Seal within 10 miles. This destroys the Chakra Seal after activation.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "25237d496ffd270a3f306d4b", name: "FOUR YANG FORMATION", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "Full Turn Action", range: "Up to 60 Feet", chakra_cost: "30 Chakra", components: "HS, CM, CS, 3 Other Four Yang Formation", duration: "Concentration", description: "You and 3 other users of this jutsu take position in 4 points, surrounding the area you wish to seal. You each take position in 4 different points no more than 60 feet away from one another and each spend your turn activating this jutsu. When all 4 are complete you bend time and space sealing away the enclosed space in a pocket dimension composed of null space. Creatures trapped in this pocket dimension, are unable to escape unless they perform the same jutsu, or can teleport using the “Flying Thunder God: Guiding Thunder”, “Displacement Sealing Trap”, “Flying Thunder God”, or “Four Yang Formation” Ninjutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9810818085166ca393b6dfd2", name: "BLOOD TO ACID", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "Special (50 Chakra)", components: "HS, CM", duration: "Instant", description: "You mold acidic into a form of your choice before attempting to infuse it into a creature you can see within range, turning all of their blood into acid, destroying them from the inside. Select one creature you can see within range. The target must make a Constitution saving throw, taking 10d12 + 40 acid damage on a failed save as all of their blood is turned to acid. A creature who passes the save only takes half damage and suffer no further effects. A creature who failed their saving throw converts all ranks of bleeding or lacerated into corroded and ignores the stack limitations found in the condition until this effect is ended on them. At the beginning of each of its turns, it must make a Constitution saving throw or be stunned until the beginning of its next turn from the never-ending pain it experiences. A creature who has had its blood turned into acid gains a rank of corroded in place of any ranks of bleeding. Additionally, it suffers 10d4 acid damage every hour as their acidic blood constantly destroys them from the inside. Its blood can be turned back to normal with a casting of this jutsu again targeting it, or by casting another ninjutsu with the medical keyword that removes conditions at S- Rank.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bd81305d3dedb16683b4895d", name: "GENOCIDE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "Special (50 Chakra)", components: "HS, CM", duration: "Instant", description: "You begin to generate corrupted medical chakra and infuse it with pure prejudice and malice towards a creature and their bloodline. Select the name of a Clan or a specific creature if you are unsure of their clan. The target must be of a level equal to or lower than your own as you fire a blast of Necrotic chakra that cannot miss, so long as you can see them. The target must make a Constitution saving throw. For every condition with a different name, they are under the effects of, they suffer a -2 penalty to their save. On a failure, the target takes 10d10+50 necrotic damage, or half as much on a successful save. At the beginning of the affected creatures turn, pass or fail, tendrils of necrotic chakra leap out from that creature, up to 100 feet, to all other creatures that share the targets clan, or bloodline based on what you chose. All such creatures, excluding the original target, must make the same saving throw, taking 50 necrotic damage on a failed save, or half as much on a success. At the beginning of a creature who fails their saving throws from the tendrils, more tendrils leap out from them with the same restrictions an additional 100 feet repeating the previous process, but excluding all creatures who were previously affected by the jutsu. This affect repeats until no other creatures who share the original targets clan or bloodline are within range of the tendrils.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f5541681c0cf0f25d43c8059", name: "HEAL", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "50 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest and release a torrent of  Medical chakra that flows out from you into injured  creatures of your choice. You cannot reduce the cost of  this jutsu by any means. You restore up to 300 hit points,  divided as you choose among any number of creatures  that you can see within range. Creatures healed by this  jutsu are also cured of all diseases and any effect that  inflicts conditions, regardless of the effects restriction  or limitation. This jutsu has no effect on undead or  constructs. Once cast, this jutsu cannot be cast again  until you complete a Full Rest.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e0a0215e9661c2748354e493", name: "IMPENDING END", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "40 Feet", chakra_cost: "35 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest and release a torrent of putrid Medical chakra that flows out from you into creatures of your choice. You cannot reduce the cost of this jutsu by any means. Creatures with 80 Hit points or less within range die as their heart stops, their blood thins, and their cells forget the functions they normally are tasked with. Creatures who have between 81 and 100 Hit points, can feel their body begin to suffer from necrosis as they attempt to resist. These creatures make a Constitution saving throw. On a failed save, they become crippled by the pain. A creature crippled by the pain, speed can never be higher than 10, they have disadvantage on all rolls using Strength or Dexterity, and if they attempt to cast a jutsu of any type while crippled they must remake their saving throw. On a failed save, they take 8d8 Necrotic damage that ignores Temporary Hit Points, Resistance and Immunity as their chakra network is attacked by the necrosis reducing their Maximum Chakra by the result as well. A crippled creature is crippled permanently, or until they have a Jutsu that removes conditions casted on them a S-Rank.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bc17a4a063fcd8899f4caffe", name: "PLAGUE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Day", range: "Self (1 Mile)", chakra_cost: "Special (100 Chakra)", components: "HS, CM", duration: "Forever", description: "You begin to generate poisonous, venomous and toxic medical chakra and infuse it directly into the air itself. Yourself and 10 other creatures of your choice are immune to the effects of this jutsu. Once this jutsu is cast, it continues to permeate the affected area forever after casting. Dark green, purple and black clouds fill the air, as a foul smell of poison and toxins sail in the wind. A low moan can always be heard. Each creature who are under the clouds when this jutsu is cast must make a Constitution saving throw. A creature who is already suffering from a disease or who is poisoned or envenomed makes their saves at a -5 penalty. On a failed save, a creature gains 5 ranks of the envenomed condition and they are permanently poisoned unless removed by a Jutsu with the medical keyword that removes conditions of S-Rank. This jutsu ignores Immunity to the Poisoned Condition and Poison Damage. A creature can never have their hit points reduced below 0 as a result of the envenomed condition, instead forced to suffer until killed by other means. Creatures who come into contact with a creature who was poisoned or envenomed by this jutsu must make the save as if they were under the clouds of this jutsu when cast. A creature who would wake up from a rest of any type under clouds created by this jutsu must make a save as if they were under the clouds of this jutsu when cast. The affected area grows by 1 mile every month until this jutsu is dispelled. The clouds can only be dispelled by 3 castings of a Ninjutsu with the Fuinjutsu keyword cast at S-Rank targeting them from within 10 feet of the original space the jutsu was cast from.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4f5e1417b2141a15e780243e", name: "SUPREME POISON DEITY", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Full Turn Action", range: "120 Feet", chakra_cost: "Special (25 Chakra)", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You mold poisonous into the form of a huge construct scorpion, known as the Supreme Poison Deity, formed entirely of poison, toxins and venom. This construct uses your Ninjutsu attack bonus and Save DC for effects that requires it. It rolls initiative as it has its own turns, using your Ninjutsu ability modifier + proficiency as its initiative.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2fec26e0e187b6761b1328fc", name: "PLANE SHIFT", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 action", range: "Touch", chakra_cost: "24 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You and up to eight willing creatures who are touching each other are transported to a different location that you’ve placed a Chakra seal prior. This location can be on the standard plane of existence, or in a pocket dimension that has not collapsed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4909086c6b430c20cefd0213", name: "REALITY BREAK", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 action", range: "60 feet", chakra_cost: "24 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You shatter the barriers between dimensions thrusting them into turmoil and madness. The target must make a Charisma saving throw or it can’t take Reactions until the jutsu ends and must also roll a d10 at the start of each of its turns; the number rolled determines what happens to the target as shown on the Reality Break Effects table. If used while inside of a pocket dimension created by another jutsu, that dimension collapses on itself, being destroyed, and ejects all creatures and objects in it outside the pocket dimension. REALITY BREAK EFFECTS D10 Effects 1-2 Collapsing World. The target takes 12d8 force damage, and is stunned until the end of the turn. If the target was in a pocket dimension, they return to the standard plane of existence. 3-5 Rending Rift. The target must make a Dexterity saving throw, taking 8d12 force damage on a failed save, or half as much damage on a successful save. 6-8 Wormhole. The target is teleported, along with everything it wearing and carrying, up to 100 miles away to an unoccupied space in a random direction. The target also takes 12d10 force damage and is prone. 9-10 Chill of the Dark Void. The target takes 12d10 Necrotic Damage and is blinded permanently. This can be removed with a medical Jutsu of A-Rank or higher.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "73551bcf016132eebed848ce", name: "REAPER DEATH SEAL", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "Special", components: "HS, CM", duration: "Instant", description: "You summon the reaper of souls. Along with casting this jutsu you target a Restrained or Incapacitated creature within range. The reaper of death reaches through you, using your soul as a glove, and into the target creature, pulling out the souls of you and your target, killing you both. Both souls are sealed into the belly of the reaper of souls and neither you or the target can be revived by any means.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "51f651f9a0385fcf1a034d51", name: "GATE OF THE AFTERLIFE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "9991cc726431e53e17c4a8fa", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Year", range: "10 Feet", chakra_cost: "Special (138 Chakra)", components: "HS, CM", duration: "Permanent", description: "You and all casters infuse chakra into chakra seals as you attempt to tear open the gates of hell with the seal of the ever after. For 8 Hours a day, for 1 Year, you and no less than 10 Casters, work together adding, reinforcing and manifesting chakra seals designed to open a portal to the afterlife. If this casting is interrupted by having chakra seals destroyed or a caster dying, the jutsu fails having to be recast from scratch. Once completed, this jutsu creates a 2-way portal to the afterlife. Living creatures who pass through this gate into the world of the afterlife can remain there for no longer than a number of hours, equal to their level. If they remain any longer their material bodies disintegrate as only their souls remain, unable to cross back over onto the material plan as a living creature ever again. A Spirit who finds this gateway, can cross over into the material plane and can possess any creature of equal or lower level than they were in life. If the creature attempts to possess a creature of lower level than it, then it completely dominates their mind and body, kicking out their spirit. The spirit has access to all features, jutsu and abilities they had access to in life and any jutsu, features and abilities the original body had access too. The spirit that was kick out of that body is sucked into the afterlife, taking the place of that escaped Spirit. If the creature attempts to possess a creature of equal or higher level than it, then the target of possession makes a Charisma save vs the Level + Proficiency of the creature. On a success, they resist. On a failure, their spirits are kicked out of their body. SEALING ART: IMPURE WORLD", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "583058aaddb5519798223978", name: "IMPURE WORLD DESTRUCTION", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Full Turn Action", range: "30 foot", chakra_cost: "45 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You infuse chakra into chakra seals as you attempt to tear into the underworld with the seal of the consecration. You summon a coffin to act as a gateway to the underworld. The coffin springs open, as shadow tendril like hands launch forward piercing the body a creature you can see within range. Make a ranged Ninjutsu attack. On a hit, you deal 18d10 necrotic damage. If this jutsu reduces a creature to 0 Hit points, their soul is torn from their body as it is sealed within the coffin. Moving forward, until there is not a soul bound to the coffin, whenever you would cast this jutsu, you instead summon an undead construct of the creature you originally killed using this jutsu. The construct acts at the end of your turn, and follows your command. It can speak freely but cannot willingly act in a way counter to any action you provide it. The construct has half as many hit points it had in life, can cast jutsu and use clan features it had in life using your chakra instead. A construct summoned this way can only remain summoned for 1 minute before being pulled back into the coffin at the end of the duration to be saved for later use. A construct that is killed while summoned does not return to the coffin, instead relinquishing the soul that was bound to it. SEALING ART:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d021b4494343f7e53fe65eb9", name: "VOID", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "1000 feet", chakra_cost: "Special (30 Chakra)", components: "HS, CM, CS", duration: "Concentration, Up to 1 Minute", description: "You infuse chakra into chakra seals as you attempt to tear into the underworld with the seal of the emptiness. You select a 30-foot radius sphere within range, creating a sphere of emptiness, where the material plane and the space inside the sphere are of different dimensional make ups. For the jutsu’s duration, the sphere and any place within 100 feet of it are difficult terrain, and non-Chakra enhanced objects fully inside the sphere are shunted to the space in-between dimensions if they aren’t being worn or carried. When the sphere appears and at the start of each of your turns, until the jutsu ends, unsecured objects within 100 feet of the sphere are pulled towards the spheres center, ending in an unoccupied space as close to the center as possible. A creature that starts its turn within 100 feet of the sphere must make a Charisma saving throw or be pulled straight towards the spheres center, ending in an unoccupied space as close as possible to the center. A creature that enters the sphere for the first time on a turn or starts its turn there takes 10d10 force damage and is restrained until it is no longer in the sphere. If the sphere is in the air, the restrained creature hovers inside the sphere. A creature can use its action to make a Strength saving throw against your Ninjutsu save DC, ending this restrained condition on itself or another creature in the sphere that it can reach. A creature who is reduced to 0 hit points by this jutsu is shunted into the space in-between dimensions where they drift forever frozen in time, along with any items it was wearing or carrying.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4e56878ea40c4b8ddf822bc2", name: "AGONIZING THORN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You generate Shards of earth and hurl them at a creature or object within range. Make a Ranged Ninjutsu Attack against the target. On a hit, the target takes 3d8 Earth damage and must make a Strength saving throw, gaining 1 rank of bruised on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "269b8bd75b31e4827ba943fb", name: "BEDROCK COFFIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You manipulate and mold the earth under your enemies to encase them in a coffin of stone. Target creature makes a Dexterity saving throw. On a failed save, they are captured inside the coffin and are treated as restrained and grappled. On a success they dodge out of the way of the coffins collapsing form. On each of their turns thereafter, they can make a Strength saving throw to force their way out. If a creature attempts to attack the coffin to break it, the coffin is an Quake Shard, has an AC equal to your Ninjutsu Save DC, 25 Hit Points, Resistance to Cold damage and vulnerability to Lightning damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you can target by +1 and the hit points of the coffin by 10. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c8f3fe8415d42481c2eb3f29", name: "BEDROCK SKIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Reaction, which you take when you take damage.", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "The Jutsu hardens the skin in response to taking damage. Reduce all damage you take except Lightning by 1d6+4 until the beginning of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage reduction by +4. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7f2edc31d310e202356e36c3", name: "DOMINUS BANNER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Bonus action", range: "Self (10-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM, W (Any)", duration: "Concentration, up to 1 minute", description: "You coat your weapon in earth chakra, before raising it above you and releasing its golden chakra into the shape of a banner, as a pulse of golden chakra enhances the weapons of your allies converting your defense into their offence. You cannot lose concentration of this jutsu as a result of damage. For the duration, one weapon you and each allied creature affected by this jutsu is wielding is enhanced by your golden earth chakra. Enhanced weapons deal an additional 1d4 Earth damage twice per turn and grants its wielder +3 Damage Reduction vs all damage except Lightning. If you or affected allied creatures let go of their weapon or it is taken from its original wielder, the golden chakra disperses.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the bonus damage to 2d4 and the damage reduction to +6. If this jutsu is cast at S-Rank, increase the bonus damage to 3d4 and the damage reduction to +9. 50 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c2b4b5077ae27be4133801af", name: "CALCITE: MIGHT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "aaeecd12fb6a8f889a26ab97"], elements: ["doton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create a surge of Earth Release Chakra and use it to amplify a willing creature you can see within range. Once successfully cast, you do not need to see where the target is and must remain within 120 feet of them. Target creatures Strength becomes 18 for the duration if it is not already. Their Unarmed, Weapon, and Taijutsu Attacks deal an additional 1d6 Earth Damage and you always know when they take damage and their current condition even if you cannot see them for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures affected by +1. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0af047073792d587786d557e", name: "EARTH FLOW RIVER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Self (30 Foot Cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You transform the surface in front of you into a mud river. The river created is a 30-foot cone, that sweeps creatures off of their feet and carries them to the end of the cone furthest away from the caster. Creatures in the path of the mud slide must make a Strength saving throw. On a failed save they are swept up and moved to the end of the stream, falling prone being disarmed of any weapons or items they are holding and having their speed reduced by 10 feet until the end of their next turn. On a successful save, no effects.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 5ft and the speed they are reduced by 5 feet. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "dc351b9a488acc91c5a1e80d", name: "EARTH SPINE GRUDGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 minute", description: "You generate Shards of earth and levitate them around yourself, creating a field of stone debris to protect you. For the duration of this jutsu, ranged attacks are made as if you are under half cover, with the floating earth around you. Also, creatures of your choice treat all spaces within 10 feet of you as difficult terrain. This floating earth counts as a single Quake Shard while active. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "454bb3e497f91d522b52a776", name: "EARTHEN ENTANGLEMENT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "Hooking and grasping arches of stone sprout from the ground in a 20-foot cube starting from a point within range. For the duration, these earthen arches turn the ground into difficult terrain. Creatures cannot take the dash or dodge actions while within this area of difficult terrain. Creature(s) of your choice in the area when you cast the ninjutsu must make a Strength saving throw or be restrained by the criss crossing stone arches until the jutsu ends. A creature restrained by the earth can use its action to make a Strength Saving Throw against your Ninjutsu save DC. On a success, it frees itself. When you cast this jutsu, the difficult terrain remains even after you end concentration on this jutsu. The difficult terrain can be cleared with 10 minutes of work attempting to do so. While the difficult terrain remains, its counted as a single Quake Shard. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "78d7771d4c14ed4636f9ae9f", name: "EARTHEN GRASP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You select a 5-foot-square of unoccupied space on the ground that you can see within range. A medium sized hand made from earth, soil and dust forms and reaches for one creature you can see within 10 feet of it. The target must make a Strength saving throw. On a failed save, the target takes 2d6 earth damage and is both grappled and restrained for the Jutsu’s duration. A creature grappled in this way has one of their hands bound and is unable to form Hand Seals or use Chakra Seals with it. As a bonus action, you can cause the hand to crush the restrained target, dealing 2d6 earth damage. As an action on their turn, the restrained target can remake the saving throw. On a success, the target escapes and is no longer restrained by the hand. As an action, you can cause the hand to reach for a different creature or to move up to 30 feet to a different unoccupied space that you can see. This movement must be along the same or connected surface the hand is attached to. The hand releases a restrained target if you do either. This hand counts as an Quake Shard.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of Earthen hands that can target other creatures by +1 and increase the damage by 1d6. 51 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "72691937ec159ad560e048e3", name: "EARTHEN TREMOR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "60 feet (20-foot cube)", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You cause a tremor in the ground on a 20-foot cube centering on a point you can see within range. Each creature other than you in that area must make a Dexterity saving throw. On a failed save, a creature takes 2d8 earth damage is knocked prone. If the ground in that area is loose earth or stone, it becomes difficult terrain until it is cleared, which takes about 10 minutes of work.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8 and the radius by 5 feet. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "21ca3dd68742e048dff8fa78", name: "GEO BREASTPLATE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Hour", description: "You create an aura of Earth Release chakra that permeates your body for the duration. This chakra acts as a breastplate of steel like material. For the duration your AC is Calculated as 13 + Your Intelligence (or Constitution, your choice) modifier + Half of your proficiency bonus. While you are gaining the benefit of this armor calculation, you gain +3 damage reduction vs all sources excluding Lightning damage. This jutsu ends if you wear armor, dismiss the jutsu as a bonus action or would change your armor calculation as a result of a clan or class feature.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the damage reduction this jutsu provides to +6. If this jutsu is cast at S-Rank, increase the damage reduction this jutsu provides to +9. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0c06106e25bc0435c73d7d65", name: "GEO GENESIS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Special", description: "You create a shard of shimmering earth, made of Earth Release Chakra. This shard can be any shape you chosen and can shimmer in any color you like. You then select a space you can see within range and throw the shimmering shard to the chosen space. As a bonus action on your turn, you may trigger the shard causing it to erupt into a blooming flowerhead made of earth. All creatures within 10 feet of the shard must make a Strength saving throw. On a failed save, you deal 2d6 + your Ninjutsu ability modifier Earth damage and 1 rank of bruised or half as much on and no additional effects on a successful save. Once the shard blooms it sits unmoving on the ground and counts as an Quake Shard. Up to 3 medium-sized creatures may safely stand on the flower of earth. As a reaction or bonus action you may cause the flower to rise 60 feet into the air taking any creature standing on it with it. The flower dissolves at the end of your next turn. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7162e8d4ff07b5be85cde588", name: "GEO ISOTOMA", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Bonus Action", range: "90 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You amplify constructs made of earth causing them to manifest an aura of Earth Release Chakra. Select an Quake Shard of your creation within range. All creatures of your choice within 60 feet of the chosen construct gains a +1 bonus to their AC, as you decrease the weight of the chosen creatures allowing them to move faster and with less resistance. A creature can be affected by no more than 2 aura created by this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. Casting this jutsu at B-Rank, increase the AC bonus to +2. Casting this jutsu at S-Rank, increase the AC bonus to +3. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2b86781fc6d2fd3c087dc3b5", name: "GEO RESONANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "90 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You amplify constructs made of earth causing them to manifest an aura of Earth Release Chakra. Select an Quake Shard of your creation within range. All creatures of your choice within 60 feet of the chosen construct must make a Strength saving throw each turn they start in the aura of a Construct. If a creature is within 2 different aura created by this jutsu they make a single Saving throw. On a failed save, a creature’s AC is reduced by 1 until the beginning of their next turn as you increase the weight of the chosen creatures forcing them to move slower. A creature can be affected by no more than 2 Auras created by this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. Casting this jutsu at B-Rank, increase the AC penalty to -2. Casting this jutsu at S-Rank, increase the AC bonus to -3. 52 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "1ef6f4a0e8f25bbdd02ea22f", name: "GEOLOCATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: ["doton"], casting_time: "1-Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 minutes", description: "You extend your chakra throughout the earth around you extending up to 30 feet from you. For the duration you gain tremor sense. Creatures who move under the surface that you are standing on are perceived by you with your tremor sense.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at C- Rank Increase the duration to 1 hour. If cast at B-Rank; 8 Hours. If cast at A-Rank 24 Hours. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9151a31995b7992ed72022f9", name: "GOLDEN GEMS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 minute", description: "You solidify your Earth Release chakra into 2 small Shimmering Crystalline Gems. The Gems can be any color you choose and they float around you for the duration. You can spend your gems to enhanced other Earth release jutsu. By spending 1 Golden Gem, when you cast a Ninjutsu with the Earth Release keyword, you are able to enhance it in one the following ways: • Reinforce: If the jutsu cast summons a construct or structure that intercepts damage, increase its Hit points by 1d10.You can spend up to 5 gems in this way. • Harden: If the jutsu cast would grant a creature temporary hit points, increase the amount gained by 1 dice. • Solidify: If the jutsu cast would deal damage, increase the damage dealt by 1 damage die.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and you generate 1 additional Gem. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4341bdbf2521522c65e72d5d", name: "HEADHUNTER TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1-Action", range: "Touch", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "While burrowing under a target, you can attempt to drag them under leaving them submerged in the earth with only their head being exposed. Target creature makes a Dexterity saving throw to avoid being snatched into the ground and restrained. If you are hidden from the target and they are unaware of your presence they make this save at disadvantage. Creatures who are restrained by this jutsu can make a Strength (athletics) check vs your Ninjutsu Save DC as an action on their turn to escape the ground, ending the restrained condition. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d8d0d6d78661b27f9db44bcc", name: "JADE DEVOTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "Self (10-foot sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minute", description: "You release a surge of earth release chakra that permeates you and your allies. All willing creatures of your choice within a 10-foot sphere centering on you, gain 4d6 temporary hit points and resistance to bludgeoning piercing and slashing damage so long as they have temporary hit points granted by this jutsu. Creatures who have temporary hit points granted by this jutsu count as Quake Shards created by you.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and temporary hit points by 1d6. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "d068e2c131f9654a015db68f", name: "JADE RAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131", "9991cc726431e53e17c4a8fa"], elements: ["doton"], casting_time: "1 Action", range: "90 feet", chakra_cost: "Special (28 Chakra)", components: "HS, CM, CS", duration: "Instant", description: "By weaving your handseals together you create a seal made completely of shimmering earth Release Chakra in the air above you. This seal then alters its angle before you release a swarm of shimmering shards of sharpened stone. All creatures in a 15-foot wide, 90-foot-long line originating from you must make a Dexterity saving throw, taking 6d6 earth damage on a failed save or half as much on a successful one. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters you increase the damage die by 3. Any creature who assists in casting this jutsu as a combination jutsu increases the damage of this jutsu by one step based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: D8, +3-4: D10, +5: D12). 53 EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2dda77e9821dd688d7b3fc00", name: "JADE SCREEN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131", "9991cc726431e53e17c4a8fa"], elements: ["doton"], casting_time: "1 Action", range: "30 feet", chakra_cost: "Special (28 Chakra)", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You summon two pillars of earth each 15 feet tall, and 5 feet thick. They each occupy a space that can hold them and must be within 25 feet of each other with no other structures directly in-between them. These pillars are structures of your design and cannot be moved once conjured. A film of earth release chakra is created between the two pillars in a straight line. This film and pillars share a number of hit points equal to twice your Ninjutsu Save DC and has resistance to Bludgeoning, Piercing and Slashing damage. All attacks or jutsu, from one side of your choice, that would pass through this film instead strike it reducing its hit points as if it was the original target. Once the hit points of the structure and film reaches 0, this jutsu immediately ends as the structure crumbles. All ranged attacks that would pass through the film from the other side pass through harmlessly and Ninjutsu and Taijutsu attacks of your choice increase their range by 10 feet, and damage by 1 damage die. This jutsu can deal additional damage in this way no more than 3 times per casting. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters neither caster needs to spend chakra to maintain concentration on this jutsu. Any creature who assists in casting this jutsu as a combination jutsu increases the damage based on the highest Charisma Modifier within the group of casters. (+0- 1: No Change, +2: +2 additional damage die, +3: 3 additional damage die, +4: 4 additional damage die, +5: 5 additional damage die). EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "057683ddd8c82618eed3ad04", name: "MOLE MOVEMENT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You begin to sink into the ground after converting the earth under your feet into a soft sand like substance. You gain a burrow speed of 30 feet. You can burrow through earth and sand alike. If you run out of chakra while underground you emerge directly up from where you are. You leave a single tunnel large enough for one person to fit through at a time. You have knowledge of how many people are on the surface directly above you in a 10-foot radius sphere centering on you. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "23f8b5f024522738e490e76d", name: "MUD WAVE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Self (20-foot cone)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You churn the earth in front of you and blast it forward in a 20-foot cone. Creatures in the cone must make a Strength saving throw taking 3d6 earth damage and being bruised on a failed save, and half as much damage and not additional effect on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage by 1d6 and the cone size by 5 feet. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "16a88840cd812c6ff0705bf8", name: "RISING ROCK TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["doton"], casting_time: "1-Action", range: "30 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You tear two large chunks of stones from the ground using the Strength of your chakra alone, hurling them at a single target. Make two ranged ninjutsu attacks against the target dealing 2d8 Earth damage on a hit. The two large chunks of stone remain after being hurled, being counted as an Quake Shard, occupying two spaces of your choice within 5 feet of the original target. Select two spaces within 5 feet of you when you cast this jutsu. These two spaces from which you pulled the stones from count as difficult terrain until cleared, which takes at least 10 minutes of work.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When this jutsu is cast at B-Rank, increase the number of attacks by +1. When this jutsu is cast at S-Rank, increase the number of attacks by +1. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ed0d307e30a85352d2d52eaa", name: "ROCK SHURIKEN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1-Action", range: "30 feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You mold and shape small stones into the shape of shuriken. When you do, you autonomously fire them all off, one after another like bullets pelting and tearing through enemies. Make a ranged ninjutsu attack. On a hit, you deal 4d6 earth damage, and inflicting 1 bruised.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. 54 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c0b640efc57aa749f9c37bf1", name: "STONE FIST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 minute", description: "You encase a single arm in rock, enabling yourself to strike with hardened punches, while also protecting yourself from direct contact. For the duration of this jutsu, when you take the attack action, you instead deal you deal your Unarmed Damage +2d6 earth damage. This Jutsu's benefits cannot be applied to any Taijutsu or Bukijutsu cast under any circumstances. For the duration of this jutsu one of your hands are occupied and cannot be used to make Hand Signs (HS) or use Chakra Seals (CS). Also, when you strike a creature with the encased arm, it does not count as direct contact with them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When this jutsu is cast at B-Rank, increase damage by 1d6. When this jutsu is cast at S-Rank, increase damage by 1d6. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "fa27a12cbdbbdef67b27fd9a", name: "TECTONIC TIDE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "Special", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You churn the ground under you and up to 2 Quake Shards of your creation and create a localized quake of earth that bends and snaps the ground under them and rolls outward from in a wave. Select up to two Quake Shards of your creation, including yourself. All other creatures within a 20-foot radius of yourself and the chosen constructs must make a Strength saving throw taking 2d8 earth damage and being knocked prone and bruised on a failed save or half as much with no additional effects on a successful save. If a creature is in more than one radius, they only make 1 saving throw, being affected by this jutsu up to twice.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 radius by 5 feet, and damage by 1d8. C-RANK: EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "1477430a59c8332a6638a95c", name: "CALCITE: SWIFT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "aaeecd12fb6a8f889a26ab97"], elements: ["doton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create a surge of Earth Release Chakra and use it to amplify a willing creature you can see within range. Once successfully cast, you do not need to see where the target is and must remain within 120 feet of them. Target creatures Dexterity becomes 20 for the duration if it is not already. They gain Proficiency in Dexterity saving throws and their speed is increased by 20 feet.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and their speed by 10 feet. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "6f5cf5c6185d826889f66465", name: "CRYSTALIZED ASCENSION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You materialize Earth release chakra into the form of armor on a willing creatures body for the duration. Target creature’s AC becomes equal to your Ninjutsu Save DC + their Dexterity Modifier and gains Temporary hit points equal to your Ninjutsu save DC. Additionally, the affected creature gains Damage reduction equal to your Ninjutsu ability modifier for the duration. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "eec43d43d15fb3dd401d1f66", name: "DARK ROCK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: ["doton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "7 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You slam your palms into the ground as the immediate area becomes blackened. A single Quake Shard is erected from the ground at a point of your choice within range. The structure is black and cold to the touch and emanates a light obstructing aura. The Structure absorbs all light within 15 feet of it creating a blackened field that cannot be seen through to the other side. Creatures within that radius are immediately blinded and cannot see while within the radius and cannot be seen by creatures outside the radius either. A creature who touches the structure can see through the blackened field as if it wasn’t there at all and loses the blinded condition so long as they remain within contact with the structure. The structure has an AC and hit point value equal to your Ninjutsu save DC. If the structure is destroyed the jutsu immediately ends. 55 EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "30aadcb1a4ceb8148d80b8b5", name: "EARTH CLONE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "dc2837c0a3446d09da7edaf6", "33ab3a61f3027398cd08f131"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "Special (8 Chakra)", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "A modified version of the Shadow Clone Technique that allows the user to create a solid construct from soil, rock and sand in their own image. The clone weights 6 times as much as the user and cannot swim (or drown). You can summon a single Earth Clone. The Earth Clone must be standing on the same surface as you to complete a task set by you. The Earth Clone counts as an Quake Shard. The Earth clone has 20 hit points and Immunity to Genjutsu based effects, Psychic & Poison damage, Resistance to Bludgeoning, Earth & Cold Damage and Vulnerability to Lightning damage. Your clone has a single replica of any melee weapons you have on you at the time of creation that is also made from the same materials that constitute it’s made from. When the clone makes an attack using this weapon or an unarmed strike it deals 1d8 earth damage. It can make up to 2 attacks using its action. The Earth Clone cannot cast jutsu, but you can cast a ninjutsu, that you know with the Earth Release keyword through your earth clone as if the clone is casting it itself. Creatures who have chakra sight can immediately tell the clone is made of earth and can distinguish the clone from the original.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the clones Hit points by 15. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c26112221fa59e847a0736da", name: "EARTH DRAGON BULLET", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["doton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You spit up a puddle of mud from your stomach after molding chakra which transforms into a Dragon head that then opens its mouth and fires compressed balls of mud that are meant to cause concussive damage on impact. Make two ranged ninjutsu attacks targeting different creatures. On a hit the target takes 8d4 earth damage and must make a Constitution saving throw. On a failed save they are bruised.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 2d4 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0024bd55c5429ce97b2ec364", name: "EARTH FLOW SPEARS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "60 ft (10 Foot cube)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "Choose a point you can see on the ground within range. A Fountain of spiked earth molded from the ground erupts in a 10-foot cube. Each creature in that area must make a Dexterity saving throw. A creature takes 3d12 earth damage on a failed save, or half as much damage on a successful one. The affected area is now considered difficult terrain until it is cleared, which requires 10 minutes of work.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d12. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2d267b1fb7a92cb76c258318", name: "GEO PROGENITURE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: ["doton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Special (8 Chakra)", description: "You weave hand seals as you can manifest multiple shards of shimmering earth, made of Earth Release Chakra. These shards can be any shape you chose and can shimmer in any color you like. You can create up to 3 shards using this jutsu with each one created costing 8 chakra. You then select a number of space you can see equal to the number of shards you create within range and throw one shimmering shard to each space. As a bonus action on your turn, you may trigger all the shards created by this jutsu, causing it to erupt into a blooming flowerhead made of earth. All creatures within 15 feet of a shard must make a Dexterity saving throw taking 4d8 Earth damage and being Dazed on a failed save or half as much on and no additional effects on a successful save. If a creature is within range or more than 1 shard, increase the damage dealt by 2d8 for each shard they are near beyond the first. A creature who is within the range or more than one shard takes a -1 penalty to their saving throw for each additional shard they are within the range of beyond the first shard. A creature who is within the range of more than one shard makes only one saving throw, not three. A creature that fails this save by 5 or more instead becomes stunned for a number of turns equal to the number of shards they are within the range of. A creature who fails this save by 10 or more and are within the range of three shards becomes petrified for 3 of their turns. 56 EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7a7b7cc99d429fc69abd3aff", name: "GEO ROCKBLADE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 minute", description: "You manifest a Geo weapon made from pure Earth Release chakra of your design and make by picking up a single stone. This stone reshapes and reforms until it takes the shape of the weapon you chose. You gain proficiency in the Stone Weapon made and the Stone weapon gains all that weapons properties. If you create a weapon without the Two-Handed Property, the weapon deals 2d6 + your Ninjutsu Ability Modifier earth damage. If you create a weapon with the Two-Handed property, the weapon deals 2d8 + your Ninjutsu Ability Modifier earth damage. If another creature takes this weapon and attempts to use it, it loses one damage die. You can dismiss this weapon as a bonus action or reaction. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a1590b8e04bb3971da8ea033", name: "GUIDE TO RESISTANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: ["doton"], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You fuse a willing creature you touch with a Fuinjutsu seal made of Earth release chakra. For the duration, the target creature gain Resistance to Bludgeoning, Piercing, Slashing Damage or Immunity to Cold Damage, and Vulnerability to Lightning Damage. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a9eec4d9753ef27dab568686", name: "MOVING EARTH CORE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Touch", chakra_cost: "6 Chakra", components: "HS, CM", duration: "1 Minute", description: "You are able to amplify constructs made of earth causing them to become far more potent, tough, and durable. Select one Quake Shard you can see and reach. By touching it, you infuse it with a surge of Earth Release chakra, amplifying it. Quake Shards you cast this jutsu on, gains the following benefits; • Bonus 2d10 + Your Ninjutsu ability modifier in Hit points or Temporary hit points. • Reduces incoming damage by 1d8 + 3 • Deals 2d6 bonus earth damage if it scores a hit with one of its attacks, once per turn. If you target an area without an Quake Shard, you can manipulate the terrain a bit, moving it up to 15 feet higher or deeper, or forming it into a simple structure of your choice within a 15-foot cube. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "de4a2e9d99992dbe144bda27", name: "MUD WOLF", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: ["doton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute.", description: "You focus on conjuring a beast made of pure earth release chakra. By fusing your earth release chakra with the surrounding dirt, earth and other earthen like minerals, you are able to conjure two mud wolves. Mud wolves are Quake Shards. The Wolves have the following stats and act as a bonus action on your turn and use your Ninjutsu attack bonus or Ninjutsu Save DC when an effect calls for it. When you command them, all wolves currently active acts at the same time, and attempt to perform the same actions against either the same creature or different creatures determined by you.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the number of Wolves you Summon by +1 and the wolves hit points by +10.", created_at: NOW, updated_at: NOW },
  { _id: "ac6dd3497e6898292b2aaab3", name: "RENDING DRILL FANG", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["doton"], casting_time: "1 Action", range: "5 Feet", chakra_cost: "8 Chakra", components: "HS, CM, M", duration: "Instant", description: "You cover your forearm with a spinning drill made of stone. Make a melee ninjutsu attack against a creature you can see in range dealing 5d6 Earth Damage and inflicting 2 rank of bruised. If this jutsu scores a critical hit, the earth drill splinters and explodes, tripling the damage dice, instead of doubling them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "3d9f98924b660822b035e8c6", name: "ROCK TANK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["doton"], casting_time: "1 Action", range: "30 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "The user covers itself with earth, soil or sand and molds it into a rolling sphere that is then launched at a target in range, crushing them beneath its new weight. Make a melee ninjutsu attack against a creature you can see within range propelling yourself towards the target creature and ending your movement occupying the targets space, if possible, dealing 4d8 Earth damage. The target also makes a Strength saving throw being knocked prone and bruised.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c4dd67333e5ee3f55823d7e8", name: "SAND ARMOR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "An extremely protective and dense layer of sand surrounds you and takes on the same texture and color of your clothes, skin and item blending in with your clothing perfectly. For the duration of this jutsu you gain 20 Temporary hit Points. While you have these temporary hit points you gain resistance to Bludgeoning, Piercing, and Slashing, Cold and Earth damage as the sand protects you. Lightning damage bypass the Temporary hit points granted by this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Temporary Hit points by 15. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "d96ef5a71439e0681e470ef1", name: "SAND COFFIN BINDING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "15 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "concentration, up to 1 minute", description: "You call forth a collection of sand, dust and pebbles to surround and capture a creature you can see within range in order to crush it. The target creature must make a Dexterity saving throw. On a failure, target creature is stunned and held 5 feet off the ground by this jutsu. They are surrounded by a mass of sand, dust and pebbles. Damage done to them from sources other than this jutsu are reduced by half. As an action, on a following turn after capturing a creature in this jutsu, the user may compress a captured creature crushing them dealing 5d12 earth damage. At the end of a captured creatures turns they makes a Strength saving throw check vs your save dc to escape regardless of being stunned.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d12 respectively EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c5e137efa34dd585ceb98062", name: "SANDSTORM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You conjure a powerful localized spiraling vortex of earth, dust and sand around Quake Shards. This localized storm is 10 feet wide and 15 feet tall. You can select one Quake Shard you can see in range. Creatures who begin their turn within the storms area, excluding the construct, must make a Strength saving throw taking 4d6 earth damage and being knocked prone on a failed save. A creature in the radius of 2 or more storms is only affected by one at a time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 or the number of constructs you can target to conjure the storm around. 58 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b821d0edc1a0b157c0973bf3", name: "TECTONIC WAVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "Self (25-foot cone)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Round", description: "You clap your hands with the force of colliding tectonic plates as your release a surge of Earth Release chakra into the air itself creating a cluster of floating crystalline earth satellites that then explode. At random. All creatures within range must make a Strength saving throw. On a failed save a creature roll 1d4+2 Recording the result. They take the result times your ninjutsu ability modifier in earth damage and are bruised. On a successful save, they take half damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the die creatures roll on a failed save by 1 step. (d4>d6>d8>d10>d12). EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "796f35da4ee19d4eeba08b9c", name: "TERRASHIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["doton"], casting_time: "1 Reaction, which you take when you or another creature you can see in range would take damage.", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 Round", description: "You slam your open palm onto the ground creating a 10-foot tall, 5 foot wide and 1-foot-thick stone wall directly in front of the creature you are protecting granting them total cover. This wall acts as an Quake Shard occupying a space of your choice within 5 feet of the target, appearing right before an attack or jutsu would hit or harm them. It has 5d6+5 Hit points, 4 DR vs all sources of damage excluding Lightning, resistance to bludgeoning, piercing, slashing and cold damage and vulnerability to lightning damage. If the damage the wall receives would exceed its hit points, when you initially conjure, the original target take any remaining damage as normal and the wall is destroyed. The wall acts as a structure otherwise. It does not dissolve or vanish instead remaining until destroyed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the hit points of the wall by 1d6+1 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c78e0485c8ee1b28869c8a91", name: "TURNING PALM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Bonus action", range: "Self (45-Foot Cube)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You place your palm onto any surface of earth and cause the earth to splinter, break, and shift. The surface you placed your hand on is now considered difficult terrain and cannot be fixed unless this same ninjutsu is used on the affected space to reverse the effect. If The surface of earth you are targeting is less than 10 feet thick, when the ground is shifted it may collapse into the open space, causing all standing on it to fall with it. Additionally, if a Ninjutsu with the earth release keyword is cast within the splintered area, creatures who would make a saving throw to resist the jutsu’s effects, suffers a 1d4 penalty to their saving throws. B-RANK: EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "67b691427766c58bf9b953c7", name: "ANTLION COLLAPSE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "60 feet (20-Foot Cube)", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You select a space you can see within range and cause the ground to collapse in and start to swirl sucking everything in a 20 ft cube towards the center to be crushed. Creatures caught in the radius and who would begin their turn in this jutsu’s radius, must make a Strength saving throw. A creature takes 5d8 Earth damage and gains 2 ranks bruised on a failed save and half as much on a success. While inside the radius of the jutsu the area is counted as difficult terrain. A creature cannot dash or gain the benefit of a bonus action while within this area.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 1d8. 59 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "299c1d1de0dea0900fe832a4", name: "BOTTOMLESS SWAMP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "120 Feet, (60 Foot Cube)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You select a space within range that you can see as a swamp-like pool begins to form as it fills a 60 ft Cube. This mud pool is difficult terrain, cannot be traversed using water walking techniques, and prevents creatures from dashing. Creatures caught in the radius when this jutsu is cast, enters the radius, or begins their turns there must make a Strength saving throw at the beginning of each of their turns for the duration. Each consecutive failure imposes additional penalties and effects on the target creature(s). On a success a creature remove one of the failure conditions in the reverse order they received them. • On the first failure, a creature is restrained as their feet have been sucked below the surface leaving their knees and above exposed. • On a second failed save, half of the creature's body is submerged and creatures restrained by this jutsu also automatically fail Dexterity saving throws. • On a third failed save, the creature is dragged below the surface. A creature pulled below the surface is counted as suffocating and can only survive a number of their turns equal to its Constitution modifier before it enters the dying condition. If this jutsu is ended, the surface of the Swamp hardens back into stone. They are no longer restrained but they are still in a thick swamp, suffocating. If this jutsu is ended, creatures trapped in the swamp are pushed to the surface and released as the ground gradually reforms to its original consistency and form. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a28c596113b81605208d42d3", name: "CALCITE: POWER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "aaeecd12fb6a8f889a26ab97"], elements: ["doton"], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create a surge of Earth Release Chakra and use it to amplify a willing creature you can reach within range. Once successfully cast, you do not need to see where the target is and must remain within 120 feet of them. Jutsu the target creature casts becomes amplified by your Earth Release Chakra. Jutsu, they cast for the duration deals an additional 3d8 Earth Damage once per turn, Clashes made with their jutsu cannot be made at disadvantage, and the Save DC for the jutsu they cast increase by +2. Additionally, if the target attempts to cast a Jutsu with the Earth Release keyword, reduce the cost of their jutsu by 2.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at S-Rank increase the bonus damage by 1d8. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "dfa84c74ab35859fc23b2f08", name: "CRADLE OF JADE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "aaeecd12fb6a8f889a26ab97", "fef9deb945f95aa08666590c"], elements: ["doton"], casting_time: "1 Reaction, which you take, when a creature other than yourself, that you can see within range would take damage.", range: "30 Feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "1 Round", description: "You surround a creature you can see within range with Earth Release Chakra in an attempt to protect them. When a you or a creature you can see within range would take damage, you can spend your reaction encasing them in chakra that quickly solidifies as Crystalline Jade right before impact. The Crystalline jade reduces the incoming damage by 10d6. The Crystalline jade has resistance to Cold Damage, and Vulnerability to Lightning Damage. The Crystalline jade then dissolves at the beginning of the affected creatures turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage reduction by 1d6. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "bd29fb0e0766ca8b32ba781c", name: "CRYSTALLIZATION: WEISS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "75 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "You create a cage of earth release chakra that you use in an attempt to trap and capture a target creature. Select one creature you can see within range. Target creature must make a Constitution saving throw at the beginning of each of their turns for the duration as you attempt to encase them into a shard of Crystal. A creature who fails 1 save begins to have crystal form across their body as they gain the Weakened condition. A creature who fails 2 saves begins to slow as their joints are overtaken by minerals, gaining the grappled Condition. A creature who fails 3 saves begins to be overtaken as they find it difficult to move gaining the restrained condition. A creature who fails 4 saves feels the crystals overtaking them as they gain the stunned condition. A creature who fails 5 saves becomes petrified for 24 hours. A creature who passes 3 saves immediately ends this Jutsu's effect on them and become immune to it for 24 hours. 60 EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bf1930dcdf3f012e289d3100", name: "EARTH PRISON DOME", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: ["doton"], casting_time: "1 Action", range: "20 Feet (10 Foot radius sphere)", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You create a dome of earth around a target or targets in a 10-foot sphere in front of you. Creatures in the targeted radius can make a Dexterity save. On a success, they can move half of their movement. On a failure, they do not get a chance to move. Creatures captured inside the dome begin to have their chakra drained at the beginning of each of their turns. Each creature reduces their current chakra by 2d10+ Your Ninjutsu ability modifier at the beginning of each of its turns. Half of the result is then transferred to the caster of this jutsu. The dome of earth has an AC equal to the users Ninjutsu Save DC and has 40 Hit Points and counts as an Quake Shard. The dome regains 2d8 Hit points at the start of each of your turns so long as it has more than 0 hit points. The Dome is Vulnerable to lightning Damage and resistant to cold damage. If the dome takes lightning damage, it does not regenerate hit points at the start of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the initial hit points by 10. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "38c9a6c8cc71ea2b07190603", name: "EARTH-STYLE WALL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["doton"], casting_time: "1 Action or 1 Reaction, which you take when you or another creature you can see in range would take damage.", range: "30 feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You convert chakra into earth and spit it from your mouth, or use earth that’s already present to quickly generate a large wall. The wall is 5 Feet Thick, 30 Feet Long and 25 Feet High and if the wall is generated within a creature's space, the creature is pushed to either side of the wall (Your choice). The wall can have any designs or shape you decide. The Walls AC is equal to your Ninjutsu Save DC, has 10d6+10 Hit Points, and 6 DR vs all sources of Damage, excluding lightning. This wall is vulnerable to Lightning Damage, resistant to bludgeoning, piercing, slashing and cold damage and counts as an Quake Shard.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the walls hit points by 1d6+1. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "af98731df7af7c6193f421d8", name: "IRON SKINNED SPEAR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "b3b9a80a8acefa31d6905369"], elements: ["doton"], casting_time: "1 Action", range: "5 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You focus Earth Release chakra throughout one of your limbs until it darkens into a dark brown hue and gains the texture of solid stone. You then use this darkened ligament to strike at a creature with enough force to tear through almost anything. Make a melee ninjutsu attack against a creature within range. On a hit, you deal 10d6 Earth damage and marking the creature with a mark of petrification. A creature marked this way makes Constitution saving throws at the beginning of each of their turns for the next minute. On a failure its skin begins to harden at the point of impact as their body begins to petrify. If the creature fails this saving throw three times their body fully hardens as they become petrified turning fully into stone for the next 24 hours. If the target creature succeeds 3 saves they reject the earth chakra from their body ending the effects of this jutsu. If this jutsu is used on a creature previously affected by this jutsu within 24 hours, they make each saving throw at advantage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the walls hit points by 1d6. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "825735b5b8808b6f26b832ca", name: "LAPIS DOMINION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: ["doton"], casting_time: "1 Action", range: "Self (90-foot cube)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You release earth release chakra from your body touching everything within a 90-foot cube originating from you. For the duration, you do not need to spend chakra to maintain this jutsu. When you cast this jutsu you erect walls of Lapis made of Earth Release chakra 30 feet high and 10 feet thick on the outside edges of this jutsu’s range. These walls have an AC equal to your Ninjutsu save DC and a number of hit points equal to 10 times your proficiency bonus. Earth Release Jutsu you cast while within your jutsu’s radius cost 2 less to cast and 1 less to maintain. When you cast this jutsu, select a number of creatures within your jutsu’s range. Those creatures are immune to this jutsu effects. All other creatures who begin their turns in your jutsu range or enter your Jutsu's range for the first time must make a Strength saving throw. On a failed Strength saving throw the target is affected by the monumental weight your chakra enforces on the area and gains 1 rank of weakened and become unable to maintain concentration on a Jutsu that does not have the Earth Release Keyword until the end of their next turn. 61 EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ac913cbeddffc31c4bbccc24", name: "LAZULI TUSK", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: ["doton"], casting_time: "1 Action", range: "80 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You generate an Quake Shard in the form of some tusked or horned creature of your description and manipulate it to ram into a target creature of your choice within range. Make a Melee Ninjutsu Attack against a target creature within range, as the Quake Shard attempts to ram the target. On a hit, you deal 3d10 Piercing damage and 3d10 Earth Damage. Once this jutsu ends, the Quake Shard stands in place occupying a 5-foot cube. The construct weighs 500 pounds, and can be used as partial cover. It counts as an Quake Shard of your creation while remaining as a part of the environment until destroyed or otherwise moved.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of Quake Shards you summon. Each Quake Shard must target a different creature. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0bf88efbee2941b9bddfdb33", name: "MAUSOLEUM DUMPLING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "60 Feet (20-Foot Cube)", chakra_cost: "11 Chakra", components: "HS, CM, M", duration: "Instant", description: "Using Chakra to enhance your physical Strength and to lighten the earth around you, you are able to lift a massive volume of earth, large enough to cast a great shadow over multiple adversaries. You throw the Large chunk of stone at a space you can see within 60 Feet. The chunk of stone then regains its weight falling at greater velocity and creating a greater impact. Creatures in the 20-foot cube that the stone chunk falls in must make a Strength saving throw, taking 8d6 earth damage and gaining 2 ranks of bruised on a failure, and half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 1d6 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "af2ed489c22fe8d749a2c927", name: "SANDWICH TECHNIQUE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "90 feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure two massive constructs of earth of your design and description that is large in size on either side of a single creature you can see in range and slam them into one another with the creature in the middle. Target creature and all creatures within 5 feet of them must make a Strength saving throw being crushed and taking 6d6 earth damage and being bruised on a failed save or half as much on a successful one. The Constructs of Stone remain as Quake Shards.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "15683ca6aa10d3f6bd370540", name: "STONE BAMBOO SHOOT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: ["doton"], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure 4 reinforced spears of earth that all converge on a single creature you can see within range from 4 different points surround the target creature. Make a Ninjutsu Attack on the target creature dealing 6d10 Earth damage as they attempt to skewer the target. A 20-foot radius cube centering on the target creature becomes difficult terrain and creatures cannot take the dash, dodge or disengage actions while within an area of difficult terrain created by this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4d01939cfb826658285eecf2", name: "UNPHASED ROCK", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: ["doton"], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "1 Minute", description: "You mark a single stone you are holding with chakra as you bind a piece of yourself to it for the duration. Select two Skill proficiencies or 1 Save Proficiency. This stone becomes imbued with that knowledge and experience, as you temporarily lose that proficiency for the duration or until you end this jutsu as a bonus action. A creature who is holding this stone with one hand gains these proficiencies for the duration. While holding this stone you cannot make handseals or use Chakra seals with the same hand holding the stone. 62 A-RANK: EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "902c7d68038d52bf4b567340", name: "ADDED/REDUCED WEIGHT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "5 Feet", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Concentration, Up 1 minute.", description: "You use your chakra to temporarily manipulate the weight of something you touch. Objects and structures, you touch increase in weight drastically, increasing 10 times in total weight. Objects and structures you touch that occupy a space no larger than a 60-foot cube, cannot handle the strain of their own weight and begin to shatter and break shattering into super heavy rubble. If used on an unwilling creature, make a Melee Ninjutsu attack on a creature. On a hit target creatures’ weight is doubled, gaining +15 bulk, and has their speed reduced to 0 feet. As an action on each of an affected creatures turn, they can make a Strength saving throw to end this Jutsu’s effect on them. If used on a willing creature, you reduce their weight to 0 as they gain a 60-foot flying speed. If flying in this way, you do not need to spend chakra to maintain concentration on this jutsu. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c591596bbbac1a25f6d7a8b3", name: "CALCITE: TENACITY", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "aaeecd12fb6a8f889a26ab97"], elements: ["doton"], casting_time: "1 Action", range: "Touch", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create a surge of Earth Release Chakra and use it to amplify a willing creature you can reach within range. Once successfully cast, you do not need to see where the target is and must remain within 120 feet of them. The target creature gains 4 DR and advantage on Strength & Constitution saving throws. If the target creature falls under a condition inflicted by a jutsu cast by a creature other than you, you may spend your reaction to immediately end the condition. Additionally, if the target creature falls to 0 hit points, you can as a reaction choose to instead heal them by an amount equal to 7d8 + 20 Hit points, when you do this jutsu immediately ends. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "729e03e377ebbb65c8879ae1", name: "CRYSTAL ARCANUM", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: ["doton"], casting_time: "1 Action", range: "30 feet", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You create a field of potent Earth Release Chakra that permeates through you and a number of Quake Shards of your choice within range 30 feet of you. Select creatures of your choice within 30 feet of yourself or an Quake Shard affected by this jutsu, gain a layer of earth release chakra that solidifies into the shape of armor of your description. Select creatures gains Temporary Hit Points equal to three times your Ninjutsu Save DC. The temporary hit points you grant them has Immunity to Cold Damage, resistance to Bludgeoning, Piercing, Slashing and Vulnerability to Lightning damage. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a630c5ba30a1c909f22f0ea1", name: "GRAVITY BREAK", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "100 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You focus a large amount of chakra into a 50 wide and 100-foot-high cylinder centered on a point within range. All creatures and objects that aren’t somehow anchored to the ground in the area begin to fall upward and reach the top of the area when you cast this ninjutsu. A creature can make a Strength saving throw to grab onto a fixed object it can reach or anchor themselves to the ground using a weapon to stab into the ground or wedge themselves into place, thus avoiding the fall. If a creature prevents themselves from falling by using a weapon they must make Strength saving throws at the beginning of each of their turns, falling on a failure. If a solid object (Such as a ceiling) is encountered in this fall, falling objects and creatures strike it just as they would during a normal downward fall. If an object or creature reaches the top of the area without striking anything, it remains there, oscillating slightly, for the duration. At the end of the duration, affected objects and creatures fall back down. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7a1cd4532e36ff951c96c4bb", name: "IRONSTONE HARDENING", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "15 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You encase your body in stone armor as hard as iron. You cannot lose concentration on this jutsu as a result of damage. Additionally, reduce all incoming damage done to you, excluding Lightning, by 10.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3. Increase the amount of damage you reduce by 5. 63 EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7ff9b29099751907357cce37", name: "JADE FOREST", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131", "9991cc726431e53e17c4a8fa"], elements: ["doton"], casting_time: "1 Action", range: "Self (120-foot sphere)", chakra_cost: "Special (110 Chakra)", components: "HS, CM, CS", duration: "Instant", description: "You create a gargantuan sized sealing circle of made of earth release chakra that ingrains itself into the earth itself in a massive cube originating from you. Stalagmites made of stone, jade and lapis erupts from the ground forcing all creatures of your choice within range to make a Strength, Dexterity and Constitution saving throw. On a failed Strength Saving throw creatures are unable to avoid being thrown around and keeping their footing in this newly forming environment gaining 5 ranks of the bruised condition and being knocked prone. On a failed Dexterity save, creatures are unable to avoid being stabbed, crushed, or struck with newly erupted stone, jade and lapis taking 7d10 piercing and 7d10 earth damage on a failed save or half as much on a successful save. A creature who fails this save by 10 or more takes maximum damage. On a failed Constitution saving throw, some of your Earth Release chakra infiltrates a creature’s body inflicting the Poisoned Condition for the next minute. After casting, this area becomes difficult terrain and counts as a single Quake Shard. A creature cannot see further than 10 feet in front of them. This forest of Stone Jade and Lapis remains until destroyed or 1 year has passed. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters you reduce the cost of this jutsu by 2 for each Caster. Any creature who assists in casting this jutsu as a combination modifies its effects based on the highest Charisma Modifier within the group of casters. (+0-2: No Change, +3-4: Disadvantage on Strength Saving throws, +4: Disadvantage on Strength & Constitution Saving throws, +5: Disadvantage on All Saving throws). EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "40dbef896b3529850a706843", name: "STARFALL WAKE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: ["doton"], casting_time: "1 Full Turn Action", range: "300 Feet", chakra_cost: "18 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You manifest a series of shimmering shards of earth 300 feet in the air that floats above you for the duration. As an Action, Bonus Action, or Reaction you can call down these shard to bombard a space you can see within range. A creatures within 10 feet of the selected space must make a Dexterity saving throw taking 9d8 Earth damage on a failed save or half as much on a successful one. A creature who would make a second saving throws in the same turn as the result of this jutsu instead would take 9d6 Earth damage on a failed save or half as much on a successful one. A creature who would make a third saving throws in the same turn as the result of this jutsu instead would take 9d4 Earth damage on a failed save or half as much on a successful one. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "44497514783fbfb185d9171e", name: "STONE DRAGON", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a giant Stone construct made of earth, dust, soil, and sand forming a Large Dragon that you can command as a bonus action. It acts at the end of your turn and uses your Ninjutsu attack bonus and Save DC when an effect calls for it.", at_higher_ranks: "For each rank you cast this jutsu above A- Rank, increase the cost of this jutsu by 3 and the dragons hit points by 20", created_at: NOW, updated_at: NOW },
  { _id: "78e924051e9f43efce55dede", name: "STONE FOREST", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Self (30 Foot Cube)", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You focus a large amount of chakra into the palms of your hands and place them on the ground. You create a field of spiked earth in a 30-foot cube originating from you. Creatures of your choice caught in range must make a Dexterity saving throw, taking 10d8 Earth Damage on a failed save, and half on a successful one. The area that was affected by the jutsu is now plagued by massive Stone spikes that reach as high as 10 feet and criss cross into a forest of spikes making it difficult terrain to traverse. Creatures inside the affected area roll at disadvantage when making Wisdom checks to perceive something. The affected area counts as a Single Quake Shard.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "63f2d86644f1b85a84b334dc", name: "STONE NEEDLE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "90 Feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You focus a large amount of chakra into a single thin but incredibly fast spear of earth that’s 90 feet long and 5 feet wide. Creatures in range must make a Dexterity saving throw taking 9d10 earth damage gaining 4 ranks of bruised and knocked prone on a failed save, or half as much damage and no further effects on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. S-RANK: EARTH RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7fe716a87ca8f09ff3cca6b8", name: "DIAMOND BONE HARDENING", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Self", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You use your mastery over chakra and Earth release to transform your bones into material simulating diamonds in toughness and weight, while also gaining some control over how they move and the speed at which they regenerate. For the duration, you regenerate 20 hit points at the beginning of each of your turns and gain Resistance to all damage excluding Lightning. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "84eb820a31be0ebbe35fb66d", name: "METEOR FALL", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: ["doton"], casting_time: "1 Action", range: "1 Mile", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Instant", description: "Upon completion you select 4 different points you can see within range. Each creature in a 30- foot radius sphere centered on the point you select must make a Dexterity Saving Throw against your Ninjutsu Save DC. Massive Chunks of stone earth and mud comes raining upon the selected areas. A creature takes 10d10 Bludgeoning & 10d10 Earth Damage and is Dazed and knocked Prone on a failed save, or half as much damage on a successful one. A creature can only be affected by one meteor per casting. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7a110a9c44916905dd732fda", name: "MOON FALL", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "b3b9a80a8acefa31d6905369"], elements: ["doton"], casting_time: "1 Full Turn Action", range: "1 Mile", chakra_cost: "Special", components: "HS, CM", duration: "Special", description: "Upon Competition of your Jutsu's handsigns you manifest a single super huge Quake Shard 1 mile in the air. Spend chakra in multiples of 35 up to twice. For every 35 chakra spent this way, the Gargantuan Moon like structure you manifest grows in size and affects a larger area when dropped. You cannot reduce the cost of this jutsu by any means. 35 Chakra: The Moon like structure falls on a point you can see within range crushing a space equal to a 30- foot sphere. Each creature who are within the 30-foot sphere and has a way to escape the radius be it by their base movement speed or a jutsu they could cast as a bonus action, makes a Dexterity saving throw. On a successful save, they are able to use their movement or a jutsu which could allow them to escape the sphere. On a failed save they take 22d12 earth damage. All creatures who are within 30 feet of the sphere, including creatures who succeeded the previous saving throw must make a Strength saving throw as the shockwave from such a massive impact deals significant damage to the area. A creature takes 12d6 Bludgeoning & 12d6 Earth Damage on a failed save or half as much damage on a successful one. 70 Chakra: The Moon like structure falls on a point you can see within range crushing a space equal to a 60- foot sphere. Each creature who are within the 60-foot sphere and has a way to escape the radius be it by their base movement speed or a jutsu they could cast as a bonus action, makes a Dexterity saving throw. On a successful save, they are able to use their movement or a jutsu which could allow them to escape the sphere. On a failed save they take 30d12 earth damage. All creatures who are within 50 feet of the sphere, including creatures who succeeded the previous saving throw must make a Strength saving throw as the shockwave from such a massive impact deals significant damage to the area. A creature takes 15d6 Bludgeoning & 15d6 Earth Damage on a failed save or half as much damage on a successful one. 65 EARTH RELEASE: PARTIAL ASSIMILATION", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bd89afea941153182b4fe6a2", name: "CYLINDER", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Self (25 feet)", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "When you cast this Jutsu, and as an Action on following turns for its duration you can form a cylinder 10 Feet in diameter and 25 feet long by using chakra to generate molecule sized earth particles. Anyone in the cylinder will begin to be deconstructed on a molecular level. Creatures that start their turn within this cylinder must make a Dexterity Saving Throw. On a failure a creature takes 14d10 Force Damage. If a creature is reduced to less than ½ of their hit points by this damage the user decides on which appendage the target creature lost. (Arm or Leg). If a creature is reduced to 0 Hit Points, they are turned to dust and are immediately killed. EARTH RELEASE: PARTICLE ASSIMILATION", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f49861bf00b8269d7be924c", name: "CUBE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: ["doton"], casting_time: "1 Action", range: "Touch", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Instant", description: "You form a cube 5 Feet in diameter by using chakra to generate molecule sized earth particles. The Cube glows white. You can throw the cube up to 30 feet or attempt to hit someone with it. Anyone hit by the cube will begin to be deconstructed on a molecular level. Make a melee or ranged Ninjutsu Attack. On a hit a creature takes 16d12 Force Damage. If a creature is reduced to less than ½ of their hit points by this damage, the user decides on which appendage the target creature lost. (Arm or Leg). If a creature is reduced to 0 hit points, they are turned to dust and are immediately killed. EARTH RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1f58a72f7de4560facd4981b", name: "STAR SHATTER", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "b3b9a80a8acefa31d6905369"], elements: ["doton"], casting_time: "1 Full Turn Action", range: "1 Mile", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create a single star shaped Quake Shard in the sky, 1 mile in the air before you cause it to shatter. Select a space you can see within range. All creatures of your choice within 120 feet of the selected space must make a Strength saving throw as the weight of a dying star is thrust upon them. On a failed save they are Stunned and knocked Prone as they become unable to move and find it hard to even breathe. A creature who begins their turn in this space, ends their turn in this space, or enters this space for the first time must make the Strength saving throw. A creature Stunned by this jutsu takes 9d8 Earth damage at the beginning of their turn. A creature Stunned by this jutsu takes 9d8 Earth damage at the end of their turns if they do not make the saving throw to end this jutsu’s effects. A stunned creature makes a Strength Saving Throw at the end of their turns (They do not automatically fail as a result of being Stunned). On a successful save, they end the Stunned condition on themselves. 66 WIND RELEASE Wind Release is the rarest of the five nature transformations, but those who can use it are able to cut through anything. Some shinobi use it by channeling wind chakra into weapons, making the blades far sharper and giving them greater reach. Wind Release can also be exhaled from the user's mouth, such as to blow away everything in the area, or generated with the user's hands, allowing precision strikes. Although Wind Release has naturally good range and power, it can be further enhanced by compressing it or layering different wind streams together. Wind Release can easily launch particles into the air, whether to create dust clouds that conceal the user's movements or sand storms that perforate targets. Wind Release is naturally strong against Lightning Release and weak against Fire Release Special Effect: Some Wind release jutsu will mention that they cause Swirl, when this happens, Creatures who would fail their saving throw, spreads all Elemental conditions currently affecting them around to all creatures, excluding the caster within 5 feet of them. Creatures hostile to the caster within 5 feet of the failing one gains 1 rank of all elemental conditions currently aff ecting it. Prerequisite: You must have the Wind Release Affinity to learn jutsu with the Wind Release Keyword. D-RANK: WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b0d2cdd68ba22e86b72c1a45", name: "AIR BULLET", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "60-feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a small sphere of compressed air in the palm of your hand before launching it at a target creature that you can see within range. You fire two bullets of air. You can direct the bullets at the same target or different ones. Make two ranged ninjutsu attack, dealing 2d8 wind damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of attacks by +1. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "33e0c90919307cd1388b0fa0", name: "AIR CURRENT DANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Bonus Action", range: "Self (10 Foot radius Sphere)", chakra_cost: "3 Chakra", components: "HS, CM", duration: "1 Minute", description: "You whip air currents around your hands and generate a dust cloud cloaking yourself and anyone in the radius of this jutsu in a thick cloud of dust and debris. All creatures are treated as if they have total cover while inside the cloud, from creatures outside the cloud and vice versa. This total cover does not prevent attacks or jutsu from entering or exiting the cloud. Creatures other than you have disadvantage on perception checks to see through the cloud if they have special vision like Chakra Sight. Also, creatures other than you, vision, is treated as if they are in dim light while inside the cloud. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "11fe9f5cf1e7eb3b6b7f446a", name: "BLURRING WIND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Reaction, which you take when you would take damage", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 Round", description: "Your body becomes blurred, shifting and wavering to all who can see you. When cast, the triggering attack rolls an additional d20, taking the lower result. For the duration, until the beginning of your next turn, hostile creatures have disadvantage on attacks against you. An attacker is immune to this effect if it doesn't rely on sight, as with blindsight, or can see through illusions, as with truesight. 67 WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0a0f2532758a63dca02c123b", name: "BUFFETING AIRWAVES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You create currents of extremely strong and compressed beams of air strong enough to Crack stone and divert waterfalls. Make a ranged ninjutsu attack. On a hit, target creature takes 4d4 Wind Damage and must make a Strength save. On a failed save they are pushed back 20 feet, knocked prone, gaining 1 rank of bleeding, and causing Swirl.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d4 and the ranks of bleed by +1 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "68d7aba12a27bf2ddf78d599", name: "COLLECTIVE GALE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["futon"], casting_time: "1 Action", range: "15 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minutes", description: "You collect wind release chakra and infuse it into your Medical Release technique. One willing creature within range breathes in this Medically infused wind. For the duration a creature who has breathed this wind does not need to breathe, Ignores the effects of 2 rank of Exhaustion and when they would regain hit points as the result of a Ninjutsu with the Medical Keyword, they regain an additional 1d4 Hit points.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, Ignores the effects of up to 1 additional rank of Exhaustion. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "20cea3ec81e2851e00c0e724", name: "COUNTER BREEZE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Reaction, which you take when you would take damage from a Ninjutsu or Taijutsu", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "1 Round", description: "You create a condensed bubble of super dense air around you in an attempt to deflect incoming attacks. Roll 3d8. The result of the roll is the amount of damage your air Bubble can prevent before it bursts. This lasts until the beginning of your next turn. Lightning Damage deals half as much damage to your air bubble and Fire Damage deals twice as much.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and roll an additional 1d8. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b704896846174406a8192c70", name: "DUST WIND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (15-foot Cone)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a strong wind from your lungs with a single breath. When you exhale you kick up a cloud of dust, dirt, and other loose debris in the target radius. Creatures who are in the affected range must make a Wisdom Saving throw. On a failed save, affected creatures cause Swirl and are considered blind until the end of their next turn on a failed save. On a successful save no further effects are applied.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 10ft WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "528f4345e03134b2d401399e", name: "FEATHER FALL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Reaction, which you take when you begin falling", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 Minute", description: "You create a single high-pressure stream of air from either your hands or feet slowing your descent while falling by 60 feet per round until the jutsu ends. If you land before the ninjutsu ends, you take no falling damage and land on your feet and the jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select 1 additional target for this Jutsu’s benefits within 30 feet of you. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "11872dd1556de07690ec2293", name: "GALE PALM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "HS, CM, M", duration: "Instant", description: "You clasp your hands together coating your open palms in a powerful gale. You make a Melee ninjutsu attack on a target creature or object. On a hit creature take 3d6 Wind Damage and make a Strength saving throw to resist being knocked back 20 feet and causing Swirl. On a successful Strength save they suffer no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 68 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ecd5375db0d1bf637cb1f7e6", name: "GRYPHONS WING BEAT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (20-foot radius)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You create two wings made of wind release chakra that beats with enough force to feel like a tornado is passing through. All creatures within range must make a Strength saving throw to resist being bruised, knocked prone and causing Swirl. A creature who is bruised finds it difficult to maintain concentrating on multiple jutsu. If a creature is concentrating on more than 1 jutsu, they must lose concentration on all but 1 jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the range by 10 feet. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9e145bc6e6655318b209e773", name: "LIONS GROWL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You weave Wind Release Chakra together, creating a thin veil of chakra in the shape of a Lion around you. This chakra then collapses on you granting you benefits as listed below; • Increase your Movement Speed by 15 feet. • You gain a +2 bonus to Ninjutsu Attack Rolls. • Ninjutsu, you cast with the Wind Release Keyword that has a range of at least 5 feet, increases their range by 10 feet. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a77081e1b9e715df25e91daa", name: "PALM VORTEX", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (10 Foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a localized vortex of cutting wind. All creatures within range must make a Dexterity saving throw to avoid being horrendously slashed. On a failed save creatures take 3d6 wind damage and being pulled 5 feet closer to you or half as much on a successful save and no additional affects. If a creature is currently affected by any elemental condition, you trigger the residual elemental energies, igniting them again. A creature under the effects of an elemental condition makes their saving throw at Disadvantage. On a failed save such a creature instead takes 3d8 + Your Ninjutsu Ability Modifier damage, of their select conditions type.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 or 1d8. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9a31f80e3136e0fa8f571be7", name: "PASSING TYPHOON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (15-foot radius sphere)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You create a powerful current of strong winds in a 15-foot radius sphere, centering on you. This field of wind also follows you. For the duration, while within its area, it deafens other creatures, extinguishes unprotected flames, becomes difficult terrain to creatures other than you and disperses vapors, gases and fogs that can be dispersed by strong winds. Additionally, ranged attacks have disadvantage if they pass into or out of the area of this jutsu. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d5d0d03cf0924ddcd14c41e6", name: "PEACOCK WHIRLWIND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "30-feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a strong wind from swiping one of your limbs. A gust of wind is generated in a 30-foot long 5-feet wide in a straight line originating from you. Creatures in the line must make a Strength saving throw, taking 2d6 wind damage, is knocked prone, gains 1 rank of bleeding and causing Swirl on a failed save, and only half damage and no further effects on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the ranks of bleed by +1. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "83d713fce9e3beb6c0796239", name: "RAGING GALE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "60 feet (15-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a powerful torrent of wind, strong enough to lift and throw most creatures. Select a space you can see within range. A spiraling torrent of wind erupts upwards. All creatures within 15 feet of the chosen space, must make a Strength saving throw. On a failed save they are thrown 30 feet upwards being dazed, taking falling damage, falling prone and causing Swirl.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the height they are thrown upwards by 15 feet. 69 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7bae5771e7445c82e600cade", name: "RAGING VORTEX", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You encircle a willing creature with potent Wind Release Chakra. For the duration, you magnify the targets physical capabilities. The target creature adds 1d4 to all Strength and Dexterity skill checks and saving throws. Their movement speed is increased by 15 feet and melee attacks they make that deal damage deals an additional 1d6 Wind Damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets you can affect by +1. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "3d3bb1023decfd9b8d2e9a7b", name: "SECOND WIND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You breathe in deeply filling your lungs and blood with chakra filtered oxygen accelerating its blood flow and slightly rejuvenating you. You recover 2d6+ Your Ninjutsu ability modifier hit points.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and roll an additional 1d6. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0af24f7d6444ff9c2a47f0fa", name: "SLICING AIRWAVES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM, M", duration: "Instant", description: "You create a powerful current of extremely strong and thin currents of wind. You swipe your hand towards your target. Make a Ranged Ninjutsu attack, creatures take 3d8 wind damage and gain 1 rank of bleeding on a hit.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d8 and ranks of bleeding by +1. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ae7b2c185b37435335f96ea3", name: "SPLITTING GALE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "90 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create a field of oppressive and potent wind that slashes and buffets any instance of Hand Signs (HS). Select a space you can see within range, all creatures within 20 feet of the chosen space who would cast a jutsu with Hand Sign (HS) component immediately takes 2d6 Wind Damage and must make a Constitution Saving throw gaining the bleeding condition on a failed save. As a bonus action on your turn, you may move the field up to 30 feet in any direction to a space you can see within range.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the area affected by 5 feet, and the damage by 1d6. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "cd0b7b0e76b3a59d303953f3", name: "SUPPORTING GALE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Reaction to making a Strength, Dexterity, or Constitution saving throw", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You throw your hands forward creating a compressed blast of air assisting you in a variety of physical tasks; from escaping, fending off an attack, or dispersing a hazardous gas. As a reaction, when you are forced to make a Strength, Dexterity, or Constitution saving throw against a Ninjutsu or Taijutsu, you instead use your Ninjutsu ability modifier in place of your Strength, Dexterity or Constitution for the triggering roll.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at C-Rank you add your proficiency to the roll if you aren’t already proficient. If cast at B-Rank you may select another creature within 20 feet of you to gain the benefits of this jutsu, using your Ability modifier and proficiency bonus. If cast at A-Rank, creatures benefiting from this jutsu roll at advantage. If cast at S- Rank, all creatures of your choice within 30 feet of you can gain this jutsu’s benefit. 70 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b8332e13ace2b87832d1347a", name: "VACUUM BOMB", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "Special", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a single point of high-density air pressure using your Wind Release Chakra before expanding it and creating a series of reactions. All creatures currently affected by an elemental condition who would have a jutsu cast on them that triggers the swirl effect, potentially passes all such conditions around to other creatures near them in an expanded space with more volatility. When a creature would have the Swirl effect trigger on them, you can cast this jutsu as a part of the same action. All creatures within 20 feet of the triggering creature who failed their save gains two ranks of all elemental conditions the triggering creature had.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the area affected by 5 feet. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9b8bba09f4547b5cf4b08e52", name: "VACUUM RAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: ["futon"], casting_time: "1 Action", range: "90 feet (20-foot cylinder)", chakra_cost: "Special (28 Chakra)", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You create a powerful updraft that sucks the oxygen and air upwards robbing creatures of the ability to breathe within range. All casters of this jutsu create a 60-foot tall, 20-foot-wide cylinder that removes all air from inside of it replacing it with furiously rotating blade of Wind Release Chakra, centered on a point of your choice within range. All creatures within the cylinder must make a Dexterity and Constitution saving throw. On a failed Dexterity save they are slashed with wind chakra repeatedly taking 2d6 Slashing Damage and 2d6 Wind Damage or half as much on a successful save. A creature makes this saving throw the beginning of each turn they begin within this cylinder. On a failed Constitution Saving throw they are robbed of their air in their lungs as they begin suffocating. A Suffocating creature can only survive a number of rounds equal to their Constitution modifier before passing out falling unconscious from the lack of air. A creature makes this saving throw at the beginning of each turn they begin within cylinder. An unconscious creature can regain consciousness when another creature spends an action waking them. Creatures inside the cylinder cannot gain the benefits of an increase to movement speed and are treated as if they are in difficult terrain. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 2d6 for each damage type. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the Height by +10 feet and radius to 30 feet, +3: Increase the Height by +20 feet and radius to 40 feet, +4: Increase the Height by +30 feet and radius to 50 feet, +5: Increase the Height by +40 feet and radius to 60 feet). WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "57a134e2b8ea409d86d53191", name: "VIOLENT WHIRLWIND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (30-Foot Cone)", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You exhale a powerful stream of wind from your mouth. Creatures caught in the target area must make a Strength Saving throw. Creatures take 2d6 Wind Damage, are pushed back 30 Feet, are knocked prone and cause Swirl on a failed save or half as much and no additional effects on a successful save. Also, vapors, gases and fogs that can be dispersed by strong winds are dispersed immediately.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. Increase the range of this jutsu by 10ft. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "5b6f61be06649ff6f138371d", name: "ZEPHYR STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "CM", duration: "1 minute", description: "You move like the wind. For the duration, your movement doesn’t provoke opportunity attacks. Your movement speed increases by 10 feet until the end of the turn you cast this jutsu. Also, once before the jutsu ends, you can give yourself advantage on one attack roll on your turn. On a hit, the attack deals an extra 2d8 wind damage and immediately ends this jutsu. 71 C-RANK: WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2b851712fa3340a3c6d7750c", name: "1,000 BLADES OF THE WIND", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "20 Foot Cone", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You create a spiraling sphere of wind chakra with a collection of cutting blades within it. Creatures in range must make a Strength Saving throw being pulled towards you and taking 4d6 Wind Damage and gaining 2 ranks of bleeding. Or half as much on a successful save and no ranks of bleeding. Creatures who fail their saving throw, are pulled towards you, ending their movement within 5 feet of you, and causing Swirl. They are then caught in a violent explosion of the cutting wind, being knocked back 20 feet and taking an additional 2d6 Wind Damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the amount of initial bleed gained by +1. WIND RELEASE: BURSTING COMPRESSED", created_at: NOW, updated_at: NOW },
  { _id: "dfc26e0ea9518c1fb19f181c", name: "BURSTING COMPRESSED  AIR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "30-feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a spiraling vortex of wind chakra around a target creatures weapon. The target creature makes a Dexterity saving throw to avoid the collapse of the wind.   On a failed save they take 3d6 slashing damage as they are sliced for holding the weapon, and cause Swirl. If they continue to hold their weapon, they must make another save at the beginning of their next turn. On a successful save they take half damage. These additional saving throws do not cause Swirl.  After 3 failed saves the weapon they are holding can’t take any more damage and shatters sending weapon shrapnel haphazardly flying. Other Creatures within 10 feet of the exploding weapon taking 3d6 slashing damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f3761cc865c124ef132485c4", name: "GALE FISTS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM, M", duration: "Concentration, up to 1 minute", description: "You coat your hands and feet in a layer of highly compressed but highly reactive wind release chakra. For the duration of this jutsu, you may use your Ninjutsu ability Modifier in place of Strength for unarmed attack rolls. Your unarmed damage is treated as Wind for the duration of this jutsu and deals damage equal to 1d10 + Ninjutsu Ability Modifier.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the damage by 1d10. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c63456bec065c647c5fe6a62", name: "GREAT BREAKTHROUGH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "Self (60 Foot Line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You create a swirling vortex of air in front of you. You compress the air until the pressure explodes forward like a cannon in a straight line. Creatures in a 5- foot wide, 60-foot-long line must make a Strength saving throw. Creatures take 4d10 Wind damage, are thrown backwards 30 feet away, gain the dazed and prone conditions, and cause Swirl on a failed save. On a success they take half damage and no further effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase damage by 1d10 and knock back distance by 10ft. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2194b3b94eccffb48d1f9312", name: "LIONS ROAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (15-foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You weave Wind Release Chakra together, creating a potent veil of chakra in the shape of a Lion around you and allied creatures. This chakra then collapses on all creatures of your choice within range granting the benefits as listed below, for the duration; • Bonus +20 Movement speed. • Ninjutsu, they cast with the Wind Release Keyword that has a range of at least 5 feet, increases their range by 10 feet, and deals an additional 1d8 Wind Damage, once per turn. • Taijutsu, they cast that has a range of touch, or 5 feet, increases their range by 10 feet, and deals an additional 1d8 Wind Damage, once per turn. 72 WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7c532a6cd7543b62ecc8751a", name: "PRESSURE SHOCKWAVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Reaction, which you take when an allied casts a jutsu", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "When you see another allied creature cast another jutsu, you create a tornado like mass that is compressed until it has a high density before being released as a shockwave, intended to boost their jutsu’s effects. If the triggering jutsu does not have a nature release keyword, the allied creature makes their attack roll at advantage or one hostile creature of your choice within range makes their saving throw at disadvantage. If the triggering jutsu has a nature release keyword, then all hostile creatures in a 60-foot cone, originating from you, must make a Strength saving throw or be pulled 15 feet towards your allied creature, take 5d6 wind damage, and causing Swirl on a failed save, or half as much and no further effect on a success. Additionally, it amplifies the triggering jutsu based on its nature release; • Earth Release: On a failed save target cannot take reactions. • Wind Release: On a failed save target gains 2 ranks of bleeding. • Fire Release: On a failed save the triggering jutsu increases its damage die by 1 step. • Water Release: On a failed save the target gains 1 rank of chilled. • Lightning Release: On a failed save the target gains 1 rank of shocked.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "33d715cdab97c042ac63fc10", name: "RAKSHASA BARRIER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "fef9deb945f95aa08666590c"], elements: ["futon"], casting_time: "1 Reaction, which you take when you would take Earth, Fire, Cold, or Lightning Damage", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Round", description: "You raise your hand and generate an intensely dense torrent of wind that circles around you, creating a bubble of wind that envelops your entire body. The bubble of wind that envelops you has a number of hit points equal to your Proficiency bonus times your Ninjutsu ability Modifier. This bubble has Resistance to Wind and Lightning Damage and vulnerability to Fire Damage. If this jutsu would trigger an additional effect as listed below, as a result of a different damage type, creatures in the effects range must make a Dexterity saving throw to avoid its effects. • If the bubble would take fire damage, all creatures within 15 feet of you must make a saving throw becoming burned on a failed save as the fire spreads around you from your rotating bubble of wind. • If the bubble would take Lightning damage, all creatures within 15 feet of you must make a saving throw becoming shocked on a failed save, as lightning jumps from you to other creatures around you. • If the bubble would take Cold damage, all creatures within 15 feet of you must make a saving throw becoming chilled on a failed save, as the cold is spread to all creatures around you. • If the bubble would take Earth damage, all creatures within 15 feet of you must make a saving throw, gaining the bleeding condition on a failed save, as they are pelted with shrapnel of earth.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the size of the area affected by 5 feet, and the number of hit points your bubble has by +10. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "d9bf7ba51eeec0c437ba28e2", name: "RECOVERING BREEZE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["futon"], casting_time: "1 Action", range: "Self (30-foot-cone)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You create a field of medical chakra infused wind release chakra that pulses outward from you. All creatures of your choice within Range, excluding yourself, regains 5d6 hit points and removes the weakened & bruised conditions.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the amount healed by 1d6. 73", created_at: NOW, updated_at: NOW },
  { _id: "950df7674e8b905a0e638ac4", name: "ROTATING FEROCIOUS WIND", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Reaction, which you take when you cast another Ninjutsu with the Wind Release keyword", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You reinforce your Ninjutsu with additional buffeting gales of wind. Ninjutsu you cast with the Wind Release keyword prior to casting this gains a +2 bonus to its initial Saving throw DC.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "39516ed6d5b8c4c534e8670f", name: "SICKLE WEASEL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Reaction to taking damage from a melee attack or from a creature within range.", range: "Self (20-foot radius sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "When you take damage you are able to collapse the circling wind around you and the triggering creature causing the wind to collide with the hostile creature creating an extremely sharp blade of wind. All creatures within 20 feet of you makes a Strength saving throw taking 5d8 Wind damage, gain 1 rank of bleed and cause Swirl on a failed save or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the initial damage by 1d8. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "18d2bc66c087bb6046a638b6", name: "TEARING GALE PALM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "7 Chakra", components: "HS, CM, M", duration: "Instant", description: "You create a large claw of your design made of semi-solid compressed wind chakra. You can attack with it targeting a single creature up to 30 feet away. Make a Ranged Ninjutsu Attack. Target Creature takes 4d6 Wind damage and gains 2 ranks of bleeding on a hit.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "f4e63f73f1a2a3ec06e9414f", name: "VACUUM BARRIER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Reaction, which you take when you see a creature within range take damage", range: "60 feet.", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You create a swirling vortex of air in front of a creature you can see within range right before take damage. The compressed air compresses then explodes pushing attacks and other forces back, protecting the creature. Reduce the damage the target creature takes by 2d8+4. This Damage Reduction is doubled if the damage is Lightning Damage and halved if the damage is Fire Damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage reduced by 1d8. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "901a875fb573b38f9588ff66", name: "VACUUM FIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["futon"], casting_time: "1 Action.", range: "Self (30-foot Radius Sphere)", chakra_cost: "Special (50 Chakra)", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "You manifest a Seal of wind Release Chakra that glows in the air. The seal then triggers completely removing all evidence of Oxygen and atmosphere from a 30-foot radius sphere centering on you. You and all other casters are immune to this jutsu’s effects. All creatures who begin their turns in this jutsu’s range must make a Constitution Saving throw or begin immediately suffocating as they are robbed of their air in their lungs. A Suffocating creature can only survive a number of rounds equal to their Constitution modifier before passing out falling unconscious from the lack of air. An unconscious creature in this jutsu’s radius automatically takes 5d10 Necrotic Damage. A creature who’s hit points are reduced to 0 as a result of this jutsu lungs, heart and other internal organs explode while inside the body. Being unable to be revived without these organs being restored as well. An unconscious creature can regain consciousness when another creature spends an action waking them. Fire & Lightning cannot exist within this Vacuum Field and if fire or lightning, a jutsu with a Fire or Lightning Release Keyword that deals fire or lightning damage would attempt to enter this fields radius or affect a creature within this fields Radius it is immediately snuffed out and negated. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 2d10. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the radius by +10 feet, +3: Increase the radius by +15 feet, +4: Increase the radius by +20 feet, +5: Increase the radius by +30 feet). 74 WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d3148f68a3bbe19b5e1e729f", name: "VACUUM SHIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Reaction which you take when you or another creature within range would take damage", range: "Self (10-foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You create a swirling vortex of air in front of you. You compress the air until the pressure implodes on itself creating a shockwave blocking attacks and reducing the lethality of attacks in your immediate area. All allied creatures in this jutsu’s radius gain 20 Temporary Hit points from the oscillating flow of wind until the end of the current turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and temporary hit points by 5 and the radius by 5ft. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "38aca42f7ae44223ac680b20", name: "WALL OF WIND", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "120 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, 1 minute", description: "A wall of strong wind rises from the ground at a point you choose within range. You make the wall up to 50 feet long, 15 feet high, and 1 foot thick. You can shape the wall in any way you choose so long as it makes one continuous path along the ground. The wall lasts for the duration. When the wall appears, each creature within its area must make a Strength saving throw. A creature takes 4d8 Slashing damage on a failed save, or half as much damage on a successful one. The strong wind keeps fog, smoke, and other gases at bay. Small or smaller flying creatures or objects can't pass through the wall. Loose, lightweight materials brought into the wall fly upward. Arrows, bolts, and other ordinary projectiles launched at targets behind the wall are deflected upward and automatically miss. Large objects such as boulders and similar objects and attacks can penetrate it. Creatures in gaseous form can't pass through it. Fire ignites the Wall of wind leaving it as a massive wall of fire. If this happens the caster of Wall of wind loses all control of it and counts as the jutsu ending. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9769e30d96bb83816826f2e1", name: "WHIRLWIND MOVEMENT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Bonus Action", range: "60 Feet", chakra_cost: "6Chakra", components: "HS, CM, M", duration: "Instant", description: "You generate a massive amount of wind Chakra around your feet to make an incredible act of speed. You teleport to one space within 60 feet. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "45d8262ea850c1580130dabc", name: "WHIRLWIND SPEAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "Self (120-foot line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You mold a projection made of wind release chakra that floats next to you. This projection can take the shape of any spear or piercing like object such as an arrow, lance, sword or anything you prefer. You then launch this projection in a straight line, piercing through all creatures in a 5-foot wide, 120-foot lone line originating from you. All creatures in range must make a Dexterity Saving throw taking 5d6 wind Damage and causing Swirl on a failed Save or half as much on a successful one. The first creature your projection would pass through that has the burned, chilled, corroded, shocked or envenomed condition has that condition exacerbated. That creature takes 2d10 fire damage if they are burned, cold damage if they are chilled, acid damage if they are corroded, lightning damage if they are shocked or poison damage if they are envenomed. On a successful save no additional damage is done.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and 1d10. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "5e7228dd5530fb6c4a313d53", name: "WHIRLWIND THRUST", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "90 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You create an updraft of cycling wind release chakra that erupts from the ground under a group of creatures. Select a space within range. All creatures within 15 feet of the selected space must make a Strength saving throw. On a failed save, creatures are thrown 30 feet upwards into the air taking 3d10 wind damage and causing Swirl. If a creature cannot safely land, they take falling damage as normal. If the space this jutsu is casted overlaps with a source of Fire or Water additional effects happen. Fire: This Jutsu ignites and becomes a flaming whirlwind instead dealing 3d12 fire damage instead of 3d10 Wind Damage. Creatures must also succeed a Constitution saving throw gaining the burned condition on a failed save. Water: This jutsu becomes swirled with a powerful torrent of Water instead dealing 3d12 Cold damage instead of 3d10 Wind Damage. Creatures must also succeed a Constitution saving throw gaining the chilled condition on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10 or 1d12. 75 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "fcbf278b0c498a7858d5d6cc", name: "WIND FRICTION SHATTER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Bonus action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, 1 minute", description: "You coat a creature whom you touch body in a layer of spinning air. The air removes most friction from its body allowing them to move at breathtaking speeds, with little resistance. They gain +1 bonus to their AC, a +20 bonus to speed, advantage on Dexterity saving throws and they gain the Friction Break special action at the start of each of their turns for the duration. Friction Break. This special action can be used to either make one additional Weapon Attack, Disengage, or use an object action. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2c87ec01d0293887d97f9c80", name: "WIND RIDER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Minute", description: "You touch a willing creature you can see within range coating them in Wind Release Chakra. For the duration, the target creature gains a 30ft flying speed, but at the end of their turn they must be within 5 feet of the ground. The creature cannot suffer falling damage as they are always carried by the wind to a safe landing. Additionally, the creature is always floating at least 5 feet off the ground for the duration.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. Starting at A-rank, an affected creature no longer needs to end its turn within 5ft of the ground. B-RANK: WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "3d69edbc059c351638a25b42", name: "10,000 SLICING BLADES", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (30-Foot radius Sphere)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You create a dome of spinning wind, centering on you. The wind spins, whips and blows at 120 mph generating an innumerable number of blades made of wind chakra. These blades fly freely throughout your dome. Anything not weighted down is picked up and thrown around the dome and sliced to pieces. Creatures, excluding you, in this dome of wind when it is cast, who first enters or begins their turns within the dome, must make a Strength saving throw taking 5d10 Wind damage and are thrown 20ft in a random direction, fall prone, and cause Swirl on a failed save or half as much on a successful one. The area within the dome is counted as difficult terrain even for flying creatures.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e6cf3e3710fe4db21062afae", name: "BACKLASH", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Reaction, when you would suffer the effects of or take damage from a Ninjutsu", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You create a vortex that spins counterclockwise just before an attack hits you. Make a Ninjutsu Ability Check vs the Rank DC of the triggering jutsu. The Rank DC equals 13 + the Jutsu’s Rank (D-Ran k: 1, C-Rank: 2, B-Rank: 3, A-Rank: 4, S-Rank: 5). If you roll Higher, the triggering jutsu’s effect is nullified and the caster of the jutsu takes the damage and effects of their own Jutsu. On a failure, you take the damage as they break through your jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e864a5e422151d872641a4fa", name: "CHERISHING BREEZES", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["futon"], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You inhale once, filling your lungs with Air that you mix medical release chakra. You then attempt to pass this air from your lungs into the lungs of another who have either died within the last minute or are dying. This can be done in a number of ways such as CPR, a kiss, simply manipulating the air to exit your lungs and enter the downed creatures. When you do, the dead or dying creature makes a Constitution Saving throw adding 2d4 to their roll vs a DC 15 + 1 for each round they have been dead. On a Success, they immediately end the dead or dying condition regaining consciousness with 1 Hit Point and a number of Temporary Hit points equal to three times your Ninjutsu Save DC. These Temporary hit points last for 10 minutes. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ae6310fd59244c155d750380", name: "DIVINE MOUNTAIN WIND", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You create a vortex where you can control the Strength for the wind. Make a ranged ninjutsu attack targeting a creature you can see within range. On a hit target creature takes 8d6 wind damage and gains 2 ranks of bleed, as the wind slices into them with enough force to upheave the ground upon impact. If there are any sources of fire in the line of fire between you and your target this jutsu ignites into a stream of fire. Increase the damage by 5d4 fire damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "871daca5664e898579a61c54", name: "GALE BLADE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "90 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You create a super thin blade of cutting wind that slices through everything in a continuous line. Select a space you can see within range. Then select a second space you can see within 60 feet of the originally selected space. Draw a straight line in between both spaces. All creatures who the line passes through or by within 5 feet must make a Dexterity saving throw, taking 6d8 wind damage, gaining 3 ranks of bleeding and causing Swirl on a failed save or half as much and no additional effects on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "1a71aea30f60523568e7d344", name: "GREAT SICKLE WEASEL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (45-foot cone)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "1 Action", description: "A blast of slicing wind erupts from your hands. Each creature in range, originating from you, makes a Strength saving throw. On a failed save, a creature takes 7d6 wind damage and are thrown back 25 feet, fall prone, gains 1 rank of lacerated, cause Swirl and cannot take reactions until the end of their next turn as they are unable to avoid being caught in the shockwave of slicing and concussive wind. This jutsu also deals twice as much damage to objects and structure.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the ranks of lacerated by +1. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9425b3d1716bf2a12bf3a3fb", name: "GRYPHONS TALONS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You place a sealing talisman on your hands as you focus your Wind Release chakra onto them activating them. Chakra forms into the shape of 2 Claws, Talons, or weapons of your description on either hand. For the duration you do not spend chakra to maintain concentration on this jutsu. For the duration you can as an action make up to two Melee Ninjutsu Attacks with these wind claws you created. Your Melee Ninjutsu attacks made with these wind claws have a range of 10 feet, and deal 3d8 + Your ninjutsu ability modifier wind damage on a successful hit. 77 WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d15f0f8419052c3730af4dc2", name: "GUST SURGE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Reaction, which you take when a creature within 45 feet of you make an Attack, Casts a Jutsu or moves towards you.", range: "Self (45- foot radius sphere)", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You punch the ground creating a single point of intense air pressure that explodes outwards blowing away all creatures and potentially all attacks. All creatures within range of your choice must make a Strength saving throw. On a failed save they are thrown back to the edge of this jutsu’s radius into a space that can hold them. Creatures who fail their Strength saving throw gains 3 ranks of bruised on a failed save. If this jutsu is used in reaction to a Ninjutsu or Taijutsu being cast, the shockwave of air pressure reduces the damage the jutsu would deal by 5d6 + 15. If the jutsu used does not deal damage the triggering creature must make a Constitution ability check vs your Ninjutsu save DC. On a success their jutsu is cast as normal. On a failure, their jutsu is also blown away as this jutsu negates it. If this jutsu is used to trigger a clash with a Jutsu with the Fire Release Keyword, you make your clash check at advantage as you are pushing all the wind away from you. If you succeed your clash check against a jutsu with the fire release keyword, they take an additional 4d8 wind Damage and must make a Constitution saving throw being burned on a failed save. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "32914bc43e4788b0194820c6", name: "MULTILAYERED GALE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["futon"], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "HS, CM, M", duration: "Concentration, up to 1 minute.", description: "You wave your hands back and forth creating layers of wind that stack on top of one another creating a barrier of wind. Your Wall of wind is extremely dense not allowing most things to pass through it. When you create your barrier of wind it has 30 Hit points. It occupies your space with you and protects you in all direction, ranged attacks targeting you are made at disadvantage. At the start of each of your turns you can enhance this barrier regenerating 3d6 of the barriers hit points. This Barrier has a vulnerability to Fire damage, and Resistance to Lightning damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the initial hit points of the barrier by 10. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "993b5172cdade5e34f0aeb57", name: "THUMB OF DESTRUCTION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: ["futon"], casting_time: "Full Turn Action", range: "120 Feet", chakra_cost: "Special (77 Chakra)", components: "HS, CM, CS", duration: "Instant", description: "You generate a super massive tornado that touches down on a space you can see within range. This Tornado is 120 feet tall and 30 feet wide. You can command it to touch down on top of a creature or space you can see within range. If you have it touch down on top of a creature, make a Ranged Ninjutsu attack, dealing 10d8 wind damage on a hit. All creatures, objects and structures, excluding casters of this jutsu, within 60 feet of the tornado must make a Strength saving throw being sucked into the eye of this storm. On a failed save they are thrown to the top of this tornado for but a moment before the tornado compresses and fires all creatures within the eye of its storm directly into the ground at sound breaking speeds. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the targeted damage by 2d8 for each additional caster. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size and damage based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the height of the tornado by 60 feet, +3: Increase the height of the tornado by 80 feet, +4: Increase the height of the tornado by 100 feet, +5: Increase the height of the tornado by 120 feet). WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "acda340061379980c57de78d", name: "VACUUM BLADE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "12 Chakra", components: "HS, CM, W (Any)", duration: "Concentration, up to 1 minute.", description: "You exhale wind release chakra onto a weapon to increase its sharpness, range and lethality. This can even be used on your unarmed strikes creating lethal blades of wind extending from those strikes. You cannot lose concentration of this jutsu as a result of damage. Enhanced weapon or unarmed strike’s deals an additional 3d6 wind damage twice per turn, its range is also increased by 10 feet. Ranged weapons also damage all adjacent spaces around its target on a successful hit. Additionally, you can use your Ninjutsu ability modifier in place of Strength or Dexterity when calculating to hit or damage with attacks enhanced by this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If cast at S-Rank, increase the damage of this jutsu by +1d6. 78 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "213231304e849e367e8c1a1a", name: "VACUUM GREAT SPHERE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "120 Feet (15-foot radius Sphere)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, 1 minute", description: "You generate 3 large Spheres of wind chakra. Choose 3 spaces in range. You send the large wind spheres to these areas and they expand outwards with the point you’ve chosen at the center, 30 feet in diameter. Creatures caught in these spheres or who enter them, movement speed is reduced to 0 and they cannot breathe while inside the sphere as the pressure prevents them from inhaling successfully. Creatures caught in the radius of any sphere can make a Strength saving throw or continue to have their movement speed reduced to 0. On a successful save, they regain half of their movement speed. A creature who begins or ends its turn within the radius of a sphere must make a Constitution saving throw. On a failure, they begin to suffocate, gaining 2 rank of exhaustion. On a success, they recover 2 rank of exhaustion caused by this jutsu, if any. Upon escaping or ending this jutsu’s effect on them, they recover from all ranks of exhaustion this jutsu imposed on them.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and select one additional space this jutsu affects. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7e5f01d174152d9cd9444f48", name: "WIND CUTTER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You create one Super sharp blade of wind and launch it at a target creature in range. Make a ranged ninjutsu attack. On a hit the target creature takes 5d10 Wind damage and gains 1 rank of lacerated.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "be6c068599f6b528904edd66", name: "WYVERNS SURGE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["futon"], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You place a sealing tag on your body in any place you desire, as you place a massive reserve of Wind Release Chakra into the tag itself, activating it and magnifying your physical potential. You do not need to spend chakra to maintain concentration on this jutsu. For the duration, once per turn, when you would deal damage with a jutsu against a creature with a jutsu with a nature release keyword, they must make a Strength saving throw. On a failed save the following occurs; • Earth Release: Affected creature gains 1 rank of the bruised condition. • Wind Release: The jutsu deals an additional 3d8 wind damage and inflicts 2 ranks of bleed. • Fire Release: Affected creatures gains 1 rank of the Burned Condition. • Water Release: Affected creatures gains 1 rank of the Chilled Condition. • Lightning Release: Affected creatures gains 1 rank Shocked Condition for the next minute. A-RANK: WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7ac66e373a560fdf24f95066", name: "CAST NET", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self (60-Foot Cone)", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "A wave of slicing wind erupts from you as you swing your hand. Each creature in a 60-foot cone must make a Strength saving throw. A creature takes 7d8 wind damage and are thrown back 60 feet, fall prone, gain 1 rank of lacerated and causing Swirl on a failed save. Creatures take half as much damage and no further effects on a successful save. 79 WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2e428f34687a5d65fb0d1ea3", name: "DEFIANCE STORM", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["futon"], casting_time: "1 Full Turn Action", range: "90 Feet (30-foot-Radius Sphere)", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "1 minute", description: "You throw a Chakra seal onto the ground before you release the chakra sealed within in creating an aura of reinforcing Wind release chakra. Select up to 4 creatures to gain the benefits of this jutsu while inside this Jutsu's radius. For the duration select creatures within this jutsu’s radius makes Strength, Dexterity and Wisdom skill checks and Saving throws at advantage, Ninjutsu they cast of B-Rank or lower has their cost reduced by -2 (Min 1.), Taijutsu & Bukijutsu they cast deal additional wind damage equal to your Ninjutsu Ability modifier. The Chakra Seal used to cast this jutsu can be targeted for attacks, although it is protected by a bubble of Wind Release Chakra. It has an AC equal to your Ninjutsu Save DC, and Hit Points equal to twice your Ninjutsu Save DC. It has Immunity to Lightning Damage and Vulnerability to Fire Damage. Once Destroyed, this jutsu immediately ends. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f7e7eadb6d5086a39b23db82", name: "DRILLING WIND BULLET", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "120 feet", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You inhale a single breath and exhale creating a spinning drill made of slicing wind that tears through everything in its path. Make a Ranged Ninjutsu attack targeting 1 creature dealing 7d10 wind damage, inflicting 3 ranks of lacerated and pushing the target back 25 feet on a hit.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "738aac4f6cdd716e89b15814", name: "EYE OF THE STORM", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Full Turn Action", range: "Self (60-foot-Radius Sphere)", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You Create a powerful twisting cyclone of wind that seals yourself and all creatures in this jutsu’s Radius off from other creatures and effects from outside this jutsu’s radius. Creatures outside this jutsu’s radius cannot see into the opaque wall of twisting wind, dust, dirt and chakra. A creature with Chakra sight when looking at the wall only sees a wall of chakra and cannot make out anything passed it. If a creature attempts to pass through the wall, they must make a Strength saving throw. On a successful save they pass through the wall. On a failed save they take 8d8 wind damage and are thrown back 30 feet. Attacks and Jutsu cannot penetrate this jutsu’s walls. While inside this jutsu’s radius, creatures cannot generate electricity preventing them from casting Jutsu with only the Lightning Release Keyword. If the wall is struck with a Jutsu with the Water Release Keyword, the walls becomes wreathed in Water Release Chakra. If this jutsu’s walls become wreathed in Water Release chakra, creatures within this jutsu’s radius cannot generate fire, preventing them from casting jutsu with only the Fire Release Keyword. If the wall is struck with a Jutsu with the Fire Release Keyword, the walls becomes wreathed in Fire Release Chakra. If this jutsu’s walls become wreathed in Fire Release chakra, creatures within this jutsu’s radius cannot generate strong wind, preventing them from casting jutsu with only the Wind Release Keyword. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "826ecc0f4aafb0c848fcf9b1", name: "LIONS FANG BLADE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "120 feet", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You mold wind Release Chakra to create a beast made purely of Wind Release Chakra, that has a design and look of your description that counts as large. Upon its creation, you command it to attack a number of creatures up to your Ninjutsu Ability Modifier once each. Make a Melee Ninjutsu attack for each creature it attacks within range as it leaps and assaults each creature. On a hit, you deal 2d8 Wind Damage. A creature that takes damage from the Beast must make a Constitution saving throw being torn apart from the thousands of blades made of Wind Release chakra that makes up your Beast. On a failed save they gain 2 ranks of Lacerated and cause Swirl.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and Lacerated ranks by 3. 80 WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "6891946359206388bbf11a68", name: "NEVER ENDING FALL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self", chakra_cost: "15 Chakra", components: "HS, CM, M", duration: "Concentration, 1 Minute", description: "You create a vacuum of air under yourself with the ability to ascend, descend and move in any direction at your own discretion. You gain a fly speed of 60 feet. If you use your action to Dash, you instead move 180 feet in the round. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1f6069ffaa0dc6150494ee17", name: "NEVERENDING BREATH", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self", chakra_cost: "15 Chakra", components: "HS, CM", duration: "10 Hours", description: "You inhale a single breath, and using chakra you are able to reinvigorate that single collection of air as if it were a new breath. You no longer need to breathe for up to 10 hours. You cannot be suffocated or drowned. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f52cd28e49ba047f497698d1", name: "SPLITTING BREEZE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "b3b9a80a8acefa31d6905369"], elements: ["futon"], casting_time: "1 Action", range: "5 Feet", chakra_cost: "Special", components: "HS, CM", duration: "Instant", description: "You mold wind Release Chakra to create a blade of wind release chakra that is so compressed it fits into the palm of your hand. The amount of power this jutsu exhibits is entirely dependent on the amount of chakra you commit to it. Spend chakra up to the listed amounts. For every chakra cost milestone hit you deal the listed effect. A creature reduced to 0 as a result of this jutsu is bisected at any angle the caster decides. The saving throw this jutsu refers to below is a Constitution save. 20 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 20d4 Wind Damage. A creature must also make a saving throw gaining 2 ranks of laceration and causing Swirl on a failed save. 30 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 30d4 Wind Damage. A creature must also make saving throw, gaining 4 ranks of laceration and causing Swirl on a failed save. 40 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 40d4 Wind Damage. A creature must also make a saving throw, gaining 6 ranks of laceration and causing Swirl on a failed save. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c5500750799f3c86d255ec3d", name: "VACUUM SERIAL WAVES", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "16 Chakra", components: "HS, CM", duration: "Instant", description: "You take a deep breath and exhale several super intense blades of wind at different angles but at multiple targets. Make a ranged Ninjutsu Attack against up to 3 targets dealing 8d6 Wind Damage and inflicting 1 rank of lacerated on a hit.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the ranks of laceration by +1. WIND RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b2fd6f737d525ef99c69ed0f", name: "VACUUM WALL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "30 feet", chakra_cost: "15 Chakra", components: "HS, CM, M", duration: "1 Round", description: "You create a vacuum of air around a willing creature in range that nullifies almost all attacks that would aspire to harm you. Until the beginning of your next turn. All Ninjutsu and Taijutsu, Melee and Ranged weapon attacks must roll 1d20 when they declare an attack targeting you. On a roll of 8 or greater, the attack is diverted or knocked away by the extremely dense wind. S-RANK: WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "480337eb8eadb524490d3e3c", name: "1 MILLION BLADE COLLISION", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["futon"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Instant", description: "You focus a massive amount of wind chakra into a sphere above the target in range and bring it down crashing into the target as a single blade. The target must make a Dexterity saving throw, creatures take 34d6 wind damage, gain 5 ranks of lacerated and cause Swirl on a failed save, or half as much damage and ranks of bleed on a Successful save. 81 WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1d62c01a6bb05aecbae19aaf", name: "BACKLASH WAVE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Reaction, which you take when you see a Ninjutsu being cast.", range: "90 Feet", chakra_cost: "28 Chakra", components: "HS, CM", duration: "Instant", description: "You see an attack as it comes towards you and you create an impenetrable forcefield of wind that’s designed to throw everything back. Make a Ranged Ninjutsu Attack vs the triggering creatures ninjutsu save DC. If your result is higher, the opponent suffers the damage and effects of their own jutsu. On a failure, the jutsu is diverted and immediately ends. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cebe19f7c2eb2ffc3196d1ee", name: "FANNED WIND", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "100 Foot Cone", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Instant", description: "A torrent of concussive wind erupts from your hands that explodes forward devastating everything in a 100-foot cone in front of you. This jutsu blows everything not tied down away and even upheaves trees and smaller structures and buildings. Creatures in its path must make a Strength saving throw being thrown back 120 feet on a failed save. If the creature hits a structure their movement ends and they take triple the falling damage as if they fell the same distance they traveled. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a94d819b483c39dfc419e7da", name: "HURRICANE OF DISASTER", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: ["futon"], casting_time: "Full Turn Action", range: "Self (120-foot radius)", chakra_cost: "Special (138 Chakra)", components: "HS, CM, CS", duration: "Instant", description: "You generate a Category 6 Hurricane that touches down with the sole intent of bringing nothing but ruin in its wake. This Hurricane extends 250 feet into the air and has a 120-foot radius. This hurricane affects all creatures except its casters within its radius. At the end of each of your turns, it moves 90 feet in a random direction (Roll 1d8. 1: North, 2: North East, 3: East, 4: South East, 5: South, 6: South West, 7: West, 8: North West.). Creatures within this jutsu’s area of effect must make a Strength saving throw being ripped from their current position and thrown 250 feet into the air taking 12d8 wind Damage and being restrained by the wind on a failed save. A creature thrown into the air may repeat their Strength Saving throw to escape this wind at the end of each of their turns, taking 12d8 wind damage on a failed save and escaping, falling to the ground on a successful save. All structures and constructs in this jutsu’s path automatically fail their saves and are destroyed as they are pulled into the hurricane’s rotation. This Hurricane lasts for 1 Minute as once cast it cannot be stopped or dispelled by its casters willingly. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 4d8. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size and damage based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the radius of the hurricane by 30 feet, +3: Increase the radius of the hurricane by 60 feet, +4: Increase the radius of the hurricane by 90 feet, +5: Increase the radius of the hurricane by 120 feet). 82 WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "491e59e180c2b8565cb5a777", name: "SPIRALING TEMPEST", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Bonus Action", range: "Self (45-foot radius)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You release a surge of Wind Release Chakra that protects and enhances all of your allies for the duration. All creatures of your choice within range gain the following; • If a creature starts their turns in this jutsu’s radius, they gain a Bonus +30 Movement speed until the end of their next turns. • They gain a +3 bonus to Ninjutsu and Taijutsu Attack Rolls. • They gain a number of Temporary Hit points equal to your Ninjutsu Save DC at the beginning of each of their turns. • Taijutsu they cast that has a range of touch, or 5 feet, increases their range by 15 feet, and deals an additional 3d8 Wind Damage. • Affected Creatures cannot be Dazed or Weakened. • Affected creatures gain Resistance to Lightning Damage. WIND RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d9e68945027920e6cc80890f", name: "TORNADO EXPLOSION", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: ["futon"], casting_time: "1 Action", range: "Self", chakra_cost: "30 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You create a spiraling cylinder of wind centered on yourself that has a 90 Foot radius and is 120 Feet High. This cylinder becomes difficult terrain for the duration, even for flying creatures. Unattended objects in this cylinder that are large or smaller are pulled upwards and spins around the center at 200 Mph. A creature that starts its turn in the cylinder must succeed a Strength save or cause Swirl and be pulled upwards towards the center and be restrained while in motion. All objects and creatures inside the cylinder, excluding yourself, take 8d10 Wind Damage at the start of each of your turns. Creatures can make a Strength save on each of its turns as an action to not be restrained on its turn. 83 FIRE RELEASE Fire Release is the most common of the five nature transformations in the leaf village and land of fire, but those who can use it are able to knead chakra and set fire to anything. Fire Release is almost always used offensively and has very few defensive applications. Some shinobi use it to damage massive areas and harm large groups of foes. Fire Release is commonly exhaled from the user's mouth. Although Fire Release has naturally amazing power, it suffers from high chakra cost and is difficult to control flames after use. Fire Release is naturally strong against Wind Release and weak against Water Release Prerequisite: You must have the Fire Release Affinity to learn jutsu with the Fire Release Keyword. D-RANK: FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fea7dd3ba912601c92c26889", name: "ABSORB HEAT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Reaction, which you take when you would take damage", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a vacuum of chakra absorbing the heat from the surrounding area and create a thin layer of fire chakra to protect yourself. You gain resistance to the triggering instance of damage. If the triggering damage or any further attacks that target you are melee attacks and the triggering creature was no more than 10 feet away when this jutsu was cast, the triggering creature takes 6 fire Damage until the beginning of your next turn. If the triggering damage was fire, you also gain +5 DR vs fire damage until the start of your next turn. If the triggering damage was cold, this jutsu fails to activate.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage dealt as a result of a melee attack by +4 and the range a creature can be to take the damage by 5 feet. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "1468b5e453324b66fe0fa055", name: "ASH CLOUD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "30 Feet (30 Foot Cloud)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You inhale and knead fire chakra in your lungs to create a cloud of ash. You exhale the ash into a target area within range that you can see. The Cloud of ash remains until blown away or dissipates which can take up to 10 minutes. Creatures inside the target area have disadvantage on attacks while inside the cloud, and are treated as if in total darkness. Creatures making ranged attacks inside the cloud cannot see creatures inside. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "015331e9ba74bd0979e11111", name: "BLAZING EMBER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest motes of fire in the palms of each of your hands. Make two Ranged Ninjutsu attacks. These attacks can target one creature or two. If targeting multiple creatures make a single Ranged Ninjutsu attack against each. On a successful hit you deal 3d4+3 fire Damage. If a creature affected by the Burned condition is hit by both attacks, they immediately suffer the damage of their condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank increase the number of attacks you can make by +1. If this jutsu is cast at S-Rank increase the number of attacks you can make by +2. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b034eac0a021f07b2144be77", name: "BLAZING HANDS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 action", range: "self (20-foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You hold your hands out and fire a sheet of flame from your hands. Each creature in a 15-foot cone must make a Dexterity saving throw. A creature takes 5d4+5 fire damage on a failed save, or half as much damage on a successful one. This fire ignites any flammable objects in the area that aren’t being worn or carried.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d4+1. 84 FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ef3069d3a73131a3dd3aa182", name: "BLUE FIRE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["katon"], casting_time: "1 Reaction, which you take when you see a creature take damage in range", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Round", description: "You manifest a sapphire-colored flame around a willing creature you can see within range protecting them. You can see a gout of blue hot flame erupts around them creating a barrier of heat. Until the beginning of the creatures next turn, ranged attacks deal reduced damage equal to 2d4+2. Melee attacks deal reduced damage equal to 2d4+2 and deals 3d6+3 in fire damage to the attacking creature once per turn. If the attacking creature would deal Cold Damage, this jutsu is immediately extinguished, ending it before any damage reduction or damage could be dealt.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage reduction by 1d4+1 and damage done by 1d6+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0022105f408692c7830802af", name: "CRIMSON SPIDER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["katon"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "You spew out fire on a point within range. The fire then collects into a medium sized Crimson Spider. This Crimson Spider can be commanded as a bonus action on your turn. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "83aa1dfe60ba98eb0f98ebf9", name: "DEMONS LANTERN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Self (5-Feet radius)", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You conjure multiple flames of chakra to surround you. These flames transform into faces of demons of your description. You shed bright light for 20 feet and dim light for another 10 feet. As a reaction, when a creature moves within 5 feet of you, you can force the target to make a Dexterity saving throw as these Demon lanterns attempt to strike the target. On a failed save, the target is set on fire and gains the Burned Condition. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3ce29ee77c388aa2c8ddd0e5", name: "ERUPTING FLAME", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You Focus chakra into the target area and create a hot spot directly under a target creature you can see in range. The target must make a Dexterity saving throw or take 3d8+3 Fire Damage. The target gains no benefits from cover against this jutsu. A creature who fails their saving throw by 5 or more gains 2 ranks of the burned condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8+1.", created_at: NOW, updated_at: NOW },
  { _id: "d54f876e0935c80a60b08c74", name: "FIREBALL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet (15 Foot radius Sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You breathe a stream of fire onto the target area which then expands into a ball of fire burning all in its range. Target creatures in range makes a Dexterity saving throw, taking 4d6+4 Fire Damage on a failed save or half as much on a success save. Flammable objects caught in the radius ignites if it isn’t being held or carried.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1, and the radius by 5ft. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "8fd5bcb46a7c85b6f50cc692", name: "FLAME BOLT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You breathe a bolt of flame at a creature or object within range. Make a ranged ninjutsu attack against the target. On a hit, the target takes fire damage equal to 3d10+3. A flammable object hit by this jutsu ignites if it isn’t being worn or carried.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "5d6ebad2a3aa34390d8995c0", name: "FLAME COAT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Bonus action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, W(Any)", duration: "Concentration, up to 10 minutes", description: "You engulf a weapon in fire chakra, coating it in a flame that enhances the lethality of the weapon. If you let go of the weapon or it is taken from you, the fire disperses. You cannot lose concentration of this jutsu as a result of damage. While you maintain concentration on this jutsu, you can engulf another weapon you are holding as a bonus action. A weapon enflamed by you, deals an additional 1d8+1 fire damage twice per turn. The fire sheds bright light in a 20- foot radius and dim light for an additional 10 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the damage to 2d8+2. If this jutsu is cast at S-Rank, increase the damage to 3d8+3. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "73baf3bc3b74cd50463e4728", name: "FLAME STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "A vertical column of flame erupts upwards from the ground towards the sky in a location you specify. Each creature in a 10-foot radius, 20-foot-high cylinder centered on a point within range must make a Dexterity saving throw taking 3d6+3 fire damage and gaining 1 rank of the burned condition on a failed save, or half as much damage on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "246d3e4c612fe015c42b1feb", name: "FLAME WHIP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "self (20-feet)", chakra_cost: "4 chakra", components: "HS, CM", duration: "Instant", description: "You conjure a flaming whip to strike at a creature you can see up to 20-feet away from you. Make a melee ninjutsu attack, dealing 2d10+2 fire damage. The target must make a Dexterity saving throw, being pulled 10 feet towards you. If a creature who failed the saving throw ends their movement within 5 feet of you, they fall prone and gain the burned condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "6fa324f778ab9c5b24b0ca00", name: "FOX FIRE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Self", chakra_cost: "3 chakra", components: "HS, CM", duration: "Concentration, up to 1 hour", description: "A flickering flame appears in your hand. The flame remains there for the duration and harms neither you or your equipment. The flame sheds bright light in a 20-foot radius and dim light for an additional 10 feet. The jutsu ends if you dismiss it. You can also attack with the flame. As an Action you can make a Ranged Ninjutsu attack on a creature you can see within 30 feet of you. On a hit, the target begins to glow with a soft, warm, and glowing radiance. While glowing in this way, this jutsu’s duration becomes Concentration, until the end of your next turn, and creatures have advantage on melee attacks targeting the creature. 86 FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "85e58f9c9dfeaa8028ace574", name: "GREEN FIRE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Bonus Action.", range: "90 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manifest an emerald-colored flame and mark a creature you can see within range with it. For the duration, when the target would make a Saving throw against a jutsu with the fire Release Keyword, they roll and additional 1d4. Reducing their saving throw by the result. If the marked creature would take fire damage from an attack that you make, you deal an additional 1d6+1 fire damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of marked creatures by +1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0e07cade53b167dc863b8f4a", name: "HELLFIRE REJECTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Reaction, which you take when you would take damage", range: "15 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "When you are hit by a creature that you can see, you release a brilliant burst of fire chakra in a 15 Foot sphere around you. Creatures of your choice caught in the radius must make a Dexterity saving throw, taking 3d8+3 fire damage on a failed save, or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ea7cc14a638f9e7f039e6b99", name: "PASSIONATE FLAMES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["katon"], casting_time: "1 Action.", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a fuchsia-colored flame and place it on a wounded creature you can see within range. Target creature rolls 2 Hit Die, spending one. When they do, they recover the result + Your Ninjutsu ability modifier. After casting the target creature gains resistance to Fire Damage until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of Hit die rolled and spent by 1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "d5158eb7ad6f8b5e0d7d5663", name: "PHOENIX FIRE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You spit forth 3 motes of fire at a creature within range. Make 3 ranged ninjutsu attacks against a target you can see within range. On a hit, the target takes 1d6+1 Fire damage. If you score at least two hits with this jutsu on the same target, they must make a Constitution saving throw gaining 1 rank of the burned condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the amount of attacks by +1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ff183e335836ca86298f0a40", name: "REKINDLED FLAMES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["katon"], casting_time: "1 Action.", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a golden-colored flame and place it on a dying creature you can see within range. Target creature is immediately stabilized and rolls 3 Hit Die, spending two. If the target has less than 3 Hit die, they roll what they have left spending all of it. If the creature has no hit die, they are not able to be stabilized. They recover the result of the rolled Hit die + Your Ninjutsu ability modifier. After casting the target creature gains resistance to Fire Damage until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of Hit die rolled by 1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0b3be8d95e142973481674a6", name: "SANGUINE SPEAR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action.", range: "5 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a sanguine-colored flame and mold it into a melee weapon of your description that you then use to strike a target within range. Make one melee ninjutsu attacks, dealing 3d6+3 fire damage on a hit. A target currently burned or chilled suffer exasperated effected. Burned: A burned creature gain an additional rank of the burned condition. Chilled: A chilled creature loses the chilled condition suffering from a sudden shift in temperatures suffering all ranks of their chilled conditions damage. Their Chilled Condition immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the number of melee ninjutsu attacks by +1. If this jutsu is cast at S-Rank, increase the number of melee ninjutsu attacks by +2. 87 FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "505840f50fa3c62ecdf68a3a", name: "SCORCHING RAY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "30 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You create 8 rays of fire and hurl them at targets within range. You can hurl up to 2 at a single target, otherwise you can target up to 8 targets. Make a ranged ninjutsu attack for each ray. On a hit the target takes 2d4+2 fire damage. If a creature is hit by both attacks it must make a Constitution Saving Throw, gaining the Burned condition on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and you create two additional rays. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7c04d225cfd4b6d03bd9d1b0", name: "SPARK FR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "5 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a highly flammable ember of fire release chakra. You can throw this ember onto any unworn or held highly flammable material or substance causing it to immediately go up in flames. The fires created by this jutsu grow in size as normal fire would and are not controlled by you. These flames are so hot they evaporate all water from sources that are not created by a Jutsu with the Water Release keyword of at least D-Rank or Higher. These flames extinguish themselves after 10 minutes.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a1d5f72e4436475b247dabd1", name: "TEMPERED METALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minute", description: "You superheat a single weapon or stack of weapons or ammunition. For the next minute these weapons glow red hot and to all creatures but you are scalding hot to the touch. Weapons affected by this jutsu gains a +1 bonus to attack and damage rolls and their damage die is increased by one step for the duration. (D4>D6>D8>D10>D12) At the conclusion of this jutsu, the weapon becomes brittle, unusable and breaks.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When this jutsu is cast at B-Rank, the bonus becomes +2 and the damage die is increased by an additional step. When this jutsu is cast at S-Rank, the bonus becomes +3 and the damage die is increased by an additional step. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "200137c03c025e666f91c0b8", name: "WHITE FIRE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["katon"], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 Minute", description: "You manifest a pale white-colored flame and mold it to coat your hands. For the duration, you do not need to spend chakra to maintain concentration on this jutsu. For the duration, Jutsu you cast with the fire release keyword always forces affected creatures to make a Constitution saving throw. On a failed save they gain the burned condition. On a successful save no further effects or conditions are imposed as a result of this jutsu. Creatures who gain the burned condition as a result of this jutsu, instead must beat a DC 20 Dexterity (Survival) Check to end the condition. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "03fa94f2999a949c1120b2b9", name: "WILDFIRE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["katon"], casting_time: "1 Action", range: "45 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a multicolored flame and fire a stream of it towards a creature you can see within range. Target creature must make a Dexterity saving throw. On a failed save they gain 1 rank of the burned condition, and take 2d12+2 Fire Damage. On a successful save they take half damage and no further effects. If the target already had the burned condition, on a failed save, they instead immediately take damage from the burned condition they have and take 3d12+3 fire damage with no further effects. On a successful save they take half damage and no further effects. C-RANK: FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c9c9d3bd69a1c536fccc06e0", name: "BLAZING ASH PILE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet (30-foot Cloud)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 minute", description: "You blow a super-heated cloud of ash at a target area you can see within range; the cloud fills a 30 Foot radius in a cloud shape. Creatures inside the cloud are treated as if they are in total darkness. At any point in time within the next minute, as a bonus action or reaction, you can ignite the cloud of ash and all creatures inside the cloud would need to make a Dexterity saving throw, taking 7d4+7 Fire Damage and the burned condition on a failed save and half as much damage and no burns on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d4+1. 88 FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "1eaeb759516ad43336a153d6", name: "BLUE FIRE EMBER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Special", description: "You manifest a sapphire-colored ember into a solid but flickering form. This flame appears in a willing creature of your choices hand within range. This flame lasts an hour and causes no harm to the creature and can be given or carried by any other creature you designate as a holder. A holder of this flame may as their bonus action coat themselves in this blue flame granting them a fast burning but dense shield of flame for a short time. Until the beginning of their next turn, they gain a number of Temporary Hit points equal to 3d8 + 10. Melee attacks that strike the creature deals 10 fire damage to all creatures within 10 feet of them as the fire sparks off of them. These Temporary Hit Points are Vulnerable to Cold damage and Resistant to Wind and Fire damage. When the creature would take Cold Damage, this armor instead takes double damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Damage by 5. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0031e8590a328d626f244f9d", name: "BURNING GAZE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You direct your gaze at an object or creature within range. Your eyes begin to glow a violent bright red and the target erupts into flames for the duration. An object begins to burn as flames engulf it. A creature must make a Dexterity saving throw gaining the burned condition for the duration. While you are concentrating on this jutsu, creatures currently suffering from the burned condition that you can see, cannot extinguish the fires that are burning them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of ranks of burned granted on a failed save by +1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "fb96762bf19be0707305bc70", name: "DANCE OF FIRE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "fef9deb945f95aa08666590c"], elements: ["katon"], casting_time: "1 Reaction, which you take when you or a creature you can see in range, either takes damage or would make a Dexterity Saving throw.", range: "Self (10-foot Radius Sphere)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 Round", description: "You manifest a super dense barrier of flame around yourself and all creatures within range. This barrier of flame has 12 hit points, An AC equal to your Ninjutsu Save DC and counts as a Flaming Structure. Creatures outside of the radius of this barrier cannot see pass through it. Creatures who target this barrier of flame with a melee attack from either side or hit you an attack while outside of it and within 15 feet of it, take 12 Fire Damage. This barrier cannot move and intercepts all attacks and Jutsu, taking damage if any would attempt to pass through the walls exterior. This wall is resistant to Wind and Fire Damage and vulnerability to Cold damage. Jutsu with the Wind Release Keyword cannot initiate a clash with it by any means.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and its hit points and damage by 8. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "deed6cc0dc7fd1812384ec40", name: "DRAGON FLAME BOMBS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["katon"], casting_time: "1 Action", range: "Self (120-Foot line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You knead chakra in your stomach and superheat it until you exhale it from your gut at terrifying speeds, leading to you being unable to truly control its path. You fire a Stream of superheated fire in a 5-foot wide, 120- foot-long line directly in front of you. Creatures in its path must make a Dexterity saving throw, taking 6d8+6 Fire damage on a failed save or half as much on a success. Objects within 5 feet of the stream of fire ignite if they are not being worn or held. The stream leaves behind a line of fire from you to the end of the 120-foot path. The fire remains for 1 minute or until extinguished.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8+1. 89 FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "59b8e33c42cbea3bb0f8ba39", name: "EMBER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Bonus Action", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest motes of fire in the palms of each of your hands. Make two Ranged Ninjutsu attacks. These attacks can target one creature or two. If targeting multiple creatures make a single Ranged Ninjutsu attack against each. On a successful hit you deal 3d4+3 fire Damage. If a creature affected by the Burned condition is hit by both attacks, they immediately suffer the damage of their condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "79b32880fcabe1a06460743c", name: "EVERFLAME SEEDS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["katon"], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a 2 gems of Fire Release Chakra infused with Medical Release Chakra that feel hot to the touch. You spend 2 of your Chakra Die, rolling and recording the result. A creature can use its bonus action to eat one gem. Eating a gem forces a creature to roll 2 Hit die, spending them both. The creature regains Hit points equal to the result of their Hit Die + The casters Chakra die roll. A creature can gain the benefits of this jutsu twice per long rest. If a creature attempts to gain the benefits of this jutsu more than twice per long rest, each time after the second, they take an amount of fire damage equal to the result of the casters Chakra Die roll + Constitution Score. This damage cannot be resisted or reduced by any means. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f9fbedef85dad2130754b5d0", name: "EXPLOSIVE CLONE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "dc2837c0a3446d09da7edaf6", "33ab3a61f3027398cd08f131"], elements: ["katon"], casting_time: "1 Action", range: "Self", chakra_cost: "Special (9 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a clone comprised of fire release chakra, made to look exactly like you called an Explosive Clone. This clone cannot take the attack action or cast jutsu. When this clone takes damage or you dismiss it as a reaction, it explodes violently. All creatures within 15 feet of the clone when it explodes must make a Dexterity saving throw, taking 7d6+7 fire damage, gaining 1 rank of the burned condition and being thrown back 10 feet. On a successful save the they only take half damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4ab98c058e2abd1f20e23944", name: "FIRE DRAGON BULLET", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You spit forth 5 globes of fire at a creature within range. Make a ranged ninjutsu attack against the target. On a hit, the target takes 10d4+10 Fire damage and gains the burned condition.", at_higher_ranks: "For each rank you cast this jutsu above C -Rank, increase the cost of this jutsu by 3 and increase the damage by 1d4+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9858d37a542a5e229179caa8", name: "FLAME ARMOR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Hour", description: "You create a layer of superheated chakra over your skin. Seemingly setting yourself on fire in any pattern you decide. You gain 20 Temporary Hit Points. For the duration, while you have Temporary Hit Points, you gain resistance to wind and fire damage and immunity to the Burned and Chilled conditions, and melee attacks that strike you also deal 15 Fire damage to the attacker.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the Temporary Hit Points gained and damage dealt by 5. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e52a85ea5afcbb3dca55d477", name: "FLAMING SEALS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["katon"], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "1 Minute.", description: "This jutsu places a flaming seal on a willing creature you touch and creates a chakra connection between you and the target until the jutsu ends. If this jutsu is cast again while a previous instance of it is active, the previous casting and its effects automatically end. When the target is within 90 feet of you, it gains a +1 bonus to all saving throws, resistance to fire damage and you always know what conditions are affecting the creature (if any).", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the bonus by +1. If this jutsu is cast at S-Rank, increase the bonus by +2. 90 FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9aab2922b134bec27174bbdb", name: "FLAMING TRAP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["katon"], casting_time: "10 Minutes", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Until Dispelled or triggered", description: "When you cast this jutsu, you inscribe a chakra seal that harms other creatures, either upon a surface (Such as a table, or a section of floor or wall) or within an object that can be closed (such as a book, a scroll, or a treasure chest) to conceal the chakra seal. If you choose a surface, the glyph can cover an area of the surface no larger than 10-feet in diameter. If you choose an object, that object must remain in place, if the object is moved more than 10-feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered. The chakra seal is nearly invisible and requires a successful Intelligence (Investigation or Ninjutsu) check against your spell save DC to be found. You decide what triggers the chakra seal when you cast the jutsu. For seals inscribed on a surface, the most typical triggers include touching or standing on the seal, removing another object covering the seal, approaching within a certain distance of the seal, or manipulating the object on which the seal is inscribed. For chakra seals inscribed within an object, the most common triggers include opening that object, approaching within a certain distance of the object, or seeing or reading the seal. Once a chakra seal is triggered, it explodes in a 15- foot radius sphere, destroying the surface it is inscribed on, Creatures in radius must make a Dexterity saving throw taking 14d6+14 fire damage on a failed save, or half as much on a successful one. Afterwards the jutsu ends. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e55396427b0e1e5023884034", name: "GREAT FIREBALL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["katon"], casting_time: "1 Action", range: "90 Feet (20-foot radius Sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You breathe a stream of fire onto the target area which then expands into a massive ball of fire, incinerating everything in its range. The target(s) must make a Dexterity saving throw or take 6d6+6 Fire Damage and 1 ranks of the burned condition or half as much on a failed save. Flammable objects caught in the radius ignites if it isn’t being worn or carried.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1 and radius by 5ft. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "5cbedb70cf3709bd313227cf", name: "GREENFLAME EMBER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Bonus Action", range: "90 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manifest an emerald-colored flame that glows with a bright hue and attempt to mark a creature you can see withing range with it. A Creature you can see within range must make a Dexterity saving throw. On a failed save being marked by this flame. For the duration, when you or an allied creature makes an attack against the marked creature, roll an additional 1d4 adding the result to your attack & damage rolls.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of marked creatures by +1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "11312d67529e80d07d316d40", name: "HEATED BODY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM", duration: "1 hour", description: "You breathe a single deep breath, using your Fire Release chakra to increase the temperature of your body as you begin to radiate heat. For the duration you gain immunity to cold environmental conditions, and creatures who are within 10 feet of you gain advantage on Wisdom (Survival) checks in cold environmental conditions. Ice and rain begin to evaporate as it come in contact with you creating heated steam. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "121717762c0d987938eab565", name: "HEATED SIGHT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: ["katon"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM", duration: "10 minutes", description: "You enhance your vision to be able to see heat itself like a snake with infrared. Creatures and objects who produce any level of heat are outlined in varying colors of your own description with brighter meaning they are warmer and dimmer meaning they are cooler in heat. Creatures whom are perceived in this way cannot gain the benefit of cover or be hidden from you. This allows you to perceive creatures hidden by steam, smoke, gas or even in non-chakra-based darkness. 91 FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f33190faac2aea6d781765bf", name: "HEAVENLY PRISON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["katon"], casting_time: "1 Action", range: "5 feet", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 minutes", description: "You take a chakra seal and imprint your chakra onto it making a melee Ninjutsu Attack against a creature; On a hit the target creature is branded with a Fire Release chakra seal. While branded with this seal, creatures have extreme difficulty molding chakra. If a creature attempts to cast a jutsu that requires Chakra Molding (CM), they must make a Constitution saving throw taking 5d8+5 Fire damage on a failure, and half as much on a success. On a failure, the brand burns them, restricting chakra flow as they lose the ability to mold chakra until the beginning of their next turn. Creatures can make a Ninshou skill Check as an action vs your Ninjutsu save DC to break the seal ending this jutsu. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4bd6de0645fb5673863f6281", name: "SANGUINE BLADE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manifest a sanguine-colored flame and mold it into a large melee weapon of your description that floats near you upon its creation. When you cast this jutsu, you can make a melee ninjutsu attack against a creature within 10 feet of the weapon. On a hit, the target takes fire damage equal to 3d6 + 3. As a bonus action, you can command the weapons to move up to 30 feet and repeat the attack against a creature within 10 feet of it. A target currently burned or chilled suffer exasperated effected. Burned: A burned creature gain an additional rank of the burned condition. Chilled: A chilled creature loses the chilled condition suffering from a sudden shift in temperatures taking 2d6 Necrotic Damage as a result. This immediately ends the Chilled condition on the creature.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the weapon gains a bonus +1 to attack and Damage rolls. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4c74e21aff931dfaae86af27", name: "SEARING RUSH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: ["katon"], casting_time: "1 Action", range: "Self (120 Foot Line)", chakra_cost: "Special (50 Chakra)", components: "HS, CM", duration: "Instant", description: "You weave handsigns as you and any other casters conjure superhot globes of flame. These globes are so hot that they begin to boil the water out of the air itself. These globes combine to form a single super compressed globe of flame that explodes with such force as it fires a powerful beam of Flame that burns the air as it passes. All creatures in a 15-foot wide 120 feet long line originating from you must make a Dexterity saving throw. On a failed save creature take 11d8+11 Fire Damage and gaining 3 ranks of burned or half as much damage and no additional conditions on a successful save. Creatures who’s Hit points are reduced to 0 as a result of this jutsu become ash. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the targeted damage by 2d8. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size and damage based on the highest Charisma Modifier within the group of casters. (+0-2: No Change, +3-4: Increase the damage die to a d10, +5: Increase the damage die to a d12). FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0513bca2f3ff6cc66b4d965d", name: "WHITE FIRE EMBER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["katon"], casting_time: "1 Full Turn Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "1 Minute", description: "You manifest a pale white-colored flame and use it to enhance your Fire Release Jutsu for the duration. For the duration, Jutsu you cast with the fire release keyword rerolls all Attack rolls of 1~5, taking the second result. Also, Jutsu you cast with the fire Release keyword rerolls all Damage rolls of 1 or 2, taking the second result. You choose when to apply this effect to a jutsu you cast. You may use this effect to enhance jutsu with the fire release keyword a number of times equal to your proficiency bonus before this jutsu immediately ends. 92 B-RANK: FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "25668e1d0d5e48f0af6ec02e", name: "ALCHEMIST FLAME", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60-foot cone", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a colorless flame that you ingest before you exhale outward spraying it across a massive range. All creatures in range must make a Constitution saving throw. On a failed save they gain the burned condition. Creatures burned by this jutsu also gain the Weakened condition for the same duration as their burned condition persists.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the range my 5 feet. FIRE RELEASE: CONTROLLED BURST", created_at: NOW, updated_at: NOW },
  { _id: "fe8839a3dddac390497eb633", name: "MOVEMENT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "10 Chakra", components: "HS, CM, M", duration: "Concentration, up to 1 minute", description: "You transfer chakra to the bottom of your feet, creating a strong repulsive force upon release of this jutsu, increasing your movement speed momentarily. Increase your movement speed by 10 until the end of your next turn.", at_higher_ranks: "This Jutsu’s movement speed boost increases by 5ft at 5th level (15ft), 11th level (20ft), 17th level (25ft) CHAKRA PULSE Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: HS Cost: 2 Chakra Keywords: Ninjutsu Description: You create a forceful pulse of chakra that erupts from your body. Each creature within 5 feet of you, other than you, must make a Strength saving throw or take 2d4 force damage and are forced prone. At Higher Levels: This Jutsu’s effectiveness increases by 2d4 at 5th level (4d4), 11th level (6d4), 17th level (8d4) CHAKRA BLOW Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Weapons Range Duration: 1 round Components: HS, CM, W(any) Cost: 2 Chakra Keywords: Ninjutsu Description: As part of the action used to cast this ninjutsu, you must make a weapon attack against one creature within the Jutsu's range, otherwise the jutsu fails. On a hit, the target suffers the attacks normal effects and takes an additional 1d6 damage. At Higher Ranks: This Jutsu’s effectiveness increases by 1d6 at 5th level (2d6), 11th level (3d6), 17th level (4d6) ENHANCED DEFENSE Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Self Duration: Instant Components: HS Cost: 2 Chakra Keywords: Ninjutsu Description: You focus chakra into the top layer of your skin, providing your resistance to Bludgeoning, Piercing, and slashing damage until the start of your next turn. ENHANCED RESISTANCE Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Reaction, Which you take when you fail a saving throw Range: Self Duration: 1 Round Components: HS Cost: 2 Chakra Keywords: Ninjutsu Description: You focus chakra throughout your body reinforcing it to attacks. You gain a +1 bonus to the next saving throw of your choice. At Higher Levels: This Jutsu’s body reinforcement increases as you increase in level. Gain an additional +1 bonus at 5th Level (+2), 11th level (+3) and 17th level (+4). 4 ENHANCED SKILL Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Reaction, which you take when you fail a skill check. Range: Self Duration: 1 Round. Components: HS Cost: 2 Chakra Keywords: Ninjutsu Description: You focus chakra toward different parts of your body to enhance your ability to complete different tasks. When you fail a skill check using a physical ability score (Strength, Dexterity or Constitution), you can add+2 to that failed check, potentially turning a failure, into a success. Once you cast this jutsu, you cannot do so again for 10 minutes. At Higher Levels: This Jutsu's skill reinforcement increases as you increase in level. This bonus increases by +2 at 5th Level (+4), 11th level (+6), 17th level (+8) ESCAPE TECHNIQUE Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Self Duration: Instant Components: HS Cost: 2 Chakra Keywords: Ninjutsu Description: You use chakra to feel the knots of ropes chains, and other tools used to bind and restrain you. This helps you figure out the best course of escape while trapped. While restrained or grappled, you can roll Sleight of Hand in place of the normally required skill check or saving throw at advantage. On a success, you are able to slip out of the grapple or restrained position, freeing yourself. FINGER CARVING SEAL Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action. Range: Touch Duration: Permanent Components: CM, CS Cost: 1 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You focus chakra into the tip of your finger and use the accumulated heat and energy to apply worlds, letters and shapes of your choice, no longer than 20 words per action taken. These words can be applied to structures and constructs and deal no damage. These words can be applied to a willing creature, leaving a permanent scar in their skin with your writings. FIRECRACKER FLASH Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: NT Cost: 2 Chakra Keywords: Ninjutsu, Bukijutsu Description: You take a bundle of flash firecrackers, and use your chakra to light the wicks of each one before throwing them in an arc in front of you. Creatures standing in front of you in a 15-foot-wide space must make a Wisdom Save, giving you advantage on your next attack against them and disadvantage on their next attack on a failed save. INVISIBILITY CLOAK Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Self Duration: Instant Components: NT Cost: 1 Chakra Keywords: Ninjutsu Description: You quickly pull a chameleon cloak over yourself while against a wall or other standing surface. Roll a stealth check with a 1d4+1 bonus to the check. If a creature would attempt to make a perception check in an attempt to find you, they make their check with a 1d4+1 penalty to their check. This penalty lasts until you move more than 10 feet from your current location. LIGHT Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Touch Duration: 1 Hour Components: CM Cost: 1 Chakra Keywords: Ninjutsu Description: You touch one object that is no larger than 10 feet in any dimension. Until the jutsu ends, the object sheds bright light in a 10-foot radius and dim light for an additional 10 feet, the light is a soft blue/ Completely covering the object with something opaque blocks the light. The jutsu ends if you cast it again or dismiss it as an action. If you target an object held or worn by a hostile creature, that creature can must make a Dexterity saving throw to avoid the jutsu. MENDING Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Minute Range: Touch Duration: Instant Components: CM Cost: 1 Chakra Keywords: Ninjutsu Description: This jutsu repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot, you mend it, leaving no trace of the former damage. 5 SEALING ART: STRING LIGHT FORMATION Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 2 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You use your chakra to create a sealing formation stretching from yourself to a target creature you can see within range, in a straight line. The target creature must make a Charisma saving throw, reducing both your and the target’s movement speed to 0 on a failed save. This can be used with others targeting the same creature, increasing the Save DC by +1 for each additional user. At the end of the target creatures turn, they remake their save. MEDICAL RELEASE: VIRTUE Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Touch Duration: 1 Round Components: HS, CM Cost: 1 Chakra Keywords: Ninjutsu, Medical Description: You touch one willing creature, imbuing it with vitality. If the target has at least 1 hit point, it gains a number of temporary hit points equal to 1d4 + you ninjutsu ability modifier. The temporary hit points are lost at the end of the creatures next turn. D-RANK: ADVANCED TRANSFORMATION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: Concentration, Up to 10 minutes Components: HS, CM Cost: 3 Chakra Keywords: Ninjutsu Description: An advanced form of the transformation technique. When cast you transform your body into a physical object such as a weapon or object of Small or Medium size. While transformed into an object you take on its physical properties and function as this object. If transformed into a weapon you also take on its weapon properties. Others can wield and use you as a weapon so long as you maintain concentration on this jutsu. You cannot transform into any object that separates into multiple pieces, disconnects or has multiple moving mechanical parts, such as an electric fan or a Safe. If you do, these additional pieces or functions do not work or cannot be moved by any means. While transformed you cannot move or act or speak. You are aware of your immediate surroundings and can hear as normal, but are unable to cast jutsu or make attacks of any kind while transformed. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When Cast at B-Rank you can transform into large or smaller objects. ALARMING TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Cube Duration: 8 Hours Components: HS, CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu, Sensory Description: You set a chakra seal that expands 30 feet across the ground or surface it is placed on and it releases a very faint and mostly undetectable aura of chakra in a 30- foot cube. Until the Jutsu ends, an alarm alerts you whenever a creature touches or enters the Seals area. When you set the seal, you can designate creatures that don’t set off the alarm. You can also choose to make the alarm mental or audible. ARMS OF BUDDHA Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 10ft Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You focus your chakra throughout your body, culminating in a golden buddha forming around you and making multiple strikes with its 100 arms. Make a Melee Ninjutsu Attack against a creature within range, on a hit the target creature takes 4d6 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and the damage by 2d6. BEAST IMITATING ART: BAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Instant Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You inscribe into your scroll the image of a bat to blind you enemies. Make a ranged ninjutsu attack against a medium or smaller sized creature. On hit the creature becomes blinded as the bat latches onto their face blocking vision. As an action on the creatures turn, they can attempt to pull the bat off by making a Strength saving throw ending the blinded condition on a successful save. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and this number of attacks this jutsu can make by +1. However, each additional attack must target a different creature. 6 BEAST IMITATING ART: DEER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Instant Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You draw an image of a herd of deer that charge from your scroll towards your chosen target. Make a ranged ninjutsu attack. On a success, the target creature takes 2d8 in Bludgeoning damage and must make a Strength saving throw, being knocked prone on a failed save. If this jutsu is cast targeting a prone Creature, you do not roll disadvantage, instead rolling advantage and dealing an additional 2d6 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. BEAST IMITATING ART: LIZARD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You summon an inky lizard in a space you can see within range that can hold it. The lizard is a construct with the following statistics; • AC 12, 5d6 (20) Hit points. The lizard immediately after being summoned, screeches a menacing sound to those around it. All creatures who begin their turn within 10 feet of the lizard excluding you, must make a Wisdom saving throw. On a failed save they gain 1 rank of Fear. So long as a creature has ranks of fear gained as a result of this jutsu they cannot willingly approach the Lizard. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range of the lizards Screech by 5 feet. BEAST IMITATING ART: PIDGEON Classification: Ninjutsu Rank: D-Rank Casting Time: Up to 10 Minute Range: Self Duration: 24 Hours Components: HS, CM, CS, NT (Empty Scroll) Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You write in your scroll a message of any length that you can conceivably write within a 10 minute or less time span. Once complete, the writings manifest into the form of a bird of your description and now carry themselves. You can also cast this jutsu targeting a message already written of 25 words or less. The bird you create has 1 hp and an AC of 15. You then specify a location that you have previously visited and a recipient who matches a general description. You can also then give the bird a letter, scroll, tag, or similarly small object to deliver to this creature. The construct travels for the duration of the jutsu towards the location, covering no more than 50 miles per 24 hours. When the bird arrives, it turns back into the message when provided a scroll to be placed on and delivers any packages to the creature you described. The bird will only release the object to the creature you specified or if killed. The creature dissipates into non-staining ink when the message is delivered or it is killed. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and duration increases by 24 hours. When casting this jutsu at B-Rank or Higher, the bird becomes large in size and is capable of carrying two medium size creatures on its back. BEAST IMITATING ART: RATS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Minute Range: 1 Mile Radius Duration: 10 Minutes Components: HS, CM, CS, NT (Empty Scroll) Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu, Sensory Description: When you cast this jutsu you draw a horde of rats into your scroll. After 1 minute the picture is finished and the rats come to life scattering around. After a 10-minute delay, you can make a Ninshou check. Based on your level of success, you become aware of a variety of things within a 1-mile radius. • DC 10: You become aware of structures that are not hidden within range. This does not inform you of their specific location or size, only their general direction. • DC 15: You become aware of any non-hidden creatures within range. This does not inform you of their specific location or even the type of creature they are, only their general direction. • DC 20: You become aware of hidden structures within range. • DC 25: You become aware of the size of Structures and the types of creatures within range. • DC 30: You become aware of hidden creatures. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the range of this jutsu to 2 miles. If this jutsu is cast at S-Rank, increase the range of this jutsu to 3 miles. 7 BEAST IMITATING ART: RETRIEVAL HAWK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 120 feet Duration: Concentration, up to 1 minute Components: HS, CM, CS, NT (Empty Scroll) Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You hurriedly draw an image of a hawk to retrieve something for you. The hawk breaks out of your scroll and attempts to retrieve an object no more than 10 pounds and bring it to a destination of your choosing within range. The hawk has a fly speed of 45ft, AC of 15 and 1 hp. The hawk must stay within the range of this jutsu from the caster at all times and does not require the caster's actions to command aside from its initial creation. The destination of delivery can be changed as a bonus action on the casters turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the hawks speed by 10 feet, the weight it can carry by 10 pounds and this jutsu’s range by 30 feet. BEAST IMITATING ART: SNAKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: When you cast this jutsu you draw an image of two snakes into your scroll infusing chakra into it making it come to life. You command the pair of snakes to wrap around your enemies. Target up to two creatures within range. Each creature must make a Strength saving throw. If any of the creatures are within 5 feet of each other they each make the save at disadvantage. On a failed save, they are restrained by the snakes as they wrap around them. A creature restrained by this jutsu, may as an action on their turn attempt another Strength save to end this condition. If affect creatures are within 5 feet of each other, when one creature succeeds all creatures within 5 feet of them, restrained conditions ends. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets by +1. BODY CAMOUFLAGE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 1 minute Components: HS Cost: 5 Chakra Keywords: Ninjutsu Description: You coat your body in chakra and begin to imitate the color and texture of the area around you blending in like a chameleon. For the duration, roll an additional +4 adding the result to your stealth checks. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and you can target one additional creature for each rank and they gain the benefits of this jutsu as well. BODY FLICKER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: 1 Round Components: HS, M Cost: 3 Chakra Keywords: Ninjutsu Description: You gain a mastery of movement, allowing you to cover much greater distance in a shorter amount of time. Until the end of your next turn, increase your speed by 30 feet. CALLING ON TEARS TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (30 Foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You manifest chakra around your tongue and throat as you use it to vibrate and magnify all sound escaping your mouth. You then release a stunning scream in an attempt to incapacitate all that hear it. All creatures in a 30-foot cone originating from you must make a Wisdom saving throw, being Deafened and Dazed until the end of their next turn on a failed save. Additionally, any traps such as explosives, trap doors or pressure plates that are within this jutsu’s range are triggered. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range by 5 feet. CATAPULT TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 action Range: 90 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Ninjutsu Description: Choose one object weighing no more than 1 bulk within range, that isn’t being worn or carried. The object flies in a straight line up to 90 feet in a direction you choose before falling to the ground, stopping early if it impacts a solid surface. If the object would strike a creature that creature must make a Dexterity saving throw. On a failed save, the object strikes the target and stops moving. In either case, both the object and the creature or solid surface takes 3d8 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the maximum bulk of the objects that this jutsu can use increases by 1 bulk, and the maximum distance by 10ft. This jutsu’s damage also changes depending on the affected object’s bulk: 1 Bulk or less: 3d8. 2 Bulk: 4d8 3 Bulk: 5d8 4 Bulk: 6d8 5 Bulk: 7d8 8 CHAKRA BOLT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Ninjutsu, Clash Description: You manifest a 4-inch sphere of pure chakra at a creature you can see within range. Make a ranged ninjutsu attack. On a hit, the target takes 3d6 damage. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. Additionally, you gain one of the following benefits based on the Damage type of this jutsu. • Earth: The target must make a Strength saving throw being Bruised on a failed Save. • Wind: The target must make a Strength saving throw being pushed back 15 feet and being knocked prone on a failed save. • Fire: Each creature within a 5-foot radius sphere of the target creature must make a Dexterity saving throw, being burned on a failed save. • Cold: Each creature within a 5-foot radius sphere of the target creature must make a Constitution saving throw, being chilled on a failed save. • Lightning: The target must make a Constitution saving throw, being shocked until the end of their next turn. • Force: Changed damage die to d8. The target must make a Dexterity saving throw being Dazed. CHAKRA LEAPING Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus action Range: Self Duration: Instant Components: HS, M Cost: 3 Chakra Keywords: Ninjutsu Description: You focus chakra into your legs, increasing your jumping Strength astronomically. Until the end of this turn, Double your jumping height. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, the duration of this jutsu becomes 1 minute. If this jutsu is cast at S-Rank, the duration becomes 1 hour. CHAKRA MARK Classification: Ninjutsu Rank: D-Rank Casting Time: Special Range: Touch Duration: 10 Minute Components: CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu, Sensory Description: You create a chakra seal and attempt to place it on a creature, structure or construct you are able to touch. When you score a hit with a melee attack or a ranged attack, you are able to mark a creature. This does not work if another creature, construct or structure intercepts the attacks damage. While a creature, construct or structure is marked with this jutsu and is within 1 mile of you, you become aware of the existence of this seal, but not its immediate location. You gain a +4 bonus to all checks made to find or track the marked creature. Additionally, if you can teleport you can choose to teleport to a marked creature, construct or structure so long as they are within 1 mile of you. Once you teleport in this way, the mark vanishes, ending this jutsu. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. At C- Rank This jutsu’s Duration becomes 1 Hour. 8 Hours at B- Rank, 24 Hours at A-Rank, Permanent at S-Rank. CHAKRA SHIELD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you take damage. Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Clash Description: You manifest a swirling barrier of chakra around you protecting you from the triggering attack. You gain 12 Temporary Hit points. If you have a nature release, this jutsu gains a single nature release keyword that you can cast, and additional effects base on the Nature release. Your shield gains one of the following benefits based on the chosen nature release. If you do not have a nature release this shield instead has 16 temporary hit points. • Earth: This jutsu gains the Construct keyword. Your shield has resistance to Cold damage, vulnerability to lightning Damage and once cast leaves behind an Quake Shard in a 5ft cube within 5ft of you. • Wind: Your shield has resistance to Lightning Damage, vulnerability to Fire Damage and once cast all creatures of your choice within 5 feet of you gains 1 rank of bleed. • Fire: Your shield has resistance to Wind Damage, Vulnerability to Cold Damage and all creatures within 10 feet of you takes fire damage equal to your Ninjutsu ability modifier. • Water: Your shield has resistance to fire damage, vulnerability to earth damage and if this jutsu is cast near a sufficient source of water, reduce the cost of this jutsu by -2. • Lightning: Your shield has resistance to Earth damage, vulnerability to wind damage and you gain a +2 to Dexterity saving throws until the beginning of your next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points you gain by +6. 9 CHAKRA SKIN Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Until Short Rest Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You coat yourself in a Protective aura of chakra, protecting you from damage. When you cast this jutsu, you lose the benefits of any Armor you are wearing, utilizing this Jutsu’s AC calculation for its duration. Your AC becomes 13 + your Intelligence Modifier + Half of your proficiency Bonus. This jutsu ends if you dismiss it as a Bonus action. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank or higher, you gain Temporary hit points equal to your Ninjutsu ability modifier. As a Bonus action on your turn, you can replenish these Temporary hit points for 5 Chakra. If this jutsu is cast at B-Rank or higher, increase the AC this Jutsu grants by +1. If this jutsu is cast at A-Rank or higher, the Temporary hit points gained, is instead equal to half of the casters Ninjutsu ability score. If this jutsu is cast at S-Rank or higher, increase the AC this Jutsu grants by +2, instead of +1. DARKVISION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Sensory Description: You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has Darkvision out to a range of 60 feet. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can affect with this jutsu by +1. ENHANCED REACTIONS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 8 Hours Components: HS Cost: 3 Chakra Keywords: Ninjutsu, Sensory Description: You store chakra in pockets behind your eyes and joints in preparation to move with a burst of speed at any moment. The first time you would roll initiative for the duration, you may add 1d4+1 to your roll. This jutsu then ends. HOLLOW STARS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 120 feet Duration: Instant Components: HS, CM, CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You force your palms together before pointing them towards the sky, shooting our four bursts of chakra that take the shape of small stars before falling to the ground in four different spaces of your choice within range, dealing damage to objects, creatures and structures occupying the space. Objects, creatures and structures in the selected spaces each take 1d4+1 damage. A creature, object or structure in the area of more than one star, takes the damage of each of these stars. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. A creature can only ever be affected by the following effects twice per casting. • Earth: You create a 10-foot cube of difficult terrain, centering on each space selected. This space remains difficult terrain until cleared. • Wind: Each creature within 5 feet of the selected space makes a Strength saving throw. On a failed save they are thrown back 5 feet from the target space and falling prone. • Fire: Each creature within 5 feet of the selected space makes a Dexterity saving throw. On a failed save they takes damage equal to the damage dealt to the target space. • Cold: Each creature within a 10-foot radius sphere of the target space must make a Constitution saving throw, being chilled on a failed save. • Lightning: If two or more selected spaces are within 15 feet of each other, lightning arcs between them in a straight line so long as there are no obstructions. Creatures in the Arcs path must make a Constitution saving throw, being shocked on a failed save • Force: Damage die increases to a d8. Also, creatures occupying select spaces are bruised. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of stars made by +1. 10 INK CLONE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet Duration: 1 Minute Components: HS, CM, CS, NT (Vial of Ink) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into the ink as you then infuse a chakra seal into it. You conjure a clone of yourself made of ink. They look, sound and act as your describe. The cost of these clones cannot be reduced below half. An Ink clone has 1 Hit point and can be no farther than 90 feet from you. It can walk, talk and interact with things but it cannot declare an attack. This clone acts at the end of your turn. As a bonus action you can command the clone to attack. When you do it pretends to weave hand seals to cast a jutsu targeting a single creature within 60 feet of it. The target creature makes a Wisdom (Insight) Check vs your Ninjutsu Save DC. On a failure, they become distracted by the clones antics. A creature distracted in this manner grants the next attack targeting it advantage and they are treated as surprised against this attack. LOCK/RELEASE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Until dispelled Components: HS, CS Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You place a chakra seal on a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and creatures you designate when the jutsu is used can open the object normally. You can also set a password that when spoken within 5 feet of the object releases the jutsu for 1 minute. This jutsu also works inversely allowing you to attempt to lock pick using your chakra alone. Make an Intelligence (Chakra Control) check vs the Locks DC as if you are picking a lock using a Security kit. Creatures attempting to open the object you have locked with this jutsu must make an Athletics check vs your Ninjutsu save DC to force open the object. MEDICAL RELEASE: ACID ARMOR Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of a highly dangerous aura of chakra that intercepts attacks for you and harms those who would try to touch you. You gain 14 temporary hit points. Creatures who would deal damage with a melee attack take 6 acid damage each time they would deal damage, while you have temporary hit points granted by this jutsu. A creature who would strike you with a weapon attack or unarmed strike whose rank is equal to or less than the rank this jutsu was cast at has their weapon suffer a permanent -1 penalty until fixed by the Mending ninjutsu. An unarmed attack such as your fists or legs can be fixed with any jutsu with the medical keyword that restores hit points or removes conditions. A weapon or limb which has reached a -5 penalty breaks, being destroyed by all of the acid covering it. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points by 7 and the acid damage by 3. MEDICAL RELEASE: ACID BEAM Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (60-Foot line) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of a powerful beam meant to melt through everything in its path. All creatures in a 60-foot long, 5-foot-wide line originating from you must make a Dexterity saving throw. On a failed save, you deal 3d6 acid damage and at the beginning of an affected creature’s next turn, they take 3d4 acid damage. Constructs and structures made of earth, metal or wood take double damage as the acid eats through them. At Higher Ranks: For each rank you cast this jutsu", created_at: NOW, updated_at: NOW },
  { _id: "1f881c4601245aad9d5e023e", name: "CROSSFIRE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: ["katon"], casting_time: "1 Action.", range: "250 feet", chakra_cost: "Special (77 Chakra)", components: "HS, CM", duration: "Instant", description: "You weave handsigns as you select one space you can see within range. The point you choose erupts with 4 different 5 feet wide, 60 feet long beams of blazing heat that fire in different directions that all originate from the point you chose. No beam can fire in the same direction and must all fire at the same time. All creatures who are in the range of any beam fired must make a Dexterity saving throw taking 12d6+12 fire damage and gaining 3 ranks of the burned condition on a failed save or half as much damage on a successful save. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the targeted damage by 3d6+3. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-2: No Change, +3-4: Increase the width of the jutsu by 5 feet, +5: Increase the width of the jutsu by 10 feet.) FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d956bb79c664f9d4ecd32439", name: "DUST TO DUST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "90 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You snap your fingers in an attempt to turn a burning target into dust. You can only target a creature currently under the burned condition forcing them to make a Constitution saving throw. On a failed save they take twice the maximum possible damage from your burned condition. If they failed by 5 or more, they instead take three times the maximum possible damage from the burned condition. If they failed by 10 or more, they instead take four times the maximum possible damage from the burned condition.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0f603067b61374b7981c7499", name: "EVERFLAME FRUIT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["katon"], casting_time: "1 Action.", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a 1 apple sized gem or shard of Fire Release Chakra infused with Medical Release Chakra that feels scalding to touch. You spend all of your Chakra Die, rolling and recording the result. A creature can use its bonus action to eat the gem. Eating a gem forces a creature to roll all of its Hit die, spending them all. A creature can also spend an action feeding this to a dead or dying creature who’s been dead for no longer than 1 minute. The creature regains Hit points equal to the result of their Hit Die + The casters Chakra die roll. A creature can gain the benefits of this jutsu once per long rest. If a creature attempts to gain the benefits of this jutsu more than once per long rest, each time after the second, they take an amount of fire damage equal to three times the casters Ninjutsu Save DC + Twice their Constitution score. This damage cannot be resisted or reduced by any means. 93 FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a1632a03fd822cb510d7be9b", name: "FIRE WALL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["katon"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You create a standing wall of fire, 1 foot thick, up to 60 Feet long, and 20 feet tall. When the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 5d10+5 fire damage, or half as much damage on a successful save. One side of the wall, selected by you when you cast this jutsu, deals 5d10+5 fire damage to each creature that ends its turn within 10 feet of that side or inside the wall. A creature takes the same damage when it enters the wall for the first time on a turn or ends its turn there. The other side of the wall deals no damage. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "df066b649f31c9221ff5622f", name: "GREAT FIRE CAGE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "b3b9a80a8acefa31d6905369"], elements: ["katon"], casting_time: "1 Full Turn.", range: "120 Feet (30ft Cube)", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You spend your entire turn focusing and weaving hand seals to achieve a state of absolute focus. You create a massive Cage of fire capturing all inside the radius of the jutsu. Creatures attempting to leave the area must make a Dexterity, Constitution and Strength saving throw. On a failed Dexterity Save, target creatures take 5d10+5 Fire Damage. On a failed Constitution Save, the target creature gains 2 ranks of Exhaustion. On a failed Strength Save, the target creature is blown back 30 feet. Target creature must make at least 2 of the 3 saves in order to escape, failing more than 1 pushes them back towards the inside of the cage. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4b6bf3b7f0fc23c4b623da7d", name: "GREAT FLAME BOMB", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["katon"], casting_time: "1 Action", range: "Self (120-Foot Line)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You knead chakra in your stomach and superheat it until you exhale it from your gut at insane speeds and force. Creatures within 5 feet of you must make a Strength saving throw being thrown back 10 feet on a failed save. You fire a Stream of blue hot fire in a 10-foot wide, 120-foot-long line directly in front of you causing objects and the environment within 5 feet of you to be set on fire. Creatures in must make a Dexterity saving throw, taking 9d6+9 Fire damage and 2 ranks of the burned condition on a failed save or half as much damage on a success. Objects within 10 feet of the stream of fire ignite if they are not being worn or held. The stream leaves behind a line of blue fire from you to the end of the 120- foot path. The fire remains for 1 minute and will spread until put out.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "89731b022814a717ab1b460b", name: "HEATED SUN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a globe of white-hot fire in a space you select within range, that you can see. Creatures who begin their turns within 20 feet of the Globe must make a Constitution saving throw, gaining the burned condition on a failed save. Flammable objects within 20 feet of it ignite, and metal begins to become too hot to touch causing those wearing or holding metal within range to take 9d4+9 Fire damage at the beginning of each turn they are in contact with it. As an action, you may move this globe 30 feet in any direction from its current placement. If this globe would enter a space another creature occupies, that creature must make the above saving throw. On a failed save, the creature gains 3 Ranks of the burned condition.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase damage by 1d4+1. 94 FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "623bbda459fcb91342b5500e", name: "HEAVENLY FLAME", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "5 feet", chakra_cost: "12 Chakra", components: "HS, CM, M", duration: "Instant", description: "You compress all of your Fire Release chakra onto the surface of your skin and release it when you hit a creature with an unarmed attack creating a targeted explosion of white-hot flame. As a part of the action to cast this ninjutsu, make a melee ninjutsu attack, against one creature within range, otherwise the jutsu fails. On a hit, the target suffers your unarmed attacks effects as normal and take 6d12+6 fire damage as the fire erupts on contact. The target creature must make a Constitution saving throw, gaining two ranks of the burned condition and falling prone on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at S-Rank, increase the number of attacks it makes by +1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b17b63e2824f810b7fad2667", name: "INVESTITURE OF FLAME", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes.", description: "Flames race across your body, shedding bright light in a 30-foot radius and dim light for an additional 30 feet for the Jutsu’s duration. The flames don’t harm you or any allied creature. Until the jutsu ends, you gain the following benefits: • You are immune to fire & wind damage. • Resistant to Bludgeoning, piercing and slashing damage. • Vulnerable to Cold damage. • Speed is increased by 15 feet. • Any hostile creature that moves within 10 feet of you on any turn, begins it turn or ends its turn there, takes 2d10 fire damage. • You can use your bonus action to create a line of fire, 15 feet long and 5 feet wide extending from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 4d12+4 fire damage and gains the burned condition on a failed save, or half as much damage on a successful one. 95 FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f20d015010fe088d3694f4a6", name: "PYRONADO", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["katon"], casting_time: "1 Action", range: "5-foot Radius", chakra_cost: "12 Chakra", components: "HS, CM, CS, W (any melee)", duration: "Concentration, Up to 1 minute", description: "You bathe your weapon in Fire Release Chakra and throw it, spinning the weapon like boomerang. The Weapon spins around you striking all creatures who come within 5 feet of you for the first time or begin their turns there. The first time each turn a Creature enters its range must make a Dexterity saving throw. On a failed save they take damage equal to your weapons damage + 6d6+6 and the burned condition or half as much and no additional effects on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the radius of this jutsu by 5 feet. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0e0ee8c25e64e36776812ff0", name: "STARFALL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["katon"], casting_time: "Full Turn Action", range: "500 Feet", chakra_cost: "Special (77 Chakra)", components: "HS, CM, CS", duration: "Concentration, Up to 1 Minute", description: "You manifest a series of shimmering shards of earth 300 feet in the air that floats above you for the duration. As an Action, Bonus Action, or Reaction you can call down these shard to bombard a space you can see within range. A creatures within 10 feet of the selected space must make a Dexterity saving throw taking 9d8 Earth damage on a failed save or half as much on a successful one. A creature who would make a second saving throws in the same turn as the result of this jutsu instead would take 9d6 Earth damage on a failed save or half as much on a successful one. A creature who would make a third saving throws in the same turn as the result of this jutsu instead would take 9d4 Earth damage on a failed save or half as much on a successful one. EARTH RELEASE: STONE DRAGON Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM Cost: 20 Chakra Keywords: Earth Release, Ninjutsu, Construct Description: You conjure a giant Stone construct made of earth, dust, soil, and sand forming a Large Dragon that you can command as a bonus action. It acts at the end of your turn and uses your Ninjutsu attack bonus and Save DC when an effect calls for it.", at_higher_ranks: "For each rank you cast this jutsu above A- Rank, increase the cost of this jutsu by 3 and the dragons hit points by 20. Large Construct, unaligned Armor Class 13+ Your Ninjutsu Ability Modifier Hit Points 150 (10d12 + 80) Speed 40 ft. STR DEX CON INT WIS CHA 21 (+5) 10 (+0) 26 (+8) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Cold, Poison, Psychic, Bludgeoning, Piercing and Slashing. Condition Immunities Charmed, Exhaustion, frightened, stunned, petrified, poisoned. Damage Vulnerabilities Lightning Senses Darkvision 60 ft., passive Perception 10 Immutable Form. The Earth Dragon is immune to any Jutsu or effect that would alter its form. Elemental Weapons. The Dragons attacks are chakra enhanced. Multiattack. The Earth Dragon can attack 3 times with its Bite. Bite. Melee Weapon Attack: reach 10 ft., one creature. Hit: 2d10 + 5 Earth damage. Dust Breath (Recharge 7-8): The dragon exhales Dust in a 30- foot cone. Each creature in that cone must make a Dexterity saving throw, taking 55 (10d10) Earth damage and 3 ranks of bruised on a failed save, or half as much damage on a successful one 64 EARTH RELEASE: STONE FOREST Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self (30 Foot Cube) Duration: Instant Components: HS, CM Cost: 19 Chakra Keywords: Earth Release, Ninjutsu Description: You focus a large amount of chakra into the palms of your hands and place them on the ground. You create a field of spiked earth in a 30-foot cube originating from you. Creatures of your choice caught in range must make a Dexterity saving throw, taking 10d8 Earth Damage on a failed save, and half on a successful one. The area that was affected by the jutsu is now plagued by massive Stone spikes that reach as high as 10 feet and criss cross into a forest of spikes making it difficult terrain to traverse. Creatures inside the affected area roll at disadvantage when making Wisdom checks to perceive something. The affected area counts as a Single Quake Shard. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. EARTH RELEASE: STONE NEEDLE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 90 Feet Duration: Instant Components: HS, CM Cost: 18 Chakra Keywords: Earth Release, Ninjutsu Description: You focus a large amount of chakra into a single thin but incredibly fast spear of earth that’s 90 feet long and 5 feet wide. Creatures in range must make a Dexterity saving throw taking 9d10 earth damage gaining 4 ranks of bruised and knocked prone on a failed save, or half as much damage and no further effects on a successful save. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. S-RANK: EARTH RELEASE: DIAMOND BONE HARDENING Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 25 Chakra Keywords: Earth Release, Ninjutsu Description: You use your mastery over chakra and Earth release to transform your bones into material simulating diamonds in toughness and weight, while also gaining some control over how they move and the speed at which they regenerate. For the duration, you regenerate 20 hit points at the beginning of each of your turns and gain Resistance to all damage excluding Lightning. EARTH RELEASE: METEOR FALL Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 1 Mile Duration: Instant Components: HS, CM Cost: 30 Chakra Keywords: Earth Release, Ninjutsu, Fuinjutsu, Kinjutsu Description: Upon completion you select 4 different points you can see within range. Each creature in a 30- foot radius sphere centered on the point you select must make a Dexterity Saving Throw against your Ninjutsu Save DC. Massive Chunks of stone earth and mud comes raining upon the selected areas. A creature takes 10d10 Bludgeoning & 10d10 Earth Damage and is Dazed and knocked Prone on a failed save, or half as much damage on a successful one. A creature can only be affected by one meteor per casting. EARTH RELEASE: MOON FALL Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Full Turn Action Range: 1 Mile Duration: Special Components: HS, CM Cost: Special Keywords: Ninjutsu, Earth Release, Kinjutsu Description: Upon Competition of your Jutsu's handsigns you manifest a single super huge Quake Shard 1 mile in the air. Spend chakra in multiples of 35 up to twice. For every 35 chakra spent this way, the Gargantuan Moon like structure you manifest grows in size and affects a larger area when dropped. You cannot reduce the cost of this jutsu by any means. 35 Chakra: The Moon like structure falls on a point you can see within range crushing a space equal to a 30- foot sphere. Each creature who are within the 30-foot sphere and has a way to escape the radius be it by their base movement speed or a jutsu they could cast as a bonus action, makes a Dexterity saving throw. On a successful save, they are able to use their movement or a jutsu which could allow them to escape the sphere. On a failed save they take 22d12 earth damage. All creatures who are within 30 feet of the sphere, including creatures who succeeded the previous saving throw must make a Strength saving throw as the shockwave from such a massive impact deals significant damage to the area. A creature takes 12d6 Bludgeoning & 12d6 Earth Damage on a failed save or half as much damage on a successful one. 70 Chakra: The Moon like structure falls on a point you can see within range crushing a space equal to a 60- foot sphere. Each creature who are within the 60-foot sphere and has a way to escape the radius be it by their base movement speed or a jutsu they could cast as a bonus action, makes a Dexterity saving throw. On a successful save, they are able to use their movement or a jutsu which could allow them to escape the sphere. On a failed save they take 30d12 earth damage. All creatures who are within 50 feet of the sphere, including creatures who succeeded the previous saving throw must make a Strength saving throw as the shockwave from such a massive impact deals significant damage to the area. A creature takes 15d6 Bludgeoning & 15d6 Earth Damage on a failed save or half as much damage on a successful one. 65 EARTH RELEASE: PARTIAL ASSIMILATION CYLINDER Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: Self (25 feet) Duration: Concentration, up to 1 minute Components: HS, CM Cost: 25 Chakra Keywords: Earth Release, Ninjutsu Description: When you cast this Jutsu, and as an Action on following turns for its duration you can form a cylinder 10 Feet in diameter and 25 feet long by using chakra to generate molecule sized earth particles. Anyone in the cylinder will begin to be deconstructed on a molecular level. Creatures that start their turn within this cylinder must make a Dexterity Saving Throw. On a failure a creature takes 14d10 Force Damage. If a creature is reduced to less than ½ of their hit points by this damage the user decides on which appendage the target creature lost. (Arm or Leg). If a creature is reduced to 0 Hit Points, they are turned to dust and are immediately killed. EARTH RELEASE: PARTICLE ASSIMILATION CUBE Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, CM Cost: 25 Chakra Keywords: Earth Release, Ninjutsu Description: You form a cube 5 Feet in diameter by using chakra to generate molecule sized earth particles. The Cube glows white. You can throw the cube up to 30 feet or attempt to hit someone with it. Anyone hit by the cube will begin to be deconstructed on a molecular level. Make a melee or ranged Ninjutsu Attack. On a hit a creature takes 16d12 Force Damage. If a creature is reduced to less than ½ of their hit points by this damage, the user decides on which appendage the target creature lost. (Arm or Leg). If a creature is reduced to 0 hit points, they are turned to dust and are immediately killed. EARTH RELEASE: STAR SHATTER Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Full Turn Action Range: 1 Mile Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 30 Chakra Keywords: Ninjutsu, Earth Release, Kinjutsu Description: You create a single star shaped Quake Shard in the sky, 1 mile in the air before you cause it to shatter. Select a space you can see within range. All creatures of your choice within 120 feet of the selected space must make a Strength saving throw as the weight of a dying star is thrust upon them. On a failed save they are Stunned and knocked Prone as they become unable to move and find it hard to even breathe. A creature who begins their turn in this space, ends their turn in this space, or enters this space for the first time must make the Strength saving throw. A creature Stunned by this jutsu takes 9d8 Earth damage at the beginning of their turn. A creature Stunned by this jutsu takes 9d8 Earth damage at the end of their turns if they do not make the saving throw to end this jutsu’s effects. A stunned creature makes a Strength Saving Throw at the end of their turns (They do not automatically fail as a result of being Stunned). On a successful save, they end the Stunned condition on themselves. 66 WIND RELEASE Wind Release is the rarest of the five nature transformations, but those who can use it are able to cut through anything. Some shinobi use it by channeling wind chakra into weapons, making the blades far sharper and giving them greater reach. Wind Release can also be exhaled from the user's mouth, such as to blow away everything in the area, or generated with the user's hands, allowing precision strikes. Although Wind Release has naturally good range and power, it can be further enhanced by compressing it or layering different wind streams together. Wind Release can easily launch particles into the air, whether to create dust clouds that conceal the user's movements or sand storms that perforate targets. Wind Release is naturally strong against Lightning Release and weak against Fire Release Special Effect: Some Wind release jutsu will mention that they cause Swirl, when this happens, Creatures who would fail their saving throw, spreads all Elemental conditions currently affecting them around to all creatures, excluding the caster within 5 feet of them. Creatures hostile to the caster within 5 feet of the failing one gains 1 rank of all elemental conditions currently aff ecting it. Prerequisite: You must have the Wind Release Affinity to learn jutsu with the Wind Release Keyword. D-RANK: WIND RELEASE: AIR BULLET Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60-feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a small sphere of compressed air in the palm of your hand before launching it at a target creature that you can see within range. You fire two bullets of air. You can direct the bullets at the same target or different ones. Make two ranged ninjutsu attack, dealing 2d8 wind damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of attacks by +1. WIND RELEASE: AIR CURRENT DANCE Classification: Ninjutsu Rank: D-Rank Casting Time: Bonus Action Range: Self (10 Foot radius Sphere) Duration: 1 Minute Components: HS, CM Cost: 3 Chakra Keywords: Wind Release, Ninjutsu Description: You whip air currents around your hands and generate a dust cloud cloaking yourself and anyone in the radius of this jutsu in a thick cloud of dust and debris. All creatures are treated as if they have total cover while inside the cloud, from creatures outside the cloud and vice versa. This total cover does not prevent attacks or jutsu from entering or exiting the cloud. Creatures other than you have disadvantage on perception checks to see through the cloud if they have special vision like Chakra Sight. Also, creatures other than you, vision, is treated as if they are in dim light while inside the cloud. WIND RELEASE: BLURRING WIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage. Range: Self Duration: 1 Round Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: Your body becomes blurred, shifting and wavering to all who can see you. When cast, the triggering attack rolls an additional d20, taking the lower result. For the duration, until the beginning of your next turn, hostile creatures have disadvantage on attacks against you. An attacker is immune to this effect if it doesn't rely on sight, as with blindsight, or can see through illusions, as with truesight. 67 WIND RELEASE: BUFFETING AIRWAVES Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You create currents of extremely strong and compressed beams of air strong enough to Crack stone and divert waterfalls. Make a ranged ninjutsu attack. On a hit, target creature takes 4d4 Wind Damage and must make a Strength save. On a failed save they are pushed back 20 feet, knocked prone, gaining 1 rank of bleeding, and causing Swirl. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d4 and the ranks of bleed by +1 WIND RELEASE: COLLECTIVE GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 15 feet Duration: 1 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu, Medical Description: You collect wind release chakra and infuse it into your Medical Release technique. One willing creature within range breathes in this Medically infused wind. For the duration a creature who has breathed this wind does not need to breathe, Ignores the effects of 2 rank of Exhaustion and when they would regain hit points as the result of a Ninjutsu with the Medical Keyword, they regain an additional 1d4 Hit points. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, Ignores the effects of up to 1 additional rank of Exhaustion. WIND RELEASE: COUNTER BREEZE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage from a Ninjutsu or Taijutsu. Range: Self Duration: 1 Round Components: HS, CM, M Cost: 5 Chakra Keywords: Wind Release, Ninjutsu, Construct, Clash Description: You create a condensed bubble of super dense air around you in an attempt to deflect incoming attacks. Roll 3d8. The result of the roll is the amount of damage your air Bubble can prevent before it bursts. This lasts until the beginning of your next turn. Lightning Damage deals half as much damage to your air bubble and Fire Damage deals twice as much. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and roll an additional 1d8. WIND RELEASE: DUST WIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot Cone) Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You generate a strong wind from your lungs with a single breath. When you exhale you kick up a cloud of dust, dirt, and other loose debris in the target radius. Creatures who are in the affected range must make a Wisdom Saving throw. On a failed save, affected creatures cause Swirl and are considered blind until the end of their next turn on a failed save. On a successful save no further effects are applied. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 10ft WIND RELEASE: FEATHER FALL Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you begin falling. Range: Self Duration: 1 Minute Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You create a single high-pressure stream of air from either your hands or feet slowing your descent while falling by 60 feet per round until the jutsu ends. If you land before the ninjutsu ends, you take no falling damage and land on your feet and the jutsu ends. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select 1 additional target for this Jutsu’s benefits within 30 feet of you. WIND RELEASE: GALE PALM Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: HS, CM, M Cost: 4 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You clasp your hands together coating your open palms in a powerful gale. You make a Melee ninjutsu attack on a target creature or object. On a hit creature take 3d6 Wind Damage and make a Strength saving throw to resist being knocked back 20 feet and causing Swirl. On a successful Strength save they suffer no additional effects. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 68 WIND RELEASE: GRYPHONS WING BEAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (20-foot radius) Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You create two wings made of wind release chakra that beats with enough force to feel like a tornado is passing through. All creatures within range must make a Strength saving throw to resist being bruised, knocked prone and causing Swirl. A creature who is bruised finds it difficult to maintain concentrating on multiple jutsu. If a creature is concentrating on more than 1 jutsu, they must lose concentration on all but 1 jutsu. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the range by 10 feet. WIND RELEASE: LIONS GROWL Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 Minute Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You weave Wind Release Chakra together, creating a thin veil of chakra in the shape of a Lion around you. This chakra then collapses on you granting you benefits as listed below; • Increase your Movement Speed by 15 feet. • You gain a +2 bonus to Ninjutsu Attack Rolls. • Ninjutsu, you cast with the Wind Release Keyword that has a range of at least 5 feet, increases their range by 10 feet. WIND RELEASE: PALM VORTEX Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (10 Foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a localized vortex of cutting wind. All creatures within range must make a Dexterity saving throw to avoid being horrendously slashed. On a failed save creatures take 3d6 wind damage and being pulled 5 feet closer to you or half as much on a successful save and no additional affects. If a creature is currently affected by any elemental condition, you trigger the residual elemental energies, igniting them again. A creature under the effects of an elemental condition makes their saving throw at Disadvantage. On a failed save such a creature instead takes 3d8 + Your Ninjutsu Ability Modifier damage, of their select conditions type. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 or 1d8. WIND RELEASE: PASSING TYPHOON Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot radius sphere) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You create a powerful current of strong winds in a 15-foot radius sphere, centering on you. This field of wind also follows you. For the duration, while within its area, it deafens other creatures, extinguishes unprotected flames, becomes difficult terrain to creatures other than you and disperses vapors, gases and fogs that can be dispersed by strong winds. Additionally, ranged attacks have disadvantage if they pass into or out of the area of this jutsu. WIND RELEASE: PEACOCK WHIRLWIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30-feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You generate a strong wind from swiping one of your limbs. A gust of wind is generated in a 30-foot long 5-feet wide in a straight line originating from you. Creatures in the line must make a Strength saving throw, taking 2d6 wind damage, is knocked prone, gains 1 rank of bleeding and causing Swirl on a failed save, and only half damage and no further effects on a successful save. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the ranks of bleed by +1. WIND RELEASE: RAGING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet (15-foot radius) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You manifest a powerful torrent of wind, strong enough to lift and throw most creatures. Select a space you can see within range. A spiraling torrent of wind erupts upwards. All creatures within 15 feet of the chosen space, must make a Strength saving throw. On a failed save they are thrown 30 feet upwards being dazed, taking falling damage, falling prone and causing Swirl. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the height they are thrown upwards by 15 feet. 69 WIND RELEASE: RAGING VORTEX Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You encircle a willing creature with potent Wind Release Chakra. For the duration, you magnify the targets physical capabilities. The target creature adds 1d4 to all Strength and Dexterity skill checks and saving throws. Their movement speed is increased by 15 feet and melee attacks they make that deal damage deals an additional 1d6 Wind Damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets you can affect by +1. WIND RELEASE: SECOND WIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You breathe in deeply filling your lungs and blood with chakra filtered oxygen accelerating its blood flow and slightly rejuvenating you. You recover 2d6+ Your Ninjutsu ability modifier hit points. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and roll an additional 1d6. WIND RELEASE: SLICING AIRWAVES Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM, M Cost: 4 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a powerful current of extremely strong and thin currents of wind. You swipe your hand towards your target. Make a Ranged Ninjutsu attack, creatures take 3d8 wind damage and gain 1 rank of bleeding on a hit. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d8 and ranks of bleeding by +1. WIND RELEASE: SPLITTING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a field of oppressive and potent wind that slashes and buffets any instance of Hand Signs (HS). Select a space you can see within range, all creatures within 20 feet of the chosen space who would cast a jutsu with Hand Sign (HS) component immediately takes 2d6 Wind Damage and must make a Constitution Saving throw gaining the bleeding condition on a failed save. As a bonus action on your turn, you may move the field up to 30 feet in any direction to a space you can see within range. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the area affected by 5 feet, and the damage by 1d6. WIND RELEASE: SUPPORTING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction to making a Strength, Dexterity or Constitution saving throw Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You throw your hands forward creating a compressed blast of air assisting you in a variety of physical tasks; from escaping, fending off an attack, or dispersing a hazardous gas. As a reaction, when you are forced to make a Strength, Dexterity, or Constitution saving throw against a Ninjutsu or Taijutsu, you instead use your Ninjutsu ability modifier in place of your Strength, Dexterity or Constitution for the triggering roll. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at C-Rank you add your proficiency to the roll if you aren’t already proficient. If cast at B-Rank you may select another creature within 20 feet of you to gain the benefits of this jutsu, using your Ability modifier and proficiency bonus. If cast at A-Rank, creatures benefiting from this jutsu roll at advantage. If cast at S- Rank, all creatures of your choice within 30 feet of you can gain this jutsu’s benefit. 70 WIND RELEASE: VACUUM BOMB Classification: Ninjutsu Rank: D-Rank Casting Time: Special Range: 60 feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a single point of high-density air pressure using your Wind Release Chakra before expanding it and creating a series of reactions. All creatures currently affected by an elemental condition who would have a jutsu cast on them that triggers the swirl effect, potentially passes all such conditions around to other creatures near them in an expanded space with more volatility. When a creature would have the Swirl effect trigger on them, you can cast this jutsu as a part of the same action. All creatures within 20 feet of the triggering creature who failed their save gains two ranks of all elemental conditions the triggering creature had. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the area affected by 5 feet. WIND RELEASE: VACUUM RAIN Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet (20-foot cylinder) Duration: Concentration, Up to 1 minute Components: HS, CM Cost: Special (28 Chakra) Keywords: Wind Release, Ninjutsu, Combination Description: You create a powerful updraft that sucks the oxygen and air upwards robbing creatures of the ability to breathe within range. All casters of this jutsu create a 60-foot tall, 20-foot-wide cylinder that removes all air from inside of it replacing it with furiously rotating blade of Wind Release Chakra, centered on a point of your choice within range. All creatures within the cylinder must make a Dexterity and Constitution saving throw. On a failed Dexterity save they are slashed with wind chakra repeatedly taking 2d6 Slashing Damage and 2d6 Wind Damage or half as much on a successful save. A creature makes this saving throw the beginning of each turn they begin within this cylinder. On a failed Constitution Saving throw they are robbed of their air in their lungs as they begin suffocating. A Suffocating creature can only survive a number of rounds equal to their Constitution modifier before passing out falling unconscious from the lack of air. A creature makes this saving throw at the beginning of each turn they begin within cylinder. An unconscious creature can regain consciousness when another creature spends an action waking them. Creatures inside the cylinder cannot gain the benefits of an increase to movement speed and are treated as if they are in difficult terrain. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 2d6 for each damage type. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the Height by +10 feet and radius to 30 feet, +3: Increase the Height by +20 feet and radius to 40 feet, +4: Increase the Height by +30 feet and radius to 50 feet, +5: Increase the Height by +40 feet and radius to 60 feet). WIND RELEASE: VIOLENT WHIRLWIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (30-Foot Cone) Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Wind Release, Ninjutsu Description: You exhale a powerful stream of wind from your mouth. Creatures caught in the target area must make a Strength Saving throw. Creatures take 2d6 Wind Damage, are pushed back 30 Feet, are knocked prone and cause Swirl on a failed save or half as much and no additional effects on a successful save. Also, vapors, gases and fogs that can be dispersed by strong winds are dispersed immediately. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. Increase the range of this jutsu by 10ft. WIND RELEASE: ZEPHYR STRIKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: 1 minute Components: CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You move like the wind. For the duration, your movement doesn’t provoke opportunity attacks. Your movement speed increases by 10 feet until the end of the turn you cast this jutsu. Also, once before the jutsu ends, you can give yourself advantage on one attack roll on your turn. On a hit, the attack deals an extra 2d8 wind damage and immediately ends this jutsu. 71 C-RANK: WIND RELEASE: 1,000 BLADES OF THE WIND Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 20 Foot Cone Duration: Instant Components: HS, CM Cost: 7 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a spiraling sphere of wind chakra with a collection of cutting blades within it. Creatures in range must make a Strength Saving throw being pulled towards you and taking 4d6 Wind Damage and gaining 2 ranks of bleeding. Or half as much on a successful save and no ranks of bleeding. Creatures who fail their saving throw, are pulled towards you, ending their movement within 5 feet of you, and causing Swirl. They are then caught in a violent explosion of the cutting wind, being knocked back 20 feet and taking an additional 2d6 Wind Damage. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the amount of initial bleed gained by +1. WIND RELEASE: BURSTING COMPRESSED AIR Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 30-feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: You conjure a spiraling vortex of wind chakra around a target creatures weapon. The target creature makes a Dexterity saving throw to avoid the collapse of the wind. On a failed save they take 3d6 slashing damage as they are sliced for holding the weapon, and cause Swirl. If they continue to hold their weapon, they must make another save at the beginning of their next turn. On a successful save they take half damage. These additional saving throws do not cause Swirl. After 3 failed saves the weapon they are holding can’t take any more damage and shatters sending weapon shrapnel haphazardly flying. Other Creatures within 10 feet of the exploding weapon taking 3d6 slashing damage. WIND RELEASE: GALE FISTS Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Bonus Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM, M Cost: 6 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You coat your hands and feet in a layer of highly compressed but highly reactive wind release chakra. For the duration of this jutsu, you may use your Ninjutsu ability Modifier in place of Strength for unarmed attack rolls. Your unarmed damage is treated as Wind for the duration of this jutsu and deals damage equal to 1d10 + Ninjutsu Ability Modifier. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the damage by 1d10. WIND RELEASE: GREAT BREAKTHROUGH Classi", created_at: NOW, updated_at: NOW },
  { _id: "35c2d395f206cd73056d2eeb", name: "SUNBEAM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Self (60-foot line)", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You create a beam of brilliant white-hot light that flashes forth from you in a 5-foot-wide, 60-foot line. Each creature in the line must make a Constitution saving throw. On a failed save, a creature takes 6d10+6 fire damage and are blinded until the end of your next turn. On a successful save they take half as much damage and no further effects. You can create a new beam of light as your action on any turn until this jutsu ends. For the duration, you shine bright light in a 30-foot radius and dim light for an additional 30 feet. This light is equivalent to sunlight.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3c323ba7aca0e0b068e86f6e", name: "BLAZING FERVOR", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "1 Minute", description: "You pump Fire Release Chakra through your veins, muscles, and even blood. When you do, for the duration, your Strength & Dexterity becomes 20. If either of these ability scores are already 20, they instead gain a +2 bonus. Melee attacks that strike you deals 15 fire damage to all creatures within 10 feet of you as you release a mass of heat from your body in response. Taijutsu attacks as a result of Jutsu you cast deal an additional 2d8+2 Fire Damage, twice per turn. Taijutsu and Bukijutsu you cast gains the Fire Release Keyword and deals fire damage instead of its listed type, if any. At the end of this jutsu’s duration, you gain 4 ranks of Exhaustion for the next hour, which cannot be removed by anything short of resting. This jutsu cannot be cast again until you complete a rest of any type. 96 FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9347a403e65b68306bace651", name: "CRIMSON BUTTERFLY", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "1 Mile", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a swarm of Fire Release projectiles in the shape of a butterflies swarm. This swarm occupies a 90-foot cube centered on a space you can see within range and can occupy the spaces of multiple creatures as they flutter around them. At the end of your next turn, all butterflies in the cube explode violently. Creatures caught in the explosion (including casters) make a Dexterity saving throw at disadvantage. On a failed save they take 9d10+9 fire damage and gain 2 ranks of the burned condition. On a successful save they take half damage and 1 rank of the burned condition.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the size of this jutsu by 10 feet and the damage by 1d10+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "da4970229896025c83b758c4", name: "DELAYED FIRE MISSILE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "90 feet", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "A beam of yellow light flashes from your hands, then condenses to linger in your hand as a glowing bead for the duration. When this jutsu ends, either because your concentration is broken or because you decide to end it, the bead blossoms with a low roar into an explosion of flame that spreads around corners. Each creature in a 20-foot radius sphere centered on that point must make a Dexterity saving throw. A creature takes fire damage equal to the total accumulated damage on a failed save, or half as much damage on a successful one. The jutsu base damage is 12d8+12. If at the end of your turn, the bead has not yet detonated, the damage increases by 6d8+6. As an action, you can make a Ranged Ninjutsu attack throwing the bead at a creature or object causing it to detonate on a hit. On a miss the target creature gets advantage on its saving throw.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the base damage and damage increase by 1d8+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "61d202fce4a601b0e3b4a404", name: "FIRE DEVASTATION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Self (120 Foot Cone)", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You breathe a stream of fire onto the target area which then expands into a massive ball of fire, incinerating everything in its radius. You fire a 120- cone-of super-heated flame. You can choose when the cone stops before reaching its maximum distance. All creatures in the steam flames must make a Dexterity saving throw, taking 14d6+14 Fire Damage and gaining the 2 ranks of the burned condition on a failed save or half damage on a successful one. Flammable objects and creatures caught in the radius are turned to ash if reduced to 0 Hit points. The affected area remains on fire at the conclusion of the jutsu.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9f35071e0d802b17065d30d8", name: "FIRE STORM", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "A storm made up of sheets of roaring flame appears in a location you choose within range. The area of the storm consists of up to ten, 10-foot cubes, which you can arrange as you wish. Each cube must have at least one face adjacent to the face of another cube. Each creature in the area must make a Dexterity saving throw. It takes 20d4+20 fire damage on a failed save or half as much on a successful one. The fire damages objects in the area and ignites flammable objects that aren’t being worn or carried. A creature in the area of more than one fiery storm is affected a maximum of once. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ff09e5a2531c40fff76cfb19", name: "GREAT FIRE ABSORPTION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "1 Round", description: "You create a vacuum of chakra, absorbing lingering fire from the surrounding area collecting it towards yourself converting it into chakra and using this new chakra to heal wounds. Lingering fire or objects on fire are all extinguished and it is absorbed into you. You heal 10 Hit points for every source of fire occupying a 5- foot cube that is absorbed this way. Fire cannot be generated or maintained in the radius of this jutsu until the beginning of your next turn. 97 FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "371e9dd0551ee49dd49c5e14", name: "IGNITION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You expel your chakra into a 60-foot radius centering from you. All flammable objects, cloth, metals or otherwise things that can heat up or be set to blaze, is ignited instantly. Metal glows red hot, clothing is caught in a flash flame, and flammable objects are burning. Creatures of your choice must make a Constitution saving throw being unable to fend of this swarm of chakra as they are set ablaze gaining 3 Ranks of the burned condition. Creatures who gain ranks of the burned condition in this way makes their Survival check at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3. If upcast to S-Rank, creatures who would take damage from the burned condition, they instead take the maximum possible damage. FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "74ad9700010e0154758c2890", name: "NOVA", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: ["katon"], casting_time: "1 Action", range: "250 Feet", chakra_cost: "Special (110 Chakra)", components: "HS, CM", duration: "Instant", description: "You select a space you can see within range. This space manifests a sphere of pure fire release chakra. The sphere begins to pull in all creatures within 120 feet of it as if it were a gravity well. All creatures within a 120 feet radius of the space you selected must make a Strength saving throw, being pulled up to 90 feet towards the space. On a successful save, they are instead pulled 45 feet. Creatures who end this movement within 30 feet of the sphere must make a Constitution saving throw as a wave of heat overwhelms them. On a failed save creatures take 50d4 + 50 Fire Damage. On a successful save they take Half. A creature who’s hit points are reduced to 0 as a result of this jutsu, are turned to ash. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the targeted damage by 10d4+10. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's damage potential based on the highest Charisma Modifier within the group of casters. (+0-2: No Change, +3-4: Increase the range of this jutsu by +80 feet, and the radius by +20 feet, +5: Increase the range of this jutsu by +250 feet, the radius by +60 feet and damage by 25d4+25.) FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "28f2d899b8a509809c90f8b0", name: "RELENTLESS BLAZE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["katon"], casting_time: "1 Action", range: "Touch", chakra_cost: "Special (110 Chakra)", components: "HS, CM", duration: "1 Minute", description: "You and all other casters, if any, touch a creature who has been dead no longer than 10 minutes, infusing its body with Fire Release chakra, giving it a temporary spark of life fueled by you. The creature awakes with full Hit points and Chakra points. All jutsu they cast lose any other Nature Release Keywords and Gain the Fire Release Keyword in its place. All Class, or Clan features that would require a Nature Release Keyword of any type works with Jutsu with the Fire Release Keyword. All damage they deal is counted as Fire Damage and ignores Resistance, and treats Immunity as Resistance instead. At the end of the 1-minute duration or if the creatures hit points is reduced to 0, they turn to ash as that spark of life goes out being unable to be revived by any means. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the duration by 1 minute. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's duration based on the highest Charisma Modifier within the group of casters. (+0-2: No Change, +3-4: Increase the duration of this jutsu to 1 hour, +5: Increase the duration of this jutsu to permanent.) FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ecbad44f91f72b9ed74bcdb8", name: "SUNBURST", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "150 Feet", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "Brilliant sunlight flashes in a 60-foot radius centered on spot you can see within range. Each creature in that light must make a Constitution saving throw, taking 12d6+12 fire damage and is blinded for 1 minute on a failed save. On a successful save, it takes half as much damage and isn’t blinded by this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1. 98 S-RANK: FIRE RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "073292d536e0c224bf529a7a", name: "DAWN", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: ["katon"], casting_time: "1 Action", range: "Self (120-foot Radius Sphere)", chakra_cost: "45 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You coat your body in such a dense amount of Fire Release chakra that you emit a painfully bright Light. All creatures who can see within range who are not behind total cover, are affected by this jutsu. Affected Creatures, must make a Constitution saving throw. On a failed save, they take 18d8+18 fire damage, become permanently blinded, and gains the 5 ranks of the burned. On a successful save they take half damage, becomes blind for the next minute and gains 3 ranks of the burned condition. A creature burned by this jutsu cannot extinguish the flames on their own and can only have either the burned condition or the Blinded condition ended by; • A Jutsu that removes conditions casted at no less than S-Rank. • Waiting 1 minute for the Burned Condition to end naturally. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a16c136711a1789667f7058c", name: "FIERY BODY", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "Self", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You temporarily transform your body into living flame. You gain immunity against Wind, fire, Bludgeoning, Piercing and Slashing damage and the Blind and Deafened conditions. You gain Vulnerability to Cold damage. When you would take fire damage or suffer an effect cause by a jutsu with only the fire release keyword, you instead regain hit points equal to half the amount of damage it would normally deal. Your melee attacks deal an additional 10d4+10 fire damage, twice per turn. Your body burns so brightly that creatures within 120 feet of you who do not avert their gaze or close their eyes at the beginning of their turns, gain the blinded condition until the end of their turn. Jutsu you cast that have the Fire Release Keyword have their save DC’s increase by +1. If you enter water, you are surrounded by a 5-foot radius of steam and bubbles that grant you partial concealment but you also take 4d6 cold damage each round you remain in the water. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "888c1079dd210c86ef718900", name: "HEAT SNAP", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "b3b9a80a8acefa31d6905369"], elements: ["katon"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "35 Chakra", components: "HS, CM", duration: "Instant", description: "You snap your fingers igniting the air surrounding a creature, instantly incinerating them. If the creature you chose to target with this jutsu has 100 hit points or fewer, it dies, burning to dust. Otherwise, they must make a Dexterity saving throw, taking 30d4 + 30 fire damage, or half as much on a successful one. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d8d0ae484ba5a52e8b7ff59a", name: "INCINERATING DRAGON FIRE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: ["katon"], casting_time: "1 Action", range: "150 Foot Cone", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Instant", description: "You inhale engorging your chest, exhaling a white-hot flame, turning most everything in your path to ash. You exhale a white-hot blaze of flame in a 150- foot cone in front of you. Creatures in this cone must make a Dexterity saving throw, taking 25d6+25 Fire damage on a failed save and half as much on a successful one. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d5f092b1fd50e8919b90f90a", name: "INFERNO RAIN", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: ["katon"], casting_time: "1 Action", range: "1 Mile", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Instant", description: "Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 20-foot-radius sphere centered on each point you choose must make a Dexterity saving throw. The sphere spreads around corners. A creature takes 22d8+22 fire damage on a failed save, or half as much damage on a successful one. A creature can only be affected by one fiery explosion per casting. FIRE RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "718877104bc90c13b761c875", name: "PHOENIX BLESSING", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "aaeecd12fb6a8f889a26ab97"], elements: ["katon"], casting_time: "1 Action", range: "Touch", chakra_cost: "Special", components: "HS, CM, CS", duration: "Permanent", description: "You touch a willing creature, passing on your flame. A creature you touch regains a number of hit and chakra points equal to your maximum hit and chakra points respectively. They gain a number of Temporary hit points equal to their Maximum Hit points and a number of Temporary Chakra points equal to their Maximum Chakra points. You end all conditions on the target and they feel immediately revitalized, gaining Advantage on all ability checks, skill checks, saving throws, and attack rolls for the next minute. After this minute duration, your Maximum Hit & Chakra points become 0, and cannot be increased by any means. 99 WATER RELEASE Water Release jutsu are most easily performed using existing water sources, such as lakes or rivers. Users can also create water within their bodies with chakra, which they expel from their mouths, though this is generally regarded as a testament of skill. Water Release is typically used offensively, doing battering damage because of the sheer volume of water or slicing damage because of the water's high pressure. Water Release can be used to trap targets, such as imprisoning them with dense water or ensnaring them with sticky water. Water is a common option, with users surrounding themselves with water to be protected from harm. Alternatively, users can hide themselves from opponents with thick mist to obscure vision or water droplets to render the user invisible. Water Release is naturally strong against Fire Release and weak against Earth Release. Prerequisite: You must have the Water Release Affinity to learn jutsu with the Water Release Keyword. D-RANK: WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3f88a6c33b51481335bdfbf1", name: "DOLPHIN BREAK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "15 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manipulate your water release chakra to generate an aquatic beast of your choice that appears to ram into a creature you can see within range. Make a melee ninjutsu attack. On a success you deal 3d6 cold damage and forcing the target creature to make a Constitution saving throw. On a failed save they gain 1 rank of Chilled. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or increase the range to 45 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When you cast this jutsu at B-Rank the amount of attacks you make becomes 2. When you cast this Jutsu at S-Rank the number of attacks you make becomes 3. WATER RELEASE: ENCOURAGING DROPLETS:", created_at: NOW, updated_at: NOW },
  { _id: "d6549b57ad7501bf95a628c5", name: "ENCOURAGING DROPLETS: THIRST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["suiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You solidify your Water Release Chakra into pure water that floats above your hand. When cast, a willing creature within range can as a part of casting this jutsu drink the water. The target gains temporary hit points equal to your Ninjutsu save DC and is healed of one of the following conditions from an effect of equal rank or lower; Bleeding, Burned, Chilled, Dazed or Poisoned. Creatures who gain Temporary hit points from this jutsu gain a special action called Encouraged Momentum which goes away at the end of their next turn. Encouraged Momentum. On your turn, you can use this special action to take the following actions; Dash, Hide, Disengage, or Dodge.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at B-Rank, increase the number of conditions healed to 2. If cast at S-Rank, increase the number of conditions healed to 3. 100 WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "876907987568a246fd55b8e8", name: "HEALING WATERS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You collect a mass of water and impart chakra into it and begin to heal a willing creature you can touch with it. This dissolves the water from being used in the healed creatures healing process. Roll 2d8, healing the target creature by the total. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to instead remove one of the following conditions in addition to restoring hit points; Bleeding, burned, poisoned or shocked conditions.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the healing by 1d8. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "cd1351b8ebfac359e1dbc202", name: "HIDDEN MIST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self (30 Foot radius sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a cloud of water particles condensing into a large cloud of mist. Creatures inside this cloud of mist cannot see more than 5 feet away from them, gaining disadvantage on Wisdom (Perception) checks to see and Attacks made while inside the cloud of mist that rely on sight. Creatures outside the mist also have disadvantage when attacking other creatures who are inside the mist. Also, when this jutsu is cast, select one creature, whom you can see. That creature becomes mist marked. For the duration of this jutsu, a creature mist marked is always perceived by you while they are in the hidden mist, cannot benefit from being hidden while inside the hidden mist and you do not gain disadvantage on attack rolls against them. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to instead select an additional creature to be mist marked. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "faf005d90df51f2a9be099b1", name: "MANTIS WINGS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest wings of water that flutter at your command. Until the end of your turn, you gain a 30-foot fly speed. At the end of this jutsu’s duration if you have not landed, your wings slow down bringing you gently down onto whatever surface may be directly below you.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. Casting this jutsu at B-Rank, gives it a Concentration, up to 1 minute duration. Casting this jutsu at A-Rank, gives it a Concentration, up to 10- minute duration at no additional chakra cost to maintain concentration. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "f88269c070b3b070d21224d5", name: "PIRANHA SWARM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "3 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute.", description: "You manifest a medium sized bubble of water that you then summon a swarm of piranhas within. When you cast this jutsu, you can make a melee ninjutsu attack against a creature within 5 feet of the swarm. On a hit, the target takes 2d4 Cold damage + 2d4 Piercing damage. As a bonus action on subsequent turns, you can command the swarm to move up to 30 feet and repeat the attack against a creature within 5 feet of it. If you cast this jutsu while submerged underwater, the piranha’s can instead be commanded to move up to 60 feet instead of 30. A creature who takes damage from this jutsu must make a Constitution Saving Throw. On a failed save, they gain 1 rank of Chilled. A creature who fails by 5 or more also gains 1 rank of Bleeding. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to increase the amount of piranhas, increasing their damage by +1d4 of each type.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d4 of each type. When this jutsu is cast at A-Rank or higher, increase the ranks of Chilled or Bleed it inflicts by +1. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "889985b61d4c16f4823f2f07", name: "SENSING WATER SPHERE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: ["suiton"], casting_time: "1 Minute", range: "5 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Day", description: "You collect a mass of water into a sphere from the surrounding area 5 feet in diameter. For the duration of this jutsu you can see movement and activity in a 250-foot radius centering on the sphere. This requires the creature who is moving, to disrupt some source of water (Puddles, bodies of water or rain). This movement or activity creates bubbles inside the sphere relative to the direction of the movement compared to the location of the sphere. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to double the sensory range of this jutsu, allowing you to see movement and activity in a 500-foot radius centered on the sphere. 101 WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f0109f165fb803329b37e285", name: "SHARKS MAW", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You manifest a construct of water release chakra around your hands to take the shape of a sharks that clamp down and bite into targets for the duration. You cannot lose concentration on this jutsu as a result of damage. For the duration, as an action, you can make a melee ninjutsu attack. On a hit, you deal 3d8 cold damage and forcing the target to make a Strength Saving Throw, being Grappled by the shark’s head on a failed save. A creature Grappled by you this way takes 1d8 Cold damage at the start of each of their turns as the sharks bite deeper into them. If you cast this jutsu while submerged underwater, the sharks grant you a swim speed of 60 feet and attacks made with this jutsu are at advantage. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or for the duration, if your melee Ninjutsu attack result is 10 higher than the targets AC, its treated as a critical hit, and creates a shockwave of water chakra that deals 2d6 cold damage to all creatures of your choice within 10 feet of you.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the attack’s damage by 1d8 and the shockwaves damage by 1d6 respectively. If this jutsu is cast at C-Rank or higher, increase the number of attacks you can make by +1. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2d860e234759f519b7083524", name: "STARCH SYRUP GUN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "60-feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You knead chakra with your spit creating a viscous substance similar to syrup. You spit it out at a creature slowing them down from the viscous and sticky nature of the liquid. Make a range ninjutsu attack against a creature you can see within range. On a hit target creature gains 1 rank of the Slowed condition until the end of their next turn. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to instead select one additional creature to target with this jutsu when you cast it.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "9b0884d7f1cfced290dbb7d4", name: "TSUNAMI MALLET", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "10 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a construct of water release chakra in the shape of a large mallet, of your design and description. This mallet is then immediately used to make a melee ninjutsu attack against a target creature within range. On a hit, you deal 3d6 cold damage and the target creature must make a Constitution Saving throw, being Chilled on a failed save. If the target of this jutsu already has ranks of chilled, they suffer a -2 penalty to their saving throw at disadvantage and this Jutsu's damage die increases by 1 step. If the target has ranks of another Elemental condition they suffer a -2 penalty to their saving throw and this jutsu’s damage die increases by 1 step. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to increase the damage die of this jutsu by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When you cast this jutsu at B-Rank the number of attacks you make increases by +1. When you cast this Jutsu at S-Rank the number of attacks you make increases by +2. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e4476ace915e643f0676823b", name: "VISCOUS WATER MASS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute.", description: "You extract water from an area near a willing creature you can see within range creating a medium sized shield of water to protect them. The target reduces incoming damage by 4. If this jutsu would reduce Fire Damage you instead reduce the damage by 6. If you would initiate a clash with a Jutsu with the clash keyword, you first check to see if the damage would be reduced to 0 as a result of this jutsu’s Damage Reduction. If the fire damage would be reduced to 0, you can then choose to initiate a clash, if you wish. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2, or for the duration, the target also increases their AC by 1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast a B-Rank, increase the AC bonus by +1 and the DR by +2. If this jutsu Is cast at S-Rank, increase the AC bonus by +2 and the DR by +6. 102 WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "a17af7a4a264589fc7b2c1ff", name: "WATER BLENDING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes.", description: "A willing creature you touch becomes invisible for the duration, water bends the light around the target hiding their presence. Anything the target is wearing or carrying is invisible as long as it is on their person. The jutsu ends for a target that attacks, casts a jutsu or physically interacts with another creature.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and you can target one additional creature. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ab075da7ed10aa04700cae43", name: "WATER CLAWS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest water release chakra in the shape of two claws that surround your hands, of your design and description. Make two melee ninjutsu attacks against a target within range, as you spin, slashing into them. On a successful hit, you deal 2d6 Cold damage. Affected creatures must make a Constitution Saving throw, gaining 1 rank of Bleed, on a failed save. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or the number of attacks by +1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WATER RELEASE: WATER FORMATION:", created_at: NOW, updated_at: NOW },
  { _id: "b82bb9363f7d0e267c87caca", name: "PUDDLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a Large Puddle of water from your stomach and expel it onto the ground in front of you. This puddle holds no more than 10 gallons of water. You can use this puddle as a source of drinking water, lay a trap, or use it as a source for more complex Water Ninjutsu. You may use the water this Jutsu produces as a Source of Water for no more than 2 water release ninjutsu of C-Rank or lower, after which, the puddle is no longer usable. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8749ec32f644d02030e45ab8", name: "WATER PALM BLADE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You generate two blades of chakra enhanced water over your hands that you launch in an arc. Make a ranged Ninjutsu Attack dealing 4d8 Cold damage on a hit. A creature affected by this jutsu becomes sheathed in vibrating water until the start of your next turn. If the target moves or is moved at least 5 feet before the start of your next turn, it explodes, dealing 1d6 cold damage to the affected creature and all creatures of your choice within 5 feet of the original target. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or increase the damage of the attack by 1 die.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage of this jutsu by 1d8. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b0a5bb44d9036f7d6397348b", name: "WATER PILLAR THRUST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a surge of water that erupts upwards from under a creature that you can see within range. This jutsu ignores cover. The target must make a Dexterity saving throw taking 3d10 Cold damage and being chilled on a failed save and half as much on a successful save and no further effects. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to affect all creatures within 5 feet of the target creature as well. A creature can only be affected by this jutsu once per casting.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the number of targets this jutsu can affect by +1 and the damage by 1d10. WATER RELEASE: WATER", created_at: NOW, updated_at: NOW },
  { _id: "36e87d7f6964ba4a71f9bef6", name: "WATER PURIFICATION/PUTRIFICATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You manipulate and mold chakra to reverberate through a source of fluid, be it mud, poisoned waters, or anything in between. Fluid up to 10 gallons that has your chakra moving through it becomes purified and turns into pure drinking water, free of all impurities or it becomes putrid, undrinkable and poisonous to drink (Your choice). If a fluid is manmade or special in any way, make a Ninshou Skill Check against the DM’s set difficulty to see if you can purify/Putrefy it or not. 103 WATER RELEASE: WATER SEALING TRAP:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a2332cae48e9f5fec379af81", name: "WATER SEALING TRAP: SUBMERGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "10 Minutes", description: "As a part of casting this jutsu, the target of this jutsu must be submerged fully in any type of Liquid. You weave a chakra seal made of water release chakra that you then place on the surface of a liquid. A creature currently submerged within this liquid becomes bound by the waters itself. Target creature must make a Strength saving throw. On a failed save, they become Restrained and unable to weave handseals for the duration. The target cannot drown while restrained by this jutsu. A Creature Restrained by this jutsu, remakes their saving throws at the end of each of their turns. On a success ending this jutsu immediately. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f5512ef5d760c952aaef75b9", name: "WATER SHIELD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Reaction, which you take when you would take damage or make a saving throw.", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 Round", description: "You create a floating wall of spiraling water, capable of pushing back creatures and blocking attacks. Increase your AC by +2 until the beginning of your next turn and reduce the next instance of damage you take by 4. If this jutsu would reduce Fire damage from another jutsu, you can initiate a Clash, and add 1d4 to your clash check. If you have a sufficient water source nearby, reduce the chakra cost of this jutsu by 2 or the first clash check you make with this jutsu, is made at advantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the DR by an additional 4. If this jutsu is cast at B-Rank increase the AC bonus by +1. If this jutsu is cast at S- Rank, increase the AC bonus by +2. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "71435c9d9b6d056c175ac927", name: "WATER SHURIKEN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You generate multiple shuriken made of water. Make a Ranged Ninjutsu attack against a creature you can see within range, dealing 4d4 cold damage. If you score a critical hit with this jutsu the damage die of this jutsu becomes a d8 as they shift into monster water shuriken. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to instead make an additional attack targeting another creature within range.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d4. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "717cffab2cadfec7d3e9f756", name: "WATER WHIP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You create a long whip of water by molding your chakra through it. Make a melee ninjutsu attack against a target in range, dealing 2d6 cold damage and pull the creature 10 feet Closer and forcing the target to make a Constitution saving throw gaining 1 rank of chilled on a failed save. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or on a failed save, the target gains a rank of bruised.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 and the distance of this jutsu by +10 feet. 104 WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "de0f50b5246ebd65b8d98d9f", name: "WHALES TORRENT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Reaction, which you take when you or a creature within range would take damage, or make a Saving throw of any type.", range: "15-foot radius", chakra_cost: "Special (28 Chakra)", components: "HS, CM, CS", duration: "1 Minute", description: "You and any other caster weave together a highly intricate mix of Water Release Chakra until you conjure a massive Barrier of Water that protects all creatures within this jutsu’s Radius. This Barrier has a number of hit points equal to 24d6. Resistance to Fire Damage, Vulnerability to Earth Damage. This Barrier intercepts all attacks and Jutsu that would cross its space for the duration or until it reaches 0 Hit points. Creatures cannot enter, exit or Cross through this barrier willingly. This Barrier lasts for the duration and cannot be ended early willingly by its casters. Creatures cannot see into the barrier but creatures can see outside of the barrier. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase its hit points by 2d6. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's defensive potency based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2-3: Increase the hit die to a d8, +4-5: Increase the hit die to a d10.) WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fec3a40adeda1a4eea3716db", name: "WHISPER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "90 feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You send bubbles made from Water Release chakra to fill the inner ear of your allies for the duration. Select up to 3 willing creatures within range to gain the benefits of this jutsu. For the duration, affected creatures who would make a Wisdom (Perception) Check adds your Ninjutsu Ability Modifier to their Check. Sound based environmental effects that force a saving throw of any type are made with advantage. Additionally, the first Saving throw made against a Genjutsu with the Auditory Keyword add your Ninjutsu Ability Modifier to their saving throw. This jutsu immediately ends after this saving throw.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures affected by this jutsu by +2. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7615d5b7c5dc1f42be6024f1", name: "WILD BUBBLE WAVE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "15 Foot Cone", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a viscous mass of bubbles and spray it out in a cone 15 feet in front of you creating a slippery ground. Each Creature standing in the area of the jutsu, must make a Dexterity saving throw, falling prone on a failed save. A Creature that enters or ends its turn on a space in the target area must also make the saving throw or fall prone. This mass of bubbles remains for 1 minute, or until washed away.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the size of the cone by 10 feet. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7efbe105aa82d774c7c4d1b2", name: "WILD WATER WAVE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a strong current of water and expel it like a jet. Make a ranged ninjutsu attack. On a hit target creature takes 2d8 cold damage and is pushed back 10 feet If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or force the target to make a Constitution saving throw gaining a rank of chilled on a failed save", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8 and the knock back distance by +10 feet. C-RANK: WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e7b1c39cedac6286468c51fb", name: "CLEANSING DROP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "45 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You manipulate your water release chakra and infuse it with Medical Release Chakra. When you do you create a single drop of water made from this jutsu, and send it to a single willing creature you can see within range allowing them to drink it. A creature who drinks this drop of water who are under any of the following effects from a Jutsu or environmental hazard of Equal Rank or lower, has two of them completely removed at your discretion; Poisoned, Burned, Shocked, Chilled, Dazed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the amount of targets you can affect by +1. 105 WATER RELEASE: CRUSHING DROPLETS:", created_at: NOW, updated_at: NOW },
  { _id: "3884e4d377c2804886c4e68e", name: "CRUSHING DROPLETS: SPILL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You manipulate your water release chakra hardening it until the waters density becomes too much for most to handle. For the duration, when you would cast a Jutsu with the Water Release Keyword, the Strength of the jutsu is modified based on your needs at the moment. Select one of the following effects when you cast the jutsu. • Cold Damage you deal with Jutsu with the Water Release Keyword is increased by an amount equal to your Proficiency Bonus. This bonus damage can happen up to twice per turn. • Attacks made with Jutsu with the Water Release Keyword are made with a bonus to hit equal to 1d4. • Creatures who would make a saving throw against a Jutsu you cast with the Water Release Keyword rolls an additional 1d4 reducing their saving throws by the result.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. When you would cast this jutsu at B-Rank you may select a creature within 5 feet of you to gain this jutsu’s benefit for the same duration. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "88b3441f2de9d1d5bbbd2dc5", name: "DROWNING BUBBLE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "b3b9a80a8acefa31d6905369"], elements: ["suiton"], casting_time: "1 Action", range: "45 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a bubble filled with water and send it towards a creature’s head to enclose it within the bubble removing their ability to breathe unless they can breathe within water. Make a ranged Ninjutsu attack against a creature within range. On a hit the creature begins to suffocate. While suffocating this way, its speed is halved and at the start of each of its turns it experiences oxygen deprivation taking 3d8 necrotic damage that ignores Damage Reduction and Resistance. At end of an affected creatures turn, they make Constitution saving throw. On a success, this jutsu ends. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7a7f966976b19a73411d61e4", name: "FOUR SHARK RAIN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["suiton"], casting_time: "1 Action", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You manipulate your water release chakra shaping it until you completely form 2 construct Sharks made of your Chakra alone. These Water Sharks Swim in midair around you waiting for your command to attack using the following stat block. You can command them as a Bonus Action on your turn. A creature can only be attacked by 2 sharks per turn. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to increase the sharks hit points by an amount equal to your character level.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the hit points of your Water Sharks by +10. If you cast this jutsu at A-Rank or higher, increase the number of Water Sharks you summon by +1. If you cast this jutsu at S- Rank or higher, increase the number of Water Sharks you summon by +1. Medium Construct, unaligned Armor Class Ninjutsu Save DC Hit Points 20 Speed 40 ft fly, 80 ft swim STR DEX CON INT WIS CHA 10 (+0) 10 (+0) 10 (+0) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Cold, Psychic Damage Resistance Fire Damage Vulnerability Earth Condition Immunities All Mental, All Physical, Exhaustion, Stunned, petrified, poisoned Senses passive Perception 10 Shark Trigger. When the Water Shark is reduced to 0 hit points, it explodes forcing all creatures within 10 feet to make a Dexterity saving throw taking 5d6 cold damage and 1 rank of chilled on a failed save or half as much damage and no further effect on a success. (Excluding Caster) Multiattack. The Water Shark can attack 2 times with its Bite. Bite. Melee Weapon Attack: + (Your ninjutsu attack bonus) to hit, reach 5 ft., one creature. Hit: 2d6 Cold damage. On hit the target must make a Strength saving throw vs the casters Ninjutsu Save DC being grappled by this Water Shark on a failed save. The Shark can only grapple one creature in this way at a time. 106 WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "3c33606a705cf3c3e1312c86", name: "FOUL LEGACY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "Self (10-foot radius)", chakra_cost: "7 Chakra", components: "HS, CM, W (Any)", duration: "Concentration, up to 1 minute", description: "You manifest water chakra that bubbles up before you unleash it like a bursting bubble, as a pulse of sapphire blue chakra enhances the weapons of your allies. You cannot lose concentration of this jutsu as a result of damage. For the duration, one weapon you and each allied creature affected by this jutsu is wielding is enhanced by your sapphire water chakra. Enhanced weapons deal an additional 2d4 Cold damage twice per turn and each time a wielder deals damage to a hostile creature, they regain hit points equal to the bonus cold damage this jutsu deals. If you or affected allied creatures let go of their weapon or it is taken from its original wielder, the sapphire chakra disperses.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank or higher, increase the damage to 4d4. WATER RELEASE: HEAVENLY MIRROR OF", created_at: NOW, updated_at: NOW },
  { _id: "d11979927836cb2f29829b74", name: "HIDING IN MIST", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You begin to turn your body into a collection of water vapor similar in consistency to mist along with everything your wearing and carrying for the duration. This jutsu ends if you drop to 0 hit points or chakra. You cannot lose concentration of this jutsu as a result of failing a concentration check, or being incapacitated. While in this form, your only movement method is a flying speed of 20 feet. You can enter and occupy the space of another creature. You have resistance to all damage, excluding Earth damage, and you have advantage on Strength, Dexterity, and Constitution Saving Throws. You can pass through small holes, narrow openings, and even mere cracks, though it treats liquids as though they were solid surfaces. You can’t fall and remain hovering in the air, even when stunned or otherwise Incapacitated. When rolling stealth to be seen as a common cloud of gas, mist or fog, you may roll at advantage. While in this form of mist, You can’t talk or manipulate objects, and any objects it was carrying or holding can’t be dropped, used, or otherwise interacted with. You cannot attack or cast jutsu while in this form. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f2ba0c272e036aa4ba90b544", name: "MEDICAL JELLYFISH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["suiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Minute", description: "You Conjure water into the shape of a jellyfish and attach it to a creature you touch. For the duration, the jellyfish will continuously inject chakra into whomever it is attached to body to heal them when they take damage. At the beginning of their turn, they recover 4 hit points. This jellyfish has the Same AC as its host, but only 1 hit point. The jellyfish can be targeted by an attack. Alternatively, If the host would make a saving throw to resist a Ninjutsu, Taijutsu or Bukijutsu effect that would damage it, the jellyfish also takes damage equal to the result if its host fails the save. If the Jellyfishes Host would fall to 0 hit points, the jelly fish shrivels up and the jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the healing by +1. 107 WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "89d260c8202af58dcd2d6c12", name: "SCORPION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "15 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You mold poisonous chakra into the shape of a scorpion stinger dripping with poison, and fully under your control. The tail has a reach of 15 feet and scores a critical hit on a roll of 19~20. For the duration, as an action you can make two melee ninjutsu attacks, dealing 4d8 + your ninjutsu ability modifier poison damage on a hit. Once per turn, a creature who takes damage from this jutsu must make a Constitution saving throw, gaining 2 ranks of envenomed on a failed save. A creature you target, who has 5 ranks of envenomed has vulnerability to poison damage from this jutsu’s attacks for the duration. MEDICAL RELEASE: WILT Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self (45-Foot cube) Duration: Concentration, up to 1 minute Components: HS, CM, CS Cost: 20 Chakra Keywords: Ninjutsu, Medical, Fuinjutsu Description: You infuse necrotic chakra into a surge of medical chakra, designed to suck the life from a target creature. You draw the life force of all creatures of your choice within range, that you can see. Each creature in the area must make a Constitution Saving throw. Construct and undead aren’t affected. Plants, Celestials, and Demons make this saving throw at disadvantage. A creature takes 10d8 Necrotic Damage and are marked with the seal of extraction for the next minute, or half as much damage and no additional effects on a successful save. A creature marked with the seal of extraction takes 5 additional Necrotic damage each time they would take damage from any source for the duration. Plants, Celestials, and Demons instead take 10 additional Necrotic damage each time they would take damage from any source for the duration. A creature marked with the seal of extraction can as an action attempt to remove the seal by making an Intelligence (Ninshou) check vs your Ninjutsu save DC, removing it early on a success. Plants, Celestials, and Demons make this skill check at disadvantage. REVERSE SEAL SUMMONING Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self Duration: Instant Components: HS, CM, CS Cost: 20 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You mark up to 6 willing Creatures with a chakra seal, marking them with your personal seal formation. With this seal, you can, as a bonus action, teleport creatures marked with your seal, to you, from up to 1 mile away. You may also Inversely teleport to them, as a bonus action, from up to 300 Feet away, occupying a space within 5 feet of them that can hold you. Creatures marked can resist being summoned causing this jutsu to fail, if they resist you do not spend chakra.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and multiply the range by 10. SEALING ART: FORCECAGE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 100 feet Duration: 1 hour Components: HS, CM, CS Cost: 19 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You impart a scroll with your chakra seal, which conjures an immobile, glowing blue, cube shaped prison composed of chakra, springs into existence around an area you choose within range. The prison can be a cage or a solid box as you choose. 43 A prison in the shape of a cage can be up to 20 feet on a side. A prison in the shape of a box can be up to 10 feet on a side, creating a solid barrier of chakra that prevents any matter from passing through it and blocking any jutsu cast into or out of the area. Both the cage and box shaped barriers have 200 Hit Points. When you can the jutsu, any creature that is completely inside this Jutsu’s area is trapped. Creatures only partially within the area, or those too large to fit inside the area, are pushed away from the center of the area until they are completely outside the area. A creature inside the Forcecage can’t leave it by non- teleportation means. If the creature tries to use teleportation to leave the Forcecage, it must first make a Charisma saving throw, on a success the creature can use that jutsu or feature to exit the Forceage. On a failure the creature can’t exit the Forcecage and wastes the use of the jutsu or effect. SEALING ART: SEAL OF DISCORD Classification: Ninjutsu Rank: A-Rank Casting Time: 10 Minutes Range: Touch Duration: Until dispelled or triggered. Components: HS, CM, CS Cost: 20 Chakra Keywords: Ninjutsu, Fuinjutsu Description: When you cast this jutsu, you inscribe a harmful seal either on a surface (such as a section of floor, a wall, or a table) or within an object that can be closed to conceal the seal (such as a book, a scroll, or a treasure chest). If you choose a surface, the seal can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; If the object is moved more than 10 feet from where you cast this jutsu, the seal is broken and this jutsu ends without being triggered. The seal is nearly invisible requiring an Intelligence (Investigation) or (Ninshou) check vs your ninjutsu save DC to find it. You decide what triggers the seal when you cast the jutsu such as touching or stepping on the seal, removing another object covering it, approaching within a certain distance of it or manipulating the object that holds it. You can further refine the trigger so the seal is activated only under certain circumstances or according to a creature’s physical characteristics (such as height or weight). You can also specify creatures that don’t trigger the seal, such as those who say a certain password. A creature cannot trigger more than one Warding Seal or Seal of Discord per turn. When you inscribe the seal, choose one of the options below for its effect. Once triggered, the seal glows, filling a 30-foot radius sphere with dim light for 10 minutes, after which time the jutsu ends. Each creature in the sphere when the seal activates is targeted by its effect, as is a creature that enters the sphere for the first time or ends its turn there. Death. Each creature makes a Charisma saving throw, taking 10d10 necrotic damage on a failed save or half as much on a successful one. Hopelessness. Each target must make a charisma saving throw. On a failed save, the target is overwhelmed with despair for 1 minute. During this time, it can’t attack or target any creature with harmful abilities, jutsu or attacks. Stunning. Each target must make a Charisma saving throw and becomes stunned for 1 minute on a failed save. SEALING ART: SHINING STARS, SOARING STRIKE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 120 feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 20 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: As a part of the requirements to cast this jutsu, you must know the Hollow Stars jutsu. You form two tiny objects in the shape of stars, in unoccupied spaces, that you can see within range. Each object has 45 Hit points and an AC equal to your Ninjutsu save DC. At the end of each of your turns, each object casts Hollow Stars at C-Rank as if you cast them, targeting appropriate locations within range of your choice. If these objects are destroyed, this jutsu immediately ends. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the number of star shaped objects made by +1. SEALING ART: TETHERED ESSENCE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 60 Feet Duration: 1 Hour Components: HS, CM, CS Cost: 20 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into a chakra seal as you attempt to mark two creatures (excluding yourself) with the seal of mirrors. Select two creature you can see within range. Each creature must make a Charisma Saving throw. They make this save at disadvantage if they are within 30 feet of each other. Either creature can willingly fail the save. If either creature saves, the jutsu has no effect. If both saves fail, the creatures are linked for the duration, regardless of the distance between them. When damage is dealt to one of them, the same damage is dealt to the other one. If hit points are restored to one of them, the same number of hit points are restored to the other one. If either of the tethered creatures is reduced to 0 hit points, the jutsu ends on both. If the jutsu ends on one creature, it ends on both. 44 SEALING ART: TOBIRAMA’S SWORD Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 17 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You conjure a sword-shaped place of spacial distortion that hovers within range. It lasts for the duration. When the sword appears, you make a melee ninjutsu attack against a target of your choice within 5 feet of the sword. On a hit, the target takes 5d10 force damage and gains 1 rank of Sealed. Until the jutsu ends, you can use a bonus action on each of your turns to move the sword up to 60 feet to a spot you can see and repeat this attack against the same target or a different one. If this jutsu scores a critical hit, the target instead gains 5 ranks of Sealed. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the amount of attacks the sword can make by 1 per round. TOUCH OF DEATH Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: CM Cost: 20 Chakra Keywords: Ninjutsu, Medical, Kinjutsu Description: You come close and begin to touch a willing creature you can reach. This touch can be in the form of a grab, kiss, or hug. When you do, you immediately become aware of all nature affinities the creature has if any. The target creature loses 10d6 Hit Points and you recover the same amount. If the creature has any Temporary Hit Points, they lose them and you gain the same amount. Temporary Hit Points you gain as a result of this Jutsu last for a minute before disappearing. If you attempt to cast this jutsu on an unwilling creature, you make a melee Ninjutsu Attack. On a hit, this Jutsu’s effects trigger as normal. Additionally, if you reduce a creatures Hit Points to 0 as a result of this jutsu, you are temporarily able to steal their nature release from them, if they have any. Until you complete a Long Rest, you randomly gain one of the target creature’s’ nature releases and one random Jutsu of C-Rank or lower, that requires that nature release that they knew. You cannot learn additional Jutsu of the stolen nature release unless you already have the chosen nature affinity. If you would gain another nature release as a result of this jutsu, you instead replace the previous nature release and jutsu known. S-RANK: CHAKRA DISTORTION FIELD Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: Self (10 foot-Radius sphere) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 30 Chakra Keywords: Ninjutsu Description: A 10-foot radius invisible sphere of chakra distortion. This area is divorced from chakra that makes up the world. Within the sphere, Ninjutsu or Genjutsu can’t be cast, and chakra items become mundane. Until the jutsu ends, the sphere moves with you, centered on you. Jutsu and other chakra-based effects except those created by an S-Ranked Artifact or Class Mods are suppressed in the sphere and can’t protrude into it. Chakra spent to cast a suppressed jutsu is lost. While an effect is suppressed, it doesn’t function, but the time it spends suppressed counts against its duration. Targeted Effects. Jutsu and other chakra effects such as Flame bolt or Doubled Pain, that target a creature or an object in the sphere have no effect on that target. Areas of Chakra. The area of another jutsu or chakra effect such as Fireball, can’t extend into the sphere. If the sphere overlaps an area of chakra, the part of the area that is covered by the sphere is suppressed. For example, the winds created by Wall of wind are suppressed within the sphere, creating a gap in the wall if the overlap is large enough. Jutsu. Any active jutsu or other chakra effect on a creature or an object in the sphere is suppressed while the creature or object is in it. Chakra items. The properties and abilities of chakra items are suppressed in the sphere. For example, a +1 Katana in the sphere functions as a non-chakra enhanced katana. A Chakra weapons properties and powers are suppressed if it is used against a target in the sphere or wielded by an attacker in the sphere. If a chakra weapon or piece of chakra enhanced ammunition fully leaves the sphere. MEDICAL RELEASE: STRENGTH OF 1000 Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 30 Chakra Keywords: Ninjutsu, Medical, Kinjutsu Description: As a prerequisite for learning this jutsu you must know the “Strength of 100 Technique” Jutsu. You have mastered the “Strength of 100 Technique” perfecting the chakra control needed and finding the most efficient way to enhance your physical Strength by over 1000 times. For the duration, your Strength score Double. Your jump distance is multiplied by 4, your movement speed is tripled, you gain advantage on Strength, Dexterity and Constitution saving throws, and you regenerate hit points equal to 2d12+ your Constitution modifier at the start of each of your turns. When you make an unarmed attack, you deal an additional 3d10 Bludgeoning damage. When this jutsu ends or you deactivate this jutsu, your body experiences a massive shock. You gain 10 ranks of Exhaustion which 45 cannot be removed or healed by any means. You must complete at least 4 weeks of Recouperation during Downtime to remove them. DEMIPLANE Classification: Ninjutsu Rank: S-Rank Casting Time: 1 action Range: 30 feet Duration: 1 hour Components: HS, CM, CS Cost: 35 Chakra Keywords: Ninjutsu, Fuinjutsu Description: When you cast this jutsu, you inscribe a transportation seal either on a surface (such as a section of floor, a wall, or a table) or within an object that can be closed to conceal the seal (such as a book, a scroll, or a treasure chest). If you choose a surface, the seal can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; if the object is moved more than 10 feet from where you cast this jutsu, the seal is broken and this jutsu ends without being triggered. The seal glows as a shadowy door forms on a flat solid surface that is attached to the surface the seal is placed on. The door is large enough to allow medium creatures to pass through unhindered. When opened, the door leads to a Demiplane that appears to be an empty room 30 feet in each dimension, made of wood or stone. When the jutsu ends, the door disappears, and any creature or objects inside the Demiplane remain trapped there, as the door also disappears from the other side. Each time you cast this jutsu, you can create a new Demiplane, or have the shadowy door connect to a Demiplane you created with a previous casting of this jutsu. Additionally, if you know the nature and contents of a Demiplane created by a casting of this jutsu by another creature, you can have the shadowy door connect to its Demiplane instead. FLYING THUNDER GOD: GUIDING THUNDER Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Reaction to another creature's Move, Attack, or Cast a Jutsu Action Range: 30 Feet Duration: Instant Components: HS, CM, CS Cost: 22 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You bend space and time by making a sealing formation in midair up to 30 feet away from you in a space you can see that you decide. Creatures, objects or Jutsu that cross through this space are immediately teleported to a location that you have previously marked with any Chakra Seal within 10 miles. This destroys the Chakra Seal after activation. FOUR YANG FORMATION Classification: Ninjutsu Rank: S-Rank Casting Time: Full Turn Action Range: Up to 60 Feet Duration: Concentration Components: HS, CM, CS, 3 Other Four Yang Formation Users Cost: 30 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You and 3 other users of this jutsu take position in 4 points, surrounding the area you wish to seal. You each take position in 4 different points no more than 60 feet away from one another and each spend your turn activating this jutsu. When all 4 are complete you bend time and space sealing away the enclosed space in a pocket dimension composed of null space. Creatures trapped in this pocket dimension, are unable to escape unless they perform the same jutsu, or can teleport using the “Flying Thunder God: Guiding Thunder”, “Displacement Sealing Trap”, “Flying Thunder God”, or “Four Yang Formation” Ninjutsu. MEDICAL RELEASE: BLOOD TO ACID Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 120 Feet Duration: Instant Components: HS, CM Cost: Special (50 Chakra) Keywords: Ninjutsu, Medical Description: You mold acidic into a form of your choice before attempting to infuse it into a creature you can see within range, turning all of their blood into acid, destroying them from the inside. Select one creature you can see within range. The target must make a Constitution saving throw, taking 10d12 + 40 acid damage on a failed save as all of their blood is turned to acid. A creature who passes the save only takes half damage and suffer no further effects. A creature who failed their saving throw converts all ranks of bleeding or lacerated into corroded and ignores the stack limitations found in the condition until this effect is ended on them. At the beginning of each of its turns, it must make a Constitution saving throw or be stunned until the beginning of its next turn from the never-ending pain it experiences. A creature who has had its blood turned into acid gains a rank of corroded in place of any ranks of bleeding. Additionally, it suffers 10d4 acid damage every hour as their acidic blood constantly destroys them from the inside. Its blood can be turned back to normal with a casting of this jutsu again targeting it, or by casting another ninjutsu with the medical keyword that removes conditions at S- Rank. 46 MEDICAL RELEASE: GENOCIDE Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 120 Feet Duration: Instant Components: HS, CM Cost: Special (50 Chakra) Keywords: Ninjutsu, Medical, Kinjutsu Description: You begin to generate corrupted medical chakra and infuse it with pure prejudice and malice towards a creature and their bloodline. Select the name of a Clan or a specific creature if you are unsure of their clan. The target must be of a level equal to or lower than your own as you fire a blast of Necrotic chakra that cannot miss, so long as you can see them. The target must make a Constitution saving throw. For every condition with a different name, they are under the effects of, they suffer a -2 penalty to their save. On a failure, the target takes 10d10+50 necrotic damage, or half as much on a successful save. At the beginning of the affected creatures turn, pass or fail, tendrils of necrotic chakra leap out from that creature, up to 100 feet, to all other creatures that share the targets clan, or bloodline based on what you chose. All such creatures, excluding the original target, must make the same saving throw, taking 50 necrotic damage on a failed save, or half as much on a success. At the beginning of a creature who fails their saving throws from the tendrils, more tendrils leap out from them with the same restrictions an additional 100 feet repeating the previous process, but excluding all creatures who were previously affected by the jutsu. This affect repeats until no other creatures who share the original targets clan or bloodline are within range of the tendrils. MEDICAL RELEASE: HEAL Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 50 Chakra Keywords: Ninjutsu, Medical Description: You manifest and release a torrent of Medical chakra that flows out from you into injured creatures of your choice. You cannot reduce the cost of this jutsu by any means. You restore up to 300 hit points, divided as you choose among any number of creatures that you can see within range. Creatures healed by this jutsu are also cured of all diseases and any effect that inflicts conditions, regardless of the effects restriction or limitation. This jutsu has no effect on undead or constructs. Once cast, this jutsu cannot be cast again until you complete a Full Rest. MEDICAL RELEASE: IMPENDING END Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 40 Feet Duration: Instant Components: HS, CM Cost: 35 Chakra Keywords: Ninjutsu, Medical, Kinjutsu Description: You manifest and release a torrent of putrid Medical chakra that flows out from you into creatures of your choice. You cannot reduce the cost of this jutsu by any means. Creatures with 80 Hit points or less within range die as their heart stops, their blood thins, and their cells forget the functions they normally are tasked with. Creatures who have between 81 and 100 Hit points, can feel their body begin to suffer from necrosis as they attempt to resist. These creatures make a Constitution saving throw. On a failed save, they become crippled by the pain. A creature crippled by the pain, speed can never be higher than 10, they have disadvantage on all rolls using Strength or Dexterity, and if they attempt to cast a jutsu of any type while crippled they must remake their saving throw. On a failed save, they take 8d8 Necrotic damage that ignores Temporary Hit Points, Resistance and Immunity as their chakra network is attacked by the necrosis reducing their Maximum Chakra by the result as well. A crippled creature is crippled permanently, or until they have a Jutsu that removes conditions casted on them a S-Rank. MEDICAL RELEASE: PLAGUE Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Day Range: Self (1 Mile) Duration: Forever Components: HS, CM Cost: Special (100 Chakra) Keywords: Ninjutsu, Medical, Kinjutsu Description: You begin to generate poisonous, venomous and toxic medical chakra and infuse it directly into the air itself. Yourself and 10 other creatures of your choice are immune to the effects of this jutsu. Once this jutsu is cast, it continues to permeate the affected area forever after casting. Dark green, purple and black clouds fill the air, as a foul smell of poison and toxins sail in the wind. A low moan can always be heard. Each creature who are under the clouds when this jutsu is cast must make a Constitution saving throw. A creature who is already suffering from a disease or who is poisoned or envenomed makes their saves at a -5 penalty. On a failed save, a creature gains 5 ranks of the envenomed condition and they are permanently poisoned unless removed by a Jutsu with the medical keyword that removes conditions of S-Rank. This jutsu ignores Immunity to the Poisoned Condition and Poison Damage. A creature can never have their hit points reduced below 0 as a result of the envenomed condition, instead forced to suffer until killed by other means. Creatures who come into contact with a creature who was poisoned or envenomed by this jutsu must make the save as if they were under the clouds of this jutsu when cast. A creature who would wake up from a rest of any type under clouds created by this jutsu must make a save as if they were under the clouds of this jutsu when cast. The affected area grows by 1 mile every month until this jutsu is dispelled. The clouds can only be dispelled by 3 castings of a Ninjutsu with the Fuinjutsu keyword cast at S-Rank targeting them from within 10 feet of the original space the jutsu was cast from. 47 MEDICAL RELEASE: SUPREME POISON DEITY Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Full Turn Action Range: 120 Feet Duration: Concentration, up to 1 minute Components: HS, CM, CS Cost: Special (25 Chakra) Keywords: Ninjutsu, Medical, Fuinjutsu, Construct Description: You mold poisonous into the form of a huge construct scorpion, known as the Supreme Poison Deity, formed entirely of poison, toxins and venom. This construct uses your Ninjutsu attack bonus and Save DC for effects that requires it. It rolls initiative as it has its own turns, using your Ninjutsu ability modifier + proficiency as its initiative. PLANE SHIFT Classification: Ninjutsu Rank: S-Rank Casting Time: 1 action Range: Touch Duration: Instant Components: HS, CM, CS Cost: 24 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You and up to eight willing creatures who are touching each other are transported to a different location that you’ve placed a Chakra seal prior. This location can be on the standard plane of existence, or in a pocket dimension that has not collapsed. REALITY BREAK Classification: Ninjutsu Rank: S-Rank Casting Time: 1 action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 24 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You shatter the barriers between dimensions thrusting them into turmoil and madness. The target must make a Charisma saving throw or it can’t take Reactions until the jutsu ends and must also roll a d10 at the start of each of its turns; the number rolled determines what happens to the target as shown on the Reality Break Effects table. If used while inside of a pocket dimension created by another jutsu, that dimension collapses on itself, being destroyed, and ejects all creatures and objects in it outside the pocket dimension. REALITY BREAK EFFECTS D10 Effects 1-2 Collapsing World. The target takes 12d8 force damage, and is stunned until the end of the turn. If the target was in a pocket dimension, they return to the standard plane of existence. 3-5 Rending Rift. The target must make a Dexterity saving throw, taking 8d12 force damage on a failed save, or half as much damage on a successful save. 6-8 Wormhole. The target is teleported, along with everything it wearing and carrying, up to 100 miles away to an unoccupied space in a random direction. The target also takes 12d10 force damage and is prone. 9-10 Chill of the Dark Void. The target takes 12d10 Necrotic Damage and is blinded permanently. This can be removed with a medical Jutsu of A-Rank or higher. Huge Construct, unaligned Armor Class 16 + Your Ninjutsu Ability Modifier Hit Points 230 (20d12 + 100) Speed 60 ft. STR DEX CON INT WIS CHA 26 (+8) 14 (+2) 21 (+5) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Acid, Poison, Psychic, Cold, Bludgeoning, Piercing and Slashing damage. Damage Resistance Lightning, Wind Damage Vulnerability Earth, Fire Condition Immunities Charmed, Chilled, Bleeding, Shocked, Exhaustion, frightened, stunned, poisoned Senses Darkvision 60 ft., passive Perception 10 Immutable Form. The Supreme Poison Deity is immune to any Jutsu or effect that would alter its form. Poisonous Weapons. The Deities attacks are chakra enhanced. One with Poison. When the Deity is in contact with a body of water regardless of size, it turns it into poison up to 100 feet out from it. Multiattack. The Supreme Poison Deity can attack 3 times. Twice with its Stinger and once with its Pincer. Stinger. Melee Weapon Attack: Reach 15 ft., one creature. Hit: 5d8 + 8 Poison damage. A creature hit by this attack must make a Constitution Saving throw. On a failed save they are Poisoned and gain 2 ranks of envenomed. Pincer. Melee Weapon Attack: Reach 10 ft., one creature. Hit: 2d10 + 8 Poison damage. A creature hit by this attack must make a Strength saving throw. On a failed save they are Grappled and restrained. A Grappled creature can make a Strength saving throw, escaping on a successful save. Poison Charges (Charges: 6): The Deity has a number of charges, which it can use to cast Ninjutsu with the Medical Keyword, that deals poison damage. When it casts a jutsu it spends a number of charges equal to the jutsu’s rank (D-Rank: 1, C-Rank: 2, B-Rank: 3, A-Rank: 4) 48 REAPER DEATH SEAL Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: HS, CM Cost: Special Keywords: Ninjutsu, Fuinjutsu, Kinjutsu Description: You summon the reaper of souls. Along with casting this jutsu you target a Restrained or Incapacitated creature within range. The reaper of death reaches through you, using your soul as a glove, and into the target creature, pulling out the souls of you and your target, killing you both. Both souls are sealed into the belly of the reaper of souls and neither you or the target can be revived by any means. SEALING ART: GATE OF THE AFTERLIFE Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Year Range: 10 Feet Duration: Permanent Components: HS, CM Cost: Special (138 Chakra) Keywords: Ninjutsu, Fuinjutsu, Combination, Kinjutsu Description: You and all casters infuse chakra into chakra seals as you attempt to tear open the gates of hell with the seal of the ever after. For 8 Hours a day, for 1 Year, you and no less than 10 Casters, work together adding, reinforcing and manifesting chakra seals designed to open a portal to the afterlife. If this casting is interrupted by having chakra seals destroyed or a caster dying, the jutsu fails having to be recast from scratch. Once completed, this jutsu creates a 2-way portal to the afterlife. Living creatures who pass through this gate into the world of the afterlife can remain there for no longer than a number of hours, equal to their level. If they remain any longer their material bodies disintegrate as only their souls remain, unable to cross back over onto the material plan as a living creature ever again. A Spirit who finds this gateway, can cross over into the material plane and can possess any creature of equal or lower level than they were in life. If the creature attempts to possess a creature of lower level than it, then it completely dominates their mind and body, kicking out their spirit. The spirit has access to all features, jutsu and abilities they had access to in life and any jutsu, features and abilities the original body had access too. The spirit that was kick out of that body is sucked into the afterlife, taking the place of that escaped Spirit. If the creature attempts to possess a creature of equal or higher level than it, then the target of possession makes a Charisma save vs the Level + Proficiency of the creature. On a success, they resist. On a failure, their spirits are kicked out of their body. SEALING ART: IMPURE WORLD DESTRUCTION Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Full Turn Action Range: 30 foot Duration: Instant Components: HS, CM, CS Cost: 45 Chakra Keywords: Ninjutsu, Fuinjutsu, Kinjutsu Description: You infuse chakra into chakra seals as you attempt to tear into the underworld with the seal of the consecration. You summon a coffin to act as a gateway to the underworld. The coffin springs open, as shadow tendril like hands launch forward piercing the body a creature you can see within range. Make a ranged Ninjutsu attack. On a hit, you deal 18d10 necrotic damage. If this jutsu reduces a creature to 0 Hit points, their soul is torn from their body as it is sealed within the coffin. Moving forward, until there is not a soul bound to the coffin, whenever you would cast this jutsu, you instead summon an undead construct of the creature you originally killed using this jutsu. The construct acts at the end of your turn, and follows your command. It can speak freely but cannot willingly act in a way counter to any action you provide it. The construct has half as many hit points it had in life, can cast jutsu and use clan features it had in life using your chakra instead. A construct summoned this way can only remain summoned for 1 minute before being pulled back into the coffin at the end of the duration to be saved for later use. A construct that is killed while summoned does not return to the coffin, instead relinquishing the soul that was bound to it. SEALING ART: VOID Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 1000 feet Duration: Concentration, Up to 1 Minute Components: HS, CM, CS Cost: Special (30 Chakra) Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into chakra seals as you attempt to tear into the underworld with the seal of the emptiness. You select a 30-foot radius sphere within range, creating a sphere of emptiness, where the material plane and the space inside the sphere are of different dimensional make ups. For the jutsu’s duration, the sphere and any place within 100 feet of it are difficult terrain, and non-Chakra enhanced objects fully inside the sphere are shunted to the space in-between dimensions if they aren’t being worn or carried. When the sphere appears and at the start of each of your turns, until the jutsu ends, unsecured objects within 100 feet of the sphere are pulled towards the spheres center, ending in an unoccupied space as close to the center as possible. A creature that starts its turn within 100 feet of the sphere must make a Charisma saving throw or be pulled straight towards the spheres center, ending in an unoccupied space as close as possible to the center. A creature that enters the sphere for the first time on a turn or starts its turn there takes 10d10 force damage and is restrained until it is no longer in the sphere. If the sphere is in the air, the restrained creature hovers inside the sphere. A creature can use its action to make a Strength saving throw against your Ninjutsu save DC, ending this restrained condition on itself or another creature in the sphere that it can reach. A creature who is reduced to 0 hit points by this jutsu is shunted into the space in-between dimensions where they drift forever frozen in time, along with any items it was wearing or carrying. 49 EARTH RELEASE Earth Release is one of the basic elemental nature transformation techniques and allows the user to manipulate the surrounding earth for offensive and defensive purposes or create it; be it dirt, mud, or rock. Earth Release techniques have the ability to change the Strength and composition of the earth from being as hard as metal to as soft as clay as well as manipulating their density, making them heavier or lighter. This includes allowing the user to travel through ground and rock in various ways which can be essential for both transportation and for setting up attacks or creating defenses or for offence. Indeed, this makes earth techniques one of the most versatile of the elemental techniques. Pre-existing earth is not necessary though, for the user can create it with their own chakra. Earth Release is naturally strong against Water Release and weak against Lightning Release. Prerequisite: You must have the Earth Release Affinity to learn jutsu with the Earth Release Keyword. Special Effect: All Structures and constructs made by a Ninjutsu with the Earth Release keyword has resistance to cold damage and vulnerability to lightning Damage, even if they jutsu does not specifically state its resistances or immunities. While structures have these vulnerabilities, they only apply to the structure, the remaining damage is taken normal. If you are a construct when the damage is applied, you take double the damage. D-RANK: EARTH RELEASE: AGONIZING T", created_at: NOW, updated_at: NOW },
  { _id: "e12430b00424d72170b0cb7c", name: "RAGING TIDE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Action", range: "Self (60-foot line)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You manipulate Surrounding Water as you pull water from the air, surrounding plants and even create water using your Water Release Chakra. This collects into a large wave that appears in front of you before it is propelled forward in a highly concussive way. All creatures in a 5-foot wide, 60-foot-long line originating from you must make a Strength saving throw. On a failed save a creature takes Cold Damage equal to 3d8, gain the chilled condition, be pushed in a straight line following the path of your jutsu, by 30 feet and fall prone. On a successful save they take half damage and no additional conditions. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can change the shape of this jutsu to a 30-foot cone.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "92ec7e94d92345d6cc0fe685", name: "ROAR OF ATLANTIS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manipulate the Water Release Chakra with a creature you touch within range. If used on yourself, you do not need to spend chakra to maintain concentration on this jutsu. For the duration, when the creature cast a Jutsu with the Water Release keyword that deals damage or inflicts a condition of any type, the affected creature becomes Wet. A wet creature remains wet for this jutsu’s duration, unless otherwise stated. A wet creature who takes damage from the following damage types triggers the following effects. Fire Damage: Once per turn, they take additional fire damage equal to 2dX, where X is the triggering jutsu’s damage die. The steam remains until the end of the target creatures next turn. The area the steam occupies is heavily obscured. The target creature is no longer wet. Lightning Damage: Once per turn, the creature has the water react to the lightning as the lightnings conductivity is multiplied and all adjacent creatures become targets for this super conduction. They take additional Lightning Damage equal to 2dX, where X is the triggering jutsu’s damage die. All creatures who are adjacent to the wet creature makes a Dexterity saving throw taking half of the lightning damage dealt on a failed save or none on a successful save. Wind Damage: Once per turn, the creature has the wet condition spread around affecting creatures near them as the water is picked up and thrown around. They take additional cold damage equal to 2dX, where X is the triggering jutsu’s damage die. All creatures who are within 10 feet of the wet creature becomes wet as well. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ffc4dc216ee150e61bd7d998", name: "WALL OF WATER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["suiton"], casting_time: "1 Action, 1 Reaction, which you take when you or an allied creature in range takes damage.", range: "60 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure up a wall of water on the ground at a point you can see within range. You can make the wall up to 30 feet long, 10 feet high, and 5 feet thick in any shape you want so long as each piece of wall is connected to another piece. The wall deforms and becomes a mass of water when the jutsu ends, filling each space it occupied with a Source of water that can be used for Water Release Ninjutsu, of C-Rank or lower, once each. The wall’s space is difficult terrain if creatures attempt to pass through it. The water wall has an AC equal to your Ninjutsu save DC and a number of Hit points equal to 6d4 + Your Ninjutsu Save DC, with resistance to Fire damage. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to instead make creatures take 2d8 Cold damage the first time they move through the wall on their turn. 108 WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bbbb6685aee71ff3f3e0b4ce", name: "WATER ABSORPTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Action.", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 Minute", description: "You place a sealing tag on one willing creature you can see within range. When you cast this jutsu, all Water sources the target is in contact with or adjacent to, is absorbed into them and is used to artificially enhance the targets physical ability. If the target is next to a water source comparable to a lake, sea, or ocean this jutsu does not consume all of the water, but up to 1000 gallons. For the duration, the creatures Strength Score becomes 20 if it not already. If their Strength score is already 20, it instead becomes 22. Their jump distance is doubled. They gain resistance to Bludgeoning damage and the first time each turn, that they would deal unarmed or weapon damage they deal additional damage equal to 2d10. When this jutsu ends, the creature becomes weakened and slowed until the end of their next turn as their body recovers from the over saturation of water in their system. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2bcaf8eeeb0854e1e842251f", name: "WATER BREATHING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM", duration: "1 hour", description: "You filter Water as it enters your lungs, being able to breathe as if you were a fish. You can breathe in water as if you were breathing air. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2ca6aeaff3cea1dae54a43a0", name: "WATER BULLET", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You knead chakra in your stomach and expel it in a large quantity of water towards a target creature. Make a ranged ninjutsu attack, dealing 4d6 cold damage that penetrates a creatures DR (damage reduction) ignoring it. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or the number of creatures you can target by +1.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "81ab405e1de2c1a0b5aed9d0", name: "WATER CLONE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "dc2837c0a3446d09da7edaf6", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Action", range: "Self", chakra_cost: "Special (8 Chakra)", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You conjure a clone made of water similar to the Shadow clone technique but with far less power, known as a Water Clone. Water Clone’s weigh half as much as the caster. You can create up to two Water Clones when casting this jutsu, each costing 8 chakra to conjure. Water Clones can cast ninjutsu with the Water Release keyword that you know of D-Rank, following normal Clone keyword restrictions. Additionally, if a damaging jutsu the Water Clone cast would use a damage die larger than a d4, the damage die the clone uses becomes a d6 instead. Water Clones, can move across water without chakra but cannot move vertically along non-water-based surfaces. If a Water Clone uses a weapon or unarmed attack, regardless of the weapon the clone uses, it deals 1d8 cold damage. If a Water Clone casts a jutsu that requires more than 1 attack roll upon casting, it only makes one attack. If multiple water clones attack the same creature, you do not make multiple attack rolls. You instead choose a lead clone and it gains a +1d6 bonus to its damage roll(s), for each additional clone that is aiding it.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the rank of jutsu water clones can cast to C-Rank. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4c61f0c0f73b5af0490e942f", name: "WATER CUTTING SWORD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 10 Minutes", description: "You Conjure water into the shape of a Sword like projection in your free hand. You do not spend chakra to maintain concentration on this jutsu. The blade is 5 feet long, the handle is 1 foot long. The design of the blade can be whatever you decide. If you let go of the blade it disperses into water again. You can use your action to make a Melee Ninjutsu attack with the Water Sword. On a hit, the target takes 4d8+Ninjutsu Ability Modifier cold damage. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to instead increase the damage die by one step, up to a d10.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If Cast at A- Rank, you can instead make two attacks with this jutsu as an action. 109 WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2daa28f9401afdc9530b81d2", name: "WATER FORMATION: POND", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a Puddle of water from your stomach and expel it onto the ground filling and covering the ground in a 25-foot cube originating from you. This puddle holds no more than 100 gallons of water. You can use this puddle as a source of drinking water, lay a trap, or use it as a source for more complex Water Ninjutsu. You may use this water as a Source of Water for up to 5 water release ninjutsu. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "499025d3159bab7e43dcdf68", name: "WATER PERMEATION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Action.", range: "Touch", chakra_cost: "6 Chakra", components: "HS, CM, CS", duration: "1 Minute", description: "You place a sealing tag on one willing creature you can see within range. For the next minute they lose physical form as they and all equipment held become a pool of water. As a pool of water, their speed becomes 60 feet, and gain a swim speed of 120 feet. They can squeeze through cracks or disconnected surfaces that are at least 1 millimeter wide. The affected creature cannot make attacks, use handsigns, or mold chakra. The affected creature cannot see, but they gain 60 feet of tremor sense. Additionally, the affected creature becomes immune to Cold, Bludgeoning, piercing and Slashing Damage. Resistant to Fire Damage, and Vulnerable to lightning Damage. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3d357022b4138469619941b3", name: "WATER PRISON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Hour.", description: "You create a dense spiraling bubble of water around a creature, capturing them inside and restraining movement and preventing them from performing Jutsu. Target creature makes a Dexterity saving throw, being restrained and captured on a failed save. The user must maintain contact with the sphere holding the captive inside. Losing contact causes the jutsu to end immediately. The sphere has an AC equal to your Ninjutsu save DC, 10 hit points, and creatures captured inside the Sphere cannot make Hand Seals or make attacks and find it difficult to breathe. The sphere intercepts all damage meant for the target, has vulnerability to earth damage, and once it reaches 0 hit points, this jutsu immediately ends. At the end of each of their turns they make a Strength saving throw. On a success they force their way out with brute force. The bubble containing a creature can be moved as an Action on behalf of the caster, as they drag it with them as part of their movement. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to make a captured creatures Saving throws to escape this jutsu at disadvantage. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3e10e415c551380e511a52c3", name: "WATER TRUMPET", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You cup your hands and create a highly pressurized stream of water, capable of piercing through steel and the ground itself. Make a Ranged Ninjutsu Attack, dealing 4d10 cold damage. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to instead deal twice as much damage to constructs and structures.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10. B-RANK: WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ec5c9d344bdcb7ed5b9e5e76", name: "ARMOR OF POSEIDON", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 10 Minutes", description: "You manipulate your water release chakra and coat your body in it creating a tangible armor of Water Release. If you are fully submerged in water, this jutsu cannot end as a result of failing a Concentration Check, and you reduce the concentration cost by -1. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to give yourself advantage on Chakra control checks to maintain concentration of this jutsu. For this jutsu’s Duration, you gain the following benefits while completely submerged in water; • You gain a 120 feet Swim Speed. • You can breathe underwater as if breathing air. • You gain 60 feet of tremor sense. • Once per turn, Jutsu you cast with the Water Release Keyword deals additional damage equal to 1 damage die. If the target is currently Chilled the jutsu instead deals additional damage equal to 2 damage die. • Attacks made underwater do not need to be rolled at disadvantage. • Attacks you make while underwater retain their full range. • In place of a weapon attack made with the attack action, you can make a Melee or Ranged Ninjutsu attack equal to the number of attacks you would make with the attack. If melee, your attack deals 3d8 + Ninjutsu ability modifier cold damage. If ranged, your attack deals 2d8 + Ninjutsu ability modifier cold damage has a range of 60/120. 110 WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4e8f83e21f5d583f3bf4d79c", name: "BLOODY MIST ABSORPTION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self (45-Foot cube)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "An advanced variation of the Hidden Mist Technique. This variation requires the user to draw blood from themselves cutting their palm, reducing their current Hit points by 5. You release a crimson red mist that fills a 45-foot-cube originating from you. All creatures inside this mist are heavily obscured and cannot clearly see anything more than 5 feet away from them. You know the location of all creatures inside this red mist and all creatures except for you suffer the following effects. • Creatures who start their turns inside the red mist, who have less than their max hit points lose 4 + Half of any bleed damage they take, in chakra. • Creatures cannot regain Hit points or remove stacks of bleeding while inside the red mist. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fd7727f2e92d006726fcde93", name: "DEEP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: ["suiton"], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "Special (77 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You and other casters manipulate Surrounding Water as you artificially manipulated the depth of water surrounding yourselves. Each Caster of this jutsu manifests a 30-foot radius sphere of water within which they gain a 60-foot swim speed and the ability to breathe within each sphere of water created during this jutsu’s casting. Each caster can then select up to 2 creatures other than themselves who will be unable to Drown while within this jutsu’s radius and gains a swim speed equal to their walking speed while inside any sphere of water created during this jutsu’s casting. Additionally, the selected creatures do not need to make a Saving throw as a result of this jutsu. Each creature selected by a caster who casts a Jutsu of any type while within a sphere of water created during this jutsu’s casting now deals cold damage instead of their jutsu’s listed damage type. Creatures who are within this jutsu’s radius when casted must make a Dexterity and Constitution saving throw. On a failed Dexterity saving throw they are pulled 30 towards the center of the sphere of water. On a successful save they are instead floating within the sphere of water in their current position. On a failed saving throw the creature was unable to hold its breath and begins drowning. A drowning creature can survive for a number of rounds equal to their Constitution Modifier (Min 1) before falling unconscious as a result of drowning. If an unconscious creature remains drowning, at the beginning of the unconscious creatures turn, they take necrotic damage equal to their level. On a successful save they are able to hold their breath for a number of rounds equal to their Constitution Modifier (Min 1.). At the beginning of a creatures turn who has exceeded the number of rounds they can hold their breath; they begin drowning as if they failed their saving throw. An unconscious creature who is no longer drowning can be awoken by another creature as a bonus action. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters reduce the cost by -2. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's radius based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2-3: Increase the radius to 90-foot radius sphere(s), +4-5: Increase the radius to 120-foot radius sphere(s)). WATER RELEASE: EXPLOSIVE COLLIDING", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b4714177f030a184f16f148b", name: "EXPLOSIVE COLLIDING SHOCKWAVE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self (60 Foot radius Sphere)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "1 Minute", description: "When you see another allied creature cast another jutsu, you create a tornado like mass that is compressed until it has a high density before being released as a shockwave, intended to boost their jutsu’s effects. If the triggering jutsu does not have a nature release keyword, the allied creature makes their attack roll at advantage or one hostile creature of your choice within range makes their saving throw at disadvantage. If the triggering jutsu has a nature release keyword, then all hostile creatures in a 60-foot cone, originating from you, must make a Strength saving throw or be pulled 15 feet towards your allied creature, take 5d6 wind damage, and causing Swirl on a failed save, or half as much and no further effect on a success. Additionally, it amplifies the triggering jutsu based on its nature release; • Earth Release: On a failed save target cannot take reactions. • Wind Release: On a failed save target gains 2 ranks of bleeding. • Fire Release: On a failed save the triggering jutsu increases its damage die by 1 step. • Water Release: On a failed save the target gains 1 rank of chilled. • Lightning Release: On a failed save the target gains 1 rank of shocked.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "235ed4ad15a708fe8d52a6fd", name: "HEAVENLY MIRROR OF HOPE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Reaction, which you take when you are targeted by a Jutsu, or would make a saving throw as a result of a jutsu who’s range is either a Line or Cone.", range: "Special", chakra_cost: "Special", components: "HS, CM", duration: "Instant", description: "You manifest a ring of water that creates a reflective film similar to that of a mirror. When you are targeted with a jutsu, you quickly raise this mirror showing your targets reflection. First, you make a Ninjutsu ability Check. The DC equals 13 + the Jutsu’s Rank. (C-Rank: 2, B-Rank: 3, A-Rank: 4, S-Rank: 5) On a success, you then spend a number of chakra casting this jutsu equal to your targets cost of casting a jutsu + the Jutsu’s Rank (D-Rank: +2, C-Rank: +5, B- Rank: +8, A-Rank: +11, S-Rank: +14.) and your mirror reflects the jutsu cast at you back onto them. Any attack rolls, they make now count as targeting themselves, and on a hit, they take their own damage. Saving throws, you would have to make; they instead make as if they were the target suffering their jutsu’s effects as normal. On a failure, your mirror shatters, ending this jutsu. 111 WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "769ee6d37213cdca7e214290", name: "MAELSTROM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "12 chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "A mass of 10-Foot-Deep Water is expelled from you or begins to swirl from a preexisting source of water, centered on a point you can see within range, begins to swirl in a 20 Foot radius. Until the Jutsu Ends, that area is difficult terrain and any creature that starts its turn there must make a Strength saving throw or take 5d8 cold damage being pulled 10 feet towards the center on a failed save, or half as much damage on a successful one. As a Bonus action you can move this maelstrom 30 feet in any direction of your choice. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or creatures with ranks of Chilled within this Jutsu's area makes their save with disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "faac220cf21132e881d7572a", name: "PAINFUL WATER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "90 feet", chakra_cost: "11 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You manipulate the Water Release Chakra within yourself and mark a creature you can see within range with this chakra. For the duration, when the creature would take damage from a jutsu with the Water Release Keyword, they take additional damage equal to your character level, once per turn. Additionally, when a creature marked with this jutsu would make a saving throw to resist the chilled condition, they roll 1d8, reducing their saving throw by the result.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost by 3 and the number of creatures you can mark by +1. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2d6f89793000e46a1004f2cc", name: "RED RAIN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "90 feet (10-foot radius)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manipulate the Water Release Chakra molding it until you create a cloud 100 feet in the air. This cloud is then sent to hover over a creature you can see within range, and begins to rain down red rain in a 10-foot radius around the creature. All creatures who are within the radius begin to be rained on and have their clothing soaked with this red rain, that dulls their senses. For the duration when a creature within this jutsu’s radius would make a saving throw to resist a jutsu cast from any creature other than you, you may roll a d8, reducing their saving throws by the result. This reduction happens once per turn, per creature. As a bonus action on your turn, you may move the cloud 40 feet raining on the new space.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost by 3 and the distance you can move the cloud by +20 feet. WATER RELEASE: REFLECTIVE DROPLETS:", created_at: NOW, updated_at: NOW },
  { _id: "29da21ad84089034283b2bdb", name: "REFLECTIVE DROPLETS: DRIP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["suiton"], casting_time: "1 Reaction, which you take when you would take damage.", range: "Self", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You manipulate your water release chakra molding it until you envelop yourself into a protected bubble, intercepting incoming attacks. This bubble barrier protects you from incoming attacks taking the damage you would take instead until the beginning of your next turn. The bubble in a water structure that has 5d8 + Your Ninjutsu ability score hit points. The bubble is Resistant to Fire Damage and Vulnerable to Earth Damage. You cannot be targeted by jutsu that does not require an attack roll and when you would make a saving throw from a jutsu that affects an area, you make your saving throw at advantage. While the bubble has hit points, melee attacks made against you, reflect some of that damage back to the triggering creature as cold damage equal to half of their attack’s damage. This effect does not trigger if the triggering damage type is Earth.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of hit-points the bubble has by 1d8. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b65270e4e6e4d8526b5a2881", name: "SHARK BOMB", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: ["suiton"], casting_time: "1 Bonus action", range: "120 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "This jutsu cannot be used without a source of water nearby deep enough to fit a medium sized creature. As a bonus action on your turn, you create a Shark construct made of solidified water. The Shark has an AC equal to your Ninjutsu Save DC and has 30 (10d6) Hit Points and has a swim speed of 40. You control this Shark and can direct it do any of the following actions: Attack: As an Action or bonus action on your turn, the shark attempts to bite into a creature currently submerged, standing near, or standing on top of the body of water it currently inhabits. Make a Melee Ninjutsu Attack, on a Hit, the target creature takes 8d8 Cold damage. On a successful hit, the target creature must make a Strength saving throw 112 being grappled by the shark on a failed save. The shark can only grapple one creature at a time. Impede: As a reaction action on your turn, the shark can attempt to impose disadvantage on a target creature by swiftly attacking and getting in the way of their next attack. Explode: As an action on your turn, the shark can explode creating a powerful shockwave of water in a 15-foot cube. Creatures in range must make a Dexterity saving throw, taking 6d10 cold damage on a failed save or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage your shark deals by 1d8. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "990eec63e90d643a327c7dda", name: "TSUNAMI BOW", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, Up to 10 minutes.", description: "You create a modified bow of solidified water that fires water from the same source. This projection can be used as an action to make 2 ranged ninjutsu attacks against a creature up to 120 feet away, that you can see. On a hit, you deal 3d12 cold damage. A target hit by this attack must make a Constitution saving throw being chilled until the end of their next turn on a failed save. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to reduce an affected creatures speed by 15 feet, until the end of their next turn. If you drop this projected weapon it dissipates at the end of the turn. Thereafter, while the jutsu persists, you can use a bonus action to cause it to reappear in your hand.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If you cast this Jutsu at S-Rank, increase the damage of this jutsu by 1d12. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "cfea62c21c81a9345c419fc3", name: "WATER FANG", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Instant", description: "You create two spiraling drills of water around a target creature you can see within range. Target creature must make a Dexterity saving throw, taking 8d6 Cold damage, being knocked prone and dazed, on a failed save, or half as much damage and no further effects on a success. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to target an additional creature.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6. WATER RELEASE: WATER NEEDLES OF", created_at: NOW, updated_at: NOW },
  { _id: "c489fb863a57fc2a1df08a4c", name: "WATER NEEDLES OF DEATH", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Reaction, taking damage from a melee attack or from a creature within 5 feet of you.", range: "Touch.", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "When a creature makes a Melee attack against you, you stomp the ground collecting a mass of water droplets from the ground and air, sharpening them into needles. The triggering creature must make a Dexterity saving throw, taking 8d10 Cold damage and reducing their movement speed by 15 on a failed save and taking half as much damage on a successful one. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can instead make all hostile creatures of your choice, within 15 feet of you when you cast this jutsu, make the saving throw as if they are also targets, taking damage on a failed save or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "8a267c4585b4ce5c5fb6f418", name: "ACID PERMEATION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self (15-foot-Radius)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect water from the air, plants, and all sources that contain it as they form bubbles surrounding you in a 15-foot radius with you in the center. This radius moved with you. When you cast this jutsu, you designate any number of creatures you can see to be unaffected by it. An affected creature’s speed is halved in the area, and when the creature enters the area for the first time on a turn or starts its turn there, it must make a Dexterity saving throw as the bubbles explodes like mines spreading freezing acid over the creature. On a failed save, the creature takes 8d8 Cold damage and gain 2 ranks of Corroded.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8. 113 WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ca3b7a9e79df08c9e23b4a1d", name: "FALLING RAIN NEEDLES", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "120 feet (90-foot cube)", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect all water within 120 feet of you as it collects into the air creating storm clouds that can fill a 90-foot cube, at a point you can see within 120 feet of you. This jutsu fails, if you can’t see a point in the air where the storm cloud could appear (for example, if you are in a room that can’t accommodate the cloud.). When you cast the ninjutsu, choose a point you can see within range, a hail of sharpened water droplets, rain over an area, pulverizing everything within 5 feet of the select area. Each creature within 5 feet of that point must make a Dexterity saving throw. A creature takes 10d6 cold damage on a failed save or half as much on a successful one. On each of your turns until the jutsu ends, you can use your bonus action to call down rain needles in this way again, targeting the same or a different point. If you are outdoors in stormy conditions when you cast this ninjutsu, the jutsu gives you control over the existing storm instead of creating a new one. Under such conditions the jutsu’s damage increases by 1d6 and the cost to maintain this jutsu is reduced by 2.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 for each damage type. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "8bd2faf00acb33e7eed7cc9d", name: "GREAT HYDRA FANG", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Action", range: "120 feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manipulate your water release chakra molding it until you manifest 9 massive serpent like heads of your description composed of Water. As an Action, or bonus action you may command a single hydra head to attack a creature you can see within range. This attack can turn corners and ignores all but total cover. Make a ranged Ninjutsu Attack on a hit you deal 8d8 cold damage. On a hit or miss the head is spent reducing the number of heads you have by 1. As a reaction, you can command a single hydra head to protect you from an incoming attack, granting you 5d8 temporary hit points against the triggering attack. When you do you reduce the number of heads you have by 1. Also, as a reaction, you can command 3 hydra heads to encircle you to completely protect you from a jutsu or effect that would force you to make a Strength, Dexterity or Constitution saving throw. When you do, you instead gain Immunity to the triggering jutsu or effect until the end of the current turn. When you use this effect, you reduce the number of heads you have by 3.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the number of Hydra heads by +1. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "103ff2b65346df00d65f44e3", name: "GREAT SHARK BULLET", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Action", range: "120 feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You manipulate your water release chakra molding it until you manifest a single gargantuan shark that you then launch at a creature within range, leaving a trail of devastation in its path. The shark is propelled in a straight line towards a single target creature. Make a Ranged Ninjutsu Attack. On a success they take cold damage equal to 10d8, and gain 2 ranks of Chilled. All creatures the shark would pass through while traveling to the target creature would suffer some effect as well. All creatures except the target creature in a 15- foot wide, up to 120-foot line makes a Dexterity saving throw. The line ends early if the space the original target creature was occupying is less than 120 feet away from when the jutsu was cast. On a failed save they take 6d8 cold damage and 1 rank of chilled. Or half as much on a successful save and no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 2d8. 114 WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "71de7758169e44d469035128", name: "RAIN TIGER AT WILL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: ["suiton"], casting_time: "1 Hour", range: "10 Miles", chakra_cost: "20 Chakra", components: "HS, CM", duration: "24 Hours", description: "You create rain clouds centered on a point of your choice that you can see 100 feet in the air that spreads outwards covering a radius up to 10 miles in size. The clouds begin to pour down a heavy rain constantly. Each rain drop is connected to the caster’s senses informing them of any and all creatures, movements, activities and actions that the raindrops come into contact with. This rain is almost entirely seen as natural otherwise. A creature with chakra sight can see the chakra in each water drop. While the caster will be aware of events and actions within the rain, this does not inform them of the exact location within the radius of this jutsu’s effect range. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ac7c52508c596b070adbdf0a", name: "TRIDENT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You manifest water release chakra in the shape of a trident, lance, spear or any polearm of your description. This projection begins to vibrate and churn the water it is comprised of turning it until it acts like a Chainsaw when it strikes a target creature. You do not spend Chakra while maintaining concentration on this jutsu and cannot lose concentration on it as a result of damage. As an action, for the duration, you make two melee ninjutsu attacks with this projection. Attacks with this projection have a range of 10 feet, has a +1 bonus to its critical threat range and deals 10d6 cold damage on a hit. Creatures who take cold damage as a result of this jutsu that has 3 or more ranks of chilled has the chilling waters bite into them, granting them an equal number of ranks of Weakened. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you make attacks targeting creatures with 3 or more ranks of chilled with advantage.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "8827027c0143ffed628a7a4a", name: "WATER DRAGON", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["suiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You expel a massive quantity of water or pull from a nearby source, conjuring a large Dragon of your description from water. The Dragon attempts to ram its target. Make a Ranged ninjutsu attack, on a hit target creature 14d6 cold damage. The target creature must make a Constitution saving throw, being stunned and knocked prone on a failed save until the end of the targets next turn. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to increase the damage die to a d8.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 for each damage type. WATER RELEASE: WATER FORMATION", created_at: NOW, updated_at: NOW },
  { _id: "d72f55d33d27821e91a1dda6", name: "WATER FORMATION: WALL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "fef9deb945f95aa08666590c"], elements: ["suiton"], casting_time: "1 Reaction, which you take when you or an allied creature within range takes damage.", range: "30 feet (5-Foot radius Sphere)", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You weave together a mixture of summoning seals and summon forth a wall of angry, irrational and non-compromising bees. The wall is 5 feet thick, 15 feet high and up to 30 feet long. The wall must be continuous and at least 5 feet thick along its entire length. You select where the wall of bees appear and the entire length must be within your line of sight and within this jutsu’s range from you. A creature that starts within the bee’s wall or that gets within 5 feet of the wall of bees agitates the insects and are swarmed by them and must make a Constitution saving throw against their assault. On a failed save they take 5d6 poison damage and are incapacitated until the end of the current turn. On a successful save they take half damage and suffer no additional effects. NEEDLE JIZO Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you would take damage. Range: Self Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 9 Chakra Keywords: Ninjutsu Description: You activate the roots of your hair causing your hair to grow at a heightened rate, while you control it to wrap around your body and harden with spiked, needle like hair protruding from it., For the duration, your movement speed is reduced to 0, each time a creature makes a melee attack against you while within 10 feet of you, they take 3d6 piercing damage, this includes the triggering attack.", at_higher_ranks: "You coat your fingertips in chakra and attempt to strike an opponent at the nape of their neck sending a surge of chakra through their central nervous system mixing up signals from their brain to the rest of their bodies. Make a Melee Ninjutsu Attack. On a hit, the target creature must make a Constitution saving throw. On a failed save, the target creature's speed is halved, it takes a -2 Penalty to AC, automatically fails Dexterity saving throws and cannot use reactions. On its turn, it can either use an action or bonus action, not both. Regardless of the creature's abilities or jutsu descriptions, it can’t make more than one attack during its turn. If the creature wants to use an action to make an ability save to end this effect, they must instead roll an Intelligence save.", created_at: NOW, updated_at: NOW },
  { _id: "a9c096e61c7a4017c99ecfe8", name: "WATER SEVERING WAVE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "60ft cone", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You cup your hands against your mouth releasing a torrent of highly pressurized water and using your chakra like a nozzle. You sweep your head from side to side targeting a cone area up to 60 feet in distance. Creatures caught in the radius of this jutsu must make a Dexterity saving throw, taking 8d10 cold damage on a failed save. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can force affected creatures to make a Constitution saving throw, gaining 2 ranks of chilled on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 for each damage type. 115 S-RANK: WATER RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4fddfc5b6869e2d8c348086a", name: "DROWN", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "b3b9a80a8acefa31d6905369"], elements: ["suiton"], casting_time: "1 Full Turn Action", range: "120 feet", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manipulate your water release chakra molding it until you reach a level of control so much so that you are able to forcibly turn air into water and vice versa as it is inhaled by other creatures. Select up to 7 creatures you can see within range. Each creature makes a Constitution saving throw. On a Failed save for the duration if they can breathe air, they instead can only breathe water. If they can breathe water, they can instead only breathe air. A creature who is currently in an environment in which they cannot breathe normally, they begin to Drown. While drowning this way, it can survive for a number of rounds equal to its Constitution modifier (minimum of 1 round). At the start of its first turn after these rounds, it drops to 0 hit points and is dying. A creature who begins their turn dying after falling to 0 hit points as a result of this jutsu, they die. While drowning they cannot speak.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "131e38a2e9fdef7ec751032a", name: "GIANT VORTEX TSUNAMI", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self (120-Foot-Cone)", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Instant", description: "You Collect water from up to 100 feet away from all sources of moisture even down to other creatures' sweat. You collect it into a massive 20 Feet tall 15 Feet wide vortex. You fire this highly destructive cyclone of water collecting, upheaving, and blowing everything in its path away in a 120-foot-cone. Creatures caught in the range of the jutsu, must make a Strength saving throw to resist being picked up by the cyclone, taking 15d10 cold damage, gaining 3 ranks of Concussed, and 3 ranks of chilled, being dragged by the vortex to the end of its path, landing prone and being Stunned until the end of their next turn on a failed saving throw, or half as much damage on a success. WATER RELEASE: GIANT WATER PRISON", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5a0d939faf6bd15791e44a67", name: "GIANT WATER PRISON DANCE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "60 Foot radius Sphere", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You knead enough water in your stomach and release enough to fill a small ocean. You then control the water creating a massive ball of Water centered around you that extends up to a 60 radius. All Creatures in the radius are picked up by the wave of water and pulled into the water sphere. All Creatures inside the Water Sphere must make a Strength saving throw, being captured inside the sphere and unable to escape, on a failed save. When captured this way, the captured creature is considered to be underwater while inside the Water prison. When the User of this Jutsu moves, the water sphere moves with him. Creatures who succeed their Strength save, can escape the Water prison if they can make it to the edge of the water sphere.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "84b6e920fa782c2c05a83782", name: "GRUDGE RAIN", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "Self (250 Foot Radius)", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 1 hour", description: "You create rain clouds centered on a point of your choice that you can see 100 feet in the air that spreads outwards covering a radius up to 10 miles in size. The clouds begin to pour down a heavy rain. For the duration, up to 5 creatures of your choice are not affected by this jutsu. All other creatures within the radius double all chakra costs. WATER RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6778b410dc32aae00d08c3f9", name: "WATER HEAVENS CONVERGENCE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: ["suiton"], casting_time: "1 Action", range: "60 Foot radius Sphere", chakra_cost: "22 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You begin to feel the presence of all free- flowing water particles within 120 feet of you. For the duration you can control all water as if it was an extension of your body. All Ninjutsu that has the Water Release keyword of A- Rank or lower, has their cost reduced by half. You gain additional actions you can use on your turn: Water Drill. As an action on your turn, you can make a ranged ninjutsu attack against a creature you can see within range dealing 10d12 cold damage as water surround and collapses over them. Water Armor. As a reaction to being hit with an attack you coat your body in a thick layer of solidified water to lessen the impact. You gain 30 temporary hit points until the beginning of your next turn. Watery Chains. As an action on your turn, you can have the surrounding water form chains as they attempt to capture a creature within range. The target must make a Strength saving throw being restrained and incapacitated on a failed save. On their turns they can make a Strength saving throw to end this effect on them. 116 Huge Construct, unaligned Armor Class 17 + Your Ninjutsu Ability Modifier Hit Points 170 (11d12 + 99) Speed 60 ft. STR DEX CON INT WIS CHA 23 (+6) 16 (+3) 28 (+9) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Acid, Poison, Psychic, Bludgeoning, Piercing and Slashing damage. Damage Resistance Fire Damage Vulnerability Earth Condition Immunities Charmed, Chilled, Exhaustion, frightened, stunned, poisoned. Senses Darkvision 60 ft., passive Perception 10 Immutable Form. The Supreme Water Lion is immune to any Jutsu or effect that would alter its form. Elemental Weapons. The Lions attacks are chakra enhanced. One with Water. When the lion is in contact with a body of water large enough for it to submerge itself, it gains a 250-foot swim speed, and Truesight 90 feet against other submerged creatures. Multiattack. The Supreme Water Lion can attack 3 times. Twice with its claws and once with its bite. Bite. Melee Weapon Attack: reach 10 ft., one creature. Hit: 6d6 + 6 Cold damage. A creature hit by this attack must make a Strength Saving throw vs your Ninjutsu Save DC. On a failed save they are grappled. Until this grapple ends, the target is restrained and the Lion cannot bite another target. Claw. Melee Weapon Attack: reach 10 ft., one creature. Hit: 3d8 + 6 Cold damage. A creature hit by this attack must make a Constitution saving throw vs your Ninjutsu Save DC. On a failed save they gain 1 rank of Chilled. Swallow. The Water Lion makes one bite attack against a Large or Smaller creature it is grappling. If the Attack hits, the target is swallowed, and the grapple ends. The swallowed target is restrained but is fully visible in the belly of the Water Lion, although it cannot be the target of any jutsu. While inside the Lion it must be able to breathe underwater or it begins to drown. A drowning creature can survive for a number of rounds equal to their Constitution Modifier (Min 1) before falling unconscious as a result of drowning. If an unconscious creature remains drowning, at the beginning of the unconscious creatures turn, they take Cold damage equal to 6d6 + 9. An unconscious creature who is no longer drowning can be awoken by another creature as a bonus action Hydro Discharge (Recharge 5-6): The Lion exhales Pure Water Release chakra in a 60- foot cone. Each creature, except its summoner in that cone must make a Dexterity saving throw vs your Ninjutsu save DC, taking 10d10 Cold damage and 2 ranks of Chilled on a failed save, or half as much damage on a successful one. WATER RELEASE: SUPREME WATER", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2a9e50dcccb90724eb6bffb0", name: "SUPREME WATER LION", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["suiton"], casting_time: "1 Full Turn Action", range: "120 feet", chakra_cost: "25 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You conjure a Huge construct made of Water & Chakra forming a Huge beast of your description that uses your Ninjutsu attack bonus and Save DC for effects that require it. It rolls initiative as it has its own turns, using your Ninjutsu Ability Modifier + Proficiency as its Initiative. You can as a bonus action on your turn, so long as you are in physical contact with this construct merge into its head. While you are merged in this way you have total Cover against attacks and other effects outside of the Lion.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "804256078b1ab79d7c650053", name: "BANQUET OF LIGHTNING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You Place your palm on the ground and conduct a jolt of lightning that runs through it towards a target creature in range. This jutsu ignores cover and can go around corners. Target creature must make a Constitution save, taking 3d6 Lightning Damage and gaining 1 rank of shocked on a failed save and only half damage on a successful one. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, a creature who fails their saving throw is also slowed for the same duration that they are shocked.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 and the number of creatures you can target by +1. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "335d8c7cc97939780cc7e32c", name: "CHARGED IMPULSE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Up to 8 Hours", description: "You touch a willing creature. For the duration, the target can add 1d8 to the first initiative roll it makes for the duration. For the next minute after rolling initiative the target can, as a bonus action on each of its turns take the dash action, this jutsu then ends. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1c21d15ca373f2cd2847778a", name: "CIRCUIT BREAKER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "90 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure your lightning release chakra to generate a jolt of electricity in an attempt to shock a creature within range. Make a Ranged Ninjutsu Attack, on a hit, you deal 1d6 Lightning Damage. If the target creature is currently concentration on a Jutsu they make their check at disadvantage. If the target has a jutsu active that doesn’t require concentration and they are not currently concentration on a jutsu, they lose the benefits of that jutsu until the end of their next turn. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, increase the damage dealt by 2 steps and add your Ninjutsu ability modifier.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the amount of attacks you make by +1. LIGHTNING RELEASE: ELECTROMAGNETIC", created_at: NOW, updated_at: NOW },
  { _id: "c2cecac587a7beda65e243e1", name: "ELECTROMAGNETIC ANNOYANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self (20-foot Cube)", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure your lightning release chakra to generate a wave of electricity. Each creature in a 20- foot cube originating from you must make a Constitution saving throw. On a failed save they gain 1 rank of Shocked. If a creature is already shocked, they make this save at disadvantage. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, all creatures who fail their saving throw have their speed reduced by 10 for each rank of shocked they have.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the cube by 5 feet. 118 LIGHTNING RELEASE: ELECTROMAGNETIC", created_at: NOW, updated_at: NOW },
  { _id: "25948ef71aafeee4fd6a497b", name: "ELECTROMAGNETIC FIELD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self (20-foot Cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You conjure your lightning release chakra to generate an aura electricity. Each creature of your choice within a 20-foot cube originating from you when this jutsu is cast, and those who begin their turns in this jutsu’s range must make a Constitution saving throw. On a failed save the first time each time they would take Lightning Damage the damage die of the lightning damage increases by 1 Step. (D4>D6>D8>D10>D12)", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "92e7cc84fffb734b424b960c", name: "ENHANCED ABILITY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "1 Minute", description: "You touch a willing creature and bestow upon it a vast increase in one of its physical abilities. Choose one of the following effects; the target gains the effect until the jutsu ends. You can only have this jutsu active on one creature at a time. Agility. The target has advantage on Dexterity Saving Throws. It also doesn’t take damage from falling 20 feet or less if it’s not incapacitated. Endurance. The target has advantage on Constitution saving throws. It also gains 10 Temporary Hit points, which are lost when the jutsu ends. Strength. The target has advantage on Strength Saving Throws. It also increases damage done with attack rolls using its Strength by +2 Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, the following effects are enhanced in the following ways; Agility. The target can dash as a bonus action for the duration. Endurance. The target gains an additional 15 temporary hit points. Strength. The target gains immunity to the Weakened condition for the next minute.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can have this active on at once increases by +1. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "8cc1025033cf2117efff709a", name: "GUIDING BOLT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "90 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "A flash of lightning erupts from your hands towards a creature of your choice within range. Make a ranged ninjutsu attack against the target. On a hit the target takes 3d8 lightning damage, and the next attack roll made against the target before the end of your next turn has advantage, thanks to the streak of electricity guiding the next attack to the target. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do this jutsu instead becomes a 60 foot long, 5-foot-wide line. All creatures in range must make a Dexterity saving throw, taking 3d8 lighting damage on a failed save or half as much on a success. Regardless of a pass or fail, the next attack roll made against affected creatures before the end of your next turn has advantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "864f152350b9a03eea7f29e4", name: "HEAVEN STEP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Bonus Action", range: "90 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You conjure your lightning release chakra to generate a mote of electricity. Select a space that another creature is not occupying that you can see within range where you throw your mote. This space can be in the air but cannot be thrown through walls or water instead stopping at the first semi-solid surface it encounters. You can choose to target a creature with this mote instead of an empty space. Make a range ninjutsu attack. On a success you deal 1d8 lightning damage and the target must make a Constitution saving throw gaining 1 rank of shocked on a failed save. The mote then occupies the closest open space as the target creature. As a reaction, you can trigger the mote to detonate. All creatures within 5 feet of the mote must make a Dexterity saving throw. On a failed save they take 2d6 Lightning damage and gain 1 rank of shocked. If a creature who makes this save is already shocked, they make their saving throw with a -2 penalty. When you do this jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8 and 1d6 respectively. 119 LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0d69f3ba14a21513d716f46a", name: "LIGHTNING BALL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You generate multiple small floating globes of lightning chakra. You fire them all off as once rapidly at a singular target. Make a Ranged Ninjutsu attack. If the target creature is wielding a metallic weapon, you make this attack at Advantage. On a hit, the target creature takes 6d4 Lightning Damage and forces the creature to make a Constitution saving throw. On a failed save it gains 1 rank of shocked. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do you create a second set of lightning globes, and you must select a second creature to target with this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the number of attacks you can make by +1. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ca8e7567b3c5d99ad949d1c9", name: "LIGHTNING BUCKLER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["raiton"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You conjure your lightning release chakra and mold it around a chakra seal until you form a shield made of Lightning. For the duration this jutsu cannot be ended as a result of a failed concentration check. The lightning shields you manifest sits on your arm and has a design of your description. For the duration, when you would take damage from a melee attack you may as a Reaction attempt to deflect the attack. When you do reduce the damage taken by 2d6 + your Ninjutsu ability Modifier. If the damage is reduced to 0, the triggering creature gains 1 rank of Shocked. If Wind damage would be the triggering damage type you instead roll 2d4 + Your ninjutsu ability modifier. For each rank of Shocked a creature has, increase the damage reduction of this jutsu by +1 die.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage reduction by +2 die. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "d52b19ef164de65c86751532", name: "LIGHTNING KNUCKLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9"], elements: ["raiton"], casting_time: "1 Action", range: "5 feet", chakra_cost: "3 Chakra", components: "HS, CM, M", duration: "Instant", description: "You cover your Fist in surging electricity using it to strike forward with an electrically charged punch. Make a melee ninjutsu (or Taijutsu) attack against a creature within range. On a hit, you deal your [Unarmed Damage] + 2d6 lightning damage and the target must make a Constitution saving throw, gaining 1 rank of shocked on a failed save. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do this jutsu gains a +1 bonus to critical threat range.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the number of attacks you can make by +1. You can only target a creature up to twice with attacks made as a result of this jutsu. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "83d1be50c48507f1b2b70644", name: "LIGHTNING REFLEX", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Reaction which you take when you are forced to make a Dexterity saving throw.", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "Your body becomes charged with lightning release chakra enhancing your reflexes to great heights. When you make a Dexterity saving throw you may roll at Advantage. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "72226090f3dd9f36287aeb78", name: "LIGHTNING REPEL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Reaction to being targeted by an attack or jutsu", range: "Self", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You create a magnetic force field around yourself misdirecting attacks away from you. Attacks have disadvantage when targeting you until the start of your next turn. 120 LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "30acc72d476d0c7df19dd3c4", name: "LIGHTNING SPEED", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You coat your body in a film of lightning as you teleport up to your movement speed to an unoccupied space that you can see, appearing as a jolt of lightning when you end your movement. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a8f9304a4e83a9e1383aab4d", name: "MARK OF JOLTS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["raiton"], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute.", description: "You conjure your lightning release chakra and mold it around a chakra seal until you form a Kanji of your own description and with its own meaning. This Kanji Floats in a space within 5 feet of you and can be moved up to 20 feet in any direction of your choice as a bonus action. Choose one of the following effects; Jolts: All creatures except you, within a 10-foot radius sphere centered on your Kanji takes lightning damage equal to 1d6 + Your Ninjutsu ability Modifier at the end of each of your turns. Shocks: All creatures except you, within a 10-foot radius sphere centered on your Kanji that takes lightning damage must make a Constitution saving throw gains 1 rank of Shocked on a failed save. Once this effect has triggered and inflicted the shocked condition 3 times this jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 or the number of triggers by +1. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2cc74edf266f24962ffc9c9a", name: "PANTHER CLAW", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "10 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant.", description: "You conjure your lightning release chakra and mold it around your arms until you conjure a projection of your description. Make a Melee Ninjutsu attack. On a hit you deal 2d10 Lightning Damage. If the target has at least 1 rank of shocked your damage die becomes d12. If the target has at least 2 ranks of shocked you also increase your critical range to 19~20. If the target has at least 3 ranks of shocked you also add your Ninjutsu Ability Modifier to the damage you deal. If the target has at least 5 ranks of shocked, you make an additional melee ninjutsu attack. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, you may add your Ninjutsu ability modifier to the damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "4224cb802b1211d05cf22da7", name: "RETRIBUTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Reaction, which you take when you take damage", range: "Self (15-foot Radius Sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure your lightning release chakra and mold it to form a defensive instrument of your choice; This can be a great sword, shield, wall, or a version of yourself made of lightning. This jutsu cannot be triggered by Psychic or Chakra damage. When you would take damage, you gain Temporary Hit Points equal to half of your Ninjutsu Save DC (rounded down). While you have Temporary hit points gained by this jutsu, you have resistance to Earth Damage and Vulnerability to Wind Damage. Each time you take damage until the end of the current turn you build up lightning release chakra. You must keep track of all damage taken until the end of the current turn. If your hit points are reduced to 0 while this jutsu is active, it immediately ends. At the end of the current turn, you discharge all of the built-up Lightning Release chakra. All creatures within a 15- foot radius sphere must make a Dexterity saving throw, taking lightning damage equal to the damage you’ve taken + 3d6 on a failed save or half as much on a successful save. If a creature is shocked, they make their saving throw at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b8f5831402b02ede7b6ba4d4", name: "SHATTERING BOLT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "A beam of crackling blue lightning lashes out towards a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged ninjutsu attack against that creature. On a hit, the target takes 2d12 Lightning damage and gains 1 rank of shocked. Once each of your turns for the duration, you can use your action to deal 2d12 lightning damage & inflict 1 rank of shocked automatically. The jutsu ends if you use your action to do anything else. The jutsu also ends if the target leaves this jutsu’s range or if it has total cover from you. When this jutsu ends, the original target loses all ranks of shocked it gained from this jutsu. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do the first target gains 2 ranks of shocked on the first hit made with this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and increase the damage by 1d12. 121 LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "13ae61ac1f13d9edbc70ec92", name: "SHOCK WHIP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You create a whip of lightning, and lash it at a target creature in range. The target must make a Strength saving throw, taking 2d10 Lightning damage and being pulled or pushed 10 feet on a failed save, or half damage on a successful save. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature who fails their saving throw gains 1 rank of shocked.", at_higher_ranks: "For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 and the range by 5ft. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "af524d655f98cdb48228eb93", name: "SPARK LR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure your lightning release chakra to generate a spark of willpower from within a creature.  A Creature you touch gains 1 Hit point and a number of temporary hit points equal to 2d6 + Your Ninjutsu ability Modifier. These Temporary hit points last for 1 minute.  Additionally, the creature gains resistance to Lightning damage so long as they have Temporary hit points granted by this jutsu. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, the first time you would take lightning damage while benefiting from temporary hit points (THP) as a result of this jutsu, you instead gain bonus THP equal to half the damage dealt.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f014ba4e71cd1414f5e52f32", name: "STATIC SENSE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: ["raiton"], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 minute", description: "You gain the ability to see electrical signals occurring in creatures or objects up to 300 Feet away. This penetrates up to 5-feet of nonmetal surfaces. You can tell when an object that works off of electricity, such as non- jutsu based communication systems, cameras, computers, and other technological devices are in active use, or are moving, and their general shape. You can tell when Creatures can generate electricity such as lightning release or as a natural phenomenon (eels, magnets, batteries etc.) LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bb5309449c12f3b06c22a6ae", name: "THOR’S MARK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Bonus Action", range: "90 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 hour", description: "You send a negatively charged spark of Lightning release chakra to attach itself to a target creature you can see within range marking it. You do not need to spend chakra to maintain concentration on this jutsu. Until the jutsu ends you deal an extra damage die to the target whenever you hit it with Ninjutsu with the Lightning Release Keyword. You also have advantage on Wisdom (Perception) or (Survival) checks you make to track or find the target. If a creature marked with this jutsu reaches 0 hit points you may move the mark to another creature as a bonus action. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3c275416391ed90a04838cc3", name: "THUNDER TEMPEST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "25 Foot Cone", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "A wave of electrical force sweeps out from you. Each creature in a 25-foot cone originating from you must make a Strength saving throw. On a Failed save a creature takes 4d4 Lightning Damage are pushed back 10 feet and shocked. On a successful save, the creature takes half as much damage and isn't pushed. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature who fails their saving throw has their initiative score reduced by 1d4, falling in the initiative order accordingly as a result. A creature can only have their initiative changed twice as a result of this effect.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d4 and knock back distance 5ft. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e0c19707528743e3ded3730e", name: "THUNDERBOLT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self (15-Foot radius Sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You generate 2 spheres of lightning on each hand, discharging them in a 15-foot radius sphere originating from you. All Creatures of your choice in the target area must make a Dexterity saving throw, taking 2d10 Lightning Damage and being shocked on a failed save and half as much on a successful one. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do increase this Jutsu's radius by 10 feet. 122", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "aaf08324ac462a2ea05cfd1e", name: "THUNDERCLAW", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You conjure your lightning release chakra to generate claws of Lightning around your hands. For the duration, you can as an action make a melee ninjutsu attack. On a hit you deal 2d6 + Your Ninjutsu ability modifier in Lightning Damage. If a target is shocked increase the damage die to a d8. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, the first time each turn you deal damage with this jutsu, if a creature has any number of ranks of shocked, increase this jutsu’s critical threat range by +1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast B-Rank or higher increase the number of attacks by +1. If cast at S-Rank, increase the number of attacks by +1. C-RANK: LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0b8d07c6fa1929180401202e", name: "AFTERSHOCK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Reaction, which you take when you deal Lightning Damage to a creature using a jutsu.", range: "Special", chakra_cost: "Special", components: "HS, CM", duration: "Instant", description: "You conjure your lightning release chakra to generate a jolt of electricity in an attempt to double up on the effects of the previous jutsu you cast. As a reaction, when you would deal lightning damage to a creature you may recast the jutsu targeting the same creatures or affecting the same area. The jutsu recast in this way have their cost doubled. If the jutsu recast has the special cost, then it costs an additional +3 Chakra. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6b2e966f7f20adad081862ba", name: "CHIDORI", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "5 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "This powerful assassination technique focuses lightning Chakra into one of your hands, which will be unable to hold items while charged, but can still be used to make hand seals without harm. You do not need to spend chakra to maintain concentration with this jutsu. As an action on your next turn, you can use your action to make a Melee Ninjutsu Attack on a target creature within range. On a hit, the target creature takes 5d10 Lightning Damage and this jutsu ends. This Jutsu has a +1 critical threat range. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, this jutsu evolves in power, becoming the Raikiri, gaining the following benefits until this jutsu ends; Bonus +20 speed, 1d4 bonus to hit, and on a critical hit, increases damage die by 1 step.", at_higher_ranks: "If this Jutsu is upcasted to at least B- Rank you immediately perform the Melee Ninjutsu attack instead of waiting till your next turn. For each rank above C-Rank, increase the cost by 3, increasing the damage done by 2d10 and Critical threat range by +1. 123 LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "197e87e36ebc71c67913e5bb", name: "JOLT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure your lightning release chakra and mold it around a chakra seal until you form a Kanji of your own description and with its own meaning. This Kanji Floats in a space within 5 feet of you and can be moved up to 20 feet in any direction of your choice as a bonus action. Choose one of the following effects; Jolts: All creatures except you, within a 10-foot radius sphere centered on your Kanji takes lightning damage equal to 1d6 + Your Ninjutsu ability Modifier at the end of each of your turns. Shocks: All creatures except you, within a 10-foot radius sphere centered on your Kanji that takes lightning damage must make a Constitution saving throw gains 1 rank of Shocked on a failed save. Once this effect has triggered and inflicted the shocked condition 3 times this jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 or the number of triggers by +1. LIGHTNING RELEASE: PANTHER CLAW Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 10 feet Duration: Instant. Components: HS, CM Cost: 4 Chakra Keywords: Lightning Release, Ninjutsu Description: You conjure your lightning release chakra and mold it around your arms until you conjure a projection of your description. Make a Melee Ninjutsu attack. On a hit you deal 2d10 Lightning Damage. If the target has at least 1 rank of shocked your damage die becomes d12. If the target has at least 2 ranks of shocked you also increase your critical range to 19~20. If the target has at least 3 ranks of shocked you also add your Ninjutsu Ability Modifier to the damage you deal. If the target has at least 5 ranks of shocked, you make an additional melee ninjutsu attack. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, you may add your Ninjutsu ability modifier to the damage dealt. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. LIGHTNING RELEASE: RETRIBUTION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you take damage. Range: Self (15-foot Radius Sphere) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Lightning Release, Ninjutsu Description: You conjure your lightning release chakra and mold it to form a defensive instrument of your choice; This can be a great sword, shield, wall, or a version of yourself made of lightning. This jutsu cannot be triggered by Psychic or Chakra damage. When you would take damage, you gain Temporary Hit Points equal to half of your Ninjutsu Save DC (rounded down). While you have Temporary hit points gained by this jutsu, you have resistance to Earth Damage and Vulnerability to Wind Damage. Each time you take damage until the end of the current turn you build up lightning release chakra. You must keep track of all damage taken until the end of the current turn. If your hit points are reduced to 0 while this jutsu is active, it immediately ends. At the end of the current turn, you discharge all of the built-up Lightning Release chakra. All creatures within a 15- foot radius sphere must make a Dexterity saving throw, taking lightning damage equal to the damage you’ve taken + 3d6 on a failed save or half as much on a successful save. If a creature is shocked, they make their saving throw at disadvantage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. LIGHTNING RELEASE: SHATTERING BOLT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Lightning Release, Ninjutsu Description: A beam of crackling blue lightning lashes out towards a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged ninjutsu attack against that creature. On a hit, the target takes 2d12 Lightning damage and gains 1 rank of shocked. Once each of your turns for the duration, you can use your action to deal 2d12 lightning damage & inflict 1 rank of shocked automatically. The jutsu ends if you use your action to do anything else. The jutsu also ends if the target leaves this jutsu’s range or if it has total cover from you. When this jutsu ends, the original target loses all ranks of shocked it gained from this jutsu. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do the first target gains 2 ranks of shocked on the first hit made with this jutsu. At Higher Ranks: For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and increase the damage by 1d12. 121 LIGHTNING RELEASE: SHOCK WHIP Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Lightning Release, Ninjutsu Description: You create a whip of lightning, and lash it at a target creature in range. The target must make a Strength saving throw, taking 2d10 Lightning damage and being pulled or pushed 10 feet on a failed save, or half damage on a successful save. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature who fails their saving throw gains 1 rank of shocked. At Higher Ranks: For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 and the range by 5ft. LIGHTNING RELEASE: SPARK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Lightning Release, Ninjutsu, Medical Description: You conjure your lightning release chakra to generate a spark of willpower from within a creature. A Creature you touch gains 1 Hit point and a number of temporary hit points equal to 2d6 + Your Ninjutsu ability Modifier. These Temporary hit points last for 1 minute. Additionally, the creature gains resistance to Lightning damage so long as they have Temporary hit points granted by this jutsu. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, the first time you would take lightning damage while benefiting from temporary hit points (THP) as a result of this jutsu, you instead gain bonus THP equal to half the damage dealt. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary Hit points by 1d6. LIGHTNING RELEASE: STATIC SENSE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Lightning Release, Ninjutsu, Sensory Description: You gain the ability to see electrical signals occurring in creatures or objects up to 300 Feet away. This penetrates up to 5-feet of nonmetal surfaces. You can tell when an object that works off of electricity, such as non- jutsu based communication systems, cameras, computers, and other technological devices are in active use, or are moving, and their general shape. You can tell when Creatures can generate electricity such as lightning release or as a natural phenomenon (eels, magnets, batteries etc.) LIGHTNING RELEASE: THOR’S MARK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: 90 Feet Duration: Concentration, up to 1 hour Components: HS, CM Cost: 4 Chakra Keywords: Lightning Release, Ninjutsu Description: You send a negatively charged spark of Lightning release chakra to attach itself to a target creature you can see within range marking it. You do not need to spend chakra to maintain concentration on this jutsu. Until the jutsu ends you deal an extra damage die to the target whenever you hit it with Ninjutsu with the Lightning Release Keyword. You also have advantage on Wisdom (Perception) or (Survival) checks you make to track or find the target. If a creature marked with this jutsu reaches 0 hit points you may move the mark to another creature as a bonus action. LIGHTNING RELEASE: THUNDER TEMPEST Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 25 Foot Cone Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Lightning Release, Ninjutsu Description: A wave of electrical force sweeps out from you. Each creature in a 25-foot cone originating from you must make a Strength saving throw. On a Failed save a creature takes 4d4 Lightning Damage are pushed back 10 feet and shocked. On a successful save, the creature takes half as much damage and isn't pushed. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature who fails their saving throw has their initiative score reduced by 1d4, falling in the initiative order accordingly as a result. A creature can only have their initiative changed twice as a result of this effect. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d4 and knock back distance 5ft. LIGHTNING RELEASE: THUNDERBOLT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-Foot radius Sphere) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Lightning Release, Ninjutsu Description: You generate 2 spheres of lightning on each hand, discharging them in a 15-foot radius sphere originating from you. All Creatures of your choice in the target area must make a Dexterity saving throw, taking 2d10 Lightning Damage and being shocked on a failed save and half as much on a successful one. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do increase this Jutsu's radius by 10 feet. 122 At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10. LIGHTNING RELEASE: THUNDERCLAW Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Lightning Release, Ninjutsu Description: You conjure your lightning release chakra to generate claws of Lightning around your hands. For the duration, you can as an action make a melee ninjutsu attack. On a hit you deal 2d6 + Your Ninjutsu ability modifier in Lightning Damage. If a target is shocked increase the damage die to a d8. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, the first time each turn you deal damage with this jutsu, if a creature has any number of ranks of shocked, increase this jutsu’s critical threat range by +1. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast B-Rank or higher increase the number of attacks by +1. If cast at S-Rank, increase the number of attacks by +1. C-RANK: LIGHTNING RELEASE: AFTERSHOCK Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you deal Lightning Damage to a creature using a jutsu. Range: Special Duration: Instant Components: HS, CM Cost: Special Keywords: Lightning Release, Ninjutsu Description: You conjure your lightning release chakra to generate a jolt of electricity in an attempt to double up on the effects of the previous jutsu you cast. As a reaction, when you would deal lightning damage to a creature you may recast the jutsu targeting the same creatures or affecting the same area. The jutsu recast in this way have their cost doubled. If the jutsu recast has the special cost, then it costs an additional +3 Chakra. LIGHTNING RELEASE: CHIDORI Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 5 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 8 Chakra Keywords: Lightning Release, Ninjutsu, Clash Description: This powerful assassination technique focuses lightning Chakra into one of your hands, which will be unable to hold items while charged, but can still be used to make hand seals without harm. You do not need to spend chakra to maintain concentration with this jutsu. As an action on your next turn, you can use your action to make a Melee Ninjutsu Attack on a target creature within range. On a hit, the target creature takes 5d10 Lightning Damage and this jutsu ends. This Jutsu has a +1 critical threat range. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, this jutsu evolves in power, becoming the Raikiri, gaining the following benefits until this jutsu ends; Bonus +20 speed, 1d4 bonus to hit, and on a critical hit, increases damage die by 1 step. At Higher Ranks: If this Jutsu is upcasted to at least B- Rank you immediately perform the Melee Ninjutsu attack instead of waiting till your next turn. For each rank above C-Rank, increase the cost by 3, increasing the damage done by 2d10 and Critical threat range by +1. 123 LIGHTNING RELEASE: JOLT Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, CM Cost: 7 Chakra Keywords: Lightning Release, Ninjutsu, Medical Description: You conjure your lightning release chakra to generate a spark of willpower from within a creature. A Creature you touch gains 5 Hit points and a number of temporary hit points equal to 4d8. These Temporary hit points last for 1 minute. So long as a creature have temporary hit points as a result of this jutsu, they gain a 10-foot bonus to their walking speed and a +2 bonus to their Dexterity saving throws. A dying creature who is affected by this jutsu gains an additional jolt of energy. Until the end of their next turn, they gain an additional Bonus action. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, increase the die used to determine temporary hit points, by 1 step. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, temporary Hit points by 1d8 and +5 walking speed. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "033d1d3ef96666641ef8490c", name: "LIGHTNING CURRENT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You slam your hand onto the ground and release lightning from your body that surges outwards up to 30 feet in all directions from you. Creatures in this radius who are not behind total cover must make a Constitution saving throw, taking 4d6 lightning damage and gains 1 rank of shocked. On a successful save the creature only takes half damage. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature who fails their saving throw becomes unable to make handsigns until the end of their next turn, as electricity overwhelms their central nervous system.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e45dac8e8dece07a14989a62", name: "LIGHTNING FANG", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "100 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You extend both of your hands into the air, releasing a mass of Lightning chakra into the sky creating thunder clouds. As an action on your turn, you can select a space within range that you can see, Lightning Strikes the area. All creatures within 5 feet of the target space must make a Dexterity Saving throw taking 3d10 Lightning Damage on a failed save, or half as much on a successful one. A creature can only be affected by one lightning strike at a time. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature who fails their saving throw has their legs begins to seize up on them, reducing their walking speed to 5 feet, bringing it to a crawl, until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and select one additional target space. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "6b5f72c6297ff65b7b4e87d0", name: "LIGHTNING FLASH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: ["raiton"], casting_time: "Special", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM, W (Thrown)", duration: "Instant", description: "You coat a weapon with the thrown quality in lightning release chakra, increasing the lethality and piercing power of the weapon and throwing them in rapid succession. When you would make a ranged weapon attack with a thrown weapon you can enhance them with lightning release increasing their damage by 1d8 lightning Damage. Overcharge. When you cast this jutsu, as a bonus action or reaction, you can overcharge its effects. When you do the lightning damage you deal ignores Damage Reduction and Temporary Hit Points as your attacks penetrate even the strongest defense.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. LIGHTNING RELEASE: LIGHTNING KING’S", created_at: NOW, updated_at: NOW },
  { _id: "1c27815ac344587afeeebeac", name: "MANTLE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self (20-foot radius sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You radiate a powerful aura of lightning energy in an aura with a 20-foot radius centered on you, enhancing the combat potential in friendly creatures. The aura moves with you. While in the aura, all creatures of your choice, deal an additional 1d6 lightning damage with weapon attacks.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the radius by 10 feet. 124 LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "74980fe4facf7f563a4bfb22", name: "LIGHTNING LIGER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["raiton"], casting_time: "1 Action", range: "90 Feet", chakra_cost: "7 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You conjure your lightning release chakra to summon a Beast formed of Lightning, that fit your description. Make a Ranged Ninjutsu attack against a creature within range. On a success they take lightning damage equal to 4d8+ your Ninjutsu Ability Modifier. Additionally, the target must make a Constitution saving throw. On a failed save they gain 1 rank of shocked. If a target is already shocked, you make your attack roll at advantage and ignore cover as the lightning beast zig zags across the field to get the best vantage to attack. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, select a second creature to target with this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "fc1958dc0fd194b491aa7b9e", name: "LIGHTNING ROD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure your lightning release chakra creating a lightning release lance, staff or polearm of your description. This projected polearm has a reach of 10 feet, the trip, deadly and thrown (90/120) properties. For the duration of this jutsu you do not need to spend chakra to maintain concentration on this jutsu. While wielding this polearm you gain the following options using the corresponding actions; Action: Make a Melee Ninjutsu attack dealing 4d10 lightning damage on a hit. Action: Make a Ranged Ninjutsu attack, throwing the lance targeting a creature you can see, within throwing range, dealing lightning damage equal to 5d6 + Ninjutsu ability modifier. Regardless of a hit or miss, the lance then explodes, creatures within 20 feet of the target must make a Dexterity saving throw, taking 3d8 lightning damage on a failed save or half as much on a successful save. The Jutsu then ends. Bonus Action: You compress your polearm into its most basic form using it to supercharge the next jutsu you cast with the Lightning Release Keyword before the end of your turn. The next jutsu you cast with the Lightning Release Keyword that has a casting time of 1 Action has its cost reduced by half and deals additional damage equal to your Ninjutsu ability modifier. This jutsu then ends. Reaction: You spin your polearm in an attempt to deflect incoming attacks. Roll 1d6. You gain a bonus to your AC equal to the result and a bonus to your Strength and Dexterity saves equal to half of the result (Min 1.) until the beginning of your next turn. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a8b6263e1d0998febad375b5", name: "LIGHTNING ROPE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "60 feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure your lightning release chakra to manifest a rope made of lightning. Make a ranged ninjutsu attack against a single creature you can see within range. On a successful hit, the target becomes restrained for the duration and gains 1 rank of shocked. A creature Restrained by this jutsu takes lightning damage equal to your Ninjutsu Ability Modifier at the beginning of each of their turns. A creature restrained by this jutsu may make a Strength saving throw once on their turns as an action to end this jutsu’s effects on them on a success. While maintaining concentration on this jutsu you must hold the lightning rope with one hand within range. Letting it go immediately ends this jutsu. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, all creatures who fail the initial saving throw gain 1 additional rank of shocked.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target with this jutsu by +1. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "1b80e2735e18d58188d7b367", name: "LIGHTNING STEP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "90 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You teleport yourself to an unoccupied space you can see within range. Immediately after you disappear, a thunderous boom sounds, and each creature within 10 feet of the space you left and the space you appeared must make a Constitution saving throw, taking 3d10 Lightning damage on a failed save, or half as much damage on a successful one. Thunder can be heard up to 300 feet away. You can bring along object as long as their weight doesn’t exceed what you can carry. You can also teleport one willing creature of your size or smaller who is carrying gear up to it carrying capacity. The creature must be within 5 feet of you when you cast this jutsu, and there must be an unoccupied space within 5-feet of your destination space for the creature to appear in; otherwise, the creature is left behind. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature who fail their saving throw have their speed reduced by the amount of damage they took, rounded down to the nearest 5-foot increment until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10. 125 LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "312c5406f24960bb1d0943cf", name: "LIGHTNING UPPERCUT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "120 feet.", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure your lightning release chakra coating it around your hands or legs and using it as a guiding force when striking. Make a ranged ninjutsu attack. On a hit lighting explodes upwards from under the target dealing lightning damage equal to 4d8, and knocking them 20 feet into the air. They do not take falling damage unless they fall more than 20 feet in this circumstance. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, the next Ninjutsu you cast with the lightning release keyword before the end of your next turn, increases its damage dice by +2.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d8. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "b273cd1f3559aa13b7e0f034", name: "LIGHTNING WALL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: ["raiton"], casting_time: "1 Full Turn Action", range: "120 feet.", chakra_cost: "Special (50 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure your lightning release chakra until you create a wall of lightning that you can place on a solid surface or suspend midair. You can make the wall up to 90 feet long, 60 feet high and 5 feet thick, or a ringed wall up to 40 feet in diameter, 60 feet high, and 5 feet thick. This wall is opaque and lasts for the duration. When the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 8d8 lighting damage and becomes shocked or half as much damage and no further effects on a successful save. On both sides of the wall each creature that ends its turn within 10 feet of it takes 8d8 Lighting damage and must make a Constitution saving throw gaining 1 rank of shocked on a failed save. A creature takes the same damage and gains the same condition when it enters the wall for the first time or ends its turn there. The wall has a number of hit points equal to the collective total of all Casters Ninjutsu Save DC. Resistance to Earth Damage and Vulnerability to Wind Damage. Its casters can decide to allow Jutsu to pass through only one side of the wall if they choose. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 1d8. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's defensive abilities based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2-3: Increase the walls Hit points by 15. +4-5: Increase the walls Hit points by 45). LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f4b069637d2dbd2962f76313", name: "OVERDRIVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: ["raiton"], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 minute", description: "You send lightning chakra through your central nervous system speeding up your body's response time and perceptive abilities. Increase your Movement speed by 20. Gain advantage in Dexterity Saves and skill checks. When making a Perception check, you may add 1d4 to the result.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase movement speed by 10ft. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "737ddc8e2b02790b306980f0", name: "REDIRECT LIGHTNING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Reaction to taking Lightning damage from a ranged attack or saving throw.", range: "Special", chakra_cost: "Special", components: "HS, CM", duration: "Instant", description: "When you cast this jutsu, you spend chakra equal to the triggering jutsu’s cost. As you are targeted by lightning, you create s similar charge of lightning release chakra inside of you to redirect the attack. You gain Resistance to the Lightning Damage until the beginning of your next turn, and make a melee Ninjutsu attack vs. the target's attack roll or Save DC (depending on whether you were targeted by an attack or saving throw). If you succeed, you redirect their attack at another single target within range, dealing half the damage of the triggering creature's attack (or saving throw), but no other effect. 126 LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0b8faafd99f503744aee563a", name: "SPIDER WEB", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "60 Feet (15-Foot cube)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a Web like pattern on the ground out of Lightning chakra expanding outwards in a 15-foot cube at a space of your choice within range. Creatures who begin their turns or enters the webs space must make a Constitution saving throw. On a failed save affected creatures gain +1 rank of Shocked. A creature who has gained ranks of Shocked as a result of this jutsu, who begins their turn in this jutsu’s area of effect, becomes Incapacitated until the end of their turn. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to Overcharge its effects. When you do, a Shocked creature who begins their turn in the affected area takes 3d12 Lightning damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, increase the size of the cube by 5 feet and damage dealt while overcharged by 1d12. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "f5e3cc3c9106915cde7e8de2", name: "STATIC FALCON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "120 Feet (15 Feet Cube)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a mass of Lightning chakra and release it in the form of a bird. This bird then flies towards a target creature you can see within range, before it explodes, discharging electricity in a 15-foot cube with a loud thunderous boom. This thunderous boom can be heard up to 300 feet away. Creatures in the affected area must make a Constitution save, taking 6d6 Lightning damage and gains 1 rank of shocked on a failed save, and half as much on a successful save. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature shocked by this jutsu must make a Constitution (Chakra control) check at the start of each of their turns for the duration of the shocked condition, or be unable to move more than 5 feet on their turns.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "2f9804e30b09d57cc6a1f8a6", name: "STATIC WEAPON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "A Weapon you touch becomes enhanced with lightning release chakra. For the duration, the weapon has a +1 bonus to attack rolls and deals an extra damage die in lightning damage each time you deal this [Weapons Damage] to a hostile creature, any number of times per turn. You cannot lose concentration of this jutsu as a result of damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of weapons this can affect by +1. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "78c823568c2cb77f0d11595e", name: "SURGE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You punch the ground creating a single point of intense air pressure that explodes outwards blowing away all creatures and potentially all attacks. All creatures within range of your choice must make a Strength saving throw. On a failed save they are thrown back to the edge of this jutsu’s radius into a space that can hold them. Creatures who fail their Strength saving throw gains 3 ranks of bruised on a failed save. If this jutsu is used in reaction to a Ninjutsu or Taijutsu being cast, the shockwave of air pressure reduces the damage the jutsu would deal by 5d6 + 15. If the jutsu used does not deal damage the triggering creature must make a Constitution ability check vs your Ninjutsu save DC. On a success their jutsu is cast as normal. On a failure, their jutsu is also blown away as this jutsu negates it. If this jutsu is used to trigger a clash with a Jutsu with the Fire Release Keyword, you make your clash check at advantage as you are pushing all the wind away from you. If you succeed your clash check against a jutsu with the fire release keyword, they take an additional 4d8 wind Damage and must make a Constitution saving throw being burned on a failed save. WIND RELEASE: MULTILAYERED GALE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute. Components: HS, CM, M Cost: 12 Chakra Keywords: Wind Release, Ninjutsu, Construct Description: You wave your hands back and forth creating layers of wind that stack on top of one another creating a barrier of wind. Your Wall of wind is extremely dense not allowing most things to pass through it. When you create your barrier of wind it has 30 Hit points. It occupies your space with you and protects you in all direction, ranged attacks targeting you are made at disadvantage. At the start of each of your turns you can enhance this barrier regenerating 3d6 of the barriers hit points. This Barrier has a vulnerability to Fire damage, and Resistance to Lightning damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the initial hit points of the barrier by 10. WIND RELEASE: THUMB OF DESTRUCTION Classification: Ninjutsu Rank: B-Rank Casting Time: Full Turn Action Range: 120 Feet Duration: Instant Components: HS, CM, CS Cost: Special (77 Chakra) Keywords: Wind Release, Ninjutsu, Combination, Kinjutsu Description: You generate a super massive tornado that touches down on a space you can see within range. This Tornado is 120 feet tall and 30 feet wide. You can command it to touch down on top of a creature or space you can see within range. If you have it touch down on top of a creature, make a Ranged Ninjutsu attack, dealing 10d8 wind damage on a hit. All creatures, objects and structures, excluding casters of this jutsu, within 60 feet of the tornado must make a Strength saving throw being sucked into the eye of this storm. On a failed save they are thrown to the top of this tornado for but a moment before the tornado compresses and fires all creatures within the eye of its storm directly into the ground at sound breaking speeds. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the targeted damage by 2d8 for each additional caster. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size and damage based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the height of the tornado by 60 feet, +3: Increase the height of the tornado by 80 feet, +4: Increase the height of the tornado by 100 feet, +5: Increase the height of the tornado by 120 feet). WIND RELEASE: VACUUM BLADE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Bonus Action Range: Touch Duration: Concentration, up to 1 minute. Components: HS, CM, W (Any) Cost: 12 Chakra Keywords: Wind Release, Ninjutsu Description: You exhale wind release chakra onto a weapon to increase its sharpness, range and lethality. This can even be used on your unarmed strikes creating lethal blades of wind extending from those strikes. You cannot lose concentration of this jutsu as a result of damage. Enhanced weapon or unarmed strike’s deals an additional 3d6 wind damage twice per turn, its range is also increased by 10 feet. Ranged weapons also damage all adjacent spaces around its target on a successful hit. Additionally, you can use your Ninjutsu ability modifier in place of Strength or Dexterity when calculating to hit or damage with attacks enhanced by this jutsu. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If cast at S-Rank, increase the damage of this jutsu by +1d6. 78 WIND RELEASE: VACUUM GREAT SPHERE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: 120 Feet (15-foot radius Sphere) Duration: Concentration, 1 minute Components: HS, CM Cost: 13 Chakra Keywords: Wind Release, Ninjutsu Description: You generate 3 large Spheres of wind chakra. Choose 3 spaces in range. You send the large wind spheres to these areas and they expand outwards with the point you’ve chosen at the center, 30 feet in diameter. Creatures caught in these spheres or who enter them, movement speed is reduced to 0 and they cannot breathe while inside the sphere as the pressure prevents them from inhaling successfully. Creatures caught in the radius of any sphere can make a Strength saving throw or continue to have their movement speed reduced to 0. On a successful save, they regain half of their movement speed. A creature who begins or ends its turn within the radius of a sphere must make a Constitution saving throw. On a failure, they begin to suffocate, gaining 2 rank of exhaustion. On a success, they recover 2 rank of exhaustion caused by this jutsu, if any. Upon escaping or ending this jutsu’s effect on them, they recover from all ranks of exhaustion this jutsu imposed on them. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and select one additional space this jutsu affects. WIND RELEASE: WIND CUTTER Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: 120 Feet Duration: Instant Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: You create one Super sharp blade of wind and launch it at a target creature in range. Make a ranged ninjutsu attack. On a hit the target creature takes 5d10 Wind damage and gains 1 rank of lacerated. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 WIND RELEASE: WYVERNS SURGE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 14 Chakra Keywords: Wind Release, Ninjutsu, Fuinjutsu Description: You place a sealing tag on your body in any place you desire, as you place a massive reserve of Wind Release Chakra into the tag itself, activating it and magnifying your physical potential. You do not need to spend chakra to maintain concentration on this jutsu. For the duration, once per turn, when you would deal damage with a jutsu against a creature with a jutsu with a nature release keyword, they must make a Strength saving throw. On a failed save the following occurs; • Earth Release: Affected creature gains 1 rank of the bruised condition. • Wind Release: The jutsu deals an additional 3d8 wind damage and inflicts 2 ranks of bleed. • Fire Release: Affected creatures gains 1 rank of the Burned Condition. • Water Release: Affected creatures gains 1 rank of the Chilled Condition. • Lightning Release: Affected creatures gains 1 rank Shocked Condition for the next minute. A-RANK: WIND RELEASE: CAST NET Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self (60-Foot Cone) Duration: Instant Components: HS, CM Cost: 19 Chakra Keywords: Wind Release, Ninjutsu Description: A wave of slicing wind erupts from you as you swing your hand. Each creature in a 60-foot cone must make a Strength saving throw. A creature takes 7d8 wind damage and are thrown back 60 feet, fall prone, gain 1 rank of lacerated and causing Swirl on a failed save. Creatures take half as much damage and no further effects on a successful save. 79 WIND RELEASE: DEFIANCE STORM Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Full Turn Action Range: 90 Feet (30-foot-Radius Sphere) Duration: 1 minute Components: HS, CM, CS Cost: 20 Chakra Keywords: Wind Release, Ninjutsu, Fuinjutsu Description: You throw a Chakra seal onto the ground before you release the chakra sealed within in creating an aura of reinforcing Wind release chakra. Select up to 4 creatures to gain the benefits of this jutsu while inside this Jutsu's radius. For the duration select creatures within this jutsu’s radius makes Strength, Dexterity and Wisdom skill checks and Saving throws at advantage, Ninjutsu they cast of B-Rank or lower has their cost reduced by -2 (Min 1.), Taijutsu & Bukijutsu they cast deal additional wind damage equal to your Ninjutsu Ability modifier. The Chakra Seal used to cast this jutsu can be targeted for attacks, although it is protected by a bubble of Wind Release Chakra. It has an AC equal to your Ninjutsu Save DC, and Hit Points equal to twice your Ninjutsu Save DC. It has Immunity to Lightning Damage and Vulnerability to Fire Damage. Once Destroyed, this jutsu immediately ends. WIND RELEASE: DRILLING WIND BULLET Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 120 feet Duration: Instant Components: HS, CM Cost: 19 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You inhale a single breath and exhale creating a spinning drill made of slicing wind that tears through everything in its path. Make a Ranged Ninjutsu attack targeting 1 creature dealing 7d10 wind damage, inflicting 3 ranks of lacerated and pushing the target back 25 feet on a hit. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10. WIND RELEASE: EYE OF THE STORM Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Full Turn Action Range: Self (60-foot-Radius Sphere) Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 20 Chakra Keywords: Wind Release, Ninjutsu Description: You Create a powerful twisting cyclone of wind that seals yourself and all creatures in this jutsu’s Radius off from other creatures and effects from outside this jutsu’s radius. Creatures outside this jutsu’s radius cannot see into the opaque wall of twisting wind, dust, dirt and chakra. A creature with Chakra sight when looking at the wall only sees a wall of chakra and cannot make out anything passed it. If a creature attempts to pass through the wall, they must make a Strength saving throw. On a successful save they pass through the wall. On a failed save they take 8d8 wind damage and are thrown back 30 feet. Attacks and Jutsu cannot penetrate this jutsu’s walls. While inside this jutsu’s radius, creatures cannot generate electricity preventing them from casting Jutsu with only the Lightning Release Keyword. If the wall is struck with a Jutsu with the Water Release Keyword, the walls becomes wreathed in Water Release Chakra. If this jutsu’s walls become wreathed in Water Release chakra, creatures within this jutsu’s radius cannot generate fire, preventing them from casting jutsu with only the Fire Release Keyword. If the wall is struck with a Jutsu with the Fire Release Keyword, the walls becomes wreathed in Fire Release Chakra. If this jutsu’s walls become wreathed in Fire Release chakra, creatures within this jutsu’s radius cannot generate strong wind, preventing them from casting jutsu with only the Wind Release Keyword. WIND RELEASE: LIONS FANG BLADE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 120 feet Duration: Instant Components: HS, CM Cost: 19 Chakra Keywords: Wind Release, Ninjutsu Description: You mold wind Release Chakra to create a beast made purely of Wind Release Chakra, that has a design and look of your description that counts as large. Upon its creation, you command it to attack a number of creatures up to your Ninjutsu Ability Modifier once each. Make a Melee Ninjutsu attack for each creature it attacks within range as it leaps and assaults each creature. On a hit, you deal 2d8 Wind Damage. A creature that takes damage from the Beast must make a Constitution saving throw being torn apart from the thousands of blades made of Wind Release chakra that makes up your Beast. On a failed save they gain 2 ranks of Lacerated and cause Swirl. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and Lacerated ranks by 3. 80 WIND RELEASE: NEVER ENDING FALL Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self Duration: Concentration, 1 Minute Components: HS, CM, M Cost: 15 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vacuum of air under yourself with the ability to ascend, descend and move in any direction at your own discretion. You gain a fly speed of 60 feet. If you use your action to Dash, you instead move 180 feet in the round. WIND RELEASE: NEVERENDING BREATH Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self Duration: 10 Hours Components: HS, CM Cost: 15 Chakra Keywords: Wind Release, Ninjutsu Description: You inhale a single breath, and using chakra you are able to reinvigorate that single collection of air as if it were a new breath. You no longer need to breathe for up to 10 hours. You cannot be suffocated or drowned. WIND RELEASE: SPLITTING BREEZE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: HS, CM Cost: Special Keywords: Wind Release, Ninjutsu, Clash, Kinjutsu Description: You mold wind Release Chakra to create a blade of wind release chakra that is so compressed it fits into the palm of your hand. The amount of power this jutsu exhibits is entirely dependent on the amount of chakra you commit to it. Spend chakra up to the listed amounts. For every chakra cost milestone hit you deal the listed effect. A creature reduced to 0 as a result of this jutsu is bisected at any angle the caster decides. The saving throw this jutsu refers to below is a Constitution save. 20 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 20d4 Wind Damage. A creature must also make a saving throw gaining 2 ranks of laceration and causing Swirl on a failed save. 30 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 30d4 Wind Damage. A creature must also make saving throw, gaining 4 ranks of laceration and causing Swirl on a failed save. 40 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 40d4 Wind Damage. A creature must also make a saving throw, gaining 6 ranks of laceration and causing Swirl on a failed save. WIND RELEASE: VACUUM SERIAL WAVES Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 16 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You take a deep breath and exhale several super intense blades of wind at different angles but at multiple targets. Make a ranged Ninjutsu Attack against up to 3 targets dealing 8d6 Wind Damage and inflicting 1 rank of lacerated on a hit. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the ranks of laceration by +1. WIND RELEASE: VACUUM WALL Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 feet Duration: 1 Round Components: HS, CM, M Cost: 15 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vacuum of air around a willing creature in range that nullifies almost all attacks that would aspire to harm you. Until the beginning of your next turn. All Ninjutsu and Taijutsu, Melee and Ranged weapon attacks must roll 1d20 when they declare an attack targeting you. On a roll of 8 or greater, the attack is diverted or knocked away by the extremely dense wind. S-RANK: WIND RELEASE: 1 MILLION BLADE COLLISION Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 120 Feet Duration: Instant Components: HS, CM Cost: 25 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You focus a massive amount of wind chakra into a sphere above the target in range and bring it down crashing into the target as a single blade. The target must make a Dexterity saving throw, creatures take 34d6 wind damage, gain 5 ranks of lacerated and cause Swirl on a failed save, or half as much damage and ranks of bleed on a Successful save. 81 WIND RELEASE: BACKLASH WAVE Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Reaction, which you take when you see a Ninjutsu being cast. Range: 90 Feet Duration: Instant Components: HS, CM Cost: 28 Chakra Keywords: Wind Release, Ninjutsu Description: You see an attack as it comes towards you and you create an impenetrable forcefield of wind that’s designed to throw everything back. Make a Ranged Ninjutsu Attack vs the triggering creatures ninjutsu save DC. If your result is higher, the opponent suffers the damage and effects of their own jutsu. On a failure, the jutsu is diverted and immediately ends. WIND RELEASE: FANNED WIND Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 100 Foot Cone Duration: Instant Components: HS, CM Cost: 30 Chakra Keywords: Wind Release, Ninjutsu Description: A torrent of concussive wind erupts from your hands that explodes forward devastating everything in a 100-foot cone in front of you. This jutsu blows everything not tied down away and even upheaves trees and smaller structures and buildings. Creatures in its path must make a Strength saving throw being thrown back 120 feet on a failed save. If the creature hits a structure their movement ends and they take triple the falling damage as if they fell the same distance they traveled. WIND RELEASE: HURRICANE OF DISASTER Classification: Ninjutsu Rank: S-Rank Casting Time: Full Turn Action Range: Self (120-foot radius) Duration: Instant Components: HS, CM, CS Cost: Special (138 Chakra) Keywords: Wind Release, Ninjutsu, Combination, Kinjutsu Description: You generate a Category 6 Hurricane that touches down with the sole intent of bringing nothing but ruin in its wake. This Hurricane extends 250 feet into the air and has a 120-foot radius. This hurricane affects all creatures except its casters within its radius. At the end of each of your turns, it moves 90 feet in a random direction (Roll 1d8. 1: North, 2: North East, 3: East, 4: South East, 5: South, 6: South West, 7: West, 8: North West.). Creatures within this jutsu’s area of effect must make a Strength saving throw being ripped from their current position and thrown 250 feet into the air taking 12d8 wind Damage and being restrained by the wind on a failed save. A creature thrown into the air may repeat their Strength Saving throw to escape this wind at the end of each of their turns, taking 12d8 wind damage on a failed save and escaping, falling to the ground on a successful save. All structures and constructs in this jutsu’s path automatically fail their saves and are destroyed as they are pulled into the hurricane’s rotation. This Hurricane lasts for 1 Minute as once cast it cannot be stopped or dispelled by its casters willingly. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 4d8. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size and damage based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the radius of the hurricane by 30 feet, +3: Increase the radius of the hurricane by 60 feet, +4: Increase the radius of the hurricane by 90 feet, +5: Increase the radius of the hurricane by 120 feet). 82 WIND RELEASE: SPIRALING TEMPEST Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Bonus Action Range: Self (45-foot radius) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 20 Chakra Keywords: Wind Release, Ninjutsu Description: You release a surge of Wind Release Chakra that protects and enhances all of your allies for the duration. All creatures of your choice within range gain the following; • If a creature starts their turns in this jutsu’s radius, they gain a Bonus +30 Movement speed until the end of their next turns. • They gain a +3 bonus to Ninjutsu and Taijutsu Attack Rolls. • They gain a number of Temporary Hit points equal to your Ninjutsu Save DC at the beginning of each of their turns. • Taijutsu they cast that has a range of touch, or 5 feet, increases their range by 15 feet, and deals an additional 3d8 Wind Damage. • Affected Creatures cannot be Dazed or Weakened. • Affected creatures gain Resistance to Lightning Damage. WIND RELEASE: TORNADO EXPLOSION Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM, CS Cost: 30 Chakra Keywords: Wind Release, Ninjutsu Description: You create a spiraling cylinder of wind centered on yourself that has a 90 Foot radius and is 120 Feet High. This cylinder becomes difficult terrain for the duration, even for flying creatures. Unattended objects in this cylinder that are large or smaller are pulled upwards and spins around the center at 200 Mph. A creature that starts its turn in the cylinder must succeed a Strength save or cause Swirl and be pulled upwards towards the center and be restrained while in motion. All objects and creatures inside the cylinder, excluding yourself, take 8d10 Wind Damage at the start of each of your turns. Creatures can make a Strength save on each of its turns as an action to not be restrained on its turn. 83 FIRE RELEASE Fire Release is the most common of the five nature transformations in the leaf village and land of fire, but those who can use it are able to knead chakra and set fire to anything. Fire Release is almost always used offensively and has very few defensive applications. Some shinobi use it to damage massive areas and harm large groups of foes. Fire Release is commonly exhaled from the user's mouth. Although Fire Release has naturally amazing power, it suffers from high chakra cost and is difficult to control flames after use. Fire Release is naturally strong against Wind Release and weak against Water Release Prerequisite: You must have the Fire Release Affinity to learn jutsu with the Fire Release Keyword. D-RANK: FIRE RELEASE: ABSORB HEAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage. Range: Self Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You generate a vacuum of chakra absorbing the heat from the surrounding area and create a thin layer of fire chakra to protect yourself. You gain resistance to the triggering instance of damage. If the triggering damage or any further attacks that target you are melee attacks and the triggering creature was no more than 10 feet away when this jutsu was cast, the triggering creature takes 6 fire Damage until the beginning of your next turn. If the triggering damage was fire, you also gain +5 DR vs fire damage until the start of your next turn. If the triggering damage was cold, this jutsu fails to activate. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage dealt as a result of a melee attack by +4 and the range a creature can be to take the damage by 5 feet. FIRE RELEASE: ASH CLOUD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet (30 Foot Cloud) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You inhale and knead fire chakra in your lungs to create a cloud of ash. You exhale the ash into a target area within range that you can see. The Cloud of ash remains until blown away or dissipates which can take up to 10 minutes. Creatures inside the target area have disadvantage on attacks while inside the cloud, and are treated as if in total darkness. Creatures making ranged attacks inside the cloud cannot see creatures inside. FIRE RELEASE: BLAZING EMBER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You manifest motes of fire in the palms of each of your hands. Make two Ranged Ninjutsu attacks. These attacks can target one creature or two. If targeting multiple creatures make a single Ranged Ninjutsu attack against each. On a successful hit you deal 3d4+3 fire Damage. If a creature affected by the Burned condition is hit by both attacks, they immediately suffer the damage of their condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank increase the number of attacks you can make by +1. If this jutsu is cast at S-Rank increase the number of attacks you can make by +2. FIRE RELEASE: BLAZING HANDS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 action Range: self (20-foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You hold your hands out and fire a sheet of flame from your hands. Each creature in a 15-foot cone must make a Dexterity saving throw. A creature takes 5d4+5 fire damage on a failed save, or half as much damage on a successful one. This fire ignites any flammable objects in the area that aren’t being worn or carried. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d4+1. 84 FIRE RELEASE: BLUE FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you see a creature take damage in range. Range: 30 feet Duration: 1 Round Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Clash Description: You manifest a sapphire-colored flame around a willing creature you can see within range protecting them. You can see a gout of blue hot flame erupts around them creating a barrier of heat. Until the beginning of the creatures next turn, ranged attacks deal reduced damage equal to 2d4+2. Melee attacks deal reduced damage equal to 2d4+2 and deals 3d6+3 in fire damage to the attacking creature once per turn. If the attacking creature would deal Cold Damage, this jutsu is immediately extinguished, ending it before any damage reduction or damage could be dealt. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage reduction by 1d4+1 and damage done by 1d6+1. FIRE RELEASE: CRIMSON SPIDER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, Up to 1 minute. Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Construct Description: You spew out fire on a point within range. The fire then collects into a medium sized Crimson Spider. This Crimson Spider can be commanded as a bonus action on your turn. FIRE RELEASE: DEMONS LANTERN Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (5-Feet radius) Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 3 Chakra Keywords: Fire Release, Ninjutsu Description: You conjure multiple flames of chakra to surround you. These flames transform into faces of demons of your description. You shed bright light for 20 feet and dim light for another 10 feet. As a reaction, when a creature moves within 5 feet of you, you can force the target to make a Dexterity saving throw as these Demon lanterns attempt to strike the target. On a failed save, the target is set on fire and gains the Burned Condition. FIRE RELEASE: ERUPTING FLAME Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Fire Release, Ninjutsu Description: You Focus chakra into the target area and create a hot spot directly under a target creature you can see in range. The target must make a Dexterity saving throw or take 3d8+3 Fire Damage. The target gains no benefits from cover against this jutsu. A creature who fails their saving throw by 5 or more gains 2 ranks of the burned condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8+1. Medium Construct, unaligned Armor Class 10 + Your Ninjutsu Ability Modifier Hit Points 18 (4d8 + Your character level) Speed 40 ft. STR DEX CON INT WIS CHA 14 (+2) 16 (+3) 12 (+1) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Acid, Fire, Psychic, Bludgeoning, Slashing Condition Immunities Charmed, Exhaustion, frightened, stunned, petrified, poisoned Senses passive Perception 10 Damage Vulnerability. The Flaming spider takes double damage from cold damage. Elemental Body. The Flame Spiders weapon attacks are chakra enhanced. Multiattack. The Flame Spider can attack 2 times with its Bite. Bite. Melee Weapon Attack: + (Your ninjutsu attack bonus) to hit, reach 5 ft., one creature. Hit: 2d4 + 2 Fire damage. Flame Web (Recharge 9-10): Ranged Weapon Attack: +(Your ninjutsu attack bonus) to hit, reach 30/60 ft., one creature. The target is covered in solidified flaming webs and is restrained by them taking 2d6+2 fire damage. As an action the restrained target can make a Strength ability check, bursting from the webbing on a success. The webbing can also be attacked and destroyed (AC 10, Hp: 5; Vulnerability to cold damage.) 85 FIRE RELEASE: FIREBALL Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet (15 Foot radius Sphere) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Clash Description: You breathe a stream of fire onto the target area which then expands into a ball of fire burning all in its range. Target creatures in range makes a Dexterity saving throw, taking 4d6+4 Fire Damage on a failed save or half as much on a success save. Flammable objects caught in the radius ignites if it isn’t being held or carried. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1, and the radius by 5ft. FIRE RELEASE: FLAME BOLT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You breathe a bolt of flame at a creature or object within range. Make a ranged ninjutsu attack against the target. On a hit, the target takes fire damage equal to 3d10+3. A flammable object hit by this jutsu ignites if it isn’t being worn or carried. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10+1. FIRE RELEASE: FLAME COAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus action Range: Touch Duration: Concentration, up to 10 minutes Components: HS, CM, W(Any) Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You engulf a weapon in fire chakra, coating it in a flame that enhances the lethality of the weapon. If you let go of the weapon or it is taken from you, the fire disperses. You cannot lose concentration of this jutsu as a result of damage. While you maintain concentration on this jutsu, you can engulf another weapon you are holding as a bonus action. A weapon enflamed by you, deals an additional 1d8+1 fire damage twice per turn. The fire sheds bright light in a 20- foot radius and dim light for an additional 10 feet. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the damage to 2d8+2. If this jutsu is cast at S-Rank, increase the damage to 3d8+3. FIRE RELEASE: FLAME STRIKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: A vertical column of flame erupts upwards from the ground towards the sky in a location you specify. Each creature in a 10-foot radius, 20-foot-high cylinder centered on a point within range must make a Dexterity saving throw taking 3d6+3 fire damage and gaining 1 rank of the burned condition on a failed save, or half as much damage on a successful one. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1. FIRE RELEASE: FLAME WHIP Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: self (20-feet) Duration: Instant Components: HS, CM Cost: 4 chakra Keywords: Fire Release, Ninjutsu Description: You conjure a flaming whip to strike at a creature you can see up to 20-feet away from you. Make a melee ninjutsu attack, dealing 2d10+2 fire damage. The target must make a Dexterity saving throw, being pulled 10 feet towards you. If a creature who failed the saving throw ends their movement within 5 feet of you, they fall prone and gain the burned condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10+1. FIRE RELEASE: FOX FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 hour Components: HS, CM Cost: 3 chakra Keywords: Fire Release, Ninjutsu Description: A flickering flame appears in your hand. The flame remains there for the duration and harms neither you or your equipment. The flame sheds bright light in a 20-foot radius and dim light for an additional 10 feet. The jutsu ends if you dismiss it. You can also attack with the flame. As an Action you can make a Ranged Ninjutsu attack on a creature you can see within 30 feet of you. On a hit, the target begins to glow with a soft, warm, and glowing radiance. While glowing in this way, this jutsu’s duration becomes Concentration, until the end of your next turn, and creatures have advantage on melee attacks targeting the creature. 86 FIRE RELEASE: GREEN FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action. Range: 90 feet Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You manifest an emerald-colored flame and mark a creature you can", created_at: NOW, updated_at: NOW },
  { _id: "4ab47544699c4a7ce0656c6e", name: "THUNDER BOMB", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self (30-foot radius Sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You collect a surge of Lightning Release Chakra into your fingertips as you pinpoint all creatures within your Jutsu’s radius that are shocked. All Shocked creatures within range can feel the Lightning chakra on them begin to react before it violently explodes creating audible sounds over 1000 feet away. Creatures with more than one rank of the Shocked Condition suffer greater impacts. Shocked creatures within range must make a Constitution saving throw taking lightning damage equal to the following based on the ranks of shocked they have or half as much on a successful save. (1 Stack: 3d8, 2 Stacks: 4d8, 3 Stacks: 5d8, 4 Stacks: 6d8, 5 Stacks: 7d8) Creatures within 10 feet of a shocked creature when this explosion happens makes a Dexterity saving throw taking half the damage on a failed save or no damage on a successful save. If a creature is shocked and within 10 feet of another shocked creature when this explosion occurs, they make their save at Disadvantage. A creature can be affected by no more than 2 explosions. The shocked condition ends on all creatures within range regardless of passing or failing. B-RANK: LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "11fb593433d3a8617ecd4cf5", name: "BANQUET OF THUNDER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "60 feet", chakra_cost: "12 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You discharge 3 jolts of lightning that tears through the ground shooting in a straight line 10 feet wide and 60 feet long. The ground the lightning travels through becomes difficult terrain. Creatures in the path of this lightning must make a Dexterity saving throw, taking 6d6 lightning damage and gaining 1 rank of shocked and weakened on a failed save or half as much damage on a successful one. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do this jutsu’s range shifts becoming a 60ft cone. Once you use this overcharge effect, you cannot do so again until you spend at least 1 Chakra die to recharge it as a Bonus action on your turn or by completing a rest of any type.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "d4c16ac105f93597ea8276c1", name: "BEAST LIGHTNING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You focus your lightning chakra, forming it into the shape of a land animal of your choice such as a Bear, a Panther, or Wolf. The Lightning Beast of your creation can, as a bonus action, be directed. Medium Construct, unaligned Armor Class 11+ Your Ninjutsu Ability Modifier Hit Points 30 (5d12 + Your character level) Speed 45 ft. STR DEX CON INT WIS CHA 12 (+2) 22 (+6) 10 (+0) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Acid, Lightning, Earth, Psychic Condition Immunities Charmed, Exhaustion, frightened, stunned, petrified, poisoned Senses passive Perception 10 Damage Vulnerability. The Lightning Beast takes double damage from Wind damage. Elemental Body. The Lightning Beast weapon attacks are chakra enhanced. Kill Switch. When your beast reaches 0 hit Points it explodes shooting lightning in all directions. All Creatures within 10 Feet of it must make a Dexterity saving throw, taking 4d10 Lightning Damage and being shocked on a failed save and half as much and no additional effects on a successful one Bite. Melee Weapon Attack: + (Your ninjutsu attack bonus) to hit, reach 5 ft., one creature. Hit: 5d8 Lightning damage. 128 LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b13b08718936816a802adfa8", name: "CHAINED LIGHTNING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "150 Feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You create a bolt of lightning that arcs towards a target of your choice that you can see within range. Three bolts then leap from the first target to as many as three other targets, each of which must be within 30 feet of the first target. A target can be a creature or an object that be targeted by only one of the bolts. A target must make a Dexterity saving throw, taking 6d10 lightning damage on a failed save, or half as much on a successful one. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature gains one rank of the shocked condition for each creature who previously failed their saving throws.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and one additional bolt leaps from the first target to another target. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "1841867c4948dc2e7b17cdf4", name: "FALSE DARKNESS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "30-foot cone", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You release a massive wave of lightning capable of disintegrating stone and creatures alike. Creatures in a 30- foot cone originating from you must make a Constitution saving throw taking 10d4 lightning damage, are blinded for 1 minute, on a failed save or half as much on a success. Creatures blinded by this jutsu remake their saves at the beginning of each of their turns. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, on a failed save, affected creatures are also deafened and gain 2 ranks of concussed for the same duration they are blinded.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d4 and the size of the cone by 5 feet. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "7d9db6a46d844b74c495c362", name: "LIGHTNING BIND", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["raiton"], casting_time: "1 Minute", range: "1 Mile", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 Hour", description: "You set up 3 Chakra seals within 15 feet of one another in a triangle formation and fill them with Lightning Release chakra. You decide on a triggering action such as a creature entering the triangle, saying a specific word, or even making a certain hand Seal and the 3 tags will create a 3-point barrier made of Lightning Release Chakra. Trapping whomever is in the barrier inside. The Barrier has 60 (10d12) Hit Points and a 13 AC. Creatures inside the Barrier cannot mold chakra and if a creature attempts to exit the interior of the barrier by force, they must make a DC 16 Constitution save, taking 5d8 Lightning Damage on a failed save or half as much on a successful one. Creatures interacting with the Outside of the barrier do not suffer adverse effects although they cannot pass through the barrier without attempting to break it. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3c3f2339facb34f1b14bf59e", name: "LIGHTNING LILY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "90 feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest your Lightning release until you create a floating flower made of Lightning. This flower sparkles and sparks harmlessly for but a moment before it detonates. Select a space you can within range for the flower to manifest. All creatures within 30 feet of the flower must make a Dexterity and Wisdom Saving throw. On a failed Dexterity saving throw they take 5d8 Lightning damage and gain 2 ranks of the shocked condition. On a successful Dexterity save they gain 1 rank of the shocked condition until the beginning of their next turn. On a failed Wisdom Saving throw they are blinded by the flash of white light until the end of their next turn. On a successful Wisdom save no further effects. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, the affected creatures only make either a Dexterity or Wisdom save to determine this jutsu’s effects, not both. Pick one when you overcharge this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "cdbc9ef795eccf26a57fca72", name: "LIGHTNING SPEAR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You create a concentrated globe of lightning around your hand, and point it in a direction of your choice. A beam of lightning shoots at blinding speeds in a straight-line piercing through everything in its path. Creatures up to 60 feet away, in a straight line from you must make a Dexterity saving throw, taking 10d6 Lightning Damage on a failed save and half as much on a successful save. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do a creature that fails their saving throw becomes incapacitated until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6. 129 LIGHTNING RELEASE: LIGHTNING", created_at: NOW, updated_at: NOW },
  { _id: "23b2641f80541f6467f94c18", name: "TRANSMISSION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Bonus Action", range: "120 feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest your Lightning release until its covering your body. Select one currently shocked creature within 120 feet. You immediately teleport to them. Until the end of this turn, you have advantage on the first Melee Attack made targeting the creature you teleport to. If the target creature dies before the end of your turn after teleporting to them you may teleport to another creature within 60 feet who also has the shocked condition. If you do, you gain advantage on the next melee attack made targeting this creature before the end of your next turn. You can only teleport using this jutsu up to twice per turn. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f44e05b967d761d72a91f72", name: "PENANCE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure your lightning release chakra to amplify and bring out, the last spark of willpower from within a fallen creature. A Creature you touch who has been dead no longer than 1 minute has their essence touched. Make a Ninshou Check vs DC (15 + 1 for every round the target has been dead.) On a success, they awake, gaining 1 Hit points and a number of temporary hit points equal to 6d10. These temporary hit points last for 1 minute. When the creature runs out of temporary hit points granted by this jutsu, they fall unconscious for 24 hours, unable to awaken by any means. A creature can be revived by this jutsu no more than once per full rest. So long as a creature have temporary hit points as a result of this jutsu, they gain a bonus to their Strength, Dexterity and Constitution saving throws equal to your Ninjutsu Ability Modifier, their Strength, Dexterity, and Intelligence ability scores are increased to 20, and any damage they deal is instead Lightning Damage that cannot be resisted. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8f7045e8a07f8a14ded5005a", name: "RAGING STORM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "60 feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You manifest your Lightning release until its covering the body of an allied creature that is not yourself. Select one willing creature you can see within range. The target creature is engulfed in a raging torrent of lightning. For this duration, Jutsu the creature casts deals additional lightning damage equal to 3d8, once per turn. They gain Resistance to Earth Damage a +20 bonus to their speed, and advantage on Dexterity saving throws. Additionally, Concentration checks they make are made at advantage as you assist in managing their chakra flow.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of targets this jutsu can affect by +1. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "e8bcd468d3f7f4f69ae14422", name: "STRIKE ARMOR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You surround yourself, in dense lightning chakra in the form of armor. This armor enhances your speed, and protects you from damage, while also enhancing your melee strikes. You cannot lose concentration on this jutsu as a result of damage. Increase your movement speed by +20 Feet, AC by +2, and a +2 bonus to the first melee attack you make on each of your turns. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "35aebcd44abca638b854f021", name: "TENACIOUS JOLTS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "90 feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You conjure your lightning release chakra forming a jolt of lightning that you use to strike a creature within range. Make a ranged ninjutsu attack. On a hit you deal 5d10 Lightning damage. The target must make a Constitution saving throw. On a failed save the affected creature becomes shocked and dazed. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, then all creatures within 10 feet of the target of your choice must make the same saving throw, taking 5d8 lighting damage on a failed save or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. 130 LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "57a7679739268ab2f307d3df", name: "THUNDERSTORM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "250 feet cloud", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "A churning cloud of lightning forms centered on a point you can see and spreads out in a 250- foot cloud and Lightning begins to flash in the area. Creatures of your choice under this cloud must make a Dexterity saving throw at the end of each of its turns taking 4d6 Lightning Damage and being shocked on a failed save or half as much damage on a successful one. A-RANK: LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "08e8369735888aa366026d74", name: "BANG", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You focus Lightning chakra into a super compressed point on the tip of your finger, pointing it at a creature you can see in range, and releasing it in a single swift motion. The lightning explodes leaving your finger with an audible explosive boom, that shatters glass and other fragile but rigid material in a 500-foot radius. Make a ranged ninjutsu attack. On a hit, the target creature takes 24d4 Lightning Damage. If the target of this jutsu has 5 or more ranks of shocked, this jutsu instead deals 24d6 lightning damage. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, while targeting a creature within 10 feet of you, increase your critical threat range by +2.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d4 or 2d6 respectively. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "6598757de1cdd0b1648bde09", name: "CRACKLE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "16 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manifest your Lightning release until it’s a storm your holding in your hands. You supercharge a willing creature you touch tripling their heart rate, blood flow, nerve reactions and cognitive functions. When cast the target regains 20 Hit points and gains 8d12 Temporary Hit points for 1 minute. While concentrating on this jutsu, the target creatures movement speed is increased by 25 feet, they gain an additional Reaction, Advantage on Dexterity, Wisdom & Intelligence ability checks, skill checks and Saving throws, and the first melee attack they make each turn, is at advantage. At the end of this jutsu’s duration the target creatures body reels from the shock of being overworked becoming Stunned for 1d4 of their turns. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "aa1dea20138065881d6cb211", name: "KEEN STORM", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["raiton"], casting_time: "1 Action", range: "Touch", chakra_cost: "Special (20 Chakra)", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You manifest your Lightning release until you can condense the sparks onto a weapon you are touching. A weapon you touch, becomes guided by your masterful lightning control. For the duration, you can make melee Ninjutsu attacks in place of weapon attacks made with this weapon. Melee Ninjutsu attacks made as a result of this jutsu deals 2d12 lightning damage and scores a critical hit on a roll of 18-20. If you score a critical hit on a creature with ranks of shocked, you trigger the conditions damage. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "40fb74032f1bf1af82bba08d", name: "KINGMAKER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["raiton"], casting_time: "1 Action", range: "Self (120-foot Radius)", chakra_cost: "Special (110 Chakra)", components: "HS, CM, CS", duration: "10 Minutes", description: "You manifest your Lightning release until you create a Chakra seal made of pure lightning. You mark yourself and each willing creature of your choice within range with this seal. For the duration creatures with this seal gain the following; • Immunity to Earth Damage • Vulnerability to Wind Damage • All damage they deal is Lightning damage that cannot be Resisted. • A +2 Bonus to Strength, Dexterity, Wisdom and Intelligence Saving throws. • Once each turn when they deal lighting damage, affected creatures succeed a Constitution Saving Throw or gain 1 rank of Shocked. • Once each turn, when they deal lightning damage, they deal an additional 2d6 Lightning damage. • At the beginning of each of their turns, they gain 10 temporary hit points. This jutsu cannot be ended early, and at the end of this jutsu’s duration an affected creature cannot cast jutsu with the Lightning Release Keyword, their speed is reduced by 10, they cannot gain advantage on checks or saving throws, and they cannot maintain concentration on jutsu until they complete a long rest. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters reduce the cost by -2. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's offensive abilities based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2-3: Increase the number of times the additional damage and saving throw for Shocked can trigger to twice per turn. +4-5: Increase the number of 131 times the additional damage and saving throw for Shocked can trigger to three times per turn). LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "96c5a713d11f3aacc96bd505", name: "LIGHTNING CLONE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "dc2837c0a3446d09da7edaf6", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "Self", chakra_cost: "Special (16 Chakra)", components: "HS, CM", duration: "1 Minute", description: "A modified version of the Shadow Clone Technique that allows the user to create a clone made of solid lightning. Lightning Clones have no measurable weight and explode if exposed to a body of water. You can only create up to 2 Lightning Clones each costing 16 Chakra to conjure. Lightning Clones must remain within 120 feet of the caster. If the cast ends its turn more than 120 feet away from a Lightning Clone it explodes. Lightning Clones can cast up to 2, B-Rank or lower Ninjutsu with the lightning release keyword that you know, following normal Clone keyword restrictions. Lightning Clones have Immunity to Genjutsu, Psychic & Poison damage, Resistance to Bludgeoning, Earth and Lightning Damage but Vulnerability to Wind Damage. It has a movement speed equal to your movement speed. Creatures who have chakra sight can tell the clone is made of lightning and can distinguish the clone from the original. When Lightning Clones have 0 hit points, have used 2 ninjutsu with the lightning release keyword, been exposed to a body of water, its Summoner has ended its turn more than 120 feet away, or been dismissed as a bonus action, it surges for a brief moment before exploding. Creatures within 20 feet of the clone when it explodes must make a Constitution saving throw taking 10d6 lightning damage and being stunned until the end of their next turn on a failed save or half as much damage on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 2d6. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "6a58a8b6de40373127913574", name: "LIGHTNING DRAGON", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "90 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "Your chakra twists and forms into a long dragon made of pure lightning, This dragon flies in a straight line of your choice. This creature occupies a space 10 feet wide and extends up to 90 feet. Creatures in the path of this dragon must make a Dexterity saving throw, taking 8d10 lightning Damage or half as much on a failed save. A creature who fails their Dexterity Saving Throw against this jutsu must also make a Constitution Saving throw, becoming Blind and Deaf on a failed save until the end of their next turn. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, this jutsu gains the Construct keyword, and the dragon remains on the field as a huge construct made of lightning, with an AC equal to your ninjutsu save DC and hit points equal to 5 x your ninjutsu ability score. It has vulnerability to wind damage, Immunity to Earth Damage, and if it would take Lightning Damage, it instead restores its hit points by the amount of damage it would take. As an action on each of your turns, you can command it to perform the effect of this jutsu again in any line extending from its current space. Otherwise, it does nothing. You must concentrate on this jutsu to maintain this construct's form.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10. LIGHTNING RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "81d562a91e0b46fa226b2c89", name: "LIGHTNING RAT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "60 Feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "Your chakra twists and forms into countless globes of lightning that hover just in front of you before you send them flying at a creature you can see in range and harm the surrounding creatures around that creature. Make a ranged ninjutsu attack dealing 10d8 lightning damage. All creatures in a 60-foot, 15 feet wide line between you and the target creature must make a Dexterity saving throw taking 10d4 lightning damage on a failed save and half as much on a success. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, all creatures who fail their saving throw gain 2 ranks of the shocked condition. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "94f3bfd1b7f7cfc447c5e2b8", name: "LIGHTNING SHIELD", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Reaction, to being damaged.", range: "Self", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "A powerful barrier of Lightning forms and protects you. Until the start of your next turn, you have a +5 AC, immunity to Lightning & Earth damage and once per turn, Creatures targeting you with an attack while within 30 feet, must make a Constitution saving throw, gaining +2 ranks of shocked on a failed save or +1 rank on a success. 132 LIGHTNING RELEASE: POWERFUL BULLET", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "442ad4a07ffe36c2705123d7", name: "POWERFUL BULLET BREATH", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You inhale a single breath, and using chakra you are able to reinvigorate that single collection of air as if it were a new breath. You no longer need to breathe for up to 10 hours. You cannot be suffocated or drowned. WIND RELEASE: SPLITTING BREEZE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: HS, CM Cost: Special Keywords: Wind Release, Ninjutsu, Clash, Kinjutsu Description: You mold wind Release Chakra to create a blade of wind release chakra that is so compressed it fits into the palm of your hand. The amount of power this jutsu exhibits is entirely dependent on the amount of chakra you commit to it. Spend chakra up to the listed amounts. For every chakra cost milestone hit you deal the listed effect. A creature reduced to 0 as a result of this jutsu is bisected at any angle the caster decides. The saving throw this jutsu refers to below is a Constitution save. 20 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 20d4 Wind Damage. A creature must also make a saving throw gaining 2 ranks of laceration and causing Swirl on a failed save. 30 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 30d4 Wind Damage. A creature must also make saving throw, gaining 4 ranks of laceration and causing Swirl on a failed save. 40 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 40d4 Wind Damage. A creature must also make a saving throw, gaining 6 ranks of laceration and causing Swirl on a failed save. WIND RELEASE: VACUUM SERIAL WAVES Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 16 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You take a deep breath and exhale several super intense blades of wind at different angles but at multiple targets. Make a ranged Ninjutsu Attack against up to 3 targets dealing 8d6 Wind Damage and inflicting 1 rank of lacerated on a hit.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the ranks of laceration by +1. WIND RELEASE: VACUUM WALL Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 feet Duration: 1 Round Components: HS, CM, M Cost: 15 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vacuum of air around a willing creature in range that nullifies almost all attacks that would aspire to harm you. Until the beginning of your next turn. All Ninjutsu and Taijutsu, Melee and Ranged weapon attacks must roll 1d20 when they declare an attack targeting you. On a roll of 8 or greater, the attack is diverted or knocked away by the extremely dense wind. S-RANK: WIND RELEASE: 1 MILLION BLADE COLLISION Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 120 Feet Duration: Instant Components: HS, CM Cost: 25 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You focus a massive amount of wind chakra into a sphere above the target in range and bring it down crashing into the target as a single blade. The target must make a Dexterity saving throw, creatures take 34d6 wind damage, gain 5 ranks of lacerated and cause Swirl on a failed save, or half as much damage and ranks of bleed on a Successful save. 81 WIND RELEASE: BACKLASH WAVE Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Reaction, which you take when you see a Ninjutsu being cast. Range: 90 Feet Duration: Instant Components: HS, CM Cost: 28 Chakra Keywords: Wind Release, Ninjutsu Description: You see an attack as it comes towards you and you create an impenetrable forcefield of wind that’s designed to throw everything back. Make a Ranged Ninjutsu Attack vs the triggering creatures ninjutsu save DC. If your result is higher, the opponent suffers the damage and effects of their own jutsu. On a failure, the jutsu is diverted and immediately ends. WIND RELEASE: FANNED WIND Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 100 Foot Cone Duration: Instant Components: HS, CM Cost: 30 Chakra Keywords: Wind Release, Ninjutsu Description: A torrent of concussive wind erupts from your hands that explodes forward devastating everything in a 100-foot cone in front of you. This jutsu blows everything not tied down away and even upheaves trees and smaller structures and buildings. Creatures in its path must make a Strength saving throw being thrown back 120 feet on a failed save. If the creature hits a structure their movement ends and they take triple the falling damage as if they fell the same distance they traveled. WIND RELEASE: HURRICANE OF DISASTER Classification: Ninjutsu Rank: S-Rank Casting Time: Full Turn Action Range: Self (120-foot radius) Duration: Instant Components: HS, CM, CS Cost: Special (138 Chakra) Keywords: Wind Release, Ninjutsu, Combination, Kinjutsu Description: You generate a Category 6 Hurricane that touches down with the sole intent of bringing nothing but ruin in its wake. This Hurricane extends 250 feet into the air and has a 120-foot radius. This hurricane affects all creatures except its casters within its radius. At the end of each of your turns, it moves 90 feet in a random direction (Roll 1d8. 1: North, 2: North East, 3: East, 4: South East, 5: South, 6: South West, 7: West, 8: North West.). Creatures within this jutsu’s area of effect must make a Strength saving throw being ripped from their current position and thrown 250 feet into the air taking 12d8 wind Damage and being restrained by the wind on a failed save. A creature thrown into the air may repeat their Strength Saving throw to escape this wind at the end of each of their turns, taking 12d8 wind damage on a failed save and escaping, falling to the ground on a successful save. All structures and constructs in this jutsu’s path automatically fail their saves and are destroyed as they are pulled into the hurricane’s rotation. This Hurricane lasts for 1 Minute as once cast it cannot be stopped or dispelled by its casters willingly. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 4d8. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size and damage based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the radius of the hurricane by 30 feet, +3: Increase the radius of the hurricane by 60 feet, +4: Increase the radius of the hurricane by 90 feet, +5: Increase the radius of the hurricane by 120 feet). 82 WIND RELEASE: SPIRALING TEMPEST Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Bonus Action Range: Self (45-foot radius) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 20 Chakra Keywords: Wind Release, Ninjutsu Description: You release a surge of Wind Release Chakra that protects and enhances all of your allies for the duration. All creatures of your choice within range gain the following; • If a creature starts their turns in this jutsu’s radius, they gain a Bonus +30 Movement speed until the end of their next turns. • They gain a +3 bonus to Ninjutsu and Taijutsu Attack Rolls. • They gain a number of Temporary Hit points equal to your Ninjutsu Save DC at the beginning of each of their turns. • Taijutsu they cast that has a range of touch, or 5 feet, increases their range by 15 feet, and deals an additional 3d8 Wind Damage. • Affected Creatures cannot be Dazed or Weakened. • Affected creatures gain Resistance to Lightning Damage. WIND RELEASE: TORNADO EXPLOSION Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM, CS Cost: 30 Chakra Keywords: Wind Release, Ninjutsu Description: You create a spiraling cylinder of wind centered on yourself that has a 90 Foot radius and is 120 Feet High. This cylinder becomes difficult terrain for the duration, even for flying creatures. Unattended objects in this cylinder that are large or smaller are pulled upwards and spins around the center at 200 Mph. A creature that starts its turn in the cylinder must succeed a Strength save or cause Swirl and be pulled upwards towards the center and be restrained while in motion. All objects and creatures inside the cylinder, excluding yourself, take 8d10 Wind Damage at the start of each of your turns. Creatures can make a Strength save on each of its turns as an action to not be restrained on its turn. 83 FIRE RELEASE Fire Release is the most common of the five nature transformations in the leaf village and land of fire, but those who can use it are able to knead chakra and set fire to anything. Fire Release is almost always used offensively and has very few defensive applications. Some shinobi use it to damage massive areas and harm large groups of foes. Fire Release is commonly exhaled from the user's mouth. Although Fire Release has naturally amazing power, it suffers from high chakra cost and is difficult to control flames after use. Fire Release is naturally strong against Wind Release and weak against Water Release Prerequisite: You must have the Fire Release Affinity to learn jutsu with the Fire Release Keyword. D-RANK: FIRE RELEASE: ABSORB HEAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage. Range: Self Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You generate a vacuum of chakra absorbing the heat from the surrounding area and create a thin layer of fire chakra to protect yourself. You gain resistance to the triggering instance of damage. If the triggering damage or any further attacks that target you are melee attacks and the triggering creature was no more than 10 feet away when this jutsu was cast, the triggering creature takes 6 fire Damage until the beginning of your next turn. If the triggering damage was fire, you also gain +5 DR vs fire damage until the start of your next turn. If the triggering damage was cold, this jutsu fails to activate. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage dealt as a result of a melee attack by +4 and the range a creature can be to take the damage by 5 feet. FIRE RELEASE: ASH CLOUD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet (30 Foot Cloud) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You inhale and knead fire chakra in your lungs to create a cloud of ash. You exhale the ash into a target area within range that you can see. The Cloud of ash remains until blown away or dissipates which can take up to 10 minutes. Creatures inside the target area have disadvantage on attacks while inside the cloud, and are treated as if in total darkness. Creatures making ranged attacks inside the cloud cannot see creatures inside. FIRE RELEASE: BLAZING EMBER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You manifest motes of fire in the palms of each of your hands. Make two Ranged Ninjutsu attacks. These attacks can target one creature or two. If targeting multiple creatures make a single Ranged Ninjutsu attack against each. On a successful hit you deal 3d4+3 fire Damage. If a creature affected by the Burned condition is hit by both attacks, they immediately suffer the damage of their condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank increase the number of attacks you can make by +1. If this jutsu is cast at S-Rank increase the number of attacks you can make by +2. FIRE RELEASE: BLAZING HANDS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 action Range: self (20-foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You hold your hands out and fire a sheet of flame from your hands. Each creature in a 15-foot cone must make a Dexterity saving throw. A creature takes 5d4+5 fire damage on a failed save, or half as much damage on a successful one. This fire ignites any flammable objects in the area that aren’t being worn or carried. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d4+1. 84 FIRE RELEASE: BLUE FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you see a creature take damage in range. Range: 30 feet Duration: 1 Round Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Clash Description: You manifest a sapphire-colored flame around a willing creature you can see within range protecting them. You can see a gout of blue hot flame erupts around them creating a barrier of heat. Until the beginning of the creatures next turn, ranged attacks deal reduced damage equal to 2d4+2. Melee attacks deal reduced damage equal to 2d4+2 and deals 3d6+3 in fire damage to the attacking creature once per turn. If the attacking creature would deal Cold Damage, this jutsu is immediately extinguished, ending it before any damage reduction or damage could be dealt. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage reduction by 1d4+1 and damage done by 1d6+1. FIRE RELEASE: CRIMSON SPIDER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, Up to 1 minute. Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Construct Description: You spew out fire on a point within range. The fire then collects into a medium sized Crimson Spider. This Crimson Spider can be commanded as a bonus action on your turn. FIRE RELEASE: DEMONS LANTERN Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (5-Feet radius) Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 3 Chakra Keywords: Fire Release, Ninjutsu Description: You conjure multiple flames of chakra to surround you. These flames transform into faces of demons of your description. You shed bright light for 20 feet and dim light for another 10 feet. As a reaction, when a creature moves within 5 feet of you, you can force the target to make a Dexterity saving throw as these Demon lanterns attempt to strike the target. On a failed save, the target is set on fire and gains the Burned Condition. FIRE RELEASE: ERUPTING FLAME Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Fire Release, Ninjutsu Description: You Focus chakra into the target area and create a hot spot directly under a target creature you can see in range. The target must make a Dexterity saving throw or take 3d8+3 Fire Damage. The target gains no benefits from cover against this jutsu. A creature who fails their saving throw by 5 or more gains 2 ranks of the burned condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8+1. Medium Construct, unaligned Armor Class 10 + Your Ninjutsu Ability Modifier Hit Points 18 (4d8 + Your character level) Speed 40 ft. STR DEX CON INT WIS CHA 14 (+2) 16 (+3) 12 (+1) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Acid, Fire, Psychic, Bludgeoning, Slashing Condition Immunities Charmed, Exhaustion, frightened, stunned, petrified, poisoned Senses passive Perception 10 Damage Vulnerability. The Flaming spider takes double damage from cold damage. Elemental Body. The Flame Spiders weapon attacks are chakra enhanced. Multiattack. The Flame Spider can attack 2 times with its Bite. Bite. Melee Weapon Attack: + (Your ninjutsu attack bonus) to hit, reach 5 ft., one creature. Hit: 2d4 + 2 Fire damage. Flame Web (Recharge 9-10): Ranged Weapon Attack: +(Your ninjutsu attack bonus) to hit, reach 30/60 ft., one creature. The target is covered in solidified flaming webs and is restrained by them taking 2d6+2 fire damage. As an action the restrained target can make a Strength ability check, bursting from the webbing on a success. The webbing can also be attacked and destroyed (AC 10, Hp: 5; Vulnerability to cold damage.) 85 FIRE RELEASE: FIREBALL Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet (15 Foot radius Sphere) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Clash Description: You breathe a stream of fire onto the target area which then expands into a ball of fire burning all in its range. Target creatures in range makes a Dexterity saving throw, taking 4d6+4 Fire Damage on a failed save or half as much on a success save. Flammable objects caught in the radius ignites if it isn’t being held or carried. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1, and the radius by 5ft. FIRE RELEASE: FLAME BOLT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You breathe a bolt of flame at a creature or object within range. Make a ranged ninjutsu attack against the target. On a hit, the target takes fire damage equal to 3d10+3. A flammable object hit by this jutsu ignites if it isn’t being worn or carried. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10+1. FIRE RELEASE: FLAME COAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus action Range: Touch Duration: Concentration, up to 10 minutes Components: HS, CM, W(Any) Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You engulf a weapon in fire chakra, coating it in a flame that enhances the lethality of the weapon. If you let go of the weapon or it is taken from you, the fire disperses. You cannot lose concentration of this jutsu as a result of damage. While you maintain concentration on this jutsu, you can engulf another weapon you are holding as a bonus action. A weapon enflamed by you, deals an additional 1d8+1 fire damage twice per turn. The fire sheds bright light in a 20- foot radius and dim light for an additional 10 feet. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the damage to 2d8+2. If this jutsu is cast at S-Rank, increase the damage to 3d8+3. FIRE RELEASE: FLAME STRIKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: A vertical column of flame erupts upwards from the ground towards the sky in a location you specify. Each creature in a 10-foot radius, 20-foot-high cylinder centered on a point within range must make a Dexterity saving throw taking 3d6+3 fire damage and gaining 1 rank of the burned condition on a failed save, or half as much damage on a successful one. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1. FIRE RELEASE: FLAME WHIP Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: self (20-feet) Duration: Instant Components: HS, CM Cost: 4 chakra Keywords: Fire Release, Ninjutsu Description: You conjure a flaming whip to strike at a creature you can see up to 20-feet away from you. Make a melee ninjutsu attack, dealing 2d10+2 fire damage. The target must make a Dexterity saving throw, being pulled 10 feet towards you. If a creature who failed the saving throw ends their movement within 5 feet of you, they fall prone and gain the burned condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10+1. FIRE RELEASE: FOX FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 hour Components: HS, CM Cost: 3 chakra Keywords: Fire Release, Ninjutsu Description: A flickering flame appears in your hand. The flame remains there for the duration and harms neither you or your equipment. The flame sheds bright light in a 20-foot radius and dim light for an additional 10 feet. The jutsu ends if you dismiss it. You can also attack with the flame. As an Action you can make a Ranged Ninjutsu attack on a creature you can see within 30 feet of you. On a hit, the target begins to glow with a soft, warm, and glowing radiance. While glowing in this way, this jutsu’s duration becomes Concentration, until the end of your next turn, and creatures have advantage on melee attacks targeting the creature. 86 FIRE RELEASE: GREEN FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action. Range: 90 feet Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You manifest an emerald-colored flame and mark a creature you can see within range with it. For the duration, when the target would make a Saving throw against a jutsu with the fire Release Keyword, they roll and additional 1d4. Reducing their saving throw by the result. If the marked creature would take fire damage from an attack that you make, you deal an additional 1d6+1 fire damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of marked creatures by +1. FIRE RELEASE: HELLFIRE REJECTION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage. Range: 15 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: When you are hit by a creature that you can see, you release a brilliant burst of fire chakra in a 15 Foot sphere around you. Creatures of your choice caught in the radius must make a Dexterity saving throw, taking 3d8+3 fire damage on a failed save, or half as much on a successful one. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8+1. FIRE RELEASE: PASSIONATE FLAMES Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action. Range: Touch Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Medical Description: You manifest a fuchsia-colored flame and place it on a wounded creature you can see within range. Target creature rolls 2 Hit Die, spending one. When they do, they recover the result + Your Ninjutsu ability modifier. After casting the target creature gains resistance to Fire Damage until the end of your next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of Hit die rolled and spent by 1. FIRE RELEASE: PHOENIX FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Fire Release, Ninjutsu Description: You spit forth 3 motes of fire at a creature within range. Make 3 ranged ninjutsu attacks against a target you can see within range. On a hit, the target takes 1d6+1 Fire damage. If you score at least two hits with this jutsu on the same target, they must make a Constitution saving throw gaining 1 rank of the burned condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the amount of attacks by +1. FIRE RELEASE: REKINDLED FLAMES Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action. Range: Touch Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Medical Description: You manifest a golden-colored flame and place it on a dying creature you can see within range. Target creature is immediately stabilized and rolls 3 Hit Die, spending two. If the target has less than 3 Hit die, they roll what they have left spending all of it. If the creature has no hit die, they are not able to be stabilized. They recover the result of the rolled Hit die + Your Ninjutsu ability modifier. After casting the target creature gains resistance to Fire Damage until the end of your next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of Hit die rolled by 1. FIRE RELEASE: SANGUINE SPEAR Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action. Range: 5 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You manifest a sanguine-colored flame and mold it into a melee weapon of your description that you then use to strike a target within range. Make one melee ninjutsu attacks, dealing 3d6+3 fire damage on a hit. A target currently burned or chilled suffer exasperated effected. Burned: A burned creature gain an additional rank of the burned condition. Chilled: A chilled creature loses the chilled condition suffering from a sudden shift in temperatures suffering all ranks of their chilled conditions damage. Their Chilled Condition immediately ends. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the number of melee ninjutsu attacks by +1. If this jutsu is cast at S-Rank, increase the number of melee ninjutsu attacks by +2. 87 FIRE RELEASE: SCORCHING RAY Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You create 8 rays of fire and hurl them at targets within range. You can hurl up to 2 at a single target, otherwise you can target up to 8 targets. Make a ranged ninjutsu attack for each ray. On a hit the target takes 2d4+2 fire damage. If a creature is hit by both attacks it must make a Constitution Saving Throw, gaining the Burned condition on a failed save. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and you create two additional rays. FIRE RELEASE: SPARK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action. Range: 5 Feet Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Fire Release, Ninjutsu Description: You manifest a highly flammable ember of fire release chakra. You can throw this ember onto any unworn or held highly flammable material or substance causing it to immediately go up in flames. The fires created by this jutsu grow in size as normal fire would and are not controlled by you. These flames are so hot they evaporate all water from sources that are not created by a Jutsu with the Water Release keyword of at least D-Rank or Higher. These flames extinguish themselves after 10 minutes. FIRE RELEASE: TEMPERED METALS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: 1 Minute Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You superheat a single weapon or stack of weapons or ammunition. For the next minute these weapons glow red hot and to all creatures but you are scalding hot to the touch. Weapons affected by this jutsu gains a +1 bonus to attack and damage rolls and their damage die is increased by one step for the duration. (D4>D6>D8>D10>D12) At the conclusion of this jutsu, the weapon becomes brittle, unusable and breaks. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When this jutsu is cast at B-Rank, the bonus becomes +2 and the damage die is increased by an additional step. When this jutsu is cast at S-Rank, the bonus becomes +3 and the damage die is increased by an additional step. FIRE RELEASE: WHITE FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 Minute Components: HS, CM, CS Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Fuinjutsu Description: You manifest a pale white-colored flame and mold it to coat your hands. For the duration, you do not need to spend chakra to maintain concentration on this jutsu. For the duration, Jutsu you cast with the fire release keyword always forces affected creatures to make a Constitution saving throw. On a failed save they gain the burned condition. On a successful save no further effects or conditions are imposed as a result of this jutsu. Creatures who gain the burned condition as a result of this jutsu, instead must beat a DC 20 Dexterity (Survival) Check to end the condition. FIRE RELEASE: WILDFIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 45 Feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu, Clash Description: You manifest a multicolored flame and fire a stream of it towards a creature you can see within range. Target creature must make a Dexterity saving throw. On a failed save they gain 1 rank of the burned condition, and take 2d12+2 Fire Damage. On a successful save they take half damage and no further effects. If the target already had the burned condition, on a failed save, they instead immediately take damage from the burned condition they have and take 3d12+3 fire damage with no further effects. On a successful save they take half damage and no further effects. C-RANK: FIRE RELEASE: BLAZING ASH PILE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 60 Feet (30-foot Cloud) Duration: 1 minute Components: HS, CM Cost: 7 Chakra Keywords: Fire Release, Ninjutsu Description: You blow a super-heated cloud of ash at a target area you can see within range; the cloud fills a 30 Foot radius in a cloud shape. Creatures inside the cloud are treated as if they are in total darkness. At any point in time within the next minute, as a bonus action or reaction, you can ignite the cloud of ash and all creatures inside the cloud would need to make a Dexterity saving throw, taking 7d4+7 Fire Damage and the burned condition on a failed save and half as much damage and no burns on a successful one. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d4+1. 88 FIRE RELEASE: BLUE FIRE EMBER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 60 feet Duration: Special Components: HS, CM Cost: 7 Chakra Keywords: Fire Release, Ninjutsu Description: You manifest a sapphire-colored ember into a solid but flickering form. This flame appears in a willing creature of your choices hand within range. This flame lasts an hour and causes no harm to the creature and can be given or carried by any other creature you designate as a holder. A holder of this flame may as their bonus action coat themselves in this blue flame granting them a fast burning but dense shield of flame for a short time. Until the beginning of their next turn, they gain a number of Temporary Hit points equal to 3d8 + 10. Melee attacks that strike the creature deals 10 fire damage to all creatures within 10 feet of them as the fire sparks off of them. These Temporary Hit Points are Vulnerable to Cold damage and Resistant to Wind and Fire damage. When the creature would take Cold Damage, this armor instead takes double damage. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Damage by 5. FIRE RELEASE: BURNING GAZE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 8 Chakra Keywords: Fire Release, Ninjutsu Description: You direct your gaze at an object or creature within range. Your eyes begin to glow a violent bright red and the target erupts into flames for the duration. An object begins to burn as flames engulf it. A creature must make a Dexterity saving throw gaining the burned condition for the duration. While you are concentrating on this jutsu, creatures currently suffering from the burned condition that you can see, cannot extinguish the fires that are burning them. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of ranks of burned granted on a failed save by +1. FIRE RELEASE: DANCE OF FIRE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you or a creature you can see in range, either takes damage or would make a Dexterity Saving throw. Range: Self (10-foot Radius Sphere) Duration: 1 Round Components: HS, CM Cost: 7 Chakra Keywords: Fire Release, Ninjutsu, Clash, Construct Description: You manifest a super dense barrier of flame around yourself and all creatures within range. This barrier of flame has 12 hit points, An AC equal to your Ninjutsu Save DC and counts as a Flaming Structure. Creatures outside of the radius of this barrier cannot see pass through it. Creatures who target this barrier of flame with a melee attack from either side or hit you an attack while outside of it and within 15 feet of it, take 12 Fire Damage. This barrier cannot move and intercepts all attacks and Jutsu, taking damage if any would attempt to pass through the walls exterior. This wall is resistant to Wind and Fire Damage and vulnerability to Cold damage. Jutsu with the Wind Release Keyword cannot initiate a clash with it by any means. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and its hit points and damage by 8. FIRE RELEASE: DRAGON FLAME BOMBS Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (120-Foot line) Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Fire Release, Ninjutsu, Clash Description: You knead chakra in your stomach and superheat it until you exhale it from your gut at terrifying speeds, leading to you being unable to truly control its path. You fire a Stream of superheated fire in a 5-foot wide, 120- foot-long line directly in front of you. Creatures in its path must make a Dexterity saving throw, taking 6d8+6 Fire damage on a failed save or half as much on a success. Objects within 5 feet of the stream of fire ignite if they are not being worn or held. The stream leaves behind a line of fire from you to the end of the 120-foot path. The fire remains for 1 minute or until extinguished. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8+1. 89 FIRE RELEASE: EMBER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Bonus Action", created_at: NOW, updated_at: NOW },
  { _id: "3140e73d8e8ad6cd1a167c5b", name: "STORM BREAKER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Full Turn Action", range: "Special", chakra_cost: "Special (20 Chakra)", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "As a part of the requirements to cast this jutsu, you must be able to see storm clouds in the sky above you. You use Lightning Release chakra to manipulate the clouds causing them to fall to ground level. All creatures in a 120-foot radius, centering on a creature you can see is plummeted into darkness as the thick storm clouds obstructs everyone’s vision with thick opaque fog and gas. The storm clouds cannot be seen through from the outside. Creatures with Chakra sight, within the storm clouds radius, is blinded by the massive volumes of chakra. Removing/Ending chakra sight, ends this blindness. For the duration, each time a creature takes lightning damage, lightning from the storm clouds is attracted to the damaged creature as a follow up lightning bolt is generated, forcing them to make a Dexterity saving throw. On a failed save, they take 6d6 lightning damage or half as much on a successful save. A creature can only be affected by this jutsu’s lightning bolt once per turn. S-RANK:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3f6e8831229d2610c766db3b", name: "GREAT SNAKE LIGHTNING", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "120 Feet", chakra_cost: "23 Chakra", components: "HS, CM", duration: "Instant", description: "You collect lightning into two massive spheres covering each hand before compressing them into globes the size of golf balls. You then perform a chakra molding shape using the balls of lightning, turning them into two snakes of your description that coil around one another as they fly towards a target of your choice that you can see within range. Make a ranged ninjutsu attack, dealing 10d12 lightning damage. On a hit, the Lightning then explodes outwards in a 30-foot radius sphere centering on the target creature. All other creatures within 30 feet of the target must make a Constitution saving throw, being stunned until the end of your next turn. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, you may select a second target for this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f7536c51deb9f715a4f52df", name: "KIRIN", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "b3b9a80a8acefa31d6905369"], elements: ["raiton"], casting_time: "1 Full Turn Action", range: "300 Feet", chakra_cost: "25 Chakra", components: "HS, CM, Thunder Clouds", duration: "Instant", description: "This jutsu requires an active thunderstorm to activate and for you and your target to be under the thunderstorm’s clouds. You create an opposite magnetic pull from the thunder cloud calling upon all of the lightning that the cloud has built up onto a single space you can see within range. This attack affects an area in the shape of a cylinder 20 Feet wide, and up to 300 feet in the sky. Creatures in the range of the lightning Bolt must make a Dexterity saving throw, taking 14d12 Lightning Damage on a failed save and half as much on a successful one. Creatures who fail their Dexterity Save are immediately Stunned for 1 minute. 133 LIGHTNING RELEASE: LIGHTNING CHAKRA", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f249cc6c246619f553e5bf8", name: "MODE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "This Jutsu does not cost Chakra to concentrate on, and you cannot lose concentration on it as a result of damage. You coat your body in a perfectly balanced layer of lightning release chakra, enhancing your damage resistance, your movement speed, and your overall striking power. Increase your AC by +3, reduce all damage you take except Wind by 8, increase your movement speed by 50 feet, and all melee attacks you make except Genjutsu Attacks deal an additional 3d10 Lightning Damage, twice per turn. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a3052f23ba718952e01e7b3e", name: "RAILGUN", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "1 Action", range: "Self (500 Foot Line)", chakra_cost: "35 Chakra", components: "HS, CM, NT (A Small Metallic object such as a", duration: "Instant", description: "You manifest your Lightning release chakra infusing it into the metallic object so much so that electricity radiates up to 60 feet off of it and glows white. Electronic tools and appliances begin to overload and short- circuit. You then create a circular barrel made of Lightning release chakra to stabilize the metallic object as you launch it through the barrel causing unrivaled destruction to anything in its path. All Creatures, objects and structures in a 15-foot wide, 500-foot line must make a Dexterity saving throw. A shocked creature makes their saving throw at disadvantage. On a failed a creature takes lightning damage equal to 12d10, is knocked prone and becomes dazed for the next minute. If a creature is shocked, they instead take 16d10 and become stunned for the next minute. Objects and structures take the maximum possible damage. On a successful save, a creature takes half of 12d10. If the creature is shocked, they instead take half of 16d10. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, this jutsu ignores cover and creatures cannot make their saving throws with advantage. LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3725ea80625e38676fcda77b", name: "STAR BREAKER", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: ["raiton"], casting_time: "10 Minutes", range: "100 Miles", chakra_cost: "Special (138 Chakra)", components: "HS, CM, CS", duration: "Instant", description: "You manifest your Lightning release chakra infusing it into hundreds of chakra seals for the casting time. You and all casters designate a single target you can see within range. Upon casting the jutsu you fire a massive beam of compressed Lighting Release chakra on the target. All casters make a ranged ninjutsu attack targeting the same target taking the highest result. On a hit, you deal 50d12 Lightning Damage. All Creatures, objects and Structures within 1 mile must make a Dexterity Saving Throw at disadvantage, taking 50d8 lightning damage on a failed save and half as much on a successful save. Structures and Objects take double damage. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters reduce the cost by -2. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's offensive abilities based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase damage by 5d12 and 5d8. +3: Increase damage by 10d12 and 10d8. +4: Increase damage by 15d12 and 15d8. +5: Increase damage by 25d12 and 25d8). LIGHTNING RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "34c2f0f8cd8c98cebe08afce", name: "THUNDERCLAP ARROW", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: ["raiton"], casting_time: "1 Action", range: "150 feet", chakra_cost: "27 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure a mass of lightning into the shape of an arrow, that you launch into the air before commanding it to crash into the ground. Choose a point within range for the arrow to land that creates a vertical explosion into the shape of a cylinder 60 feet wide and 100 feet high. All creatures within range must make a Dexterity saving throw, taking 15d10 lightning damage on a failed save . Creatures must also succeed a Constitution Saving Throw being Stunned until the end of their next turn on a failed save. This jutsu ignores Resistance to Lightning Damage. Overcharge. When you cast this jutsu with its listed casting time, you can choose to spend your Bonus Action or Reaction to overcharge its effects. When you do, each creature in a 10ft wide line between you and the target space must make a Dexterity save, taking 10d6 lightning damage on a failed save. All damage from this jutsu ignores Resistance, Damage Reduction and Temporary Hit Points. 134 GENJUTSU ne of the main jutsu categories which uses chakra. Unlike ninjutsu, the effects of Genjutsu are not real, being only sensory illusions experienced by those who fall victim to it. Genjutsu falls under the broad category of Yin Release. A Genjutsu is created when a ninja controls the chakra flow of a target's cerebral nervous system, thereby affecting their five senses; this is frequently used to create false images and/or trick the body into believing it has experienced physical pain. Special Effects: Genjutsu isn’t tangible and cannot be physically blocked. Barriers, blanket Damage Reduction, Resistance and Immunity from Jutsu cannot block or reduce damage from Genjutsu unless granted by a Genjutsu. Most Genjutsu that require a saving throw will have the effects of a Critical Success, Success, Failure or Critical Failure listed A creature who Critically Fails, follows the effect of only a Critical Failure, not a Failure as well, unless otherwise specified. The follo wing are the breakdowns for how to calculate each. • Critical Success: Beat the Save DC by 5 or more • Failure: Fail to meet or beat the Save DC. • Success: Beat the Save DC. • Critical Failure: Saving throw result is 5 or more, lower than the Save DC. E-RANK:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "280ca43005ff450385aafae0", name: "AFFECTION", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "2 Chakra", components: "CM", duration: "Concentration, up to 1 Minute", description: "For the duration, you have advantage on all Persuasion checks directed at one creature you touch that isn’t hostile towards you. When the jutsu ends the creature may realize that you used a jutsu to influence its mood if it doesn’t fit your previous relationship. A creature prone to violence might attack you if they realize this. Another creature may seek retribution in other ways (At the DM’s discretion), depending on the nature of your interactions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ae38ebbc3c2169388bb580f4", name: "CLONE TECHNIQUE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "2 Chakra", components: "HS", duration: "Concentration, up to 1 minute", description: "The most basic clone technique that is taught in most academies across the ninja world. By using this technique, the user creates 2 duplicates of themselves. The clones stay near you and disappear when attacked. The clones appear by the user's side and cannot stray more than 5 feet away from the original. The duplicates look like the user and are perfect duplicates, but they cannot speak or perform any action that requires having a body, like lifting an object or attacking a creature. Once touched by another creature or object or violently shaken, it disappears in a puff of smoke. After Activation, as a reaction you make a creature attacking you roll an additional 1d6, subtracting the result from their total attack roll. Doing this causes one of your clones to be struck regardless of the attack missing or hitting you. After the duration or both of your clones have been struck, this jutsu immediately ends. Any creature using a Jutsu with the Sensory Keyword or that can see through Genjutsu are not affected by this jutsu", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b0afe1696849b658e4f16594", name: "DISTANT ECHO", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "1 Chakra", components: "HS, CM", duration: "Up to 1 minute", description: "You create a sound within range that lasts for the duration. The sound also ends if you dismiss it as an action or use this jutsu again. The sound you create can be any volume, ranging from a whisper to a scream. It can be your voice or another sound you have heard before such as another person's voice, a lion's roar or a shattering vase. The sound continues unabated throughout the duration or you can make discrete sounds at different times before the jutsu ends.", at_higher_ranks: "This Jutsu’s proficiency increases as you increase in level. At 5th level select 1 additional location for the sound to originate. 11th level, 2 additional locations, 17th level, 3 additional locations.", created_at: NOW, updated_at: NOW },
  { _id: "0bc54a36d3600b0a6407bb39", name: "DOUBT", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "2 Chakra", components: "CS", duration: "1 Minute", description: "For the duration, you have advantage on all Intimidation checks directed at one creature you touch that you are interacting with. When the jutsu ends the creature may realize that you used a jutsu to influence its mood if it doesn’t fit your previous relationship. A creature prone to violence might attack you if they realize this. Another creature may seek retribution in other ways (At the DM’s discretion), depending on the nature of your interactions. O 159", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ce5d984b7e7ef20f130bb2dd", name: "ENCODE THOUGHTS", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "2 Chakra", components: "HS, CM", duration: "8 Hours", description: "You draw out a memory, an idea, or a message from your mind, and seal it into a tangible string of glowing seals called a thought strand, which persists for the duration or until you cast the jutsu again. The thought strand appears in an unoccupied space on a surface of your choice, such as a wall, blank scroll, book, or skin in the form of text or images of your memories design. If you cast this Genjutsu while concentrating on a Genjutsu or ability that allows you to manipulate the thoughts of others (such as Memory Domination), you can transform the thought or memories you read, rather than your own into a thought strand.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f360bba31a83e806909f5076", name: "ENHANCED THOUGHTS", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a"], elements: [], casting_time: "1 Reaction, which you take when you fail a skill check", range: "Self", chakra_cost: "2 Chakra", components: "HS", duration: "1 Round.", description: "You focus chakra toward different parts of your mind to enhance your ability to process information. When you fail a skill check using a mental ability score (Intelligence or Wisdom), you can add+2 to that failed check, potentially turning a failure, into a success. Once you cast this jutsu, you cannot do so again for 10 minutes.", at_higher_ranks: "This Jutsu's skill reinforcement increases as you increase in level. This bonus increases by +2 at 5th Level (+4), 11th level (+6), 17th level (+8)", created_at: NOW, updated_at: NOW },
  { _id: "e5d931831012eaae9743f64f", name: "FEATHER BURST", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "Self", chakra_cost: "2 Chakra", components: "HS, CM", duration: "Instant", description: "A simple illusion of sight. When hit by an attack, the opponent sees you burst into black raven feathers reforming at your current location. When hit by a melee attack, roll 1d8 reducing damage taken by the result and move 10 feet away. This movement does not provoke attacks of opportunity.", at_higher_ranks: "This Jutsu’s proficiency increases as you increase in level rolling 1d8 when you reach 5th level (2d8), 11th level (3d8), 17th level (4d8)", created_at: NOW, updated_at: NOW },
  { _id: "2662bdcd35d29ccb1222ac1e", name: "FLASH", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "2 Chakra", components: "HS, NT (Firecrackers)", duration: "Instant", description: "A mix of firecrackers and Chakra to make the flash they produce 10 times more intense. Select a Space up to 30 feet away. Creatures within 5 feet of the space you select must make a Wisdom save. On a failed save, the next attack targeting them has advantage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "efb3955867d8091fc7db488b", name: "MESSAGE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "2 Chakra", components: "HS", duration: "1 round", description: "You point your finger towards a creature within range that you can see and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear. You can cast this genjutsu through solid objects if you are familiar with the target and know it is beyond the barrier. This jutsu doesn’t have to follow a straight line and can travel freely around corners or through openings.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8e3653897bc11886b7a52c02", name: "MIND SLIVER", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "1 Chakra", components: "HS, CM", duration: "1 Round.", description: "You inject a disorienting spike of chakra into the mind of one creature you can see within range. Make a Ranged Genjutsu attack, dealing 1d6 psychic damage. The target must also succeed an Intelligence saving throw. On a failed save, until the end of its next turn, it must roll a d4 and subtract the number from the first saving throw they make for the duration.", at_higher_ranks: "This Jutsu’s proficiency increases as you increase in level rolling an additional 1d6 when you reach 5th level (2d6), 11th level (3d6), 17th level (4d6) 160", created_at: NOW, updated_at: NOW },
  { _id: "fe344cee679900ecfffbca3d", name: "MINOR ILLUSION", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "2 Chakra", components: "HS", duration: "1 Minute", description: "You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this genjutsu again. If you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else’s voice, a lion’s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends. If you create an image of an object— such as a chair, muddy footprints, or a small chest—it must be no larger than a 5-foot cube. The image can’t create sound, light, smell, or any other sensory effect. Physical interaction with the image reveals it to be an illusion, because things can pass through it. If a creature uses its action to examine the sound or image, the creature can determine that it is an illusion with a successful Intelligence (Investigation), or Wisdom (Illusion) check against your genjutsu save DC. If a creature discerns the illusion for what it is, the illusion becomes faint to the creature.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8009b2dba7dbaa226044fddb", name: "PAIN", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Bonus Action", range: "60 Feet", chakra_cost: "2 Chakra", components: "HS", duration: "Concentration, up to 1 minute", description: "You point at a creature within range and the sound of a dolorous bell fills the air around it for the moment. The next time the target would take damage, they take an additional 1d4 psychic damage. This jutsu then ends.", at_higher_ranks: "This Jutsu’s effectiveness increases by one die when you reach 5th level (2d4), 11th level (3d4), 17th level (4d4).", created_at: NOW, updated_at: NOW },
  { _id: "2b5ebcefbe73b4bd2bb79406", name: "RELEASE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "2 Chakra", components: "HS, CM", duration: "Instant", description: "This technique allows the user to isolate and forcefully remove the effect of a single Genjutsu effect, so long as it can be dispelled. You must first be aware that you or your target is under the effect of a Genjutsu. As part of the activation of this jutsu, make an Illusion Check at advantage vs the Save DC of the Genjutsu. On a success you free yourself or your target from the Genjutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "10d70660617cb7690e3040c7", name: "TRANSFORM", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "1 Chakra", components: "HS", duration: "Concentration, up to 10 Minutes", description: "This technique is taught to every student of the academy. Using this technique, the user assumes the form of a creature, object or animal of the same size category as they are or smaller. They may freely designate the specifics of their new form (such as height, weight, hair texture and color, skin tone, etc.). This transformation is purely cosmetic and an illusion. When you use a Charisma based skill action in an attempt to deceive, lie or misguide another creature, you use this new form, so long as it is relevant to your act, to enhance that lie with convincing movements and gestures. If you are not benefiting from the Voice Change Genjutsu active, you gain only half of the following bonus. While transformed, when you use a Charisma based skill action in an attempt to deceive, lie or misguide another creature, you use this new form, so long as it is relevant to your act, you can add+4 to the checks made. You can gain this bonus, once per round, or once every minute if in combat or a social scene.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "36a24e0242a9d9481bf517f1", name: "TRUE STRIKE (CHANGED)", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Reaction, which you take when you miss a creature you target with an attack roll", range: "Self", chakra_cost: "2 Chakra", components: "HS, CM", duration: "Instant", description: "You focus your genjutsu towards a single creature in range. Your genjutsu grants you a brief insight into one target’s defenses. You gain a +2 bonus on the triggering attack roll, potentially turning a miss into a hit. You can gain the benefit of this jutsu once per round.", at_higher_ranks: "This Jutsu’s bonus increases by +1 when you reach 5th level (+3), 11th level (+4), 17th level (+5)", created_at: NOW, updated_at: NOW },
  { _id: "1111df386a7f1a0030f6e582", name: "VOICE CHANGE", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "1 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You coat your tongue in chakra, manipulating the vibrations it provides while speaking. You imitate the voice of any creature you’ve heard before with amazing accuracy. Creatures would need to actively take the See through lies, skill action to tell your voice is fabricated. 161 D-RANK:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6cbf512100d7eef9ed3f7844", name: "ANIMAL COMPANION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Concentration, up to 10 Minute", description: "You select an animal you can see within range and alter its disposition towards you. This animal will see you as a member of its pack, its child, its parent, or its Master (your choice). The animal will be able to understand your commands and will act on them for the duration. The target creature must make a Charisma save, becoming charmed by you for the duration. The animal can fight on your behalf, once the creature reaches half health this jutsu ends. They may then stay and fight to survive or run based on the type of animal they are. (DM’s description)", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select one additional animal you can see.", created_at: NOW, updated_at: NOW },
  { _id: "4a0e13bc18adccfd8de486a9", name: "BANE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (30-Feet)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You release a pulse of chakra targeting all hostile creatures within 30 feet of you causing them feel deep seeded regret or dread. All hostile creature of your choice within 30 feet of you must make a Charisma saving throw as their mind is wrought with negative thoughts. Success: No further effects. Failure: Affected creatures suffers a 1d4 penalty to all attack roll, saving throws and checks it makes for the duration. Critical Failure: Affected creatures suffers a 1d6 penalty to all attack roll, saving throw and skill checks it makes and it cannot gain the benefit of jutsu that provide bonuses to it of the same rank or lower for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the radius by 10-feet. If cast at B-Rank the die increases by one step. If cast at S-Rank, the die increases by two steps.", created_at: NOW, updated_at: NOW },
  { _id: "d59162bfa7ac347995b8ed80", name: "CAUSE FEAR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You awaken a sense of mortality in one creature you can see within range after releasing some potent aromas from incents you spread and use as the catalyst for your genjutsu. A construct or undead is immune to this effect. The target must make a Wisdom saving throw at the beginning of each of its turns for the duration. Critical Success: This jutsu ends on the affected creatures, removing all ranks of fear granted by this jutsu. Success: Affected creature does not gain a rank of fear. Failure: Affected creatures gains one rank of fear against the caster until this jutsu ends. Critical Failure: Affected creatures gains two ranks of fear against the caster until this jutsu ends and falls prone from the shock.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select 1 additional creature who must all be within 30 feet of each other when you target them.", created_at: NOW, updated_at: NOW },
  { _id: "3e912f3c626b3e30a29cd011", name: "CHARMING DISSONANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You attempt to suppress strong emotions in up to 3 creatures who can see and hear you within range. You speak with a reverberating confidence that quells their fears, anger, and confusion. Up to 3 creatures you choose must make a charisma saving throw; A creature can choose to fail this saving throw if it wishes. If a creature fails its saving throw, choose one of the following effects. • You can suppress any effect causing a target to be charmed or feared. When this jutsu ends, any suppressed effect resumes, provided that its duration has not expired in the meantime. • Alternatively, you can make a target indifferent about creatures of your choice that it is hostile towards. This indifference ends if the target or its allies are attacked. When this jutsu ends, the creature becomes hostile again.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select 1 additional creature.", created_at: NOW, updated_at: NOW },
  { _id: "043d52ae4be2438af8d0f637", name: "CLOAK OF SHADOWS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You cloak a willing creature you touch in illusionary darkness, granting it a +1d4 bonus to Hide or Sneak attempts vs creatures that rely on sight for the duration. Additionally, if cast in Dim Light or Darkness, creatures attempting an Identify Genjutsu action, make their check at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at B-Rank, the duration increases to “up to 10 minutes” and no longer costs chakra to maintain concentration. If cast at A-Rank, this jutsu’s duration becomes 1 Hour and no longer requires concentration. 162", created_at: NOW, updated_at: NOW },
  { _id: "f64fef3a560fa8caa75f99c8", name: "COLOR SPRAY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a dazzling array of flashing, colored lights, that spring forth from your hand. Creatures in a 15-foot cone, originating from you must make an Intelligence saving throw. Critical Success: Affected creature is able to completely resist this jutsu’s effect. Success: Affected creature gain 1 rank of Dazzled. Failure: Affected creatures Blinded until the end of their next turn. Critical Failure: Affected creatures becomes blinded and must remake the intelligence saving throw at the end of each of its turns to realize it’s not actually blinded, ending this jutsu’s effects on them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "4a3e555d83e7f6c213dad197", name: "COMMAND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "CM", duration: "1 Round.", description: "You speak a one-word command to a creature you can see within range. The target must make a Wisdom saving throw or follow the command on its next turn. The jutsu has no effect if the target is undead, if it doesn’t understand your language, or if your command is directly harmful to it. Some typical commands and their effects follow. You might issue a command other than one described here. If you do so, the GM determines how the target behaves. If the target can’t follow your command, the jutsu ends. • Approach: The target moves towards you by the shortest and most direct route, ending its turn if it moves within 5 feet of you. • Drop: The creature drops whatever it is holding and then ends its turn. • Grovel: The target falls prone and then ends its turn. • Flee: The target turns and spends its turn moving away from you by the fastest means available. • Halt: The target doesn’t move or take actions. A flying creature stays aloft, provided that it is able to do so. If it must move to stay aloft, it flies the minimum distance needed to remain in the air.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "bead2075d997b84c3b51ea8a", name: "COMPELLED DUEL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You attempt to compel a creature into a duel. They see you as the only worthy foe in the area and will do everything they can to fight you and only you, while becoming indifferent towards other combatants. One creature that you can see must make a wisdom saving throw. Success: Affected creature ignores this jutsu and suffers no effects. Failure: Affected creature becomes drawn to you suffering a -1d6 penalty to all attacks rolls against creatures other than you for the duration. A compelled creature must remake their saving throw at the end of each of its turns to end this effect on them. This jutsu ends if you attack any other creature or if a friendly creature to you, would assist you in any way. Critical Failure: Affected creatures becomes drawn to you, becoming unable to target any other creature other than you for the duration. This jutsu ends if you attack any other creature or if a friendly creature to you would assist you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ff15310b04f1528d471eb23f", name: "COMPREHEND LANGUAGES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "3 Chakra", components: "HS, CM", duration: "1 Hour", description: "For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching a creature who can already understand the language.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "19c984809c12f9fa518d2d1e", name: "CONFIDENCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 Minute", description: "You select up to 3 willing creatures in range, that you can see, reinforcing their confidence in themselves, allowing them to act with little to no hesitation. For the duration, whenever a target creature makes an Ability check, they add +2 to the result. The first time the succeed on an Ability check, this jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, this bonus instead becomes a +3. If this jutsu is cast at S-Rank, this bonus instead becomes a +4. 163", created_at: NOW, updated_at: NOW },
  { _id: "b065f43e310472264bc4fcfd", name: "CORRUPTION: ANIMUS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to mentally disable the confidence and Strengths of your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures who would gain dice-based bonuses as a result of features or traits to their attack or damage rolls, they instead treat those bonuses, as penalties, for the duration. Critical Failure: Same as failure, but this inversion also extended to Jutsu based bonuses.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "7a165996fa1baa4594255bae", name: "CORRUPTION: ASPERITY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to inject a sense of harshness towards allies, in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: If the affected creature would cast a jutsu that allows them to omit or exclude its allies, for every hostile creature they select, they must also choose one ally as a target as well, even if they have a limited number of targets they can select, that selected ally counts as one of its choices. Once this effect takes place, this jutsu ends. Critical Failure: Same as failure, but this effect lasts for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "dc652b1366bcf75d2903f799", name: "CORRUPTION: AUDACITY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to inject a sense of harshness towards allies, in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Creatures who would attempt to make an attack of any type targeting a creature you are allied with, the affected creature is mentally forced to hold back on the Strength of the attack, reducing the damage they deal by 1 damage die, to a minimum of 1 damage die. Critical Failure: Same as failure, but the damage die reduction is increased to 2.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the damage die reduction by 1. If this jutsu is cast at S-Rank, increase the damage die reduction by 2.", created_at: NOW, updated_at: NOW },
  { _id: "3b890b153d1f2c608b0f8259", name: "CORRUPTION: DISDAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to mentally corrupt the feeling of happiness and stability in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures who would attempt to cast a jutsu as a reaction, that would interrupt the casting of another jutsu, must roll a d20. On a roll of 11 or higher, they lose their reaction, unable to interrupt their original target. Critical Failure: Same as failure, but on a roll of 6 or higher they lose their reaction, unable to interrupt their original target. 164", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "61e29412f1d09b5af4dc35be", name: "CORRUPTION: ENMITY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to inject a sense of broken morale and distrust in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures whose ally is casting a jutsu, must spend its reaction to cast a jutsu that would Interrupt the casting of their allies. Once they attempt to interrupt the casting, this jutsu then ends. Critical Failure: Same as failure, but the affected creature must spend its reaction to attempt to interrupt all of its allies jutsu castings, if able, for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "bc80f2d32fccf7bc12ec2dca", name: "CORRUPTION: GALL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to inject a sense of impudence in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures cannot upcast their jutsu for the duration. If they would attempt to do so, they still spend the chakra, but its effects remains its base rank. Critical Failure: Same as failure, but the affected creature must attempt to upcast their jutsu cast to the highest rank possible, spending the chakra as normal, but its effects remain as its base rank.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "fef14c36c14c4211d8eacae5", name: "CORRUPTION: INSOLENCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to inject a sense of harshness towards allies, in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Creatures under the effect of a Genjutsu, that grants a die-based bonus, have this bonus halved. Critical Failure: Creatures under the effect of a Genjutsu, that grants a die-based bonus, cannot benefit from this bonus for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "a6e626b957762fff03d3c453", name: "CORRUPTION: SPITE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to mentally disable the physical Strengths of your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures suffer a -2 penalty to all Strength based attack and damage rolls. Critical Failure: Same as failure, but the penalty is reduced by an additional -2.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the penalty by an additional -1. 165", created_at: NOW, updated_at: NOW },
  { _id: "117c28307d7e56f0be2cc79c", name: "CORRUPTION: TEMERITY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to suppress their boldness in combat. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature loses the benefit of jutsu based bonuses to speed, becoming unable to benefit from them for the duration. An affected creature remakes their saving throw at the end of each of their turns. Critical Failure: Same as failure, but this also extends into class and class features as well.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "83e48d1bdaeca83e185ecfcb", name: "CORRUPTION: VILE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to mentally disable the physical flexibility of your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures suffer a -2 penalty to all Dexterity based attack and damage rolls. Critical Failure: Same as failure, but the penalty is reduced by an additional -2.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the penalty by an additional -1.", created_at: NOW, updated_at: NOW },
  { _id: "0bcb6597131df0a4365bae29", name: "DETECT EVIL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "10 minutes", description: "For the duration, you know if there is someone within 60 feet of you with a hostile intention. You do not know their direct location only that they are within the range of this genjutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b63e6cfda0f05e0dd81aadd1", name: "DETECT ILLUSIONS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (10-foot Radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 Minutes", description: "For the duration, you can sense the presence of Genjutsu of D-Rank or Lower within 10 feet of you. If you sense Genjutsu in this way, you can use your action to see a faint aura around any visible creature or object in the area that is affected by a Genjutsu. Additionally, if a Genjutsu affects an area, the affected area with glow with this aura instead of any individual creatures or objects. This jutsu cannot penetrate through barrier, walls or surfaces and does not provide insight on the Rank or number of Genjutsu affecting a creature.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the rank of Genjutsu you can detect.", created_at: NOW, updated_at: NOW },
  { _id: "f0b54c1292eaf526da29d442", name: "DETECT INTENTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Select a creature you can see within range. If the target is not aware of your presence roll your Illusion Skill vs their passive Deception. On a success you know what the creatures most immediate intention is. This does not explain why they are trying to do whatever it is they are trying to do just what it is they want to do. If the target is aware of your presence, they make a Wisdom saving throw. On a failure you gain the same information as you would if they weren’t aware of your presence. On a success they can hide their intention instead hiding it behind another set of intentions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "32d4484adb8ed57a17bad69e", name: "DISTANT WORDS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Minute", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Until Dispelled", description: "You implant a message within an object in range, a message that is uttered when a trigger condition is met. Choose an object that you can see and that isn’t being worn or carried by another creature. Then speak the message, which must be 25 words or less, though it can be delivered over as long as 10 minutes. Finally, determine the circumstance that will trigger the jutsu to deliver your message. When that circumstance occurs, a disembodied voice can be heard originating from the object and recites the message in your voice and at the same volume you spoke. When you cast this jutsu, you can have the jutsu end after it delivers its message, or it can remain and repeats its message whenever the trigger occurs. 166 The triggering circumstance can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the object. For example, you could instruct the illusion to speak when any creature moves within 30 feet of the object or when a silver bell rings within 30 feet of it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ac4efd2c23024bd2eca108a3", name: "DISTORT VALUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 Minutes", description: "When you cast this Genjutsu target an object no more than 1 foot on a side, doubling the objects perceived value by adding an illusionary flourish or reducing its perceived value by half with the help of illusionary dents or scratches. Anyone examining the object must roll an investigation or Illusions check against your genjutsu save DC to see through this genjutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the object by 5.", created_at: NOW, updated_at: NOW },
  { _id: "5b23b17f3b07df98311d6626", name: "DOUBLED PAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Bonus Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You target a creature and amplify their nervous system, enhancing all instances of pain to a massive degree. Select a target creature you can see within range. For the duration, whenever you deal damage using a Genjutsu, you deal an additional 1d8 Psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select one additional creature to be affected.", created_at: NOW, updated_at: NOW },
  { _id: "a0fac816dccce99780b2578a", name: "ENVIRONMENTAL AFFINITY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Special", description: "The environment seems to shift and swirl around you. For this jutsu’s duration, creatures looking at you see the natural terrain moving at your beck and call giving them pause. If cast while you are not in combat, this jutsu lasts for 1 hour. For that duration, you make your next initiative roll at advantage. If cast while in combat, this jutsu’s duration becomes Concentration, Up to 1 Minute, and creatures that target you with an attack or jutsu treat you as if you are in half cover. If the terrain is not natural and instead industrial such as a concrete hallway, steel floors, or anything similar, a creature makes a Wisdom (Illusions) check vs your Genjutsu Save DC at advantage, gaining immunity to this jutsu for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When casted at B-Rank this jutsu no longer requires concentration.", created_at: NOW, updated_at: NOW },
  { _id: "acdef7eefa6f838306e47f7f", name: "EXTRASENSORY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a barrage of supersensory sensations meant to overwhelm a creatures senses. Select one creature within range. Select creature must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature is suffering a 1d4 penalty to their next attack roll. Failure: Affected creature gains 2 ranks of Dazzled. Critical Failure: Affected creature gains 2 ranks of Dazzled and at the beginning of their next turn, they must roll a d10. On a roll of 1 or 2, they flinch losing their Action.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "999426dfcc72f54bca8969e3", name: "FRENZY: BLACK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to black out the thoughts of your targets, making it difficult for them to form coherent or even manageable thoughts. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures begins to suffer mental black outs. At the beginning of each of their turns, they must make a Wisdom ability check vs a DC 13. On a failed check, all creatures in the turn initiative, is treated as a hostile creature for them, and they cannot exclude creatures in the effect area of a jutsu or features effects. At the end of each of their turns, they remake their saving throw, ending this jutsu’s effect on them on a success. Critical Failure: Same as failure, but the ability check DC is increase to a DC 16.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. 167", created_at: NOW, updated_at: NOW },
  { _id: "f3e4b444bf1ee2402a1bd0ba", name: "FRENZY: BLUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "45 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You collect and build illusionary chakra, attempting to inflict a fit of depressing madness causing your eyes to glow blue. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: If the affected creature would make a saving throw for the duration, on a failed save, they after suffering the triggering jutsu’s effects, they fall prone and have their movement speed reduced by half, until the end of their next turn. Creatures remake their saving throw against this jutsu, at the end of each of their turns. Critical Failure: Same as failure, but their speed is instead reduced to 0.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "80b61c14532f36d6675f91d8", name: "FRENZY: CYAN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 feet (20-foot cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Round", description: "You collect and build illusionary chakra, attempting to inflict a fit of unstable madness meant to break the minds of creatures in the affected areas, as their eyes flash a cyan color. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: If the affected creature attempts to take an action or bonus action, it must make a Wisdom ability check vs a DC 13. On a failure, they stand still laughing manically, wasting the attempted action. On a success, they can take their actions as normal. This effect ends at the end of the affected creatures turn. Critical Failure: Same as failure, but the ability check DC is increased to 16.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cube by 5 feet", created_at: NOW, updated_at: NOW },
  { _id: "460c90d58c1777463e0434ca", name: "FRENZY: GREEN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action.", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to infuse a target within range, with an aspect of your madness, causing their eyes to glow green. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects, instead only becoming concussed until the end of the next turn. Failure: Affected creatures succumbs to your aspect of madness. For the duration, if they would attempt to cast a Jutsu with a casting time of a Bonus Action, they must roll a 1d4. On a roll of 1 or 2, they fail to cast it as they lose focus with constant mutterings. On a roll of 3 or 4, they cast it as normal, and remake their saving throw to end this jutsu’s effects, while still unaware it is affected by this Genjutsu. Critical Failure: Same as failure, but they instead must roll a 1d6, only being able to cast normally on a roll of a 5 or 6.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b6ab89adc34c1309a16ca999", name: "FRENZY: MAGENTA", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You collect and build illusionary chakra, attempting to bring about a spiral of lustful insanity, causing their eyes to glow with a Magenta color. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: When the affected creature attempts to cast a jutsu or make an attack targeting another creature, they must make a Wisdom ability check vs a DC 13. On a failed save, they gain 3 ranks of Charm against that target for the duration. Critical Failure: Same as failure, but the ability check DC is increased to 16.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. 168", created_at: NOW, updated_at: NOW },
  { _id: "b61013eb3c16ee578bd1745b", name: "FRENZY: ORANGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You collect and build illusionary chakra, attempting to inflict a fit of calm insanity, causing their eyes to flicker orange. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: The affected creature must spend its bonus action, on each of its turns calmly but in a harmful way scratch at its arms, drawing wounds upon it, dealing 1d8+ the targets Strength modifier slashing damage. They then remake their saving throw vs this jutsu, ending it on a successful save. Critical Failure: Same as failure, but they instead must spend their action, not their bonus action, and they deal 2d6 + the targets Strength modifier slashing damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1 and the critical failure damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "daedfe71e48a4bc03e3690a1", name: "FRENZY: PURPLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action.", range: "45 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You collect and build illusionary chakra, attempting to touch the madness building deep in the psyche of your foes causing their eyes to glow purple. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s secondary effects. Failure: Affected creatures falls into a momentary madness. The next time they would cast a jutsu that deals damage, they must target a creature they consider an allied creature, before the end of their next turn. Critical Failure: Same as failure, but they also must cast a jutsu of at least C-Rank on their next turn if they have access to a jutsu of such rank. If they only have access to D-Rank jutsu, they instead cast one of these.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "ff6440d824e43dce1b22d181", name: "FRENZY: RED", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action.", range: "30 feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You collect and build illusionary chakra, attempting to bring about a fit of rage and fury to a creature, causing their eyes to glow red. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature gains a rank of Berserk. Critical Failure: Affected creature gains a rank of Berserk that is not lost at the end of its turn. Instead it must make a wisdom saving throw at the end of its turn, ending this condition on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "3d8026ca5c806b06f9cee1c1", name: "FRENZY: SILVER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You collect and build illusionary chakra, attempting to inflict a fit of twisted psychosis, causing your eyes to flash silver. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: The affected creature finds it difficult to maintain focus on anything if they would take damage. When the target would take damage, for the duration, they automatically fail their concentration check Critical Failure: Same as failure, but when they lose concentration of a jutsu while under this jutsu’s effects, they take 2d6 psychic damage, for each jutsu they lose concentration of.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1 and the critical failure damage by 1d6. 169", created_at: NOW, updated_at: NOW },
  { _id: "fb1b802577ffb82d1ce54c3b", name: "FRENZY: YELLOW", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action.", range: "30 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You collect and build illusionary chakra, attempting to bring about a fit of insanity as their eyes flash a golden yellow. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: If the affected creature would make an attack on their next turn, they gain an additional action, which they must use to make an additional attack, using the same ability, action or jutsu. If the jutsu would end after making the original first attack, it instead does not until this additional attack is made. This additional attack must be targeting one of its allies within the attacks, jutsu’s or abilities range. This effect immediately ends if they never make an attack on the turn following this jutsu’s casting. Critical Failure: Same as failure, but they must make both the original attack and the additional attack, targeting an allied creature.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "623fbcd0a2593dac2b862581", name: "GLAMOR TONGUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 10 Minutes", description: "A willing creature you touch is enhanced with a Genjutsu that makes the words they speak seem more interesting, attractive or compelling. For the duration an affected creature has advantage on all charisma-based checks using skills to talk with another creature. When a creature who finds them even slightly attractive hears them speak, that creature must make a Charisma Saving throw. On a failed save that creature gains 1 rank of charmed against them for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f39827a467a1f90671a601fe", name: "HEROISM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "A willing creature you touch is imbued with heroic bravery. Until the genjutsu ends, the creature is immune to the fear condition and gains temporary hit points equal to twice your Genjutsu ability modifier at the start of each of its turns. When the Genjutsu ends, the target loses any remaining temporary hit points.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures affected by this jutsu by 1.", created_at: NOW, updated_at: NOW },
  { _id: "9312d1aeb3dcdc00b2cfec38", name: "HYPNOSIS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You manifest a collection of sheep wool in the form of pollen as you attempt to lull a creature into a deep sleep. Select a creature you can see within range. The target must make a Wisdom saving throw. A creature who is currently in combat is immune to this jutsu’s effects. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature is slowed until the end of the next turn as they are only slightly drowsy. Failure: Affected creature begins to daydream. They become blind and deafened to all events and happenings that is further than 10 feet away from them. Anything that would affect them or the area within 10 feet of them would break them from this day dream. Critical Failure: Affected creature falls asleep, unconscious for the next 10 minutes. A creature who is asleep in this way can be awoken by yells, screams or loud sounds or by being physically shaken or taking damage of any type.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "deaa56aa3b14f8de94be8bfa", name: "ILLUSIONARY REINFORCEMENT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when an allied creature makes an attack roll or saving throw.", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a possible future and show it to your ally, granting them the chance to take ability to take that future by the horns. When an allied creature makes an attack roll or saving throw, you also roll 1d20. The allied creature can choose to use your d20 result or their own. 170", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0370243273a2ea7300c9289e", name: "ILLUSORY SCRIPT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "3 Chakra", components: "HS, CM, CS", duration: "Permanent", description: "You take a Chakra Seal and write upon it as you imbue your chakra into the parchment. For the duration, you and any creatures you designate when you cast the jutsu, can see the writing as it should be. To all others, the writing appears as if it were written in an unknown or foreign script that is unintelligible. Alternatively, you can cause the writing to appear to be an entirely different message, written in a different hand and language, though the language must be one you know. Should the jutsu be dispelled, the original script and the illusion both disappear. A creature with chakra sight or truesight can read the hidden message.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cdaa94c9edd0af3ab6aed9fc", name: "IMPERFECT SILENCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet (15 Foot radius Sphere)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "Select a space you can see in a 60-foot radius. All creatures in and attempting to enter a 30-foot sphere centering on your selected space must make an Intelligence Saving throw. Success: Affected creature is able to resist this Jutsu's effect being able to hear other creatures while within the spheres radius. Failure: Affected creatures becomes deafened and unable to hear other creatures who are also inside the spheres radius. If an affected creature leaves the radius this jutsu’s effect ends on them. Critical Failure: Affected creatures become deafened for the duration. A deafened creature must remake their intelligence saving throw at the end of each of their turns to end this jutsu’s effect on themselves.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d5697f4c95e1bca8fcd7f96b", name: "INEPTITUDE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You bend the minds of a target creature making them less capable than they once were. Select one creature that you can see within range. The target must make a Charisma saving throw. Success: Affected creature is able to resist this Jutsu's effect. Failure: Affected creature suffers a 1d6 penalty to attack rolls. Critical Failure: Affected creatures suffers a 1d8 penalty to attack rolls.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at B- Rank, increase the penalty by 1 die. If cast at S-Rank, increase the penalty by 2 dice.", created_at: NOW, updated_at: NOW },
  { _id: "f27ba8b78dddb76a0d4ef307", name: "INSINUATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You unleash a torrent of conflicting desires into the mind of one creature you can see within range, impairing its ability to make decisions. The target must make an Intelligence saving throw Success: Affected creature is able to resist this Jutsu's effect but still takes 1d12 Psychic damage. Failure: Affected creature takes 2d12 psychic damage and makes their chakra control check to maintain concentration at disadvantage. Critical Failure: Affected creatures takes 3d12 + Genjutsu Ability modifier psychic damage and loses concentration on a jutsu with the lowest cost they are currently concentrating on.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "b33a881f8227ee9358084bdb", name: "LIGHT BLINDNESS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You target a creature you can see in range and attempt to switch its brains perception of light. The target creature must make an Intelligence Save. If this jutsu is cast on a creature who is not benefiting from Bright Light prior to this jutsu’s casting, this jutsu gains the Unaware Keyword for the duration. Success: Affected creature is able to resist this Jutsu's effect. Failure: Affected creature treats Bright light as Dim light, and Dim light as total darkness for the duration. Critical Failure: Affected creatures treat Bright Light as total darkness for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets by +1.", created_at: NOW, updated_at: NOW },
  { _id: "1669c636cfdcc0001cd621d5", name: "LOST LIES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "15 Foot Cube", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "10 Minutes", description: "You bind your chakra to a Chakra seal and mark an area. Your chakra radiates in a 15-foot cube centering on the chakra seal you placed. For the duration of this jutsu, creatures that start their turn, or enter the Chakra seals area for the first time must make a Charisma saving throw. On a failed save, the creature cannot speak a deliberate lie while in the radius, instead being unable to speak at all when they attempt to do so. 171", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "48fb9e913b45ac6cc09361ef", name: "LOTUS: ANXIOUS PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "30 feet (10-foot cube)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Lotus petals, spreading them in a unique way. Select a space you can within range as you fill a 10-foot cube with a petal dance of revulsion. A creature who’s failed this jutsu’s save once before, cannot be affected again for 1 minute. As they flutter in front of you, all creatures within range must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures enters a state of panic. For the duration, creatures must spend its action to take the Dash action. At the end of an affected creatures turns, remake their saving throw, ending this effect on a success. If it cannot move or has a movement speed of 0, this jutsu immediately ends. Critical Failure: Same as failure, but the target must also spend its bonus action to make an Athletics check vs a DC 15, to gain an additional +10 movement speed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c617135bca16add0492a10c0", name: "LOTUS: BITTER PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 feet (5-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Lotus petals, spreading them in a unique way. Select two points you can within range as you fill two, 5-foot radius’s with a petal dance of bitterness. A creature who’s failed this jutsu’s save once before, cannot be affected again for 1 minute. As they flutter, all creatures within range must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature enters a bitter state of mind as for the duration, if a creature allied to themselves, within their movement speed range would take damage from an attack, they must spend their reaction to interpose the attack, becoming the new target. At the end of an affected creatures turns, remake their saving throw, ending this effect on a success. Critical Failure: Same as failure, but they gain an additional reaction which can only be used to interpose attacks targeting their allies.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ae51604e6e8cb495c08c4101", name: "LOTUS: CALMING PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (20-foot Cube)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Lotus petals, spreading them enough to fill a 20-foot cube originating from yourself in a dance of serenity. A creature who’s failed this jutsu’s save once before, cannot be affected again for 1 minute. As they flutter in front of you, all creatures within range must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature enters a calm and less hostile state, lacking a drive for combat. For the duration, calmed creatures cannot take a hostile action towards another creature. This jutsu immediately ends if another creature would attempt to take a hostile action towards another creature that this affected creature can see. This does not prevent them from acting in their self-interest, but instead only prevents them from directly engaging in hostile actions. Critical Failure: Same as failure, but this jutsu’s duration is increased to 10 minutes.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "42110ef683c1dda8308c32d3", name: "LOTUS: DANCING PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (10-foot radius)", chakra_cost: "4 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Lotus petals, spreading them around yourself in a dance of despair. Once this jutsu is cast, you cannot cast it again until the end of your next turn. As they flutter around you, all creatures within range must make a Charisma saving throw to realize they should hold their breath before inhaling the poisonous pollen. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects, but still takes 2d6 poison damage. Failure: Affected creature inhales a mass of poisonous petal pollen taking 3d6 poison damage and are begin to cough and retch in an attempt to remove the pollen from their breathing passages. Creatures who failed this save lose concentration of any Ninjutsu they are concentrating on for the duration. As an action on an affected creatures turn, they can make a Constitution check vs a DC 13. On a success, this jutsu’s effects end. Critical Failure: Same as failure, but if the target attempts the ability check to end its effects, all creatures who are currently unaffected by this jutsu, within 10 feet of the retching target must also make the DC 11 Constitution ability check. On a failure, they suffer the effects of this jutsu’s failure. On a success, they suffer no effects. 172", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "318211a51204040d023a1cdc", name: "LOTUS: FURIOUS PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (20-foot Cone)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Lotus petals, spreading them in a wide cone originating from yourself in a dance of anger. Once this jutsu is cast, you cannot cast it again until the end of your next turn. A creature who’s failed this jutsu’s save once before, cannot be affected again for 1 minute. As they flutter in front of you, all creatures within range must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature enters an enraged state, full of anger and fury. For the duration, enraged creatures must upcast all jutsu cast to its highest possible rank. If a jutsu cast does not have the ‘At Higher Ranks’ language, they instead increase the cost of the jutsu cast by +3. Affected creatures can spend an Action on their turn attempting to calm down, by making a DC 13 Charisma ability check. On a success, this jutsu ends. Critical Failure: Same as failure, but the DC to end this effect is increased to 16.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6a56c38fbc772b6edc5fb9dc", name: "LOTUS: GLOOM PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Lotus petals, throwing them in a straight line in a dance of gloom. A creature who’s failed this jutsu’s save once before, cannot be affected again for 1 minute. As they flutter in front of you, all creatures within range must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature enters a gloomy state of mind as for the duration, they cannot cast jutsu that would grant creatures other than itself a bonus to attack, damage, speed, skill or ability checks. If they are currently concentrating on such a jutsu, they lose concentration on it. Affected creatures can spend its Action to make a DC 13 Wisdom ability check to end this jutsu’s effects on them. Critical Failure: Same as failure, but this jutsu’s duration is increased to 10 minutes.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0fff27e4d9f239690b179d69", name: "LOTUS: GUILTY PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Bonus Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Round", description: "You grasp a hand full of poisonous Lotus petals, spreading them in a unique way by throwing them against a creature you can see within range. As they flutter, the target creature must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature enters a guilty state of self- loathing. For the duration, creatures cannot lie and must answer any questions as truthfully as possibly. If asked a question, it spends it Action answering the first question it is asked. Creatures can only ask questions on their turn. This jutsu then ends. Critical Failure: Same as failure, but they also must spend their bonus action answering the second question asked.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "53f7f51c65b8cdd23f8753da", name: "LOTUS: PANICKED PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when you see a hostile creature attempt to Interrupt an allied creatures.", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Round", description: "You grasp a hand full of poisonous Lotus petals, spreading them in a unique way throwing them against a creature you can see attempting to interrupt the casting of another creatures jutsu. This jutsu’s casting is treated as an attempt to Interrupt a creatures jutsu. As they flutter, select creature in range must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects, but still increases the cost of the jutsu they cast by +3 Failure: Affected creature increases the cost of the jutsu they cast by +6. Critical Failure: Affected creature increases the cost of the jutsu they cast by +9.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the cost of the affected creatures jutsu by +2. 173", created_at: NOW, updated_at: NOW },
  { _id: "6e04c0ca381c3f3e3c0084c6", name: "LOTUS: REVILED PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 feet (10-foot Cube)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Lotus petals, spreading them in a unique way. Select two points you can within range as you fill both 10-foot cubes with a petal dance of revulsion. A creature who’s failed this jutsu’s save once before, cannot be affected again for 1 minute. As they flutter in front of you, all creatures within range must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature enters a state of repulsion. For the duration, affected creatures refuse effects that would grant them temporary hit points or healing. Affected creatures can spend its action to make a DC 13 Intelligence check to ends its effects to see through their own thoughts. Critical Failure: Same as failure, but the ability check DC to end this jutsu is increased to 16.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a5ce00e4c4e33868cda1c9b5", name: "LOTUS: SHAMEFUL PETALS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 feet (5-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Lotus petals, spreading them in a unique way. Select two points you can within range as you fill two, 5-foot radius’s with a petal dance of bitterness. A creature who’s failed this jutsu’s save once before, cannot be affected again for 1 minute. As they flutter, all creatures within range must make a Charisma saving throw to as the pollen begins to affect their emotional state. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature enters a shameful state of mind as for the duration, unable to gain the benefit of jutsu based Damage reduction. An affected creature remakes this saving throw at the end of each of its turns, ending this jutsu’s effects on a success. Critical Failure: Same as failure, but they also cannot gain the benefit of bonuses to AC as a result of Jutsu. MEDICAL RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e8a1e55fb5330be59fca6a15", name: "HEALED THOUGHTS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a restorative illusion designed to help soothe the mental scars of battle. Select one Mental or Sensory condition a creature is under the effects of and reduce it by 1 rank.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of conditions with different names this jutsu can select by +1.", created_at: NOW, updated_at: NOW },
  { _id: "217c7fb3c50787f9bf5dc3f8", name: "MIND MIST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit)", duration: "Concentration, up to 1 minute", description: "You release a mist formed of illusory chakra as you suppress the targets mental combat potential. One creature of your choice within range must make a Wisdom saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature becomes poisoned and reduces the damage they deal by 1d6 for the duration. Critical Failure: Affected creature becomes poisoned and reduces the damage they deal by 1d8 for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage reduction by 1d6 or 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "0ba1e3b6bf431453803b2384", name: "NIGHT: BITTER DARKNESS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Reaction, which you take when a hostile creature casts a jutsu that affects an area with any shape.", range: "90 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a potent but powerful sense of loneliness and solitude in the form of illusionary chakra, and impose it on a hostile creature you can see in range who is casting a jutsu with range. The target creature must make an Intelligence saving throw. This counts as Interrupting this jutsu’s casting. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s secondary effects until the end of your next turn. Success: Affected creature is able to resist this jutsu’s negative effects. Failure: Affected creatures jutsu they are casting has its shape size reduced by a set size. Sphere/Radius, Cube, Cone, Line: 10 feet, and Cylinder: 5 Feet width, 10 feet height, down to a minimum of 5 feet for any effect area. Critical Failure: Same as failure, but the targets jutsu effect area size is reduce by an additional 10 feet. 174", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the jutsu’s effect area size reduction by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "3797228f2eb46913e2d16978", name: "NIGHT: BITTER FEELINGS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Reaction, which you take when an hostile creature gains a rank of a Mental or Sensory", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a potent but powerful sense of spite or hatred in the form of illusionary chakra, and impose it on a hostile creature you can see in range who has just gained a rank of either a Mental or Sensory condition, that can have more than 1 rank. The target creature must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s secondary effects until the end of your next turn. Success: Affected creature is able to resist this jutsu’s negative effects. Failure: Affected creatures gains 1 additional rank of the same condition. Critical Failure: Same as failure, but the target instead gains 2 additional ranks of the same condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0e0783266d23efeaf7441001", name: "NIGHT: BITTER LIGHT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Reaction, which you take when a hostile creature casts a jutsu that affects a single target.", range: "60 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a potent but powerful sense of friendliness or comradery in the form of illusionary chakra, and impose it on a hostile creature you can see in range who is casting a jutsu with range. The target creature must make an Intelligence saving throw. This counts as Interrupting this jutsu’s casting. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s secondary effects until the end of your next turn. Success: Affected creature is able to resist this jutsu’s negative effects. Failure: Affected creatures must select a new target, even if this means they would have to select a creature allied to them. They cannot select the same creature they previously did to trigger this jutsu’s reaction. Critical Failure: Same as failure, the target must now select a creature allied to themselves, even if a creature hostile to it is also in range.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bf02f5a15b70403d7fa51a05", name: "NIGHT: BITTER REACTIONS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Reaction, which you take when a hostile creature would take damage.", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a potent but powerful sense of sluggishness in the form of illusionary chakra, and impose it on a target creature you can see in range who has taken damage. This reactions effects takes place before the target creatures reaction-based effects, if any. The target creature must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s effects until the end of your next turn. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creatures thought speed is reduced. They become unable to take reactions until the end of the current turn. Critical Failure: Same as failure, but they cannot take reactions until the beginning of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c0f3f6a064bf21020e68d0c6", name: "NIGHT: BITTER VENGEANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when an allied creature takes damage.", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a potent but powerful sense of hyper aggressiveness in the form of illusionary chakra, and impose it on an allied creature you can see in range who has taken damage, excluding yourself. They gain a boost to their aggressiveness, increasing their bonus to attack and damage rolls by 1d6 until the end of their next turn. At the conclusion of their next turn though, they suffer a bit of psychosis, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s secondary effects until the end of your next turn. Success: Affected creature is able to resist this jutsu’s negative effects. Failure: Affected creature suffers a small but painful feedback, taking 2d6 psychic damage. Critical Failure: Same as failure, but they also gain a 1d6 penalty to their attack and damage rolls until the end of their next turn. 175", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1fd50a2acaec340188d652e7", name: "NIGHT: FRIGID PAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a blade of chilling illusionary chakra to strike through a targets senses, impeding them temporarily. Make a melee Genjutsu attack again a creature you can see within range. On a hit, you deal 4d6 psychic damage and force them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s secondary effects until the end of your next turn. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creatures senses are damaged. They gain 1 rank of Concussed. Critical Failure: Same as failure, but they instead gain 2 ranks of Concussed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and the number of targets by +1.", created_at: NOW, updated_at: NOW },
  { _id: "8ae01ee025fb1294b7176499", name: "NIGHT: FRIGID SIGHT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You manifest an aura of chilling illusionary chakra centered on you affecting all creatures of your choice within range forcing them to make an Intelligence saving throw. If the target has Chakra sight, they do not gain advantage on this saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s effects for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: If the affected creature has Chakra sight or Darkvision, they gain 2 ranks of Dazzled while inside of the radius of this jutsu so long as they are gaining the benefits of said special senses, as the illusionary chakra overwhelms their visual senses. Critical Failure: Same as failure, but affected creatures also lose Chakra sight or Darkvision for the duration of this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e409b4bb37d82d2a94ef5eeb", name: "NIGHT: FRIGID THOUGHTS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (25-foot cube)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You manifest a shockwave of chilling illusionary chakra from your voice, influencing the thoughts of creatures in range affecting all creatures of your choice in a 25-foot cube, originating from you within range forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s effects for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature is overwhelmed by the illusionary chakra, as they find it difficult to think and thus cannot think a full thought through without being assailed by slowed ideas. They gain 1 rank of Slowed for the duration. Critical Failure: Same as failure, but they also gain 1 rank of Dazzled for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cube by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "97066cba2fb52baaf6e44a3a", name: "NIGHT: FRIGID TOUCH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You manifest a beam of chilling illusionary chakra from within yourself, affecting all creatures of your choice in a 5-foot wide, 30-foot line, originating from you within range forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s effects for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature is overwhelmed by the illusionary chakra, as they find it difficult to feel and thus cannot distinguish pain from healing. The next Genjutsu that would affect them for the duration, gains the Unaware keyword, this jutsu then ends. Critical Failure: Same as failure, but they also take 3d6 psychic damage at the beginning of each of their turns for the duration. A creature who critically failed this jutsu’s saving throw remakes its save at the end of each of its turns, ending this jutsu’s critical failure damage on a success. 176", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7d9c08fd5722a9c59851da6a", name: "NIGHT: FRIGID WORDS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Self (20-foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You manifest a wave of chilling illusionary chakra from your words alone, affecting all creatures of your choice within range forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s effects for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature is overwhelmed by the illusionary chakra, as they find it difficult to hear and thus are distracted. They become Deafened to all sound not originating from you. Critical Failure: Same as failure, but affected creatures also gain a 1d4 penalty to all saving throws against Genjutsu with the Auditory keyword for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b2fad64243451aea98afcf6b", name: "NIP AT THE HEELS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You slam your hands onto the ground creating an illusory puff of smoke as a pack of wild dogs that look aggressive rush in and nip at one creature you can see within range, which must make an Intelligence saving throw. A target that is at least 10 feet off the ground (in a tree, flying, and so forth) or has any senses, features or active jutsu that would give it advantage to its Wisdom (Perception), has advantage on the saving throw. Success: Affected creature is able to resist this Jutsu's effect. Failure: Affected creature has disadvantage on Attack rolls and skill checks against one other creature of your choice as it becomes distracted by the attacking dogs. At the end of each of its turns, the target remakes its saving throw, ending the effect on itself on a successful save. Critical Failure: Same as Failure and the affected creature(s) who would cast a jutsu with the Hand Sign (HS) or Mobility (M) components would take 2d8 psychic damage as the dogs bite into them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "24c179184ce0033606d0e404", name: "PAINFUL VISION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You target one creature you can see within range as you begin to intensify their sensitivity to light. The target creature must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this Jutsu's effect. Success: Affected creature is able to resist most of this jutsu’s effects but gains sunlight sensitivity, causing them to suffers a -2 penalty to Attack rolls while in bright light until the end of their next turn. Failure: At the beginning of an affected creatures turn that they take 2d8 + your Genjutsu ability modifier in psychic damage. If they are in dim light, they instead take 2d6 + your Genjutsu ability modifier in psychic damage. At the end of each of the affected creatures turns they remake the saving throw, ending this jutsu on a success. Critical Failure: At the beginning of an affected creatures turn that they take 3d8 + your Genjutsu ability modifier in psychic damage. If they are in dim light, they instead take 3d6 + your Genjutsu ability modifier in psychic damage. At the end of each of the affected creatures turns they remake the saving throw, ending this jutsu on a success. If they are in bright light, they remake their saving throw at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8 or 1d6, and the number of creatures you can target by +1. 177", created_at: NOW, updated_at: NOW },
  { _id: "c417dcc4688f0917a4541aa7", name: "PAINFUL VOICE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (30-Foot Cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You cup your hands and scream through the opening on the other end. All creatures that can hear you in a 30-foot cone originating from you must make a Wisdom Saving throw. Critical Success: Affected creature is able to resist this Jutsu's effect. Success: Affected creature is able to resist most of this jutsu’s effects but becomes deafened until the end of their next turn. Failure: Affected creature takes 4d6 psychic damage. Critical Failure: Affected creature takes 4d8+Genjutsu ability modifier psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 or 1d8 and the range by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "4033591e2ab8a9d40598e1f4", name: "PHANTOM LIGHT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "3 Chakra", components: "HS, CM", duration: "1 Hour", description: "You touch a single object that measure less than 10 feet in every dimension. Until this Jutsu ends, you and up to 3 other creatures can see Bright light originating from that object in a 20-foot radius, and dim light for another 20 feet. The light can be colored as you like. Only you and the selected creatures can gain benefit from this artificial light source. You can use your bonus action to dismiss this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of objects you can affect with this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "2cf03e969b0a6682b069ece0", name: "PSIONICS: ASSURANCE!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when you see a hostile creature take damage", range: "60ft", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant.", description: "You see a creature take damage, and can see the impact it leaves. You take this opportunity to ensure that the damage dealt, sticks. The triggering creature must make an Intelligence saving throw. Success: Affected creature is able to resist most of this jutsu’s effects, taking 2d6 psychic damage. Failure: Affected creature takes an amount of psychic damage equal to Xd6, where X equals your Genjutsu ability modifier. Critical Failure: Affected creature suffers the effects of a failure and becoming Slowed until the end of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e3eaf09c9da6b6818e93760f", name: "PSIONICS: BRAIN LOCK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You attempt to lock a targets thoughts, into a never-ending cycle of circular thought, always ending on its previous answer. Select one hostile creature you can see and reach within range, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature must spend its action, on each of its subsequent turns recasting the same jutsu (of your choice), it cast on its previous turn. If the target did not cast a jutsu on its last turn, this jutsu immediately ends. This creature remakes its saving throw at the end of each of its turns, ending this jutsu on a success. Critical Failure: Same as failure, but also the creature gains a 1d4 penalty to its first saving throw to end this jutsu’s effects on it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "076a5b1a62075d91ad909495", name: "PSIONICS: CONFUSION!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You attempt to shatter the string of thought a creature has, instilling severe confusion while also causing them mental pain through inconsistency. Select one target within range. They must make a Wisdom saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature gains 1 rank of Confusion. Critical Failure: Affected creature gains 1 rank of Confusion, and the first check made to end the condition is increased by 2.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. 178", created_at: NOW, updated_at: NOW },
  { _id: "255007745f13e9733f647928", name: "PSIONICS: CUT!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest blades formed of illusionary chakra, that rend through a creatures mental defenses. Make a ranged Genjutsu attack dealing 4d8 psychic damage. If this jutsu is cast while within 10 feet of the target creature, increase the critical threat range of this attack by +1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8. If this jutsu is cast at B-Rank, increase the critical threat range by +1. If this jutsu is cast at S- Rank, increase the critical threat range by +2.", created_at: NOW, updated_at: NOW },
  { _id: "689476853c0bf9a45f4ce5af", name: "PSIONICS: DELAY!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a delayed sound that remains humming for a few moments before vanishing. You then select one creature whom you can see within range. At the end of your next turn this jutsu takes effect. If the target creature has cast a jutsu of any type on their next turn, they take 3d12 psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "062ff86a3905678090930055", name: "PSIONICS: DRAIN!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minute", description: "You attempt to drain the mental power of a hostile creature you can see, making it more difficult for them to think clearly in the moment. Select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: The hostile creature takes 3d6 psychic damage, and suffers a 1d4 penalty on all Intelligence based attack rolls and skill checks for the next minute. Critical Failure: Same as Failure, but damage is increased to 5d8.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and 1d8, respectively.", created_at: NOW, updated_at: NOW },
  { _id: "66c210e8dabbe5218490bef0", name: "PSIONICS: EXPOSE WEAKNESS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You attempt to expose the weakness of your foes by making them unconsciously expose themselves. Select one creature you can see within range, forcing them to make an Intelligence Saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature immediately begins to move in unnatural and clumsy ways. Attacks targeting the creature gains a 1d4 bonus to hit, once per turn, per creature. Critical Failure: Same as failure, but they also reduce their AC by 1, for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "f494834066589ec92c0486ff", name: "PSIONICS: FALSE FUTURE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You attempt to force a vision of a false future onto a target, causing them to make a poorly informed decision. Select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: The hostile creature must spend its reaction, to move no less than 30 feet, if it can, into a space it would move into if its turn were right now. Critical Failure: Same as failure, but its movement speed it reduced by half after its movement ends, until the end of its next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures this can target by +1. 179", created_at: NOW, updated_at: NOW },
  { _id: "bf1c09574ca3592e873aa1a0", name: "PSIONICS: FORTRESS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a suit of illusionary armor. This armor grants you a +1 bonus to your AC. If you would be the target of a Genjutsu attack, you instead treat this bonus as a +2. If a creature manages to score a hit with a melee weapon or taijutsu attack against you, you force them to make an Intelligence saving throw as you send back a psychic feedback. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature immediately falls prone and drops their weapon, if any. This does not prevent damage. This Jutsu then ends. Critical Failure: Same as failure, but their movement speed is also reduced to 0, until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, you gain 5 Psychic Damage reduction for this jutsu’s duration. If this jutsu is cast at S-Rank, you gain 10 Psychic Damage reduction for this jutsu’s duration.", created_at: NOW, updated_at: NOW },
  { _id: "1609c1a253f8e35be7b66885", name: "PSIONICS: HOSTILE TRANSFER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You attempt to transfer the negative mental conditions of an allies creature to a hostile one. Select one allied creature you can see within range who has ranks of a Mental condition. When you do, select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: The Hostile creature gains one of the Mental conditions the allied creature has, (your choice) Critical Failure: The hostile creature gains all Mental conditions the allied creature has, and the allied creature loses each mental condition the hostile creature gains.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of hostile creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "a41117c30979e5b3f8282c4b", name: "PSIONICS: MEDITATE!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You steady your thoughts, finding balance and inner peace in the moment of battle. For the duration, you gain a 1d4 bonus to Genjutsu attacks and deal an additional 1d6 psychic damage with Genjutsu you cast.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the to hit and damage bonus by 1 die step (1d6, 1d8). If this jutsu is cast at S- Rank, increase the to hit and damage bonus by 1 die step (1d8, 1d10).", created_at: NOW, updated_at: NOW },
  { _id: "c8343db66e7687df4716cc6c", name: "PSIONICS: MIGRAINE!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You outstretch your hand and select a target within range. The target creature must make an Intelligence saving throw. If their Intelligence ability score is 12 or less, they make this save at disadvantage. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature sees their body swell and experience an extraordinary amount of pain as their head feels like it will explode. They take 4d4 psychic damage and until the end of their next turn, they suffer a -10 penalty to their speed. Critical Failure: Affected creature sees their body swell and experience an extraordinary amount of pain as their head feels like it will explode. They take 6d4 psychic damage and until the end of their next turn, they suffer a -20 penalty to their speed and the next jutsu they cast and concentration cost they pay, cost is doubled, before the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d4 and the number of creatures they can target by +1. 180", created_at: NOW, updated_at: NOW },
  { _id: "928a30149f64b9b68396ba4d", name: "PSIONICS: MIND BLANK!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You weave a guttural and visceral sound that echoes outward designed to create pockets of blank space in the minds of the listener. Select a creature whom can hear you within range. The target must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this Genjutsu’s effects. Success: Affected creatures next jutsu cast increases its cost by +4 Failure: Affected creature becomes unable to cast a jutsu they cast on their previous turn. If they would attempt to cast such a jutsu, it fails. Critical Failure: Affected creature becomes unable to cast a jutsu they cast on their previous turn. If they would attempt to cast such a jutsu, it fails, and they suffer a splitting migraine taking 5d6 psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "f52f7505f579b4287b6746d6", name: "PSIONICS: PSYCHO WAVE!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest gauntlet of formed of illusionary pulses, that beat on the thought patterns of a creature, leaving it mentally drained. All creatures within a 15-foot cone originating from you must make a Wisdom saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature is Dazzled and Confused. Critical Failure: Affected creature is Dazzled, Confused and Concussed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "a97a3867b18fc9bab3b388d5", name: "PSIONICS: PULSE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (20 –feet)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a pulse of thought, meant to inflict pain and disorient everyone near you. All creatures of your choice, within range must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 3d4 psychic damage and is forced to move back 10 feet away from you. Critical Failure: Affected creature takes 5d4 psychic damage and is forced to move back 25 feet away from you.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage by 1d4 and radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "e4f28221033c56c208a3c9c1", name: "PSIONICS: RANGE CRIPPLING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You attempt to reduce a creatures effective combat range by clouding their vision and imposing visual limitations upon them Select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature gains 2 ranks of Dazzled for the duration. Ranks of Dazzled inflicted by this jutsu does not go away at the end of the affected creatures turns, instead only going away when this jutsu ends Critical Failure: Same as failure, but also if the creature would cast a jutsu or make an attack with a range, greater than 15 feet, reduce the range of the jutsu or attack by 10 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures this can target by +1 and the range reduction of a critical failure by 5 feet. 181", created_at: NOW, updated_at: NOW },
  { _id: "6dae8fdf5e281782ac94747b", name: "PSIONICS: SHARED THOUGHTS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You attempt to see into and share the thoughts of a creature you can see, seeing what they are thinking or planning. Select one creature you can see within range, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Additionally, they become aware someone tried to peer into their mind. Success: Affected creature is able to resist this jutsu’s effects. Failure: The hostile creature begins to unknowingly share their thoughts with you. At the beginning of each of its turns, the DM informs you of the jutsu they are casting, actions they are taking or the thoughts it has during its turn only. If the target would cast a jutsu or make an attack, you gain the benefit of a successful Read the Enemy reaction. At the end of each of the targets turns, it remakes it saving throw, while still unaware it is sharing thoughts with you. Critical Failure: Same as Failure, but the target does not get to remake its saves until it becomes aware it is under the effects of this Genjutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e23af340197965e9a52491b6", name: "PSIONICS: SHOCK!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You release a powerful jolt of psionic chakra meant to overwhelm the sensory receptors of a creature. One creature of your choice within range must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 6d4 psychic damage. This damage ignores Resistance and treats Immunity as resistance. Critical Failure: Affected creature takes 6d6 psychic damage and becomes Dazed. This damage ignores Damage Reduction and ignores Resistance and treats Immunity as resistance.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d4 or 1d6 or the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "c136325a5dd7667d35de88c9", name: "PSIONICS: STRIKE!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You coat the hands and feet of a creature you touch in psionic energy. Making each strike harm both the body and mind simultaneously. When they would deal damage with an unarmed attack, they deal an additional 1d10 psychic damage, once per turn. If they would score a critical hit while gaining the benefits of this jutsu, you can choose to convert all damage dealt with the attack into psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "6ef6f6ef416e991bdbe96d00", name: "PSIONICS: SUPPRESS FOCUS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You attempt to force a creature gaining the benefit of a buff of any type, to no longer benefit from that buff. Select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: If the target is under the effects of Jutsu that grants it a bonus to attacks, damage, AC, skill checks or ability checks, select one of the aforementioned statistics. It has the chosen benefits suppressed, becoming unable to gain that boost to the chosen statistic for the duration. Critical Failure: Same as failure, but instead of one statistic, they cannot gain a jutsu based bonus to any of the listed statistics for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures this can target by +1. 182", created_at: NOW, updated_at: NOW },
  { _id: "6bd462d6580cd8e22bc2d49e", name: "PUPPETS OF DARKNESS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You weave chakra creating animated illusions of a creatures shadow within range, causing it to attack. As a bonus action, when you cast this jutsu or as a bonus action on subsequent turns, while you maintain concentration, command the shadow to attack. Make a Melee Genjutsu attack against a target creature. On a hit, you deal 2d10 psychic damage and they must make an Intelligence saving throw, being dazed until the start of your next turn on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you target with this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "feb686348f6910ea4dae05ee", name: "SANCTUARY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Bonus Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 minute", description: "You weave chakra creating a hazy ward of illusions protecting a creature within range against attack. Until this jutsu ends, any creature who targets the warded creature with an attack or a jutsu must first succeed a Wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or jutsu. This ward does not protect against area effects, such as a Fire Release: Fireball or any similar jutsu. If the warded creature makes an attack or casts a jutsu that affects a creature, this jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you target with this jutsu by +1. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "c942d2bce14a7cd0f0339a92", name: "DELUSIONS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You infuse chakra into chakra seals as you attempt to mark a creature you can see in range with the seal of the desires. The target creature must make a Charisma Saving throw. On a failed save, the target is marked with the seal of desires as they begin to see flashes and visions of the things they want most in life causing them to freeze in place, focusing on the things before them. For the duration, a creature who is marked with this seal, at the beginning of each of their turns remake the saving throw, being stunned until the end of their turn on a failed save. On a successful save, they resist the seals effects, ending this jutsu. If the target would take damage, they repeat the saving throw to end this jutsu. Another creature who can touch the affected target, can attempt a Wisdom (Illusions) check vs your Genjutsu save DC to forcefully end this jutsu on them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If Cast at B-Rank, increase the number of creatures you target with this jutsu to 2. If Cast at S-Rank, increase the number of creatures you target with this jutsu to 3. SEALING ART:", created_at: NOW, updated_at: NOW },
  { _id: "9cd05cebb8804b8332959f40", name: "SWEET DREAMS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You infuse chakra into chakra seals as you attempt to mark a willing creature you can see in range with the seal of the rest. For the duration, as a bonus action you can force the creature to experience a hyper accelerated sleep pattern. The target creature gains some of the benefit of a short rest allowing them to spend hit die to recover hit points. The affected creature does not regain any features or resources that would reset or be recovered on a short rest.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you target with this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "a2e81e560887c33055b32c3a", name: "SEMBLANCE OF DREAD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You morph your visage into that of a faceless monstrosity known as Nyarlathotep. This visage can be of your own description as this monstrosity has no known singular description. For the duration, any creature within 20 feet of you becomes unable to willingly move closer to you unless it makes a successful Wisdom saving throw at the start of its turn. Constructs and undead are immune to this effect. Additionally, you gain advantage on saving throws to resist the fear condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the radius by 5 feet. 183", created_at: NOW, updated_at: NOW },
  { _id: "ed01566518f1d94abdd2df3c", name: "SHADOW BITE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You create a single momentary needle of darkness that erupts upwards from a creatures shadow that you can see within range. Make a ranged Genjutsu attack. On a hit you deal psychic damage equal to 4d6 + Your Genjutsu ability modifier and reducing their speed by 10 until the start of your next turn. A creature who’s speed is reduced in this way cannot benefit from additional speed for the duration of their speed reduction.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you can target by +1, the damage by 1d6 and the speed reduction by -5.", created_at: NOW, updated_at: NOW },
  { _id: "178ffe5552b247731be8d2f1", name: "SILENT IMAGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15- foot cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn’t accompanied by sound, smell, or other sensory effects. You can use your action to cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Physical interaction with the image reveals it to be an illusion, because things can pass through it, causing the Genjutsu to immediately end.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c76efda900493a2ec34e83f7", name: "SILHOUETTE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "100 feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You create a shadow play against a screen or wall. The surface can encompass up to 100 square feet and does not have a singular point of origin, instead making use of all the shadows that mundane objects and structures give off. The number of creatures that can see the shadow play equals your Genjutsu ability modifier. The shadowy figures make no sound but they can dance, run, move, kiss, fight, and so forth. Most of the figures you can create are based on creatures you may have seen before.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1b511477f0a7faceafd3d2b8", name: "SOFT SPOKEN SONG", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You begin to hum a tune or speak a phrase of your choice. When you do, all willing creatures within 30 feet of you begin to feel revitalized by your melody. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Creatures who begin their turns within range, gain advantage on Saving throws to resist Genjutsu with the Auditory Keyword, regardless of any other keywords the Jutsu may have. Additionally, Genjutsu with the Auditory and Unaware Keywords, lose the unaware keyword when affecting creatures benefiting from this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9519c4c3eeb9695b86b7e2d4", name: "SONG OF THE ANCIENTS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "self (20-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You begin to hum or sing an erratic tune in an unintelligible language designed to send those who hear it into a short bout of madness. When you do, all creatures within a 20-foot radius of you begin to experience bouts of madness. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Creatures who begin their turns within range must make an intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature gains the madness condition until the end of their next turn. Critical Failure: Affected creature gains the madness condition for 1d4 of their turns.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the radius by 5. 184", created_at: NOW, updated_at: NOW },
  { _id: "873975aecd6d0d81ba5ba7e8", name: "SOUNDLESS, BLINDING ECHO", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "self (30 Foot Cone)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You scream in a silent misleading roar, you then cup your hands around your mouth while screaming. All creatures of your choice in a 30-foot cone in front of you, must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this Jutsu's effect. Success: Affected creature is able to resist most of this jutsu’s effects but becomes deafened until the end of their next turn. Failure: Affected creature takes 2d6 psychic damage and becomes blinded. At the end of each of its turns the target can make another saving throw to end this effect. Critical Failure: Affected creature becomes blind on a failed save. At the end of each of its turns the target can make another saving throw to end this effect. The creature also takes 4d6 psychic damage the turn they fail the save and 4d6 psychic damage at the beginning of the casters next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f3334e712a136ee5f79d0f9c", name: "STARTLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You weave together an image designed to startle and scare a creature but for a moment. Select one creature you can see withing range, target must make a Charisma saving throw. A creature immune to being frightened is immune to this jutsu’s effects. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature is spooked ending concentration on one jutsu it is concentrating on with the highest base cost. Critical Failure: Affected creature is spooked ending concentration on all jutsu it is concentrating on.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "a5d90de282288d6e6794f69b", name: "THOUGHT FILM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when you take psychic damage.", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a psychic barrier designed to protect your mind from the harm another creature would inflict on it. When you would take psychic damage, you reduce the damage taken by 3d6. Additionally, you gain a 1d4 bonus to saving throws made to resist a Genjutsu’s effect, if any.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage reduction by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "1428de79af34ab0d76e1cb24", name: "THOUGHT REJECTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when you would take damage.", range: "90 feet (10-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You take a snapshot of the pain you feel, and attempt to inject it into the mind of a creature within range. Select a point you can see within range, where you send your psychic projection, which then explodes affecting all creatures within 10 feet of the chosen point. All affected creatures must make a Wisdom saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 4d6 psychic damage. Critical Failure: Affected creature gains 1 rank of Dazzled and takes 4d6 psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "e13b4ea1df58d3610183d94f", name: "UNBOUND LAUGHTER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM, NT (Laughing Powder)", duration: "Concentration, up to 1 minute.", description: "A creature of your choice that you can see within range, perceives everything as extremely funny and falls into a fit of laughter if this jutsu affects it. The target must make a Wisdom save. If the creature is damaged the jutsu ends immediately. A creature with an intelligence score of 4 or less is unaffected. A creature with a wisdom score of 15 or more makes its save with advantage. Critical Success: Affected creature is able to resist this Jutsu's effect. Success: Affected creature is able to resist most of this jutsu’s effects but becomes unable to take reactions until the beginning of its next turn. Failure: Affected creature succumbs to a fit of laughter falling prone and being unable to take reactions. A laughing creature remakes its saving throw at the end of each of its turns to end this jutsu’s effects. Critical Failure: Affected creature falls into a fit of laughter falling prone and becoming incapacitated. A laughing creature remakes its saving throw at the end of each of its turns to end this jutsu’s effects. 185", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "975a090f4d1739e02f154057", name: "UNGLAMOROUS FACE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 Minutes", description: "A willing creature you touch, has its face twisted until it becomes as mundane as possible. So much so that they become absolutely un-unique and incapable of standing out. For the duration, they become unrecognizable and become unable to be pointed out in a crowd. A creature attempting to see through this illusion must make a Wisdom (Insight) or Wisdom (Illusions) check vs your Genjutsu Save DC. On a success, they become immune to this genjutsu’s effects for the next hour.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a938d06f2c5534ccffbc6c7b", name: "VIPERS GRIP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "3d7fe1bb5775caf4818c287e", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit)", duration: "1 Minute", description: "You release an odorless poison into the air spending 1 charge of your Poison Kit and affecting creatures within 30 feet of you who inhale it. Creatures within range, must make a Wisdom saving throw. If an Envenomed creature is cured of the envenomed condition inflicted by this jutsu, this jutsu immediately ends. Critical Success: Affected creature is able to resist this Jutsu's effect becoming immune to it for the next 24 hours. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature becomes envenomed for the next minute and begin to see glimpses of snakes and other reptilian beasts converging on them. At the beginning of an envenomed creatures turn they must make a Wisdom (Acrobatics) check vs your Genjutsu Save DC. On a failed check they are restrained by the snaked until the beginning of their next turn. Critical Failure: Affected creature becomes envenomed for the next minute and begin to see glimpses of snakes and other reptilian beasts converging on them. At the beginning of an envenomed creatures turn they must make a Wisdom (Acrobatics) check at disadvantage vs your Genjutsu Save DC. On a failed check they are restrained by the snaked for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b94479a91ad2f85444f001ad", name: "WEAPONS OF DARKNESS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure daggers made of darkness and fear. When they strike a target creature it instills them with a terrible sense of dread. The blade is similar in size and shape to a Kunai, and it lasts for the Duration. These daggers are simply illusions but feel extremely real if they strike a creature. You can throw them up to 60 feet before they dissipate. You can spend your action to Make a melee or ranged Genjutsu attack against a target creature in range. On a hit, the target creature takes 5d4 Psychic damage. If you throw the illusionary dagger, it dissolves and reforms in your hand after colliding with a creature or surface.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is Cast at C-Rank or higher, increase the damage by 1d4. If this jutsu is cast at B-Rank, you can make two attacks instead of one. If this jutsu is cast at A-Rank or higher, you may add your Genjutsu ability modifier to the damage dealt. If this jutsu is cast at S-Rank, you can make three attacks instead of one. C-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "6a5bc60439f8c1d3ff442876", name: "ABHORRENT APPARITION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant.", description: "You weave a collection of handseals conjuring a large incomprehensible monstrosity known as Mh'ithrha that hovers above you. Select a number of creatures that you can see and that can see you within range, equal to your proficiency bonus. Each selected creature can see this monstrosity as its visage and design goes against all things rational and sane. The selected creature must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this Jutsu's effects becoming immune to it for the next minute cast from the same creature. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 4d6 psychic damage and gains 1 rank of Concussion. Critical Failure: Affected creature takes 4d6 + Genjutsu ability modifier psychic damage and gains 2 ranks of Concussion. 186", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "103010cf624ef1d7b03a6fb8", name: "ALIENATION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You manifest a pulse of illusory chakra that overwhelms a creature in an attempt to make it difficult for them to communicate or be communicated with. Select one creature within range, who must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu’s effects for 1d4 of its turns. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature loses the ability to communicated with or understand others for the duration. Critical Failure: Affected creature suffers the failure effect and also cannot carry weapons, chakra seals, or ninja tools effectively, becoming unable to use them for the duration.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the number of creatures this jutsu can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e4aec08a0f24c260e8ff1c0a", name: "BATTLE SENSE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (20 Foot-radius)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 minute", description: "You link the minds of all willing creatures within range. When you do, you manifest a type of heads-up display that appears in the mind of each creature. This display provides a litany of information on each other. Everyone affected by this jutsu shares the followings benefits; • Aware of any conditions affecting another creature while within 100 feet of one another. • Always aware of each other’s location from up to 1 mile away. • Can perform the help action as a Reaction, only with each other up to 30 feet away. If a creature affected by this jutsu performs the help action in this way, the helped creature gains one of the following benefits until the end of the helped creatures next turn. (The person who performed the help action as a reaction, chooses the benefit) o +1d4 bonus to their next attack roll. o +1d4 bonus to their next saving throw. o +1d6 bonus to their next skill check. o +2d6 psychic damage bonus to their next damage roll.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "934cdb78f20a70f1c9dafd09", name: "BLUR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minutes", description: "Your body becomes blurred, shifting and wavering to all who can see you. When cast, the triggering attack rolls an additional d20, taking the lower result. For the duration, until the beginning of your next turn, hostile creatures have disadvantage on attacks against you. An attacker is immune to this effect if it doesn't rely on sight, as with blindsight, or can see through illusions, as with truesight. 67 WIND RELEASE: BUFFETING AIRWAVES Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You create currents of extremely strong and compressed beams of air strong enough to Crack stone and divert waterfalls. Make a ranged ninjutsu attack. On a hit, target creature takes 4d4 Wind Damage and must make a Strength save. On a failed save they are pushed back 20 feet, knocked prone, gaining 1 rank of bleeding, and causing Swirl.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d4 and the ranks of bleed by +1 WIND RELEASE: COLLECTIVE GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 15 feet Duration: 1 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu, Medical Description: You collect wind release chakra and infuse it into your Medical Release technique. One willing creature within range breathes in this Medically infused wind. For the duration a creature who has breathed this wind does not need to breathe, Ignores the effects of 2 rank of Exhaustion and when they would regain hit points as the result of a Ninjutsu with the Medical Keyword, they regain an additional 1d4 Hit points. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, Ignores the effects of up to 1 additional rank of Exhaustion. WIND RELEASE: COUNTER BREEZE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage from a Ninjutsu or Taijutsu. Range: Self Duration: 1 Round Components: HS, CM, M Cost: 5 Chakra Keywords: Wind Release, Ninjutsu, Construct, Clash Description: You create a condensed bubble of super dense air around you in an attempt to deflect incoming attacks. Roll 3d8. The result of the roll is the amount of damage your air Bubble can prevent before it bursts. This lasts until the beginning of your next turn. Lightning Damage deals half as much damage to your air bubble and Fire Damage deals twice as much. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and roll an additional 1d8. WIND RELEASE: DUST WIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot Cone) Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You generate a strong wind from your lungs with a single breath. When you exhale you kick up a cloud of dust, dirt, and other loose debris in the target radius. Creatures who are in the affected range must make a Wisdom Saving throw. On a failed save, affected creatures cause Swirl and are considered blind until the end of their next turn on a failed save. On a successful save no further effects are applied. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 10ft WIND RELEASE: FEATHER FALL Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you begin falling. Range: Self Duration: 1 Minute Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You create a single high-pressure stream of air from either your hands or feet slowing your descent while falling by 60 feet per round until the jutsu ends. If you land before the ninjutsu ends, you take no falling damage and land on your feet and the jutsu ends. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select 1 additional target for this Jutsu’s benefits within 30 feet of you. WIND RELEASE: GALE PALM Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: HS, CM, M Cost: 4 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You clasp your hands together coating your open palms in a powerful gale. You make a Melee ninjutsu attack on a target creature or object. On a hit creature take 3d6 Wind Damage and make a Strength saving throw to resist being knocked back 20 feet and causing Swirl. On a successful Strength save they suffer no additional effects. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 68 WIND RELEASE: GRYPHONS WING BEAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (20-foot radius) Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You create two wings made of wind release chakra that beats with enough force to feel like a tornado is passing through. All creatures within range must make a Strength saving throw to resist being bruised, knocked prone and causing Swirl. A creature who is bruised finds it difficult to maintain concentrating on multiple jutsu. If a creature is concentrating on more than 1 jutsu, they must lose concentration on all but 1 jutsu. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the range by 10 feet. WIND RELEASE: LIONS GROWL Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 Minute Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You weave Wind Release Chakra together, creating a thin veil of chakra in the shape of a Lion around you. This chakra then collapses on you granting you benefits as listed below; • Increase your Movement Speed by 15 feet. • You gain a +2 bonus to Ninjutsu Attack Rolls. • Ninjutsu, you cast with the Wind Release Keyword that has a range of at least 5 feet, increases their range by 10 feet. WIND RELEASE: PALM VORTEX Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (10 Foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a localized vortex of cutting wind. All creatures within range must make a Dexterity saving throw to avoid being horrendously slashed. On a failed save creatures take 3d6 wind damage and being pulled 5 feet closer to you or half as much on a successful save and no additional affects. If a creature is currently affected by any elemental condition, you trigger the residual elemental energies, igniting them again. A creature under the effects of an elemental condition makes their saving throw at Disadvantage. On a failed save such a creature instead takes 3d8 + Your Ninjutsu Ability Modifier damage, of their select conditions type. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 or 1d8. WIND RELEASE: PASSING TYPHOON Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot radius sphere) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You create a powerful current of strong winds in a 15-foot radius sphere, centering on you. This field of wind also follows you. For the duration, while within its area, it deafens other creatures, extinguishes unprotected flames, becomes difficult terrain to creatures other than you and disperses vapors, gases and fogs that can be dispersed by strong winds. Additionally, ranged attacks have disadvantage if they pass into or out of the area of this jutsu. WIND RELEASE: PEACOCK WHIRLWIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30-feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You generate a strong wind from swiping one of your limbs. A gust of wind is generated in a 30-foot long 5-feet wide in a straight line originating from you. Creatures in the line must make a Strength saving throw, taking 2d6 wind damage, is knocked prone, gains 1 rank of bleeding and causing Swirl on a failed save, and only half damage and no further effects on a successful save. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the ranks of bleed by +1. WIND RELEASE: RAGING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet (15-foot radius) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You manifest a powerful torrent of wind, strong enough to lift and throw most creatures. Select a space you can see within range. A spiraling torrent of wind erupts upwards. All creatures within 15 feet of the chosen space, must make a Strength saving throw. On a failed save they are thrown 30 feet upwards being dazed, taking falling damage, falling prone and causing Swirl. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the height they are thrown upwards by 15 feet. 69 WIND RELEASE: RAGING VORTEX Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You encircle a willing creature with potent Wind Release Chakra. For the duration, you magnify the targets physical capabilities. The target creature adds 1d4 to all Strength and Dexterity skill checks and saving throws. Their movement speed is increased by 15 feet and melee attacks they make that deal damage deals an additional 1d6 Wind Damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets you can affect by +1. WIND RELEASE: SECOND WIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You breathe in deeply filling your lungs and blood with chakra filtered oxygen accelerating its blood flow and slightly rejuvenating you. You recover 2d6+ Your Ninjutsu ability modifier hit points. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and roll an additional 1d6. WIND RELEASE: SLICING AIRWAVES Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM, M Cost: 4 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a powerful current of extremely strong and thin currents of wind. You swipe your hand towards your target. Make a Ranged Ninjutsu attack, creatures take 3d8 wind damage and gain 1 rank of bleeding on a hit. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d8 and ranks of bleeding by +1. WIND RELEASE: SPLITTING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a field of oppressive and potent wind that slashes and buffets any instance of Hand Signs (HS). Select a space you can see within range, all creatures within 20 feet of the chosen space who would cast a jutsu with Hand Sign (HS) component immediately takes 2d6 Wind Damage and must make a Constitution Saving throw gaining the bleeding condition on a failed save. As a bonus action on your turn, you may move the field up to 30 feet in any direction to a space you can see within range. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the area affected by 5 feet, and the damage by 1d6. WIND RELEASE: SUPPORTING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction to making a Strength, Dexterity or Constitution saving throw Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You throw your hands forward creating a compressed blast of air assisting you in a variety of physical tasks; from escaping, fending off an attack, or dispersing a hazardous gas. As a reaction, when you are forced to make a Strength, Dexterity, or Constitution saving throw against a Ninjutsu or Taijutsu, you instead use your Ninjutsu ability modifier in place of your Strength, Dexterity or Constitution for the triggering roll. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at C-Rank you add your proficiency to the roll if you aren’t already proficient. If cast at B-Rank you may select another creature within 20 feet of you to gain the benefits of this jutsu, using your Ability modifier and proficiency bonus. If cast at A-Rank, creatures benefiting from this jutsu roll at advantage. If cast at S- Rank, all creatures of your choice within 30 feet of you can gain this jutsu’s benefit. 70 WIND RELEASE: VACUUM BOMB Classification: Ninjutsu Rank: D-Rank Casting Time: Special Range: 60 feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a single point of high-density air pressure using your Wind Release Chakra before expanding it and creating a series of reactions. All creatures currently affected by an elemental condition who would have a jutsu cast on them that triggers the swirl effect, potentially passes all such conditions around to other creatures near them in an expanded space with more volatility. When a creature would have the Swirl effect trigger on them, you can cast this jutsu as a part of the same action. All creatures within 20 feet of the triggering creature who failed their save gains two ranks of all elemental conditions the triggering creature had. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the area affected by 5 feet. WIND RELEASE: VACUUM RAIN Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet (20-foot cylinder) Duration: Concentration, Up to 1 minute Components: HS, CM Cost: Special (28 Chakra) Keywords: Wind Release, Ninjutsu, Combination Description: You create a powerful updraft that sucks the oxygen and air upwards robbing creatures of the ability to breathe within range. All casters of this jutsu create a 60-foot tall, 20-foot-wide cylinder that removes all air from inside of it replacing it with furiously rotating blade of Wind Release Chakra, centered on a point of your choice within range. All creatures within the cylinder must make a Dexterity and Constitution saving throw. On a failed Dexterity save they are slashed with wind chakra repeatedly taking 2d6 Slashing Damage and 2d6 Wind Damage or half as much on a successful save. A creature makes this saving throw the beginning of each turn they begin within this cylinder. On a failed Constitution Saving throw they are robbed of their air in their lungs as they begin suffocating. A Suffocating creature can only survive a number of rounds equal to their Constitution modifier before passing out falling unconscious from the lack of air. A creature makes this saving throw at the beginning of each turn they begin within cylinder. An unconscious creature can regain consciousness when another creature spends an action waking them. Creatures inside the cylinder cannot gain the benefits of an increase to movement speed and are treated as if they are in difficult terrain. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 2d6 for each damage type. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the Height by +10 feet and radius to 30 feet, +3: Increase the Height by +20 feet and radius to 40 feet, +4: Increase the Height by +30 feet and radius to 50 feet, +5: Increase the Height by +40 feet and radius to 60 feet). WIND RELEASE: VIOLENT WHIRLWIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (30-Foot Cone) Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Wind Release, Ninjutsu Description: You exhale a powerful stream of wind from your mouth. Creatures caught in the target area must make a Strength Saving throw. Creatures take 2d6 Wind Damage, are pushed back 30 Feet, are knocked prone and cause Swirl on a failed save or half as much and no additional effects on a successful save. Also, vapors, gases and fogs that can be dispersed by strong winds are dispersed immediately. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. Increase the range of this jutsu by 10ft. WIND RELEASE: ZEPHYR STRIKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: 1 minute Components: CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You move like the wind. For the duration, your movement doesn’t provoke opportunity attacks. Your movement speed increases by 10 feet until the end of the turn you cast this jutsu. Also, once before the jutsu ends, you can give yourself advantage on one attack roll on your turn. On a hit, the attack deals an extra 2d8 wind damage and immediately ends this jutsu. 71 C-RANK: WIND RELEASE: 1,000 BLADES OF THE WIND Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 20 Foot Cone Duration: Instant Components: HS, CM Cost: 7 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a spiraling sphere of wind chakra with a collection of cutting blades within it. Creatures in range must make a Strength Saving throw being pulled towards you and taking 4d6 Wind Damage and gaining 2 ranks of bleeding. Or half as much on a successful save and no ranks of bleeding. Creatures who fail their saving throw, are pulled towards you, ending their movement within 5 feet of you, and causing Swirl. They are then caught in a violent explosion of the cutting wind, being knocked back 20 feet and taking an additional 2d6 Wind Damage. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the amount of initial bleed gained by +1. WIND RELEASE: BURSTING COMPRESSED AIR Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 30-feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: You conjure a spiraling vortex of wind chakra around a target creatures weapon. The target creature makes a Dexterity saving throw to avoid the collapse of the wind. On a failed save they take 3d6 slashing damage as they are sliced for holding the weapon, and cause Swirl. If they continue to hold their weapon, they must make another save at the beginning of their next turn. On a successful save they take half damage. These additional saving throws do not cause Swirl. After 3 failed saves the weapon they are holding can’t take any more damage and shatters sending weapon shrapnel haphazardly flying. Other Creatures within 10 feet of the exploding weapon taking 3d6 slashing damage. WIND RELEASE: GALE FISTS Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Bonus Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM, M Cost: 6 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You coat your hands and feet in a layer of highly compressed but highly reactive wind release chakra. For the duration of this jutsu, you may use your Ninjutsu ability Modifier in place of Strength for unarmed attack rolls. Your unarmed damage is treated as Wind for the duration of this jutsu and deals damage equal to 1d10 + Ninjutsu Ability Modifier. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the damage by 1d10. WIND RELEASE: GREAT BREAKTHROUGH Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (60 Foot Line) Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a swirling vortex of air in front of you. You compress the air until the pressure explodes forward like a cannon in a straight line. Creatures in a 5- foot wide, 60-foot-long line must make a Strength saving throw. Creatures take 4d10 Wind damage, are thrown backwards 30 feet away, gain the dazed and prone conditions, and cause Swirl on a failed save. On a success they take half damage and no further effects. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase damage by 1d10 and knock back distance by 10ft. WIND RELEASE: LIONS ROAR Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (15-foot radius sphere) Duration: Concentration, Up to 1 Minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: You weave Wind Release Chakra together, creating a potent veil of chakra in the shape of a Lion around you and allied creatures. This chakra then collapses on all creatures of your choice within range granting the benefits as listed below, for the duration; • Bonus +20 Movement speed. • Ninjutsu, they cast with the Wind Release Keyword that has a range of at least 5 feet, increases their range by 10 feet, and deals an additional 1d8 Wind Damage, once per turn. • Taijutsu, they cast that has a range of touch, or 5 feet, increases their range by 10 feet, and deals an additional 1d8 Wind Damage, once per turn. 72 WIND RELEASE: PRESSURE SHOCKWAVE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when an allied creature casts a jutsu. Range: 60 feet Duration: Instant Components: HS, CM Cost: 8 Chakra Keywords: Wind Release, Ninjutsu Description: When you see another allied creature cast another jutsu, you create a tornado like mass that is compressed until it has a high density before being released as a shockwave, intended to boost their jutsu’s effects. If the triggering jutsu does not have a nature release keyword, the allied creature makes their attack roll at advantage or one hostile creature of your choice within range makes their saving throw at disadvantage. If the triggering jutsu has a nature release keyword, then all hostile creatures in a 60-foot cone, originating from you, must make a Strength saving throw or be pulled 15 feet towards your allied creature, take 5d6 wind damage, and causing Swirl on a failed save, or half as much and no further effect on a success. Additionally, it amplifies the triggering jutsu based on its nature release; • Earth Release: On a failed save target cannot take reactions. • Wind Release: On a failed save target gains 2 ranks of bleeding. • Fire Release: On a failed save the triggering jutsu increases its damage die by 1 step. • Water Release: On a failed save the target gains 1 rank of chilled. • Lightning Release: On a failed save the target gains 1 rank of shocked. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WIND RELEASE: RAKSHASA BARRIER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you would take Earth, Fire, Cold, or Lightning Damage Range: Self Duration: 1 Round Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash, Construct Description: You raise your hand and generate an intensely dense torrent of wind that circles around you, creating a bubble of wind that envelops your entire body. The bubble of wind that envelops you has a number of hit points equal to your Proficiency bonus times your Ninjutsu ability Modifier. This bubble has Resistance to Wind and Lightning Damage and vulnerability to Fire Damage. If this jutsu would trigger an additional effect as listed below, as a result of a different damage type, creatures in the effects range must make a Dexterity saving throw to avoid its effects. • If the bubble would take fire damage, all creatures within 15 feet of you must make a saving throw becoming burned on a failed save as the fire spreads around you from your rotating bubble of wind. • If the bubble would take Lightning damage, all creatures within 15 feet of you must make a saving throw becoming shocked on a failed save, as lightning jumps from you to other creatures around you. • If the bubble would take Cold damage, all creatures within 15 feet of you must make a saving throw becoming chilled on a failed save, as the cold is spread to all creatures around you. • If the bubble would take Earth damage, all creatures within 15 feet of you must make a saving throw, gaining the bleeding condition on a failed save, as they are pelted with shrapnel of earth. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the size of the area affected by 5 feet, and the number of hit points your bubble has by +10. WIND RELEASE: RECOVERING BREEZE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (30-foot-cone) Duration: Instant Components: HS, CM Cost: 8 Chakra Keywords: Wind Release, Ninjutsu, Medical Description: You create a field of medical chakra infused wind release chakra that pulses outward from you. All creatures of your choice within Range, excluding yourself, regains 5d6 hit points and removes the weakened & bruised conditions. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the amount healed by 1d6. 73 WIND RELEASE: ROTATING FEROCIOUS WIND Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you cast another Ninjutsu with the Wind Release keyword. Range: Self Duration: Instant Components: HS, CM Cost: 7 Chakra Keywords: Wind Release, Ninjutsu Description: You reinforce your Ninjutsu with additional buffeting gales of wind. Ninjutsu you cast with the Wind Release keyword prior to casting this gains a +2 bonus to its initial Saving throw DC. WIND RELEASE: SICKLE WEASEL Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction to taking damage from a melee attack or from a creature within range. Range: Self (20-foot radius sphere) Duration: Instant Components: HS, CM Cost: 8 Chakra Keywords: Wind Release, Ninjutsu Description: When you take damage you are able to collapse the circling wind around you and the triggering creature causing the wind to collide with the hostile creature creating an extremely sharp blade of wind. All creatures within 20 feet of you makes a Strength saving throw taking 5d8 Wind damage, gain 1 rank of bleed and cause Swirl on a failed save or half as much on a success. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the initial damage by 1d8. WIND RELEASE: TEARING GALE PALM Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM, M Cost: 7 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a large claw of your design made of semi-solid compressed wind chakra. You can attack with it targeting a single creature up to 30 feet away. Make a Ranged Ninjutsu Attack. Target Creature takes 4d6 Wind damage and gains 2 ranks of bleeding on a hit. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WIND RELEASE: VACUUM BARRIER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you see a creature within range take damage. Range: 60 feet. Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a swirling vortex of air in front of a creature you can see within range right before take damage. The compressed air compresses then explodes pushing attacks and other forces back, protecting the creature. Reduce the damage the target creature takes by 2d8+4. This Damage Reduction is doubled if the damage is Lightning Damage and halved if the damage is Fire Damage. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage reduced by 1d8. WIND RELEASE: VACUUM FIELD Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action. Range: Self (30-foot Radius Sphere) Duration: Concentration, Up to 1 minute. Components: HS, CM Cost: Special (50 Chakra) Keywords: Wind Release, Ninjutsu, Fuinjutsu, Combination, Kinjutsu Description: You manifest a Seal of wind Release Chakra that glows in the air. The seal then triggers completely removing all evidence of Oxygen and atmosphere from a 30-foot radius sphere centering on you. You and all other casters are immune to this jutsu’s effects. All creatures who begin their turns in this jutsu’s range must make a Constitution Saving throw or begin immediately suffocating as they are robbed of their air in their lungs. A Suffocating creature can only survive a number of rounds equal to their Constitution modifier before passing out falling unconscious from the lack of air. An unconscious creature in this jutsu’s radius automatically takes 5d10 Necrotic Damage. A creature who’s hit points are reduced to 0 as a result of this jutsu lungs, heart and other internal organs explode while inside the body. Being unable to be revived without these organs being restored as well. An unconscious creature can regain consciousness when another creature spends an action waking them. Fire & Lightning cannot exist within this Vacuum Field and if fire or lightning, a jutsu with a Fire or Lightning Release Keyword that deals fire or lightning damage would attempt to enter this fields radius or affect a creature within this fields Radius it is immediately snuffed out and negated. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 2d10. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the radius by +10 feet, +3: Increase the radius by +15 feet, +4: Increase the radius by +20 feet, +5: Increase the radius by +30 feet). 74 WIND RELEASE: VACUUM SHIELD Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction which you take when you or another creature within range would take damage. Range: Self (10-foot radius sphere) Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a swirling vortex of air in front of you. You compress the air until the pressure implodes on itself creating a shockwave blocking attacks and reducing the lethality of attacks in your immediate area. All allied creatures in this jutsu’s radius gain 20 Temporary Hit points from the oscillating flow of wind until the end of the current turn. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and temporary hit points by 5 and the radius by 5ft. WIND RELEASE: WALL OF WIND Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 120 feet Duration: Concentration, 1 minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: A wall of strong wind rises from the ground at a point you choose within range. You make the wall up to 50 feet long, 15 feet high, and 1 foot thick. You can shape the wall in any way you choose so long as it makes one continuous path along the ground. The wall lasts for the duration. When the wall appears, each creature within its area must make a Strength saving throw. A creature takes 4d8 Slashing damage on a failed save, or half as much damage on a successful one. The strong wind keeps fog, smoke, and other gases at bay. Small or smaller flying creatures or objects can't pass through the wall. Loose, lightweight materials brought into the wall fly upward. Arrows, bolts, and other ordinary projectiles launched at targets behind the wall are deflected upward and automatically miss. Large objects such as boulders and similar objects and attacks can penetrate it. Creatures in gaseous form can't pass through it. Fire ignites the Wall of wind leaving it as a massive wall of fire. If this happens the caster of Wall of wind loses all control of it and counts as the jutsu ending. WIND RELEASE: WHIRLWIND MOVEMENT Classification: Ninjutsu Rank C-Rank Casting Time: 1 Bonus Action Range:60 Feet Duration: Instant Components: HS, CM, M Cost: 6Chakra Keywords: Wind Release, Ninjutsu Description: You generate a massive amount of wind Chakra around your feet to make an incredible act of speed. You teleport to one space within 60 feet. WIND RELEASE: WHIRLWIND SPEAR Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (120-foot line) Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You mold a projection made of wind release chakra that floats next to you. This projection can take the shape of any spear or piercing like object such as an arrow, lance, sword or anything you prefer. You then launch this projection in a", created_at: NOW, updated_at: NOW },
  { _id: "785a8e695d80056f06da22a8", name: "CAJOLERY OF GLAMOUR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 Minute", description: "A powerful Genjutsu, that puts a creature under an illusion only using words and speech. While in the Genjutsu, the target can be easily swayed by their will and self-assurance. Select a target creature you can see within range; the target must make a Charisma saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: They are also more inclined to believe the worst-case scenario and are more willing to go against their better judgement and their own goals. Critical Failure: Affected creature suffers the effects of a failure and becomes paranoid of all other creatures excluding the caster for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "50edb36b7504afdd6929d771", name: "CATNAP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 action", range: "30 Feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You make a calming gesture, and up to three willing creatures of your choice that you can see within range fall unconscious for the genjutsu’s duration. The genjutsu ends on a target early if it takes damage or someone uses an action to shake or slap it awake. If a target remains unconscious for the full duration, that target gains the benefit of a short rest, and it can’t be affected by this genjutsu again until it finishes a long rest. 187", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e91ccc45727a7ead7b8b5b0c", name: "CHAKRA SHATTER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when you see a creature casting a Ninjutsu or Genjutsu that requires HS.", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You attempt to break the concentration of a creature in the process of casting a Jutsu that requires handsigns by creating an illusion that throws off their focus, creating an imbalanced chakra flow within them. This jutsu counts as an Interrupt. You force the creature to deal with a powerful chakra disrupting illusion. If the jutsu cast is of a Rank equal to or lower than this jutsu when you cast it, you make a contested Illusions check vs the targets Ninshou or Illusion check (If Ninjutsu, they make a Ninshou check. If Genjutsu, they make an Illusions check). If the Jutsu is of a higher rank, they make their check at advantage. If you win the contested skill check, their jutsu’s casting fails, has no effect and the jutsu that failed cannot be cast until the end of that creatures following turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3.", created_at: NOW, updated_at: NOW },
  { _id: "433f9002d58950dc2dceb930", name: "CIRCULAR MOVEMENT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d7fe1bb5775caf4818c287e", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "6 Chakra", components: "HS, CM, NT (Poison Kit)", duration: "1 minute.", description: "You release an odorless poison into the air that you then manipulate to affect up to two creatures you can see within range. Each of the selected creatures must make a Intelligence saving throw. On a failed save, they become poisoned. A creature poisoned as a result of this jutsu is both unaware they are poisoned and also cannot willingly move further than 30 feet from their current position, regardless of the direction they move in. When a creature attempts to move further than 30 feet from their current position, they instead spend their remaining movement walking backwards, moving back to their starting position. A creature moving backwards is unaware they are moving backwards, instead believing they are still moving forwards and the distance between them and the location they are attempting to move to is growing infinitely for the duration. If a creature poisoned as a result of this jutsu is cured of the poisoned condition, this jutsu also ends on them immediately.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7d5f8e7594c0c586298e828a", name: "CLOSING IN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "Select one creature you can see within range. The target must make an Intelligence saving throw, which it makes at disadvantage if it’s an enclosed space. Critical Success: Affected creature is able to resist this Jutsu's effects. Success: Affected creature is able to resist most of this jutsu’s effects but begins to see the world shift slightly becoming unable to take the dash or dodge actions until the end of their next turn. Failure: Affected creature see’s the world is closing in on them and threatening to crush it. Even in open or clear terrain, the creature feels as though it is sinking into a pit or that the land is rising around it gaining disadvantage on skill checks and ranged attack rolls for the duration, remaking its saving throw at the end of each of its turns to break free of this Genjutsu’s effect. Critical Failure: Affected creature suffers the same effect as a failure but also takes 2d6+Genjutsu ability modifier psychic damage at the beginning of each of its turns.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the number of creatures you can target by +1 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "36bd610e52e09ef589e5c9ab", name: "CORRUPTION: BALEFUL INCEPTIONS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action.", range: "Self (15-foot radius)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and release illusionary chakra, corrupting the thoughts of all targets, forcing them to have dangerous thoughts of betrayal. Select up to 3 creatures of your choice within a 15-foot radius sphere, centered on you, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next minute. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures, who see their allies attempting to cast a jutsu must spend its reaction to take the Attack action, with a weapon if the weapon would have a larger damage die in place of their unarmed damage, if able against the triggering creature. The creature whom the affected creature attacks must be in range of their attacks, if they are not, the affected creature is forced to move up to 15 feet closer as part of the reaction taken before taking the attack action. An affected creature remakes saving throws at the end of each of its turns, ending this jutsu on a success. Critical Failure: Same as failure, but affected creature instead must move its full movement towards their triggering allies. 188", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the size of the radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "4aa288d8c91fa502f64ebc9d", name: "CORRUPTION: CRUELTY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to mentally scar them with a seal of cruelty. Select one creature you can see within range, forcing them to make a Charisma saving throw. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures are marked with a seal of cruelty, corrupting and burning through their psyche. At the beginning of each of their turns, this seal forces their mind to discharge large chunks of chakra, dealing 3d6 chakra damage. Affected creatures can, as an action, remake their saving throw to end this jutsu’s effects. Critical Failure: Same as failure, but the chakra damage is increased to 5d6.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of target creatures by +1.", created_at: NOW, updated_at: NOW },
  { _id: "7ede7de84147168261dac4bb", name: "CORRUPTION: HATRED", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to mentally impose a level of physical invalidation on your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures who would make a Constitution saving throw, must instead make a Constitution ability check, once per round. A creature under this effect, remakes their saving throw at the end of each of their turns, to end this jutsu’s effect on them. Critical Failure: Same as failure, but the target must now make that ability check up to twice per round if forced.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of target creatures by +1.", created_at: NOW, updated_at: NOW },
  { _id: "f78093305d69cce5d1ee2fc4", name: "CORRUPTION: HOSTILITY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to mentally inject a sense of your hostility into your foes, causing them to focus on both you and everything else going on. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures who would make a Dexterity saving throw, must instead make a Dexterity ability check, once per round. A creature under this effect, remakes their saving throw at the end of each of their turns, to end this jutsu’s effect on them. Critical Failure: Same as failure, but the target must now make that ability check up to twice per round if forced.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of target creatures by +1.", created_at: NOW, updated_at: NOW },
  { _id: "6b903bf66d26650e46c58ba5", name: "CORRUPTION: LOATHING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, attempting to mentally inject a level of self-loathing on your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures who would make a Strength saving throw, must instead make a Strength ability check, once per round. A creature under this effect, remakes their saving throw at the end of each of their turns, to end this jutsu’s effect on them. Critical Failure: Same as failure, but the target must now make that ability check up to twice per round if forced.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of target creatures by +1. 189", created_at: NOW, updated_at: NOW },
  { _id: "92e94b87fadd089de72e9698", name: "CORRUPTION: MALFEASANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "33ab3a61f3027398cd08f131", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action.", range: "90 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You collect and build illusionary chakra, corrupting the thoughts of your targets, forming a psychological tumor in the back of their mind. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next minute. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures, for the duration begins to experience a growing mass of mental energy. At the beginning of each of their turns, they gain 2 Psychic Malignance, up to a maximum of 20. When this jutsu ends as a result of a successful saving throw or the duration expiring, all Psychic Malignance a creature has detonates, dealing 1d10 psychic damage for each Psychic Malignance a creature has when it detonates. A creature can choose to remake their saving throw, once on each of its turns, ending this jutsu on a success. Critical Failure: Same as failure, but creatures instead gain 3 Psychic Malignance.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of target creatures by +1.", created_at: NOW, updated_at: NOW },
  { _id: "b2ee53121d8b1e76ad93e933", name: "DANCING BLADES", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM, W (Any)", duration: "Concentration, Up to 1 minute.", description: "When you cast Dancing blades, you create four Illusionary copies of a weapon you are currently holding. This illusionary weapon floats within 5 feet of you hovering spinning and circling around you, while mimicking your attacks. As an action, you may spend one of your illusionary weapons to slam into a creature within range. Make a Ranged Genjutsu attack targeting a creature up to 60 feet away. On a hit you deal 2d10 + Your Genjutsu ability modifier. When you are hit by a melee attack that exceeds your AC by 1-3, one of your illusory weapons parries the attack, preventing you from taking damage and destroying the illusory weapon. When you are hit by a melee attack that exceeds your AC by 4-6, you take half damage from the triggering attack and one illusory weapon is destroyed. If you make a genjutsu attack that scores a hit, while this jutsu is active, one of your illusory weapons also strike the target dealing psychic damage equal to 1d10. An attacker must be able to see you, in order to see the illusory weapons to be affected by this jutsu. This jutsu has no effect if you are invisible, hidden, in total darkness or if the attacker is blinded.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of illusory weapons you summon by +1.", created_at: NOW, updated_at: NOW },
  { _id: "bcd428c27c2ad9c8c3c9c252", name: "DARK DEMENTING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "3d7fe1bb5775caf4818c287e", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "9 Chakra", components: "HS, CM, NT (Poison Kit)", duration: "1 minute.", description: "You cast a dark shadow over a target creatures thoughts by manipulating the particles of a special drug concoction. Select one creature you can see within range to send this odorless gaseous drug to affect. The creature must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this Jutsu's effects, gaining advantage against this jutsu’s effects if cast against them a second time within the next hour Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature begin to see a shadow out of the corner of their eyes for the duration, always there, always just out of sight gaining 1 rank of fear at the end of each turn it begins in a space that is not brightly lit. It will also avoid dim light and darkness, choosing to spend each action it has to find light or escape to light, rationalizing the fear as its own. An affected creature remakes the saving throw at the end of each of its turns to end this effect. Critical Failure: Affected creature suffers the same effect as a failure but instead does not remake saving throws at the end of each of its turns, and only when it would take damage. 190", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6d14199e64c450c7f9d9b876", name: "ENTHRALL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 minute", description: "You weave a distracting string of words, causing creatures of your choice that you can see within range and that can hear you to make a Wisdom saving throw. Any creature that can’t be charmed succeeds on this saving throw automatically, and if you or your companions are fighting the target creature, it has advantage on the save. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature gains disadvantage on Wisdom (Perception) and Wisdom (Insight) checks made to perceive and interact with any other creature other than the caster of this genjutsu for the duration or until the target can no longer hear you. This genjutsu ends if you stop communicating with the creature for longer than 6 seconds. Critical Failure: Affected creature suffers the effects of a failure but instead automatically fail all Wisdom (perception) and Wisdom (Insight) checks made to perceive and interact with other creatures, only seeing the caster and ignoring all others.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "27ae443b627d08d7cddcd79b", name: "FALSE PAIN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "aaeecd12fb6a8f889a26ab97", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "You speak words of reinforcement. Select up to two willing creatures other than yourself that you can see within range. Each of the selected creatures pain receptors becomes dulled and numb, becoming unable to feel the pain or sickness they felt prior. For this jutsu’s duration, all damage they would take is delayed, until this jutsu ends. They record all damage they would normally take over the course of the encounter as normal. Additionally, they ignore the effects of the Weakened, Dazed, Incapacitated, and poisoned conditions for this jutsu’s duration. If any of the aforementioned conditions duration would last beyond this jutsu’s duration, they begin suffering the effects of that condition as normal. At the end of this jutsu’s duration, affected creatures take psychic damage equal to the total delayed damage they have recorded at once. This damage ignores Resistance and Immunity.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2509fb4d70984fba88274b0e", name: "FALSE VISIONS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "You begin to create false visions that a creature will see regardless of what is really happening. Select one creature that you can see within range. The target creature must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature becomes blinded, but begins to hallucinate seeing only what you declare they see. Describe what the affected creature will see other creatures do on their respective turns. This can be anywhere from attempting to cast a jutsu, attempt to attack them, go in another direction, attempt to hide or anything they would be able to see. When they take damage, the damage is dealt as normal, and they remake the saving throw ending this jutsu on a success. Critical Failure: Affected creature suffers the effects of a failure but instead they make their saving throw to end this jutsu with a 1d4 penalty to the result.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "edbf8f9e61197370c8680f1d", name: "FLOWER PETAL ESCAPE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Reaction, to being Damaged", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "An advanced version of the “Feather Burst” Genjutsu. When you are hit your body breaks into a swarm of flower petals of your own description, while you regroup yourself from a stealthy position. When you are struck by an attack you may roll 2d4, reducing the triggering creatures attack bonus by the result, potentially causing the attack to miss, making any damage you took prior never actually happen. As part of the activation of the jutsu, regardless if you are hit or not; Make a Dexterity (Stealth) or Wisdom (Stealth) check vs the triggering creatures Passive perception. On a success, you immediately moving up to your movement speed away without triggering an attack of opportunity and you become hidden from the triggering creature if you end your movement in a space where you are at least partially covered.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and reduce attack bonus further by 1d4. 191", created_at: NOW, updated_at: NOW },
  { _id: "aa62a66b58c1f342837036e7", name: "FOG OF WAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "90 feet (30-foot cube)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "You cloud the minds of your opponents, hindering their perception of the environment around them, veiling reality with twisted illusions. All creatures within a 30-foot cube, centered on a point you can see within range must make a Wisdom saving throw. On a failed save they fall under this genjutsu’s influence for the duration. A creature who is under this genjutsu’s influence remains under its influence until the jutsu ends or they end this jutsu’s effects on themselves. Creatures under this jutsu’s influence have disadvantage on Wisdom (Perception) checks made to locate enemies. Additionally, if an affected creature makes an attack against a creature that has at least one other creature adjacent to it-friend or foe- the affected creature must roll a d20. On a roll of 11 or higher, its attack is applied to the adjacent creature instead. (Randomly decide the new target if there are more than one adjacent creature) and deals damage as normal if it hits. At the beginning of an affected creatures turn, they make a wisdom saving throw. On a successful save, the creature is unhindered by this jutsu until the beginning of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "214b72b08d9ea0190679770b", name: "GENJUTSU BREAK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Instant", description: "Choose one creature, object, or Genjutsu effect within range. Any Genjutsu of equal rank or lower is transferred into the Chakra seal used in this jutsu’s casting, immediately ending its effect on the affected creature(s), or object(s). For each Genjutsu of higher rank, affecting the target, make an ability check using your Genjutsu ability. The DC equals 12 + The Jutsu’s Rank. Rank (B-3, A-4, S-5). On a successful check, the Genjutsu is transferred to the Chakra seal and can be stored for no more than 10 minutes. For the duration of this hour, you can attempt to transfer this genjutsu to another creature within 5 feet of you by spending an action to make a Melee Genjutsu attack against a creature within 5 feet of you. On a hit the Sealing tag is applied to the target, and at the beginning of its next turn they must make a saving throw against the original save DC to resist its effects as if the jutsu were originally cast on them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. The removed jutsu has no effect if its rank is less than or equal to the rank of this jutsu when you cast it.", created_at: NOW, updated_at: NOW },
  { _id: "acbcc6b486b8cf6071307472", name: "HALLUCINATORY TERRAIN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "10 Minutes", range: "300 Feet", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "24 Hours", description: "You make natural terrain in a 150-foot cube in range look, sound, and smell like some other sort of natural terrain. Thus, open fields or a road can be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road. Creatures within the area aren't changed in appearance. The tactile characteristics of the terrain are unchanged. Creatures entering the area are likely to see through the Illusion. If the difference isn't obvious by touch, a creature examining the Illusion can attempt a Wisdom (Illusion) check against your Genjutsu save DC to disbelieve it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fc294ecf7272409993c25a35", name: "HAZE CLONE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (45-foot radius sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "This technique creates a thin haze centered on the user that spans a 45-foot radius sphere, that once cast, does not move. Creatures inside the radius see duplicates formed from the haze. The duplicates do not move or make a sound, instead they burst into more haze when touched. While inside the haze the user gain the benefits of partial cover, and can take the hide action without fully obscuring themselves due to the number of duplicates there are. Creatures outside the radius of this jutsu, do not see any haze or any duplicates. Creatures who enter the radius do begin to see the duplicates of the user. 192", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f411bd08da240188ec744557", name: "HYPNOTIC PATTERNS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "120 Feet (30-foot-cube)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. The pattern appears for a moment and vanishes. Each creature in the area who sees the pattern must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this Jutsu's effects, gaining advantage against this jutsu’s effects if cast against them a second time within the next hour. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature becomes enamored by the colors, being unable to leave the radius of the cube and having their movement speed reduced by half. Additionally, they cannot maintain concentration on more than one jutsu while enamored in this way. They remake their saving throws at the end of each of their turns, ending this jutsu on themselves on a success. The Jutsu ends for an affected creature if it takes any damage. Critical Failure: Affected creature suffers the same effect as a failure but also becomes incapacitated as their movement speed is reduced to 0 for the duration. The Jutsu also ends for an affected creature if it is moved more than 10 feet against its will.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fe1adf46e4ce58476fe54ce5", name: "ILLUSORY BAMBOOZLEMENT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Permanent", description: "You create the illusion of a trap upon an object you touch, such as a door, a chest, or a 5-foot square area of floor. A creature specifically looking for traps that examines the object must make a Wisdom saving throw. On a successful save the jutsu ends and the creature realizes the trap was not real. Success: Affected creature is able to see through this illusory trap, rendering it useless against them. Failure: Affected creature believes the object contains a trap. If the creature then tries to disarm or otherwise interact with the trap in order to set it off, it must make a Dexterity (Sleight of hand) check vs your Genjutsu save DC. On a successful check, it creates a feedback dealing 2d10 psychic damage, and they realize that the trap was only an illusion, immediately ending this jutsu. On a failed check, the creature takes 5d10 psychic damage and is stunned for 1 round, believing that it accidentally set off the trap and was injured by it. The illusion then resets as if the trap can trigger multiple times Critical Failure: Affected creature suffers the same effect as a failure but the damage die becomes a d12.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "505c57aedec4023f46bbd21d", name: "ILLUSORY MISDIRECTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You conjure a beautiful illusory creature of your description. All creatures who aren’t blinded within 30 feet of the conjured illusion must make a Charisma saving throw. On a failed save they become charmed by the illusory creature for the duration. As a bonus action, on your turn, you can reveal that the creature you created, is actually not what the charmed creatures believed it to be, while still having the same beautiful features as when you created them. Affected creatures must make a Charisma saving throw. On a failed save, they are in shock from the realization of the creature turning into something else entirely, as they become dazed. On a success they steel themselves, ending the charmed condition. Regardless, when you reveal the illusory creatures true nature, regardless if affected creatures pass or fail, this jutsu immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9ecf90538fd87873ba39a957", name: "INNOCUOUS ASPECT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius)", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Concentration, Up to 10 minute", description: "You create an area of false visions that encompasses all willing creature in a 20-foot radius centered on you, of your choice. You do not need to spend chakra to maintain concentration on this jutsu. You and each affected creature takes on the appearance of a harmless creature or object of your choice. Each image is identical and only appearance is affected. Sound, movement or physical inspection can reveal that this is a genjutsu. A creature that uses its action to study the image visually can determine that it is an illusion with a successful Wisdom (Illusions) check vs your Genjutsu save DC. If a creature discerns the illusion for what it is, that creature sees through the image. 193 MEDICAL RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2c81ad7e5fad8ff3b8bfaca6", name: "SHARED PAIN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "60 feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a self-sustaining illusion designed to help soothe the mental scars of battle. Select one willing allied creature within range. You share your pain with them, reducing the damage you take by half, and inflicting psychic damage on the target ally equal to the damage you took.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of allies you can target by +1. You instead divide the damage you take, by the number of allied creatures you target with this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "c64ed08b352b746b3acbdc3b", name: "MENTAL BARRIER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 reaction, which you take when you are forced to make an Intelligence, Wisdom or Charisma saving throw", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 round", description: "You protect your mind with a wall of looping, repetitive thought. As a reaction, when you would make a saving throw against a Genjutsu without the Unaware keyword, you gain a 1d6 bonus in one of the following saving throws Intelligence, Wisdom, or Charisma, until the end of the current turn. You also gain resistance to Psychic damage for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fa9d767965372c7d6dfcb6f6", name: "MENTAL SHIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 Minute", description: "You manifest an armor of illusory chakra that shields and protects you from assaults of other psychic based attacks or effects. You reduce all incoming Psychic Damage by 5, if you would reduce psychic damage to 0 while gaining the benefits of this jutsu, and the hostile jutsu or effect would also attempt to inflict an effect or condition, you ignore that effect or condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the psychic Damage Reduction by 5.", created_at: NOW, updated_at: NOW },
  { _id: "eac65f3b685776c2c51b00a0", name: "MENTAL TAUNT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You create a sound of attraction. Meant to force creatures to focus on you against their will. Select a creature within range and force them to make a Charisma saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature must target you with any jutsu they cast until the end of their next turn. Critical Failure: Same effect as failure, and they cannot cast jutsu or used features, effects or items that would heal them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "bd293f7dcd62bf71ae1d47fc", name: "MIND SPIKE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 action", range: "60 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "10 minutes", description: "You reach into the mind of one creature you can see within range. Make a ranged Genjutsu Attack as you launch a psychic lance into the mind of the target. On a hit, the target takes 5d8 psychic damage and must make a Wisdom saving throw. Success: Affected creature is able to resist this Genjutsu’s effects. Failure: Affected creature’s location is always known by the caster. The affected creature cannot gain the benefit of being hidden from the caster. If the affecter creature is invisible, it begins to glow a bright neon purple to you, allowing the caster to ignore any effect granting the creature invisibility Critical Failure: Affected creature suffers the effect of failure, and their location is also always known by one other creature of the casters choice.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. 194", created_at: NOW, updated_at: NOW },
  { _id: "009cbcf80b22c5b13ab41f81", name: "MIND THRUST", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 bonus action", range: "90 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 round", description: "You thrust a blade formed through your genjutsu into the mind of one creature you can see within range. The target must make an Intelligence saving throw. Success: Affected creature is able to resist this Genjutsu’s effects. Failure: Affected creature’s takes 2d8 psychic damage, and it can’t take a reaction until the end of its next turn. Critical Failure: Affected creature takes 3d8+Genjutsu ability modifier psychic damage, it can’t take a reaction until the end of its next turn and At the beginning of the targets next turn, they must make an Intelligence saving throw. On a failed save, the target must choose to either move, take an action, or a bonus action. It can only do one of the three.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "caf91bf6d48661c20a24bd85", name: "MIND-BODY RECOVERY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "aaeecd12fb6a8f889a26ab97", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Bonus Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "10 minutes", description: "You soothe a target's suffering and pain by making their mind unaware of it while also raising their tolerance for pain. Select up to 3 willing creatures within range. Target creatures gain 3d6+5 Temporary Hit points for the duration. When this jutsu ends they lose any remaining Temporary Hit points from this jutsu. Additionally, you are able to remove one mental condition of C-Rank of lower.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the temporary hit points by 1d6+3 and the rank of mental condition you can remove by one.", created_at: NOW, updated_at: NOW },
  { _id: "eb06d28a146124fc5378a019", name: "NIGHT TERRORS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You amplify the fear that lurks in the heart of all creatures. As a part of casting this jutsu, you must target one creature who currently has at least 1 rank of fear. The target creature must make a Charisma saving throw. On a failed save, any genjutsu currently affecting them, that would inflict, or has inflicted the fear condition immediately ends. The target creatures current ranks of fear double. If they have 3 or more ranks when they fail this jutsu’s saving throw, their ranks of fear instead immediately becomes 5 for the duration. A creature who has any number of fear ranks as a result of this jutsu cannot gain additional ranks of fear from other sources. Additionally, affected creature remake their Charisma saving throw at the end of each of their turns. On a successful save they remove all ranks of fear and ends this jutsu’s effects on themselves. Alternatively, when you lose concentration on this jutsu, the affected creature immediately loses all ranks of fear.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "13f567659b135099260f8a16", name: "OUTFLANK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "Select one creature you can see within range. For the duration, when you make a genjutsu attack against the creature, an illusory double of you attempts the same attack. When you make a Genjutsu attack of any type targeting the select creature for the duration, your illusory double attacks with the same attack from a different angle. Make a second Genjutsu attack against the creature with the same bonuses to your attack (if any), if your initial attack misses. On a successful hit, they take half damage and suffer any additional effects as normal. Additionally, as a reaction when an allied creature performs an attack targeting the same creature, you can create an illusory double of your allied creature performing the same attack. The attacking allied creature makes their attack at advantage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e2b4f8bae10294282ee4817e", name: "PHANTOM DRAGON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You touch one willing creature within range. All creatures of your choice who can see them within 120 feet, see your ally as they transform into dragon of your description of large size. While looking at this illusion, observers make a Wisdom saving throw to see through it. On a failed save, they see your ally as a large dragon for the duration. When you ally attempts to attack or cast a jutsu of any type, the illusory dragon looks as if it is performing the jutsu itself, be it breathing fire, performing an aggressive martial attack or creating illusions using its draconic aura. When your affected ally deals damage to a creature, who sees them as an illusory dragon, they deal an additional 3d10 psychic damage to affected creatures, once per turn. 195 Alternatively, as an action on their turn, the affected ally can perform a ferocious roar. All creatures within 120 feet excluding you and other creatures who have seen through this genjutsu must make a Charisma saving throw. On a failed save they gain 1 rank of fear for the next minute against the illusory dragon. A creature who has ranks of fear as a result of this jutsu can spend their action to remake the charisma save removing all ranks of fear they have on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "84f01f8503319f9fae2009fc", name: "POISON LOTUS FIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "10 Minutes", range: "Special", chakra_cost: "Special", components: "HS, CM, NT (Poison Kit & Any Poisonous", duration: "Special", description: "As a part of casting this jutsu, you must have fertile soil which can facilitate a flowers growth. You take your poisonous flower and infuse a dose of poisonous chemicals into the flower itself before you plant the flower into the soil and infuse your chakra into it giving it life and influencing the potency of the poison this jutsu produces. If this flower, before or after being planted is killed or destroyed, this jutsu immediately ends, requiring you to recast it. The flowers look like a sacred lotus with purple petals. Creatures looking for this flower, if they are proficient in Nature, Medicine, or Survival they may make any of the aforementioned skill checks vs your Genjutsu Save DC being able to find it on a success. If the creature is not proficient, they instead make a Wisdom (perception) check with a -5 penalty, to their check. If your flower is in a bed of other sacred lotuses, regardless if they are proficient or not, they take a -5 Penalty to their check. The flower has 1 Hit point and an AC of 5. At the conclusion of casting this jutsu you can infuse different volumes of chakra into the soil and roots facilitating different effects. 8 Chakra: This flower grows, producing purple flower buds in the shape of a sacred lotus flower. As an action, for the next minute, while you are within 90 feet of this flower, the flower blooms releasing a potent poisonous, but odorless gas. All creatures within 60 feet of the flower of your choice must make an Intelligence save saving throw at the beginning of each of their turns. On a failed save they become poisoned. A creature poisoned as a result of this jutsu who would make a saving throw or skill check as the result of, or against a Genjutsu you cast, must roll an additional 1d4, reducing their saving throw or check by the result. Additionally, the poisoned creature treats all Genjutsu you cast as if it has the unaware keyword. After 1 minute or after the flower is destroyed, this jutsu ends. 16 Chakra: You gain all previous chakra costs effects. In addition, you can activate this jutsu while you are within 120 feet of the flower and it affects all creatures within 90 feet of it. 24 Chakra: You gain all previous chakra costs effects. In addition, affected creatures instead rolls 2d4, reducing their saving throw or check by the result and any psychic damage they would take deals additional psychic damage equal to twice your Genjutsu ability modifier if it doesn’t already add your Genjutsu ability modifier to the damage rolls. 32 Chakra: You gain all previous chakra cost effects. In addition, genjutsu you cast while within 250 feet of your flower, does not require you to spend chakra to maintain concentration for up to 10 minute. Additionally, any genjutsu you cast with a duration of concentration, up to 1 minute, instead becomes 10 minutes, while within 250 feet of your flower. After 10 minutes, or after the flower is destroyed, this jutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "04ee4e366146f5aa1bfa366d", name: "POWER TRIP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "Special", components: "HS, CM", duration: "Instant", description: "You mentally track all of the pain you’ve experienced this encounter. Record the difference between your current hit points and your maximum hit points. On your next turn, if you would deal psychic damage to a creature, you can spend a number of chakra up to the amount recorded. When you do, the target who took the psychic damage takes additional damage equal to the amount of chakra spent. Once this jutsu is cast and you successfully deal bonus damage with its effects, you cannot cast it again until at least 10 minutes have passed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7e592a476d95dc26d6fb42c0", name: "POWERFUL CALM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 Foot radius Sphere", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You release a Genjutsu aura originating from you completely suppressing creatures in a 60-foot sphere centering on you, aggressive feelings for 4d8 Minutes. If the target is attacked, damaged or the end of the rolled time passes, creatures return to being hostile to whomever they were hostile to before with compressed and compounded rage. Creatures in the target area must make a Charisma saving throw, losing all will to fight for the rolled duration on a failed save. On a success, creatures remain aggressive and cannot be affected by this Genjutsu again for 24 hours. 196", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "38c109bcfeaef7e37eb055b8", name: "PSIONICS: BEAM!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (60-foot line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a wave of psionic chakra that disorients creatures that are touched by it. All creatures of your choice in a 5-feet wide, 60-feet long line, originating from you must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 2d10 psychic damage and becomes confused. Critical Failure: Affected creature takes 3d10 psychic damage and gains 2 ranks of confused.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "a0ea3f01cb60d0ae5488aeba", name: "PSIONICS: DARK DAZE!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a shockwave of psionic chakra and release it into an omnidirectional wave around you. All creatures of your choice in a 30-foot radius, originating from you must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 3d8 psychic damage and becomes dazzled. Critical Failure: Affected creature takes 5d8 psychic damage and affected creatures gains 3 ranks of dazzled.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "147167a9e5f33baed1d242e6", name: "PSIONICS: DARK PULSE!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a shockwave of psionic chakra and release it into a dark wave of mental force. All creatures in a 30-foot cone, originating from you must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 4d6 psychic damage and at the beginning of their next turn must roll a d8. On a roll of 1 or 2 their next jutsu fails to cast. They still spend the chakra as normal. Critical Failure: Affected creature takes 6d6 psychic damage and their next jutsu fails to cast, they spend double the chakra cost as normal.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the range of the cone by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "ede6022248c12f6ea24fa105", name: "PSIONICS: MIND CRUNCH!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest fangs of black psionic chakra that bite into your enemies thoughts. Make a ranged Genjutsu attack. On a hit you deal 2d10 psychic damage and the affected creature must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creatures AC is reduced by 1, until the end of their next turn. Failure: Affected creatures AC is reduced by 2, until the end of their next turn. Critical Failure: Affected creatures AC is reduced by 2, two ranks of concussion and they cannot take reactions until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "551a205d44b54cd6ef3413d4", name: "PSIONICS: PAUSE!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Round", description: "You manifest a pulse of illusory chakra that delays a creatures synaptic response time to events. Select one creature you can see within range, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu’s effects for 1d4 of its turns. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature decides on their actions on their turn, but can only actively take them at the end of the next creatures turn. If the affected creature would target a creature who is no longer in range, their jutsu fails to cast. Critical Failure: Affected creature decides on their actions on their turn, but they can only actively take them on initiative count 0.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the number of creatures this jutsu can target by +1. 197", created_at: NOW, updated_at: NOW },
  { _id: "d2177dac9de8b9471d0d33bc", name: "PSIONICS: PSYCHO CUT!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a vertical slash of psionic chakra from your hand that you whip towards your enemies. Make a ranged Genjutsu attack, with a +1 to its critical threat range. On a hit you deal 3d6+ your genjutsu ability modifier in psychic damage and the affected creature must make an Intelligence saving throw. If this jutsu scores a critical hit, the target suffers the effects of a Critical failure, regardless of their saving throw results. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature gains 1 rank of Confused until the beginning of their next turn Failure: Affected creatures gains 1 rank of Confused until the end of their next turn. Critical Failure: Affected creatures gains 1 rank of Confused, Dazzled and Concussed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the number of creatures you can target by +1 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "3c46db37ee7e22432a6406ba", name: "RABENDA: ENIGMATIC REDUCTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Self (20-foot Cube)", chakra_cost: "5 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "1 Minute", description: "You grasp a hand full of poisonous Rabenda flower buds, enhancing them with your chakra and spreading its spores into a storm filling a 20-foot cube originating from yourself. As they flutter in front of you, all creatures who begin their turns within range must make a Charisma saving throw to as the pollen begins to intrude on their subconscious. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to this jutsu’s casting for the duration. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature who casts a jutsu suffers a temporary reduction to their casting stat, for the remainder of this jutsu’s duration. Each time an affected creature casts a Jutsu while in this jutsu’s area suffers a -1 penalty to all checks, saves, attack rolls, and saving throws associated with that ability score. This penalty stacks up to a maximum of -3. A creature suffering such a penalty, can spend its Action to remake this jutsu’s saving throw, ending its effects. Critical Failure: Same as failure, but the maximum penalty is increased to -5", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the size of the radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "4ac0410decf0ddd6003a4b83", name: "RABENDA: ENIGMATIC STORM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 feet (10-foot radius)", chakra_cost: "7 Chakra", components: "HS, CM, NT (Poison Kit, 1 Charges)", duration: "Concentration, up to 1 minute", description: "You grasp a hand full of poisonous Rabenda flower buds, enhancing them with your chakra and spreading its spores into a storm filling a 10-foot radius, centered on a space you can see in range. Once this jutsu is cast, you cannot cast it again until the end of your next turn after this jutsu ends. All creatures who begin their turns in this jutsu’s range must make a Charisma saving throw as their mind is overwhelmed with intruding thoughts from the Genjutsu enhanced flower buds. You can move the torrent of flower buds, as an action on each of your turns, up to 30 feet in any direction. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature becomes slowed for the duration and at the beginning of each affected creatures turns, they gain 1 rank of Concussed, while inside the affected area. Critical Failure: Same as failure, but they instead gain 2 ranks of concussed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e3cc1b35f8974c4022660776", name: "RINGING BELL DISTORTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "7 Chakra", components: "HS, CM, NT (Bells), W (Thrown weapon)", duration: "Concentration, up to 1 Minute", description: "You attach a bell to a thrown weapon and select up to 3 spaces within range to throw them. The bells ring out diluting the sense of all creatures who can hear them in a 20-foot radius from each of the selected locations, causing them to see hallucinations of your design such as seeing multiple mirages of you, or seeing their own allies in your place. All creatures in the target radiuses must make an Intelligence Saving throw, gaining disadvantage on all attacks and providing advantage to all creatures targeting it for an attack for the duration. 198", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "55881625c480689c10b29e7c", name: "SHADOW MONSTERS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "Select one creature you can see within range. The select creature must make a Wisdom Saving throw. Success: Affected creature is able to resist this Genjutsu’s effects. Failure: Affected creature becomes berserk, seeing all of its allies become shadowy monsters in a horrific fashion of your description. Affected creature makes a Wisdom saving throw if they deal damage to one of their allies. On a success, they end the berserk condition. Critical Failure: Affected creature becomes berserk, seeing all of its allies become shadowy monster in a horrific fashion of your description. You and up to 3 other creatures of your choice transform and begin to look like its allies as it mentally sees you as allied creatures for the duration. Affected creature makes a Wisdom saving throw at disadvantage if they deal damage to one of their allies. On a success, they end the berserk condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "5aa9e596af50b6f0230745a9", name: "SLEEP OF THE DEEP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 Foot Radius", chakra_cost: "6 Chakra", components: "HS, CM", duration: "8 Hours", description: "Your chakra creeps into the dreams of others, haunting and terrifying them. Choose any number of sleeping creatures that you are aware of within range. Creatures that do not need to sleep, cannot be targeted. The creatures must make a Wisdom Saving Throw. On a failed save they do not benefits from any form of rest for the duration and when they awaken from any rest they may take, they gains 2 ranks of Exhaustion and are Demoralized for as long as they have any ranks of Exhaustion inflicted by this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1d0084036a2d4be1dedc966b", name: "SONG OF COURAGE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "self (30-foot radius)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You begin to hum or sing an inspirational tune designed to make those who hear it believe they can achieve anything. All creatures of your choice within range begins to experience this refreshing delusion. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Creatures who begin their turns within range gain immunity to the fear condition until the beginning of their next turn. Additionally, creatures who have to make saving throws against a jutsu a hostile creature has cast, cannot make the saving throw at disadvantage. Finally, the affected creature ignores any penalties to their rolls as a result of a hostile creatures jutsu or effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the radius by 5.", created_at: NOW, updated_at: NOW },
  { _id: "98fbd9c283004cb11872f346", name: "SONG OF PAIN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "self (30-foot radius)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You begin to hum or sing a tune of pain and suffering designed to make those who hear it experience bouts of pain that they can only wish would end. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Creatures who begin their turns within range who attempts to cast a jutsu with the Mobility (M) keyword, must make an Intelligence Saving throw. On a failed save, if they experience extreme muscle pain in parts of the body you see them attempting to utilize, causing them to lose the jutsu attempted.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the radius by 5. 199", created_at: NOW, updated_at: NOW },
  { _id: "46ddaeff00a698a7789307b4", name: "SONG OF RESPITE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "aaeecd12fb6a8f889a26ab97", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "self (30-foot radius)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 10 minutes", description: "You begin to hum or sing a tune of restoration and healing designed to make those who hear it feel as if their wounds are closing and being mended. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. All allied creatures of your choice within range gains a number of temporary hit points equal 1d4+ your Genjutsu Ability Modifier at the beginning of each of your turns. Temporary Hit points gained as a result of this jutsu remain for up to 1 minute after this jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the radius by 5.", created_at: NOW, updated_at: NOW },
  { _id: "e9cc79b795fce90902808108", name: "SUGGESTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1Action", range: "30 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Special", description: "You suggest a course of activity (limited to a sentence or two) and use genjutsu to influence a creature you can see within range that can hear and understand you. Creatures that can’t be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable. Asking the creature to stab itself, throw itself onto a spear, immolate itself, or do some other obviously harmful act ends the jutsu. The target must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this Genjutsu’s effects and is aware you attempted to control it. Success: Affected creature is able to resist this Genjutsu’s effects. Failure: Affected creature immediately follows your suggestion. This jutsu lasts for 1 minute or until the target has completed a finite suggestion or the suggestion becomes harmful to the creature or has other obvious negative effects. Critical Failure: Affected creature is affected in the same as if they normally failed, but the duration becomes 1 hour.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "353435d84dd8161c981f3840", name: "THOUGHT SHIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "8 Hour", description: "You weave a clouding veil over the mind of one creature you touch. For the duration, the target’s mind can’t be read or detected, creatures can’t telepathically communicate with the target unless the target allows it, and the target has advantage on saving throws against any effect that would determine whether it is telling the truth. Additionally, the target has advantage on the first Intelligence or Wisdom saving throw it makes against a Genjutsu. Regardless if you pass or fail the save, this jutsu then ends on that creature. 200", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5761c2a73375efad9e4e3e68", name: "TRUE LIGHT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "self (30-foot radius)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minutes", description: "Your body releases a golden radiance that spreads out from you, providing bright light up to 30 feet away. Any creature or object in the area of bright light that are invisible, transformed, or hidden as a result of a Genjutsu of C-Rank or Lower, they are immediately revealed. Likewise, any Genjutsu with the Visual keyword of C-Rank or lower within 30 feet of you becomes feeble and transparent as their illusory nature becomes obvious. A creature who’s Genjutsu would be revealed to be an illusion may as a reaction make a Wisdom (Illusions) check at disadvantage vs your Genjutsu save DC. On a success, their Genjutsu retains is shape and form without revealing its true nature. A hostile creature attempting to cast a Genjutsu of C- Rank or lower that has the visual keyword, while within the bright light, must make a Wisdom saving throw. On a failed save, any creature who would make a saving throw as a result of their Genjutsu, makes their saving throw at advantage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the rank of jutsu this jutsu affects to a rank equal to the rank you cast this jutsu at", created_at: NOW, updated_at: NOW },
  { _id: "878c255f09463d1a345f88c5", name: "ZONE OF TRUTH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "15 Foot radius Sphere", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes.", description: "You create a chakra filled zone that guards against deception in a 30-foot sphere centered on a point of your choice within range. Until the Genjutsu ends, a creature that enters the jutsu’s area for the first time on a turn or starts its turn there must make a Charisma saving throw. You know whether each creature succeeds or fails on its saving throw. Critical Success: Affected creature is able to resist this Genjutsu’s effects and you are unaware if it passed or failed the save. Success: Affected creature is able to resist some of this jutsu’s effects but they still find it difficult to lie. They suffer a 1d4 penalty to Deception checks. Failure: Affected creature find it very difficult to speak any deliberate or intentional lies as they show a look of obvious discomfort and suffers a 1d6 penalty to Deception checks. Critical Failure: Affected creature becomes unable to speak if they would lie. B-RANK:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9f77d5f3aff65a93f6863e0d", name: "BLESS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Self (30-Feet)", chakra_cost: "10 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You release a pulse of chakra targeting all  allied creatures within 30 feet of you causing them feel deep  seeded Pride or ambition. Whenever an allied creature  makes an attack roll, saving throw, or skill check during this  jutsu’s duration, they can roll an additional 1d4 and add the  number rolled to their Attack, Saving throw, or skill check.  This jutsu’s cost cannot be reduced below 1, by any  means.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the radius by 10 feet. If cast at S-Rank the die becomes a d6.", created_at: NOW, updated_at: NOW },
  { _id: "24821f1e2aa3134846d6c76a", name: "CHAOTIC WORLD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "3d7fe1bb5775caf4818c287e", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CM, NT (Poison Kit)", duration: "Concentration, up to 1 minute.", description: "You throw a handful of colorful dust into the air while saying a litany of disjointed phrases. A moment later, a 25-foot cube centered on a point you can see within range fills with multicolored light, cacophonous sound, and overpowering scents and other confusing sensory information. The effect is dizzying and overwhelming. A creature who begins its turn while within the cube, must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this Genjutsu’s effects and becomes aware that they were a target of some Illusory effect. Success: Affected creature is able to resist this genjutsu’s effects. Failure: Affected creature becomes blinded, deafened and falls prone. An affected creature cannot stand up or recover from any single condition granted by this jutsu, while within the area. However, all conditions automatically end if a creature leaves this jutsu’s area or this jutsu ends. Critical Failure: Same effect as failure, but affected creature instead must begin to remake their saving throws at the end of each of their turns to end the jutsu’s effect, if they leave the area of the jutsu.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3, the range of this jutsu by 15 feet, and the size of the cube by 5 feet. 201", created_at: NOW, updated_at: NOW },
  { _id: "17f0437c25cd82ba239f81bb", name: "COMMAND OF THE FOUND", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You issue a single command, no longer than 25 words, directed at a single creature whom you can see who’s name you include in your command. If the creature can hear you, they must make a Charisma saving throw. If you command a creature to enter hazardous terrain, or to injure itself, it remakes its charisma saving throw each time it takes damage or suffer any effects fall under any conditions, immediately ending this jutsu on a success, or completing the task as commanded. Once completed, this jutsu then immediately ends. Success: Affected creature is able to resist this genjutsu’s effects. Failure: Affected creature becomes charmed by you and must attempt to complete whatever command you issued to them by any means necessary for the duration. Critical Failure: Same effect as failure, but affected creature instead rationalizes the command as being beneficial to both themselves and for you, seeing it as mutually beneficial. At the end of this jutsu’s duration, they lose any will or drive to complete the task.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the number of creature you can target with this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "1e85c6a5f3a2766821fb7fcc", name: "COMPULSION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "Creatures of your choice that you can see within range and that can hear you must make a Wisdom saving throw. A target automatically succeeds on this saving throw if it can’t be charmed. Success: Affected creature is able to resist this genjutsu’s effects. Failure: For the duration, you can spend a bonus action on each of your turns to designate a direction. The affected targets must use as much of its movement as possible to move in that direction on its next turn. It can take its action before it moves. After moving in this way, it can remake its saving throw to try and end this effect. They cannot be compelled to move into an obviously hazardous terrain, such as a fire pit, but it will provoke an attack of opportunity. Critical Failure: Same effect as failure, but affected creature can be commanded to move into a hazardous terrain.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "aba4ae66989da2819c585f86", name: "CONFUSION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d7fe1bb5775caf4818c287e", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You attempt to shatter the string of thought a creature has, instilling severe confusion while also causing them mental pain through inconsistency. Select one target within range. They must make a Wisdom saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature gains 1 rank of Confusion. Critical Failure: Affected creature gains 1 rank of Confusion, and the first check made to end the condition is increased by 2.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. 178 PSIONICS: CUT! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Tactile Description: You manifest blades formed of illusionary chakra, that rend through a creatures mental defenses. Make a ranged Genjutsu attack dealing 4d8 psychic damage. If this jutsu is cast while within 10 feet of the target creature, increase the critical threat range of this attack by +1. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8. If this jutsu is cast at B-Rank, increase the critical threat range by +1. If this jutsu is cast at S- Rank, increase the critical threat range by +2. PSIONICS: DELAY! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory Description: You manifest a delayed sound that remains humming for a few moments before vanishing. You then select one creature whom you can see within range. At the end of your next turn this jutsu takes effect. If the target creature has cast a jutsu of any type on their next turn, they take 3d12 psychic damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d12. PSIONICS: DRAIN! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: 1 Minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Tactile, Unaware Description: You attempt to drain the mental power of a hostile creature you can see, making it more difficult for them to think clearly in the moment. Select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: The hostile creature takes 3d6 psychic damage, and suffers a 1d4 penalty on all Intelligence based attack rolls and skill checks for the next minute. Critical Failure: Same as Failure, but damage is increased to 5d8. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and 1d8, respectively. PSIONICS: EXPOSE WEAKNESS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory, Tactile, Unaware Description: You attempt to expose the weakness of your foes by making them unconsciously expose themselves. Select one creature you can see within range, forcing them to make an Intelligence Saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature immediately begins to move in unnatural and clumsy ways. Attacks targeting the creature gains a 1d4 bonus to hit, once per turn, per creature. Critical Failure: Same as failure, but they also reduce their AC by 1, for the duration. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. PSIONICS: FALSE FUTURE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Unaware Description: You attempt to force a vision of a false future onto a target, causing them to make a poorly informed decision. Select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: The hostile creature must spend its reaction, to move no less than 30 feet, if it can, into a space it would move into if its turn were right now. Critical Failure: Same as failure, but its movement speed it reduced by half after its movement ends, until the end of its next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures this can target by +1. 179 PSIONICS: FORTRESS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual, Tactile Description: You conjure a suit of illusionary armor. This armor grants you a +1 bonus to your AC. If you would be the target of a Genjutsu attack, you instead treat this bonus as a +2. If a creature manages to score a hit with a melee weapon or taijutsu attack against you, you force them to make an Intelligence saving throw as you send back a psychic feedback. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature immediately falls prone and drops their weapon, if any. This does not prevent damage. This Jutsu then ends. Critical Failure: Same as failure, but their movement speed is also reduced to 0, until the end of their next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, you gain 5 Psychic Damage reduction for this jutsu’s duration. If this jutsu is cast at S-Rank, you gain 10 Psychic Damage reduction for this jutsu’s duration. PSIONICS: HOSTILE TRANSFER Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Genjutsu, Auditory, Tactile Description: You attempt to transfer the negative mental conditions of an allies creature to a hostile one. Select one allied creature you can see within range who has ranks of a Mental condition. When you do, select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: The Hostile creature gains one of the Mental conditions the allied creature has, (your choice) Critical Failure: The hostile creature gains all Mental conditions the allied creature has, and the allied creature loses each mental condition the hostile creature gains. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of hostile creatures you can target by +1. PSIONICS: MEDITATE! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Bonus action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM Cost: 3 Chakra Keywords: Genjutsu, Tactile Description: You steady your thoughts, finding balance and inner peace in the moment of battle. For the duration, you gain a 1d4 bonus to Genjutsu attacks and deal an additional 1d6 psychic damage with Genjutsu you cast. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the to hit and damage bonus by 1 die step (1d6, 1d8). If this jutsu is cast at S- Rank, increase the to hit and damage bonus by 1 die step (1d8, 1d10). PSIONICS: MIGRAINE! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Tactile Description: You outstretch your hand and select a target within range. The target creature must make an Intelligence saving throw. If their Intelligence ability score is 12 or less, they make this save at disadvantage. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature sees their body swell and experience an extraordinary amount of pain as their head feels like it will explode. They take 4d4 psychic damage and until the end of their next turn, they suffer a -10 penalty to their speed. Critical Failure: Affected creature sees their body swell and experience an extraordinary amount of pain as their head feels like it will explode. They take 6d4 psychic damage and until the end of their next turn, they suffer a -20 penalty to their speed and the next jutsu they cast and concentration cost they pay, cost is doubled, before the end of their next turn. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d4 and the number of creatures they can target by +1. 180 PSIONICS: MIND BLANK! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory, Tactile, Unaware Description: You weave a guttural and visceral sound that echoes outward designed to create pockets of blank space in the minds of the listener. Select a creature whom can hear you within range. The target must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this Genjutsu’s effects. Success: Affected creatures next jutsu cast increases its cost by +4 Failure: Affected creature becomes unable to cast a jutsu they cast on their previous turn. If they would attempt to cast such a jutsu, it fails. Critical Failure: Affected creature becomes unable to cast a jutsu they cast on their previous turn. If they would attempt to cast such a jutsu, it fails, and they suffer a splitting migraine taking 5d6 psychic damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1 and the damage by 1d6. PSIONICS: PSYCHO WAVE! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual Description: You manifest gauntlet of formed of illusionary pulses, that beat on the thought patterns of a creature, leaving it mentally drained. All creatures within a 15-foot cone originating from you must make a Wisdom saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature is Dazzled and Confused. Critical Failure: Affected creature is Dazzled, Confused and Concussed. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 5 feet. PSIONICS: PULSE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (20 –feet) Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory, Tactile Description: You manifest a pulse of thought, meant to inflict pain and disorient everyone near you. All creatures of your choice, within range must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 3d4 psychic damage and is forced to move back 10 feet away from you. Critical Failure: Affected creature takes 5d4 psychic damage and is forced to move back 25 feet away from you. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage by 1d4 and radius by 5 feet. PSIONICS: RANGE CRIPPLING Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual Description: You attempt to reduce a creatures effective combat range by clouding their vision and imposing visual limitations upon them Select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature gains 2 ranks of Dazzled for the duration. Ranks of Dazzled inflicted by this jutsu does not go away at the end of the affected creatures turns, instead only going away when this jutsu ends Critical Failure: Same as failure, but also if the creature would cast a jutsu or make an attack with a range, greater than 15 feet, reduce the range of the jutsu or attack by 10 feet. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures this can target by +1 and the range reduction of a critical failure by 5 feet. 181 PSIONICS: SHARED THOUGHTS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Unaware Description: You attempt to see into and share the thoughts of a creature you can see, seeing what they are thinking or planning. Select one creature you can see within range, forcing them to make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Additionally, they become aware someone tried to peer into their mind. Success: Affected creature is able to resist this jutsu’s effects. Failure: The hostile creature begins to unknowingly share their thoughts with you. At the beginning of each of its turns, the DM informs you of the jutsu they are casting, actions they are taking or the thoughts it has during its turn only. If the target would cast a jutsu or make an attack, you gain the benefit of a successful Read the Enemy reaction. At the end of each of the targets turns, it remakes it saving throw, while still unaware it is sharing thoughts with you. Critical Failure: Same as Failure, but the target does not get to remake its saves until it becomes aware it is under the effects of this Genjutsu. PSIONICS: SHOCK! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Tactile Description: You release a powerful jolt of psionic chakra meant to overwhelm the sensory receptors of a creature. One creature of your choice within range must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 6d4 psychic damage. This damage ignores Resistance and treats Immunity as resistance. Critical Failure: Affected creature takes 6d6 psychic damage and becomes Dazed. This damage ignores Damage Reduction and ignores Resistance and treats Immunity as resistance. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d4 or 1d6 or the number of creatures you can target by +1. PSIONICS: STRIKE! Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Tactile Description: You coat the hands and feet of a creature you touch in psionic energy. Making each strike harm both the body and mind simultaneously. When they would deal damage with an unarmed attack, they deal an additional 1d10 psychic damage, once per turn. If they would score a critical hit while gaining the benefits of this jutsu, you can choose to convert all damage dealt with the attack into psychic damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. PSIONICS: SUPPRESS FOCUS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual Description: You attempt to force a creature gaining the benefit of a buff of any type, to no longer benefit from that buff. Select one hostile creature you can see within range, forcing them to make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: If the target is under the effects of Jutsu that grants it a bonus to attacks, damage, AC, skill checks or ability checks, select one of the aforementioned statistics. It has the chosen benefits suppressed, becoming unable to gain that boost to the chosen statistic for the duration. Critical Failure: Same as failure, but instead of one statistic, they cannot gain a jutsu based bonus to any of the listed statistics for the duration. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures this can target by +1. 182 PUPPETS OF DARKNESS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Tactile Description: You weave chakra creating animated illusions of a creatures shadow within range, causing it to attack. As a bonus action, when you cast this jutsu or as a bonus action on subsequent turns, while you maintain concentration, command the shadow to attack. Make a Melee Genjutsu attack against a target creature. On a hit, you deal 2d10 psychic damage and they must make an Intelligence saving throw, being dazed until the start of your next turn on a failed save. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you target with this jutsu by +1. SANCTUARY Classification: Genjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: 30 Feet Duration: 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual, Unaware Description: You weave chakra creating a hazy ward of illusions protecting a creature within range against attack. Until this jutsu ends, any creature who targets the warded creature with an attack or a jutsu must first succeed a Wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or jutsu. This ward does not protect against area effects, such as a Fire Release: Fireball or any similar jutsu. If the warded creature makes an attack or casts a jutsu that affects a creature, this jutsu ends. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you target with this jutsu by +1. SEALING ART: DELUSIONS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 5 Chakra Keywords: Genjutsu, Visual, Fuinjutsu Description: You infuse chakra into chakra seals as you attempt to mark a creature you can see in range with the seal of the desires. The target creature must make a Charisma Saving throw. On a failed save, the target is marked with the seal of desires as they begin to see flashes and visions of the things they want most in life causing them to freeze in place, focusing on the things before them. For the duration, a creature who is marked with this seal, at the beginning of each of their turns remake the saving throw, being stunned until the end of their turn on a failed save. On a successful save, they resist the seals effects, ending this jutsu. If the target would take damage, they repeat the saving throw to end this jutsu. Another creature who can touch the affected target, can attempt a Wisdom (Illusions) check vs your Genjutsu save DC to forcefully end this jutsu on them. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If Cast at B-Rank, increase the number of creatures you target with this jutsu to 2. If Cast at S-Rank, increase the number of creatures you target with this jutsu to 3. SEALING ART: SWEET DREAMS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 4 Chakra Keywords: Genjutsu, Visual, Fuinjutsu Description: You infuse chakra into chakra seals as you attempt to mark a willing creature you can see in range with the seal of the rest. For the duration, as a bonus action you can force the creature to experience a hyper accelerated sleep pattern. The target creature gains some of the benefit of a short rest allowing them to spend hit die to recover hit points. The affected creature does not regain any features or resources that would reset or be recovered on a short rest. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you target with this jutsu by +1. SEMBLANCE OF DREAD Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (20-foot radius) Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual Description: You morph your visage into that of a faceless monstrosity known as Nyarlathotep. This visage can be of your own description as this monstrosity has no known singular description. For the duration, any creature within 20 feet of you becomes unable to willingly move closer to you unless it makes a successful Wisdom saving throw at the start of its turn. Constructs and undead are immune to this effect. Additionally, you gain advantage on saving throws to resist the fear condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the radius by 5 feet. 183 SHADOW BITE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual, Tactile Description: You create a single momentary needle of darkness that erupts upwards from a creatures shadow that you can see within range. Make a ranged Genjutsu attack. On a hit you deal psychic damage equal to 4d6 + Your Genjutsu ability modifier and reducing their speed by 10 until the start of your next turn. A creature who’s speed is reduced in this way cannot benefit from additional speed for the duration of their speed reduction. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you can target by +1, the damage by 1d6 and the speed reduction by -5. SILENT IMAGE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 10 minutes Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual, Unaware Description: You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15- foot cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn’t accompanied by sound, smell, or other sensory effects. You can use your action to cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Physical interaction with the image reveals it to be an illusion, because things can pass through it, causing the Genjutsu to immediately end. SILHOUETTE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 100 feet Duration: Concentration, up to 10 minutes Components: HS, CM Cost: 3 Chakra Keywords: Genjutsu, Visual, Unaware Description: You create a shadow play against a screen or wall. The surface can encompass up to 100 square feet and does not have a singular point of origin, instead making use of all the shadows that mundane objects and structures give off. The number of creatures that can see the shadow play equals your Genjutsu ability modifier. The shadowy figures make no sound but they can dance, run, move, kiss, fight, and so forth. Most of the figures you can create are based on creatures you may have seen before. SOFT SPOKEN SONG Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Concentration, up to 10 minutes Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory Description: You begin to hum a tune or speak a phrase of your choice. When you do, all willing creatures within 30 feet of you begin to feel revitalized by your melody. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Creatures who begin their turns within range, gain advantage on Saving throws to resist Genjutsu with the Auditory Keyword, regardless of any other keywords the Jutsu may have. Additionally, Genjutsu with the Auditory and Unaware Keywords, lose the unaware keyword when affecting creatures benefiting from this jutsu. SONG OF THE ANCIENTS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: self (20-foot radius) Duration: Concentration, up to 10 minutes Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Tactile Description: You begin to hum or sing an erratic tune in an unintelligible language designed to send those who hear it into a short bout of madness. When you do, all creatures within a 20-foot radius of you begin to experience bouts of madness. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Creatures who begin their turns within range must make an intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature gains the madness condition until the end of their next turn. Critical Failure: Affected creature gains the madness condition for 1d4 of their turns. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the radius by 5. 184 SOUNDLESS, BLINDING ECHO Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: self (30 Foot Cone) Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory, Visual, Unaware Description: You scream in a silent misleading roar, you then cup your hands around your mouth while screaming. All creatures of your choice in a 30-foot cone in front of you, must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this Jutsu's effect. Success: Affected creature is able to resist most of this jutsu’s effects but becomes deafened until the end of their next turn. Failure: Affected creature takes 2d6 psychic damage and becomes blinded. At the end of each of its turns the target can make another saving throw to end this effect. Critical Failure: Affected creature becomes blind on a failed save. At the end of each of its turns the target can make another saving throw to end this effect. The creature also takes 4d6 psychic damage the turn they fail the save and 4d6 psychic damage at the beginning of the casters next turn. STARTLE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual Description: You weave together an image designed to startle and scare a creature but for a moment. Select one creature you can see withing range, target must make a Charisma saving throw. A creature immune to being frightened is immune to this jutsu’s effects. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature is spooked ending concentration on one jutsu it is concentrating on with the highest base cost. Critical Failure: Affected creature is spooked ending concentration on all jutsu it is concentrating on. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. THOUGHT FILM Classification: Genjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you take psychic damage. Range: Self Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Tactile Description: You manifest a psychic barrier designed to protect your mind from the harm another creature would inflict on it. When you would take psychic damage, you reduce the damage taken by 3d6. Additionally, you gain a 1d4 bonus to saving throws made to resist a Genjutsu’s effect, if any. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage reduction by 1d6. THOUGHT REJECTION Classification: Genjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage. Range: 90 feet (10-foot radius) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Tactile Description: You take a snapshot of the pain you feel, and attempt to inject it into the mind of a creature within range. Select a point you can see within range, where you send your psychic projection, which then explodes affecting all creatures within 10 feet of the chosen point. All affected creatures must make a Wisdom saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature takes 4d6 psychic damage. Critical Failure: Affected creature gains 1 rank of Dazzled and takes 4d6 psychic damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. UNBOUND LAUGHTER Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, up to 1 minute. Components: HS, CM, NT (Laughing Powder) Cost: 4 Chakra Keywords: Genjutsu, Auditory, Inhale Description: A creature of your choice that you can see within range, perceives everything as extremely funny and falls into a fit of laughter if this jutsu affects it. The target must make a Wisdom save. If the creature is damaged the jutsu ends immediately. A creature with an intelligence score of 4 or less is unaffected. A creature with a wisdom score of 15 or more makes its save with advantage. Critical Success: Affected creature is able to resist this Jutsu's effect. Success: Affected creature is able to resist most of this jutsu’s effects but becomes unable to take reactions until the beginning of its next turn. Failure: Affected creature succumbs to a fit of laughter falling prone and being unable to take reactions. A laughing creature remakes its saving throw at the end of each of its turns to end this jutsu’s effects. Critical Failure: Affected creature falls into a fit of laughter falling prone and becoming incapacitated. A laughing creature remakes its saving throw at the end of each of its turns to end this jutsu’s effects. 185 UNGLAMOROUS FACE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual Description: A willing creature you touch, has its face twisted until it becomes as mundane as possible. So much so that they become absolutely un-unique and incapable of standing out. For the duration, they become unrecognizable and become unable to be pointed out in a crowd. A creature attempting to see through this illusion must make a Wisdom (Insight) or Wisdom (Illusions) check vs your Genjutsu Save DC. On a success, they become immune to this genjutsu’s effects for the next hour. VIPERS GRIP Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (30-foot radius) Duration: 1 Minute Components: HS, CM, NT (Poison Kit) Cost: 5 Chakra Keywords: Genjutsu, Visual, Inhale, Unaware Description: You release an odorless poison into the air spending 1 charge of your Poison Kit and affecting creatures within 30 feet of you who inhale it. Creatures within range, must make a Wisdom saving throw. If an Envenomed creature is cured of the envenomed condition inflicted by this jutsu, this jutsu immediately ends. Critical Success: Affected creature is able to resist this Jutsu's effect becoming immune to it for the next 24 hours. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature becomes envenomed for the next minute and begin to see glimpses of snakes and other reptilian beasts converging on them. At the beginning of an envenomed creatures turn they must make a Wisdom (Acrobatics) check vs your Genjutsu Save DC. On a failed check they are restrained by the snaked until the beginning of their next turn. Critical Failure: Affected creature becomes envenomed for the next minute and begin to see glimpses of snakes and other reptilian beasts converging on them. At the beginning of an envenomed creatures turn they must make a Wisdom (Acrobatics) check at disadvantage vs your Genjutsu Save DC. On a failed check they are restrained by the snaked for the duration. WEAPONS OF DARKNESS Classification: Genjutsu Rank: D-Rank Casting Ti", created_at: NOW, updated_at: NOW },
  { _id: "df51e2b421deb8f5071c93be", name: "DARK LOTUS FIELD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Hour", range: "Special", chakra_cost: "Special", components: "HS, CM, NT (Poison Kit & Any Poisonous", duration: "Special", description: "As a part of casting this jutsu, you must have fertile soil which can facilitate a flowers growth. You take your poisonous flower and infuse a dose of poisonous chemicals into the flower itself before you plant the flower into the soil and infuse your chakra into it giving it life and influencing the potency of the poison this jutsu produces. If this flower, before or after being planted is killed or destroyed, this jutsu immediately ends, requiring you to recast it. The flowers look like a sacred lotus with black petals. Creatures looking for this flower, if they are proficient in Nature, Medicine, or Survival they may make any of the aforementioned skill checks vs your Genjutsu Save DC being able to find it on a success. If the creature is not proficient, they instead make a Wisdom (perception) check with a -5 penalty, to their check. If your flower is in a bed of other sacred lotuses, regardless if they are proficient or not, they take a -5 Penalty to their check. The flower has 10 Hit point and an AC of 15. At the conclusion of casting this jutsu you can infuse different volumes of chakra into the soil and roots facilitating different effects. 11 Chakra: This flower grows, producing black flower buds in the shape of a sacred lotus flower. As an action, for 10 minutes, while you are within 100 feet of this flower, the flower blooms releasing a black poisonous, but odorless cloud. All creatures within 60 feet of the flower of your choice must make a Intelligence saving throw at the beginning of each of their turns. On a failed save they become envenomed for the next hour. A creature envenomed as a result of this jutsu takes a -2 penalty to their attack and damage rolls, saving throws, skill checks. Additionally, the poisoned creature treats all Genjutsu you cast as if it has the unaware keyword. After 10 minutes or after the flower is destroyed, this jutsu ends. 22 Chakra: You gain all previous chakra costs effects. In addition, you can activate this jutsu while you are within 250 feet of the flower and it affects all creatures of your choice within 120 feet of it. 33 Chakra: You gain all previous chakra costs effects. In addition, affected creatures instead have a -5 penalty to their attack and damage rolls, and any psychic damage they would take deals additional psychic damage equal to twice your Genjutsu ability modifier. If any psychic damage you deal, adds your Genjutsu ability modifier, this jutsu’s damage is in addition to it. 44 Chakra: You gain all previous chakra cost effects. In addition, genjutsu you cast while within 250 feet of your flower, does not require you to spend chakra to maintain concentration for up to 1 Hour. Additionally, any genjutsu you cast that requires concentration, instead has its duration become 1 hour, while within 250 feet of your flower so long as your flower is still alive. After 1 hour, or after the flower is destroyed, this jutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "67fe9c19aecf3e636941391c", name: "DETRIMENTAL ENVIRONMENT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "90 feet (60-foot cube)", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, 10 Minutes", description: "You create an illusory hostile environment designed to act detrimental to creatures of your choice. You do not need to spend chakra to maintain concentration on this jutsu. Select a space you can see within range. The environment in a 60-foot cube centered on this point begins to move and act seemingly on its own. When a creature begins its turn in the space, or enters the space for the first time it must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this Genjutsu’s effects and becomes immune to this jutsu until the end of its next turn. Success: Affected creature is able to resist this genjutsu’s effects. Failure: Affected creature begin to see and hear the environment begin to turn on them, grappling and holding them in place. Their speed is reduced to 0 and they lose the ability to move one of their hands. An affected creature remakes their save at the end of each of their subsequent turns, ending this Genjutsu on a success. Critical Failure: Same effect as failure, but affected creature instead loses the ability to move either hand.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5cbcc530788a0e9aa3b50adb", name: "EFFORTLESS PARALYSIS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a visual image of your own description that grabs and restrains a creature you can see within range. The target must make a Wisdom Saving throw. This jutsu has no effect on undead, constructs, plants, or Demons. Success: Affected creature is able to resist this genjutsu’s effects. Failure: Affected creature becomes stunned for the duration. A stunned creature remakes their save at the end of each of its turns or when it takes damage, ending this jutsu’s effect on it, on a success. Critical Failure: Same effect as failure, but affected creature also only makes its saves when it takes damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4852ef2cddc66f0221b882d4", name: "ENCROACHING DARKNESS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "150 feet (60-foot radius sphere)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Hour", description: "You cause menacing shadows to invade an area, centered on a point you can see within range. Creatures become unable to see Bright or dim light as it seems to vanish before their eyes. Any jutsu or effect of C- Rank or lower that would create light, does not produce visible light for creatures within range to see. Yourself and up to 3 creatures of your choice are immune to this jutsu’s effects and are treated as if being concealed by darkness against creatures who are under this jutsu’s effects. A creature can, on their turn as an Action, make a Wisdom saving throw. On a successful save, they can see through the darkness until the beginning of their next turn. If a jutsu of B-Rank or higher is cast within this jutsu’s area of effect that produces light, this jutsu immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e790c49d45889f48ddcac0a2", name: "ENEMIES ABOUND", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You reach into the mind of one creature you can see and force it to make an Intelligence saving throw. A creature automatically succeeds if it is immune to the fear condition. Success: Affected creature is able to resist this genjutsu’s effects. Failure: Affected creature becomes berserked for the duration. A berserked creature makes a charisma saving throw at the end of each of its turns, ending this Jutsu's effects on them on a success. Critical Failure: Same effect as failure, but affected creature also take 4d6 psychic damage at the end of each of their turns, they don’t end this jutsu’s effect.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "90da61366c4b72eb432ce284", name: "EYES OF TRUTH", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "HS, CM, NT (Glass or translucent crystal)", duration: "1 minute", description: "You coat your glass or crystal in chakra that creates a visual illusion, that shows what friendly creatures in a 60-foot radius centering on you is able to see. If they see an illusion or can perceive something with special senses like Truesight, or Chakra Sight, you can also see what they can see, while looking through this glass or crystal.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d2fa3b6e709d22abafb00a6e", name: "FEAR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Self (15-foot cube)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You awaken a sense of mortality in one creature you can see within range after releasing some potent aromas from incents you spread and use as the catalyst for your genjutsu. A construct or undead is immune to this effect. The target must make a Wisdom saving throw at the beginning of each of its turns for the duration. Critical Success: This jutsu ends on the affected creatures, removing all ranks of fear granted by this jutsu. Success: Affected creature does not gain a rank of fear. Failure: Affected creatures gains one rank of fear against the caster until this jutsu ends. Critical Failure: Affected creatures gains two ranks of fear against the caster until this jutsu ends and falls prone from the shock.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select 1 additional creature who must all be within 30 feet of each other when you target them. CHARMING DISSONANCE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory Description: You attempt to suppress strong emotions in up to 3 creatures who can see and hear you within range. You speak with a reverberating confidence that quells their fears, anger, and confusion. Up to 3 creatures you choose must make a charisma saving throw; A creature can choose to fail this saving throw if it wishes. If a creature fails its saving throw, choose one of the following effects. • You can suppress any effect causing a target to be charmed or feared. When this jutsu ends, any suppressed effect resumes, provided that its duration has not expired in the meantime. • Alternatively, you can make a target indifferent about creatures of your choice that it is hostile towards. This indifference ends if the target or its allies are attacked. When this jutsu ends, the creature becomes hostile again. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select 1 additional creature. CLOAK OF SHADOWS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual, Unaware Description: You cloak a willing creature you touch in illusionary darkness, granting it a +1d4 bonus to Hide or Sneak attempts vs creatures that rely on sight for the duration. Additionally, if cast in Dim Light or Darkness, creatures attempting an Identify Genjutsu action, make their check at disadvantage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at B-Rank, the duration increases to “up to 10 minutes” and no longer costs chakra to maintain concentration. If cast at A-Rank, this jutsu’s duration becomes 1 Hour and no longer requires concentration. 162 COLOR SPRAY Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual Description: You manifest a dazzling array of flashing, colored lights, that spring forth from your hand. Creatures in a 15-foot cone, originating from you must make an Intelligence saving throw. Critical Success: Affected creature is able to completely resist this jutsu’s effect. Success: Affected creature gain 1 rank of Dazzled. Failure: Affected creatures Blinded until the end of their next turn. Critical Failure: Affected creatures becomes blinded and must remake the intelligence saving throw at the end of each of its turns to realize it’s not actually blinded, ending this jutsu’s effects on them. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 10 feet. COMMAND Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: 1 Round. Components: CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Unaware Description: You speak a one-word command to a creature you can see within range. The target must make a Wisdom saving throw or follow the command on its next turn. The jutsu has no effect if the target is undead, if it doesn’t understand your language, or if your command is directly harmful to it. Some typical commands and their effects follow. You might issue a command other than one described here. If you do so, the GM determines how the target behaves. If the target can’t follow your command, the jutsu ends. • Approach: The target moves towards you by the shortest and most direct route, ending its turn if it moves within 5 feet of you. • Drop: The creature drops whatever it is holding and then ends its turn. • Grovel: The target falls prone and then ends its turn. • Flee: The target turns and spends its turn moving away from you by the fastest means available. • Halt: The target doesn’t move or take actions. A flying creature stays aloft, provided that it is able to do so. If it must move to stay aloft, it flies the minimum distance needed to remain in the air. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you target by +1. COMPELLED DUEL Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Visual Description: You attempt to compel a creature into a duel. They see you as the only worthy foe in the area and will do everything they can to fight you and only you, while becoming indifferent towards other combatants. One creature that you can see must make a wisdom saving throw. Success: Affected creature ignores this jutsu and suffers no effects. Failure: Affected creature becomes drawn to you suffering a -1d6 penalty to all attacks rolls against creatures other than you for the duration. A compelled creature must remake their saving throw at the end of each of its turns to end this effect on them. This jutsu ends if you attack any other creature or if a friendly creature to you, would assist you in any way. Critical Failure: Affected creatures becomes drawn to you, becoming unable to target any other creature other than you for the duration. This jutsu ends if you attack any other creature or if a friendly creature to you would assist you. COMPREHEND LANGUAGES Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 1 Hour Components: HS, CM Cost: 3 Chakra Keywords: Genjutsu, Auditory, Unaware Description: For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching a creature who can already understand the language. CONFIDENCE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: 1 Minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory Description: You select up to 3 willing creatures in range, that you can see, reinforcing their confidence in themselves, allowing them to act with little to no hesitation. For the duration, whenever a target creature makes an Ability check, they add +2 to the result. The first time the succeed on an Ability check, this jutsu ends. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, this bonus instead becomes a +3. If this jutsu is cast at S-Rank, this bonus instead becomes a +4. 163 CORRUPTION: ANIMUS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action. Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Unaware. Description: You collect and build illusionary chakra, attempting to mentally disable the confidence and Strengths of your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures who would gain dice-based bonuses as a result of features or traits to their attack or damage rolls, they instead treat those bonuses, as penalties, for the duration. Critical Failure: Same as failure, but this inversion also extended to Jutsu based bonuses. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. CORRUPTION: ASPERITY Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory, Unaware. Description: You collect and build illusionary chakra, attempting to inject a sense of harshness towards allies, in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: If the affected creature would cast a jutsu that allows them to omit or exclude its allies, for every hostile creature they select, they must also choose one ally as a target as well, even if they have a limited number of targets they can select, that selected ally counts as one of its choices. Once this effect takes place, this jutsu ends. Critical Failure: Same as failure, but this effect lasts for the duration. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. CORRUPTION: AUDACITY Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory, Unaware. Description: You collect and build illusionary chakra, attempting to inject a sense of harshness towards allies, in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Creatures who would attempt to make an attack of any type targeting a creature you are allied with, the affected creature is mentally forced to hold back on the Strength of the attack, reducing the damage they deal by 1 damage die, to a minimum of 1 damage die. Critical Failure: Same as failure, but the damage die reduction is increased to 2. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the damage die reduction by 1. If this jutsu is cast at S-Rank, increase the damage die reduction by 2. CORRUPTION: DISDAIN Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action. Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Unaware Description: You collect and build illusionary chakra, attempting to mentally corrupt the feeling of happiness and stability in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures who would attempt to cast a jutsu as a reaction, that would interrupt the casting of another jutsu, must roll a d20. On a roll of 11 or higher, they lose their reaction, unable to interrupt their original target. Critical Failure: Same as failure, but on a roll of 6 or higher they lose their reaction, unable to interrupt their original target. 164 CORRUPTION: ENMITY Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action. Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 3 Chakra Keywords: Genjutsu, Visual, Unaware. Description: You collect and build illusionary chakra, attempting to inject a sense of broken morale and distrust in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures whose ally is casting a jutsu, must spend its reaction to cast a jutsu that would Interrupt the casting of their allies. Once they attempt to interrupt the casting, this jutsu then ends. Critical Failure: Same as failure, but the affected creature must spend its reaction to attempt to interrupt all of its allies jutsu castings, if able, for the duration. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. CORRUPTION: GALL Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory, Unaware. Description: You collect and build illusionary chakra, attempting to inject a sense of impudence in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures cannot upcast their jutsu for the duration. If they would attempt to do so, they still spend the chakra, but its effects remains its base rank. Critical Failure: Same as failure, but the affected creature must attempt to upcast their jutsu cast to the highest rank possible, spending the chakra as normal, but its effects remain as its base rank. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. CORRUPTION: INSOLENCE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Auditory, Unaware. Description: You collect and build illusionary chakra, attempting to inject a sense of harshness towards allies, in your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Creatures under the effect of a Genjutsu, that grants a die-based bonus, have this bonus halved. Critical Failure: Creatures under the effect of a Genjutsu, that grants a die-based bonus, cannot benefit from this bonus for the duration. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. CORRUPTION: SPITE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action. Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory Description: You collect and build illusionary chakra, attempting to mentally disable the physical Strengths of your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures suffer a -2 penalty to all Strength based attack and damage rolls. Critical Failure: Same as failure, but the penalty is reduced by an additional -2. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the penalty by an additional -1. 165 CORRUPTION: TEMERITY Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual. Description: You collect and build illusionary chakra, attempting to suppress their boldness in combat. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until the end of the casters next turn. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creature loses the benefit of jutsu based bonuses to speed, becoming unable to benefit from them for the duration. An affected creature remakes their saving throw at the end of each of their turns. Critical Failure: Same as failure, but this also extends into class and class features as well. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. CORRUPTION: VILE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action. Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory Description: You collect and build illusionary chakra, attempting to mentally disable the physical flexibility of your foes. Select one creature you can see within range, forcing them to make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures suffer a -2 penalty to all Dexterity based attack and damage rolls. Critical Failure: Same as failure, but the penalty is reduced by an additional -2. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the penalty by an additional -1. DETECT EVIL Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: 10 minutes Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual, Sensory Description: For the duration, you know if there is someone within 60 feet of you with a hostile intention. You do not know their direct location only that they are within the range of this genjutsu. DETECT ILLUSIONS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (10-foot Radius) Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual Description: For the duration, you can sense the presence of Genjutsu of D-Rank or Lower within 10 feet of you. If you sense Genjutsu in this way, you can use your action to see a faint aura around any visible creature or object in the area that is affected by a Genjutsu. Additionally, if a Genjutsu affects an area, the affected area with glow with this aura instead of any individual creatures or objects. This jutsu cannot penetrate through barrier, walls or surfaces and does not provide insight on the Rank or number of Genjutsu affecting a creature. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the rank of Genjutsu you can detect. DETECT INTENTION Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 3 Chakra Keywords: Genjutsu, Visual, Sensory Description: Select a creature you can see within range. If the target is not aware of your presence roll your Illusion Skill vs their passive Deception. On a success you know what the creatures most immediate intention is. This does not explain why they are trying to do whatever it is they are trying to do just what it is they want to do. If the target is aware of your presence, they make a Wisdom saving throw. On a failure you gain the same information as you would if they weren’t aware of your presence. On a success they can hide their intention instead hiding it behind another set of intentions. DISTANT WORDS Classification: Genjutsu Rank: D-Rank Casting Time: 1 Minute Range: 30 feet Duration: Until Dispelled Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory Description: You implant a message within an object in range, a message that is uttered when a trigger condition is met. Choose an object that you can see and that isn’t being worn or carried by another creature. Then speak the message, which must be 25 words or less, though it can be delivered over as long as 10 minutes. Finally, determine the circumstance that will trigger the jutsu to deliver your message. When that circumstance occurs, a disembodied voice can be heard originating from the object and recites the message in your voice and at the same volume you spoke. When you cast this jutsu, you can have the jutsu end after it delivers its message, or it can remain and repeats its message whenever the trigger occurs. 166 The triggering circumstance can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the object. For example, you could instruct the illusion to speak when any creature moves within 30 feet of the object or when a silver bell rings within 30 feet of it. DISTORT VALUE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual, Unaware Description: When you cast this Genjutsu target an object no more than 1 foot on a side, doubling the objects perceived value by adding an illusionary flourish or reducing its perceived value by half with the help of illusionary dents or scratches. Anyone examining the object must roll an investigation or Illusions check against your genjutsu save DC to see through this genjutsu. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the object by 5. DOUBLED PAIN Classification: Genjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: 60 Feet Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Tactile Description: You target a creature and amplify their nervous system, enhancing all instances of pain to a massive degree. Select a target creature you can see within range. For the duration, whenever you deal damage using a Genjutsu, you deal an additional 1d8 Psychic damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and select one additional creature to be affected. ENVIRONMENTAL AFFINITY Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Special Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Visual Description: The environment seems to shift and swirl around you. For this jutsu’s duration, creatures looking at you see the natural terrain moving at your beck and call giving them pause. If cast while you are not in combat, this jutsu lasts for 1 hour. For that duration, you make your next initiative roll at advantage. If cast while in combat, this jutsu’s duration becomes Concentration, Up to 1 Minute, and creatures that target you with an attack or jutsu treat you as if you are in half cover. If the terrain is not natural and instead industrial such as a concrete hallway, steel floors, or anything similar, a creature makes a Wisdom (Illusions) check vs your Genjutsu Save DC at advantage, gaining immunity to this jutsu for the duration. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When casted at B-Rank this jutsu no longer requires concentration. EXTRASENSORY Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Visual, Inhale, Tactile Description: You manifest a barrage of supersensory sensations meant to overwhelm a creatures senses. Select one creature within range. Select creature must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature is suffering a 1d4 penalty to their next attack roll. Failure: Affected creature gains 2 ranks of Dazzled. Critical Failure: Affected creature gains 2 ranks of Dazzled and at the beginning of their next turn, they must roll a d10. On a roll of 1 or 2, they flinch losing their Action. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. FRENZY: BLACK Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory Description: You collect and build illusionary chakra, attempting to black out the thoughts of your targets, making it difficult for them to form coherent or even manageable thoughts. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects. Failure: Affected creatures begins to suffer mental black outs. At the beginning of each of their turns, they must make a Wisdom ability check vs a DC 13. On a failed check, all creatures in the turn initiative, is treated as a hostile creature for them, and they cannot exclude creatures in the effect area of a jutsu or features effects. At the end of each of their turns, they remake their saving throw, ending this jutsu’s effect on them on a success. Critical Failure: Same as failure, but the ability check DC is increase to a DC 16. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. 167 FRENZY: BLUE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 45 feet Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Unaware Description: You collect and build illusionary chakra, attempting to inflict a fit of depressing madness causing your eyes to glow blue. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: If the affected creature would make a saving throw for the duration, on a failed save, they after suffering the triggering jutsu’s effects, they fall prone and have their movement speed reduced by half, until the end of their next turn. Creatures remake their saving throw against this jutsu, at the end of each of their turns. Critical Failure: Same as failure, but their speed is instead reduced to 0. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. FRENZY: CYAN Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet (20-foot cube) Duration: 1 Round Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory Description: You collect and build illusionary chakra, attempting to inflict a fit of unstable madness meant to break the minds of creatures in the affected areas, as their eyes flash a cyan color. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: If the affected creature attempts to take an action or bonus action, it must make a Wisdom ability check vs a DC 13. On a failure, they stand still laughing manically, wasting the attempted action. On a success, they can take their actions as normal. This effect ends at the end of the affected creatures turn. Critical Failure: Same as failure, but the ability check DC is increased to 16. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cube by 5 feet FRENZY: GREEN Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action. Range: 30 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Unaware Description: You collect and build illusionary chakra, attempting to infuse a target within range, with an aspect of your madness, causing their eyes to glow green. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist most of this jutsu’s effects, instead only becoming concussed until the end of the next turn. Failure: Affected creatures succumbs to your aspect of madness. For the duration, if they would attempt to cast a Jutsu with a casting time of a Bonus Action, they must roll a 1d4. On a roll of 1 or 2, they fail to cast it as they lose focus with constant mutterings. On a roll of 3 or 4, they cast it as normal, and remake their saving throw to end this jutsu’s effects, while still unaware it is affected by this Genjutsu. Critical Failure: Same as failure, but they instead must roll a 1d6, only being able to cast normally on a roll of a 5 or 6. FRENZY: MAGENTA Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory, Unaware Description: You collect and build illusionary chakra, attempting to bring about a spiral of lustful insanity, causing their eyes to glow with a Magenta color. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: When the affected creature attempts to cast a jutsu or make an attack targeting another creature, they must make a Wisdom ability check vs a DC 13. On a failed save, they gain 3 ranks of Charm against that target for the duration. Critical Failure: Same as failure, but the ability check DC is increased to 16. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. 168 FRENZY: ORANGE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 5 Chakra Keywords: Genjutsu, Auditory Description: You collect and build illusionary chakra, attempting to inflict a fit of calm insanity, causing their eyes to flicker orange. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu for the next 10 minutes. Success: Affected creature is able to resist this jutsu’s effects. Failure: The affected creature must spend its bonus action, on each of its turns calmly but in a harmful way scratch at its arms, drawing wounds upon it, dealing 1d8+ the targets Strength modifier slashing damage. They then remake their saving throw vs this jutsu, ending it on a successful save. Critical Failure: Same as failure, but they instead must spend their action, not their bonus action, and they deal 2d6 + the targets Strength modifier slashing damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1 and the critical failure damage by 1d6. FRENZY: PURPLE Classification: Genjutsu Rank: D-Rank Casting Time: 1 Action. Range: 45 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Genjutsu, Visual, Unaware Description: You collect and build illusionary chakra, attempting to touch the madness building deep in the psyche of your foes causing their eyes to glow purple. Select one creature you are aware of, that can hear you within range, forcing them to make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s e", created_at: NOW, updated_at: NOW },
  { _id: "b5b992985ab047d48f8d84ca", name: "FORGET ME NOT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "11 Chakra", components: "HS, CM, NT (Poison Kit or Poisonous Flower)", duration: "Special", description: "You infuse chakra into a poisonous flower that you are holding. When you release the flower, all creatures except yourself within 5 feet of the flower are hit with a powerfully potent, yet odorless plume of poisonous pollen laced with your chakra. Creatures within range must make a Constitution and Intelligence saving throw, in that order. On a failed Constitution saving throw, the affected creature becomes poisoned for 1 hour (This cannot become envenomed) and a creature poisoned by this jutsu makes the next saving throw at disadvantage. On a failed Intelligence saving throw, they lose all memory of the past 24 hours, for the next hour as it becomes a haze. This memory is still there, but clouded and hazy. If they attempt to remember, they must make an Intelligence save throw at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3. When you cast this jutsu at A-Rank, on a failed save, their memory is permanently clouded over by this jutsu until Dispelled.", created_at: NOW, updated_at: NOW },
  { _id: "62fc99eb633f0d8ce97d66bb", name: "FRENZY: BLADES", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You collect and build all of your madness and instability and focus it into the shape of floating blades of your design. These blades oscillate around you and can be commanded to strike at your command. You manifest 4 of such blades. When you would deal damage with a Genjutsu with the ‘Frenzy’ prefix, you subconsciously fire a blade made by this jutsu, making a ranged genjutsu attack at advantage, dealing 4d8 psychic damage on a hit. Alternatively, as a bonus action, you can command one of these blades to strike your enemies. Make a ranged Genjutsu attack, dealing 5d8 psychic damage on a hit. A creature who takes damage from this jutsu must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s secondary effects. Failure: Affected creatures falls prone and falls into a bit of insanity as their eyes begin to swell and their thoughts slow down, as they gain the Slowed condition until the end of their next turn. Critical Failure: Affected creature falls prone and falls into a bout of insanity as their eyes begin to swell and their thoughts slow down, as they gain the Slowed condition for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d2eb31ca858b270f4c839d27", name: "FRENZY: BURST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You collect and build all of your madness and instability and focus it into a beam, that another creature is forced to take on. Select one creature you can see within range, and make a range Genjutsu attack, dealing 8d6 psychic damage. On a successful hit, the target must also make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s secondary effects. Failure: Affected creatures falls prone and falls into a bit of insanity. They become Berserk. Critical Failure: Affected creature falls prone and falls into a bout of insanity. They gain 2 ranks of Berserk.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c8e110117727b37d973583e3", name: "FRENZY: CACKLE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action.", range: "Self (30 feet)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You collect and build all of your madness and instability and release it into an echoing wave that tears through the minds of creatures within range. All creatures, including yourself, in range must make an Intelligence saving throw. You make your saving throw at advantage. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature becomes blinded until the end of the current turn as their madness blinds them. Failure: Affected creatures takes 4d12 psychic damage and becomes blinded for the next minute, remaking saving throws at the end of each of their turns, ending this jutsu’s effect on a success. Critical Failure: Affected creatures takes 6d12 psychic damage and becomes blinded, deafened, and incapable of smelling or tasting as they begin to laugh manically for the next minute, remaking their saving throw at the end of each of their turns, with a 1d4 penalty ending this jutsu’s effect on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fd28a82da22438daffa5b3fd", name: "INVISIBILITY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You quickly pull a chameleon cloak over yourself while against a wall or other standing surface. Roll a stealth check with a 1d4+1 bonus to the check. If a creature would attempt to make a perception check in an attempt to find you, they make their check with a 1d4+1 penalty to their check. This penalty lasts until you move more than 10 feet from your current location. LIGHT Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Touch Duration: 1 Hour Components: CM Cost: 1 Chakra Keywords: Ninjutsu Description: You touch one object that is no larger than 10 feet in any dimension. Until the jutsu ends, the object sheds bright light in a 10-foot radius and dim light for an additional 10 feet, the light is a soft blue/ Completely covering the object with something opaque blocks the light. The jutsu ends if you cast it again or dismiss it as an action. If you target an object held or worn by a hostile creature, that creature can must make a Dexterity saving throw to avoid the jutsu. MENDING Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Minute Range: Touch Duration: Instant Components: CM Cost: 1 Chakra Keywords: Ninjutsu Description: This jutsu repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot, you mend it, leaving no trace of the former damage. 5 SEALING ART: STRING LIGHT FORMATION Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 2 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You use your chakra to create a sealing formation stretching from yourself to a target creature you can see within range, in a straight line. The target creature must make a Charisma saving throw, reducing both your and the target’s movement speed to 0 on a failed save. This can be used with others targeting the same creature, increasing the Save DC by +1 for each additional user. At the end of the target creatures turn, they remake their save. MEDICAL RELEASE: VIRTUE Classification: Ninjutsu Rank: E-Rank Casting Time: 1 Action Range: Touch Duration: 1 Round Components: HS, CM Cost: 1 Chakra Keywords: Ninjutsu, Medical Description: You touch one willing creature, imbuing it with vitality. If the target has at least 1 hit point, it gains a number of temporary hit points equal to 1d4 + you ninjutsu ability modifier. The temporary hit points are lost at the end of the creatures next turn. D-RANK: ADVANCED TRANSFORMATION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: Concentration, Up to 10 minutes Components: HS, CM Cost: 3 Chakra Keywords: Ninjutsu Description: An advanced form of the transformation technique. When cast you transform your body into a physical object such as a weapon or object of Small or Medium size. While transformed into an object you take on its physical properties and function as this object. If transformed into a weapon you also take on its weapon properties. Others can wield and use you as a weapon so long as you maintain concentration on this jutsu. You cannot transform into any object that separates into multiple pieces, disconnects or has multiple moving mechanical parts, such as an electric fan or a Safe. If you do, these additional pieces or functions do not work or cannot be moved by any means. While transformed you cannot move or act or speak. You are aware of your immediate surroundings and can hear as normal, but are unable to cast jutsu or make attacks of any kind while transformed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When Cast at B-Rank you can transform into large or smaller objects. ALARMING TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Cube Duration: 8 Hours Components: HS, CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu, Sensory Description: You set a chakra seal that expands 30 feet across the ground or surface it is placed on and it releases a very faint and mostly undetectable aura of chakra in a 30- foot cube. Until the Jutsu ends, an alarm alerts you whenever a creature touches or enters the Seals area. When you set the seal, you can designate creatures that don’t set off the alarm. You can also choose to make the alarm mental or audible. ARMS OF BUDDHA Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 10ft Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You focus your chakra throughout your body, culminating in a golden buddha forming around you and making multiple strikes with its 100 arms. Make a Melee Ninjutsu Attack against a creature within range, on a hit the target creature takes 4d6 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and the damage by 2d6. BEAST IMITATING ART: BAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Instant Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You inscribe into your scroll the image of a bat to blind you enemies. Make a ranged ninjutsu attack against a medium or smaller sized creature. On hit the creature becomes blinded as the bat latches onto their face blocking vision. As an action on the creatures turn, they can attempt to pull the bat off by making a Strength saving throw ending the blinded condition on a successful save. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and this number of attacks this jutsu can make by +1. However, each additional attack must target a different creature. 6 BEAST IMITATING ART: DEER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Instant Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You draw an image of a herd of deer that charge from your scroll towards your chosen target. Make a ranged ninjutsu attack. On a success, the target creature takes 2d8 in Bludgeoning damage and must make a Strength saving throw, being knocked prone on a failed save. If this jutsu is cast targeting a prone Creature, you do not roll disadvantage, instead rolling advantage and dealing an additional 2d6 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. BEAST IMITATING ART: LIZARD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You summon an inky lizard in a space you can see within range that can hold it. The lizard is a construct with the following statistics; • AC 12, 5d6 (20) Hit points. The lizard immediately after being summoned, screeches a menacing sound to those around it. All creatures who begin their turn within 10 feet of the lizard excluding you, must make a Wisdom saving throw. On a failed save they gain 1 rank of Fear. So long as a creature has ranks of fear gained as a result of this jutsu they cannot willingly approach the Lizard. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range of the lizards Screech by 5 feet. BEAST IMITATING ART: PIDGEON Classification: Ninjutsu Rank: D-Rank Casting Time: Up to 10 Minute Range: Self Duration: 24 Hours Components: HS, CM, CS, NT (Empty Scroll) Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You write in your scroll a message of any length that you can conceivably write within a 10 minute or less time span. Once complete, the writings manifest into the form of a bird of your description and now carry themselves. You can also cast this jutsu targeting a message already written of 25 words or less. The bird you create has 1 hp and an AC of 15. You then specify a location that you have previously visited and a recipient who matches a general description. You can also then give the bird a letter, scroll, tag, or similarly small object to deliver to this creature. The construct travels for the duration of the jutsu towards the location, covering no more than 50 miles per 24 hours. When the bird arrives, it turns back into the message when provided a scroll to be placed on and delivers any packages to the creature you described. The bird will only release the object to the creature you specified or if killed. The creature dissipates into non-staining ink when the message is delivered or it is killed. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and duration increases by 24 hours. When casting this jutsu at B-Rank or Higher, the bird becomes large in size and is capable of carrying two medium size creatures on its back. BEAST IMITATING ART: RATS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Minute Range: 1 Mile Radius Duration: 10 Minutes Components: HS, CM, CS, NT (Empty Scroll) Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu, Sensory Description: When you cast this jutsu you draw a horde of rats into your scroll. After 1 minute the picture is finished and the rats come to life scattering around. After a 10-minute delay, you can make a Ninshou check. Based on your level of success, you become aware of a variety of things within a 1-mile radius. • DC 10: You become aware of structures that are not hidden within range. This does not inform you of their specific location or size, only their general direction. • DC 15: You become aware of any non-hidden creatures within range. This does not inform you of their specific location or even the type of creature they are, only their general direction. • DC 20: You become aware of hidden structures within range. • DC 25: You become aware of the size of Structures and the types of creatures within range. • DC 30: You become aware of hidden creatures. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the range of this jutsu to 2 miles. If this jutsu is cast at S-Rank, increase the range of this jutsu to 3 miles. 7 BEAST IMITATING ART: RETRIEVAL HAWK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 120 feet Duration: Concentration, up to 1 minute Components: HS, CM, CS, NT (Empty Scroll) Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You hurriedly draw an image of a hawk to retrieve something for you. The hawk breaks out of your scroll and attempts to retrieve an object no more than 10 pounds and bring it to a destination of your choosing within range. The hawk has a fly speed of 45ft, AC of 15 and 1 hp. The hawk must stay within the range of this jutsu from the caster at all times and does not require the caster's actions to command aside from its initial creation. The destination of delivery can be changed as a bonus action on the casters turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the hawks speed by 10 feet, the weight it can carry by 10 pounds and this jutsu’s range by 30 feet. BEAST IMITATING ART: SNAKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: When you cast this jutsu you draw an image of two snakes into your scroll infusing chakra into it making it come to life. You command the pair of snakes to wrap around your enemies. Target up to two creatures within range. Each creature must make a Strength saving throw. If any of the creatures are within 5 feet of each other they each make the save at disadvantage. On a failed save, they are restrained by the snakes as they wrap around them. A creature restrained by this jutsu, may as an action on their turn attempt another Strength save to end this condition. If affect creatures are within 5 feet of each other, when one creature succeeds all creatures within 5 feet of them, restrained conditions ends. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets by +1. BODY CAMOUFLAGE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 1 minute Components: HS Cost: 5 Chakra Keywords: Ninjutsu Description: You coat your body in chakra and begin to imitate the color and texture of the area around you blending in like a chameleon. For the duration, roll an additional +4 adding the result to your stealth checks. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and you can target one additional creature for each rank and they gain the benefits of this jutsu as well. BODY FLICKER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: 1 Round Components: HS, M Cost: 3 Chakra Keywords: Ninjutsu Description: You gain a mastery of movement, allowing you to cover much greater distance in a shorter amount of time. Until the end of your next turn, increase your speed by 30 feet. CALLING ON TEARS TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (30 Foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You manifest chakra around your tongue and throat as you use it to vibrate and magnify all sound escaping your mouth. You then release a stunning scream in an attempt to incapacitate all that hear it. All creatures in a 30-foot cone originating from you must make a Wisdom saving throw, being Deafened and Dazed until the end of their next turn on a failed save. Additionally, any traps such as explosives, trap doors or pressure plates that are within this jutsu’s range are triggered. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range by 5 feet. CATAPULT TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 action Range: 90 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Ninjutsu Description: Choose one object weighing no more than 1 bulk within range, that isn’t being worn or carried. The object flies in a straight line up to 90 feet in a direction you choose before falling to the ground, stopping early if it impacts a solid surface. If the object would strike a creature that creature must make a Dexterity saving throw. On a failed save, the object strikes the target and stops moving. In either case, both the object and the creature or solid surface takes 3d8 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the maximum bulk of the objects that this jutsu can use increases by 1 bulk, and the maximum distance by 10ft. This jutsu’s damage also changes depending on the affected object’s bulk: 1 Bulk or less: 3d8. 2 Bulk: 4d8 3 Bulk: 5d8 4 Bulk: 6d8 5 Bulk: 7d8 8 CHAKRA BOLT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Ninjutsu, Clash Description: You manifest a 4-inch sphere of pure chakra at a creature you can see within range. Make a ranged ninjutsu attack. On a hit, the target takes 3d6 damage. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. Additionally, you gain one of the following benefits based on the Damage type of this jutsu. • Earth: The target must make a Strength saving throw being Bruised on a failed Save. • Wind: The target must make a Strength saving throw being pushed back 15 feet and being knocked prone on a failed save. • Fire: Each creature within a 5-foot radius sphere of the target creature must make a Dexterity saving throw, being burned on a failed save. • Cold: Each creature within a 5-foot radius sphere of the target creature must make a Constitution saving throw, being chilled on a failed save. • Lightning: The target must make a Constitution saving throw, being shocked until the end of their next turn. • Force: Changed damage die to d8. The target must make a Dexterity saving throw being Dazed. CHAKRA LEAPING Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus action Range: Self Duration: Instant Components: HS, M Cost: 3 Chakra Keywords: Ninjutsu Description: You focus chakra into your legs, increasing your jumping Strength astronomically. Until the end of this turn, Double your jumping height. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, the duration of this jutsu becomes 1 minute. If this jutsu is cast at S-Rank, the duration becomes 1 hour. CHAKRA MARK Classification: Ninjutsu Rank: D-Rank Casting Time: Special Range: Touch Duration: 10 Minute Components: CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu, Sensory Description: You create a chakra seal and attempt to place it on a creature, structure or construct you are able to touch. When you score a hit with a melee attack or a ranged attack, you are able to mark a creature. This does not work if another creature, construct or structure intercepts the attacks damage. While a creature, construct or structure is marked with this jutsu and is within 1 mile of you, you become aware of the existence of this seal, but not its immediate location. You gain a +4 bonus to all checks made to find or track the marked creature. Additionally, if you can teleport you can choose to teleport to a marked creature, construct or structure so long as they are within 1 mile of you. Once you teleport in this way, the mark vanishes, ending this jutsu. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. At C- Rank This jutsu’s Duration becomes 1 Hour. 8 Hours at B- Rank, 24 Hours at A-Rank, Permanent at S-Rank. CHAKRA SHIELD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you take damage. Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Clash Description: You manifest a swirling barrier of chakra around you protecting you from the triggering attack. You gain 12 Temporary Hit points. If you have a nature release, this jutsu gains a single nature release keyword that you can cast, and additional effects base on the Nature release. Your shield gains one of the following benefits based on the chosen nature release. If you do not have a nature release this shield instead has 16 temporary hit points. • Earth: This jutsu gains the Construct keyword. Your shield has resistance to Cold damage, vulnerability to lightning Damage and once cast leaves behind an Quake Shard in a 5ft cube within 5ft of you. • Wind: Your shield has resistance to Lightning Damage, vulnerability to Fire Damage and once cast all creatures of your choice within 5 feet of you gains 1 rank of bleed. • Fire: Your shield has resistance to Wind Damage, Vulnerability to Cold Damage and all creatures within 10 feet of you takes fire damage equal to your Ninjutsu ability modifier. • Water: Your shield has resistance to fire damage, vulnerability to earth damage and if this jutsu is cast near a sufficient source of water, reduce the cost of this jutsu by -2. • Lightning: Your shield has resistance to Earth damage, vulnerability to wind damage and you gain a +2 to Dexterity saving throws until the beginning of your next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points you gain by +6. 9 CHAKRA SKIN Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Until Short Rest Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You coat yourself in a Protective aura of chakra, protecting you from damage. When you cast this jutsu, you lose the benefits of any Armor you are wearing, utilizing this Jutsu’s AC calculation for its duration. Your AC becomes 13 + your Intelligence Modifier + Half of your proficiency Bonus. This jutsu ends if you dismiss it as a Bonus action. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank or higher, you gain Temporary hit points equal to your Ninjutsu ability modifier. As a Bonus action on your turn, you can replenish these Temporary hit points for 5 Chakra. If this jutsu is cast at B-Rank or higher, increase the AC this Jutsu grants by +1. If this jutsu is cast at A-Rank or higher, the Temporary hit points gained, is instead equal to half of the casters Ninjutsu ability score. If this jutsu is cast at S-Rank or higher, increase the AC this Jutsu grants by +2, instead of +1. DARKVISION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Sensory Description: You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has Darkvision out to a range of 60 feet. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can affect with this jutsu by +1. ENHANCED REACTIONS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 8 Hours Components: HS Cost: 3 Chakra Keywords: Ninjutsu, Sensory Description: You store chakra in pockets behind your eyes and joints in preparation to move with a burst of speed at any moment. The first time you would roll initiative for the duration, you may add 1d4+1 to your roll. This jutsu then ends. HOLLOW STARS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 120 feet Duration: Instant Components: HS, CM, CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You force your palms together before pointing them towards the sky, shooting our four bursts of chakra that take the shape of small stars before falling to the ground in four different spaces of your choice within range, dealing damage to objects, creatures and structures occupying the space. Objects, creatures and structures in the selected spaces each take 1d4+1 damage. A creature, object or structure in the area of more than one star, takes the damage of each of these stars. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. A creature can only ever be affected by the following effects twice per casting. • Earth: You create a 10-foot cube of difficult terrain, centering on each space selected. This space remains difficult terrain until cleared. • Wind: Each creature within 5 feet of the selected space makes a Strength saving throw. On a failed save they are thrown back 5 feet from the target space and falling prone. • Fire: Each creature within 5 feet of the selected space makes a Dexterity saving throw. On a failed save they takes damage equal to the damage dealt to the target space. • Cold: Each creature within a 10-foot radius sphere of the target space must make a Constitution saving throw, being chilled on a failed save. • Lightning: If two or more selected spaces are within 15 feet of each other, lightning arcs between them in a straight line so long as there are no obstructions. Creatures in the Arcs path must make a Constitution saving throw, being shocked on a failed save • Force: Damage die increases to a d8. Also, creatures occupying select spaces are bruised. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of stars made by +1. 10 INK CLONE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet Duration: 1 Minute Components: HS, CM, CS, NT (Vial of Ink) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into the ink as you then infuse a chakra seal into it. You conjure a clone of yourself made of ink. They look, sound and act as your describe. The cost of these clones cannot be reduced below half. An Ink clone has 1 Hit point and can be no farther than 90 feet from you. It can walk, talk and interact with things but it cannot declare an attack. This clone acts at the end of your turn. As a bonus action you can command the clone to attack. When you do it pretends to weave hand seals to cast a jutsu targeting a single creature within 60 feet of it. The target creature makes a Wisdom (Insight) Check vs your Ninjutsu Save DC. On a failure, they become distracted by the clones antics. A creature distracted in this manner grants the next attack targeting it advantage and they are treated as surprised against this attack. LOCK/RELEASE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Until dispelled Components: HS, CS Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You place a chakra seal on a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and creatures you designate when the jutsu is used can open the object normally. You can also set a password that when spoken within 5 feet of the object releases the jutsu for 1 minute. This jutsu also works inversely allowing you to attempt to lock pick using your chakra alone. Make an Intelligence (Chakra Control) check vs the Locks DC as if you are picking a lock using a Security kit. Creatures attempting to open the object you have locked with this jutsu must make an Athletics check vs your Ninjutsu save DC to force open the object. MEDICAL RELEASE: ACID ARMOR Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of a highly dangerous aura of chakra that intercepts attacks for you and harms those who would try to touch you. You gain 14 temporary hit points. Creatures who would deal damage with a melee attack take 6 acid damage each time they would deal damage, while you have temporary hit points granted by this jutsu. A creature who would strike you with a weapon attack or unarmed strike whose rank is equal to or less than the rank this jutsu was cast at has their weapon suffer a permanent -1 penalty until fixed by the Mending ninjutsu. An unarmed attack such as your fists or legs can be fixed with any jutsu with the medical keyword that restores hit points or removes conditions. A weapon or limb which has reached a -5 penalty breaks, being destroyed by all of the acid covering it. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points by 7 and the acid damage by 3. MEDICAL RELEASE: ACID BEAM Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (60-Foot line) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of a powerful beam meant to melt through everything in its path. All creatures in a 60-foot long, 5-foot-wide line originating from you must make a Dexterity saving throw. On a failed save, you deal 3d6 acid damage and at the beginning of an affected creature’s next turn, they take 3d4 acid damage. Constructs and structures made of earth, metal or wood take double damage as the acid eats through them. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and 1d4. 11 MEDICAL RELEASE: ACID STRING Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (20-foot cube) Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of barbed wires, enough to fill a 20-foot cube originating from you. For the duration, creatures, excluding you, who would begin their turn or enter for the first time on their turn, the affected area, they take 7 acid damage and an additional 7 acid damage for every 5 feet they would move through the affected area. A creature cannot take damage from the same 5 by 5-foot square more than once per round. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the affected area by 5 feet. MEDICAL RELEASE: ACID TAIL Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of a beast’s tail, be it a massive dragon tail, or large lions tail. Make one melee ninjutsu attack. Compare the result of your attack against all creatures in a 15-foot cone, originating from you. For each success, you deal 2d6 + 1d6 acid damage, for each additional creature hit after the first. Additionally, all creatures you deal damage to must make a Strength Saving throw. On a failed save, creatures are knocked prone and gain 1 rank of corroded. MEDICAL RELEASE: ACID WHIPS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of two whips of acid designed to grapple and melt into your foes. Make two ranged ninjutsu attack, dealing 2d6 acid damage on a hit. Additionally, creature you hit must make a Strength saving throw. On a failed save, they become grappled by you and your acid whips for the duration. A creature grappled by your acid whips takes 1d6 acid damage at the beginning of each of their turns. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of attacks you make by +1. MEDICAL RELEASE: ACIDIC CLEANSE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15 feet) Duration: Special Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You learn to bend acidic substances to your will, molding and manipulating them like puppets on a string. All creatures within 15 feet of you who are under the effects of the corroded condition has their condition ended, as you collect all of the left-over acid into a ball above your head. The ball floats for up to 1 minute or until used. The next time you would cast a jutsu that would deal acid damage you can spend the ball of acid, upcasting the jutsu by 1 rank at no cost, ignoring upcasting limitations. MEDICAL RELEASE: BROKEN BODY Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate a surge of twisted medical release chakra designed to shatter the bones and splinter the muscles of your target. A creature you can reach must make a Strength saving throw. On a failed save their bones twist and their muscles spasm as they take 4d8 necrotic damage and they cannot use their arms to hold a weapon until the end of their next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8. MEDICAL RELEASE: CORRUPT MISSILE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM, CS Cost: 4 Chakra Keywords: Ninjutsu, Medical, Fuinjutsu Description: You begin to generate a mass of twisted medical release chakra designed to be fired like a missile, bolt or beam. Make a ranged ninjutsu attack targeting one creature you can see in range. On a hit you deal 2d8 + your ninjutsu ability modifier necrotic damage. Additionally, the next time the affected creature would regain chakra within the next minute, they regain half of the listed amount At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8. 12 MEDICAL RELEASE: CORRUPTION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute. Components: HS, CM, CS Cost: 4 Chakra Keywords: Ninjutsu, Medical, Fuinjutsu Description: You begin to generate a surge of twisted medical release chakra designed spread like a curse, draining all creatures in range. Select a space you can see within range. You manifest a 5- foot radius field of corruption. At the beginning of each of your turns for the duration, the size of the field grows by 5 feet. All creature who begins their turns within the affected area or first enter the affected area on their turns, must make a Charisma saving throw. On a failed save creatures take 3d12 necrotic damage and no damage on a successful save. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d12. MEDICAL RELEASE: DETECT POISON AND DISEASE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 10 minute Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical, Sensory Description: For the duration, you can sense the presence and location of poisons, poisonous creatures and diseases within 30 feet of you. This jutsu can penetrate most barriers, but is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt. MEDICAL RELEASE: ENSNARING STRIKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: 1 Round Components: CM, M Cost: 4 Chakra Keywords: Ninjutsu, Medical Description: The next time you hit a creature with a melee or ranged weapon or unarmed attack before this jutsu ends, you inject chakra into your enemy’s muscles attempting to restrict their movements. The target must make a Strength saving throw or be restrained until the end of their next turn. A large or larger creature has advantage on the saving throw. While restrained by this jutsu, the target takes 1d8 poison damage at the start of each of its turns. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8 MEDICAL RELEASE: GOODBERRY Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, M Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: With fine chakra control, you can touch up to 5 fruits or nuts that are then infused with medical release chakra for the duration. A creature can use its action to eat any of the 5 affected food items. Eating a food infused with this jutsu restores 1 hit point and provides enough nourishment to sustain a creature for one day. A creature cannot benefit from this jutsu more than twice per long rest. The infused food loses its potency if they have not been consumed within 24 hours of casting this jutsu. MEDICAL RELEASE: GRIM MASK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM, CS Cost: 5 Chakra, 1 Hit Die Keywords: Ninjutsu, Medical, Fuinjutsu, Kinjutsu Description: You weave summoning seals together and infuse them with medical release chakra manifesting the mask of the Reaper of death. The mask siphons a small fraction of your life force to don it, but it grants you a great deal of power in return. You cannot lose concentration of this jutsu as a result of damage. Attacks you make deal an additional 1d4 necrotic damage for the duration. If an attack you make or jutsu you cast would deal necrotic damage as a part of its casting or through its lingering effects, the additional damage inste", created_at: NOW, updated_at: NOW },
  { _id: "7a0fbbed77a56b1839176c73", name: "KEEN THOUGHTS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 Minute", description: "You touch a creature within reach who you can see. For the duration you increase their focus and enhance their mental efficiency. For the duration target creature gain a +1 to their critical threat range with Genjutsu attacks. Additionally, when they score a critical hit with a Genjutsu attack, add 2 additional damage die to the damage roll.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the critical threat range by +1. If this jutsu is cast at S-Rank, when they score a critical hit with a Genjutsu attack, you instead add 5 additional damage die to the roll.", created_at: NOW, updated_at: NOW },
  { _id: "626ea183344e879b93c66fbc", name: "LABYRINTHINE HOWL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "Self (60 feet)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "1 Round", description: "You let loose the howl of a ravenous beast, 205 causing each hostile creature within range that can hear you to make a Wisdom saving throw. On a failed save, a creature believes it has been moved into a labyrinth and is under attack by a savage beast of your description. An affected creature on its turn must decide to face the beast head on or defend itself from the beast. A creature that faces the beast takes 8d6 psychic damage and this jutsu ends. A creature that defends itself from the beast falls prone and is stunned until the beginning of its next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "adacc490510ef19940b91011", name: "MADDENING SHADOWS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "150 feet (60-foot radius sphere)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Illusory Darkness spreads from a point you choose within range to fill a 60-foot radius sphere until this jutsu ends. A creature with Darkvision or Chakra Sight can’t see through this darkness. Shrieks, gibbering, and maddening laughter can be heard within the darkness. Whenever a creature starts its turn in the sphere, it must make a Charisma Saving throw Critical Success: Affected creature is able to resist this Genjutsu’s effects and becomes immune to this jutsu until the end of its next turn. Success: Affected creature is able to resist this genjutsu’s effects, taking only 3d8 psychic damage. Failure: Affected creature takes 6d8 psychic damage. A creature whose HP is reduced to 0 as a result of this jutsu has its HP instead reduced to 1. Critical Failure: Affected creature takes 8d8 psychic damage. A creature whose HP is reduced to 0 as a result of this jutsu has its HP instead reduced to 1 and they gain 5 ranks of fear for the next 24 hours or until they have a Jutsu with the medical keyword of B-Rank or higher that can end the fear condition cast on them.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "ca1435512b0c804d83c06996", name: "MAJOR IMAGE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "12 Chakra", components: "HS, CM, CS", duration: "Until Dispelled", description: "You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 20-foot cube. The image appears at a spot that you can see within range and lasts for the duration. It seems completely real, including sounds, smells, and temperature appropriate to the thing depicted. You can’t create sufficient heat or cold to cause damage, a sound loud enough to deal damage or deafen a creature, or a smell that might sicken a creature. As long as you are within range of the illusion, you can use your action to cause the image to move to any other spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. Similarly, you can cause the illusion to make different sounds at different times, even making it carry on a conversation, for example. Physical interaction with the image reveals it to be a genjutsu, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Illusion check against your genjutsu save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and its other sensory qualities become faint to the creature. MEDICAL RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "65f63e52366febabc512d12b", name: "PSIONIC GUARD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, Special", description: "You manifest a supportive sound that remains humming in the mind of an allied creature for the duration. Select one allied creature to gain the benefit of this jutsu, whom cannot concentrate on more than 1 jutsu for its duration. When the affected creature would make an Intelligence, Wisdom or Charisma saving throw, you can choose to make it for them, using your saving throw bonuses.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dd6d47a56467096307980aef", name: "MEMORY DOMINATION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Until Restored", description: "You attempt to reshape another creature’s 206 memories. One creature that you touch must make an Intelligence saving throw. If you are fighting the creature, it has advantage on the saving throw. On a failed save, the target becomes charmed by you for 1 minute. The charmed target is incapacitated and unaware of its surroundings, though it can still hear you. If it takes any damage or is targeted by another jutsu, this jutsu ends, and none of the target’s memories are modified. While this charm lasts, you can affect the target’s memory of an event that it experienced within the last 12 Months and that lasted no more than 1 Day. You can Temporarily overwrite all memory of the event, allow the target to recall the event with perfect clarity and exacting detail, change its memory of the details of the event, or create a memory of some other event. You must speak to the target to describe how its memories are affected and it must be able to understand your language for the modified memories to take root. Its mind fills in any gaps in the details of your description. If the jutsu ends before you have finished describing the modified memories, the creature’s memory isn’t altered. The modified memories take hold when the jutsu ends. A modified memory doesn’t necessarily affect how a creature behaves, particularly if the memory contradicts the creature’s natural inclinations, allegiance, or beliefs. An illogical modified memory is dismissed, perhaps as a bad dream. The DM might deem a modified memory too nonsensical to affect a creature in a significant manner. A Genjutsu Break or Greater Restorative Jutsu cast on the target, specifically intended to restore the creature’s true memory will restore the memory.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9b3ffe35d6439d7864ee7058", name: "MENTAL SCHISM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "11 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You manifest a second mind. A second ‘you’. This second mind exists and functions independently of your primary mind. It cannot control or influence your physical body, but it able to perform mental actions freely. On each of your turns, this second mind gains 1 action and 1 reaction, which is can only use to complete purely mental task such as making any Intelligence or Wisdom based skill checks, Read the Enemy, Search, or cast any E-Rank Ninjutsu or Genjutsu that doesn’t require hand signs (HS) or Ninja tools (NT).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "85240974743101d405597404", name: "MISLEADING DUPLICATE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You become invisible at the same time that an illusory double of you appears where you are standing. The double lasts for the duration, but the invisibility ends if you attack or cast a Jutsu. You can use your action to move your illusory double up to twice your speed and make it gesture, speak, and behave in whatever way you choose. You can see through its eyes and hear through its ears as if you were located where it is. On each of your turns as a bonus action, you can switch from using its senses to using your own, or back again. While you are using its senses, you are blinded and deafened in regard to your own surroundings. You can move up to 120 Feet away from your duplicate.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "11bdb0959495f3c3fceed2e6", name: "PARASITIC RIDER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You take the teachings of the Yamanaka clan and attempt to invade the mind of another creature you can see within range. You make a similar hand sign to that of the Yamanaka and fire your consciousness into the target creature, they must make a Charisma saving throw. A creature aware of your presence automatically passes their saving throw. You cannot lose concentration on this jutsu as a result of damage and your body is forced to spend chakra to maintain concentration so long as you occupy the body of another creature. When you cast this jutsu your body remains where it is, falling prone and becoming stunned for the duration. You lose all ability to experience sensations your body experiences, such as pain etc. If your body is killed this jutsu’s duration becomes permanent or until dispelled, as you have no body to return to, remaining trapped in the body you chose to inhabit. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes aware that something or someone has attempted to enter their mind. Success: Affected creature is able to resist this jutsu’s effects. Failure: You enter the mind of the target creature. You cannot control or influence them by any means, but you can see and experience everything they do through their senses. If they would take damage, you must make a Charisma saving throw vs your own Save DC to remain within the body of the creature. Critical Failure: You gain the effects of the Failure effect, and you can occasionally act as a voice in their mind speaking to them as if you were their normal thoughts. This does not control them or take away their free will, but you may make Charisma based skill checks to attempt to influence them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3a3ff224094aeb94c6af1143", name: "PHANTASMAL KILLER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You tap into the nightmares of a creature you can see within range and create an illusory manifestation of its deepest fears, visible only to that creature. The target must make a Wisdom saving throw. 207 Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature gains 1 rank of fear until the end of their next turn. Failure: Affected creatures gains 3 ranks of fear for the duration, remaking saving throws at the end of each of their turns, ending this jutsu’s effect on a success. Critical Failure: Same as failure, but affected creatures also takes 6d10 psychic damage at the beginning of each of their turns that they remain feared.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "b09004bcabd920b71ae995d8", name: "PROGRAMMED ILLUSIONS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "60 Foot radius Sphere", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Until Dispelled", description: "After placing your specially made Genjutsu chakra seal onto a surface of your choice, the chakra seal creates an illusion of an object, creature, or some other visible phenomenon within range that activates when a specific condition occurs. This Genjutsu was imperceptible until then. It must be no larger than a 30- Foot cube, and you decide when you cast the Genjutsu how the illusion behaves and what sounds it makes. The scripted performance can last up to 5 minutes. But will repeat from the beginning. When the condition you specify occurs, the illusion springs into existence and performs in the manner you described. Once the Illusion finishes performing, it repeats from the beginning continuing until the condition of the illusion being cast is no longer met. Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the illusion can determine that it is an illusion with a successful Genjutsu (Wisdom) check against the Jutsu save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dbdf711c05c116665c6fccc3", name: "PSIONICS: CRUSH!", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You create the image of yourself that enlarges and attempts to crush your target by stepping on them. Select one creature you can see within range, and make a range Genjutsu attack, dealing 5d10 psychic damage. On a successful hit, the target must also make a Wisdom saving throw. Success: Affected creature is able to resist this jutsu’s secondary effects. Failure: Affected creatures falls prone and find it difficult to stand. If they would attempt to stand, they must spend all of their movement. Critical Failure: Affected creature falls prone and cannot stand. They remain prone until another creature assists them to help them stand. While prone in this way, their movement speed is 0.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c17a26fee5147306c7b43988", name: "PSIONICS: SENSORY OVERLOAD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You press your index and middle finger to side of your head and your ring finger on your check. You flood your eyes with chakra and send a wave of chakra at a nearby creature to cause their chakra network to overload, shutting their senses down. Make a melee genjutsu attack. On hit, the creature becomes blinded until the end of their next turn and must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature is able to resist this Jutsu's effects. Failure: Affected creatures becomes concussed. Critical Failure: Same as Failure and the affected creature becomes disoriented, their legs become wobbly and they become unable to feel, taste, hear or smell for the next minute. Creatures who possess an Intelligence of 8 or less automatically critical fail this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at S-Rank, creatures who fail their saving throw against this jutsu also become incapacitated.", created_at: NOW, updated_at: NOW },
  { _id: "f80b4b7cc3275f1abe6ce517", name: "PSIONICS: TORMENT!", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action.", range: "Self (30 feet)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You create a mundane sound that pulses outward and all who perceives it, hears it as a brutally high decibel that causes intense pain and agony. All creatures of your choice within 30 feet of you must make a Wisdom saving throw. 208 Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creatures takes 5d8 psychic damage and gains 3 ranks of Dazzled. Critical Failure: Affected creature takes 5d8 psychic damage, gains 3 ranks of Concussed and gains a rank of slow. A slowed creature remakes their Wisdom saving throw at the end of each of their turns to end that condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "70e0ce0f9e8ed6b764c10d28", name: "PSIONICS: TRICK ROOM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (100-foot-Cube)", chakra_cost: "13 Chakra", components: "HS, CM, CS", duration: "10 Minutes", description: "You outstretch your hand and place a genjutsu upon all creatures within a 100-foot cube emerging from yourself. Make an Genjutsu Ability Check against a DC equal to 10 + the number of unwilling creatures being affected. If you succeed this check, while within this jutsu's area of effect, the initiative order is reversed. Additionally, creatures effected by this jutsu that are under the effects of a jutsu, feature or trait that would increase their movement speed, any increase to their movement speed instead reduces it. Additionally, any decrease to their movement speed instead increases it. If a creature under this jutsu's effects leaves this jutsu's area of effect, this Jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the size of the cube, by 50 feet.", created_at: NOW, updated_at: NOW },
  { _id: "30878e4110043ca5dfb4a5c9", name: "PSYCHIC BLAST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You unleash a destructive wave of mental power in a 30-foot cone. Each creature in the area must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature takes 4d8 psychic damage. Failure: Affected creatures takes 7d8 psychic damage and is knocked prone. Critical Failure: Affected creatures take 10d8 psychic damage, is knocked prone and incapacitated until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "c6596f1302f6409719c64916", name: "REQUEST OF THE DAMNED", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "You issue a single command, no longer than 25 words, directed at a single creature whom you can see who’s name you include in your command. If the creature can hear you, they must make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature becomes blinded by rage, becoming berserked, until the end of their next turn. Failure: Affected creatures becomes berserked and becomes unable to see the caster of this jutsu. While berserked, they take 3d6 psychic damage and remakes their saving throw at the end of each of their turns ending this jutsu on a success. Critical Failure: Same as failure, but they instead take 5d6 psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the number of creature you can target with this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e09ae932761d38ec1b0af9e1", name: "RUBBER MIND", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when you would gain a Mental or Sensory condition as the result of failing a saving throw, caused by a Genjutsu.", range: "60 feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Instant", description: "You coat your mind in a chakra designed to be malleable and reflect change well. When you would gain a mental or sensory condition you can bounce it back to any hostile creature within range. Target creature must make an Intelligence saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature gains whatever Mental or Sensory conditions you would gain as if they failed their own saving throw. Critical Failure: Affected creature suffers the same effects of a Failure, and also cannot remove the condition themselves and instead must spend an action to remake this jutsu’s saving throw to end them. SEALING ART:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ae25904888e5ab132f7e7d44", name: "CURSED TONGUE SEAL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Minute", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Permanent", description: "As a part of the activation of this jutsu. The target must currently be incapacitated or willing. Over the course of a minute, you tattoo a seal on a target creatures’ tongue. You select 1 topic, which you wish for 209 the target creature to be unable to speak of. Once this jutsu is casted the target creature becomes unable to speak, write, or willing reveal information on or about the topic you chose. A creature can attempt to undo the effects of this jutsu by making a Ninshou check against your Genjutsu Save DC + 5. An affected creature cannot gain a bonus to this check as the result of a jutsu. Each attempt takes 1 hour. On a successful check the target creature becomes able to speak on the topic freely again. SEALING ART:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b4061338c1489bdf7ee29780", name: "IMPRISONED THOUGHTS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You manifest an illusory seal, designed to seal away thoughts and memories. Select one creature whom you can see within range. That target must make a Charisma saving throw. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature has their thoughts sealed. The last jutsu they cast, cannot be recast for the duration, each attempt leading to it failing and the chakra still being spent. Critical Failure: Affected creature suffers the same effects of a Failure, and also cannot cast any jutsu that both you and it has on its known jutsu list.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "c4b87de2600b0f71c9075140", name: "SLOW", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "1 minute.", description: "You alter the perception of time for up to six creatures of your choice in a 40-foot cube within range. Each target must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects. Success: Affected creature becomes slow until the end of the next turn. Failure: Affected creatures gains 1 rank of slow for the next minute. A slowed creature remakes their saving throw at the end of each of their turns, ending this jutsu’s effects on themselves. Critical Failure: Same as Failure, but they gain 2 ranks of slow, instead of 1.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of targets by 2.", created_at: NOW, updated_at: NOW },
  { _id: "62b8db16041d4ba1a9d5f2af", name: "SONG OF RETREAT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "self (45-foot radius)", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You begin to hum or sing a tune of avoidance designed to make those who hear it want to run. All creatures of your choice within range begins to experience this anxiousness to escape. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Creatures whom you selected, who begin their turns within range fall under the following effects if they are allied or hostile to you when you cast this jutsu; Hostile: If you select a hostile creature to experience this feeling, they must make a Wisdom saving throw. On a failed save, they must spend their turn doing everything they can to move away from the closest hostile creature near it. Allied: If you select an Allied Creature to experience this feeling, they gain the benefits of the Dash and Disengage action when attempting to move away from a hostile creature. Additionally, they cannot have their movement impeded as a result of difficult terrain, and they do not trigger attacks of opportunity. A creature loses the benefits of this jutsu and cannot gain them until the end of their next turn if they attempt to cast a jutsu that deals damage or declare an attack of any kind.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "20388ca19ece07b4bc48be77", name: "SONG OF REVERSAL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "self (45-foot radius)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You begin to hum or sing a tune of defeat designed to make those who hear it believe they cannot achieve anything. All creatures of your choice within range begins to experience this delusion of despair. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. 210 Creatures who begin their turns within range must make a Charisma saving throw. Creatures who fail the saving throw, who have advantage or disadvantage from any source, now have the opposite. (Advantage becomes Disadvantage, and Disadvantage becomes Advantage.). Additionally, creatures who fail, who begin their turn within range who have penalties to their attack rolls, skill checks, or Saving throws now instead lose those penalties, and gain bonuses equal to the penalty lost. Alternatively, if a creature who fails begins their turn within range who have bonuses to their attack rolls, skill checks, or saving throws now instead lose those bonuses and gain penalties equal to the bonus lost.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "74141a2ebd7489fa371b794b", name: "SONG OF WAR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "self (45-foot radius)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You begin to hum or sing a tune of battle designed to make those who hear it want to engage in endless conflict. All allied creatures of your choice within range begins to experience this lust for battle. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Select Creature(s) gain the following until the beginning of your next turn. • +5 Bonus to Ninshou, Illusions, and Martial Arts skill checks. • +3 Bonus to Initiative Count. If This would put your initiative score above another creature, move up 1 step in the turn order. • +2 Bonus to Attack & Damage rolls & Saving throws.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d772e4be48b0327460510dcc", name: "TREE BINDING DEATH", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create the illusion of the target being completely bound by a growing tree as you vanish from sight. You will remain invisible to all the target creature's senses as it is affected by the Genjutsu. The illusion will remain until the target takes damage or resists the Genjutsu. Select up to 3 Target creatures you can see within range, each target must make a Wisdom save. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature becomes Slowed until the end of the next turn. Failure: Affected creatures becomes incapacitated, blind, deafened and grappled for the duration. Affected creatures remakes their saving throws at the end of each of their turns to end this Jutsu's effects on them. Critical Failure: Same as Failure, but affected creatures are stunned instead of incapacitated.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "08916348f79990e50a5e0bc9", name: "UNLIMITED FOCUS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You touch a willing creature who you can see. You impart upon them a focusing genjutsu designed to enhance their perception and reactionary abilities. For the duration, affected creature gains the following; • Adds 1d6 to any Constitution (Chakra Control) check they make to maintain concentration on jutsu. • They gain an additional Bonus action. • When they would make an Intelligence or Charisma Saving throw vs a Genjutsu, they roll an additional 1d4 adding the result to their saving throw.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1a90f08881dcf1540ef143d6", name: "UNMISTAKABLE FEAR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "90 Foot Cube", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You project a phantasmal Genjutsu image of all creatures' worst fears in a target area. Each creature in a 90 Foot Cube originating from you must make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature drops whatever it is holding. 211 Failure: Affected creatures drops whatever it is holding and gains 2 ranks of fear for the duration, remaking their saving throws at the end of each of their turns. When a creature with ranks of fear would take psychic damage, they take an additional 5d6 psychic damage. Critical Failure: Same as Failure, but affected creatures instead take 5d8 psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "c5078dc57ac5266b61dff419", name: "UNRELENTING PAIN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You target a single creature as you create an image of them being impaled repeatedly by multiple sharp objects slowly while they are unable to stop it. The target creature must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature takes 4d6 psychic damage. Failure: Affected creatures takes 13d6 psychic damage. Critical Failure: Same as Failure and the affected creature is stunned until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "4c3e61cf5efd989a147ae38a", name: "WORD OF THE LOST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute.", description: "You utter a few words of destitution directed at a single creature whom you can see who’s name you include in your statement. If the creature can hear you, they fall under the effects of this jutsu as they suffer a series of mental flashes and fractured memories for this jutsu’s duration. At the beginning of an affected creatures turn they make an Intelligence saving throw. On a failure, the creature suffers a number of fracture’s based on the severity of their failure. • Failed by 1~4: They gain 1 Fracture. • Failed by 5~9: They gain 2 Fractures. • Failed by 10~14: They gain 3 Fractures. • Failed by 15+: They gain 4 Fractures. A creature suffers a number of effects based on the number of fractures they have. • A creature with 2 or more fractures cannot cast jutsu of A-Rank or Higher. This limitation grows in severity for every 2 Fractures a creature has. (4 Fractures; B-Rank or Higher, 6 Fractures; C-Rank or Higher, 8 Fractures; D-Rank or Higher.) • A creature with 3 or more fractures cannot maintain concentration on more than one jutsu at a time. • A creature with 5 or more fractures cannot recognize their allies and views all creatures as hostile. • A creature with 7 or more fractures doubles the cost of all jutsu they cast. • A creature with 9 or more fractures lose the ability to cast jutsu with the Hand Sign (HS) component. • A creature with 10 or more fractures instead permanently retain all fractures and becomes a mental vegetable moving forward. They can attempt to make an Intelligence saving throw once every 30 Days. On a success they reduce the number of fractures they have by -3. A-RANK:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3174569616583feae5dcff4a", name: "BLACK SUNSHINE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius)", chakra_cost: "20 Chakra", components: "HS, CM, NT (A Gem,", duration: "Concentration, up to 1 minute.", description: "You hold up a jewel or other crystalline object as it disappears, leaving behind a sphere of pulsing purple chakra. The orb radiates an ominous purple light that affects all creatures within a 60-foot radius centered on you, that moves with you. All creatures of your choice within range who begin their turn within this jutsu’s radius must make a Wisdom saving throw. On a failed save you become invisible to them for the duration. Additionally, Creatures you designate become invisible at the same time you do to the same creatures who fail their wisdom saving throw if they’re within 60 feet of you and if light from the orb can reach the space they occupy. An invisible creature casts a faint purple shadow. A creature attempting to find these faint shadows can as an action make a Wisdom (Perception) check vs your Genjutsu save DC. On a success they can see and track the shadows allowing them to target them, making attacks at disadvantage vs invisible creatures. A creature repeats their saving throw at the end of each of their turns becoming immune to their jutsu until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the radius of this jutsu by 15.", created_at: NOW, updated_at: NOW },
  { _id: "738dda721e5dfd1ddf7547a1", name: "BRINGER OF DARKNESS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 Foot radius Sphere", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You release a surge of chakra from yourself attempting to remove the sight, Sound, and Tactile senses of all creatures in a 30 Foot Radius centering on you. Each creature within range must make a Wisdom saving throw, becoming Blind, Deafened and being unable to even feel when they are touching or being touched on a failed save. Creatures who attempt to enter the radius or end their turns in the radius of this jutsu must make the Wisdom save as well. Creatures who are affected by this jutsu are still affected even if they leave the radius of this jutsu until they succeed their Wisdom save. At the end of each of their turns, creatures may make a Wisdom save to resist the effects of this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f5095ab489155263a8f90df1", name: "DANCE MACABRE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Concentration, Up to 10 minutes", description: "Threads of dark chakra leap from your fingers into the ground as 5 medium dark phantasms are conjured from the ground under your control. Each dark phantasm immediately stands up and takes a shape of your choice. Its attack and damage rolls are increased by your genjutsu ability modifier. You can use a bonus action to command the creature you make with this genjutsu, issuing the same command to all of them. You decide what action the creatures will take and where they will move during your turn. Once an order is given, the creatures continue to follow it until the task is complete. The creatures have the following statistics.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d6c7020f888bad55b232fd8a", name: "DEVIL SIGHT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "19 Chakra", components: "HS, CM", duration: "1 Minute", description: "You touch a willing creature who you can see. You impart upon them eyes of absolute authority. Affected creature gains 60 Feet of Dark Vision that see’s through all forms of Chakra based Darkness. Medium Illusion Fiend, unaligned Armor Class 10 + Your Genjutsu Ability Modifier Hit Points 55 (10d8 + 10) Speed 30 ft. STR DEX CON INT WIS CHA 1 (-5) 18 (+4) 12 (+1) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Acid, Psychic Condition Immunities Charmed, Exhaustion, frightened, stunned, petrified, poisoned Senses Darkvision 60 ft., passive Perception 10 Incorporeal Movement. The phantasm can move through other creatures and objects as if they were difficult terrain. It takes 5 damage if it ends its turn inside an object. Phantasmal Stride. The Phantasm can use your Stealth bonus. Claws. Melee Weapon Attack: +(Genjutsu Attack Bonus) to hit, reach 5 ft., one creature. Hit: 2d6 + 5 Psychic damage 213 Additionally, creatures who gain Darkvision as a result of this jutsu gain truesight against Genjutsu of A-Rank or lower. If this jutsu is cast again, while currently affecting another creature, it ends on that other creature immediately.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1887fed91a8c42724e8beb31", name: "DEVILS AMBITION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "18 Chakra", components: "HS, CM, NT (Poison Kit)", duration: "1 Minute", description: "You take a venomous concoction of different steroids and performance enhancers and release it into the air, manipulating it to affect and enhance up to 2 willing creatures you can see within range. Affected creature gain the following benefits for the duration; • Strength, Dexterity, and Intelligence Check results can never be lower than their Character Level. • You gain expertise in Ninjutsu, Genjutsu and Taijutsu attack rolls. • They gain a +3 bonus to saving throws vs Genjutsu with the Auditory keyword. • If they miss an attack roll against the last creature that dealt damage to them, they may reroll the missed attack once per turn. At the conclusion of this jutsu, affected creatures 3 ranks of Envenomed for the next hour, which cannot be removed by jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1c82aad8ee387dc16ff4fddb", name: "DEVILS ASSAULTS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You speak words of aggression and pain against one creature that can hear you within range. Affected creature begins to see illusionary duplicates of you as they make a barrage of martial attacks against them. Make 3 Ranged Genjutsu attacks dealing psychic damage equal to 2d12 + Your genjutsu ability Modifier on a successful hit. If you successfully score at least two genjutsu attacks using this jutsu, the next genjutsu attack you make against the same creature is at advantage and you reroll 1’s and 2’s for damage, taking the second result, even if it is a 1 or a 2. If you successfully score at least three attacks, the target must succeed a Charisma Saving Throw or gain a rank of Concussed.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of genjutsu attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "cf313c10edbf33316d22efb0", name: "DEVILS FEARS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (90 Feet)", chakra_cost: "16 Chakra", components: "HS, CM", duration: "Instant", description: "You speak words of fear and anguish, against all creature who are experiencing bouts of fear. All creatures within range who have at least 1 rank of fear, must make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature is able to resist this Jutsu's effects. Failure: Affected creatures takes 3d10 Psychic damage for each rank of fear they have. Critical Failure: Same as Failure but instead affected creatures takes 4d10 Psychic damage per rank of Fear they have. Additionally, creatures whose Charisma scores are 8 or lower, automatically critically fail this jutsu saving throw.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "63088d335c070f13b86236cc", name: "DIE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You utter a word of absolute authority commanding a creature to attack itself with its most potent attack. Target creatures whom can see and hear you within range, must make a Charisma saving throw. 214 Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature is able to resist this Jutsu's effects. Failure: On the affected creatures next turn, they must cast a jutsu or make an attack of the casters choice, targeting themselves. If commanded to perform an attack they do not know or are able to perform, they perform the last offensive damaging attack they used in combat, but on themselves. If they have not performed any damaging actions this combat, they instead take 8d10 psychic damage. Critical Failure: Same as Failure but affected creature automatically scores a critical hit against themselves on the first attack made.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "96557b9cd713763095644158", name: "DOMINATE MAN", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You attempt to beguile a humanoid that you can see within range. It must make a Wisdom saving throw or be charmed by you for the duration. If you or creatures that are friendly to you are fighting it, it has advantage on the saving throw. While the target is charmed, you have a telepathic link with it as long as the two of you are within 1 mile of each other. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey. You can specify a simple and general course of action, such as \"Attack that creature\", \"Run over there\", or \"Fetch that object\". If the creature completes the order and doesn’t receive further direction from you, it defends and preserves itself to the best of its ability. You can use your action to take total and precise control of the target. Until the end of your next turn, the creature takes only the actions you choose, and doesn’t do anything that you don’t allow it to do. During this time, you can also cause the creature to use a reaction, but this requires you to use your own reaction as well. Each time the target takes damage, it makes a new Wisdom saving throw against the spell. If the saving throw succeeds, the genjutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d009cf2c932e7394594ba100", name: "GEAS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "17 Chakra", components: "HS, CM", duration: "30 Days", description: "You place a genjutsu based command on a creature that you can see within range, forcing it to carry out some service or refrain from some action or course of activity as you decide. If the creature can understand you, it must make a Wisdom saving throw or become charmed by you for the duration. While the creature is charmed by you, it takes 9d10 psychic damage each time it acts in a manner directly counter to your instructions, but no more than once each day. A creature that can’t understand you is unaffected by the genjutsu. You can issue any command you choose, short of an activity that would result in certain death. Should you issue a suicidal command, the genjutsu ends. You can end the spell early by using an action to dismiss it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8c4ee01e3476df1526ea0721", name: "GLIBNESS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "10 Minutes", description: "For the duration of this jutsu, when you make a Charisma check, you can replace the number you roll with a 10. Additionally, no matter what you say, jutsu that would determine if you are telling the truth indicates that you are being truthful.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2cb73d696760f5a3ce4cdecc", name: "KEEN FOCUS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 Minute", description: "You touch a creature within reach who you can see. For the duration you maximize their focus and enhance their mental efficiency. For the duration target creature increase their critical threat range by +1. Also, when affected creatures score a critical hit on a creature, they increase their damage die by 1 step. (D4>D6>D8>D10>D12) Additionally, the first time an affected creature would fall to 0 hit points, they instead fall to 1 hit point. This jutsu then immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the critical threat range by +1. If this jutsu is Cast at S-Rank, If the next jutsu the affected creature cast that scores a critical hit, they instead add 2 additional damage die to the roll.", created_at: NOW, updated_at: NOW },
  { _id: "f59e2276ad45b6c1a53e9c30", name: "LACKLUSTER THOUGHTS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "17 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You speak unfocused words and statements of indecision into a chakra seal before you then attempt to implant them into the mind of a creature you can see within range. Select creature within range must make an Intelligence Save at the beginning of each of their turns. On a failed save, they instead spend their turn doing completely unproductive activities such as drawing in the sand fixing the straps on their armor, counting their 215 kunai and shuriken or verbally planning out scenario’s in elaborate 10 step plans. If a creature succeeds their Intelligence Save by 10 or more, this jutsu immediately ends on them and they become immune to this genjutsu for 1 hour.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of creatures this jutsu can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "8e30754feb9a191d5ddafb60", name: "MENTAL CLONE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Year", range: "Touch", chakra_cost: "20 Chakra a Week for 52 weeks consistently.", components: "HS, CM, CS (Over 100), Replacement Body", duration: "Instant", description: "This jutsu requires a living replacement body void of consciousness and 100 Chakra seals systematically placed around the replacement body. This jutsu creates an inert duplicate of a living creature's consciousness with all of its current memories and experiences as a safeguard against death. This mental clone is cultured over the course of 1 year, as the user would offer a portion of its chakra weekly to grow the psyche of the clone. You can only have one mental clone at a time. You can choose to have the clone be a younger version of the subject. This culturing must be maintained consistently for at least a year. If the subject does not offer its chakra for more than 1 week, the culturing is prematurely stopped as the mental clone awakes with an insufficient amount of chakra as its own person and not linked to the original subject as intended. If this jutsu is completed successfully, at any time after the clone matures, if the original creature dies, its consciousness is transferred to the clone provided the consciousness isn’t damaged and is able to transfer. The clone only retains the mental stats (Intelligence, Wisdom & Charisma) of the original subject and all of its knowledge at the point of this Jutsu’s original start.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "80f94e00315f61992dcabc9c", name: "MIND BREAK", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "17 Chakra", components: "HS, CM", duration: "Instant", description: "You Target a creature and attempt to shatter their psyche by subjecting them to a yearlong mental torture session on them in the span of 6 seconds. Target creature must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature takes 5d12 psychic damage. Failure: Affected creature takes 10d12 psychic damage. Critical Failure: Affected creature takes 13d12 psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "e3203f01d93075eaede62d4a", name: "MIRAGE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "3d7fe1bb5775caf4818c287e", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "10 minutes", range: "1 Mile", chakra_cost: "16 Chakra", components: "HS, CM, CS", duration: "10 Days", description: "You make terrain in an area up to 1 square mile look, sound, smell and even feel like some other sort of terrain. The terrain's general shape remains the same, however, open fields or a road could be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. You can also alter the appearance of structures or add them where none are present. This does not affect creatures in the area. Creatures with true sight can see through the illusion to the terrain’s true form however, all other elements of the illusion remain, so while the creature is aware of the illusion’s presence, the creature can still physically interact with the illusion.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7fb23fb1e2279226a4e4220b", name: "POISON FOREST", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "3d7fe1bb5775caf4818c287e", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Foot Cube", chakra_cost: "19 Chakra", components: "HS, CM, NT (Poison Dust)", duration: "Concentration, up to 1 minute", description: "As part of the activation of this jutsu, you spread the poison dust you need for this jutsu in a 30 Foot Sphere in front of you. Creatures in the target area must make a Intelligence saving throw, being under the effects of this Genjutsu on a failed save. Creatures affected by this Genjutsu are trapped inside a Forest of Poison trees unable to leave the 30ft sphere turning around and running away from the edges of the radius. For the duration, creatures who end their turn under this Genjutsu take 5d8 poison damage. At the end of each target's turn, they make a Constitution save to end the Jutsu’s effect on them.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "b42914955b546a9aa6efb37b", name: "PSYCHIC CRUSH", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 action", range: "60 feet", chakra_cost: "15 Chakra", components: "HS, CM", duration: "Instant", description: "You overload the mind of one creature you can see within range, filling its psyche with discordant 216 emotions. The target must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature takes 6d6 psychic damage. Failure: Affected creature takes 12d6 psychic damage and are confused Critical Failure: Affected creature takes 14d6 Psychic damage and are Confused and Berserk.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "20cc5994a46c963400ea260c", name: "SEEMING", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "17 Chakra", components: "HS, CM", duration: "8 Hours", description: "This genjutsu allows you to change the appearance of any number of creatures that you can see within range. You give each target you choose a new, illusory appearance. An unwilling target can make a Charisma saving throw, and if it succeeds, it is unaffected by this genjutsu. The genjutsu disguises physical appearances as well as clothing, armor, weapons, and equipment. You can make each creature seem 1 foot shorter or taller and appear thin, fat, or in-between. You can’t change a target’s body type, so you must choose a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you. The genjutsu lasts for the duration, unless you use your action to dismiss it sooner. The changes wrought by this genjutsu fail to hold up to physical inspections. For example, if you use this genjutsu to add a hat to a creature’s outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel the creature’s head and hair. If you use this genjutsu to appear thinner then you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair. A creature can use its action to inspect a target and make an Intelligence (Investigation) or Wisdom (Illusion) check against your genjutsu save DC. If it succeeds, it becomes aware that the target is disguised.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7961aad9786e7a6317e2df26", name: "UNLIMITED PAIN", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "18 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You target a creature and maximize their nervous systems sensitivity to pain. One creature you can see within range must make an Intelligence saving throw. On a failed save, for the duration, Once per turn, when the affected creature takes psychic damage, they take an additional 3d8 damage. Additionally, whenever a creature deals damage to the affected creature they reroll 1’s and 2’s, taking the second result. If this jutsu is cast on a creature who is currently under the effects of the Doubled Pain is targeted with this jutsu, they make their saving throw at disadvantage and if they fail the saving throw, you lose concentration on the doubled pain genjutsu and this jutsu instead deals an additional 4d8 psychic damage, and you reduce the concentration cost of this jutsu by half for the duration. If a creature is targeted by the Unrelenting Pain genjutsu while under the effects of this genjutsu, they make their saving throw at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of creatures this jutsu can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "0b8d77343786b32f9589f44f", name: "UNLIMITED PLEASURE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "aaeecd12fb6a8f889a26ab97", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "18 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You target willing creature(s) and maximize their nervous systems sensitivity to pleasure and recouperation. Three creature(s) you can see within range who would gain temporary hit points as a result of a Genjutsu, also regains a number of hit points equal to the number of temporary hit points gained. If the Genjutsu cast that gains temporary hit points has the Medical keyword, increase the die rolled by 1 step and reroll all 1’s and 2’s, taking the second result. (D4>D6>D8>D10>D12)", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of creatures this jutsu can target by +2.", created_at: NOW, updated_at: NOW },
  { _id: "620bdee1629fa4b51838af79", name: "WILL BREAKER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "Special (20 Chakra)", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You target creature(s) and attempt to break their will by planting seeds of doubt and despair deep into their mind. Select one creature you can see within range. The target must make either an Intelligence, Wisdom or 217 Charisma save at the beginning of each of their turns (Your choice, this cannot be changed once selected). Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature reduces the chosen Ability score by 1d4 for the duration. A creature who’s ability score is reduced to 0 by this jutsu takes psychic damage equal to 14d8 + Your genjutsu ability modifier, this jutsu then immediately ends. A creature within 5 feet of the affected creature use its action to make a Wisdom (Illusions) check vs your Genjutsu Save DC. On a success, they tear the break this genjutsu’s hold on the affected creature immediately ending this jutsu. Critical Failure: Same as Failure, but instead they reduce the chosen ability score by 1d6.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of creatures this jutsu can target by +2. S-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "6612c9e67abcf2409bac2d47", name: "ANTIPATHY/SYMPATHY", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Hour", range: "60 Feet", chakra_cost: "28 Chakra", components: "HS, CM, CS", duration: "10 Days", description: "This genjutsu attracts or repels creatures of your choice. You target something within range, either a huge or smaller object or creature or an area that is no larger than a 200-foot cube. Then specify a kind of intelligent creature, such as Sage’s beasts, Demons, or even Humans. You inject the target with an aura that either attracts or repels the specified creatures for the duration. Choose antipathy or sympathy as the aura’s effect. Antipathy. The genjutsu causes creatures of the kind you designated to feel an intense urge to leave the area and avoid the target. When such a creature can see the target or comes within 60 feet of it, the creature must make a Wisdom saving throw or become frightened. The creature remains frightened while it can see the target or is within 60 feet of it. While frightened by the target, the creature must use its movement to move to the nearest safe spot from which it can’t see the target. If the creature moves more than 60 feet from the target and can’t see it, the creature is no longer frightened, but the creature becomes frightened again if it regains sight of the target or moves within 60 feet of it. Sympathy. The enchantment causes the specified creatures to feel an intense urge to approach the target while within 60 feet of it or able to see it. When such a creature can see the target or comes within 60 feet of it, the creature must make a Wisdom saving throw or use its movement on each of its turns to enter the area or move within reach of the target. When the creature has done so, it can’t willingly move away from the target. If the target damages or otherwise harms an affected creature, the affected creature can make a Wisdom saving throw to end the effect, as described below. Ending the Effect. If an affected creature ends its turn while not within 60 feet of the target or able to see it, the creature makes a Wisdom saving throw. On a successful save, the creature is no longer affected by the target and recognizes the feeling of repugnance or attraction as magical. In addition, a creature affected by the genjutsu is allowed another Wisdom saving throw every 24 hours while the genjutsu persists. A creature that successfully saves against this effect is immune to it for 1 minute, after which time it can be affected again.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fed3f4e6567c4cef0af97bb5", name: "EAGLE’S EYE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius)", chakra_cost: "30 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You impart the visual prowess of the eagle- eyed kings of the sky. Yourself and all creatures of your choice within range gains the following benefits; • 120 Feet of Chakra Sight. • 90 Feet of Dark Vision. • 60 feet of blind sight. • 30 Feet of True Sight. • The range of ranged attacks are doubled.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c2758896617428c946c1c1ae", name: "FEEBLEMIND", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "150 Feet", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Instant", description: "You blast the mind of a creature that you can see within range, attempting to shatter its intellect and personality. The target takes 8d6 psychic damage and must make an Intelligence saving throw. On a failed save, the creature’s Intelligence and Charisma scores become 1. The creature can’t cast jutsu, activate chakra items, understand language, or communicate in any intelligible way. The creature can, however, identify its friends, follow them, and even protect them. At the end of every 30 days, the creature can repeat its saving throw against this genjutsu. If it succeeds on its saving throw, the genjutsu ends. The spell can also be ended by an A-Rank Genjutsu break, Restorative, or Mind-Body Recovery. 218", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "41389de2c6e3c8de16b910f9", name: "LIONS PRESENCE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius)", chakra_cost: "30 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You exude the courage of the infallible kings of the jungle. All hostile creatures within range must make a charisma saving throw. On a failed save, for the duration they gain the following while within range of you; • Affected creatures cannot score critical hits. • Affected creatures have a -5 penalty to attack rolls, skill checks and ability checks. • Affected creatures cannot maintain concentration on more than 1 Jutsu. • Affected creature loses resistance and immunity to the Fear condition. • Affected creature becomes vulnerable to psychic damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d8e943e97edb5d82a6a1ae28", name: "MAZE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "28 Chakra", components: "HS, CM", duration: "Concentration, 10 Minutes", description: "You select up to 4 creatures you can see within range. Each creature must make a Wisdom saving throw. On a failed save you banish the minds of the creature into a labyrinth of your design. The target mentally remains there for the duration or until it escapes the maze. A mentally trapped creature falls prone and is physically stunned, but mentally active. On each of its turns it can do one of the following vs your Genjutsu save DC in an attempt to escape. They can only make one of the following skills checks if they are proficient. If they are not proficient in any of the following, they instead make a flat Intelligence Check vs your Genjutsu save DC to escape. A creature does not add expertise or any feature that doubles their proficiency bonus for these checks; • Intelligence (Investigation) check. On a successful check, it finds the exit immediately ending this Jutsu's effects upon them. • Wisdom (Insight) check. On a successful check, at the beginning of its next turn, it remakes its wisdom saving throw at advantage, ending this Jutsu's effects upon them on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ecaa5fedc04c4f84eccc70c3", name: "MENTAL PRISON", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "22 Chakra", components: "HS, CM", duration: "Up to 1 minute", description: "You attempt to bind a creature within an illusory cell that only it perceives. One creature you can see within range must make an Intelligence saving throw. The target succeeds automatically if it is immune to being charmed. On a successful save, the target takes 5d10 psychic damage, and the genjutsu ends. On a failed save, the target takes 5d10 psychic damage, and you make the area immediately around the target’s space appear dangerous to it in some way. You might cause the target to perceive itself as being surrounded by fire, floating razors, or hideous maws filled with dripping teeth. Whatever form the illusion takes, the target can’t see or hear anything beyond it and is restrained for the genjutsu’s duration. If the target is moved out of the illusion, makes a melee attack through it, or reaches any part of its body through it, the target takes 10d10 psychic damage, and the genjutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f1b0b7f5fe8a5a801de651ea", name: "NEVERENDING DREAM", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "3d4ef417aa13fb1eaec5abc1", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Hour", range: "Touch", chakra_cost: "28 Chakra", components: "HS, CM, CS", duration: "Until Dispelled", description: "You create a looping Genjutsu of your description and seal it into your custom-made chakra seal. You have to make a Melee Genjutsu attack, on a creature in range. On a hit, the target creature must make a Wisdom save. On a failed save, they are placed into the Genjutsu loop that you created. Their body is rendered sleep for the duration. At the end of each day, the targeted creature makes a Wisdom save at disadvantage. On a successful save, the target creature becomes one step closer to waking up. The target creature needs to succeed 5 times in a row to successfully awake from this Genjutsu. While this Genjutsu is in use, it cannot be used on another creature unless they end the Genjutsu on another creature first.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bb6751bacaf0155ee9d25441", name: "RABBITS FRENZY", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius)", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You create an illusory mirage of angry, ferocious, man-eating rabbits with glowing red eyes that follow you and attack all creatures of your choice within range. As an action on each of your turns, you can make a melee genjutsu attack against up to 4 creatures you can see within range. On a hit, the swarm of rabbits attack the creature biting and tearing into them, ripping pieces from their flesh and ferociously holding them down. You deal psychic damage equal to 27d4 and the target creature must make a Charisma saving throw. On a failed save they gain 3 ranks of fear against you for 1 minute and are restrained until the end of their next turn. 219 If you make a melee genjutsu attack against a restrained creature using this jutsu, you reroll all 1’s, taking the second result.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5ce319cd8d9ecee9a7ff0b21", name: "SLUG DANCE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "30 Chakra", components: "HS, CM, CS", duration: "1 Day", description: "You place yourself under a powerful Genjutsu designed to snap you out of any other Genjutsu effect you may be under at any point of time by transferring the Genjutsu to a Chakra Seal you have prepared. You cannot reduce the cost of this jutsu. When targeted by an Jutsu or Art that requires a Saving throw with the Genjutsu Keyword, you can choose to automatically succeed. This jutsu then ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e5997c972d88ad852d77b7de", name: "SNAKE PLAY", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "22 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure snakes that appear under the target as more begin to appear, swarming the target and constricting them to the point of being unable to breathe. Select up to 7 Creatures in range. The target(s) must make a Wisdom Saving Throw, being Stunned and suffering 2 rans of Exhaustion as they hold their breath, under the impression that they are unable to breathe. At the end of each of their turns they must make another Wisdom save, suffering another two ranks of Exhaustion on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5d79a9701a267c5f45027aa4", name: "TOAD SONG", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "97a529e82067b359e2044cea", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "30 Feet radius Sphere", chakra_cost: "30 Chakra", components: "HS, CM, Toad Oil", duration: "Permanent", description: "As part of the activation of this jutsu you coat your throat in toad oil, transforming some of it into that of a toad for the duration. You harmonize your vocal cords to sing a Powerful but calm melody. All Creatures in the radius who can hear you, immediately fall into a deep sleep, unable to stay awake until they are released or killed. Roll 20d10 + Genjutsu Modifier + Proficiency modifier. The total is how many hit points of creatures this jutsu can affect. All creatures who have less Hit Points than the rolled result immediately fall asleep, unable to awake without the user releasing the effect of this jutsu, being released by another creature or Jutsu or being killed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8b140efc0667c302ec7a50cf", name: "WOLVES COMPANIONSHIP", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius)", chakra_cost: "40 Chakra", components: "HS, CM, NT (Poison Kit or Wolf’s Bane", duration: "10 Minutes", description: "You create an illusory mirage of wolves that follow you as a pack and aid or hinder any creature of your choice when commanded. Roll four d20’s, recording the results. For this jutsu’s duration, whenever a creature rolls a d20 as a part of their action, you can replace their d20’s result with the result of one of your d20’s. Additionally, you can spend any one of your d20 results to instead grant any creature of your choice advantage on any single d20 roll they make. Or, you can spend two of your d20 results, to instead impose disadvantage on up to 4 creatures of your choice on the next d20 roll they make. Or, you can spend three of your d20 results, to instead treat the next d20 roll by one creature of your choice as a critical hit, regardless of their d20 result. Or, you can spend four of your d20 results, to instead make one creature of your choice treat all rolls they make until the end of their next turn count as a Natural 1. Finally, as an action on your turn you can spend 20 chakra, to grant yourself another four d20’s for this jutsu, which also extends this jutsu’s duration by 5 minutes. 220", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d8a903e6848a8f29c7f6b186", name: "WORST FEAR", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "79eaf0305561cf512f55ad70", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Drawing on the deepest fears of a group of creatures, you create illusory creatures in their minds, visible only to them. Each creature in a 30-foot-radius sphere centered on a point of your choice within range must make a Wisdom saving throw. On a failed save, creatures gain 5 ranks of fear for the duration. The illusion calls on the creature’s deepest fears, manifesting its worst nightmares as a tangible threat. At the end of each of the frightened creature’s turns, it must make a Wisdom saving throw or take 8d10 psychic damage. On a successful save, the genjutsu ends for that creatures. 1 TAIJUTSU A basic form of techniques and refers to any techniques involving the martial arts or the optimization of natural human abilities. Taijutsu is executed by directly accessing the user's physical and mental energies, relying on the stamina and Strength gained through training. It typically does not require chakra, though chakra may be used to enhance its techniques. Taijutsu generally require no hand seals to perform, occasionally making use of certain stances or poses, and are far quicker to use than ninjutsu or Genjutsu. Taijutsu is simply put: hand-to-hand combat. D-RANK:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0146073da555b1696c18d075", name: "1000 YEARS OF DEATH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "As a part of casting this jutsu you must be hidden from the target You quickly move behind the target as you take your extended fingers and uncomfortably strike your opponent in an attempt to humiliate them. Make a melee taijutsu attack. On a hit the target must make a Charisma saving throw. On a failed save they quickly recoil being pushed 15 feet in a straight line as they are taken aback in shame. Until the end of the creatures next turn the next melee attack against the target is at advantage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d4478230ae1d98566fadcf1c", name: "AVALANCHE DANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You strike at your opponent’s joints trying to make them crumble from the weight of their own body. Make a Taijutsu attack, dealing your [Unarmed Damage] + 1d6 and the target must make a Strength saving throw, gaining 1 rank of Bruised on a failed save. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by +1d6. If this jutsu is cast at B-Rank or higher, increase the number of attacks you can make by +1. If this jutsu is cast at S-Rank, increase the damage die of this jutsu to a d8.", created_at: NOW, updated_at: NOW },
  { _id: "f8ef7cc1534407dd88e3e723", name: "BESTIAL FURY KICK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You perform a devastating round house kick with enough force to even effect creatures 10 feet away from you. Make a melee taijutsu attack targeting a creature in range On a hit, you deal your [Unarmed Damage] + 2d4 and the target must make a Strength saving throw, being pushed back 10 feet on a failed save. If this jutsu is used as a Finisher, all creatures in a 15- foot cone directly in front of you must make a Strength saving throw, taking your [Unarmed Damage] + 2d6, being push back 10 feet and falling prone on a failed save or half as much damage on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d4 or 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "cc1711320e959ee76a2b4781", name: "BOLTING BLOSSOM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You attempt to deliver a series of straight jabs. Make two taijutsu attacks, each dealing 3d6 bludgeoning damage. If you hit with both of these attacks on a single target, they are knocked prone. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage die by 1 step (D6>D8>D10>D12). If this jutsu is cast at B-Rank or higher increase the number of attacks by +1. If this jutsu is cast at S-Rank, add your Taijutsu Ability modifier to the damage rolls.", created_at: NOW, updated_at: NOW },
  { _id: "94a744618456916a3664070d", name: "BRACE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you are forced to make a Strength or Constitution saving throw", range: "Self", chakra_cost: "3 Chakra", components: "M", duration: "1 round", description: "You brace for impact from an effect you know you can’t avoid. You gain a +2 bonus when making a Strength or Constitution saving throw.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase your saving throw by +4. If this jutsu is cast at S-Rank, increase your saving throw by +6. 222", created_at: NOW, updated_at: NOW },
  { _id: "b9b3ded1192c3186fca822f5", name: "BUTTERFLY KICK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You jump and perform a series of kicks that keep you suspended in the air. While performing these kicks, you create an image of a butterfly’s wings. Make a melee taijutsu attack against all creatures of your choice who are adjacent to you, comparing your resolve vs their AC. On a hit, you deal your [Unarmed Damage] + 2d4 and forcing all creatures you hit to make a Strength saving throw gaining 1 rank of concussed on a failed save. If this jutsu is used as a Finisher, all creatures in a 15- foot cube originating from you make a Strength saving throw. On a failure save they take your [Unarmed Damage] + 2d8, gain 1 rank of concussed, and are knocked prone. On a successful save they take half damage and no further effects. After targets make their saving throws, select an unoccupied space up to 15 feet away that can hold you as you move into this space without triggering attacks of opportunity.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank or higher, increase the damage dealt by 2d4 or 1d8. If this jutsu is cast at B-Rank or higher, increase the number of attacks or ranks of concussed by +1. If this jutsu is cast at A-Rank or higher increase the damage dealt by 2d4 or 1d8. If this jutsu is cast at S-Rank, creatures cannot benefit from Jutsu based bonuses to their AC or Strength saving throw.", created_at: NOW, updated_at: NOW },
  { _id: "ddc9e4a3c6fdc217c71ad622", name: "CERBERUS STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You quickly strike out at different targets you can see within range. Select up to three targets within range and make a melee taijutsu attack, comparing the result to each of their AC’s. On a hit you deal your [Unarmed Damage] + 1d8, they cannot take attacks of opportunity until the beginning of their next turn and the next melee attack that targets any affected creature gains a bonus +2 to the attack roll before the end of your next turn. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d10. CLAWING SWIFT", created_at: NOW, updated_at: NOW },
  { _id: "05d3f9145e8b704057dee4ca", name: "FANG", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "15 Feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You coat your hands in a poisonous liquid and use your medical release chakra to maintain its viscosity and lethality. For the duration, your hands, feet or teeth are coated in a heavily poisonous substance, ready to be used as striking instruments. For the duration, you can spend your action to make a melee ninjutsu attack. On a hit you deal 3d4 poison damage and once per turn, you can force the target creature to make a Constitution saving throw. On a failed save, the target gains 1 rank of envenomed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d4. If this jutsu is cast at B-Rank the number of attacks you can make becomes two. If this jutsu is cast at S-Rank, the number of attacks you can make becomes three. MEDICAL RELEASE: TWISTED HEALING Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you see a creature regain hit points. Range: 60 Feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate a surge of twisted medical release chakra designed to reverse the effects of healing, even making it detrimental to do so. When you see a creature begin to mend their wounds, or have their wounds mended by another within range, you can swiftly prevent it. Roll 4d6, you reduce the amount of hit points regained by the result. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of targets by +1, and the healing prevented by 1d6. MEDICAL RELEASE: VENOM SHOCK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant. Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You generate a surge of medical release chakra and imitate the violent and un controllable currents of lightning release nature transformations. Select one creature you can see within range. The target creature must make a Constitution saving throw. On a failed save, they take 3d8 poison damage and gain the envenomed condition or half as much on a successful save and no further effect. A creature envenomed as a result of this jutsu suffers a -1 penalty to Strength saving throws for each rank of envenomed they have. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8 MEDICAL RELEASE: VENOMOUS SHARDS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot cube) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You mold medical release chakra in your hands to imitate the substance and structure of the earth release nature transformation, before releasing it as a quake of sickly green or dark purple crystalline structures from the ground itself. All creatures in a 15-foot cube originating from you, must make a Constitution saving throw. On a failed save, creatures take 2d12 poison damage and have their movement speed reduced by 10 feet for the next minute. On a successful save a creature takes half damage and no further effect. A jutsu or effect that would end the poisoned condition, can also remove this effect. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d12 and the size of the cube by 5 feet. If this jutsu is cast at B-Rank and above on a failed save this jutsu also inflicts the envenomed condition. If this jutsu is cast at A-Rank and above, on a failed save this jutsu also leaves the affected area as difficult terrain. MEDICAL RELEASE: WITHER AND BLOOM Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet (10-foot radius sphere) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate a surge of twisted medical release chakra designed to invoke life and death. All creature of your choice in a 10-foot radius sphere centered on a point you can see within range, must make a Constitution saving throw. On a failed save they take 3d6 necrotic damage. Additionally, one creature of your choice within the chosen area regains 3d6 hit points. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the hit points regained by 1d6. MEDICAL RELEASE: WOUNDS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate a surge of twisted medical release chakra designed to tear open wounds and rend the flesh. Make a range ninjutsu attack against a creature you can see. On a hit, you deal 3d10 necrotic damage. A creature who currently has ranks of bleeding, has one rank of bleeding evolve into one rank of laceration. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d10. 16 OPPRESSIVE AURA Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 10 feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You begin to exert chakra into an oppressive aura around yourself with enough intensity to be seen by the naked eye and even move loose materials such as dirt, leaves, and water droplets. Creatures who are within 10 feet of you upon activation of this jutsu must make a Strength saving throw to not be pushed to their knees and become prone for the duration, becoming unable to stand while inside the aura. Creatures knocked prone by this jutsu remakes their saving throw at the beginning of their turn to end the effect. If a you, or an affected creature moves outside of the aura, the jutsu’s effect ends on them immediately. A creature affected by this jutsu, who ends or escapes its effects, cannot be affected again until the end of their next turn. SEALING ART: BIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute Components: HS, CM, CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into a chakra seal as you attempt to mark a person with the seal of binding. A creature within range, must make a Charisma saving throw. On a failed save the target creature is Restrained for the duration and gains 1 rank of Sealed. A creature restrained by this jutsu remakes their save at the end of each of their turns. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets by +1. SEALING ART: BLOCK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you make when you or a willing creature you can see are targeted or would make a saving throw against a jutsu with the Fuinjutsu keyword Range: 60 feet Duration: 1 Round Components: HS, CM, CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into a chakra seal as you attempt to manifest a seal of protection. When you or a willing creature would be the target of, or would make a saving throw or skill check against, any jutsu with the Fuinjutsu keyword you enact a defensive ward meant to protect until the beginning of your next turn. They gain a +2 bonus to their AC, saving throws, and ninshou checks against jutsu with the Fuinjutsu keyword. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase your AC and saving throw bonus to +3. If this jutsu is cast at S-Rank or higher, increase your AC and saving throw bonus to +4. SEALING ART: FRACTURE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM, CS Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into a chakra seal as you attempt to mark a person with the seal of descension and then shatter it causing a fracture in their internal balance of Yin and Yang. A creature you can see within range, must make a Charisma saving throw. On a failed save the target creature takes 3d8 Force damage and gains 1 rank of Sealed. A creature with 3 or more ranks of Sealed makes this saving throw at disadvantage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. If this jutsu is cast at B-Rank or higher, increase the ranks of Sealed inflicted to 2. SEALING ART: LOCK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into a chakra seal as you attempt to mark an object with a seal of objection. You must select either an unattended object or a creature you can see within range who is holding an item. If an unattended item it is instantly bound to the surface it is currently resting on. If a creature holding an object, that creature must make a Strength saving throw. On a failed save the object the target is holding is sealed and bound to the nearest surface within range; be it the floor, a wall, or ceiling. For the jutsu’s duration the item remains bound to that surface unable to be moved by any means. A creature within 5 feet of the sealed object may attempt to remove the seal by making an Intelligence (Ninshou) check vs your Ninjutsu save DC. On a successful save they break the seal freeing the item. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range by 30 feet. 17 SEALING ART: REVERBERATE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, up to 1 minute Components: HS, CM, CS, W (Any) Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into a chakra seal as you mark a weapon you touch with a seal of veneration. For the duration, this [Weapons Damage] die is increased by +1. If the weapon already rolls more than one die when it deals damage, you instead increase the damage die by one step. (d4>d6>d8>d10>d12) This weapon cannot be targeted with another jutsu or effect that would change its damage type, die, add additional damage die, or augment it further by any means. If it is the target of such a jutsu or effect, it shatters. If this weapon scores a critical hit the seal shatters and you reroll any 1’s taking the second result. This jutsu then immediately ends. SENSING TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: Special Range: Self Duration: 10 minutes Components: HS Cost: 5 Chakra Keywords: Ninjutsu, Sensory Description: You are able to knead chakra in such a way that you can begin to sense other creatures chakra signatures clearly when you try. You can only cast this jutsu on your turn, and casting it does not cost action economy. When this jutsu is cast, for the duration, you gain access to a unique special action called Sense Chakra. This special action can be gained and used in addition to other special actions you gain and use. This special action counts as a Skill-Action and both a Constitution and Wisdom based skill. Sense Chakra. As a Bonus action, you can make a Perception check using either Constitution or Wisdom vs the Passive Chakra control (Chakra control bonus + 10) of all creatures within 30 feet of you. On a success, you gain the benefit of the Chakra Sensing special sense against them for the duration until they either have 0 chakra or they make and succeed their Suppress Chakra skill action. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range of the Sense Chakra skill action by 30ft. SHADOW SNAKE BITE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 15 Feet Duration: Instant Components: HS, CS Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You summon a snake formed from chakra that originates from a location of your body, that reaches out and attacks the target creature in range. Make a Ninjutsu attack. Target creature takes 2d8 Poison damage and must make a Strength saving throw on a Hit. On a failed Strength save, the target creature is restrained by the snake. As an action on a restrained creatures turn, they can attempt another Strength saving throw to end this condition on themselves. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets this jutsu affects by +1. SUBSTITUTION TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage. Range: Self Duration: Instant Components: HS, M Cost: 5 Chakra Keywords: Ninjutsu Description: You quickly replace yourself with an object, allowing you a swifter escape with smaller margins for error. When you would take damage you may increase your AC by +3 until the beginning of your next turn. If this bonus would cause the triggering attack to miss, you may move up to half of your movement away. If you activate this jutsu as a result of making a saving throw, you must still make the saving throw even if your movement would move you to the outside of its range. SUMMONING TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: Full Turn Action Range: 10 Feet Duration: Instant Components: HS, CS, CM Cost: Special (See Summoning Section for Jutsu breakdown) Keywords: Ninjutsu, Fuinjutsu Description: You must have formed a Blood Contract with a Sage Tribe, such as one found in the Summoning Jutsu section found at the end of the Ninjutsu chapter in order to successfully cast this jutsu. If a creature refuses or cannot be summoned, You spend chakra according to the rank this jutsu was cast. It appears where the user designates and can act as a Bonus Action on the user's turn, on the user's initiative order. You can communicate with the creature and it will listen to you and only you in combat. You can direct it to perform the following actions: Attack (Unarmed, Weapon, or Jutsu), Dodge, and Help. The creature can perform an Action and Move. The summoned creature must remain within 120 feet of the summoner. All sage creatures can speak common. At Higher Ranks: For each rank you cast this jutsu above D-Rank, you summon a corresponding creature equal in level and rank to the Rank used upon activation. 18 THUNDEROUS SCREECH Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot cone) Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Ninjutsu Description: You create a focused high-pitched screech that affects creatures in the direct path of the sound waves. Creatures in the target area must make a Constitution saving throw. On a failed save their body is rocked by the thunderous shockwave of sound. They gain 1 rank of Concussed and lose concentration on any one Jutsu of equal rank or lower they were concentrating on. On a successful save they suffer no effects. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the cone size by +5ft. C-RANK: BEAST IMITATING ART: BEAR Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 minute Components: HS, CM, CS, NT (Empty Scroll) Cost: 7 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You draw a picture of a bear. Infusing chakra into it as it exits your scroll and standing next to you. You summon a construct Ink bear. The construct bear has the following Statistics; You may command the Ink Bear as a bonus action on your turn. The Ink bear may take an appropriate reaction if able, such as attack of opportunity. The Ink Bear uses your Ninjutsu Attack bonus and Save for all of its attacks and effect save DC’s At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Ink Bears Hit points by 2d10+6. BEAST IMITATING ART: LION Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 minute Components: HS, CM, CS, NT (Empty Scroll) Cost: 9 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You draw a picture of a lion. Infusing chakra into it as it exits your scroll and standing next to you. You summon a construct Ink Lion. The construct Lion has the following Statistics; You may command the Ink Lion as a bonus action on your turn. The Ink Lion may take an appropriate bonus action if able. The Ink Lion uses your Ninjutsu Attack bonus for all of its attacks. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Ink Lions Hit points by 2d8+2. BEAST SENSES Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Touch Duration: 1 Hour Components: HS, CM, CS Cost: 6 Chakra Keywords: Ninjutsu, Sensory Description: You touch a willing beast. For the duration of the jutsu, you can use your action to temporarily gain the special senses or sensory features of the beast you touch for up to 1 hour. After which this jutsu ends. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the length of time you retain the special senses by 1 hour. Medium Construct, unaligned Armor Class 12 + Your Ninjutsu Ability Modifier Hit Points 45 (5d10 + 15) Speed 35 ft. STR DEX CON INT WIS CHA 19 (+4) 12 (+1) 16 (+3) 1 (-5) 10 (+0) 1 (-5) Condition Immunities Charmed, Chilled, Exhaustion, frightened, stunned, poisoned. Senses Darkvision 30 ft., passive Perception 10 Immutable Form. The Ink Bear is immune to any Jutsu or effect that would alter its form. Inky Weapons. The Ink Bears attacks are chakra enhanced. Multiattack. The Ink Bear can attack twice with their claws. Claw. Melee Weapon Attack: +X to hit, reach 5 ft., one creature. Hit: 1d12 + 4 Slashing damage. Body Block. The Ink Bear as a reaction may interpose an attack targeting an allied creature within 30 feet of it. When it does, the triggering attack is treated as if it was targeting the Ink Bear. Charge! (Recharge 11-12): The Ink Bear dashes 70 feet in a straight line. All creatures in its path must make a Strength Saving throw. On a failed save, they take 3d6 bludgeoning damage, are knocked prone and Dazed. Medium Construct, unaligned Armor Class 12 + Your Ninjutsu Ability Modifier Hit Points 30 (5d8 + 5) Speed 40 ft. STR DEX CON INT WIS CHA 18 (+4) 18 (+4) 12 (+1) 1 (-5) 10 (+0) 1 (-5) Condition Immunities Charmed, Chilled, Exhaustion, frightened, stunned, poisoned. Senses Darkvision 30 ft., passive Perception 10 Immutable Form. The Ink Lion is immune to any Jutsu or effect that would alter its form. Inky Weapons. The Ink Lions attacks are chakra enhanced. Multiattack. The Ink Lion can attack twice with their claws. Claw. Melee Weapon Attack: +X to hit, reach 5 ft., one creature. Hit: 2d8 + 4 Slashing damage. Maul (Recharge 5-6). The Ink Lion as a bonus action, may enter a pouncing stance targeting a creature within 15 feet of it. When it does, it leaps to maul the target creature. Until the end of this turn, its Claw attacks against the target creature are made at advantage. 19 CHAKRA SPHERE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 60 feet. Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 8 Chakra Keywords: Ninjutsu Description: You create a 5-foot diameter floating sphere of dense chakra in an unoccupied space you can see within range. As a bonus action on your turn, you can command the sphere to move up to 30 feet and make a single melee ninjutsu attack against a creature within 5 feet of it. On a success, the target takes 2d8 damage. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. • Earth: As an action on your turn or when the jutsu ends, you can cause one or more spheres to explode. Each creature within 15-feet of the spheres space(s) must make a Strength saving throw. On a failed save the creature takes gains 1 bruised and concussed. • Wind: Each creature hit by a sphere must make a Strength saving throw being knocked back 20 feet on a failed save. • Fire: Each creature who begins their turns within 5 feet of the sphere must make a Constitution saving throw, being burned on a failed save. • Water: Your sphere can move through allied spaces. When it does, roll its damage die, granting the creature(s) who’s space it moved through temporary hit points equal to the result. A creature can only gain temporary hit points this way once per turn. • Lightning: Each creature hit by a sphere must make a Constitution saving throw, being shocked. • Force: The damage die becomes a d10. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 the damage by 1d8 and the number of spheres created by +1, controlling each sphere independently with the same action. A creature can only be affected by two spheres each turn. Additionally, you can change the Nature Release and corresponding Damage type to one you currently know. CHAKRA TENTACLES Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 90 feet. Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 9 Chakra Keywords: Ninjutsu Description: You create squirming tentacles of chakra that fill a 20-foot cube on a surface that you can see within range. When a creature enters the affected area for the first time or starts its turn there, they must make a Strength saving throw. On a failed save they take 3d6 bludgeoning damage and are restrained for the duration. A creature restrained by this jutsu takes 3d6 bludgeoning damage at the beginning of each of its turns. A creature restrained by this jutsu can use its action to remake it’s saving throw. On a success, it free’s itself. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 the damage by 1d6 and the cube size by 5ft. SEALING ART: DARKNESS Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 60 feet (15-foot radius sphere) Duration: Concentration, up to 10 minutes. Components: HS, CM, CS Cost: 9 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You imbue your chakra seal to conjure a field of darkness. You throw your seal at a point you choose within range. The chakra-based darkness spreads from the seal, to fill a 15-foot radius sphere for the duration. The darkness spreads around corners. A creature with Darkvision or Chakra Sight can’t see through this darkness, and light created using an effect or jutsu of C-Rank or lower cannot illuminate it. If the point you choose is on an object you are holding or one that isn’t being worn or carried, the darkness emanates from it and moves with it. If any of this jutsu’s area overlaps with an area of light created by a jutsu of B-Rank or higher this darkness is dispelled. HAIR BINDING TECHNIQUE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 30 feet Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 8 Chakra Keywords: Ninjutsu Description: Using chakra, you activate the roots of your hair and begin to manipulate it freely. Because of the malleability of this hair, the user can attempt to grapple creatures completely immobilizing them. Select one creature within range. Make a melee ninjutsu attack. On a hit, the target is grappled by you. Creatures grappled by this jutsu cannot use Chakra Seals (CS). At the end of a restrained creatures turn, they make a Strength saving throw, escaping on a success. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 the number of creatures you can target by +1. 20 HIDING IN SHADOW TECHNIQUE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 15 feet Duration: 10 Minutes Components: HS, CM Cost: 6 Chakra Keywords: Ninjutsu Description: As a part of the requirements to cast and maintain this jutsu a creature or object within range must be casting a shadow. You select a creature, structure or objects shadow within range. Stealthily slipping inside of it, and gaining total concealment for this jutsu’s duration. For the duration of this jutsu, you can see and hear from the shadow but cannot act, speak, or move. When the creatures shadow moves, you move along with it. You may end this jutsu early as a bonus action expelling yourself from the shadow appearing in the closest space near the target that can hold you. If the target would lose their shadow by any means, this jutsu immediately ends as you appear in the closes space near the target that can hold you. LIVING WEAPON Classification: Ninjutsu Rank: C-Rank Casting Time: 1 bonus action Range: Touch (60 feet) Duration: Concentration, up to 1 Minute Components: CM Cost: 8 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You touch a weapon an imbue it with your chakra and it begins to float within range and does so for the duration or until you dismiss this jutsu. When you cast this jutsu you can move the weapon 30 feet an make a melee ninjutsu attack against a creature within 5 feet of the weapon. On a hit, the target takes the 2d8 + your ninjutsu ability modifier of your weapon’s damage type. As a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack against a creature within 5 feet of it. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. MEDICAL RELEASE: ACID SPRAY Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (30 Foot Line) Duration: Instant Components: HS, NT Cost: 6 Chakra Keywords: Ninjutsu, Medical Description: You take a vial of poison ingesting and using your fine control of chakra, blend it with your stomach acid that you spray out like a jet in a straight line. Creatures in range must make a Dexterity saving throw. On a failed save, affected creatures take 6d4 Acid Damage and gain 1 rank of Corroded and they take another 2d4 Acid damage at the start of their next turn. On a success the target takes half as much damage and suffer no additional effects. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the initial and delayed damage by 2d4. MEDICAL RELEASE: ACIDIC BLAST Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (30-foot-cone) Duration: Instant Components: HS, CM Cost: 7 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate acidic medical chakra and release it into a spray of boiling acid. All creatures in range must make a Dexterity saving throw, taking 6d6 acid damage on a failed save and half as much on a successful save. A creature who fails their saving throw gains 1 rank of the corroded condition. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. MEDICAL RELEASE: ACIDIC BLOOD Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when a creature other than yourself, within range would take Bludgeoning, piercing or slashing damage from an attack. Range: 60 Feet Duration: 1 Round Components: HS, CM Cost: 7 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate acidic medical chakra and infuse it into a willing creature within range. When a willing creature would take bludgeoning, piercing or slashing damage before the beginning of their next turn, their body reacts by ejecting acidic blood. All creatures within 5 feet of the affected creature takes 9 acid damage, and must make a Constitution saving throw being corroded on a failed save. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 3. MEDICAL RELEASE: ACIDIC BOLT Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 90 Feet Duration: Instant Components: HS, CM Cost: 6 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate acidic medical chakra and mold it into an arrow, lance or bullet. Make a ranged ninjutsu attack against a creature in range. On a hit you deal 4d6 acid damage. All creatures in a 15-foot cone originating from the target much make a Dexterity saving throw, being corroded on a failed save. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by 1. 21 MEDICAL RELEASE: AID Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 30 Feet Duration: 1 Hour Components: HS, CM, CS Cost: 8 Chakra Keywords: Ninjutsu, Medical Description: You imbue a chakra seal with medical release chakra before placing it on up to three creatures within range. Each target’s Maximum Hit Points increase by 15 for the duration and they regain 15 Hit Points. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and a target’s Maximum Hit Point increase and healing done by an additional 10. MEDICAL RELEASE: AURA OF LIFE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (30-foot radius sphere) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 7 Chakra Keywords: Ninjutsu, Medical Description: You infuse medical chakra into yourself as you release it as an aura of supporting energy. For this jutsu’s duration, anytime you or a non- hostile creature in this jutsu’s radius would take damage from a hostile creature, they immediately regain 8 Hit Points. A creature can only be healed by this jutsu 5 times per casting, after which this jutsu no longer affects them. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the maximum number of times a creature can be healed by this jutsu by +2. MEDICAL RELEASE: AURA OF PURITY Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (30-foot radius sphere) Duration: Instant Components: HS, CM, CS Cost: 9 Chakra Keywords: Ninjutsu, Medical Description: You infuse medical chakra into yourself as you release it as an aura of cleansing energy. You release a potent wave of medical release chakra. All creatures within range who are currently under the effects of a Mental or Sensory conditions as a result of a jutsu of equal rank or lower, has all stacks (if any) of their condition removed, cleansing them. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. Listed conditions inflicted by jutsu of equal rank or lower are removed. MEDICAL RELEASE: CHAKRA NEEDLES Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, W Cost: 7 Chakra Keywords: Ninjutsu, Medical Description: You create needles formed from your chakra and launch them at a creature you can see within range. Make a Ranged Ninjutsu check. Target creature takes 6d6 Necrotic damage on a hit and must make a Constitution saving throw, losing 10 movement speed until the end of their next turn on a failed save. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, damage by 1d6 and reduce target movement by 5. MEDICAL RELEASE: CHAKRA TRANSFER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: CM Cost: Special Keywords: Ninjutsu, Medical Description: You place your hand on a creature and share your chakra with them, transferring it to them. Spend a number of Chakra die up to your proficiency bonus. When you do roll the spent die, recording the result and adding your Constitution modifier. Transfer the result to a willing creature. Chakra die spent in this way cannot be regained until you complete a long rest. If the creature is affected by a Genjutsu, they gain advantage on their next saving throw. MEDICAL RELEASE: CORRUPT WAVE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (30-foot line) Duration: Instant Components: HS, CM Cost: 6 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate corrupted medical chakra and release it as a destructive wave of desecrating energy. All creatures in a 30-foot long, 10-foot-wide line originating from you, must make a Constitution saving throw, taking 6d4 necrotic damage or half as much on a success. Creatures who failed, take 4d4 necrotic damage at the beginning of their next turn. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the initial damage by 1d4. 22 MEDICAL RELEASE: ENCROACHING ENTROPY Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute. Components: HS, CM Cost: 8 Chakra Keywords: Ninjutsu, Medical Description: You weave necrotic and decaying medical release chakra together and manifest it into a point you can see within range. The point ex", created_at: NOW, updated_at: NOW },
  { _id: "79bcdf2d4084b15a5702c7c7", name: "CRANE WING FORMATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You leap and perform a swinging attack that creates the visage of a Crane before attempting to contort around a target creature within range and forcing them to the ground with this advanced grapple. Make a taijutsu attack against the target knocking them prone and grappling them on a hit. You can have a number of creatures grappled as you have hands. The target grappled with this taijutsu can use their action on their turn to make a Strength saving throw to escape the grapple and cannot escape the grapple following normal grapple rules. On a failed save, you may make an unarmed attack against the target dealing twice your [Unarmed Damage] on a hit.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank or higher, you can select one additional creature to target with this jutsu. 223", created_at: NOW, updated_at: NOW },
  { _id: "c98f63231b1672a032b894de", name: "CYCLONE SURGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Self (5-feet)", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You leap into the air, while performing a spinning strike, hitting and knocking all creatures into the air with you. You leap 15 feet into the air striking all creatures within range. Make a melee taijutsu attack, comparing the results to all creatures of your choice within range AC. On a hit, you deal your [Unarmed Damage] + 2d4 and are thrown 15 feet into the air, becoming airborne until the end of the current turn. An airborne creature cannot cast jutsu with the Mobility (M) keyword until they land and take no falling damage as a result of this jutsu. Until the end of your turn, you or an allied creature can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action, Bonus action or Reaction, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c44dfd62edab6f1587ca9a1b", name: "DEEP DIVE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "5 feet", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "You attempt to body slam a creature into the furthest surface from you. Make a grapple check against a creature you can reach. On a success, you immediately dash with them moving up to your full movement towards the furthest surface you can reach (such as a wall). If there are no other surfaces near you, you instead slam them into the ground. Regardless of where you slam them, they take bludgeoning damage equal to your unarmed damage. If you and the target creature are standing on Water or completely submerged when this jutsu is cast, you make your grapple check at advantage. On a success, you instead dive straight down up to twice your movement speed to the bottom of the body of water slamming them into the body of waters floor dealing bludgeoning damage equal to twice your unarmed damage. This jutsu can be used if you are already grappling a creature, instead attempting to slam the creature immediately without any additional checks. When you successfully slam a creature using this jutsu, your grapple ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "03e738cceb6d82f4dda2db19", name: "DEMON FIST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "Perform a powerful uppercut with enough force to generate a shockwave that runs along the ground that can deal concussive damage. Make a ranged taijutsu attack against a creature you can see within range who is currently standing on the same surface as you. On a hit, you deal 3d6 bludgeoning damage. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the activation cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "25906237b34b942384590656", name: "DEMPSEY ROLL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take damage from a melee attack or when a creature misses you with a melee attack.", range: "5 Feet", chakra_cost: "Special", components: "M", duration: "1 Round", description: "You take a boxers stance, when you are confronted by a melee attack from a creature within 5 feet of you. Until the beginning of your next turn, each melee attack that targets you, you can spend 4 chakra. When you do, you attempt to duck and weave granting yourself a +2 Bonus to your AC against the triggering creature and then immediately make one unarmed attack in response to the triggering melee attack. This bonus to AC stacks up to twice.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the activation cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the AC bonus by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e7cf4b7fcb5d85937721d514", name: "DRAGGING FULL ROTATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when a creature misses you with a melee attack.", range: "5 Feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "When a creature within 5 feet of you misses you with a melee attack, you quickly reach out grabbing them before they can make any further action, using their momentum against them, dragging them 10 feet with you in any direction of your choice, before throwing them a number of feet equal to 5 x your Strength modifier (Min 1.). A creature who’s movement is interrupted by a solid surface (such as a tree or wall) takes bludgeoning damage equal to 1d6 for every 10 feet you would have thrown them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the distance you throw an affected creature by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "b40bf224f397f104cd336cf9", name: "DRAGON PALM STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Dragon Fist Stance. You perform a myriad of distracting movements before collecting your chakra into your palm for a single powerful thrust, striking a creatures core and knocking them away. Make a melee taijutsu attack against a creature you can see in range. On a hit, you deal your [Unarmed Damage] + 2d4 and push the target back 10 feet. If this jutsu is used as a Finisher you instead deal [Unarmed Damage] + 2d12 damage and the distance the target is pushed by 10 feet. If the target would hit a solid surface as a result of this push. They take 1d6 bludgeoning damage for every 10 feet that they were unable to be moved.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d4 or 1d12 and the push distance by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "f84f0b3e63894890fc004451", name: "DRAW!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you take damage from an attack.", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You quickly dash backwards creating distance between yourself and another creature. As a as a reaction when you would take damage from an attack, you can dodge backwards, moving up to 10 feet away from the triggering target in an attempt to escape the attacks range. When you do, make a contested Dexterity saving throw vs the attack roll result. On a success the triggering attack misses you. You then immediately move up to 20 feet towards the triggering creature, making an unarmed attack, on a hit you deal your [Unarmed Damage] + 2 [Unarmed Damage die].", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by +1 [Unarmed Damage die].", created_at: NOW, updated_at: NOW },
  { _id: "0e61f2b390780034c3ff712d", name: "DYNAMIC ENTRY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You perform a high jump kick that propels you towards a target creature you can see in range. Make a Taijutsu Attack. On a hit target creature takes 3d10 Bludgeoning damage. Regardless if you hit or miss, you move up to 30 feet, ending your movement within 5 feet of the original target.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "a5b260a3b297554e1f72fa48", name: "ERRATIC COMBO", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Drunken Fist Stance. You sway in and out of combat, dancing around your opponent in a drunken stupor throwing them off. Make two melee taijutsu attacks against a single creature you can reach. On a hit, you deal 2d6 bludgeoning damage. Each time you successfully hit a creature using this jutsu, you increase your AC by +1 until the beginning of your next turn. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "ae97ffee0d2df0a553d6f14f", name: "EXORCISM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You perform a multi-strike combination with all of your Strength and Body weight. Make three melee taijutsu attacks. On a hit you deal 1d12 bludgeoning damage and push the target 5 feet in any direction of your choice. If you score at least one attack on a creature, they must make a Constitution saving throw. On a failed save they gain +1 rank of Bruised. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the damage by +1d12. If this jutsu is cast at S-Rank, increase the damage by +1d12. 225", created_at: NOW, updated_at: NOW },
  { _id: "f0994df51428cff603d99d17", name: "FALLING DRAGON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "As part of the activation of this jutsu, the target creature must be airborne or falling. You leap upwards following an airborne or falling target. You curl your body into a ball as you spin faster and faster before you find yourself above the target. You uncurl yourself as your perform a spinning drop kick, sending the target creature crashing down. Make a melee taijutsu attack against the airborne or falling creature. On a hit, you deal your [Unarmed Damage] + 3d6, sending them crashing down into the ground landing prone. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 3d6 bludgeoning damage. You then come falling after them at great speeds, making a second melee taijutsu attack, slamming both of your feet into the prone creature. On a hit, you deal 3d6 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "521fa676ff0480a98a735efe", name: "FEATHER COMBO", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action or 1 Reaction, which you take when you are falling or airborne.", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "As part of the activation of this jutsu, you must be airborne, falling or be targeting an airborne or falling creature. You perform an aerial combo, striking out against a creature within range. Make two melee taijutsu attacks targeting. On a hit, you deal your [Unarmed Damage]. If you hit the same creature twice, you use the momentum of the second strike to propel yourself up to 20 feet in any direction of your choice and land in a space that can hold you suffering no falling damage. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by +1d6.", created_at: NOW, updated_at: NOW },
  { _id: "fbd583954556997ceca958b9", name: "FIRST HEAVENLY BREATH: INHALE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "Concentration, up to 10 Minutes", description: "You increase your lungs capacity twofold. Doing so increases your oxygen intake and your physical Strength similarly. You cannot lose concentration on this jutsu as a result of damage and you cannot maintain concentration on Ninjutsu or Genjutsu for the duration. Increase your Taijutsu attack bonus +1, Taijutsu Damage by 1d8 twice per turn, and Speed by +10.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1308bcf67a75dbc0e532ed55", name: "FORCEFUL BULL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "CS, M", duration: "Concentration, up to 1 minute", description: "You focus chakra throughout your muscles enhancing your physical Strength and fortitude. For the duration, your Strength and Constitution ability scores becomes 16 if they are lower than 16. You gain +15 temporary hit points that last for the duration. When you would cast a Taijutsu with the Finisher keyword, on a successful hit or if a target fails their saving throw they gain +1 rank of concussed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a11214b821e56f2b39eb1e0f", name: "GRACEFUL CAT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Concentration, up to 1 minute", description: "You focus chakra throughout your muscles enhancing your physical Dexterity and Cunning. For the duration, your Dexterity and Wisdom ability scores becomes 16 if they are lower than 16. You do not suffer fall damage from falls less than 30 feet. Your movement speed is increased by +20 feet and you gain a +2 to your passive perception. When you would cast a Taijutsu with the Combo keyword, you gain +10 bonus to your movement speed until the end of the turn you cast it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "aca9bff4d0c7d24903110ccc", name: "HAMMER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Bonus Action", range: "5 feet", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "As part of the activation of this jutsu, you must be targeting a creature who can be targeted by a taijutsu with the Finisher keyword regardless of the range. You bring your hands together, interlocking your fingers until your hands resemble a single bludgeoning device. Make a melee taijutsu attack dealing your [Unarmed Damage] + 3d8 bludgeoning damage and the target must make a Strength saving throw. On a failed save they gain +1 rank of concussed and Dazed", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d8. 226", created_at: NOW, updated_at: NOW },
  { _id: "3685b9bb9a63e8d8141862b4", name: "HEAT UP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, M", duration: "1 Round", description: "You release a surge of chakra throughout your body, activating your bodies adrenaline production and kicking it into high gear for single swift moment while also increasing your bodies sensitivity to pain. You cannot reduce the cost of this jutsu by any means. The next taijutsu you cast, that requires an attack roll increases its damage die by 1 Step until the end of your turn. (D4>D6>D8>D10>D12) Additionally, until the beginning of your next turn, you gain vulnerability to the next instance of Bludgeoning, Piercing or Slashing damage from a hostile creature.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast a C-Rank or higher, you reroll all 1’s, 2’s and 3’s taking the second result. If this jutsu is Cast at B- Rank or higher, increase damage dies by 1 additional step. If this jutsu is cast at A-Rank or higher, the next taijutsu you cast that requires an attack roll ignores Resistance and Immunity. If this jutsu is cast at S-Rank, this Jutsu's duration becomes 1 Minute causing the following; Increase Taijutsu damage dies by 2 additional seps for the duration and you gain Vulnerability to Bludgeoning, Piercing or Slashing, your choice when cast, for the duration.", created_at: NOW, updated_at: NOW },
  { _id: "7220442bb3c6e244f8d06139", name: "HIGH MONK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You perform a high kick combo. Make two Taijutsu attacks, dealing your [Unarmed Damage] + 1d6. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 2d6, leap back 15 feet that doesn’t provoke opportunity attacks. This movement does not provoke opportunity attacks.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the leap back range by 5 feet. If this jutsu is cast at B- Rank, increase the damage dealt by 1d6. If this jutsu is cast at S-Rank, increase the damage dealt by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "ab87c21a068f174cc23f68f7", name: "HOWLING KNUCKLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Concentration, Up to 1 Minute", description: "As a requirement to activate this jutsu, you must currently be in the Wolf Fist Stance. You do not spend chakra to maintain concentration on this jutsu. You begin to exhibit the ferocious power of wolves as you become a one-person wolf pack. For the duration, you may perform the Wolf Fang Fist as a Bonus Action. You can do this, once per turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bc35faa4349fe1e20e5fbc95", name: "IRON KNUCKLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Iron Fist Stance. You perform a single high-powered strike with full intention to cause harm. Make a melee taijutsu attack. On a hit, you deal your [Unarmed Damage] + 2d6 and force the target to make a Strength saving throw. On a failed save, you knock them back a number of feet equal to 5 x your Strength ability modifier. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 4d6 and on a failed save they are knocked back a number of feet equal to 10 x your Strength ability modifier and if they strike a solid surface that is less than 5 feet thick, they break through it if they have 10 or more feet remaining to be knocked back, taking 3d6 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "4454aaf5598bd6c577c2077f", name: "IRON STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You punch with enough force to tear through any defense your enemy might have. Make a taijutsu attack. On a hit, they take your [Unarmed Damage] + 2d6. If the target would cast a Jutsu as a Reaction to the damage you deal, the cost of their jutsu is increased by +4 due to the strain required to keep up with your strike. If their Jutsu does not cost chakra, they must spend 10 chakra to take their reaction. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 4d6 and the cost of Reaction jutsu cast vs you is instead increased by +8.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and the cost increase of Reaction jutsu by +4. 227", created_at: NOW, updated_at: NOW },
  { _id: "014ed4915ddc0f94201e13c0", name: "LEAF GALE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You perform a Spinning low kick throwing your target off balance. A target creature in range must make a Dexterity saving throw. On a failed save, they are knocked prone and must spend an Action to stand until the end of their next turn. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "82e07fc21c5828f0b015656b", name: "LEAF KICK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You deliver a single falling kick, strong enough to bring the environment crumbling down around you. Make a Melee Taijutsu attack against a creature within range. On a hit you deal your Unarmed damage + 1d12 and the target must make a Strength saving throw. On a failed save they gain 1 rank of Slowed until the end of their next turn. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 3d12 and on a failed save the target falls prone as your force them into the ground shattering it, causing the area within a 10ft cube originating from you to be treated as difficult terrain.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "d4bfa7b1e3d62445f3d3cbab", name: "LEAF UPPERCUT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You perform a single backflip kick or rising uppercut with enough force to crack the ground underneath you. Make a single melee taijutsu attack. On a hit, you knock the creature 30 feet into the air dealing 3d6 bludgeoning damage. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. If the Taijutsu Finisher has the Leaf prefix, it increases its damage by +1 damage die.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "32614b868864bf9b42a544a7", name: "LEAPING STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take, when an allied creature declares they are going to make a melee attack.", range: "15 Feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Frog Fist Stance. You enter a leaping stance prepared to support your team. When an allied creature within range would declare to you they are going make a melee attack against a creature within 30 feet of them, you stomp the ground knocking them into the air as you leap and jut your feet out, launching them towards their target at high speeds. The allied creature is moved up to 30 feet in a straight line towards their targets, ending in a space adjacent to them of their choice, where they then must make their melee attack. When they do, they can use either your Taijutsu attack bonus or their normal attack bonus. Regardless, on a success, they deal additional damage equal to your [Unarmed Damage].", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and damage bonus by +1 [Unarmed Damage die].", created_at: NOW, updated_at: NOW },
  { _id: "1182ca1bf2293a4385cf6e8f", name: "MIRAGE BLITZ", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you would take damage from a melee attack.", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You perform a special spinning dodge designed to give you a slight upper hand on your next strike. When you would take damage from a melee attack, you gain a +3 bonus to your AC, potentially turning a hit into a miss as you leap back and react with a single strike. Make a melee taijutsu attack against the triggering creature. On a hit, you deal twice your [Unarmed Damage], pushing the target back 15 feet and the target must make a Strength saving throw, being knocked prone on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "05ecdb8b683934a75ce16f20", name: "MOONLIGHT HIGH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "As part of the activation of this jutsu, you must also have moved at least 15 feet towards the target. You make a leaping, spinning double roundhouse kick. Make two melee taijutsu attacks. On a hit, you deal your [Unarmed Damage] + 1d6. If both attacks are successful, the target is knocked back 20 feet and must make a Constitution saving throw. On a failed save they gain 1 rank of confused. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. 228", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1fde8d3df841e21132b4b4fc", name: "NECK CHOP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You attempt to strike at a vital pressure point on the nape of the neck of a humanoid target. Make a melee taijutsu attack. On a hit, deal your [Unarmed Damage] + 1d6 and the target must make a Constitution saving throw. On a failed saved, they become Dazed. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "03a20301c0ef61702a2d74c2", name: "NOBLE IMPACT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You move in to strike your opponent by taking a regal series of attacks. Make four taijutsu attacks against a single creature within range. On a hit you deal 1d6 bludgeoning damage. If you successfully score a hit with at least 2 attacks against one creature, they cannot cast a Jutsu that requires Mobility (M) as an Action or Bonus Action, until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the number of attacks made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "a06370fb0fd2a499064f6ada", name: "OSTRICH WHIRLWIND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "As part of the activation of this jutsu, you can only use this taijutsu against a prone target who can be targeted by a Finisher. You perform a rather acrobatic display of skill. By kicking a prone creature, you propel yourself backward while performing a second sweeping kick while moving away. Make two melee taijutsu attacks, on a hit you deal your [Unarmed Damage] + 2d10. You then choose a space you can see within 20 Feet, leaping to that location, without triggering attacks of opportunity.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b7b9f7410fce2d62537cda6c", name: "PRAYING STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You make a powerful strike to the core of your opponent, sending shockwaves through their body that would break a lesser foe, and stun greater ones. Make a melee taijutsu attack. On a hit, you deal 1d4 bludgeoning damage and force the target to make a Constitution saving throw. On a failed save they are Stunned until the end of the current turn. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d4. If this jutsu is cast at B-Rank or higher, increase the damage dealt by your [Unarmed Damage]", created_at: NOW, updated_at: NOW },
  { _id: "74222eac5704f25384136202", name: "PRIDEFUL ASSAULT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Lion Fist Stance. You enter a prideful stance showing your overwhelming superiority and power. Make two melee taijutsu attacks. On a hit you deal your [Unarmed Damage] + 1d6. If your targets have ranks of Fear, increase this Jutsu's damage die by 1 step. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 1d10 and if you score two hits on the target, they must make a Wisdom saving throw, gaining +1 rank of fear on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6 or 1d10. If this jutsu is cast at A-Rank or higher, you can increase the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "64bbc64190a8b80869521ff2", name: "RABBIT FURY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Rabbit Fist Stance. You enter a blitzing stance, overwhelming your enemies with speed and agility. Move on a straight line up to your movement speed, ending in a space of your choice moving through hostile creatures’ spaces ending your movement in a space of your choice that can hold you. Make two taijutsu attacks comparing the result to all hostile creatures of your choices AC, whose space you pass through, dealing your [Unarmed Damage] + 1d4. If you hit a creature with two or more attacks, they must make a Dexterity saving throw. On a failed save they are knocked prone. If you move through a large, or larger creatures space, for each space of theirs you move through after the first you make one additional attack. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. 229", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "a29ac64de03476edfedf9f2e", name: "RISING DRAGON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 bonus action", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You move to strike a target from below, lifting them off of the ground. Make a Taijutsu attack, dealing your [Unarmed Damage] +1d8. The target is launched 30 Feet into the air until the end of your current turn, landing on their feet with no falling damage at the end of the current turn unless otherwise stated. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "98c4b2a5fcd42fc5694e69d7", name: "ROYAL GUARD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you take damage", range: "Self", chakra_cost: "Special", components: "CM, M", duration: "1 Round", description: "You quickly mold your chakra, creating multiple layers of armor from it and raising your guard to nullify an attack at the exact moment it would hit you. When you would take damage you nullify the impact by meeting it with an equal amount of chakra. Until the start of your next turn, each time you would take damage, you can spend chakra equal to the damage taken, gaining Immunity to the attack or jutsu’s damage and effects until the end of the current turn. If an effect does not deal damage or cost chakra, this jutsu does not prevent its effects. You can activate this Jutsu's effects a number of times equal to your Taijutsu ability modifier, per casting.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1899ca792da2d9ddb28b8372", name: "RUSHING LION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Concentration, up to 1 minute", description: "You focus chakra throughout your muscles enhancing your physical Strength and Dexterity. For the duration, your Strength and Dexterity ability scores becomes 16 if they are lower than 16. Your Jump height is doubled and you cannot make Strength of Dexterity checks at disadvantage. When you would cast a Taijutsu that affects an area and forces a saving throw increase the size of area by +5 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e115da68666ab6d3635d5101", name: "SECOND HEAVENLY BREATH: PANTING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "Special", description: "As a requirement to activate this jutsu, you must have First Heavenly Breath: Inhale currently active. You end your concentration on that jutsu and this one takes its place, maintaining the same duration limitation and Jutsu casting restrictions. You retain all of the effects and duration of that jutsu, stacking them with this jutsu’s effects. You increase your lungs capacity fourfold. Doing so increases your oxygen intake even further as your body expands and your muscles become more prominent. Increase your taijutsu attack bonus by +1, bonus taijutsu damage by 1d8 twice per turn, and you gain 10 temporary hit points.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "28ffd708c49a6397af1ad6b8", name: "SERPENT FANG DOUBLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Serpent Fist Stance. You enter a low striking stance showing your overwhelming focus and precision as you disable your opponent with surgical accuracy. Make two melee taijutsu attacks dealing your [Unarmed Damage] + 1d8. A creature who is hit by at least one of these attacks, must make a Constitution saving throw. On a failed save they gain +1 rank of Weakened. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 1d12 and if you score two hits on the target, they must make a Constitution saving throw, gaining +2 rank of Weakened on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d8 or 1d12. 230", created_at: NOW, updated_at: NOW },
  { _id: "835fa6d652d26024801112ff", name: "SILENT MOVEMENT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Concentration, Up to 1 minute", description: "As a requirement to activate this jutsu, you must currently be in the Silent Fist Stance. You enter a neutral stance, designed to exemplify silence and emptiness throwing most creatures off of being able to predict your actions. You do not spend chakra to maintain concentration on this jutsu. For the duration creatures cannot make reactions to one of the following. Pick one (This cannot be changed unless this jutsu is recast); • Your Movement. • Bonus Actions you make. • Reactions you take.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a940bbb81288f868af53ecdd", name: "SNAKE CONSTRICTING GRIP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Special", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Concentration, up to 1 minute.", description: "When you deal [Unarmed Damage] to a creature as a result of an Unarmed attack, you can cast this jutsu as part of that same attack. When you do, that target must make a Strength saving throw, being restrained on a failed save. As an action on the target creatures turn, they may attempt a Strength saving throw to escape your hold.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3678627b68169120fc8151cc", name: "STRAIGHT IMPACT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "Special", components: "M", duration: "Special", description: "You take a readied stance preparing your fist or foot for a single powerful strike. When you activate this jutsu, you can spend 5 chakra coating your fist in this chakra. You learn to be able to commit additional actions to make this attack stronger. You can spend your bonus action and an additional 5 Chakra to magnify this jutsu by 1 step. You can spend your reaction and an additional 5 chakra to magnify this jutsu by 1 step. You can inflict the stunned condition on yourself at the end of your turn until the beginning of your next turn to magnify this jutsu by 1 step. Make a single fiery taijutsu attack. On a hit, you deal your unarmed damage + 2d4 on a hit. For each step you magnify this jutsu by, increase the bonus damage by 2d4. If this jutsu is used as a Finisher, for each step you magnify this jutsu by, increase the bonus damage by 4d4.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the chakra spent activating this jutsu’s initial & additional effect by 3. If this jutsu is cast at B-Rank, increase the damage die of this jutsu by 1 step (D4>D6). If this jutsu is cast at S-Rank, increase the damage die of this jutsu by 1 step (D6>D8)", created_at: NOW, updated_at: NOW },
  { _id: "1e959eea3539bf323557b70f", name: "SWALLOW DANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Self (10-Foot Cone)", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "You perform a powerful wide sweeping roundhouse kick, lifting both yourself and all creatures you strike. All creatures in a 10-foot cone originating from you must make a Dexterity saving throw. On a failed save they take your unarmed damage + 1d8 and are launched 15 feet into the air until the end of the current turn, falling prone. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "b92ced1d4521ce83cdcb5101", name: "SWITCH KICK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You leap and perform a swift double kick in an attempt to support your team by queuing up a powerful finisher. As a part of casting this jutsu, you must have either a Bonus Action or reaction available to use. Make two taijutsu attacks against a creature within range dealing your [Unarmed Damage] on a hit. If you score at least a successful hit with this jutsu, you must spend either your bonus action or reaction. When you do, you grant your ally an additional reaction which they can only use to cast a Taijutsu with the Finisher Keyword that has a casting time of 1 action. Until the end of your turn, you or an allied creature can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action, Bonus action or reaction ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f184423835f8bb1d6b41fef7", name: "WILD DANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "3 Chakra", components: "M", duration: "Instant", description: "You first attack your opponent with a kick, which is immediately followed by a punch and another kick, striking them at 3 different angles. Make three melee taijutsu attacks. On a hit, each attack deals 1d8 bludgeoning damage and push them 5 feet in any direction of your choice. If the target cannot be pushed back because of a structure or construct such as a wall or tree, you strike them into it, dealing an additional +1d6 damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. If you cast this jutsu at B-Rank or higher, increase 231 the damage the target takes from striking a wall by 1d6. If this jutsu is cast at S-Rank, increase the damage the target takes from striking a wall by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "1ae9b206d914ea1b1a6cb7ff", name: "WISE TURTLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Concentration, up to 1 minute", description: "You focus chakra throughout your muscles enhancing your physical Strength and Cunning. For the duration, your Strength and Wisdom ability scores becomes 16 if they are lower than 16. Your lifting Strength is doubled and you gain a +2 to your passive perception. When you would cast a Taijutsu with a range greater than 5 feet, increase its damage by +1 damage die. C-RANK:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3e32728318b2cbdeef431b7a", name: "10-COUNT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "You dash forward to perform a series of rapid but light strikes designed to get your blood flowing. Make a number of Taijutsu Attacks equal to your Taijutsu Ability Modifier, dealing 1d4 bludgeoning damage, to a maximum of 10. If you successfully hit a creature with at least 3 of these taijutsu attacks, the next taijutsu you cast before the end of your turn gains a +3 bonus to attack and damage rolls. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If cast at B-Rank or higher, increase the damage by +1d4. If cast at A-Rank or higher, increase the damage by +1d4. If cast at S-Rank or higher, this jutsu’s cast time becomes a bonus action.", created_at: NOW, updated_at: NOW },
  { _id: "70d7e997a34f97fb2e5ee7c1", name: "ADAMANTINE ACALA", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "You perform a powerful kick to a targets center crushing their center of gravity and breaking their form. Make a melee taijutsu attack, dealing your [Unarmed Damage] + 2d8 and the target must make a Strength saving throw, being pushed back 30 feet on a failed save. If this jutsu is used as a Finisher, you make two kicks to the core, shattering their center of gravity and destroying their form. Make two melee taijutsu attacks, dealing your [Unarmed Damage] + 3d8 and the target must make a Strength saving throw, being pushed back 30 feet and falling prone and dazed on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "b078629f487226b76ff9dc30", name: "BEAST", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (15-foot Cone)", chakra_cost: "9 Chakra", components: "M", duration: "Instant", description: "You inscribe into your scroll the image of a bat to blind you enemies. Make a ranged ninjutsu attack against a medium or smaller sized creature. On hit the creature becomes blinded as the bat latches onto their face blocking vision. As an action on the creatures turn, they can attempt to pull the bat off by making a Strength saving throw ending the blinded condition on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and this number of attacks this jutsu can make by +1. However, each additional attack must target a different creature. 6 BEAST IMITATING ART: DEER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Instant Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You draw an image of a herd of deer that charge from your scroll towards your chosen target. Make a ranged ninjutsu attack. On a success, the target creature takes 2d8 in Bludgeoning damage and must make a Strength saving throw, being knocked prone on a failed save. If this jutsu is cast targeting a prone Creature, you do not roll disadvantage, instead rolling advantage and dealing an additional 2d6 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. BEAST IMITATING ART: LIZARD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You summon an inky lizard in a space you can see within range that can hold it. The lizard is a construct with the following statistics; • AC 12, 5d6 (20) Hit points. The lizard immediately after being summoned, screeches a menacing sound to those around it. All creatures who begin their turn within 10 feet of the lizard excluding you, must make a Wisdom saving throw. On a failed save they gain 1 rank of Fear. So long as a creature has ranks of fear gained as a result of this jutsu they cannot willingly approach the Lizard. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range of the lizards Screech by 5 feet. BEAST IMITATING ART: PIDGEON Classification: Ninjutsu Rank: D-Rank Casting Time: Up to 10 Minute Range: Self Duration: 24 Hours Components: HS, CM, CS, NT (Empty Scroll) Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You write in your scroll a message of any length that you can conceivably write within a 10 minute or less time span. Once complete, the writings manifest into the form of a bird of your description and now carry themselves. You can also cast this jutsu targeting a message already written of 25 words or less. The bird you create has 1 hp and an AC of 15. You then specify a location that you have previously visited and a recipient who matches a general description. You can also then give the bird a letter, scroll, tag, or similarly small object to deliver to this creature. The construct travels for the duration of the jutsu towards the location, covering no more than 50 miles per 24 hours. When the bird arrives, it turns back into the message when provided a scroll to be placed on and delivers any packages to the creature you described. The bird will only release the object to the creature you specified or if killed. The creature dissipates into non-staining ink when the message is delivered or it is killed. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and duration increases by 24 hours. When casting this jutsu at B-Rank or Higher, the bird becomes large in size and is capable of carrying two medium size creatures on its back. BEAST IMITATING ART: RATS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Minute Range: 1 Mile Radius Duration: 10 Minutes Components: HS, CM, CS, NT (Empty Scroll) Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu, Sensory Description: When you cast this jutsu you draw a horde of rats into your scroll. After 1 minute the picture is finished and the rats come to life scattering around. After a 10-minute delay, you can make a Ninshou check. Based on your level of success, you become aware of a variety of things within a 1-mile radius. • DC 10: You become aware of structures that are not hidden within range. This does not inform you of their specific location or size, only their general direction. • DC 15: You become aware of any non-hidden creatures within range. This does not inform you of their specific location or even the type of creature they are, only their general direction. • DC 20: You become aware of hidden structures within range. • DC 25: You become aware of the size of Structures and the types of creatures within range. • DC 30: You become aware of hidden creatures. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the range of this jutsu to 2 miles. If this jutsu is cast at S-Rank, increase the range of this jutsu to 3 miles. 7 BEAST IMITATING ART: RETRIEVAL HAWK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 120 feet Duration: Concentration, up to 1 minute Components: HS, CM, CS, NT (Empty Scroll) Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu, Construct Description: You hurriedly draw an image of a hawk to retrieve something for you. The hawk breaks out of your scroll and attempts to retrieve an object no more than 10 pounds and bring it to a destination of your choosing within range. The hawk has a fly speed of 45ft, AC of 15 and 1 hp. The hawk must stay within the range of this jutsu from the caster at all times and does not require the caster's actions to command aside from its initial creation. The destination of delivery can be changed as a bonus action on the casters turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the hawks speed by 10 feet, the weight it can carry by 10 pounds and this jutsu’s range by 30 feet. BEAST IMITATING ART: SNAKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM, CS, NT (Empty Scroll) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: When you cast this jutsu you draw an image of two snakes into your scroll infusing chakra into it making it come to life. You command the pair of snakes to wrap around your enemies. Target up to two creatures within range. Each creature must make a Strength saving throw. If any of the creatures are within 5 feet of each other they each make the save at disadvantage. On a failed save, they are restrained by the snakes as they wrap around them. A creature restrained by this jutsu, may as an action on their turn attempt another Strength save to end this condition. If affect creatures are within 5 feet of each other, when one creature succeeds all creatures within 5 feet of them, restrained conditions ends. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets by +1. BODY CAMOUFLAGE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 1 minute Components: HS Cost: 5 Chakra Keywords: Ninjutsu Description: You coat your body in chakra and begin to imitate the color and texture of the area around you blending in like a chameleon. For the duration, roll an additional +4 adding the result to your stealth checks. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and you can target one additional creature for each rank and they gain the benefits of this jutsu as well. BODY FLICKER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: 1 Round Components: HS, M Cost: 3 Chakra Keywords: Ninjutsu Description: You gain a mastery of movement, allowing you to cover much greater distance in a shorter amount of time. Until the end of your next turn, increase your speed by 30 feet. CALLING ON TEARS TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (30 Foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You manifest chakra around your tongue and throat as you use it to vibrate and magnify all sound escaping your mouth. You then release a stunning scream in an attempt to incapacitate all that hear it. All creatures in a 30-foot cone originating from you must make a Wisdom saving throw, being Deafened and Dazed until the end of their next turn on a failed save. Additionally, any traps such as explosives, trap doors or pressure plates that are within this jutsu’s range are triggered. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range by 5 feet. CATAPULT TECHNIQUE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 action Range: 90 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Ninjutsu Description: Choose one object weighing no more than 1 bulk within range, that isn’t being worn or carried. The object flies in a straight line up to 90 feet in a direction you choose before falling to the ground, stopping early if it impacts a solid surface. If the object would strike a creature that creature must make a Dexterity saving throw. On a failed save, the object strikes the target and stops moving. In either case, both the object and the creature or solid surface takes 3d8 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the maximum bulk of the objects that this jutsu can use increases by 1 bulk, and the maximum distance by 10ft. This jutsu’s damage also changes depending on the affected object’s bulk: 1 Bulk or less: 3d8. 2 Bulk: 4d8 3 Bulk: 5d8 4 Bulk: 6d8 5 Bulk: 7d8 8 CHAKRA BOLT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Ninjutsu, Clash Description: You manifest a 4-inch sphere of pure chakra at a creature you can see within range. Make a ranged ninjutsu attack. On a hit, the target takes 3d6 damage. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. Additionally, you gain one of the following benefits based on the Damage type of this jutsu. • Earth: The target must make a Strength saving throw being Bruised on a failed Save. • Wind: The target must make a Strength saving throw being pushed back 15 feet and being knocked prone on a failed save. • Fire: Each creature within a 5-foot radius sphere of the target creature must make a Dexterity saving throw, being burned on a failed save. • Cold: Each creature within a 5-foot radius sphere of the target creature must make a Constitution saving throw, being chilled on a failed save. • Lightning: The target must make a Constitution saving throw, being shocked until the end of their next turn. • Force: Changed damage die to d8. The target must make a Dexterity saving throw being Dazed. CHAKRA LEAPING Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus action Range: Self Duration: Instant Components: HS, M Cost: 3 Chakra Keywords: Ninjutsu Description: You focus chakra into your legs, increasing your jumping Strength astronomically. Until the end of this turn, Double your jumping height. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, the duration of this jutsu becomes 1 minute. If this jutsu is cast at S-Rank, the duration becomes 1 hour. CHAKRA MARK Classification: Ninjutsu Rank: D-Rank Casting Time: Special Range: Touch Duration: 10 Minute Components: CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu, Sensory Description: You create a chakra seal and attempt to place it on a creature, structure or construct you are able to touch. When you score a hit with a melee attack or a ranged attack, you are able to mark a creature. This does not work if another creature, construct or structure intercepts the attacks damage. While a creature, construct or structure is marked with this jutsu and is within 1 mile of you, you become aware of the existence of this seal, but not its immediate location. You gain a +4 bonus to all checks made to find or track the marked creature. Additionally, if you can teleport you can choose to teleport to a marked creature, construct or structure so long as they are within 1 mile of you. Once you teleport in this way, the mark vanishes, ending this jutsu. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. At C- Rank This jutsu’s Duration becomes 1 Hour. 8 Hours at B- Rank, 24 Hours at A-Rank, Permanent at S-Rank. CHAKRA SHIELD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you take damage. Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Clash Description: You manifest a swirling barrier of chakra around you protecting you from the triggering attack. You gain 12 Temporary Hit points. If you have a nature release, this jutsu gains a single nature release keyword that you can cast, and additional effects base on the Nature release. Your shield gains one of the following benefits based on the chosen nature release. If you do not have a nature release this shield instead has 16 temporary hit points. • Earth: This jutsu gains the Construct keyword. Your shield has resistance to Cold damage, vulnerability to lightning Damage and once cast leaves behind an Quake Shard in a 5ft cube within 5ft of you. • Wind: Your shield has resistance to Lightning Damage, vulnerability to Fire Damage and once cast all creatures of your choice within 5 feet of you gains 1 rank of bleed. • Fire: Your shield has resistance to Wind Damage, Vulnerability to Cold Damage and all creatures within 10 feet of you takes fire damage equal to your Ninjutsu ability modifier. • Water: Your shield has resistance to fire damage, vulnerability to earth damage and if this jutsu is cast near a sufficient source of water, reduce the cost of this jutsu by -2. • Lightning: Your shield has resistance to Earth damage, vulnerability to wind damage and you gain a +2 to Dexterity saving throws until the beginning of your next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points you gain by +6. 9 CHAKRA SKIN Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Until Short Rest Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu Description: You coat yourself in a Protective aura of chakra, protecting you from damage. When you cast this jutsu, you lose the benefits of any Armor you are wearing, utilizing this Jutsu’s AC calculation for its duration. Your AC becomes 13 + your Intelligence Modifier + Half of your proficiency Bonus. This jutsu ends if you dismiss it as a Bonus action. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank or higher, you gain Temporary hit points equal to your Ninjutsu ability modifier. As a Bonus action on your turn, you can replenish these Temporary hit points for 5 Chakra. If this jutsu is cast at B-Rank or higher, increase the AC this Jutsu grants by +1. If this jutsu is cast at A-Rank or higher, the Temporary hit points gained, is instead equal to half of the casters Ninjutsu ability score. If this jutsu is cast at S-Rank or higher, increase the AC this Jutsu grants by +2, instead of +1. DARKVISION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Sensory Description: You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has Darkvision out to a range of 60 feet. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can affect with this jutsu by +1. ENHANCED REACTIONS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 8 Hours Components: HS Cost: 3 Chakra Keywords: Ninjutsu, Sensory Description: You store chakra in pockets behind your eyes and joints in preparation to move with a burst of speed at any moment. The first time you would roll initiative for the duration, you may add 1d4+1 to your roll. This jutsu then ends. HOLLOW STARS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 120 feet Duration: Instant Components: HS, CM, CS Cost: 5 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You force your palms together before pointing them towards the sky, shooting our four bursts of chakra that take the shape of small stars before falling to the ground in four different spaces of your choice within range, dealing damage to objects, creatures and structures occupying the space. Objects, creatures and structures in the selected spaces each take 1d4+1 damage. A creature, object or structure in the area of more than one star, takes the damage of each of these stars. If you have a nature release, this jutsu gains a single nature release keyword that you can cast and it’s damage type becomes the corresponding nature releases damage type (Water = Cold). If you do not have a nature release this jutsu instead deals Force Damage. A creature can only ever be affected by the following effects twice per casting. • Earth: You create a 10-foot cube of difficult terrain, centering on each space selected. This space remains difficult terrain until cleared. • Wind: Each creature within 5 feet of the selected space makes a Strength saving throw. On a failed save they are thrown back 5 feet from the target space and falling prone. • Fire: Each creature within 5 feet of the selected space makes a Dexterity saving throw. On a failed save they takes damage equal to the damage dealt to the target space. • Cold: Each creature within a 10-foot radius sphere of the target space must make a Constitution saving throw, being chilled on a failed save. • Lightning: If two or more selected spaces are within 15 feet of each other, lightning arcs between them in a straight line so long as there are no obstructions. Creatures in the Arcs path must make a Constitution saving throw, being shocked on a failed save • Force: Damage die increases to a d8. Also, creatures occupying select spaces are bruised. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of stars made by +1. 10 INK CLONE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet Duration: 1 Minute Components: HS, CM, CS, NT (Vial of Ink) Cost: 4 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You infuse chakra into the ink as you then infuse a chakra seal into it. You conjure a clone of yourself made of ink. They look, sound and act as your describe. The cost of these clones cannot be reduced below half. An Ink clone has 1 Hit point and can be no farther than 90 feet from you. It can walk, talk and interact with things but it cannot declare an attack. This clone acts at the end of your turn. As a bonus action you can command the clone to attack. When you do it pretends to weave hand seals to cast a jutsu targeting a single creature within 60 feet of it. The target creature makes a Wisdom (Insight) Check vs your Ninjutsu Save DC. On a failure, they become distracted by the clones antics. A creature distracted in this manner grants the next attack targeting it advantage and they are treated as surprised against this attack. LOCK/RELEASE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Until dispelled Components: HS, CS Cost: 3 Chakra Keywords: Ninjutsu, Fuinjutsu Description: You place a chakra seal on a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and creatures you designate when the jutsu is used can open the object normally. You can also set a password that when spoken within 5 feet of the object releases the jutsu for 1 minute. This jutsu also works inversely allowing you to attempt to lock pick using your chakra alone. Make an Intelligence (Chakra Control) check vs the Locks DC as if you are picking a lock using a Security kit. Creatures attempting to open the object you have locked with this jutsu must make an Athletics check vs your Ninjutsu save DC to force open the object. MEDICAL RELEASE: ACID ARMOR Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 10 Minutes Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of a highly dangerous aura of chakra that intercepts attacks for you and harms those who would try to touch you. You gain 14 temporary hit points. Creatures who would deal damage with a melee attack take 6 acid damage each time they would deal damage, while you have temporary hit points granted by this jutsu. A creature who would strike you with a weapon attack or unarmed strike whose rank is equal to or less than the rank this jutsu was cast at has their weapon suffer a permanent -1 penalty until fixed by the Mending ninjutsu. An unarmed attack such as your fists or legs can be fixed with any jutsu with the medical keyword that restores hit points or removes conditions. A weapon or limb which has reached a -5 penalty breaks, being destroyed by all of the acid covering it. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points by 7 and the acid damage by 3. MEDICAL RELEASE: ACID BEAM Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (60-Foot line) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of a powerful beam meant to melt through everything in its path. All creatures in a 60-foot long, 5-foot-wide line originating from you must make a Dexterity saving throw. On a failed save, you deal 3d6 acid damage and at the beginning of an affected creature’s next turn, they take 3d4 acid damage. Constructs and structures made of earth, metal or wood take double damage as the acid eats through them. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and 1d4. 11 MEDICAL RELEASE: ACID STRING Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (20-foot cube) Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of barbed wires, enough to fill a 20-foot cube originating from you. For the duration, creatures, excluding you, who would begin their turn or enter for the first time on their turn, the affected area, they take 7 acid damage and an additional 7 acid damage for every 5 feet they would move through the affected area. A creature cannot take damage from the same 5 by 5-foot square more than once per round. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the affected area by 5 feet. MEDICAL RELEASE: ACID TAIL Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15-foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of a beast’s tail, be it a massive dragon tail, or large lions tail. Make one melee ninjutsu attack. Compare the result of your attack against all creatures in a 15-foot cone, originating from you. For each success, you deal 2d6 + 1d6 acid damage, for each additional creature hit after the first. Additionally, all creatures you deal damage to must make a Strength Saving throw. On a failed save, creatures are knocked prone and gain 1 rank of corroded. MEDICAL RELEASE: ACID WHIPS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You manifest acidic chakra in the form of two whips of acid designed to grapple and melt into your foes. Make two ranged ninjutsu attack, dealing 2d6 acid damage on a hit. Additionally, creature you hit must make a Strength saving throw. On a failed save, they become grappled by you and your acid whips for the duration. A creature grappled by your acid whips takes 1d6 acid damage at the beginning of each of their turns. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of attacks you make by +1. MEDICAL RELEASE: ACIDIC CLEANSE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (15 feet) Duration: Special Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You learn to bend acidic substances to your will, molding and manipulating them like puppets on a string. All creatures within 15 feet of you who are under the effects of the corroded condition has their condition ended, as you collect all of the left-over acid into a ball above your head. The ball floats for up to 1 minute or until used. The next time you would cast a jutsu that would deal acid damage you can spend the ball of acid, upcasting the jutsu by 1 rank at no cost, ignoring upcasting limitations. MEDICAL RELEASE: BROKEN BODY Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: You begin to generate a surge of twisted medical release chakra designed to shatter the bones and splinter the muscles of your target. A creature you can reach must make a Strength saving throw. On a failed save their bones twist and their muscles spasm as they take 4d8 necrotic damage and they cannot use their arms to hold a weapon until the end of their next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8. MEDICAL RELEASE: CORRUPT MISSILE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM, CS Cost: 4 Chakra Keywords: Ninjutsu, Medical, Fuinjutsu Description: You begin to generate a mass of twisted medical release chakra designed to be fired like a missile, bolt or beam. Make a ranged ninjutsu attack targeting one creature you can see in range. On a hit you deal 2d8 + your ninjutsu ability modifier necrotic damage. Additionally, the next time the affected creature would regain chakra within the next minute, they regain half of the listed amount At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8. 12 MEDICAL RELEASE: CORRUPTION Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, up to 1 minute. Components: HS, CM, CS Cost: 4 Chakra Keywords: Ninjutsu, Medical, Fuinjutsu Description: You begin to generate a surge of twisted medical release chakra designed spread like a curse, draining all creatures in range. Select a space you can see within range. You manifest a 5- foot radius field of corruption. At the beginning of each of your turns for the duration, the size of the field grows by 5 feet. All creature who begins their turns within the affected area or first enter the affected area on their turns, must make a Charisma saving throw. On a failed save creatures take 3d12 necrotic damage and no damage on a successful save. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d12. MEDICAL RELEASE: DETECT POISON AND DISEASE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: 10 minute Components: HS, CM Cost: 5 Chakra Keywords: Ninjutsu, Medical, Sensory Description: For the duration, you can sense the presence and location of poisons, poisonous creatures and diseases within 30 feet of you. This jutsu can penetrate most barriers, but is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt. MEDICAL RELEASE: ENSNARING STRIKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: 1 Round Components: CM, M Cost: 4 Chakra Keywords: Ninjutsu, Medical Description: The next time you hit a creature with a melee or ranged weapon or unarmed attack before this jutsu ends, you inject chakra into your enemy’s muscles attempting to restrict their movements. The target must make a Strength saving throw or be restrained until the end of their next turn. A large or larger creature has advantage on the saving throw. While restrained by this jutsu, the target takes 1d8 poison damage at the start of each of its turns. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8 MEDICAL RELEASE: GOODBERRY Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, M Cost: 5 Chakra Keywords: Ninjutsu, Medical Description: With fine chakra control, you can touch up to 5 fruits or nuts that are then infused with medical release chakra for the duration. A creature can use its action to eat any of the 5 affected food items. Eating a food infused with this jutsu restores 1 hit point and provides enough nourishment to sustain a creature for one day. A creature cannot benefit from this jutsu more than twice per long rest. The infused food loses its potency if they have not been consumed within 24 hours of casting this jutsu. MEDICAL RELEASE: GRIM MASK Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM, CS Cost: 5 Chakra, 1 Hit Die Keywords: Ninjutsu, Medical, Fuinjutsu, Kinjutsu Description: You weave summoning seals together and infuse them with medical release chakra manifesting the mask of the Reaper of death. The mask siphons a small fraction of your life force to don it, but it grants you a great deal of power in return. You cannot lose concentration of this jutsu as a result of damage. Attacks you make deal an additional 1d4 necrotic damage for the duration. If an attack you make or jutsu you cast would deal necrotic damage as a part of its casting or through its lingering effects, the additional damage instead becomes a 1d8. Additionally, an attack you make that scores a critical hit or one where you roll the maximum damage possible on the die, if your target is classified as a player character, it loses 1 hit die. If your target is classified as an Adversary, it loses 1 Tenacity die. 13 MEDICAL RELEASE: GRIM SIPHON Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM, CS Cost: 5 Chakra, 1 Hit Die Keywords: Ninjutsu, Medical, Fuinjutsu, Kinjutsu Description: You weave summoning seals together and infuse them with medical release chakra manifesting the hand of the Reaper of death. The hand siphons a small fraction of your life force to summon it, but it grants you a great deal of power in return. Select one creature you can see within range, that creature must make a Charisma saving throw, taking 2d8 + your ninjutsu ability modifier necrotic damage, and depending on the targets classification different effects would be applied to them. If the target is classified as a player character, they lose 1 hit die on a failed save or half as much damage and no hit die loss on a success. Another creature of your choice that it within 20 feet of your target regains hit points equal to the damage dealt. If the target is classified as an Adversary, they lose 1 Tenacity die, and you gain it for 1 minute, able to use it as a bonus to one ability check, skill check or saving throw. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. MEDICAL RELEASE: GRIM WEAPON Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Touch Duration: Concentration, up to 1 minute Components: HS, CM, W (Any) Cost: 4 Chakra Keywords: Ninjutsu, Medical, Fuinjutsu, Kinjutsu Description: You weave summoning seals together, infusing them into your weapon and medical release chakra that manifests as an echo of reaping b", created_at: NOW, updated_at: NOW },
  { _id: "4700cbc6457dcb137b4f7d27", name: "BREAK SPIRAL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (5-foot radius)", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "You leap onto your back on the ground as your perform a series of spinning kicks resembling a spinning top, striking all creatures around you. This jutsu can only be cast as a Finisher. All creatures within 5 feet of you must make a Dexterity saving throw. On a failed save they take are buffeted by a series of spinning kicks taking your [Unarmed Damage] + 6d6 and are knocked prone. A creature who failed their saving throw by 5 or more are Dazed and must spend their Action to stand from being prone.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the radius of this jutsu by 5 feet. 232", created_at: NOW, updated_at: NOW },
  { _id: "63d057d33b96e22c2489664b", name: "BURNING FIRE: DRUM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when a creature within 5 feet of you deals damage with a melee attack against yourself or an allied creature.", range: "5 Feet", chakra_cost: "9 Chakra", components: "M", duration: "1 Minute", description: "You reach your hand out and attempt to beat the left lung of a hostile creature. Make a melee taijutsu attack against the triggering creature. On a hit, their lung swells. For the next minute, when the affected creature casts a Jutsu with the Mobility (M) component, they take 2d6 necrotic damage, which ignores Resistance, Immunity, Damage Reduction and Temporary Hit Points, as their lung swells more. A creature who would trigger this Jutsu's damaging effect 5 or more times while under its effects has their lung rupture, dealing 10d6 necrotic damage, which ignores Resistance, Immunity, Damage Reduction and Temporary Hit Points and gain 4 ranks of Exhaustion for the next 24 hours, this jutsu then immediately ends. A creature can spend their action to make a Constitution Saving throw to end this jutsu’s effects on them. Alternatively, a creature can end this effect with any Jutsu with the Medical Keyword, that removes conditions of C-Rank or lower.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the number of creatures you can target by +1. If cast at A- Rank or higher, when a creature lung ruptures, they instead take 15d6 Necrotic Damage. If cast at S-Rank, creatures make their saving throw to end this jutsu’s effects, at disadvantage.", created_at: NOW, updated_at: NOW },
  { _id: "5e8add6ded24e65e3e5795b5", name: "COLLIER SHOOT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "You leap off the ground no more than 5 feet and perform a powerful roundhouse kick targeting a creatures neck as you attempt to drag them into the ground. Make a melee taijutsu attack. On a hit, you deal your [Unarmed Damage] + 2d8 and the target must make a Strength saving throw. On a failed save, the target is knocked prone and is embedded into the ground as you kick them no more than 2 feet into the ground. A creature embedded into the ground is counted as Restrained by the ground itself and must make a Strength (Athletics) check vs your Taijutsu save DC to pull themselves from the ground. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d8. .", created_at: NOW, updated_at: NOW },
  { _id: "e35446e1e356aa8524311b98", name: "COMBAT CLONE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "9 Chakra", components: "M", duration: "Concentration, Up to 1 minute.", description: "You take notice of another creatures fighting style, and begin to adjust your muscle memory to copy a creatures movements almost identically. This jutsu’s cost cannot be reduced by any means. Make a Martial Arts check targeting a creature you can see within range, using your Taijutsu ability modifier vs a DC (10 + Targets Level). On a success, you imitate their physical movements granting you the following benefits; • Your unarmed damage die becomes equal to the creatures unarmed or natural weapon damage die. • If the target has the Multiattack trait, you can make a number of unarmed attacks equal to the number of attacks they can make using their multiattack feature, with your Attack Action. • If the target is gaining the benefits of a Taijutsu Stance, you gain that stances benefits as if you knew it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a6c0a4448c36a5d301f28faf", name: "DRAGON TAIL FOOT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Self (5 Feet)", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "You perform sweeping kick, before performing a downward vertical kick to slam a target creature into the ground. Creatures within 5 feet of you must make a Dexterity saving throw, being knocked prone. If a target is knocked prone by the effect of this jutsu, select one target and make a single melee taijutsu attack dealing your [Unarmed Damage] + 3d6. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "8d0df4b9adad990ac242411e", name: "EARLY SACRIFICE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when a melee attack misses you.", range: "5 Feet", chakra_cost: "6 Chakra", components: "M", duration: "Instant", description: "After dodging an enemy’s melee attack, you leap on their shoulder and attempt to throw them 30 feet in a direction of your choice. The target must make a Strength saving throw, being thrown 30 feet in a straight line, in a direction of your choice. A thrown target must make a Dexterity saving throw, landing prone on a failed save. 233 If the target hits a surface such as a wall, ceiling, or large or larger object they take damage as if they were falling.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0a3220d99c2ea3081e3d55d2", name: "ELEMENTANIA", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant.", description: "As a part of casting this jutsu, you can only target a creature whom you can target with a Finisher as a result of a Jutsu cast with the Combo keyword. You bob and weave in and out of a creatures combat range, building up momentum, preparing yourself for a massive strike that takes the shape and visage of a roaring elemental storm. Make a melee taijutsu attack, dealing your [Unarmed Damage] + 4d12. Your attack gains the following benefits based on the elemental affinity you wished to imitate (Pick one when you cast this jutsu) • Earth: The ground and earth around you shakes and upheaves. All creatures within 10 feet of the original target must make a Dexterity saving throw, taking 3d6 bludgeoning damage from the erupting earth. • Wind: The wind whips and whistles as you forcefully move it out of your way. The target must make a Strength saving throw, being thrown back 15 x your Taijutsu ability modifier, feet on a failed save. If the target would hit a solid surface as a result of this knock back. They take 2d6 bludgeoning damage for every 15 feet that they were unable to be moved. • Fire: Your attack creates such wind resistance that your striking limb ignites into flame on impact. Your attack instead deals Fire damage and the target must make a Constitution saving throw, gaining 1 rank of the burned condition on a failed save. • Water: Your attack becomes graceful, like flowing water, allowing you to strike far more effectively. Reroll all 1’s and 2’s, taking the second result. • Lightning: Your attack is swift, decisive and powerful, like lightning. When your attack hits the target, creatures up to 300 feet away can hear an audible boom erupt from the point of impact. All creatures, excluding you, within 30 of the target creature must make a Constitution saving throw, being Dazed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4f3efb5607cdf4f5facdafc2", name: "ERUPTING FALLING STOMP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "15 Feet", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "You pump chakra into your legs as you stomp, creating a shockwave of force from your Strength alone. Creatures in a 15-foot cube originating from you must make a Strength saving throw, taking 3d8 bludgeoning damage and gaining 1 rank of bruised on a failed save or half as much on a success. If this jutsu is used as a Finisher, your stomp upheaves the ground creating cracked surfaces and jutting terrain. The affected area becomes difficult terrain and all creatures who fail their saving throw instead take 5d8 bludgeoning damage and +1 rank of bruised on a failed save or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and the size of the cube by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "c0e58b681d7216035709e02e", name: "EVENING HEAVENLY CRUSH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 reaction which you take when a target is forcefully moved more than 5 feet from you.", range: "Self", chakra_cost: "6 Chakra", components: "M", duration: "Instant", description: "You dash to keep up with a thrown or knocked back creature who is moved further than 5 feet away from you. You take the dash action as a reaction and must end your movement within 5 feet of the target creature. As a part of the same reaction, you also make an unarmed attack as if you are making an attack of opportunity against the target.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1da0e05d907b16531523d6c9", name: "FALCON DROP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "6 Chakra", components: "M", duration: "Instant", description: "This jutsu can only be used as a Taijutsu Finisher. As part of the activation of this jutsu, the target creature must be airborne or falling. Make a melee Taijutsu attack against falling creature. On a hit, you pile drive them into the ground dealing 5d12 Bludgeoning damage, leaving them prone, weakened and bruised.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d12", created_at: NOW, updated_at: NOW },
  { _id: "6c80120915341903ea87d93a", name: "FIERCE SNAKE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus action", range: "5 Feet", chakra_cost: "6 Chakra", components: "M", duration: "Instant", description: "You rapidly strike a target with blinding speed, striking fast enough to leave after ima ges of your attacks. The next time you take the Attack action before the end of the current turn, you make +1 additional attack.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank or higher, increase the number of additional attacks you make to +2. 234", created_at: NOW, updated_at: NOW },
  { _id: "d423d0641fde43921ca50de0", name: "FIST SLAM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "6 Chakra", components: "M", duration: "Instant", description: "As a part of the activation of this taijutsu, you must target a prone creature. Make a melee taijutsu attack against the prone target dealing 6d6 bludgeoning damage and creating a 15-foot-deep hole in the ground while leaving them dazed. If this jutsu is used as a Finisher, your strike drives home your Strength and ferocity. On a hit, you deal 9d6 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6", created_at: NOW, updated_at: NOW },
  { _id: "539fd80746c4ac0839873531", name: "FLOWING WATER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "9 Chakra", components: "M", duration: "Concentration, up to 1 minute", description: "You loosen your stance, allowing your body to become more fluid and adaptable to both incoming and outgoing attacks. Select two Taijutsu or Weapon stances that you know. You gain both of their benefits for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f5a02dfda2b628c7b23cbbd4", name: "FLOWING WATER: NO BEAT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant.", description: "You move with the grace and ruthlessness of a raging tide, slipping past an enemies weak points and washing them away as smoothly as running water. Make two melee taijutsu attacks against a single creature. On a hit your attacks do not deal damage, instead, at the conclusion of your attacks, the target must make a Constitution saving throw. For every attack that successfully hit after the first, the target suffers a -1 penalty to their saving throw. On a failed save, the target suffers 2 ranks of Exhaustion until the end of their next turn. If this jutsu is used as a Finisher, for every attack that successfully hit after the first, the target suffers a -2 penalty to their saving throw.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the number of attacks you make by +1.", created_at: NOW, updated_at: NOW },
  { _id: "ce7fad439a9f9f275b3bad10", name: "FOURTH HEAVENLY BREATH: WHEEZE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "CM", duration: "Special", description: "As a requirement to activate this jutsu, you must have Third Heavenly Breath: Breathe currently active. You end your concentration on that jutsu and this one takes its place, maintaining the same duration limitation and Jutsu casting restrictions. You retain all of the effects and duration of that jutsu, stacking them with this jutsu’s effects. You increase your lungs capacity Sixteen-fold. Doing so increases your blood flow and you begin to glow with a yellow aura and your muscles and organs become far more resistant to damage. Increase your taijutsu attack bonus by +2, taijutsu damage by 1d8 twice per turn, and you gain +15 temporary hit points that stack with other temporary hit points gained as a result of this jutsu. At the end of this jutsu’s duration you gain 1 rank of the weakened condition until your next rest which cannot be removed by Jutsu of B-Rank or lower.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a8885b910512620f524dbbbd", name: "FRICTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "9 Chakra", components: "M", duration: "Instant.", description: "You coat a creature whom you touch body in a layer of spinning air. The air removes most friction from its body allowing them to move at breathtaking speeds, with little resistance. They gain +1 bonus to their AC, a +20 bonus to speed, advantage on Dexterity saving throws and they gain the Friction Break special action at the start of each of their turns for the duration. Friction Break. This special action can be used to either make one additional Weapon Attack, Disengage, or use an object action. WIND RELEASE: WIND RIDER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Bonus Action Range: Touch Duration: 1 Minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: You touch a willing creature you can see within range coating them in Wind Release Chakra. For the duration, the target creature gains a 30ft flying speed, but at the end of their turn they must be within 5 feet of the ground. The creature cannot suffer falling damage as they are always carried by the wind to a safe landing. Additionally, the creature is always floating at least 5 feet off the ground for the duration.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. Starting at A-rank, an affected creature no longer needs to end its turn within 5ft of the ground. B-RANK: WIND RELEASE: 10,000 SLICING BLADES Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Self (30-Foot radius Sphere) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: You create a dome of spinning wind, centering on you. The wind spins, whips and blows at 120 mph generating an innumerable number of blades made of wind chakra. These blades fly freely throughout your dome. Anything not weighted down is picked up and thrown around the dome and sliced to pieces. Creatures, excluding you, in this dome of wind when it is cast, who first enters or begins their turns within the dome, must make a Strength saving throw taking 5d10 Wind damage and are thrown 20ft in a random direction, fall prone, and cause Swirl on a failed save or half as much on a successful one. The area within the dome is counted as difficult terrain even for flying creatures. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 WIND RELEASE: BACKLASH Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Reaction, when you would suffer the effects of or take damage from a Ninjutsu Range: Self Duration: Instant Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vortex that spins counterclockwise just before an attack hits you. Make a Ninjutsu Ability Check vs the Rank DC of the triggering jutsu. The Rank DC equals 13 + the Jutsu’s Rank (D-Ran k: 1, C-Rank: 2, B-Rank: 3, A-Rank: 4, S-Rank: 5). If you roll Higher, the triggering jutsu’s effect is nullified and the caster of the jutsu takes the damage and effects of their own Jutsu. On a failure, you take the damage as they break through your jutsu. 76 WIND RELEASE: CHERISHING BREEZES Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, CM Cost: 12 Chakra Keywords: Wind Release, Ninjutsu, Medical Description: You inhale once, filling your lungs with Air that you mix medical release chakra. You then attempt to pass this air from your lungs into the lungs of another who have either died within the last minute or are dying. This can be done in a number of ways such as CPR, a kiss, simply manipulating the air to exit your lungs and enter the downed creatures. When you do, the dead or dying creature makes a Constitution Saving throw adding 2d4 to their roll vs a DC 15 + 1 for each round they have been dead. On a Success, they immediately end the dead or dying condition regaining consciousness with 1 Hit Point and a number of Temporary Hit points equal to three times your Ninjutsu Save DC. These Temporary hit points last for 10 minutes. WIND RELEASE: DIVINE MOUNTAIN WIND Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 13 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vortex where you can control the Strength for the wind. Make a ranged ninjutsu attack targeting a creature you can see within range. On a hit target creature takes 8d6 wind damage and gains 2 ranks of bleed, as the wind slices into them with enough force to upheave the ground upon impact. If there are any sources of fire in the line of fire between you and your target this jutsu ignites into a stream of fire. Increase the damage by 5d4 fire damage. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 WIND RELEASE: GALE BLADE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: 90 Feet Duration: Instant Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: You create a super thin blade of cutting wind that slices through everything in a continuous line. Select a space you can see within range. Then select a second space you can see within 60 feet of the originally selected space. Draw a straight line in between both spaces. All creatures who the line passes through or by within 5 feet must make a Dexterity saving throw, taking 6d8 wind damage, gaining 3 ranks of bleeding and causing Swirl on a failed save or half as much and no additional effects on a successful one. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. WIND RELEASE: GREAT SICKLE WEASEL Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Self (45-foot cone) Duration: 1 Action Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: A blast of slicing wind erupts from your hands. Each creature in range, originating from you, makes a Strength saving throw. On a failed save, a creature takes 7d6 wind damage and are thrown back 25 feet, fall prone, gains 1 rank of lacerated, cause Swirl and cannot take reactions until the end of their next turn as they are unable to avoid being caught in the shockwave of slicing and concussive wind. This jutsu also deals twice as much damage to objects and structure. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the ranks of lacerated by +1. WIND RELEASE: GRYPHONS TALONS Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 14 Chakra Keywords: Wind Release, Ninjutsu, Fuinjutsu, Clash Description: You place a sealing talisman on your hands as you focus your Wind Release chakra onto them activating them. Chakra forms into the shape of 2 Claws, Talons, or weapons of your description on either hand. For the duration you do not spend chakra to maintain concentration on this jutsu. For the duration you can as an action make up to two Melee Ninjutsu Attacks with these wind claws you created. Your Melee Ninjutsu attacks made with these wind claws have a range of 10 feet, and deal 3d8 + Your ninjutsu ability modifier wind damage on a successful hit. 77 WIND RELEASE: GUST SURGE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Reaction, which you take when a creature within 45 feet of you make an Attack, Casts a Jutsu or moves towards you. Range: Self (45- foot radius sphere) Duration: Instant Components: HS, CM, CS Cost: 14 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You punch the ground creating a single point of intense air pressure that explodes outwards blowing away all creatures and potentially all attacks. All creatures within range of your choice must make a Strength saving throw. On a failed save they are thrown back to the edge of this jutsu’s radius into a space that can hold them. Creatures who fail their Strength saving throw gains 3 ranks of bruised on a failed save. If this jutsu is used in reaction to a Ninjutsu or Taijutsu being cast, the shockwave of air pressure reduces the damage the jutsu would deal by 5d6 + 15. If the jutsu used does not deal damage the triggering creature must make a Constitution ability check vs your Ninjutsu save DC. On a success their jutsu is cast as normal. On a failure, their jutsu is also blown away as this jutsu negates it. If this jutsu is used to trigger a clash with a Jutsu with the Fire Release Keyword, you make your clash check at advantage as you are pushing all the wind away from you. If you succeed your clash check against a jutsu with the fire release keyword, they take an additional 4d8 wind Damage and must make a Constitution saving throw being burned on a failed save. WIND RELEASE: MULTILAYERED GALE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute. Components: HS, CM, M Cost: 12 Chakra Keywords: Wind Release, Ninjutsu, Construct Description: You wave your hands back and forth creating layers of wind that stack on top of one another creating a barrier of wind. Your Wall of wind is extremely dense not allowing most things to pass through it. When you create your barrier of wind it has 30 Hit points. It occupies your space with you and protects you in all direction, ranged attacks targeting you are made at disadvantage. At the start of each of your turns you can enhance this barrier regenerating 3d6 of the barriers hit points. This Barrier has a vulnerability to Fire damage, and Resistance to Lightning damage. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the initial hit points of the barrier by 10. WIND RELEASE: THUMB OF DESTRUCTION Classification: Ninjutsu Rank: B-Rank Casting Time: Full Turn Action Range: 120 Feet Duration: Instant Components: HS, CM, CS Cost: Special (77 Chakra) Keywords: Wind Release, Ninjutsu, Combination, Kinjutsu Description: You generate a super massive tornado that touches down on a space you can see within range. This Tornado is 120 feet tall and 30 feet wide. You can command it to touch down on top of a creature or space you can see within range. If you have it touch down on top of a creature, make a Ranged Ninjutsu attack, dealing 10d8 wind damage on a hit. All creatures, objects and structures, excluding casters of this jutsu, within 60 feet of the tornado must make a Strength saving throw being sucked into the eye of this storm. On a failed save they are thrown to the top of this tornado for but a moment before the tornado compresses and fires all creatures within the eye of its storm directly into the ground at sound breaking speeds. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the targeted damage by 2d8 for each additional caster. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size and damage based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the height of the tornado by 60 feet, +3: Increase the height of the tornado by 80 feet, +4: Increase the height of the tornado by 100 feet, +5: Increase the height of the tornado by 120 feet). WIND RELEASE: VACUUM BLADE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Bonus Action Range: Touch Duration: Concentration, up to 1 minute. Components: HS, CM, W (Any) Cost: 12 Chakra Keywords: Wind Release, Ninjutsu Description: You exhale wind release chakra onto a weapon to increase its sharpness, range and lethality. This can even be used on your unarmed strikes creating lethal blades of wind extending from those strikes. You cannot lose concentration of this jutsu as a result of damage. Enhanced weapon or unarmed strike’s deals an additional 3d6 wind damage twice per turn, its range is also increased by 10 feet. Ranged weapons also damage all adjacent spaces around its target on a successful hit. Additionally, you can use your Ninjutsu ability modifier in place of Strength or Dexterity when calculating to hit or damage with attacks enhanced by this jutsu. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If cast at S-Rank, increase the damage of this jutsu by +1d6. 78 WIND RELEASE: VACUUM GREAT SPHERE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: 120 Feet (15-foot radius Sphere) Duration: Concentration, 1 minute Components: HS, CM Cost: 13 Chakra Keywords: Wind Release, Ninjutsu Description: You generate 3 large Spheres of wind chakra. Choose 3 spaces in range. You send the large wind spheres to these areas and they expand outwards with the point you’ve chosen at the center, 30 feet in diameter. Creatures caught in these spheres or who enter them, movement speed is reduced to 0 and they cannot breathe while inside the sphere as the pressure prevents them from inhaling successfully. Creatures caught in the radius of any sphere can make a Strength saving throw or continue to have their movement speed reduced to 0. On a successful save, they regain half of their movement speed. A creature who begins or ends its turn within the radius of a sphere must make a Constitution saving throw. On a failure, they begin to suffocate, gaining 2 rank of exhaustion. On a success, they recover 2 rank of exhaustion caused by this jutsu, if any. Upon escaping or ending this jutsu’s effect on them, they recover from all ranks of exhaustion this jutsu imposed on them. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and select one additional space this jutsu affects. WIND RELEASE: WIND CUTTER Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: 120 Feet Duration: Instant Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: You create one Super sharp blade of wind and launch it at a target creature in range. Make a ranged ninjutsu attack. On a hit the target creature takes 5d10 Wind damage and gains 1 rank of lacerated. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 WIND RELEASE: WYVERNS SURGE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 14 Chakra Keywords: Wind Release, Ninjutsu, Fuinjutsu Description: You place a sealing tag on your body in any place you desire, as you place a massive reserve of Wind Release Chakra into the tag itself, activating it and magnifying your physical potential. You do not need to spend chakra to maintain concentration on this jutsu. For the duration, once per turn, when you would deal damage with a jutsu against a creature with a jutsu with a nature release keyword, they must make a Strength saving throw. On a failed save the following occurs; • Earth Release: Affected creature gains 1 rank of the bruised condition. • Wind Release: The jutsu deals an additional 3d8 wind damage and inflicts 2 ranks of bleed. • Fire Release: Affected creatures gains 1 rank of the Burned Condition. • Water Release: Affected creatures gains 1 rank of the Chilled Condition. • Lightning Release: Affected creatures gains 1 rank Shocked Condition for the next minute. A-RANK: WIND RELEASE: CAST NET Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self (60-Foot Cone) Duration: Instant Components: HS, CM Cost: 19 Chakra Keywords: Wind Release, Ninjutsu Description: A wave of slicing wind erupts from you as you swing your hand. Each creature in a 60-foot cone must make a Strength saving throw. A creature takes 7d8 wind damage and are thrown back 60 feet, fall prone, gain 1 rank of lacerated and causing Swirl on a failed save. Creatures take half as much damage and no further effects on a successful save. 79 WIND RELEASE: DEFIANCE STORM Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Full Turn Action Range: 90 Feet (30-foot-Radius Sphere) Duration: 1 minute Components: HS, CM, CS Cost: 20 Chakra Keywords: Wind Release, Ninjutsu, Fuinjutsu Description: You throw a Chakra seal onto the ground before you release the chakra sealed within in creating an aura of reinforcing Wind release chakra. Select up to 4 creatures to gain the benefits of this jutsu while inside this Jutsu's radius. For the duration select creatures within this jutsu’s radius makes Strength, Dexterity and Wisdom skill checks and Saving throws at advantage, Ninjutsu they cast of B-Rank or lower has their cost reduced by -2 (Min 1.), Taijutsu & Bukijutsu they cast deal additional wind damage equal to your Ninjutsu Ability modifier. The Chakra Seal used to cast this jutsu can be targeted for attacks, although it is protected by a bubble of Wind Release Chakra. It has an AC equal to your Ninjutsu Save DC, and Hit Points equal to twice your Ninjutsu Save DC. It has Immunity to Lightning Damage and Vulnerability to Fire Damage. Once Destroyed, this jutsu immediately ends. WIND RELEASE: DRILLING WIND BULLET Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 120 feet Duration: Instant Components: HS, CM Cost: 19 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You inhale a single breath and exhale creating a spinning drill made of slicing wind that tears through everything in its path. Make a Ranged Ninjutsu attack targeting 1 creature dealing 7d10 wind damage, inflicting 3 ranks of lacerated and pushing the target back 25 feet on a hit. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10. WIND RELEASE: EYE OF THE STORM Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Full Turn Action Range: Self (60-foot-Radius Sphere) Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 20 Chakra Keywords: Wind Release, Ninjutsu Description: You Create a powerful twisting cyclone of wind that seals yourself and all creatures in this jutsu’s Radius off from other creatures and effects from outside this jutsu’s radius. Creatures outside this jutsu’s radius cannot see into the opaque wall of twisting wind, dust, dirt and chakra. A creature with Chakra sight when looking at the wall only sees a wall of chakra and cannot make out anything passed it. If a creature attempts to pass through the wall, they must make a Strength saving throw. On a successful save they pass through the wall. On a failed save they take 8d8 wind damage and are thrown back 30 feet. Attacks and Jutsu cannot penetrate this jutsu’s walls. While inside this jutsu’s radius, creatures cannot generate electricity preventing them from casting Jutsu with only the Lightning Release Keyword. If the wall is struck with a Jutsu with the Water Release Keyword, the walls becomes wreathed in Water Release Chakra. If this jutsu’s walls become wreathed in Water Release chakra, creatures within this jutsu’s radius cannot generate fire, preventing them from casting jutsu with only the Fire Release Keyword. If the wall is struck with a Jutsu with the Fire Release Keyword, the walls becomes wreathed in Fire Release Chakra. If this jutsu’s walls become wreathed in Fire Release chakra, creatures within this jutsu’s radius cannot generate strong wind, preventing them from casting jutsu with only the Wind Release Keyword. WIND RELEASE: LIONS FANG BLADE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 120 feet Duration: Instant Components: HS, CM Cost: 19 Chakra Keywords: Wind Release, Ninjutsu Description: You mold wind Release Chakra to create a beast made purely of Wind Release Chakra, that has a design and look of your description that counts as large. Upon its creation, you command it to attack a number of creatures up to your Ninjutsu Ability Modifier once each. Make a Melee Ninjutsu attack for each creature it attacks within range as it leaps and assaults each creature. On a hit, you deal 2d8 Wind Damage. A creature that takes damage from the Beast must make a Constitution saving throw being torn apart from the thousands of blades made of Wind Release chakra that makes up your Beast. On a failed save they gain 2 ranks of Lacerated and cause Swirl. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and Lacerated ranks by 3. 80 WIND RELEASE: NEVER ENDING FALL Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self Duration: Concentration, 1 Minute Components: HS, CM, M Cost: 15 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vacuum of air under yourself with the ability to ascend, descend and move in any direction at your own discretion. You gain a fly speed of 60 feet. If you use your action to Dash, you instead move 180 feet in the round. WIND RELEASE: NEVERENDING BREATH Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: Self Duration: 10 Hours Components: HS, CM Cost: 15 Chakra Keywords: Wind Release, Ninjutsu Description: You inhale a single breath, and using chakra you are able to reinvigorate that single collection of air as if it were a new breath. You no longer need to breathe for up to 10 hours. You cannot be suffocated or drowned. WIND RELEASE: SPLITTING BREEZE Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: HS, CM Cost: Special Keywords: Wind Release, Ninjutsu, Clash, Kinjutsu Description: You mold wind Release Chakra to create a blade of wind release chakra that is so compressed it fits into the palm of your hand. The amount of power this jutsu exhibits is entirely dependent on the amount of chakra you commit to it. Spend chakra up to the listed amounts. For every chakra cost milestone hit you deal the listed effect. A creature reduced to 0 as a result of this jutsu is bisected at any angle the caster decides. The saving throw this jutsu refers to below is a Constitution save. 20 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 20d4 Wind Damage. A creature must also make a saving throw gaining 2 ranks of laceration and causing Swirl on a failed save. 30 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 30d4 Wind Damage. A creature must also make saving throw, gaining 4 ranks of laceration and causing Swirl on a failed save. 40 Chakra: You make a single melee Ninjutsu attack. On a successful hit, you dealing 40d4 Wind Damage. A creature must also make a saving throw, gaining 6 ranks of laceration and causing Swirl on a failed save. WIND RELEASE: VACUUM SERIAL WAVES Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 16 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You take a deep breath and exhale several super intense blades of wind at different angles but at multiple targets. Make a ranged Ninjutsu Attack against up to 3 targets dealing 8d6 Wind Damage and inflicting 1 rank of lacerated on a hit. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the ranks of laceration by +1. WIND RELEASE: VACUUM WALL Classification: Ninjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 feet Duration: 1 Round Components: HS, CM, M Cost: 15 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vacuum of air around a willing creature in range that nullifies almost all attacks that would aspire to harm you. Until the beginning of your next turn. All Ninjutsu and Taijutsu, Melee and Ranged weapon attacks must roll 1d20 when they declare an attack targeting you. On a roll of 8 or greater, the attack is diverted or knocked away by the extremely dense wind. S-RANK: WIND RELEASE: 1 MILLION BLADE COLLISION Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 120 Feet Duration: Instant Components: HS, CM Cost: 25 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You focus a massive amount of wind chakra into a sphere above the target in range and bring it down crashing into the target as a single blade. The target must make a Dexterity saving throw, creatures take 34d6 wind damage, gain 5 ranks of lacerated and cause Swirl on a failed save, or half as much damage and ranks of bleed on a Successful save. 81 WIND RELEASE: BACKLASH WAVE Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Reaction, which you take when you see a Ninjutsu being cast. Range: 90 Feet Duration: Instant Components: HS, CM Cost: 28 Chakra Keywords: Wind Release, Ninjutsu Description: You see an attack as it comes towards you and you create an impenetrable forcefield of wind that’s designed to throw everything back. Make a Ranged Ninjutsu Attack vs the triggering creatures ninjutsu save DC. If your result is higher, the opponent suffers the damage and effects of their own jutsu. On a failure, the jutsu is diverted and immediately ends. WIND RELEASE: FANNED WIND Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: 100 Foot Cone Duration: Instant Components: HS, CM Cost: 30 Chakra Keywords: Wind Release, Ninjutsu Description: A torrent of concussive wind erupts from your hands that explodes forward devastating everything in a 100-foot cone in front of you. This jutsu blows everything not tied down away and even upheaves trees and smaller structures and buildings. Creatures in its path must make a Strength saving throw being thrown back 120 feet on a failed save. If the creature hits a structure their movement ends and they take triple the falling damage as if they fell the same distance they traveled. WIND RELEASE: HURRICANE OF DISASTER Classification: Ninjutsu Rank: S-Rank Casting Time: Full Turn Action Range: Self (120-foot radius) Duration: Instant Components: HS, CM, CS Cost: Special (138 Chakra) Keywords: Wind Release, Ninjutsu, Combination, Kinjutsu Description: You generate a Category 6 Hurricane that touches down with the sole intent of bringing nothing but ruin in its wake. This Hurricane extends 250 feet into the air and has a 120-foot radius. This hurricane affects all creatures except its casters within its radius. At the end of each of your turns, it moves 90 feet in a random direction (Roll 1d8. 1: North, 2: North East, 3: East, 4: South East, 5: South, 6: South West, 7: West, 8: North West.). Creatures within this jutsu’s area of effect must make a Strength saving throw being ripped from their current position and thrown 250 feet into the air taking 12d8 wind Damage and being restrained by the wind on a failed save. A creature thrown into the air may repeat their Strength Saving throw to escape this wind at the end of each of their turns, taking 12d8 wind damage on a failed save and escaping, falling to the ground on a successful save. All structures and constructs in this jutsu’s path automatically fail their saves and are destroyed as they are pulled into the hurricane’s rotation. This Hurricane lasts for 1 Minute as once cast it cannot be stopped or dispelled by its casters willingly. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 4d8. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size and damage based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the radius of the hurricane by 30 feet, +3: Increase the radius of the hurricane by 60 feet, +4: Increase the radius of the hurricane by 90 feet, +5: Increase the radius of the hurricane by 120 feet). 82 WIND RELEASE: SPIRALING TEMPEST Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Bonus Action Range: Self (45-foot radius) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 20 Chakra Keywords: Wind Release, Ninjutsu Description: You release a surge of Wind Release Chakra that protects and enhances all of your allies for the duration. All creatures of your choice within range gain the following; • If a creature starts their turns in this jutsu’s radius, they gain a Bonus +30 Movement speed until the end of their next turns. • They gain a +3 bonus to Ninjutsu and Taijutsu Attack Rolls. • They gain a number of Temporary Hit points equal to your Ninjutsu Save DC at the beginning of each of their turns. • Taijutsu they cast that has a range of touch, or 5 feet, increases their range by 15 feet, and deals an additional 3d8 Wind Damage. • Affected Creatures cannot be Dazed or Weakened. • Affected creatures gain Resistance to Lightning Damage. WIND RELEASE: TORNADO EXPLOSION Classification: Ninjutsu Rank: S-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM, CS Cost: 30 Chakra Keywords: Wind Release, Ninjutsu Description: You create a spiraling cylinder of wind centered on yourself that has a 90 Foot radius and is 120 Feet High. This cylinder becomes difficult terrain for the duration, even for flying creatures. Unattended objects in this cylinder that are large or smaller are pulled upwards and spins around the center at 200 Mph. A creature that starts its turn in the cylinder must succeed a Strength save or cause Swirl and be pulled upwards towards the center and be restrained while in motion. All objects and creatures inside the cylinder, excluding yourself, take 8d10 Wind Damage at the start of each of your turns. Creatures can make a Strength save on each of its turns as an action to not be restrained on its turn. 83 FIRE RELEASE Fire Release is the most common of the five nature transformations in the leaf village and land of fire, but those who can use it are able to knead chakra and set fire to anything. Fire Release is almost always used offensively and has very few defensive applications. Some shinobi use it to damage massive areas and harm large groups of foes. Fire Release is commonly exhaled from the user's mouth. Although Fire Release has naturally amazing power, it suffers from high chakra cost and is difficult to control flames after use. Fire Release is naturally strong against Wind Release and weak against Water Release Prerequisite: You must have the Fire Release Affinity to learn jutsu with the Fire Release Keyword. D-RANK: FIRE RELEASE: ABSORB HEAT Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you would take damage. Range: Self Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You generate a vacuum of chakra absorbing the heat from the surrounding area and create a thin layer of fire chakra to protect yourself. You gain resistance to the triggering instance of damage. If the triggering damage or any further attacks that target you are melee attacks and the triggering creature was no more than 10 feet away when this jutsu was cast, the triggering creature takes 6 fire Damage until the beginning of your next turn. If the triggering damage was fire, you also gain +5 DR vs fire damage until the start of your next turn. If the triggering damage was cold, this jutsu fails to activate. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage dealt as a result of a melee attack by +4 and the range a creature can be to take the damage by 5 feet. FIRE RELEASE: ASH CLOUD Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet (30 Foot Cloud) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You inhale and knead fire chakra in your lungs to create a cloud of ash. You exhale the ash into a target area within range that you can see. The Cloud of ash remains until blown away or dissipates which can take up to 10 minutes. Creatures inside the target area have disadvantage on attacks while inside the cloud, and are treated as if in total darkness. Creatures making ranged attacks inside the cloud cannot see creatures inside. FIRE RELEASE: BLAZING EMBER Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet Duration: Instant Components: HS, CM Cost: 4 Chakra Keywords: Fire Release, Ninjutsu Description: You manifest motes of fire in the palms of each of your hands. Make two Ranged Ninjutsu attacks. These attacks can target one creature or two. If targeting multiple creatures make a single Ranged Ninjutsu attack against each. On a successful hit you deal 3d4+3 fire Damage. If a creature affected by the Burned condition is hit by both attacks, they immediately suffer the damage of their condition. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank increase the number of attacks you can make by +1. If this jutsu is cast at S-Rank increase the number of attacks you can make by +2. FIRE RELEASE: BLAZING HANDS Classification: Ninjutsu Rank: D-Rank Casting Time: 1 action Range: self (20-foot cone) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Fire Release, Ninjutsu Description: You hold your hands out and fire a sheet of flame from your hands. Each creature in a 15-foot cone must make a Dexterity saving throw. A creature takes 5d4+5 fire damage on a failed save, or half as much damage on a successful one. This fire ignites any flammable objects in the area that aren’t being worn or carried. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d4+1. 84 FIRE RELEASE: BLUE FIRE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you see a creature take dama", created_at: NOW, updated_at: NOW },
  { _id: "877d8916cf649f67992225d3", name: "GRASS PALM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 bonus action", range: "5 Feet", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "You perform a series of martial attacks attempting to cripple and disable creatures surround you. Make a melee taijutsu attack against each creature within 5 feet of you dealing your [Unarmed Damage] + 2d10. Targets you hit with this taijutsu must make a Strength saving throw being disarmed and gaining +1 rank of weakened. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by +1d10.", created_at: NOW, updated_at: NOW },
  { _id: "a0dc39c86ac3a250e265ac9f", name: "HEAVY JOLT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "7 Chakra", components: "M", duration: "Instant.", description: "You take a low stance as you place all of your weight into your primary leg, before you perform a powerful sweeping kick, cracking their air from the weight of it. All creatures within 5 feet of your of your choice must make a Dexterity saving throw. On a failed save, creatures take your [Unarmed Damage] + 4d8 and are Dazed. On a successful save they take half damage and no further effects. If at least one creature fails the saving throw, you can choose to knock that creature back 30 feet. If you do, you immediately move up to 25 feet, following after them. Your movement does not provoke attacks of opportunity, but your targets movement does.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "f6f8c9ea4d3f59939bc0c664", name: "INTERSECTION COUNTER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction which you take when hit by a melee attack", range: "Self", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "You raise your knee and slam your elbow, into an incoming attack catching it in between them. As a reaction, make a melee Taijutsu attack, on a hit you reduce the damage you take by your [Unarmed Damage] + 4d6.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of attacks this applies to by +1.", created_at: NOW, updated_at: NOW },
  { _id: "66181ac1fd30ba8d7ccf5068", name: "JOLTING LIGHTNING: STRUM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "CM, M", duration: "1 Minute", description: "You can see tension in the muscles and body of your friends and can release that tension with a single pressure point press. This jutsu cannot have its cost reduced by any means. Select one willing creature other than you, who you can reach as you press a pressure point on their back. When you do you release a buildup of pooled chakra within them. Affected creature can spend up to two chakra die, regaining a number of chakra points equal to the result. Additionally, for the duration the affected creature gains an additional use of any 1 class feature with a use limitation or 1 additional spendable resource. If this additional resource isn’t spent by the end of the duration it is lost. (Ex. Actualization Die, Hunter Exploit, Brave Order, Preserve or Take Life, Chakra Recovery or Superiority Die etc.) A creature can only benefit from this effect of this jutsu once per short rest.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, you can target up to two creatures, instead of one. If this jutsu is Cast at A- Rank or higher, affected creatures instead regain 2 additional class features uses/resources.", created_at: NOW, updated_at: NOW },
  { _id: "60e92b1dc72fb63d98dcdf31", name: "LAGGING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "8 Chakra", components: "M", duration: "Instant.", description: "You open your hand and angle your fingers until your hand looks more like a claw as you attempt to slam your hand into the joints of your enemies to delay their actions. Make a melee taijutsu attack. On a hit, you deal your [Unarmed Damage] and the target must make a Strength saving throw. On a failed save, until the end of their next turn, If the affected creature attempts any activity that requires an action they must roll a d20. On a roll of 11 or more, their action is delayed until their next turn, in which they spend their next action to complete this original activity. Regardless of the result, this jutsu then immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, reduce the die roll result to 9 or higher to delay the action. If this jutsu is cast at A-Rank, reduce the die roll result to 7 or higher to delay the action. If this jutsu is cast at S-Rank, reduce the die roll result to 5 or higher. 236", created_at: NOW, updated_at: NOW },
  { _id: "81db8be65a269bd2927dfb8a", name: "LATE DEATH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Reaction, which you take when you or an allied creature within 5 feet of you would fall to 0 hit points.", range: "5 feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant.", description: "You delay the death of a friend, by any means necessary. When a creature within 5 feet of you falls to 0 hit points you strike a series of pressure points in a desperate attempt to save them, if only for a moment. The target remains at 0 hit points, but stays conscious until the end of their next turn, after which they fall unconscious failing 1 death saving throws.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, the creatures instead fails 0 death saving throws. If this jutsu is cast at S-Rank, the creature remains at 1 Hit point.", created_at: NOW, updated_at: NOW },
  { _id: "8bfb616f2a07dbd008380b35", name: "LEAF GREAT FLASH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "You charge at your target and unleash a powerful lateral kick, aiming at their head, giving them a concussion. Make a taijutsu attack dealing your [Unarmed Damage] + 2d12 on a hit and forcing the target to make a Constitution saving throw. On a failed save they gain +1 rank of Concussed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d12", created_at: NOW, updated_at: NOW },
  { _id: "374adbed18512e0ab0f6fbcd", name: "LEAF HURRICANE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (15 Foot radius Sphere)", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "You perform a powerful spinning backwards kick, fast enough to not be seen and powerful enough to create a strong whirlwind affecting creatures surrounding the user. Creatures in a 15 Foot radius centering on you must make a Dexterity saving throw taking your [Unarmed Damage] + 2d6 bludgeoning damage and are knocked prone and pulled 10 feet towards you, ending this movement in a space that can hold them. If this jutsu is used as a Finisher, you kick twice causing the whirlwind to manifest and then explode outward. Creatures in range must make a Dexterity saving throw, taking your [Unarmed Damage] + 2d8 and pulling them 10 feet closer towards you on a failed save. Immediately after the whirlwind expands pushing everyone away. All creatures in range must make a Strength saving throw, taking your [Unarmed Damage] + 2d8 and pushing them 30 feet away on a failed save. Creatures who pass either save, take half damage and suffer no further effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 or 1d8, respectively.", created_at: NOW, updated_at: NOW },
  { _id: "d4352b89e4018427423fe090", name: "LEAF SKY BREAKER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Reaction, which you take when you or an allied creature within 10 feet of you would take damage from a melee attack from a creature within range.", range: "15 feet", chakra_cost: "9 Chakra", components: "M", duration: "Instant.", description: "When you or an allied creature within range would take damage from a melee attack. You twist your body in a way that builds momentum and kinetic energy, before you kick skyward creating a powerful updraft, creating a barrier of air between the triggering creature and its target. You create a wall of air and pure force. The triggering creature must make a Strength Saving throw. On a failed save they are thrown 30 feet upwards. Taking damage as if they fell at the end of the current turn. You grant one ally within 15 feet of you an additional reaction which they can only use to cast a Taijutsu with the Finisher Keyword that has a casting time of 1 action Until the end of the current turn, an allied creature within 15 feet of you, can target the triggering creature with a Taijutsu Finisher regardless of range, once per turn, using a Reaction.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fbd936f7644830896c9f42b5", name: "LIMIT RELEASE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "Special", components: "CM, M", duration: "1 Round", description: "You press the pressure points of a willing creature you can reach. When you do, you inject a mass of chakra into them. Spend a number of chakra die up to a max of an amount equal to twice your proficiency bonus. The target must spend an equal number of chakra die, if they are unable this jutsu immediately ends. Once both you and the target spend chakra die, depending on the amount of chakra die spent between the both of you, the target gains different Limiter releasing effects. • 2 Chakra Die: The target rolls spent chakra die, dealing additional damage equal to the amount rolled, on the first attack they make on their next turn. They are then overcome by lethargy as they gain 2 ranks of the Weakened condition until the end of your next turn. • 4 Chakra Die: The target rolls spent chakra die, adding half the result to their next attack roll and the full result to the damage of the same attack they make on their turn. They are then overcome by lethargy as they gain 2 ranks of Weakened condition until the end of your next turn. • 8 Chakra Die: The target gains 1 Additional action on their turn. At the end of their turn, they become stunned until the beginning of their following turn. • 16 Chakra Die: The target gains 1 Additional Action on their turn and can use their Bonus action to complete an activity that requires 1 Action. At the end of their turn, they become stunned for 1d4 rounds. 237 • 32 Chakra Die: The target gains 1 Additional action on their turn and can use their Bonus Action and Reaction to complete an activity that requires 1 Action. At the end of their turn, they become stunned for 1 Minute. This cannot be removed by any means.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d17972c08b5cb1fe2652185a", name: "LIONS BARRAGE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "Select one creature you can see in range as you make two flying axe kicks attempting to disable it. Make two melee taijutsu attacks. On a hit, you deal your [Unarmed Damage] + 1d6. If both attacks hit, the target is Dazed until the end of their next turn. If this jutsu is used as a Finisher, it must be against a falling target. You make three falling, lateral axe kicks attempting to cripple the target. Make three melee taijutsu attacks. On a hit, you deal your [Unarmed Damage] + 2d6. If all three of these attacks hit, the target gains 3 ranks of Bruised and lands Prone.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "2b872455e90f45542388c337", name: "PRESSURE POINT BARRAGE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "9 Chakra", components: "M", duration: "Instant", description: "You unleash a barrage of precise strikes into your targets pressure points crushing their form. Make a melee taijutsu attack, dealing your [Unarmed Damage] + 3d4. The target must make a Constitution saving throw being Weakened and Slowed for 1 minute. At the end of the targets turn, they can remake their saving throw to end either one of the inflicted conditions. They repeat the save until they the end of the duration or they remove all conditions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d0bdb00acf2c4fbd8a7f55ea", name: "RAKSHASA’S PALM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant", description: "You build up chakra into the palm of your hand, until each time you flex your fingers the air crackles with thunderous booms. Make a melee taijutsu attack against a creature you can see within range, on a hit you deal your [Unarmed Damage] + 6d4 and the target must make a Constitution saving throw being Dazed on a failed save until the end of their next turn. If this jutsu is used as a Finisher, you must instead double the cost to cast this jutsu. Make a melee taijutsu attack. On a hit, you deal your [Unarmed Damage] + 10d4. If a structure, construct or separate creature would attempt to intercept this jutsu’s damage, both the interposing structure and the original target takes the listed damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "9efa7650343bd788d2db92ff", name: "RAKSHASA’S SOLE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "CM, M", duration: "Concentration, Up to 1 minute.", description: "You build up chakra into the sole of your feet, until each step you take crushes the ground you walk on. You cannot lose concentration on this jutsu as a result of damage. For the duration, you gain a special reaction called Rakshasa’s Sole, which you can take when you would make a Strength or Dexterity saving throw from a Ninjutsu or Taijutsu cast that has the shape of a Sphere, Cylinder, Cone or Line. Rakshasa’s Sole. When you take this reaction, you perform a round house kick, striking the Jutsu initiating a Clash. You make this Clash check at advantage and can reroll 1’s and 2’s taking the second result. If you win the clash check, you deal damage equal to 3 times your Unarmed Damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If you cast this jutsu at B-Rank if you win the clash check you instead deal 4 times your [Unarmed Damage]. If you Cast this jutsu at A- Rank, if you win the clash check, you instead deal 5 times your [Unarmed Damage]. If you cast this jutsu at S-Rank, if you win the clash check, you instead deal 6 times your [Unarmed Damage].", created_at: NOW, updated_at: NOW },
  { _id: "f96629a6a7573a8c3ed897e2", name: "RISING FALCON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you are falling or pushed at least 10 feet.", range: "5 Feet", chakra_cost: "6 Chakra", components: "CM, M", duration: "Instant", description: "You kick the air or another creature with enough force to propel your entire body in a different direction. If you choose to kick the air, you propel yourself up to 30 feet in any direction. This movement does not provoke attacks of opportunities and if you would end this movement within 5 feet of a hostile creature you can perform a powerful sweeping kick by making a single melee Taijutsu attack, dealing your [Unarmed Damage] + 4d6. If you choose to kick another creature, you must pass through or by them as part of your fall or forced movement. Make a single melee taijutsu attack. On a hit, you deal your [Unarmed Damage] +4d6, and propel yourself up to 30 feet in any direction. This movement cannot provoke attacks of opportunity and if you would end this movement within 5 feet of another hostile creature, you can perform a power sweeping kick by making another melee taijutsu attack targeting this creature, dealing your [Unarmed Damage] + 4d6. 238", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the number of times you can propel yourself by striking a creature by +1.", created_at: NOW, updated_at: NOW },
  { _id: "78da6fa81003ae59dfa6e5f1", name: "ROYAL FLUSH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Special", range: "5 Feet", chakra_cost: "Special", components: "CM, M", duration: "Concentration, Up to 1 minute", description: "As a part of casting this jutsu you must currently be gaining the benefit of Royal Guard. After you reduce damage you take to 0, as a result of Royal Guard, you must end its effects, replacing them with this jutsu’s effects. At the end of your next turn, this jutsu then ends. You do not need to spend chakra to maintain concentration of this jutsu. • You gain a number of temporary hit points equal to the damage reduced as a result of Royal Guard. • Your movement speed is increased by +20 feet. • Your next Strength or Dexterity based check gains a +10 bonus. Once used you cannot gain this effect until this jutsu’s next casting. • The next time you would deal damage with a Taijutsu attack, you can choose to end this jutsu, dealing damage equal to the amount of Temporary Hit points you gained as a result of this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "38f21ab19d8114b40b28c66b", name: "SAFETY RELEASE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "CM, M", duration: "1 minute.", description: "An alternative version of the Body Pathway Derangement. Instead of mixing up a creatures brain signals, you temporarily increase their efficiency. Select one creature, other than yourself that you can see and touch. The targets body experiences no direct changes, but their central nervous system carries signals significantly faster than previously gaining the following benefits; • The creatures speed is increased by half of their current speed, rounded down to the nearest 5. • +1 Bonus to AC. • +1d4 bonus to Dexterity Saving throws. • So long as you can take an Action, you cannot lose the ability to or be prevented from making a Bonus Action or Reaction, so long as an activity fits the abilities reactions triggering requirements. Only 1 creature can benefit from this jutsu at a time. If you cast this jutsu targeting another creature, the previous creature loses its benefits. Additionally, if the creature ever falls under the Shocked condition, this jutsu, immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3733472329191bab9cf5e9eb", name: "SCATTERING WAVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (15-foot radius)", chakra_cost: "8 Chakra", components: "CM, M", duration: "Instant", description: "You inject your fist or foot with a surge of chakra that you use to strike the ground, creating a shockwave of force. All creatures within 15 feet of you must make a Strength saving throw. On a failed save they take your [Unarmed Damage] + 3d6 and are pushed back to the edge of this jutsu’s radius, into a space that can hold them. If the creatures are stopped from moving by a wall or structure, they take 1d6 damage for every 10 feet of movement they had left (min 1d6)", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3, the damage by 1d6 and this jutsu’s radius by +5 feet. If this jutsu is cast at B-Rank or higher, all creatures of your choice within 5 feet of you become immune to this jutsu’s effects. 239", created_at: NOW, updated_at: NOW },
  { _id: "93208fe20b8047418169993c", name: "SEIKUKEN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "M", duration: "Concentration, Special", description: "As a part of casting this jutsu, you must currently be under the effects of any Taijutsu Stance, or Stance granted by Clan Features such as the Gentle Fist Stance or the Shikotsumyaku Stance. If you are not benefiting from any of these stances, this jutsu immediately ends. You stand calm and still, emptying your mind. You begin to control the entire radius within your arm’s length, creating a metaphorical, spherical shield around you. You do not need to spend chakra to maintain this jutsu, instead you cannot gain the benefit of a Bonus action, by any means. For the duration, creatures who make a melee attacks targeting you suffer a 1d6 penalty to their attack rolls and you gain a 1d6 bonus to your melee taijutsu attack rolls targeting a hostile creature within 5 feet of you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "07185ce083531ea0165437e6", name: "SHADOW DANCING LEAF", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Reaction which you take after casting a taijutsu", range: "Full Movement", chakra_cost: "6 Chakra", components: "M", duration: "Instant", description: "As part of the activation of this jutsu, you must have used a Taijutsu as a Standard or Bonus action prior to this Jutsu's activation. You immediately teleport up to your full movement speed behind a target within range. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "39191c07b8a0b41a6aec2c4a", name: "THIRD HEAVENLY BREATH: BREATHE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "9 Chakra", components: "CM", duration: "Special", description: "As a requirement to activate this jutsu, you must have Second Heavenly Breath: Panting currently active. You end your concentration on that jutsu and this one takes its place, maintaining the same duration limitation and Jutsu casting restrictions. You retain all of the effects and duration of that jutsu, stacking them with this jutsu’s effects. You increase your lungs capacity eight-fold. Doing so increases your oxygen intake as your skin begin to turn red as your blood vessels swell as your muscles and organs begin to swell. Increase your taijutsu attack bonus by +1, bonus damage by 1d8 twice per turn, and you gain 10 temporary hit points that stack with temporary hit points gained by other Heavenly Breath Taijutsu you cast. Upon ending this jutsu, you gain 2 ranks of the Weakened condition until your next rest, which cannot be removed by jutsu of C-Rank or lower.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8f18f2d6945895b71d4b0491", name: "TWIN HEAVENLY SWALLOW", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "Special (32 Chakra)", components: "M", duration: "Instant", description: "This jutsu can only be cast if you have one other caster. You and the second caster perform a series of well- orchestrated strikes in sequence with one another back and forth with you performing the final strike. Each caster makes 2 melee taijutsu attacks against the target creature, dealing their unarmed damage + 2d4 on a hit. If both casters successfully hit the target with 2 or more melee taijutsu attacks, then both casters make one more melee taijutsu attack. If both final attacks are successful, the target takes each casters unarmed damage + 3d8 and are launched 20 away, landing prone. Combination: When this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. • +0-1: No Change. • +2-3: Both casters makes 1 additional initial melee taijutsu attack. • +4-5: Both casters makes 2 additional initial melee taijutsu attacks.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f385885c67ef8ba6492ba2ee", name: "WELTER MOVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Special", range: "Self", chakra_cost: "6 Chakra", components: "M", duration: "1 Round", description: "As a part of casting this jutsu, you must currently be under the effects of any Taijutsu Stance, or Stance granted by Clan Features such as the Gentle Fist Stance or the Shikotsumyaku Stance. If you are not benefiting from any of these stances, this jutsu immediately ends. When you would move 10 feet before making a melee attack, you can activate this jutsu, granting yourself a +1 Bonus your attack rolls and Dexterity Saving throws. These bonuses last until the beginning of your next turn. You can activate this jutsu no more than three times per turn. Each time you activate this jutsu, you must move 10 feet and perform a melee attack targeting either the same or another creature. Creatures who’s attack result would be equal to your AC counts as a miss for the duration. If you would succeed a Dexterity saving throw while gaining the benefit of this jutsu you take no damage and suffer no effects while benefiting from this jutsu. Finally, the first time you would be hit by an attack while gaining the benefit of this jutsu, you lose its benefits. 240", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1133677c5aff05117bcef5f5", name: "WHIRLWIND DEATH DROP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 action", range: "5 feet", chakra_cost: "9 Chakra,", components: "M", duration: "Instant", description: "You perform a spinning backwards kick followed by a devastating downward axe kick. Make two Taijutsu attack On a hit, each attack deals your [Unarmed Damage] + 2d8. If this jutsu is used as a Finisher, you make three spinning kicks. Make three melee taijutsu attacks, dealing your [Unarmed Damage] + 2d8. If a creature is hit with at least two of your attacks, they must make a Constitution saving throw, being stunned until the beginning of their next turn on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "976962e9658fa88097ae2d24", name: "WHIRLWIND SNAP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Self (15-foot Cone)", chakra_cost: "7 Chakra", components: "M", duration: "1 Round", description: "You perform a reverse round house kick. All creatures in a 15-foot cone originating from you must make a Strength saving throw. On a failed save they take your [Unarmed Damage] + 2d6 and are pulled up to 10 feet closer to you into a space that can hold them and are Bruised until the beginning of their turns, or half as much on a successful save. Until the end of the current turn, an allied creature within 15 feet of you, can target the triggering creature with a Taijutsu Finisher regardless of range, once per turn, using a Reaction.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3, the damage by 1d6 and the cone size by +5 feet. B-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "34788a79219045361481a3a9", name: "AFTER IMAGE TECHNIQUE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, when you are targeted by an attack that you can see, that is not a critical hit.", range: "Self", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "You move fast enough to leave behind a duplicate of yourself purely from your movement speed alone. Right before a creature hits you, you instantly teleport up to your full movement to another space leaving behind a copy of yourself that dissipates when hit by the initial attack.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "606daf800719f7d78f0c5829", name: "ASAKUJAKU: MORNING PEACOCK", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "Special (14 Chakra)", components: "M", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu Finisher targeting an airborne or falling creature. As a part of casting this jutsu, you must be gaining the benefits of at least the Gate of Tomon from the 8-Inner Gates: Keimon Taijutsu feat or Keimon or any 8 Inner gate granted by the 8-Inner Gates: Shimon. Once this jutsu is cast, you cannot cast it again until you spend at least 10 minutes recovering from the strain it places on your body. You leap into the air in a distinctive stance and begin punching the enemy repeatedly, so quickly in fact that they are set ablaze by the sheer speed and friction which in turn, creates a peacock-like fan of flames around the target. Make a number of melee taijutsu attacks equal to your proficiency bonus dealing 1d6 damage on the first hit, then each successful hit after the first, increase damage die by +1. You cannot add your ability modifier to the damage dealt in any way. If you Score at least 5 hits this way, at the conclusion of this jutsu, the target is slammed back into the ground, taking falling damage as if they had fallen 50 feet and have to make a Constitution saving throw, being stunned until the end of their next turn on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8b9d0446be1ce57a7981c9ae", name: "ASAKUJAKU: MORNING DOVE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "Special (14 Chakra)", components: "M", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu Finisher targeting an airborne or falling creature. As a part of casting this jutsu, you must be gaining the benefits of at least the Fifth Heavenly Breath: Respire Taijutsu or any Heavenly Breath taijutsu of a higher rank. Once this jutsu is cast, you cannot cast it again until you spend at least 10 minutes recovering from the strain it places on your body. You leap into the air in a distinctive stance as air fills your lungs and your muscles bulge from your blood pathways expansion. You begin to punch with enough force to imitate falling stars. Each punch create small sonic booms without enough force to be felts up to 100 feet away. You strike with enough consistency and technique to create the image of dove from the expansion of air surrounding you and your target. Make a number of melee taijutsu attacks equal to the number of Heavenly Breaths you are benefiting from dealing bludgeoning damage equal to 1d10 + Your taijutsu ability modifier on each hit. If you Score at least 5 hits this way, at the conclusion of this jutsu, the target is slammed back into the ground and have to make a Constitution saving throw, being stunned until the end of their next turn on a failed save. 241", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a8f615f0b46c85d67ed52b2b", name: "BREAKER FIST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "You perform a full power strike, putting all of your weight and momentum behind this strike. If this jutsu is cast targeting a creature who is gaining the benefits of Damage Reduction or Resistance, you ignore them for this jutsu’s damage roll. Make a melee taijutsu attack dealing your [Unarmed Damage] + 5d8. If this jutsu is used as a Finisher, on a hit, you instead deal your [Unarmed Damage] + 7d8, and the target must make a Constitution Saving Throw. On a failed save, they are shaken as they become Staggered until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "22bbe7fb48c90773f7ab284b", name: "CHERRY BLOSSOM IMPACT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You amass enough chakra on the tips of your knuckles to completely obliterate a small home, choosing to instead strike a single creature with this monstrous impact. You store up chakra as you make a single, powerful strike releasing it on impact. Make a single melee taijutsu attack against a target in range. On a hit, the target takes your [Unarmed Damage] + 4d12. The target also has to make a Constitution saving throw being dazed and bruised. If this jutsu is used as a Finisher, if you successfully score a hit, all creatures, objects and structures touching the ground (excluding you) within 30 feet of the target, must make a Dexterity saving throw taking 6d6 Bludgeoning damage and falling prone on a failed save, or half as much on a successful one. The affected area becomes difficult terrain.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d12 and 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "f7f39d5537d97f34cb873521", name: "DRAGON BREAK", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu Finisher. As a part of casting this jutsu, you must currently be under the effects of the Dragon Stance. You interlock your hands and perform a powerful strike to the targets core while both hands are imitating the bottom and top half of a dragons maw. Make two melee taijutsu attacks, dealing your [Unarmed Damage] + 3d8. For each successful hit the target must make a Strength saving throw. On each failed save, the target creature suffers a 1d4 penalty to their melee attacks, and skill checks that use Strength or Dexterity until the end of your next turn. If this jutsu is used as a Finisher, you instead my three melee taijutsu attacks.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "48f899bce1a8c86b9c2ab98e", name: "DRAGON CRUSH", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "10 Chakra", components: "M", duration: "Instant", description: "This jutsu can only be cast as a Finisher. As a part of casting this jutsu, you must target a creature who is Dazed, Prone or Stunned. Make a melee taijutsu attack, dealing your [Unarmed Damage] + 8d10 and forcing the creature to make a Constitution saving throw. On a failed save, their condition persists, extending the duration of it by 1 round. If they are only Prone you instead deal an extra damage die and they gain 1 rank of Bruised.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "903ef974e59db43ad871ffad", name: "FIFTH HEAVENLY BREATH: RESPIRE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "14 Chakra", components: "CM", duration: "Special", description: "As a requirement to activate this jutsu, you must have Fourth Heavenly Breath: Wheeze currently active. You end your concentration on that jutsu and this one takes its place. You retain all of the effects and duration of that jutsu, stacking them with this jutsu’s effects. You increase your veins and arteries size and blood flow twenty-fold. The aura that surrounds you begins to glow far more intensely as it begins to spin. Your first two taijutsu attacks per turn are made at advantage, deal 1d8 bonus damage, and you gain 20 temporary hit points which stack with other THP granted by Heavenly Breath taijutsu. Upon ending this jutsu, you gain 1 rank of the weakened condition and one rank of the slowed condition until you finish a long rest. This cannot be removed or ended early except by a jutsu with the Medical keyword of A-Rank or higher. 242", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7a76048741f0fc1674f76762", name: "FORCE WAVE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "Special (49 Chakra)", components: "M", duration: "Instant", description: "This jutsu can only be cast if you have one other caster who is within 15 feet of you. The second caster as a part of their reaction, moves to a space within 5 feet of you that they can occupy. You and the second caster perform a cross strike switching places with each other while creating a shockwave of force that that expands outward. All creatures in a 30-foot cone originating from both casters in the same direction, must make a Strength saving throw vs whichever of the two casters has the higher Taijutsu save DC. Depending on the severity of the failure, the creature takes an escalating amount of damage and suffers additional penalties. • Failed by 1~4: Bludgeoning damage equal to both casters unarmed damage + 9d6 and are knocked prone. • Failed by 5~9: Bludgeoning damage equal to both casters unarmed damage + 12d6, are knocked prone and dazed until the beginning of their next turn. • Failed by 10~14: Bludgeoning damage equal to both casters unarmed damage + 15d6, are knocked prone and dazed until the end of their next turn. • Failed by 15+: Bludgeoning damage equal to both casters unarmed damage + 18d6, are knocked prone, dazed until the end of their next turn, and are knocked back 30 feet. If their movement would be stopped by a solid surface less than 5 feet thick, they take an additional 2d6 bludgeoning damage and are forced through it. If their movement would be stopped by a solid surface 5 or more feet thick, then they take damage as if they fell 5 times their distance they had remaining to move, rounded up. Combination: When this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. • +0-1: No Change. • +2-3: Affected creatures suffer a -2 penalty to their saving throw. • +4-5: Affected creatures suffer a 1d6+1 penalty to their saving throw.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "62df7b2896647c187c7104ae", name: "FULL HOUSE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action or Reaction, which you only take while airborne, falling, or jumping at minimum 30 feet.", range: "30 feet", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "While falling you change trajectory to instead come down diagonally against a creature within range. You come down aggressively with the force of a falling star. Move up to 30 feet towards a creature you can see within range, ending your movement within 5 feet of the target. Make a melee taijutsu attack dealing your [Unarmed Damage] + 4d8. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 7d8 and all creatures within 10 feet of the target must make a Strength saving throw as the force of your kick cracks the air and creates an unprecedented shockwave. On a failed save the creatures are thrown 10 feet away into a pace that can hold them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ad1ad7f0791351a1d0e2904f", name: "GLIMMER DRAGON", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you would only take when a creature would score a critical hit against you.", range: "Self", chakra_cost: "11 Chakra", components: "M", duration: "1 Round", description: "When you would be hit by a critical hit, you reinforce your body with muscle, blood and chakra, cushioning the impact. The triggering critical hit and all subsequent critical hits are treated as a regular hit, until the beginning of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3794ccb70f2fb6030b4c36be", name: "HEAVENLY FOOT OF PAIN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "14 Chakra", components: "CM, M", duration: "instant", description: "You put an enormous amount of chakra into the heel of your foot as you make a single downward kick. Make a Taijutsu attack against a target in range. On a hit target takes 7d10 Bludgeoning damage. If this jutsu is used as a Finisher, additionally, all surrounding creatures, objects and structures (excluding you), within 30 feet of the target must make a Dexterity saving throw. On a failed save they fall prone, are knocked into the air 30 feet, suffering falling damage and are incapacitated until the end of the current turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "5e6f2d3f190c45a310897b20", name: "HUNTER’S FEAST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "60 feet", chakra_cost: "12 Chakra", components: "M", duration: "Concentration, up to 1 minute", description: "You hone in on your adversaries physical form, looking for ways to strike them in their vital points. You do not need to spend chakra to maintain concentration on this jutsu. Make a Taijutsu ability check vs a DC 13 + the targets rank (E-Rank: 0, D-Rank: 1, C-Rank: 2, B-Rank: 3, A-Rank: 4, S-Rank: 5). On a success, you find weak points in their form. This jutsu does not work against inorganic creatures such as constructs. For the duration, while you can see the creature, the first two times each turn you deal your [Unarmed Damage], you deal +2d8 necrotic damage to the target. If the target would ever leave your line of sight this jutsu immediately ends. 243", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d95cb082b2dc750b8053125c", name: "KING’S FANG", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "11 Chakra", components: "M", duration: "Instant", description: "As a part of casting this jutsu, you must currently be under the effects of the Lion Stance. This jutsu attacks count as unarmed attacks for the Lion Fist Stance’s bonus action effect. You ferociously attack a creature with the aggression and passion of a lion king. Make two melee taijutsu attacks targeting a creature you can see within range, dealing your [Unarmed Damage] + 2d6. On each successfully hit, the target must make a Constitution saving throw. On a failed save they gain the bruised condition. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] +2d10 on each successful hit.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3. If this jutsu is cast at S-Rank, increase the number of attacks you make by +1.", created_at: NOW, updated_at: NOW },
  { _id: "725afbe9ae68ca660fe2ad27", name: "INCURSION OF CLARITY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "13 Chakra", components: "M", duration: "Instant", description: "You release a surge of chakra throughout your body removing all impurities and assisting in recovering from physical debilitations. You can remove one of the following condition types currently affecting you Physical or Sensory and granting you advantage against the same condition for 1 minute.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cf5733abe8dabeda7a1d48a3", name: "LEAF EARTH CRUSH", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Self (30-Foot Cone)", chakra_cost: "13 Chakra", components: "CM, M", duration: "Instant", description: "You slam your feet into the ground with the Passion of Youth TM, fragmenting and shattering the earth. All creature in in range must make a Dexterity saving throw to dodge and avoid the spears of stone, metal or whatever materials the ground is made of. On a failed save, creatures take 3d8 piercing damage and are knocked 25 feet into the air, becoming airborne until the end of the current turn. The affected area becomes difficult terrain until cleared or restored. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8ece9fa2b46d728fc8de295d", name: "LEAF GUST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 bonus action", range: "Self (30-foot Cone)", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "You swipe your leg with enough force to create a localized shockwave strong enough to bludgeon creatures and objects in range while also blowing them away. Creatures and objects in a 30-foot cone originating from you must make a Strength saving throw, being knocked up 30 feet into the air on a failed save. An airborne creature cannot take a reaction to jutsu you cast with the Finisher keyword before the end of the current turn. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a7384c0609a95f4f310c24d9", name: "LEAF HOT WIND", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Full Movement", chakra_cost: "14 Chakra", components: "M, CM", duration: "Instant", description: "This jutsu can only be used as a Taijutsu Finisher. You begin to perform a series of roundhouse kicks with enough force to ignite the air around your legs turning them into flaming kicks as your tear through everything in your path. Select a space within range that you can see and move to that location regardless of other creatures in your path. All creatures of your choice who you would pass through on your way to the location must make a Dexterity Saving Throw taking 3d6 Fire damage and gaining 2 ranks of the Burned condition on a failed save or only half damage and no further effects on a successful save. If you end your movement within 5 feet of a hostile creature, make a Taijutsu Attack against a target, dealing your [Unarmed Damage] + 7d10 Fire damage. The target must make a Strength Saving Throw gaining 3 ranks of Bruised on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage of your targeted attack damage by 1d10. 244", created_at: NOW, updated_at: NOW },
  { _id: "f349833d5f26383c83800525", name: "LEAF HURRICANE BULLET", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "45 feet", chakra_cost: "10 Chakra", components: "M", duration: "Instant", description: "You strike with enough force to create a focused bullet of air pressure to strike at ranged targets. Make two ranged taijutsu attack, dealing 5d8 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of ranged taijutsu attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "560d1fb92edca9dabaea9d4f", name: "MACHINE GUN PUNCH!", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "You perform a series of insanely fast strikes so fast that your fists grow hot from the resistance of the air around them. You lock yourself in place, and cannot move from the space you cast this jutsu in. Make 5 melee Taijutsu attacks. On a hit, you deal [Unarmed damage]. The strain of this jutsu causes you to suffer blowback from each successful strike. You take 1d6+1 necrotic damage that cannot be reduced or resisted or reacted to for each successful attack you land.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9a4e8bde9efb60d0f13d4e6a", name: "MAXIMUM ENTRY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "45 feet", chakra_cost: "13 Chakra", components: "M", duration: "Instant", description: "You move at remarkable speeds vanishing like the wind. Choose up to 5 creatures you can see within range. Make a melee taijutsu attack against each target. On a hit, a target takes your [Unarmed Damage] + 4d8 and inflict 1 rank of bruised. You then teleport to an unoccupied space you can see within 5 feet of one of your targets you hit or missed. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "eab288f8232e0b39fa7635ac", name: "ONE MAN FRONT LOTUD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "45 feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "As part of the requirements of this jutsu, you must have at least the “First Heavenly Breath: Inhale” or any of the Heavenly breaths thereafter active or any of the 8 Inner Gates class feature active. You leap into the air before beginning to spin turning yourself into a drill with enough force to create spiraling wind and dust that trails you as you come crashing down into a target of your choice that you can see within range. Make a melee taijutsu attack against the target, dealing your [Unarmed Damage] + 5d6. All creatures within 10 feet of the target must make a Strength saving throw to avoid being thrown back 10 feet from the force. If this jutsu is used as a Finisher, you instead make a melee taijutsu attack against the target, dealing your [Unarmed Damage] + 5d12. Additionally, all creatures within 10 feet of the target must make a Strength saving throw, being knocked back 20 feet from the force, becoming incapacitated from the force and falling prone.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "852158e53f363db0fdceb556", name: "OWL DROP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "As a part of the activation of this jutsu, you must be hidden from the target of this taijutsu. You leap downward over your target as your wrap your legs around their neck. You squeeze and twist, attempting to knock them out instantly. Make a melee taijutsu attack against the target to grapple them. On a success the target must make a Constitution saving throw falling unconscious on a failed save. An unconscious creature remains unconscious for 10 minutes, or until they are moved, touched, take damage or are in the area of a Jutsu's effect. 245", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cbbbb496ee24a03473bfdb2e", name: "PACK AGGRESSION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "As a part of casting this jutsu, you must currently be under the effects of the Wolf’s Stance. You ferociously attack a creature with the aggression and ferocity of a pack of wolves. Make two melee taijutsu attacks targeting a creature you can see within range dealing your [Unarmed Damage] + 2d6. On each successful hit, increase your next attacks critical threat range by +1 for this jutsu’s duration. If this jutsu is used as a Finisher, you instead make three melee taijutsu attacks.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "34a76607850a7181304fc249", name: "PASSIONATE DANCING LEAF", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Self (45-foot cone)", chakra_cost: "13 Chakra", components: "CM, M", duration: "Instant", description: "You are filled to the brim with the Passion of Youth TM, and you let it guide your movements. All creature in a 45-foot cone originating from you must make a Dexterity saving throw to dodge and avoid the plethora of punches and kicks you throw out as you dance across the battlefield, before returning back to place in an instant. On a failed save, creatures take 5d6 bludgeoning damage and are knocked prone. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3, the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "152beb0e5168cdf0a5329f43", name: "PISTON FIST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "You make a basic strike against a target within range. As a part of the activation of this jutsu, make a taijutsu attack. On a hit you deal your [Unarmed Damage] + 6d4 as a surge of chakra erupts from your joint forcing the attack deeper. If this jutsu is used as a Finisher, you instead make a melee taijutsu attack with a +2 bonus to your critical threat range, dealing your [Unarmed Damage] + 9d4. If you score a critical with this Taijutsu Finisher, you do not double your [Unarmed Damage] die, you instead deal your [Unarmed Damage] + 25d4.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by +1d4.", created_at: NOW, updated_at: NOW },
  { _id: "cfbb54a62d4a53d93ac21447", name: "PREDATORS FANG", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "13 Chakra", components: "M", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu Finisher. As a part of casting this jutsu, you must currently be under the effects of the Serpent Fist Stance. You take both of your hands and shape them into a serpents open maw with its fangs showing before you perform a series of strikes meant to break an enemy down. Make three melee taijutsu attacks, dealing your [Unarmed Damage] + 2d8. For each successful hit the target must make a Strength saving throw. On each failed save, the target creature suffers a -1 penalty to their Strength or Dexterity ability scores for the next minute. A creature whose ability score is penalized in this way can spend a full-turn-action to readjust themselves, restoring their ability scores back to normal.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "c8f8c8504b49adfeee45eb7b", name: "QUAKING LEG", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 bonus action", range: "5 feet", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "You make a basic strike against a target within range. As a part of the activation of this jutsu, make a taijutsu attack. On a hit, the target take your [Unarmed Damage] and gains 2 ranks of Weakened. Additionally, the affected creature is unable to take reactions until the end of the current turn. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. 246", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0f0706fb8f827b10e58844e2", name: "RABBIT BOSS STOMP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "As a part of casting this jutsu, you must currently be under the effects of the Rabbit Fist Stance. You kick with the force of 10,000 rabbits stomping someone to death. Make one melee taijutsu attacks targeting a creature you can see within range dealing your [Unarmed Damage] + 6d8 and all creatures in a 30-foot cone originating from the target creature must make a Strength saving throw suffering the residual shockwave taking 6d8 bludgeoning damage on a failed save or half as much on a success. The affected area behind the original target creatures becomes difficult terrain as the ground shatters and collapses from your kick. If this jutsu is used as a Finisher, the damage die becomes a d12.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3, the damage by 1d8 or 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "f0dd7334495df0b20703680a", name: "REVERSE GUARD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, being damaged by a melee attack.", range: "Self", chakra_cost: "Special (14 Chakra)", components: "M", duration: "Instant", description: "As a Reaction to being hit by a melee attack, Make a Martial Arts check. Your roll becomes your AC until the end of this turn and against the triggering attack. If a melee attack would miss you this turn, you can reverse the attack on to the target, and the attack now instead targets the triggering creature. If they would miss your AC by 10, you gain an additional Reaction which you can use to cast a Taijutsu with the casting time of 1 action.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0998281a10f913ddb128d665", name: "ROYAL REVENGE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Special", range: "5 feet", chakra_cost: "Special", components: "M", duration: "Instant", description: "As a part of casting this jutsu, you must currently be under the effects of the Royal Guard Taijutsu. You release the pent-up kinetic energy you’ve absorbed into a single potent blow with unwasted movements. Make a single melee taijutsu attack, targeting a creature you can see within range. On a hit, you deal bludgeoning damage equal to 1.5 times the amount of damage you’ve reduced to 0, as a result of Royal Guard. Regardless of a hit or miss, immediately after the melee taijutsu attack made as a result of this jutsu, Royal Guard immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "caaefcb922fe629dba928156", name: "STAR SHOWER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action, which you can only take while airborne, falling, or jumping at minimum 30 feet.", range: "60 feet (20-foot cube)", chakra_cost: "13 Chakra", components: "M", duration: "Instant", description: "While falling you strike the air, creating pockets of force that strike like bullets, pelting the ground. Select a space you can see in range. All creatures in a 20-foot cube originating from this space must make a Dexterity Saving Throw taking your [Unarmed Damage] + 6d8 Bludgeoning damage and falling Prone on a failed save. The area affected by this jutsu becomes cracked and riddled with fist sized craters and imprints becoming Difficult Terrain.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3, the damage by 1d8, and the size of the cube by 5-feet", created_at: NOW, updated_at: NOW },
  { _id: "bd2a2a741452d8ba4d34826d", name: "STEEL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special", components: "CM, M", duration: "Special", description: "You release chakra throughout your body, enhancing your physicality temporarily. This self enhancement reinforces your hands and feet allowing you to break previously inconceivable structures and materials with strikes alone. When this jutsu is cast, you must spend 10 chakra, then an additional +5 chakra for every additional round you want this jutsu active beyond the first, up to a maximum of 10 rounds (1 minute). While gaining the benefits of this jutsu, you gain +7 DR (Damage reduction) vs B/P/S, +2d6 bonus to melee unarmed/weapon, Taijutsu & Bukijutsu damage rolls twice per turn & deal double damage to objects, structures and constructs.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "172ac820bd14f3f415f51e4f", name: "STEEL KNUCKLE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Iron Fist Stance and this Jutsu can only be cast as a Finisher. You perform a series of high-powered strikes with full intention to cause harm, break bones and crush your enemies. Make a two melee taijutsu attacks. On a hit, you deal your [Unarmed Damage] + 3d12 and force the target to make a Strength saving throw. On a failed save, you knock them back a number of feed equal to 10 x your Strength ability modifier. If you knock a creature away from you with any attack granted by this jutsu, you gain bonus movement speed up to the number of feet you knocked the target away, 247 which you can only use to move to a space within 5 feet of the target that can hold you. If they strike a solid surface that’s less than 5 feet thick, they tear through it if they have at least 10 or more feet remaining to be knocked back, taking 4d6 bludgeoning damage for each surface they go through.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3, the damage by 1d12 and 1d6", created_at: NOW, updated_at: NOW },
  { _id: "380a8aaa3fa54317adb15808", name: "STILL EARTH: REVERB", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "CM, M", duration: "10 Minutes", description: "You can see stiffness in the joints of your friends and can release that tension with a single joint adjustment. This jutsu cannot have its cost reduced by any means. Select one willing creature other than you, who you can reach as you press their bodies joints into place with firm but gentle motions. When you do release a buildup of tension and stress within them. Affected creatures experience a bliss of resistance free movement for the duration granting them a bonus +10 to movement speed and +1 to AC, Strength and Dexterity saving throws. Additionally, for the duration the affected creature gains an additional use of any 1 clan feature with a use limitation or 1 additional spendable resource. If this additional resource isn’t spent by the end of the duration it is lost. (Ex. Speed Dice, Sharingan use limit etc.) A creature can only benefit from this jutsu once per long rest. Finally, if this creature is ever under the effects of the weakened condition, this jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank or higher, you can target up to two creatures, instead of one.", created_at: NOW, updated_at: NOW },
  { _id: "124f7e030b8957d193bbc047", name: "TRIPLE DOUBLE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "You support your allies by breaking your mutual enemies defenses, setting them up for a brutal finisher. Make a single melee taijutsu attack against a creature within range. On a hit, you deal your unarmed damage. You grant two allies within 15 feet of you an additional reaction, which they can only use to cast a Taijutsu or Bukijutsu with the Finisher keyword that has a casting time of 1 Action. Until the end of the current turn, up to two allied creatures within 15 feet of you, can target the triggering creature with a Taijutsu or Bukijutsu Finisher regardless of range, one per turn each, using a reaction.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0bac9eb5ec7478ce1bb3bc20", name: "TWIN FRONT LOTUS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "9991cc726431e53e17c4a8fa", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "Special (49 Chakra)", components: "M, W (Battle Wire)", duration: "Instant", description: "This jutsu can only be cast if you have one other caster who is within 15 feet of you. The second caster as a part of their reaction moves to a space within 5 feet of you that they can occupy. As part of the requirements of this jutsu, both you and the second caster must have at least the First Heavenly Breath: Inhale or any of the Heavenly Breaths thereafter active or any of the 8 Inner Gates class feature active the target must be airborne or falling. You and the second caster leap into action grabbing and wrapping the target in you and the second casters battle wire as you begin to spin creating a 3-person drill creating dust trails as the three of you come crashing down into the ground with the force of a meteor. Each caster makes a melee taijutsu attack each dealing their unarmed damage + 5d8. If this jutsu is used as a Finisher, you both instead make a melee taijutsu attack against the target, dealing the attacking creatures unarmed damage + 5d12. Additionally, all creatures within 30 feet of the target must make a Strength saving throw, being knocked back 20 feet from the force and falling prone. Combination: When this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. • +0-1: No Change. • +2-3: Affected creatures must make a Constitution saving throw vs whichever of the two casters has the higher taijutsu save DC, becoming Incapacitated for 1d4 rounds on a failed save. • +4-5: Affected creatures must make a Constitution saving throw vs whichever of the two casters has the higher taijutsu save DC, becoming Stunned for 1d4 turns on a failed save. 248", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "636529194da8d488caabe570", name: "UNPREDICTABLE BLOWS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Drunken Fist Stance. You sway in and out of combat, dancing around your opponent in a drunken stupor throwing them off, while also making it difficult to pint you down into any single space. While you are engaged with at least 2 hostile creatures, make one melee taijutsu attack against each hostile creature you are currently engaged with. On a hit you deal your [Unarmed Damage] + 3d8. Each time you successfully hit a creature using this jutsu, you increase your AC by +1 until the beginning of your next turn, and that creature cannot make an opportunity attack against you until the beginning of their next turn. Additionally, you gain a +1 bonus to saving throws to resist being Physical conditions and a +10 bonus to movement speed until the end of the current turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d8. A-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "a7022730c1e1cae19976fe38", name: "AMPHIBIOUS GOUT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus action", range: "Self (15-feet)", chakra_cost: "15 Chakra", components: "M", duration: "1 Round", description: "As a requirement to activate this jutsu, you must currently be in the Frog Fist Stance. You enter a highly mobile stance designed to allow you to assist all allies in martial combat. Until the beginning of your next turn, allied creatures (including yourself) who would attempt to make a melee taijutsu attack targeting a creature while both creatures are within 15 feet of you, you may add 1 die to their next attack roll, equal to the die size of your [Unarmed Damage] dice, as you support them and yourself, by bouncing around in the 15-foot radius supporting each strike and reinforcing each hit with one of your own. Additionally, until the beginning of your next turn, hostile creatures who would attempt to make a melee or range attack targeting any allied creatures (including yourself) within 15 feet of you, reduces any damage they do by twice your [Unarmed Damage].", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e3842c90c5fb0270301ccec3", name: "COMBO BREAK", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Reaction, which you take when you would take damage or fail a saving throw against a jutsu with the Combo keyword or a jutsu that allows a taijutsu or bukijutsu to target you with a jutsu with the Finisher keyword regardless of range.", range: "Self", chakra_cost: "17 Chakra", components: "M", duration: "Instant", description: "This jutsu can be cast even if you cannot normally gain the benefits of a reaction. You raise your defenses in preparation of being the target of a Finisher. You treat all jutsu with the Finisher keyword as if it was not cast as a Finisher until the end of the current turn. If a jutsu can only be cast as a finisher, you are no longer a valid target, and if there are no other valid targets, the jutsu casting is interrupted and fails.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "756bd0d5e12db0db0ac9f067", name: "COMBO EXTENDER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "16 Chakra", components: "M", duration: "Concentration, Special", description: "As part of the requirements of this jutsu, you must have at least the “Third Heavenly Breath: Breathe” or any of the Heavenly breaths thereafter active and you cannot lose concentration of this jutsu as a result of damage. For the Duration of your Heavenly breath’s, you gain a special action called Combo Extension. Combo Extension. This special action is regained for the duration of this jutsu, at the beginning of each of your turns. For the duration, this special action can be cast a Taijutsu with a Casting time of either an Action or Bonus Action or take the Dash action.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1e2309d0a02a2633c9a711ef", name: "DEATH BLOSSOM", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "20 Chakra", components: "M", duration: "Instant", description: "You strike a downed creature in the chest, in an attempt to stop their beating heart with a single strike. This jutsu can only be used against a creature who is dazed, prone and who is not a construct. Make a melee taijutsu attack. On a hit, the target must make a Constitution saving throw. On a failed save, they take 10d6 in necrotic damage which cannot be reduced by any means or half as much on a success. If this jutsu is used as a Finisher, on a failed save, the target instead takes 10d6 necrotic damage and suffers 5 ranks of Lacerated. If a creature has its hit points reduced to 0 as a result of this jutsu or Laceration cause by this jutsu, their heart explodes. 249", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7fee29e54e9c067d8de7ce37", name: "DISABLING BLOW", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "15 Chakra", components: "M", duration: "Instant", description: "You strike at your target’s joints attempting to disable them for an extended period of time. Make a taijutsu attack against each target within 5 feet of you, of your choice. Each target takes twice your [Unarmed Damage] and have their movement speed reduced by half and forcing them to make a Constitution saving throw. On a failed save, they gain +2 ranks of Weakened and become unable to take reactions against you. An affected creature can remake their saving throw at the end of each of their turns to gain the ability to take reactions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d093b64bf2cb9acc76706978", name: "DRACONIC DRIVE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "18 Chakra", components: "CM, M", duration: "Instant", description: "As a part of the requirements of this jutsu you must have at least the Third Heavenly Breath: Breathe or any Heavenly Breaths thereafter active or at least Seimon from the 8 Inner Gates: Seimon Taijutsu Feat. You leap backwards into the sky as you release chakra from your spine creating jets of chakra that keep you in the air before propelling you downward towards a creature you can see in range. Make a melee taijutsu attack dealing your [Unarmed Damage] +6d6. Regardless of a hit or miss, you create a shockwave originating from the same space of the original target emanating out in a 20-foot radius sphere. All creatures in this radius, excluding you, must make a Dexterity saving throw. On a failed save they take 6d6 bludgeoning damage and becoming dazed for 1 minute or half as much damage on a successful save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1ddf06a484e07f4ac2f5ac58", name: "FINAL LOTUS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "18 Chakra", components: "CM, M", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu Finisher. As part of the requirements of this jutsu, you must have at least the “Fifth Heavenly Breath: Respire” or any of the Heavenly breaths thereafter active or at least Tomon from the 8 Inner Gates: Keimon Taijutsu Feat. The target of this jutsu must be restrained or grappled. Make five taijutsu attacks against the target. On a Hit, Target creature takes Unarmed damage +1d6. If all five attacks hit, you make a 6th attack. On a hit with the 6th attack, you deal 10d6 Bludgeoning damage and knock the target prone. (This Jutsu cannot score a critical hit) After this jutsu, you immediately end either your Heavenly Breaths or 8 Inner Gates.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fc74b57d7b2acb92c7304af9", name: "HEAVEN KILLER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "Special (70 Chakra)", components: "CM, M", duration: "Instant", description: "This jutsu can only be cast if you have one other caster who is within 15 feet of you. The second caster as a part of their reaction moves to a space within 5 feet of you that they can occupy. Both casters leap in to strike the target creature using each other as leverage while juggling the target in between their strikes. Make a combined number of melee taijutsu attacks equal to their combined Taijutsu ability modifier (Max 10), with each caster attacking one after the other with no caster attacking twice in a row. On a hit, the attacker deals their [Unarmed Damage] +2d6. If at least seven attacks were successful, both casters make one final melee taijutsu attack, but only the attack with the highest result is counted. Based on the degree of success over the target AC, this attack deals increased damage. • Succeeds by 1~4: Both casters [Unarmed Damage] + 4d6. • Succeeds by 5~9: Both casters [Unarmed Damage] + 6d6. • Succeeds by 10~14: Both casters [Unarmed Damage] +8d6. • Succeeds by 15+: Both casters [Unarmed Damage] + 10d6. Combination: When this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. • +0-1: No Change. • +2-3: Increase damage die by one step (D6>D8>D10>D12). • +4-5: Increase damage die by two steps (D6>D8>D10>D12).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "763ba5dec55cc91e39c93df6", name: "IRON GUARD", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "Self", chakra_cost: "15 Chakra", components: "M", duration: "1 Round.", description: "As a requirement for this jutsu you must currently be gaining the benefit of any Taijutsu Stance. As a reaction to taking damage, add your Taijutsu ability modifier to your DR (damage reduction). Immediately after you reduce the triggering damage, you gain a thin armor of chakra armor, represented as temporary hit points which total to an amount equal to twice your Taijutsu save DC. These temporary hit points vanish at the beginning of your next turn. 250", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bd0d8f346e0e16c7abf194af", name: "LANDSLIDE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "20 Chakra", components: "M", duration: "Special", description: "As a part of the requires to cast this jutsu, you must currently be standing on an incline or slope style terrain. You take a solid stance and stomp the ground sending out light but effective shockwaves throughout the surrounding terrain. All delicate structures, environment, creatures and materials excluding you, within 120 feet, that is not anchored into the ground at least 1 to 5 feet deep or holding on to something that is anchored into the ground, begin to aggressively slide down the incline or slope. Once cast, this inclined or slopped surface counts as difficult terrain. All stone, must, snow, trees, debris, structures and creatures that begin to slide down this incline or slope must make a Dexterity saving throw at the beginning of each of their turns to avoid being struck by other falling debris sliding down the slope with them. Things falling or sliding down this slope or incline do not stop falling or sliding until the reach solid, flat ground. All objects, environment, structures and constructs fall 60 feet per round, while creatures fall 45 feet per round. Creatures who fail their saving throws are struck with a solid surface or object, structure or creature sliding as a result of this jutsu and suffer 4d6 bludgeoning damage per object, structure or creature within 5 feet of them while sliding. A creature can spend their reaction on another creatures turn to attempt a Strength (Athletics) check to slow their decent by half (round down) at the beginning of their next turn. A creature no longer standing on the inclined or sloped surface at the beginning of their turn does not need to make any athletics checks or saving throws due to this jutsu. This landslides duration is entirely DM’s discretion based on the total height of the actual incline or slope and the volume of things that fall in its totality. This jutsu can stripe a large section of a mountain side or begin a city threatening avalanche on a snowcapped mountain.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "391874e52cee6f395231c9b0", name: "MAGNUM KNUCKLE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "15 Chakra", components: "CM, M", duration: "Concentration, up to 1 Minute", description: "You enrich your arms and legs with chakra that increases combat prowess. For the duration, you have advantage on attack of opportunities, and twice per turn, your unarmed attacks deal an additional die of damage. Also, up to twice per turn, when you make an unarmed attack, target creatures must make a Constitution saving throw or reduce their movement speed by 10 until the end of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dd174ef8acf45b7290ec45ff", name: "PHANTOM MOBILITY", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "15 Chakra", components: "M", duration: "Concentration, up to 1 minute", description: "As a requirement to activate this jutsu, you must currently be in the Silent Fist Stance. If you cast this jutsu while you are currently gaining the benefits of the Silent Movement taijutsu, reduce this jutsu’s cost by half (rounded down), and you immediately end concentration on the Silent Movement taijutsu, while still retaining its benefits for this jutsu’s duration. While you are gaining this jutsu’s benefits; You can move through a creatures space while suffering no movement penalties and requiring no skill checks. When you take the dash action, you can do so as a bonus action and ignore difficult terrain. When water or wall walking, you move at your full speed and finally, unarmed attacks you make deal half their damage to creatures of your choice who are adjacent to your attacks original target.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "76d5d49594b972408010b02c", name: "REAL IMPACT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "20 Chakra", components: "CM, M", duration: "Instant", description: "As a requirement to cast this jutsu, you can only target creatures who are both Dazed and Slowed. This jutsu can only be cast as a Finisher. You reel back preparing to perform a rising uppercut with enough chakra to distort the area around you from the force of your attack alone. Make a melee taijutsu attack, on a hit you deal your [Unarmed Damage] + 10d8 and all creatures, including the original target who are adjacent to you must make a Strength saving throw. On a failed save they are thrown 30 feet into the air, becoming airborne. All other creatures excluding your original target, until the end of the current turn, can be targeted by your allies within 30 feet of you with a taijutsu or bukijutsu Finisher regardless of range, once per turn, using their reaction, ignoring its listed casting time. 251", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b4b548d5a24d67b3737d6055", name: "SAVAGE ROAR", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (70 Chakra)", components: "M", duration: "Concentration, up to 1 minute", description: "This jutsu can only be cast if you have one other caster who is within 15 feet of you. The second caster as a part of their reaction moves to a space within 5 feet of you that they can occupy. You and the second caster perform a symbiotic fighting stance, roaring and working in consistent tandem, never acting independently. For the duration of this jutsu, you do not need to spend chakra to maintain concentration on this jutsu. When you or the second caster would spend their action or bonus action to cast a taijutsu, both casters of this jutsu perform the same jutsu, gaining its benefits simultaneously, so long as both casters could cast it. (Ex. A caster who cannot cast a specific Hijutsu cannot cast the same jutsu as another caster who can cast that Hijutsu) When a jutsu is cast in this fashion both casters do not need to know the jutsu, but must be able to fulfill the conditions of the jutsu cast to gain its benefits. If they cannot this jutsu (Savage Roar) immediately ends. Regardless of the taijutsu cast, if it would normally force the other caster to make a saving throw, they are immune to its offensive effects. Combination: When this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. • +0-1: No Change. • +2-3: Both casters gain a +2 bonus to their taijutsu attack rolls. • +4-5: Both casters gain a 1d4+1 bonus to their taijutsu attack rolls and a +1 bonus to their taijutsu save DC.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "18ee518ffb783f7a7f24f14a", name: "SEIDOU GOITSU", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "M", duration: "Special", description: "An advanced and dangerous technique that’s a part of an ancient martial arts made by combining the opposing chakra of Yin and Yang. This jutsu works by having your Yin chakra first becomes focused inward, while your Yang chakra explodes outward resulting in an explosive boost in the user’s physical abilities. At the beginning of each of your turns, you can choose to attempt to maintain this jutsu or end it. If you attempt to maintain it, make a Martial arts check vs a DC 20. On a success, you maintain this jutsu. Each time after the first, when you make this jutsu while this jutsu is active, increase the DC by +2. On a failed check this jutsu immediately ends. If you end this jutsu instead of attempting to maintain it, this jutsu ends with no further effect. While gaining the benefits of this jutsu, unarmed attacks and taijutsu attacks you make are all made at advantage. Additionally, you deal bonus damage equal to your level, twice per turn, with unarmed and taijutsu attacks. If this jutsu ends as a result of failing the check to maintain it, you gain a number of ranks of the Weakened condition, for a number of minutes equal to the number of rounds this jutsu remained active.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c7ff32b946fd436dee84f00a", name: "SIXTH HEAVENLY BREATH: GASP", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "19 Chakra", components: "CM", duration: "Special", description: "As a requirement to activate this jutsu, you must have Fifth Heavenly Breath: Respire currently active. You end your concentration on that jutsu and this one takes its place. You retain all of the effects and duration of that jutsu, stacking them with this jutsu’s effects. You increase your heart and lung size two-fold. Doing so increases your body’s ability to filter poisons and provide nutrition throughout. The aura that surrounds you begins to glow far more intensely as it begins to coalesce into a storm like formation. Your first two taijutsu deal 1d8 bonus damage, and you gain 30 Temporary Hit Points which stack with other Temporary Hit Points granted by Heavenly Breath taijutsu. Upon ending this jutsu, you gain 2 ranks of the Weakened condition and 1 rank of the Slowed condition until you finish a long rest. This cannot be removed or ended early except by a jutsu with the Medical keyword of S-Rank.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "eee34db7a4bf780dcfa7dce6", name: "SUPREME PACIFICATION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "18 Chakra", components: "M", duration: "Special", description: "An advanced pacification technique meant to completely remove a creature from combat or prevent them from entering combat all together. As a part of the activation of this jutsu, you must target a single creature putting all of your focus upon them. Make a single melee taijutsu attack. On a hit, you immediately grapple and restrain the target. The target can spend their reaction to make an opposed Strength (Athletics) check to break free immediately ending this jutsu, remaining grappled and restrained on a failed check. On an affected creatures turn; they must spend an action to attempt to escape by making a Strength saving throw. While a creature is grappled and restrained this way, they cannot form hand seals (HS), perform the help action, or make any Strength of Dexterity skill checks. Additionally, they cannot speak or make verbal sounds as you have their mouth covered as well. After 5 rounds, a creature restrained in this way, must begin to make Constitution saving throws at beginning 252 of each of their turns. On a failed save, they fall unconscious. While you are grappling a creature in this way, your movement speed is reduced by half, you cannot take the dash action, you cannot form HS, and you cannot concentrate on ninjutsu or genjutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "160a9629bebba467aaadfc98", name: "SUPREME VIOLENCE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "19 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "You pump chakra through your body until you can puppet your body with your chakra alone allowing you to react with but a thought. As a part of the activation of this jutsu you cannot concentrate on any Ninjutsu or Genjutsu for the duration of this Taijutsu. For the duration you gain a bonus to your AC equal to half of your proficiency bonus and you gain a special reaction call Violent Reprisal. Violent Reprisal. When a creature would make a melee attack with you as their target, you can spend your reaction to cast a Taijutsu with the casting time of 1 action that makes no more than two attacks against the triggering creature", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6499743d313584e19fac41bc", name: "TENEBROUS CLAW", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "18 Chakra", components: "M", duration: "Instant", description: "You perform a series of blows with enough speed, Strength, and striking power to generate sparks of electricity with each blow. Make three melee taijutsu attacks against one creature you can see within range, dealing your [Unarmed Damage] + 2d8. If this jutsu is used as a Finisher, you deal your [Unarmed Damage] + 3d8 and a creature who is hit with at least one of these attacks, must make a Strength saving throw. On a failed save, they gain 3 ranks of the Bruised condition.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "3ca6acec0d3961bb616f1a1d", name: "TIGER LILY", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Bonus action", range: "30 Feet", chakra_cost: "18 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "You enter a state of serenity and gain impenetrable clarity of the world around you. For the duration you gain 60 feet of blind sight.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0f9c123e0971284797bc87e0", name: "TRUE RAKSHASA’S PALM", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "As a part of casting this jutsu, you must currently have both Rakshasa’s Palm and Rakshasa’s Sole on your known jutsu list. You combine both techniques forming a perfect fusion of both, managing a balance. For the duration of this jutsu, you cannot lose concentration of this jutsu as a result of Damage or failing a concentration check. While you are gaining the benefits of this jutsu, you cannot cast or maintain concentration on Rakshasa’s Palm or Rakshasa’s Sole. You gain the following benefits for the duration; • Twice per turn, Taijutsu you cast deal an additional 2d6 Damage on a hit. • When you score a successful hit with a Taijutsu attack, once per turn, you may force a target to make a Strength saving throw, gaining 2 ranks of bruised on a failed save. • You deal the maximum possible damage to structures and constructs. • As a reaction, which you can take when you would make a Strength or Dexterity saving throw from a ninjutsu or taijutsu cast that has the shape of a sphere, cylinder, cone, or line, you can perform a round house kick, striking the jutsu while also initiating a clash. • When you would make a Strength (Martial arts) check for the clash, you make it at advantage and reroll 1’s and 2’s.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the damage by 1d6. If you cast this jutsu at S-Rank, when you win a clash check with this jutsu’s reaction, you deal 7 times your [Unarmed Damage]. VIOLENT LEAF ADAMANTINE-STRENGTH", created_at: NOW, updated_at: NOW },
  { _id: "5c13ca371a8a727544ae54a0", name: "WHIRLWIND", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Special", range: "5 Feet", chakra_cost: "18 Chakra", components: "CM, M", duration: "Instant", description: "You generate a strong wind from swiping one of your limbs. A gust of wind is generated in a 30-foot long 5-feet wide in a straight line originating from you. Creatures in the line must make a Strength saving throw, taking 2d6 wind damage, is knocked prone, gains 1 rank of bleeding and causing Swirl on a failed save, and only half damage and no further effects on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the ranks of bleed by +1. WIND RELEASE: RAGING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 60 feet (15-foot radius) Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You manifest a powerful torrent of wind, strong enough to lift and throw most creatures. Select a space you can see within range. A spiraling torrent of wind erupts upwards. All creatures within 15 feet of the chosen space, must make a Strength saving throw. On a failed save they are thrown 30 feet upwards being dazed, taking falling damage, falling prone and causing Swirl. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the height they are thrown upwards by 15 feet. 69 WIND RELEASE: RAGING VORTEX Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You encircle a willing creature with potent Wind Release Chakra. For the duration, you magnify the targets physical capabilities. The target creature adds 1d4 to all Strength and Dexterity skill checks and saving throws. Their movement speed is increased by 15 feet and melee attacks they make that deal damage deals an additional 1d6 Wind Damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of targets you can affect by +1. WIND RELEASE: SECOND WIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You breathe in deeply filling your lungs and blood with chakra filtered oxygen accelerating its blood flow and slightly rejuvenating you. You recover 2d6+ Your Ninjutsu ability modifier hit points. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and roll an additional 1d6. WIND RELEASE: SLICING AIRWAVES Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM, M Cost: 4 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a powerful current of extremely strong and thin currents of wind. You swipe your hand towards your target. Make a Ranged Ninjutsu attack, creatures take 3d8 wind damage and gain 1 rank of bleeding on a hit. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d8 and ranks of bleeding by +1. WIND RELEASE: SPLITTING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet Duration: Concentration, Up to 1 minute Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a field of oppressive and potent wind that slashes and buffets any instance of Hand Signs (HS). Select a space you can see within range, all creatures within 20 feet of the chosen space who would cast a jutsu with Hand Sign (HS) component immediately takes 2d6 Wind Damage and must make a Constitution Saving throw gaining the bleeding condition on a failed save. As a bonus action on your turn, you may move the field up to 30 feet in any direction to a space you can see within range. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the area affected by 5 feet, and the damage by 1d6. WIND RELEASE: SUPPORTING GALE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Reaction to making a Strength, Dexterity or Constitution saving throw Range: Self Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You throw your hands forward creating a compressed blast of air assisting you in a variety of physical tasks; from escaping, fending off an attack, or dispersing a hazardous gas. As a reaction, when you are forced to make a Strength, Dexterity, or Constitution saving throw against a Ninjutsu or Taijutsu, you instead use your Ninjutsu ability modifier in place of your Strength, Dexterity or Constitution for the triggering roll. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at C-Rank you add your proficiency to the roll if you aren’t already proficient. If cast at B-Rank you may select another creature within 20 feet of you to gain the benefits of this jutsu, using your Ability modifier and proficiency bonus. If cast at A-Rank, creatures benefiting from this jutsu roll at advantage. If cast at S- Rank, all creatures of your choice within 30 feet of you can gain this jutsu’s benefit. 70 WIND RELEASE: VACUUM BOMB Classification: Ninjutsu Rank: D-Rank Casting Time: Special Range: 60 feet Duration: Instant Components: HS, CM Cost: 5 Chakra Keywords: Wind Release, Ninjutsu Description: You create a single point of high-density air pressure using your Wind Release Chakra before expanding it and creating a series of reactions. All creatures currently affected by an elemental condition who would have a jutsu cast on them that triggers the swirl effect, potentially passes all such conditions around to other creatures near them in an expanded space with more volatility. When a creature would have the Swirl effect trigger on them, you can cast this jutsu as a part of the same action. All creatures within 20 feet of the triggering creature who failed their save gains two ranks of all elemental conditions the triggering creature had. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the area affected by 5 feet. WIND RELEASE: VACUUM RAIN Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: 90 feet (20-foot cylinder) Duration: Concentration, Up to 1 minute Components: HS, CM Cost: Special (28 Chakra) Keywords: Wind Release, Ninjutsu, Combination Description: You create a powerful updraft that sucks the oxygen and air upwards robbing creatures of the ability to breathe within range. All casters of this jutsu create a 60-foot tall, 20-foot-wide cylinder that removes all air from inside of it replacing it with furiously rotating blade of Wind Release Chakra, centered on a point of your choice within range. All creatures within the cylinder must make a Dexterity and Constitution saving throw. On a failed Dexterity save they are slashed with wind chakra repeatedly taking 2d6 Slashing Damage and 2d6 Wind Damage or half as much on a successful save. A creature makes this saving throw the beginning of each turn they begin within this cylinder. On a failed Constitution Saving throw they are robbed of their air in their lungs as they begin suffocating. A Suffocating creature can only survive a number of rounds equal to their Constitution modifier before passing out falling unconscious from the lack of air. A creature makes this saving throw at the beginning of each turn they begin within cylinder. An unconscious creature can regain consciousness when another creature spends an action waking them. Creatures inside the cylinder cannot gain the benefits of an increase to movement speed and are treated as if they are in difficult terrain. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 2d6 for each damage type. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the Height by +10 feet and radius to 30 feet, +3: Increase the Height by +20 feet and radius to 40 feet, +4: Increase the Height by +30 feet and radius to 50 feet, +5: Increase the Height by +40 feet and radius to 60 feet). WIND RELEASE: VIOLENT WHIRLWIND Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Action Range: Self (30-Foot Cone) Duration: Instant Components: HS, CM Cost: 3 Chakra Keywords: Wind Release, Ninjutsu Description: You exhale a powerful stream of wind from your mouth. Creatures caught in the target area must make a Strength Saving throw. Creatures take 2d6 Wind Damage, are pushed back 30 Feet, are knocked prone and cause Swirl on a failed save or half as much and no additional effects on a successful save. Also, vapors, gases and fogs that can be dispersed by strong winds are dispersed immediately. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. Increase the range of this jutsu by 10ft. WIND RELEASE: ZEPHYR STRIKE Classification: Ninjutsu Rank: D-Rank Casting Time: 1 Bonus Action Range: Self Duration: 1 minute Components: CM Cost: 4 Chakra Keywords: Wind Release, Ninjutsu Description: You move like the wind. For the duration, your movement doesn’t provoke opportunity attacks. Your movement speed increases by 10 feet until the end of the turn you cast this jutsu. Also, once before the jutsu ends, you can give yourself advantage on one attack roll on your turn. On a hit, the attack deals an extra 2d8 wind damage and immediately ends this jutsu. 71 C-RANK: WIND RELEASE: 1,000 BLADES OF THE WIND Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 20 Foot Cone Duration: Instant Components: HS, CM Cost: 7 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a spiraling sphere of wind chakra with a collection of cutting blades within it. Creatures in range must make a Strength Saving throw being pulled towards you and taking 4d6 Wind Damage and gaining 2 ranks of bleeding. Or half as much on a successful save and no ranks of bleeding. Creatures who fail their saving throw, are pulled towards you, ending their movement within 5 feet of you, and causing Swirl. They are then caught in a violent explosion of the cutting wind, being knocked back 20 feet and taking an additional 2d6 Wind Damage. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d6 and the amount of initial bleed gained by +1. WIND RELEASE: BURSTING COMPRESSED AIR Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 30-feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: You conjure a spiraling vortex of wind chakra around a target creatures weapon. The target creature makes a Dexterity saving throw to avoid the collapse of the wind. On a failed save they take 3d6 slashing damage as they are sliced for holding the weapon, and cause Swirl. If they continue to hold their weapon, they must make another save at the beginning of their next turn. On a successful save they take half damage. These additional saving throws do not cause Swirl. After 3 failed saves the weapon they are holding can’t take any more damage and shatters sending weapon shrapnel haphazardly flying. Other Creatures within 10 feet of the exploding weapon taking 3d6 slashing damage. WIND RELEASE: GALE FISTS Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Bonus Action Range: Self Duration: Concentration, up to 1 minute Components: HS, CM, M Cost: 6 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You coat your hands and feet in a layer of highly compressed but highly reactive wind release chakra. For the duration of this jutsu, you may use your Ninjutsu ability Modifier in place of Strength for unarmed attack rolls. Your unarmed damage is treated as Wind for the duration of this jutsu and deals damage equal to 1d10 + Ninjutsu Ability Modifier. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the damage by 1d10. WIND RELEASE: GREAT BREAKTHROUGH Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (60 Foot Line) Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a swirling vortex of air in front of you. You compress the air until the pressure explodes forward like a cannon in a straight line. Creatures in a 5- foot wide, 60-foot-long line must make a Strength saving throw. Creatures take 4d10 Wind damage, are thrown backwards 30 feet away, gain the dazed and prone conditions, and cause Swirl on a failed save. On a success they take half damage and no further effects. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase damage by 1d10 and knock back distance by 10ft. WIND RELEASE: LIONS ROAR Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (15-foot radius sphere) Duration: Concentration, Up to 1 Minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: You weave Wind Release Chakra together, creating a potent veil of chakra in the shape of a Lion around you and allied creatures. This chakra then collapses on all creatures of your choice within range granting the benefits as listed below, for the duration; • Bonus +20 Movement speed. • Ninjutsu, they cast with the Wind Release Keyword that has a range of at least 5 feet, increases their range by 10 feet, and deals an additional 1d8 Wind Damage, once per turn. • Taijutsu, they cast that has a range of touch, or 5 feet, increases their range by 10 feet, and deals an additional 1d8 Wind Damage, once per turn. 72 WIND RELEASE: PRESSURE SHOCKWAVE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when an allied creature casts a jutsu. Range: 60 feet Duration: Instant Components: HS, CM Cost: 8 Chakra Keywords: Wind Release, Ninjutsu Description: When you see another allied creature cast another jutsu, you create a tornado like mass that is compressed until it has a high density before being released as a shockwave, intended to boost their jutsu’s effects. If the triggering jutsu does not have a nature release keyword, the allied creature makes their attack roll at advantage or one hostile creature of your choice within range makes their saving throw at disadvantage. If the triggering jutsu has a nature release keyword, then all hostile creatures in a 60-foot cone, originating from you, must make a Strength saving throw or be pulled 15 feet towards your allied creature, take 5d6 wind damage, and causing Swirl on a failed save, or half as much and no further effect on a success. Additionally, it amplifies the triggering jutsu based on its nature release; • Earth Release: On a failed save target cannot take reactions. • Wind Release: On a failed save target gains 2 ranks of bleeding. • Fire Release: On a failed save the triggering jutsu increases its damage die by 1 step. • Water Release: On a failed save the target gains 1 rank of chilled. • Lightning Release: On a failed save the target gains 1 rank of shocked. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WIND RELEASE: RAKSHASA BARRIER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you would take Earth, Fire, Cold, or Lightning Damage Range: Self Duration: 1 Round Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash, Construct Description: You raise your hand and generate an intensely dense torrent of wind that circles around you, creating a bubble of wind that envelops your entire body. The bubble of wind that envelops you has a number of hit points equal to your Proficiency bonus times your Ninjutsu ability Modifier. This bubble has Resistance to Wind and Lightning Damage and vulnerability to Fire Damage. If this jutsu would trigger an additional effect as listed below, as a result of a different damage type, creatures in the effects range must make a Dexterity saving throw to avoid its effects. • If the bubble would take fire damage, all creatures within 15 feet of you must make a saving throw becoming burned on a failed save as the fire spreads around you from your rotating bubble of wind. • If the bubble would take Lightning damage, all creatures within 15 feet of you must make a saving throw becoming shocked on a failed save, as lightning jumps from you to other creatures around you. • If the bubble would take Cold damage, all creatures within 15 feet of you must make a saving throw becoming chilled on a failed save, as the cold is spread to all creatures around you. • If the bubble would take Earth damage, all creatures within 15 feet of you must make a saving throw, gaining the bleeding condition on a failed save, as they are pelted with shrapnel of earth. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the size of the area affected by 5 feet, and the number of hit points your bubble has by +10. WIND RELEASE: RECOVERING BREEZE Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (30-foot-cone) Duration: Instant Components: HS, CM Cost: 8 Chakra Keywords: Wind Release, Ninjutsu, Medical Description: You create a field of medical chakra infused wind release chakra that pulses outward from you. All creatures of your choice within Range, excluding yourself, regains 5d6 hit points and removes the weakened & bruised conditions. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the amount healed by 1d6. 73 WIND RELEASE: ROTATING FEROCIOUS WIND Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you cast another Ninjutsu with the Wind Release keyword. Range: Self Duration: Instant Components: HS, CM Cost: 7 Chakra Keywords: Wind Release, Ninjutsu Description: You reinforce your Ninjutsu with additional buffeting gales of wind. Ninjutsu you cast with the Wind Release keyword prior to casting this gains a +2 bonus to its initial Saving throw DC. WIND RELEASE: SICKLE WEASEL Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction to taking damage from a melee attack or from a creature within range. Range: Self (20-foot radius sphere) Duration: Instant Components: HS, CM Cost: 8 Chakra Keywords: Wind Release, Ninjutsu Description: When you take damage you are able to collapse the circling wind around you and the triggering creature causing the wind to collide with the hostile creature creating an extremely sharp blade of wind. All creatures within 20 feet of you makes a Strength saving throw taking 5d8 Wind damage, gain 1 rank of bleed and cause Swirl on a failed save or half as much on a success. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the initial damage by 1d8. WIND RELEASE: TEARING GALE PALM Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM, M Cost: 7 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a large claw of your design made of semi-solid compressed wind chakra. You can attack with it targeting a single creature up to 30 feet away. Make a Ranged Ninjutsu Attack. Target Creature takes 4d6 Wind damage and gains 2 ranks of bleeding on a hit. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WIND RELEASE: VACUUM BARRIER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when you see a creature within range take damage. Range: 60 feet. Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a swirling vortex of air in front of a creature you can see within range right before take damage. The compressed air compresses then explodes pushing attacks and other forces back, protecting the creature. Reduce the damage the target creature takes by 2d8+4. This Damage Reduction is doubled if the damage is Lightning Damage and halved if the damage is Fire Damage. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage reduced by 1d8. WIND RELEASE: VACUUM FIELD Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action. Range: Self (30-foot Radius Sphere) Duration: Concentration, Up to 1 minute. Components: HS, CM Cost: Special (50 Chakra) Keywords: Wind Release, Ninjutsu, Fuinjutsu, Combination, Kinjutsu Description: You manifest a Seal of wind Release Chakra that glows in the air. The seal then triggers completely removing all evidence of Oxygen and atmosphere from a 30-foot radius sphere centering on you. You and all other casters are immune to this jutsu’s effects. All creatures who begin their turns in this jutsu’s range must make a Constitution Saving throw or begin immediately suffocating as they are robbed of their air in their lungs. A Suffocating creature can only survive a number of rounds equal to their Constitution modifier before passing out falling unconscious from the lack of air. An unconscious creature in this jutsu’s radius automatically takes 5d10 Necrotic Damage. A creature who’s hit points are reduced to 0 as a result of this jutsu lungs, heart and other internal organs explode while inside the body. Being unable to be revived without these organs being restored as well. An unconscious creature can regain consciousness when another creature spends an action waking them. Fire & Lightning cannot exist within this Vacuum Field and if fire or lightning, a jutsu with a Fire or Lightning Release Keyword that deals fire or lightning damage would attempt to enter this fields radius or affect a creature within this fields Radius it is immediately snuffed out and negated. Combination: If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 2d10. Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-1: No Change, +2: Increase the radius by +10 feet, +3: Increase the radius by +15 feet, +4: Increase the radius by +20 feet, +5: Increase the radius by +30 feet). 74 WIND RELEASE: VACUUM SHIELD Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Reaction which you take when you or another creature within range would take damage. Range: Self (10-foot radius sphere) Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You create a swirling vortex of air in front of you. You compress the air until the pressure implodes on itself creating a shockwave blocking attacks and reducing the lethality of attacks in your immediate area. All allied creatures in this jutsu’s radius gain 20 Temporary Hit points from the oscillating flow of wind until the end of the current turn. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and temporary hit points by 5 and the radius by 5ft. WIND RELEASE: WALL OF WIND Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 120 feet Duration: Concentration, 1 minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: A wall of strong wind rises from the ground at a point you choose within range. You make the wall up to 50 feet long, 15 feet high, and 1 foot thick. You can shape the wall in any way you choose so long as it makes one continuous path along the ground. The wall lasts for the duration. When the wall appears, each creature within its area must make a Strength saving throw. A creature takes 4d8 Slashing damage on a failed save, or half as much damage on a successful one. The strong wind keeps fog, smoke, and other gases at bay. Small or smaller flying creatures or objects can't pass through the wall. Loose, lightweight materials brought into the wall fly upward. Arrows, bolts, and other ordinary projectiles launched at targets behind the wall are deflected upward and automatically miss. Large objects such as boulders and similar objects and attacks can penetrate it. Creatures in gaseous form can't pass through it. Fire ignites the Wall of wind leaving it as a massive wall of fire. If this happens the caster of Wall of wind loses all control of it and counts as the jutsu ending. WIND RELEASE: WHIRLWIND MOVEMENT Classification: Ninjutsu Rank C-Rank Casting Time: 1 Bonus Action Range:60 Feet Duration: Instant Components: HS, CM, M Cost: 6Chakra Keywords: Wind Release, Ninjutsu Description: You generate a massive amount of wind Chakra around your feet to make an incredible act of speed. You teleport to one space within 60 feet. WIND RELEASE: WHIRLWIND SPEAR Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: Self (120-foot line) Duration: Instant Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu, Clash Description: You mold a projection made of wind release chakra that floats next to you. This projection can take the shape of any spear or piercing like object such as an arrow, lance, sword or anything you prefer. You then launch this projection in a straight line, piercing through all creatures in a 5-foot wide, 120-foot lone line originating from you. All creatures in range must make a Dexterity Saving throw taking 5d6 wind Damage and causing Swirl on a failed Save or half as much on a successful one. The first creature your projection would pass through that has the burned, chilled, corroded, shocked or envenomed condition has that condition exacerbated. That creature takes 2d10 fire damage if they are burned, cold damage if they are chilled, acid damage if they are corroded, lightning damage if they are shocked or poison damage if they are envenomed. On a successful save no additional damage is done. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and 1d10. WIND RELEASE: WHIRLWIND THRUST Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Action Range: 90 feet Duration: Instant Components: HS, CM Cost: 8 Chakra Keywords: Wind Release, Ninjutsu Description: You create an updraft of cycling wind release chakra that erupts from the ground under a group of creatures. Select a space within range. All creatures within 15 feet of the selected space must make a Strength saving throw. On a failed save, creatures are thrown 30 feet upwards into the air taking 3d10 wind damage and causing Swirl. If a creature cannot safely land, they take falling damage as normal. If the space this jutsu is casted overlaps with a source of Fire or Water additional effects happen. Fire: This Jutsu ignites and becomes a flaming whirlwind instead dealing 3d12 fire damage instead of 3d10 Wind Damage. Creatures must also succeed a Constitution saving throw gaining the burned condition on a failed save. Water: This jutsu becomes swirled with a powerful torrent of Water instead dealing 3d12 Cold damage instead of 3d10 Wind Damage. Creatures must also succeed a Constitution saving throw gaining the chilled condition on a failed save. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10 or 1d12. 75 WIND RELEASE: WIND FRICTION SHATTER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Bonus action Range: Touch Duration: Concentration, 1 minute Components: HS, CM Cost: 8 Chakra Keywords: Wind Release, Ninjutsu Description: You coat a creature whom you touch body in a layer of spinning air. The air removes most friction from its body allowing them to move at breathtaking speeds, with little resistance. They gain +1 bonus to their AC, a +20 bonus to speed, advantage on Dexterity saving throws and they gain the Friction Break special action at the start of each of their turns for the duration. Friction Break. This special action can be used to either make one additional Weapon Attack, Disengage, or use an object action. WIND RELEASE: WIND RIDER Classification: Ninjutsu Rank: C-Rank Casting Time: 1 Bonus Action Range: Touch Duration: 1 Minute Components: HS, CM Cost: 9 Chakra Keywords: Wind Release, Ninjutsu Description: You touch a willing creature you can see within range coating them in Wind Release Chakra. For the duration, the target creature gains a 30ft flying speed, but at the end of their turn they must be within 5 feet of the ground. The creature cannot suffer falling damage as they are always carried by the wind to a safe landing. Additionally, the creature is always floating at least 5 feet off the ground for the duration. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. Starting at A-rank, an affected creature no longer needs to end its turn within 5ft of the ground. B-RANK: WIND RELEASE: 10,000 SLICING BLADES Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Self (30-Foot radius Sphere) Duration: Concentration, up to 1 Minute Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: You create a dome of spinning wind, centering on you. The wind spins, whips and blows at 120 mph generating an innumerable number of blades made of wind chakra. These blades fly freely throughout your dome. Anything not weighted down is picked up and thrown around the dome and sliced to pieces. Creatures, excluding you, in this dome of wind when it is cast, who first enters or begins their turns within the dome, must make a Strength saving throw taking 5d10 Wind damage and are thrown 20ft in a random direction, fall prone, and cause Swirl on a failed save or half as much on a successful one. The area within the dome is counted as difficult terrain even for flying creatures. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 WIND RELEASE: BACKLASH Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Reaction, when you would suffer the effects of or take damage from a Ninjutsu Range: Self Duration: Instant Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vortex that spins counterclockwise just before an attack hits you. Make a Ninjutsu Ability Check vs the Rank DC of the triggering jutsu. The Rank DC equals 13 + the Jutsu’s Rank (D-Ran k: 1, C-Rank: 2, B-Rank: 3, A-Rank: 4, S-Rank: 5). If you roll Higher, the triggering jutsu’s effect is nullified and the caster of the jutsu takes the damage and effects of their own Jutsu. On a failure, you take the damage as they break through your jutsu. 76 WIND RELEASE: CHERISHING BREEZES Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: Touch Duration: Instant Components: HS, CM Cost: 12 Chakra Keywords: Wind Release, Ninjutsu, Medical Description: You inhale once, filling your lungs with Air that you mix medical release chakra. You then attempt to pass this air from your lungs into the lungs of another who have either died within the last minute or are dying. This can be done in a number of ways such as CPR, a kiss, simply manipulating the air to exit your lungs and enter the downed creatures. When you do, the dead or dying creature makes a Constitution Saving throw adding 2d4 to their roll vs a DC 15 + 1 for each round they have been dead. On a Success, they immediately end the dead or dying condition regaining consciousness with 1 Hit Point and a number of Temporary Hit points equal to three times your Ninjutsu Save DC. These Temporary hit points last for 10 minutes. WIND RELEASE: DIVINE MOUNTAIN WIND Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 13 Chakra Keywords: Wind Release, Ninjutsu Description: You create a vortex where you can control the Strength for the wind. Make a ranged ninjutsu attack targeting a creature you can see within range. On a hit target creature takes 8d6 wind damage and gains 2 ranks of bleed, as the wind slices into them with enough force to upheave the ground upon impact. If there are any sources of fire in the line of fire between you and your target this jutsu ignites into a stream of fire. Increase the damage by 5d4 fire damage. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 WIND RELEASE: GALE BLADE Classification: Ninjutsu Rank: B-Rank Casting Time: 1 Action Range: 90 Feet Duration: Instant Components: HS, CM Cost: 14 Chakra Keywords: Wind Release, Ninjutsu Description: You create a super thin blade of cutting wind that slices through everything in a", created_at: NOW, updated_at: NOW },
  { _id: "4932615037cddd0b10d89f3c", name: "VIOLENT STRANGLING", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "19 Chakra", components: "CM, M", duration: "Instant", description: "With a sudden movement you grip a targets throat with such speed most don’t get a chance to react. Make a melee taijutsu attack against the target. On a hit, the target is grappled and restrained. The target also cannot make hand seals as you hold one of their hands. The target also gains 2 ranks of Exhaustion. At the end of each of the targets turns they gain 2 ranks of Exhaustion. As an Action, on each of the targets turns, they can make a Strength saving throw to escape your grip on a success. When a creature would escape this jutsu they lose all ranks of Exhaustion gained from this Jutsu", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d42b1915aaa7db119e5007b2", name: "WORLD BREAKER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (60-foot Cube)", chakra_cost: "19 Chakra", components: "CM, M", duration: "Instant", description: "You strike the ground with such force that you destroy the surrounding area with little concern. All creatures in a 60-foot cube originating from you must make a Dexterity saving throw taking 10d10 bludgeoning damage as the surface is destroyed and pieces of the ground shoot out in random directions. The affected area is counted as difficult terrain and creatures that are greater than 10 feet from each other are heavily obscured from one another. If this jutsu is used as a Finisher, all creatures who fail their saving throw gain 3 ranks of Bruised.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. S-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "7ce903b644432b6311686f96", name: "BLACK NERIUM", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "30 Chakra", components: "CM, M", duration: "1 minute", description: "You attempt to press a point on the base of a hostile creatures neck. When you do, you reverse their bodies blood flow completely throwing their heart off and causing blood vessels to explode. Make a melee taijutsu attack. On a hit, the target must make a Constitution saving throw at the beginning of each of their turns for the next minute. Each time they would fail their saving throw, they suffer a -1 penalty to their Strength, Dexterity and Constitution ability checks, skill checks, attack rolls and saving throws for the duration and suffer 5d6 necrotic damage which cannot be reduced or resisted by any means. A creature who would fail all 10 saving throws, dies. As every blood vessel in their body collapses. A creature who is targeted with a Jutsu with the medical keyword that would end conditions or restore hit points cast at S- Rank, has this jutsu’s effect immediately end.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "169f588cfc14af1607ba20f1", name: "BLUE ROSE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (30 Chakra)", components: "CM, M", duration: "1 minute", description: "You enter a state of absolute passion and ambition. You gain two additional Bonus Actions for the duration. While gaining the benefit of this jutsu, you cannot gain the benefit of Ninjutsu, Genjutsu, Taijutsu or Bukijutsu that would provide you with additional special actions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d2704b14d7e3868f90008d24", name: "CRIMSON SKIES", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (45-foot cylinder)", chakra_cost: "25 Chakra", components: "CM, M", duration: "Instant", description: "You punch skyward with enough force to ignite the air around you, sparking flames and cinder to erupt. This creates an updraft of flames made by pure kinetic friction. This in turn turns the sky red for any creature who is within 1 mile of you. This sudden change in atmospheric pressure creates a sudden shift in air pressure creating a massive cyclone that lasts for but a moment. 254 All creatures (excluding you) within 45 feet of you must make a Strength saving throw. On a failed save, they take 10d8 fire damage from the spark of flames or half as much on a success Immediately after, all creatures in the same area must remake their saving throw. Creatures who failed their first saving throw makes this second saving throw at disadvantage. On a failed second saving throw, creatures are thrown 120 feet in a random direction taking 10d8 bludgeoning damage as they strike the ground or a solid surface. On a successful save, they take half damage and are instead thrown only 60 feet in a random direction.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5df1ad77c9877f47fc852242", name: "DAYTIME TIGER", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "20 Chakra", components: "M", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu Finisher. As part of the requirements of this jutsu, you must have at least the “Sixth Heavenly Breath: Gasp” or the 7th Gate of Wonder of the 8 Inner Gates class feature active. You take your palm and tap it with a closed fist creating a vortex of air pressure. Make a range Taijutsu attack. On a hit the target takes 10d12 bludgeoning and 10d12 force damage. Each creature within 30 feet around the target creature must make a Dexterity saving throw. A target takes 10d10 Force Damage on a failed save, or half on a successful one.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "08e01412f62399cfc4d5ef0e", name: "DREADNAUGHT GUARD", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (35 Chakra)", components: "CM, M", duration: "Special", description: "As a part of casting this jutsu, you must currently have both the Royal Guard and Royal Revenge Taijutsu on your known jutsu list. You take everything learned from both of the aforementioned jutsu and apply it to yourself in the most literal fashion. You generate a hazy, but dense aura of chakra around yourself designed to protect you from basically all forms of damage. For the duration this jutsu adjusts your physicality in the following ways. Once you use this jutsu, you cannot gain its benefits until you complete a long or full rest. • Your speed is reduced by 15 feet. • You cannot cast or maintain Ninjutsu or Genjutsu. • You gain a number of Temporary Hit Points equal to 10 times your Taijutsu save DC. o This jutsu lasts for 10 minutes or until the temporary hit points granted by this jutsu is reduced to 0. • For the duration of this Jutsu, you spend half as much chakra to reduce damage with Royal Guard.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d1df0d404f62ea8040b960f5", name: "EVENING ELEPHANT", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 Feet Line", chakra_cost: "21 Chakra.", components: "M", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu Finisher. This is the ultimate culmination of offensive taijutsu. As a part of the activation of this jutsu, you must currently be under the effects of at least either Sixth Heavenly Breath: Gasp Taijutsu or 7th Gate of Wonder or higher. Make 5 Taijutsu attacks against a target. Each attack you make is treated as a shockwave that affects all creatures in a 15-foot-wide, 60 feet long line behind your initial target. On a hit, the target creature takes 5d10 bludgeoning damage. All creatures behind the target creature must make a Dexterity saving throw taking 5d8 force damage on a failed save or half as much on a successful one. (This Jutsu cannot score a critical hit)", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e2ab3218ec48093e40243f5f", name: "FINAL FURY", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "Special (88 Chakra)", components: "CM, M", duration: "Instant", description: "This jutsu can only be cast if you have one other caster who is within 15 feet of you. The second caster as a part of their reaction moves to a space within 5 feet of you that they can occupy. You and the second caster perform a joint combined series of strikes attacking vital points across a targets body. Each caster make three melee taijutsu attacks, dealing their unarmed damage + 5d8 on a hit. If both casters successfully hit their target with all of their attacks the target must make a Constitution saving throw vs the Taijutsu save DC of the caster with the highest DC. On a failed save the target gains 5 stacks of the Weakened condition for the next 24 hours. Combination: When this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. • +0-1: No Change. • +2-3: Both casters gain a +2 bonus to their taijutsu attack rolls. • +4-5: Both casters gain a +2 bonus to their taijutsu attack 255 rolls, +1d4 bonus to damage rolls and a +1 bonus to their taijutsu save DC.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ebc7637ee6782e6f3eee5836", name: "HELL ON EARTH", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (60-foot sphere)", chakra_cost: "35 Chakra", components: "CM, M", duration: "Instant", description: "As a requirement of casting this jutsu you must target a prone creature. This jutsu can only be cast as a Finisher. You raise your hand to the sky, beckoning the heavens and projecting your essence of self into you hand. You then attempt to create a direct fissure through the prone target into the underworld with a single blow. When you strike the target, you also create a 60-foot radius sphere of destruction powered by your essence alone. Make a single melee taijutsu attack. On a hit, you deal 10d12 +80 bludgeoning damage. Regardless of a hit or miss, all creatures, excluding you and the original target, must make a Dexterity saving throw taking 10d8 + 80 bludgeoning damage on a failed save, or half as much on a success. After using this jutsu, you cannot use it again until you complete a rest. If you attempt to use this jutsu a second time before you complete a rest, you must also spend 5 Hit dice in addition to the chakra cost.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9bbb3e819d7b51aa474d469f", name: "LEAF DRAGON GOD", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "28 Chakra.", components: "M", duration: "Instant", description: "An Ultimate taijutsu created by a legendary master. You perform an upward spin kick which quickly becomes a pressurized tornado that shapes itself into a dragon with long whiskers. Move yourself up to 120 feet in any direction even turning corners and up walls. All creatures who you pass within 5 feet of, must make a Strength saving throw being pulled into the tornado and thrown to the end of it landing 5 feet in front of where ever you end your movement, taking 12d8 bludgeoning damage and taking additional damage as if they were falling. On a successful save they only take half damage. Creatures take twice the amount of falling damage as a result of this jutsu. Creatures who fail the Strength saving throw must also succeed a Constitution saving throw being slashed by the debris this taijutsu picks up taking 6d8 slashing damage on a failed save or half as much on a successful save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "81d3fc0d77d8b8cec0538cdb", name: "NIGHT GUY", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "Special (1 Chakra)", components: "CM, M", duration: "Instant", description: "As a part of casting this jutsu, you must currently have at least the Seventh Heavenly Breath: Exhale or the 8th Gate of Death from the 8 Inner Gates Taijutsu Specialist, Passionate Youth class feature active. You begin to emit an enormous amount of red steam, known as the ‘Steam of Blood’, and your chakra manifests into a red burning beast of your description around your body. You then shout an activation word of your choice, before dashing forward with such force that space in front of you becomes distorted. You may select any creature or space you can see or within 120 feet of you. You move in as straight a line as possible. You move through all structures, environmental obstructions and anything similar as if you could phase through them. You ignore summoned constructs and structures created by Jutsu, features or traits. Additionally, the target cannot gain the benefits of any Reaction they use until the beginning of their next turn. You then kick, with the force required to distort time and space. Make a melee taijutsu attack, at advantage, rerolling any result that’s less than 8 on the die. On a hit, the target must succeed a Strength Saving Throw. On a failure, they are reduced to 0 Hit Points and their body is atomized, becoming unable to be revived by any means. On a success you instead deal Xd12 + 100 bludgeoning damage, where X = the casters level + Proficiency + Taijutsu ability modifier. At the conclusion of this attack, all of the blood in the users body is boiled out of them, forcing the end of their Heavenly breaths and/or 8 Inner Gates, they then begin to turn to ash, crumbling into dust over the course of the next minute.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "22f105079f1ef86bada93d60", name: "RED LOTUS", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (30 Chakra).", components: "CM, M", duration: "1 minute", description: "You enter a state of absolute instinct and focus. You gain 2 additional Reactions for the duration. While gaining the benefit of this jutsu, you cannot gain the benefit of Ninjutsu, Genjutsu, Taijutsu or Bukijutsu that would provide you with additional special actions. 256", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bbf85f8dc538793c1591da3d", name: "SEVENTH HEAVENLY BREATH: EXHALE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "CM", duration: "Concentration, up to 10 Minutes", description: "As a requirement to activate this jutsu, you must have Sixth Heavenly Breath: Gasp currently active. You end your concentration on that jutsu and this one takes its place. You retain all of the effects and duration of that jutsu, stacking them with this jutsu’s effects. You turn off your heart’s limiters allowing it to pump an unquantifiable amount of oxygen through your body. The aura that surrounds you begins to glow far more intensely as it begins to take a shape of your choice such as a skull, eyes, or a demon. Your first two taijutsu attacks per turn gain a +5 bonus to hit and are made at advantage, deal 7d8 bonus damage, and you gain 40 Temporary Hit Points which stack with other Temporary Hit Points granted by Heavenly Breath taijutsu. Upon ending this jutsu, you gain 7 ranks of the weakened condition and 7 ranks of the slowed condition until you finish a one week of downtime. This cannot be removed or ended early by any means.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b7760e9261af8f44d5b11145", name: "SSSTYLISH COMPLIMENTS", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (30 Chakra)", components: "CM, M", duration: "Special, up to 1 minute", description: "You begin to perform a series of extremely disrespectful movements designed to not only show how absolutely amazing you are, but how woefully unprepared your enemies are to deal with someone of your caliber. While you are under the effects of this jutsu you gain the following; • For the next minute, each time you would score two successful hits on a creature you gain a +1 bonus to your AC and saving throws until the beginning of your next turn, to a maximum of +5. • For the duration, you cannot suffer penalties to your AC, attack rolls or saving throws. • When you would succeed a saving throw that would inflict a condition or deal damage, you instead suffer no effects or damage. • When a creature would miss you with an attack, you may take the Attack Action targeting the triggering creature. • The first time you would take damage, or suffer any hostile creatures effect, this jutsu immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1793db97f2d6254e3022e3b8", name: "THE LAST WALTZ", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (5 feet)", chakra_cost: "26 Chakra", components: "M", duration: "Concentration, up to 1 minute", description: "You can only cast this jutsu while you are adjacent to at least one hostile creature. The hostile creature(s) you are adjacent to must make a contested Strength or Dexterity (Martial Arts) check vs your Strength or Dexterity (Martial Arts) check. If the adjacent creatures fail the contested check, for the duration, when they would move or teleport away from you, you may move up to your movement speed to become adjacent to them again. (This does not spend any movement if you move on another creature’s turn.) Different dimensions count as an infinite distance away. When you move up to someone, you may take the Attack Action targeting them. On a hit, they cannot target any other creature with a melee or ranged attack except for you until the end of the current turn. Additionally, when you would take the Attack Action, you can take one Attack Action targeting each creature adjacent to you individually.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "09a87e801dbae0fee21aa514", name: "WHITE LILY", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "Special (25 Chakra)", components: "CM, M", duration: "Concentration, up to 1 minute", description: "You press a point on the base of a willing ally’s spine. When you do, you release their bodies limited synapse response time, enhancing it, allowing an allied creature to move at the speed of thought. For the duration, the target gains an additional Bonus Action and Reaction. The target of this jutsu cannot concentrate on any other jutsu for the duration. After one minute their body slows down, becoming weakened for 1 hour. You cannot target yourself with this jutsu. If a creature benefiting from this jutsu gains 2 or more ranks of Shocked, they become Stunned until the end of their next turn. A creature cannot gain the benefits of this jutsu more than once per rest. 1 BUKIJUTSU Bukijutsu (Literally meaning: sword hidden in the hand techniques) pertains to techniques that entail the throwing of shuriken, kunai, Senbon, or any other number of hand-held weapons. Bukijutsu can be used in combination with Taijutsu, ninjutsu, and/or chakra flow in order to create more devastating techniques Special Effect: Chain. Jutsu with this keyword are a link in the dance of steel, and as such have steps: 1, 2, and 3. Jutsu with the Chain X keyword have different effects when cast in a chain. The first jutsu you cast with the Chain keyword is considered Chain 1. The next is considered Chain 2, and then Chain 3. Once you cast a Chain 3, your chain resets to 0. You cannot cast a Jutsu with this keyword that has the same name, more than once per chain. Your Chain value cannot be raised outside your turn, and casting a Jutsu without the chain keyword interrupts your chain, resetting it to 0. D-RANK:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a6b96cf8da2f0d0bfdccca37", name: "1 -SHOT CRUSHING BLOW", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You perform a rising strike with your weapon striking and crushing the target from below. Make a melee Taijutsu attack using your weapon, dealing your [weapons damage] + 2d6. On a hit, the target must also succeed a Strength saving throw, reducing their AC by 1d4 until the start of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "a58a469bcf655eff652fd657", name: "1-STRIKE SLASH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You perform a wide arcing slash with your weapon, slicing into them with little wasted movement. Make a melee Taijutsu attack using your weapon, dealing your [weapons damage] + 2d6. On a hit, the target must also succeed a Constitution saving throw gaining 1 ranks of bleeding on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "1ec9a46d706520e10717f3e3", name: "2-CROSS STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You perform a double striking slash with your weapon, attacking two different angles forming an “X” at the intersections of the attack. Make two melee Taijutsu attacks using your weapon dealing your [weapons damage]. On each hit, the target must also succeed a Constitution saving throw, gaining 1 rank of bruised on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the target suffers a -1 penalty on their save.", created_at: NOW, updated_at: NOW },
  { _id: "b3f7689c94a38b1161271ef8", name: "2-POINT PENETRATE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You perform a double strike attacking at your opponent’s shoulders or legs in an attempt to destabilize them. Make two melee Taijutsu attacks using your weapon, dealing your [weapons damage]. If a target is hit at least once, it must also succeed a Constitution saving throw gaining reducing the targets speed by 10 feet, for each successful attack, until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the target suffers a -1 penalty on their save. 258", created_at: NOW, updated_at: NOW },
  { _id: "d676c6eaf2bc3d7c43178d69", name: "36 PSI AIR CANNON [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 action", range: "30 feet", chakra_cost: "5 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You use the air itself to slash the target from a distance. As you swing your sword you launch an air- compressed projectile spiraling towards the target. Make a Ranged Taijutsu Attack against a target creature in range. On a hit, you deal your [weapons damage]+1d12. The creature must make a Dexterity saving throw, gaining 1 rank of Slowed on a failed save. If this jutsu is cast as a Chain 2, this jutsu deals an additional 2d12 damage. If this jutsu is cast as a Chain 3 the target creatures gets an additional rank of slow", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage die by +1.", created_at: NOW, updated_at: NOW },
  { _id: "846d05b65b923005932e5b5a", name: "3-LATERAL SLASH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You perform a triple strike attacking your opponent’s joints in an attempt to disarm and disable them. Make three melee Taijutsu attacks using your weapon, dealing your [weapons damage], do not add your ability modifier to the damage dealt. Once, if you would deal damage with this jutsu, the target must also succeed a Constitution saving throw dropping any weapon they have, as it is then knocked 10 feet away from them, and being dazed until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the target suffers a -1 penalty on their save.", created_at: NOW, updated_at: NOW },
  { _id: "1b824f020882f6d3f0cffe1c", name: "3-POINT PIERCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You perform a 3-point strike in multiple points made to penetrate the target's defense. Make three melee Taijutsu attacks with your weapon, dealing your [weapons damage], do not add your ability modifier to damage dealt. The target must also make a Constitution saving throw. On a failed save they gain one rank of weakened until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the target suffers a -1 penalty on their save.", created_at: NOW, updated_at: NOW },
  { _id: "c487178b1a1abbb10b0486e6", name: "ACHILLES HEEL [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "5 Chakra", components: "W (Melee Piercing), M", duration: "1 minute", description: "You aim to cripple your target by aiming at the weak point in their armor. Target one creature in range that is wearing armor. Make a Martial Arts check vs their AC. If you roll higher than their AC, you have noticed their weak spots in their armor. For the duration you ignore any DR from their Armor and their AC is reduced by 1. This jutsu ends early if you lose sight of them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "41e23d9a7686585b7cbc9e82", name: "ARROW NOTCH SLASH [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Weapon range", chakra_cost: "5 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You slice into a creature in an instant slash, leaving no room for interference. Only the target creature can react to this jutsu. Make a Melee Taijutsu Attack against a target creature in range. On a hit, you deal your [weapons damage]+2d4 and you can choose to move 10 feet away from the creature before the damage is rolled.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 2d4", created_at: NOW, updated_at: NOW },
  { _id: "0b5285e231e235f90c57f3d7", name: "BIDING FURY STANCE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "W (Any Power), M", duration: "1 minute", description: "You enter a stance to absorb the damage you take to prepare to dish out even more. Every time you are hit or would react to an attack to make it miss you gain 1 Fury. You can hold a number of Fury equal to your level at a time. This Fury can be spent on other jutsu with the “Binding Fury-” Prefix. 259", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "518713a3ce7db00bec531a9d", name: "BIDING FURY: DRAGON FLURRY [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "weapons range", chakra_cost: "4 Chakra", components: "W (Any Power), M", duration: "1 minute", description: "(Must be under the effects of a Binding Fury Stance to cast) You perform a rapid combo of attacks to break down your enemy. Make two melee Taijutsu Attacks, dealing your [weapons damage]+ 1d4 on a hit. If you land both attacks, you can spend 2 or more Fury to make an additional attack per Fury spent, up to 4 attacks.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8bd51bc39af027de7e6db296", name: "BIDING FURY: HORIZONTAL BLOCK [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 reaction to taking damage", range: "weapons range", chakra_cost: "4 Chakra", components: "W (Any Power), M", duration: "1 minute", description: "(Must be under the effects of a Binding Fury Stance to cast) When you would be hit with an attack, you can spend 2 or more Fury to try and parry the damage. Roll your [weapons damage die] a number of times equal to the amount of Fury Spent and reduce the damage taken by the rolled amount. If you would reduce this damage to 0, make a number of attacks per every 2 Fury spent, dealing your [weapons damage die] on a hit.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "16925fd029dc9b910832d5c9", name: "BLADE OF SIN: SLOTH [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 action", range: "Weapon range", chakra_cost: "5 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You seek to emulate the power of one of the Seven Deadly Sins of Humanity in your blade, imbuing the Sin of Sloth inside the edge. Make a melee Taijutsu Attack against a creature in range. On a hit you deal your [weapons damage]+1d8. The target creature must make a Constitution saving throw. On a failure, they move down the initiative tracker as they lose the motivation to act as fast as before. If this jutsu is cast as a Chain 2, it deals an additional 2d8 damage. If this jutsu is cast as a Chain 3 has disadvantage on its Constitution Saving throw.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d12. Starting at A-rank, if the target is the last in initiative when they would fail their saving throw, they instead cannot move or act until the end of their next turn.", created_at: NOW, updated_at: NOW },
  { _id: "6bdd539670d59b6c03815af1", name: "BLUNT STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Any Ranged Bludgeoning), M", duration: "Instant", description: "You ready your weapon before you bludgeon the weapon with your chakra and aim for your target's core striking at the center of their chest. Make a ranged Taijutsu Attack using your weapon, dealing your [weapon’s damage] + 2d4 but as bludgeoning damage. On a hit, the target must succeed a Constitution saving throw. On a failed save, the target is Dazed and if they would make a concentration check to maintain a Genjutsu or Ninjutsu, they roll an additional 1d8, reducing their check by the result.", at_higher_ranks: "For each rank, you cast this jutsu above D-Rank increasing the cost of this jutsu by 3 and the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "17fe814118154328ef959a23", name: "BOUNCE CHAIN RICOCHET [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Any Thrown), M", duration: "Instant", description: "You make your attack with the aim that it hits as many people as possible. Make a ranged Taijutsu Attack against a creature in range On a hit, you deal your [weapon’s damage]+1d8. On a hit, you can make a second ranged Taijutsu Attack against another creature in range with a -2 penalty to the attack roll. If this second attack hits, you can make a third attack against a creature in range, this time with an additional -2 penalty.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d8. 260", created_at: NOW, updated_at: NOW },
  { _id: "2406882502bd42896930e701", name: "BREATH OF ASH: SCORCH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest fire release chakra until it laces the striking portion of your weapon. The fire release chakra begins to transform into gouts of ash that emanate off of your weapon with a menacing haze. Select a creature you can see in range and make a single ranged Taijutsu attack, with a +1 bonus to your critical threat range. On a hit, you deal your [weapons damage] + 2d6 fire damage and the target is overwhelmed by the ash causing them to be blinded until the beginning of their next turn, or the first time they are targeted by an attacked before their turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at B-Rank, you can target a second creature with this jutsu. If this jutsu is cast at S-Rank, you can target a third creature with this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "1ca7ff2c30bddee09958c279", name: "BREATH OF BEASTS: FANG", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest chakra until it laces the striking portion of your weapon. The chakra begins to manifest in the form of any beast of your choice in any color that can be seen plainly by others. You begin to swing wildly and unpredictably, fueled by instinct and primal urges. Make two melee Taijutsu attacks, dealing your [weapons damage] + 1d6, you do not add your ability modifier to the damage rolled.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank or higher, increase the damage by 1d6. If this jutsu is cast at B-Rank increase the number of attacks by +1. If this jutsu is cast at S-Rank increase the number of attacks by +2.", created_at: NOW, updated_at: NOW },
  { _id: "6ef032a1d71a785baede0a9e", name: "BREATH OF DUST: SOKUSEI", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest earth release chakra until it laces the striking portion of your weapon. The earth release chakra begins to magnify the weight and striking power of your attacks allowing you tear through anything in your path is little difficulty. Make a single ranged Taijutsu attack against one creature you can see within range, this jutsu cannot score a critical hit. On a hit, you deal your [weapons damage] + 1d12 earth damage and the target is pushed back 5 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "031b03b29821400eb0f5af10", name: "BREATH OF EARTH: SMASH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self (10 feet radius)", chakra_cost: "5 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest earth release chakra until it laces the striking portion of your weapon. The earth release chakra begins to magnify the weight and striking power of your attacks allowing you crush anything in your path is little difficulty. You fool your opponent(s) into thinking you are striking and suddenly shift your attack into another angle. All creatures within range who’s Taijutsu ability score, is lower than your own suffers a 1d4 penalty to this jutsu’s saving throw. All creatures of your choice must make a Dexterity saving throw. On a failed save they take your [weapons damage] + 2d6 earth damage and are knocked prone and bruised on a failed save, or half as much and no further effects on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6 and the radius by 5 feet. If this jutsu is cast at B-Rank, creatures would instead suffer a 1d6 penalty to this jutsu’s saving throw. If this jutsu is cast at S-Rank, creatures would instead suffer a 1d8 penalty to this jutsu’s saving throw. 261", created_at: NOW, updated_at: NOW },
  { _id: "2b294c1dfced835490a1f087", name: "BREATH OF ECHO: REVERB", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "CM, W (Any Range), NT (Any explosive tool),", duration: "Instant", description: "You begin to collect and manifest chakra until it manifest into the shape of a sound note of your choice, hovering over the striking portion of your weapon. This note can be seen plainly by any other creature who can manipulate chakra. You fire two powerful shots creating an explosion of sound able to disorient your foes on contact. Make two ranged Taijutsu attacks, dealing your [weapons damage]. On each hit, the target and all creatures within 5 feet of them, must make a wisdom saving throw, being dazzled on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d4. If this jutsu is cast at C-Rank or higher, increase the number of attacks by +1. If this jutsu is cast at B-Rank or higher, the target is also dazed on a failed save.", created_at: NOW, updated_at: NOW },
  { _id: "2f6f45764508dfb0e656d6c0", name: "BREATH OF ENOKI: INFEST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action.", range: "Self", chakra_cost: "5 Chakra", components: "CM, W (Any Ranged), M", duration: "Concentration, up to 1 minute.", description: "You begin to collect and manifest medical chakra until it laces the striking portion of your weapon. The medical chakra begins to cause your weapon to glow with a soft pink hue. For the duration when you would deal damage with a weapon attack or Taijutsu attack using this weapon, once per turn the target must make a Constitution saving throw, reducing their AC by 1 for the duration. A creature can only have their AC reduced by this jutsu twice.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the AC reduction limit increases by 1.", created_at: NOW, updated_at: NOW },
  { _id: "9044f61be2c6e69aeada8859", name: "BREATH OF FLAME: UNKNOWING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "5 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest fire release chakra until it laces the striking portion of your weapon. The fire release chakra begins to transform into gouts of flame that erupt off of your weapon with a glorious flickering. You then dash towards your target and perform a single powerful swipe attempting to decapitate them in one strike. Select a creature you can see that you could reach using your full movement. Move into a space adjacent to the target creature within your movement range. Make a single melee Taijutsu attack against one creature you can see, with a +1 bonus to your critical threat range. On a hit, you deal your [weapons damage] + 2d6+2 fire damage. If this jutsu scores a critical hit, the target gains 1 rank of burned.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and your critical threat range by +1. If this jutsu is cast at B- Rank, increase your damage by 1d6+1. If this jutsu is cast at S-Rank, when you score a critical hit with this jutsu, you instead quadruple the fire damage of this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "7dc66b85f4edfef9729ffd7e", name: "BREATH OF RAIN: CUMULOUS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Weapons range", chakra_cost: "5 Chakra", components: "CM, W (Any Range), M", duration: "Instant", description: "You begin to collect and manifest water release chakra until it laces the striking portion of your weapon. The water release chakra begins to transform into streams of water, capable of being seen and felt as you release your weapon and it follows and flows around it with an enhanced strike. Make a single ranged Taijutsu attack against one creature you can see. On a hit, you deal twice your [weapons damage die] + your Taijutsu ability modifier cold damage and the target must make a Constitution saving throw being dazed on a failed save. This jutsu’s attack roll cannot be made at disadvantage or with any penalties to hit as a result of a condition or hostile creatures Jutsu's, traits or features.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and your [weapons damage die] by +1. If this jutsu is cast at C-Rank or higher, if the target of your attack is prone or dazed, you gain a +1d4 bonus to hit. If this jutsu is cast at B-Rank or higher, and the target of your attack is prone, weakened or dazed, you instead gain a 1d6 bonus to hit. If this jutsu is cast at S-Rank, this jutsu’s attack roll is also made at advantage, regardless of circumstance. 262", created_at: NOW, updated_at: NOW },
  { _id: "ddf9334fecb2540206d8be9e", name: "BREATH OF ROSES: PLUM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Reaction, which you take when you take damage, excluding from a genjutsu", range: "Self (5 Feet)", chakra_cost: "5 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest medical chakra until it laces the striking portion of your weapon. The medical chakra begins to cause your weapon to glow with a soft pink hue. When you would take damage you begin to make a series of rotating strikes to deflect as much damage as possible. Reduce the damage you would take by your [weapons damage] + 2d8. Additionally, all hostile creatures adjacent to you must make a Dexterity saving throw, taking poison damage equal the amount of damage you reduced as a result of this jutsu or half as much on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage reduced by 1d8. If this jutsu is cast at C-Rank or higher, increase the range hostile creature can take damage from this jutsu to 10 feet. If this jutsu is cast at B-Rank or higher, increase the Damage Reduction die size to a d10. If this jutsu is cast at S-Rank, creatures who fail their saving throw as a result of this jutsu takes double damage.", created_at: NOW, updated_at: NOW },
  { _id: "e13a0887812d61bc8f30955b", name: "BREATH OF SKIES: CLOUD FALL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest wind release chakra until it laces the striking portion of your weapon. The wind release chakra begins to spiral around the users weapon creating whipping torrents of wind. This wind propels backs up your ability to propel this weapon with the force needed to cut through a cloud and pierce the sky. Make a two ranged Taijutsu attacks against one creature you can see within range. On a hit, you deal your [weapons damage die], in wind damage, inflicting a rank of bleeding on a hit. You do not add your ability modifier to the damage rolls of this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "9e274a44e30644b428997652", name: "BREATH OF SOUND: ROAR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (15-foot radius sphere)", chakra_cost: "5 Chakra", components: "CM, W (Any Melee), NT (Any explosive tool),", duration: "Instant", description: "You begin to collect and manifest chakra until it manifest into the shape of a sound note of your choice, hovering over the striking portion of your weapon. As your chakra manifests, all surrounding sound becomes muffles and you enter a deep state of focus. You attach the explosive tool to your weapon and perform a symphony of swings as the tag readies to detonate. All creatures, excluding yourself, must make a Wisdom saving throw, taking your [weapons damage] + 1d12 and becoming dazzled and blinded on a failed save, until the beginning of their next turn. For each rank of quality your explosive tool is above its base quality, creatures suffer a -1d4 to their saving throw.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage of this jutsu by 1d12. If this jutsu is cast at B-Rank or higher, they are instead blinded until the end of their next turn.", created_at: NOW, updated_at: NOW },
  { _id: "f104704260d84b7f167361a2", name: "BREATH OF SPARKS: JOLT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest lightning release chakra until it laces the striking portion of your weapon. The lightning release chakra begins to collect and spark off of your weapon with violent jolts. You prepare for multiple powerful shots. Roll 1d4, recording the result. Select a number of creatures you can see within range equal to the result, as you fire off a volley of lightning charged shots to each. Make a ranged Taijutsu attack against each target creature, dealing twice your [weapons damage die] + 1d8 lightning damage. You do not add your ability modifier to the damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the initial die used to determine the number of target creatures by 1 step (D4>D6>D8>D10>D12). If this jutsu is cast at C-Rank or higher, increase the damage by 1d8. If this jutsu is cast at B-Rank or higher, increase your [weapons damage die] by 1. If this jutsu is cast at A- Rank or higher, increase the damage by 1d8. If this jutsu is cast at S-Rank, increase your [weapons damage die] by 1. 263", created_at: NOW, updated_at: NOW },
  { _id: "7597c2f00a986b46dc94f8dc", name: "BREATH OF THUNDER: FLASH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "5 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest lightning release chakra until it laces the striking portion of your weapon. The lightning release chakra begins to collect and spark off of your weapon with violent jolts. You prepare for a single powerful strike. Select a creature you can see that you could reach using your full movement. Move into a space adjacent to the target creature within your movement range. Make a single melee Taijutsu attack against the target creature. On a hit, you deal your [weapons damage] + 2d10 lightning damage and if the target is benefiting from temporary hit points, you deal damage to the creatures hit points and temporary hit points simultaneously. You do not add your ability modifier to the damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d10. If this jutsu is cast at C-Rank, you can select a second creature within 30 feet of your original target and move into a space adjacent to them making a second attack. If this jutsu is cast at B-Rank, select a third creature within 30 feet of the second target and move into a space adjacent to them making a third attack. If this jutsu is cast at A-Rank or higher, select a fourth creature within 30 feet of the third target and move into a space adjacent to them making a fourth attack.", created_at: NOW, updated_at: NOW },
  { _id: "198380c2a312eb9a11b30b7f", name: "BREATH OF WATER: SURFACE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Weapons range", chakra_cost: "5 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest water release chakra until it laces the striking portion of your weapon. The water release chakra begins to transform into streams of water, capable of being seen and felt as you then move to strike with a powerful concentrated attack. Make a single melee Taijutsu attack against one creature you can see. On a hit, you deal your [weapons damage] + 1d10 cold damage and the target must make a Strength saving throw being dazed on a failed save. This jutsu’s attack roll cannot be made at disadvantage or with any penalties to hit as a result of a condition or hostile creatures Jutsu's, traits or features.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d10. If this jutsu is cast at C-Rank or higher, if the target of your attack is prone or dazed, you gain a +1d4 bonus to hit. If this jutsu is cast at B-Rank or higher, and the target of your attack is prone, weakened or dazed, you instead gain a 1d6 bonus to hit. If this jutsu is cast at S-Rank, this jutsu’s attack roll is also made at advantage, regardless of circumstance.", created_at: NOW, updated_at: NOW },
  { _id: "ae04dba755ab12f52b219a84", name: "BREATH OF WIND: CUTTER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest wind release chakra until it laces the striking portion of your weapon. The wind release chakra begins to spiral around the users weapon creating whipping torrents of wind. You use this enhanced field of wind to propel you towards your enemy. Make a three melee Taijutsu attacks against one creature you can see within range. On a hit, you deal your [weapons damage die], in wind damage, but you do not add your ability modifier to your [weapons damage].", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the number of attacks by +1. BURST FIRE (NEW, REPLACES SCATTER", created_at: NOW, updated_at: NOW },
  { _id: "477634cf7b9283ffb6436b07", name: "BURST FIRE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Self (45-foot cone)", chakra_cost: "5 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "You ready several attacks before unleashing all of them out in front of you. All creatures in a 30-foot cone originating from you, must make a Dexterity saving throw. On a failed save you deal your [weapons damage] + 1d6. or half as much on a success. If you have to roll your weapons ammunition die, roll twice, taking the lower result. If this jutsu is cast as a Chain 2, it deals an additional 1d6 damage. If this jutsu is cast as a Chain 3 the additional damage becomes 2d8", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "9cc0a04f2efd54384888e3c0", name: "BURSTING FLING [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "5 Chakra", components: "W (Any Thrown), M, CM", duration: "Instant", description: "You imbue your weapon with chakra, turning it into a hazard even after it lands. Make a ranged taijutsu attack, on a hit you deal your [weapons damage] +1d6. Regardless of the result, the weapon shatters and its pieces create a minefield in a 10ft radius around the target, that last until the start of your next turn. The first time a creature would move within this radius, it takes 2d4 slashing damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and both damages by 1d6. 264 CARPET OF STEEL (CHANGED, WAS NEEDLE", created_at: NOW, updated_at: NOW },
  { _id: "1518c3038f2ae8ac8affe8d7", name: "CARPET OF STEEL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "45 Feet (20-Foot Cube)", chakra_cost: "4 Chakra", components: "W (Any Ammunition), M", duration: "Instant", description: "You ready a stack of your weapons and scatter them across the ground in up to 45 feet away in a 20-foot cube. The area becomes difficult terrain and creatures that move while inside the area suffer 1d4 Piercing Damage for every 5 feet they move within the area. Spaces that have already been traversed are no longer difficult terrain and no longer deal damage if moved through again.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the radius of the jutsu by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "3c7ec11234d611211bbbd2a5", name: "CHAIN PULL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "3 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You throw your weapon wrapping it around a target and pulling towards yourself. The target must succeed a Strength saving throw. On a failed save they are moved 10 feet closer to you in a straight line, cannot make handsigns until the beginning of their next turn, and also become restrained by you. At the end of the target creatures' turns, they can make a Strength saving throw to escape the restrain. If this jutsu is cast as a Chain 2, you can target an additional creature in range. If this jutsu is cast as a Chain 3, target creatures have disadvantage on the initial saving throw.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d6bf4c380612c76a23771cfc", name: "CHAKRA TOUCHED AMMUNITION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus action", range: "Touch", chakra_cost: "4 Chakra", components: "W (Any Ammunition), M", duration: "Concentration, up to 1 minute", description: "You lace all of your ammunition with chakra, enhancing both its lethality and efficiency. For the duration, whenever you would deal damage with the affected weapon with the ammunition property, you add an additional 1d4 damage of the weapon’s type, twice per turn. Additionally, when you would roll your ammunition die, roll an additional ammunition die, taking the higher result. Finally, if you would cast a jutsu that spend a whole ammunition die, you can choose to instead end this jutsu, and not spend the die.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank, increase the damage to 2d4. If this jutsu is cast at A-Rank or higher, increase the damage to 3d4.", created_at: NOW, updated_at: NOW },
  { _id: "97825414c5c57257d19bb9d4", name: "CRIPPLING STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Any), M", duration: "Instant", description: "You focus your weapons attack on crippling your enemy, to make them far less effective than they are currently. Make a melee or ranged Taijutsu attack based on the weapon used for this jutsu, dealing your [weapons damage]. On a hit, the target must make a Strength saving throw. On a failed save they are Dazed and weakened, and are also knocked prone. Additionally, if you score a critical hit with this jutsu, they make their saving throw at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the [weapons damage die] by 1.", created_at: NOW, updated_at: NOW },
  { _id: "42ebe6bd796c072484cf4756", name: "CURVED SLASH [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Any Ranged Slashing), M", duration: "Instant", description: "You perform a single throw that curves and slashes with frightening accuracy. Make a ranged Taijutsu Attack against a creature you can see within range dealing your [weapons damage] + 2d8. On a hit the creature must make a Constitution saving throw or be blinded until the end of their next turn on a failed save. If they fail by 5 or more, they are instead blinded until the end of your turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. 265", created_at: NOW, updated_at: NOW },
  { _id: "559c56d4a006aab209e37eef", name: "CUTTING VIBRATIONS [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "W (Melee Slashing), M", duration: "Concentration, 1 minute", description: "You focus your chakra into your weapon so that it vibrates at supersonic speeds, enhancing its cutting capabilities. For the duration when you deal Slashing damage with your weapon to a target wearing armor, you reduce the Armor bonus of the target creature by 1. This can only occur once per round. If this reduces their armor bonus to 0, you instead deal an extra die of [weapons damage].", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "94dd7bb502919fa3babb43b5", name: "DANCE PERFORMANCE: NEUTRAL STANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "4 Chakra", components: "W (Any), M", duration: "1 Round", description: "You draw your weapon, taking on a light stance, like that of a dancer's. For the duration of this jutsu, any Bukijutsu you cast with Dance Performance in its name has an increased critical threat range. Increase the critical threat range of Taijutsu Attack rolls of the aforementioned jutsu by +1. If the jutsu instead forces a saving throw, a creature that rolls a 1 or 2 on the d20 for their save takes double damage if they fail.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank, increase the critical threat range by +1. If this jutsu is cast at A-Rank, increase the critical threat range by +2 and if the creature would roll a 5 or lower on the d20 for the saving throw, they are considered vulnerable", created_at: NOW, updated_at: NOW },
  { _id: "5473eccd0bfa2a849a7ea8f4", name: "DANCING FOOL’S DANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You swing your weapon in a wide arc striking all creatures in the arc. Make a melee Taijutsu Attack. All creatures of your choice, within your weapons range originating from you become the target of this attack, comparing your attack result to their AC as if you attacked each one individually. On a hit, you deal your [weapons damage] + 2d4 and each creature must succeed a Dexterity saving throw. On a failed save they are knocked prone.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "9aa68a8183709b173c2d3b4c", name: "DANCING FOOL’S WHIP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "5 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You violently whip your weapon with enough force to crack the ground from the impact. Creatures in a 15-foot cube originating from you must succeed a Dexterity saving throw, being whipped repeatedly by your weapon. On a failed save, the target takes your [weapons damage] + 2d4 and gains the bleeding condition. On a successful save they only take half damage and no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "0dc4dab05a95f71e305f649c", name: "DANGER ZONE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Double your Weapon’s range", chakra_cost: "5 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You quickly spin your weapon around you, using chakra to extend its range further. All creatures within range must make a Dexterity Saving Throw. On Failure they take 3d6 Slashing damage and gain a rank of bleeding.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d6. If this jutsu is cast at A-Rank target creatures take half on a success.", created_at: NOW, updated_at: NOW },
  { _id: "ec32bed81eec7055329fb21c", name: "DEBILITATING SHOT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Any Thrown) M", duration: "1 Round", description: "You begin to throw weapons rapidly targeting your enemies pressure point to puncture them. Make a ranged Taijutsu Attack dealing your [weapon’s damage] + 4d4. The target must also make a Constitution saving throw, gaining 1 rank of weakened on a failed save as your senbons lodge themselves into their joints, or half as much damage on a successful save. A creature weakened by this jutsu can, as an action make a Wisdom (Survival) check vs your Taijutsu save DC to remove the lodged senbons on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1. 266", created_at: NOW, updated_at: NOW },
  { _id: "8206a8c7f6a7f9dfa7e294a6", name: "DEMONIC DANCE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You spin around with your weapon, a dance- like attack that bewilders enemies. Make a Melee Taijutsu Attack against all creatures in range. On a hit, you deal your [weapons damage], this damage increases by 1d4 for each creature hit.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the range of this jutsu by 5 feet. If this jutsu is cast at A-Rank, the range instead becomes your Current movement speed.", created_at: NOW, updated_at: NOW },
  { _id: "30264c1a542d5fec670cc320", name: "DEVILS GAMBIT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "W (Any), M", duration: "1 Round", description: "You take a bet fit for a devil. At the cost of enhancing your weapons lethality and accuracy you throw caution to the wind. Until the beginning of your next turn, the first weapon or Taijutsu attack made as a result of a Bukijutsu you cast, is at advantage and you increase your [weapons damage die] by 1. But in exchange for this bet, all creatures first attack made targeting you is at advantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase your [weapons damage die] by 3. If this weapon is cast at S-Rank, increase your [weapons damage die] by 5.", created_at: NOW, updated_at: NOW },
  { _id: "2b4c0f4c28460c97aa0ffad9", name: "DOUBLE SHOT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "W (Any Ranged), M", duration: "1 Round", description: "You prep two separate attacks to go off in a single attack. Before the end of your current turn, the next time you would make a ranged weapon attack, you make an additional one as a part of the same action, that must target another creature. Additionally, this additional attack benefits from any effects that would normally only affect the first or one weapon attack.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the number of additional attacks to two. If this jutsu is cast at S-Rank, increase the number of additional attacks to three.", created_at: NOW, updated_at: NOW },
  { _id: "865116ca71cfd7103b3b9ae1", name: "DOUBLE TROUBLE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Any Ranged Bludgeoning), M", duration: "Instant", description: "You perform a swift burst of 2 shots that leave the enemy staggering. Make two ranged Taijutsu Attacks using your weapon, dealing your [weapons damage] +1d6. If a target is hit at least once, it must also succeed a Strength saving throw reducing the targets speed by 10 feet, for each successful attack, until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the target suffers a -1 penalty on their save.", created_at: NOW, updated_at: NOW },
  { _id: "e883923faeb1524fd72c7844", name: "DRAGON FLY DASH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "W (Any), M", duration: "Instant", description: "You launch your weapon towards an allied creature you can see in range, ordering them to strike with it in your place. Select one willing creature you can see in range and you throw your chosen weapon to them. Until the end of the current turn, the weapon thrown retains all bonuses and effects as if you were wielding it. The target creature can spend their reaction to make one melee Taijutsu attack, targeting a creature in their range, dealing the [weapons damage] + your ability modifier. As a part of the same reaction, the allied creature can choose to throw your weapon back to you.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the number of attacks they make by +1. 267", created_at: NOW, updated_at: NOW },
  { _id: "c08674b65524044c91a65b30", name: "DRAGON SLAYER THRUST [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "15 feet", chakra_cost: "5 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You charge a thrusting attack before lashing at with precise timing to deal a lethal blow to your enemy. Make a Martial Arts check versus a target creature in range’s AC. If you roll higher, this jutsu gains advantage on the attack roll. Move up to the target creature and make a Melee Taijutsu Attack. This movement cannot provoke an attack of opportunity. On a hit, you deal your [weapons damage] and the creature must make a Constitution saving throw. On a failed save they cannot react until the end of the current turn. If this jutsu is cast as a Chain 2, you gain advantage on your Martial Arts check. If this jutsu is cast as a Chain 3 you deal twice your weapons damage on a hit.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "ffa9df01df5d50543e298e91", name: "DRAGON’S FAR-REACHING FIST [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Any Ranged Bludgeoning), M", duration: "Instant", description: "You perform a 2 quick shots that disorient and debilitate the enemy. Make two ranged Taijutsu Attacks against a creature you can see within range dealing your [weapons damage]. On each hit, the target must also succeed on a Constitution saving throw, becoming dazed on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the target suffers a -1 penalty on their save.", created_at: NOW, updated_at: NOW },
  { _id: "43e70840a8e2adfefaf4a411", name: "DRAGONFLY LANDING [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "Your jump up and then stab down with an uncounterable amount of thrusts. Make 3 Melee Taijutsu Attacks against a target creature in range. On a hit you deal your [weapon’s damage die]. If you hit a creature with at least 3 attacks, they are knocked prone as you land on top of them.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the number of attacks by 1.", created_at: NOW, updated_at: NOW },
  { _id: "2f5b77a7f6b43509da0c6a03", name: "ECHO-THRUST [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon’s range", chakra_cost: "5 Chakra", components: "W (Melee Piercing), M", duration: "Concentration, 1 Minute", description: "You pour chakra into your forearm so that you can thrust twice in one motion. The first time you would hit a creature with a weapon attack on each of your turns, you can deal damage to a second creature, that is within 5ft of both you and the original target.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a9d7eddc6ff011b782b08c6f", name: "ENHANCED BLOCKING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "W (Any Polearm), M", duration: "Concentration, up to 1 minute", description: "You brace your weapon and enter a more guarded stance. You cannot lose concentration of this jutsu as a result of damage. For the duration, while you are wielding a Polearm type weapon, you gain an additional +1 bonus to AC. Additionally, any bonuses to AC you have as a result of the blocking property or weapon seals, you add that bonus to the first Strength or Dexterity saving throw you would make each round. Also, for the duration of this jutsu, you can spend your reaction when you would take damage, to reduce the damage you take by twice your [weapons damage die]. If you reduce the damage to 0, you gain an additional reaction until the start of your next turn that can only be used to cast this jutsu again.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage you reduce by 1 [weapons damage die].", created_at: NOW, updated_at: NOW },
  { _id: "ca0e9af8110ace01df9c1df5", name: "ETERNAL EDGE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Any), M", duration: "1 minute", description: "You line your weapon with a chakra thin edge, protecting it from any damage. Your weapon cannot suffer any penalties from any trait, feature, or jutsu of equal rank or lower that would destroy or damage the weapon, or reduce their attack rolls.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3. Starting at C-Rank, the duration becomes 10 minutes. Starting at B-rank, the duration becomes 1 hour, starting at A-rank, the duration becomes 8 hours. Starting at S-rank, the duration becomes 24 hours. 268", created_at: NOW, updated_at: NOW },
  { _id: "fe6ff69b97b888810d9f8aa9", name: "EXTERMINATE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon’s range", chakra_cost: "5 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You strike twice in a X-shape in an attempt to hamper your opponent’s ability to attack back. Make Two melee Taijutsu Attacks. On a hit you deal your [weapon's damage die] +1d12. If both attacks are successful, your opponent must make a Constitution saving throw. On a failure they have a -2 to all attack rolls until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d12, and the Attack roll penalty by 1.", created_at: NOW, updated_at: NOW },
  { _id: "6eff8d531973964c6d0b3128", name: "FAR-REACHING FANG [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Double your Weapons Range", chakra_cost: "5 Chakra", components: "W (Ranged Piercing), M", duration: "Instant", description: "Your weapon is just an extension of yourself, it is your fang to defend what needs defending. You flood your weapon with chakra to enhance its ability to fly far and it’s damage power. Make a Ranged Taijutsu Attack against a creature in range. On a hit you deal your [weapons damage] +2d10 and the target creature must make a Strength Saving throw or be knockback 15 feet. If they hit a structure or construct, they are pinned to it, being grappled to the wall until they use an action to free themselves", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d8. If cast at B-rank, they are knocked back an additional 15 feet. If cast at S-rank, they are knocked back an additional 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "b3c3c81ec3ba359c13e1cabc", name: "FLASHING STREAKS [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Self (60 feet)", chakra_cost: "5 Chakra", components: "W (Ranged Slashing), M", duration: "Instant", description: "You ready yourself to throw your weapons at high speeds, making streaks of light in the air. Make a Ranged Taijutsu Attack against a number of creatures in range equal to your Taijutsu ability modifier. On a hit you deal your [weapons damage] +2d4 slashing damage and the target creature must make a Dexterity Saving Throw or gain 2 ranks of bleeding", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "694298d3e6e6079c10cb87bf", name: "FLYING SWALLOW: CROSS CUT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Any Melee dual wield), M", duration: "Instant", description: "As a part of the activation of this jutsu, you must have a weapon in both hands that meet this bukijutsu component requirements. You make two swinging cuts in a single stoke by swinging both of your weapons inward. Make a two Taijutsu attacks against up to two enemies within 5 feet of you, dealing the [weapons damage] + 1d4, and the target must make a Strength saving throw to avoid being disarmed of their weapon or item they are holding.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "d792d5317331e105378dc48f", name: "FLYING SWALLOW: SPINNING TOP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Any Melee dual wield), M", duration: "Instant", description: "As a part of the activation of this jutsu, you must have a weapon in both hands that meet this bukijutsu’s component requirements. You spin like a top striking all creatures in your immediate vicinity. All creatures within your weapons range, must make a Dexterity saving throw. On a failed save they take your [weapons damage] + 2d6 or half as much on a success. Depending on the damage type of the chosen weapons creatures who fail their saving throws suffer additional effects. • Bludgeoning: Affected creatures are knocked prone. • Piercing: Affected creatures gain 1 ranks of weakened until the end of their next turn. • Slashing: Affected creatures gain 1 rank of the bleeding condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6. 269", created_at: NOW, updated_at: NOW },
  { _id: "0c1dcb095ff61f4de6d783ed", name: "FLYING SWALLOW: STRAIGHT LINE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "4 Chakra", components: "W (Any Melee dual wield), M", duration: "Instant", description: "As a part of the activation of this jutsu, you must have a weapon in both hands that meet this bukijutsu’s component requirements. You dash in a straight line, up to 30 feet, moving through any hostile creatures space you come across, ending your movement in a space up to 30 feet away from you, in a straight line. Make two melee Taijutsu attacks. All creatures, of your choice, whose space you passed through as a result of this jutsu count as targets for these two melee Taijutsu attacks, comparing their results to each creatures AC. On a hit, you deal either of your [weapons damage] + 1d4 and the damaged creatures must make a Strength saving throw, being knocked prone on a failed save, or no further effects on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "559aef658910d309ca225860", name: "GRASS-CUTTING STRIKE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon’s range", chakra_cost: "4 Chakra", components: "W (Melee Slashing, M", duration: "Instant", description: "You swing your weapon low, in an attempt to hobble the enemy. Male a Melee Taijutsu Attack targeting one creature in range. On a hit you deal your [weapons damage] +2d4 and lower your opponents speed by half until the end of your next turn as you cut at their ankles. If this jutsu is cast as a Chain 2, it deals an additional 3d4 damage. If this jutsu is cast as a Chain 3 the damage die of this jutsu becomes d8.", at_higher_ranks: "For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and the damage die by +1.", created_at: NOW, updated_at: NOW },
  { _id: "547833d569ec7446a193313c", name: "GREAT DRAGON SHOCKWAVE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Weapon range", chakra_cost: "5 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You quickly raise and slice down with your blade with such force that it creates a shockwave. Make a Melee Taijutsu Attack against a target creature in range. On a hit, you deal your [weapons damage] +1d8. All creatures within range other than the target must make a Strength saving throw or be knocked back 15 feet.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "d74e8f1e5c7167be3aaea4f6", name: "HEAVENLY UPROAR [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "weapons range", chakra_cost: "5 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You swing upwards with a rising force to the heavens before swinging back down to bring your opponent crashing to the earth. Make a melee Taijutsu Attack against a creature in range. On a hit, you deal your [weapons damage] and the creature must make a Strength saving throw. On a fail, you make a second melee Taijutsu Attack that deals your [weapons damage] +1d12 on a hit. On a success, you make the attack but at disadvantage, and you cannot gain an advantage on this attack by any means.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "78ad548b98170187468c6d7b", name: "HIDDEN SHADOW SHOT [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Any 2 Thrown), M", duration: "Instant", description: "You throw your weapon however hiding in its Shadow is the true attack. Make a ranged Taijutsu Attack against a creature in range. The target creature must make a Perception check versus a Dc of 10+your Sleight of Hand. On a fail, this attack gains advantage and they cannot react. On a hit, you deal your [weapon's damage]. If this jutsu is cast as a Chain 2, it deals an additional 2d6 damage. If this jutsu is cast as a Chain 3 the additional damage becomes 2d8", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3. If this jutsu is cast at B-Rank increase the number of attacks by 1. At S- Rank this jutsu gains an additional attack. 270", created_at: NOW, updated_at: NOW },
  { _id: "4a132f515fc4cfe0248b5c05", name: "HIDDEN WEAPON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Weapon Range", chakra_cost: "3 Chakra", components: "W (Any Hidden), M", duration: "Instant", description: "You are able to quickly draw and stow your weapon in such a fashion that it’s almost impossible to track or react to. Until the end of the next turn the first time you would make a weapon or Taijutsu attack using a weapon that fits this jutsu’s component requirement, you make such an attack at advantage, with an +1 bonus to the attacks critical threat range. Once you deal damage to a creature with a weapon that’s gaining the benefit of this jutsu, as a part of the same action used to attack, you can make a Dexterity (Sleight of Hand) check vs the targets Passive perception. On a success, you are able to hide the weapon before they are able to realize what they were attacked with. If you fail the check, weapons you use cannot gain the benefit of this jutsu while targeting that creature until you complete a rest of any type.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the critical threat range bonus to +2. If this jutsu is cast at S-Rank, increase the critical threat range bonus to +3.", created_at: NOW, updated_at: NOW },
  { _id: "d16c38c22b6bc225c0e605fc", name: "HOLES OF DESPAIR [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon’s range", chakra_cost: "5 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "(This jutsu cannot crit) You thrust your weapon out from different angles as you seek to riddle your opponent with holes. Make three melee Taijutsu Attacks dealing your [weapons damage die] on hit. If at least two attacks are successful, the target creature gains a rank of bleeding. If this jutsu is cast as a Chain 2, increase the rank of bleeding by 1. If this jutsu is cast as a Chain 3 make an additional attack.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 the ranks of bleeding by 1. If this jutsu is cast at A-rank or higher it can regain the ability to score a critical hit.", created_at: NOW, updated_at: NOW },
  { _id: "16e341cc1fb432f770cb8c1d", name: "IAIJUTSU: LION’S SONG [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "Placing a single, sheathed sword upright and listening to the \"breath\" of your opponent, you rapidly unsheathe, attack while passing by your target, and then re- sheathe your sword. Make a melee Taijutsu Attack against a creature in range. On a hit, you deal your [weapons damage] +1d10. If you beat your opponent’s AC by 10 they cannot react to this jutsu.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d10. If this jutsu is cast at B-Rank, you only need to beat the AC by 5 to make the attack unable to be reacted to. If this is cast at S-Rank, you gain advantage on the roll. If you already have advantage this jutsu’s casting cannot be reacted to.", created_at: NOW, updated_at: NOW },
  { _id: "f4b137fd68329aadb791ad59", name: "IMPALER STAB [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon’s range", chakra_cost: "5 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You thrust your weapon into your enemy, and keep it there. Make a melee Taijutsu Attack. On a hit deal your [weapons damage]. You then can choose to keep it there. Doing so means you cannot attack with that weapon while it is Impaled, however the target creature becomes grappled by your weapon. While they are grappled you can use your bonus action to twist the weapon, dealing your [weapons damage die]. You also can add your [weapons damage die] to all rolls to maintain the grapple. A creature can choose to instead forcible remove themselves from the weapon as an action, automatically escaping the grapple but gaining 2 ranks of bleeding.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage die by 1. If this jutsu is cast at B-Rank you have advantage on checks to maintain the grapple. If this jutsu is cast at S- Rank, they instead gain two tanks of Lacerated for forcible ending the grapple.", created_at: NOW, updated_at: NOW },
  { _id: "d446a7b7bf12ba9458c74042", name: "IRON WEB DEFLECTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, which you take when you take damage", range: "Self", chakra_cost: "4 Chakra", components: "W (Any Flail)", duration: "1 Round", description: "You quickly wrap yourself in the chain or wire from your weapon to soften the blow of an attack before it actually strikes. Roll your [weapons damage die] twice, then add your ability modifier. Reduce the triggering damage by the result.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and roll your [weapons damage die] two more times. 271", created_at: NOW, updated_at: NOW },
  { _id: "57f274772c41c0bccb810fd0", name: "KISS OF THE MOON [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (All Ranged), M", duration: "Instant", description: "You send out your attack in a high arc that disappears from your opponent’s eyes and falls as if from the moon itself. Make a Ranged Taijutsu Attack against a creature in range. They must make a Wisdom save equal to your Taijutsu Save DC. On a failed save this attack gains advantage as they lose sight of the attack as it rises up and falls back down. On a success it gains disadvantage as they keep track of it. On a hit you deal your [weapons damage] +2d6.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the number of creatures you can target by one.", created_at: NOW, updated_at: NOW },
  { _id: "55522235662d669c74cf725d", name: "KNEE BREAKER [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "A series of low jabs at an opponent's lower body with the intent to ruin their legs. Make 2 melee Taijutsu Attacks at a target creature in range. On a hit, you deal your [weapon’s damage]. If you hit a creature twice with this jutsu, they are knocked prone. A creature knocked prone from this jutsu must spend its full movement to stand up.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the range of this jutsu by 5 feet. If this jutsu is cast at B-Rank, increase the number of attacks by 1. If this jutsu is cast at S-Rank, increase the number of attacks by 1.", created_at: NOW, updated_at: NOW },
  { _id: "722c130b5f76e8dc675ce759", name: "LINEAR DRIVE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Double your remaining movement speed.", chakra_cost: "5 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You take a wide stance with your weapon before dashing to deliver a single thrust at the enemy at a great speed, with the intent to ram them through. Make a weapon attack against a target creature in range. You gain a +1 to your attack roll for every 30 feet you moved, to a max of +5. On a hit you deal your [weapons damage] and + 1d10 for every 30 feet you moved to strike them, to a max of 3d10. If you deal 20 damage or more with this jutsu, the target creature also gains a rank of Bleeding and Slowed until the end of your next turn.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and your movement speed by 30 feet.", created_at: NOW, updated_at: NOW },
  { _id: "540a1a3de461fb2fda52a6e5", name: "MANIPULATED TOOLS: BINDING METEOR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "25 feet", chakra_cost: "3 Chakra", components: "W (Weapon Scroll), M", duration: "Instant", description: "You summon forth a weighted chain from your weapon scroll and use it to restrain multiple targets you can see within range. Make a melee Taijutsu attack against up to three targets, who are within 25 feet of one another. On a hit you grapple them and chain them to each other. Creatures chained together cannot move more than 25 feet from one another. Additionally, creatures chained together can, as an action, make a Dexterity (Acrobatics) or (Sleight of Hand) check vs your Taijutsu save DC, escaping the chains on a success. A creature who fails this check makes it harder to escape for other chained creatures. All other chained creatures who attempt to escape after another creature has failed, suffers a -2 penalty to their check, until the end of their next turn. This penalty stacks.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "9501550c770f5688e8f9156b", name: "MANIPULATED TOOLS: BLADE KICK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "45 feet", chakra_cost: "4 Chakra", components: "W (Weapon Scroll), M", duration: "Instant", description: "You summon forth series of swords, knives and spears that you kick and launch towards a creature to impale them. Roll 1d4, record the result. Make a range Taijutsu attack dealing Xd4 piercing damage and inflicting 2 ranks of bleed on a hit. (X= the result)", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the die rolled by 1 step. (1d4>1d6>1d8>1d10>1d12.) 272", created_at: NOW, updated_at: NOW },
  { _id: "8c1bc04f0b84dadafbfaf2a0", name: "MANIPULATED TOOLS: BLADE RAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot radius sphere)", chakra_cost: "4 Chakra", components: "W (Weapon Scroll), M", duration: "Instant", description: "You unravel your weapon scroll in the air, and reflexively summon forth a series of swords, knives and spears that rain down bombarding a space you can see within range. All creatures in a 15-foot radius sphere originating from a point you can see within range, must make a Dexterity saving throw. On a failed save, they take 3d6 + your Taijutsu ability modifier in piercing damage or half as much on a success. Additionally, the affected area becomes difficult terrain until after creature moves through it. The first time a creature would walk through any affected space would take 1d4 damage from the scattered bladed weaponry left behind protruding from the ground.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "b5bc1781f012d653b95f4fb0", name: "MANIPULATED TOOLS: BLADE WALL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (10-foot radius)", chakra_cost: "3 Chakra", components: "W (Weapon Scroll), M", duration: "Instant", description: "You unravel your weapon scroll in a 10-foot circle around you as you simultaneously summon a series of bladed weapons from it. All creatures in a 10-foot radius centering on you must make a Dexterity saving throw. On a failed save they take 3d8 piercing damage and they cannot upcast jutsu they cast until the end of their next turn on a failed save and gaining the bleeding condition or half damage on a successful save and no further effect.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the radius by 5 feet and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "8324b91af17494685411ce23", name: "MONKEY KING’S STANCE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "Special (When you deal damage with a bludgeoning weapon)", range: "Self", chakra_cost: "5 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You channel the energy from the strike into your weapon and hold that energy in a passive state as it builds up, much like the Monkey King himself. You can cast this jutsu when you deal damage with your weapon to take the stance, and its effects change depending on the circumstances you release the jutsu. You can only hold this jutsu until the end of your next turn, then it ends. While this jutsu is active you cannot cast another jutsu besides this one. Action: You leap up and bring your weapon down on the head of your enemy. Make a Melee Taijutsu Attack against a creature in your weapons range. On a hit, you deal your [weapon’s damage] +2d8 and the target creature must make a Constitution saving throw, becoming Concussed on a failed save. Bonus Action: You dash to the side and make a wide strike at the legs of your opponent. Make a Melee Taijutsu Attack against a target creature within 10 feet of you. On a hit, you deal your [weapon’s damage] +2d4 and the target creature must make a Strength Saving throw, being knocked prone on a failure. Reaction: You strike out with a fast blow to the side of your opponent that shatters guards. Male a Melee Taijutsu Attack against a target creature within 5 feet of you. On a hit, you deal your [weapon’s damage]. If your opponent has a bonus to AC or from a jutsu, feature, or trait this attack breaks through it and uses that energy as an extra force. This jutsu deals an additional 2d6 damage and ignores bonus that bonus AC. On a successful hit you gain that bonus AC until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage die of the jutsu by 1.", created_at: NOW, updated_at: NOW },
  { _id: "06f257037043c777d6d6f764", name: "MONKEY KINGS 10,000 HAIRS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "W (Melee Bludgeoning), M", duration: "Concentration, up to 10 minute", description: "You bathe your weapon in chakra until the chakra around it forms and shapes itself to resemble the famed Ruyi Jingu Bang. A legendary staff used by the fabled monkey king, Son Wukong. You cannot lose concentration as a result of damage. For the duration, when you would take the attack action or cast a Bukijutsu with the Monkey Kings prefix with your weapon, you can choose to give it the Reach X property, where X equals your Taijutsu ability modifier and twice per turn when you would deal damage with a weapon attack, or Taijutsu attack you deal bonus damage equal to 1d6.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the bonus damage to 2d6. If this jutsu is cast at S-Rank, increase the bonus damage to 3d6. 273", created_at: NOW, updated_at: NOW },
  { _id: "bc3d307ae85069521f0821b2", name: "MONKEY KINGS FANG", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Melee bludgeoning), M", duration: "Instant", description: "You spin your weapon above your head before swinging it at a target, at a downward angle and following with the butt end of the weapon. Make two melee Taijutsu attacks dealing your [weapons damage] + 1d6. You do not add your ability modifier to the damage dealt. If two attacks successfully strike a target, it must make a Strength saving throw being dazed on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of attacks made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "9030d8729aff3ad46739316f", name: "MONKEY KINGS TAIL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You swing your weapon around your body before locking it behind your back using both of your hands and performing a sideways spin, slamming it into all creatures in front of you. Make a melee Taijutsu attack against a creature you can see within range dealing your [weapons damage] + 2d6 and forcing the target to make a Constitution saving throw being dazed on a failed save. Additionally, depending on how long your weapon is, it may reach beyond striking one creature and instead striking multiple creatures in a 5-foot-wide line, with the length of it being determined by however many ranks of Reach it has. For every rank of Reach your weapon has, it extends 5 feet in a straight line. All creatures, excluding your original target, who is in this extended range, must make a Dexterity saving throw, taking your [weapons damage] on a failed save or no damage on a success. If this jutsu is cast as a Chain 2, increase the damage die by +2. If this jutsu is cast as a Chain 3 make an additional attack", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "39c4c0c6c09102074a7df872", name: "MONKEY KINGS WEIGHT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "W (Melee Bludgeoning), M", duration: "Concentration, up to 1 minute.", description: "You fill your weapon with enough chakra to multiply its weight well over 10 times its normal weight. You cannot lose concentration on this jutsu as a result of damage. For the duration of this jutsu, you multiply the weight of your bludgeoning weapon just before impact, while resetting its weight back to normal after impact. Each time you would deal damage with a melee Taijutsu attack under the effects of this jutsu, increase its [weapons damage die] by 1 step. (D4>D6>D8>D10>D12).", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, increase the damage die by 2 steps. If this jutsu is cast at S-Rank, increase the damage die by 3 steps.", created_at: NOW, updated_at: NOW },
  { _id: "527478e3230ca49e875e9c4c", name: "MULTIPOINT STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Simple Multiattack), M", duration: "Instant.", description: "You lash out with a flurry of attacks meant to completely overwhelm your enemy in the blink of an eye. You make a series of pinpoint strikes and multiple parts of your targets body. Make a single melee or ranged Taijutsu attack that multiplies in effectiveness as you repeat the same motion over and over. On a hit, you deal your [Weapons Damage] +2 additional damage die.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the bonus damage die by +1. 274", created_at: NOW, updated_at: NOW },
  { _id: "46b0ae5d88a10124e1d9333a", name: "NOBUNAGA’S COURAGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "5 Chakra", components: "W (Any Polearm), M", duration: "1 Minute", description: "You unleash a monstrous roar, filled with contempt and rage, while wielding your polearm weapon. This fills you with such animosity and anger that you become far more courageous and begin to imitate the look of the famed warrior, Oda Nobunaga causing great fear to your enemies and instilling great honor in your allies. All allies who are within range that can hear you, the first time that they would gain any ranks of the following conditions for the next minute; Charmed, Daze, Fear. They do not, instead becoming immune to the jutsu, feature, trait or effect that affected them, until the end of that turn. All hostile creatures who are within range that can hear you, must succeed a Charisma saving throw. On a failed save, the first time they would take damage from any weapon attacks you make using your Polearm weapon, they gain 1 rank of any of the following (Your choice), for the next minute, or until they spend an Action to remake their saving throw to end this effect on them; • Dazed • Fear • Weakened", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "820f5a027d7cd66a04cfe64b", name: "OFFENSIVE DODGE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 reaction when you are targeted by a melee attack", range: "Weapon’s range", chakra_cost: "5 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You take a reverse grip on your weapon and attempt to strike before you are struck. Make a melee attack against the triggering creature. On a hit you deal your [weapons damage die] + Taijutsu ability modifier. and raise your AC against the triggering attack by the base weapon damage die rolled as you drag your weapon along the attack, trying to throw it off target", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0eda45515d24fbae999cb470", name: "PAIN ASSAULT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "5 Chakra", components: "W (Any Ammunition), M", duration: "Instant", description: "You spend a full ammunition die to overwhelm your enemy with a wall of arrows, darts, bolts, shuriken, kunai or Senbon. All creatures in a 30-foot cone originating from you, must succeed a Dexterity saving throw. On a failed save, they take Xd4 damage of your chosen weapons type, where X equals the size of the die spent. (D4=4, D6=6, D8=8, D10=10, etc.)", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage die by 1 step. (D4>D6>D8>D10>D12) 275", created_at: NOW, updated_at: NOW },
  { _id: "506b71d7fb6f5ed5112fc08c", name: "PAIN BARRAGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-Foot radius Sphere)", chakra_cost: "5 Chakra", components: "W (Any Ammunition), M", duration: "Instant", description: "You leap in the air and spin while striking all targets in the area. Choose up to 10 creatures you can see within range. Roll your ammunition stack twice, taking the higher result. All selected creatures must succeed a Dexterity saving throw. On a failed save select creatures takes Xd4+Taijutsu ability modifier of your chosen [weapons damage] type. (X = The result of your ammunition stack.) Or half as much on a successful save. You then land in an unoccupied space you can see within the range of this jutsu. This jutsu spends the ammunition stack entirely.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d4", created_at: NOW, updated_at: NOW },
  { _id: "103f5d26c5f44550c153d147", name: "PAIN DANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius Sphere)", chakra_cost: "4 Chakra", components: "W (Any Ammo), M", duration: "Instant", description: "You launch a burst of your choice of weapons around yourself, attempting to hit all creatures surrounding you. All Creatures in a 20-foot radius sphere centered on you must succeed a Dexterity saving throw, taking your [weapons damage] + 2d8, and are dazed on a failed save, and half as much damage and no additional effects on a successful one. After casting this jutsu, you lower your ammo die by 2.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and Damage by 1d8", created_at: NOW, updated_at: NOW },
  { _id: "4389466d5767e8ea738eba5f", name: "PAPER BOMB BARRAGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "NT (1 Paper Bomb)", duration: "Instant", description: "You prepare a cluster of paper bombs which are consumed in the casting of this jutsu, in between your fingers on both hands and launch them at a single Target covering them in the prepared Bombs. A target you can see within range, makes a Dexterity saving throw, taking 7d4 Fire Damage on a failed save or half as much on a successful one. Creatures within 10ft of the target creature, excluding the target creature, also make the Dexterity Save, taking 5d4 Fire damage on a failed save or half as much on a successful one. For every quality of item used above the basic item quality, you increase this jutsu’s damage by 4d4.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b293816489740ed9b8019cfb", name: "PINNING SHOT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Any Ranged Piercing), M", duration: "Special", description: "You make a series of ranged attacks designed to pin your enemy in place in a way of your choosing. Make a ranged Taijutsu Attack, using your weapon of choice dealing your [weapons damage] + 1d10 and forcing the target creature to make a Strength saving throw, being restrained on a failed save. A creature restrained in this way, or another creature within 5 feet of the restrained creature can spend an action to make a Strength (Athletics) check vs your save DC, ending this condition on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the number of creatures you can target by +1. If this jutsu is cast at B-Rank, increase the damage by 2d10. If this jutsu is cast at S-Rank, increase the damage by 4d10", created_at: NOW, updated_at: NOW },
  { _id: "c22ac103bb9ce4128efe3d3d", name: "PREPARED SHOT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "Reaction to being targeted with a melee attack.", range: "Weapon Range", chakra_cost: "4 Chakra,", components: "W (Ranged Piercing), M", duration: "Instant", description: "You react to being attacked in close quarters combat. You leap back 5 feet, if possible, and immediately attack the triggering creature, piercing them indiscriminately attempting to halt their attack. Make a ranged Taijutsu Attack dealing your [weapons damage] + 3d4 Piercing damage on a hit. Affected creature must make a Constitution saving throw, being stunned until the end of their current turn on a failure. On a success they step forward 5 feet, if possible, and complete the attack. None of this movement triggers an Attack of opportunity.,", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and Damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "70d22b99d56e03f0750d1ce1", name: "PUSH SHOT [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "You perform a triplet of attacks, the force behind them enough to blow them away. Make three ranged Taijutsu Attacks using your weapon, dealing your [weapons damage], do not add your ability modifier to the damage dealt. If a target is hit at least once, it must also succeed a Strength saving throw knocking them back 10 feet, for each successful attack.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the target suffers a -1 penalty on their save. 276", created_at: NOW, updated_at: NOW },
  { _id: "6949be43321a263d7c5cba46", name: "RANGE EXTENDER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "4 Chakra", components: "W (Any Range), M", duration: "Concentration, up to 1 Minute", description: "You focus chakra into your iris’s, increasing your perceptive range, and allowing you to work with a much farther range. For the duration, the first time you would make a ranged Taijutsu or weapon attack per turn, you double the range of the attack.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0db7d70727a4e4fbcde84bae", name: "REBOUND SWING [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action, when you miss with a Melee", range: "Weapon’s range", chakra_cost: "4 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You quickly try to recover after your miss by pumping chakra into your arms to rebound the opposite way. You can remake the same attack at disadvantage targeting the same creature.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, you instead make the attack normally. If it is cast at S-Rank you make it advantage.", created_at: NOW, updated_at: NOW },
  { _id: "21baf91a921fa3389d5ab4ed", name: "SHADOWED SHOT [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Self (90 feet)", chakra_cost: "5 Chakra", components: "W (Ranged Slashing), M", duration: "Instant", description: "You throw your weapon as if it was a single shot, but in its shadow hides another. Select a creature in range and make a Ranged Taijutsu Attack. The target creature must make a Perception check against your attack roll. On a failure they fail to see the second weapon, and take an amount of slashing damage equal to your [weapons damage die], regardless of hit or miss. On a hit you deal your [weapons damage].", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by die on a failed Perception check by one die.", created_at: NOW, updated_at: NOW },
  { _id: "e411602a220c00bbf9137f07", name: "SHATTER SHOT [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Double your Weapons Range", chakra_cost: "5 Chakra", components: "W (All Ranged), M", duration: "Instant", description: "You pour chakra into your weapon as it fires, so much that it shatters as it flies, dealing damage over a wide area. Select a 20-foot radius area. Hostile Creatures in that area must make a Dexterity saving throw. On a failed save they take 4d6 damage of your weapons type and gain a rank of Dazzled as the explosion throws them off balance.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage of both attack and save by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "55e807e46f4c34c05a85814b", name: "SHOOTING STAR [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "weapons range", chakra_cost: "5 Chakra", components: "W (Any Thrown), M", duration: "Instant", description: "You throw your weapon with a focus of speed over power. Make a ranged Taijutsu Attack against a creature in range. On a hit you deal your [weapon’s damage die]. If you would target a creature within your weapon's normal range, this attack has advantage. If it is targeting a creature in your long range, you make the attack with disadvantage and cannot gain advantage, however, this attack deals an additional 2d10 damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0fa5ca6812d7dadbd3c4f488", name: "SHOT PUT CRASH [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "4 Chakra", components: "W (Any Ranged Bludgeoning), M", duration: "Instant", description: "You perform a single shot meant to pierce through defenses. Make a ranged Taijutsu Attack against a creature you can see within range dealing your [weapons damage] + 2d6 but as bludgeoning damage. This jutsu ignores half cover and deals double damage to constructs and structures.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. 277", created_at: NOW, updated_at: NOW },
  { _id: "97b7482f919582c97d0a4666", name: "SOARING DRAGON [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You swing as hard as you can upward while also jumping yourself, aiming to slice your opponent into the air with you. Make a melee Taijutsu Attack against a creature in range. On a hit, you deal your [weapons damage] +2d4 and they rise into the air with you 30 feet. If this jutsu is cast as a Chain 2, increase the damage die by 2. If this jutsu is cast as a Chain 3 make an additional attack", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "7a0af527e09b4ee062804670", name: "SOUL HUNT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 bonus action", range: "Self", chakra_cost: "5 Chakra", components: "W (Ranged Piercing), M", duration: "Concentration, up to 1 minute", description: "This jutsu does not cost chakra to maintain concentration on it. You begin to lace your weapons with chakra before firing. The first ranged weapon attack made with a Ranged Piercing weapon each turn, has a bonus to its critical threat ranged equal to +1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher increase the critical threat range by +1. If this jutsu is cast at S-Rank, increase the critical threat range by +1.", created_at: NOW, updated_at: NOW },
  { _id: "1ad737fdfdfb597709210985", name: "SOUL MARK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "4 Chakra", components: "W (Any), M", duration: "1 minute", description: "You fire off every receptor in your mind and eyes locking onto one creature you can see within range. For the duration, select one creature to soul mark. The selected creature cannot benefit from three fourths or half cover. When you would deal damage with a weapon attack, you deal an additional 1d10 damage of your [weapons damage] type. A creature remains marked until it reaches 0 hit points or you can no longer see it. Once a creature is no longer marked, you must recast this jutsu to soul mark them again. While this jutsu has a target, any time you would make a weapon attack targeting another creature not soul marked, you reduce damage dealt by 1d6.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the number of creatures you can mark by +1.", created_at: NOW, updated_at: NOW },
  { _id: "9e4954baa5e5b0b2533fe9a0", name: "SOUL REND [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon’s range", chakra_cost: "6 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You aim your weapon to cut at the very soul of your opponent. You wind up your strike and then unleash it in one flurry. Make a melee Taijutsu Attack at disadvantage against a creature in range. On a hit, you deal 4d6 slashing damage and the target creature gains a rank of bleeding. If this jutsu is cast as a Chain 2, the target creature gains an additional rank of bleeding. If this jutsu is cast as a Chain 3 the damage becomes 6d12.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f872e0720614cdee9547b580", name: "SOUL STEAL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "5 Chakra", components: "W (Any), M", duration: "Concentration, up to 1 minute", description: "You learn to aim at a targets spirit, instead of their body, allowing your attacks to strike true and deep. The first time each turn a weapon attack you make scores a critical hit, doubles your ability modifier damage and also ignore temporary hit points.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the number of critical threat range of the first ranged weapon attack you make each turn by +1.", created_at: NOW, updated_at: NOW },
  { _id: "39f5fe129f78c7f9ef7934d4", name: "STILL POND, RACING RIVER [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self(15 foot radius sphere)", chakra_cost: "5 Chakra", components: "W (Any), M", duration: "Instant", description: "You hold your weapon in a perfect perpendicular stance as you wait for the moment to strike. When a creature would make a weapon or Taijutsu Attack while in your weapon’s range until the start of your next turn, you strike out, drawing it to yourself. Make a Taijutsu Attack against the triggering creature. On a hit you deal your [weapons damage] and you become the new target for the attack. 278", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7eb5e2be90c897483119c34d", name: "STONE FORM [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 reaction to a creature reacting to your reacting to your Bukijutsu", range: "self", chakra_cost: "Special", components: "W (Any Polearm), M", duration: "Instant", description: "You quickly cancel out your Bukijutsu and use that energy to prepare for another. You cancel your last jutsu before its effects can take place and take a cross guard. If the creature would make an attack as a reaction you are hit regardless of the roll. If you would take damage from the creatures reaction you reduce the damage by the damage of the Bukijutsu that was canceled. If you would reduce this damage to 0, the next Bukijutsu you cast is automatically upcast by 1 rank.", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "55222ba82e5dd83f1e6d705e", name: "STORM OF STEEL [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "Special (28 Chakra)", components: "W (Any), M", duration: "Instant", description: "You and any ally within 30 feet of the target creature prepare to unleash a maelstrom of iron and steel on to your enemy. All participating creatures make a Taijutsu Attack against the creature in question, one at a time. On a hit they deal their [weapons damage] +3d8. After every creature has attacked the listed effects take place: If Bludgeoning Damage, they must make a Strength Saving throw with a -1 penalty for every hit with a weapon of said type against the highest Taijutsu Save DC. On a fail they gain 1 rank of Bruised as they are beaten around. If Slashing Damage, they must make a Dexterity Saving throw with a -1 penalty for every hit with a weapon of said type against the highest Taijutsu Save DC. On a fail, they gain 1 rank of Bleeding as they are sliced to ribbons. If Piercing Damage, they must make a Constitution Saving throw with a -1 penalty for every hit with a weapon of said type against the highest Taijutsu Save DC. On a fail, they gain 1 rank of Slowed as their joints are punctured. Combination: When this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. • +0-1: No Change • +2-3: The damage die of the jutsu increases to a d10 • +4-5: The damage die of the jutsu increases to a d12", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9a2241de777b342b2ceee106", name: "SUNDERING SPEAR [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "4 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "Your stab your spear forward, flooded with chakra meant to either harm flesh or sunder steel. Make a Melee Taijutsu Attack against a creature in range. On a hit, you can either deal your [weapons damage], or reduce their Damage Reduction by an amount equal to your damage until the beginning of your next turn. If this jutsu is cast as a Chain 2, you can do both without having to choose. If this jutsu is cast as a Chain 3 make an additional attack.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f98ef64cfae12ccccdaba37", name: "SWORD AURA: RED [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Self", chakra_cost: "5 Chakra", components: "W (Any Blade), M", duration: "1 minute", description: "You begin to unlock the ability to create a Sword Aura, a path only master swordsmen could even hope to follow. You send a controlled flood of chakra into your sword, the striking portion flaring red from the chakra. Your blade pierces 4 dr for the duration. When you would deal damage to a creature with this weapon, once per turn you can force them to make a Strength Saving throw. On a failed save they take 1d10 Fire damage and are knocked prone as your blade explodes with force.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2beafd391baa63d040298380", name: "TOADS WHIPPING TONGUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 bonus action", range: "Self", chakra_cost: "4 Chakra", components: "W (Any Flail), M", duration: "Concentration, up to 1 minute", description: "This jutsu does not cost chakra to maintain concentration on it. You enhance your weapon with chakra to control its trajectory mid attack. For the duration, weapon attacks you make with a Flail Weapon have a +1 to attack and damage rolls, an additional application of reach, and has a +2 bonus on Trip and Grapple attempts.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at C-Rank or higher, the weapon instead has a +2 to attack and damage rolls. If cast at B-rank or higher, the weapon gains an addition application of reach. If cast at A-Rank of higher, the weapon has a +3 bonus to attack and damage rolls. If cast at S-Rank, the weapon has a +10 bonus to trip and grapple attempts. 279", created_at: NOW, updated_at: NOW },
  { _id: "0a0fb6769b4e930b9a55288a", name: "TYGER CLAWS [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "5 Chakra", components: "W (Ranged Slashing), M", duration: "Instant", description: "You throw your weapon so that it strikes at a diagonal, slicing down your enemy with precision. Make a Ranged Taijutsu Attack against a creature in range. On a hit you deal your [weapons damage] +1d8 and the target creature must make a Constitution Saving throw. On a failure they are cut deeply along their chest and take and extra 2d8 slashing damage", at_higher_ranks: "For every rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage of both attack and save by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "b4afce76ea6d7c3ed83ea913", name: "WEAPON BREAK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 reaction, which you take when you take damage from a melee attack.", range: "Self", chakra_cost: "5 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You quickly react to being hit by using your weapon to catch the attacking weapon at a vulnerable angle. The creature who triggered this reaction must succeed a Dexterity saving throw, having their weapon break on a failed save. If the triggering creatures weapon has a bonus to attack and/or damage rolls or a weapon enhancement seal, it can only be broken by a weapon which has an equal or greater bonus to attack and/or damage rolls or an equal or greater ranked weapon enhancement seal.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8cd86f00aa583f37f48e1c53", name: "WEAPON DEFLECT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["fb718456f059602109e2c3ac"], elements: [], casting_time: "1 reaction, which you take when you are targeted by a melee weapon attack that you can see.", range: "Self", chakra_cost: "5 Chakra", components: "W (Any Weapon), M", duration: "1 round", description: "You enter a defensive stance with your weapon, parrying any incoming attack. You gain a +2 bonus to your AC until the beginning of your next turn. Until the end of your next turn, the next Bukijutsu you cast with the Chain keyword, increases its damage by +2 damage dice.", at_higher_ranks: "For each rank you cast this jutsu above D-rank, increase the cost of the jutsu by 3. If this jutsu is cast at B-rank, increase the AC bonus by +1 and the damage bonus by +1 damage die. If this jutsu is cast at S-Rank, increase the AC bonus by +2 and the damage bonus by +2 damage dice.", created_at: NOW, updated_at: NOW },
  { _id: "8052b6645af24a83ebfeef20", name: "WIRE TRAP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "10 Minutes", range: "10ft Cube", chakra_cost: "3 Chakra", components: "NT (Battle wire & Trappers Kit)", duration: "Instant", description: "You set a trap in a target Location. This Trap has a triggering area the size of a 15-foot cube centering on the trap. Creatures who enter this area trigger the trap. Once triggered, the triggering creature must make a Dexterity saving throw, being restrained on a failed save. Restrained creatures make a Strength saving throw at the beginning of each of their turns. On a success, they break the wire, ending the restrained condition on themselves.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f28af252de661eaaf612cc9e", name: "WOUNDING SLICE [NEW]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon’s range", chakra_cost: "5 Chakra", components: "W (Melee Slashing, M", duration: "Instant", description: "You coat your weapon in a cloak of jagged chakra before slicing down with the intent to severely maim. Make a Melee Taijutsu Attack at disadvantage against a target creature in range. On a hit you deal your [weapons damage] +2d10 and inflict 1 rank of bleeding.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the ranks of bleed by 1.", created_at: NOW, updated_at: NOW },
  { _id: "4c4e0076805024eb5b23187c", name: "YOSAKU STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 action", range: "Self (15-foot cone)", chakra_cost: "5 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You swing your weapon with enough force to create a lateral wave of cutting force. Creatures in a 15-foot cone in front of you must make a Dexterity saving throw. On a failed save you deal your [weapons damage] + 3d4 on a failed save or half as much on a successful one. You do not add your ability modifier to the damage. Creatures who are within 5 feet of you when you cast this jutsu make their save at disadvantage. If this jutsu is cast as a Chain 2, you can add your ability modifer to the damage roll. If this jutsu is cast as a Chain 3 increase the damage die by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and range of this jutsu by 5 feet. 280 C-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "f5b6668992c3c045567f457c", name: "1080 PSI AIR CANNON [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (90 feet long, 5-foot-wide line)", chakra_cost: "8 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You use the air itself to slash all who stand before you. As you swing your sword you launch an air- compressed cross slash, spiraling forward. All creatures in the area of effect must make a Constitution Saving throw, taking twice your [weapons damage] on a failure, and gaining 1 rank of Bleeding, or half as much damage on a success. If this jutsu is cast as a Chain 2, increase the rank of bleeding by 1. If this jutsu is cast as a Chain 3 creatures gain disadvantage on their saving throw.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c0944874e2f1e00197249bc7", name: "AFFLIGAM [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Any Flail), M", duration: "instant", description: "You whip your weapon to build up momentum to prepare for an all-out attack. The next Bukijutsu you cast with this weapon rolls its [weapons damage die] twice instead of once. If the next jutsu you cast requires a Flail Weapon, the Bukijutsu also increases the damage die of the jutsu by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, you instead increase the damage die of a Flail Bukijutsu by 2 steps. If this is cast at S-Rank, you instead roll your [weapons damage die] 3 times.", created_at: NOW, updated_at: NOW },
  { _id: "3b001be88c9f3215c36a5c74", name: "AFTERGLOW", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "30 Feet.", chakra_cost: "6 Chakra", components: "W (Melee Any), M", duration: "Instant", description: "You take a reverse grip with your weapon and prepare to cut down everyone in your way. Select a space within range. You dash through at blinding speeds to that select location. This movement does not provoke attacks of opportunity. All creatures whom you pass through while on the way to the select location are the targets of your attacks. Make a melee Taijutsu attack for each creature you pass through while moving, dealing your [weapons damage] on a hit. You end your movement in the selected space.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fb17b3391fdc4290fdc1e0e7", name: "AUGMENTED LETHALITY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "6 Chakra", components: "W (Any Deadly), M", duration: "Concentration, up to 1 minute.", description: "You focus on the lethality of your chosen weapon and attempt to enhance how deadly it can truly be while in your hands. For the duration, weapons you have with the Deadly trait, instead adds two additional damage die on a critical hit. You cannot lose concentration on this jutsu as a result of damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "36292b0a97114466a74470b7", name: "BIDING FURY: LIVER BLOW [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "X-Foot Cone", chakra_cost: "8 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You aim a strong blow right at your enemies liver, looking to make them lose the will to fight, if only for a moment. Make a melee Taijutsu attack, dealing your [weapons damage] +2d10 on a hit. On a hit, the target creature must also make a Constitution Saving throw. On a failed save their focus is shattered, ending any concentration jutsu cast at a lower rank then this jutsu and gaining a rank of Bruised. You can spend a Fury when casting this jutsu to increase the save DC by 1, per Fury Spent, up to a max of 5 Fury. If this jutsu is cast as a Chain 2, increase the damage die by 1. If this jutsu is cast as a Chain 3 make an additional attack", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d12, and the max Fury that can be spent by 2.", created_at: NOW, updated_at: NOW },
  { _id: "0ed9e73d60266da9a778b3c3", name: "BIDING FURY: TIGER BARRAGE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Special (Cone)", chakra_cost: "8 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You lash out with your weapon with the ferocity of a tiger, aiming to turn a foe into mincemeat. Make 2 melee Taijutsu attacks, comparing the results to all creatures in a X-Foot Cone in front of you, where X equals the ranks of Reach your weapon has, times 15ft. On a hit you deal your [weapons damage] +1d12. You can spend 2 Fury to make an extra melee Taijutsu attack. You can spend up to 6 Fury in this way. If this jutsu is cast as a Chain 2, increase the damage die by 1. If this jutsu is cast as a Chain 3 increase the damage die by an additional +1", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d12, and the max Fury that can be spent by 281", created_at: NOW, updated_at: NOW },
  { _id: "e05f4a6cb58318656935ed43", name: "BITE OF THE VIPER [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "7 Chakra", components: "W (Any Ranged Slashing), M", duration: "Instant", description: "You perform 3 strikes that devastate your opponent. Make three ranged Taijutsu attacks using your weapon, dealing your [weapons damage] +1d8 poison damage, do not add your ability modifier to the damage dealt. On a hit a creature must make a Constitution saving throw, gaining 1 rank of envenomed on a failed save, a creature can make this save once per casting.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the target suffers a -1 penalty on their saves.", created_at: NOW, updated_at: NOW },
  { _id: "a420b93e50e16475bae1e2ca", name: "BLADE OF SIN: GREED [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Any Blade), M", duration: "Concentration, Up to 1 Minute", description: "You seek to emulate the power of one of the Seven Deadly Sins of Humanity in your blade, imbuing the Sin of Greed inside the edge. For the next minute, when you would deal damage with a weapon attack or Bukijutsu, you also reduce the targets Maximum Health by half of the damage taken. A creature can restore the lost Maximum with a jutsu that removes conditions of an equal or higher rank then this jutsu was cast at.", at_higher_ranks: "For each rank this jutsu is cast above C-Rank, increase the cost by 3. If this jutsu is cast at A- Rank you instead reduce the targets Maximum Health by the full amount.", created_at: NOW, updated_at: NOW },
  { _id: "6db514c63848ef7c51803316", name: "BLUNT FORCE CONNECTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range (10ft radius Sphere)", chakra_cost: "8 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You take a stance that allows you to place all of your weight behind your attack. Make a melee Taijutsu attack against a target creature. On a hit, you deal your [weapons damage] + 3d8 and the target falls prone. A 15- foot cube originating from you becomes difficult terrain. All creatures in this cube must make a Strength saving throw, falling prone on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and Damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "ab99693d7e9e9b0e8830c0ad", name: "BOLTING SAKURA", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "W (Any Power), M", duration: "Concentration, 1 minute", description: "You close your defenses as you guard your body with your weapon. You do not need to spend Chakra to maintain concentration on this jutsu. When you activate this jutsu, you enter this guarded form until the start of your next turn, you can reenter this form by spend an action on your turn. While in guarded form, increase your AC by half of your Taijutsu attack bonus (Rounded down).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a41bb4ccf8af4b31d2e3cd75", name: "BOUNDING BLOSSOM [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Long Jump Range (20 feet radius sphere)", chakra_cost: "8 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "(you must move at least 10 feet before casting this jutsu, and you must jump in the same direction you moved) You leap into the air and strike down with the butt of your polearm, scattering your foes and leveling the ground. After landing from your leap, all creatures within a 20-foot radius sphere from you must make a Strength Saving Throw, taking 4d10 damage and being knocked prone on a failed save, and half as much and no further effects on a successful save. If you land in the same space a creature is occupying then they make their save at disadvantage and you can add your [weapons damage] to the damage of this jutsu. If this jutsu is cast as a Chain 2, increase the damage die by 1. If this jutsu is cast as a Chain 3 increase the damage die by an additional +2", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d10. If this jutsu is cast at A-Rank, creatures who fail also become Staggered. 282", created_at: NOW, updated_at: NOW },
  { _id: "664d2d5cea06b30cad83cd68", name: "BOWLING SPARE SHOT [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon's Range", chakra_cost: "8 Chakra", components: "W (Ranged Bludgeoning), M", duration: "Instant", description: "You throw your weapon at an angle to bounce and make an impossible shot possible. Make a ranged Taijutsu attack against a creature in range. On a hit you deal your [weapons damage] +2d8 and then you can target another creature that you can draw a straight line to from the first target creature, no longer then your weapons range, as if it originated from the first target creature. Make a second ranged Taijutsu attack, dealing [weapons damage] +2d6 on a hit. Any creature between the two target creatures must make a Dexterity saving throw, taking [weapons damage] +2d4 on a failed save, and no damage on a successful one. If this jutsu is cast as a Chain 2, increase all the damage die by 1. If this jutsu is cast as a Chain 3 increase all the damage die of this jutsu by 1 step", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "f3e9d6b7799e7d3683327298", name: "BOWLING STRIKE SHOT [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon's Range", chakra_cost: "8 Chakra", components: "W (Ranged Bludgeoning), M", duration: "Instant", description: "You throw your weapon with the power to knock in foe off their feet, forgoing accuracy for more power. Make a ranged Taijutsu attack against a creature in range at disadvantage. On a hit you deal your [weapons damage] +2d12 and the target creature is knocked prone. If one of the die from this jutsu rolls the maximum, they also gain a rank of Concussed until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "22ae99b4c784b4a96c2683eb", name: "BREATH OF ASH: CHIMNEY CLEARING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action.", range: "Self (30-foot cylinder)", chakra_cost: "8 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest fire release chakra until it laces the striking portion of your weapon. The fire release chakra begins to transform into gouts of ash that emanates from your weapon. You then choose to fire directly into the sky. When you do, your weapon releases a funnel of flame that erupts from you as you manifest a 30-foot high, 10- foot-wide funnel of flame. All creatures excluding you must make a Dexterity saving throw. Depending on the severity of their failure they suffer additional effects. On a successful save, they take half of the following damage; [weapons damage] + 5d6 fire damage. ● Failed by 1~4: [weapons damage] + 5d6 fire damage. ● Failed by 5~9: [weapons damage] + 6d6 fire damage and 1 rank of burned. ● Failed by 10~14: [weapons damage] + 7d6 fire damage and 2 ranks of burned. ● Failed by 15+: [weapons damage] + 8d6 fire damage and 3 ranks of burned.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at B-Rank, increase the radius of this jutsu by 5 feet. If this jutsu is cast at S-Rank, increase the radius of this jutsu by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "5bc753b15f38cc0b8129c07b", name: "BREATH OF BEASTS: DEVOUR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "9 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest chakra until it laces the striking portion of your weapon. The chakra begins to manifest in the form of any beast of your choice in any color that can be seen plainly by others. You begin to swing wildly and unpredictably, fueled by instinct and primal urges. Make two melee Taijutsu attack. On a hit, you your [weapons damage] + 2d6. When you deal damage with this jutsu, you impost an effect based on the damage type of the weapon used. • Bludgeoning: Target creature makes a Strength saving throw, becoming bruised and gaining 1 rank of the weakened condition until the end of their next turn on a failed save. • Piercing: The creature must make a Constitution saving throw, becoming dazed and having their movement speed reduced by -15, until the end of their next turn on a failed save. • Slashing: The creature must make a Dexterity saving throw, gaining 2 ranks of bleeding on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6. 283", created_at: NOW, updated_at: NOW },
  { _id: "3f524eb2f7428120f1555f02", name: "BREATH OF DUST: INSTABILITY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "7 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "(You cannot score a critical hit with this jutsu) You begin to collect and manifest earth release chakra until it laces the striking portion of your weapon. The earth release chakra begins to magnify the weight and striking power of your attacks allowing you blow through anything in your path with little difficulty. You fire multiple shots in an attempt to strike multiple angles at once. Make a single ranged Taijutsu attack against one creature you can see within range. On a hit, you deal your [weapons damage die] + 2d4 earth damage, you do not add your ability modifier to damage. If your first is 5 or higher than the AC of your target, make a second melee Taijutsu attack against the same creature, dealing 3d6 earth damage and inflicting the bruised condition. If the second attack is 5 or higher than the AC of your target, make a third attack against the same creature, dealing 3d6 earth damage and inflicting the bruised condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at S-Rank, the earth damage increases by 1 step, to a d8.", created_at: NOW, updated_at: NOW },
  { _id: "c2411c2a7b6ec38e4e521f6f", name: "BREATH OF EARTH: BIPOLAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "9 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "(You cannot score a critical hit with this jutsu) You begin to collect and manifest earth release chakra until it laces the striking portion of your weapon. The earth release chakra begins to magnify the weight and striking power of your attacks allowing you crush anything in your path is little difficulty. You spin with such power that basically anyone standing in your way becomes a memory. Make a single melee Taijutsu attack against one creature you can see within range. On a hit, you deal your [weapons damage die] + 2d6 earth damage, you do not add your ability modifier to damage. If your first is 5 or higher than the AC of your target, make a second melee Taijutsu attack against the same creature, dealing 3d6 earth damage and inflicting the bruised condition. If the second attack is 5 or higher than the AC of your target, make a third attack against the same creature, dealing 3d6 earth damage and inflicting the bruised condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at S-Rank, the earth damage increases by 1 step, to a d8.", created_at: NOW, updated_at: NOW },
  { _id: "4b883bc61d8c4e6bcfbe4678", name: "BREATH OF ECHO: ROAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "7 Chakra", components: "CM, W (Any Range), NT (Any explosive tool),", duration: "Instant", description: "You begin to collect and manifest chakra until it manifest into the shape of a sound note of your choice, hovering over the striking portion of your weapon. This note can be seen plainly by any other creature who can manipulate chakra. You throw two explosive tools towards your enemy, then release one powerful shot, cutting through them to strike your enemy, causing a slight delay before they explode with a thunderous sound. Make one ranged Taijutsu attacks, dealing your [weapons damage]. Regardless of a hit or not, the target and all creatures within 10 feet of them must make a Dexterity saving throw. If the target was successfully hit, they make their save with a 1d4 penalty. On a failed save, creatures take 8d6 force damage and are knocked prone and deafened until the end of your next turn or half as much damage and no additional effects on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6 and the size of the area by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "4f30d5f64ac75f398fc79bc5", name: "BREATH OF ENOKI: INVASIVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action.", range: "Weapon Range", chakra_cost: "8 Chakra", components: "CM, W (Any Ranged), NT (Poison Kit), M", duration: "Instant", description: "You begin to collect and manifest medical chakra until it laces the striking portion of your weapon. The medical chakra begins to cause your weapon to glow with a soft pink hue. You fire a single attack into the ground or space your target is in, releasing a powerful burst of poisonous fumes to weaken them further. Select a space you can see within range. All creatures within 10 feet of the chosen space must make a Constitution saving throw. Depending on the severity of their failure, the poison does increasingly more things. ● Failed by 1~4: 5d6 poison damage and 1 ranks of corroded. ● Failed by 5~9: 5d6 poison damage and 2 rank of corroded. ● Failed by 10~14: 5d6 poison damage, 2 ranks of corroded, and 1 rank of envenomed. ● Failed by 15+: 5d6 poison damage, 2 ranks of corroded, and 2 rank of envenomed. 284", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b4bcfbcf65397db513aebf36", name: "BREATH OF FLAME: UNDULATION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action or 1 Reaction, which you take when you would take damage from a melee attack or would take damage as a result of a Strength, Dexterity or Constitution saving throw.", range: "Self (10 feet)", chakra_cost: "8 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest fire release chakra until it laces the striking portion of your weapon. The fire release chakra begins to transform into gouts of flame that erupt off of your weapon with a glorious flickering. You then choose to either spin your weapon in a circular fashion, either striking multiple enemies at once or blocking and deflecting incoming hostile and harmful attacks and effects depending on the action used to cast this jutsu. Action: You spin striking all creatures within range attempting to decapitate them. All creatures of your choice must make a Dexterity saving throw. Depending on the severity of their failure they suffer additional effects. On a successful save, they take half of the following damage; [weapons damage] + 4d6 fire damage. ● Failed by 1~4: [weapons damage] + 4d6 fire damage. ● Failed by 5~9: [weapons damage] + 6d6 fire damage and 1 rank of burned. ● Failed by 10~14: [weapons damage] + 8d6 fire damage and 2 ranks of burned. ● Failed by 15+: [weapons damage] + 8d6 fire damage and 3 ranks of burned. Reaction: You and all creatures of your choice within range reduce incoming damage by your [weapons damage] + 4d6. This Damage Reduction is doubled against fire or wind damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage reduced by 1d6. If this jutsu is cast at B-Rank, increase the radius of this jutsu to 15 feet. If this jutsu is cast at S-Rank, increase the radius of this jutsu to 20 feet.", created_at: NOW, updated_at: NOW },
  { _id: "53d26b87c93e12af8050c7eb", name: "BREATH OF FOG: SMOG", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b7c3bde363176d05f69f793a"], elements: [], casting_time: "1 Action", range: "Self (15 feet)", chakra_cost: "8 Chakra", components: "CM, W (Any Ranged), M", duration: "Concentration, up to 1 minute.", description: "You begin to collect and manifest Illusionary chakra until it radiate off of your weapon similar to that of a thick smog, of a color of your choosing. The chakra begins to take the same consistency as a thick gas that makes it difficult to see through. You generate this smog centered on you that expands outward up to 10 feet and goes around corners. This smog follows you and cannot be blown away by strong winds. Creatures other than you, cannot see through this smog and you are treated as being fully obscured visually against them. When a creature enters the smog the effects of this jutsu no longer affect them, allowing them to see you clearly as if the smog was no longer there. Creatures, creatures attacks and jutsu can still pass through this haze, entering and/or exiting it. The first time each turn you would make an attack or cast a jutsu while maintaining this jutsu, your Weapons or Taijutsu critical threat range is increased by +1.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the number of creatures you can target with this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "996d22fdc915db95d5c5a872", name: "BREATH OF MIST: HAZE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b7c3bde363176d05f69f793a"], elements: [], casting_time: "1 Action", range: "Self (15 feet)", chakra_cost: "8 Chakra", components: "CM, W (Any Melee), M", duration: "Concentration, up to 1 minute.", description: "You begin to collect and manifest Illusionary chakra until it radiate off of your weapon similar to that of a mist. The chakra begins to take the same consistency as a thick haze that makes it difficult to see through. You generate this haze centered on you that expands outward up to 15 feet and goes around corners. This haze follows you and cannot be blown away by strong winds. Select one hostile creature you can see when you cast this jutsu. This creature cannot see through this haze and you are treated as being fully obscured visually against them. Creatures, creatures attacks and jutsu can still pass through this haze, entering and/or exiting it. The first time each turn you would make an attack or cast a jutsu while maintaining this jutsu, your Weapons or Taijutsu critical threat range is increased by +1.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the number of creatures you can target with this jutsu by +1. 285", created_at: NOW, updated_at: NOW },
  { _id: "03ca8f8d359b72a4b4fd14fe", name: "BREATH OF RAIN: DRIZZLE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "8 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest water release chakra until it laces the striking portion of your weapon. The water release chakra begins to transform into streams of water, capable of being seen and felt as you perform a zigzag or curved attack, attacking in an irregular motion. When casting this jutsu, you can choose to make a Zigzag or Curved attack. • Zigzag: Make one ranged Taijutsu attack against a creature in your weapons range. Each creature within of your choice, between you and your target must make a Dexterity saving throw. On a hit or failed save, you deal your [weapons damage] + 4d6 cold damage and affected creatures gain 1 rank of chilled or half as much damage on a successful save. A creature whom you target that is either Dazed or chilled grants you a 1d4 bonus to hit. A creature whom you force to make a saving throw that is either Dazed or chilled suffers a 1d4 penalty to their saving throw. • Curved: You fire off a curved shot, capable of bypassing defenses. Make one ranged Taijutsu attack. This attack ignores boosts to AC as a result of features, traits or jutsu. On a hit, you deal twice your [weapons damage die] + 3d8 cold damage, and being dazed on a failed save or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6 or 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "68c9d889595a23d19f9f0734", name: "BREATH OF ROSES: HANAGOROMO", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action.", range: "Weapons Range", chakra_cost: "8 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest medical chakra until it laces the striking portion of your weapon. The medical chakra begins to cause your weapon to glow with a soft pink hue. You unleash a single strike that bends, curves and twists around you as if you made multiple strikes at once. Make one melee Taijutsu attack targeting a creature, depending on the severity of your success, your attack is increasingly more effective. ● Beat AC by 0~4: [weapons damage] + 2d6 poison damage. ● Beat AC by 5~9: [weapons damage] + 4d6 poison damage and 1 rank of envenomed. ● Beat AC by 10~14: [weapons damage] + 6d6 poison damage and 2 ranks of envenomed. ● Beat AC by 15+: [weapons damage] + 8d6 poison damage and 3 ranks of envenomed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "928a4ebafa52f1224a06c94d", name: "BREATH OF SKIES: STORM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "9 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest wind release chakra until it laces the striking portion of your weapon. The wind release chakra begins to spiral around the user’s weapon creating whipping torrents of wind. When you fire your weapon, it creates a torrenting spiral of wind, enough to imitate a storming tornado. Make three ranged Taijutsu attacks against a creature or spread across multiple creatures you can reach within range. On a hit you deal twice your [weapons damage die], in wind damage, these attacks cannot score a critical hit. If a creature is hit by all three attacks you manifest a shockwave of wind that tear through the ground knocking the target prone and inflicting 1 rank of lacerated.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank or higher, increase the damage of this jutsu to instead deal three times your [weapons damage die]. If this jutsu is cast at S-Rank or higher, increase the damage of this jutsu to instead deal four times your [weapons damage die]. 286", created_at: NOW, updated_at: NOW },
  { _id: "fdfb322370b942991688a640", name: "BREATH OF SOUND: SCORE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "6 Chakra", components: "CM, W (Any Melee), M", duration: "Concentration, up to 1 minute", description: "You begin to collect and manifest chakra until it manifest into the shape of a sound note of your choice, hovering over your eyes as you begin to listen to all of the sounds created as a result of battle. For the duration you do not spend chakra to maintain this jutsu, instead you must spend a bonus action to maintain it. Choose one of the following tempos when you cast this jutsu. You can the benefit of this tempo until the beginning of your next turn. At the beginning of each of your turns thereafter, you can select a different tempo if you would like. • Moderato: You strike with great force to the strum of the battle. The first time each turn you would deal damage with a melee weapon or Taijutsu attack you make with a bukijutsu with the Breath of Sound prefix, you add your level to the damage dealt. • Allegretto: Breath of Sound bukijutsu you cast has their save DC increased by +1d4. • Vivacissimo: You speed yourself up to strike at the right time, when they are at the most vulnerable. You have advantage on the first melee weapon or Taijutsu attack you make with a bukijutsu with the Breath of Sound prefix, each turn. • Andante: You match your pace to your opponents to defend and parry perfectly against their every move. You gain a special reaction which can only be used when you would take damage from an attack, or make a Strength or Dexterity saving throw. If used against an attack, make a contested melee Taijutsu attack. If your attack is higher than theirs, their attack misses. If used against a saving throw, you add your [weapons damage] to the first saving throw made, each turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "59c7c534212bda8164771e4f", name: "BREATH OF SPARKS: SURGE [ NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest lightning release chakra until it laces the striking portion of your weapon. The lightning release chakra begins to collect and spark off of your weapon with violent jolts. You prepare for a volley of attacks as you fire multiple times, enhanced by lightning. Make two ranged Taijutsu attacks using your weapon, dealing your [weapons damage] + 2d8 lightning damage, you do not add your ability modifier to the damage dealt. If the target any ranks of the Shocked condition, you make your attacks at advantage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage dealt by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "fa903d7350937adac5a3570c", name: "BREATH OF THUNDER: SWARM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest lightning release chakra until it laces the striking portion of your weapon. The lightning release chakra begins to collect and spark off of your weapon with violent jolts. You prepare for a volley of attacks as you strike multiple times, enhanced by lightning. Make two melee Taijutsu attacks using your weapon, dealing your [weapons damage] + 3d6 lightning damage, you do not add your ability modifier to the damage dealt. If the target any ranks of the Shocked condition, you make your attacks at advantage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage dealt by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "76b8394e267233b036f9372a", name: "BREATH OF WATER: WHEEL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "8 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest water release chakra until it laces the striking portion of your weapon. The water release chakra begins to transform into streams of water, capable of being seen and felt as you perform a vertical or lateral spin forward, attacking in a circular motion. When casting this jutsu, you can choose to make a lateral or vertical spin, regardless of the option chosen, if it requires a saving throw, creatures make a Dexterity saving throw. • Lateral Spin: Make one melee Taijutsu attack against a creature in your weapons range. Each creature within your weapons range, of your choice, must make a saving throw. On a hit or failed save, you deal your [weapons damage] + 5d6 cold damage and affected creatures gain 1 rank of chilled or half as much damage on a successful save. A creature whom you target that is either Dazed or chilled grants you a 1d4 bonus to hit. A creature whom you force to make a saving throw that is either Dazed or chilled suffers a 1d4 penalty to their saving throw. • Vertical Spin: Move to a space within 20 feet of you in a straight line. Each creature you pass through must make a saving throw, taking your [weapons damage] + 7d4 cold damage, and being dazed on a failed save or half as much on a successful one. If a creature is within 5 feet of where you end your movement, and did not make a saving throw as a result of this jutsu, you can make a single melee Taijutsu attack targeting them. On a hit, you deal your [weapons damage] + 7d4 cold damage, knocking them prone.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6 or 1d4. 287", created_at: NOW, updated_at: NOW },
  { _id: "ec4f87a5fe224cf4f1fc3f43", name: "BREATH OF WIND: CLAWS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "9 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest wind release chakra until it laces the striking portion of your weapon. The wind release chakra begins to spiral around the user’s weapon creating whipping torrents of wind. You lift your weapon upwards towards the right, above your head and unleashes four vertical strikes at once down on the enemy resembling claws. Make four melee Taijutsu attacks against a creature or spread across multiple creatures you can reach within range. On a hit you deal your [weapons damage] + 1d6 wind damage but you do not add your ability modifier to your [weapons damage], these attacks cannot score a critical hit. If a creature is hit by at least 3 attacks you manifest a shockwave of wind that tear through the ground knocking the target prone and inflicting 1 rank of lacerated.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank or higher, increase the wind damage of this jutsu by an additional 1d6 and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "551290ba78e7288f8c583fe0", name: "BRUTAL BLOCK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Any Power), M", duration: "1 Round", description: "You raise your weapon to block incoming damage at its source. When you would take damage you raise your weapon’s in a cross-guard fashion. You reduce the first instance of incoming damage each turn by your [weapons damage] + 3d6. When you do, you reinforce your next attack with the force sent towards you. Until the end of your next turn, each time you reduce an incoming attacks damage by any amount, you increase your next attacks critical threat range by +1.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage reduced by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "dfdb7d11cf7a69e07e43b0fd", name: "BUZZSAW BLITZ [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (15-foot radius Sphere)", chakra_cost: "8 Chakra", components: "W (Any Thrown), M", duration: "Concentration, 1 minute", description: "You toss you weapon with enough force to spin around you like a lethal buzzsaw. For the duration of this jutsu, you cannot make attacks using the weapon used to cast this jutsu. For the duration, creatures who start their turn within 15 feet of you must make a Constitution Saving throw or take your [weapons damage] +2d4 and gain 1 rank of bleeding. Creatures who start their turn exactly 15 feet away from you have disadvantage on their save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the ranks of bleeding by 1.", created_at: NOW, updated_at: NOW },
  { _id: "6466e25281e1c58ed83f7bf0", name: "CENTIPEDE DANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You perform a series of brutal and efficient strikes with your weapon in an attempt to cripple and debilitate the target. Make two melee Taijutsu attacks against a creature you can see within range, with your weapon. On a hit you deal your [weapons damage] + 2d6, you do not add your ability modifier to the damage dealt. If you hit with at least one of your attacks the affected target must success a Strength Saving throw. If you successfully hit a creature more than once with this jutsu, they suffer a -1 penalty to their save for each additional hit after the first. On a failed save, the target is Weakened for the next minute as you dislocate multiple bones in the targets body. A weakened creature can spend an action to relocate their bones pushing them back into place.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "947c63da3351509256a81b2d", name: "CHAIN KILL [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "a1d637e2d9f405b664a39ef4"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "10 Chakra", components: "W (Any Flail), M", duration: "instant", description: "You whip your weapon into a frenzy, ready to strike down your foes in rapid succession. Make a melee Taijutsu attack against the closest enemy within range, dealing twice your [Weapon's Damage] on a hit. If there are multiple close enemies, select one. If you reduce a creature to 0 hit points using this jutsu, you can move to the next closest enemy and make another melee Taijutsu attack. This cycle can repeat multiple times until you run out of movement, miss, or fail to reduce a creature to 0 hit points. Each time you make a melee Taijutsu attack after the first, you suffer a -3 penalty to the next attack you make with this jutsu. 288", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7180d751d328ec6ca6550ecd", name: "CHAKRA SABRE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "6 Chakra", components: "W (Any), CM", duration: "Concentration, up to 1 Minute", description: "You manifest a sheath of chakra around your weapon. This sheath reinforces the weapon enhancing it beyond its normal limitations. For the duration, you cannot lose concentration of this jutsu as a result of damage, and twice per turn, when you would deal damage with a weapon or Taijutsu attack, you increase your [weapons damage die] by +1.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, you instead increase your [weapons damage die] by +2.", created_at: NOW, updated_at: NOW },
  { _id: "1fb83526772886e3ae670a2a", name: "CHAKRA-SEEKING ROUNDS [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Weapons Range", chakra_cost: "8 Chakra", components: "W (Any Ammo), M", duration: "1 Minute", description: "(You must cast this jutsu after damaging a target with an Ammunition weapon) You attuned your ammunition to your opponent’s chakra signature, helping guide your weapons to their intended recipients. Make a contested Chakra Control check using your Taijutsu ability modifier versus the target creature. On a success, you gain the following benefits for the duration of this jutsu; • The creature has disadvantage on Stealth checks against you and your allies • Once per round, when you miss a ranged weapon or Taijutsu attack against the target creature with a weapon with the Ammunition property, you can reroll the attack with half of your usual attack bonus. This reroll cannot crit.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. At B- Rank, the duration becomes 10 minutes and you can reroll a missed attack once per turn. At S-Rank the duration becomes 1 hour and you can reroll a missed attack twice per turn.", created_at: NOW, updated_at: NOW },
  { _id: "7592fc462becf05dc21f28f5", name: "COILING STRIKE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action or Reaction after casting a Bukijutsu that targeted another creature.", range: "Twice Weapons Range", chakra_cost: "8 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "Using the force from your previous attack, you coil around your weapon, compounding the force into another powerful strike. You can move to any unoccupied space within twice your weapons range and then make a melee Taijutsu attack targeting a creature you can reach, dealing your [weapons damage] +xd4, where X is the base damage dice of the previous jutsu and inflict 2 ranks of Bleeding. If the creature has taken piercing damage from a Bukijutsu you have cast this turn, you have advantage on this attack and increase the damage die by 1 step.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e4b03aa28b7cd52065557573", name: "COIN TOSS [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "15 feet", chakra_cost: "6 Chakra", components: "W (Any Ammunition), M, NT (50", duration: "Instant", description: "You toss a 50 Ryo coin into the air within 15 feet of you to augment the trajectory of your next attack, improving its effectiveness with style. After casting this jutsu, your next ranged weapon or ranged Taijutsu attack (as part of a Bukijutsu) is aimed at the coin, bouncing off of it before being redirected to your intended target, causing the attack roll to be made at advantage, gains a +1 bonus to critical threat range, and ignores up to three-quarters cover. Using this jutsu destroys the 50 Ryo coin.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If cast to B-Rank or higher, increase the bonus to critical threat range to +2 and on a critical hit the target gains 1 rank of Lacerated. If cast to S-Rank or higher, increase the bonus to critical threat range to +3 and on a critical hit the target gains 2 ranks of Lacerated.", created_at: NOW, updated_at: NOW },
  { _id: "fa4fbb4df748e13e44d62bfc", name: "COLLATERAL POINT STRIKES [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "W (Ranged Piercing), M", duration: "Instant", description: "By forcing your chakra into an arrow at the moment of release, you can splinter the arrow into multiple parts. Choose a number of creatures up to your Taijutsu modifier, make a ranged Taijutsu attack against each target, on a hit, you deal your weapon’s damage + 1d4, increasing the dice by 1d4 for each successful hit against each unique target (up to a max of 3d4)", at_higher_ranks: "For each rank you cast this jutsu above C-rank increase the cost by 3 and the damage by 1d4 and max by 1d4. 289", created_at: NOW, updated_at: NOW },
  { _id: "3e956dfff425fdba501a66db", name: "CRESCENT MOON BEHEADING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "9 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You switch your weapon into a two-handed grip to the best of your abilities. You attack with your weapon with the ferocity to behead your enemy. Make a single melee Taijutsu attack dealing your [weapons damage] + 2d10. If you roll 4 or more 10’s on a d10, with this jutsu’s damage die, the creature is immediately beheaded.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and Damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "6a5521b0af53549c24713383", name: "CRESCENT MOON CRIPPLING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "9 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You switch your weapon into a two-handed grip to the best of your abilities. You spin with enough force to pick up dust and slightly heat the attacking end of your weapon. Make a single melee Taijutsu attack dealing your [weapons damage] + 3d8. If you roll 5 or more 8’s on a d8, with this Jutsu's damage die, the target creature is permanently crippled becoming Dazed and Weakened until targeted by a Jutsu with the Medical Keyword of B-Rank or Higher, that removed conditions.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and Damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "ede3ef13871b569b1ba55b82", name: "CRESCENT MOON IMPACT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "9 Chakra", components: "W (Any Ranged or Thrown), M", duration: "Instant", description: "You take your bow as you rapidly fire a swarm of shots into directly into your target with enough force to tear holes in steel and concrete. Make a single ranged Taijutsu attack, dealing your [weapons damage] +6d4. If you roll 6 or more 4’s on a d4, with this Jutsu's damage die, you tear through the targets body, leaving them with a gaping wound. Affected creature gains 5 ranks of lacerated. The medicine check DC to remove lacerated is increased to 30.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and Damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "0a823ccb3719a88f02a49fa2", name: "CRESCENT MOON PENETRATION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "9 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You grip your weapon with two-hands to the best of your abilities. You attack with your weapon with the ferocity to pierce straight through their heart. Make a single melee Taijutsu attack dealing your [weapons damage] + 4d6. If you roll 6 or more 6’s with the this jutsu’s damage die, the target creature is immediately killed as you pierce straight through their heart.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and Damage by 1d6", created_at: NOW, updated_at: NOW },
  { _id: "649d4a565fab3291c9c24361", name: "CRIMSON MASK [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons", chakra_cost: "8 Chakra", components: "W (Ranged Slashing), M", duration: "Instant", description: "You throw your weapon to cut right above your target’s eyes, blinding them with a crimson mask of their blood. Make a ranged Taijutsu attack against a target creature in range. On a hit you deal your [weapons damage] +1d6. The target creature then must make a Constitution saving throw, gaining a rank of Bleeding on a failure. While they have this rank of bleeding they also suffer from the Blinded condition. If this jutsu is cast as a Chain 2, increase the damage die by 2. If this jutsu is cast as a Chain 3 increase the damage die by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "86a2e30c38bb2e9e3974ef36", name: "CRUSHING THOUGHTS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Melee Bludgeoning), M", duration: "1 Minute", description: "As a requirement to activate this jutsu, you must currently be in the Crushing Stance. You begin to focus on ways to crush your opponent using the power of blunt strikes. For the duration of this jutsu, you gain pierce (6) against heavy armor, and pierce (4) against medium armor.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. At A-rank increase the ranks of pierce by +2 and +1 (8 and 4 respectively). At S-rank, increase the ranks of pierce by +4 and +2 (10 and 5 respectively). 290", created_at: NOW, updated_at: NOW },
  { _id: "35f71231018695da6984189a", name: "CYPRESS IMPACT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range (20-foot radius sphere)", chakra_cost: "7 Chakra", components: "W (Any Bow), M", duration: "Instant", description: "You take your bow as you rapidly first a swarm of shots into the sky before they begin to rain down up to your weapons range away, in a 15-foot radius sphere centered on a point of your choice. Each bolt or arrow is tethered to you as your chakra is used as a binding chain. Creatures in the radius of this jutsu must make a Dexterity saving throw taking your [weapons damage] + 3d8, being restrained by the bolts or arrows pinning them to the ground on a failed save until the beginning of their next turn or only half as much damage on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of spaces you can select by +1.", created_at: NOW, updated_at: NOW },
  { _id: "15a57674fd5949dd1ba03bce", name: "DANCE PERFORMANCE: GAMBIT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "9 Chakra", components: "W (Any)", duration: "Concentration, up to 1 minute", description: "You enter a focused but extremely passive stance with a looser grip on your weapon and more chakra around the edge and the soles of your feet, letting gravity and speed take the wheel. You do not spend chakra to maintain concentration on this jutsu. You can only drop concentration of this jutsu as a bonus action on your turn. For the duration, if you move more than 20 feet before making an attack with your weapon, you increase your critical threat range by +1 and Your [weapons damage die] is also increased by +1. For the duration of this jutsu, melee attacks against you have a +1 critical threat range.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher increase the [weapons damage die] by +1. If this jutsu is cast at A-Rank or higher, increase the weapons critical threat range by +1. If this jutsu is cast at S-Rank, increase both by an additional +1.", created_at: NOW, updated_at: NOW },
  { _id: "e35e683360fa5baddb68435e", name: "DANCE PERFORMANCE: FLAMENCO", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "7 Chakra", components: "W (Melee, Any), M", duration: "Instant", description: "Your fiery moves bring down even the toughest of foes. Make three melee Taijutsu attacks against a creature you can see within range, dealing your [weapons damage] + 2d4 fire damage for each attack. You do not add your ability score to damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the fire damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "db9cc9d57b304da6b6ca4e52", name: "DANCE PERFORMANCE: PREPARATION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Melee, Any), M", duration: "Concentration, up to 1 minute.", description: "You change your breathing, preparing for an extreme dance. For the duration of this jutsu, jutsu with Dance Performance in the name that deal damage also gain the Chain (1) keyword.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e3044c4ebec243c6c32228e2", name: "DANCE PERFORMANCE: SECOND STEP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Any Melee Weapon)", duration: "Instant", description: "You swing your weapon in a violent circle around you hitting all creatures around you. All Creatures within your weapons range of attack of your choice must make a Dexterity Saving throw. On a Failed save, they take your [weapons damage] + 5d4 and become Dazed until the end of their next turn or half as much on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and Damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "ba04cb5e6f890ff1bdb21b9c", name: "DANCING FOOL TWISTER [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "8 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You whip your weapon with the Strength to create a small twister at your command. All creatures in your weapon range in a sphere around you must make a Strength Saving Throw or take your [weapons damage] +2d8 and be thrown back 30 feet. If this jutsu is cast as a Chain 2, increase the damage die by 1. If this jutsu is cast as a Chain 3 increase the damage die by an additional +1", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and the number of feet thrown in the air by 10. 291", created_at: NOW, updated_at: NOW },
  { _id: "206f1df48e1fdb0a210d2af0", name: "DANCING FOOL’S EMBRACE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range (15-foot Radius sphere)", chakra_cost: "8 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You whip your weapon with the finesse to wrap around your enemies and bring them into a tight and lethal embrace. All hostile creatures in range must make a Strength Saving Throw or be pulled within 5 feet of you and become restrained and take your [weapons damage]. While you have a creature restrained in this way, you cannot use the weapon used to cast this jutsu for attacks or other jutsu. As a Bonus action, while you have a creature restrained by this jutsu, you can immediately tighten the embrace, dealing 3d10 damage. A creature can remake this save as an action and at the end of their turns to end the Restrained condition. If this jutsu is cast as a Chain 2, increase the damage die by 1. If this jutsu is cast as a Chain 3 increase the damage die by an additional +1", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the range by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "5479b004ebd99642edd807ef", name: "DISARMING RIPOSTE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction", range: "5 Feet", chakra_cost: "8 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You use your weapon to get around your opponent’s guard as they attack, and then bring it up in an attempt to disarm them, literally. As a reaction to being hit with a melee attack, you increase your ac by 1+ half your [weapons damage die]. If this would increase your AC by enough to make the triggering attack miss, you can make a melee Taijutsu attack contested by the original attack roll. On a hit you deal your [weapons damage] and then the triggering creature must make a Strength Saving throw or be disarmed of their weapon. If you had a free hand when you cast this jutsu, you instead grab their weapon from them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4c1310166ebbbdd1d763c858", name: "DRAUPNIR JAVELIN [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "8 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You trace the design of your spear in chakra and create a near copy of it made of chakra. You then throw the copy towards a target creature in range, sending it flying out in a deadly arc. Make a Ranged Taijutsu attack against the target creature. On a hit you deal your [weapons damage] +1d12 and they must make a Constitution saving throw. On a failed save they are rooted to the ground, becoming restrained, remaking the save at the start of their turns to end the condition. As a Bonus Action or reaction, you can cause the copy of the spear to explode, ending the restrained condition and dealing 2d12 force damage to the creature and any creature within 5 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8afea698066777762245e206", name: "EARTH BREAKER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range (20-foot cube)", chakra_cost: "8 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You slam your weapon into the ground with enough force to upheave the earth. Creatures in a 20- foot cube originating from you must make a Dexterity saving throw taking 3d8 bludgeoning damage and is knocked prone on a failed save. If a creature falls prone within your weapons attack range when you cast this bukijutsu, you may, as a part of casting this jutsu, make a melee Taijutsu attack against the prone target dealing your [weapons damage] + 2d12 Bludgeoning on a hit.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8 and 1d12 respectively. 292", created_at: NOW, updated_at: NOW },
  { _id: "623c52bcb360d3efda6e3203", name: "EXECUTIONER’S SWING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "9 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "As a requirement to activate this jutsu, you must be targeting a creature who is either; Grappled, Prone, Restrained, shocked, slowed, Stunned, or Unconscious. You swing your blade with such ferocity that the air and other materials or objects in its path doesn’t recognize that it’s been slashed. Make a melee Taijutsu attack, with a +1 bonus to its critical threat range, dealing your [weapons damage] + 6d6 slashing damage on a hit. If this jutsu is cast as a Chain 2, increase the damage die by 2. If this jutsu is cast as a Chain 3 increase the damage die by 1 steo.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at S-Rank, increase the bonus damage die by 1 step.", created_at: NOW, updated_at: NOW },
  { _id: "3e14c0f318b081ee33d1dc8d", name: "FALLING BLADE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "8 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You perform a single Powerful downward slash that slices through just about everything in your path. Make a melee Taijutsu attack with a 1d4 penalty to the attack, because of how obvious your attack angle is. On a hit, you deal your [weapons damage] + 3d10 and inflicting two ranks of the Bleeding Condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and Damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "1844b6626a394aa07476993b", name: "FLYING SWALLOW: PENETRATE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "W (Melee Piercing, Light), M", duration: "Instant", description: "As a part of the activation of this jutsu, you must have a weapon in both hands that meet this bukijutsu component requirements. You take your weapon and infuse chakra into the heels of your feet and use the increased power to penetrate whatever is in your way. Make two melee Taijutsu attacks against up to two enemies within 5 feet of you dealing your [weapons damage] + 3d6, you do not add your ability modifier to damage. Affected creatures must make a Constitution saving throw having their AC is reduced by 1d4 for each successful hit, until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "ad8d66c07aff822705abb2ab", name: "FRONT BEHEADING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "Special", components: "W (Any), M", duration: "Instant", description: "You Flip the grip of your weapon to perform another attack but in the opposite fashion. You immediately cast the Bukijutsu you previously cast as an Action this turn, as a bonus action. When you do cast this Bukijutsu, increase the cost by +3. When cast as part of a chain. You can cast the last bukijutsu you cast, regardless of chain casting limits. You can only use Front Beheading once per chain.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "82d83467c13d17224c8863be", name: "FUMA KOTARO’S SKILL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Throwing Stance. You begin to embody the legendary shinobi and tactician Fuma Kotaro. His technique begin to radiate from you. Select a number of creatures you can see within range, equal to your proficiency bonus. Make one ranged Taijutsu attack against each creature, dealing your [weapons damage] + 2d12. Additionally, for each successful hit, you gain special resource called Hojo dice which are D4’s. These dice last until the end of your next turn and you can give them to allied creatures which they can choose to use as bonuses to their next attack, damage or skill check roll. A creature can only ever have two dice at a time. 293", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5fa5ed813af36da581e3f454", name: "GRAND SLAM [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "8 Chakra", components: "W (Melee bludgeoning), M", duration: "Instant", description: "You enter the stance of a batter and swing your weapon towards your target making a Taijutsu melee attack. On a hit, you deal your [weapons damage] + 3d8 and makes a Constitution Saving throw. On a failed save they are knocked back 40 feet. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage as if they had fallen an equal distance.", at_higher_ranks: "For each rank you cast above C- rank, increase the cost by 3, the critical threat range by +1 and the distance the enemy would be knocked back by 20 ft. If upcast to B-Rank or higher, if you score a critical hit with this jutsu, the creature automatically fails their Constitution save.", created_at: NOW, updated_at: NOW },
  { _id: "1f1a1b887d5f4b8e580995a9", name: "GUAN YU’S LOYALTY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Melee, Two-Handed or Versatile), M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Polearm Stance. You begin to embody the legendary general and warrior Guan Yu. His essence begins to seep into your pores and his ferocity and Strength becomes yours as you perform a wide and powerful sweep in a circle around yourself. All creatures in your weapons range originating from you, of your choice, must make a Dexterity saving throw taking your [weapons damage] + 4d12 on a failed save or half as much on a success, you do not add your ability modifier to damage. Additionally, until the beginning of your next turn, creatures who would enter a space that your weapon can could reach they suffer a penalty to their attack roll against you equal to your [weapons damage die].", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "e4670b75d4a41424356f5c31", name: "GUARDIAN KNIGHT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Medium or Heavy Armor), M", duration: "Concentration, up to 1 minute.", description: "As a requirement to activate this jutsu, you must currently be in the Defensive Stance. You cannot lose concentration of this jutsu as a result of damage. You solidify your defenses and reinforce your position. For the duration, you gain a +1 bonus to AC if wearing Medium Armor and +2 if wearing Heavy Armor. Additionally, if the armor you have has the Reinforced property, you increase your Reinforced value by +2.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage you reduce by +2.", created_at: NOW, updated_at: NOW },
  { _id: "5924bbc0f4bad8de2872e9f0", name: "HEAVEN CUTTER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "8 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You swipe your weapon upwards with enough force to create an updraft. This updraft manifests a cylinder of force. You create a 30-foot-high, and 15-foot- wide cylinder originating from you. Creatures in this cylinder must make a Strength saving throw or be thrown upwards, towards the top of the cylinder. At the end of your turn, creatures and objects thrown upwards fall to the ground, landing prone, taking fall damage, and gaining 1 rank of weakened until the end of their next turn. If this jutsu is cast as a Chain 2, you can cast a Chain X jutsu as a bonus action this turn. If this jutsu is cast as a Chain 3 they instead fly 90 feet into the air.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7e5767b2c011e2c099987109", name: "HEAVENLY PUNISHMENT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "9 Chakra", components: "W (Any Weapon)", duration: "Instant", description: "You strike with your weapon from as many angles as you can see an opening for. Roll 1d4 + 1. Make a number melee or ranged Taijutsu attacks equal to the result dealing your [weapons damage] on a hit. These attacks cannot score a critical hit.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the size of the die by 1 step. (D4>D6>D8>D10) 294", created_at: NOW, updated_at: NOW },
  { _id: "b251325f3cdfdd12a9344e4e", name: "HEAVY METAL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, which you take when you would take damage.", range: "Self", chakra_cost: "9 Chakra", components: "W (Heavy Armor), M", duration: "1 Round.", description: "You ensure the armor your wearing is the most potent thing on the battle field by using its coverage to intercept all incoming damage. Until the start of your next turn, you have a +4 bonus to AC against the triggering creature, and a +2 bonus to your AC against all other attacks targeting you. Additionally, if the armor you have has the Reinforced property, you increase your Reinforced value by +4.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage you reduce by 2.", created_at: NOW, updated_at: NOW },
  { _id: "fe33507adf75b25520f1f7ec", name: "HOLLOW SILHOUETTE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "60 feet", chakra_cost: "8 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "As you spin your weapon and move towards the target you sidestep back and forth quickly into their blind sides, leaving only an outline of you to see. Make a contested Stealth check against the target creature’s Perception. On a success you can immediately move to be within 5 feet of them and you gain advantage on the next attack roll you make against them this turn. On a failure you have disadvantage on the next attack roll against them this turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the range by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "47abb6daf4ca4baa50b63f51", name: "HURRICANE DANCE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons", chakra_cost: "8 Chakra", components: "W (Ranged Slashing), M", duration: "Instant", description: "You throw your weapon in a circle around you, slicing at all around you and making it hard to even stand near you. All creatures in a 15-foot radius around you must make a Dexterity saving throw when this jutsu is cast. On a failed save they take 5d6 slashing damage and lower their movement speed by 20 feet. On a successful save they take half damage and no further effects. At the start of a creature who failed this save turn they must make a Constitution saving throw. On a failed save they take an additional 3d6 slashing damage and cannot move towards you this turn as the weapons slash into their tendons.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "f9baeaa1c41490616e80c7be", name: "IRON WEB DOME [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 reaction to you or ally in range takes damage", range: "Radius Sphere up to weapons range", chakra_cost: "8 Chakra", components: "W (Any Flail), M", duration: "instant", description: "You whip your weapon around at high speeds, creating a dome to defend against attacks. You can set the radius of this doom up to your weapons range. The Dome has an AC equal to your Taijutsu Save DC and Hp equal to twice your [weapons damage] and intercepts all damage originating outside the dome. A creature who hits the dome with a melee attack and fails to break it takes damage equal to your [weapon’s damage die].", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, a creature who hits with it a melee attack instead takes twice your [weapons damage die] in damage, regardless of if it breaks or not.", created_at: NOW, updated_at: NOW },
  { _id: "44376ffa53fe49fe4cbaa074", name: "LETHAL AMMO TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "6 Chakra", components: "W (Any, Ammunition), M", duration: "1 Round.", description: "You sharpen and increase the weight of your ammunition by using your chakra. Until the start of your next turn, ranged weapon attacks you make add 1d4 to both attack and damage rolls. Additionally, if the result of the d20 and d4 is equal to or greater than 20, the attack is treated as a natural 20.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the size of the bonus die by 1 step.", created_at: NOW, updated_at: NOW },
  { _id: "1781dd549de471ef914121b4", name: "LIGHT WEIGHT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "9 Chakra", components: "W (Light Armor), M", duration: "Concentration, up to 1 minute.", description: "You begin to make full use of all of the mobility and freedom your armor provides. For the duration, you gain a +10 bonus to your movement speed and you add half of your Armor bonus to your Dexterity saving throws. If you are ever knocked prone, restrained or grappled, this jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the movement speed bonus by +10. 295", created_at: NOW, updated_at: NOW },
  { _id: "bf5699ccbd12e295476a80b0", name: "MIKIRI COUNTER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, being hit with an attack.", range: "Self", chakra_cost: "9 Chakra", components: "W (Any Melee Weapon), M", duration: "Instant", description: "You see a melee attack coming at you and your body doesn’t allow it to proceed any further. You instinctively use your hand or feet to not only attempt to parry the attack, but to also drive the attack into the ground, getting it stuck and opening the triggering creature up to a counter attack. When you are hit with a melee attack, make a melee Taijutsu attack, if your attack result is higher than the triggering creatures, their attack and all other attacks made as part of the same action misses and you make a single melee attack against them dealing your [weapons damage] and reducing the creature’s AC by 1d4 until the start of their turn. If they attacked with a weapon, their weapon falls from their hands on the ground within their space.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "59982e24e481e6ceb8645a9b", name: "MODERATE REFLEXES", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "9 Chakra", components: "W (Medium Armor), M", duration: "1 minute.", description: "You begin to make full use of the balance in mobility and protection your armor provides. For the duration, you gain a +10 bonus to your movement speed, and if the armor you have has the Reinforced property, its value increases by +3. Additionally, you add half of your Armor bonus to your Strength saving throws, rounded down. If you are ever knocked prone, restrained or grappled, this jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the movement speed bonus by +5 and the Damage Reduction by +2.", created_at: NOW, updated_at: NOW },
  { _id: "ba565ceca2ed39f36e0589b5", name: "MONKEY KINGS ARROGANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "9 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You spin your weapon around yourself with enough force to create updrafts and powerful winds. But all of the weapon spinning is mostly for show as you then use your weapon to launch your allies like missiles towards a creature of your choice helping them crash into them. Select up to two allied and willing creatures within your weapons range. They are thrown a number of feet up to 10 x your Taijutsu ability modifier. If they would end this movement within 5 feet of a hostile creature, they can spend their reaction to cast a Jutsu that requires a melee attack, that has a casting time of 1 Action, targeting the hostile creature. Additionally, the creatures you throw gain a bonus to their melee attack roll, equal to your [weapons damage die].", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d0c3e874ff043cf083a7208e", name: "MONKEY KINGS CUNNING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "7 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You spin your weapon around in a series of distracting twirls before you strike as your targets arm and leg joints disabling their mobility and striking power. Make two melee Taijutsu attacks using your weapon, dealing your [weapons damage] + 2d10. If at least two attacks using this jutsu are successful, you reduce the targets speed by -10 and they have a -1 penalty to Strength and Dexterity based Saving throws, skill checks and attack rolls until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3, the movement speed penalty by -5 and the saving throw, skill check and attack roll penalty by -1. 296", created_at: NOW, updated_at: NOW },
  { _id: "2791695179c3caa3cefb78e3", name: "MULTISHOT BOW TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 bonus action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Any Bow)", duration: "1 Round", description: "You quickly prepare multiple shots from your bow of choice, ready to fire on hostile creatures. You skillfully knock two arrows or bolts into your bow as you prepare to fire. Until the beginning of your next turn, when you deal damage with your bow, you roll your [weapons damage die] twice adding the results together with your ability modifier on a hit. You only roll your ammunition die once per attack as usual. Also, creatures within the range of your weapon provoke attacks of opportunity for you the first time they move. You gain additional reactions equal to your Taijutsu ability modifier, that you can only use to make a ranged Taijutsu attack if a creature triggers attacks of opportunity until the beginning of your next turn. Creatures hit by your attacks of opportunity using your bow, have their movement reduced to 0, until the beginning of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0080e3fa1f46a16459739db9", name: "MURDEROUS STABBING LINK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "15 feet.", chakra_cost: "8 Chakra", components: "W (Melee Piercing)", duration: "Instant", description: "You perform a series of thrusts with your weapon with enough force to penetrate steel, sending powerful piercing shockwaves up to 15 ft in a straight line stopping at the first creature hit. Make a melee Taijutsu attack against a target within range, dealing your [weapons damage] + 2d10 and gains the bleeding condition, and all creatures in a 15-foot line behind the target takes damage equal to half of the result. If this jutsu is cast as a Chain 2, increase the damage die by 2. If this jutsu is cast as a Chain 3 increase the damage die by 1 step", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ed50dec68e510bbf45027c4a", name: "MUSASHI’S WILL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "W (Any), M", duration: "Concentration, up to 1 minute", description: "As a requirement to activate this jutsu, you must currently be in the Two-Weapon Stance. You cannot lose concentration on this jutsu as a result of damage. You roar, releasing a rush of adrenalin throughout your body. For the duration, when you take the attack action you gain an additional weapon attack. Additionally, if you cast a Bukijutsu that requires you to make two or more attacks, you make 1 additional attack.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cee8f95c3d53a72fc61fac1c", name: "NOBUNAGA’S FURY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "8 Chakra", components: "W (Any Two-Handed), M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Great Weapon Stance. Your eyes glaze over with a blood fueled fury, for but a moment. Make one melee Taijutsu attack using your weapon, dealing your [weapons damage] + 4d8, rerolling all 1’s and 2’s, taking the second result even if it is a 1 or 2. Additionally, if you score a critical hit with this attack you add your level to the damage dealt.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c8b6f6eadb1a5bbff8fac78a", name: "NOBUNAGA’S RAGE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "8 Chakra", components: "W (Any Heavy), M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the Heavy Weapon Stance. Your eyes glaze over with a blood fueled rage, for but a moment. Select one creature you can see within your weapons range, as you swipe it towards them with such speed and ferocity that the ground, air, and even water crackles and ignites from the force of your attack alone. You can choose to either make a melee Taijutsu attack using the weapon or force the creature to make a Strength saving throw. If you make a melee Taijutsu attack, on a hit, you deal your [weapons damage] + 8d6 The select creature must make a Strength saving throw taking your [weapons damage] +6d6 on a failed save or half as much on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "b3c70b2c0e26a133434e5cc0", name: "POST SETTER [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "1 Action", chakra_cost: "8 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You plunge your weapon into the foot of your target, rooting them to the ground. Make a melee Taijutsu attack against a creature in range. On a hit deal your [weapons damage] and they become Restrained until the start of your next turn. While they are restrained you cannot use this weapon. While they are restrained an allied creature can use their reaction to cast a Bukijutsu or a Taijutsu Finisher or a Chain X Bukijutsu. 297", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e47df9c28b9ec4a5c32c5b22", name: "PRIDE OF LETO [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Ranged Piercing), M", duration: "Instant", description: "You funnel your chakra into the point of your weapon, feeling the pride of the mother of the twin archers in your bones, unleashing a scatter of shots toward a creature within range. Roll 1d4, choose any number of targets to hit with an attack based on the roll. (You may attack the same target more than once.) Make a ranged Taijutsu attack for each shot. On a hit, you deal your [weapon’s damage]. You do not add your ability modifier to the damage roll. If this jutsu is cast as a Chain 2, you can add your ability modifer to up to 2 damage rolls. If this jutsu is cast as a Chain 3 you instead roll a 1d6 for choosing targets.", at_higher_ranks: "For each rank, you cast this jutsu above C-rank, increase the cost by 3. If this jutsu is cast at A-rank or higher, increase the damage die of your weapon by 1.", created_at: NOW, updated_at: NOW },
  { _id: "984a5099fffb5a96aad9c120", name: "RETREATING THROW [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, when a creature would miss you with a melee attack", range: "Weapon's Range", chakra_cost: "8 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "After someone misses you with an attack you quickly retreat and you reset your positioning. Move up to your movement speed to a space you can stand on. After the conclusion of your movement make a ranged Taijutsu attack dealing your [weapon’s damage] and forcing the creature to make a Strength saving throw or be restrained on a failed save, as your weapon pins their foot to the ground. A creature restrained by this jutsu can, as an action make a repeat the saving throw, ending the restrained condition on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "62069eea2ca8408e583dd89c", name: "RIPPING LUNGE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "10 feet", chakra_cost: "8 Chakra", components: "W (Ranged Slashing), M", duration: "Instant", description: "You lunge forward, using chakra to spin your weapon while striking your opponent in the opposite direction to maximize the amount of lethal rip page, showing how your weapon is not out of options in close range. Make a melee Taijutsu attack, on a hit you deal your twice your [weapons damage die]. If you roll the maximum damage on your [weapons damage die], you also leap back half your movement speed. This movement does not trigger an attack of opportunity.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "58b94709dbd27b38e2c8a93d", name: "SEEKING ARROW [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "Action", range: "90 Feet", chakra_cost: "8 Chakra", components: "CM, M, W (Ranged Piercing)", duration: "Instant", description: "You imbue a projectile with chakra, granting your weapon the ability to seek out a target. Choose a creature you can see within range. The projectile flies toward that creature, moving around corners if necessary and ignoring three-quarters cover and half cover. If the target is within the weapon's range and there is a path large enough for the projectile to travel to the target, the target must make a Dexterity saving throw against your Taijutsu save. Otherwise, the projectile disappears after traveling as far as it can. On a failed save, the target takes damage as if it were hit by the projectile, plus an extra 4d6 force damage. On a successful save, the target takes half as much damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "5232546c51dbb69f9cb18bfc", name: "SERRATION WAVE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "45 Foot Cone", chakra_cost: "8 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You swing your weapon in a wide arc meant to impede movement and lockdown your enemies. All creatures in a 45-foot cone in front of you must make a Dexterity Saving Throw. On a failed save they take your [weapons damage] +2d4 and lose half their movement speed until the end of their next turn. On a success they take half damage and do not suffer any additional effects.", at_higher_ranks: "for every rank above C-rank this jutsu is cast, increase the chakra cost by 3 and damage die by 1 step. If this is cast at A-Rank they instead lose all movement on a failed save and half on a success.", created_at: NOW, updated_at: NOW },
  { _id: "2b4892409560eb6a1c842797", name: "SHOCKWAVE SLASH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "30ft", chakra_cost: "7 Chakra", components: "W (Melee Slashing), CM, M", duration: "Instant", description: "You coat the ends of your weapon in chakra before swinging and creating a crescent shaped wave of super sharp chakra that cuts through all enemies in its path. Targets in a 30-foot line that’s 5-feet wide must make a Dexterity saving throw, taking [weapons damage] +3d4 slashing damage on a failed save, or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and Damage by 2d4. 298", created_at: NOW, updated_at: NOW },
  { _id: "d134c5d724446302b2acc596", name: "SPEAR ASSAULT [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Half Remaining Movement", chakra_cost: "8 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You thrust out with your weapon while also making afterimages of the weapon while moving forward. You can move up to half your remaining movement speed in a direction as a part of casting this jutsu. All hostile creatures within 5 feet of your movement path must make a Dexterity saving throw, taking your [weapons damage] +1d10 on a failed save and gaining a rank of bleeding.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. If this jutsu is cast as an A-Rank, you can instead move your full movement.", created_at: NOW, updated_at: NOW },
  { _id: "52c97369bad05669daff42a7", name: "SPINNING STEEL BALL [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon's Range", chakra_cost: "8 Chakra", components: "W (Ranged Bludgeoning), M", duration: "Concentration, Up to 1 minute", description: "You coat your weapon in chakra that keeps it spinning, building up energy before unleashing it in devastating fashion. For the duration of this jutsu, your weapon increases its die step by 1 and range by 30 feet. If you would deal damage to a Bruised creature, you roll damage as if they had an additional rank of Bruised.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a25686cf1dfd500139d6688e", name: "SQUALL'S FURY [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range (30-foot cube)", chakra_cost: "8 Chakra", components: "W (Ranged Piercing), M", duration: "Instant", description: "You fire multiple projectiles into the sky which then fall down like rain upon your enemies. Choose a point you can see within range. All creatures within a 30-foot cube of that point must make a Dexterity saving throw or take your [weapons damage] + 2d6 and gain a rank of Slowed on a failed save, or half as much and no additional effects on a successful one. If you have to roll your weapons ammunition die, roll twice, taking the lower result.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the ranks of Slow by 1 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "6ad3389a09f9601008075532", name: "STRAIGHT RETURN [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action or Reaction after making a Ranged attack with a thrown weapon", range: "Weapons Range", chakra_cost: "8 Chakra", components: "W (Any Thrown), M", duration: "Instant", description: "You quickly pull-on attached chakra or iron strings to pull your weapon back, looking to catch your enemies off guard. All creatures in a straight, 5-foot-wide line from you to your weapon must make a Dexterity Saving Throw, taking your [weapons damage] +2d6 on a failed save and being knocked prone, taking half as much and no further effects on a success. If you miss a creature with a ranged attack before casting this jutsu, they have disadvantage on this saving throw, being lulled into a false sense of security. If this jutsu is cast as a Chain 2, increase the damage die by 1. If this jutsu is cast as a Chain 3 increase the damage die by an additional +1", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage die by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "4a2e4a3b098a6a32e0692613", name: "SURPRISE ATTACK [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons", chakra_cost: "8 Chakra", components: "W (Ranged Slashing), M", duration: "Instant", description: "As a requirement for casting this jutsu, you must target a willing creature within 5 feet who knows Advanced Transformation and is currently in the form of a ranged slashing weapon. You throw your ally in an easily avoidable trajectory to catch your enemy off guard. Make a ranged Taijutsu attack vs target creatures Passive Perception. On a success, your attack is seen as genuine and they believe that you have just missed. Your ally can then, as a reaction, revert into their original form and make a weapon attack or cast a jutsu with a casting time of 1 action. This attack is made at advantage and they are treated as surprised against this attack. On a failure, your ally can still use their reaction to complete the jutsu, however they make their attack at disadvantage. 299", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c18a6ce5d9cb1009e33412b4", name: "SWIFT JUSTICE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Reaction when you or an allied creature within range takes damage from a melee attack.", range: "Weapons Range", chakra_cost: "8 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You strike out with your polearm to serve justice to those who seek to wrong you. Make a melee Taijutsu attack against the triggering creature: If this in reaction to you taking damage, you deal [weapons damage] plus ¼ of the damage you took on a hit as you use the momentum of your enemy and use it to fuel your attack If this is in reaction to an ally taking damage, you reduce the damage they take by your [weapons damage] on a hit as you disrupt their attack, lessening the power.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0e02474dea8921829fc8eccf", name: "SWORD AURA: ORANGE [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Any Blade), M", duration: "1 Minute", description: "You must be under the effects of Sword Aura: Red to cast this jutsu. You Strengthen your Sword Aura, flooding more chakra into your sword, the striking portion flaring orange from the mixing of chakra. Sword Aura: Red ends and you replace the effects with this jutsu’. Your weapon now has pierce (8). Twice per turn when you deal [weapons damage], you can force all creatures in your weapons range to make a Strength Saving Throw, taking 2d10 Fire damage on a failed save and they are knocked prone from the force of the blast. If a creature fails this save twice in the same turn, they also gain a rank of Concussed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "90b87abbecfa40cfbb2dcdc1", name: "SWORD AURA: YELLOW [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You must be under the effects of a Sword Aura to cast this jutsu. You use the built-up chakra in your blade to have it explode out in a lethal yellow color as your spin, striking all who stand before you. All creatures within your weapons reach must make a Dexterity saving throw, taking your [weapons damage] +3d8 on a failed save. On a success they instead take half damage", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6b2e69214d5d7ca79bcd61a1", name: "TAMETOMO’S ACCURACY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "9 Chakra", components: "W (Any Ranged), M", duration: "1 Round", description: "As a requirement to activate this jutsu, you must be in the Sharpshooter Stance. You make attacks at such odd angles that it becomes basically impossible to avoid you and you use this accuracy to support your allies. When you would see your ally make a ranged attack, you can, as a part of their attack make a ranged Taijutsu attack using your weapon. On a hit, you deal your [weapons damage] and the target must make a Constitution saving throw to resist gaining 3 ranks of bleeding on a failed save as your shot punctured a vein or artery. You can only make an attack this way once per turn, until the beginning of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at S-Rank, it scores a critical hit on a d20 roll of 16-20.", created_at: NOW, updated_at: NOW },
  { _id: "42acffa524b6e7e9b4bd4d22", name: "TANUKI’S TRICKERY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Reaction, which you take when a creature you can see would make a ranged attack.", range: "90 Feet", chakra_cost: "6 Chakra", components: "W (Any Thrown), M", duration: "Instant", description: "You throw your weapons with such efficiency and knowledge for how they will hinder your targets, that you become a major headache on the battlefield. When you would see a hostile creature making a range attack, you throw your weapon, making a ranged Taijutsu attack. On a hit, you select a new valid target for the attack other that the caster themselves. If a jutsu makes a specification in regards to the casters allies or hostile creatures, you ignore that distinction as a part of this jutsu’ s effect. 300", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d0dc891218fd3cfb3d0f78b7", name: "THOUSAND SCATTERED BLOSSOMS [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range (15-foot Radius sphere)", chakra_cost: "8 Chakra", components: "W (Any Thrown), M", duration: "Instant", description: "You throw your weapon towards a point and using your skill and chakra you bounce it around at high speeds in that area, as if lethal blossoms had been scattered. Choose a point in your weapons range. All creatures within a 15-foot radius sphere centered on that point need to make Dexterity Saving throws, taking your [weapons damage] +2d4 damage and gaining a rank of bleeding. If a creature fails by 5 or more, they instead gain 2 ranks of Bleeding. If this jutsu is cast as a Chain 2, increase the damage die by 2. If this jutsu is cast as a Chain 3 creature’s have a d4 penalty to their saving throw.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage die by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "648442596033d08a855128d3", name: "TOKUGAWA’S PRIDE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action.", range: "Self", chakra_cost: "9 Chakra", components: "W (Any Slashing), M", duration: "Concentration, up to 1 Minute", description: "As a requirement to activate this jutsu, you must be in the Blade Stance. While holding your weapon you begin to acknowledge its beauty and perfection. This fills you with the Pride of Tokugawa. When you cast this jutsu, your amazement with your blades sharpness doesn’t end there. Every two successful Taijutsu attacks made with your weapon increases its critical threat range by +1 until the end of each of your turns.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e46469be8cc0aa97ab93ce41", name: "TORIYAMA’S GENIUS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "6 Chakra", components: "W (Any), M", duration: "Concentration, up to 1 minute", description: "Your mind begins to wander as you begin to fight with pre-choreographed maneuvers you thought of on the fly. For the duration, you can gain the benefit of two Weapon Stances. You can switch the weapon stances at will as a bonus action. You do not need to know the stances in order to gain their benefits, instead, if you do not know a weapon stance, you can gain its benefits until the end of your next turn, after which you must switch to another stance immediately. When you end this jutsu, you cannot recast it until at least 1 minute has passed in which you stress your mind thinking of different things.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e40c9189541594793d4bdfec", name: "TRIPLE WINDMILL BLADES", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60ft", chakra_cost: "7 Chakra", components: "W (Thrown property and Battle Wire)", duration: "Instant", description: "You launch your prepared weapons into two different directions intentionally avoiding hitting your target then pulling on the battle wire to cause them to avert their direction and change trajectory. Target Creature has the wires circle them until the weapons land in the ground locking them into place. Target creature must make a Dexterity Saving throw or become Restrained. A creature restrained by this jutsu can, as an action make a Strength check vs your Taijutsu save DC to escape, ending the restrained condition. Additionally, restrained creatures cannot make hand seals.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a5d958e0b10828553cc28b9f", name: "VIPER’S RETREAT [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Weapons range", chakra_cost: "8 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You take a step back while thrusting at your full range. Make a melee attack against the triggering creature, dealing your [weapons damage] on a hit and giving them one rank of Bleeding. At the same time you step back until the target creature is at the very end of your weapons range. This movement cannot trigger an attack of opportunity from the target creature.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, they gain 2 ranks of bleeding instead. 301", created_at: NOW, updated_at: NOW },
  { _id: "9bc3528a39fa4922a9b359ec", name: "WRECKING BALL [NEW]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Line (Weapons Range)", chakra_cost: "8 Chakra", components: "W (Ranged Bludgeoning), M", duration: "instant", description: "You throw your weapon with such ferocity, it is if a wrecking ball swings from your hand. All creatures in a 5-foot-wide line stretching from you to a point no more than your weapons normal range must make a Strength Saving Throw. On Failure they take your [weapons damage] +2d10 and are knocked prone. On a success they only take half damage and no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "efd65629a1ca00e030970739", name: "YASUKE’S LEGACY", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action.", range: "Self", chakra_cost: "7 Chakra", components: "W (Any), M", duration: "Concentration, up to 1 minute", description: "As a requirement to activate this jutsu, you must be in the Equilibrium Stance. You cannot lose concentration on this jutsu as a result of damage. Your weapon is equal parts a tool, an extension of your body and your true self. You take a stance reminiscent of the legendary Samurai Yasuke, in which you gain a +1 bonus to all of your saving throws, +1 bonus to your Bukijutsu’s damage die and your weapons gain the reach property, if they did not already.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "06b64b64c91098bb6755684c", name: "YOICHI’S FOCUS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action.", range: "Weapon Range", chakra_cost: "7 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "You focus your mind and eyes on a target of your choice. Make a ranged Taijutsu attack, targeting one creature you can see dealing your [weapons damage]. This attack has a +1 bonus to critical threat range. If you score a critical hit with this attack, you multiply your [weapons damage die] by 3.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If you cast this jutsu at A-Rank and score a critical hit, you multiply your [weapons damage die] by 4. B-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "31cc0a78442ae53068328dff", name: "1-STRIKE PIERCING BLOW", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "14 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You put your utmost focus behind a single strike with your piercing weapon, meant to end the fight in that very instant. Make a melee Taijutsu Attack, dealing 7d8 Piercing Damage and forcing the target creature to make a Constitution saving throw, being Stunned on a failed save until the end of the next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and Damage by 1d8", created_at: NOW, updated_at: NOW },
  { _id: "16335df482d803cb0fca6737", name: "ABYSSAL AURA [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b7c3bde363176d05f69f793a"], elements: [], casting_time: "1 Bonus Action", range: "Self (30-foot radius sphere)", chakra_cost: "12 Chakra", components: "W (Any Flail), M", duration: "1 minute", description: "You spin your weapon slowly, letting the end of it clink against the other end or the ground, it’s slow grind eliciting fear from those around you. For the duration, creatures who start their turn within 30 feet of you must make a Wisdom Saving throw on a failed save; they become Uneasy until the end of your next turn. You gain the following benefits against an Uneasy enemy: • Your weapon attacks against an Uneasy target deal an extra 1d8 force damage • You can always react against an Uneasy Enemy as long as you can still act, regardless of circumstance. • An Uneasy Enemy always triggers an Attack of Opportunity when they leave your range, regardless of circumstance. • An Uneasy Enemy has disadvantage on attack rolls not against you.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, and range by 15 feet. 302", created_at: NOW, updated_at: NOW },
  { _id: "471c82957acad4618e2c616e", name: "AIR SNATCHER [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Ranged Bludgeoning), M, CM", duration: "Instant", description: "You fire your weapon with enough force to rip the air out of your opponent. Make a Ranged Taijutsu attack Against a creature in range, dealing your [weapons damage] +5d10 and reducing the target creature's speed by 10 feet on a hit and until the end of their next turn, the target creature also has disadvantage on their next Constitution Saving Throw. If this jutsu is cast as a Chain 2, increase the damage die by 2. If this jutsu is cast as a Chain 3 increase the damage die by an additional +2", at_higher_ranks: "For each rank you cast this jutsu above B rank, increase the cost by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "430b060efb0e74f4507c1610", name: "ALL-IN ATTACK [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "Special (36 Chakra).", components: "W (Any)", duration: "Concentration, Up to 1 Minute", description: "You lead your allies to capitalize on a brief moment where the enemy is left completely open. To cast this jutsu you must have at least 1 ally within 30 feet who can join in on the casting. If that ally has benefited from Baton Pass in this combat, they can immediately join the casting without needing to spend a reaction. All casters make two Melee Taijutsu attacks against the target creature, dealing [weapons damage] +3d8 on a hit. If the target is hit with at least 1 attack from all creatures it gains 2 ranks of weakened and bruised. If all attacks are successful, it instead gains 5 ranks of weakened and bruised. If this jutsu would reduce a target creatures health to 0, they are instead killed immediately. Combination: When this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. • +0-1: No Change. • +2-3: The damage die of the jutsu increases to a d10. • +4-5: The damage die of the jutsu increases to a d12.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "20a62cd94b3237c2fcfd0066", name: "AMMO HEART [NAME/ CHANGED]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "11 Chakra", components: "W (Ammunition Group), M", duration: "Concentration, up to 1 minute.", description: "As a requirement to activate this jutsu, you must have a weapon from the Ammunition weapon group equipped. All Bukijutsu you cast, that uses a Jutsu with the Ammunition property does not require you to roll the ammunition die. Additionally, when a creature would make a melee attack against you, at the conclusion of the attack, you can move 10 feet in any direction as you move to create distance.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "57e88881dc6bd3f4b1a55279", name: "AMPUTATION PUNISHMENT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Chained Hand Scythe, Hand Scythe,", duration: "Instant", description: "You leap over your opponent while hooking your blade being an enemy’s limbs and pulling violently to sever them. Make a melee Taijutsu attack, dealing your [weapons damage] + 5d8 and the target must make a Dexterity saving throw. On a failed save the target loses mobility and function in one of their arms being unable to hold things, form hand seals or manipulate objects with it until they complete a rest. A jutsu that removes conditions, cast at C-Rank or Higher can heal the targets arm(s), granting it mobility and function. If a creature has both arms disabled by this jutsu, and would have an arm disabled for the second time, they make a Constitution saving throw. On a failed save, one of their arms is amputated. 303", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2f8a4fa36b3d38e037bfe4bf", name: "ARROW OF APOLLO [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Double Weapon Range", chakra_cost: "12 Chakra", components: "W (Any Ranged Piercing), M, CM", duration: "Instant", description: "You pull your drawstring and feel the power of the Sun against your skin, lighting your arrow ablaze with heavenly light. Make a ranged Taijutsu attack toward a target within range. On a hit, you deal your [weapons damage] + 8d4. This jutsu gains additional effects if it is used between 12:00pm to 2:00pm; If this is the case, then this jutsu instead deals double your [weapon’s damage] + 8d6 on a hit and the target must succeed a Constitution saving throw or gain 2 ranks of Burned. If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by an additional 1 step", at_higher_ranks: "For each rank you cast this jutsu above B rank, increase the cost by 3. If this jutsu is cast at A- rank, the time you may gain the additional benefits of the day extends to 4:00 pm. If this jutsu is cast at S rank, you may draw on the last sources of daylight of the setting sun. The time you may gain the additional benefits of the day extends to 6:00 pm, and this jutsu deals an additional 2d8 damage.", created_at: NOW, updated_at: NOW },
  { _id: "e67ca69a2d92fcecd24c76c2", name: "ARROW OF ARTEMIS [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Double Weapon's Range", chakra_cost: "12 Chakra", components: "W (Ranged Piercing), M", duration: "Instant", description: "You pull your drawstring and feel the moonlight on your skin Your arrow glows silver with the power of moonlight. Make a ranged Taijutsu attack toward a target within range. On a hit, you deal your [weapons damage] + 8d4. This jutsu gains additional effects if the current phase of the moon is a Full Moon. If this is the case, then this jutsu instead deals double your [weapon’s damage] + 10d6 on a hit and the target must succeed a Constitution saving throw or gain 3 ranks of Bleeding. If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by an additional 1 step", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3. If this jutsu is cast at A-rank, you may gain the Full Moon benefits on a Half Moon. If this jutsu is cast at S rank, you gain the Full Moon benefits on a Crescent Moon, and deal an additional 2d8 damage.", created_at: NOW, updated_at: NOW },
  { _id: "2ee2fa8f29c3731fe53749e0", name: "ARROW RAIN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "11 Chakra", components: "W (Any Bow), M", duration: "Instant", description: "When you cast this jutsu you must spend one ammunition stack. You knock as many arrow or bolts into your bow and fire them in an arc that then begin to raid down completely overwhelming all within range. Select a space you can see within range. All creatures within 30 feet of the select space, who are not under total cover from a structure must make a Dexterity saving throw, taking your [weapons damage] + 3d8. Creatures who fail their saving throw by 5 or more are pinned to the ground, being knocked prone and restrained. A creature restrained in this way can spend their action to make a Strength (Athletic) check vs your Taijutsu save DC to escape, ending the restrained condition.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "4755e98e64fc1f7fa8141c92", name: "BATON PASS [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action After hitting an enemy (or a 1 Reaction after critically hitting an enemy) with a weapon or Taijutsu attack", range: "30 feet radius sphere", chakra_cost: "12 chakra", components: "W (Any)", duration: "Instant", description: "You quickly shift the momentum of the fight by creating an opening for an ally. You can give an ally within range an additional reaction to cast a Chain X Bukijutsu or a Taijutsu with the Finisher keyword, or make a weapon attack against the triggering creature. If the preceding jutsu was a critical hit, this jutsu casting time becomes 1 Bonus Action or Reaction. If this jutsu is cast as a Chain 2, the allied creature can then cast this jutsu at no cost as a reaction if they hit, targeting another creature other then you. If this jutsu is cast as a Chain 3 The second allied creature can then target a third different allied creature with this jutsu on a hit. 304", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9f4b7546f56c615ff41ba3f4", name: "BIDING FURY: VELOCITY UNTOLD [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra, X Fury", components: "W (Any Power), M", duration: "Concentration (1 minute)", description: "You build up your energy and Fury to unleash it in one punch, converting the speed into untold power. Make a Melee Taijutsu attack dealing your [weapons damage] + 7d8. This jutsu gains additional effects depending on how much fury is spent: • 4: This jutsu’s damage die increases to a d10. • 6: You have advantage on this jutsu’s attack roll. • 8: This jutsu’s damage die is increased to a d12. • 10: This jutsu deals an additional 2 damage die. • 12: The target of his jutsu cannot react to its casting or attack roll.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, and the damage die by +1.", created_at: NOW, updated_at: NOW },
  { _id: "bf8dba7b6ac90594f02f58f3", name: "BINDING SHOT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Thrown, Battle Wire) M", duration: "1 Minute", description: "You launch a set of thrown weapons wrapped in Battle Wire at an enemy, intended to use them as a much more lethal bola. Target an enemy within range, make a ranged Taijutsu attack. On a hit the target takes [weapons damage] + 4d6. The target then must make a Dexterity saving thrown, being restrained on a failure and no effects on a successful save. A creature who begins its turn restrained by this jutsu gains 2 ranks of bleeding. A creature can remake the save at the end of their turns.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2eb11eb16afe7bdc8f66c7c1", name: "BLADE HEART", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "11 Chakra", components: "W (Blade Group), M", duration: "Concentration, up to 1 minute", description: "As a requirement to activate this jutsu, you must have a weapon from the Blade weapon group equipped. Your heart and your blade become one. As a bonus action on your turn or as a reaction to taking damage, you can assume your parrying stance until the beginning of your next turn gaining its benefits. While in this Parrying stance, you gain a +2 bonus to your AC and Dexterity saving throws. If you are disarmed this jutsu immediately end. Additionally, when you score a critical hit using your weapon with a weapon or Taijutsu attack, the target gains 1 rank of lacerated.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "613b6aa4ca413bdbfb03ffa3", name: "BLADE OF SIN: PRIDE [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 reaction when you take damage from a melee attack", range: "Weapon range", chakra_cost: "12 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You seek to emulate the power of one of the Seven Deadly Sins of Humanity in your blade, imbuing the Sin of Pride inside the edge. When a creature would damage you with a melee attack, roll your [weapons damage] +4d8 and reduce the damage by the rolled amount. If you reduce the damage to 0, the target creature must make a Charisma Saving throw or become Demoralized until the end of the current turn.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3 and the Damage Reduction by 2d8. If this jutsu is cast at A-Rank, the triggering creature makes their save at disadvantage. If this jutsu is cast at S-Rank, all hostile creatures within 30 feet instead must make the save and the Demoralized last until the end of your next turn.", created_at: NOW, updated_at: NOW },
  { _id: "0b4748e22eca245ef97a2fd5", name: "BLUE MOON [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You whip your weapon before channeling so much chakra into the end it looks like a blue moon at the end of your weapon. Make 3 Melee Taijutsu attacks against a creature in range dealing your [weapons damage die] +2d8. If you are successful with at least 2, you force the affected creature to make a Constitution saving throw, becoming staggered on a failed save. If this jutsu is cast as a Chain 2, increase the damage die by 2. If this jutsu is cast as a Chain 3 increase the damage die by an additional 1 step", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, and the damage by 1d8. 305", created_at: NOW, updated_at: NOW },
  { _id: "84d41b40c258488668fc36ee", name: "BLUNT FORCE TRAUMA [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon’s Range", chakra_cost: "12 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You swing your weapon looking to inflict as much force into your opponent that they will never be the same again. Make a melee Taijutsu attack at, dealing [weapons damage] +3d8 on a hit and forcing the target creature to make a Constitution saving throw. On a failed save, they gain 3 ranks of Bruised. If you critically hit with this jutsu, they have disadvantage on this save And instead become Staggered If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by an additional 1 step", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, damage by 1d12 And the ranks of Concussed by 1.", created_at: NOW, updated_at: NOW },
  { _id: "1f133e9243d1f1a911e8bc91", name: "BONE BREAKER [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "f4476d87b21771883686f854"], elements: [], casting_time: "1 Action", range: "Weapon’s Range", chakra_cost: "12 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You aim your blow to break a bone, to maim your foe and hobble them in this fight. Make a melee Taijutsu attack at disadvantage as you aim your blow at a specific location. On a hit, you deal your [weapons damage] and choose a which bone you broke below: Shoulder: The target creature has disadvantage on Melee attacks until they are either healed with a Medical jutsu cast at B-Rank or higher or spend a Full Turn Action setting it back into place. Shin: Target creature takes 1d6 force damage for every 5 feet they willingly move. They also have disadvantage on Saving Throws that would forcibly move them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4576f00b38566e611b401921", name: "BRANDING PUNISHMENT [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon's Range", chakra_cost: "12 Chakra", components: "M, W (Any Blade)", duration: "Instant", description: "To cast this jutsu the target must have at least 1 rank of Bleeding. You swing your blade into the opponent's bleeding wound, ripping it out and making it fester. Make a melee Taijutsu attack, on a hit you deal 7d6 slashing damage and the target suffers 1 rank of exhaustion for one minute. This Jutsu has a critical threat range of 19-20. If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by +3", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "afdf0d6d4df4dcec87ed5aaf", name: "BREACH-N-CLEAR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Thrown) M, NT (2x Breaching tags).", duration: "Instant", description: "You Hastily take out a collection of breaching tags and attach them to your weapon, throwing and embedding it into a Construct or Structure in front of you. Select a Construct or Structure within range, Make a Ranged Taijutsu attack, dealing you [weapons damage] + 6d6 Fire and 6d6 Bludgeoning on hit. Any construct reduced to 0 HP as a result of this Jutsu cannot be remade without acquiring entirely new materials.", at_higher_ranks: "For each rank you cast this Jutsu above B rank, increase the cost of the Jutsu by 3, and you equip Breaching tags of a higher variety, if done, increase the Fire and Bludgeoning damage by 2d6 each. 306", created_at: NOW, updated_at: NOW },
  { _id: "f45edd20f232420110b0cc8f", name: "BREATH OF ASH: DUST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action.", range: "Self (60-foot line)", chakra_cost: "13 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest fire release chakra until it laces the striking portion of your weapon. The fire release chakra begins to transform into gouts of ash and smoke that erupt off of you, and your weapon with a glorious and wrathful flickering. Select a creature you can see within range. You fire in a straight line towards them. All creatures in a straight line, 10 feet wide, between you and the target becomes the target of this attack. Make one ranged Taijutsu attack. All creatures whose space your line passes through become the target of this attack comparing their AC vs your attack result. On a successful attack you deal your [weapons damage] +8d4+8 Fire Damage. If you score a critical hit with this attack, only one creature of your choice suffers the effects of a critical hit.", at_higher_ranks: "For each rank you cast this jutsu above fadincrease the cost of this jutsu by 3 and the damage by 1d4+1. If this jutsu is cast at S-Rank, if you score a critical hit with this attack, all creatures suffer the effects of the critical hit.", created_at: NOW, updated_at: NOW },
  { _id: "a533eb4a608afe8926301a8f", name: "BREATH OF DUST: PEACEKEEPER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest earth release chakra until it laces the striking portion of your weapon. The earth release chakra begins to magnify the weight and striking power of your attacks allowing you crush anything in your path is little difficulty. Select one creature you can see within range as you fire multiple attacks into the air and quickly quadruple the weight of your attacks causing them to fall back to the earth while homing in on them. Make 2 ranged Taijutsu attacks, dealing your [weapons damage] + 3d8. A creature you hit with 2 or more attacks using this jutsu must make a Strength saving throw as you disable one of their legs (your choice) on a failed save. A creature with a disabled leg in this way cannot move effectively, causing them to be unable to cast jutsu with a Mobility (M) component, Dash, dodge, disengage or move while prone. A jutsu which removes conditions cast at B-Rank or higher can restore the disabled leg.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ed1d45461ac6dc2efcad152f", name: "BREATH OF EARTH: JUSTICE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "13 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest earth release chakra until it laces the striking portion of your weapon. The earth release chakra begins to magnify the weight and striking power of your attacks allowing you crush anything in your path is little difficulty. You utilize a powerful barrage of strikes from a series of differing angles doing great damage. Select one creature you can see within range as you strike with a flurry of weapon attacks followed by manifestations of earth release chakra of your design. Make 2 melee Taijutsu attacks using your weapon, dealing your [weapons damage] + 3d10 earth damage. A creature you hit with 2 or more attacks using this jutsu must make a Strength saving throw as you disable one of their arms (your choice) on a failed save. A creature with a disabled arm in this way cannot use that arm to wield weapons, fulfill jutsu hand seals (HS) requirements or grapple for the next minute. A jutsu which removes conditions cast at B-Rank or higher can restore the disabled arm.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "50d241b73deabf710ba28c7a", name: "BREATH OF ECHO: CRESCENDO", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "13 Chakra", components: "CM, W (Any Ranged), NT (Any explosive", duration: "Instant", description: "You begin to collect and manifest chakra until it manifest into the shape of a sound note of your choice, hovering over your eyes as you begin to listen to all of the sounds created as a result of battle. You then throw a large number of explosive tools into the air at different, intentional points. You then fire dozens of shots through them by creating an unstopping wave of explosions that follow your attack. All creatures of your choice in a 5-foot wide, 30-foot line originating from you must make a Dexterity saving throw, taking your [weapons damage] + 3d8 force damage, being knocked prone, blinded and deafened for 1 minute on a failed save, or half as much damage and no further effects on a success. A blinded and deafened creature can make a Constitution saving throw at the end of each of their turns to end these effects on them on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d8. 307", created_at: NOW, updated_at: NOW },
  { _id: "ae01b5eed4164d37994782ce", name: "BREATH OF ENOKI: ERADICATE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "aaeecd12fb6a8f889a26ab97", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action.", range: "Weapon Range", chakra_cost: "14 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest medical chakra until it laces the striking portion of your weapon. The medical chakra begins to cause your weapon to glow with a soft pink hue. Select a creature you can see within range as you release waves of medical chakra following the same concepts of chakra scalpels into each of your attacks. Make 3 ranged Taijutsu attack with your weapon, dealing your [weapons damage] + 3d4 poison damage, you do not add your ability modifier to the damage dealt. You can make these attacks at different creatures or all at the same one. When a creature takes poison damage from this jutsu, they must make a Constitution saving throw, gaining 1 rank of Envenomed, Corroded and Weakened. A creature who takes poison damage from this jutsu more than once, repeats the saving throw at a stacking -1 penalty to this saving throw for each subsequent successful attack.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "7fabd43d9edd6ad7d3f458be", name: "BREATH OF FLAME: RENGOKU", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action.", range: "Self (60-foot line)", chakra_cost: "13 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest fire release chakra until it laces the striking portion of your weapon. The fire release chakra begins to transform into gouts of flame that erupt off of you, and your weapon with a glorious and wrathful flickering. Select a space you can see within range that passes through one or more creatures in a 10-foot wide, 60- foot-long line, originating from you. You move to a space at the end of this line that can hold you leaving behind a bright, powerful and burning gout of flame in your wake. Make one melee Taijutsu attack. All creatures whose space your line passes through become the target of this attack comparing their AC vs your attack result. On a successful attack you deal your [weapons damage] + 6d6+6 Fire Damage. If you score a critical hit with this attack, only one creature, of your choice suffers the effects of a critical hit.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at S-Rank, if you score a critical hit with this attack, all creatures suffer the effects of the critical hit.", created_at: NOW, updated_at: NOW },
  { _id: "330ad2289f431fd6a72b4cb0", name: "BREATH OF RAIN: DOWNPOUR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "13 Chakra", components: "CM, W (Any Range), M", duration: "Instant", description: "You begin to collect and manifest water release chakra until it laces the striking portion of your weapon. The water release chakra begins to transform into streams of water, capable of being seen and felt as you fire a single shot into the sky, which then scatters and rains downs an innumerable number of beasts made of water onto creatures of your choice. Select a number of creatures you can see within range equal to your proficiency bonus, as you fire your attack into the air. Make one ranged Taijutsu attacks using your weapon comparing the result to each targets AC. On a successful hit, you deal your [weapons damage] + 3d8 cold damage. If any target has any ranks of the chilled, or are Dazed, you make your attacks at advantage. If you score a critical hit with this attack, only one creature, of your choice suffers the effects of a critical hit.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d6, and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "79fabb18671d6aa8176fb7f1", name: "BREATH OF ROSE: FUTILITY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action.", range: "Weapons Range", chakra_cost: "13 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest medical chakra until it laces the striking portion of your weapon. The medical chakra begins to create a visage of a poisonous flowers as your move your weapon. Select one create you can see within range you begin to move around them, imitating the movements of a throned stem striking them with each passing gesture. Make three melee Taijutsu attack with your weapon, dealing your [weapons damage die] + 2d6 poison damage. A creature who you successfully hit with at least one attack granted by this jutsu, must make a Constitution saving throw gaining 1 rank of lacerated and envenomed on a failed save. A creature hit with three attacks makes this save at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d6. 308", created_at: NOW, updated_at: NOW },
  { _id: "dc15f8edec0a6bfc372c9225", name: "BREATH OF SKIES: TWISTER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "be25cd280a254892a04b3a6b", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "13 Chakra", components: "CM, W (Any), M", duration: "Instant", description: "You begin to collect and manifest wind release chakra until it laces the striking portion of your weapon. The wind release chakra begins to spiral around the user’s weapon creating whipping torrents of wind. You you’re your attack, like a corkscrew, rotating it in drill like motion, allowing the wind Release to create a massive and powerful spiraling funnel. All creatures of your choice in a 5-foot wide, 60-foot line originating from you must make a Dexterity saving throw, taking your [weapons damage] + 8d4 wind damage and 1 ranks of lacerated on a failed save or half as much and no ranks of lacerated on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "854ae8bac7e886569efdef8a", name: "BREATH OF SOUND: PERFORMANCE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "13 Chakra", components: "CM, W (Any Melee), NT (Any explosive tool),", duration: "Instant", description: "You begin to collect and manifest chakra until it manifest into the shape of a sound note of your choice, hovering over your eyes as you begin to listen to all of the sounds created as a result of battle. You then throw a large number of explosive tools into the air at different, intentional points. You then sprint through them attack each one as you pass by creating an unstopping wave of explosions that follow you as you attack anyone in your way. Select a space you can see within range, that passes through one or more creatures in a 5-foot wide, 60- foot-long line, originating from you. You move into a space adjacent to the end of that line, that can hold you, leaving behind a festival of explosions and light. All creatures who your line would pass through must make a Dexterity saving throw, taking your [weapons damage] + 3d10 force damage, being knocked prone, blinded and deafened for 1 minute on a failed save, or half as much damage and no further effects on a success. A blinded and deafened creature can make a Constitution saving throw at the end of each of their turns to end these effects on them on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "b8f569ea5ce0c04f7faeb3d4", name: "BREATH OF SPARKS: OVERLOAD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Double Weapon Range", chakra_cost: "13 Chakra", components: "CM, W (Any Ranged), M", duration: "Instant", description: "You begin to collect and manifest lightning release chakra until it laces the striking portion of your weapon. The lightning release chakra begins to collect and spark off of your weapon and body with violent jolts. You prepare for a powerful singular shot as your lightning follows behind your attack in the image of a beast of your description. Select one creature you can see within range. Make one ranged Taijutsu attacks, dealing your [weapons damage] + 5d10 lightning damage. If the target has any ranks of the Shocked condition, you make your attacks at advantage. If your beats the creatures AC by 10 or more, the creature cannot take a reaction until the end of the current turn, and you ignore any Damage Reduction they are benefiting from.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "a9ad84b2f3c20d10ae85cce0", name: "BREATH OF THUNDER: KAMI", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Double Movement Speed", chakra_cost: "13 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest lightning release chakra until it laces the striking portion of your weapon. The lightning release chakra begins to collect and spark off of your weapon and body with violent jolts. You prepare for a powerful singular forward slash as your lightning follows behind you in the image of a beast of your description. Select one creature you can see within range. Move yourself into a space adjacent to the chosen creature that can hold you. Make one melee Taijutsu attacks using your weapon, dealing your [weapons damage] + 6d12 lightning damage. If the target has any ranks of the Shocked condition, you make your attacks at advantage. If your beats the creatures AC by 10 or more, the creature cannot take a reaction until the end of the current turn, and you ignore any Damage Reduction they are benefiting from.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d12. 309", created_at: NOW, updated_at: NOW },
  { _id: "5b63ffd180c8a3f6e4d4c270", name: "BREATH OF WATER: FLUX", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "13 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest water release chakra until it laces the striking portion of your weapon. The water release chakra begins to transform into streams of water, capable of being seen and felt as you perform a series of continuous flowing attacks that begin to manifest a powerful dragon made of water that collapses on top your target. Select a number of creatures you can see within range equal to your proficiency bonus. Move yourself into a space adjacent to the last creature chosen that can hold you. Make one melee Taijutsu attacks using your weapon comparing the result to each targets AC. On a successful hit, you deal your [weapons damage] + 5d8 cold damage. If any target has any ranks of the chilled, or are Dazed, you make your attacks at advantage. If you score a critical hit with this attack, only one creature, of your choice suffers the effects of a critical hit.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d8, and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "0b814a493d6763530f0ef479", name: "BREATH OF WIND: GUSTS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "be25cd280a254892a04b3a6b", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "13 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You begin to collect and manifest wind release chakra until it laces the striking portion of your weapon. The wind release chakra begins to spiral around the user’s weapon creating whipping torrents of wind. You spin sideways, rotating your body in an uppercut motion, allowing the wind Release to create a massive and powerful arcing slash. All creatures of your choice in a 5-foot wide, 60-foot line originating from you must make a Dexterity saving throw, taking your [weapons damage] + 4d6 wind damage and 1 ranks of bleeding on a failed save or half as much and no ranks of lacerated on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "171d735b20c1fdd443061009", name: "CASTLE CRASHER [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 reaction when a creature summons a construct or structure or gains THP on your turn.", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You feint out of your attack, ending the previous jutsu, and instead slam your weapon to break down whatever wall was thrown against you. Make a Melee Taijutsu attack targeting the construct or structure. If it is THP, you have disadvantage on this attack roll. On a hit you deal your [weapons damage] +5d12. Constructs and Structures take double damage from this attack. If you reduce the Construct, Structure, or THP to 0, you gain an additional reaction which can be used to recast the jutsu that was used to cast this one. If you do not reduce it to 0, you instead regain half of the previous jutsu chakra usage back.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f02a04488a719824771b4562", name: "COMBO VAULT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Weapon), M", duration: "Instant", description: "You leap over your opponent landing behind them then quickly dash back to your previous position. Striking the enemy as you pass by. Make two Taijutsu attacks with your weapon dealing your [weapons damage] on each hit. For each successful hit you make using this jutsu, you gain a +1d4 to hit on your next bukijutsu cast this turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3d02c78233abc6c4e0000450", name: "COUNTER-STRIKE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "Reaction, to being targeted for an attack.", range: "5 Feet", chakra_cost: "11 Chakra", components: "W (Any Melee Weapon), M", duration: "Instant", description: "As a Reaction to being attacked, you take it head on in an attempt to lock the opponent in front of you, preventing them from dodging. You take the maximum possible damage from the attack that you were targeted with. Immediately after you take the damage, you are able to cast 1 bukijutsu with the Casting time of 1 Action or Bonus Action at no additional chakra cost of B-Rank or lower. 310", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cbfd806e21d6946fc69a7d6e", name: "CROSS SLASH [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Ranged Slashing), M, CM", duration: "Instant", description: "You perform 2 powerful throws with enough force to leave a gash in any armor made by the hands of man. Make two ranged Taijutsu attacks against a single creature dealing your [weapons damage] + 3d6 with each hit. If you successfully hit a creature with both attacks, you tear open their guard removing any chance they could defend themselves from you. A creature who is hit by both attacks, cannot gain the benefit of bonuses to AC or Temporary hit points as a result of Armor, Jutsu, features or traits against you until the end of your next turn. If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by +3.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "640c78673c32094a7e65732c", name: "CTE TRIGGER [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Ranged Bludgeoning), M, CM", duration: "Instant", description: "You aim your blow directly at the temple of your foe, looking to scramble their brain like an egg. Make a ranged Taijutsu attack, dealing twice your [weapons damage] on a hit and forcing the creature to make a Constitution Saving Throw. On a fail, the target creature gains 2 Ranks of Concussed. If they do not clear these ranks of Concussed in 1 minute, they become permanent until cleared by a Medical jutsu cast at A- Rank or higher. If this jutsu is cast as a Chain 2, increase the damage die of your weapon by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by an additional 1 step", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c27d13188b3f621f5af84f93", name: "DANCE PERFORMANCE: THIRD STEP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (15-foot Cube)", chakra_cost: "14 Chakra", components: "W (Any Melee), M", duration: "Instant", description: "You spin, stopping in a wide slash. Each creature in a 15-foot cube originating from you must make a Dexterity saving throw. On a failed save, a creature takes your [weapons damage] + 3d10 and gaining 3 ranks of bruised until the end of their next turn. On a successful save, a creature takes half as much damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3, the damage by 1d10, and the ranks of bruised by +1.", created_at: NOW, updated_at: NOW },
  { _id: "6a79571687a004307a185c77", name: "DANCER'S GRACE [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon's Range", chakra_cost: "12 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You unleash the fury of your blade, dancing and spinning multiple times, going faster with each rotation. All creatures within your weapons range must succeed 2 Dexterity saving throws, taking your [weapon’s damage] +2d10 on a failure and gaining 1 rank of bleeding for each failure If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by +2.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the number of Dexterity Saving throws needed by 1.", created_at: NOW, updated_at: NOW },
  { _id: "60e359d8fecb2bea176ee26e", name: "DEMONIC CULLING: EYE BASKET [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range (15-foot radius sphere)", chakra_cost: "12 Chakra", components: "W (Any Flail), M", duration: "Concentration, up to 1 minute", description: "You spin your weapon with chakra and quickly surround your target within the spin. As it envelopes your target you tighten the circle around them, conforming into a sphere like pattern before sinking into them from above in a 15-foot radius around them. All creatures in range must succeed a Strength saving throw taking [weapons damage] +6d8 damage, becoming prone and restrained on a failed save, and only half damage with no conditions on a success. At the start of their turn, they may remake the save, ending the conditions on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8", created_at: NOW, updated_at: NOW },
  { _id: "94cb149c3c8a53dac387e5df", name: "DUAL RING [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range (Twice Weapons Range)", chakra_cost: "12 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You spin your weapon around in a ring around you, extending it with your chakra to create a dual ring of death. All creatures within twice your weapons range must make a Dexterity Saving Throw, taking your twice [weapons damage die] on a failed save and gaining a rank of bleeding, taking half damage and no effects on a success. Creatures within your normal weapons range make their save at disadvantage and instead take twice your [weapons damage] on a failed save and 3 ranks of bleeding and half damage and no ranks on a pass.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3 and the ranks of bleeding on a failed save by 1. 311", created_at: NOW, updated_at: NOW },
  { _id: "19877246e71891c1e245a640", name: "EARTH SPIDER SEWING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "10 Minutes", range: "60-foot cube", chakra_cost: "13 Chakra", components: "W (Battle Wire), M", duration: "1 Hour", description: "You lace an area with razor sharp wires less than a foot above ground level. Trapping, damaging, and hindering all creatures who aren’t aware of them or their locations exactly. For the duration, select a space the size of a 60-foot cube to fill with razor sharp wires. Select creatures that you can see to be unaffected by this jutsu. For the duration, creatures who enter the radius of this jutsu move as if the area this jutsu inhabits is difficult terrain. Creatures who cast Jutsu with a Mobility (M) component, must make a Dexterity saving throw being restrained by the wires as they get wrapped up inside of them on a failed save. Creatures who make weapon attacks must make a Strength saving throw, having their weapon caught on a wire and being unable to complete the attack on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "23a74686728ffe0eb4028fe9", name: "ECLIPSE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "W (Bludgeoning), M", duration: "Concentration, up to 1 minute.", description: "You enter a stance that prevents others from capitalizing on any openings as your weapon sits firmly grasped in both hands. For the duration, bukijutsu and weapon attacks made with a weapon that deals bludgeoning damage also forces the target to make a Constitution saving throw. On a failed save the target(s) gain 1 rank of Weakened and becomes dazed. If a creature gains a rank of weakened this way, the duration of any previous ranks of weakened is increased to the end of your next turn. You can only force a creature to make a Constitution save this way once per turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "06f97faef6437d459824a395", name: "FANGS OF MEDUSA [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Double Weapon Range", chakra_cost: "12 Chakra", components: "W (Any Ranged Slashing), NT (Poison or", duration: "Instant", description: "The chthonic enemy of the moon’s hatred swells within you; it’s seething rage like poison to your chakra. Make a ranged Taijutsu attack toward a target within range. On a hit, you deal your [weapons damage] + 4d8 poison damage. This jutsu gains additional effects if the current phase of the moon is a Full Moon. If this is the case, then this jutsu instead deals double your [weapon’s damage] + 6d10 on a hit and the target must succeed a Constitution saving throw or gain 3 ranks of Envenomed. If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by +2.", at_higher_ranks: "For each rank you cast this jutsu above B-rank, increase the cost by 3. If this jutsu is cast at A rank, you may gain the Full Moon benefits on a Half Moon. If this jutsu is cast at S rank, you may gain the Full Moon benefits on a Crescent Moon, and this jutsu deals an additional 2d10 Damage.", created_at: NOW, updated_at: NOW },
  { _id: "1dc19a810e965611fe389d19", name: "FANGS OF PYTHON [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Double Weapon Range", chakra_cost: "12 Chakra", components: "W (Any Ranged Slashing), NT (Poison or", duration: "Instant", description: "The chthonic enemy of the sun’s hatred swells within you; it’s seething rage like poison to your chakra. Make a ranged Taijutsu attack toward a target within range. On a hit, you deal your [weapons damage] + 4d8 necrotic damage. This jutsu gains additional effects if it is used between 12:00pm to 2:00pm; If this is the case, then this jutsu instead deals double your [weapon’s damage] + 6d8 on a hit and the target must succeed a Constitution saving throw or gain 2 ranks of Envenomed. If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by an additional 1 step", at_higher_ranks: "For each rank you cast this jutsu above B rank, increase the cost by 3. If this jutsu is cast at A rank, the time you may gain the additional benefits of the day extends to 4:00 pm. If this jutsu is cast at S rank, you may draw on the last sources of daylight of the setting sun. The time you may gain the additional benefits of the day extends to 6:00 pm, and this jutsu deals an additional 2d8 damage. 312", created_at: NOW, updated_at: NOW },
  { _id: "b38623ac70112e67d26724a6", name: "FISTS OF HELIOS [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Double Weapon Range", chakra_cost: "12 Chakra", components: "W (Any Ranged Bludgeoning), M, CM", duration: "Instant", description: "The former Titan of the sun’s pride swells within you; its ancient flame sets your chakra ablaze. Make a ranged Taijutsu attack toward a target within range. On a hit, you deal your [weapons damage] + 3d10 fire damage. This jutsu gains additional effects if it is used between 12:00pm to 2:00pm; If this is the case, then this jutsu instead deals double your [weapon’s damage] + 4d12 on a hit and the target must succeed a Constitution saving throw or gain 2 ranks of Burning. If this jutsu is cast as a Chain 2, increase the damage die by +2. If this jutsu is cast as a Chain 3 increase the damage die by an additional +1.", at_higher_ranks: "For each rank you cast this jutsu above B rank, increase the cost by 3. If this jutsu is cast at A-rank, the time you may gain the additional benefits of the day extends to 4:00 pm. If this jutsu is cast at S rank, you may draw on the last sources of daylight of the setting sun. The time you may gain the additional benefits of the day extends to 6:00 pm, and this jutsu deals an additional 2d8 damage.", created_at: NOW, updated_at: NOW },
  { _id: "47f1693289eee03d9f3d85ed", name: "FISTS OF SELENE [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Double Weapon Range", chakra_cost: "12 Chakra", components: "W (Any Ranged Bludgeoning), M, CM", duration: "Instant", description: "The former Titan of the moon’s pride swells within you; its ancient serenity calms your chakra to a still pond. Make a ranged Taijutsu attack toward a target within range. On a hit, you deal your [weapons damage] + 3d10 cold damage. This jutsu gains additional effects if the current phase of the moon is a Full Moon. If this is the case, then this jutsu instead deals double your [weapon’s damage] + 6d12 on a hit and the target must succeed a Constitution saving throw or gain 3 ranks of Concussed. If this jutsu is cast as a Chain 2, increase the damage die by 2 If this jutsu is cast as a Chain 3 increase the damage die by an additional +1.", at_higher_ranks: "For each rank you cast this jutsu above B rank, increase the cost by 3. If this jutsu is cast at A rank, you may gain the Full Moon benefits on a Half Moon. If this jutsu is cast at S rank, you may gain the Full Moon benefits on a Crescent Moon, and this jutsu deals an additional 2d12 Damage.", created_at: NOW, updated_at: NOW },
  { _id: "9c0fd612cd36881b720de39f", name: "FLYING SWALLOW: FLURRY GUARD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, which you take when you would take damage.", range: "Weapon Range", chakra_cost: "11 Chakra", components: "W (Any Melee), M", duration: "1 Round", description: "As a part of the activation of this jutsu, you must have a weapon in both hands that meet this Bukijutsu’ s component requirements. You raise both of your weapons blocking an incoming flurry of attacks in a powerful guarded stance. You gain a +4 bonus DR vs all melee and ranged attacks (Excluding from Genjutsu). Each time the same creature makes an attack targeting you, after the triggering attack, you gain an additional +2 DR vs all of their melee and ranged attacks. At the conclusion of the triggering creatures action used to make the triggering attacks, you immediately send all of that built up defense back at them. Make two melee Taijutsu attacks, one with each weapon. On a hit, you deal your [weapons damage] + 3d6 + the Total DR bonus gained as a result of this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "3283084424514a99493a4c44", name: "FLYING SWALLOW: PENULTIMATE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "14 Chakra", components: "W (Any Melee), M", duration: "Instant", description: "As a part of the activation of this jutsu, you must have a weapon in both hands that meet this Bukijutsu’ s component requirements. You perform a swift series of powerful and accurate strikes with both weapons. Before finishing with a powerful strike with both weapons simultaneously. Make two melee Taijutsu attacks, one with each weapon, dealing your [weapons damage] + 1d10. If you scored at least one hit with each weapon, you attack one final time dealing both [weapons damage die] + your Taijutsu ability modifier + 2d10.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "69fbc9305e0ba00a7390c89a", name: "HAZY NIGHT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "W (Melee Slashing), M", duration: "Concentration, up to 1 minute.", description: "You move with such fine control that nothing is wasted. Each movement leaves behind afterimages of your last movement. For the duration, bukijutsu made with a weapon that deals slashing damage that forces a target to make a saving throw, are always made with a -2 penalty. 313", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f12546f2a90cdf40c8f812dc", name: "HEAVEN EARTH IMPACT [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You raise your weapon to the heavens and swing it down through the very crust of the earth. Make a melee Taijutsu attack at disadvantage as you telegraph the attack from how much power you put into the attack. On a hit you deal twice your [weapons damage] and the target creature must make a Strength Saving Throw, becoming prone and restrained into the ground. They can remake this save as an action and at the end of their turn to end this restraint.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4af4030f50e8c3eb583f0600", name: "HEXA HARMONY [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Twice Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "(This jutsu cannot crit) You stab forward with frightening accuracy, hitting the 8 chakra cores on your foe to disrupt their inner harmony. Make 8 Melee Taijutsu attacks, each dealing your [weapons damage die]. This jutsu gains additional effects for how many successful attacks you made. You gain all benefits you qualify for: • 1-2: Target creature loses the total damage in chakra as well. • 3-4: Target creature has disadvantage on concentration checks made to maintain jutsu for the next minute. • 5-7: Target creature can only concentrate on one jutsu for the next minute. • 8: Target creature cannot concentrate on any jutsu for the next minute. This jutsu’s effects can end early if the target is healed with a medical jutsu of A-Rank or higher, or they spend a full turn action making a Chakra Control check vs your Taijutsu save DC.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e60b97262ed60bb311a0b0e3", name: "ICHIMONJI", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "14 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You take a solid striking form and perform 2 powerful slashes with enough force to leave a gash in the ground below the blade. The first slash is downward creating the gash in the ground, the second slash is upward creating a high-pitched singing sensation from the edge of the blade. Make two melee Taijutsu attacks against a single creature dealing your [weapons damage] + 4d6 with each hit. If you successfully hit a creature with both attacks, you tear open their guard removing any chance they could defend themselves from you. A creature who is hit by both attacks, cannot gain the benefit of bonuses to AC or Temporary hit points as a result of Armor, Jutsu, features or traits against you until the end of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8921c1a4df1ca04c88eb0448", name: "JUDGEMENT CUT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "12 Chakra", components: "W (Any Melee Slashing), M", duration: "Instant", description: "You take your weapon and coat it in your chakra, and use your raw skill to gauge the distance between yourself and your target. Select a space you can see within range. All creatures within 5 feet of this space must make a Dexterity saving throw. On a failed save, a target takes 5d8 Slashing damage on a failed save, or half as much on a success. Additionally, you can choose to spend an additional 6 Chakra to use this jutsu again targeting the same space, forcing all creatures to repeat the saving throw. You can do this twice per casting.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the number of spaces you can select by +1. A creature can only be affected by one instance this jutsu at a time. 314", created_at: NOW, updated_at: NOW },
  { _id: "2c085e61a7ff447b084bb7cc", name: "LASHING ATTACK [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You make a series of attacks with your weapon, each one using the force of the last to deliver a greater blow. Make 5 Melee Taijutsu attacks against a creature in range rolling one damage roll, depending on how many of them hit • 1 hit: [weapons damage] +6d4 damage. • 2 hits: [weapons damage] +6d6 damage and 1 rank of bleed. • 3 hits: [weapons damage] +6d8 damage and 2 ranks of bleed. • 4 hits: [weapons damage] +6d10 damage, 4 ranks of bleed and knocked prone. • 5 hits: [weapons damage] +6d12 damage, 6 ranks of bleed, dazed and prone.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, and the damage by 1dx.", created_at: NOW, updated_at: NOW },
  { _id: "0cbd3b7f6e4b6725a5eda19b", name: "LETHAL MOMENTUM [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "12 Chakra", components: "W (Any Ranged Slashing), M, CM", duration: "Special", description: "You use your chakra to spin your weapon at a lethal tempo. Your weapon gains the returning property if it did not have it already and deals an additional die of damage. After making a ranged attack with the weapon and it returns to you, you must make a Sleight of Hand check vs a DC 10. On a success this jutsu remains active. On a fail you take your twice your [weapons damage die] in damage as you catch the weapon incorrectly and this jutsu ends. Every Successful catch raises the DC by 4. For every catch, up to 5 catches, your weapon deals an additional die of damage, however you take an additional die of damage as well. This jutsu can be ended safely as a Bonus action.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "514c972b04e2d9f6ef3004b8", name: "LONG KISS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "12 Chakra", components: "W (Any Bow), M", duration: "Instant", description: "You knock your bow or bolt and point it into the sky directly above you firing it into the sky and using your chakra to guide it like a falling missile. Select a space you can see within range that a creature is occupying. Make a ranged Taijutsu attack, dealing your [weapons damage] + 6d8. Additionally, all other creatures within 10 feet of the target space must make a Dexterity saving throw, because if your original attack scores a hit, it splinters, and explodes as your chakra compresses the splinters or metal fragments into more bolts or arrows and scatters them. On a failed save creatures take 4d8 piercing damage and are dazed or half as much damage on a success and not additional effects.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the number of spaces you can select by +1 Creatures can only be affected by one Area of effect per turn as a result of this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "1f0780d1dc1cd370f6c383c3", name: "MONKEY KINGS CROWN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "11 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You twirl your weapon around yourself, building up momentum and kinetic energy in an attempt to strike an opponent’s head with enough force to crush steel and shatter stone. Make one melee Taijutsu attacks using your weapon, dealing your [weapons damage] + 5d10. If you deal at least 30 damage with this jutsu, the target must make a Strength saving throw gaining 2 ranks of bruised.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of this jutsu by 3 and the damage by 1d10. 315", created_at: NOW, updated_at: NOW },
  { _id: "3c5c24f3d867950c3c3df573", name: "MONKEY KING'S GIFT [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon’s Range", chakra_cost: "12 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You ready your weapon in a neutral stance before you unleash your combined knowledge and skill in martial arts into one attack that flows into the next. Roll xD8, where X equals the number of Chains you cast uninterrupted before this jutsu, using the highest die rolled. Make a number of Melee Taijutsu attacks equal to the highest die rolled against a target creature in range, dealing your [weapons damage] +1d4 on a hit. If you hit the creature at least two times, they must make a Constitution Saving throw or be Dazed. If they fail by 5 or more they are Dazed for one minute. For every two attacks that hit past the first two, they make this save with a -1 penalty. If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by an additional 1 step", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the die used to determine the number of attacks by 1 step.", created_at: NOW, updated_at: NOW },
  { _id: "a0d97a2d4c631900ab57ad6a", name: "MOONLIGHT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "W (Melee Piercing), W", duration: "Concentration, up to 1 minute.", description: "As part of the activation of this jutsu, you must also have moved at least 15 feet towards the target. You make a leaping, spinning double roundhouse kick. Make two melee taijutsu attacks. On a hit, you deal your [Unarmed Damage] + 1d6. If both attacks are successful, the target is knocked back 20 feet and must make a Constitution saving throw. On a failed save they gain 1 rank of confused. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. 228 NECK CHOP Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: M Cost: 3 Chakra Keywords: Taijutsu, Combo Description: You attempt to strike at a vital pressure point on the nape of the neck of a humanoid target. Make a melee taijutsu attack. On a hit, deal your [Unarmed Damage] + 1d6 and the target must make a Constitution saving throw. On a failed saved, they become Dazed. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. NOBLE IMPACT Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: M Cost: 3 Chakra Keywords: Taijutsu Description: You move in to strike your opponent by taking a regal series of attacks. Make four taijutsu attacks against a single creature within range. On a hit you deal 1d6 bludgeoning damage. If you successfully score a hit with at least 2 attacks against one creature, they cannot cast a Jutsu that requires Mobility (M) as an Action or Bonus Action, until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the number of attacks made by +1. OSTRICH WHIRLWIND Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: M Cost: 4 Chakra Keywords: Taijutsu, Finisher Description: As part of the activation of this jutsu, you can only use this taijutsu against a prone target who can be targeted by a Finisher. You perform a rather acrobatic display of skill. By kicking a prone creature, you propel yourself backward while performing a second sweeping kick while moving away. Make two melee taijutsu attacks, on a hit you deal your [Unarmed Damage] + 2d10. You then choose a space you can see within 20 Feet, leaping to that location, without triggering attacks of opportunity. PRAYING STRIKE Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: M Cost: 3 Chakra Keywords: Taijutsu, Combo Description: You make a powerful strike to the core of your opponent, sending shockwaves through their body that would break a lesser foe, and stun greater ones. Make a melee taijutsu attack. On a hit, you deal 1d4 bludgeoning damage and force the target to make a Constitution saving throw. On a failed save they are Stunned until the end of the current turn. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d4. If this jutsu is cast at B-Rank or higher, increase the damage dealt by your [Unarmed Damage] PRIDEFUL ASSAULT Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: M Cost: 4 Chakra Keywords: Taijutsu, Finisher Description: As a requirement to activate this jutsu, you must currently be in the Lion Fist Stance. You enter a prideful stance showing your overwhelming superiority and power. Make two melee taijutsu attacks. On a hit you deal your [Unarmed Damage] + 1d6. If your targets have ranks of Fear, increase this Jutsu's damage die by 1 step. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 1d10 and if you score two hits on the target, they must make a Wisdom saving throw, gaining +1 rank of fear on a failed save. At Higher Ranks: For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d6 or 1d10. If this jutsu is cast at A-Rank or higher, you can increase the number of attacks by +1. RABBIT FURY Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: Movement Speed Duration: Instant Components: M Cost: 3 Chakra Keywords: Taijutsu, Combo Description: As a requirement to activate this jutsu, you must currently be in the Rabbit Fist Stance. You enter a blitzing stance, overwhelming your enemies with speed and agility. Move on a straight line up to your movement speed, ending in a space of your choice moving through hostile creatures’ spaces ending your movement in a space of your choice that can hold you. Make two taijutsu attacks comparing the result to all hostile creatures of your choices AC, whose space you pass through, dealing your [Unarmed Damage] + 1d4. If you hit a creature with two or more attacks, they must make a Dexterity saving throw. On a failed save they are knocked prone. If you move through a large, or larger creatures space, for each space of theirs you move through after the first you make one additional attack. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. 229 At Higher Ranks: For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d4. RISING DRAGON Classification: Taijutsu Rank: D-Rank Casting Time: 1 bonus action Range: 5 feet Duration: Instant Components: M Cost: 3 Chakra Keywords: Taijutsu, Combo Description: You move to strike a target from below, lifting them off of the ground. Make a Taijutsu attack, dealing your [Unarmed Damage] +1d8. The target is launched 30 Feet into the air until the end of your current turn, landing on their feet with no falling damage at the end of the current turn unless otherwise stated. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. ROYAL GUARD Classification: Taijutsu Rank: D-Rank Casting Time: 1 Reaction, which you take when you take damage. Range: Self Duration: 1 Round Components: CM, M Cost: Special Keywords: Taijutsu Description: You quickly mold your chakra, creating multiple layers of armor from it and raising your guard to nullify an attack at the exact moment it would hit you. When you would take damage you nullify the impact by meeting it with an equal amount of chakra. Until the start of your next turn, each time you would take damage, you can spend chakra equal to the damage taken, gaining Immunity to the attack or jutsu’s damage and effects until the end of the current turn. If an effect does not deal damage or cost chakra, this jutsu does not prevent its effects. You can activate this Jutsu's effects a number of times equal to your Taijutsu ability modifier, per casting. RUSHING LION Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: M Cost: 4 Chakra Keywords: Taijutsu Description: You focus chakra throughout your muscles enhancing your physical Strength and Dexterity. For the duration, your Strength and Dexterity ability scores becomes 16 if they are lower than 16. Your Jump height is doubled and you cannot make Strength of Dexterity checks at disadvantage. When you would cast a Taijutsu that affects an area and forces a saving throw increase the size of area by +5 feet. SECOND HEAVENLY BREATH: PANTING Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Special Components: CM Cost: 5 Chakra Keywords: Taijutsu Description: As a requirement to activate this jutsu, you must have First Heavenly Breath: Inhale currently active. You end your concentration on that jutsu and this one takes its place, maintaining the same duration limitation and Jutsu casting restrictions. You retain all of the effects and duration of that jutsu, stacking them with this jutsu’s effects. You increase your lungs capacity fourfold. Doing so increases your oxygen intake even further as your body expands and your muscles become more prominent. Increase your taijutsu attack bonus by +1, bonus taijutsu damage by 1d8 twice per turn, and you gain 10 temporary hit points. SERPENT FANG DOUBLE Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: M Cost: 4 Chakra Keywords: Taijutsu, Finisher Description: As a requirement to activate this jutsu, you must currently be in the Serpent Fist Stance. You enter a low striking stance showing your overwhelming focus and precision as you disable your opponent with surgical accuracy. Make two melee taijutsu attacks dealing your [Unarmed Damage] + 1d8. A creature who is hit by at least one of these attacks, must make a Constitution saving throw. On a failed save they gain +1 rank of Weakened. If this jutsu is used as a Finisher, you instead deal your [Unarmed Damage] + 1d12 and if you score two hits on the target, they must make a Constitution saving throw, gaining +2 rank of Weakened on a failed save. At Higher Ranks: For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d8 or 1d12. 230 SILENT MOVEMENT Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, Up to 1 minute Components: M Cost: 4 Chakra Keywords: Taijutsu Description: As a requirement to activate this jutsu, you must currently be in the Silent Fist Stance. You enter a neutral stance, designed to exemplify silence and emptiness throwing most creatures off of being able to predict your actions. You do not spend chakra to maintain concentration on this jutsu. For the duration creatures cannot make reactions to one of the following. Pick one (This cannot be changed unless this jutsu is recast); • Your Movement. • Bonus Actions you make. • Reactions you take. SNAKE CONSTRICTING GRIP Classification: Taijutsu Rank: D-Rank Casting Time: Special Range: 5 feet Duration: Concentration, up to 1 minute. Components: M Cost: 4 Chakra Keywords: Taijutsu Description: When you deal [Unarmed Damage] to a creature as a result of an Unarmed attack, you can cast this jutsu as part of that same attack. When you do, that target must make a Strength saving throw, being restrained on a failed save. As an action on the target creatures turn, they may attempt a Strength saving throw to escape your hold. STRAIGHT IMPACT Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: Touch Duration: Special Components: M Cost: Special Keywords: Taijutsu, Finisher Description: You take a readied stance preparing your fist or foot for a single powerful strike. When you activate this jutsu, you can spend 5 chakra coating your fist in this chakra. You learn to be able to commit additional actions to make this attack stronger. You can spend your bonus action and an additional 5 Chakra to magnify this jutsu by 1 step. You can spend your reaction and an additional 5 chakra to magnify this jutsu by 1 step. You can inflict the stunned condition on yourself at the end of your turn until the beginning of your next turn to magnify this jutsu by 1 step. Make a single fiery taijutsu attack. On a hit, you deal your unarmed damage + 2d4 on a hit. For each step you magnify this jutsu by, increase the bonus damage by 2d4. If this jutsu is used as a Finisher, for each step you magnify this jutsu by, increase the bonus damage by 4d4. At Higher Ranks: For each rank you cast this jutsu above D-Rank increase the chakra spent activating this jutsu’s initial & additional effect by 3. If this jutsu is cast at B-Rank, increase the damage die of this jutsu by 1 step (D4>D6). If this jutsu is cast at S-Rank, increase the damage die of this jutsu by 1 step (D6>D8) SWALLOW DANCE Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: Self (10-Foot Cone) Duration: Instant Components: M Cost: 5 Chakra Keywords: Taijutsu, Combo Description: You perform a powerful wide sweeping roundhouse kick, lifting both yourself and all creatures you strike. All creatures in a 10-foot cone originating from you must make a Dexterity saving throw. On a failed save they take your unarmed damage + 1d8 and are launched 15 feet into the air until the end of the current turn, falling prone. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. At Higher Ranks: For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and the damage by 1d8. SWITCH KICK Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: M Cost: 4 Chakra Keywords: Taijutsu, Combo Description: You leap and perform a swift double kick in an attempt to support your team by queuing up a powerful finisher. As a part of casting this jutsu, you must have either a Bonus Action or reaction available to use. Make two taijutsu attacks against a creature within range dealing your [Unarmed Damage] on a hit. If you score at least a successful hit with this jutsu, you must spend either your bonus action or reaction. When you do, you grant your ally an additional reaction which they can only use to cast a Taijutsu with the Finisher Keyword that has a casting time of 1 action. Until the end of your turn, you or an allied creature can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action, Bonus action or reaction ignoring its listed casting time. WILD DANCE Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: M Cost: 3 Chakra Keywords: Taijutsu, Combo Description: You first attack your opponent with a kick, which is immediately followed by a punch and another kick, striking them at 3 different angles. Make three melee taijutsu attacks. On a hit, each attack deals 1d8 bludgeoning damage and push them 5 feet in any direction of your choice. If the target cannot be pushed back because of a structure or construct such as a wall or tree, you strike them into it, dealing an additional +1d6 damage. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. If you cast this jutsu at B-Rank or higher, increase 231 the damage the target takes from striking a wall by 1d6. If this jutsu is cast at S-Rank, increase the damage the target takes from striking a wall by 1d6. WISE TURTLE Classification: Taijutsu Rank: D-Rank Casting Time: 1 Action Range: Self Duration: Concentration, up to 1 minute Components: M Cost: 4 Chakra Keywords: Taijutsu Description: You focus chakra throughout your muscles enhancing your physical Strength and Cunning. For the duration, your Strength and Wisdom ability scores becomes 16 if they are lower than 16. Your lifting Strength is doubled and you gain a +2 to your passive perception. When you would cast a Taijutsu with a range greater than 5 feet, increase its damage by +1 damage die. C-RANK: 10-COUNT Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: M Cost: 7 Chakra Keywords: Taijutsu, Combo Description: You dash forward to perform a series of rapid but light strikes designed to get your blood flowing. Make a number of Taijutsu Attacks equal to your Taijutsu Ability Modifier, dealing 1d4 bludgeoning damage, to a maximum of 10. If you successfully hit a creature with at least 3 of these taijutsu attacks, the next taijutsu you cast before the end of your turn gains a +3 bonus to attack and damage rolls. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. At Higher Ranks: For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3. If cast at B-Rank or higher, increase the damage by +1d4. If cast at A-Rank or higher, increase the damage by +1d4. If cast at S-Rank or higher, this jutsu’s cast time becomes a bonus action. ADAMANTINE ACALA Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: M Cost: 8 Chakra Keywords: Taijutsu, Finisher Description: You perform a powerful kick to a targets center crushing their center of gravity and breaking their form. Make a melee taijutsu attack, dealing your [Unarmed Damage] + 2d8 and the target must make a Strength saving throw, being pushed back 30 feet on a failed save. If this jutsu is used as a Finisher, you make two kicks to the core, shattering their center of gravity and destroying their form. Make two melee taijutsu attacks, dealing your [Unarmed Damage] + 3d8 and the target must make a Strength saving throw, being pushed back 30 feet and falling prone and dazed on a failed save. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. BEAST Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: Self (15-foot Cone) Duration: Instant Components: M Cost: 9 Chakra Keywords: Taijutsu, Finisher Description: You perform a powerful spinning movement before you end it with a swift motion which converts all of that momentum into the shape of a lion head that erupts from your hands made from the force of your movement alone. All creatures within a 15-foot cone, originating from you must make a Strength saving throw. On a failed save they take your [Unarmed Damage] + 2d8, are bruised and knocked prone, or half as much on a successful save. If this jutsu is used as a Finisher, the lion head is both larger, more ferocious and impacts the immediate environment. On a failed they take your [Unarmed Damage] + 4d8, and gain +2 ranks of bruised, are pushed back 20 feet and fall prone on a failed save or half as much damage on a successful one. A creature who fails this saving throw by 5 or more and are gaining the benefits of Temporary hit points lose all temporary hit points. At Higher Ranks: For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d8. BREAK SPIRAL Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: Self (5-foot radius) Duration: Instant Components: M Cost: 7 Chakra Keywords: Taijutsu, Finisher Description: You leap onto your back on the ground as your perform a series of spinning kicks resembling a spinning top, striking all creatures around you. This jutsu can only be cast as a Finisher. All creatures within 5 feet of you must make a Dexterity saving throw. On a failed save they take are buffeted by a series of spinning kicks taking your [Unarmed Damage] + 6d6 and are knocked prone. A creature who failed their saving throw by 5 or more are Dazed and must spend their Action to stand from being prone. At Higher Ranks: For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the radius of this jutsu by 5 feet. 232 BURNING FIRE: DRUM Classification: Taijutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when a creature within 5 feet of you deals damage with a melee attack against yourself or an allied creature. Range: 5 Feet Duration: 1 Minute Components: M Cost: 9 Chakra Keywords: Taijutsu Description: You reach your hand out and attempt to beat the left lung of a hostile creature. Make a melee taijutsu attack against the triggering creature. On a hit, their lung swells. For the next minute, when the affected creature casts a Jutsu with the Mobility (M) component, they take 2d6 necrotic damage, which ignores Resistance, Immunity, Damage Reduction and Temporary Hit Points, as their lung swells more. A creature who would trigger this Jutsu's damaging effect 5 or more times while under its effects has their lung rupture, dealing 10d6 necrotic damage, which ignores Resistance, Immunity, Damage Reduction and Temporary Hit Points and gain 4 ranks of Exhaustion for the next 24 hours, this jutsu then immediately ends. A creature can spend their action to make a Constitution Saving throw to end this jutsu’s effects on them. Alternatively, a creature can end this effect with any Jutsu with the Medical Keyword, that removes conditions of C-Rank or lower. At Higher Ranks: For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the number of creatures you can target by +1. If cast at A- Rank or higher, when a creature lung ruptures, they instead take 15d6 Necrotic Damage. If cast at S-Rank, creatures make their saving throw to end this jutsu’s effects, at disadvantage. COLLIER SHOOT Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 5 Feet Duration: Instant Components: M Cost: 7 Chakra Keywords: Taijutsu, Combo Description: You leap off the ground no more than 5 feet and perform a powerful roundhouse kick targeting a creatures neck as you attempt to drag them into the ground. Make a melee taijutsu attack. On a hit, you deal your [Unarmed Damage] + 2d8 and the target must make a Strength saving throw. On a failed save, the target is knocked prone and is embedded into the ground as you kick them no more than 2 feet into the ground. A creature embedded into the ground is counted as Restrained by the ground itself and must make a Strength (Athletics) check vs your Taijutsu save DC to pull themselves from the ground. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. At Higher Ranks: For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the damage by 1d8. . COMBAT CLONE Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 30 feet Duration: Concentration, Up to 1 minute. Components: M Cost: 9 Chakra Keywords: Taijutsu Description: You take notice of another creatures fighting style, and begin to adjust your muscle memory to copy a creatures movements almost identically. This jutsu’s cost cannot be reduced by any means. Make a Martial Arts check targeting a creature you can see within range, using your Taijutsu ability modifier vs a DC (10 + Targets Level). On a success, you imitate their physical movements granting you the following benefits; • Your unarmed damage die becomes equal to the creatures unarmed or natural weapon damage die. • If the target has the Multiattack trait, you can make a number of unarmed attacks equal to the number of attacks they can make using their multiattack feature, with your Attack Action. • If the target is gaining the benefits of a Taijutsu Stance, you gain that stances benefits as if you knew it. DRAGON TAIL FOOT Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: Self (5 Feet) Duration: Instant Components: M Cost: 7 Chakra Keywords: Taijutsu, Combo Description: You perform sweeping kick, before performing a downward vertical kick to slam a target creature into the ground. Creatures within 5 feet of you must make a Dexterity saving throw, being knocked prone. If a target is knocked prone by the effect of this jutsu, select one target and make a single melee taijutsu attack dealing your [Unarmed Damage] + 3d6. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. EARLY SACRIFICE Classification: Taijutsu Rank: C-Rank Casting Time: 1 Reaction, which you take when a melee attack misses you. Range: 5 Feet Duration: Instant Components: M Cost: 6 Chakra Keywords: Taijutsu Description: After dodging an enemy’s melee attack, you leap on their shoulder and attempt to throw them 30 feet in a direction of your choice. The target must make a Strength saving throw, being thrown 30 feet in a straight line, in a direction of your choice. A thrown target must make a Dexterity saving throw, landing prone on a failed save. 233 If the target hits a surface such as a wall, ceiling, or large or larger object they take damage as if they were falling. ELEMENTANIA Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant. Components: CM, M Cost: 9 Chakra Keywords: Taijutsu, Finisher Description: As a part of casting this jutsu, you can only target a creature whom you can target with a Finisher as a result of a Jutsu cast with the Combo keyword. You bob and weave in and out of a creatures combat range, building up momentum, preparing yourself for a massive strike that takes the shape and visage of a roaring elemental storm. Make a melee taijutsu attack, dealing your [Unarmed Damage] + 4d12. Your attack gains the following benefits based on the elemental affinity you wished to imitate (Pick one when you cast this jutsu) • Earth: The ground and earth around you shakes and upheaves. All creatures within 10 feet of the original target must make a Dexterity saving throw, taking 3d6 bludgeoning damage from the erupting earth. • Wind: The wind whips and whistles as you forcefully move it out of your way. The target must make a Strength saving throw, being thrown back 15 x your Taijutsu ability modifier, feet on a failed save. If the target would hit a solid surface as a result of this knock back. They take 2d6 bludgeoning damage for every 15 feet that they were unable to be moved. • Fire: Your attack creates such wind resistance that your striking limb ignites into flame on impact. Your attack instead deals Fire damage and the target must make a Constitution saving throw, gaining 1 rank of the burned condition on a failed save. • Water: Your attack becomes graceful, like flowing water, allowing you to strike far more effectively. Reroll all 1’s and 2’s, taking the second result. • Lightning: Your attack is swift, decisive and powerful, like lightning. When your attack hits the target, creatures up to 300 feet away can hear an audible boom erupt from the point of impact. All creatures, excluding you, within 30 of the target creature must make a Constitution saving throw, being Dazed. ERUPTING FALLING STOMP Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 15 Feet Duration: Instant Components: M Cost: 7 Chakra Keywords: Taijutsu, Finisher Description: You pump chakra into your legs as you stomp, creating a shockwave of force from your Strength alone. Creatures in a 15-foot cube originating from you must make a Strength saving throw, taking 3d8 bludgeoning damage and gaining 1 rank of bruised on a failed save or half as much on a success. If this jutsu is used as a Finisher, your stomp upheaves the ground creating cracked surfaces and jutting terrain. The affected area becomes difficult terrain and all creatures who fail their saving throw instead take 5d8 bludgeoning damage and +1 rank of bruised on a failed save or half as much on a success. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and the size of the cube by 5 feet. EVENING HEAVENLY CRUSH Classification: Taijutsu Rank: C-Rank Casting Time: 1 reaction which you take when a target is forcefully moved more than 5 feet from you. Range: Self Duration: Instant Components: M Cost: 6 Chakra Keywords: Taijutsu Description: You dash to keep up with a thrown or knocked back creature who is moved further than 5 feet away from you. You take the dash action as a reaction and must end your movement within 5 feet of the target creature. As a part of the same reaction, you also make an unarmed attack as if you are making an attack of opportunity against the target. FALCON DROP Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: M Cost: 6 Chakra Keywords: Taijutsu, Finisher Description: This jutsu can only be used as a Taijutsu Finisher. As part of the activation of this jutsu, the target creature must be airborne or falling. Make a melee Taijutsu attack against falling creature. On a hit, you pile drive them into the ground dealing 5d12 Bludgeoning damage, leaving them prone, weakened and bruised. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d12 FIERCE SNAKE Classification: Taijutsu Rank: C-Rank Casting Time: 1 Bonus action Range: 5 Feet Duration: Instant Components: M Cost: 6 Chakra Keywords: Taijutsu Description: You rapidly strike a target with blinding speed, striking fast enough to leave after ima ges of your attacks. The next time you take the Attack action before the end of the current turn, you make +1 additional attack. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank or higher, increase the number of additional attacks you make to +2. 234 FIST SLAM Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant Components: M Cost: 6 Chakra Keywords: Taijutsu, Finisher Description: As a part of the activation of this taijutsu, you must target a prone creature. Make a melee taijutsu attack against the prone target dealing 6d6 bludgeoning damage and creating a 15-foot-deep hole in the ground while leaving them dazed. If this jutsu is used as a Finisher, your strike drives home your Strength and ferocity. On a hit, you deal 9d6 bludgeoning damage. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 FLOWING WATER Classification: Taijutsu Rank: C-Rank Casting Time: 1 Bonus Action Range: Self Duration: Concentration, up to 1 minute Components: M Cost: 9 Chakra Keywords: Taijutsu Description: You loosen your stance, allowing your body to become more fluid and adaptable to both incoming and outgoing attacks. Select two Taijutsu or Weapon stances that you know. You gain both of their benefits for the duration. FLOWING WATER: NO BEAT Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant. Components: CM, M Cost: 9 Chakra Keywords: Taijutsu, Finisher Description: You move with the grace and ruthlessness of a raging tide, slipping past an enemies weak points and washing them away as smoothly as running water. Make two melee taijutsu attacks against a single creature. On a hit your attacks do not deal damage, instead, at the conclusion of your attacks, the target must make a Constitution saving throw. For every attack that successfully hit after the first, the target suffers a -1 penalty to their saving throw. On a failed save, the target suffers 2 ranks of Exhaustion until the end of their next turn. If this jutsu is used as a Finisher, for every attack that successfully hit after the first, the target suffers a -2 penalty to their saving throw. At Higher Ranks: For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3 and the number of attacks you make by +1. FOURTH HEAVENLY BREATH: WHEEZE Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: Self Duration: Special Components: CM Cost: 9 Chakra Keywords: Taijutsu Description: As a requirement to activate this jutsu, you must have Third Heavenly Breath: Breathe currently active. You end your concentration on that jutsu and this one takes its place, maintaining the same duration limitation and Jutsu casting restrictions. You retain all of the effects and duration of that jutsu, stacking them with this jutsu’s effects. You increase your lungs capacity Sixteen-fold. Doing so increases your blood flow and you begin to glow with a yellow aura and your muscles and organs become far more resistant to damage. Increase your taijutsu attack bonus by +2, taijutsu damage by 1d8 twice per turn, and you gain +15 temporary hit points that stack with other temporary hit points gained as a result of this jutsu. At the end of this jutsu’s duration you gain 1 rank of the weakened condition until your next rest which cannot be removed by Jutsu of B-Rank or lower. FRICTION Classification: Taijutsu Rank: C-Rank Casting Time: 1 Action Range: 5 feet Duration: Instant. Components: M Cost: 9 Chakra Keywords: Taijutsu, Finisher Description: You move in to finish off your enemy with a powerful debilitating strike. Make a melee taijutsu attack. On a hit you deal your [Unarmed Damage] and the target must make a Constitution saving throw. On a failed save the target is stricken with a crippling affliction causing them to be unable to take the Dash, Dodge, Disengage, Help or Ready Action for the next minute. If this jutsu is used as a Finisher, you make three melee taijutsu attacks. If all three attacks are successful, then the target immediately fails their saving throw and the target cannot take the Dash, Dodge, Disengage, Help, Ready, Use an Object, or any Skill-Actions for the next minute. An affected creature can make spend an action to make a Constitution ability check vs your Taijutsu save DC to end this effect early. 235 GRASS PALM Classification: Taijutsu Rank: C-Rank Casting Time: 1 bonus action Range: 5 Feet Duration: Instant Components: M Cost: 7 Chakra Keywords: Taijutsu, Combo Description: You perform a series of martial attacks attempting to cripple and disable creatures surround you. Make a melee taijutsu attack against each creature within 5 feet of you dealing your [Unarmed Damage] + 2d10. Targets you hit with this taijutsu must make a Strength saving throw being disarmed and gaining +1 rank of weakened. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. At Higher Ranks: For each rank you cast this jutsu above C-Rank increase the cost of t", created_at: NOW, updated_at: NOW },
  { _id: "5b33ea22d4b4628dd3b6307c", name: "OCEAN PARTER [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range (20-foot cube)", chakra_cost: "12 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You slam your weapon down on its end with the force to part the ocean itself. All creatures within a 20- foot cube centered on the slam must make a Strength Saving throw, taking your [weapons damage] +2d10 on a fail and being knocked up 30 feet. While they are in the air, you gain advantage on Melee attacks against them and if they fall at the end of the current turn. If they fall sooner than that, the fall damage die is increased to a d8. If this jutsu is cast as a Chain 2, increase the damage die by 1 step. If this jutsu is cast as a Chain 3 increase the damage die by +2.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3 and the damage by 1d10. If this jutsu is cast at A-Rank, the fall damage die instead becomes a d10. If this jutsu is cast at S-Rank, the fall damage die instead becomes a 12 and creatures have disadvantage on their saving throw.", created_at: NOW, updated_at: NOW },
  { _id: "7dc1768fa8c3d50035ebb84b", name: "ONI'S MIGHT [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "W (Any Power), M", duration: "Concentration (1 minute)", description: "You funnel all of your Strength into the striking section of your weapon, with all the might of the ferocious Oni. For the duration your weapon attacks with a Power weapon deal an additional 1d8 Bludgeoning damage and your Taijutsu attacks with a Power weapon have a +1 critical threat range.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, the damage die by a step and the critical threat range by +1.", created_at: NOW, updated_at: NOW },
  { _id: "becdc8e1f638b5f26dd2c435", name: "POLEARM HEART", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "11 Chakra", components: "W (Polearm Group), M", duration: "Concentration, up to 1 minute.", description: "As a requirement to activate this jutsu, you must have a weapon from the Polearm weapon group equipped. This weapon gains +1 rank of the reach property. All Bukijutsu you cast, that requires an attack roll or forces another creature to make a saving throw, that deals damage, gain pierce (5) for the duration. Additionally, when you score a critical hit using your weapon with a weapon or Taijutsu attack, the target falls prone and reduces their movement speed by 15ft until the end of their next turn. 316", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5b9b34e4ed1a37a99dbbe6ba", name: "POWER HEART [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "11 Chakra", components: "W (Power Group), M", duration: "Concentration, up to 1 minute", description: "As a requirement to activate this jutsu, you must have a weapon from the Power weapon group equipped. Your heart and your power weapon become one. When you would strike an enemy with a successful weapon attack, once per turn, you can force them to make Strength saving throw. On a failed save they gain 1 rank of bruised. Additionally, when you score a critical hit using your weapon with a weapon or Taijutsu attack, the target gains 1 rank of concussed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "95a58d539345f611dfd1ae31", name: "QUICK DRAW", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "self (15ft cone)", chakra_cost: "12 Chakra", components: "W (Melee Slashing), M", duration: "1 round", description: "You take a withdrawn stance gripping your weapon and prepare for a powerful sweeping strike. You spend your turn preparing this attack until the beginning of your next turn. You cannot take Bonus action the turn you use this jutsu or a reaction after using this jutsu. At the start of your next turn, you can move up to your speed, and when you finish this movement, you swing with all of your force, all creatures in front of you in a 15 feet cone, must make a Dexterity saving throw at disadvantage, taking your [Weapon’s damage] +4d12 damage on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cc4c307729219324c043ecb4", name: "RECURVE STANCE [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Ammo) M", duration: "Concentration up to 1 Minute", description: "Chakra courses through your body and out into your weapon, causing you to retain some control of your shots even after they have soared through the air, curving and bending them in ways many would deem impossible. You don’t need to spend Chakra to maintain concentration on this Jutsu. For the duration of this Jutsu your Ranged Weapon attacks ignore half cover, and treat 3/4ths cover as half cover, if an enemy summons a construct to intercept your attack, you deal double damage to that construct. If an enemy reacts with a Jutsu, Feature, or trait that increases their AC, you may spend 2 chakra to reroll the attack without any bonuses aside from your ability modifier and proficiency, potentially turning the miss into a hit.", at_higher_ranks: "For Rank you cast this jutsu above B-rank, increase the cost of this jutsu by 3. Startint at A-rank, you ignore 3/4 cover. Starting at S-Rank, you gain a +2 bonus to rerolled attacks.", created_at: NOW, updated_at: NOW },
  { _id: "08de8f82a319c588e4e14340", name: "RELENTLESS BARRAGE [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "Weapons Range", chakra_cost: "12 Chakra. Special", components: "W (Any thrown)", duration: "Concentration, Up to 1 Minute", description: "You steady yourself in your stance, streaming your chakra into your fingertips in preparation to overwhelm your opponents with a steady stream of brutal strikes. As an Action on your turn, you may make two ranged Taijutsu attacks against a target within range, dealing [weapons damage] + 3d6. Each time you take this action on subsequent turns, deal an additional 1d6 damage. Should you reach 6d6 Bonus damage as a result of activating this jutsu multiple times, your next Ranged Taijutsu attack automatically crits. 317", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e670ec632f03427ef7324a5f", name: "RIOT JAVELIN [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "12 Chakra", components: "W (Any Thrown), M", duration: "Instant", description: "You throw your weapon and attempt to impale a creature pinning them to the wall. Make a ranged Taijutsu attack dealing your [weapon’s damage] + 6d8 on a hit and knocking them back 30 feet. If a creature collides with a solid object, their movement is stopped, taking falling damage equal to the distance they would have fallen. When a creature collides with a solid object they must make a Strength saving throw or be restrained. A creature repeats the Strength saving throw at the start of each of their turns, ending the condition on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "133cef119308c7f4bf78e202", name: "RUPTURE GALE ORB [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You whip your weapon into a sphere around you before you let it erupt out with a large burst. All creatures within your weapons range must make a Strength Saving throw. On a failure they are pulled within 5 feet of you. On a success they are only pulled up to 10 feet towards you. After, all creatures within 5 feet of you must make Constitution Saving throw as the small gale around you erupts, dealing your [weapons damage] +2d12 and being knocked prone. If this jutsu is cast as a Chain 2, increase the damage die by +2. If this jutsu is cast as a Chain 3 increase the damage die by an additional +2.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "8b34c5b714426a7fc03a4e41", name: "SHATTERING WILL [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Self (15-foot radius sphere)", chakra_cost: "12 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You slam your weapon on the ground delivering a mighty blow designed to instill fear in your opponents. Creatures in range other than you, must succeed a Dexterity saving throw taking your [weapons damage] +4d6 Bludgeoning damage and being knocked prone on a failed save, or half as much on a successful one and suffering no other effects. Regardless of whether a creature passes or fails, all hostile creatures within range must make a Wisdom saving throw, gaining 1 rank of fear on a failed save, gaining disadvantage if they fail the Dexterity saving throw. If this jutsu is cast as a Chain 2, this jutsu deals an additional 6 damage die, if this jutsu is cast as a Chain 3, increase the damage die by an additional +4.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7ca295ed3f634cd9e5e2f7c5", name: "SILENT KILLING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "W (Melee Slashing or Piercing), M", duration: "Instant", description: "As a part of the requirement for activating this jutsu, you must be hidden from that target creature you are targeting. You sneak towards your target and strike at their most vital points. Make a Taijutsu Attack vs target creatures Passive Perception. On a Success you treat this attack as a hit dealing 15d4 Damage of your chosen weapon type. If you reduce the target creature's Hit Points to 0, they immediately are killed.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and Damage by 2d4", created_at: NOW, updated_at: NOW },
  { _id: "e19a41fb03d75f933ae1d754", name: "SOUL SCATTER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "14 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "You manifest multiple shots of ammunition with your chakra, before loading them into your weapon and firing them. Select a number of creatures equal to your Taijutsu ability modifier. Make a single ranged Taijutsu attack, using the result vs each of their Armor Class values. You do not roll ammunition die when casting this jutsu. On a hit, you deal your [weapons damage] + 4d8, each target must make a Constitution saving throw or be knocked prone and restrained by your shot. A restrained creature can, as an action, attempt to remove the construct shot from themselves by making a Strength saving throw. 318", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b78c7cbd4b0e97a706664a98", name: "STAMINA STRIKE [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Flail), M", duration: "Instant", description: "You whip your weapon before slamming it into the center of your enemy, looking to ruin their flow and stamina. Make a Melee Taijutsu attack against a creature in range, dealing your [weapons damage] +4d6 damage and the target creature must make a Constitution Saving Throw. If you crit this attack, the target creature automatically fails this save. On a failed save, the target creature becomes Dazed until the end of their next turn and loses an amount of chakra equal to the jutsu damage rolled. If this jutsu is cast as a Chain 2, increase the damage die by +6, if this jutsu is cast as a Chain 3, increase the damage die by an additional +4.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "b46937ab97bafdcf7923104a", name: "SUICIDE BOMBING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, which you take when someone else takes an action", range: "30 feet radius sphere", chakra_cost: "11 Chakra", components: "NT (Paper bombs), M", duration: "Instant", description: "You open your clothing revealing a series of paper bombs all rigged to explode. You have enough time to speak a few more words before they all ignite and explode. All creatures within 30 feet of you must make a Dexterity saving throw at disadvantage. You take maximum damage. On a failed save the targets takes 15d6 fire damage, or half as much on a failure.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "96886768d8360591d3f24028", name: "SUN SPEAR [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon’s Range (30-foot cone)", chakra_cost: "12 Chakra", components: "W (Melee Piercing), M", duration: "Instant", description: "You spin your weapon along its edge fast enough to ignite the very air before stabbing forwards, looking to impale your foe with the fury of the sun. Make a Melee Taijutsu attack against a creature in range. On a hit your deal your [weapons damage] +2d10 fire damage and on hit or miss, All creatures in a 30-foot cone from the point of impact, excluding the original target, must succeed a Dexterity saving throw, taking the fire damage rolled on a failure and half on a success. If this jutsu is cast as a Chain 2, increase the damage die by +4, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "101b5fb6db1dc20e17631fca", name: "SUNWING SHOT [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Ammunition), M", duration: "Instant", description: "You aim your shot so that it has a source of bright light shining right behind it. Merging the light into the chakra imbued in the ammunition. You cannot cast this jutsu in dim light or darkness. Make a Ranged Taijutsu attack against a target in range. On a hit, you deal [weapons damage] +2d10 fire damage and the target creature must make a Constitution Saving throw, gaining a rank of Burned. If they fail by 5 or more they also become Blinded until the end of the current turn. If this jutsu is cast as a Chain 2, increase the damage die by +3 if this jutsu is cast as a Chain 3, increase the damage die by an additional +1 and, creatures suffer a - 1d4 penalty to their saving throw.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, and the damage + 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "7681b7d0a5416dd0952dc827", name: "SWORD AURA: GREEN [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "W (Any Blade), M", duration: "1 Minute", description: "You must be under the effects of Sword Aura: Orange to cast this jutsu. You Strengthen your Sword Aura, flooding more chakra into your sword, the striking portion chilling green from the mixing of chakra. Sword Aura: Orange ends and you replace the effects with this jutsu. Your weapon gains pierce (12). Twice per turn when you deal [weapons damage], you can force all creatures in your weapons range to make a Strength Saving Throw, taking 3d10 Poison damage and gaining 2 ranks of Bleeding on a failed save and a half damage on a pass.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "aa6e2e35d12951689466d3df", name: "TENDON SHOT [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Ammo) M", duration: "Instant", description: "You take a quick assessment of the enemies movements, their fighting styles, do they use kicks? Punches? Weapons? All of them can be disabled if you know where to strike, and you do. Make a Ranged Taijutsu attack against a target within range, on hit, deal your [weapons damage die] + 8d4. On hit the target must also make a Constitution saving throw, on a fail, you've pierced a tendon or nerve relating to their fighting style, roll a 1d4+1. The affected creature has disadvantage on that many Taijutsu and/or weapon attacks.", at_higher_ranks: "For Rank you cast this jutsu above B- rank, increase the cost of this jutsu by 3, the die size of the 1d4+1 by 1, and the damage by 1d4 319", created_at: NOW, updated_at: NOW },
  { _id: "1215fb4ce2e0d4175a4bd2da", name: "THREE THOUSAND WORLDS [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You integrate all your power and chakra into your sword, lacing it with enough chakra to cut any and everything that stands before you. If this jutsu is cast targeting a creature who is gaining the benefit of the Dodge action, you do not make the attack at disadvantage. If this jutsu is cast targeting a creature who is gaining the benefits of Temporary hit points, Damage Reduction or Resistance, you ignore them for this attack and damage roll. Make a melee Taijutsu attack dealing your [weapons damage] + 5d6 and on a hit the target creature makes a Constitution Saving Throw, gaining 1 rank of Lacerated. If this jutsu is cast as a Chain 2, increase the damage die by +5,if this jutsu is cast as a Chain 3, increase the damage die by an additional +3, additionally, this jutsu inflicts an additional rank of lacerated.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "e4844a74b7abbeef01f94a55", name: "TWIN RISING DRAGONS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet radius Sphere", chakra_cost: "12 Chakra", components: "NT (Weapon Scrolls), M", duration: "Concentration, up to 1 Minute,", description: "You grasp two of the scrolls with throwing weapons sealed into them and unleash them in a double helix formation. As you leap, the scrolls create a field of thin but strong wires, allowing for you to remain 30 feet off the ground, standing airborne between them. For the duration of this jutsu, as an action, you can make up to 3 ranged Taijutsu attacks each round, targeting 1 creature each attack, dealing 4d6 piercing damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c029d779e85282c0e1e5a0a1", name: "WHIRLWIND CATAPULT [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "up to half Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Thrown), M", duration: "Instant", description: "You throw your weapon around yourself, causing a whirlwind of steel and blood up to the end of your range. All creatures in a sphere around you with a radius up to your weapons range need to make a Dexterity and Strength Saving Throw. On a failed Dexterity Saving throw they take your [weapons damage] + 2d6 and gain 2 ranks of bleeding, taking half damage and 1 rank of bleeding on a success. On a failed Strength Saving throw, they are thrown to the outer edge of the sphere. If this jutsu is cast as a Chain 2, increase the damage die by+2, additionally, this jutsu inflicts and additional rank of bleed on failure, if this jutsu is cast as a Chain 3, increase the damage die by an additional +3, additionally, this jutsu inflicts an additional rank of bleed on a success and failure, up to 3 total.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3, and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "13a11c3a4622a07089e9ecf3", name: "WHIRLWIND STRIKE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Melee Weapon), M", duration: "Instant", description: "You spin in a violent fashion striking all creatures surrounding you. All creatures of your choice within your weapons range must make a Dexterity saving throw, taking your [weapons damage] + 5d10 on a failed save, or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and Damage by 1d10. 320", created_at: NOW, updated_at: NOW },
  { _id: "c77ad249a6c88814540fb417", name: "WIRE CRUCIFIXION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "11 Chakra", components: "W (Battle Wire), M", duration: "Instant", description: "As a part of casting this jutsu, you must be in a forest, urban environment, or cavernous terrain. You pull your wires, revealing threads already surrounding a target you can see within range. Select two creatures within range. Both must make a Strength saving throw, being grappled, restrained, being unable to make hand seals and gaining 2 ranks of bleeding on a failed save. On the targets turn, they spend an action to make a Strength saving throw to break the wires, ending the grappled and restrained condition on themselves and also being able to make hand seals again. A creature that ends its turn grappled and restrained by this jutsu gains an additional 2 ranks of bleed.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of creatures affected by this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "fd1743b7c11bec6f74afdac4", name: "WITCH HUNTER [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "02498f5c0812d94cde669aca", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "12 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You spin your weapon with a cruel smile and reel back to deliver a deadly swing that would dismantle apart any witch. Each creature in a 15-foot cone must make a Dexterity saving throw, or take your [weapons damage] + 1d10 force damage and gain 1 rank of weakened and bleeding on a failed save. Creatures within 5 feet of you make this saving throw at disadvantage. On a successful save, a creature takes half as much damage and no additional effects. If a creature is concentrating on a jutsu and fails the save, concentration immediately ends. On a successful save they still make their concentration check at disadvantage. If this jutsu clashes with a Ninjutsu, you gain advantage on the clash check. If this jutsu is cast as a Chain 2, If this jutsu is cast as a Chain 2, increase the damage die by +2, if this jutsu is cast as a Chain 3, this jutsu inflicts an additional rank of weakened.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "893f180e48c6a8ff8eb07cd4", name: "YIN-YANG INVERSION [NEW]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "12 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You spin your weapon, pooling the light and dark energies into the two different ends before you strike out with one of them. Yin Strike: Make a Melee Taijutsu attack, dealing your [weapons damage] on a hit. You can then force the creature to make a Constitution Saving Throw. On a failed save they must spend and roll 1d4 Hit die and you heal half of the rolled amount. You can only heal from this jutsu once per creature per rest. Yang Strike: Make a Melee Taijutsu attack, dealing your [weapons damage] on a hit. You can then force the creature to make a Constitution Saving Throw. On a failed save they must roll 1d4 Hit die and they lose that much in current and maximum HP. A creature can only lose maximum HP from this jutsu once per rest.", at_higher_ranks: "For every rank you cast this jutsu above B-Rank, increase the cost by 3 and the hit die rolled by 1. 321 A-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "fed2e0bb2c32d46b0e426f63", name: "1-SHOT PIERCE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "15 Chakra", components: "W (Ranged Piercing), M", duration: "Instant", description: "You put your all into a single shot with your ranged weapon, intended to end the fight with prejudice intent. Make a ranged Taijutsu attack, dealing your [weapons damage] + 6d8 and forcing the target creature to make a Constitution saving throw, being staggered on a failed save. If this jutsu is cast as a Chain 2, increase the damage die by +4, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "c0153b88607e8c55a12b677c", name: "AFTERIMAGE STORM [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Self (Weapon range radius sphere.)", chakra_cost: "16 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You spin, around striking any and everything that stands in your path. Make a Taijutsu attack targeting all creatures in range. On a hit you deal your [weapons damage] and all creatures must make a Dexterity Saving throw, hit or miss. If you crit with this attack all creatures make their saves at disadvantage. On a failed save, the after images of the weapon strikes them repeatable. They take your [weapons damage] +3d4 and gain 2 rank of bleeding. On a success they take half damage and if they were still hit, gain 1 rank of bleeding. If this jutsu is cast as a Chain 2, increase the damage die by +4, if this jutsu is cast as a Chain 3, creatures who fail instead gain 2 ranks of Lacerated.", at_higher_ranks: "For every rank you cast this jutsu above A-Rank, increase the cost by 3, the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "66a676533e9763d484c16163", name: "ARMOR PIERCE [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 action", range: "30 feet", chakra_cost: "16 chakra", components: "W (Any Ammo)", duration: "Instant", description: "You prepare a full power shot, putting all of your weight and momentum behind it. If this jutsu is cast targeting a creature who is gaining the benefit of the Dodge action, you do not make the attack at disadvantage. If this jutsu is cast targeting a creature who is gaining the benefits of Temporary hit points, Damage Reduction or Resistance, you ignore them for this attacks and damage rolls. Make a ranged Taijutsu attack dealing your [weapons damage] + 6d8.If you critically hit with this attack, you reduce the targets DR from armor by half until it is repaired. If this jutsu is cast as a Chain 2, increase the damage die by +4, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "8a23dec30efef488482a39f1", name: "ASSASSIN’S BREATH [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "W (Any Thrown Weapon), M", duration: "Special, Concentration", description: "You enter a state of utmost stillness, moving no muscles not even your lungs. You take in a large breath and hold it, preparing for a perfect shot while regulating your body with you own Chakra instead of breathing. During this time you can't speak or breathe as you remain as absolutely still as possible to take your shot. While this jutsu is active, the [weapons damage] of your thrown weapons is rolled at advantage, and deals an additional die of damage (Two if your die size is a D4) additionally, for each Weapon and Taijutsu attack you hit while benefitting from this jutsu you deal additional damage equal to your proficiency bonus twice per creature, per turn. Finally, at the end of each of your turns, you must make a Chakra Control check to upkeep this stance benefits, where the DC equals 13+Number of rounds this jutsu has been active. 322", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2abfb64a472bc0c2c9219776", name: "BENTHIC DESCENT [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "W (Any Melee Piercing) M", duration: "Instant", description: "You strike your foe into the air before quickly following up with a strike to slam them down. A target creature in range must make a Strength Saving Throw, taking your [weapons damage] on a failure. You then can make a Melee Taijutsu attack at advantage against a creature who fails, dealing your [weapons damage] +6d10 on a success and knocking them prone and inflicting 2 ranks of weakened.", at_higher_ranks: "For each rank you cast this above A- Rank, increase the cost by 3. If this jutsu is cast at S- Rank, you can instead force all creatures in weapons range to make the Strength Saving Throw.", created_at: NOW, updated_at: NOW },
  { _id: "dd9ba6d96d3744327aed4d44", name: "BESTOWAL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Weapons range", chakra_cost: "17 Chakra", components: "W (Melee Slashing or Piercing), M, CM", duration: "Concentration, up to 1 Minute", description: "You focus your chakra and inject it into your weapon. As a part of the activation of this jutsu make a melee Taijutsu attack. targeting a creature within range. On a hit, you deal your [weapons damage] and draw blood from your target, coating your weapon in it. For the duration, you weapon deals an additional 4d8 necrotic damage twice per turn. Is you miss on this first attack, this jutsu fails and you lose concentration immediately. 323", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "66b22f9de2b3cf9ad7e086f8", name: "BINDING FURY: METEOR [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "f4476d87b21771883686f854"], elements: [], casting_time: "1 Action", range: "Weapons range", chakra_cost: "16 Chakra, all your current Fury stacks", components: "W (Any Power), M", duration: "Instant", description: "You channel all your stored energy into your fist before slamming it into your enemy’s core, with the force of a meteor. Make a Melee Taijutsu attack against a target creature in range. On a hit your deal twice your [weapons damage] + Xd12 fire damage where X equals your current Fury stacks and force the target creature to make a Strength Saving throw to avoid be knocked prone and restrained into the ground until the start of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1fe3c10722a8f611163cd4dd", name: "BLADE OF SIN: ENVY [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon range", chakra_cost: "12 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You seek to emulate the power of one of the Seven Deadly Sins of Humanity in your blade, imbuing the Sin of Envy inside the edge. Make a Melee Taijutsu attack against a creature in range. On a hit you deal your [weapons damage] +5d8 and if the target creature is gaining any type of positive buff from a jutsu, feature or trait they must make a Constitution Saving Throw. On a failed save any dice-based benefits they receive from the jutsu feature or traits is reduced by 1 step (d12>d10>d8>d6>d4>0)and you gain a d4 bonus of the same benefit until the end of your next turn If this jutsu is cast as a Chain 2, increase the damage die by +5, if this jutsu is cast as a Chain 3, additionally you reduce their benefits by 2 steps and you gain a d6 bonus instead.", at_higher_ranks: "For every rank you cast this jutsu above A-Rank, increase the cost by 3 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "fc045402e94edd92278cef21", name: "BLISTERING EDGE [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "16 Chakra", components: "W (Any Melee Slashing) M", duration: "Concentration (1 Minute)", description: "For the duration you sharpen the edge of your blade so that when you swing your blade with high speed it ignites the air, burning the edge of the blade from friction alone. Twice per turn for the duration you can convert your [weapons damage] into fire damage and force a creature who takes [weapons damage] to make a Constitution Saving throw or gain a rank of Burned.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c4cc3fd5a2f8df8a12973f69", name: "BLOOD SHOT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "19 Chakra", components: "W (Ranged Piercing), M", duration: "1 Round", description: "Your blood begins to rush as you prepare a shot using ammunition with this rush. Until the start of your next turn, any time you would deal damage to a creature with a ranged weapon, which deals piercing damage, the creature gains 1 rank of bleeding. A creature cannot gain more than 5 ranks of bleeding in this way, as a result of this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3. Starting at S-rank, the duration becomes concentration, up to 1 minute, and a creature cannot gain more than 5 ranks of bleeding from this jutsu per turn.", created_at: NOW, updated_at: NOW },
  { _id: "84bd2a201cd2e8b485b46022", name: "BREATH OF MOON: CATASTROPHE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "16 Chakra", components: "W (Any Melee), M", duration: "Instant", description: "You collect and manifest a dark chakra until it laces the striking portion of your weapon, curving it like a crescent moon. Each swing creates distortions in the area, devastating the terrain and manifesting waves of force capable of obliterating everything in its path. All creatures in a 30-foot-cone, originating from you, must make a Dexterity saving throw, taking 5d12 slashing damage on a failed save, or half as much on a success. Until the end of your next turn, you can cast a Bukijutsu with the “Breath of Moon Prefix “using either your Action, Bonus Action or Reaction, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a66c9781a1da95700f3e44e3", name: "BREATH OF MOON: EVENING PALACE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "W (Any Melee), M", duration: "Instant", description: "You collect and manifest a dark chakra until it laces the striking portion of your weapon, curving it like a crescent moon. Each swing creates distortions in the area, devastating the terrain and manifesting waves of force capable of distorting space, removing all in its way. Make a melee Taijutsu attack, dealing your [weapons damage] + 7d12 ignoring Resistance and treating immunity as resistance. Until the end of your next turn, you can cast a Bukijutsu with the “Breath of Moon Prefix”using either your Action, Bonus Action or Reaction, ignoring its listed casting time. 324", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "49939afc6f3979c484318e47", name: "BREATH OF MOON: LOATHSOME", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "15 Chakra", components: "W (Any Melee), M", duration: "Instant", description: "You collect and manifest a dark chakra until it laces the striking portion of your weapon, curving it like a crescent moon. Each swing creates distortions, devastating the terrain and manifesting waves of force. You swing your weapon twice with such ferocity, that the space around you distorts removing the distance between you and another creature. Select a creature you can see within range as you cut through the distance, teleporting to a space adjacent to the target that can hold you. Make two melee Taijutsu attacks, dealing your [weapons damage] + 4d12. Until the end of your next turn, you can cast a Bukijutsu with the “Breath of Moon Prefix”using either your Action, Bonus Action or Reaction, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c058963a7e4330369c9e93c8", name: "BREATH OF MOON: MOONGAZING", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "Weapons Range", chakra_cost: "15 Chakra", components: "W (Any Melee), M", duration: "Instant", description: "You collect and manifest a dark chakra until it laces the striking portion of your weapon, curving it like a crescent moon You swing your weapon in the shape of a crescent moon with the intent of deflecting some of the incoming damage. Roll your [weapons damage] + 5d12, recording the result. Until the end of the current turn, you manifest a wall of force generated purely by the distortions your swings make. This wall of force has a number of hit points equal to the result, and intercepts all damage. Until the end of your next turn, the next Bukijutsu you cast with the “Breath of Moon:” Prefix, gains a +2d12 bonus to damage once per casting.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9d70c4ebb546146039346a9b", name: "BREATH OF MOON: MOONSWATHS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "15 Chakra", components: "W (Any Melee), M", duration: "Instant", description: "You collect and manifest a dark chakra until it laces the striking portion of your weapon, curving it like a crescent moon. Each swing creates distortions in the area, manifesting into crescent moons that bombard an area with reckless abandon. Select up to 4 spaces you can see within range. All creatures within 5 feet of each space must make a Dexterity saving throw, taking 4d12 slashing damage on a failed save or half as much on a success. A creature can only be affected by this jutsu once per casting. Until the end of your next turn, you can cast a Bukijutsu with the “Breath of Moon Prefix “using either your Action, Bonus Action or Reaction, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "00e16cca1f6cfe5dc2f18d60", name: "BURST AMMO [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 action", range: "30 feet", chakra_cost: "8 chakra", components: "W (Any Ammo)", duration: "Instant", description: "You perform a series of quick attacks with enough force to penetrate steel, blasting through your enemy. Make a ranged Taijutsu attack against the target, dealing your [weapons damage] +4d10 and all creatures in a 20-foot cone behind the target takes damage equal to half of the result. If this jutsu is cast as a Chain 2, increase the damage die by +6, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2, additionally, creatures suffer a -1d4 penalty to their saves", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "ddab10c94c60592abb371266", name: "CHASING FANG", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Up to your Full Movement.", chakra_cost: "17 Chakra", components: "W", duration: "Instant", description: "You first launch a fist full of throwing weapons 325 towards a target to break their focus. Make a ranged Taijutsu attack. On a hit, you deal your thrown [weapons damage] + 3d8, which is then follow up with a Powerful Swing. Make a melee Taijutsu attack, dealing your [weapons damage] + 6d10. If your first attack hits, this one is made at advantage. If this jutsu would score a critical hit, you can choose to either maximize damage or double your damage die as normal.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and Damage by 1d8 & 1d10, respectively.", created_at: NOW, updated_at: NOW },
  { _id: "ab7b0c58b584ac3979d14a29", name: "COUNTER SHOT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, which you take when targeted by an attack", range: "Weapons Range", chakra_cost: "15 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "As a reaction to being attacked, you take the attack head on in an attempt to lock the opponent in perfect targeting range, preventing them from dodging. You take the maximum possible damage from the attack you were targeted with. Immediately after you take the damage, you are able to cast 1 Bukijutsu with a casting time of 1 action or 1 bonus action at no additional chakra cost of B-Rank or lower.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e67723ca183f2ad777a56d9a", name: "CRESCENT MOON DANCE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Up to your Full Movement.", chakra_cost: "19 Chakra", components: "W (Any Melee Weapon), M", duration: "Instant", description: "You move with such speed you create 2 additional afterimages that move separately from you. Make 3 melee Taijutsu attacks against a single target dealing your [weapons damage die]. If three attacks score a hit, you deal an additional 8d10 of whatever damage your weapon deals and the target cannot take reactions until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "23725f3493db372c6ce37a58", name: "CRESCENT MOON SHOT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "You fire three arrows rapidly, with all three seemingly landing at the same time. Make 3 ranged Taijutsu attacks against a single target, dealing your [weapon’s damage die]. If three attacks hit, you deal an additional 8d10 damage of whatever your weapon deals, and the target can't take reactions until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "d085b35071f6a770621c0c62", name: "DANCE PERFORMANCE: GROOVE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b7c3bde363176d05f69f793a"], elements: [], casting_time: "1 Full-Turn Action", range: "60 Feet", chakra_cost: "20 Chakra", components: "W (Any), M", duration: "Concentration, up to 1 minute.", description: "You move so fast you create multiple afterimages, one in front of each creature of your choice within range. Each creature your afterimages are in front of must make a Charisma saving throw, being charmed by you for the duration, as you begin dancing to a rhythm sounded out on your weapon. While charmed by you in this way, the affected creature must use all of its actions dancing, and its movement speed is reduced to 5 feet. An affected creature cannot break free of this dance on its own. Instead, another creature must use its action to make a Charisma (Performance) check against your Genjutsu save DC, breaking them out of your dance on a success. A creature broken out of your dance is immune to this jutsu when cast by you for the next 24 hours.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5940c1d28a677bdee6911af3", name: "DARK NIGHT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "16 Chakra", components: "W (Any Ranged), M", duration: "Concentration, up to 1 minute.", description: "You fire three arrows rapidly, with all three seemingly landing at the same time. Make 3 ranged Taijutsu attacks against a single target, dealing your [weapon’s damage die]. If three attacks hit, you deal an additional 8d10 damage of whatever your weapon deals, and the target can't take reactions until the end of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ffc877a17ad48956b236023a", name: "DEADLY RANGED CONNECTION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "16 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "You perform a series of quick attacks with enough force to penetrate steel. Make 3 ranged Taijutsu attacks against a target within range, dealing your [weapons damage die] + 3d4 and gains the bleeding condition on each hit. If this jutsu is cast as a Chain 2, increase the damage die by +4, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2, additionally, if you land all attacks, the creature suffers a rank of lacerated, in place of any bleed.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "0b6786a7007fd1b90f2982e7", name: "DEMON HUNTER [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "16 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You spin your weapon with a cruel smile and reel back to deliver a deadly swing that would dismantle apart any demon. Each creature in a 20-foot cone must make a Dexterity saving throw, or take your [weapons damage] +1d12 force damage and gain 1 ranks of weakened and 1 ranks of bleeding on a failed save. Creatures within 5 feet of you make this saving throw at disadvantage. On a successful save, a creature takes half as much damage and no additional effects. If a creature is concentrating on a jutsu and fails the save, concentration immediately ends. On a successful save they still make their concentration check at disadvantage. If this jutsu clashes with a Ninjutsu, you gain advantage on the clash check and the triggering creature gains disadvantage. If this jutsu is cast as a Chain 2, increase the damage die by +4, if this jutsu is cast as a Chain 3, increase the damage die by an additional +1, additionally, this jutsu inflicts an extra rank of its listed conditions.", at_higher_ranks: "For every rank you cast this jutsu above A-Rank, increase the cost by 3 and the damage by 1d12. If this jutsu is cast at S-Rank you instead gain the benefits for clashing against any jutsu type.", created_at: NOW, updated_at: NOW },
  { _id: "e3061ce7ab9db47bda73de4e", name: "DRAGON-BLADE [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "15 Chakra", components: "W (Melee Slashing), CM", duration: "1 Round", description: "You coat your blade in flowing chakra in the shape of a fierce dragon that guides your strikes. Until the start of your next turn, your weapon deals 2 additional damage dice in force damage, double your movement speed, and increase your AC by +1. Additionally, when you reduce a creature's hit points to 0, you can make a single melee weapon attack. You can make this additional attack a number of times equal to your Taijutsu ability modifier (Max of 5).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "80aafd51c827db7fcf92abca", name: "DRAGON-STRIKE [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Full Turn Action", range: "Self (90-foot line)", chakra_cost: "19 Chakra", components: "W (Any Ranged), CM", duration: "Instant", description: "You aim your weapon and coat it in a twisting chakra that and then becomes a pair of dragons that spiral around each other when you fire, expanding until the weapon is completely obscured. All creatures in a 90 feet long, 15 feet wide line, originating from you, must make a Dexterity saving throw taking 8d10 force damage on a failed save, or half as much damage on a successful one.", at_higher_ranks: "For every rank you cast this jutsu above A-Rank, increase the cost by 3 and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "188c0bba9d94293f38095436", name: "EARTH SHATTER [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "16 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You wind up a powerful overhead swing and send it straight into the ground crackling the earth. Each creature in a 15-foot cone must make a Strength saving throw, taking your [weapons damage] + 1d12 and being dazed, bruised, knocked prone on a failed save. If this jutsu is cast as a Chain 2, increase the damage die by +2, if this jutsu is cast as a Chain 3, increase the damage die by an additional +1", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a436b3c1487a8ad1d0cff02d", name: "ECLIPSED SUN IMPACTS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Up to your Full Movement.", chakra_cost: "19 Chakra", components: "W (Melee Bludgeoning), M", duration: "Instant", description: "You move with purpose and your weapon follows a predestined path. You strike fast enough to leave ripples in the air and surrounding gasses as your weapon ignites upon impact. Make a melee Taijutsu attack, dealing your [weapons damage] + 6d8. The target also gains 2 ranks of burned. If this jutsu is cast as a Chain 2, increase the damage die by +6, if this jutsu is cast as a Chain 3, increase the damage die by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and Damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "01bf0f2cae85afe5988f3d41", name: "ELEMENTAL BACKLASH", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "8d54405acfe4fd3d67fe3d50"], elements: [], casting_time: "1 Reaction, which you take when you would take Earth, Wind, Fire, Cold, or Lightning Damage.", range: "Self", chakra_cost: "20 Chakra", components: "W (Any Melee), M", duration: "Instant", description: "As a part of casting this jutsu, you must have a nature release or be able to cast a jutsu with a nature release keyword. When you would suffer the effects of any elemental damage, you can call upon your own nature release to attempt a violent counter strike. Roll your [weapons damage die] + Xd12, where x is your proficiency bonus, and record the result. If your result is higher than the damage you would take, you immediately counter the triggering damage 328 effect as if you had won a clash, dealing the result to all creatures of your choice within 10 feet of you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6532cc9af3d1e224aa094d2d", name: "FATAL BLOW", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "779d29453b00c99fe6a14d9c"], elements: [], casting_time: "1 Action", range: "15 Feet", chakra_cost: "Special (20 Chakra)", components: "W (Any Melee), M", duration: "Instant", description: "As part of casting this jutsu, your target must be prone, restrained, or incapacitated. You take a great leap bringing your weapon into a spiraling ascent towards a target. The target must make a Dexterity saving throw. On a failed saving throw, they take your [Weapon's Damage] + X damage to their hit points, and half as much as chakra damage. The value of X is decided by your current chain. Also on a failed saving throw, roll a d20. On an 18-20, double this jutsu's damage die. On a successful saving throw, the target completely avoids your saving throw as they roll out of the way. If this jutsu is cast while under a lightning storm, your weapon is struck magnificently with a strike of lightning as you ascend and is imbued with the wrath of the sky. This jutsu's damage type becomes lightning and its damage die is increased by +2, and the range you must roll on the d20 to double this jutsu's damage die is increased by +1. These special effects can also be triggered if your weapon is under the effects of a Jutsu with the Lightning Release keyword. You may cast this jutsu Chain 1, 2, or 3, depending on your current chain number, which determines this jutsu's damage and effects. Casting this jutsu breaks your current chain upon its conclusion. • Chain 1: You may cast this jutsu as a Chain 1 if your Chain number is 0 or 1. This jutsu's damage becomes 5d10. • Chain 2: You may cast this jutsu as a Chain 2 if your Chain number is 1 or 2. This jutsu's damage becomes 6d10, and the target makes their saving throw with disadvantage. • Chain 3: You may cast this jutsu as a Chain 3 if your Chain number is 2 or 3. This jutsu's damage becomes 7d12, the target makes their saving throw with disadvantage, and the range you must roll on the d20 to double this jutsu's damage die is increased by +1.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ccb8674c120ca9314b4d6263", name: "FATAL INSTINCTS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "19 Chakra", components: "M, CM", duration: "Concentration, up to 1 Minute", description: "You inject chakra into every muscle you have and begin to exercise mental control over your body moving at the speed of thought. For the duration, increase your initiative by +10, moving yourself up in the initiative count based on this new bonus. When you make Dexterity saving throws roll an additional 2d20 and take the highest roll. You cannot gain advantage on Dexterity saving throws. You also gain one additional Reaction and Bonus action. When this jutsu ends, you are moved down 3 spaces in the initiative count and become stunned until the end of your next turn. 329", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "34e11743d0ab1af07be57e86", name: "FINAL SHOT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "1-Mile", chakra_cost: "20 Chakra", components: "W (Any Ammunition), M", duration: "Instant", description: "You concentrate a great amount of chakra into a single shot and release it with enough force to destroy a mountain. You must spend a d8 stack of ammunition as a part of this jutsu’s cost. Make a ranged Taijutsu attack, dealing your [weapon’s damage] + 4d8 force damage and becoming dazed on a hit. All creatures within 30ft of the original target, including itself, must make a Dexterity saving throw, taking 3d8 force damage and being dazed on a fail, half as much damage on a success. If the first target is hit by the attack and fails their save, it becomes stunned. If this jutsu is cast as a Chain 2, increase the damage die by +2 on its initial hit, if this jutsu is cast as a Chain 3, increase the damage die by an additional +4 to its initial hit and the secondary damage", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e734b17fee6f2099c7376cd1", name: "INFERNAL SLASH [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "W (Any Melee Slashing) M", duration: "Instant", description: "You swing your blade from such a low angle it’s almost as if it rose from the hells themselves. Make a melee Taijutsu attack against a target creature in range, dealing your [weapons damage] +9d6 slashing damage and inflicting 1 rank of lacerated against the target. If the target has any stacks of Laceration, they trigger immediately, dealing its damage.", at_higher_ranks: "For each rank you cast this above A- Rank, increase the cost by 3, and the attacks damage by 2d6 and the ranks of Lacerated by 1.", created_at: NOW, updated_at: NOW },
  { _id: "4edec6a92338f6aaab2c7b9b", name: "KILLER BEE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Full Turn Action", range: "Self", chakra_cost: "20 Chakra", components: "W (x5 Tanto), M", duration: "Concentration, up to 1 minute.", description: "You hold 5 of your weapons in the gaps between your armpits, the hinge joints of your arms and legs, and various other places; before placing a final Tanto in your mouth, leaving your hands completely free. This jutsu allows for quick and unpredictable attacks, that catch your enemies off-guard. While under the effects of this jutsu, you cannot concentrate on any other jutsu. This jutsu provides you the following benefits; • Melee weapon attacks you make cannot be reacted to. • As a reaction you can deflect an attack against you, adding +5 to your AC against the triggering attack. If this would cause the attack to miss, you can make a melee weapon attack as a part of the same reaction, as long as the target is within range. • As a bonus action, you can make 2 melee weapon attacks. • As an action you can take the dash action and make 3 melee weapon attacks. • As a full turn action, you make use of all of your weapons and strike with them. Make five melee weapon attacks, once with each weapon. If they all hit, the creature is stunned until the end of their next turn. • All of these benefits are only applicable while using Tanto. Switching to a different weapon or even holding a weapon that is not a Tanto will automatically end this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a0fa98600b2d275cc7591502", name: "MOONBANE'S WRATH [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "W (Any Melee Bludgeoning) M", duration: "Instant", description: "You imbue your weapon with the fury of the moon itself, looking to smite all who stand before you. Make 3 Melee Taijutsu attacks and resolve the effect of how many hit, rolling damage only once. • 1: On a hit you deal your [weapons damage] +6d4 and inflict 1 rank of bruised. • 2: On 2 hits you deal your [weapons damage] +6d8 and inflict 3 ranks of bruised. • 3: On 3 hits you deal your [weapons damage] +6d12 and inflict a rank of Staggered.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e82af3a64c8e95986a502da3", name: "OVERCOMER [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Self (30 foot long, 15-foot-wide line)", chakra_cost: "16 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You dash forward, swinging your weapons side to side as you charge with the power to overcome a frontline of any army that stands before you. Make one attack roll and compare to the AC of all hostile creatures in a 60 foot long, 15-foot-wide line in front of you as you dash to the end of the line. This movement does not trigger Attacks of opportunities against anyone except for those who are within 10 feet of you when you cast this jutsu. On a hit, you deal your [weapons damage] +4d6 and all creatures hit must make a Strength Saving Throw. On a failed save they are knocked prone and thrown to be within 5 feet of you at the end of the line. If that space is occupied they move to the next available and closest space. If this jutsu is cast as a Chain 2, increase the damage die by +3, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2, and its initial movement no longer triggers Attacks of opportunity", at_higher_ranks: "For every rank you cast this jutsu above A-Rank, increase the cost by 3, the range by 30 feet and the damage by 2d6", created_at: NOW, updated_at: NOW },
  { _id: "0d1fd12c5ff0472212ea8064", name: "OVERLORD'S DECREE [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "16 Chakra", components: "W (Any Power), M", duration: "Concentration (10 minutes)", description: "You channel your chakra outward to intimidate and let everyone know who is in control of the battle. For the duration of the jutsu you reduce all damage you take by your [weapons damage]. If you reduce damage from a melee attack to 0, the target creature must make a Wisdom Saving throw or gain a rank of Fear/Demoralized until this jutsu ends or they damage you, whichever comes first.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "953301f9afd5be86813aed97", name: "PIERCING MOON SHOT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "300 Feet", chakra_cost: "19 Chakra", components: "W (Any Bow), M, CM", duration: "Instant", description: "You knock your bow and engulf your arrow or bolt in so much chakra that it becomes visible. The arrow or bolt takes a shape of your choice and description before you fire it. Make a ranged Taijutsu attack dealing your [weapons damage] + 10d6. Additionally, the must make a Strength saving throw, becoming Staggered for 1 minute, and are knocked prone. A Staggered creature makes a Constitution saving throw at the end of each of its turns to end this condition.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "1cefbee18c50a87840eeb668", name: "POINT BLANK BURST", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Full Turn Action", range: "Self (15-foot cone)", chakra_cost: "20 Chakra", components: "CM, W (Any ranged), M", duration: "Instant", description: "You supercharge your weapon with enough chakra to cause your ammunition to explode in front of you. All targets within range must make a Dexterity saving throw, taking 10d6 bludgeoning damage and becoming Staggered on a failed save, and only half damage and no further effects on a successful one.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1a8fa56cbc689da4953cf1c0", name: "PRIDE'S FALL [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "16 Chakra", components: "(W any Thrown) M", duration: "1 Minute", description: "Pride Fall requires the practitioner to tap into their inner pride, drawing Strength from their conviction and determination to emerge victorious in combat As the practitioner engages in combat, they channel their prideful energy into each strike, imbuing their attacks with potent force and intensity. Select one creature you can see within weapons range for, and the following effects apply to that target only, if you take a turn and fail to damage or target your marked creature, this jutsu immediately ends. For the Duration, Bukijutsu with the (Thrown) keyword have their DC increased by +2. Furthermore, whenever you would cast a Bukijutsu with a Thrown Weapon that makes an Attack roll, you may make one Weapon Attack as a part of the same action. 332", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6385d93f94a43a6bf55a968d", name: "PROJECTED FORCE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "30ft", chakra_cost: "20 Chakra", components: "W (Any Melee Weapon), M, CM", duration: "Instant", description: "By placing a large amount of chakra onto your weapon, you unleash it as a shockwave of force in a straight line stopping at the first enemy hit. Make a ranged Taijutsu attack, dealing your [weapons damage] + 8d12 force damage.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and Damage by 2d12.", created_at: NOW, updated_at: NOW },
  { _id: "62b433e2de79e247dcd64094", name: "REVERSAL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "Reaction, Target creature moving within 5 feet of you", range: "Self", chakra_cost: "17 Chakra", components: "W (Any Melee Weapon), M", duration: "Instant", description: "You begin to hum or sing a tune of defeat designed to make those who hear it believe they cannot achieve anything. All creatures of your choice within range begins to experience this delusion of despair. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. 210 Creatures who begin their turns within range must make a Charisma saving throw. Creatures who fail the saving throw, who have advantage or disadvantage from any source, now have the opposite. (Advantage becomes Disadvantage, and Disadvantage becomes Advantage.). Additionally, creatures who fail, who begin their turn within range who have penalties to their attack rolls, skill checks, or Saving throws now instead lose those penalties, and gain bonuses equal to the penalty lost. Alternatively, if a creature who fails begins their turn within range who have bonuses to their attack rolls, skill checks, or saving throws now instead lose those bonuses and gain penalties equal to the bonus lost. SONG OF WAR Classification: Genjutsu Rank: B-Rank Casting Time: 1 Action Range: self (45-foot radius) Duration: Concentration, up to 10 minutes Components: HS, CM Cost: 14 Chakra Keywords: Genjutsu, Auditory Description: You begin to hum or sing a tune of battle designed to make those who hear it want to engage in endless conflict. All allied creatures of your choice within range begins to experience this lust for battle. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. Select Creature(s) gain the following until the beginning of your next turn. • +5 Bonus to Ninshou, Illusions, and Martial Arts skill checks. • +3 Bonus to Initiative Count. If This would put your initiative score above another creature, move up 1 step in the turn order. • +2 Bonus to Attack & Damage rolls & Saving throws. TREE BINDING DEATH Classification: Genjutsu Rank: B-Rank Casting Time: 1 Action Range: 90 Feet Duration: Concentration, up to 1 minute Components: HS, CM Cost: 12 Chakra Keywords: Genjutsu, Inhale, Tactile, Visual Description: You create the illusion of the target being completely bound by a growing tree as you vanish from sight. You will remain invisible to all the target creature's senses as it is affected by the Genjutsu. The illusion will remain until the target takes damage or resists the Genjutsu. Select up to 3 Target creatures you can see within range, each target must make a Wisdom save. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature becomes Slowed until the end of the next turn. Failure: Affected creatures becomes incapacitated, blind, deafened and grappled for the duration. Affected creatures remakes their saving throws at the end of each of their turns to end this Jutsu's effects on them. Critical Failure: Same as Failure, but affected creatures are stunned instead of incapacitated. UNLIMITED FOCUS Classification: Genjutsu Rank: B-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, up to 1 minute Components: HS, CM Cost: 12 Chakra Keywords: Genjutsu, Visual, Auditory Description: You touch a willing creature who you can see. You impart upon them a focusing genjutsu designed to enhance their perception and reactionary abilities. For the duration, affected creature gains the following; • Adds 1d6 to any Constitution (Chakra Control) check they make to maintain concentration on jutsu. • They gain an additional Bonus action. • When they would make an Intelligence or Charisma Saving throw vs a Genjutsu, they roll an additional 1d4 adding the result to their saving throw. UNMISTAKABLE FEAR Classification: Genjutsu Rank: B-Rank Casting Time: 1 Action Range: 90 Foot Cube Duration: Concentration, up to 1 minute Components: HS, CM Cost: 14 Chakra Keywords: Genjutsu, Visual, Tactile Description: You project a phantasmal Genjutsu image of all creatures' worst fears in a target area. Each creature in a 90 Foot Cube originating from you must make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature drops whatever it is holding. 211 Failure: Affected creatures drops whatever it is holding and gains 2 ranks of fear for the duration, remaking their saving throws at the end of each of their turns. When a creature with ranks of fear would take psychic damage, they take an additional 5d6 psychic damage. Critical Failure: Same as Failure, but affected creatures instead take 5d8 psychic damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. UNRELENTING PAIN Classification: Genjutsu Rank: B-Rank Casting Time: 1 Action Range: 60 Feet Duration: Instant Components: HS, CM Cost: 14 Chakra Keywords: Genjutsu, Visual, Tactile Description: You target a single creature as you create an image of them being impaled repeatedly by multiple sharp objects slowly while they are unable to stop it. The target creature must make a Wisdom saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature takes 4d6 psychic damage. Failure: Affected creatures takes 13d6 psychic damage. Critical Failure: Same as Failure and the affected creature is stunned until the end of their next turn. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. WORD OF THE LOST Classification: Genjutsu Rank: B-Rank Casting Time: 1 Action Range: 90 feet Duration: Concentration, Up to 1 minute. Components: HS, CM Cost: 14 Chakra Keywords: Genjutsu, Auditory, Unaware, Kinjutsu Description: You utter a few words of destitution directed at a single creature whom you can see who’s name you include in your statement. If the creature can hear you, they fall under the effects of this jutsu as they suffer a series of mental flashes and fractured memories for this jutsu’s duration. At the beginning of an affected creatures turn they make an Intelligence saving throw. On a failure, the creature suffers a number of fracture’s based on the severity of their failure. • Failed by 1~4: They gain 1 Fracture. • Failed by 5~9: They gain 2 Fractures. • Failed by 10~14: They gain 3 Fractures. • Failed by 15+: They gain 4 Fractures. A creature suffers a number of effects based on the number of fractures they have. • A creature with 2 or more fractures cannot cast jutsu of A-Rank or Higher. This limitation grows in severity for every 2 Fractures a creature has. (4 Fractures; B-Rank or Higher, 6 Fractures; C-Rank or Higher, 8 Fractures; D-Rank or Higher.) • A creature with 3 or more fractures cannot maintain concentration on more than one jutsu at a time. • A creature with 5 or more fractures cannot recognize their allies and views all creatures as hostile. • A creature with 7 or more fractures doubles the cost of all jutsu they cast. • A creature with 9 or more fractures lose the ability to cast jutsu with the Hand Sign (HS) component. • A creature with 10 or more fractures instead permanently retain all fractures and becomes a mental vegetable moving forward. They can attempt to make an Intelligence saving throw once every 30 Days. On a success they reduce the number of fractures they have by -3. A-RANK: BLACK SUNSHINE Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: Self (60-foot radius) Duration: Concentration, up to 1 minute. Components: HS, CM, NT (A Gem, Jewel, or crystalline object that can fit in the palm of your hand) 212 Cost: 20 Chakra Keywords: Genjutsu, Visual Description: You hold up a jewel or other crystalline object as it disappears, leaving behind a sphere of pulsing purple chakra. The orb radiates an ominous purple light that affects all creatures within a 60-foot radius centered on you, that moves with you. All creatures of your choice within range who begin their turn within this jutsu’s radius must make a Wisdom saving throw. On a failed save you become invisible to them for the duration. Additionally, Creatures you designate become invisible at the same time you do to the same creatures who fail their wisdom saving throw if they’re within 60 feet of you and if light from the orb can reach the space they occupy. An invisible creature casts a faint purple shadow. A creature attempting to find these faint shadows can as an action make a Wisdom (Perception) check vs your Genjutsu save DC. On a success they can see and track the shadows allowing them to target them, making attacks at disadvantage vs invisible creatures. A creature repeats their saving throw at the end of each of their turns becoming immune to their jutsu until the end of their next turn. At Higher Ranks: For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the radius of this jutsu by 15. BRINGER OF DARKNESS Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 Foot radius Sphere Duration: Concentration, up to 10 minutes Components: HS, CM Cost: 18 Chakra Keywords: Genjutsu, Auditory, Tactile, Visual Description: You release a surge of chakra from yourself attempting to remove the sight, Sound, and Tactile senses of all creatures in a 30 Foot Radius centering on you. Each creature within range must make a Wisdom saving throw, becoming Blind, Deafened and being unable to even feel when they are touching or being touched on a failed save. Creatures who attempt to enter the radius or end their turns in the radius of this jutsu must make the Wisdom save as well. Creatures who are affected by this jutsu are still affected even if they leave the radius of this jutsu until they succeed their Wisdom save. At the end of each of their turns, creatures may make a Wisdom save to resist the effects of this jutsu. DANCE MACABRE Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, Up to 10 minutes Components: HS, CM Cost: 18 Chakra Keywords: Genjutsu, Visual, Auditory, Tactile, Construct Description: Threads of dark chakra leap from your fingers into the ground as 5 medium dark phantasms are conjured from the ground under your control. Each dark phantasm immediately stands up and takes a shape of your choice. Its attack and damage rolls are increased by your genjutsu ability modifier. You can use a bonus action to command the creature you make with this genjutsu, issuing the same command to all of them. You decide what action the creatures will take and where they will move during your turn. Once an order is given, the creatures continue to follow it until the task is complete. The creatures have the following statistics. DEVIL SIGHT Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: Touch Duration: 1 Minute Components: HS, CM Cost: 19 Chakra Keywords: Genjutsu, Visual Description: You touch a willing creature who you can see. You impart upon them eyes of absolute authority. Affected creature gains 60 Feet of Dark Vision that see’s through all forms of Chakra based Darkness. Medium Illusion Fiend, unaligned Armor Class 10 + Your Genjutsu Ability Modifier Hit Points 55 (10d8 + 10) Speed 30 ft. STR DEX CON INT WIS CHA 1 (-5) 18 (+4) 12 (+1) 1 (-5) 10 (+0) 1 (-5) Damage Immunities Acid, Psychic Condition Immunities Charmed, Exhaustion, frightened, stunned, petrified, poisoned Senses Darkvision 60 ft., passive Perception 10 Incorporeal Movement. The phantasm can move through other creatures and objects as if they were difficult terrain. It takes 5 damage if it ends its turn inside an object. Phantasmal Stride. The Phantasm can use your Stealth bonus. Claws. Melee Weapon Attack: +(Genjutsu Attack Bonus) to hit, reach 5 ft., one creature. Hit: 2d6 + 5 Psychic damage 213 Additionally, creatures who gain Darkvision as a result of this jutsu gain truesight against Genjutsu of A-Rank or lower. If this jutsu is cast again, while currently affecting another creature, it ends on that other creature immediately. DEVILS AMBITION Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 Feet Duration: 1 Minute Components: HS, CM, NT (Poison Kit) Cost: 18 Chakra Keywords: Genjutsu, Inhale Description: You take a venomous concoction of different steroids and performance enhancers and release it into the air, manipulating it to affect and enhance up to 2 willing creatures you can see within range. Affected creature gain the following benefits for the duration; • Strength, Dexterity, and Intelligence Check results can never be lower than their Character Level. • You gain expertise in Ninjutsu, Genjutsu and Taijutsu attack rolls. • They gain a +3 bonus to saving throws vs Genjutsu with the Auditory keyword. • If they miss an attack roll against the last creature that dealt damage to them, they may reroll the missed attack once per turn. At the conclusion of this jutsu, affected creatures 3 ranks of Envenomed for the next hour, which cannot be removed by jutsu. DEVILS ASSAULTS Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 120 Feet Duration: Instant Components: HS, CM Cost: 18 Chakra Keywords: Genjutsu, Visual, Auditory, Tactile Description: You speak words of aggression and pain against one creature that can hear you within range. Affected creature begins to see illusionary duplicates of you as they make a barrage of martial attacks against them. Make 3 Ranged Genjutsu attacks dealing psychic damage equal to 2d12 + Your genjutsu ability Modifier on a successful hit. If you successfully score at least two genjutsu attacks using this jutsu, the next genjutsu attack you make against the same creature is at advantage and you reroll 1’s and 2’s for damage, taking the second result, even if it is a 1 or a 2. If you successfully score at least three attacks, the target must succeed a Charisma Saving Throw or gain a rank of Concussed. At Higher Ranks: For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of genjutsu attacks by +1. DEVILS FEARS Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: Self (90 Feet) Duration: Instant Components: HS, CM Cost: 16 Chakra Keywords: Genjutsu, Auditory, Tactile Description: You speak words of fear and anguish, against all creature who are experiencing bouts of fear. All creatures within range who have at least 1 rank of fear, must make a Charisma saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature is able to resist this Jutsu's effects. Failure: Affected creatures takes 3d10 Psychic damage for each rank of fear they have. Critical Failure: Same as Failure but instead affected creatures takes 4d10 Psychic damage per rank of Fear they have. Additionally, creatures whose Charisma scores are 8 or lower, automatically critically fail this jutsu saving throw. At Higher Ranks: For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the damage by 1d10. DIE Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM Cost: 18 Chakra Keywords: Genjutsu, Auditory, Tactile Description: You utter a word of absolute authority commanding a creature to attack itself with its most potent attack. Target creatures whom can see and hear you within range, must make a Charisma saving throw. 214 Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature is able to resist this Jutsu's effects. Failure: On the affected creatures next turn, they must cast a jutsu or make an attack of the casters choice, targeting themselves. If commanded to perform an attack they do not know or are able to perform, they perform the last offensive damaging attack they used in combat, but on themselves. If they have not performed any damaging actions this combat, they instead take 8d10 psychic damage. Critical Failure: Same as Failure but affected creature automatically scores a critical hit against themselves on the first attack made. DOMINATE MAN Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 Feet Duration: Concentration, up to 10 minutes Components: HS, CM Cost: 20 Chakra Keywords: Genjutsu, Auditory Description: You attempt to beguile a humanoid that you can see within range. It must make a Wisdom saving throw or be charmed by you for the duration. If you or creatures that are friendly to you are fighting it, it has advantage on the saving throw. While the target is charmed, you have a telepathic link with it as long as the two of you are within 1 mile of each other. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey. You can specify a simple and general course of action, such as \"Attack that creature\", \"Run over there\", or \"Fetch that object\". If the creature completes the order and doesn’t receive further direction from you, it defends and preserves itself to the best of its ability. You can use your action to take total and precise control of the target. Until the end of your next turn, the creature takes only the actions you choose, and doesn’t do anything that you don’t allow it to do. During this time, you can also cause the creature to use a reaction, but this requires you to use your own reaction as well. Each time the target takes damage, it makes a new Wisdom saving throw against the spell. If the saving throw succeeds, the genjutsu ends. GEAS Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 Feet Duration: 30 Days Components: HS, CM Cost: 17 Chakra Keywords: Genjutsu, Auditory, Tactile, Kinjutsu Description: You place a genjutsu based command on a creature that you can see within range, forcing it to carry out some service or refrain from some action or course of activity as you decide. If the creature can understand you, it must make a Wisdom saving throw or become charmed by you for the duration. While the creature is charmed by you, it takes 9d10 psychic damage each time it acts in a manner directly counter to your instructions, but no more than once each day. A creature that can’t understand you is unaffected by the genjutsu. You can issue any command you choose, short of an activity that would result in certain death. Should you issue a suicidal command, the genjutsu ends. You can end the spell early by using an action to dismiss it. GLIBNESS Classification: Genjutsu Rank: A-Rank Casting Time: 1 action Range: Self Duration: 10 Minutes Components: HS, CM Cost: 20 Chakra Keywords: Genjutsu, Fuinjutsu, Unaware Description: For the duration of this jutsu, when you make a Charisma check, you can replace the number you roll with a 10. Additionally, no matter what you say, jutsu that would determine if you are telling the truth indicates that you are being truthful. KEEN FOCUS Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: Touch Duration: Concentration, Up to 1 Minute Components: HS, CM, CS Cost: 20 Chakra Keywords: Genjutsu, Fuinjutsu Description: You touch a creature within reach who you can see. For the duration you maximize their focus and enhance their mental efficiency. For the duration target creature increase their critical threat range by +1. Also, when affected creatures score a critical hit on a creature, they increase their damage die by 1 step. (D4>D6>D8>D10>D12) Additionally, the first time an affected creature would fall to 0 hit points, they instead fall to 1 hit point. This jutsu then immediately ends. At Higher Ranks: For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the critical threat range by +1. If this jutsu is Cast at S-Rank, If the next jutsu the affected creature cast that scores a critical hit, they instead add 2 additional damage die to the roll. LACKLUSTER THOUGHTS Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 90 Feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 17 Chakra Keywords: Genjutsu, Auditory, Fuinjutsu Description: You speak unfocused words and statements of indecision into a chakra seal before you then attempt to implant them into the mind of a creature you can see within range. Select creature within range must make an Intelligence Save at the beginning of each of their turns. On a failed save, they instead spend their turn doing completely unproductive activities such as drawing in the sand fixing the straps on their armor, counting their 215 kunai and shuriken or verbally planning out scenario’s in elaborate 10 step plans. If a creature succeeds their Intelligence Save by 10 or more, this jut u immediately ends on them and they become immune to this genjutsu for 1 hour. At Higher Ranks: For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of creatures this jutsu can target by +1. MENTAL CLONE Classification: Genjutsu Rank: A-Rank Casting Time: 1 Year Range: Touch Duration: Instant Components: HS, CM, CS (Over 100), Replacement Body Cost: 20 Chakra a Week for 52 weeks consistently. Keywords: Genjutsu, Fuinjutsu, Kinjutsu Description: This jutsu requires a living replacement body void of consciousness and 100 Chakra seals systematically placed around the replacement body. This jutsu creates an inert duplicate of a living creature's consciousness with all of its current memories and experiences as a safeguard against death. This mental clone is cultured over the course of 1 year, as the user would offer a portion of its chakra weekly to grow the psyche of the clone. You can only have one mental clone at a time. You can choose to have the clone be a younger version of the subject. This culturing must be maintained consistently for at least a year. If the subject does not offer its chakra for more than 1 week, the culturing is prematurely stopped as the mental clone awakes with an insufficient amount of chakra as its own person and not linked to the original subject as intended. If this jutsu is completed successfully, at any time after the clone matures, if the original creature dies, its consciousness is transferred to the clone provided the consciousness isn’t damaged and is able to transfer. The clone only retains the mental stats (Intelligence, Wisdom & Charisma) of the original subject and all of its knowledge at the point of this Jutsu’s original start. MIND BREAK Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 Feet Duration: Instant Components: HS, CM Cost: 17 Chakra Keywords: Genjutsu, Visual, Auditory, Tactile Description: You Target a creature and attempt to shatter their psyche by subjecting them to a yearlong mental torture session on them in the span of 6 seconds. Target creature must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature takes 5d12 psychic damage. Failure: Affected creature takes 10d12 psychic damage. Critical Failure: Affected creature takes 13d12 psychic damage. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d12. MIRAGE Classification: Genjutsu Rank: A-Rank Casting Time: 10 minutes Range: 1 Mile Duration: 10 Days Components: HS, CM, CS Cost: 16 Chakra Keywords: Genjutsu, Auditory, Tactile, Inhale, Visual Description: You make terrain in an area up to 1 square mile look, sound, smell and even feel like some other sort of terrain. The terrain's general shape remains the same, however, open fields or a road could be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. You can also alter the appearance of structures or add them where none are present. This does not affect creatures in the area. Creatures with true sight can see through the illusion to the terrain’s true form however, all other elements of the illusion remain, so while the creature is aware of the illusion’s presence, the creature can still physically interact with the illusion. POISON FOREST Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 60 Foot Cube Duration: Concentration, up to 1 minute Components: HS, CM, NT (Poison Dust) Cost: 19 Chakra Keywords: Genjutsu, Inhale, Visual, Tactile Description: As part of the activation of this jutsu, you spread the poison dust you need for this jutsu in a 30 Foot Sphere in front of you. Creatures in the target area must make a Intelligence saving throw, being under the effects of this Genjutsu on a failed save. Creatures affected by this Genjutsu are trapped inside a Forest of Poison trees unable to leave the 30ft sphere turning around and running away from the edges of the radius. For the duration, creatures who end their turn under this Genjutsu take 5d8 poison damage. At the end of each target's turn, they make a Constitution save to end the Jutsu’s effect on them. At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 2d8. PSYCHIC CRUSH Classification: Genjutsu Rank: A-Rank Casting Time: 1 action Range: 60 feet Duration: Instant Components: HS, CM Cost: 15 Chakra Keywords: Genjutsu, Tactile Description: You overload the mind of one creature you can see within range, filling its psyche with discordant 216 emotions. The target must make an Intelligence saving throw. Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature takes 6d6 psychic damage. Failure: Affected creature takes 12d6 psychic damage and are confused Critical Failure: Affected creature takes 14d6 Psychic damage and are Confused and Berserk. SEEMING Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 30 Feet Duration: 8 Hours Components: HS, CM Cost: 17 Chakra Keywords: Genjutsu, Visual Description: This genjutsu allows you to change the appearance of any number of creatures that you can see within range. You give each target you choose a new, illusory appearance. An unwilling target can make a Charisma saving throw, and if it succeeds, it is unaffected by this genjutsu. The genjutsu disguises physical appearances as well as clothing, armor, weapons, and equipment. You can make each creature seem 1 foot shorter or taller and appear thin, fat, or in-between. You can’t change a target’s body type, so you must choose a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you. The genjutsu lasts for the duration, unless you use your action to dismiss it sooner. The changes wrought by this genjutsu fail to hold up to physical inspections. For example, if you use this genjutsu to add a hat to a creature’s outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel the creature’s head and hair. If you use this genjutsu to appear thinner then you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair. A creature can use its action to inspect a target and make an Intelligence (Investigation) or Wisdom (Illusion) check against your genjutsu save DC. If it succeeds, it becomes aware that the target is disguised. UNLIMITED PAIN Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 90 Feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 18 Chakra Keywords: Genjutsu, Tactile, Fuinjutsu Description: You target a creature and maximize their nervous systems sensitivity to pain. One creature you can see within range must make an Intelligence saving throw. On a failed save, for the duration, Once per turn, when the affected creature takes psychic damage, they take an additional 3d8 damage. Additionally, whenever a creature deals damage to the affected creature they reroll 1’s and 2’s, taking the second result. If this jutsu is cast on a creature who is currently under the effects of the Doubled Pain is targeted with this jutsu, they make their saving throw at disadvantage and if they fail the saving throw, you lose concentration on the doubled pain genjutsu and this jutsu instead deals an additional 4d8 psychic damage, and you reduce the concentration cost of this jutsu by half for the duration. If a creature is targeted by the Unrelenting Pain genjutsu while under the effects of this genjutsu, they make their saving throw at disadvantage. At Higher Ranks: For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of creatures this jutsu can target by +1. UNLIMITED PLEASURE Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 90 Feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: 18 Chakra Keywords: Genjutsu, Medical, Tactile Description: You target willing creature(s) and maximize their nervous systems sensitivity to pleasure and recouperation. Three creature(s) you can see within range who would gain temporary hit points as a result of a Genjutsu, also regains a number of hit points equal to the number of temporary hit points gained. If the Genjutsu cast that gains temporary hit points has the Medical keyword, increase the die rolled by 1 step and reroll all 1’s and 2’s, taking the second result. (D4>D6>D8>D10>D12) At Higher Ranks: For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of creatures this jutsu can target by +2. WILL BREAKER Classification: Genjutsu Rank: A-Rank Casting Time: 1 Action Range: 120 Feet Duration: Concentration, Up to 1 minute Components: HS, CM, CS Cost: Special (20 Chakra) Keywords: Genjutsu, Fuinjutsu, Auditory, Tactile Description: You target creature(s) and attempt to break their will by planting seeds of doubt and despair deep into their mind. Select one creature you can see within range. The target must make either an Intelligence, Wisdom or 217 Charisma save at the beginning of each of their turns (Your choice, this cannot be changed once selected). Critical Success: Affected creature is able to resist this jutsu’s effects and becomes immune to this jutsu until the end of their next turn. Success: Affected creature is able to resist this jutsu’s effects. Failure: Affected creature reduces the chosen Ability score by 1d4 for the duration. A creature who’s ability score is reduced to 0 by this jutsu takes psychic damage equal to 14d8 + Your genjutsu ability modifier, this jutsu then immediately ends. A creature within 5 feet of the affected creature use its action to make a Wisdom (Illusions) check vs your Genjutsu Save DC. On a success, they tear the break this genjutsu’s hold on the affected creature immediately ending this jutsu. Critical Failure: Same as Failure, but instead they reduce the chosen ability score by 1d6. At Higher Ranks: For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3 and the number of creatures this jutsu can target by +2. S-RANK: ANTIPATHY/SYMPATHY Classification: Genjutsu Rank: S-Rank Casting Time: 1 Hour Range: 60 Feet Duration: 10 Days Components: HS, CM, CS Cost: 28 Chakra Keywords: Genjutsu, Visual Description: This genjutsu attracts or repels creatures of your choice. You target something within range, either a huge or smaller object or creature or an area that is no larger than a 200-foot cube. Then specify a kind of intelligent creature, such as Sage’s beasts, Demons, or even Humans. You inject the target with an aura that either attracts or repels the specified creatures for the duration. Choose antipathy or sympathy as the aura’s effect. Antipathy. The genjutsu causes creatures of the kind you designated to feel an intense urge to leave the area and avoid the target. When such a creature can see the target or comes within 60 feet of it, the creature must make a Wisdom saving throw or become frightened. The creature remains frightened while it can see the target or is within 60 feet of it. While frightened by the target, the creature must use its movement to move to the nearest safe spot from which it can’t see the target. If the creature moves more than 60 feet from the target and can’t see it, the creature is no longer frightened, but the creature becomes frightened again if it regains sight of the target or moves within 60 feet of it. Sympathy. The enchantment causes the specified creatures to feel an intense urge to approach the target while within 60 feet of it or able to see it. When such a creature can see the target or comes within 60 feet of it, the creature must make a Wisdom saving throw or use its movement on each of its turns to enter the area or move within reach of the target. When the creature has done so, it can’t willingly move away from the target. If the target damages or otherwise harms an affected creature, the affected creature can make a Wisdom saving throw to end the effect, as described below. Ending the Effect. If an affected creature ends its turn while not within 60 feet of the target or able to see it, the creature makes a Wisdom saving throw. On a successful save, the creature is no longer affected by the target and recognizes the feeling of repugnance or attraction as magical. In addition, a creature affected by the genjutsu is allowed another Wisdom saving throw every 24 hours while the genjutsu persists. A creature that successfully saves against this effect is immune to it for 1 minute, after which time it can be affected again. EAGLE’S EYE Classification: Genjutsu Rank: S-Rank Casting Time: 1 Action Range: Self (60-foot radius) Duration: 10 Minutes Components: HS, CM Cost: 30 Chakra Keywords: Genjutsu, Visual Description: You impart the visual prowess of the eagle- eyed kings of the sky. Yourself and all creatures of your choice within range gains the following benefits; • 120 Feet of Chakra Sight. • 90 Feet of Dark Vision. • 60 feet of blind sight. • 30 Feet of True Sight. • The range of ranged attacks are doubled. FEEBLEMIND Classification: Genjutsu Rank: S-Rank Casting Time: 1 Action Range: 150 Feet Duration: Instant Components: HS, CM Cost: 25 Chakra Keywords: Genjutsu, Tactile, Kinjutsu Description: You blast the mind of a creature that you can see within range, attempting to shatter its intellect and personality. The target takes 8d6 psychic damage and must make an Intelligence saving throw. On a failed save, the creature’s Intelligence and Charisma scores become 1. The creature can’t cast jutsu, activate chakra items, understand language, or communicate in any intelligible way. The creature can, however, identify its friends, follow them, and even protect them. At the end of every 30 days, the creature can repeat its saving throw against this genjutsu. If it succeeds on its saving throw, the genjutsu ends. The spell can also be ended by an A-Rank Genjutsu break, Restorative, or Mind-Body Recovery. 218 LIONS PRESENCE Classification: Genjutsu Rank: S-Rank Casting Time: 1 Action Range: Self (60-foot radius) Duration: 10 Minutes Components: HS, CM Cost: 30 Chakra Keywords: Genjutsu, Auditory Description: You exude the courage of the infallible kings of the jungle. All hostile creatures within range must make a charisma saving throw. On a failed save, for the duration they gain the following while within range of you; • Affected creatures cannot score critical hits. • Affected creatures have a -5 penalty to attack rolls, skill checks and ability checks. • Affected creatures cannot maintain concentration on more than 1 Jutsu. • Affected creature loses resistance and immunity to the Fear condition. • Affected creature becomes vulnerable to psychic damage. MAZE Classification: Genjutsu Rank: S-Rank Casting Time: 1 Action Range: 60 feet Duration: Concentration, 10 Minutes Components: HS, CM Cost: 28 Chakra Keywords: Genjutsu, Visual Description: You select up to 4 creatures you can see within range. Each creature must make a Wisdom saving throw. On a failed save you banish the minds of the creature into a labyrinth of your design. The target mentally remains there for the duration or until it escapes the maze. A mentally trapped creature falls prone and is physically stunned, but mentally active. On each of its turns it can do one of the following vs your Genjutsu save DC in an attempt to escape. They can only make one of the following skills checks if they are proficient. If they are not proficient in any of the following, they instead make a flat Intelligence Check vs your Genjutsu save DC to escape. A creature does not add expertise or any feature that doubles their proficiency bonus for these checks; • Intelligence (Investigation) check. On a successful check, it finds the exit immediately ending this Jutsu's effects upon them. • Wisdom (Insight) check. On a successful check, at the beginning of its next turn, it remakes its wisdom saving throw at advantage, ending this Jutsu's effects upon them on a suc ess. MENTAL PRISON Classificati", created_at: NOW, updated_at: NOW },
  { _id: "df74699e778b1bbf689923b9", name: "SAKURA TWISTER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "20 Chakra", components: "CM, W (Any Melee), M", duration: "Instant", description: "You grip your weapon, crouch down and do a slight dash forward, twisting your entire body to execute a devastating slash. Make a melee Taijutsu attack, dealing your [weapons damage] + 5d8, you do not add your ability modifier to the damage. If this attack hits you can make a second melee Taijutsu attack against the same creature as a bonus action, dealing your [weapons damage] + 4d8, you do not add your ability modifier to the damage. If this attack hits you can make a third melee Taijutsu attack against the same creature as a reaction, dealing your [weapons damage] + 3d8, you do not add your ability modifier to the damage, and the target is knocked prone and Staggered.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e1648fabf605ddaabe9081be", name: "SHADOW ECLIPSE [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "W (Any Ranged Bludgeoning) M", duration: "Special", description: "You fire your weapon with such a high arc that it eclipses the sun and moon themselves, using the shadows generated to mask its approach as you let it hover there. You can cast this jutsu and delay it, in doing so you lose access to the weapon until it resolves. Make a Melee Taijutsu against a target creature in range at the start of the jutsu casting, dealing your [weapons damage] + 4d12. For every other turn after the first, this jutsu’s damage grows by 2d12, but can never roll more jutsu damage die than your character level.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "099a2501ea227ecafff41678", name: "SHADOW RUSH", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Bonus Action", range: "90 Feet", chakra_cost: "18 Chakra", components: "W (Melee Piercing or Slashing), M, CM", duration: "Instant", description: "You cloak yourself in an inky dark aura meant to accelerate your movement. You make a Dash towards your target creature in range, attempting to stab them first as you impact them then using their body as a Launch pad, jumping into the air directly after. First, move up to 90 feet in any direction towards a creature you can see within range, ending your movement within 5 feet of them. Second, make a melee Taijutsu attack against the target creature, on a hit the target takes your [weapons damage] + 3d4. Target creature must make a Constitution save to resist allowing you to leap off of their body. On a failed save, you leap half your movement speed into the air. You are able to, as a part of this action, cast a bukijutsu with the Chain X keyword.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e09100e4c8d524e4db78fb9a", name: "SHINOBI CROSS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "W (Any Melee Weapon), M", duration: "Concentration, up to 1 Minute", description: "You take a Powerful stance with no openings for attack. After activating this jutsu, attacks against you allows you to use a bukijutsu with the casting time of 1 action, as a reaction. 333", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "be97addb07d5c4c6b2cdf1c7", name: "SNIPER’S FOCUS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "CM, W (Any Range), M", duration: "Instant", description: "You take a relaxed stance drawing your weapon back and preparing for a full force attack. You spend your turn preparing this attack until the beginning of your next turn. You cannot take a bonus action or reaction after using this jutsu. At the start of your next turn, you fire with full force. All creatures in a line 5 feet wide and 100 feet long originating from you must make a Dexterity saving throw at disadvantage, taking your [Weapon’s damage] + 6d12 damage of your weapon’s type.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3, and the Save DC of this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "90ebe381fa6d049297e62bd5", name: "STANCHION SKY PILLAR [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons range (30-foot radius sphere.)", chakra_cost: "16 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You slam your weapon down like a pillar from the palace of the gods, caring not with what is below the point of impact. Make a Melee Taijutsu attack against a creature in range, dealing twice your [weapons damage] +4d12 and they become Bruised on a hit. If the target creature was prone, your critical threat range increases by +1 for this attack. If they are already Staggered you instead deal thrice your [weapons damage]. Afterwards on a hit, you can force out the energy generated from the attack, forcing all hostile creatures within 30 feet of the target creature to make a Strength Saving throw, taking half of the damage rolled and being knocked back to the edge of the sphere, gaining 2 ranks of Bruised. If this jutsu is cast as a Chain 2, increase the damage die by +4, to its initial hit, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2 to its initial hit, and creatures make their Strength save versus the total damage.", at_higher_ranks: "For every rank you cast this jutsu above A-Rank, increase the cost by 3, the range by 30 feet and the damage by 2d6", created_at: NOW, updated_at: NOW },
  { _id: "ec9bc62222ae7bba69f4f423", name: "STARSTREAM [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self, 15 Feet radius", chakra_cost: "16 Chakra", components: "W (Any Thrown Weapon), M", duration: "Concentration, 1 Minute", description: "A delicate and precise technique, the caster must carefully plan the arrangement of the shuriken, and carefully string them up with battle wire before swinging them precisely into a star-shaped pattern around them, warding off attacks and providing a deadly flourish of steel. As an action, and when this jutsu is cast, the caster may maneuver the storm of steel to strike a creature no more than 5 feet outside of the radius. Make a Range Taijutsu attack against a target creature, dealing [weapons damage] + 4d6 on a hit. While this jutsu is up any creature beginning or ending their turn within its radius must make a Dexterity saving throw, taking double [weapons damage] on a pass, or half as much on a failed save. Finally, during the duration of this Jutsu, You and Any friendly creatures behind this radius, are considered to have half cover against ranged attacks", at_higher_ranks: "For each rank you cast this above A- Rank, increase the cost by 3, and the attacks damage by 2d6", created_at: NOW, updated_at: NOW },
  { _id: "395e2fdc1652d289d2baff6c", name: "SWORD AURA: BLUE [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (60-foot line) or Movement Speed", chakra_cost: "16 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You must be under the effects of a Sword Aura to cast this jutsu. You use the built-up chakra in your blade to have it explode out in a shining blue slash as your slash, striking all who stand before you. You can either cast Arrow or Break. Arrow: All creatures within a 10-foot wide and 60- foot line your weapons reach must make a Dexterity saving throw, taking your [weapons damage] +6d8 on a failed save and gaining 1 rank of bleeding. On a success they instead take half damage Break: Select a Target creature in your Full movement speed. You dash to them and slash with your weapon. Make a Melee Taijutsu attack, dealing your [weapons damage] 5d10 on a hit and causing 3 ranks of bleeding.", at_higher_ranks: "For every rank you cast this jutsu above A-Rank, increase the cost by 3. If this jutsu is cast at S-Rank, you can instead cast Cross, which lets you cast both. Select a target in range and cast Break, and all creatures in between you and the target are targeted by Arrow. 334", created_at: NOW, updated_at: NOW },
  { _id: "6fed6c1b6caa05c1310ad4b9", name: "SWORD AURA: INDIGO [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "16 Chakra", components: "W (Any Blade), M", duration: "1 Minute", description: "You must be under the effects of Sword Aura: Green to cast this jutsu. You Strengthen your Sword Aura, flooding more chakra into your sword, the striking portion shining an amazing indigo from the mixing of chakra. Sword Aura: Green ends and you replace the effects with this Justus’. Your weapon gains pierce (16). Twice per turn when you deal [weapons damage], you can force all creatures in your weapons range to make a Strength Saving Throw as the energy of your sword lashes out. Taking 4d10 force damage and gaining 2 ranks of Concussed on a failed save and a half damage on a pass.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7938bc99e396c4144931ad2b", name: "THUNDERSTORM [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 action", range: "Weapon Range", chakra_cost: "16 chakra", components: "W (Any Ammo), M", duration: "Instant", description: "You line up three quick shots, raining them down on your foe like a thunderstorm. This jutsu cannot critically hit. Make 6 ranged Taijutsu attacks with your weapon, dealing your [weapons damage die] + 2d8 damage. On each hit, the target must also make a Constitution saving throw. On a failed save, they gain one rank of weakened until the end of their next turn. If they fail at least 3, they are also restrained for the same duration. If they fail at least 6 they are instead stunned for the same duration.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage die by +1, and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "7e20b18a76ff5747bacd748e", name: "TWINSHOT [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "(W any 2 Thrown) M", duration: "Instant", description: "An advanced variation of the \"Hidden Shadow Shot\" you prepare Two Thrown weapons in your hand launching them at the same time feigning that they are aimed at the same person. Your weapons collide mid-air, sending the other one to hit a new target instead. Select two targets, and make one attack roll targeting both of them. Select one target, and that target must make a Perception check versus your attack roll, on a fail they are unable to notice the incoming switch-up attack, and cannot react to the attack roll. On hit, both enemies take double your [weapons damage die] + 4d6 damage, inflicting 2 ranks of bleed on hit. If this jutsu is cast as a Chain 2, increase the damage die by +3, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2, and inflicts 2 ranks of lacerated on hit in place of bleed.", at_higher_ranks: "For each rank you cast this above A- Rank, increase the cost by 3, the damage by 2d6 and the ranks of bleeding by 2", created_at: NOW, updated_at: NOW },
  { _id: "ffa0581de450ab909735b941", name: "UNIVERSE SLASH [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "16 Chakra", components: "W (Any Ranged Slashing) M", duration: "Instant", description: "You fire your weapon with the might of the universe itself, meaning nothing can stand in your way. Make a Ranged Taijutsu attack against a target you know is in range. You do not have to have a line of sight to the target but they cannot be hidden. This attack ignores THP and DR and all constructs and structures between you and the target are destroyed immediately. You do not roll this attack at disadvantage to the dodge action. On a hit you deal your twice your [weapons damage] and the target creature must make a Constitution Saving Throw or gain 2 ranks of lacerated. 335", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "947d2a018cfe4506a17cd020", name: "WARRIORS PACE [NEW]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 reaction when a creature would be knocked back", range: "Weapons range", chakra_cost: "16 Chakra", components: "W (Any Power), M", duration: "Instant", description: "You immediately match steps with the opponent, locking them in to a deadly waltz with you. You can move with them as they move, ending your movement within a 5-foot space that could hold you. At the end of the movement you make a Melee Taijutsu attack for every 10 feet they were knocked back, dealing your [weapons damage die] plus 2d8 on hit. If you successful attack at least 3 times, at the end of the movement the target gains 2 ranks of bruised and you can make an additional Melee Taijutsu attack that deals your [weapons damage] +2d8 If this jutsu is cast as a Chain 2, increase the damage die by +2, if this jutsu is cast as a Chain 3 This jutsu damage becomes d10s, and the target gains 3 ranks of bruised, instead of 2, if you land 3 Melee Taijutsu attacks.", at_higher_ranks: "For every rank you cast this jutsu above A-Rank, increase the cost by 3, the damage die by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e16331a6757490ceb156528d", name: "BINDING FURY: DRAGON'S ROAR [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons reach", chakra_cost: "24 Chakra", components: "M, W (Any Power)", duration: "Instant", description: "(Must be under the effects of a Binding Fury Stance to cast) You unleash all of your pent of fury into an endless flurry of attacks. Make 3 melee Taijutsu attacks against a targeted creature. On hit, deal your [weapons damage] +2d10. If all 3 of these attacks hit you can spend 1 Fury to make an additional attack dealing your [weapons damage die] against the same creature. You can continuously spend 1 Fury to make an additional attack against the creature until you miss an attack roll or you make 10 attack rolls, whichever comes first. If this jutsu is cast as a Chain 2, increase the damage die by +3, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2, and each attack made as a result of spending *Fury* deals an additional 1d6 damage on hit. 336", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ba5e9a1f879038007084e1d4", name: "BLACK BLADE [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "26 Chakra", components: "W (Any Blade), M, CM", duration: "Instant", description: "As part of the requirements for casting this jutsu, your weapon must be under the effects of a jutsu that would provide it an increase to damage in any way, such as the jutsu Lightning Release: Static Weapon, Mortal Draw, Fire Release: Flame Coat, etc. You take your already enhanced weapon and funnel more powerful chakra within it, causing it to radiate intense black chakra. You move to a space within 120 feet in any path of your choosing. For every 30 feet you move, you jump in the air and send a slash of black chakra in a 45-foot long, 15-foot-wide line. All creatures within range of one of these lines must make a Dexterity saving throw, on a failed save they take your [weapon’s damage die] + 2d8 damage of the damage type of the jutsu that buffs your damage (This jutsu ignores restrictions that prevent damage bonuses from jutsu to apply multiple times), or half much damage on a success. A creature makes a save for each line that passes through its space. A creature that fails this saving throw by 5 or more lowers their maximum hit points by half the damage dealt for the next minute. This effect can be removed early by a medical effect that removes conditions of S- Rank or higher. If this occurs, the effected creature cannot suffer the fall by 5 or more effect of this jutsu for the next minute.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bd157f90f735699dbf547df2", name: "BREATH OF SUN: FAKE RAINBOW", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, which you take when targeted by an attack", range: "Self", chakra_cost: "Special (25 Chakra)", components: "W (Any), M", duration: "1 Round", description: "You begin to collect and manifest a bright chakra until it laces the striking portion of your weapon, causing it to shine, like the rising sun. This chakra then begins to glow brightly with enough intensity to nullify any chakra based or natural darkness until the end of the current turn. This shine creates a hazy illusion of all movement you make. Until the end of your next turn, creatures cannot add their proficiency bonus to attacks made against you as they lose the motivation to follow through with the attack instinctually.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "844a42e710c60a980743e415", name: "BREATH OF SUN: HEAT HAZE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "Special (30 Chakra)", components: "W (Any), M", duration: "Instant", description: "You begin to collect and manifest a bright chakra until it laces the striking portion of your weapon, causing it to shine, like the rising sun. This chakra then begins to glow brightly with enough intensity to nullify any chakra based or natural darkness until the end of your current turn. This shine creates a hazy illusion of all movement you make. To cast this jutsu, you must be under the effect of Breath of Sun: Raging Sun or Breath of Sun: Fake Rainbow. After casting this jutsu, Raging Sun and Fake Rainbow end. Make a melee weapon attack as quickly or slowly as you like. Regardless of the result of the attack, you automatically hit. You can roll to hit and declare the attack a hit or a miss, and the target can choose to react accordingly as they normally would, but regardless of the result or any penalties they impose or bonuses they gain, you automatically hit, dealing your [weapons damage] + 12d12. This jutsu cannot gain the benefits of a critical hit, damage dice multiplication or alteration effects. This jutsu cannot benefit from bonuses to damage as a result of other jutsu, class or clan features.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9f5b160d93b86abaee009d56", name: "BREATH OF SUN: RAGING SUN", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "Special (30 Chakra)", components: "W (Any), M", duration: "Instant", description: "You begin to collect and manifest a bright chakra until it laces the striking portion of your weapon, causing it to shine, like the rising sun. This chakra then begins to glow brightly with enough intensity to nullify any chakra based or natural darkness until the end of your current turn. This shine creates a hazy illusion of all movement you make. Make two melee Taijutsu attacks with reverence behind each swing. On a successful hit, you deal your [weapons damage] + 6d8. On a miss, you instead gain a +5 bonus to your AC until the end of your next turn. This bonus does not stack with itself. 337", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "93c58718559082f2fd3c0544", name: "DANCE PERFORMANCE: FINAL STEP", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "300 Feet", chakra_cost: "Special (35 Chakra)", components: "W (Any), M", duration: "Instant", description: "You finish your battle dance by moving faster than the eye can see, affecting anything in your sight. Make two melee or ranged Taijutsu attacks. Compare the results against each creature of your choice that you can see within range, seemingly teleporting between each space, ending in an unoccupied space you can see. This movement does not provoke opportunity attacks. Each hit deals your [weapons damage] + 5d6, and each creature you hit gains 2 ranks of lacerated. Additionally, if you cast a jutsu with Dance Performance in the name as part of a chain, you can cast this jutsu as a reaction, treating it as a Chain 3.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9f8e72f90b6b40139d50d7ca", name: "DEVIL HUNTER [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "20-foot radius sphere", chakra_cost: "24 Chakra", components: "W (Any Polearm), M", duration: "Instant", description: "You spin your weapon with a cruel smile and reel back to deliver a deadly swing that would dismantle apart any devil. Make one Melee Taijutsu attack targeting Each creature in a 20-foot radius sphere. Dealing your [weapons damage] +8d6 force damage and gain 2 ranks of weakened and 2 ranks of Lacerated on a failed save. If a creature is concentrating on a jutsu and takes damage the concentration immediately ends if it is below S-Rank or the creature has a higher level then you. If it does not immediately end, then they still make their concentration check at disadvantage. If this jutsu clashes with another jutsu, you gain advantage on the clash check and the triggering creature gains disadvantage. If this jutsu is cast as a Chain 2, increase the damage die by +6, and one additional rank of Weakened and Lacerated if this jutsu is cast as a Chain 3, increase the damage die by an additional +2, and two additional ranks of lacerated, and one additional rank of weakened", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3332033432ae75f6cd11f0ca", name: "INSTANT ECLIPSE [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "26 Chakra", components: "M, NT (2 weapons Scrolls with a Thrown", duration: "Instant", description: "You grasp two of the scrolls sealed with ammunition into them and unfurl them in a double helix formation as you jump 60 feet into the air. The sealed ammunition creates a blanket of steel above your opponent, enough to block out the sun. All creatures in a 30-foot radius originating from you, other than you, must succeed a Dexterity saving throw taking 35d4 piercing damage on a failed save or half as much on a successful save. You take no falling damage and land on your feet. 338", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b1e1430adca9543d6188545e", name: "JUGGERNAUT [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "Special", range: "Self", chakra_cost: "Special", components: "M, W (Any Power)", duration: "Instant", description: "Once you get started there's no stopping your momentum. Once per turn, if you hit a creature with a melee Taijutsu attack after moving at least 30 feet, spend 10 chakra and deal an additional 4d8 damage. If you activate this jutsu again the following turn increase the chakra cost by 5 chakra and the bonus damage by an additional 2d8, up to a max of 12d8 bonus damage. This damage and chakra cost resets if you go a turn without casting it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "312f8df64ca99c3ceaa4d5f9", name: "LIVING FORCE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "25 Chakra", components: "W (Any Melee Weapon), M, CM,", duration: "Instant", description: "You draw upon negative emotions allowing it to leak out and coalesce with your chakra turning it into Strength. You make a single devastating swing with your weapon, with enough force to collapse the ground, and ignite the air ablaze around you. Make a melee Taijutsu attack, dealing your [weapons damage] + 20d6 fire damage. Creatures within 15 feet of you must make a Dexterity saving throw, taking the damage dealt on a failed save or half as much on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0e2f86c11d7a3036458b0e71", name: "MERCILESS HAVOC [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "87db194b8f9f4fe2140fb4c3", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Self (15-foot line)", chakra_cost: "24 Chakra", components: "CM, M, W (any polearm)", duration: "Instant", description: "You slam your weapon down into your opponent and quickly follow up with a flurry of strikes. Each swing creates a spectral visage of your weapon that passes through all enemies in front of you. Make 7 melee Taijutsu attacks vs the AC of all targets in this jutsu's range. On hit, targets take your [weapons damage die] +1d4. A target that is hit by all 7 attacks is knocked prone and has their movement speed reduced to 0 until the end of their next turn. These attacks cannot score a critical hit. If this jutsu is cast as a Chain 2, increase the damage by 2 steps, if this jutsu is cast as a Chain 3, increase the damage die by an additional 2 steps.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b9e50946d1a5e66df2a9b540", name: "MORTAL DRAW", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "25 Chakra", components: "W (Melee Slashing or Piercing), M, CM", duration: "Concentration, up to 1 Minute", description: "As a part of this jutsu, you impale yourself with your weapon, coating it in your blood, reduce your current hit die to 0, and you take 4d12 necrotic damage to yourself that cannot be reduced in any way. You cannot lose concentration on this jutsu as a result of damage. As a result, your weapon becomes a living embodiment of your lifeforce extending in range and enhancing its lethality. For the duration your weapon’s range is doubled, deals +4d12 necrotic damage twice per turn, ignores resistances and immunity, and deals double damage to structures and constructs. 339", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0bc39ac366eb827a7a94c4a4", name: "PHOENIX BLAST [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (240 feet long, 15 feet wide line)", chakra_cost: "24 Chakra", components: "W (Any Ranged), M", duration: "Instant", description: "You fire your weapon after extending its range with your chakra and send it forward in a wide line of pure destruction. All creatures in range must make a Dexterity Saving Throw or take your [weapons damage] + 5d4 and gain the Stunned condition until the start of your next turn. On a successful save they take half damage and no additional effects. All non-chakra enhanced constructs and structures are immediately destroyed, and all chakra enhanced constructs and structures take maximum damage. If a creature would take 0 damage from passing this Justus save, they instead take ¼ of the damage. If this jutsu is cast as a Chain 2, increase the damage die by +5, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2, and creatures suffers a - 1d4 to their save", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f2df409e3b95a95477c2c65a", name: "RAZOR'S SWIFT [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Weapons reach", chakra_cost: "24 Chakra", components: "M, Weapon (any polearm)", duration: "Instant", description: "You jab your weapon into your opponent’s torso, then twirl it above your head at rapid speeds manipulating the air pressure around you, pulling nearby enemies in. Make a melee Taijutsu attack, on hit, the target takes your [weapons damage], then all creatures within your weapons reach+10 feet must a Strength saving throw. Creatures that fail take damage equal to your [weapons damage die] +3d8 and are pulled 15 feet toward you, or half as much damage on success with no additional effects. If this jutsu is cast as a Chain 2, increase the damage die by +3, if this jutsu is cast as a Chain 3, increase the damage die by an additional +1, and your weapon reach extends to +15 feet for this casting.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "06cd335f40a50cb40b62abb8", name: "SHADOWFALL", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "Special (25 Chakra)", components: "CM", duration: "1 Round", description: "You generate a surge of chakra throughout your body preparing for a powerful burst of speed and power. You gain 3 additional actions as a part of the activation of this jutsu until the end of your turn, which you then gain 5 ranks of exhaustion. These actions must be used to perform multiple bukijutsu in a row.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2d88913a71ac6eaa4c9a7d76", name: "SKY SPLITTER", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "100 Feet", chakra_cost: "30 Chakra", components: "W (Any Melee Weapon), M, CM", duration: "Instant", description: "You make a single swing with enough force to split to sky and the earth from the weight of your attack alone. All creatures in a 100-foot long, 15 feet wide line, originating from you, must make a Dexterity saving throw taking your [weapons damage] +10d10 on a failed save or half as much on a successful save. The ground tears open and leaves a 50-foot-deep crevasse from this bukijutsu. Creatures who are more than 5 feet from the edge of either crevasse must make a Dexterity saving throw or fall the full distance to the bottom. 340", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4fb6b29237c0c8f955dabe9d", name: "SKYFORCE [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "aaeecd12fb6a8f889a26ab97", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "28 Chakra", components: "M, W (Any Power)", duration: "Instant", description: "(To cast this jutsu, the target must be airborne) You fuel your weapon with sapping chakra, then leap into the air and strike your opponent in their abdomen. Make a melee Taijutsu attack against an airborne target. On hit they take your [weapons damage] +5d8. A creature hit by this jutsu also takes double fall damage as they are sent plummeting into the ground. If you reduce a creatures to 0 hit points with this jutsu, regain health equal to the amount of damage dealt with this jutsu. If this jutsu is cast as a Chain 2, increase the damage die by +5, if this jutsu is cast as a Chain 3, increase the damage die by an additional +5", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0b49680d252e7ee60146ab5a", name: "SPIRAL CLOUD PASSAGE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (25 feet)", chakra_cost: "25 Chakra", components: "W (Melee Slashing), M", duration: "Instant", description: "You leap into the air while slashing relentlessly, Striking everyone and everything around your multiple times. Make 3 melee Taijutsu attacks. All creatures within 25-feet of you of your choice are targets. The result of the 3 attacks represent the rolls made in attempts to get over each creature's AC. On each successful hit, target creature(s) takes your [weapons damage die] + 3d10 Slashing Damage. If you roll a critical hit all creatures suffer the effects of the critical hit.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5241ef35951292252b668b9a", name: "SWORD AURA: VIOLET [NEW]", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "7408973a5be6f437e6f50f89"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius Sphere)", chakra_cost: "24 Chakra", components: "W (Any Blade), M", duration: "Instant", description: "You must be under the effects of a Sword Aura to cast this jutsu. You use the built-up chakra in your blade to have it explode out in a violent violet explosion as you slash down, raining your sword aura over a wide area, striking all who stand before you. All creatures of your choice within the area of this jutsu must make a Dexterity Saving Throw or take your [weapons damage] +3d6 and gain 3 ranks of Lacerated as you rain down violet swords made of your sword aura. On a success they take half damage and instead gain 2 ranks of bleeding. If this jutsu is cast as a Chain 2, increase the damage die by +4, if this jutsu is cast as a Chain 3, increase the damage die by an additional +2, and an additional rank of lacerated", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b15a8f4a4d970007c2dcdddd", name: "THE ZONE", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Full turn action", range: "Self", chakra_cost: "30 Chakra", components: "CM, W (Any), M", duration: "Concentration, up to 1 minute", description: "Your mind and body enter a state of clarity that can only be achieved through dedicated training and skill. As a part of the activation of this jutsu you cannot maintain concentration on any other jutsu for the duration. You gain the following benefits; • Your Weapon and Taijutsu attack can't be reacted to, and treat damage immunity as Resistance and ignore resistance. • Your movement speed is doubled and your AC is increased by 2. • You have advantage on Weapon and Taijutsu attack rolls and increase your Bukijutsu save DC by +1 • You cannot lose concentration on this jutsu as a result of failing a concentration check. You can end this jutsu early as a bonus action, and you may reactivate it as a bonus action, spending half of the initial cost. Once this jutsu ends you cannot use this jutsu again until you finish a full rest. 341", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e4ac6649a8b711ef15932936", name: "HUMAN COCOON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special", components: "HS, CM", duration: "Special", description: "Using the Insects that are inhabiting your body, you create a cocoon large enough to hold you and hang from any surface that can hold you for a variety of scenarios both in and out of combat. Out of Combat: This cocoon is Waterproof and can be used as a Sleeping bag allowing you to hover above the ground, away from land creatures who can’t reach you. While inside your Cocoon, you look like a large insect going through metamorphosis not garnering the attention of other creatures. If used as a part of a Short Rest, you recover the maximum possible hit points or Chakra from hit dice and Chakra dice rolled. If used as part of a long rest, you recover additional hit points equal to your level + proficiency bonus. In-Combat: By spending 3 Chakra, for the next minute, you can assume a defensive position within your cocoon suspending yourself in a stealthy position. While in this stealthy position stealth checks are made with 1d8 bonus to the check. Any movement or action used to complete any task other than maintaining your stealth immediately ends stealth and this jutsu’s bonus.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "edcae2e53808e950efb7d83a", name: "INSECT SPHERE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You send a swarm of insects to entrap a target creature. The target must make a Dexterity saving throw. On a failed save they are restrained as you deal 4d4 poison damage to the restrained target at the end of each of your turns. Restrained creatures can make a Strength saving throw at the end of each of their turns. On a success, the jutsu ends on them. While restrained in this way Jutsu the creature casts has its base cost increased by +4. If the jutsu requires hand seals (HS) as a component, its base cost increases by an additional +4.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage by 2d4 and the jutsu cost penalty by +2 for each cost increase instance.", created_at: NOW, updated_at: NOW },
  { _id: "1faa96e0f0df8d78f1554ace", name: "PARASITIC DESTRUCTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS", duration: "Instant", description: "You send your swarm of insects to strike a creature in range, ignoring cover. Make a ranged ninjutsu attack dealing 4d6 poison damage. A creature damaged increases the base cost of the next jutsu they cast by +4.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage by 2d6 and Chakra cost increase by +4.", created_at: NOW, updated_at: NOW },
  { _id: "d2c3d6df58cace7a08ce9f2c", name: "SPINDLE FORMATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS", duration: "Concentration, up to 1 Minute", description: "You create a ring of insects that spin around you violently. Creatures of your choice in a 5-foot radius sphere centered on you must succeed a dexterity saving throw, taking 3d8 poison damage on a failed save or half as much on a success as they start their turns in the target radius or attempt to enter the target radius.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the radius by 5 feet and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "768d71ef9a4ec15738b4359c", name: "INSECT CLONE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "dc2837c0a3446d09da7edaf6"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (8 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "Your variation of the shadow clone technique, where you create a single clone of yourself formed out of Insects, called an Insect Clone. This clone does not have any weapons or tools and cannot speak. Insect Clones are able to cast up to 2 D-Rank Aburame Clan Hijutsu but cannot maintain concentration on any jutsu. After the clone reaches 0 Hit points, performs 2 Aburame clan Hijutsu, its Summoner has ended its turn more than 120 feet away or is dismissed as a bonus action the jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the rank of jutsu Insect clones can cast to C-Rank.", created_at: NOW, updated_at: NOW },
  { _id: "8d36e5548a1ad01cef9063d9", name: "INSECT JAMMING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (10-feet)", chakra_cost: "7 Chakra", components: "HS", duration: "Concentration, up to 1 minute", description: "You spread hungry and festering insects around you in an attempt to secretly infest other creatures of your choice. Select any number of creatures of your choice within range. Creatures must make a constitution saving throw, but remain unaware what you have done unless they have Chakra sight or can sense chakra via Chakra Sensing. On a failed save creatures becomes lightly infested with your insects. A creature who is infested can become aware if they take the Search skill action vs your save DC. Regardless, for the duration, infested creatures who would cast a jutsu that requires any of the following components, they increase the base cost of the jutsu by  +4 for each component the jutsu cast has; • Hand Seals (HS) • Chakra molding (CM) • Chakra Seals (CS) • Mobility (M)", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b4c3757ff97425df3d4d5265", name: "INSECT JAR TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, when you or an allied creature in range would take damage.", range: "Self (10-feet)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 Round", description: "Your insects swarm around you and allied creatures creating a 10-foot barrier centered on you. The barrier erected has 4d10+12 hit points, and intercepts damage meant for you or any creature within the barriers area. This barrier lasts until the beginning of your next turn and creatures within the barriers area cannot be targeted by jutsu or effects that require line of sight. When this barrier is erected, all creatures of your choice are ejected from its area, being pushed to the closest space on the outside of the barriers area.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and hit points by 2d10+6", created_at: NOW, updated_at: NOW },
  { _id: "6127ae6e484dadf1dd1083c9", name: "INSECT AMP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "14 Chakra", components: "HS", duration: "Concentration, up to 1 minute.", description: "You fill your insects with an intense surge of Chakra enhancing their overall potential and abilities. For the duration, when you would cast an Aburame Hijutsu that deals damage, its increase is increased by +1 damage die and now adds your ninjutsu ability modifier if it did not already. Additionally, if an Aburame Hijutsu you cast would increase the base cost of a creatures jutsu, that base cost penalty is increased by an amount equal to the rank of the Hijutsu cast. (D-Rank: +4, C-Rank: +6, B-Rank: +8, A-Rank: +10, S-Rank: +12)", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5a937aa7e2390c969e2a7bd6", name: "PARASITIC INSECT CLOUD", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot cube)", chakra_cost: "12 Chakra", components: "HS", duration: "Concentration, up to 1 minute", description: "Your insects create a noxious gas that is exuded from your body. When you cast this jutsu, you select an area you can see within range and the gas is moved to this area. Creatures in the path of the gas on the way to the chosen location, and creatures who start their turn in the gas, must make a Constitution saving throw, becoming poisoned and taking 5d8 poison damage on failure, or taking half damage and suffering no effects on a success. At the beginning of a creatures turn where they start inside the gas they repeat the saving throw. As a bonus action on each turn thereafter, for this jutsu’s duration you may move this cloud 30 feet.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d8", created_at: NOW, updated_at: NOW },
  { _id: "3fe912835932d072a18291d2", name: "PARASITIC GIANT INSECT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "20 Chakra", components: "HS", duration: "Instant", description: "As part of the activation of this jutsu, you select one creature you can see within range. The target creature becomes swarmed by parasitic beetle as they land on them and begins to attempt to burrow into their skin. The target makes a constitution saving throw at the beginning of each of its turns for the next minute as they resist having the beetles burrow into them. Each time a creature fails this saving throw, they gain a rank of Envenomed, Weakened and Dazzled for the next 10 minutes. A creature who fails this saving throw 5 or more times begins to experience a violent outburst of constantly reproducing beetles as they escape through the targets skin and flesh taking 10d12 poison damage and 12d10 Chakra damage. A creature who succeeds their saving throw 5 or more times ends this jutsu immediately. Once you cast this jutsu, you cannot cast it again until you spend at least 10 minutes nurturing a new parasitic giant insect.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the", created_at: NOW, updated_at: NOW },
  { _id: "a2117c72732643f55c36f6ca", name: "BODY FAT CUSHION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you would take damage.", range: "Self", chakra_cost: "4 Chakra or 2 Calories", components: "CM", duration: "Instant", description: "You expand your body like a balloon reducing damage by cushioning impacts. You gain resistance to Bludgeoning and Slashing damage, and take an additional die of damage from Piercing damage, until the start of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "57e71d5f494577dbefa4be81", name: "EMPTY CRASH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "4 Chakra or 2 Calories", components: "M", duration: "Instant", description: "You smash the ground upheaving chunks of stone and hurling them towards a target creature within range. Make a Ranged Taijutsu attack. On a Hit you deal 4d6 Bludgeoning damage. If the Partial Expansion Clan jutsu is active when you use this jutsu, you instead deal 6d6 Bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the Chakra cost of this jutsu by 3 or the Calorie cost by 1 and damage by 2d6", created_at: NOW, updated_at: NOW },
  { _id: "1d7c81a7393c8228a02a5197", name: "HUMAN BOULDER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra or 3 Calories", components: "HS, CM, M", duration: "Instant", description: "You expand your body like a balloon retracting your arms and legs inside your fat. You use your Chakra to spin your body like a bowling ball while also preventing yourself from getting dizzy. You hurl yourself in a straight line towards a target creature and crush everyone else in your way. Move yourself up to 30 feet in a straight line, ending your movement occupying the space of the target creature. Make a melee taijutsu attack against the target creature dealing 2d12+your strength modifier bludgeoning damage on a successful hit. The target creature is moved to the closest space of your choice within 5 feet that it can occupy. Creatures in your path, whom you pass through must make a dexterity saving throw, taking 4d6 bludgeoning damage on a failed save and half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the Chakra cost of this jutsu by 3 or the Calorie cost by 1 and damage by 2d12 and 2d6. If this jutsu is cast at B-Rank or higher your hair spikes as you deal an additional 4d6 piercing damage to the target creature and creatures you pass through. If this jutsu is cast at S-Rank, increase the distance you can move up to 90 feet, being able to move in any direction and turn corners. Creatures can only be affected by this jutsu no more than twice if you would pass over them more than once using this additional movement.", created_at: NOW, updated_at: NOW },
  { _id: "6ac62296212bfbd509a11a14", name: "PARTIAL EXPANSION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra or 2 Calories", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "If you spend Calories to activate this jutsu, you do not have to spend Chakra to maintain this jutsu for the duration. You temporarily expand a portion of your body enhancing the impact potential of each unarmed attack. Your unarmed attack range is 10 feet for the duration and your unarmed damage die becomes a d8.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the Chakra cost of this jutsu by 3 or the Calorie cost by 1. When cast at B-Rank, increase the damage by 1d8 (2d8). When cast at S-Rank, increase the damage by 2d8. (3d8).", created_at: NOW, updated_at: NOW },
  { _id: "ba2cd57fd3548b457e0e2862", name: "FULL-BODY-EXPANSION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra or 4 Calories", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "If you spend Calories to activate this jutsu, you do not have to spend Chakra to maintain this jutsu for the duration. You temporarily expand your entire body growing in size. For the Duration you increase your Size by 1 Category (Medium > Large > Huge). You also increase the damage you deal using Akimichi clan jutsu that use strength by xd4 (X= your Strength Modifier). This bonus damage can be applied no more than twice per turn. You also gain advantage on all Constitution saving throws. You can cast this Jutsu a second time, increasing your size by 1 category to a maximum of Huge. This makes the Cost of maintaining this jutsu become 8 Chakra per round. If you become Huge as a result of this Jutsu, the bonus damage your Akimichi clan jutsu deals instead becomes Xd6. Also, creatures make saving throws against Akimichi Clan Jutsu you cast at disadvantage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a3a370b5c0780e9515f6472c", name: "MULTI-SIZE ARM MISSILE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "9 Chakra or 5 Calories", components: "HS, CM, M", duration: "Instant", description: "You can only cast this jutsu while gaining the benefits of either Partial Expansion or Full-Body- Expansion Akimichi clan jutsu. When you cast this jutsu you hold your arm out in front of you as you then inject a mass of Chakra and Calories into it as it rapidly expands. So quickly in fact that it strikes, crushes and pushes everyone in a 30-foot line originating from you. All creatures in range must make a Strength saving throw taking your [Unarmed Damage] + 2d8 on a failed save or half as much on a success. Creatures who failed their saving throw are bruised, knocked back 10 feet, and are knocked prone.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the Chakra cost of this jutsu by 3 or the Calorie cost by 2 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "1db3f738e60ab7db6701aec8", name: "SUPER OPEN HAND SLAP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra or 5 Calories", components: "CM, M", duration: "Instant", description: "As part of the requirements of this jutsu, you must already have either Partial Expansion or Full- Body-Expansion jutsu active. Chakra erupts from the palm of your hand to the point of it becoming visible. This Chakra increases the weight, muscle density and impact of your palms. As a part of the activation of this jutsu, make a Melee Taijutsu Attack. On a Hit, you deal your [Unarmed Damage]+ 5d8. Regardless of if you hit or not, all creatures, excluding the original target creature, within 10-fee of the original target, must make a Dexterity saving throw, taking 4d8 bludgeoning damage on a failed save or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C- Rank, Chakra cost of this jutsu by 3 or the Calorie cost by 2 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "1cea3c7cd04ee9c5e80aebf8", name: "BUTTERFLY MODE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "6 Calories", components: "HS, CM", duration: "1 minute", description: "You release Chakra from your back as it forms into the shape of butterfly wings and becomes visible to the naked eye of your design. For the duration of this jutsu, you cannot use the Full-Body-Expansion jutsu and you gain immunity to poison damage. You increase the damage you deal making melee weapon or unarmed attacks or casting Akimichi Hijutsu using strength, by an amount equal to Xd6 (X= your Proficiency bonus). If you would cast a Taijutsu that isn’t an Akimichi clan Hijutsu, you instead increase the damage by half the bonus damage die, you would if it were an Akimichi Hijutsu. This bonus damage can be applied no more than twice per round. You also gain advantage on strength and constitution and saving throws, and Strength based ability and skill checks When this jutsu ends, you lose all remaining Calories and cannot gain Calories until you complete a long rest.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9884901a6f6ff4baec66c801", name: "CALORIC RECHARGE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special", components: "CM", duration: "Instant", description: "By spending any number of Calories, you are able to regain hit points by forcibly converting them into healing energies. For every Calorie spent this way, you regain 1d6 Constitution modifier in hit points, up to a maximum of 10 Calories spent. Once you have spent a total of 10 Calories in this way casting this jutsu prior to completing a rest of any type, you must complete a rest before you can recast this jutsu in this way.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, you instead regain 1d8 + your constitution modifier in hit points per Calorie. If this jutsu is cast at S- Rank, you instead regain 1d10 + your constitution modifier in hit points per Calorie.", created_at: NOW, updated_at: NOW },
  { _id: "ee407f75cacc5ee295cc21e3", name: "BUTTERFLY BULLET BOMB", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "Special", components: "HS, CM, M", duration: "Instant", description: "As part of the requirements for this jutsu, you must have either Full-Body-Expansion or Butterfly Mode jutsu active. You forcibly convert all of your remaining Calories into Chakra and funneling it into your fist as you attempt to make a devastating single attack. Reduce your remaining Calories to 0. Make a melee taijutsu attack against a creature in range. On a hit, you deal 10d10 Bludgeoning + 1d10 additional damage for every Calorie you had remaining before this jutsu’s casting and all creatures in a 30-foot cone behind the target creature must make a Dexterity saving throw, taking half the damage dealt as bludgeoning damage, being knocked back 20 feet and becoming staggard on a failed save. After the conclusion of this jutsu, Butterfly Mode ends immediately, and you cannot regain Calories until you take a long rest.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, Chakra cost of this jutsu by 3 and the", created_at: NOW, updated_at: NOW },
  { _id: "4fd5e0b87541d4f46d971960", name: "BREAK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You create a precise, targeted explosion, inflicting 10 force damage to an unattended object that you can see within range. Even if the object remains intact, it flings small shards of shrapnel at creatures within 5 feet of it. Each creature must make a Dexterity saving throw, taking 3d6 piercing damage on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage to objects by 10 and the damage to creatures by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "12542b6daf797f38e2cdf804", name: "CLAY BIRDS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You mold clay, earth, or another inorganic earthen substance into three birds of your description. These birds then soar towards a target within range, ignoring cover. Make one ranged Ninjutsu attacks. On a hit you deal force damage equal to 3d10 + your Ninjutsu ability modifier. On a hit, affected creature(s) must make a Strength saving throw, being knocked prone and blinded until the end of their next turn on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of creatures you can target by +1 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "1403dad88bf3e5bfe29d9abd", name: "CLAY SPIDERS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Bonus Action", range: "45 feet", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You mold clay, earth, or another inorganic earthen substance into a cluster of small spiders that scurry and skitter towards a creature before attaching themselves to it and detonating in a glorious explosion. Select one creature you can see within range. The spiders climb their way onto the target. At the beginning of the creatures next turn you ca decide if the spiders detonate forcing the original target and all creatures within 10 feet of them to make a Dexterity saving throw. On a failed save creatures take 3d6 force damage on a failed save or half as much on a successful one. If the affected creature would take fire damage before the spiders detonate, the spiders react like gunpowder and explode immediately, forcing the creature to make a dexterity saving throw at disadvantage, taking 5d6 force damage on a failed save. If the affected creature takes lightning damage, or casts a Jutsu with the lightning release keyword with a range of self the spiders become inert immediately ending nullifying this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "88dcf141b9e0006a0f93f8cb", name: "FURY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, M", duration: "Concentration, up to 1 Minute", description: "You begin to channel explosive chakra throughout your body, making everything you touch explode on contact, giving you an advantage in hand-to- hand combat. For the duration your [Unarmed Damage] becomes 2d6 and instead deals force damage. The first time each turn when you would deal [Unarmed Damage] to a creature with DR (damage reduction) as a result of Armor, you reduce their total DR by -2 for the next minute. This effect can stack up to 3 times. A creature whose DR is reduced by this jutsu can spend an Action restore their DR back to its original value.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, the DR penalty increases to -3. If this jutsu is cast at S-Rank, the damage die becomes 3d6.", created_at: NOW, updated_at: NOW },
  { _id: "fe69889cf37fdd3c1a8ed814", name: "PUNCH!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "You channel explosive chakra into one of your fists, before swinging out in a furious haymaker. Make a taijutsu attack against a creature or object within range. On a hit, you deal your unarmed damage + 6d4 force damage. Additionally, the target must make a Strength saving throw, being pushed back 15 feet, falling prone and being Dazed on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d4. If this jutsu is Cast at B-Rank or higher, the number of attacks you can make is increased to two.", created_at: NOW, updated_at: NOW },
  { _id: "4a036dfea16dc56ce4c0dabc", name: "SOOT PILE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "Self (15-Foot cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minute", description: "You emit a large explosion of toxic ash and soot from your palms, creating a lingering cloud of poison filling a 15-foot cube originating from you, that settles after one minute. Creatures other than you, that enter the cloud’s radius for the first time on their turn, or are within the cloud at the beginning of their turns, must make a Constitution Saving Throw, gaining 1 rank of Envenomed on a failure.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a362d75161e6addc751aff31", name: "CLAY FLIGHT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 minutes", description: "You mold clay, earth or another inorganic earthen substance into the shape of a single bird of your description that you then inject your chakra into through a special chakra seal. You do not lose concentration of this jutsu as a result of failing a concentration check. This bird grows in size until it is large enough to carry one creature on its back and has the capability to aid you in battle. This bird is proficient in all saves and uses half of your ninjutsu ability modifier as its proficiency bonus. You can command the bird as a bonus action on your turn. Additionally, you can as a reaction command the bird to use its Detonate ability. The bird has the following statistics;", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ad3d7327a2dad358b3fff39a", name: "FLIGHT OF THE TSURUBEBI", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM, M", duration: "Concentration, up to 10 minutes", description: "You build up chakra in your palms, and the soles of your feet, and release it in bursts to fly short distances. You do not need to spend chakra to maintain concentration on this jutsu and it uses your ninjutsu attack bonus or save DC for effects that require it. For the duration you gain 3 special movements that you may take instead of your movement action on each of your turns. Each movement allows you to move up to half of your speed by flying. This movement does not provoke attacks of opportunity, and whenever you use one of these movements, all creatures within 5 feet of where you began your movement must make a dexterity saving throw, taking 3d8 force damage on a failed save. You must end each movement on a solid object or ground that can hold you. If you do not, you fall and your movement ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of movements by 1.", created_at: NOW, updated_at: NOW },
  { _id: "6735aa58083a46a101ef5fa3", name: "PRIME", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "6 Chakra", components: "HS, CM", duration: "8 Hours", description: "You seal explosive chakra into a non- chakra enhanced medium or smaller object that you touch, priming it to be detonated on your command. Anytime during the duration of this jutsu, you can use an action, bonus action, or Reaction to detonate any number of objects affected by this jutsu, if you have line of sight each of them. Upon detonation, each creature within 15 feet of it must make a Dexterity saving throw, or take 3d8 Force damage. A creature in the area of more than one fiery burst is affected up to three times. Objects within the radius of the blast take damage as well.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "409a3902b5720e61647c78b2", name: "REPELLING BLAST", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Reaction which you take when hit by a melee or ranged attack.", range: "60 feet", chakra_cost: "6 Chakra", components: "CM, M", duration: "Instant", description: "You hold up an opened palm, and launch forth an explosion, precise enough to send projectiles flying back at their senders. Reduce the damage of the attack by 5d6 + your Ninjutsu Modifier. If this reduces the damage to 0, the attacking creature becomes the target of the attack, using your damage reduction result as damage so long as they are within range. This jutsu can transfer the attack's effects as well. Additionally, if this reduces the damage of a melee attack to 0, the attacking creature must make a Strength save. On a failed save, a weapon of Greater or lesser quality is destroyed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage reduction by 2d6 and the quality of a melee weapon that can be destroyed is increased by 1 step.", created_at: NOW, updated_at: NOW },
  { _id: "c8131df9e72339c1541ca527", name: "ABSOLUTE DEATH BOMBING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "200 feet", chakra_cost: "14 Chakra", components: "HS, CM, M", duration: "Instant", description: "You create a small, volatile ball of chakra, hurling it into the air, where it flies towards a space you can see within range towards the ground and explodes in a 40-foot radius. All creatures in the area must make a constitution saving throw, taking 6d8 force damage, or half as much on a successful save. Creatures who fail the save by 5 or more take an additional 3d8 damage and gain the deafened and weakened condition for 1 minute.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "7f8854afdcc9233b2b8340b8", name: "CLAY CHASE DOWN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 Minute", description: "You create two constructs made of clay that will autonomously hunt down creatures of your choice. The constructs have hit points equal to twice your ninjutsu save DC and an AC equal to your Ninjutsu save DC. If the constructs hit points reach 0, it explodes. Select a target for each construct to hunt down. At the end of each of your turns, the construct moves 30 feet towards its target, if the target is flying it will move to a space where it is as close as physically possible to the creature. If the construct ends its movement within 5 feet of its target, it explodes. When a construct explodes, all creatures within 10 feet of it must make a Strength saving throw. On a failed save, they take 8d6 force damage and gain 1 rank of Bruised or half as much on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "5a00bd1986d6f103260403c8", name: "LANDMINE FIST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "12 Chakra", components: "CM, M", duration: "Instant", description: "As a part of the activation of this jutsu, you must have Explosion Release: Fury! active. You gather a frightening amount of chakra into your fist, before slamming it into an opponent. Make a melee taijutsu attack. On a hit, you deal your [Unarmed Damage] + 8d6 Force damage. Each creature in a 10-foot cone behind the initial target must make a Dexterity saving throw, On a failed save, creatures take the same damage the original creature took. On a success, they take half damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, damage by 2d6 and the size of the cone by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "ae6517e28e2ed95550a3b036", name: "TOWER OF THE SUN", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "Full Turn Action", range: "Self", chakra_cost: "20 Chakra", components: "CM", duration: "Instant", description: "You release the chakra limiters in your body, and create a monstrous, tower shaped explosion using your body as its catalyst. You die, and leave behind no corpse. All creatures within 500 feet of you must make a Constitution saving throw, taking 200d4 + 100 Force damage on a failed save or half as much on a success. Unattended objects and structures within range of this jutsu are instantly destroyed.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and damage by 25d4 +25.", created_at: NOW, updated_at: NOW },
  { _id: "3e802d3f5ceb56e2353b91f6", name: "ATOMIC MISSILE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "Full Turn Action", range: "120 Feet", chakra_cost: "20 Chakra", components: "CM, M", duration: "Instant", description: "You propel yourself at a target within range. The target can be a space, a creature, object or structure as your use your explosion release launches you like a missile. While propelling yourself, your chakra rotates you furiously like a bullet as smoke begins to trail behind you, as you ram into your target causing a reckless explosion on impact. All creatures, objects and structures within 60 feet of the target, excluding you must succeed a Dexterity saving throw. On a failed save taking your unarmed damage + 10d8 force damage or half as much on a successful save. Additionally, all creatures within 15 feet of the target excluding you must succeed a Constitution Saving Throw. On a failed save, they take 6d8 Force damage and all equipment they are carrying or wearing of Greater Quality or lower is destroyed, or they take half as much damage and no other effects on a success.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "9b3f2716568af1433ae7571b", name: "CLAY DRAGON", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (22 Chakra)", components: "CM, HS", duration: "Concentration, Up to 10 minutes", description: "You weave your handsigns, summoning a huge dragon formed from clay, earth or another inorganic earthen substance of your description. You cannot lose concentration on this jutsu as a result of a failed concentration check. You command the dragon telepathically and it only listens to you. It enters the initiative directly after you and requires no action to command it. It is proficient in all saving throws, using your ninjutsu ability modifier as its proficiency bonus and uses your ninjutsu attack bonus or save DC for effects that require it. You may as a bonus action or reaction cause the dragon to use its Detonation ability. The dragon has the following Statistics; At Higher Ranks: For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and Hit", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fb8fdc21f6ee5bc88ff2a330", name: "BLOODLETTING WEAPONRY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You bite your thumb and swathe your arm to the side, forming a melee weapon in your hand using the blood of your thumb and the water molecules in the air. Select one melee weapon of your choice. You create this weapon as a +1 weapon. This weapon loses the heavy property if it possessed it and gains the Finesse property if it does not possess it. You are always proficient with weapons you create with this jutsu and can use Wisdom for weapon attack and damage rolls. The weapon's damage can be either cold or necrotic (you choose upon casting), though the weapon still counts as its original damage type for the purpose of casting Bukijutsu. Once per turn, when you attack with this weapon, you can make an additional weapon attack. If your Ketsuryūgan is active while this jutsu is active, you cannot lose concentration on this jutsu as the result of damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to B-Rank, the weapon becomes a +2 weapon and once per turn when you hit a creature with an attack using this weapon, they must succeed a Constitution saving throw or gain one rank of Bleeding (or Lacerated, if they are Lacerated). If cast to S-Rank, the weapon becomes a +3 weapon and gains an additional weapon property of your choice.", created_at: NOW, updated_at: NOW },
  { _id: "afa1560695709821035f6670", name: "BLOOD DAGGERS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You manipulate the water and iron in the atmosphere to make two iron-rich aqua daggers that swirl around you in the air. As a bonus action, you can send out one dagger at a creature within 60 feet. Make a ranged ninjutsu attack, dealing 3d6 + your Ninjutsu ability modifier in piercing damage on hit. Once all daggers have been thrown, this jutsu ends. If your Ketsuryūgan is active while this jutsu is active, increase the damage die of each dagger by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the number of daggers created by +1.", created_at: NOW, updated_at: NOW },
  { _id: "fdc072aba2092192377f5ed1", name: "ENHANCED CIRCULATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you are targeted or take damage from an attack or would make a Constitution saving throw.", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "1 Round", description: "You quickly improve the blood flow to your heart, briefly granting you heightened reaction speed and survivability. Until the start of your next turn, increase your AC by +4, including against the triggering attack, and you have advantage on Constitution saving throws.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8a6b382251909d6d0e784eab", name: "ICHOROUS ILLUSIONS!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS,CM", duration: "Concentration, up to 1 minute", description: "As part of the requirements for casting this jutsu, you must have the Ketsuryūgan clan feature active. You make eye contact with a creature and place them under a unique genjutsu which hijacks the blood flow to their brain. The creature must make a Wisdom saving throw. Affected creatures can repeat their saving throw at the end of each of their turns, and once per turn when they would take damage. A creature resistant or immune to fear has advantage on this saving throw. Critical Success: This jutsu ends and the target becomes immune to this jutsu for 1d4+1 rounds. Success: The creature experiences a mild tension headache, but is able to resist this jutsu's effects, ending this jutsu. Failure: The target begins to hallucinate, distorting the appearance of creatures around them, making them unable to distinguish friend from foe. When the target would go to target one of your allies, it must succeed a Perception check vs your Genjutsu Save DC at disadvantage. On a failure, the creature believes your ally to be one of their allies and attacks a creature that is hostile to you within range instead. If there is no such creature within range, their attack or jutsu fails. The creature is also unable to utilize or benefit from abilities that would allow them to omit creatures from being affected by an attack or jutsu for the duration. Critical Failure: Same effects as a failure, however, the creature is now swarmed with panic. A creature under this jutsu's effects can only move, take the attack action, or cast a jutsu of C-Rank or lower on their turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6c003d28409a47434b7c6068", name: "KETSURYŪGAN!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "As part of the requirements for casting this jutsu, you must have the Ketsuryūgan clan feature active. You look into the eyes of a creature and utilize your Ketsuryūgan to make your genjutsu more effective. Genjutsu that you have on your jutsu known list, at no additional chakra cost. The jutsu must have a casting time of 1 action or bonus action, must not have the range of self, and must not have the NT or M components, to be used with this jutsu. The range of the genjutsu cast becomes the range of this jutsu and can only affect the target you are making eye contact with. This jutsu can be used without breaking stealth. Your Genjutsu gains a +1 to attack, damage die, and initial Save DC. If the Genjutsu allows the creature to repeat their saving throw to end the jutsu's effect, the next time they would do so, they roll at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 4 and the rank of the Genjutsu that can be cast by 1", created_at: NOW, updated_at: NOW },
  { _id: "5f1677b511247e48003fd06d", name: "BLOOD LAKE!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b816b9a2e7670f7792937f0e", "b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "A genjutsu that causes the target to experience a drowning sensation, exhausting themselves as if their body truly underwent physical trauma. Select one target within range. This creature must succeed a Wisdom saving throw. If this jutsu is used while your Ketsuryūgan is active, all creatures within 5 feet of the target, of your choice, must also make this saving throw. Critical Success: The creature is able to resist this jutsu effects, and cannot be affected by this jutsu for 1 minute. Success: The creature is able to resist this jutsu's effects. Failure: The creature loses sight of their surroundings, and sees a small fissure open underneath their feet, revealing a red ocean. The creature falls into water and feels as though it has been trapped for several days, constantly trying to escape and not drown. The creature gains 2 ranks of Exhaustion for 1d4 rounds. Critical Failure: Same effects as a failure, but the target takes 4d8 psychic damage, and the Exhaustion lasts for 1d4+2 rounds. They also gain 3 ranks of Exhaustion.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the range by 15 feet, and the duration of the Exhaustion condition by 1 round.", created_at: NOW, updated_at: NOW },
  { _id: "4a5ab9695229190974658bd4", name: "RED DEATH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "9 Chakra", components: "HS, W (Shuriken, Kunai, or Blood Dagger)", duration: "Instant", description: "You infuse a weapon or dagger from the Blood Daggers hijutsu and enhanced it with vile blood, so potent that it appears almost black. Once this jutsu is cast, until the end of your next turn, the next weapon attack or Ninjutsu attack made with your weapon (whichever it uses), deals an additional 3d10 cold damage. The creature must also make a Constitution saving throw, gaining 1 rank of bleeding, or Lacerated if they are currently lacerated on a failed save. Once you land this attack, this jutsu ends. If this jutsu is used while your Ketsuryugan is active, this jutsu's damage also deals damage to the creature's chakra points, and on a failed save the creature becomes unable to recover hit or chakra points until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "d5e075b02bbd7a920d00a5ea", name: "SANGUINE SPHERE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You form a large 10-foot sphere of water in front of you and spit fresh blood into a sphere, turning it completely red. You then move the sphere to a point within range and cause it to explode into shards of water. Each creature of your choice within 20 feet of the sphere when it explodes must make a Dexterity saving throw. On a failed save, creatures take 6d6 cold damage and gain 2 ranks of bleeding, or half the ranks of bleeding as ranks of Lacerated if they are currently Lacerated. If an affected creature already has ranks of bleeding or is Lacerated, on a failed save, you can alternatively choose to give them the Weakened condition for the duration of their bleeding and/or lacerated condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d6, and the ranks of bleeding by +1.", created_at: NOW, updated_at: NOW },
  { _id: "cdeb0a61f265b8b49f908317", name: "BLOOD CLOT SPIKES", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when a creature would cast a Jutsu with the M component.", range: "60 feet", chakra_cost: "10 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "As a reaction to a creature using a jutsu with the M component, you manipulate their blood to coagulate and spike, restricting their blood flow. Make a Ninshou or Illusions skill check contested by their passive Martial Arts. You gain a +1 to your skill check for each rank of Bleeding the target may possess (Max +5). On a success, the creature’s movement is interrupted being reduced to 0 until the end of their next turn, causing their jutsu to fail and chakra to be wasted. The creature also takes 4d8 necrotic damage. If your Ketsuryūgan is active when you cast this jutsu and you succeed your skill contest by 5 or more, the target is restrained for the duration of this jutsu, able to make a Strength saving throw at the start of each of their turns to break free. If a target is restrained for an entire minute, they fall unconscious due to their inhibited blood flow.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c46eec1f55aa592aff2edb92", name: "NUMBNESS!", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "1 Minute", description: "As part of the requirements for casting this jutsu, you must have the Ketsuryūgan clan feature active. Make a ranged genjutsu attack against one creature in range. On a hit, you make a creature feel invincible, distracting them from the fact that their body has been compromised. Each time the creature takes damage while this jutsu is active, if they possess damage reduction, their damage reduction value is treated as half, otherwise, they take an extra 1d6 + your Genjutsu ability modifier in necrotic damage, which cannot be reduced. A creature cannot be under this jutsu's effects multiple times. This jutsu's effects can trigger a number of times equal to your proficiency bonus, after which this jutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "11be71fb85f8aa5513c53da4", name: "BLOOD DRAGON ASCENSION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra (Special)", components: "CM, CS", duration: "Concentration, up to 1 minute", description: "As a part of the requirements of this jutsu, you must have the Ketsuryūgan active and be near a sufficient source of water. You slash both of your wrists and allow the blood to pour into the water below. The wounds on your arms heal and the water bubbles and boils, until it erupts into a dragon. You command the Dragon, and it only listens to you (no action needed). The cost of this jutsu cannot be reduced in any way. It is proficient in all saving throws, using your Ninjutsu or Genjutsu ability modifier as its proficiency bonus and uses your ninjutsu or genjutsu attack bonus or save DC for effects that require it. (You must decide whether the Blood Dragon uses your Ninjutsu or Genjutsu scores on casting. This cannot be changed later, and it must use the same score for both its proficiency bonus, and attack and save dc). You may as a bonus action or reaction cause the Dragon to use its Detonation ability. The Blood Dragon rolls initiative as it has its own turns, using your Ninjutsu or Genjutsu Ability Modifier as its Initiative, and uses the following Statistics; The Blood Dragon uses your Ninjutsu attack bonus for", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5c1ee21a841c4f1ad8a1744b", name: "DIVIDE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "M, W (Any Thrown)", duration: "Instantaneous", description: "By Coating your weapon in Chakra, and creating an extremely powerful spin you sharpen the edge just enough to split the air and even sound. Make a Ranged taijutsu attack, dealing 3d10+ Taijutsu ability modifier Slashing damage on a hit.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d10", created_at: NOW, updated_at: NOW },
  { _id: "24b25fb7d3991cd84bac4be1", name: "SPLIT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot Cone)", chakra_cost: "5 Chakra", components: "M, W (Any Thrown)", duration: "Instant", description: "You release a collection of thrown weapons that cover a wide range piercing through everything and one in their path. Creature in range must make a Dexterity saving throw, taking your weapons damage+ 2d8 on a failed save or half as much with a successful one.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "d9dc1de3870b333d4a10ab5e", name: "RAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet (30-foot radius sphere)", chakra_cost: "4 Chakra", components: "M, W (Any Thrown)", duration: "Instant", description: "You launch the thrown weapons into the sky before your weapons collide bouncing off of each other as they rain downward in a cascade of dangerous steel. Every creature in the target area must succeed a Constitution Saving throw to weather the rain of steel. On a failure they take your weapons damage+1d10 and gaining 1 rank of Bleeding. On a success they take half damage and suffer no effects.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "0974e282030cdef60060956a", name: "STORM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "M, W (Any Thrown & Battle Wire)", duration: "Concentration, Up to 1 Minute", description: "You launch your weapons that are lined with your battle wires surrounding a target creature before you pull back snapping the wire, constricting them. Target creature must succeed a Strength saving throw, being Restrained for the duration, on a failed check. Target creature can remake the Strength save on their turn as an action to end this effect.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0cd1ff5104276bd71473ed0e", name: "CROSS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "M, W (Any Shuriken)", duration: "Instant", description: "You perform an enhanced version of Falling Heaven: Divide launching 2 Shuriken with either hand forming a cross as it cuts through anything to reach its objective. Make two ranged taijutsu attacks, dealing weapons damage+ 2d8 Slashing damage on each hit. If you land both hits on the same creature, they must make a Dexterity saving throw, becoming blinded on a failed save, until the end of their next turn as their face is slashed and blood gets into their eyes.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8 for each hit.", created_at: NOW, updated_at: NOW },
  { _id: "13b477d4397e4e91a4b821fb", name: "PENETRATE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "CM", duration: "1 minute", description: "You focus Chakra onto the edge of your next weapon thrown. For the duration, ranged attacks made with a Weapon with the Thrown keyword increases its damage die by 1 step. (d4>d6>d8>d10>d12) and gains a +1 bonus to its critical threat range.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and critical threat range by 1.", created_at: NOW, updated_at: NOW },
  { _id: "a54ac369621a63ededf8e9af", name: "PROTECT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, that you take when you are hit by an attack.", range: "Self", chakra_cost: "6 Chakra", components: "M, W (Any Thrown)", duration: "1 Turn", description: "You spin your weapon in front of you while coated in your Chakra creating a spinning shield. When you take damage, roll your [Weapons Damage] + 1d10, reducing the damage by the result, until the end of the current turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and reduce damage by an additional 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "afef3df9b4c7cd2f4482ee01", name: "FOCUS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "11 Chakra", components: "M, CM", duration: "Concentration, up to 1 minute", description: "You pour chakra into your retina’s increasing your focus and overall accuracy with ranged weapons. For the duration, when you make a ranged attack, you may roll an additional 2d4 adding the result to your roll. On a roll of two 4’s you treat the roll as a critical hit. You can gain the benefit of this jutsu, twice per round.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cad90a2e2890120ac6776315", name: "CALAMITY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (40-feet)", chakra_cost: "13 Chakra", components: "M, W (Any Thrown)", duration: "Instant", description: "You begin to spin launching weapons in every direction piercing and slashing enemies as they fall within range. Creatures of your choice, within 40 feet of you must succeed a Dexterity saving throw, taking your weapons damage+ 5d8 Slashing damage on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "c27cbd17108b591a218bbe14", name: "EXECUTION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "90 feet Line", chakra_cost: "20 Chakra", components: "M, W (Any Thrown)", duration: "Instant", description: "The perfected and secret art of the Fuma Clan. The most lethal of their Falling Heaven series of jutsu. The user takes their Shuriken and line it with Chakra thin enough to separate Water molecules, and coats the blades of their weapon in such an aura before launching it with enough force to momentarily cut through gravity itself making the weapon immune to the forces of gravity for a short time. Make one Ranged Taijutsu Attack and compare the result to each creature’s AC in range (10-Foot Wide, 90-feet long). On a hit", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4e51cc7fd9ddcf0c6cadfb1b", name: "JETTISON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Reaction, which you take when you are targeted by an attack", range: "Self (10-foot radius sphere)", chakra_cost: "5 Chakra", components: "CM", duration: "1 Round", description: "You release an explosion of wind protecting you with a burst of air. Until the start of your next turn, you have a +4 Bonus to AC including the triggering attack. Creatures who are within 10ft. of you when you cast this jutsu must succeed a Strength saving throw, taking 2d6 wind damage and push to the edge of this jutsu’s radius into a space that can hold them on a fail.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "34bf2202df5f3bfc2040f358", name: "SOARING WIND VEIL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (15-foot Cylinder)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You create a vortex of ferocious wind 15- foot-radius, 60-foot-high cylinder centering on you. When a creature other than you enters the jutsu's area for the first time on a turn or starts its turn there, they are pushed back by the pressure and must make a Strength saving throw taking 3d6 wind damage on a failed save or half as much on a successful one. Creatures inside the radius of this jutsu are heavily obscured from creatures who aren't and vice versa.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 and radius by 5 feet. When you cast this jutsu at B-Rank or Higher, you can see through this obstruction.", created_at: NOW, updated_at: NOW },
  { _id: "1267ca6cf96a3a53aecafab3", name: "STORM GEYSER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure a blast of wind that launches upwards from under a creature that you can see within range. The target must succeed a Dexterity saving throw taking 2d8 wind damage and being knocked up 30ft., falling prone on a failed save and half as much on a successful save and no further effects.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the number of targets this jutsu can affect by +1 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "02e1d9fe223d0ad163e3c514", name: "TEMPEST STEP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You coalesce a powerful gust of wind at your feet, allowing for a burst of quick movement. Choose an unoccupied space within 30 feet in any direction, including up. Each creature you pass within 5 feet of during this movement must make a Dexterity saving throw, being knocked prone on a failed save. This movement does not provoke an attack of opportunity.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the distance you move by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "bb3f88dba862bf63fec68aa9", name: "VACUUM COLLAPSE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You coat your hand in wind chakra before releasing it as a disrupting pulse. Make a melee ninjutsu attack, dealing 4d10 wind damage against the target creature on a hit the target. On a hit, the target must also succeed a Constitution saving throw, becoming weakened until the end of their next turn on a failed save as the air is forced out of their lungs.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the ranks of weakened gained by +1.", created_at: NOW, updated_at: NOW },
  { _id: "5615262b39f7a70aeec7dfa4", name: "VICIOUS VORTEX", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (15-foot radius sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You unleash a rotating force of wind that drags everything to its center. Each creature in a 15-foot radius sphere centered on you, other than you, must make a Strength saving throw. On a failed save, creatures and objects take 5d6 wind damage and are pulled to the center being knocked prone or half as much damage and no additional effects on a successful save. This jutsu deals double damage to structures and objects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6 and radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "86e879ff63745c4c9dc8c534", name: "WIND SERPENT’S MAW", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (45-foot Cone)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You create a maw of wind that roars pushing back all in its path. Creatures in range must succeed a Strength saving throw being knocked back 30ft. and taking 4d8 wind damage and suffering 1 rank of bleed on a failed save. On a successful save, creatures take half as much damage and no additional effects. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking the damage they would have taken as if they had fallen an equal distance.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8 and knock back by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "aebc127c9bd0af7823f04de8", name: "WHIRLWIND BOMB", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You condense a rampaging ball of wind before throwing it, causing it to explode. Make a ranged ninjutsu attack against the target. On a hit, the target takes 7d8 wind damage. Hit or miss, the target and each creature within 15 feet of it must succeed on a Constitution saving throw or take 4d4 wind damage and becoming dazed until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 1d8 and 1d4 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "e731befa0bfe305786d365f9", name: "HIGH WIND DESTRUCTION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (90-foot radius)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a powerful swirling area of wind that prevents creatures from acting against your will. You can choose a number of creatures equal to your Ninjutsu ability modifier to be unaffected by the adverse effects of this jutsu as the wind flows around them. When a creature other than you creature enters the jutsu's area for the first time on a turn or starts its turn there, they are pushed back by the wind and must make a Strength saving throw being knocked back 45ft. on a failed save or half as much on a successful one. Flying creatures are knocked back twice the distance. Creatures inside the radius of this jutsu are heavily obscured from creatures who aren't and vice versa. You always know the location of creatures inside the radius of this jutsu, ignoring any visual penalties. All creatures other than you in the area are treated as if they are in difficult terrain, even for flying creatures. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking double the damage they would have taken as if they had fallen an equal distance.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the knock back by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "eacce25b18bde96622eb3e29", name: "SEVERE WIND DESTRUCTION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Full Turn Action", range: "Self (45-foot Cylinder)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You create a spiraling pillar of wind centered on yourself that towers over even the tallest of creatures. This tornado has a 45-foot-radius and is 150- foot-high. This cylinder becomes difficult terrain for each creature other than you for the duration, even for flying creatures. Unattended objects in this cylinder that are large or smaller are pulled upwards and spins around the center at 150 mph. A creature that starts its turn in the cylinder must succeed on a Strength saving throw or be pulled upwards towards the center and be restrained while in motion. All objects and creatures inside the cylinder take 5d12 wind damage at the start of each of your turns. Creatures can make a Strength saving throw at the start of each of their turns as to not be restrained for this turn. If a creature or object other than you is in this jutsu's radius for 3 consecutive turns they are flung out, after rising to the height of this cylinder taking falling damage and being knocked prone.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and", created_at: NOW, updated_at: NOW },
  { _id: "bd1387bf0298a9fc561d6966", name: "SKILLED MIST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Self (20-foot Cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You expel a powerful cloud of mist from your mouth that begins to melt anything it touches. Creatures, objects and structures in range, must make a Dexterity saving throw, taking 4d6 acid damage on a failed save, and gaining a rank of Corroded or half as much damage and no additional effect on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d6. If this jutsu is cast at B-Rank, you instead inflict 2 ranks of corroded on a failed save.", created_at: NOW, updated_at: NOW },
  { _id: "dc18494f9f29e6c42c3a8a1a", name: "ERUPTING PROPULSION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Movement speed", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You expel a powerful jet stream of mist from your body that jets you forward allowing you to strike a creature with accelerated force. As a part of the activation of this jutsu, you may select a space, you can see within your movement speed range, that is adjacent to a hostile creature, and immediately move to that space. Make a melee taijutsu attack against the target creature dealing your [Unarmed Damage] + 2d8 on a hit. On a hit target creature must make a Constitution saving throw, being pushed 15 feet and falling prone on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "3167f3e42d53f2a57496a503", name: "ERUPTING PHYSIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "You swirl boiling chakra into your muscles. You do not need to spend chakra to maintain concentration on this jutsu. For the duration, Taijutsu you cast can deal an additional 1d8 Acid damage twice per turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, the bonus damage becomes 2d8. If this jutsu is cast at S-Rank, the bonus damage becomes 3d8.", created_at: NOW, updated_at: NOW },
  { _id: "08300374eb9e649db73c63d5", name: "STEAM BULLET", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You expel a powerful bullet of acid from your body. Make a ranged ninjutsu attack against a creature within range, dealing 4d8 acid damage on a hit and forcing the target to make a constitution saving throw. On a failed save, the target gains 1 rank of the corroded condition and is blinded until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d8. If this jutsu it cast at B-Rank increase the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "5445552fefdaaee057710634", name: "WATER EVAPORATION/ FIRE EXTINGUISH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Reaction, which you would take when a creature would cast a Ninjutsu with the Fire or Water release", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You see a creature conjuring fire or water using it for either an offense or defense as you interrupt the casting of the jutsu. You attempt to Interrupt the jutsu being cast. Make a Contested check using your Ninshou vs the targets Constitution saving throw. On a success, the target jutsu’s casting fails. Due to the clash of chakra, they spend twice their jutsu’s base cost.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "135d8e18e1297d077321eb60", name: "UNRIVALED STRENGTH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM, M", duration: "Concentration, up to 1 minute", description: "You compress your boiling chakra into your body rapidly amplifying your physical strength to a great degree. You do not need to spend chakra to maintain concentration on this jutsu and you cannot lose concentration of it when you take damage. If you use Strength as your Taijutsu ability score, your [Unarmed Damage] die becomes 3d6.", at_higher_ranks: "For each rank you cast this or higher, your [Unarmed Damage] die instead becomes 3d8.", created_at: NOW, updated_at: NOW },
  { _id: "4c5e946ee21be3bbeb0ce9f7", name: "STEAM ARMOR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Reaction, which you take when you would take damage.", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You release powerful jets of steam from every pore of your body, creating a powerful barrier of steam between you and the triggering attack. Roll 3d10 + 5, reducing damage by the result. If damage would be reduced to 0, and at least one hostile creature it within 20 feet of you, select one hostile creature to takes 5d8 Acid damage and inflict 1 rank of corroded. If this jutsu would reduce the damage of a jutsu that deals either the Fire, Wind, or Cold damage, you double the amount of damage this jutsu would reduce.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, The damage reduction by 1d10+5, and damage done by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "46f0220157ee691144e849f7", name: "CORROSIVE VIPER FANG", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You coil corrosive Boil Release chakra around your arm as it forms a snake make of steam. Make two melee taijutsu attacks dealing your [Unarmed Damage] + 2d8 Acid Damage. If the target creature has ranks of the Corroded condition, you gain a +2 bonus to your attack roll. On a hit, the next time the damaged creature would make a saving throw against a Futton clan Jutsu, they reduce the result of their saving throw by -2 until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "eee8f8020a40057481406d28", name: "ACIDIC DRAGONS BREATH", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "7e75ac7584ff55c12a68c048"], elements: [], casting_time: "1 Action", range: "Self (30-Foot line)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You fire a beam of acid in a straight line spreading a massive wave of corroding acid. Creatures in a 30-foot long, 5-feet wide line in front of you must succeed a Dexterity saving throw, taking 8d8 Acid damage, and gaining 2 ranks of Corroded on a failed save, or half as much on a successful one. Also, creatures, excluding you, within 5 feet of the beam must make a constitution saving throw taking 6d6 Acid damage and 1 rank of corroded on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d8 and 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "d0c6588521adf59c1ee59611", name: "SCORPIONS STINGER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "7e75ac7584ff55c12a68c048"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You coat your body in a highly compressed cloak of steam, that you then shape into a stinger the same shape as a Scorpions stinger. Make a melee Taijutsu attack. On a hit, you deal your unarmed + 5d12 acid damage and the target gains +1 rank of Corroded.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "541123ef887e5063a98b9fd7", name: "ACIDIC EXPLOSION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius sphere)", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You release a massive flux of acidic steam for your body, enough to fill a 20-foot radius sphere. All creatures, objects, and structures of your choice, in the radius must make a constitution saving throw taking 10d10 Acid Damage and gaining 3 ranks of Corroded on a failed save. On a successful save they take half damage. After this jutsu’s initial casting, your body continues to release acidic steam. At the beginning of each creatures turns who begins within the steams radius or who would enter the radius for the first time each turn, they must make a constitution saving throw, taking 5d10 acid damage and gaining 2 ranks of corroded on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, initial", created_at: NOW, updated_at: NOW },
  { _id: "3132ef211de99aad756a9dab", name: "BLADE CRASH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minute", description: "You manifest Data Release within your hands as you mold it into a more stable shape, creating a digital sword that you throw at an enemy in order to pin them. Make a ranged ninjutsu attack against a creature within range, dealing 2d8 force damage and imposing a grappling contest against the creature on a hit. For this contest, you may use your Ninshou skill. If you succeed this check, the creature is pinned to the ground by the sword for 1 minute, grappled. A creature grappled this way counts as restrained. A creature grappled this way at the start of each of its turns may remake the check, ending this condition on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage by 2d8 or number of targets by +1 (Pick one).", created_at: NOW, updated_at: NOW },
  { _id: "bbfbedbf7bcab869519ef3c3", name: "FIREWALL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Round", description: "As a reaction when you would take damage, you can quickly manifest a barrier of data release to protect you. Reduce the initial instance of damage you would receive by 3d8. After this occurs, your barrier splits from yourself, transforming into a shield of your design. This shield floats around you, and while you have a shield, the next time you take damage, you can block with a shield, reducing the damage taken by 4d4. After you block with a shield, it is destroyed. This jutsu ends early if all shields you possess are destroyed. For each shield you possess, you gain a +1 bonus to AC.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage reduced by 1d8. If cast to B-Rank, increase the number of shields created by +1, and the damage reduction for each shield to d6s. If cast to S-Rank, increase the number of shields created by +1, and the", created_at: NOW, updated_at: NOW },
  { _id: "4ce02148a84eb230fb52dd9a", name: "SURGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You weave signs to manifest your Data Release chakra behind you, forming into holographic wings of a color of your choice. Until the start of the next turn, you gain flying speed equal to your movement speed, can hover, and ignore difficult terrain. Also, when you first cast this jutsu, you may take the Dash or Disengage actions, as part of the same action.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to C-Rank or higher, you can choose to concentrate on this jutsu, giving it a casting time of Concentration, up to 1 minute. If cast to B-Rank or higher, you can concentrate on this jutsu for 10 minutes, and when you Dash or Disengage as part of casting this jutsu, gain +30ft of movement speed until the start of your next turn. If cast to A-Rank or higher, this jutsu no longer requires you to concentrate on it to benefit from it for 10 minutes. If cast to S-Rank or higher, your movement speed is increased by +30ft for the duration of the jutsu, and when you Dash or Disengage as part of casting this jutsu,  +30ft (60ft total) until the start of your next turn.", created_at: NOW, updated_at: NOW },
  { _id: "05c75708d6e22ec7ed0a21dc", name: "TORRENT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "You outstretch your hand and launch a series of prismatic particles and glitches that cause your arm to appear pixelated and emit 10 feet of bright light of any color. Make two ranged ninjutsu attacks against a creature within 30 feet as you launch blasts of data at them, dealing 2d8 force damage and imposing a Strength saving throw on each hit. On a failed save, the creature is knocked back 10 feet and falls prone. A creature knocked prone and/or knocked out of this jutsu's range, as a result of this jutsu, does not result in consecutive attack rolls made with this jutsu to be made at disadvantage due to the creature being prone, or prevent the creature from targeted due to limited range.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the number of attacks made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "d88c23f366c38d3961beca94", name: "COMPILE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "9 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "You generate a stream of Data release which flows down your arms which converges into either a large broadsword of opake blue chakra, or two large claws of translucent red chakra. You cannot lose concentration of this jutsu as the result of taking damage or failing a concentration check. On your turn, you can spend 3 chakra to switch your weapon to the other weapon this jutsu provides. • Data Sword: This sword deals 2d6 force damage and possesses the Deadly, Finesse, Light, and Versatile (d8) properties. This sword uses Intelligence for attack and damage rolls. This sword can cast any Bukijutsu that does not require a ranged weapon, and that deals Slashing damage. • Data Claws: These claws deal 3d4 force damage and possess the Critical, Finesses, Light, and Unarmed properties, and can use Intelligence for attack and damage rolls.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and gain a +1 to unarmed/weapon attack and damage rolls with your Data Sword/Data Claws.", created_at: NOW, updated_at: NOW },
  { _id: "c6dcac2c58de39650231ae79", name: "VPN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Bonus Action, or Reaction", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Special", description: "You quickly cover a willing creature within reach in a reservoir of Data Release chakra, generating an obscuring aura to immerse the creature. For the duration, the creature does not produce sound and is Invisible, until they make an attack, deal damage, or receive damage. At the end of each of your turns (or every 10 minutes, if not in combat), you must spend 4 chakra, plus +1 chakra for each instance of this jutsu you have active at a time. Creatures under this jutsu's effects can mentally communicate with each other across any distance.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the range you can affect creatures from by 10 feet, and the number of creatures you can affect during this jutsu's initial casting by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e4a09f9264eaf8d708830b1b", name: "ZIP BLADE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You mark a target within range and generate 3 holographic blades which fly at them like a zipline. Make a ranged ninjutsu attack. On a hit, the target takes 4d10 force damage and is Shocked until the end of your next turn. This attack roll ignores bonuses to AC from a jutsu, trait, or feature (excluding changes to AC calculation). If you exceed the target's AC by 5 or more, the swords collide in a small explosion on the target. Each creature within 5 feet of the target, other than the target, of your choice, must succeed a Dexterity saving throw or take half the damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "fb9af94d6fedd687102e0c86", name: "ANTIVIRUS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "Special (12 Chakra)", components: "HS, CM, CS", duration: "Concentration, up to 1 Minute", description: "You release a pulse of Data Release from yourself which can causes an angel or demonic construct to materialize and fight alongside you. When you cast this jutsu, choose between a Data Angel or Data Demon. Your choice affects the appearance and abilities of your construct. Angels appear as winged centurion knights, meant to aid the weak. Demons appear as monsters, meant to punish the wicked.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 4, and the number of constructs created by +1. You can choose whether these additional constructs are Angels or Demons.", created_at: NOW, updated_at: NOW },
  { _id: "fc1f65675f076b27a19fcf87", name: "DATA VISUALIZATION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Full Turn Action", range: "Touch", chakra_cost: "10 Chakra", components: "HS, CM", duration: "Special", description: "You touch a willing or incapacitated creature and begin combing through their memories searching for a specific event. The creature does not need to remember said event at the present moment to use this jutsu, they simply need to have seen or heard it. Make a Ninshou or Sleight of Hand check with your choice of Dexterity or Intelligence vs. a DC equal to how far back the memory was recorded. (Within the past day: 12, Within the past week: 16, Within the past month: 20, Within the past six months: 24, Within the past year: 28, Within the past five years: 32, six or more years: 36+) On a success, you locate the memory and retract your hand from the creature, holding a sphere of Data Release containing a copy of the memory. The length of the memory starts at 10 minutes, though you can, as many times as you'd like, increase the cost of this jutsu by 1 to add one more minute. You can then choose to broadcast the memory in a small cloud of lightning across a 15- foot space that you could reach, or place it into a monitor. Alternatively, you can crush the orb, releasing the memory into the minds of all willing creatures within 15 feet. Each creature is immersed completely in the memory, standing the same place it was recorded, perfectly recreated, and able to explore/move in their own way as if they were time travelers. When viewing a memory, you can freely pause, rewind, or fast forward through the memory, and can move up to 60 feet in the memory's space, potentially revealing new information. Once you succeed this check and end this jutsu, you cannot use this jutsu on the creature again for 1 day, and cannot cast this jutsu again for the next 8 hours as the technique is taxing on your chakra network.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c562ca1458ff835ec9ff0772", name: "DDOS ATTACK", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "90-foot Cube", chakra_cost: "22 Chakra", components: "HS, CM", duration: "Instant", description: "The ultimate jutsu of the Genwa Clan, the absolute culmination of all Data Release techniques. You stick your hands out in front of you, forming two large discs of data release, one blue, one red. The sky darkens, causing your discs to become the brightest source of light. You then crash your hands together, shattering the discs and releasing particles in a 90-foot cube in front of you. From these particles, Data Angels and Data Demons form, soaring past all creatures, slashing, clawing, and blasting at them. Each creature must succeed a Dexterity saving throw, taking 7d8 Force damage, becoming Weakened, and falling prone on failed save, or half damage and no further effects on a success. The angels and demons then rise into the air and dive down with incredible force, resulting in a massive explosion. Creatures must succeed a Strength saving throw, at disadvantage if they failed their Dexterity saving throw, or take 7d8 Force damage and become Dazed and Shocked, or take half damage and no further", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f421974dfb82bee12dc16646", name: "MEDICAL FIST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You coat your hands in medical chakra designed to sap the life force of anyone you touch. Your damage, when you would hit someone with an unarmed or melee taijutsu attack, you gain temporary hit points equal to the damage roll of your Unarmed Damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of the jutsu by 3 and increase the damage die by 1d8 up to a maximum of 3d8. If this jutsu is cast as a B-Rank, you increase the as an S-Rank, you gain twice as many temporary hit points when you gain temporary hit points this way.", created_at: NOW, updated_at: NOW },
  { _id: "cf6ffa63164ef20169b4ecd9", name: "SAPPING STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "Your hands glow a pinkish hue as you get ready to strike your target. Choose one creature in range and make a melee ninjutsu attack, on a hit you deal 3d8 Necrotic damage, and regain hit points equal to half the damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of the jutsu by 3 and increase the damage by 1d8. If you cast this jutsu at A- Rank or higher you instead regain hit point equal to the full damage dealt.", created_at: NOW, updated_at: NOW },
  { _id: "fe58948330d75725141d1984", name: "BLOOMING CHERRY BLOSSOM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "4ca66bf77ffa28385682255c", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "You rush towards a target before unleashing a volley of attacks. Make two taijutsu attacks against a creature within range. On a hit you deal your these attacks the target is knocked prone. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of the jutsu by 3 and increase the damage by 1d6. If this jutsu is cast at B- Rank of higher increase the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "ed3aad25130c87f664ef97fe", name: "LASTING HEALING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You cover your hands in chakra, which being glowing in a light pink hue. A creature you touch immediately regains 2d6 Hit Points. Additionally, at the start of each of the affected creatures turns they regain 1d4 Hit Points.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of the jutsu by 3 and increase per turn healing by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "a75ccb79a3db602acb7cd89b", name: "HEALING CLOAK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 Minute", description: "Your entire body is covered in soothing medical chakra as you begin to glow a soft pink. When you cast this jutsu you regain 2d8 hit points. Also, while in combat, for the duration of this jutsu you regain 1d8 hit points at the start of your turn. You may as a reaction heal 3d8 hit points, when you do this jutsu immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f3d5201a60ddb7da69b3bfe", name: "COLOSSAL IMPACT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "5 feet (30-foot radius)", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "You drive your fist into the stomach of a creature with enough power to lift them off their feet, you then slam them into the ground with a massive amount of force. Make a melee taijutsu attack, on a hit you deal your [Unarmed Damage] + 3d8 and each creature (excluding you) within 30 feet must make a dexterity saving throw as you slam the creature into the ground, taking 3d6 bludgeoning damage on a failed save or half as much on a success. The creature you initially attacked has disadvantage on this saving throw and is knocked prone on a failure.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of the jutsu by 3 and increase the damage by 1d8 and 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "084c002bba942186a421c64c", name: "DEFENSIVE CLOAK", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You cover your entire body in vile cloak of medical jutsu, that harms any who touch you. You do not pay concentration costs to maintain this jutsu. When a creature hits you with a melee attack, they take 2d6 Necrotic damage and you gain temporary hit points equal to half the Necrotic damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of the jutsu by 3 and increase the damage die by 1 step (d6>d8>d10>d12). If you cast this jutsu at A-Rank or higher you instead gain temporary hit points equal to the full damage dealt.", created_at: NOW, updated_at: NOW },
  { _id: "73f0004a9c20c305487d7c4c", name: "OFFENSIVE CLOAK", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (12 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You cover your entire body in a bolstering cloak of medical jutsu. When you make an unarmed attack, you deal an additional 2d8 Necrotic damage, any number of times per turn, and once per turn, an affected creature must succeed a Constitution saving throw or be unable to regenerate hit points until the end of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a47b16f7926fb889e30aa504", name: "CHERRY BLOSSOM FINALE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "4ca66bf77ffa28385682255c", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius)", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "This jutsu can only be cast as a Finisher. You slam your fist into the ground creating a giant shockwave. Each creature in range must make a Dexterity saving throw, taking your [Unarmed Damage]  + 8d8 on a failure, or half as much on a success. If a creature is prone, they have disadvantage on the saving throw. After the conclusion of this jutsu, the area is counted as difficult terrain.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of the jutsu by 3 and increase the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "d7cbf151aa390a06b86709e2", name: "FALLING BLOSSOM REPRISE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Full Turn Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "1 Minute", description: "You must be under the effects of “Hanami Style: Defensive Cloak” and “Hanami Style: Offensive Cloak” to cast this jutsu. A last-ditch technique of the Haruno Clan, You use your finite control of medical chakra, spreading it throughout yourself. Your veins begin to glow a dark magenta as the chakra spreads throughout your chakra network. You lose the effects of Defensive and Offensive cloak, with this jutsu instead taking their place. You cannot concentrate on another jutsu while this jutsu is active. While under the effects of this jutsu you gain the following benefits: • When a creature hits you with a melee attack, they take 3d12 Necrotic damage and you regain an equal amount of Hit Points. • Your [Unarmed Damage] becomes 4d8 and deals Necrotic damage, additionally when you deal damage to a creature with a melee attack, they are unable to regain hit points until the end of their next turn. • When you score a critical hit with a Medical or Taijutsu, you instead triple the damage dice. At the conclusion of this jutsu, you are no longer able to mold chakra until you complete a long rest, as your", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a6576247b0214aba463a86ec", name: "ADAPTIVE CAMOUFLAGE TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "Your coat your body in Chakra, performing a more advanced version of the Body Camouflage Technique changing the texture of your skin while also adapting to the changing environment not having to consistently focus on your surroundings. For the duration, you gain a +4 bonus to checks made with the Hide and Sneak actions. Additionally, you cannot be tracked without the aid of a Jutsu as you leave behind no tracks or traces of your movement.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "25cbd769456e02766366b1ed", name: "COBRA", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "1 Minute", description: "You can only gain the benefit from one Striking Stance at a time. If you enter another Striking Stance while currently benefiting from this one, the one immediately ends. You enter the coiling stance of a Cobra. For the duration, weapon and taijutsu attacks made using a component weapon ignores temporary hit points, instead dealing direct damage to the target creature.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ad85d8a401254b23e239877e", name: "FORMATION OF ONE THOUSAND SNAKES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (15-foot Cube)", chakra_cost: "5 Chakra", components: "M, W (Broadsword, Kunai, Katana or Odachi)", duration: "Instant", description: "You release a series of blade swings so much so that you create the visage of one thousand snakes coiling around you. Your attacks are so viscous that all creatures of your choice in a 15-foot cube originating from you must succeed a dexterity saving throw. A creature who fails the save takes double your weapons damage die plus your taijutsu ability modifier or half as much on a successful save. If the weapons has two or more base damage die (such as an Odachi’s 2d6), you instead add one additional damage die. A creature who would fail their saving throw by 5 or more gains 1 rank of bleed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the dice multiplier by 1. (Double or +1 damage die > Triple or +2 damage die > Quadruple or +3 damage die > Quintuple or  +4 damage die > Sextuple or +5 damage die).", created_at: NOW, updated_at: NOW },
  { _id: "15a58d810077f495eca437b2", name: "PYTHON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "M, W (Broadsword, Kunai, Katana or Odachi)", duration: "1 Minute", description: "You can only gain the benefit from one Striking Stance at a time. If you enter another Striking Stance while currently benefiting from this one, the one immediately ends. You enter the striking stance of a python. For the duration, creatures gaining a bonus to their AC as a result of a jutsu, feature or trait and structures summoned as a result of a jutsu, feature or trait intended to intercept damage dealt become Vulnerable to the first Taijutsu Attack you make using a component weapon on your turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e7ff76658486a70402640f1a", name: "MAMBAS HARDENED SCALES", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you take damage.", range: "Self", chakra_cost: "6 Chakra", components: "CM", duration: "1 round", description: "You skin becomes encased in Chakra taking the shape of a snake’s scales layering itself and hardening at the point of impact reducing the potency of incoming damage. You gain +6 DR (damage reduction) vs all sources of damage until the beginning of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and DR by +4.", created_at: NOW, updated_at: NOW },
  { _id: "83ede32b39eb771b184b9178", name: "POISON COBRA DANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "9 Chakra", components: "M, W (Broadsword, Kunai, Katana or Odachi)", duration: "Instant", description: "You perform a flurry of graceful strikes each with the deadly precision of a cobra’s bite. Make two melee Taijutsu attacks, dealing your [Weapons Damage] + 2d8. On a hit, the affected creature must make a Strength saving throw being knocked prone on a failure. If these attacks are made against a creature with ranks of envenomed, increase the damage dealt by +1d8.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, increase the number of attacks made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "65dc03c91288e69c04ba8269", name: "PYTHONS GAZE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You inject a surge of Chakra into your eyes increasing your visual perception, making it look like the world is slowing down around you. You do not spend Chakra to maintain concentration with this jutsu. For the duration, creatures whom you can see within range actions seemingly slow down to a crawl. Melee weapons attacks or Hebi clan Bukijutsu you cast cannot be made at disadvantage and creatures within range cannot gain advantage against any Hebi clan Bukijutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "92857264e2b6a8cde29ed21b", name: "VIPER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "7 Chakra", components: "W (Katana, Broadswords or Odachi)", duration: "Concentration, up to 1 minute", description: "You can only gain the benefit from one Striking Stance at a time. If you enter another Striking Stance while currently benefiting from this one, the one immediately ends. You do not spend Chakra to maintain this Jutsu. You enter the poisonous stance of a Viper. For the duration, weapon attacks and Hebi clan Bukijutsu cast using one of this jutsu’s components ignore slashing resistance and pierces damage reduction, instead dealing direct damage to the target creature. Additionally, the component weapons chosen can now be used as components with Bukijutsu that requires Melee Piercing.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b8c8f98c6e97098e5ee52f1d", name: "SERPENT ADAPTATION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "M, CM", duration: "Concentration, up to 1 minute", description: "You pour Chakra throughout your body, growing fangs, poison sacks, hardening your skin and allowing you to elongate your arms and legs like whips. For the duration, your melee attack, and Bukijutsu range increased by 5 feet as you stretch your arms to compensate. Your movement speed increases by 10 feet. If you have Mamba’s Hardened Scales on your known jutsu list, casting it does not consume Chakra.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "177ffb3e4be06df1e44d8662", name: "MAMBA POISONOUS BLADE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, W (Katana, Broadswords or Odachi)", duration: "Concentration, up to 1 Minute", description: "You envelop your weapon in a poison only found in the infamous Black Mamba. Twice per turn, your weapon deals an additional +2d6 poison damage. Creatures who take poison damage from this weapon must make a constitution saving throw, gaining +2 ranks of Envenomed on a failed save. A creature Envenomed by this jutsu has difficulty taking reactions. When they are first poisoned or envenomed by this jutsu, they cannot take a reaction until the beginning of their next turn. At the beginning of each of their turns, they must remake their constitution saving throw, losing the ability to take a reaction until the beginning of their following turn on a failed save. On a success, they can take reactions as normal.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c8b68e6ab98836ec42ba436a", name: "VIPERS POISONOUS WAVE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30 feet)", chakra_cost: "12 Chakra", components: "HS, CM, W (Katana, Broadswords or Odachi)", duration: "Instant", description: "You create a wave of poisonous Chakra that erupts from your weapon as you swing it. All creatures in a 10-foot wide, 30 feet long line must succeed a Dexterity saving throw, taking 6d8 Poison damage and half as much on a failed save. If the weapon you use is under the effects of Mamba’s Poisonous Blade, or the Poison Potency Hebi Clan Feature, creatures make their save with a -2 penalty. If the weapon you use is under the effects of both Mamba’s Poisonous Blade and the Poison Potency Hebi Clan Feature, you instead deal 6d12 Poison damage or half as much on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d8 or 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "bc95f45ba3be41e5177810f1", name: "SILVER COBRAS BLESSING", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "Special", components: "HS, CM", duration: "Instant", description: "You ingest a powerful potent Poison that reduces your current Chakra to 0. You gain the Poisoned condition at the conclusion of this jutsu which cannot be removed, resisted, or ignored by any means for the next hour. For the next minute you gain the following effects; • You cannot suffer the effects of the Bruised, poisoned, weakened, slowed condition for the duration. • Your Taijutsu ability score increases by any amount equal to your Proficiency bonus. • You can cast all Hebi clan jutsu that you have on your known jutsu list at no cost. • Hebi clan jutsu that have the “Striking Stance:” pre-fix can be cast using an action, bonus action or reaction. • You can concentrate on up to 3 different Hebi Clan Jutsu ignoring any effects that would prevent you from maintaining more than one Striking Stances. After one minute, you fall unconscious for the next hour, being unable to be awoken until the hour has passed. When", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b4f06676a1d6b7a782581b08", name: "COMET BEAM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "5 Chakra or 2 Star Chakra", components: "HS, CM", duration: "Instant", description: "You launch a condensed beam of solid star chakra at a target in range. Make a ranged ninjutsu attack dealing 3d10 Force damage. A creature hit by this jutsu must also make a Strength save or be pushed 10ft.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 (or 1 star chakra), also increase the damage dealt by 2d10, and pushes a target back 10 additional feet.", created_at: NOW, updated_at: NOW },
  { _id: "c906f13da7f49cec0eb25771", name: "STAR ROPE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra or 2 Star Chakra", components: "HS, CM", duration: "Instant", description: "You condense a beam of Star Chakra into a fine, tangible rope. Make a melee Ninjutsu attack roll with reach against a target in range, dealing 2d6 slashing damage. On a hit, you may choose to also grapple the target, which lasts for 1 minute or until you dismiss it (no action), or it breaks free with a successful Athletics or Acrobatics check contested against your Ninjutsu save DC as an action. When you hit a target with this jutsu, and it's no more than one size categories larger, you can also pull that creature up to 20 feet toward you.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 (or 1 star chakra), and the damage by 2d6. If cast to B-Rank or higher, the target becomes restrained in addition to being grappled.", created_at: NOW, updated_at: NOW },
  { _id: "58218fc5923d5825ba014f62", name: "KUJAKU BEAST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "Special (6 Chakra or 3 Star Chakra)", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You cannot lose concentration on this jutsu as a result of taking damage. You summon a medium- sized bestial construct composed of pure star chakra in an unoccupied space within range. You may dismiss the construct at any time which ends the jutsu. As part of the action to cast this jutsu, you may command the beast to move up to 30 feet and attack a single target within 5 feet of it. On subsequent turns you can command the beast to move and take the attack action as a bonus action. Otherwise, the construct defends itself. Synchronize: Two Kujaku Beasts within 5 feet of each other can morph together to become stronger. As an action, you can spend half the cost of this jutsu to fuse the Beasts together, combining their current hit points and increasing its size category by 1, and its damage dice by 1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 (or 1 star chakra), also increase the construct's hit points by 2d6 (or +8) and it deals an extra 1d6 damage. When you cast this jutsu at B-Rank or above, you create one additional construct.", created_at: NOW, updated_at: NOW },
  { _id: "45d04120a2e1fa91810f468c", name: "FEATHER SLICE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "20 feet", chakra_cost: "5 Chakra or 2 Star Chakra", components: "HS, CM", duration: "Instant", description: "As a prerequisite to this jutsu you must have the Kujaku Mode active. The feathers of your Kujaku Mode shape into blade-like density. Make a melee ninjutsu attack against a target in range, dealing 3d8 + your Ninjutsu ability modifier in Force damage and if the target is a creature, it must make a Constitution saving throw or gain one rank of Bleeding.", at_higher_ranks: "For each rank you cast this jutsu above D-rank, increase the cost of the jutsu by 3 (or 1 star chakra), and it deals an extra 2d8 damage. When you cast this jutsu at B-Rank or above, you inflict one more rank of Bleeding.", created_at: NOW, updated_at: NOW },
  { _id: "b0f197f9e367b7180fedaa90", name: "HYPNOTIC DANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "8 Chakra or 4 Star Chakra", components: "HS, CM", duration: "Instant", description: "As a prerequisite to this jutsu you must have the Kujaku Mode active. You sway your chakra feathers back and forth. Up to two creatures you choose that can see you within range must make a Wisdom saving throw. Targets that fail against this jutsu can repeat the save at the end of each of its turns, ending the effects on itself on a success. Success: Affected target does not gain a rank of Charmed. Failure: Affected target gains one rank of Charmed against the caster for the next minute. While charmed this way, it is also considered Dazzled. Critical Failure: Affected creatures gain two ranks of Charmed against the caster for the next minute. While charmed this way, it is also considered Dazzled.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 (or 1 star chakra), and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "9f46fc74131b9210dbf6e05e", name: "PEACOCK WINGS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra or 4 Star Chakra", components: "HS, CM", duration: "Concentration, up to 10 Minutes", description: "As a prerequisite to this jutsu you must have the Kujaku Mode active. The feathers of your Kujaku Mode shift into two pairs of wings that grant you a flying speed of 60 feet, and can hover. When you cast this jutsu, you may choose to force all creatures within a 15-foot radius of you to make a Dexterity save or be knocked prone by the beat of your wings. Also, you can use an action to make a ranged ninjutsu attack against a target within 60 feet that you can see, as you launch chakra feathers from your wings. These chakra feathers deal 3d6 + your Ninjutsu ability modifier in force damage. A creature hit by this attack reduces its speed by 10 until the end of its next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 (or 1 star chakra), and increase the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "83c00c0d8335f960f7c7f372", name: "NOVACHARGE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "Special", components: "CM", duration: "1 Round", description: "You overclock the power of your next Ninjutsu with a surge of Star Chakra. When you cast this jutsu, you spend a minimum of 2 Star Chakra and a maximum of 8 Star Chakra, empowering the next Ninjutsu you cast before the start of your next turn; • 2+ Star Chakra: For every 2 Star Chakra spent, your Ninjutsu deals an additional 1d10 force damage. • 2+ Star Chakra: All targets affected by your Ninjutsu must succeed a Constitution saving throw or be knocked back a number of feet based on the rank of 20ft., A-Rank: 30ft., S-Rank: 40ft.). o If the target fails their save by 5 or more, they are Weakened until the end of their next turn. • 4+ Star Chakra: Creatures have disadvantage on effects to dispel, interrupt, or negate the casting. • 6+ Star Chakra: Targets make their Constitution saving throw at disadvantage. • 8 Star Chakra: The damage bonus of Novacharge becomes a d12, and adds twice your casting modifier.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4ffc857b608e1cc10a766610", name: "COSMIC PRESSURE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius)", chakra_cost: "13 Chakra or 6 Star Chakra", components: "CM", duration: "Concentration, up to 1 Minute", description: "As a prerequisite to this jutsu you must have the Kujaku Mode active. The feathers of your Kujaku Mode bolden as your mere presence is fueled by cosmic energy. An aura of distorting starlight surrounds you, and with this cosmic presence you exude a calming or frightening pressure. Until the jutsu ends, any creature that targets you with an attack or hostile jutsu must first make a Wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or jutsu. A creature that fails a save this way also gains one rank of Charmed or Fear (pick one) which last for the duration. Once a creature succeeds this Wisdom saving throw, it becomes immune to this effect until recast this jutsu. Also, for the duration, a heavy aura of Star Chakra surrounds you in a 20- foot radius. Creatures that enter this radius for the first time or start their turn in it must make a Strength saving throw, gaining 1 rank of Slowed on a failed save. A target that fails this save is also unable to mold chakra while it remains in the aura. If a creature fails this save by 5 or more, they are restrained until the start of its next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 (or 1 star chakra), increase the aura's radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "75a9c217d136337a6c2dcf9d", name: "KUJAKU DRAGON", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "Special (14 Chakra or 7 Star Chakra)", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You cannot lose concentration on this jutsu as a result of taking damage. You form a massive swell of star chakra that shapes itself into a dragon-like creature composed of pure star chakra in an unoccupied space within range. This dragon is a huge-sized construct. You may dismiss the construct at any time, ending this jutsu. As part of the action casting this jutsu, you may command the dragon to move up to 60 feet and make up to two attacks at targets within 15 feet of it. On subsequent turns you can command the dragon to move and take the attack action as a bonus action. Otherwise the construct defends itself.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 (or 1 star chakra), the construct's hit points by 2d8 (or +10) and it deals an extra 1d8 damage with its attacks.", created_at: NOW, updated_at: NOW },
  { _id: "92da7ce85a2b05a62e838649", name: "COSMIC FLARE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius)", chakra_cost: "13 Chakra or 6 Star Chakra", components: "CM", duration: "Concentration, up to 1 Minute", description: "As a prerequisite to this jutsu you must have the Kujaku Mode active. With your tail feathers pointed skyward, you gather a mass amount of star chakra above you. This star chakra radiates in a 120-foot sphere which ignores any form of cover and bypasses jutsu or chakra protection. For the duration, ranged attacks against you have disadvantage. You may exclude a number of creatures up to your proficiency bonus from the effects of this jutsu, all others that begin their turn in this sphere or enter it for the first time gain 1 rank of Slowed and must make two Constitution saving throws: 1st Save: On a fail, the creature is blinded for 1 minute or until it's obscured from view of the sphere's center. 2nd Save: On a failure, the creature gains two ranks of Weakened and 1 rank of Exhaustion. If this save is failed by 5 or more they are also stunned for 1 minute. A stunned creature can repeat its save at the end of each of its turns to end the stunned condition on itself on a pass. On consecutive turns, as an action you may launch a concentrated blast of raw Star Chakra in a 120-foot cone originating from 10 feet above you. You can fuel additional Star Chakra into this attack to deal extra damage. All creatures in the cone must make a Dexterity saving throw or take 10d10 + Xd10 (X = every 1 additional Star Chakra spent) Force damage, or half as much on a successful save. Once this attack has been made, the jutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7fe4a92348c75e096adf3857", name: "CELESTIAL APPARITION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction, which you take when you reach 0 hit points or would die", range: "Self", chakra_cost: "Special", components: "HS, CM", duration: "10 Minutes", description: "When you would die, or otherwise be reduced to 0 hit points, you can cast this jutsu to restore yourself to a ghostly form as your essence is manifested into pure star chakra. You gain an extra reaction that can only be used to cast this jutsu. This reaction cannot be negated by conditions or effects. Once cast, your body dies but you become a shimmering spirit comprised of Star Chakra gaining the following; • Equipment you carry is duplicated in your ghostly form, but when an item is no longer being worn or held by you it vanishes. • Your unarmed and weapon damage becomes force. • You have resistance to all damage besides necrotic, psychic, and chakra damage. This resistance cannot be overcome by any means. • You cannot regain or spend chakra points after this jutsu is cast. Instead, casting only your remaining Star Chakra for all features and jutsu. You regain a number an amount of Star Chakra equal to your level. If this amount exceeds your maximum then you gain the remainder in temporary hit points. • Your hit points remain at 0 and cannot exceed this amount, but you gain a number of temporary hit points equal to all current chakra you had before casting this jutsu. If you had 0 chakra, then you can spend a number of Star Chakra to gain temporary hit points (5 temp HP for every 1 Star Chakra). If these temporary hit points would reach 0, damage dealt to you reduces your Star Chakra total instead. • You cannot be revived or restored of Hit Points, even after the effects of this jutsu end. • You can immediately take an extra turn, entering yourself into initiative order at that moment. • This ghostly form lasts for 10 minutes or until you reach 0 temporary hit points and", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "56a6ef2b3f7babf41e683a7b", name: "GREAT WATER ARM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "5 Chakra", components: "W (Any Melee), CM, M", duration: "Instant", description: "You quickly enlarge your main arm by moving the Water in your body. Make a melee Ninjutsu or Taijutsu attack with the weapon used to cast this jutsu. On a hit, you deal your weapons damage + 2d8 and force a target to make a Strength saving throw. On a failed save, they are knocked back 15 feet and are dazed. On a success, nothing happens. If you are gaining the effects of the Hydrofication Hozuki clan Jutsu, increase the damage die by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank or higher, increase the damage by 1d8. If this jutsu is cast at B-Rank or higher, increase the number of attacks made by +1. If this jutsu is cast at S-Rank, increase the damage die by one step.", created_at: NOW, updated_at: NOW },
  { _id: "b9345eb3913dcb0b913022a1", name: "WATER BODY[CHANGED]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Reaction, which you take when you take damage from an attack.", range: "Self", chakra_cost: "5 Chakra", components: "-", duration: "1 Round", description: "You are able to quickly turn yourself into Water, allowing you to dodge more attacks. When damaged by an attack, you may increase your AC by +3 until the start of your next turn. Also, you gain Resistance to Bludgeoning, Piercing and Slashing damage but take an extra die of Lightning damage the first time you take Lightning damage before the start of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4b91a4424124a0b4052549f5", name: "WATER MUSCLES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "Concentration, up to 1 minute.", description: "You empower your muscles by controlling the Water inside your body. This jutsu does not cost Chakra to maintain concentration. For the duration damage dealt with attacks and jutsu that rely on your Strength adds 2d4 for their damage rolls. You can only gain the benefit of this bonus damage, twice per turn. Additionally, you can add +4 to skill checks that use your Strength modifier in any way. If you are currently benefitting from the Hydrofication Clan jutsu, the damage bonus instead becomes 5d4.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage bonus by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "36d6f2a96c0b4b3aa76262d1", name: "WATER ESCAPE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "1 Round", description: "You turn yourself into Water to escape your restraints. If you are currently grappled or restrained, you turn into a puddle of Water, escaping the grapple or restrained conditions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "794de9c2457992fd98c711e9", name: "HOZUKI BLADE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You weave together streams of Water to create a sword of solidified Water in your hand. This construct sword lasts until the jutsu ends. It counts as a simple melee weapon with which you are proficient. It deals 3d6 + your Strength or Dexterity modifier in either cold, Slashing, Piercing or Bludgeoning damage on a hit and has the Versatile (d8), Deadly and Finesse properties. You choose the damage type at the time of casting this jutsu. In addition, when you use the sword to attack a target that is at least halfway submerged in Water, you make the attack roll with advantage. If you are currently using the Hydrofication Jutsu, the dice size increases by one step (d6 > d8 > d10 > d12). If you drop the weapon, it dissipates at the end of the turn. Thereafter, while the jutsu persists, you can use a bonus action to cause the sword to reappear in your hand. If you would cast a jutsu that would allow you to deal this weapons damage that is under the effects of this jutsu, you only deal this jutsu’s damage once, after which you default to 2d6 (or d8, if holding with two hands)", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e4b42a9f1413b111121a947a", name: "WATER BLOB", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "9 Chakra", components: "CM", duration: "Concentration, up to 1 minute.", description: "A target creature you can see within range must succeed on a Dexterity saving throw or they are now grappled with their head being submerged in a bubble of Water, made from your body. While grappled this way, they begin to suffocate. While suffocating this way, it is difficult to maintain concentration on jutsu and must make a Constitution (Chakra Control) check to maintain concentration, losing the jutsu on a failure. A creature begins to drown after a number of rounds equal to its Constitution modifier (Min 1). While grappled in this way, when a creature attempts to escape this grapple, they can spend their action to make their Strength (Athletics) or Dexterity (Acrobatics) checks contested by either your Strength (Chakra Control), or Constitution (Chakra Control) check. At the start of its first turn after these rounds and the beginning of each of its turns it remains grappled, it takes necrotic damage equal to 4d8 + Your Ninjutsu ability modifier. If you are currently using the Hydrofication Jutsu, skill checks made to escape the grapple is made with a 1d4 penalty.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "de46902d596b463a43cfad2f", name: "WATER GUN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You form a bullet on the edge of your finger and shoot it at a target within range. Make two ranged Ninjutsu attacks against two separate creatures within range. On a hit, you deal 5d8 + Ninjutsu ability Modifier cold damage. If you are currently using Hydrofication jutsu, increase the damage die by one step (d8 > d10).", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "234c4453a5e05c46edd03f2e", name: "DOUBLE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You form bullets on the edge of each of your fingers and Fire them off with enough spread to imitate a shotgun. Creatures in a 15-foot cone in front of you must succeed a Dexterity saving throw, taking 6d6 cold damage and being chilled on a failed save, or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d6 and the cone size by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "1e920c55f635ead1770b6560", name: "HYDROFICATION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You turn yourself into a mixture of Water and oil, liquifying entirely turning into a sentient pool of fluid that you can control. For the duration of this jutsu, you can transform any part of your body into this liquid mixture, allowing you to fit through any crack large enough for Water to fit through. You gain resistance to bludgeoning, piercing, slashing and immunity to Fire damage. You gain vulnerability to Lightning damage. Additionally, your strength and Constitution scores increase by +4, while using this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5f11ab202f9544322ec0a171", name: "WATER BALLOON", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot Cube)", chakra_cost: "10 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "You create a puddle of Water mixed with oil, producing bubbles that float around you. These bubbles are then launched at a 15-foot cube of area within range with enough speed to cause concussive damage. Creatures of your choice, who first enter the chosen area or who begin their turn within it must succeed a Dexterity saving throw taking 4d10 bludgeoning damage and being Dazed or half as much on a successful save. As an action on your turn, you can choose to move the target area up to 30 feet in any direction within range. If you are currently using the Hydrofication Jutsu, increase the damage die by 1 step. (d10 > d12).", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "7da7a0431c017d0cd01f1c18", name: "DEMON WAVE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "16 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "As a requirement to activate this jutsu, you must have Hydrofication currently active. You end your concentration on that jutsu and this one takes its place. You retain all effects of Hydrofication, including extra effects given to other jutsu and add this jutsu's effects to them. You cannot lose concentration of this jutsu as the result of failing a concentration check. You create and merge with a larger body of Water, increasing your size to huge and increasing your Strength score by +4 and Constitution score by +2. When you cast a jutsu with the Water Release keyword, it always gains the benefits of any alternative effects the jutsu could receive as the result of being cast near a source of water (excluding cost reduction) and are upcast by +1 ranks for free. If this would cause the jutsu to be cast beyond S-Rank, apply the effects of the upcast an additional time (if applicable). Additionally, as a reaction when you see an allied creature within 10 feet of you, targeted for an attack, you can interpose for that ally changing the target of that attack", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a15aaf0a0952180546106e29", name: "GENTLE COUNTER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you take damage from a melee attack.", range: "Self", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "As a part of casting this jutsu, you must be gaining the benefits of the Gentle Fist Stance. You instantly react to an incoming attack. When you are damaged with a melee attack, you may roll 1d8 + Your Unarmed attack bonus. Reduce the damage you received by the result.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and reduce damage by an additional 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "efa7d4b8866308bba5b3c630", name: "PALM ROTATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Reaction, which you take when you are targeted for an attack, would take damage, or make a Strength or Dexterity saving throw.", range: "Self (5 feet)", chakra_cost: "5 Chakra", components: "CM, M", duration: "1 Round", description: "You spin at a violent speed, while releasing Chakra from every Chakra point on your body. Creating a dome of blue Chakra repelling most attacks. Until the start of your next turn you have a +4 Bonus to AC. If you are subject to a jutsu that requires you to make a Strength or Dexterity saving throw you make the save at advantage. Creatures who are within 5 feet of you when you cast this jutsu must succeed a Strength saving throw, taking 2d8 Force damage and being pushed back 5 feet on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "458d8e2494507f646cba6748", name: "PALM STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Special", range: "5 feet", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "As part of the requirements of this jutsu, you must be benefiting from the Gentle Fist Stance. Once per turn, you cast this jutsu when you would deal Chakra Damage with a melee attack. When this jutsu is cast you deal an additional 3d8 chakra damage and you can choose to either Disrupt I or Block I their chakra pathways. If you deal Chakra damage to a creature that has 0 Chakra, you instead deal double the resulting Chakra damage as force damage. Disrupt I: You increase the cost of all jutsu they cast by  +3, until the end of their next turn. Block I: You force the target creature to make a Constitution Saving Throw, becoming unable to mold Chakra until the start of your next turn on a failed save. They can remake the saving throw to remove this effect at the end of their turns.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 2d8 and if you use Disrupt I increase the cost of their next jutsu by an additional +3.", created_at: NOW, updated_at: NOW },
  { _id: "24f167f8e01507628528630a", name: "GENTLE REPRIEVE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action or 1 Bonus Action.", range: "Touch", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "As part of the requirements of this jutsu be benefiting from the Gentle Fist Stance. You reach out to touch an allied creature, using your chakra to speed up the flow of their chakra network aiding in their chakra efficiency or their chakra recovery If you choose to aid in their chakra recovery, this jutsu is an Action and you force the target creature to spend up to 2 Chakra die, recovering the result + Your Wisdom Modifier. If you choose to aid in their chakra efficiency, this jutsu is a Bonus action and reduces the cost of the next jutsu an allied creature casts by 2. This effect cannot be used on yourself.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If aiding in efficiency reduce the cost by an additional 1 at B-Rank, and by 2 at S-Rank. If aiding in chakra recovery, increase the number of Chakra die spent by +1 for every rank above D-Rank.", created_at: NOW, updated_at: NOW },
  { _id: "fb6f04a1ff301d0e1ef85bc4", name: "VACUUM WALL PALM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "3 Chakra", components: "CM, M", duration: "Instant", description: "You thrust your palm forward at a creature you can see in range creating an invisible blast of Chakra. Make a ranged Taijutsu attack. On a hit you deal 5d4 force damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d4 and the range by +10 feet. If this jutsu is cast at B-Rank or higher, you force the target creature to make a Constitution Saving Throw, becoming unable to Mold Chakra until the beginning of their next turn.", created_at: NOW, updated_at: NOW },
  { _id: "5b336e21bbc13f06c0766546", name: "8-TRIGRAMS 64 PALMS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (5 feet)", chakra_cost: "7 Chakra", components: "CM, M", duration: "Instant", description: "As part of the requirements of this jutsu you must have Byakugan active and be benefitting from the Gentle Fist Stance. You perform the Hyūga clan final maneuver of the Gentle fist. Make a single melee Taijutsu attack, comparing the result against all creatures of your choice AC, within 5 feet of you. On a hit, you deal your chakra damage dealt as force damage and you can choose to either Disrupt II or Block II their chakra pathways. If the target creature has 0 Chakra, you instead deal double the result as force damage. Disrupt II: You increase the cost of all jutsu they cast by +9, until the end of your next turn. Block II: You force the target creature to make a constitution saving throw, becoming unable to mold Chakra for 2 of their turns (or Elite Actions).", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d8 and if you use Disrupt II increase the cost of their next jutsu by an additional +6. If this jutsu is cast at B-Rank or higher, you instead make 2 attacks and creatures you strike with both attacks suffer increased effects from Disrupt II and Block II. This jutsu cannot make more than 2 attacks by any means per casting. Disrupt II: You increase the cost of all jutsu they cast by +12, until the end of your next turn. Block II: You force the target creature(s) to make a constitution saving throw, becoming unable to mold Chakra for 3 of their turns (or Elite Actions). They can remake the saving throw to remove this effect at the end of their turns.", created_at: NOW, updated_at: NOW },
  { _id: "0f11221a0b829c378058531e", name: "8-TRIGRAMS GRID PALM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (15-foot radius)", chakra_cost: "7 Chakra", components: "CS, CM, M", duration: "Concentration, up to 1 minute", description: "You slam your hand on the ground creating a network of grids along the ground that then cover all enemies inflicting great pain on them. All creatures of your choice, within range, must make a charisma saving throw, becoming restrained by the intense pain they experience for the duration. Creatures restrained in this way remake their saves at the end of each of their turns.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e12097388215d53dc66bf5cf", name: "GIANT PALM ROTATION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2ded2a8f1f84ae58520744f8", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Reaction, when you or an allied creature within range are targeted, would make a Strength, Dexterity, Constitution saving throw, or take damage.", range: "Self (10-foot radius sphere)", chakra_cost: "9 Chakra", components: "CM, M", duration: "1 Round", description: "The perfected form of the “Palm Rotation” taught only to those of the main branch of the Hyūga clan. As part of the requirements of this jutsu you must be benefitting from the Gentle Fist Stance. This creates a dome of visible blue Chakra, repelling everything of your choice up to 15 feet away in a radius centered on you. Until the start of your next turn, you and all creatures you have selected to not be affected by this jutsu within 10 feet of you benefit from this Jutsu’s effects. You & affected allies gain a +4 bonus to AC. If any of you are subject to a jutsu that requires you to make a Strength, Dexterity or Constitution saving throw you make the save at advantage. Creatures benefiting from this jutsu cannot benefit from bonuses to AC from other Reactions. Hostile creatures who are within 10 feet of you when you cast this jutsu must succeed a Strength saving throw against your Taijutsu Save DC taking 4d8 Force damage and being knocked back 10 feet on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d91f061f5f56f19af0b84b74", name: "ONE-BODY BLOW", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "3b3956975690cc3e21e9dbdb", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction which you take when you are grappled, restrained, or Prone as a result of a hostile creatures jutsu, feature, trait or action.", range: "Self", chakra_cost: "6 Chakra", components: "CM", duration: "Instant", description: "You release Chakra from every Chakra point in the body creating a shockwave originating from you knocking creatures around you away from you. First, if you are under the effect of a jutsu, feature, trait or action that would allow you to make a skill check or saving throw to end any of the triggering conditions, you automatically succeed the skill check or saving throw. Finally, all creatures of your choice, within 10ft of you must make a Strength saving throw, being knocked prone on a failed save and becoming unable to mold Chakra for until the end of your next turn. They can remake the saving throw to remove this effect at the end of their turns.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3dca06e252f78e38e9d2f6b5", name: "8-TRIGRAMS SPIRALING HEAVEN PALM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "10 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "As part of the requirements of this jutsu you must be benefitting from the Gentle Fist Stance and have the Byakugan active. You take a single breath sharpening your Gentle Fist stance making each strike more precise and lethal than the last, making each strike accurately bludgeon the internal organs of your foes. This jutsu costs no Chakra to concentrate on. For the duration you gain the following benefits: • Chakra damage you deal ignore Damage reduction. • When you make an unarmed attack that deals chakra damage, you deal an equal amount of damage to the target as Force damage. • Each successful unarmed attack you make in the same turn, that deals Chakra damage increases the cost of the next Jutsu the affected creature casts by +2. This stacks up to 3 times per round.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d70fd05a034ed914e1313294", name: "8-TRIGRAMS 64 PALMS DEFENSE (CHANGED)", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "2ded2a8f1f84ae58520744f8", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action or 1 Reaction to being damaged or being targeted by a jutsu with the Clash keyword", range: "Self (5 feet)", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "Created by a main branch Hyūga years ago. This is a variation on the “8-Trigrams 64 Palms”. As part of the requirements of this jutsu you must have Byakugan active and be benefitting from the Gentle Fist Stance. This jutsu can be cast as an Action or Reaction for different effects. Regardless, when you cast this jutsu, all creatures of your choice in a 5-foot radius centered on you must succeed a Dexterity saving throw or take 3d8 force damage and be pushed back 5 feet. Action: If this jutsu is cast as an Action, gain a +2 bonus to your AC until the start of your next turn, increase the damage dealt by this jutsu to 5d8, and on a failed save creatures are also knocked prone. Reaction: If this jutsu is cast as a Reaction, increase your AC by +5 until the start of your next turn and gain a +1d8 bonus to your next clash check before the start of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "b47650dc197a7105dd4dc7c4", name: "MOUNTAIN CRUSHER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "3b3956975690cc3e21e9dbdb", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "12 Chakra", components: "CM, M", duration: "Instant", description: "As part of the requirements of this jutsu you must have Byakugan active and be benefitting from the Gentle Fist Stance. An advanced and amplified version of the “Vacuum Wall Palm”. All Creatures in range must make a constitution saving throw, taking 15d4 force damage on a failed save, being knocked back 15 feet, and falling prone on a failed save. On a successful save, they instead take half damage with no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "55f2162652c14361a3fbd9ff", name: "8-TRIGRAMS 128 PALMS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "3b3956975690cc3e21e9dbdb", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (10-foot Radius)", chakra_cost: "17 Chakra", components: "CM, M", duration: "Instant", description: "This is the result of years of training and trying to achieve greater techniques than the main branch usually allows. This is the absolute peak of the Hyūga Gentle Fist technique within the Side Branch. As part of the requirements of this jutsu you must have Byakugan active and be benefitting from the Gentle Fist Stance and have the 8-Trigrams 64 palms learned. Make a three melee Taijutsu attack, comparing the result against all creatures of your choice AC within 10 feet of you as you dash between each one striking faster than the eye can see. On a hit, you deal your [Unarmed Damage] +3d8 Chakra damage and dealing half of the chakra damage dealt, as force damage the targets hit points and you can choose to either Disrupt III or Block III their chakra pathways. If the target creature has 0 Chakra, you instead deal double the result as force damage. Disrupt III: You increase the cost of all jutsu they cast by +15, until the end of your next turn. Block III: You force the target creature to make a constitution saving throw, becoming unable to mold Chakra for 3 of their turns (or Elite Actions). They can remake the saving throw to remove this effect at the end of their turns.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and damage by 1d8. If this jutsu is cast at S-Rank, creatures you strike suffer increased effects from Disrupt III and Block III. Disrupt III: You increase the cost of all jutsu they cast by +20, until the end of your next turn. Block III: You force the target creature(s) to make a constitution saving throw, becoming unable to mold Chakra for 4 of their turns (or Elite Actions).", created_at: NOW, updated_at: NOW },
  { _id: "a478b31939999a042302cb64", name: "LION PALM", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "2ded2a8f1f84ae58520744f8", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "15 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "The ultimate culmination of the Main Branches research and training. You release Chakra from your hands coating and molding it into two guardian lions with a visible but intimidating presence. For the Duration of this jutsu, you do not spend Chakra to maintain this jutsu. As part of the requirements of this jutsu you must have Byakugan active and be benefitting from the Gentle Fist Stance. Additionally, unarmed attacks using the Gentle Fist Stance and Hyūga Clan Hijutsu that make Melee Taijutsu attacks use a D10 damage die, Hyūga Clan Hijutsu have their costs reduced by -3 & Hyūga clan jutsu deal an extra damage die on a hit. As a Bonus action on your turn, you can make a Ranged Taijutsu attack on a creature you can see up to 30 feet away, firing off one of the Lions on your hand at them like a missile. On a Hit, you deal 3d10 + Taijutsu", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "52d7ed69ca5f63f86c70db71", name: "CHIMNEY DANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "CM, M", duration: "1 Minute", description: "Your feet begin to release small cinders which convert the air surrounding them into smoke which you use to propel your movement. For the duration, your movement speed increases by 10 feet and you gain an additional reaction per round. This reaction can only be used to take attacks of opportunity. Creatures provoke attacks of opportunity if they move in or out of 10 feet of you. If you hit with an attack of opportunity, you deal an extra 1d8+1 of Fire damage. If you are currently receiving the benefits of the Smoke Form jutsu, you make attacks of opportunity at advantage, and the bonus damage increases to a d10.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to B-Rank or higher, increase the damage by 1d8+1 and you can use your movement speed to fly and can hover. If cast to S-Rank, increase the damage by 1d8+1 and you gain an extra reaction which you can only use to take an attack of opportunity.", created_at: NOW, updated_at: NOW },
  { _id: "b74815e75f94e41585f0af7b", name: "FUME SUBSTITUTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Reaction, which you take when you are targeted by an attack or would take damage from an attack that targets you.", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "1 Round", description: "You quickly morph your body into smoke to avoid being struck by an enemy's assault. Increase your AC by +5 for the triggering attack, and for every other attack you are targeted with, you reduce the attack roll by a 1d4 potentially causing the attack to miss you. For each attack that misses you as a result of this jutsu you may move to a space within 10 feet of you as a gust of smoke. This does not provoke attacks of opportunity. If you are currently receiving the benefits of the Smoke Form hijutsu, you can instead move up to 15 feet when an attack misses you as a result of this jutsu, and reduce consecutive attack rolls by 1d6+1.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3a0ea18ce056bf27621332b8", name: "INCINERATING BURST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "Your body briefly erupts into smoke which bursts into fire. You shed 20-feet of bright light and 10 feet of dim light thereafter. You morph your body into smoke, moving to a space within 5 feet of the target as you simultaneously go for a flaming uppercut. Make a melee ninjutsu or taijutsu attack. On a hit, you deal 1d8+1 Fire damage and the creature becomes Burned until the end of their next turn. If you hit your first attack, you can make a 2nd attack against the creature or another creature within range, as you morph into smoke again, comboing into a spin kick from above or a lateral kick. On a hit, you deal 1d8+1 Fire damage and the creature must make a Strength saving throw against your Ninjutsu or Taijutsu Save DC, whichever is higher. On a failed save, if you choose to perform a spin kick from above, they are knocked prone. If you choose to make a lateral kick, they are knocked back 15 feet.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the damage by 1d8+1. If cast to B-Rank, you can perform this jutsu as a reaction, when you would take an attack of opportunity, as if you cast this jutsu at C-Rank.", created_at: NOW, updated_at: NOW },
  { _id: "d203af275df3655065b609c8", name: "SULFUR BOMB", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a large quantity of smoke in your hand and throw it at space within 60 feet, generating a 15-foot sphere of smoke. Each creature within the sphere must make a Dexterity saving throw, taking 3d6+3 Fire damage and falling prone on a failed save, or half as much damage and no further effects. The smoke created by this jutsu persists for 1 minute, causing creatures within to become heavily obscured for as long as they still within, though you can see through the smoke just fine. Creatures that end their turns within this smoke cloud, take 1d10+1 necrotic damage which cannot be reduced by any means. If the creature remains in the smoke cloud for the entire minute, they fall Unconscious, unable to breathe.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d6. If upcast to B-Rank or higher, you can disperse the leftover smoke as a free action on your turn, otherwise, the smoke now lasts 10 minutes. C-RANK", created_at: NOW, updated_at: NOW },
  { _id: "0f952c113f94c2a00eb14b38", name: "CINDER FIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (15-foot radius)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You breathe out an enormous quantity of smoke from your mouth creating a field of heavy gas all around you. You do not need to spend chakra to concentrate on this jutsu. For the duration, a 15-foot radius of smoke surrounds you, lightly obscuring you from creatures who cannot see through chakra enhanced smoke. Creatures, other than you, that enter or start their turn within the field of smoke take 5 Fire damage, plus an additonal 5 Fire damage for every 5 feet they willingly move within this radius, as the air they breath burns their lungs. This damage cannot be reduced by any means. Creatures who possess a breathing apparatus do not take damage from walking in this jutsu's area of effect. Also, when you deal fire damage to creatures within this radius, you deal an additional die of fire damage, once per turn, and ignore resistance to fire damage. This jutsu ends early if you move more than 90 feet from your original location. 80", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fadc3c5ca4891589c4bc0c51", name: "SMOKE AEGIS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Reaction, when another creature you could reach with your movement speed would be hit with an attack or fail a Strength, Dexterity, or Constitution saving throw.", range: "Movement Speed", chakra_cost: "8 Chakra", components: "CM, M", duration: "Instant", description: "You see an ally within range begin to succumb to peril and quickly move to protect them. Select a creature you could reach with your full movement. You morph your body into smoke and manifest in the space your ally was in, your smoke form producing gusts that push them 5 feet behind you. If this jutsu was done in response to an attack roll, the attack automatically hits you and you raise both arms up and form a smoke barrier with 5d6 temporary hit points. If this jutsu was used in response to a failed save, the creature you protected no longer suffers the effects of a failed save, and you roll the saving throw in their place at disadvantage, with a +2 bonus to the saving throw result. If you reduce the attacks damage to 0, or succeed the saving throw, you immediately counter with a melee Ninjutsu attack, dealing your unarmed damage in fire damage and knocking the creature back 15 feet on hit. If you are currently receiving the benefits of the Smoke Form hijutsu, you can move to a creature within double your movement speed, your barrier gains 5d8+your Ninjutsu ability modifier in temporary hit points if it is an attack, or gain a +3 bonus to the saving throw.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the temporary hit points gained by 1 die, or the save bonus by +1 (Pick one).", created_at: NOW, updated_at: NOW },
  { _id: "eae854359c4deb6be53d966f", name: "SMOKE DRAGON", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (90-foot line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You emit a large amount of fumes and gasses from your body and produce a large dragon construct in front of you. You send this dragon out in a 90-foot long, 5-foot wide line. All creatures within range of your choice must make a Constitution saving throw, taking 4d8+4 Fire damage and becoming dazed until the end of their next turn on a failed save. You can control how long this line becomes. If you are currently receiving the benefits of the Smoke Form hijutsu, you can morph your whole body into smoke and travel with the dragon without expending your movement speed. Upon ending your movement, creatures within 10 feet of you provoke attack of opportunity attacks.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3, the damage by 2d8+2. If upcast to A-Rank, increase the width of the line by 5 feet. B-RANK", created_at: NOW, updated_at: NOW },
  { _id: "a0447ad4a1954e8efa530191", name: "BURNING SWEEP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (25-long, 65-foot wide, 30-foot high cube)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You aggressively slash the air in front of you, creating two large pillars far in front of you that generate a large gust of wind and ash. You then use smoke to levitate into the air, creating two more pillars in front of you at your sides, creating a 25-foot long, 65- foot wide, 30-foot high cube. Creatures caught in the awesome forces of smoke and wind within this jutsu's range must make a Dexterity saving throw, as the pillars return to your arms and you expel the energy towards them all. Creatures that cannot be moved make this saving throw at advantage. Creatures who fail their saving throw against this jutsu take 9d6+9 Fire damage and gain 1 rank of Burned. Creatures who fail their saving throw by 5 or more have the wind knocked out of them, reducing their movement speed to 0 until the end of their next turn. If you are currently receiving the benefits of the Smoke Form hijutsu, creatures of Medium size or smaller make this jutsu's saving throw at disadvantage, and the damage increases by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the damage by 1 step (1d6<1d8<1d10<1d12).", created_at: NOW, updated_at: NOW },
  { _id: "2230e1527d5ab84df1caeb4e", name: "SMOKE FORM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You turn yourself and your clothes into smoke for the duration of this jutsu. You still appear mostly the same, however, smoke continues to perspire off your body and fall to the ground beneath you, like a reservoir. When you move, your body quickly shifts into smoke. For the duration of this jutsu, you do not provoke attacks of opportunity when you move, and are able to pass through small gaps and cracks, large enough for air to get through. You are also immune to fall damage. Your weapon attacks deal an additional die of fire damage, once per turn, and you gain immunity to fire damage, whilst also gaining vulnerability to Wind damage. Your AC increases by +1, and the Iburi Clan hijutsu you cast other than this one have their cost reduced by 2 (Min. 1). 81 A-RANK", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "40d74b706abac843e032f9e9", name: "BODY OXIDATION TECHNIQUE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Full Turn Action", range: "30 feet", chakra_cost: "Special (18 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "As part of the requirements for casting this jutsu, you must be benefitting from the Smoke Form hijutsu. The signature jutsu of the Iburi clan, where the user enters the body of a creature and takes control of their actions. You cannot lose concentration on this jutsu as a result of taking damage. Select a creature within range. This creature must make a Charisma saving throw. On a failed save, you entire their body, rendering them incapacitated and unable to move. While in a creature's body, you feel all sensations their body feels and cannot take actions or reactions, or concentrate on other jutsu. Additionally, whenever the creature takes damage from an exterior source, you take half the damage they took as Necrotic damage. At the start of each of the creature's turns, they repeat the Charisma saving throw, expelling you from their body on a success, or remaining incapacitated and unable to move on failure. At the start of each of your own turns, you can impose a Constitution or Intelligence saving throw on the creature. After imposing either saving throw, your turn ends. • Constitution Save: On a failed Constitution saving throw, the creature takes 5d12 necrotic damage which bypasses resistance, immunity, and temporary hit points. The creature also gains 3 stacks of internal bleeding. • Intelligence Save: On a failed Intelligence saving throw, you command the creature to move and take 1 Action that they can take, other than a class or adversary feature. When this jutsu ends, you reappear in a space within 5 feet of the creature you were possessing, and automatically end your Smoke Form jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "936ad16131f876053162c21d", name: "ORBITAL DROP", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "4ca66bf77ffa28385682255c", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Movement Speed (120-Foot sphere)", chakra_cost: "20 Chakra", components: "CM, M", duration: "Instant", description: "As part of the requirements for casting this jutsu, you must be benefitting from the Smoke Form hijutsu. You move up to your movement speed at a space within range and send yourself high into the air with a burst of smoke. Your body splits into 3 pillars of smoke that rise tangent to each other 200 feet into the air. As the smoke pillars rise, they are set on fire from the friction in the air. These pillars merge and reform into your body, and you begin hurling back down to earth like a missile. As you hit the ground, you create a massive explosion, annihilating creatures within a 120-foot sphere. Each creature within range must make a Dexterity saving throw, taking 10d10+10 Fire damage, gaining 3 ranks of Burned, and becoming blinded until the end of their next turn on a failed save. On a successful save, creatures take half damage and gain only 1 rank of Burned. If a creature possesses any ranks of Burned prior to being affected by this jutsu, this jutsu ignores any resistances and immunities to Fire damage the creature may have. The area this jutsu effects permanently becomes difficult terrain, and as this jutsu concludes, your Smoke Form jutsu automatically ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9397a9a170f016903a30dae4", name: "BEAST-HUMAN CLONE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "10 minutes", description: "Your Nin-Dog uses the advanced transformation technique, transforming to look exactly like you, with notable differences. They still need to be on all fours and they cannot talk, so they make poor replacements for infiltration. While in this form, when your Nin-Dog is within 15 feet of you and either of you, are the target of an attack, the other one, not being targeted, can switch places with the target of the attack and make an unarmed or natural weapon attack (their choice) as a reaction. If the result of their attack roll is higher than the triggering creature’s attack was a melee attack, the creature automatically takes damage attributed to the attack type you or your Nin-Dog chose.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the distance the special reaction can be used by 10 feet. If this jutsu is cast at B-Rank, while you are within 15 feet of your Nin-Dog, if you cast an Inuzuka Clan Hijutsu that has a casting time of “1 Action, 1 Bonus Action”, you can choose to only spend 1 action. If you do, both you and your Nin-Dog cast the jutsu simultaneously, attempting to target the same creature.", created_at: NOW, updated_at: NOW },
  { _id: "a69f9cc8cbf5ecb013a1db6c", name: "DYNAMIC MARKING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (10-foot radius)", chakra_cost: "4 Chakra", components: "M", duration: "10 Minutes", description: "Your Nin-Dog leaps into the air, and spins while releasing Chakra charged urine over the area. Creatures in a 10-foot radius centered on the Nin-Dog are covered in the Urine. Affected creatures exude a faint but obvious stench that can be tracked by you or your Nin-Dog. For the duration, you & your nin- dog have blindsight when searching for or attacking creatures affected by this jutsu. When you make a perception check to find an affected creature, you gain advantage on the roll. Also, when you or your Nin-Dog make an attack using an Inuzuka clan jutsu against an affected creature, roll a 1d4, adding the result to your attack roll.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the radius of this jutsu, by 5ft. 85", created_at: NOW, updated_at: NOW },
  { _id: "e54538878e3461cb9e3d3c62", name: "FOUR LEGS TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 Minute", description: "You gain the ability to move like a dog. For the duration of this jutsu, you ignore difficult terrain and your movement speed increases by 15 feet and your wall walking, Water walking, and climbing speed becomes equal to your movement speed. Your movement speed also cannot be reduced as a result of a jutsu, feature or trait. (This does not count for conditions).", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and movement speed bonus by +5.", created_at: NOW, updated_at: NOW },
  { _id: "12b881705cdb028734ab8591", name: "TUNNELING FANG", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "As part of the requirements of this jutsu you must have the Four Legs Technique active or your Nin-Dog must have Beast-Human Clone active. You or your nin-dog begin to spin at an accelerated rate attempting a spiraling body slam. Move up to 30 feet into an adjacent space next to the target creature and make a melee Taijutsu attack against it, so long as you can see or smell it within range. On a hit, you deal 2d6 slashing and 2d6 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 1d6 for each damage type. C-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "a95da62dbd81544c34333d00", name: "FANG OVER FANG", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action, 1 Bonus Action.", range: "30 feet", chakra_cost: "7 Chakra", components: "CM, M", duration: "Instant", description: "As part of the requirements of this jutsu you must have the “Four Legs Technique” active and your Nin- Dog must have “Beast-Human Clone” active. You or your Nin-Dog begin to spin at an accelerated rate chasing down enemies and performing a spiraling body slam in rapid succession. As an action, make a melee Taijutsu attack against a target creature in range. On a hit dealing 3d6 slashing damage and 3d6 bludgeoning damage. As a bonus action you may command your Nin-Dog to cast this jutsu. They make a melee Taijutsu attack. On a hit they deal 3d4 slashing damage and 3d4 bludgeoning damage. If both Attacks Hit the same creature, the target creature must make a strength save, falling prone on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d6 for each damage type for only your attack using the jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "fede1062c5cff466eea1b1d7", name: "FANG TEARING FANG", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "As part of the requirements of this jutsu you must have the Four Legs Technique active. As part of the activation of this jutsu, make two melee Taijutsu attacks against a target creature in range. On a hit you deal unarmed damage + 2d6. If you hit with both attacks, the target creature must succeed a strength saving throw, being knocked prone on a failed save. You also gain an additional Bonus action until the end of this turn. You may only gain a Bonus Action as a result of this Jutsu once per round.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the number of attacks made by +1. If this jutsu is cast at S-Rank, increase the number of attacks made by +1 86", created_at: NOW, updated_at: NOW },
  { _id: "3a7d8285331f430589f80318", name: "IRON FANGS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "6 Chakra", components: "HS", duration: "1 minute", description: "You or your nin dog focus Chakra into your nails, enhancing their sharpness and hardness, making your unarmed strikes and Taijutsu much more effective. For the duration, your unarmed damage becomes 4d4 Slashing damage and you can use Dexterity for unarmed attack rolls for the duration. You cannot add your ability modifier to unarmed damage rolls.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d4. B-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "0e01978e4f36d4bca344731c", name: "DOUBLE HEADED WOLF", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "As part of the requirements of this jutsu you must be in direct contact with your Nin-Dog. You perform the Inuzuka Clans Secret Transformation Technique, fusing you and your dog, and transforming you both into a huge creature with 2 heads and combining your senses and strengths. For the duration, you gain the following benefits; You do not need to spend Chakra to maintain this jutsu, and while you have the temporary hit points granted by this jutsu you cannot lose concentration on this jutsu as a result of damage. • Increase your Strength and Dexterity Ability scores by +4. • You are now a Huge creature. • You can no longer perform Hand Seals, but can perform any Inuzuka Clan Jutsu ignoring its need for HS if any. • Your speed is increased by 30 feet. • You gain resistance to Bludgeoning, Piercing, and Slashing damage. • You gain a pool of Temporary hit points equal to 10 times you or your Nin-Dogs constitution modifier (whichever is higher). • You can no longer command your Nin- Dog, but you gain all of its Senses, Traits, Features, and Skill Proficiencies for the duration of this Jutsu. • Inuzuka Clan Jutsu you cast while in this form cost is reduced by half and adds your Strength and Dexterity Modifier to damage rolls if they don’t already, ignoring any limitation such as with Iron Fangs.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9903b4c5ef6ad13335365101", name: "FANG WOLF FANG", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "13 Chakra", components: "HS, CM, M", duration: "Instant", description: "As part of the requirements of this jutsu, you must have the Double Headed Wolf Inuzuka clan jutsu active. You perform a much more devastating variation of the tunneling fang as a double headed wolf, tearing into your target and ripping them apart. Make a melee Taijutsu attack, dealing 5d6 slashing & 5d6 piercing damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d6 for each damage type. A-RANK:", created_at: NOW, updated_at: NOW },
  { _id: "834b25a182465d4314f04bdf", name: "TAIL CHASING FANG", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "15 Chakra", components: "M", duration: "Instant", description: "As part of the requirements of this jutsu, you must have the Double Headed Wolf Inuzuka clan jutsu active. An ultra-violent variation on the Fang Wolf Fang technique where you curl into a ball and roll at a ferocious speed towards an enemy as if chasing after your own tail. Move up to 120 feet in any direction, being able to turn or change direction. At the end of your movement, all creatures in the path of your movement must make a Dexterity saving throw, taking 7d8 slashing & 7d8 piercing damage on a failed save, or half as much on a successful one. MAGNET RELEASE: DUST", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "847166a1979a79a320feca09", name: "DUST IMMOBILIZATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "1 Hour", description: "You touch an object that weighs no more than 10 pounds, and use dust of your description (Gold, Iron, Sand, Salt, Gravel) to create a chakra seal to affix it in place. You and the creatures you designate when you cast this jutsu, can move the object normally. If the object is fixed in the air, it can hold up to 4000 pounds in weight. More weight causes the object to fall, otherwise, a creature can use an action to make a Strength (Athletics) check against your Ninjutsu save DC. On a success the creature can move the object up to 10 feet. If the object is more 20 feet or more from its original position, the seal breaks, ending this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When you cast this jutsu at C-Rank, the DC to move the object increases by 5, it can carry up to 8000 pounds of weight, and the duration is increases to 24 hours. If you cast this jutsu at A-Rank or Higher, the DC to move the object increases by 10, it can carry up to 20,000 pounds of weight, and the duration becomes permanent until dispelled.", created_at: NOW, updated_at: NOW },
  { _id: "6ae73f564e0d9dee9171e42c", name: "DUST COAT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You draw dust particles around yourself of your description (Gold, Iron, Sand, Salt, Gravel) to create a virtually invisible armor to protect yourself from attacks. For the Duration, your AC is calculated as 13 + your Ninjutsu Ability Modifier + Your Proficiency bonus. Additionally, you gain a number of Temporary hit points equal to your Ninjutsu save DC. This jutsu ends early if you don armor of any type, change your AC calculation source or you end it as a bonus action. If you lose all temporary hit points granted by this jutsu; as a bonus action, you can pay 5 chakra to gain temporary hit points equal to your Ninjutsu save DC.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When you cast this jutsu at B-Rank, Your AC begins its calculation with 14. When you cast this jutsu at S-Rank, Your AC begins its calculation with 15.", created_at: NOW, updated_at: NOW },
  { _id: "4ac08a65466479f6ae5dfe7e", name: "DUST PARTICLE DRIZZLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (30-foot Cone)", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "You begin to collect and manifest water release chakra until it laces the striking portion of your weapon. The water release chakra begins to transform into streams of water, capable of being seen and felt as you perform a zigzag or curved attack, attacking in an irregular motion. When casting this jutsu, you can choose to make a Zigzag or Curved attack. • Zigzag: Make one ranged Taijutsu attack against a creature in your weapons range. Each creature within of your choice, between you and your target must make a Dexterity saving throw. On a hit or failed save, you deal your [weapons damage] + 4d6 cold damage and affected creatures gain 1 rank of chilled or half as much damage on a successful save. A creature whom you target that is either Dazed or chilled grants you a 1d4 bonus to hit. A creature whom you force to make a saving throw that is either Dazed or chilled suffers a 1d4 penalty to their saving throw. • Curved: You fire off a curved shot, capable of bypassing defenses. Make one ranged Taijutsu attack. This attack ignores boosts to AC as a result of features, traits or jutsu. On a hit, you deal twice your [weapons damage die] + 3d8 cold damage, and being dazed on a failed save or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When you cast this jutsu at B-Rank, Your AC begins its calculation with 14. When you cast this jutsu at S-Rank, Your AC begins its calculation with 15.", created_at: NOW, updated_at: NOW },
  { _id: "8751e108e29012ce80a22155", name: "DUST SHIELD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action or 1 Reaction, which you take when you or an allied creature would take damage.", range: "Special", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Special", description: "You draw dust particles around yourself of your description (Gold, Iron, Sand, Salt, Gravel) to create a wall made entirely of the substance of choice, in any design of your choosing. This wall protects you from damage and can even protect other willing creatures. As an Action, you can manifest this dust shield surrounding either yourself or another willing creature within 30 feet of you. If the affected creature moves from its current space at all, this jutsu ends. While active, a creature gains a Dust Shield. This Dust shield protects them from all attacks, from any direction. This Dust shield has an AC equal to your Ninjutsu save DC, is treated as an Earthen construct, has total of 15 Hit points and remains until dispelled, the creature moves out of its current space, or the Dust shields hit points are reduced to 0. Alternatively, as a reaction when you or an allied creature within 30 feet of you, would take damage, and neither of you are already under the effect of this jutsu, you can protect that creature, granting them a Dust Shield that has 15 Hit points and lasts until the start of their next turn. Regardless of how you cast this jutsu, the Dust shield created by this jutsu has resistance to Cold, Fire and Earth Damage, but Vulnerability to Lightning Damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the Dust Shield Hit points by 15. When you cast this jutsu a B-Rank or higher, affected creature cannot be moved by any means 90 if you don’t want them to be, while gaining the benefits of this jutsu. MAGNET RELEASE: MAGNETIC", created_at: NOW, updated_at: NOW },
  { _id: "9c1108ff5cb3f481c76750a1", name: "MAGNETIC POLARIZATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "You focus your magnetic chakra on a point within range. Your chakra then expands to fill a 20-foot cube from that point, magnetizing any objects and creatures within that area when you cast this jutsu. Each target must succeed on a constitution saving throw or become magnetized for the duration. Unattended objects automatically fail this saving throw. While Magnetized any attack rolls against the target has advantage if the attacker uses weapons made of metals and the affect targets have their speed, if any, reduced by 15 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the size of the cube by 10 feet. C-RANK MAGNET RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "0b84c1779d8696ca18f9713e", name: "DUST WINGS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You form a mass of dust particle of your description (Gold, Iron, Sand, Salt, Gravel) on your back, forming massive wings of your design and description. While this jutsu is active, you gain a flying speed of 30 feet, and can hover. Additionally, you can use an action to do one of the following; Dust Feathers: You form dust particles from your wings of the same material into darts. Make a ranged ninjutsu attack against a target within 60 feet of you, that you can see. If the creature is marked with your Magnetic Mark feature, you can target them as if you can see them, even if you are blinded or in darkness and even ignoring full cover. On a hit, the target takes 2d8 piercing damage and 2d8 earth damage. Dust Spear: You form your wings into a giant spear of dust. Make a ranged ninjutsu attack against a target within 30 feet of you that you can see. If the creature is marked with your Magnetic Mark feature, you can target them as if you can see them, even if you are blinded or in darkness and even ignoring full cover. On a hit, the target takes 4d8 piercing damage and 4d8 earth damage. Additionally, each creature within 10 feet of the target must make a Dexterity saving throw. On a failed save, a creature takes 4d8 bludgeoning damage and is pushed back 10 feet. On a success, a creature takes half as much damage and is not pushed back. Using Dust Spear, uses all of the dust in your wings, ending this jutsu immediately after resolving its effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. When you use Dust Feathers, make an additional attack with it for every rank you casted this jutsu above C-Rank. When you use Dust Spear, increase the Piercing earth and bludgeoning damage by 1d8 each. MAGNET RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "c26a72134517309b39f493e4", name: "MAGNET WAVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "20ee567a744c63cf38fc80c9"], elements: [], casting_time: "1 Action", range: "Self (15 feet)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You form a mass of dust particle of your description (Gold, Iron, Sand, Salt, Gravel) and release it from your current position. All creatures within 15 feet of you of your choice when you cast this jutsu, must succeed a constitution saving throw, taking 4d10 earth damage on a failed save, or half as much on a successful one. This damage happens once per casting. A creature that fails this saving throw becomes magnetized for the duration. While a creature is magnetized in this way, you can use your bonus action and choose a point, object or other creature within 60 feet of the magnetized creature that you can see. When you do, you forcefully attempt to pull a magnetized creature in a straight line towards the target, ending in an unoccupied space as close to the target as possible (even if that space is in the air). The magnetized creature must succeed a Strength saving throw to resist this effect. If the creature is marked as a result of the Magnetic Mark Jiton Clan feature, they make this saving throw at disadvantage. You can choose any number of magnetized creatures to attempt pull towards that same point, object or other creature. A magnetized creature can use its action to repeat their saving throw to end the magnetized condition on themselves on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d10 and the range by 5 feet. MAGNET RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "ced886bf02f57d49b74d33f9", name: "SEALING DUST SPHERE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "Using your magnetic chakra and a special seal, you create a sphere of dust particles of your description (Gold, Iron, Sand, Salt, Gravel) with a 10-foot radius on a point you can see within range. The sphere can hover in the air, but no more than 10 feet off the ground. The sphere remains for the jutsu’s duration. Any creature in the sphere's space must make a Strength saving throw. On a successful save, a creature is ejected from that space to the nearest unoccupied space outside it. A Huge or larger creature succeeds on the saving throw automatically. On a failed save, a creature is restrained by the sphere and is engulphed by the dust particles. At the end of each of its turns, a restrained target can repeat the saving throw. The sphere can restrain a maximum of four Medium or smaller creatures or one Large creature. If the sphere restrains a creature in excess of these numbers, a random 91 creature that was already restrained by the sphere falls out of it and lands prone in a space within 5 feet of it. As an action, you can move the sphere up to 30 feet in a straight line. If it moves over a pit, cliff, or other drop, it safely descends until it is hovering 10 feet over ground. Any creature restrained by the sphere moves with it. You can ram the sphere into creatures, forcing them to make the saving throw, but no more than once per turn. When the spell ends, the sphere falls to the ground and extinguishes all normal flames within 30 feet of it. Any creature restrained by the sphere is knocked prone in the space where it falls", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the size of the gold sphere increases. At B-Rank, the sphere has a 15- foot radius, and can restrain a maximum of five Medium or smaller creatures, one Large creature, or one Huge creature. At A-Rank, the sphere has a 20-foot radius, and can restrain a maximum of six Medium or smaller creatures, two Large creatures, one Huge creature, or one Gargantuan creature. At S-Rank, the sphere has a 30-foot radius, and can restrain a maximum of eight Medium or smaller creatures, three Large creatures, two Huge creatures, or one Gargantuan creature B-RANK MAGNET RELEASE:", created_at: NOW, updated_at: NOW },
  { _id: "81a62bace0c1844b32fa8f92", name: "MAGNETIC DUST FIST", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a large hand of dust particles of your description (Gold, Iron, Sand, Salt, Gravel) in an unoccupied space you can see within range. The hand lasts for the jutsu's duration, and it moves at your command, mimicking the movements of your own hand. The hand is an object that has AC 20 and hit points equal to your hit point maximum. If it drops to 0 hit points, the jutsu ends. It has a Strength of 26 (+8) and a Dexterity of 10 (+0). The hand doesn't fill its space. When you cast this jutsu, and as a bonus action on your subsequent turns, you can move the hand up to 60 feet and then cause one of the following effects with it. Clenched Fist: The hand strikes one creature or object within 5 feet of it. Make a melee ninjutsu attack for the hand using your game statistics. On a hit the target takes 4d8 earth damage. Forceful Hand: The hand attempts to push a creature within 5 feet of it in a direction you choose. Make a check with the hand's Strength contested by the Strength (Athletics) check of the target. If the target is Medium or smaller, you have advantage on the check. If you succeed, the hand pushes the target up to 5 feet plus a number of feet equal to 5 times your ninjutsu ability modifier. The hand moves with the target to remain within 5 feet of it. Grasping Hand: The hand attempts to grapple a Huge or smaller creature within 5 feet of it. You use the hand's Strength score to resolve the grapple. If the target is Medium or smaller, you have advantage on the check. While the hand is grappling the target, you can use a bonus action to have the hand crush it. When you do so, the target takes bludgeoning damage equal to 2d6 + your ninjutsu ability modifier. Interposing Hand: The hand interposes itself between you and a creature you choose until you give the hand a different command. The hand moves to stay between you and the target, providing you with half cover against the target. The target can't move through the hand's space if its Strength score is less than or equal to the hand's Strength score. If its Strength score is higher than the hand's Strength score, the target can move toward you through the hand's space, but that space is difficult terrain for the target.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the damage from the clenched fist option by 2d8, and the grasping hand by 2d6. MAGNET RELEASE: IMPERIAL DUST", created_at: NOW, updated_at: NOW },
  { _id: "de8153a5bfc43bb48e31afb0", name: "IMPERIAL DUST FUNERAL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "20ee567a744c63cf38fc80c9"], elements: [], casting_time: "1 Action", range: "300 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 5 rounds", description: "Using your magnetism, you summon a wall of dust particles of your description (Gold, Iron, Sand, Salt, Gravel) into existence at a point you choose within range. You can make the wall up to 250 feet long. 250 feet high, and 50 feet thick. The wall lasts for the duration. When the wall appears, each creature within its area must make a strength saving throw. On a failed save, a creature takes 5d8 earth damage, or half as much damage on a successful save. At the start of each of your turns after the wall appears, the wall, along with any creatures in it, moves 50 feet away from you. Any Huge or smaller creature inside the wall or whose space the wall enters when it moves must succeed on a Strength saving throw or take 4d8 earth damage. A creature can take this damage only once per round. At the end of the turn, the wall's height is reduced by 50 feet, and the damage creatures take from the jutsu on subsequent rounds is reduced by 1d8. When the wall reaches 0 feet in height, the jutsu ends. A creature caught in the wall can attempt to move within it, but every foot moved costs 3 feet of movement. Because of the force of the wave, the creature must make a successful Strength (Athletics) check against your ninjutsu save DC in order to move at all. If it fails the check, it can't move. A creature that moves out of the area falls to the ground. 92 A-RANK MAGNET RELEASE:", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0ce07c886dbbe470b2013c34", name: "DUST PARTICLE WORLD", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "150 feet (40-foot radius sphere)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a two masses of dust particles of your description (Gold, Iron, Sand, Salt, Gravel) of opposing magnetic fields, and then merge them together, repelling the particles across a 40-foot radius sphere centered on a point you choose within range. The particles then come together, forming massive arrays of spikes that branch off irregularly, making the spikes nearly impossible to evade, and the area very difficult to see through. For the duration, the jutsu's area is difficult terrain. Creatures attempting to see through the area have disadvantage. Any creature of your choice, that enters the jutsu's area for the first time on a turn or starts its turn there must make a constitution saving throw. The creature takes 4d10 piercing damage and 4d10 earth damage on a failed save becoming poisoned, or half as much damage on a successful one. If a poisoned creature fails this saving throw, the creature becomes stunned instead. If a creature fails this saving throw while stunned in this way, the creature instead becomes unconscious. A creature rendered unconscious from this jutsu no longer takes damage from it. A creature that is stunned or unconscious as a result of this jutsu and is no longer within this jutsu’s range, can make a constitution saving throw at the end of each of its turns. On a success, an unconscious creature becomes stunned instead and a stunned creature ends its stunned Condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "054ad99c9c62dadbfc228d25", name: "MISPLACED MISFIRE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Special", range: "Touch", chakra_cost: "4 Chakra", components: "M, CM", duration: "Instant", description: "After missing an unarmed strike or Taijutsu attack roll, you quickly fix your mistakes, using a jet on one of your legs or arms to quickly propel an attack forward. Make a Taijutsu Attack dealing your [Unarmed Damage] in force damage. You can only use this jutsu once per round.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1 damage die.", created_at: NOW, updated_at: NOW },
  { _id: "20edc615369f95b116f5cff7", name: "CHAKRA CANNON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "urning one of your arms into a cannon, you fire a beam of raw chakra. Make a ranged ninjutsu attack. On a hit, you deal 2d10 force damage. Raw Chakra Form: If you cast this jutsu when within Raw Chakra Form, add half your Constitution Modifier to the damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "3b3baff6f71f09a2bef82a61", name: "FURIOUS FISTS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You grow jets at the back of your elbows or ankles, enhancing unarmed attacks with the power of chakra thrusters. For the duration, melee unarmed/ weapon attacks, melee Taijutsu attacks or grapple attacks you make deal an additional 1d8 force damage, up to three times per turn. Raw Chakra Form: When you are in your Raw Chakra Form and benefiting from this jutsu, you do not spend Chakra to concentrate on it.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3. If this jutsu is cast at B-Rank or higher increase the damage by 1d8 and creatures you hit gain 1 rank of Bruised, once per creature per round. If this jutsu is cast at S-Rank you ignore resistance to bludgeoning damage, and treat immunity as resistance. RAW CHAKRA TRANSFERENCE", created_at: NOW, updated_at: NOW },
  { _id: "d92da9b305f843ec16cca7f6", name: "RAW CHAKRA TRANSFERENCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Full Turn Action", range: "Self (90-foot cone)", chakra_cost: "21 Chakra", components: "HS, CM, M", duration: "Concentration, up to 1 Minute", description: "As part of moving, you may cast this jutsu, forming jets at your back. Until the end of your turn, your speed increases by 20ft. Additionally, your Jump Distance and Height during this turn are multiplied by x4. When you use Hellfire Jets, you may choose to float, not falling until the start of your next turn. You may float for two rounds this way before you automatically start to fall and must touch a surface with your legs to propel yourself again. You may also float to ignore the penalty to speed of Water and Climbing. Raw Chakra Form: If you cast this Jutsu when within your Raw Chakra Form, until the start of your next turn, you reduce all Area of Effect damage by half your Strength Score, provided you can move. CHAKRA CANNON: OVERDRIVE", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "029797a7691034b96ff61631", name: "HELLFIRE JETS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Special", range: "Touch", chakra_cost: "6 Chakra", components: "CM, M", duration: "Instant", description: "You form a shield out of your body using one of your arms to block an attack. Your AC is increased by +4 for the duration, and the Shield has 25 HP an enemy must first break to deal damage to you. The shield cannot block Genjutsu attacks. If you would have to make a Dexterity Saving Throw that deals a reduced effect on a successful saving throw (such as dealing half damage), instead roll a Strength Saving Throw. On a success, your shield reduces the damage of the ability by 5. Raw Chakra Form: If you cast this justu when within your Raw Chakra Form, add your Strength Modifier to the Shields HP.", at_higher_ranks: "For each rank above C-Rank you cast this jutsu, increase the HP of the shield by 10. B-RANK", created_at: NOW, updated_at: NOW },
  { _id: "35a995cfa76609d19a2203d0", name: "OVERDRIVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Full Turn Action", range: "Self (90-foot cone)", chakra_cost: "21 Chakra", components: "HS, CM, M", duration: "Concentration, up to 1 Minute", description: "An enhanced version of the “Machine Gun Punch” Taijutsu, you make multiple, incredibly fast and powerful attacks. Make a number of Melee Taijutsu attacks equal to your proficiency bonus, dealing your [Unarmed Damage Die] + 2d6 Force. Raw Chakra Form: If you cast this jutsu when within your Raw Chakra Form, you cannot have disadvantage on the attack rolls.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "543290edf7e0b472f6fa986f", name: "IRON-SHINE GUARD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Reaction, when targeted by an attack roll", range: "Self", chakra_cost: "8 Chakra", components: "CM, M", duration: "1 Round", description: "Aiming cannons from out of your chest, you attempt to produce so much fire-power you can push back an attack. When a creature makes a ninjutsu attack roll at you, by casting this jutsu you can propel it back. Make a ninjutsu attack roll. If your attack roll is higher than theirs, you are not hit by the attack, instead sending it back at them. The pushed back attack deals the full damage it would have and any other effects that the jutsu you reflected dealt. You must cast this jutsu before the creature makes its attack roll. Raw Chakra Form: If you cast this justu within Raw Chakra Form, you have advantage on the Ninjutsu Attack Roll.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6c6c5e5f4dcd5a99547a9baf", name: "JET PROPULSION BARRAGE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "13 Chakra", components: "CM, M", duration: "Instant", description: "Hardening raw chakra over your body, your body grows thick scales. For the duration, your AC increases by +1 and when you would take non-psychic damage, reduce it by 6. If you are wearing medium armor, you reduce non-psychic damage by 4 instead. If wearing heavy armor, you reduce non-psychic damage by 2 instead. While you benefit from this jutsu, you have advantage on Constitution Saving Throws. Raw Chakra Form: When you are in your Raw Chakra Form and benefiting from this jutsu, you do not spend Chakra to concentrate on it.", at_higher_ranks: "For each rank above B-Rank you cast this jutsu, increase the cost by 3 and the Damage Reduction by 3. If wearing medium armor, increase it by 2 instead. If wearing heavy armor, increase it by 1 instead. 97 A-RANK OBLITERATION WARP CANNON", created_at: NOW, updated_at: NOW },
  { _id: "14c787ffb082a4cd3f9affe8", name: "WARP BEAM REFLECTION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, when a creature makes a Ninjutsu attack roll against you.", range: "Special", chakra_cost: "15 Chakra", components: "HS, CM", duration: "Instant", description: "With your bone weapon in hand, you stab forward at an increasingly chaotic pace fast enough to create the appearance of afterimages as each strike attempts to strike a slightly different part of the target from a slightly different angle. Make two melee taijutsu attacks. On a hit, you deal your [Weapons Damage] + 1d6. If at least one of these attacks hits a creature, the target must make a Strength saving throw, being knocked prone on a failed save and you can move 10 feet into any direction of your choice.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at B-Rank or higher, on a failed save the target is also pushed 10 feet in any direction of your choice. If this jutsu is cast at S- Rank, this jutsu’s casting time can be 1 Reaction that you take when a creature triggers your attack of opportunity.", created_at: NOW, updated_at: NOW },
  { _id: "55739cae19743485c055c144", name: "TOUGHENED FOREST (NEW)", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You extract bones to a greater degree, allowing them to stick out in a variety of positions, creating a makeshift lethal but protective armor. You gain 12 temporary hit points. If a creature hits you with a melee attack while you have these hit points, the creature takes 8 piercing damage that pierces DR.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points and piercing damage by +8. DANCE OF BULLET SEEDLINGS", created_at: NOW, updated_at: NOW },
  { _id: "3e2d65f01c809b863d5d012c", name: "OBLITERATION WARP CANNON", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Full Turn Action", range: "Self (90-foot cone)", chakra_cost: "21 Chakra", components: "HS, CM, M", duration: "Concentration, up to 1 Minute", description: "With your Bone Weapon in hand, you strike with a flurry of focus and grace befitting of the weapons chosen striking preference. Make 2 melee taijutsu attacks, dealing this [Weapons Damage]. On a hit, the target must make a Constitution saving throw. On a failed save, based on the damage type of your weapon this jutsu inflicts a different condition. • Bludgeoning. +1 rank of Bruised. • Piercing. +1 rank of Weakened. • Slashing. +1 rank of Bleeding.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage you deal by 1d6. C-RANK", created_at: NOW, updated_at: NOW },
  { _id: "9c89a19e0644c4a2fb394671", name: "DANCE OF THE CAMELLIA [CHANGED]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "M, W (Any Bone Weapon)", duration: "Instant", description: "With your bone weapon in hand, you stab forward at an increasingly chaotic pace fast enough to create the appearance of afterimages as each strike attempts to strike a slightly different part of the target from a slightly different angle. Make two melee taijutsu attacks. On a hit, you deal your [Weapons Damage] + 1d6. If at least one of these attacks hits a creature, the target must make a Strength saving throw, being knocked prone on a failed save and you can move 10 feet into any direction of your choice.%At Higher Ranks@For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at B-Rank or higher, on a failed save the target is also pushed 10 feet in any direction of your choice. If this jutsu is cast at S- Rank, this jutsu’s casting time can be 1 Reaction that you take when a creature triggers your attack of opportunity.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6. If this jutsu is cast at B-Rank or higher, on a failed save the target is also pushed 10 feet in any direction of your choice. If this jutsu is cast at S- Rank, this jutsu’s casting time can be 1 Reaction that you take when a creature triggers your attack of opportunity.", created_at: NOW, updated_at: NOW },
  { _id: "ca41697aad43a344cfb178b1", name: "DANCE OF THE LARCH [CHANGED]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "5 Chakra", components: "M", duration: "1 minute", description: "You extract bones to a greater degree, allowing them to stick out in a variety of positions, creating a makeshift lethal but protective armor. You gain 12 temporary hit points. If a creature hits you with a melee attack while you have these hit points, the creature takes 8 piercing damage that pierces DR.%At Higher Ranks@For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points and piercing damage by +8.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points and piercing damage by +8.", created_at: NOW, updated_at: NOW },
  { _id: "86c9816918bf77971ca73dfe", name: "DANCE OF BULLET SEEDLINGS [CHANGED]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "45 feet", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "You outstretch a free hand and fire off the bones in your fingers like bullets with enough force to tear through armor and flesh like paper. You fire a collection of bone bullets. You can select up to three creatures within range that you can see. Make a single ranged taijutsu attack, comparing the result against the selected creatures AC. On a hit, a target takes 5d4 Piercing damage.%Lust for Battle. You gain +2 in Strength and Dexterity saving throws and the last creature that dealt damage to you, takes additional damage from you equal to your proficiency bonus, twice per turn.%At Higher Ranks@For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 the damage by 2d4 and the number of creatures you can target by +1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 the damage by 2d4 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "615a3bca7001b153c0923793", name: "DANCE OF THE KATSURA [CHANGED]", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "M, W (Bone Weapon)", duration: "Instant", description: "With your Bone Weapon in hand, you strike with a flurry of focus and grace befitting of the weapons chosen striking preference. Make 2 melee taijutsu attacks, dealing this [Weapons Damage]. On a hit, the target must make a Constitution saving throw. On a failed save, based on the damage type of your weapon this jutsu inflicts a different condition.%• Bludgeoning. +1 rank of Bruised.%• Piercing. +1 rank of Weakened.%• Slashing. +1 rank of Bleeding.%At Higher Ranks@For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage you deal by 1d6.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage you deal by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "136e9576457dad7f140cab2f", name: "DANCE OF THE WILLOW [CHANGED]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "Reaction, which you take when you would take damage from a melee attack.", range: "Weapons Range", chakra_cost: "8 Chakra", components: "M, W (Bone Weapon)", duration: "Instant", description: "As a reaction to being hit you twirl, spin, and gracefully retaliate against your attacker. Make a melee taijutsu attack vs the triggering creature. On a hit you deal your [Weapons damage] + 1d8 and can move up to 10 feet in any direction of your choice. At the conclusion of your attack as a result of this jutsu, you gain an additional reaction which can only be used to cast this jutsu.%At Higher Ranks@For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8 for each hit.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8 for each hit.", created_at: NOW, updated_at: NOW },
  { _id: "bd8f89e5e0ca65d4f158a66a", name: "DANCE OF THE SETSUGEKKA", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "Special", range: "Special", chakra_cost: "9 Chakra", components: "M, W (Bone Weapon)", duration: "Concentration, up to 1 minute", description: "When you would strike a creature, you leave behind a small bone fragment inside of them that you then cause to grow and expand.%As a part of the same action used to cast another Kaguya clan Hijutsu that deals damage to a creature, you can cast this jutsu forcing them to make a Constitution saving throw. On a failed save you leave behind the bone fragment. On a success you are unable to leave it behind.%A creature who failed their Constitution saving throw begins to experience their internal organs being stabbed by the growing bone mass, taking 3d8 Necrotic damage that ignore damage reduction.%For the next minute the affected creature remakes this saving throw at the beginning of each of its turns taking 3d8 Necrotic damage on a failed save or no damage on a success.%A creature can attempt to dig out this fragmented bone from them by making a Strength (Medical) check vs your Taijutsu Save DC, forcibly removing it on a success. A creature can only be under the effects of this jutsu once at any given time.%At Higher Ranks@For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If cast at A-Rank increase the damage by 1d8.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If cast at A-Rank increase the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "af1c677a02e33a36c54ca65d", name: "TEN-FINGER DRILLING BULLETS [CHANGED]", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "8 Chakra", components: "CM", duration: "Instant", description: "You clasp your hands together pointing your fingers in any direction of your choice firing them all at once with enough of a combined force to rip through even chakra barriers. You finger bullets like a shotgun burst in a 30-foot cone originating from you.%All creatures in range must make a Dexterity saving throw taking 6d4 piercing damage and gains 2 ranks of Bleeding on a failed save or half as much damage and no additional effects on a success.%At Higher Ranks@For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 2d4.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "706528aa1ee13ab1218a01d1", name: "DANCE OF CLEMATIS: FLOWER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "14 Chakra", components: "M, CM", duration: "Instant", description: "You pour chakra into your arm, over- calcifying it creating a large drill shaped bone that covers the lower half of your arm starting at your elbow.%You dash as your full movement in a straight line stopping at the first creature you encounter. Make a melee taijutsu attack against the creature dealing 7d10 piercing damage. This attack has a +2 bonus to its critical threat range.%At Higher Ranks@For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d10.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "20b2b51422f59f20b7f6c60e", name: "DANCE OF CLEMATIS: VINE [CHANGED]", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "M", duration: "1 minute", description: "You tear out your spine while also tripling its length and changing its structure by adding sharpened spikes to it. This becomes a modified Bone Weapon modeled after a whip. It uses the statistics of the whip weapon, but its damage die is 2d6 and it has the Reach 4 weapon property. Creatures grappled by this weapon cannot form Hand signs (HS).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a7f9f91ff755a1ed6602b890", name: "DANCE OF THE SEEDLING FERN [CHANGED]", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "20 Chakra", components: "CM", duration: "Instant", description: "The perfected and final dance of the Kaguya clan. The Sixth and final dance is also the most devastating and deadly. By means of this technique you focus and empower your bones before sending them through the ground around you, expanding them and having them rise like trees in a forest. Creatures in range other than you, must make a Dexterity saving throw taking 11d8 Piercing damage on a failed save, or half as much on a successful one.%The bone forest remains for 1 minute after casting this jutsu. The bone pillars are 10 to 15 feet tall and occupy a portion of each space in range. Creatures moving within the affected area must spend 3 feet of movement for every 1 feet traveled (5 traveled costs 15 feet of speed). You can fuse into and teleport freely throughout the bone forest, up to twice per turn. Bone pillars have 45 hit points. If a bone pillar takes damage while you’re inside, you take any remaining damage the bone pillar could not. At the end of the 1-minute duration after this jutsu", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7efe613cf7c171042e23860e", name: "VULGAR MOCKERY", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "This is a unique variant of \"Vicious Mockery\". You unleash an aggressive assault of profane insults towards a creature in range, if the target can hear you, it must make a Wisdom saving throw.%Success@The target takes no damage and suffers no additional effects.%Failure@The target takes 4d6 psychic damage and has disadvantage on the first attack it makes until the end of its next turn.%Critical Failure@Same effects as a failure, but the target suffers disadvantage on all attacks it makes until the end of its next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f990e2aa3787b1d5914b6505", name: "AMPED SHOT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM, W (Auditory Ninja Tool)", duration: "Instant", description: "You focus your chakra into your Auditory Ninja Tool to unleash a powerful sound wave at an enemy. Make a ranged Genjutsu attack. On hit the target takes 3d8 + your Genjutsu ability modifier in psychic damage and must succeed a Wisdom saving throw or gain 1 rank of Disorientation.%At Higher Ranks@For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to C-Rank or higher, increase the damage die of this or higher, increase the number of attacks made by +1. If cast to A-Rank or higher, increase the damage die of this jutsu by 1 step, to a maximum of a d12. If cast to S-Rank, increase the number of attacks made by +1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to C-Rank or higher, increase the damage die of this or higher, increase the number of attacks made by +1. If cast to A-Rank or higher, increase the damage die of this jutsu by 1 step, to a maximum of a d12. If cast to S-Rank, increase the number of attacks made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "52cb77cfc427254dbe169691", name: "PSYCHIC ENHANCEMENT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, W (Auditory Ninja Tool)", duration: "Concentration, up to 1 Minute", description: "You enhance the power of your Auditory Ninja Tool by focusing your chakra through it, it resonates with a deadly tune. Attacks with your Auditory Ninja Tool use your Genjutsu ability modifier for attack rolls. Creatures hit by your Auditory Ninja Tool take 3d4  + your Genjutsu ability modifier psychic damage and, once per round, must make an Intelligence saving throw gaining 1 rank of Disorientation on a failed save.%At Higher Ranks@For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage die by 1 step (d4>d6>d8>d10>d12). If cast to B-Rank or higher, this jutsu’s duration becomes 10 min.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage die by 1 step (d4>d6>d8>d10>d12). If cast to B-Rank or higher, this jutsu’s duration becomes 10 min.", created_at: NOW, updated_at: NOW },
  { _id: "205af9af9dfe0f64fe97512c", name: "SONIC RUPTURE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Bonus Action", range: "60 feet", chakra_cost: "5 Chakra", components: "CM, W (Auditory Ninja Tool)", duration: "Instant", description: "This is a unique variant of \"Vicious Mockery\". You unleash an aggressive assault of profane insults towards a creature in range, if the target can hear you (Though it need not understand you), it must make a Wisdom saving throw.%Critical Success@The target takes no damage and loses all ranks of Disorientation.%Success@The target takes no damage and suffers no additional effects.%Failure@The target takes Xd6 psychic damage on a failure, where X = 1 + the ranks of Disorientation the target has.%Critical Failure@The target the target takes Xd6 psychic damage on a failure, where X =2 + twice the ranks of Disorientation the target has.%At Higher Ranks@For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage of this jutsu by 1 step (d4>d6>d8>d10>d12). If this jutsu is cast at S-Rank the target also gains the Deafened condition until they remove all ranks of Disorientation.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage of this jutsu by 1 step (d4>d6>d8>d10>d12). If this jutsu is cast at S-Rank the target also gains the Deafened condition until they remove all ranks of Disorientation.", created_at: NOW, updated_at: NOW },
  { _id: "2d75fbe1707a76173c218986", name: "HYPNOTIC MUSIC", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "120 feet (20-foot radius)", chakra_cost: "8 Chakra", components: "CM, W (Auditory Ninja Tool)", duration: "Concentration, up to 1 Minute", description: "This is a unique variant of “Hypnotic Patterns”. You play an enchanting song that captivates those in a 20-foot radius sphere originating on a point in range, and causes them to dance like no one is watching.%Each creature in the area who hears this song must make a Wisdom saving throw.%While charmed by this jutsu, the creature cannot hear anything besides the music being made by the genjutsu.%Critical Success@This jutsu’s effects end on the target and they have advantage on their next saving throw against this jutsu within the next 10 minutes.%Success@No effects, and this jutsu ends on the target.%Failure@The creature is Charmed and Restrained, enraptured by the music. The target may remake this saving throw to end this jutsu’s effects at the end of each of their turns. This jutsu’s effects end immediately if the take damage or are knocked prone.%Critical Failure@Same effects a failure, but the target is also Incapacitated for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "16265d17b8fb8f0255f52426", name: "FORCEFUL INTERROGATION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 10 Minutes", description: "You reach into the mind of your target, latching onto the most delicate parts of their brain speaking an incomprehensible language, compelling them to spill their cuts.%Select a creature in range, the target must make a Charisma saving throw, on a failed save, whenever they are asked a question, they must answer completely and truthfully, otherwise they take 7d4 psychic damage and gain 1 rank of disorientation.%A creature under the effects of this Genjutsu remakes their saving throw each time they respond to a question.%If the creature answers truthfully, they make the save at advantage. If they lie or refuse to answer, they instead make the save at disadvantage.%At Higher Ranks@For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d4.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "6cb4a5500cb35d33db5f104a", name: "PSYCHIC INTERRUPTION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Reaction, which you take when a creature within range would cast a jutsu with the HS component", range: "60 feet", chakra_cost: "5 Chakra", components: "CM, W (Auditory Ninja Tool)", duration: "Instant", description: "When you see a creature attempt to weave hand seals for their jutsu, you release a sound wave in response attempting to disturb them. Target creature must make a Wisdom saving throw, losing the ability to weave hand seals until the start of their next turn and gaining 1 rank of Disorientation on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bf596acd39bc6c594864116d", name: "TRIO REQUIEM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Full Turn Action", range: "10 Feet", chakra_cost: "Special (15 Chakra)", components: "HS, CM, CS, W (Auditory Ninja Tool)", duration: "10 Minute", description: "You summon 1 of 3 legendary Doki to your aid. Doki can be controlled on your turn using your bonus action while equipped with your Auditory Ninja Tool.%As a Bonus action on your turn, you can dismiss all summoned Doki. If a Doki is reduced to 0 Hit Points it unsummons, and you cannot summon the same Doki until you complete a full rest. Additionally, you can not summon the same Doki more than once per long rest and you cannot have more than one of the same Doki summoned at a time.%While your Doki is within 5 feet of an ally, and that ally is targeted by an attack, you can use your reaction to command the Doki to interpose the attack, becoming its new target.%Some Doki abilities may require a saving throw, in which case the DC is equal to your Ninjutsu or Genjutsu Save DC.%At Higher Ranks@For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 5 and the number of Doki summoned by 1. You cannot summon more than 1 of the same Doki this way", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 5 and the number of Doki summoned by 1. You cannot summon more than 1 of the same Doki this way", created_at: NOW, updated_at: NOW },
  { _id: "9e16918ad3f83d529028db27", name: "AMPED WAVE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "11 Chakra", components: "CM, W (Auditory Ninja Tool)", duration: "Concentration, up to 1 Minute", description: "You flow chakra through your Auditory Ninja Tool, enhancing its sounds with terrifying melodies. Genjutsu you cast with the Auditory Keyword reduce their Critical Fail range by 2. This does not stack with other effects that would reduce your Critical Fail range.%At Higher Ranks@For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the Critical Failure range by 1.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the Critical Failure range by 1.", created_at: NOW, updated_at: NOW },
  { _id: "1179f60f0cd1e8d99b27f523", name: "CHAINS OF PHANTASIA", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius sphere)", chakra_cost: "25 Chakra", components: "CM, W (Auditory Ninja Tool)", duration: "Instant", description: "You play a demonic sound, creating a dark hellscape where only pain and suffering exist for all those under the effects of this genjutsu. All creatures within range must make a Wisdom save.%Critical Success@The target suffers no effects and is immune to this genjutsu for the next 24 hours.%Success@The target takes no damage and suffers no additional effects.%Failure@The target takes 10d8 Psychic damage, and is restrained as threads wrap around them.%Critical Failure@The target takes 10d8 Psychic damage, and is restrained and cannot take actions as threads wrap around them.%Creatures under the effects of this genjutsu are Blind and Deaf to all other creatures outside the caster. At the end of a creatures turn they may remake the save to end the effects of this genjutsu on themselves otherwise taking an additional 10d8 damage. If a creature under the effects of this genjutsu takes any damage besides psychic damage, they immediately remake the save at advantage. If a creature has 0 chakra, this jutsu instead", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2b8c170b16b799b0503a1e80", name: "NEON MARKER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You cover your hand with neon lightning up the area around you, before quickly striking a creature within range. Make a Melee Ninjutsu Attack against a creature within range. On a hit, the target takes 3d6+3 lightning damage and the target creature sheds bright light in a 20-foot radius and dim light for an additional 20 feet for 1d4 rounds. The light can be colored as you like.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 2d6+2 and die which determines the number of rounds the target is lit increases by 1 step. (1d4>1d6> 1d8>1d10>1d12)", created_at: NOW, updated_at: NOW },
  { _id: "433b75731e0715bbe260f29a", name: "PLASMA BEAM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create and shoot out a Plasma beam from your fingertip, piercing and cauterizing whatever it goes through. Make a Ranged Ninjutsu attack roll against a creature in range, dealing 2d8+2 fire damage on a hit.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 1d8+2 and you can make one additional attack against another creature within range.", created_at: NOW, updated_at: NOW },
  { _id: "1fbdb7383acbec27bf55e9b2", name: "PLASMA SWALLOW", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, W(Any)", duration: "1 Minute", description: "A chakra flow technique where the user flows plasma through their weapon. You send continuous arcs of plasma through your blade. For the duration of this jutsu, your weapon deals an additional 1d8 fire or lightning damage on a hit, twice per turn. While this jutsu is active, you ignore the HS component for your Keton Hijutsu and are considered a source of bright light in a 30-foot radius. When you land a hit with your weapon, you can spend up to your remaining Energy Die, adding them to the damage dealt and producing 10 feet of bright light per die spent in the affected space until the start of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B rank, increase the damage by 1d8. If this jutsu is cast at S-Rank, increase the damage die by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "85dc8da20d443cafdcf2da72", name: "NEON FLASH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Reaction, which you take when you are targeted by an attack", range: "Self (10-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "When you would be targeted by an attack or jutsu you unleash a wave of bright light to disorient your opponent. All creatures within 10 feet of you must make a Dexterity saving throw. On a failed save, creatures take 2d8+2 fire damage and are Blinded until the start of your next turn. On a successful saving throw, creatures take half damage and suffer no further effects. Against all non-blinded creatures, you treat your AC as +3 higher until the start of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6d35411fd4f80de5a999d23c", name: "SPARKLER CHAIN EXPLOSION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You summon two orbs of plasma and throw them at different places producing a series of bright explosions. Each creature in a 10-foot-radius sphere centered on each point you choose must make a Dexterity saving throw. A creature takes 3d6+3 fire damage on a failed save, or half as much damage on a successful one. A creature in the area of more than one explosion is affected a maximum of twice.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d6+1, and the amount of explosions by +2.", created_at: NOW, updated_at: NOW },
  { _id: "9912e3a5f7cd56aba369d39b", name: "NOVA", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "90 feet (30-foot Sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You create an orb of Plasma chakra in your hands before throwing it at a point centered in range. This orb then erupts into an explosion of plasma. All creatures within 30 feet of the target location must make a Dexterity Saving Throw, taking 4d10+4 lighting damage and gaining 1 rank of shocked or burned (caster's choice) on a failed save, or half damage and no effects on a success. Following the explosion, the center of the explosion is a source of bright light in a 30-foot radius and dim light for an additional 30 feet for 1 minute. The light can be colored as you like. At Higher Ranks: For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d10. If this jutsu is cast at A rank or higher, creatures who fail the saving throw are affected by both conditions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "818b4306bb9702434af09f23", name: "PROJECTED CHAOTIC EXPLOSION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (45-foot cone)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You create an orb of plasma and project its energy forwards causing a series of colorful explosions. Each creature in a 45-foot cone must make a Dexterity saving throw. A creature takes 5d10+5 fire damage on a failed save, or half as much damage on a successful one. Following the explosion, the entire area of the jutsu shines a dim light for 20 feet for 1 minute. The light can be colored as you like.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10+1, and the range by 5ft.", created_at: NOW, updated_at: NOW },
  { _id: "59a83f90d08ef74ed67cad2a", name: "NEON STEP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You transform your entire body into Neon. Your movement speed is doubled, ranged attacks have disadvantage to hit you, and you may use your reaction to teleport to a source of bright light if that source of light is within a range equal or less than your movement speed away from you. Doing this causes this jutsu to end and the light source to dissipate.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3. If this jutsu is cast to A-Rank or higher, using the special reaction granted by this jutsu no longer automatically ends it the first time you use this reaction per casting. If this jutsu is cast to S-Rank, your movement speed is instead tripled.", created_at: NOW, updated_at: NOW },
  { _id: "f4f855d7427c6b60394e6284", name: "CHAOS RISING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 chakra", components: "HS, CM", duration: "Instant", description: "(This jutsu cannot score a critical hit.) You send plasma chakra into your limbs and prepare an assault on a target. Make 3 melee ninjutsu attacks on a target creature, dealing 3d8+3 fire damage and knocking them 10 feet into the air on each hit (You rise with the creature). If you hit with 2 or more attacks, the creature becomes Shocked until the end of their next turn. If you hit with all 3 attacks, the creature becomes burned for the same duration. At Higher Ranks: For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If cast to S-Rank, increase the damage by 1d8+1.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d42a9416f9db7b4ba2208486", name: "CHAOS DESTRUCTION WAVE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (120-foot line)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You cusp both hands, charging an orb of growing plasma before finally releasing it in a 120- footlong, 10-foot-wide line of destruction. All creatures within range must make a Dexterity saving throw, taking 9d10+9 lightning Damage on a failed save or half on a success. A creature with the burned condition makes this saving throw at disadvantage. Creatures who fail their Dexterity saving throw must make a Constitution saving throw at disadvantage, becoming burned, and becoming stunned the end of their next turn on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, and", created_at: NOW, updated_at: NOW },
  { _id: "557aed262111042cddd36725", name: "IMPERVIOUS ARMOR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Reaction, which you take when you are targeted for an attack, would take damage, or make a Strength or Constitution saving throw.", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Round", description: "You quickly turn your skin into a steel-like material before suffering a hostile effect. For the duration, you gain resistance to the triggering damage and gain 1d6+your Ninjutsu ability modifier in temporary hit points. These temporary hit points do not protect you from Lightning damage. You also gain advantage on Strength and Constitution saving throws for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hit points gained by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "738727656abebd249b6f2623", name: "STEEL PROJECTILE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create an object made of steel and launch it at high speed towards a target within range, make a ranged ninjutsu attack, dealing 3d10 + your Ninjutsu ability modifier in [X] damage on hit and reducing the result of their next saving throw by 1d4.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to B-Rank or higher, increase the number of attacks made by +1. If cast to S-Rank, increase the number of attacks made by +1. The saving throw reduction does not stack.", created_at: NOW, updated_at: NOW },
  { _id: "8549f0780fec01a597c0a0bf", name: "STEEL TELEKINESIS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You are able to command Steel from long ranges. You can lift objects made of or connected to steel of Medium size or lower. You can even use this to lift and move creatures wearing armor. You select 1 target creature within range wearing armor made of metal, forcing them to make a Strength Saving throw. On a Failed Save they are restrained and moved up to 30 feet in any direction of your choice. On future turns if they are still restrained you can use your bonus action to move them up to 30 ft in any direction of your choice. A creature can attempt to remake the Strength Saving throw at the end of each of their turns to end being restrained.", at_higher_ranks: "For each rank for each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by 1.", created_at: NOW, updated_at: NOW },
  { _id: "23897549c701d545081744c1", name: "STEEL RAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest numerous thrown weapons such as Shuriken or Kunai at a point within 60 feet and unleash all of them upon all targets within a 15-foot sphere. All creatures within range must make a Dexterity saving throw, taking 3d8 [X] damage and gaining one rank of a specified condition on a failed saving throw, or half damage and no effects on a successful saving throw. The condition gained depends on the damage type of this jutsu (Bludgeoning/Earth=Bruised, Slashing=Bleeding, Piercing=Weakened).", at_higher_ranks: "For each rank for each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d8. STEEL RELEASE: STEEL SHIELD TECHNIQUE", created_at: NOW, updated_at: NOW },
  { _id: "6673ce89fb1a86fb83b3637f", name: "Steel Shield Technique", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Reaction, which you take when you or an ally are targeted by an attack or would take damage.", range: "15 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 Round", description: "You intercept an attack targeting you or an ally in range with a steel wall. This wall is a construct, and is 10 feet tall, 15 feet wide, and 5 feet thick. This wall appears right before the attack hits you or your ally, intercepting all damage and effects. This wall has 7d6 hit points, an AC equal to your Ninjutsu Save DC, and reduces all damage received by -5 (excluding lightning damage). The wall also provides half cover to all creatures within 5ft. If the damage the wall receives exceeds its hit points, the originally targeted creature takes any remaining damage and effects. This wall does not disappear at the beginning of your next turn, instead remaining as a structure unless destroyed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the hit points of the wall by 2d6, the width by 5 feet, and the height by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "c4379f62bb119114d72c1754", name: "STEEL SPEAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure a massive spear made of steel before sending it flying towards a target within range, make a ranged ninjutsu attack, dealing 6d8 [X] damage. If you score a critical hit with this jutsu’s attack roll, the steel spear splinters and explodes, tripling the damage dice, instead of doubling them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 2d8, and this jutsu bonus to critical threat range by +1.", created_at: NOW, updated_at: NOW },
  { _id: "82ebae7fda3e7d08a120c80f", name: "STORM OF STEEL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute.", description: "You create a massive quantity of steel weapons above you in a 30-foot radius. All hostile creatures that start their turn or enter this area for the first time on their turn must make one of the following saving throws based on your selected damage type between Bludgeoning, Piercing, or Slashing damage with your Weapon Formation feature. On a successful saving throw, creatures take half damage and no effects. • Bludgeoning (Constitution): On a failure, creatures take 4d10 bludgeoning damage and are Dazed. • Piercing (Strength): On a failure, creatures take 6d6 piercing damage and are grappled for the duration. • Slashing (Dexterity): On a failure, creatures take 5d8 slashing damage and are Lacerated.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10/1d6/1d8 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "8e19002e3552d3182c1f617c", name: "STEEL SUIT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You wrap a thin sheet of metal around your body to greatly increase your defensive capabilities. You cannot lose concentration on this jutsu as a result of damage. For the duration of this Jutsu you gain 10d10 Temp hit points. These Temporary Hit points reduce any damage taken by -5 excluding lightning damage. Also, while you have temporary Hit Points granted by this jutsu you are counted as a Quake Shard and deal +2d10 additional damage on all unarmed and melee weapon attacks, twice per turn. When the temporary Hit Points provided by this jutsu reach 0 the jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the temporary hit points by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "a4ef8a1e51f2101b23c2727c", name: "BINDING METAL CHAINS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "90 feet (20-Foot Radius)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You focus your chakra deep underground creating a huge amount of steel before dozens of steel chains launch outside of the surface attempting to restrain those you command them to. Each creature within range that you select must make a Dexterity saving throw. On a failed save the target takes 4d8 [X] damage and is restrained by your chains. For the remainder of the Jutsu if a creature enters the range of your chains or starts there turn in the range of the chains while not already being restrained by the chains you may choose for them to make a Dexterity saving throw or become restrained and take 4d6 [X] damage. A creature can attempt to stop being restrained by the chains by making a Strength Saving throw at the end of each of their turns to end being restrained. The area taken up by the chains is counted as difficult terrain.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the radius by 10 feet and the damage by 2d8 and 2d6 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "9729087d709c84bc79687a3b", name: "METAL PRISON", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Permanent", description: "You constrict and bind a creature with metal, choose one creature in range, they must make a Strength saving throw, being Restrained by the metal prison. While restrained this way, the creature has full cover, and if they attempt to cast a jutsu with the HS component, they must succeed a Ninshou check at disadvantage against your Ninjutsu Save DC or else the jutsu fails to be cast and the chakra is wasted. The metal prison has an AC equal to your Ninjutsu Save DC and 120 Hit Points. The metal prison is resistant to all damage excluding lightning damage. A creature can attempt to remake the Strength Saving throw at the end of each of their turns to end being restrained. Each time a creature fails the Strength saving throw the DC", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a2c54433aec30a86321662f2", name: "DARK ISOLATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 Minute", description: "As part of the activation of this jutsu, you must have the Kurugan class feature active. Using the abilities granted by your Kurugan, you begin to summon a tangible manifestation of loneliness to cloak the target, dragging it into a void of pure isolation. Select one creature you can see within range. All creatures allied to the target within 60 of it, must make a Wisdom saving throw. Success: Affected creatures resist this jutsu’s effects, being able to see their ally Failure: Creatures allied to the target can no longer see them. They are still aware they are present, but are unable to interact with them. Critical Failure: Same as failure, but they forget the target exists for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "33ed747dbad7df073d3640e2", name: "DARK DEVOTION FIST", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "5 Feet", chakra_cost: "4 Chakra", components: "M, CM", duration: "Concentration, up to 1 minute", description: "Your fists and feet erupt into fiery black chakra as you fuse your attacks with the power of false molding. For the duration, you can use your Wisdom as your Taijutsu ability score when casting a Taijutsu. Additionally, [Unarmed Damage] die becomes 2d6 and deals Necrotic damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "302db0667640e543ac75b24c", name: "PIERCE THE VEIL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Special", description: "As part of the activation of this jutsu, you must have the Kurugan class feature active. Also, you cannot lose concentration on this jutsu as a result of failing a concentration check. By focusing your chakra into your eyes, you are able to pierce the veil far more accurately. For your Kurugan’s duration, you gain the following benefits; • You can calculate your AC with Wisdom instead of Dex. • When you use your bonus action Kurugan feature, the target of your next attack roll, cannot gain the benefits of a Reaction that grants them a bonus to AC. • By spending 1 minute focusing, you can immediately cast Sealing Art: Divination Technique at half of its listed cost ignoring the HS, CM, CS components. Additionally, you can cast Sealing Art: Divination Technique in this way twice per casting of this jutsu ignoring the limitation of seeing into the future as listed in the jutsu itself, once per long rest.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "665e62467849b4bc54cdb907", name: "SPIRALING DARK WALL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "Reaction, which you take when you would take damage.", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Round", description: "A Spiraling wall of black chakra appears to protect you. Until the start of your next turn, you gain a  +3 bonus to AC and 8 DR (damage reduction) including against the triggering attack. Also, you gain immunity to Psychic damage vs Genjutsu with the Visual, Auditory and/or Tactical keywords. This doesn’t affect Genjutsu with Inhale.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and DR by +4.", created_at: NOW, updated_at: NOW },
  { _id: "a5a806d9f9018bbc78505930", name: "DARK WAVE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b7c3bde363176d05f69f793a"], elements: [], casting_time: "1 Action", range: "Self (60-feet)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "A line of spiraling black chakra 60 feet long and 5 feet wide emanates from you in a direction you choose. Each creature in range must make a Charisma saving throw. On a failed save, creatures take 4d8 Necrotic damage and gain 1 rank of Concussed as they begin to rapidly age and revert back to their normal age suffering shock, or half as much damage on a pass.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "dced8f328e129ad7728fabb3", name: "DARK DRAIN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Action", description: "Dark chakra washes over a creature you strike, draining vitality from it. Make a melee Ninjutsu (or Taijutsu) attack dealing 4d10 necrotic damage. If the target creature has Temporary hit points you first drain all temporary hit points they have, gaining them as temporary hit points for yourself. Then, you gain hit points equal to half the necrotic damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "2e771734879c5730002420a7", name: "DARK BLADE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Your entire arm erupts into black shadowy chakra that extends into a shadowy blade. This chakra sword lasts until the Jutsu ends. It counts as a simple melee weapon with which you are proficient. It deals 3d8 necrotic damage on a hit and has the finesse, light, and thrown properties (range 20/60). In addition, when you use the weapon to attack a target in dim light or darkness, you make the attack roll with advantage. If you drop the weapon or throw it, it dissipates at the end of the turn. Thereafter, while the jutsu persists, you can use a bonus action to cause the weapon to reappear covering your hand.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1779707ffebbea068daf3bfd", name: "DARK RIFT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 Minutes", description: "You attempt to send one creature that you can see within range into a pocket dimension made entirely of imaginary chakra. The target must make a Charisma saving throw. On a failed save, the targets consciousness is banished into a dimension of fiction seeing only what you want them to see. Their body is left behind as it becomes Stunned for the duration and is treated as a vegetable until their consciousness returns. If a creature affected by this jutsu is classified as an Elite or Solo they make their saving throw at advantage. A creature who fails this saving throw, while unaware of what is happening to their body, if they would take damage they remake their saving throw for each instance of damage taken. If the targets mind must remain there for the entire duration of the jutsu, when they return, their mind suffers a shocks from the shift of illusion back to reality taking 10d10 psychic damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b899d87f59fcbea7a50ab7e3", name: "DARK CONTINGENCY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "10 Minutes", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "10 Days", description: "Choose a jutsu of B-Rank or lower that you can cast, that has a casting time of 1 action, and that can target you. You cast that jutsu—called the contingent jutsu—as part of casting contingency, expending chakra for both, but the contingent jutsu doesn’t come into effect. Instead, it is stored in a chakra seal on your person and takes effect when a certain circumstance occurs. You describe that circumstance when you cast the two jutsu. For example, a contingency cast with sensing technique might stipulate that sensing technique comes into effect when you are immersed in a cloud of fog or other obscuring vapor. The contingent jutsu takes effect immediately after the circumstance is met for the first time, whether or not you want it to, and then contingency ends. The contingent jutsu takes effect only on you, even if it can normally target others. You can use only one contingency jutsu at a time. If you cast this jutsu again, the effect of another contingency jutsu on you ends. It also ends if the chakra seal is ever removed from you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c20dd93d94e63b9d97835c3e", name: "UNFETTERED FORESIGHT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "1 Minute", description: "(As a part of the casting of this Jutsu you must have the Kurugan active.) You release all limiters on your Kurugan, allowing you to freely see all possible events pertaining to you, filtering through thousands of possible futures. For the duration of your Kurugan, you cannot be surprised by anything, your skill checks & saving throws have advantage. All other hostile creatures have disadvantage on attack rolls against you for the duration. You always know what time it is, and the exact moment a minor event will happen, such as a bell ringing, or someone’s name being called in your vicinity. Additionally, you can, as an action touch one creature you can reach, and peer into their immediate future, casting Sealing Art: Divination Technique at no cost ignoring the HS, CM, CS components, allowing you to see their future. If you have Pierce the Veil active, your Kurugan features have no use limit for the duration. At the conclusion of this jutsu, you expend all uses of your Kurugan features until you complete a long rest.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ead3a3c202ff8afceb4db3fb", name: "DARK DISPLACEMENT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Instant", description: "(As a part of the casting of this Jutsu you must have the Kurugan active.) By focusing the chakra used to peer into the future you are able to grab ahold of the power of temporal shifts focusing it around your hands. Doing this ages your arm faster than your body, ever- so-slightly. Make a melee Ninjutsu or Taijutsu Attack against a target you can see in range. On a hit you deal 9d10 Necrotic Damage to the target creature. The target must make a Charisma saving throw, reducing their maximum hit point by half of the damage dealt. If a targets maximum Hit points reach 0, they age to dust being unable to be revived by any means. A creature can restore the maximum hit point value by casting a Ninjutsu with the Medical keyword that removes", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "89f09f42b446e28b2f873ff2", name: "EXPEDIENCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, M", duration: "Concentration, up to 1 minute.", description: "You focus your chakra, granting yourself immense speed. This allows you to act faster than almost anyone else on the battlefield. For the duration you can use one of the listed effects once per turn at no action cost on your turn. You can benefit from this Jutsu a number of times equal to your Ninjutsu Ability Modifier per casting[Min 1]. Evasive Maneuvers: Before the start of your next turn, the first attack made against you is made at Disadvantage and the first Dexterity Saving Throw you make is at Advantage. Deduce: Make a Perception or Investigation Check against the AC of a creature you can see. On a success, before the start of your next turn, the next attack you make targeting that creature has a +1 to its Critical Threat Range and the next Jutsu you cast increases its Save DC by +1 for the first saving throw it forces the creature to make.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cb312ce7dab87e987e244485", name: "MIRROR IMAGE TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "1 minute.", description: "You mold your Wind and Lightning Release Chakra into very convincing clones of yourself. Three clones of yourself appear in your space. Until the jutsu ends, the clones move with you and mimic your actions, shifting positions at hyper speed so it’s impossible to track which image is real. You can use your bonus action to dismiss the clones. Each time a creature targets you with an attack during the jutsu's duration, roll a d20 to determine whether the attack instead targets on of your clones. If you have three clones, you must roll a 6 or higher to change the attack's target to a clone. With two clones, you must roll an 8 or higher. With one clone, you must roll an 11 or higher. If the creature that targets you has true sight or tremor sense, you make this roll with disadvantage. A clone's AC equals 10 + your Dexterity modifier  + half your proficiency bonus. If an attack hits a clone, the clone is destroyed. A clone can only be destroyed only by an attack that hits it. It ignores all other damage and effects. The jutsu ends when all three clones are destroyed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7e454527f7e1568c1e0126c6", name: "PHASE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Reaction, which you take when you take damage or would make a Dexterity saving throw.", range: "Self", chakra_cost: "5 Chakra", components: "HS, M", duration: "1 round.", description: "Just before being hit by an attack, you vibrate fast enough to make most attacks harmlessly pass through you. Until the start of your next turn, you gain a +4 bonus to AC against attacks and advantage on Dexterity saving throws.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9830410ddfadfe075aa7759f", name: "AIR SHATTERING STRIKE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You mold and compress your Chakra around yourself and instantly strike out with it faster than the eye can see. Make a melee Ninjutsu attack roll against a target you can see within range. On a hit, the target takes 4d6 Wind damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 2d6 and you can make one additional attack against another creature within range.", created_at: NOW, updated_at: NOW },
  { _id: "9d97741b5584890fbe533a0c", name: "AURA OF QUICKNESS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (30-foot Sphere)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 Hour", description: "You extend your chakra creating a 30-foot radius bubble of chakra, that occasionally crackles with a soft yellow lightning. For the duration of this Jutsu, the aura moves with you, centered on you. Each Creature of your choice, that begins its turn within your aura has its speed increased by 15 feet until the end of their next turn. If used during exploration or land travel, you treat Normal Travel Pace as Fast Travel Pace, and you double Fast Travel Paces distances.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the in combat movement speed bonus by an additional 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "f3f1916ebab2f26a574d1b39", name: "SHADOWLESS FLIGHT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, M", duration: "1 round", description: "You imbue yourself with incredible speed, enhancing your physical form. Until the start of your next turn, once per turn, you can make an additional weapon or unarmed attack when you use your action to make at least one Taijutsu, weapon or unarmed attack. This additional attack ignores resistances, and if it is made against a target that used a Taijutsu or made a weapon attack as part of its last turn, you have advantage on the attack roll. Additionally, while this jutsu is active, you impose disadvantage on melee attacks against you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e4daba48f2f4f887d88c6bda", name: "THUNDER FLASH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (Special)", chakra_cost: "7 Chakra", components: "HS, M", duration: "1 round", description: "You focus Chakra into your legs and rush forward with explosive power. As a part of casting this jutsu, you move to the last unoccupied space in a 30-foot long, 10-foot-wide line from your starting position. This movement does not provoke opportunity attacks. Each creature you pass through during this movement must make a Dexterity saving throw, taking 6d6 Wind damage on a failed save, and half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 2d6 the distance you move by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "c01f7ec0d1f0b783bd878682", name: "FLASH STEP", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "HS, CM", duration: "1 minute.", description: "You focus your Chakra into your legs, granting you an immeasurable amount of speed, leaving the view of all until you’re prepared for your next move. You cannot lose Concentration on this Jutsu as a result of damage. Roll a d20 at the end of each of your turns for the duration of the jutsu. On a roll of 11 or higher, you vanish from your current location, moving at hyper speed. At the start of your next turn, and when the jutsu ends if you are still running, you return to an unoccupied space of your choice that you can see within 10 feet of the space you vanished from. If no unoccupied space is available within that range, you appear in the nearest unoccupied space chosen at random. You can dismiss this jutsu as an Action. While moving at hyper speed, your Chakra flow to your senses are slightly restricted. You can only see shades of gray, and you can’t see anything more than 60 feet away from the space you vanished. You can’t affect anything while in this state either.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1e1ed1666c8fe0f0325dde4e", name: "SPIRALING FLASH", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "13 Chakra", components: "HS, M", duration: "Instant", description: "You can briefly become faster than the eye can see as you go to strike a selection of targets. Select a number of creatures within range, up to an amount equal to your proficiency bonus. Make a melee Ninjutsu attack against each target. On a hit, a target takes 7d8 Wind damage. For every successful attack you make, you gain a +1 bonus to your next Saving throw or skill check, up to a maximum of +5, until the end of your next turn. Additionally, after all attacks have been made, you can then teleport to an unoccupied space you can see within 5 feet of one of the targets you hit or missed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5aaaa928fe5e72e55db57bb8", name: "SPEED SIPHON", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "Your mastery of Swift Release allows you to remove speed from one creature within range. Select a creature you can see within range. You begin to attempt to drain them of their movement and speed. Target creature, at the beginning of each of their turns, must make a Constitution saving throw. On a failed save, they gain 2 ranks of Weakened and Slowed. While the target is slowed or weakened in this way, the target cannot gain bonuses to speed by any means. The target also has disadvantage on all attack rolls, skill checks and saving throws except Constitution skill checks and saving throws, as its speed, reaction time, and movement ability to being taken away. Finally, if a target tries to cast a jutsu, it must first make a Constitution saving throw. On a failed save the target fails the jutsu’s casting, and the Chakra is wasted as if they cast the jutsu. A target suffering from this speed siphoning make a constitution saving throw at the end of each of its turns. On a successful save, they remove 1 rank of the Slowed or Weakened conditions, of their choice. The target gains an additional application of the slowed or weakened", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "90959e23bd03dff65c1d0fa5", name: "SHADOW IMITATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, to an ally being the target of an attack that you can see", range: "45 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Round", description: "As part of the requirements of this jutsu, you must know the Shadow Possession Jutsu. You manipulate your shadow and stretch it outwards, attempting to fuse your shadow with a willing creature. As a reaction, you grant the target creature your shadow is attached to a +2 to their AC and an advantage on Dexterity saving throws until the end of the current turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the AC Bonus by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e8f58be98811463212b4b771", name: "SHADOW NECK BINDING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "45 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "As part of the activation requirement of this jutsu, you must have a creature already restrained by the Shadow Possession, Shadow Imitation Field, Shadow Sewing Needle or Black Spider Lily Jutsu. As a Bonus action, creatures Restrained by any of the aforementioned jutsu, take 4d6 Necrotic damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "d0c113222082e90dedf1d184", name: "SHADOW SILHOUETTE DISTRACTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "45 feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must know the Shadow Possession Jutsu. By molding Chakra into your shadow, you are able to give it a shape as it stands up from the ground, but it retains an extremely thin width. Your shadow stands as tall as you and follows your every whim. It cannot grab or carry anything nor can it touch or interact. This jutsu is extremely useful for distractions and misdirection. This jutsu can be used from stealth without revealing your location and can also be used alongside a stealth roll.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4e7dbaf839891196f5c7e63e", name: "SHADOW POSSESSION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "Special (4 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 Minute.", description: "The famous Shadow possession of the Nara Clan allows the user to mold Chakra into their shadow, controlling it. Select one creature you can see within range. Target creature has to make a Dexterity Saving throw. On a failed save they are restrained for the duration of the jutsu and they cannot take actions. They make the exact same physical movements you make. You cannot make them attack themselves, nor can you make them cast jutsu of any type. They mirror your movements and gestures and nothing else. As an action on the affected creatures turn, they can make a Strength saving throw to end this Jutsu’s effect on them. The Shadow possession jutsu is unique in that it is most affected by the time of day and the amount of available light a Nara is in. In Dim Light, this Jutsu’s range is reduced by half. In complete darkness, this jutsu cannot be used.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the range of this jutsu by 15ft and creatures no longer make the exact same physical movements you make unless you want them to.", created_at: NOW, updated_at: NOW },
  { _id: "b42765d7acd81820213fd149", name: "SHADOW GATHERING", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "45 feet", chakra_cost: "6 Chakra", components: "CM", duration: "Concentration", description: "As part of the requirements of this jutsu, you must know the Shadow Possession Jutsu. You materialize thin tendrils of shadows that you can control to interact with objects. This jutsu can be used to slide under doors, through small holes, and other entrances that would otherwise be impossible to squeeze through. Make a DC 15 Ninshou Check to handle complicated objects like keyboards, door handles, or locks. This jutsu can also be used to retrieve items and pull them back to the user no heavier than 25 pounds.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "778cb2345a2abb74f3165d6a", name: "SHADOW IMITATION FIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "20-foot Radius on the ground.", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "As part of the requirements of this jutsu, you must have the Shadow Possession Jutsu. You expand your shadow in a 20-foot radius circle centering from you capturing all creatures within it who are on the same surface as you. All Creatures in the radius upon activation, must make a Strength saving throw, being restrained and being unable to take actions on a failed save for the duration. On an affected creatures turn, they can make a Strength saving throw to break free from this jutsu, ending its effect on them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the radius by 5ft.", created_at: NOW, updated_at: NOW },
  { _id: "2d76ef6b15030a6495047e81", name: "SHADOW SEWING NEEDLE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 Feet.", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must know the Shadow Possession Jutsu. You materialize your shadow but splinter and sharpen them into needle-like spikes. You create 5 needle-like threads of shadow. Make a single ranged ninjutsu attack against up to 5 target creatures within range, once each. On a hit, you deal 2d6 piercing damage. You can choose to send more than one tendril towards a single creature. If you do, increase the damage of your attack by 1d6 for each additional tendril targeting them. Regardless of the number of tendrils targeting a single creature, you only ever make a single ranged ninjutsu attack per creature targeted. On a successful hit, affected creatures must make a Strength saving throw. For every two tendrils targeting the same creature, increase the initial save DC by +1. On a failed save they fall under the effects of the Shadow Possession Nara Clan Jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of tendrils by 1.", created_at: NOW, updated_at: NOW },
  { _id: "4f5fd2e63fb453fa0b45e9bb", name: "BLACK SPIDER LILY", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must know the Shadow Possession Jutsu. This is an advanced version of the “Shadow Possession” jutsu. Select up to 8 Creatures within range, each creature must make a Dexterity saving throw. On a failed save the target is restrained and counts as being under the effect of the Shadow Possession Nara clan Hijutsu of equal rank to this Jutsu’s Casting.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and select 1 additional target creature in range.", created_at: NOW, updated_at: NOW },
  { _id: "b3a38104c8625a4453ff4223", name: "SHADOW TRANSPORT TECHNIQUE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "12 Chakra", components: "CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must have the Shadow Possession Jutsu. You can select a creature currently restrained by the Shadow Possession, Shadow Imitation Field, Shadow Sewing Needle or Black Spider Lily jutsu. You can fall into your shadow, moving through it and coming out within 5ft of a restrained target. You must still be in range of other creatures you have restrained, otherwise those jutsu immediately ends on those creatures.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "650429c282daac9150519215", name: "SHADOW WEB EXECUTION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "90 feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must know the Black Spider Lily Jutsu active and have at least 1 creature restrained by a Nara Clan Hijutsu. As a Bonus action, all creatures currently captured must succeed a constitution saving throw. On a failed save affected creatures take 12d8 Necrotic damage and suffer 1 rank of Exhaustion or half as much on a successful save and no further", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f4e0d4111194b20bd2d8e5d2", name: "LIGHTNING WHIP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You form a current of Water like Lightning in your hand, swinging it at a creature within range. Make a melee ninjutsu attack, dealing 5d6 Lightning damage on a ht. A creature who takes damage from this jutsu must succeed a constitution saving throw, gaining the shocked condition and reducing their movement speed by half on a failed save on a failed save. If you score a critical hit with this jutsu, the creature is restrained by the Lightning. A creature restrained in this way until the beginning of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "01ff34d76ce71de8f50b1089", name: "LASER BEAM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (30-feet line)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "(This jutsu cannot score a critical hit) You conjure a beam of lightning and water that bends around corners and piercing its targets with lethal efficiency. Make one ranged Ninjutsu attack against all creatures within a 30- foot line, comparing your attack roll result against each creature's AC (You do not make this attack at disadvantage if used within 5 feet of a target), dealing 5d6 lightning damage if your result matches or exceeds their AC. If a creature within range has the Shocked condition, this jutsu bends and shifts ignoring its normal Attack direction, and coiling and moving to target the shocked creature. This jutsu can target up to two shocked creatures this way.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "07e250989eb3bf2f2f9f53e5", name: "SECONDARY DISCHARGE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Reaction, which you take when you cast a Jutsu that deals Lightning Damage", range: "60 feet", chakra_cost: "Special (4 Chakra)", components: "HS, CM", duration: "Instant", description: "You empower the triggering jutsu, pouring more lightning chakra into it. It gains one of the following effects (Your choice). • Gain a +2 bonus to the triggering jutsu’s first attack roll. If this attack beats a creatures AC by 5 or more, you may make a second attack, with the same bonus, targeting a second creature, within the triggering jutsu’s range. • Gain a +1 bonus to the triggering jutsu’s Save DC. If a creature would fail the triggering jutsu’s save DC by 5 or more, they gain +1 rank of Shocked, and you may select one additional creature within 60 feet of you, forcing them to make the triggering jutsu’s saving throw as if they were in its radius or original target.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5105e8c110f6c768db001740", name: "THUNDER CLOUD INNER WAVE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action.", range: "Self (30 feet)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a thick ring of thunderclouds around yourself. For the duration, once per turn as an action or bonus action, you may Fire a jolt of Lightning from yourself targeting a space you can see within 30 feet of you. All creatures within 5 feet of the chosen space must make a dexterity saving throw taking 3d8 Lightning damage and gaining 1 rank of the shocked condition. Alternatively, once per round, if you haven’t used this Jutsu’s Action or Bonus Action effect on your previous turn, as a Reaction to a creature moving or casting a Jutsu with the Mobility Keyword, you can Fire off a defensive jolt of Lightning towards a single creature. Make a ranged ninjutsu attack against a creature within 30 feet of you. On a hit, you deal 3d8 Lightning damage and the targets speed is reduced to 0 until the end of the current turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "3c0cef71ccad7d2f41a79773", name: "STORM’S SHOCK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action.", range: "Self (20-foot cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "An advanced version of the Lightning Release: Thunderbolt jutsu, you form a large ball of Lightning and Water Release Chakra, discharging it into a shockwave, using the Waters properties to avoid your allies. Each creature of your choice within a 20 feet cube, originating from you must make a Constitution Saving Throw, taking 4d6 Lightning damage and being Shocked on a failed save, or half as much damage and no further effects on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3, the damage by 2d6, and the size of the cube by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "6442f3c7b4b8fd6116d84c26", name: "LASER SIGHT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (20-foot Radius)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You Fire bolts of storm Chakra at each creature within a 15-foot radius centered on you. This radius extends around corners, and you do not need to see the creatures to affect them. When you cast this jutsu, you can designate any number of creatures to be unaffected by this jutsu. The remaining creatures in range creatures take 4d8 Lightning damage and must make a Constitution saving throw, being Shocked on a failed save. Creatures already shocked make this saving throw with a 1d4 penalty.", at_higher_ranks: "For each rank you cast this jutsu above C- Rank, increase the cost of this jutsu by 3, the damage by 2d8 and radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "ac8fbd70456acbfb4ca5715b", name: "LIGHTNING SPLASH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "60 feet (25-foot Cube)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You throw a bubble of Lightning at a point you can see within range. The bubble explodes filling a 25-foot cube. Creatures within range, must succeed a Constitution saving throw, taking 4d8 Lightning damage and being shocked on a failed save or half as much damage on a successful one and no additional effects. Creatures who take damage from this jutsu that already have ranks of shocked increases the damage they take by 1 die step.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "cce5857da4efd28eb5ae80d0", name: "SNAKE CHAINS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Select one target creature you can see within range as snakes made of Water & Lightning shoots towards the target, attempting to restrain them. Target creature(s) must make a Dexterity saving throw. On a failed save, they become restrained for the duration, unable to make handseals, and gain 2 ranks of Shocked. Restrained creatures make a Constitution saving throw at the end of each of their turns, ending this jutsu’s effects on a successful save. Additionally, if the target is standing on a body of Water when making their saving throws vs this jutsu’s effects, they make their saving throw with a -2 penalty.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and you may choose one additional creature to target with this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "56b35fa39beef73206e9bd9e", name: "TRI-BEAM", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (60-foot Line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You form your storm Chakra into a small sphere in front of you, which then Fires outward into a 60- foot line originating from you. Make a single ranged Ninjutsu attack comparing your result to the AC of each creature in range, dealing 4d10 Lightning damage and forcing affected creatures to make a Constitution saving throw, gaining +1 rank of Shocked on a failed save. The Chakra then reforms into a ball in front of you. For the duration of this jutsu, you can use an action on each subsequent turn to Fire this wave again in any direction, but always in a 30-foot line, originating from yourself. A creature with ranks of shocked takes an additional 1d10 Lightning damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "68d79b2e63304bdb68ae55b7", name: "BLACK LIGHTNING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "Special (14 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You manifest a surge of black lightning chakra from your body, boosting your storm release to new heights. This jutsu's effects change depending on your chosen Style with the Twin Style Clan Feature. You do not need to spend chakra to maintain concentration of this jutsu. • Storm Style: Your Lightning Release takes on a black color as an aura of black electricity surrounds you. For the duration, when you deal lightning damage or cast a jutsu with the Lightning Release keyword, you may spend 3 chakra to grant the following benefits; o +1 bonus to Save DC. o +2d6 bonus to damage, up to two times per casting. If the target is Shocked, this bonus becomes +2d8. o Grant the Lightning Release jutsu the benefits of any Overcharge effects it may possess. • Laser Style: You form a blade of water and violently mash both your Lightning and Water Release chakra natures to create a black blade of electrified lightning known as the Laser Blade. This weapon counts as any melee weapon of your choice that you are proficient in (choose which weapon upon casting), gaining the weapon's properties and the following benefits; o Weapon attacks made with the Laser Blade count as Ninjutsu attacks for the purpose of interacting with features, and may use your Ninjutsu ability modifier for attack and damage rolls. o The weapon's damage die is replaced with 3d8 lightning damage. If used as a component in a Bukijutsu, after your weapon's damage is dealt the first time in the Bukijutsu's casting, it is lowered to 2d8 for the rest of the casting. o If you hit a hostile creature wielding a non- chakra enhanced weapon that is benefitting from a bonus to AC from a feature, jutsu, or trait that requires this weapon, you slice right through their weapon, destroying it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8a2fe5e15a82af9bb614a563", name: "LASER DANCE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minutes", description: "You form your storm Chakra into a large sphere and send it to a point you can see within range. As part of casting this jutsu, and as an action on each of your subsequent turns, you can Fire up to three beams of Lightning, making up to 3 ranged ninjutsu attacks against creatures within a 30-foot radius of the sphere. You can direct these beams towards a single target or many, up to the number of beams you Fire. On a hit, you deal 3d6 Lightning damage. If you hit the same creature with at least two beams, the creature must succeed on a Constitution saving throw, being incapacitated until the end of your next turn on a failed save, overloading their body with supercharged storm Chakra.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the number of attacks by one.", created_at: NOW, updated_at: NOW },
  { _id: "560a4ba42eb66a5ce5e619d6", name: "STORM WAVE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (60-foot Cone)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure and Fire a 60-foot cone in front of you. All Creatures in the radius must succeed a Constitution saving throw, taking 8d8 Lightning damage and gaining 2 ranks shocked on a failed save, or half as much damage, and 1 rank of shocked until the end of an affected creatures next turn on a successful save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a94f5c03c7dcc65087d92213", name: "LASER CIRCUS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You Fire an absurd amount of Lightning beams towards up to 10 targets of your choice. You make a ranged ninjutsu attack per creature, against your selected target(s) within range. You can direct any number of these beams towards a single target or many, up to the number of beams you fire (Still making a single attack roll per creature). On a hit, you deal 1d12 per beam directed at a target, plus your Ninjutsu ability modifier. These beams ignore cover.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d2a1e318c4522f688c8596ab", name: "RAGING WAVE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "2ba225b4cbc6b15589913089"], elements: [], casting_time: "1 Action", range: "Self (30-foot Radius)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "An advanced version of Water Release: Maelstrom, you expel an enormous amount of Water from your mouth, simultaneously charging it with Lightning, and making it swirl in a 30-foot radius around you. Until the jutsu ends, this area is difficult terrain for any creature except you, and any creature that starts its turn there or moves there for the first time on their turn must succeed on a Strength saving throw. On a failed save, a creature takes 7d10 Lightning damage and is pushed 15 feet away from the center of the area. On a successful save, a creature takes half as much damage, and is only pushed 5 feet away. Additionally, a creature that starts its turn in the area or moves there for the first time on their turn must also succeed on a Constitution saving throw, gaining 3 ranks", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9571c3e79f85375356f1908a", name: "DRAGON AEGIS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "Reaction, which you take when you take damage", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 turn", description: "Your coat your body in Chakra creating draconic scales and wing constructs of your design, made of Chakra that you conjure in between you and the attack. You gain 3d6 + 10 Temporary Hit points until the end of the current turn. These Temporary Hit points are in addition to any other Temporary hit points granted by Ryu Clan Hijutsu. If you are concentrating on Dragons Cloak, you do not lose these temporary hit points at the end of the turn, instead retaining them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and your Temporary hit points by 5", created_at: NOW, updated_at: NOW },
  { _id: "bcd95274a24894ca183099e4", name: "DRAGON AURA", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (15 feet)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You create a whipping aura of elemental Chakra that surrounds you and extends out up to 15 feet from you. For the duration, creatures within range take damage equal to your Ninjutsu ability modifier each turn they begin inside the aura. Also, creatures who would make a saving throw while within your aura against a jutsu of the same nature release as the aura reduce the result of their saving throw by 1.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the aura by 5 feet. Increase the saving throw penalty to -2 at B-Rank and -3 at S-Rank.", created_at: NOW, updated_at: NOW },
  { _id: "ffb257d265e8c4745b56efc1", name: "DRAGON BREATH", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "20-foot cone", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "(This jutsu deals the same damage type as the nature release chosen by your Blood of the Dragon Clan Feature) You inhale and release a wave of destructive Chakra that matches your affinity. Creatures in range must succeed a Dexterity saving throw, taking 3d8 damage on a failed save or half on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the size of the cone by 5 feet and the damage by 2d8 damage.", created_at: NOW, updated_at: NOW },
  { _id: "04ace4287975ee742be1cbcf", name: "DRAGON VISION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Hour", description: "Your pupils narrow into draconic slits, granting you phenomenal sight. For the duration, you are immune to the blinded condition, gain Dark vision and have a +5 bonus to Wisdom (Perception) and (Insight) checks. You can see the Nature Affinities other creatures can use if any, you also gain 30 feet of Chakra sight able to see how much Chakra a creature has based on an aura they exude.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e90f30cfa83c88b98b525b6a", name: "DRAGONS BOMB", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "(This jutsu deals the same damage type as the nature release chosen by your Blood of the Dragon Clan Feature) You collect Chakra into a sphere about the size your body before compressing it into one about the size of a golf ball. You take this super compressed ball of Chakra and ram it into your target creating a shockwave that affects creatures and objects near the target creature. Make a melee ninjutsu attack. On a hit, you deal 4d10 damage. The target creature and all creatures, excluding you, in a 15-foot radius around the target must make a constitution saving throw, being pushed back 15 feet from the shockwave. Creatures who fail the Constitution save takes 3d6 damage and falls prone on a failed save or half as much on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the initial damage by 2d10, and the Shockwave damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "a6ef7bcd5dea2b7fb0f7492e", name: "DRAGONS STRIKE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (Special)", chakra_cost: "8 Chakra", components: "HS, CM, W (Katana)", duration: "Instant", description: "(This jutsu deals the same damage type as the nature release chosen by your Blood of the Dragon Clan Feature) You bathe your katana in your Chakra, so much so that it vibrates and hums loud enough to sound like revolving fan blades. You make a single decisive slash releasing the attack and destroying everything in your path. You have two options for the size and shape of this attack. Horizontal Slash. You swing your sword from left to right releasing a violent gale of your elemental energy catching all creatures in a 25-foot cone. Creatures in range must succeed a Dexterity saving throw taking 5d8 damage and being knocked prone on a failed save or half as much on a successful one. Vertical Slash. You swing your sword straight down releasing a single beam of elemental energy from your katana. The Beam flies down a straight line 60 feet long and 10 feet wide. Creatures in range must succeed a Dexterity saving throw taking 7d6 damage and being knocked prone on a failed save or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Horizontal damage by 2d8 or the Vertical damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "28ca2f74fa518304af42edcd", name: "DRAGON’S WRATH", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You amplify your body with your Nature affinity, creating a light but harmless aura and effect symbolizing your Chakra. For the duration Increase your AC by +1, increase your movement speed by +20 and you gain a  +2 bonus on Strength and Dexterity saving throws for the duration. If you cast this jutsu while you are gaining the benefits of Dragons Rage, you reduce the cost of this jutsu by 2. Additionally, if you are gaining the benefits of Dragons Rage the duration of this Jutsu becomes 1 Minute.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6e23fcafada62b4f80726be7", name: "DESTRUCTIVE WAVE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "(This jutsu deals the same damage type as the nature release chosen by your Blood of the Dragon Clan Feature) You collect your Elemental energy into your body and compress it into a single spot like your mouth or hands and prepare to Fire in all directions by striking the ground creating a shockwave the Fires out in all directions overwhelming all enemies. Each creature you choose within 30-feet of you must succeed a constitution saving throw or take 10d6 damage and be knocked prone on a failed save or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, damage by 2d6 and size of the area by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "91d5bf28163809a3f2585f3b", name: "DRAGON CLOAK", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You cover your body in Chakra and mold it until its visible to the naked eye. Your Chakra then begins to bubble and boil until it takes the shape of a dragon like shell the covers your entire form. You are still visible inside the shell of Chakra. For the duration, you gain 30 Temporary Hit Points, your unarmed attacks deal an additional die of damage and you gain a +2 bonus on Constitution and Wisdom saving throws while you still have temporary hit points from this jutsu. If you cast this jutsu while you are gaining the benefits of Dragons Rage or Dragons Wrath, you reduce the cost of this jutsu by 3 for each one currently active. Additionally, if you are gaining the benefits of Dragons Wrath you no longer need to maintain concentration on this jutsu but you still gain its benefits for the duration of this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and Temporary Hit points by 15.", created_at: NOW, updated_at: NOW },
  { _id: "5c63c50d004bf9796fd49dc0", name: "DRAGONS ASCENSION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "1 minute", description: "You keep all of your Chakra inside you not allowing any of it to leak out enhancing your physical attributes past their limits, matching your physical prowess to that of a Dragons. Your Strength, Dexterity and Constitution all becomes 24 for the duration. Your speed is doubled and you gain more feral sounding speaking patterns. You gain a +2 bonus on Intelligence and Charisma saving throws. You lose the ability to cast and concentrate on Non-Ryu Clan jutsu for the duration. When this jutsu ends, make a constitution save vs a DC 20 + 1 for every round this jutsu remained active. On a failure, you fall to the ground prone and stunned for a number of minutes equal to rounds you had this jutsu active. If you cast this jutsu while you are gaining the benefits of Dragons Rage, Dragons Wrath or Dragons Cloak you reduce the cost of this jutsu by 4 for each one currently active. Additionally, if you are gaining the benefits of Dragons Wrath and/or Dragons Cloak you no longer need to maintain concentration on that jutsu but you", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b8c80f73290623dd36290396", name: "GREAT FOREST TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "7e75ac7584ff55c12a68c048"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You change the structure of your arms or legs into that of Chakra enhanced wood. You transform your appendage into a fork of multiple branches. Make a melee Ninjutsu attack against a creature you can see within range. On a hit you deal 2d8 Earth damage and the target must make a Strength saving throw. On a failed save, they are grappled by you until they either escape or you choose to release them. A creature grappled by you can be pulled 10 feet closer towards you as a bonus action on each of your turns. A grappled creature can spend its action to remake its saving throw to escape this grapple on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage by 2d8 and range by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "0d2d9a8e79f2b5557d01d587", name: "WORLD OF TREES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "3d57bcaf8e2305d5f41328cf"], elements: [], casting_time: "1 Action", range: "Self (30-foot Cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minute", description: "You clap your hands together as you inject Chakra into the ground giving birth to a host of roots, and plants that surge upwards filling a 30- foot cube originating from you with bulging wood and roots. All creatures of your choice treat the area as difficult terrain and cannot take the dash or dodge actions while inside the radius. Additionally, Senju clan Hijutsu you cast while inside the area of this jutsu ignores temporary hit points and structures that would intercept damage for a creature.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the size of the cube by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "c1ea25811569673c8e34ec0a", name: "PIERCING BARK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "7e75ac7584ff55c12a68c048"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You clap your hands together as you inject Chakra into the ground controlling a single root enhancing it until it listens to your mental command. Make a ranged Ninjutsu attack, targeting a creature you can see within range as the root bursts forth from the ground, sharpening themselves to produce wood like spears. On a hit, target creature takes 3d6 Earth damage, and must make a Strength saving throw as the impaled roots take hold to the ground again, rooting them in place. On a failed save the target gains 1 rank of Sealed and one of their hands are restrained, making it unable to be used for Handsigns (HS) or Chakra Seals (CS). A creatures can have each arm restrained by this jutsu separately. A creatures arm(s) restrained by this jutsu can use its action to remake their saving throw to end this effect, freeing themselves from the rooted wood on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage by 2d6. If this jutsu is cast at B-Rank, increase the ranks of Sealed inflicted to 2. If this jutsu is cast at S-Rank, increase the ranks of Sealed inflicted to 3.", created_at: NOW, updated_at: NOW },
  { _id: "43c7de334bb11b6d0c63af41", name: "FOO DOG HEADS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "6a2e982b856edc094ce115ea"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You clap your hands together as you inject Chakra into the ground before conjuring 4 Wooden pillars that fill up to 4 different spaces that you can see with a Quake Shard that’s 10 feet tall, 5 feet thick, made of wood, has an AC equal to your Ninjutsu save DC, and 25 hit points. Each Earthen Construct emits a suppressive aura affecting creatures of your choice within 15 feet of each pillar. Select creatures who are within a 15-foot radius of a pillar at the beginning of their turns or would enter the radius for the first time on their turns, must make a Constitution saving throw taking 6d6 Chakra damage gaining 1 rank of Sealed on a failed save or half as much and no further effects on a success. A creature can only be affected by 1 pillars aura per turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the hit points of the Pillar by 15 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "ef3426ea77138ad4bcd08a73", name: "GREAT SPEAR TREE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "7e75ac7584ff55c12a68c048"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot Cube)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You clap your hands together as you inject Chakra into the ground. You select a space you can see within range, where a large tree explodes from the ground without any leaves or foliage but instead sharpened wooden branches filling a 15-foot Cube. Creatures within range of the massive tree makes a Dexterity saving throw, taking 8d4 Earth damage and being restrained by the massive tree on a failed save, or half as much damage and no additional effects on a success. Creatures restrained by this jutsu must make Strength saving throws to end the restrained condition on themselves at the end of each of their turns. The tree that appears, remans for 1 hour before it wilts and turns to dust or is destroyed by other means. This tree has an AC equal to your Ninjutsu Save DC and 40 Hit points and counts as a Quake Shard.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and summon a second tree in a difference space, within range. A creature can only be affected by one instance of this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "31b9f8e0d2cbec64b79b359d", name: "HŌBI TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "7e75ac7584ff55c12a68c048"], elements: [], casting_time: "1 Reaction, which you take when you or a creature you can see within range would take damage.", range: "Self (10-foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Round", description: "You clap your hands together as you inject Chakra into the ground. You conjure a massive wooden dome that is a Quake Shard of your design and description. All creatures of your choice are protected, while other creatures whom you did not select are pushed out from the protection of this structure to the edge, on a space that can hold them harmlessly. The structure intercepts all damage except from Genjutsu. The structure breaks line of sight as all affected creatures gain total cover for the duration. The structure splinters and dissolves at the beginning of your next turn. A creature can leave the protection of the structure, but cannot reenter it once they leave. The structure has 30 Hit points.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the Hit Points of the Structure by +10", created_at: NOW, updated_at: NOW },
  { _id: "095b356dc04bc60366cd91a0", name: "HOTEI TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You clap your hands together as you inject Chakra into the ground. You conjure multiple hands of wood that jut from the ground and attempt to grapple up to two creatures you can see within range. Target creature must succeed a Dexterity saving throw, being grappled. On a successful save, no further effects. A grappled creature must also make a Strength saving throw being pulled prone as the hands retract into the ground dragging the creature to the ground with it. On a successful save, they remain standing. A grappled or prone creature can make a Strength saving throw as an action on their turn to end the effect.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and select one additional creature for this jutsu to affect.", created_at: NOW, updated_at: NOW },
  { _id: "e173d8d479ccf7b6fb775745", name: "WOOD CLONE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "7e75ac7584ff55c12a68c048"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (10 Chakra)", components: "HS, CM", duration: "Instant", description: "You clap your hands together as you inject chakra into the ground conjuring clones made of wood. This is an even more advanced Version of the Shadow Clone Technique, where you manifest clones made of hardened, malleable and dense wood known as a Wood Clone. You can conjure up to 6 Wood Clones at once, each costing 10 chakra per clone. Wood Clones act at once and all attempt to perform the same command give. If commanded to perform the help action, they can only help the Summoner. Wood Clones are conjured with a replica of any weapons you have on you at the time of creation that is also made from chakra enhanced wood. When a Wood Clone makes an attack using this weapon or an unarmed attack it deals 1d10+Ninjutsu ability modifier earth damage regardless of the attack used. It can make up to 2 attacks using its action. All Wood Clones have 15 Hit Point and can use all Senjutsu Hijutsu on your known list of C-Rank or lower up to twice, each. Wood Clones use your Constitution save bonus for all saving throws. After the clone reaches 0 Hit points, performs 2 Senju clan Hijutsu or is dismissed as a bonus action, the jutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "87da7efc89b823a20c04e0e8", name: "WOOD DRAGON SUMMONING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "Special (14 Chakra)", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "You clap your hands together as you inject Chakra into the ground conjuring a massive wooden serpentine dragon. You command the Dragon and it only listens to you (no action needed), acting at the end of each of your turns. It is proficient in all saving throws, using your Ninjutsu ability modifier as its Proficiency bonus and uses your ninjutsu attack bonus or save DC for effects that require it. You may as a Bonus action, or reaction cause the dragon to use its Detonation ability. It uses the following Statistics; WOOD RELEASE: TREE BIND FLOURISHING", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e4e933eb6b71e7c8c1422d44", name: "TREE BIND FLOURISHING BURIAL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "587205fc5e2f018201761d63"], elements: [], casting_time: "Full Round Action", range: "90 feet (30-foot cylinder)", chakra_cost: "Special (20 Chakra)", components: "HS, CM, CS", duration: "Until Dispelled or Destroyed", description: "You clap your hands together as you inject Chakra into the ground. Bringing a large surge of vitality into the foliage deep in the ground. Select a space you can see within range. A massive tree, 90-feet tall and 30-feet wide, made of roots, explodes upwards attempting to capture all creatures in its path. This jutsu’s counts as a Quake Shard. All creatures in a 30-foot wide, 90-foot-high cylinder must make a Strength saving throw, being restrained on a failed save, as the tree completely captures, overtakes, and binds them inside it. On a successful save, they escape the binding of the tree’s roots. Creatures who failed the saving throw gain 3 ranks of Sealed, have total cover from all creatures both inside and outside the tree and begin to feel immense pressure, as the tree begins to compress and feed off of their biological mass as nutrients. Restrained creatures take 7d8 Earth and Chakra damage at the beginning of each of their turns. A restrained creature can use an action on its turn, to make a Strength saving throw. Once they succeed twice, they fully escape this jutsu’s bindings. A creature who’s hit points reach 0 while under the effects of this jutsu becomes a part of the tree. The Tree conjured by this jutsu remains and does not dissolve. The Tree Conjured by this jutsu", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f8bde14921e2b753a87b576", name: "SCORCHING MURDER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 minute", description: "You create 4 motes of superheated flame that circle around you like mini satellites. As a bonus action on each of your turns, you can spend a mote, allowing you to make a ranged Ninjutsu attack, throwing it at a creature you can see within 30 feet. On a hit, target creature takes 3d8+3 Fire damage and must succeed a Constitution saving throw, being Burned on a failed save. Once all motes have been expended this jutsu immediately ends. You can alternatively spend the motes created by this jutsu to fuel other Scorch Release jutsu you cast, enhancing their effects.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of motes you create by 3 and damage of this jutsu by 1d8+1.", created_at: NOW, updated_at: NOW },
  { _id: "c2e2f44358d1c452e541a457", name: "MURDEROUS FLAME", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure multiple globes of superheated flame, combining them into a single globe that you then Fire as a beam of white flame in a 30 foot long, 5 feet wide line. All creatures in its path must succeed a Dexterity saving throw, taking 3d8+3 Fire damage and being burned on a failed save or half as much on a successful save. You can spend 2 motes created by Scorch Release: Scorching Murder, increasing the damage die of this jutsu to a d10 and creature(s) who fail the saving throw instead gain 2 ranks of Burned and creatures who pass the save gain 1 rank of Burned. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and damage by 2d8+2.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5f3b2ddbe7c9950ebb400d5e", name: "MURDEROUS REVITALIZATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure multiple globes of superheated flame, revitalizing a creature you touch. They regain 3d6 hit points. If you spend 3 motes created by Scorch Release: Scorching Murder, they also reduce their Exhaustion by 1 rank. A creature who died as a result of Exhaustion cannot have their Exhaustion reduced by this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and hit points regained by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "7cfbcf2427d0eb34567ceaf9", name: "SLAUGHTERING FLAME", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "60 feet (20-foot radius sphere)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure globes of superheated flame, compressing it into a small sphere and throwing it towards a space you can see within range. The sphere explodes when reaching its destination. All creatures in the radius must make a Dexterity saving throw, taking 2d8+2 Fire damage and gaining the Burned condition on a failed save, or only half as much damage on a successful save. You can spend motes created by Scorch Release: Scorching Murder, for every mote spent, increase the damage of this jutsu by 1d8+1. You can spend up to 3 motes this way.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the ranks of Burned gained by +1.", created_at: NOW, updated_at: NOW },
  { _id: "29b3518975b238ca9c927600", name: "BLAZING MURDER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot cube)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure globes of superheated flame that you then compress into a sphere the size of a basketball. You then throw this sphere into the air before clapping your hands together to focus, releasing the super-heated flames into the air like rain filling a 15- foot cube you can see. All creatures within range must succeed a Constitution Saving Throw. On a failed save they take 4d4+4 Fire Damage and gain 2 ranks of the Burned condition. On a successful save they take half as much damage and gain 1 rank of the Burned condition until the end of their next turn. At Higher Ranks: For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage by 2d4, and the size of the cube by 5 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cfdc622055db4694c0084612", name: "VIOLENT SLAUGHTERING FLAME", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure globes of superheated flame and create a stream of superheated flame, burning everything in your path. You Fire a 30-foot cone of flame destroying everything in your way. Creatures in range, must succeed a Dexterity saving throw, taking 5d8+5 Fire damage and being burned on a failed save or half as much on a successful save. Creatures who fail this saving throw by 5 or more also drop any metal items they are holding. If they would pick up these items before the end of their next turn they take 1d8 Fire damage. Creatures who fail this saving throw by 10 or more find it hard to breathe as all the air evaporates from their lungs as they become stunned until the end of their next turn. You can spend motes created by Scorch Release: Scorching Murder, for each mote spent, all creatures within range suffer a -1 penalty to their saving throw. You can spend up to 5 motes this way.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and damage by 2d8+2", created_at: NOW, updated_at: NOW },
  { _id: "358ec22c53c070eaf76affc2", name: "PAINFUL VIOLENCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You cannot lose concentration on this jutsu as a result of damage. You conjure multiple globes of superheated flame and coat your fist and feet in them for the duration. When you first cast this jutsu and as an Action on each subsequent turn for this jutsu’s duration, you can make a single Melee Ninjutsu Attack. On a hit, you deal 4d6+4 Fire damage and the target creature gains the Burned condition. When you make the attack granted by this Jutsu, you can spend motes created by the Scorch Release: Scorching Murder. For every three motes spent, you can make one additional attack. You can spend 6 motes in this way.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "63a130a63ac870437f914fa8", name: "HELLFIRE MURDER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure globes of superheated flame that you use to manifest a massive ball of super-heated flame about 8 feet in diameter. You then slam this ball into the ground directly under you attempting to incinerate everything near you. All creatures, excluding you, within the radius must succeed a Constitution Saving Throw. On a failed save, they take 10d8+10 Fire damage and gain 2 ranks of Burned or half as much damage on a success You can spend motes created by the Scorch Release: Scorching Murder to enhance this jutsu. For every two motes spent this way, you select one creature to be unaffected by this jutsu and increase this jutsu’s damage by 2d8. You can spend up to 4 motes this way. You can spend up to 4 motes this way.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the radius by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "6a615c3e722e2cf085ecf569", name: "VENGEFUL MIRAGE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure globes of superheated flame and enhance the body of a creature you touch, increasing its reactionary speed significantly. For the duration you do not need to spend Chakra to maintain this jutsu. The affected creature’s [Unarmed Damage] becomes 4d4+4 Fire damage instead of whatever it did previously. Creatures who would make a melee attack against the affected creature, must make a Wisdom saving throw as they see a mirage made from extreme heat. On a failed save they gain a +1 rank of Weakened.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "761068ab3b3ae562da636039", name: "MAJESTIC VIOLENT MURDERING HELLFIRE DESTROYER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "22 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure an innumerable number of globes of superheated flame, fusing them, to create a single massive sphere of super-heated flame. Make a ranged ninjutsu attack against a target you can see within range, dealing 8d12+8 Fire damage on a hit. Regardless if you hit or miss, all other creatures within 60 feet of the original target must succeed a Constitution Saving Throw taking 3d12+3 Fire damage and being Burned on a failed save. Creatures who’s hit points are reduced to 0 as a result of this jutsu are turned to dust and leave behind only a shadow of their physique stained in ash on the ground or wall. You can spend motes created by the Scorch Release: Scorching Murder to enhance this jutsu. For every mote spent, increase both instances of damage by 1d12+1. You", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c366f3bddac33ce9c3afdd0c", name: "PAPER SHURIKEN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "CS", duration: "Instant", description: "You create 3 razor-sharp shuriken from paper, and guide them with your chakra. Make a ranged, ninjutsu attack for each shuriken you create. You can make the attack against one target or many. On a hit, you deal 1d4+1 Slashing damage. This Jutsu’s damage pierces DR not gained from Jutsu. A creature gains 1 rank of Bleeding for each shuriken that deals damage to them. While under the effects of Dance of Shikigami, you can choose to cast this jutsu as a bonus action.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3, and create two additional shuriken.", created_at: NOW, updated_at: NOW },
  { _id: "a518e392b2e28ee4919cd7a3", name: "PAPER SUBSTITUTION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you take damage.", range: "Self", chakra_cost: "5 Chakra", components: "HS, CS", duration: "1 Round", description: "You turn your body into a mound of small, paper squares, that upon impact scatter, nullifying a significant amount of damage. You gain +3 bonus to AC and resistance to Bludgeoning, piercing and slashing damage until the beginning of your next turn. While you are gaining the benefits of Dance of the Shikigami Hijutsu, you instead gain immunity to Bludgeoning, Piercing and Slashing Damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "59ccb1d245dfe2e1b133254c", name: "TRACKING TAG", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "CS", duration: "24 hours", description: "You attach a paper tag with your chakra signature to a target, which changes color to blend in with their clones or skin. You may detect the general location of this tag from up to a mile away. When you are within 500 feet, you may detect its exact location.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "06dc6810c47ee46efc9054a6", name: "PAPER TRAP", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "10 Minutes", range: "Self", chakra_cost: "Special", components: "CS", duration: "Until Triggered or Dispelled", description: "You take a chakra seal, and infuse it with your chakra, making it very similar to a breaching tag. Each time you cast this jutsu, you create 2 of such tags. These tags must be prepped and set on a solid surface and can only be activated as a Reaction. Each trap takes 10 minutes to prep and set. You do not spend chakra to make such a paper trap, you instead must spend 5 chakra to activate the trap. For every trap you activate, you must spend 5 chakra. All creatures within 30 feet of the trap when detonated must succeed a Dexterity saving throw. On a failed save the creature takes 4d6 fire damage. A creature who fails a saving throw suffers a -2 penalty to each subsequent saving throw they make against other Paper traps (This penalty stacks). A creature can be affected by up to 10 Paper traps at once.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d9db109d2711ae2eb354b13e", name: "ORIGAMI SERVITOR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "500 Feet", chakra_cost: "7 Chakra", components: "CS", duration: "1 Hour", description: "You use origami to create a paper animal, such as a crane or butterfly, and send it out to gather information. The Origami you create, is a tiny object with a flying speed of 60 feet and a stealth bonus equal to your Ninjutsu Save DC. While this jutsu is active, you may spend an action to see and hear as if you were in the same location as your origami. While doing this your body is incapacitated and unaware of its surrounding. Any damage to your body returns your senses.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3, the range your Origami can travel by 250 feet, and increase their Stealth Bonus by +2. If this jutsu is casted at B-Rank, increase the Duration to 8 hours and 24 hours at A-Rank.", created_at: NOW, updated_at: NOW },
  { _id: "6c5cafa94fa2520a16811af4", name: "PAPER DRIZZLE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "90 Feet (30-foot cube)", chakra_cost: "8 Chakra", components: "CS", duration: "Instant", description: "You briefly form a pair of papery wings, which rain Senbon, made of paper on an area of your choosing, that you can see within range. Each creatures in the target area, must succeed a Dexterity saving throw, taking 4d10 piercing damage on a failed save, or half as much on a successful on. While under the effects of Dance of Shikigami, you can choose to only affect hostile creatures within the area of effect, and increase the radius of the jutsu to a 45-foot cube.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3 and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "4e30b696e12d8612ee986661", name: "PAPER CLONE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "dc2837c0a3446d09da7edaf6"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (8 Chakra)", components: "CS", duration: "Concentration, up to 1 Hour", description: "You conjure a clone made of paper, similar to the Shadow Clone Technique, but more durable to a space it can occupy within 10 feet of you, known as a Paper Clone. Paper Clones are made of paper and weighs 1/10th of the casters weight. You may create up to 2 Paper Clones, each costing 8 chakra. Paper Clones have Immunity to bludgeoning, piercing and slashing damage, Vulnerability to fire damage and can cast up to two C-Rank and lower Shikigami Clan Hijutsu before this jutsu ends. Paper Clones made using this jutsu cannot create a Clones of its own. Paper Clones cannot concentrate on jutsu. If a Paper Clone casts a jutsu that requires more than 1 attack roll upon casting, it only makes one attack. If multiple clones attack the same creature, you do not make multiple attack rolls. You instead choose a lead clone and it gains a +1d4 bonus to its damage roll(s), for each additional clone that is aiding it. Paper Clones can change their color to blend in with any surface as an Action. When it does it can make a Stealth check using your Ninshou or Stealth, whichever is higher. Paper Clones are automatically dispelled if it enters a body of water. Paper Clones can make a melee weapon attack with its action. If it does it deals 1d8 slashing damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e9950edd0a1e877268707cbb", name: "PAPER CHAKRAM", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "5 feet (120 feet)", chakra_cost: "10 Chakra", components: "CS", duration: "1 minute.", description: "You create an incredibly sharp chakram of paper, which you mentally command to attack opponents repeatedly for the duration or until you dismiss this jutsu. When you cast this jutsu, the chakram appears within 5 feet of you, and you can move the chakram up to 30 feet and make an attack against a target within 5 feet of the chakram. On a hit, the target takes slashing damage equal to 6d6 + your ninjutsu ability modifier. The chakram has a critical hit range of 19-20. On a critical hit, the target also gains the 4 ranks of the bleeding condition. As a bonus action on each of your turns, you may move the chakram up to 30 feet and repeat the attack against a target within 5 feet. While under the effects of Dance of the Shikigami, when moving the chakram, you may have it make an attack against each creature it passes during its movement. A creature can only be targeted by the chakram once per turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3, the damage by 1d6 and the critical hit range by 1.", created_at: NOW, updated_at: NOW },
  { _id: "87ca3216d418d1e938b9f784", name: "PAPER COFFIN", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "80 feet", chakra_cost: "14 Chakra", components: "CS", duration: "Concentration, up to 1 minute.", description: "You cover a target in sheets of paper, with restrict their movements and plug their nose and mouth, suffocating them. You do not need to pay chakra, to maintain concentration on this jutsu. A target creature you can see within range must succeed on a Dexterity saving throw or be covered by countless sheets of paper. On a success, they avoid the paper, ending the jutsu. While trapped by the paper, they are restrained, unable to cast jutsu that require Hand Signs (HS), draw or stow weapons or make complete complex body movements like making a weapon attack. They also begin suffocating. At the start of each of the suffocating creatures turns, it takes 5d6+15 Necrotic Damage that cannot be reduced by any means. A creature that does not need to breathe cannot take damage from this jutsu. During this time, the creature cannot speak, but you can allow it to do so, halting the suffocation by one round. At the end of the creature's turn, it can make a Strength saving throw, breaking free of the paper on a successful save. A creature can attempt to destroy the paper Coffin you have created. Your Sokushinbutsu has an AC equal to your Ninjutsu save DC, 25 Hit points and Vulnerability to Fire damage. If your Sokushinbutsu’s hit points are reduced to 0, this jutsu ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "45964b01ae3a1ac16eef3589", name: "DANCE OF THE SHIKIGAMI", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "18 Chakra", components: "CS", duration: "Concentration, up to 10 minute.", description: "With your mastery of paper, you turn yourself into a paper angel, with a body untouchable by mundane weaponry and the ability to take to the skies. Until this jutsu ends, you gain the following benefits: • You gain Resistance to bludgeoning, piercing, and slashing damage. • You gain a flying speed of 60 feet. You can use your Bonus Action to select a space you can see up to 60 feet away. All creatures in a 15-foot cube centered on this space must succeed a Dexterity Saving Throw. On a failed save, creatures take 6d8 Piercing damage and gains the Lacerated condition, or half as much damage on a successful saving throw. You have advantage", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "af1e88c7489660c9b5bc2073", name: "CRYSTAL ARMOR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You create a layer of crystalline chakra across your body designed to act as a second skin protecting you from powerful blows and crippling attacks. You gain 4 DR (damage reduction) vs all sources, except Lightning. While you are gaining the benefit of this jutsu, you are counted as a Quake Shard of your own creation.", at_higher_ranks: "For each rank you cast this jutsu above or higher, increase the DR to 8. If cast at A-Rank or higher, or higher, increase the DR to 12.", created_at: NOW, updated_at: NOW },
  { _id: "425e533ee5817f9015481f4a", name: "CRYSTAL NEEDLES", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest pink, blue, red, or green crystal rods that you then launch at a creature you can see in range. Make two ranged ninjutsu attacks against a creature you can see within range. On a hit, you deal 3d6 Earth damage and the affected creatures speed is reduced by -10, until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost by 3 and the number of attacks by", created_at: NOW, updated_at: NOW },
  { _id: "fa2d9dd38d170fee50828643", name: "CRYSTAL WHEEL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You manifest pink, blue, red, or green crystal ring around yourself that you cause to spin like a buzzsaw around you. For this jutsu’s duration, you increase your Movement speed by 5 x your Ninjutsu ability modifier, you ignore difficult terrain and creatures who would make an attack of opportunity against you takes 10 earth damage as the crystal ring slashes into them as you pass them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost by 3 and the damage by 5.", created_at: NOW, updated_at: NOW },
  { _id: "86f726ddf28a0b57f5a1456c", name: "JADE CRYSTAL BLADE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You manifest pink, blue, red, or green crystal blades on either arm of yours. As an action on each of your turns, you can make two melee ninjutsu attacks against a creature you can see within 5 feet of you. On a hit, you deal 2d8 earth damage. If you successfully hit a creature with both attacks, the target gains 2 ranks of bleeding.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "4f2f6c1dc401ee2dc172e842", name: "HEXAGONAL CRYSTAL SHURIKEN", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Permanent, until used", description: "You manifest a d6 stack of pink, blue, red, or green crystal shuriken. These shuriken have no bulk, and you can only ever have 1 Stack at a time. If you manifest another stack, the previous stack dissolves. These shuriken have the same range as normal shuriken, deals a d8 earth damage and have the Deadly 3 weapon property. Weapon attacks made with these shuriken can be made using your Ninjutsu attack bonus. They also count as components for bukijutsu that require a ranged slashing weapon. If you score a critical hit with these shuriken, they shatter and splinter dealing half the damage dealt to all creatures within 5 feet of the original target.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost by 3 and the size of the stack by 1 step (D6>D8>D10>D12)", created_at: NOW, updated_at: NOW },
  { _id: "60c8152ab49923b687f24c39", name: "SHURIKEN WILD DANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self (5-Feet radius)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You manifest pink, blue, red, or green crystal shuriken that spin around your furiously, protecting you from harm and damaging creatures that get too close. Ranged attacks against you deals reduced damage equal to 2d6. This damage reduction doesn’t count against lightning damage. Creatures of your choice, who begins or ends its turn within 5 feet of you, take 3d6 earth damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "73026206e8af24b76c15500d", name: "JADE CRYSTAL HEXAGONAL PILLARS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (60 Foot Radius)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, Up to 10 minutes", description: "You manifest five, large pink, blue, red or green crystalline pillars around the edge of this jutsu’s radius, with you in the center. Each of these pillars for the duration, counts as a Quake Shard. For the duration, you and creatures of your choice within this jutsu’s radius gains the following benefits; • Jutsu cast, with the Earth Release keyword, of a rank equal to or lower than this jutsu, can be cast without the Hand Seal (HS) requirements. • Jutsu cast, with the Earth Release Keyword, that requires concentration, reduce concentration costs by -1. (Min 1.) • Allied creatures, excluding yourself gain 6 DR (damage reduction) At Higher Ranks: For each rank you cast this jutsu above C-Rank increase the cost by 3 and the DR by +2. If cast at A- Rank or above increase the cost reduction for concentrating on Earth Release jutsu to -2 (Min 1.)", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "eab155984383dce9bc28e137", name: "CRYSTAL FRUIT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action or Reaction, which you take when a creature you see would take damage.", range: "90 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You manifest a pink, blue, red, or green crystal dome around a creature of your choice within range designed to protect or trap a creature. If this jutsu is cast targeting a willing creature, you manifest the crystal dome around them almost instantly. This dome intercepts all attacks and damaging effects except Genjutsu. If this jutsu is cast targeting an unwilling creature, that creature makes a Dexterity saving throw being encased in the dome on a failed save. While inside the crystal dome, it intercepts all attacks and damaging effects except Genjutsu. The dome an AC equal to your Ninjutsu save DC, Resistance to Cold Damage and Vulnerability to Lightning Damage and a number of Hit point equal to 6d8+15. A creature cannot willingly pass through the crystal, requiring it to be destroyed, dispelled, removed in order to move from the creatures current space.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost by 3 and the number of hit points the Dome has by 1d8+5.", created_at: NOW, updated_at: NOW },
  { _id: "63aeccdc557bf45ab96d4467", name: "CRYSTAL PRISON", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You manifest a pink, blue, red, or green crystalline structure, completely encasing a creature you touch within. This jutsu’s cost and concentration costs cannot be reduced by any means except by Crystal Release: Jade Crystal Hexagonal Pillars. Make a melee ninjutsu attack. On a hit, the target must succeed a Constitution saving throw, on a failed save you infuse your target with your Crystal Release Chakra for the next minute. At the beginning of each of its turns must succeed a Constitution (Chakra Control) check vs your Ninjutsu Save DC for the duration. Each time a creature fails, their cellular structure begins to resemble that of a Crystal. A creature who fails one or more times gains one rank of the Slowed Condition as it becomes hard to move the way they want. A creature who fails two or more times gains the restrained condition as their cells begin to take on a crystalline make up solidifying and crystallizing them. A creature who fails three or more times becomes incapacitated as their body is overtaken by crystalline cells. A creature who fails five or more times becomes Petrified permanently, until you recast this jutsu on them, or a Ninjutsu with the medical Keyword that removes conditions of any type is cast on them at A-Rank or Higher. If their Petrified figure is damage or destroyed in anyway, the creature petrified, is immediately killed, with no way to be revived. ART CREDIT Guren by Acolnahuacatl on DeviantArt CRYSTAL RELEASE: CRYSTAL IMPRISONMENT", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5ce346a1c169b429c96e9a64", name: "CRYSTAL IMPRISONMENT WAVE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "Full Turn Action", range: "Self (30-Foot Radius sphere)", chakra_cost: "Special (25 Chakra)", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "As a part of casting this jutsu, you must know the Crystal Release: Crystal Prison Hijutsu. You perform the Crystal Release: Crystal Prison Hijutsu, but on a massive scale, affecting all creatures within range. Each creature within a 30-foot radius, must make a Dexterity saving throw. On a failed save, they fall under the", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "52a40373e09e24f5d5b18fb4", name: "HIDDEN SHADOW SNAKE HANDS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "1 minute", description: "For the duration your unarmed attack range is the same has the same range as your Soft Physique Modification Feature and you gain the benefits and penalties of that feature. Your unarmed damage deals 1d6 + Your Ninjutsu Modifier Piercing damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When you upcast this jutsu at C-Rank, once you grapple a creature, you can, as an action or bonus action, command your snakes to bite or constrict the creature. • Bite: The target takes 2d8 Poison Damage and have to succeed a constitution Saving throw, gaining one rank of Envenomed on a failure. • Constrict: The target takes 2d8 bludgeoning Damage and must succeed a Strength Saving throw or else be restrained on a failure. If cast at B-Rank, the unarmed die becomes a d8 and the Bite and Constrict damage is increased by 1d8. If cast at S-Rank, the unarmed die becomes a d10 and the Bite and Constrict damage is increased by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "0841775abf058b6f78ee0c62", name: "BINDING GLARE SNAKE SPELL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute.", description: "The user summons up to two snakes which crawl out from one's sleeves. Up to two creatures of your choice within the range of your unarmed attack must succeed a Dexterity saving throw, gaining the restrained condition until this jutsu ends and taking 2d8 bludgeoning damage on a failure. A restrained creature can attempt to end being restrained by succeeding a Strength saving throw on their turns.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d12. If cast at B-Rank, increase the amount of creatures to 3 and the radius by 5 feet. If cast at S-Rank, increase the amount of creatures to 4 and the radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "f39bb24d636428cc20f61be7", name: "HIDDEN SHADOW SNAKE BURIAL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "The user burrows their arms underground and extends their limbs to grab an opponent by their ankles, dragging them into the ground, and burying them with only their head being exposed. The target must succeed a Dexterity Saving Throw, being restrained and unable to make HS on a failure. If the target is unaware of your presence, they make their save at disadvantage. Creatures who are restrained by this jutsu can make a Strength Saving Throw as an action on their turn to end the effect of this jutsu. This jutsu ignores cover.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d194ebd790d1411ba5ba593e", name: "SNAKE CLONE TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you take damage.", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "1 round", description: "In response to being harmed, the user’s body disintegrates into dozens of small snakes and reform in the same spot moments later. Until the start of your next turn, you have a +4 Bonus to AC, including against the triggering attack. If a melee attack were to miss you thanks to this AC increase the creature who missed must succeed a Constitution saving throw or else gain the poisoned condition until the start of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the range by 5 feet and any damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "543aa3bf11d295181096f6bd", name: "SLITHERING SNAKE MODE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "9 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "The user turns the lower half of their body into a snake's tail, which greatly increases their speed and agility. You do not spend chakra to maintain concentration of this jutsu. For the duration, your movement speed is doubled, and you gain advantage on Dexterity Saving Throws and ignore difficult terrain. Additionally, you have advantage on grapple checks against you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0f60224634ebbb1bf9336145", name: "STRIKING SHADOW SNAKE ASSAULT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30-foot Cube)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "The user buries his hands and summons a large amount of snakes that emerge from underground. Creatures in this radius must succeed a Dexterity saving throw, taking 2d8 piercing and 2d8 poison damage and must make a Constitution saving throw, gaining one rank of Envenomed on a Failure. On a successful dexterity save the creature only takes half damage. This jutsu ignores total cover.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase each damage type by 1d8 piercing.", created_at: NOW, updated_at: NOW },
  { _id: "8306c9dd9a9cebf7c24974c8", name: "NATURE SNAKE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30ft", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "The user creates a snake construct of chakra, sending it towards an enemy. Make a ranged ninjutsu attack, on a hit, the target takes 4d6 force damage and must make a constitution or be knocked back 30 ft. Alternatively if you have an elemental keyword, you may instead pick one of the following effects based on the Nature Release selected. • Earth: Target Creature takes 2d10 bludgeoning damage and 2d8 earth Damage and must also make a Constitution saving throw gaining the Weakened condition until the end of their next turn on a failure. • Wind: The jutsu gains a Range of 60 Feet and deals 3d6 slashing and 3d6 wind damage. • Fire: Target creature takes 2d8 force and 2d8 fire damage, and all creatures in a 25-foot cone behind the target creature must also make a Constitution saving throw, gaining two ranks of the burned condition on a failed save. • Water: Target creature takes 2d10 cold and 2d10 bludgeoning damage and is forced to make a Strength saving throw. On a failed save, the target creature is knocked back by 15 feet and becomes prone. • Lightning: Target creature takes 2d8 force and 2d8 lightning damage, and must make a Constitution saving throw, being Shocked for 1d4 rounds on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "99e7c2e453a9a149a5051a00", name: "FORMATION OF TEN THOUSAND SNAKES", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60-Foot cone", chakra_cost: "14 Chakra", components: "CM, HS", duration: "Instant", description: "You release a countless number of snakes from your mouth or cloth that moves violently towards everyone in front of you. Creatures in a 60-foot cone originating from you must succeed a Constitution saving throw at disadvantage, taking 3d10 piercing and 3d10 poison damage and gaining two ranks of envenomed on a failed save. On a successful save they take half damage and suffer no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "8b753e738c559a554147ebf4", name: "GATHERING OF THE SNAKES", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you would take lethal damage of any type or when you would", range: "Self", chakra_cost: "14 Chakra", components: "CM, HS", duration: "Instant", description: "Snakes emerge from where the user was damaged, and pull the body back together, undoing the damage sustained. After using this jutsu, you cannot use it again for 1d4 weeks.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f06f063466b3995c88ba4066", name: "TWIN SNAKES MUTUAL DEATH TECHNIQUE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Full Turn Action", range: "Touch", chakra_cost: "20 Chakra", components: "CM, HS", duration: "Instant", description: "In order to cast this jutsu, you must unite at least one hand with the target creature that must be under the restrained or grappled condition. The user grabs one of their intended victim's hands and forces it to assist in performing the necessary hand seals. Once this is done, the user and the victim both die instantaneously.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f8b15c7ccd8c995c60d2c59d", name: "GREAT SNAKE STRIKE", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet (60-foot cone)", chakra_cost: "20 Chakra", components: "CM, HS", duration: "Instant", description: "An evolved version of the Nature Release: Nature Snake Hijutsu. The user generates multiple snake constructs of chakra to swarm and attack all creatures in a 60-foot cone, originating from a point within 60 feet. All creatures within range must make a Strength saving throw, taking 8d10 force damage and being knocked prone. Creatures who fail this saving throw by 5 or more become restrained until the start of their next turn, as they are constricted and restrained by snakes. On a successful saving throw, creatures take half as much damage and no further effects. Alternatively, if you have access to a Nature Release, you may pick one of the following effects, replacing this jutsu’s normal effects (excluding the fail by 5 or more effect); • Earth: Creatures instead take 4d10 bludgeoning and 4d10 earth damage, and gain 2 ranks of Bruised on a failed saving throw. • Wind: This jutsu gains an additional 30 feet of range and increases the size of its cone by +10ft. Creatures instead take 5d6 slashing and 5d6 wind damage and gain one rank of Bleeding on a failed saving throw. • Fire: Creatures instead 14d4+14 fire damage and gain 1 rank of Burned on a failed saving throw. • Water: Creatures instead take 10d6 cold damage and gain 1 rank of Chilled, fall prone, and are knocked back 15 feet on a failed saving throw. The affected area becomes a source of water for the next minute for jutsu of B-Rank or lower. • Lightning: Creatures instead take 6d12 lightning damage and are Shocked and Weakened for 1d4 rounds on a failed saving throw (roll once, for all affected", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c2811d61e0a7097fc823a90a", name: "WEB BIND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "5 Chakra", components: "CM", duration: "1 Minute", description: "You knead sticky webbing in your mouth and spit it out covering the target area in front of you. Creatures in the target area must make a Dexterity saving throw, being restrained on a failed save as the sticky web restricts movement for the duration. A restrained creature makes a Strength saving throw at the end of each of their turns to end this jutsu’s effect on them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the size of the cone by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "d0173829265fcf198ceb9599", name: "WEB THROW", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "CM", duration: "Instant", description: "You knead sticky webbing in your mouth and spit it out towards a creature you can see within range latching on to them and preparing to pull or throw them up to 30 feet from their original location. Target creature must make a Strength saving throw. On a failed save choose a space up to 30 feet away from the target creatures current space as you use your web to forcibly throw them into the selected space dealing 3d6 bludgeoning damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the distance you can throw a creature by 10 feet and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "f37ad04c6386ce7d5bf0368e", name: "TERRIBLE SHOT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Web Weapon: Short or Longbow)", duration: "Instant", description: "You spin your webs reinforcing your bow to have enhanced tension strength able to handle twice the normal tension put on a normal bow. Make a ranged taijutsu attack using your Web Bow. On a hit, you deal your [Weapons Damage] + 2d6.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "39bec5427424814efb3048aa", name: "SPIDER WEB UNROLLING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Reaction, which you take when a hostile creature would move at least 10 feet or cast a Jutsu with", range: "60 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "You knead sticky webbing in your hand in preparation for when a creature moves enough to catch them in a compromising position. The triggering creature must make a Dexterity saving throw. On a failed save they are restrained and knocked prone on a failed save as the sticky web restricts movement. As a bonus action on your turns, you can pull the restrained creature up to 15ft closer to you. A creature restrained by this jutsu finds it difficult to break out using pure strength due to the tensile strength of the webs. The Webs holding the creature has an AC of 5 and 12 hit points with immunity to Bludgeoning and piercing damage. If the webs are reduced to 0 hit points this jutsu immediately ends. A creature can choose to spend its action to make a Strength saving throw at disadvantage to end this jutsu’s effect on them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the hit points of the web by +12.", created_at: NOW, updated_at: NOW },
  { _id: "96050d10e6494f4611571a1e", name: "SPIDER WEB AREA", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Minute", range: "120-foot radius sphere", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Until dispelled or ended.", description: "(You must know the Web Bind Tsuchigumo Clan Jutsu to cast this jutsu) You take time to spread a network of extremely thin and almost invisible webs. For the duration of this jutsu creatures who enter the radius of this jutsu immediately alert you to their presence and location regardless of their stealth check. You can also as an action target one creature whom you can see while both you and them are in the radius of your jutsu. By ending this jutsu you attempt to ensnare the target by focusing on them and taking direct control of the webbing. The target creature must make a Dexterity saving throw at disadvantage, coming under the effects of the Web Bind Tsuchigumo Clan Jutsu on a failed save and no further effects on a successful one.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "24837477002cfa37c2018d7f", name: "SPIDER WEB FLOWER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 round", description: "You spit several small nets of webbing from your mouth at up to 3 targets. Make a Ranged Ninjutsu attack against up to three targets you can see in range. Target creatures become restrained by the webbing until the beginning of your next turn unable to form handseals.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "07a514878c735522fa5f4fe6", name: "SPIDER WEB WALL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Hour", description: "You anchor webbing between two solid masses (such as walls or trees). Creatures are heavily obscured from each other on either side of the webbing. Each creature that starts its turn in the webs or that enters them must make a Strength saving throw. On a failed save the creature is restrained as long as it remains in the webs or until it breaks free. Attacks that pass through the wall of webs destroy it, ending this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "37cd5d41ee66be0cf8e40e24", name: "TERRIBLE SPLIT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "14 Chakra", components: "CM", duration: "Instant", description: "You create a handful of special golden arrows with a drill like tip capable of ripping and shredding through, rock, bone, steel and flesh alike. You manifest a d4 stack of drill tipped arrows which can only be used with a Web Short or Longbow or When you can a Tsuchigumo clan Hijutsu that requires a Web Short or Longbow. When used as ammunition your [Weapon Damage] becomes 3d10 and pierces DR (damage reduction), temporary hit points and interposing structures.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0a777d513cc2c6d8ca1442dd", name: "BROOD MOTHER SUMMONING", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CS, CM", duration: "1 Minute", description: "You weave handseals as you summon your clans ancestral protector, the Brood Mother Arachnid. This is a Large creature that acts on its own at the end of each of your turns. You can give it direction as a bonus action on your turn, in which if you do it gains a bonus +2 to its attacks and checks as a result of receiving direction, otherwise it will act in your favor attempting to cause harm to your enemies as seen in its stat block. It uses your Ninjutsu attack bonus and Save DC when an effect calls for it. If it is killed, it is unsummoned and must spend at least 1 week regenerating, before it can be summoned again.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the Brood Mothers Arachnids hit points by 30.", created_at: NOW, updated_at: NOW },
  { _id: "3b3e7bfb793cb45600d72201", name: "RAIN OF SPIDERS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (60-foot cylinder)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "1 Hour", description: "You draw out one of your clans secret summoning scrolls, releasing a large nest of spiders that all attack in a 30-foot radius, 60 feet tall cylinder centered on you. Creatures in the target area must make a Strength Saving Throw, being Restrained & Incapacitated for the duration, on a failed save. Creatures affected by this jutsu can make an Athletics Check vs your Ninjutsu", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bbb343dc16fe217e8ff9d586", name: "GENJUTSU: SHARINGAN!", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must have the Sharingan clan feature active. By making eye contact with a creature while your Sharingan is active, you are able to cast any Genjutsu of D-Rank or lower that you could learn at no additional Chakra cost with the Visual keyword, that does not require mobility (M), a Chakra seal (CS), a weapon (W) or ninja tools (NT) components and cannot have a range of self. The genjutsu cast must have a casting time of 1 action or bonus action. The range of the genjutsu becomes the range of this jutsu and can only affect the target creature you are looking at. This can be done without breaking stealth.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 4 and the rank of the Jutsu that can be cast by 1 (D>C>B>A>S)", created_at: NOW, updated_at: NOW },
  { _id: "ee4f25b93f3d0fb0692af9f1", name: "UCHIHA AWAITING STANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you are targeted by an attack or would make a Dexterity saving", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "1 Round", description: "As a reaction, you force the triggering creature and all subsequent attacks targeting you, to roll at disadvantage or you gain advantage on the triggering Dexterity saving throw and all subsequent Dexterity saving throws until the beginning of your next turn. When a creature misses you with an attack or you pass a Dexterity saving throw, you immediately make a melee weapon attack or cast a D-Rank taijutsu or Bukijutsu that you know. If the jutsu cast is an Uchiha clan Hijutsu, you may cast it at 0 Cost. You can attack or cast a jutsu, in this way, once per casting of this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the rank of the jutsu cast by 1 (D>C>B>A>S).", created_at: NOW, updated_at: NOW },
  { _id: "d30aadbb4aeee75b366b1139", name: "UCHIHA GREAT ASSAULT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "Make a melee taijutsu attack against a target creature in range. On a hit you deal 3d8 bludgeoning damage. You also gain advantage on your next melee or Taijutsu attack against that creature on your next turn. If this jutsu is cast as a result of Uchiha Awaiting Stance, it is automatically upcast to the same rank at no additional cost.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "6ed70ccac5ef0c36289a7cfe", name: "UCHIHA SHURIKEN RAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf"], elements: [], casting_time: "1 Action", range: "30 feet (10-foot radius sphere)", chakra_cost: "4 Chakra", components: "W (Shuriken or Kunai), NT, M", duration: "Instant", description: "You consume a stack of shuriken or Kunai, and launch them at once into the air. Creatures in the target area, must succeed a Dexterity saving throw. On a failed save, the target creature(s) take 5d4 Slashing damage and become restrained in place until the end of their next turn as they are pinned to the closest surface to them or half as much damage and no additional effects on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "13a8cd9ae62bba813a338458", name: "UCHIHA EMBER BULLET", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "This is a unique variation of the “Fire Release: Phoenix Fire” Jutsu. Make a Ranged Ninjutsu attack against a target creature in range. On a hit, they take 5d6 + 5 and gain 1 rank of Burned.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and damage by 2d6+2", created_at: NOW, updated_at: NOW },
  { _id: "10faf53373f5099e440170be", name: "GENJUTSU: DEFLECT!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Reaction, which you take when you or another creature you can see fall under the effects of a", range: "30 feet", chakra_cost: "8 Chakra", components: "CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must have the Sharingan active. You may immediately attempt to make a Standard Jutsu ability check using your Genjutsu Ability modifier vs the triggering Genjutsu. On a success, you end the Genjutsu affecting you or another creature as it becomes Deflected. When you do you must select another targeting within range, that you can see and make eye contact with. The target creature must make a Wisdom saving throw. Success: The target resists this jutsu’s effects. Failure: Affected creatures falls under the effect of the Deflected Genjutsu as if you had cast it. They follow the original Failure effect of that Genjutsu. Critical Failure: Same as failure, but the target follows the original Critical Failure effect of that Genjutsu. If that Genjutsu had no critical failure effect, they instead becomes Restrained for the Genjutsu’s original duration. A restrained creature is unable to make hand signs and begins to remake their saving throw at the end of each of their turns to end this effect on them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3d5d07764a32941b07e90a06", name: "GENJUTSU: RED STAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "9 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "You attempt to put a group of creatures under a unique and powerful Genjutsu. The sun turns red and begins to slowly approaching. Select a space you can see within range. All creatures in a 20-foot radius sphere centered on this space must make a Wisdom saving throw. Success: This jutsu ends and the target resists its effects. Failure: creature gains 2 rank of fear against the sun and will try to escape any source of light opting to move into total darkness. It must spend its entire turn looking for cover or concealment from all light sources. A creature that begins its turn under any source of light takes psychic damage equal to 5d8 and remakes their save at the end of each of their turns, ending this genjutsu on a success. Critical Failure: Same as failure, but the target also takes 2d8 additional psychic damage for each rank of fear they have at the beginning of its turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e51ba92d04efb8a9c5cb8c25", name: "UCHIHA FLAME BALL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 feet (20-foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "instant", description: "This is a unique variation of the “Fire Release: Great Fireball” Jutsu. You Fire a stream of Fire 5 feet wide and up to 60 feet long in a straight line originating from you. This Fire stops at a space of your choice along this distance and expands into a large 20-foot radius sphere of blazing orange flame centering on the selected space. All creatures in both this Jutsu's stream and blazing sphere, must succeed a Dexterity saving throw. On a failed save they take 11d4+11 Fire damage and the burned condition on a failed save or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 2d4+2.", created_at: NOW, updated_at: NOW },
  { _id: "b2344a7dc7f8d439297cb6dd", name: "UCHIHA FLAME FLOWER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "This is a unique variation of the Fire Release: Hot Sun Jutsu, where you create 8 smaller ruby red spheres of Fire in the air and have them float midair no higher than 30 feet and no further than 120 feet from you. As a Bonus action on your turn, you may command a single sphere to attack a single creature. Make a Ninjutsu attack against a single creature. On a hit they take 4d8+4 Fire damage and the sphere is lost. If you miss you still lose one of the Fire spheres.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0a2b504634a6cca2b652565d", name: "GENJUTSU: EPHEMERA", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "As part of the requirements of this jutsu, you must have the Sharingan clan feature active. You look towards a target creature and attempt to place them into powerful illusion designed to torture them if they choose to not follow your command. You can give them any 1-word command that they can reliably accomplish in 6 seconds. If the command would cause harm to them in some way, this jutsu automatically ends. If they submit to the command they perform it and continue to perform it, even if they already completed it. They would repeat the same action forgetting that they already did the task for the duration. If they choose to resist the command they must make a Wisdom saving throw. Critical Success: This jutsu ends and the target becomes immune to this jutsu for the next minute. Success: This jutsu ends and the target resists its effects. Failure: The target begin to experience a massive torrent of torturous visions of your choice, that both you and they can see. Their fears, concerns, desires and regrets begin to materialize on the targets body in a variety of different ways of your description. Each turn they begin not completing your request, they take 5d10 psychic damage, gain 1 rank of Concussed and 1 rank of confused. Critical Failure: Same as failure, but the damage die instead becomes a d12.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2d5c8522eae7c69481bba692", name: "UCHIHA FLAME SPIRAL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "fef9deb945f95aa08666590c"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "The ultimate Uchiha Fire Release. As part of the requirements of this jutsu, you must have the Sharingan active. You conjure three flaming tornados. Each tornado is a column with a radius of 5 feet, and a height of 30 feet. Creatures within the tornadoes areas when you cast this jutsu and whose space the tornadoes pass through must make a Dexterity saving throw taking 10d10+10 Fire damage on a failed save or half as much on a successful one. Additionally, a creature who would make a saving throw to resist the effects of this jutsu must also make a constitution saving throw, being burned on a failed save. As a bonus action on each of your turns, you may command each tornado separately, moving them up to 60 feet each. A tornado cannot occupy the same space as another tornado. A creature cannot be affected by more than 1 tornado per turn. The Flaming tornados can be dispersed with enough force. The Flaming Tornados has an AC equal to your Ninjutsu save DC, and hit points equal to ten times your Ninjutsu Ability Modifier. The Flaming Tornado counts as a flaming construct, has vulnerability to cold damage, and when damaged by Wind damage, regains hit points", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c583e4a7f885827fb351a001", name: "ADAMANTINE STRIKING CHAINS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "33ab3a61f3027398cd08f131", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You inscribe a Chakra seal onto the palm of your hand and manifest one large Chakra-based chain from a location of your choice on your body. Make a ranged Ninjutsu attack against a creature you can see within range, as your Chakra chain smashes into them, dealing 4d6 force damage and increasing the base cost of their next jutsu cast by +5.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, damage by 2d6 and the base cost increase by +5.", created_at: NOW, updated_at: NOW },
  { _id: "ad32614ca46c6d56babbe03b", name: "BASIC SEAL", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "33ab3a61f3027398cd08f131", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "CM, CS", duration: "Instant", description: "You inscribe a Chakra seal onto the palm of your hand and create a three-point seal formation and attempt to seal away a large portion of a target creature's Chakra by slamming the seal onto the creature for a limited time. Make a melee ninjutsu attack. On a hit, the target takes 4d6 chakra damage and gains a rank of Sealed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the chakra damage by 2d6. If this jutsu is cast at B-Rank or higher, increase the number of ranks of Sealed by 1. If this jutsu is cast at S-Rank increase the number of ranks of Sealed by 2.", created_at: NOW, updated_at: NOW },
  { _id: "787c7af5eaa2d93975ed495a", name: "FONT OF LIFE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "aaeecd12fb6a8f889a26ab97", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "Special", components: "CM", duration: "Instant", description: "You sacrifice your blood, Chakra and essence to mend the injuries of an ally. A willing creature, other than yourself, may bite you, dealing 1 piercing damage, which cannot be reduced in any way. When they do, you spend Chakra die up to your remaining Chakra die. For each Chakra die spent, the target regains hit points equal to the result of the Chakra die rolled + your constitution modifier.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "eec4a740d384a1dc185e6613", name: "FLASH ANCHOR", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction, which you take when you would take damage or make a saving throw or contested", range: "Self", chakra_cost: "5 Chakra", components: "CM, CS", duration: "1 Round", description: "You quickly deploy Chakra seals around you to create an immovable defensive barrier. Until the start of your next turn, you gain a +2 bonus to your AC, saving throws, skill checks and cannot be moved by any means.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank, the bonus is increased to +4. If this jutsu is cast at S-Rank, the bonus is increased to +6.", created_at: NOW, updated_at: NOW },
  { _id: "566dea1b73c49e6c3cf0e4c4", name: "ADAMANTINE BARRIER", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "33ab3a61f3027398cd08f131", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet.", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 minutes", description: "You expertly weave a net creating an impregnable barrier using your adamantine sealing chains. The barrier appears at a point you can see within range. It can be free floating or resting on a solid surface. You form it into a sphere with a 15-foot radius. It lasts for the duration. If the wall cuts through a creature’s space when it appears the creature is pushed to one side of the wall. (You decided which side) If a hostile creature attempts to move through the barrier without the caster’s permission, it must make a charisma saving throw. On a failed save, it cannot push through the barrier for the remainder of the turn. Additionally, for the duration of the jutsu, any creatures outside the barrier who targets a creature inside the barrier with an attack or jutsu, must make a charisma saving throw. On a failed save the creature must choose a new target outside of the barrier, or lose the attack or jutsu. Area of effects can still move through the barrier as if it wasn’t there.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the size of the barrier by 5ft.", created_at: NOW, updated_at: NOW },
  { _id: "45ace541a2e7ac5f4ea19a9e", name: "ADAMANTINE BINDING CHAINS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Your body produces 4 large Chakra-based chains from your back that you control as if they were extensions of your body. They act on your order all at the same time, targeting the same creature. As a bonus action on your turn, you may have the Chakra chains act using either of the following abilities. • Whip: Make a ranged Ninjutsu attack against a target creature, dealing 4d10 Chakra Damage on a hit. • Bind: Select one creature you can see within range. The target creature must make a Strength Saving Throw. On a failed save, their movement is reduced by half and cannot make hand signs (HS). Additionally, the affected creature cannot gain bonuses to their movement or take the Dash action for the duration. A creature can remake the saving throw to end this effect as an Action.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 2d10 and the number of creatures you can target with Bind by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e69eab37bc0eddc2046496c8", name: "5-PRONGED SEAL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "33ab3a61f3027398cd08f131", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Up to 1 Week", description: "An advanced version of the Uzumaki Art: Basic Seal, requiring two Chakra seals layered on top of one another and reinforced with a 5-point seal of your design, made to lock away Chakra for powerful creatures. Make a melee ninjutsu attack against a creature within range. On a hit, the target is infused with the 5-pronged seal. For the duration, the first time the affected creature casts a Ninjutsu or Genjutsu each round, they double the base cost of the jutsu cast. Also, they have disadvantage on Chakra Control checks for the duration. After 1 week this jutsu immediately ends. A creature can attempt to make an Intelligence (Ninshou) check vs your Ninjutsu save DC as a Full-Turn Action on their turn to end this jutsu’s effect on them. If this jutsu is currently affecting a creature with ranks of the Sealed condition, any Saving throw or skill check made to remove ranks of Sealed or resist Jutsu with the Fuinjutsu Keyword is made at disadvantage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "61e2da9773b3b7fc54b09d7d", name: "UZUMAKI STUBBORNNESS", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you would fall to 0 hit points.", range: "Self", chakra_cost: "Special (12 Chakra)", components: "HS, CM", duration: "Instant", description: "Your determination and Chakra reserves are powerful enough to keep you standing despite your body suffering grievous injuries. When you fall to or below 0 hit points, you may as a reaction inject Chakra throughout your body forcing yourself to survive, instead dropping to 1 hit point. You gain an additional reaction which you can only use to cast this jutsu. This additional reaction lasts until the beginning of your next turn. You can cast this Jutsu up to three times per round. At the beginning of your next turn, you gain 1 rank of weakened for the next minute as the stress from maintaining consciousness and fighting through the trauma takes its toll on you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "56ca072af821e070f6bc4039", name: "UZUMAKI BREAK", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "33ab3a61f3027398cd08f131", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet (10-foot cube)", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Instant", description: "Using your knowledge of seals and Fuinjutsu, you surgically attempt to dismantle and break all jutsu you see within range, that is currently being maintained or is active. As part of the activation of this jutsu, select a space you can see with range make a Ninjutsu ability check against a DC (13+ rank of the jutsu, D-Rank: 1, C-Rank: 2, B-Rank: 3, A-Rank: 4, S-Rank: 5). On a success you understand the inner workings of all active Ninjutsu and Genjutsu of the result rank or lower in range and how to break them, immediately ending its effects. You decide which jutsu you want to affect when you cast this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d90566b0ecbde343581fcadd", name: "RIVER DAM SEAL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action.", range: "Touch", chakra_cost: "25 Chakra", components: "HS, CM, CS", duration: "Permanent", description: "As a part of the activation of this jutsu. The target must have at least 5 ranks of Sealed. You generate an infamous seal that grows in size so much so that it encompasses up to a 60-foot radius before instantly compressing down into a 1 kanji seal that can say or mean anything you wish. Make a melee Ninjutsu attack against the target. On a hit the seal wraps itself around the target warping the seals on them into a new and unique seal known as the River Dam Seal. River Dam Seal. This hyper powerful seal causes the target to lose all ranks of the Sealed condition as this effect replaces them. Creatures with this seal placed upon them suffer the following effects; • A creature with the River Dam Seal is counted as having 5 ranks of the Sealed condition for the purposes of interacting with features, traits and jutsu and cannot gain ranks of the Sealed condition while they have the River Dam Seal. • A creature with the River Dam Seal increases the base chakra cost of all Jutsu, features and traits that cost chakra by +15. • A creature with the River Dam Seal suffers a -5 penalty to all of their Ninjutsu & Genjutsu Save DCs. • A creature can spend a Full Turn Action to make a DC 30", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6b358049589ad2da7cc52eb2", name: "BLOOD DRAIN", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You lunge at a creature with your sharp fangs, aiming to drink deep. Make a melee Taijutsu attack, dealing your [Unarmed Damage] on hit. You also deal 3d8 Necrotic damage on a hit and recover hit points equal to half the damage dealt with the Necrotic Damage Dice of this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the necrotic damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "096d9decb1f39da74ee2d5d3", name: "CHARMING GAZE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "You gaze at a creature for but a moment, causing them to become mildly infatuated with you. They must succeed on a Charisma Saving Throw or gain 1 rank of the Charmed against you until the end of their next turn. The target is not aware that they are Charmed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the ranks of Charmed gained by +1.", created_at: NOW, updated_at: NOW },
  { _id: "17c473d399d41b79a73cd6f1", name: "CLAWS OF NIGHT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "1 Minute", description: "Turning your nails into sharp claws, your attacks with your bare hands become vicious enough to slice through walls. Your [Unarmed Damage Die] becomes 2d6 Slashing Damage. If you would cast a Taijutsu with these claws, you can change the damage type to Slashing. If you do, the Taijutsu deals an extra die of damage, once per casting.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d883a22e8f034660a6a5c935", name: "REND", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "To cast this jutsu, you must be benefitting from the Claws of Night jutsu. You lash out at a creature with your claws, attempting to unleash the blood within. Make 2 melee Taijutsu Attacks, each dealing your add your ability modifier to the damage dealt. For every two attacks you hit with this jutsu, the target gains 1 rank of Bleeding. Until the end of the current turn, you may target one affected creature with a Taijutsu with the Finisher keyword, as an action or bonus action, regardless of range, ignoring the jutsu’s listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to C-Rank or higher, add half your ability modifier to the damage of this jutsu. If cast to B-Rank or higher, make an additional attack with this jutsu. If cast to A-Rank or higher, you instead add your full ability modifier to the damage of this jutsu. If cast to S-Rank or higher, make an additional attack with this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "ba9326d4409b0dc00e142ae2", name: "MISTY LEAP", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "Your form turns into that of a fine mist. You may move up to 40ft in any direction, including up. You are able to fit through small gaps with ease. At the end of this movement, you return to your normal state. If you cast this jutsu whilst moving against heavy wind, you only move up to half the maximum distance.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the distance you move by 20 feet.", created_at: NOW, updated_at: NOW },
  { _id: "60b7b6418078394e81bc2e1e", name: "MISTED AVOIDANCE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, when you take damage", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "Your body turns into a puff of smoke as you dash away to avoid harm. Make a melee Taijutsu attack, using your choice of Dexterity or Charisma as your Taijutsu ability modifier, contested by the attack roll or DC of the ability used. If you roll higher, you take no damage and move anywhere within 30ft. If you fail, reduce the damage by twice your proficiency bonus.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fc5d8f03fc11018fed0878d9", name: "MORTAL FEAR", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "9 Chakra", components: "CM", duration: "Concentration, up to 1 Minute", description: "You stare into the soul of a creature, forcing them to confront their mortal nature. They must succeed a Charisma Saving Throw or gain 2 ranks of Fear against you and take 1d6 Psychic damage, piercing DR and temporary hit points. If you maintain this jutsu, they must make the same saving throw at the start of each turn. If they have 5 ranks of Fear, they are treated as being Vulnerable to the Psychic damage of this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the Psychic damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "b0f5054e1062b2576ffa324a", name: "THRALL", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "10 feet", chakra_cost: "13 Chakra", components: "CM", duration: "10 Minutes", description: "Whispering words of command or affection to a creature close to you, you force them into servitude. They must succeed a Charisma Saving Throw or become Charmed. While Charmed this way, they will act as your loyal servant and perform actions they normally may not, such as even harming an ally. If you command them to harm their allies in any way, they may remake their saving throw once the command is executed, ending this condition and thus this jutsu on a success. Starting from the second time you command a creature to harm their allies, the creature gains a +1 bonus to their saving throw to end this jutsu, which stacks.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "973717ce3ad5817fe2e3f255", name: "VAMPYR", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You tap deep into your bloodline, unleashing a similar power to what the great Bat Sage once had, becoming a true creature of darkness. For the duration, gain the following features; • You gain a +2 bonus on all Strength, Dexterity and Charisma skill checks and saving throws. • You benefit from the Claws of Night jutsu at no extra cost and the damage of the claws increases to 2d8. • Your Speed increases by 15ft, and you do not provoke attacks of opportunity. • Once per turn, you may deal an additional 2d4 Necrotic Damage when dealing damage of any kind. If you are within Dim Light or Darkness, you gain additional benefits; • Increase the bonus to Strength, Dexterity, and Charisma skill checks and saving throws by +1 (+3), and gain this bonus on attack rolls made using these ability scores. • Increase your movement speed further by +15 feet. • Each time a creature would gain any ranks of Charmed or Fear from you, increase the total by 1.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b84fb46c64ff7ffc0c1fe55b", name: "THROATSLICER", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "20 Chakra", components: "M", duration: "Instant", description: "To cast this jutsu, you must be benefitting from the Claws of Night jutsu. You make a single quick cut to a creature’s throat with your claws. Make a Taijutsu Attack. On a hit, you deal your [Unarmed Damage] + 9d8 Slashing Damage, and the target must succeed a Constitution saving throw or become Dazed and Lacerated. If this jutsu is used as a Finisher, the damage is instead your [Unarmed Damage] + 10d10 slashing, and on a failed saving throw, the target is Incapacitated until the end of their next turn and gains 3 ranks of Lacerated. If a creature reaches 0 hit points as the result of this jutsu, they immediately die as you slice their throat.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d8 or 2d10", created_at: NOW, updated_at: NOW },
  { _id: "d2f1b0c460661f8f5845873d", name: "FIRST CUT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Katana or Odachi), M", duration: "Instant", description: "You assume a readied stance before swinging for a creature’s midsection. Make a melee taijutsu attack on a creature within range. On a hit you deal your weapons damage + 3d6 and the target gains 1 rank of bleed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "f3ed71f9b98eb5cc48bee916", name: "ENTRY CUT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Reaction, which you take when initiative is rolled.", range: "Movement Speed", chakra_cost: "4 Chakra", components: "W (Katana or Odachi), M", duration: "Instant", description: "You quickly dash forward as you draw your sword with the intent to finish the battle before it begins. Make a melee taijutsu attack on a creature within range. On a hit you deal your weapons damage + 2d6. If this attack scores a critical hit the creature is counted as surprised for the first round of combat.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 the damage by 1d6, and the critical threat range by +1.", created_at: NOW, updated_at: NOW },
  { _id: "cad05afd361c8db44fb48ff9", name: "QUICK CUT", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "5 Chakra", components: "W (Katana or Odachi), M", duration: "Instantaneous", description: "You strike so fast your enemy doesn’t have time to react. Make a melee taijutsu attack on a creature within range. On a hit you deal your weapons damage + 3d6. If the target would cast a Jutsu as a Reaction to the damage you deal, the cost of their jutsu is increased by  +6 due to the strain required to keep up with your strike. If their jutsu or choice of reaction, does not cost chakra, they must spend 12 chakra to take their reaction.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d6 and the extra cost to take a reaction by +4.", created_at: NOW, updated_at: NOW },
  { _id: "74006aa5b0e992725bc64927", name: "KISHO GUARD", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Reaction, which you take when you would take damage, excluding from Genjutsu", range: "Self", chakra_cost: "5 Chakra", components: "W (Katana or Odachi), M", duration: "1 round", description: "You assume a stance meant for your blade to block and your body to swiftly avoid incoming blows, until the start of your next turn you gain a +4 to your AC and when you are hit by an attack, reduce the incoming damage by your Strength modifier (maximum 5).", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3. If you cast this jutsu at B-Rank you instead reduce damage by twice your Strength modifier (max 10). If this jutsu is cast at S-Rank, you instead reduce incoming damage by your weapon’s damage.", created_at: NOW, updated_at: NOW },
  { _id: "89105034e3bca6294f5df4bb", name: "SECOND CUT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Bonus Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Katana or Odachi), M", duration: "Instant", description: "This jutsu can only be cast directly after you hit with Multi-Swing Style: First Cut and must target the same creature. After slashing the creature’s stomach, you bring the blade up and attempt to strike diagonally across their chest. Make a melee taijutsu attack on a creature within range. On a hit you deal your weapons damage + 4d8 and the target must make a Constitution saving throw gaining 2 ranks of bleed on a failure. If they roll a 1 or 2 on the saving throw, they instead gain 4 ranks of bleed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "d84c5ad86094f83521effc94", name: "DISARMING CUT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Katana or Odachi), M", duration: "Instant", description: "You attempt to disarm an opponent. Make a melee taijutsu attack on a creature within range. On a hit you deal your weapons damage + 6d6 , and the target must make a Strength saving throw dropping their weapon on a failure. If you roll 4 or more 6’s on a d6, with this jutsu’s damage die, you cut off the creature’s arm at the elbow.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "b8428aeff24a927f343491d5", name: "DISABLING CUT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Weapon Range", chakra_cost: "8 Chakra", components: "W (Katana or Odachi), M", duration: "Instant", description: "You try to sever the tendons on a creature’s leg preventing them from fleeing. Make a melee taijutsu attack on a creature within range. On a hit you deal your weapons damage + 7d4 and the target must make a Dexterity saving throw halving their movement speed on a failure until the end of their next turn. If you roll 5 or more 4’s on a d4, with this jutsu’s damage die, you cut off the creature’s leg. Their movement speed is reduced by 15 feet, cannot Dash Dodge or Disengage using their walking speed, and double the cost of all jutsu with the M component until their leg is healed or they gain a replacement.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "b8d2306cdcd98f165b6e1aad", name: "THIRD CUT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Reaction, which you take after you score a hit with Multi-Swing Style: Second Cut.", range: "Weapon Range", chakra_cost: "14 Chakra", components: "W (Katana or Odachi), M", duration: "Instant", description: "This jutsu can only be cast directly after you hit with Multi-Swing Style: Second Cut and must target the same creature. After performing the diagonal slash, you bring your sword upward in the opposite direction creating an “X” slash across their chest. Make a melee taijutsu attack on a creature within range. On a hit you deal your weapons damage + 6d10 and the target must succeed a Constitution saving throw or become stunned until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "d61f95e6236ac6dbaf206966", name: "MULTI-CUT", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Self (30-foot Line)", chakra_cost: "14 Chakra", components: "W (Katana or Odachi), M", duration: "Instant", description: "You quickly dash forward in a straight line attempting to cleave multiple people in two. Make a melee taijutsu attack, comparing the result against each creature within a 5-foot wide, 30-foot long line. On a hit you deal your weapons damage + 6d10 and creatures must make a Constitution saving throw, gaining 2 ranks of bleeding on a failed save. If you roll 4 or more 10’s on this jutsu’s damage die, the first creature hit by this attack is instantly cleaved in half, instantly killing them, for each additional 10 you roll afterwards, the next creature in the line is also cut in half.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, the damage by 1d10, and the length of the line by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "75e35ca04608360f72d7e521", name: "FINAL CUT", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "Special", range: "Weapon Range", chakra_cost: "20 Chakra", components: "W (Katana or Odachi), M", duration: "Instant", description: "This jutsu can only be cast immediately after Multi-Swing Style: Third Cut, and must target the same creature. You step back slightly and perform one final cut attempting to behead the creature. Make a melee taijutsu attack. On a hit you deal your weapons damage + 12d12, rerolling 1’s and 2’s taking the second result and the creature gains 5 ranks of lacerated. If you roll 4 or more 12’s on a d12, with this jutsu’s damage die, the creature is immediately beheaded. If the target creature is stunned when you cast this jutsu, and you beat their AC by 5 or more, this attack automatically scores a critical hit. After casting this jutsu you gained the Dazed condition until the end of your", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6e0f3d3d5ebd6d1bccd7850d", name: "MIND BODY TRANSFER", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 minute", description: "You perform the Yamanaka Clans most prolific jutsu invading the mind and body of a target creature and overwriting their consciousness with your own. Target one creature you can see within range with sentient thought such as another Human, animal, or anything that fits the previous sentient thought pre- requisite. Puppets, inanimate objects and even some foreign creatures may be immune to this jutsu such as Mutants or Demons. Be sure to Check with your DM to see what may not be applicable. The select creature must make a Charisma saving throw. On a Failed save, you transfer your consciousness into your target's body for 1 minute. Once you possess a creature's body, you control it and act on its turns, using its body. While you are inhabiting the body of another creature, you gain the following; • When making Attack rolls, skill checks or Casting Jutsu you know that uses Strength, Dexterity or Constitution, you instead use the statistics of the creature who’s body you are occupying. • When making Attack rolls, skill checks, or Casting Jutsu you know that uses Intelligence, Wisdom or Charisma, you continue to use your own statistics. • You retain the benefit of your own class and clan features. You cannot activate or cast class features or jutsu that would inflict negative conditions on the host body, such as Exhaustion. • You gain access to any General or Clan traits the creature may have that you are aware of. • You do not have access to any Class or Role Traits/Features that the creature may have. • You retain access to your own list of Hijutsu, Ninjutsu, Taijutsu, Bukijutsu and Genjutsu. • You do not gain access to the host creatures list of Jutsu under any circumstances. But you can end concentration on jutsu they were concentrating on or gaining the benefit from. • If the host body takes any damage, they immediately attempt another saving throw, ending this effect on a successful save. On a successful save, you fall unconscious until the beginning of your next turn at which time your consciousness returns to your body. • The host does not count as willing to effects that they would not normally be willing for. • Your body is left where you last were before you cast this ability. It is functionally unconscious", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "caae73df782ceef409f4f15a", name: "BESTIAL MIND DOMINATION", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 minute", description: "You perform a less intense version of the Mind body transfer technique on an animal or some creatures with less mental fortitude than a human. Select a single target creature that you can see within range. Target creature must succeed an Intelligence saving throw against your Genjutsu save DC, becoming friendly towards you and becoming more inclined to complete tasks for you for the duration, on a failed save. The affected creature will fight for you if asked. While they are friendly towards you, you can command them with both verbal and non-verbal actions. You can also understand things about them, such as them", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "62536f495bb5642570bc1fa3", name: "MIND BODY DISTURBANCE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You perform a modified version of the Mind body transfer technique on a humanoid creature you can see within range disassociating the mind and bodies activities and then forcing them to reset causing a significant amount of Psychic damage to the creature. Target creature must succeed a Charisma saving throw. On a failed save target creature takes 3d8 Psychic Damage and is Dazed or half as much damage on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "49cd4f19415bb48ada774bee", name: "MIND DETECTION TECHNIQUE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (90 Feet)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 Minute", description: "Using the Yamanaka Clan family teachings, you manifest a minor telepathic field around yourself. You become aware of all creatures who are capable of sentient thought within 90 feet of you. While you are aware of a creature presence it does not automatically reveal them from stealth but you do become aware of the direction they are in relation to you. Creatures whom you are not familiar with or whom you have sensed before with this jutsu are immediately recognizable, being able to distinguish who they are from memory alone.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank, the duration becomes 10 minutes. If this jutsu is Cast at B-Rank, the radius becomes 500 feet. If this jutsu is cast at S-Rank, the radius becomes 1 mile.", created_at: NOW, updated_at: NOW },
  { _id: "66a3340b4c17807b01ab1802", name: "MIND CONNECTION TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "500 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "10 minutes", description: "You create a temporary telepathic link between yourself and a willing creature with which you are familiar and within range. Until the jutsu ends, you and the target can instantaneously share words, images, sounds, and other sensory messages with one another and the target recognizes you as the creature it is communicating with. The target must be able to understand the messages and pictures you are sending it in order for it to comprehend your intentions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "60d83c2ce1197fb9a0e4fb41", name: "MIND CLONE TECHNIQUE", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 minute", description: "You split your consciousness into two identical clones of each other. You then perform the mind body transfer as normal on up to two target creatures you can see within range. Both creatures must make a Charisma save against your Genjutsu save DC. On a failed save target creature, you transfer your consciousness into your target's body for 1 minute. They are controlled by you as if their body was yours. On a successful save, you fall prone until the beginning of your next turn unable to move or act otherwise until your consciousness returns to your body. Each body is controlled by a separate consciousness and therefore do not know what the other is thinking but will act as you would for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "de1770d44f4dee182055dfbb", name: "MIND BODY AUGMENTATION", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Using the Yamanaka clans propensity for mental exploration, you are able to enhance the mental receptors of a willing creature you can touch, within range. Pick one between Intelligence, Wisdom and Charisma. For the duration, the affected creature gains proficiency in the chosen ability scores saving throw. A creature that already has proficiency in the chosen score instead gains a +2 bonus to saving throws made with said score.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at A-Rank, you may select +1 additional creature.", created_at: NOW, updated_at: NOW },
  { _id: "639a8ede45b4c9bbf4e5446e", name: "MASS MIND BODY DANCE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You issue a course of action (limited to a sentence or two) and influence up to 6 creatures of your choice that you can see and can hear you within range. Each target must make a Charisma saving throw against your Genjutsu save DC. On a failed save it pursues the course of action to the best of its ability. A creature cannot be ordered to harm themselves in any way or be made to perform an action that they know would harm themselves as a result. The commanded action will continue to be attempted the entire duration. If the activity is completed in a shorter time, the jutsu immediately ends. Creatures are fully conscious of their actions, but cannot stop themselves for the duration of this jutsu. If a creature would take damage of any kind for the duration, they remake the Saving throw at Advantage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "af964e69390c0ee9c5b0c662", name: "MASS MIND BODY DISJUNCTION", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (30 Feet)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "Using the same principles as Mind body disturbance, you emit a wave of psychic chakra that resets the connection of a creatures mind and body. All creatures of your choice within 30 feet of you, must succeed a Charisma saving throw, taking 8d6 psychic damage and becoming dazed until the start of your next turn on a failed save or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "66fde755d28c5b246da2b66c", name: "CURSED SEAL", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Week", range: "5 Feet", chakra_cost: "20 Chakra", components: "HS, CM, NT, CS", duration: "Permanent", description: "You take a puppet, doll, or an item of humanoid shape, no smaller than 1 size category of the target and place a secret Yamanaka sealing jutsu on the item. You can only have one such item created at a time and creating another destroys the existing item. You create conditions and triggers for the seal beforehand and place them on the item. Once placed, when a creature triggers the chakra seal, the triggering creature must immediately succeed a Charisma Saving throw against your Genjutsu or Ninjutsu save DC (Whichever is higher). On a failed save, the target creature's consciousness is sealed inside of the item used. While sealed, the target creatures’ body immediately becomes Incapacitated as their consciousness is now locked away inside of an object of the user’s choice. They do not have the capacity to make any further saves unless their original body is damaged, in which case they can attempt a Charisma Saving Throw to escape. If the item is destroyed this jutsu ends and the creature's consciousness attempts to re-enter their body. If the body is dead, their consciousness is trapped wandering unable to bind to anyone or anything, they are effectively dead and cannot be revived.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a2d58f8ff1229d0d83b79d64", name: "GREAT MIND-BODY SYNCHRONIZATION", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (1 Mile)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 10 Minutes", description: "You focus all of your being inwards, and open your mind to all willing creatures within a mile of you, establishing a telepathic link, with the ability to transfer information and lend aid at the speed of thought. Until the jutsu ends, you and the targets are aware of all creatures under the effects of this jutsu, and can instantaneously share words, images, sounds, and other sensory messages with any number other creatures affected by this jutsu, and the recipient is aware of who communicates with them. Additionally, when an affected creature casts a Ninjutsu or Genjutsu, they use the highest Ninjutsu or Genjutsu ability modifier for attack rolls and save DC. Lastly, the passive perception and passive insight of each creature affected increases by half of your", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b8868a2d823fe5157755a6db", name: "LAVA STREAM", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (20-foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You combine Fire and Earth Release Chakra in your mouth before releasing a stream of lava in a cone in front of you. All creatures in the radius of this jutsu must make a Dexterity saving throw, taking 2d6 Fire and 2d6 Earth damage and being burned on a failed save or half as much damage on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and damage by 1d6 of each damage type and the range by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "9440bf2e9bf71d8d0d080f9c", name: "LAVA ROCK", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You combine Fire and Earth Release Chakra in your palm conjuring a mass of lava, that you launch at a target you can see within range. Make a ranged ninjutsu attack, on a hit you deal 2d8 Fire and 2d8 Earth damage and the lava splashes outward. All creatures within 10 feet of the original target must make a Dexterity saving throw taking 1d6 Fire and 1d6 Earth damage on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the attacks damage by 1d8 and 1d6 of each damage type respectively.", created_at: NOW, updated_at: NOW },
  { _id: "7dffb089428271e468c917d4", name: "QUICKLIME HARDENING", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You gather Lava release Chakra in your mouth, before spitting out a glob of quicklime at a target. Make a ranged ninjutsu attack against a target you can see within range. On a hit, you deal 3d6 Fire damage and the target must make a Constitution saving throw, gaining the burned conditions on a failed save. If a creature burned by this jutsu, takes cold damage before the end of their next turn, they must succeed a Strength saving throw, being petrified for one of their turns.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "f4a426d97c989b031c581412", name: "RUBBER DEFENSE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Reaction, which you take when you would take damage.", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "The user quickly exudes a protective coating of rubber around them increasing their AC by +3 and gaining 15 temporary hit points until the beginning of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the temporary hit points by 10.", created_at: NOW, updated_at: NOW },
  { _id: "9f8912e79eed3e3e0471634b", name: "RUBBER BALL", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Reaction which you take when an ally or object is targeted by an enemy", range: "30 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 Round", description: "You quickly spit out a blob of rubber designed to protect your target. The target creature gains 20 temporary hit points until the beginning of their next turn. If they were targeted by a melee attack, the triggering creature makes a Strength check vs your Ninjutsu save DC, being pushed back 15 feet on a failed check.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3, and the temporary Hit points by 10.", created_at: NOW, updated_at: NOW },
  { _id: "c6c1dd574aa471e97acb9ef3", name: "EXPANDING FLAME RINGS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "45d71f187e5dc189329c0f97", "88053ac8cbcd506835027aab"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM, W (any Shuriken or Chakram)", duration: "Instant", description: "You use Lava release Chakra to augment a Shuriken or Chakram that you have turning it into a bright red glowing piece of metal that keeps the shape of the Ninja tool used. You then throw them with extreme force. Make a ranged Ninjutsu (or Taijutsu) attack. On a hit, you deal your weapons damage + 3d10 Fire damage. All creatures within 10 feet of the original target (excluding you) must succeed a Dexterity saving throw, taking 2d10 Fire damage on a failed save or half as much on a successful one. If a Shuriken is used for this jutsu, you reduce your ammunition die by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 2d10 LAVA RELEASE: RUBBER WALL", created_at: NOW, updated_at: NOW },
  { _id: "bfb07f82814c48a03858e0cb", name: "RUBBER WALL ENHANCEMENT", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Bonus Action", range: "15 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You slam your hands onto the ground where rubber erupts from the ground directly in front of you. The wall is 15 feet tall, 15 feet wide, and 10 feet thick. The wall is a Quake Shard, with an AC equal to your Ninjutsu save DC, temporary hit points equal to 5d8+15 and resistance to piercing and slashing damage, with immunity to bludgeoning damage. If this wall is anchored to another structure, such as a wall or tree, the wall and the structure it is attached to gains additional temporary hit points equal to your Ninjutsu ability score and gains resistance to piercing and slashing damage, immunity to bludgeoning damage and loses any vulnerability to lighting damage, if any.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the temporary hit points by 1d8+5.", created_at: NOW, updated_at: NOW },
  { _id: "2b8b70f8790c9aa2b0a24999", name: "LAVA CHAKRA MODE", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You coat your body in lava release Chakra, gaining a multitude of benefits. You cannot lose concentration on this jutsu as a result of damage; • You gain a +2 bonus to AC. • You gain 10 temporary hit points at the beginning of each of your turns. • You gain Immunity to Fire and Earth damage. • You gain resistance to bludgeoning, piercing, slashing and Wind damage • You gain Vulnerability to cold damage. • You count as a Quake Shard for jutsu or features that you use that require them. • At the end of each of your turns, adjacent creatures of your choice takes 5 Fire damage. This pierces DR (damage reduction) • Your [Unarmed Damage] becomes 2d6 Fire damage. • Successful melee attacks against you deal 10 damage to the attacking creature. This pierces DR (damage reduction). • Yoton clan Hijutsu increases their damage die by 1 step. (D4>D6>D8>D10>D12). • When you would create difficult terrain using a jutsu with the Earth Release keyword, the affected spaces become lava pools, dealing 1d10 Fire damage to creatures who begin their turns in them. • When you would create an area of effect using a Jutsu with the Fire Release keyword, the affected space becomes superheated with molten stone until the beginning of your next turn. Creatures who begin their turn in this area gain 1 rank of the burned condition.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and temporary hit points by +5.", created_at: NOW, updated_at: NOW },
  { _id: "27d97c5dc4dcc81f2396e2b0", name: "SCORCHING STREAM ROCK", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (60-foot line)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You coat your hand in Lava release Chakra as you punch forward creating a super-heated shockwave with enough heat to melt rock. All creatures structures and constructs in a 60 feet long, 5 feet wide line directly in front of you must succeed a Dexterity saving throw taking 8d8 Fire damage on a failed save and gaining the burned and corroded condition. On a successful save, you instead deal half damage. All Structures that are destroyed by this jutsu melt becoming a molting pool of fluid that acts like Lava. Its space becomes difficult terrain. A creature that attempts to move through the affected space takes 2d10 Fire damage and gains the burned and corroded conditions.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of the jutsu by 3, and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "69d3c480135418e663fac6d7", name: "PLANET-BRANDING BLAST", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (45-foot Cube)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You punch the ground and conjure an eruption of lava and magma, enough to fill a 45-foot cube originating from you. All creatures in range, must succeed a Dexterity saving throw taking 10d10 Fire damage and gaining 1 rank of Burned, Corroded and Bruised on a failed save and half as much damage on a successful save. Additionally, the affected area becomes filled with lava, pooling until it is covered in a thin sheet of it. For the next 10 minutes, this area is treated as hazardous terrain filled with lava. Creatures, structures and constructs that would begin their turn in or would enter this hazardous area for the first time on their turn take 1d10 Fire damage and must succeed a Constitution Saving Throw or gain 1 rank of Burned and Weakened.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3,", created_at: NOW, updated_at: NOW },
  { _id: "2e30408e7b234a19cd33807b", name: "ICE DAGGERS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "50 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You collect Water particles from the air itself and freeze them into daggers made of ice, before you throw them at a target creature. Make a ranged ninjutsu attack dealing 3d6 cold damage on a hit Regardless of a successful hit or not, all creatures excluding this jutsu’s caster within 10 feet of the target must make a Dexterity saving throw, taking 2d6 cold damage and inflicting 1 rank of Chilled on a failed save or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 for each instance of damage.", created_at: NOW, updated_at: NOW },
  { _id: "b13f57755137a2eb01b49876", name: "ICE PRISON", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You release a stream of jagged Ice crystals forward before they explode upward into a mist and resolidify over a creature freezing them in place. Select one target creature in range. Target creature makes a Dexterity save being stunned for the duration and gains a rank of Chilled as a result of being encased in ice on a failed save. A creature stunned inside the ice is deafened but can otherwise see everything they normally could while frozen. The ice trapping the creature has an AC equal to your Ninjutsu save DC and 10 Hit points. If its hit points are reduced to 0 this jutsu ends. Any excess damage is dealt to the target creature. The target creature on its turn, makes a Strength saving throw to break out of the ice at the end of its turns.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c0934266b1701bb00133d890", name: "ICE DOME OF NOTHINGNESS", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Reaction, which you take when you or an allied creature within range would take damage.", range: "Self (5-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 round", description: "You quickly materialize a dome of ice protecting yourself and creatures within 5 feet of you. The dome of Ice intercepts all attacks until the start of your next turn absorbing the damage until it shatters. Any excess damage is transferred to you. The dome has an AC equal to your Ninjutsu Save DC and 25 Hit points.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the Domes Hit points by 10", created_at: NOW, updated_at: NOW },
  { _id: "460e5279fc08808a8a829458", name: "ICE NEEDLE", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Bonus action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure Water into the shape of a thin sword like construct in your free hand. You do not spend Chakra to maintain concentration on this jutsu. The blade is 5 feet long, the handle is 1 foot long. The design of the blade can be whatever you decide. If you let go of the blade it disperses into Water again. You can use your action to make a melee Ninjutsu or Taijutsu attack with the Ice sword. On a hit, the target takes 2d10+Ninjutsu ability modifier cold damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at C-Rank, increase the damage by 1d10. If this jutsu is cast at B-Rank, increase the number of attacks you can make with this weapon to two. If this jutsu is cast at S- Rank, increase the number of attacks you can make with this weapon to three.", created_at: NOW, updated_at: NOW },
  { _id: "ebe13a021504c4ee9340042a", name: "CERTAIN-KILL ICE SPEARS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (10-foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You slam your palms onto the ground instantly freezing the air around you creating spears of ice impaling everything around you, making the area this jutsu was casted in as difficult terrain. Creatures in this jutsu radius, excluding yourself, must make a Dexterity saving throw, taking 3d10 cold damage and gaining 1 rank of chilled on a failed save or half as much on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d10. If this jutsu is cast at A-Rank or higher, increase the ranks of chilled to +2.", created_at: NOW, updated_at: NOW },
  { _id: "073b4e1a80c1db8ccd47e4f1", name: "FROZEN CAPTURING FIELD", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "self (30 feet cube)", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "The ground erupts outward from you covering a 30-foot cube across the ground freezing the feet of creatures in range. Creatures in range must make a Dexterity saving throw, being restrained and gaining a rank of chilled on a failed save. Creatures captured in this jutsu can make strength saving throw as an action on their turn to escape this jutsu. The area this jutsu affects leaves behind an Ice- covered ground being treated as difficult terrain. Creatures who enter this area of this jutsu must make a Dexterity saving throw to avoid falling prone on the slippery surface of the ice. The Ice remains until melted or 1 hour has passed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cdbae5cb6b101548a3af019f", name: "TEN THOUSAND ICE PETALS", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "20ee567a744c63cf38fc80c9"], elements: [], casting_time: "1 Action", range: "Self (40-foot cone)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You freeze Water and air in front of you while launching it forwards creating an innumerable onslaught of ice daggers that tears through everything in a 40-foot cone. Creatures in range must make a Dexterity saving throw. On a failed save, creatures take 4d8 cold damage and gain 1 rank of chilled on a failure or half as much on a success. If a construct, structure or object would take damage from this jutsu, it takes double damage as its structural integrity is affected by the extreme cold.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8. If this jutsu is cast at A-Rank or higher the increase the ranks of chilled inflicted to +2.", created_at: NOW, updated_at: NOW },
  { _id: "a88a214a042bb1b9d80ec72d", name: "TEARING DRAGON, FIERCE TIGER", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure a large Tiger or dragon made of snow or ice you make. Upon casting this jutsu choose which creature you summon which determines how the Jutsu works and its range and effect radius. • Tiger: The Tiger forms and begins to rush at a target creature. If there is any Water or Water Release Jutsu in between you and the target creature, it immediately freezes, ending the jutsu. Creatures submerged within Water or gaining the benefits of a Water Release jutsu with a range of Self or Touch must succeed a Dexterity save, gaining 2 ranks of chilled on a failed save. Upon reaching the target, the Ice Tiger then explodes firing ice shards in a 30-foot radius centering on the target. All creatures in the radius must succeed a Dexterity saving throw taking 12d4 cold damage and gaining 1 rank of Chilled on a failed save or half as much damage and no further effects on a successful save. • Dragon: The Dragon forms and begins to rush at a target creature. If there is any Water or Water Release Jutsu in between you and the target creature, it immediately freezes, ending the jutsu. Creatures submerged within Water or gaining the benefits of a Water Release jutsu with a range of Self or Touch must succeed a Dexterity save gaining 2 ranks of chilled on a failed save. Upon reaching the target, the dragon slams into the target creature. Creatures in a 90-foot long, 10-foot-wide line, originating from you, must succeed a Strength saving throw taking 8d6 cold damage, gaining 1 rank of chilled and are push back 10 feet on a failed save or half as much damage and no further effects on a successful save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1783e1a2ded1a4623833057e", name: "TWIN DRAGON WHIRLWIND", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "20ee567a744c63cf38fc80c9"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius sphere)", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You freeze the air around you and swirl it creating a localized ice storm. For the duration you cannot be targeted by ranged attacks or effects that require line of sight. Creatures who enter the radius of your whirlwind must make a Constitution saving throw. On a failed save, they gain 2 ranks of chilled. Additionally, creatures within the radius of this jutsu who failed the saving throw are blinded by the strong Winds and ice shards slicing at their eyes for the duration or unless they leave the radius.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7cd1853ac2cc52cf9e38d429", name: "DEMONIC ICE MIRRORS", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "20ee567a744c63cf38fc80c9"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius Sphere)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a dome of Chakra enhanced reflective Ice mirrors. This dome encompasses a 20-foot radius and the enhanced mirrors line the radius of the dome. Each mirror is 4 feet wide and 6 feet tall. Upon manifestation you create enough mirrors to occupy the outside radius of the sphere leaving about 2 feet of space between each mirror on each side. You meld inside one of the Ice mirrors and gain the ability to teleport to any other ice mirror within this jutsu’s radius, by spending 5 feet of movement. While inside of your Demonic Ice Mirrors you are nearly imperceptible, as your ice mirrors make perfect duplicates of yourself reflect on their surface. While in your ice mirrors, creatures are unaware of your location. Each time you make an attack, or use your movement to teleport, each creature within the dome can make a perception check at disadvantage against your Ninjutsu Save DC at disadvantage, to find your location. Creatures with Chakra Sight instead make this check at advantage. Also, while inside of your Demonic Ice Mirrors, you gain a +5 bonus to AC and have advantage on Dexterity saving throws, and gain access to the following special actions; Reflective Ice Needles. As an Action, make three ranged attacks, targeting all creatures within the radius of the Demonic Ice Mirrors, dealing 4d8 cold damage. Reflective Frost Dispersal. As a reaction to creatures attempting to move more than 10 feet while inside the radius the mirrors, you make two melee/ranged Ninjutsu attacks, dealing 4d6 cold damage to the target and reducing their movement speed to 0. The first time you use this reaction per round, you gain two additional reactions until the start of your next turn (Taking Elite Actions does not remove these reactions early). These reactions can only be used to take this special reaction again. Creatures inside the radius of your jutsu can move freely throughout the radius of it. A creature who wishes to leave the radius can make a Dexterity save attempting to squeeze through your", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9e8de13cd5f40a3f10ff293e", name: "Example Jutsu Name", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 chakra", components: "Hands", duration: "30 seconds", description: "Its hawter than an Amaterasu!", at_higher_ranks: "Double Amaterasu??", created_at: NOW, updated_at: NOW },
  { _id: "5d2a7fbd90dc4fb957e43d1e", name: "Decaying Explosion", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "", range: "", chakra_cost: "", components: "", duration: "", description: "1", at_higher_ranks: "1", created_at: NOW, updated_at: NOW },
  { _id: "983309bbf87cc38a112b95ea", name: "Energy Ball Explosion", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "", range: "", chakra_cost: "", components: "", duration: "", description: "2", at_higher_ranks: "2", created_at: NOW, updated_at: NOW },
  { _id: "911ed50bda17c005979928db", name: "Thunder Ray Explosion", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "", range: "", chakra_cost: "", components: "", duration: "", description: "3", at_higher_ranks: "3", created_at: NOW, updated_at: NOW },
  { _id: "5d7c68434edb07bae24ec895", name: "Inner Core Explosion", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "", range: "", chakra_cost: "", components: "", duration: "", description: "4", at_higher_ranks: "4", created_at: NOW, updated_at: NOW },
  { _id: "5ad21e6ca0890371520a2efc", name: "Outer Core Explosion", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "", range: "", chakra_cost: "", components: "", duration: "", description: "5", at_higher_ranks: "5", created_at: NOW, updated_at: NOW },
  { _id: "56fb7a600bc94d5321c9a986", name: "Explosive Ball Storage", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: ["raiton"], casting_time: "", range: "", chakra_cost: "", components: "", duration: "", description: "6", at_higher_ranks: "6", created_at: NOW, updated_at: NOW },
  { _id: "8cb637d24b0415e371622de4", name: "Toxic Release: Caustic Blades", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "4 Chakra", components: "CM, HS", duration: "Concentration, up to 1 minute", description: "You coat either your fists or a melee weapon within reach with fuming toxic chakra. If coating your fists, you may use Intelligence for its attack and damage rolls. Your fists or the weapon now deal an additional 1d8 poison damage on each hit. When you score a critical hit against a creature this way it must succeed a Constitution saving throw or become envenomed. Creatures you damage with a melee attack enhanced by this jutsu that have ranks of envenomed inflicted take an additional 1d6 poison damage for each rank it possesses.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "812ddf71f7568da0ffe57b87", name: "Toxic Release: Fever Dream", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet (5-foot Sphere)", chakra_cost: "5 Chakra", components: "CM, HS", duration: "Concentration, 1 minute", description: "You lace the air of a toxic bubble with hallucinogenic toxins, inciting horrific visuals. You create a 5-foot sphere of invisible toxins at a points you can see in range. Creatures within the sphere must make a Wisdom saving throw. A creature that fails against this genjutsu can repeat the save at the end of each of its turns, ending the effects on itself on a success. Critical SuccessThe creature is unaffected and is immune to the effects of this jutsu for 24 hours. SuccessThe creature is unaffected. FailureThe creature takes 3d4 + genjutsu modifier poison damage and gains 1 rank of Fear against you for the next minute. Critical FailureThe creature takes 3d6 + genjutsu modifier poison damage and gains 1 rank of Fear against you for the next minute. While it has this rank of Fear it is considered Poisoned.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, increase the damage dealt by 2d4 and 2d6 respectively, and the size of the sphere increases by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "8b9ce16c9a727f5b30fc1a3c", name: "Toxic Release: Infesting Wind", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "4 Chakra", components: "CM, HS", duration: "Instant", description: "A gale of toxic gas infects a creature in range, forcing them to stumble away from the cloud. The target must succeed a Constitution saving throw, or it takes 2d8 poison damage and gains 1 rank of envenomed, and moves 5 feet in a random direction if it can move and its speed is at least 5 feet. Roll a d4 for the direction1, north; 2, south; 3, east; or 4, west. This movement doesn’t provoke opportunity attacks, and if the direction rolled is blocked, the target doesn't move.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage dealt by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "ef421cb8a7aff42b8b170e0d", name: "Toxic Release: Toxic Bellow", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "CM, HS", duration: "1 minute", description: "You breathe deeply, lacing the air in your lungs with a heavy dosage of toxins, then spew a cloudy orb at a target in range. Make a ranged ninjutsu attack. On a hit, you deal 4d6 poison damage. Then the target and any creature within a 10-foot radius sphere at that point must make a Consitution saving throw. On a failed save, creatures take 2d4 poison damage and become poisoned until the end of their next turn, or take half as much damage on a success. The sphere lingers in that space for the next minute. Creatures that enter this space for the first time on a turn or begin their turn there must succeed a Constitution saving throw or take 2d4 poison damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage dealt by 1d6 and 1d4 damage respectively.", created_at: NOW, updated_at: NOW },
  { _id: "646c69551d4dcbfd07d3f144", name: "Toxic Release: Fume Form", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "7 Chakra", components: "CM, HS", duration: "Concentration, up to 1 minute", description: "You begin to emit a foul fog expelling from the open pores of your skin, enshrouding your body. Until the jutsu ends, you gain the following benefits: - You have resistance to bludgeoning, piercing, and slashing damage, but vulnerability to wind damage. - As a bonus action on your turn, you transform fully into fog, gaining a flying speed equal to your walking speed. This flying speed lasts until the end of the current turn where you harmlessly fall 50 feet. While befitting from this speed, your movement doesn’t provoke opportunity attacks, and you can pass through narrow openings as small as 1 inch. If you end your movement without enough space, you are shunted to the nearest unoccupied space.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6da953c88006a8f83d6fcc16", name: "Toxic Release: Murderous Breath", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "Self (40-foot cone)", chakra_cost: "9 Chakra", components: "CM", duration: "Instant", description: "You spew a deathly exhale of noxious fumes in a 40-foot cone. All creatures in the area must make a Constitution saving throw, taking 8d6 poison damage and gain 1 rank of envenomed on a failed save, or half as much damage on a successful save. A creature that fails this save also reduces its hit point maximum by an amount equal to the poison damage dealt. This hit point reduction lasts until its next long rest or if it is healed by a medical ninjutsu of A-Rank or higher. A creature's hit point maximum reduced to 50  or less with this jutsu also suffers the poisoned condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage dealt by 2d6 and the cone increases its range by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "4ade17a6b32f2dc861bdbe01", name: "Toxic Release: Sickening Slumber", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM, HS", duration: "Concentration, up to 10 minutes", description: "You lace the air surrounding a creature with hallucinogenic toxins, inducing a sudden wave of nausea and fatigue. The creature must make a Wisdom saving throw. Creatures that fail against this jutsu can repeat the save at the end of each of its turns, ending the effects on itself on a success. Critical SuccessThe creature is unaffected and is immune to the effects of this jutsu for 1 hour. SuccessThe affected creature takes half damage from *Failure*. FailureThe affected creature takes 4d6 + genjutsu modifier poison damage and gains 1 rank of envenomed. A creature envenomed this way suffered the effects of slowed as if it had equal ranks of both conditions. Critical FailureThe affected creature suffers the same effects of *Failure*, but is also rendered unconscious for the next 10 minutes. A creature who is unconscious this way can be awoken if its ranks of envenomed are removed, or by taking damage of any type except poison or damage from the envenomed condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "5898fa0ae085c2bb99c68196", name: "Toxic Release: Cloudkill", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "12 Chakra", components: "CM, HS", duration: "Concentration, up to 10 minutes", description: "You create a 40-foot-radius sphere of toxic fog centered on a point. The area is heavily obscured and spreads around corners. It spreads around corners. It lasts for the duration or until strong wind disperses it. When a creature enters the area for the first time on a turn or starts its turn there, that creature must make a Constitution saving throw. The creature takes 8d8 poison damage and gains 2 ranks of envenomed on a failed save, or half as much damage on a successful one and 1 rank of enenomed. Creatures are affected even if they hold their breath or don’t need to breathe. Plants take double damage from this jutsu. While concentrating on this jutsu, you can take control of the fog as a bonus action and command it to move 30 feet in any direction you choose along the ground. Otherwise, the fog moves 10 feet away from you at the start of each of your turns, rolling along the surface of the ground. The vapors, being heavier than air, sink to the lowest level of the land, even pouring down openings.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage dealt by 2d8, and the size of the sphere by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "30c72c140d115c469e19373b", name: "Toxic Release: Noxious Nightmare", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "15 Chakra", components: "CM, HS", duration: "Concentration, up to 1 minute", description: "You lace 20-foot radius sphere of air surrounding creatures with hallucinogenic toxins at a point you can see in range, melting their minds with toxin fueled fear and misery. Creatures in this area must make a Wisdom saving throw. Creatures that fail against this jutsu can repeat the save at the end of each of its turns, ending the effects on itself on a success. SuccessA creature is unaffected. FailureAn affected creature takes 4d12 + genjutsu modifier poison damage and gains 1 rank of envenomed, and 1 rank of fear against you for the next minute. Each time the creature takes damage from the envenomed condition, it loses grip on its own sanity, reducing its Intellgence and Wisdom by -1. - When a creature reaches 0 Intelligence, it loses the ability to cast Ninjutsu. - When a creature reaches 0 Wisdom, it loses the ability to cast Genjutsu - When a creature reaches 0 in both scores, its mind succumbs to madness and it dies. Critical FailureAn affected creature takes 6d12 + genjutsu modifier poison damage and gains 2 rank of envenomed, and 2 rank of fear against you for the next minute. Each time the creature takes damage from the envenomed condition, it loses grip on its own sanity, reducing its Intellgence, Wisdom, and Charisma scores by -2.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, increase the damage dealt by 2d12, and increase the sphere's radius by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "5a8fc804f8fb265158a4f2a3", name: "Toxic Release: Creeping Death", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "3d7fe1bb5775caf4818c287e"], elements: [], casting_time: "1 Action", range: "Self (60-foot sphere)", chakra_cost: "20 Chakra", components: "CM, HS", duration: "Concentration, up to 1 minute", description: "Toxic chakra fumes from every inch of your body as you become a walking bomb of toxicity. For the duration, you exude a 30-foot radius sphere of pure toxic chakra. The sphere spreads around corners and the area is heavily obscured. Plants and adversaries less than 1/4th of your level immediately die. Creatures other than you that begin their turn or enter the area for the first time on a turn take 10d4 poison damage, then must make a Constitution saving throw. On a failed save, it gains 2 ranks of envenomed, and becomes poisoned. At the end of each turn a creature remains poisoned this way, it must make another Constitution saving throw, gaining 1 rank of Exhaustion on a failed save. A creature that fails the initial saving throw also reduces its hit point maximum by an amount equal to the poison damage dealt. This hit point reduction lasts until its next long rest or if it is healed by a medical ninjutsu of S-Rank or higher. A creature's hit point maximum reduced to 50  or less by this effect becomes enters a pseudo-dying condition. While in this condition it makes death saving throws at the start of its turn. After failing all death saves, it is reduced to 0 hit points and dies. While maintaining concentration, you can use your action on your turn to expel the slow exhaust of toxic chakra all at once, causing an abrupt explosion following the rise of a mushroom cloud of poison. All creatures within a 120-foot sphere must make a Constitution saving throw, taking 15d6 poison damage on a failed save or half as much on a successful save. The jutsu then immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "477bdd83dfd2f96fb28bd82e", name: "Detain: Chain", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "45 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You make a finger gun and shoot a powerful chakra bullet. Make a ranged ninjutsu attack against a creature. On a hit you deal 3d6+2 Force damage. This bullet ricochets off the original target and to a different one. On a hit, select another creature within range, comparing the original attack roll vs the new target's AC. On a hit you deal the same rolled damage to the second target. If this jutsu would kill a target, you can choose to just knock them out.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d6+1. When casted at B-rank you may chain up to 3 targets. At S-rank this becomes 4 targets.", created_at: NOW, updated_at: NOW },
  { _id: "8b722f7e7b16af6b6e3f61b8", name: "Detain: Stun", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "33ab3a61f3027398cd08f131", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You shoot a creature, attempting to harmlessly restrain them. Make a ranged ninjutsu attack against a creature in range. On a hit they gain one rank of the Shocked condition. If this jutsu scores a critical hit, the creature is also Slowed until the end of their next turn. If a creature is hit with another Cerealian Hijutsu while they have a condition from this jutsu, they take an extra 2d12 damage on a crit.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "53af8351dcb6f8ef1b936cdd", name: "Interpose Shot", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction you take when you or an ally in range would be targeted by a ranged attack", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You quickly shoot out a chakra bullet in an attempt to eliminate a ranged threat. Make a ranged ninjutsu attack against the attack, if the result is higher than the triggering attack's roll the attack is negated and you compare your attack roll to the triggering creature's AC. On a hit you pierce through the target, dealing 4d4+3 Force damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d4+1.", created_at: NOW, updated_at: NOW },
  { _id: "a27b6c023d4b9396e772d787", name: "Meta Lock-On", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "Special", range: "30 Feet", chakra_cost: "5 Chakra", components: "M, CM", duration: "Concentration, up to 1 Minute", description: "To cast this jutsu you must have Evolved Eye Awakening active. You do not need to pay chakra as a part of concentrating on this jutsu. You lock onto a creature, not allowing them to leave your sight. When you hit a creature with a ranged attack or as an action, you are able to lock onto a creature as long as you can see them. Otherwise, a target creature is marked for the duration. You gain a 1d4 bonus to all ranged weapon attacks and attacks from Cerelian hijutsu against this creature. This creature can not gain benefits of becoming invisible or being hidden from you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "81e50aa474e8554c8ce433ac", name: "Assassinate:Chakra Point Pierce", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You strike a creature's chakra point with extreme precision. Make a ranged ninjutsu attack, on a hit you deal 5d8+4 Necrotic damage and half the result as chakra damage. On a critical hit, you deal an amount of chakra damage equal to the amount of necrotic damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8+1.", created_at: NOW, updated_at: NOW },
  { _id: "a9ed1ddb2dee56e8d7dda0a3", name: "Detain: King Breaker", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You fire a blast of chakra perfectly configured to weaken a creature's ability to concentrate. Make a ranged ninjutsu attack. On a hit you deal 3d10+2 Force damage. Additionally, if the creature is concentrating on a jutsu, they reduce their roll by 1d4+1. You can choose to knock out a target with this jutsu, as opposed to dealing a lethal blow.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d10+1.", created_at: NOW, updated_at: NOW },
  { _id: "32cfcb9dbe93bcb4a7a1c9d5", name: "Cerealian Effigy", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CS, CM", duration: "Concentration, up to 1 Minute", description: "You aim at a point you can see on the ground within range and fire your chakra in the space. In the space arises a medium sized spirit of pure ghostly chakra. For the duration of this jutsu, when an allied creature passes through the spirit or starts their turn in the space heal 2d6+3 Hit Points. This spirit cannot heal constructs or undead. Hostile creatures that would pass through or start their turn in the spirit invoke its wrath, taking 2d6 Necrotic damage. As a bonus action on your turn, you can move a spirit up to 30 feet to a space that you can see. A creature can only be affected by a single spirit once per round.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the amount of spirits created by +1.", created_at: NOW, updated_at: NOW },
  { _id: "5b7fd117aef350c11796ee65", name: "Assassinate: Decaying Shot", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You fire a bullet of chakra that lingers in a target. Make a ranged ninjutsu attack. On a hit you deal 6d10+5 Necrotic damage. At the end of the target's turn it must make a constitution save. At the end of their turn they take 1d10 Necrotic damage. They must repeat this save at the end of their turns until they make a successful save. On a success, the effects of this jutsu immediately end.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 2d10+1.", created_at: NOW, updated_at: NOW },
  { _id: "0a5317586221f074fbe44d1e", name: "Exploding Earth's Core", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "45 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "The chakra bullet you fire erupts underground, creating a giant explosion of fire underneath targets. Select a 10-foot radius within the range. All creatures in the space must make a dexterity saving throw. On a failed save they take 7d8+6 Fire damage. On a success they take  half. If a creature fails this save by 5 or more, they take twice the result in damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 2d8+1.", created_at: NOW, updated_at: NOW },
  { _id: "3a6b1e5888468d69fb324aea", name: "Deadeye, Dead Man", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "To cast this jutsu you must have Evolved Eye Awakening active. With your most precise attack, you strike at a specific area of a target to unleash a debilitating effect. Make a ranged ninjutsu attack and select one of the following limbs, the outcome changing depending on the limb; - HeadOn a hit, you deal 10d12+9 Necrotic damage. The Creature must make a Constitution save, on a failed save they are blinded and dazed until the end of their next turn. - ArmOn a hit, you deal 8d10+7 Force damage. The Creature must make a Strength save, on a failed save they cannot use weapons and one arm is completely unusable until the end of their next turn. - BodyOn a hit, you deal 8d8 Necrotic damage. The Creature must make a Constitution save, on a failed save they are paralyzed until the end of their next turn. - LegOn a hit, you deal 8d10+7 Force damage. The Creature must make a Dexterity save, on a failed save the creature's movement speed is reduced to 0 and they are slowed until the end of their next turn. If you reduce a creature's HP to 0 with a critical hit, the chosen limb flies off in the same instant. In the case of the Body  it pierces the heart.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b7679ff8a1410874cb5b1349", name: "Aspect of the Moonmaiden: Third Eye", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 Hour", description: "You center yourself and open your third eye, allowing you to directly perceive the weave of Magick. For the duration, your view of reality shifts. You gain a unique form of chakra sight and blindsight of 30 feet, which does not require sight. You can not perceive anything that is more than 30 feet away from you. You also gain immunity to genjutsu with the Visual keyword. You can perceive the Nature Affinities other creatures if any, are able to perceive how much Chakra a creature has based on an aura they exude, and can now perceive when a creature or area is under the effects of a Ninjutsu or Genjutsu of any type. Additionally, you can make an Charisma (History) check to learn about the history of an object you are touching or your location, potentially causing cause you to experience vivid visions of the past connected to the object or location. At Night, under the light of the stars and any phase of the moon except the new moon, you increase the range of your chakra sight and blindsight to 60 feet and gain a +10 bonus to Charisma (History) checks.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2c1ef857f0a1dc7efae61b51", name: "Dark Omen: Only Woe", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You channel the ambient mana around your vessel before speaking a dark prophecy of the future to come. One creatures of your choice within 30 feet of you must make a Charisma saving throw, as the shackles of a dark fate settle around their soul. At Night, under the light of the stars and any phase of the moon except the new moon, they instead make their save at disadvantage. Critical SuccessAffected creature is able to resist this Jutsu’s effect, becoming immune to further castings of this Jutsu for the next 10 minutes. SuccessAffected creatures suffer disadvantage to the first attack roll, saving throw, or skill check they make after being affected by this Jutsu. FailureAffected creatures suffer disadvantage to all attack rolls, saving throws, and skill checks they make until the start of your next turn. Critical FailureAffected creatures suffer disadvantage to all attack rolls, saving throws, skill checks they make until the start of your next turn and take 2d6 Psychic damage each time they fail a roll while under the affects of this Jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast at B-Rank, this Jutsu instead lasts 2 rounds on Failure or Critical Failure. If cast at S-Rank this Jutsu instead lasts 3 rounds on Failure or Critical Failure. 49 src='https://i.imgur.com/IWJFLka.png' 50", created_at: NOW, updated_at: NOW },
  { _id: "a7d8c31fa020b5d99e58b76a", name: "Dark Omen: Toil and Trouble", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "613c7fdf9b141553412a1829"], elements: [], casting_time: "1 Bonus Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You channel the ambient mana around your vessel before speaking a dark prophecy of the future to come. One creature of your choice within 60 feet of you must make an Intelligence saving throw, as the weight of their future bears down, threatening to crush them. At Night, under the light of the stars and any phase of the moon except the new moon, they instead make their save at disadvantage. SuccessThe affected creature increases the concentration costs of each jutsu by +5. FailureThe affected creature increases the concentration costs of each jutsu by +5 and reduces their current Hit points by the same amount. Critical FailureThe affected creature increases the concentration costs of each jutsu by +5, must pay the cost in both Chakra and Hit points, and is forced to concentrate on this Jutsu with you. It must use up one of its concentration slots to do so, can not choose to end concentration on this Jutsu, and can not lose concentration on this Jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and concentration costs of each Jutsu by +5. If cast at B-Rank or higher, increase the number of creatures you can target in range by +1", created_at: NOW, updated_at: NOW },
  { _id: "8a45940eea4da61551f9b99f", name: "Witch Blade", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf", "87db194b8f9f4fe2140fb4c3", "e2257790dcd0ffd8e33f7574"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM, W (Kunai)", duration: "1 Minute", description: "You create 3 spectral blades out of pure chakra that mimics the appearance of your Ichor Weapon and circles around you like mini-satellites. As a bonus action on each of your turns, you can spend a spectral blade, allowing you to make a melee Ninjutsu or Taijutsu attack, slicing at a creature you can see within 30 feet. On a hit, the target creature takes your [weapon damage] + 1d10 Force damage and must succeed a Charisma saving throw, taking half the result as Chakra damage on a failed save. Once all spectral blades have been expended this jutsu immediately ends. You can alternatively spend the spectral blades created by this jutsu to fuel other *Blood Moon* Hijutsu you cast, enhancing their effects. If you would recast this jutsu, you retain all unspent spectral blades, adding them to your new total.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the number of spectral blades you create by 3 and damage of this jutsu by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "7302cf1fcb7c8b5ea7a2d3c3", name: "Waxing Crescent Eclipse", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "e2257790dcd0ffd8e33f7574"], elements: [], casting_time: "1 Reaction, which you can take when you would take damage", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM, W (Any)", duration: "Instant", description: "As a part of casting this jutsu, you must spend 1 spectral blade created by the *Witch Blade* jutsu. You call a spectral blade to your hand in the moment before an attack would hit and parry it. When you are damaged with an attack, you may roll your [weapon damage] + 2d8 and reduce the damage you receive by the result. If you reduce the damage to 0, you may immediately use the spectral blade to attack any creature within 30 feet, as if using it as part of the *Witch Blade* jutsu. You can spend spectral blades created by *Witch Blade.* For each spectral blade spent, you maintain the benefits of this jutsu against an additional instance of damage, until the end of your next turn. You can spend up to 3 spectral blades this way.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and reduce damage by an additional 2d8. If cast at B-Rank increase the damage reduction by 1 step. If cast at S-Rank increase the damage reduction by 2 steps.", created_at: NOW, updated_at: NOW },
  { _id: "08f9228bc5860229c98e4c4b", name: "Witch Bolt", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "613c7fdf9b141553412a1829"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM, W (Quarterstaff)", duration: "Concentration, up to 1 minute", description: "A beam of crackling, Ichor infused chakra lances out toward a creature within range, forming a sustained arc between you and the target. Make a ranged Ninjutsu attack roll against that target. On a hit, the target takes 3d12 force damage and becomes *Bonded* to you for the duration of this jutsu. When you take an instance of damage reduce it by 1d12. Creatures that are *Bonded* to you take this damage in your place, reducing their current HP by 1 for every point of damage you reduced via this jutsu. On each of your turns for the jutsu's duration, you can use your Action to deal 3d12 Force damage to the target automatically. The jutsu also ends if the target ever moves outside double this jutsu's range or gains total cover from you.", at_higher_ranks: "For each rank, you cast this Jutsu above D-Rank, increase the cost of this Jutsu by 3 and your damage by 1d12 and the damage reduction by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "7119a7d18d1131472280de13", name: "Aspect of the Moonmaiden: Prophecy", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 hour", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 minute", description: "As part of the requirements of this jutsu you must be under the light of the stars and any phase of the moon except the new moon and be benefitting from the *Aspect of the MoonmaidenThird Eye* jutsu. You study the stars with your Astral third eye, receiving their wisdom through unspoken word and ancient promisses. Ask up to three questions that can be answered with a yes or no. You must ask your questions before the spell ends. You receive a correct answer for each question. The weave of fate shown by the night sky is never set in perfect clarity, so you might receive “unclear” as an answer if a question pertains to information that lies beyond the reach of celestial knowledge. In a case where a one-word answer could be misleading or contrary to the Moonmaiden’s interests, the GM might offer a short phrase as an answer instead. If you cast this jutsu two or more times before finishing your next full rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer. The GM makes this roll in secret.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "430fcb0b485eed98d9c334dc", name: "Dark Omen: Heart of Newt", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "instant", description: "You channel the ambient mana around your vessel before speaking a dark prophecy the creature's true nature. Select one creature you can see within range, forcing them to make a Charisma saving throw, as the words begin to echo endlessly in their deep subcontious, changing their perception of their body. At Night, under the light of the stars and any phase of the moon except the new moon, they instead make their save at disadvantage. SuccessThe affected creature gains 1 rank of the Confused condition until the start of your next turn, as their grip on reality momentarily slips. FailureAffected creature takes 4d6 psychic damage and gains 2 ranks of Concussion and Weakened. Critical FailureAffected creature takes 6d6 psychic damage and gains 3 ranks of Concussion and Weakened.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the number of creatures you can target by +1 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "5ce0c35abae665e3ce9d8864", name: "Piercing Blades of Binding Moonlight", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "e2257790dcd0ffd8e33f7574"], elements: [], casting_time: "1 Action", range: "60 feet (15-foot radius sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You conjure a volley of magical swords made out of pure moonlight high up in the sky, before calling on them to rain down on your enemies. Target creatures in range makes a Dexterity saving throw, taking 2d10 Force damage, set their movement speed to 0, and double the cost of all Jutsu for the duration on failure, or half as much on a successful save. Creatures can make a Charisma saving throw at the end of each of their turns to end all effects. At Night, under the light of the stars and any phase of the moon except the new moon, they instead make their saves at disadvantage. You can spend spectral blades created by *Witch Blade*, for each spectral blade spent, increase the damage by 2d10. You can spend up to 3 spectral blades this way.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and damage by 1d10 and the radius by 5ft.", created_at: NOW, updated_at: NOW },
  { _id: "0c2fcc06caa8439e0ed84fee", name: "Tears of the Moon", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "613c7fdf9b141553412a1829"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "8 Chakra, 2 Chakra Die", components: "HS, CM", duration: "1 minute", description: "You harvest a special blend herbs at midnight, touched by the Moonmaiden's kiss, and brew them into a potent healing potion, ready to by activated at a moments notice via prayer and an infusion of Magick. When cast, a willing creature within range can drink the potion as a part of casting this jutsu. The target gains Hit Points and temporary Chakra Points equal 4d8 + your Ninjutsu ability modifier. Additionally, select one type of conditions between Elemental, Physical, Mental, or Sensory. The target creature gains  resistance to conditions of the  chosen category for the next,  minute and removes all ranks  of up to 2 conditions of your choice  they may possess. At Night,  under the light of the stars  and any  phase of the moon  except the new moon,  you increase the all dice  rolled as part of this  jutsu by one step.", at_higher_ranks: "For  each rank you cast this jutsu  above C-Rank, increase the cost  of this jutsu by 3 and healing and  temporary chakra points by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "c2ba3418aba11cf696f827ce", name: "Aspect of the Moonmaiden: Soar", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "10 Chakra", components: "HS, CM", duration: "Concentration, up to 8 Hours", description: "A signature technique of virtually every Coven of the land of Cackles, the Dasomia Coven believes it was the Moonmaiden who first taught witches how to fly as she journeyed across the land, sharing her wisdom with many of the lesser witches. Channeling the ambient mana into your staff, a broom, or another similarly convenient object, you use it to take flight. You do not need to spend chakra to maintain Concentration on this jutsu. You increase your movement speed by 30 feet, gain a fly speed equal to your movement speed, and can hover. If used during exploration or land travel, you treat normal travel pace as Fast travel pace, and you double Fast travel paces distances. At Night, under the light of the stars and any phase of the moon except the new moon, you instead increase your movement speed by 60 feet.", at_higher_ranks: "For  each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the movement speed gained by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "9c893c3cd896463c37a444ff", name: "Waxing Crescent Blood Moon", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "2f6189c677ac38c9ac5435cf", "87db194b8f9f4fe2140fb4c3", "e2257790dcd0ffd8e33f7574"], elements: [], casting_time: "1 Action", range: "Full movement", chakra_cost: "12 Chakra", components: "HS, CM, W (Any)", duration: "Instant", description: "You channel the ambient mana around your vessel before teleporting to anywhere within 10 feet of your target, shrouded in a veil of starry darkness before unleashing a combo of multiple simultaneous attacks with your spectral blades. Make two melee Ninjutsu or Taijutsu attacks, dealing your [weapon damage] + 3d10 Force damage for each attack. On each hit, the target must succeed a Charisma saving throw, taking half the result as Chakra damage on a failed save. At Night, under the light of the stars and any phase of the moon except the new moon, increase this jutsu's damage by one step. You can spend spectral blades created by *Witch Blade.* For every three spectral blades spent, you can make one additional melee ninjutsu or Taijutsu attack. You can spend 6 spectral blades in this way.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and damage of this jutsu by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "a2b1f07134c2cd13b7304ae9", name: "Comet Rain", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "613c7fdf9b141553412a1829"], elements: [], casting_time: "1 Action", range: "Full Movement", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "As part of the activation of this jutsu, you must be airborne and flying or hovering at least 30 feet off the ground. You take the sky, raining magical explosions down into the area beneath you You move up to your full movement in a straight line. All creatures within 15 feet of the ground you fly over while on the way to the select location must make a Dexterity saving throw, taking 8d8 Force damage and being knocked prone, or half as much on success. The area permanently becomes difficult terrain and is shrouded in a starry darkness.  A creature with Chakra Sight can’t see through this darkness, and light created using an effect or jutsu of B-Rank or lower cannot illuminate it.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and increase the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "ed9b860a17651f1e30d03e81", name: "Aspect of the Moonmaiden: Moongazing", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "613c7fdf9b141553412a1829"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "HS, CM", duration: "1 Minute", description: "As part of the requirements of this jutsu you must be be benefitting from the *Aspect of the MoonmaidenThird Eye* jutsu. You look to the moon and stars, seeing the Moonmaiden's path clearly and understanding what you must do to follow. Regardless of the time of time, you always are considered to be under a stary sky featuring the cresecent moon, and treat all Magick die as two steps higher. At Night, under the light of the stars and any phase of the moon except the new moon, you also reduce the cost of all Dasomia Hijutsu by -3 and reroll all 1's on Magick die and Dasomia Hijutsu damage rolls.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8fc4ad05a228dfdd15c4385c", name: "Blood of the Covenant", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Hour", range: "Touch", chakra_cost: "Special (100 Chakra, 3 Hit Die per creature)", components: "HS, CM", duration: "Permanent", description: "As part of the requirements of this jutsu you must be under the light of the stars and the Full Moon. You invite a number of creatures up to your proficiency bonus to partake in an ancient blood ritual, underneath the pale moonlight of the Moonmaiden, inviting them in your Coven. Each creature must offer up an equal share of their blood, permanently reducing their maximum Hit Die by the amount offered, to take part in this Jutsu. This Jutsu lasts until one of its casters is killed outright or fails its final death saving throw. For the duration of this Jutsu, all creatures may speak telepathically to one another regardless of distance, ignore all Keywords for the sake of assisting in a Combination Jutsu, double the any discounts given for combination casting a Jutsu, may freely share Hit points and Chakra points with one another as a Bonus Action, and gain access to all C rank or lower Hijutsu each caster can cast. CombinationIf this jutsu is cast as a Combination jutsu with 2 or more casters reduce the cost by -5. Any creature can participate in this ritual, regardless of not having access to the appropriate Keywords.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dc712a74fe5df186074f7180", name: "Dark Omen: Full Blood Moon", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "e2257790dcd0ffd8e33f7574"], elements: [], casting_time: "1 Full Turn Action", range: "10 feet", chakra_cost: "19 Chakra, 4 Hit Die", components: "HS, CM, CS", duration: "Concentration, Up to 1 minute", description: "As part of the requirements of this jutsu you must be under the light of the stars and any phase of the moon except the new moon. Dasomian legends have spoken of a Presence sealed away in a prison secreted away by the Moonmaiden in the dark side of the moon. You conjure an echo of its presence, imprinted into the weave of magick, and offer a sacrifice of your own blood to create of vessel of chakra bond under your control for it to inhabit. The moon turns Blood Red as part of casting this Jutsu and the Moon Presence uses your Genjutsu attack bonus and Save DC for effects that require it. It rolls initiative as it has its own turns, using your Genjutsu ability modifier + Proficiency as its Initiative. You can as a bonus action on your turn, so long as you are in physical contact with the Moon Presence, you can merge  into its head. While you are merged in this way you have total Cover against attacks and other effects outside of it. ___ >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6f8011e7189c80a0c175eb79", name: "Black Powder: Grenade", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "60 Feet (15 Foot radius Sphere)", chakra_cost: "5 Chakra", components: "W (Crossbow), M", duration: "Instant", description: "You toss a bundle of Black Powder high in the air, mixed with various sharp edges of metal, before shooting it out of the sky mid fall. Target creatures in range makes a Dexterity saving throw, taking your [Weapon Damage] + 3d6 Fire damage and one rank of the Burned condition on a failed save or half as much on a success save. Flammable objects caught in the radius ignites if it isn’t being held or carried. You spend a full stack of Black Powder Ammunition, as part of using this Jutsu.", at_higher_ranks: "For each rank, you cast this Jutsu above D-Rank, increase the cost of this Jutsu by 3 and your damage by 2d6 and radius by 5ft.", created_at: NOW, updated_at: NOW },
  { _id: "b4fb63f1d9e298c2769b54a4", name: "Fragmentation Shot", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (15-foot cone)", chakra_cost: "5 Chakra", components: "W (Crossbow), M", duration: "Instant", description: "You load a special shot that will immediately explode into a wave of shrapnel  upon being fired, showering all those before you in a mix of burning black powder residue and metal sharpnel. Creatures in a 15-foot cone in front of you must make a Dexterity saving throw. On a failed save you deal your [Weapon Damage] + 2d10 on a failed save or half as much on a successful one. Creatures  who are within 10 feet of you when  you cast this jutsu make  their  save at disadvantage.", at_higher_ranks: "For each   rank you cast this jutsu above  D-Rank, increase the cost of this  jutsu by 3, range of this jutsu by 5  feet, and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "d3bfacad606249912c253daf", name: "Gansuringa's Initiative", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Reaction, which you take when initiative is rolled", range: "Weapon Range", chakra_cost: "3 Chakra", components: "W (Crossbow), M", duration: "Instant", description: "When the chips are down, lives are on the line, and all bets are off, the records will always show that you shot first. You may make a single ranged Taijutsu attack roll. On you, you deal your [Weapon Damage] + 4d4. Regardless of whether you score a hit or not, you gain a bonus to initiative equal to 1d4.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increases the cost of this jutsu by 3 and your initiative bonus and damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "6440893300ff3909dae56e82", name: "Gansuringa's Luck", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Reaction, which you can take when you are targeted by an attack or would take damage", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "Those of the Gansuringa clan often find that when it comes to their survival, luck often seems to follow the wake of skill. Until the start of your next turn, you gain a +3 bonus to your AC, and when you would be subjected to damage for the first time while benefiting from this Jutsu, you gain 10 Temporary Hitpoints until the end of the current turn and may move up to 10 feet in a direction of your choice, without provoking an attack of opportunity.", at_higher_ranks: "For each rank, you cast this Jutsu above D-Rank, increase the cost of this Jutsu by 3 and your &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Temporary hitpoints granted by 10.", created_at: NOW, updated_at: NOW },
  { _id: "1f1de3b2f351dce801cbc5ec", name: "Black Powder: Sucker Punch", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Bonus Action", range: "5 feet", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "You fight dirty, throwing black powder into your opponent's eyes before striking them with an underhanded or unexpected blow. Make one melee Taijutsu attack. On hit you deal your [Unarmed Damage] + 3d10. Regardless of whether you score a hit or not, ranged attacks made against a creature within 5 feet no longer impose disadvantage until the end of your turn, and the next time the creature would take Fire damage or damage from a Crossbow with the Black Powder Ammunition weapon property, they must make a Constitution Saving Throw. On Failure, they become Blinded until the end of their next turn and gain 2 ranks of the Burned Condition. On success, they instead gain 1 rank of the Burned condition. You spend a full stack of Black Powder Ammunition, as part of using this Jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and your damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "614bf630d8c33aaf0dc463eb", name: "Covering Fire", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Reaction, which you take when you see a creature be targeted by an attack or take damage in range.", range: "Weapon Range", chakra_cost: "6 Chakra", components: "W (Crossbow), M", duration: "Instant", description: "Seeing another in danger, you still shoot first, creating a wall of covering fire that leaves an opponent only two optionsback off or die. When you see another creature within range take damage, you can fire your weapon wildly, reducing your Ammunition or Black Powder Ammunition die by 2 steps. When you do, the creature that dealt damage to your target must either reduce the damage dealt by your [Weapon Damage] + 2d6 or automatically take an amount of Piercing damage equal to your [Weapon Damage] + 2d6. After using this Jutsu, you gain another Reaction that can only be used to cast the Covering Fire Jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increases the cost of this jutsu by 3 and add 1d6 to your weapon's damage.", created_at: NOW, updated_at: NOW },
  { _id: "ec335fb942e053e495656ae0", name: "Gansuringa's Mantle", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "Special", range: "Self", chakra_cost: "*Special (7 Chakra)*", components: "CM", duration: "1 Round", description: "There is that certain something that all legendary Gansuringas seem to have - a presence in this world that can't be explained, and is understood by only those around them. You can activate this jutsu at the start of your turn. Until the beginning of your next turn you gain a +1d4 bonus to your attack rolls, damage rolls, saving throws, ability checks, and skill checks. Furthermore, all creatures must roll 1d20 when they declare an attack targeting you. On a roll of 16 or higher, the attack is diverted through what seems like a whimsy of fate or sheer dumb, blind luck alone.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dcbcd3f47d6ecb6bf8761bf9", name: "Lead Storm", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "Self (30 foot radius)", chakra_cost: "12 Chakra", components: "W (Crossbow), M", duration: "Instant round", description: "(This Jutsu cannot score a critical hit). Drawing your weapon you become a blur of circular motion, sending a devastating amount of lead or iron  in all directions with inhuman speed and precision.  Make three ranged Taijutsu attacks, comparing  the result against the AC of all creatures  of your choice within 30  feet of you. On hit  you deal your [Weapon Damage]  + 2d6 and the target  gains 1 rank of the  Bleeding condition.", at_higher_ranks: "For  each rank you cast this  jutsu above B-Rank,  increase the cost of  this  jutsu by  3 and the damage  by 1d6. 49 src='https://i.pinimg.com/originals/8a/31/1b/8a311ba5c253699d19d4f7137776a2dd.png' 50", created_at: NOW, updated_at: NOW },
  { _id: "e9ec3c1eb54193ce9c6a1a36", name: "Gansuringa's Challenge", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "CM", duration: "1 Minute", description: "You call out to a creature, deciding to settle things once in for all in a duel to the death - be it theirs or yours. Select one creature you can see within range, forcing them to make a Charisma saving throw. During Dusk, while the sun is setting and the sky is painted in reds, yellows, and oranges they instead make their save at disadvantage. Critical SuccessThe affected creature suffers disadvantage to all attack rolls made to creatures other than you until the end of their next turn. SuccessThe affected creature suffers disadvantage to  all attack rolls made to creatures other than you. FailureThe affected creature becomes drawn to  you, becoming  unable to target any other creature   other than you for the duration. Critical FailureThe affected creature becomes  drawn to you, becoming unable to target any other  creature other than you for the duration. Once per  turn, whenever you use a reaction against the  affected creature, you gain another.", at_higher_ranks: "For each rank you cast this  Jutsu above B-Rank, increase the cost of this  Jutsu by 3. If cast at S-Rank, you may spend an  additional 14 chakra to cast It's High Noon as a  Reaction, targeting only creatures that have Failed  or Critically Failed their save against this Jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "723236323163eedb4cf6fbc3", name: "It's High Noon", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Full Turn Action", range: "Weapon Range", chakra_cost: "20 Chakra", components: "W (Crossbow), M", duration: "Concentration, 1 round", description: "(This Jutsu cannot score a critical hit). You pause and enter a state of absulute  serenity and determination, remembering  the face of your father. For the Duration of  this  jutsu, you do not spend Chakra to maintain  this jutsu. Mark up to five creatures within  weapon range, reducing your ammunition dice  by 1 step for each one. At the start of your next turn,  make a single ranged taijutsu attack against each  creature at  advantage, regardless of range. On a hit  they take your [Weapons Damage] + 12d12. If you mark  and hit only a single creature, they take double damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "46dc8b55ab4636cfe138e887", name: "Burnout Glare", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Reaction, which you take when you would take damage from a ranged attack that you can see", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must have the *Kyūtaigan* clan feature active. You focus your burning sight to destroy the incoming attack, reducing the damage by 4d8+4. If the damage is reduced to 0, you suffer no further effects. If the damage being reduced is cold, you also create a cloud of steam surrounding you in a 20-foot sphere which lasts for 1 minute or until dispersed. *Self Immolation:* When you spend the chakra cost using your hit points, the damage reduction die becomes a d12.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage reduction by 1d8+1.", created_at: NOW, updated_at: NOW },
  { _id: "f79f7206cd5b1659e89084fa", name: "Command Flames", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "3 Chakra", components: "CM", duration: "*Special*", description: "As part of the requirements of this jutsu, you must have the *Kyūtaigan* clan feature active. With little more than a glance, you can control any visible flame. You choose a non chakra-enhanced flame that you can see within range and that's occupying up to a 5-foot cube. You affect it in up to two of the following ways: - You instantaneously expand the flame 5 feet in one direction, provided that wood or other fuel is present in the new location. - You instantaneously extinguish the flames within the cube. - You double or halve the area of bright light and dim light cast by the flame, change its color, or both. The change lasts for the duration of your Kyūtaigan. - You cause simple shapes — such as the vague form of a creature, an inanimate object, or a location — to appear within the flames and animate as you like. The shapes last for the duration of your Kyūtaigan. - You warm up to 5 cubic feet of nonliving material for the duration of your Kyūtaigan. *Self Immolation:* When you spend the chakra cost using your hit points, this jutsu can affect chakra-enhanced flames, including lingering flames cast by jutsu. When this jutsu is used to manipulate another creature's jutsu, you must succeed a Chakra Control check against their Save DC.", at_higher_ranks: "As part of the requirements of this jutsu, you must have the *Kyūtaigan* clan feature active. With little more than a glance, you can control any visible flame. You choose a non chakra-enhanced flame that you can see within range and that's occupying up to a 5-foot cube. You affect it in up to two of the following ways: - You instantaneously expand the flame 5 feet in one direction, provided that wood or other fuel is present in the new location. - You instantaneously extinguish the flames within the cube. - You double or halve the area of bright light and dim light cast by the flame, change its color, or both. The change lasts for the duration of your Kyūtaigan. - You cause simple shapes — such as the vague form of a creature, an inanimate object, or a location — to appear within the flames and animate as you like. The shapes last for the duration of your Kyūtaigan. - You warm up to 5 cubic feet of nonliving material for the duration of your Kyūtaigan. *Self Immolation:* When you spend the chakra cost using your hit points, this jutsu can affect chakra-enhanced flames, including lingering flames cast by jutsu. When this jutsu is used to manipulate another creature's jutsu, you must succeed a Chakra Control check against their Save DC.", created_at: NOW, updated_at: NOW },
  { _id: "85ab4c1110ba1ec6d32508c6", name: "Devil Circus", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (15-foot sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You light the air around you with swirling embers in a 15-foot radius sphere centered on you. This sphere sheds bright light for 15 feet and dim light for an additional 15 feet. Invisible creatures caught in the sphere are illuminated by the embers. Ranged weapon attacks and attack rolls from Water Release jutsu are made at disadvantage if they are cast within the sphere or target a creature inside the sphere, nor can Water Release jutsu benefit from being near a sufficient source of water. For the duration, you can can launch a mote of embers at a point you can see in 60 feet, making a ranged ninjutsu attack as a bonus action, dealing 2d4+2 fire damage on a hit. On a hit or miss, the area hit by the mote glows with 5 feet of bright light and an additional 5 feet of dim light, and benefits from the same effects as the sphere. This light lasts for the duration of the jutsu. *Self Immolation:* When you spend the chakra cost using your hit points, hostile creatures with ranks of burned that begin their turn in the sphere take the maximum damage of its burned die.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the ember mote damage by 2d4+2 and the radius of the sphere increases by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "92d2da6594bb81ce895469ab", name: "Hellfire Lance", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You manipulate fire chakra in your hand as it takes the shape of a lengthy, flaming rod. Make a ranged ninjutsu attack against a target in range. On a hit, you deal 3d8+3 fire damage, and the target gains 1 rank of burned. *Self Immolation:* When you spend the chakra cost using your hit points, you can cause the rod to explode on impact, causing all creatures (including the target) in a 5 foot radius to make a Dexterity saving throw, taking half the damage on a failure and becoming slowed until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage by 1d8+1. When you cast this jutsu at B-Rank or above, you make two ranged ninjutsu attacks instead.", created_at: NOW, updated_at: NOW },
  { _id: "dd05b6e54dbf7018346e275c", name: "Devil Rings", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 minute", description: "You create four rings of fiery chakra that swirl around you like wispy ribbons of energy which make your form translucent. For the duration, you have resistance to fire and cold damage. You can move through the space of other creatures and ignore difficult terrain. The first time on your turn you enter the space of another creature, it takes 1d6+1 fire damage. Once per turn, if you roll fire damage, you can maximize one die of the fire damage dealt. When a creature would damage you with a melee attack, it must first succeed a Dexterity saving throw or take 2d6+2 fire damage and gain 1 rank of burned on a failure, or take half that much damage on a success. As an action, you can transform one or more of these rings into a crimson chain, hurling it at a creature nearby to grapple and restrain them. Make a single melee ninjutsu attack against a target within 30 feet, selecting a different target for each ring transformed. On a hit, you deal 2d8+2 fire damage and the target becomes grappled and restrained. A creature can make a strength saving throw to break free of the grapple and restrain at the end of each of its turns. You can transform four rings at once, dealing 8d8+8 fire damage instead and the target must succeed a Charisma saving throw or become burned. While burned this way it is also Maddened. *Self Immolation:* When you spend the chakra cost using your hit points, you can spend two rings as an action to make two melee ninjutsu attacks at up to two targets within 60 feet. On a hit, each ring deals 2d8+2 fire damage and the target is grappled and restrained in place. While restrained this way it also suffers 1 rank of burned. A creature can make a Strength saving throw to break free of the grapple and restrain at the end of each of its turns.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage reduction by 2d8+2. When you cast this jutsu at B-Rank or above, you make two ranged ninjutsu attacks instead.", created_at: NOW, updated_at: NOW },
  { _id: "f823d371b6236121c7afbbe4", name: "Genjutsu: Ignite Anger!", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "As part of the requirements of this jutsu, you must have the *Kyūtaigan* clan feature active. You lock onto a creature you can see within range. You begin to stir the creature's emotions, causing them to become angered and irrational as their body spikes with adrenaline. The creature must make a Charisma saving throw. Creatures immune to the berserk condition are still affected by this genjutsu The creature can repeat the save at the end of each of its turns, ending the effect on itself with a success. SuccessThe creature takes half the damage of Failure and suffers no additional effects. FailureThe creature takes 2d6 psychic damage and 2d6+2 fire damage and becomes berserk for the next minute. Critical FailureThe creature takes 3d6 psychic damage and 3d6+3 fire damage and becomes berserk for the next minute. At the beginning of each of its turns it remains berserk, it gains 1 rank of burned if it doesn't already have it. If it has a rank of burned already the creature instead takes fire damage equal to the number of ranks of burned it has. *Self Immolation:* When you spend the chakra cost using your hit points, the creature has disadvantage on its saving throw to end the effects on itself.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and increase the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "17d67d0c70665005fd76b4f2", name: "Hellfire Rebuke", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Reaction, which you take when damaged by a creature within 60 feet of you that you can see", range: "60 feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You shift your fiery rage, and the creature that &emsp;damaged you is momentarily surrounded by hellish flames. &emsp;The creature must make a Dexterity saving throw, taking &emsp; 4d10 fire damage and gains one rank of burned on a failed &emsp; save, or half as much damage on a successful one.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bad16c804f5de2fb3ef0f520", name: "Hellfire Core Blast", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (150-foot line)", chakra_cost: "*Special* (15 Hit Points, *Self Immolation*)", components: "HS, CM", duration: "Instant", description: "A stroke of screaming fire forming a line 150 feet long and 15 feet wide blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 8d12+8 fire damage and gains two ranks of burned on a failed save and be knocked back to the end of the line and fall prone, or half as much damage on a successful save and one rank of burned. A creature that failed this save by 5 or more reduces its hit point maximum by half the fire damage dealt, and cannot regain these reduced hit points until it takes a rest or is healed by a medical jutsu of A-Rank or higher.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and increase the damage dealt by 2d12+2. When you cast this jutsu at S-Rank, this jutsu's damage cannot be reduced, and you gain 5 temporary hit points for each creature that failed the save by 5 or more which lasts for 1 minute.", created_at: NOW, updated_at: NOW },
  { _id: "33a090e6dd4f51b71534d773", name: "Devil Claw", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "12 chakra", components: "HS, CM", duration: "1 minute", description: "You coat one of your arms with a raging claw of fiery chakra. For the duration, when you make an unarmed attack, one of those attacks deals an additional 2d10 fire damage and has Reach (2) and Deadly (1). Creatures dealt fire damage this way cannot regain hit points until the end of their next turn, unless they're healed by a justu of A-rank of higher with the Medical keyword. For the duration, when you make an attack roll as part of a jutsu you cast with the Fire Release keyword, you can instead make a melee ninjutsu attack with a reach of 15 feet. On a hit, you deal 2d10 fire damage in addition to the jutsu's damage and effects. Fire damage you deal this way deals double damage to objects, constructs, and structures. *Self Immolation:* When you spend the chakra cost using your hit points, you coat both arms with fiery chakra. For the duration, when you make an unarmed attack, up to two of those attacks deals an additional 2d10 fire damage and has Reach (2), Deadly (1), and Multiattack.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b819946aff393687624e4cb8", name: "Sundering Stare", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "15 chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "As part of the requirements of this jutsu, you must have the *Kyūtaigan* clan feature active. Your gaze burns with searing intensity hot enough to ignite creatures with a glance. When you cast this jutsu, and as an action on each of your turns as long as the jutsu remains active, you can choose a creature you can see within 60 feet of you. It must make a Constitution saving throw. A creature suffering from the burned condition has disadvantage on this save. On a failure, the creature begins to smolder and burn from the inside out, causing the target to shed bright light in a 30-foot radius and dim light for an additional 30 feet, and taking 10d8 fire damage and gaining 1 rank of burned which last for the duration. On a successful save, the creature takes half damage. These flames can’t be extinguished and last for the duration. If damage from this jutsu reduces a target to 0 hit points, the target is turned to ash. Objects, constructs, and structures of your choice in a direct line between you and creature are lit on fire by this jutsu, taking the twice the damage. On consecutive turns, if the same creature is targeted, increase the damage die by 1 step (d6<d8<d10<d12) to a maximum of a d12. *Self Immolation:* When you spend the chakra cost using your hit points, a creature suffering from any ranks of burned afflicted by this jutsu also suffers equal ranks of slowed.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, and increase the damage dealt by 2d8 and increase the number of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "fdfc204545724c40dedbc9b7", name: "Toad Oil Bullet / Spray", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "Special", range: "Special", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant.", description: "The user converts their chakra into an extremely sticky oil and spits it out of their mouth. You are able to cast this jutsu in multiple ways  Action You spits it out as a spray, moving your head from side to side. Every creature in a 20ft Cone must succeed a Dexterity Saving Throw, on a failure, the creature gains one rank of the *Doused* condition.  Bonus ActionYou focus the oil into a compacted bullet capable of traveling further. Select a creature within 30 ft that you can see and make a Ranged Ninjutsu attack. On a hit, the creature gains one rank of the *Doused* condition.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the range of the cone by 10ft, or the attack by 15ft. If this jutsu is cast at B-Rank, increase the ranks of  *Doused* to 2. If this jutsu is cast at S-Rank, increase the ranks of  *Doused* to 3.", created_at: NOW, updated_at: NOW },
  { _id: "cc7455ed4e08b797410e7ce4", name: "Toad Smoke Technique", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, to being targeted with an attack.", range: "Self (10ft Radius Sphere)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant.", description: "The user produces a burst of a smoke from their body, forming a thick smokescreen to mask their movements. After this reaction is casted, you and all creatures within the smoke screen count as if being heavily obscured, unable to be seen. Additionally, once the attack that trigger this reaction ends, you are able to move 5ft without provoking attacks of opportunity. A moderate wind (At least 10 miles per hour) disperses the smoke in 4 rounds. A Strong wind (20+ miles per hour) disperses it in one round.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the radius by 10ft.", created_at: NOW, updated_at: NOW },
  { _id: "e9084d781a36a82bc773b7b1", name: "Toad Spying Technique", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to one Hour.", description: "The user places a Kanji of Vision on a summoned or wild toad to access its point of view, seeing and hearing everything around the toad as the user's pupils become toad-shaped. For the duration of this Jutsu, the user is considered both Blind and Deaf, as they are incapable of seeing or hearing with their own body, instead perceiving the world through the eyes of the marked creature. The user can end this Jutsu as a Bonus Action. This Jutsu does not allow the user to control the movement of the creature. If the user suffers any damage while concentrating on this Jutsu, it immediately ends. <!-- Cool background image --> <!-- Full page stain -->", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0769711b56dce528e41f0e81", name: "Summoning: Toad Bomb", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Until triggered.", description: "You summon small toads filled with oil and try to place them on a creature. Select one creature within range, and make a melee Ninjutsu Attack, on a hit, the toads are placed on the target. A creature whos Passive Perception is greater than your Ninjutsu Save DC, or that has Chakra Sight or Chakra Sense, are able to notice the Toads, and can take them off with an Action. The toads and the oil within them can be ignited as a Bonus Action or as a Reaction, dealing 3d6+3 fire damage. Alternatively The toads will ignite if the target creature suffer any fire or Lightning damage, if this happens, increase the damage die from a d6 to a d8. If in addition to this, the creature was already covered in oil from one of your Hijutsus, the damage die increases to a d10. A creature maked with this jutsu counts as if having one rank of the *Doused* condition. When casting this Jutsu, you can spend 5 chakra to summon another toad, increasing the damage of this Jutsu by 1d6+1 per additional toad summoned. You can do this up to 5 times.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1", created_at: NOW, updated_at: NOW },
  { _id: "c18547805c5024fdb1f39360", name: "Myōboku Oil Technique", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Bonus Action.", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 Minute.", description: "The user expels a special mixture of toad oil used by the sage tribe in their training, completely covering one creature. Select one willing creature within range. The selected creature becomes doused, gaining one rank of the condition. Additionally, the creature gains advantage on Chakra Control checks and no longer needs to make Concentration checks as a result of damage. The creature also gains resistance against the Grappled and Restrained conditions imposed by physical means. This jutsu ends early if the user loses the rank of doused by igniting the oil or by cleaning it with water.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "29a74ea7b4bff6bcc788c3a9", name: "Sealing Art: Frog Suppresion", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "587205fc5e2f018201761d63", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "60ft (20-foot square)", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to one Minute.", description: "The user erects four pillars from the ground, within 5. Ft of the edges of the area, leaving a 20ft square inside. The pillars create a field that paralyses anyone caught inside. Anyone inside the area at the moment of casting this jutsu or anyone that enters the area, must succeed a Constitution Saving Throw, being Dazed, Shocked and reducing their movement speed to 0 until on a failed save, or reducing their base movement speed by half until the end of their next turn on a success. A creature that first enter or start their turn inside of the area must make another Saving throw at the start of each of his turn in order to resist the effects", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the range of the square by 10 ft.", created_at: NOW, updated_at: NOW },
  { _id: "3f782e72523b8c84f361f9fa", name: "Sealing Art: Elemental Sealing Method", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action or 1 Reaction to being targeted, hit or damaged by a Ninjutsu with a Nature Release Keyword.", range: "5ft", chakra_cost: "8 Chakra, 1 Blank Scroll", components: "HS, CM, CS", duration: "Instant.", description: "The user pulls a Scroll with a special sealing formula, which has a blank space left in its centre that quickly tries to absorb any nearby Nature Release infused chakra. You are able to cast this jutsu in multiple ways;  ActionChoose any Nature Release-based effect that you can se and reach. You can target objects, creatures and even places under the effect of a Jutsu with a Nature Release. Make a Ninshou Check against the Ninjutsu Save DC of the jutsu, on a success, you absorb it, ending its effects. ReactionMake a Ninshou Check against the Ninjutsu Save DC of your opponent, on a success, you absorb the Jutsu, nullifying its effects. If the objective of this jutsu has a Nature Release Keyword that you have affinity with, the Ninshou Check is made at advantage. If the user attempts to absorb a Jutsu two ranks higher than this Jutsu, the Sealing fail automatically. (C > B > A > S > Art)", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3.", created_at: NOW, updated_at: NOW },
  { _id: "c0977ba2f3813df5c64e1642", name: "Frog Conversion Technique", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Full Turn Action", range: "Touch", chakra_cost: "13 Chakra", components: "HS, CM, CS", duration: "Concentration, Up to an hour.", description: "*As part of the requirements for this jutsu, the objective must be under the Paralyzed, Grappled, Restrained,  or Unconscious condition.* By placing a Seal the forehead of a target you attempt to transform it into a frog, not only physically, but mentally as well. The target must succeed a Charisma Saving Throw being transformed on a failed save, and remaking their saving throw at the end of each of their turns. On a success, the jutsu fails and the chakra is lost, unable to attempt to seal the creature again for the next 24 hours as the creature is sure that its not a frog. (lmao) A creature affected that suffer damage by a hostile creature is transformed back to their normal form, ending this Jutsu on the process. This jutsu disrupts the target’s mental state for the duration, and while transformed, will act as a frog.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "111bda6384cfce8f8f2f1b9c", name: "Summoning: Toad's Fire", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Until dispelled.", description: "You mark a 10x10ft square on the ground with a summoning seal covering the entire area. You can activate this seal as Reaction or as a Bonus Action on your turn. The seal will open a one-way portal to the esophagus of a massive toad that breath fire, making a fire pillar on the place. Every creature on the range must succeed a Dexterity Saving Throw, taking 8d8+8 fire damage on a failed save and being Burned or half as much on a successful one. If the creatures on top of the seal are not aware of it, they make the Saving Throw at disadvantage. Once activated, the portal keeps  burning until the user dispells it as a Bonus Action. A creature that first enter or start their turn inside of the area must make another Saving &nbsp;&nbsp;&nbsp;&nbsp;throw at the start of each of his turn in order to resist the &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;effects &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;", at_higher_ranks: "For each rank you cast &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;this jutsu above B-Rank, increase the &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;cost of this jutsu by 3, the size of the area by&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 5x5ft and the damage by 1d8+1.", created_at: NOW, updated_at: NOW },
  { _id: "53630f67dba2a476eb13d5f7", name: "True Fire of Samadhi", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "30ft", chakra_cost: "18 Chakra", components: "HS, CM, CS", duration: "Until dispelled.", description: "You set on fire a creature with the flames of purgatory, a fire release jutsu so potent that their flames are inextinguishable by wind or water. Select a creature within range. The creature must succeed a Charisma Saving Throw as you mark them with the a Seal of the purgatory. On a failed save, the creature gain 5 ranks of burned that cannot be extinguished by normal means. For the duration of this Jutsu, the creature cannot gain the benefit of jutsus with the Medical Release. A creature that wants to end this jutsu, must cast a jutsu with the Fuinjutsu keyword targeting the original target of this Jutsu and succed a Ninshu Check at disadvantage against your Ninjutsu Save DC, ending this Jutsu and removing the Burned ranks on a succesfull check. <!-- Cool background image --> <!-- Full page stain -->", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "75897c44ac276ac321c69b4e", name: "Destruction Cannon", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You shoot out a blast of pure energy that penetrates through almost all defenses. This jutsu ignores half and three quarters cover. Make a ranged ninjutsu attack dealing 2d12 force damage and inflicting a rank bruised.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d12. If this jutsu is cast at B-Rank, increase the ranks of bruised by +1. If this jutsu is cast at S-Rank, increase the ranks of bruised by +2.", created_at: NOW, updated_at: NOW },
  { _id: "e8d79a783f4d41ddf7c190c2", name: "Psionic Barrier", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction when you would be moved, take damage, or be forced to make a saving throw", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a barrier of psychic energy that repels and protects you from things that would otherwise harm you. You create a barrier that has 5d6 temporary hit points. You gain advantage on the triggering saving throw and you cannot be moved by any means. Any excess damage breaks through and affects the targeted creature as normal.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the number of temporary hit points by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "f14a9fc798c76b1499387f24", name: "Psyche Cleanser", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a cleansing psychic energy that dispels any negative thoughts and feelings that a creature may be feeling. Select one *Mental* or *Sensory* condition. An allied creature is are healed of one of those conditions, removing all ranks, if any. A creature who has their conditions removed in this way gain 2d6 temporary hit points and resistance to psychic damage until the start of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the amount of creatures you can target by +1 and the number of temporary hit points by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "7e76374e73082501ece42125", name: "Telekinetic Shove", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You impose your will over another creature force alone. You may force a creature to move 30 feet in any direction of your choice. When you do a creature must make a Strenght saving throw or be pushed or pulled 30 feet in the direction of your choice. A creature moved this way takes 2d6 force damage and if they collide with a creature or object their movement is stopped, taking falling damage equal to the distance they would have fallen.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the distance they are moved by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "32c5e04a3b48493a622bf0ab", name: "Flight of Focus", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You concentrate the chakra in your body and circulate the energy continously fueling the taxing process of flight. For the duration of this jutsu you gain a flying speed equal to your walking speed and you can hover. Your movement does not provoke opportunity attacks and you ignore difficult terrain.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f73ddb6b1e6ce9032bbc9dc9", name: "Force Whips", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You manifest your chakra into 2 tangible whips used to destroy and defend with equal efficiency. You do not spend chakra to maintain concentration with this jutsu. These whips have varied uses depending on the user's wishes. As an action you can make a melee ninjutsu attack against a creature within 15 feet. On a hit, you deal 5d6 force damage and force them to make a Strength saving throw. On a failed save they become restrained and can use their action to repeat the saving throw to break out. You can only have two creatures restrained by this jutsu at once.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "2c7444a49008373bc417ac42", name: "Pillar of Suffering", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You use your chakra to force the creatures to suffer as much as humanly possible. Each creature in a 15-foot radius, 60-foot-high cylinder centered on a point within range must make a Strength saving throw or take 10d4 force damage on a failed save or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 3d4.", created_at: NOW, updated_at: NOW },
  { _id: "71aba504e8d4822a2b628ef3", name: "Charge Bomb", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "90 feet (20-foot radius sphere)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You charge a ball of energy in your palm before overloading it and throwing it like a bomb. Choose a point you can see within range. Each creature within a 20-foot radius sphere of that space must make a Dexterity saving throw or take 6d10 force damage and be dazed on a failed save or half as much on a successful save and no further effect. If a creature fails this saving throw by 5 or more they become stunned until the start of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "c9e7941d94509ede36bb60af", name: "Telekinetic Helix Hands", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You flow chakra throw your body that manifests itself in a helix of energy that covers you in a surge of energy. You cannot lose concentration on this jutsu as a result of damage. For the duration of this jutsu, as an action you can make 2 melee ninjutsu attacks dealing force damage equal to 3d8 + ninjutsu ability modifier. If you hit a creature with 2 or more of these attacks they gain 2 ranks of bruised.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at S-Rank, increase the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "6584769fb681cd8ce88b51d6", name: "Dead Zone", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction when you see a creature cast a jutsu that requires chakra molding", range: "Self (30-foot radius sphere)", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You create an aura of superiority that nullifies and deactivates techniques that you deem unsatisfactory. All jutsu equal to or lower rank this than the rank this jutsu is cast, of your choice, end. If a jutsu that requires chakra molding was cast before entering this radius it is dispelled as your superior technique snuffs it out completely.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3.", created_at: NOW, updated_at: NOW },
  { _id: "97287fc50ab016418929e747", name: "Disaster", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius sphere)", chakra_cost: "24 Chakra", components: "HS, CM", duration: "Instant", description: "You unleash all of your energy into one giantic attack that decimates and destroys everything unfortunate enough to be in its path. All creatures and objects within 60 feet of you must make a Strength saving throw or become dazed and take 24d4 force damage and be knocked back to the edge of this jutsu's radius on a failed save or half as much damage on a successful one. If a creature or object would collide with another creature or object their movement is stopped, taking falling damage equal to the distance they would have fallen. Structures and objects take double damage.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage die by 1 step.", created_at: NOW, updated_at: NOW },
  { _id: "a90c59c9a2f3026b025552af", name: "Steel Release: Impervious Armor", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Reaction, which you take when you are", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 round", description: "You quickly turn your skin into a steel-like material before being hit. Until the start of your next turn, you reduce any damage received by your proficency bonus+your ninjutsu modifier. Lightning damage is unaffected by this damage reduction. You also gain temporary hit points equal to 2d8 + your ninjutsu ability modifier, and advantage on strength and constitution saving throws. At Higher RankFor each rank for each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the temporary hitpoints gained by 2d8.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6ab64b335a03f5d48f6939ec", name: "Steel Release: Steel Projectile", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create an object made of steel and launch it at high speed towards a target within range, make a ranged ninjutsu attack, dealing 3d8 earth damage on hit and reducing the result of their next saving throw by 1d4. At Higher RankFor each rank for each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of attacks by 1. A creature is only affected by the saving throw reduction once per turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "38d5186241fdae1f57dd73e9", name: "Steel Release: Steel Telekinesis", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action.", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You are able to command Steel  from long ranges. You can lift objects made of or connected to steel of Medium size or lower. You can even use this to lift and move creatures wearing armor. You select 1 target creature within range wearing armor made of metal, forcing them to make a Strength Saving throw. On a failed Save  they are restrained and moved up to 30 feet in any direction of your choice. On future turns if they are still restrained you can use your bonus action  to move them up to 30 ft  in any direction of your choice. A creature can attempt to remake the Strength Saving throw at the end of each of their turns to end being restrained. Additionally, if a creature is under the effects of Steel ReleaseSteel Restraints  they automatically fail the Str saving throw. At Higher RankFor each rank for each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by 1.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "afa2fa90bdaac3f27aa3de33", name: "Steel Release: Steel Restraints", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action.", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 minute", description: "You shoot out multiple shackles made of metal at a target creature within range, make a ranged ninjutsu attack dealing 2d8 earth damage and forcing the target creature to make a Strength saving throw or gaining the restrained condition. A creature can attempt to remake the Strength Saving throw at the end of each of their turns to end being restrained. Additionally, if a creature is under the effects of Steel ReleaseSteel Telekinesis they make the Strength saving throw at Disadvantage. At Higher RankFor each rank for each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by 1.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b767342bdcd10501d2f03cb5", name: "Steel Release: Steel Shield Technique", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Reaction, which you take when you or an ally are", range: "10 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 round", description: "You summon a wall of steel to intercept an attack targeting you or an ally within range. The Steel wall is 10-foot tall, 15 foot wide, and 1 foot thick. This wall acts as a Steel construct occupying a space of your choice within 10 feet of you, appearing right before an attack or jutsu would harm you. This has 8d6 Hit points, Resistance to all damage types except lightning damage. If the damage the wall receives would exceed its hit points, when you initially conjure it. The original target takes any remaining damage as normal and the wall is destroyed. The wall acts as a structure otherwise. It does not dissolve or vanish instead remaining until destroyed. At Higher Rank For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the hit points of the wall by 2d6, and increase the Wide of the Wall by 5ft.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3e23a09f81c6c9ca27f700a7", name: "Steel Release: Steel Spear", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 round", description: "You conjure a massive spear made of steel before sending it flying towards a target creature within range, make a ranged ninjutsu attack, dealing 6d8 earth damage on a hit. If you score a natural 20, with this jutsu, the steel spear splinters and explodes, tripling the damage dice, instead of doubling them. At Higher Rank For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8. If this jutsu is casted at least at A-Rank this jutsu crits on  19-20. >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "da345bc10dbe53c21ebeaeff", name: "Steel Release: Thrusting Steel Emergence", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "60 ft (15 Foot Cube)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "Choose a point you can see on the ground within range. A series of Steel pikes rocket upwards from the ground in a 15-foot cube. Each creature in that area must make a Dexterity saving throw. A creature takes 3d10 earth damage on a failed save, or half as much damage on a successful one. If a creature fails this save by 5 or more they gain 2 ranks of bleeding. At Higher Rank For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d10.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e1d280865a899332ef7c4c48", name: "Steel Release: Steel Suit", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1  Action", range: "Self", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You wrap a thin sheet of metal around your body to greatly increase your defensive capabilities. You cannot lose concentration on this jutsu as a result of damage. For the Duration of this Jutsu you gain 12d10 Temp hit points. These Temporary Hit points reduce any damage taken by -5 excluding lightning damage. Additionally, while you have temporary Hit Points granted by this jutsu you are counted as an Earthen Construct and deal 1d10 additional damage on all unarmed and weapon melee attacks. When the temporary Hit Points provided by this jutsu reach 0 the jutsu ends. <div style= \"text-alignright\"> At Higher Rank For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the temporary Hit  Point Dice by 2d10. </div>", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "80beb570fe685004660eaef5", name: "Steel Release: Binding Metal Chains", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1  Action", range: "Self (20 Foot Radius)", chakra_cost: "14 Chakra", components: "Hs, CM", duration: "Concentration, Up to 1 minute", description: "You focus your chakra deep underground creating a huge amount of steel before dozens of steel chains launch outside of the surface attempting to restrain those you command them to.  Each creature within range that you select must make a Dexterity saving throw. On a failed save the target takes 4d8 earth damage and is restrained by your chains. For the remainder of the Jutsu if a creature enters the range of your chains or starts there turn in the range of the chains while not already being restrained by the chains you may choose for them to make a Dexterity saving throw or become restrained and take 4d6 damage. A creature can attempt to stop being restrained by the chains by making a  Strength Saving throw at the end of each of their turns to end being restrained. The area taken up by the chains is counted as difficult terrain. At Higher Rank For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the radius by 10 feet and the damage by 2d8 and 2d6 respectively.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "10d2896400407c54e1c72775", name: "Steel Release: Metal Prison", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "20 Chakra", components: "Hs, CM", duration: "Permanent", description: "You constrict and bind a creature with metal, choose one creature in range, they must make a Strength saving throw, being Restrained by the metal prison and unable to cast jutsu with the HS component on a failed Save. The metal prison has an AC equal to your Ninjutsu Save DC and 200 Hit Points. The metal prison is resistant to all damage excluding lightning damage. A creature can attempt to remake the Strength Saving throw at the end of each of their turns to end being restrained. Each time a creature fails the strength saving throw the DC increases by 4 to a max of +20.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "aac02b2b96ffc6277057793c", name: "Haunting Darkness", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "A large shadow begins to expand from your feet and haunting sounds can be heard by other creatures as it nears them. All creatures within range must make a Wisdom saving throw. You impose a -1 penalty if this jutsu is cast during Sundown/Twilight, and a -2 penalty if this jutsu is used during Night. These penalties only apply to this jutsu's initial saving throw. Affected creatures may reattempt their saving throw at the end of each of their turns. ___ - Critical Success Affected creature is able to resist this jutsu's effects. - SuccessAffected creature is able to resist most of this jutsu's effects, being slightly shaken and reducing their movement speed by -10 feet until the end of their next turn. - FailureAffected creature sees their worst fears begin to manifest and take form from the shadow beneath them. For the duration, they are Frightened and Slowed, and take 3d4 psychic damage at the start of each of their turns. - Critical FailureSame effects as a failure, plus an additional rank of Fear and Slowed for the duration.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the radius by 5 feet, and the damage by 3d4.", created_at: NOW, updated_at: NOW },
  { _id: "cb917193e161b29011440060", name: "Umbral Strike", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "You manifest a limb of a creature of darkness over your arm as you target a creature within range for an attack. Make a ranged Ninjutsu attack. You may perform a melee Ninjutsu (or Taijutsu) attack if the target is within 10ft. On a hit you deal 3d8 force damage. If you choose to deal a melee attack, increase the damage dealt by your unarmed damage. Also on a hit, you may use one of the following *Skill-Based Actions* (Shove, Steal, Trip). You may use your Ninjutsu ability modifier for these Skill-Based Actions.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to C-Rank or higher, increase the damage of this jutsu by 1 step. If cast to B-Rank or higher, increase the number of attacks by +1. If cast to A-Rank or higher, increase the damage die of this jutsu by 1 step. If cast to S-Rank, increase the number of attacks by +1. />", created_at: NOW, updated_at: NOW },
  { _id: "ae24501df6d21dcd99f7cc76", name: "Shadow Leap", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Movement Speed", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "*Special*", description: "You conjure a beast of shadow and momentarily merge with it, becoming a living shadow as you teleport to a source of darkness within range. If you teleport to a space that is not within 10 feet of any hostile creature, you may immediately take the *Hide* action as part casting this jutsu, making your Stealth check at advantage. You may use your Ninjutsu ability modifier in place of Dexterity for this check. If you succeed, for the next minute (concentration) you do not produce sound while you remain in stealth, and as a bonus action on subsequent turns you may teleport with this jutsu again and immediately *Hide* once more with no need for additional Stealth checks. Alternatively, if you do teleport to a space within 10 feet of a creature, you do not immediately *Hide*. Instead, the next attack you make against the closest target before the end of the current turn is made at advantage and deals an additional 2d10 force damage, once per casting. On a hit, you gain the benefits of the Disengage action. This jutsu then ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "8e5197c008d5baf3f2557a57", name: "Awaiting Penumbra", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "*Special*", description: "You attempt to invade another creature's shadow, commanding one of your creations to lie in waiting. Select one creature within range. The range of this jutsu is doubled during Sundown/Twilight and tripled during Night. Casting this jutsu does not break stealth. Make an Illusions skill check at advantage vs the target's passive perception. On a success, your shadow hides within the target's shadow, and your target is unaware this has occurred. This jutsu fails against Nara targets or targets that do not have a shadow. Also on a success, choose between *Umbral Revenge* or *Umbral Stalk* starting from your next turn. If you do not declare an effect within the next minute, this jutsu ends early. - Umbral RevengeAs a bonus action, you command your creation to emerge from the target's shadow and attack. Make a melee Ninjutsu attack, dealing 1d12 + your Ninjutsu ability modifier in force damage and imposing a Wisdom saving throw on a hit. On a failure, the target is Dazzled and Blinded until the end of their next turn. The first time this effect is used on a target per long rest, the target is Surprised for the duration of the attack. This jutsu then ends. - Umbral StalkYou decide to have your shadow remain with the target. This jutsu's duration becomes 24 hours and for the duration, you are aware of whether the target is conscious as well as their general direction. At any point, you may as a Full Turn Action manifest your shadow from underneath the target. For the next minute, you are blinded to your surroundings, and instead see through the eyes of your Shadow Beast, controlling it. The Shadow Beast has 1 hit point, an AC equal to your Ninjutsu Save DC, and 60 feet of movement speed. The Beast shares your ability scores, skill proficiencies, and Kurashi clan features. You may have your Beast explore and interact with the environment for the duration. After the duration concludes, the Beast is dispelled and this jutsu ends.", at_higher_ranks: "For each rank cast above D-Rank, increase the cost of this jutsu by 3, the damage by 1d12, and the number of targets by +1 (You decide to use *Umbral Revenge* or *Umbral Stalk* for each creature; Only one creature can be targeted by *Umbral Stalk* at a time.) If cast to B-Rank, the Shadow Beast cannot be detected by jutsu with the Sensory keyword.", created_at: NOW, updated_at: NOW },
  { _id: "f538db32adbf16b998cc7f74", name: "Spectre Aegis", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction, which you take when you take damage or fail a saving throw", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "1 Round", description: "You deploy your monstrous shadows to protect you from harm. Until the start of your next turn, you gain a +3 bonus to AC and a +2 bonus initial saving throw made. Also, once per casting, select one of the following effects; - Lash OutIf the triggering creature you activated this jutsu against is within 20 feet of you, you can command your shadows to lash out. Make a melee Ninjutsu attack against the target, dealing 2d8 necrotic damage. On a critical hit, the target gains 1 rank of bleeding and is knocked back 15 feet. - Strengthen SelfYou command your shadows to strengthen your defenses even more. Increase the bonus to AC and saving throws by +1, and gain 2d8 temporary hit points for the duration. - Support AlliesAn altruistic command. You command your shadows to protect your allies instead of yourself. A number of allies, other than you, equal to your Ninjutsu ability modifier, gain the benefits of this jutsu as if you chose Strengthen Self.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the chakra cost by 3, and the damage or temporary hit points by 2d8. If cast to B-Rank or higher, when you use Lash Out gain a +1 bonus to critical threat range. If cast to A-Rank or higher, increase the number of attacks made with Lash Out by +1. If cast to S-Rank, gain an additional +1 to critical threat range with Lash Out. <style> .page", created_at: NOW, updated_at: NOW },
  { _id: "ac18945cdc2159cdafa1a26f", name: "Call to the Void: Lesser Shade", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "*Special* (9 Chakra)", components: "HS, CM, CS", duration: "Concentration, up to 1 Minute", description: "You weave signs and command your shadow to split, the fragment moving up to 30 feet away from you and forming into a *Lesser Shade*. A Lesser Shade is a creature of your own description, and uses the following statistics; If this jutsu is cast during Sundown/Twilight, gain advantage on checks to maintain concentration. If cast during Night, gain the aforementioned effect, and when you roll for concentration, you may pay 1/3rd this jutsu's chakra cost to maintain concentration automatically. The Lesser Shade is proficient in all saving throws, uses your Ninjutsu (or Genjutsu) Attack Bonus and Save DC, and can be commanded as part of summoning it and as a bonus action on subsequent turns. When you first summon the Lesser Shade, you designate its *Focus*. Select from one of the following below. *Companion Focus.* Your Companion Shade is geared to assistance and is of Large size. It gains a +20 bonus to movement speed, ignores difficult terrain, and shares your skill proficiencies, and it may carry any creature of medium size or lower without any reduction to its movement speed. *Guardian Focus.* Your Guardian Shade is geared towards protection and is of Medium size. It produces a 15-foot aura that grants all allies (other than itself) within it +3 DR. The Lesser Shade may, as a reaction, redirect an attack made against an ally (other than itself) within 15 feet towards itself. When it does so, it reduces the damage by 3d8. *Warrior Focus.* Your Warrior Shade is geared towards combat and is of Medium size. It gains a +1 bonus to attack and damage rolls with its weapons and an additional 15hp.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the hit points of the Lesser Shade by 3d6+8. If cast to A-Rank, you may summon a second Lesser Shade. This new Lesser Shade must have a different Focus. You can command this new shade at the end of your turns,  as opposed to a bonus action. ___ >", created_at: NOW, updated_at: NOW },
  { _id: "fee082b1411772fe299f42bc", name: "Shadow Dragon", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "33ab3a61f3027398cd08f131", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You pull from the darkness around you and manifest the head of a hungry \"dragon\" above you. This starving dragon hungers and blesses those who feed it. All hostile creatures within range, up to an amount equal to your Genjutsu ability modiifer must make a Wisdom saving throw as the dragon opens its mouth and begins to feast upon their shadows. Creatures that do not have a Shadow, or who are of the Nara clan, automatically pass this saving throw. On a failed saving throw, the target is Dazed and has their movement speed halved until the end of their next turn. The dragon then exhales, releasing a spores of mending shadow. All allied creatures within range recover a total of 4d6+4 hit points (divide these hit points amongst all allied creatures). For each hostile creature who failed their saving throw, increase the hit point total by 1d6+2. />", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "24e26ad42c882b3fda4d7427", name: "Reach of Shadows", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Full Turn Action", range: "Self", chakra_cost: "10 Chakra", components: "HS, CM, CS, NT (*Special*)", duration: "10 minutes", description: "A signature jutsu useful for deriving information while all means to acquire the info seem lost. To cast this jutsu, you must be standing near a location where a creature died within the past 72 hours. You weave a single sign, conjuring two creatures of shadow to dive into the abyss below where blood was split. Make an Insight or Investigation check vs a DC equal to 10 + the creature's level (Only your DM is aware of DC value). On a failure, this jutsu fails as your monsters of shadow come back with nothing. On a success, your monsters drag the soul of the creature that was killed through the void, holding them aloft in the air, restrained. The soul of the creature cannot be damaged and cannot take any actions, but can speak as it has its full intelligence and memory. This jutsu fails if the targeted soul is sealed by some effect or *thing*. Every minute, the soul can attempt a Charisma saving throw to break free. While conversing with the spirit, twice per casting you can command your shadows to slightly harm the soul to intimidate it, giving you or an ally advantage on your next Wisdom or Charisma check. Once this jutsu ends or the soul breaks free, it returns to the spirit realm and cannot be affected by this jutsu again. /> /> /> /> /> /> /> /> />", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f87ef921633bae4b6016446e", name: "Call to the Void: Deific Shade", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "120 feet (90-foot radius)", chakra_cost: "18 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 Minute", description: "You weave signs and command your entire shadow to move up to 120 feet from you. For the duration of this jutsu, your movement speed is halved. Your shadow erupts into a gaseous maniacal being that expands  in a 90-foot radius. This being represents a Kurashi's deepest fears and repressed emotions. When you would make a concentration check for this jutsu, you may spend 6 chakra to automatically succeed the check. All creatures inside this radius cannot be seen from outside of it (and likewise, creatures within cannot see out of it). All creatures inside this radius (other than you) cannot take the Dash, Hide, or Disengage actions and have their speed reduced by -20 feet. At the start of your turns, all hostile creatures must make a Charisma saving throw; Targets make this saving throw with a -1d4 penalty if this jutsu is used during Sundown/Twilight, or, if at Night, at disadvantage. ___ - SuccessTargets take half as much damage (9d8) and gain 1 rank of Fear until the end of their next turn. - FailureTargets take 9d8 psychic damage and gain 2 ranks of Fear and Slowed until the end of your next turn. - Critical FailureTargets take 10d10 psychic damage and  gain 3 ranks of Fear and  Slowed until the end of your next turn. Additionally, while this jutsu is active treat all other Kurashi Hijutsu as being cast during Night, and if any *Lesser Shades* are present from the Call to the VoidLesser Shade Hijutsu, they become *Greater Shades*. *Greater Shades* gain a +2 bonus to all ability scores (up to a maximum of 22), and gain an extra 20 hp. They also gain additional benefits, depending on their focus. - Companion FocusThe Companion Shade gains a flying speed equal to its movement speed and may carry up two medium or smaller creatures. All creatures riding recover 2d10 hit points at the start of each of their turns. - Guardian FocusThe Guardian Shade gains resistance to all damage and when it would interpose an attack, it may make one attack using *Shade Strike* against the triggering creature. - Warrior ShadeThe Warrior Shade gains a +1 to attack and critical threat range, and increases the damage die of its weapons by +1. It may also make three attacks with the Multiattack trait. Once this jutsu ends, you must make a flat d20 check. You cannot add any modifiers to this check. If your result is 11 or less, you fall prone and are Dazed until the end of your next turn, as you begin to have a seizure. If you succeed, you are &emsp;&emsp;&emsp;&emsp;&emsp;Concussed, but are otherwise stable. Regardless &emsp;&emsp;&emsp;of your result, gain 1 rank of Fear against yourself. <div class = \"kurashi\">", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0e569b0a5eaec6754b24ae11", name: "Cloud Release: Airbag", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Reaction, which you take when you are", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Round", description: "Just before you an attack would have the chance to do you harm, you create a small thick cloud between you and your attacker to absorb the attack's force. Until the start of your next turn, you gain a +4 bonus to AC against attacks, advantage on Strength saving throws, you reduce all knock back you would be forced to move by half.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c1fa03fe18734b59c3cb24d3", name: "Cloud Release: Cloud Whip", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a long whip made from a chain of clouds. Make a melee ninjutsu attack against a target in range, dealing 4d6 Wind damage and forcing the target creature to make a Strength saving throw, being pulled 10 feet towards you and being knocked prone on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "facc41dfec614b9a31372021", name: "Cloud Release: Floating Clouds", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Bonus Action", range: "30 Feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "1 Minute", description: "You send a Miniature cloud towards a creature within range. For the duration when that creature would be knocked into the air they are knocked upwards an additional 10 feet. You can also choose to target an allied creature, in which case the cloud hovers near them and when they would be knocked into the air, gently lowers them to the ground preventing fall damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the  height the creature would be knocked upwards by 10. If this jutsu is casted at B-Rank or higher you may select 1 additional creature to be affected of this jutsu when you would cast it.", created_at: NOW, updated_at: NOW },
  { _id: "caf52de0af82dc4127c70e45", name: "Cloud Release: Fog Cloud", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minute", description: "You create a 30-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it. Creatures inside this cloud of fog cannot see more than 5 feet away from them, gaining disadvantage Attacks made while inside the cloud of fog that rely on sight. Creatures outside the fog also have disadvantage  when attacking other creatures who are inside the mist. Also, when this jutsu is cast, select one creature, whom you can see. That creature becomes *Fog Marked*. For the duration of this jutsu, while a fog marked creature is in the cloud it is always perceived by you, cannot benefit from being hidden, and you do not gain disadvantage on attack rolls against them. You can move the fog cloud up to 30 feet as a bonus action on your turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "083e6bafa77d77a1e064c502", name: "Cloud Release: Cloud Shredder", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 minute", description: "You form a small cloud above a target creature within range, which begins to shoot out razor sharp pellets of rain down on them forcing the target creature to make a Dexterity saving throw. On a failed save they take 3d8 Wind damage and gain 1 rank of bleed. Additonally, for the duration of the jutsu the target must remake their saving throw at the start of each of their turns, taking the damage and gaining an additonal rank of bleed on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d8. If this Jutsu is cast at B-Rank all creatures within 5 feet of the target must also  make the Dexterity saving throw. If this Jutsu is cast at A-Rank all creatures within 10 feet of the target must also  make the Dexterity saving throw. If this Jutsu is cast at S-Rank all creatures within 15 feet of the target must also  make the Dexterity saving throw.", created_at: NOW, updated_at: NOW },
  { _id: "23ff9ad29b7c41568f737dbc", name: "Cloud Release: Flying Nimbus", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "10 Minutes", description: "You summon a small cloud below your feet which lifts you off of your feet. You gain a fly speed of 45 feet or equal to your normal movement speed (which ever is greater). You also gain the ability to hover in place. You may carry 1 other creature of medium size or lower on the cloud.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the flying speed by 15 feet.  If this Jutsu is cast at B-Rank it gains a duration of 1 hour.  If this Jutsu is cast at A-Rank, you can cast it as a Bonus Action, instead of an Action.", created_at: NOW, updated_at: NOW },
  { _id: "b27d0c4d327934fb48ddf341", name: "Cloud Release: Vapor Trail Explosion", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You unleash a stream of clouds holding intense sharp winds 5 feet wide and up to 60 feet long in a straight line originating from you. This trail of clouds stops at a space of your choice along this distance and expands into a large 20-foot radius sphere of slashing hail coming from a cloud centered on the selected space. All creatures in both this Jutsu's stream and radius, must make a Dexterity saving throw. Taking 4d8 Wind damage and gaining 1 rank of bleed and chilled on a failed save, or half as much damage and no additonal effects on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "45f060a89211ee0fb5ada372", name: "Cloud Release: Cloud Forged Dragon", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (60-foot Cone)", chakra_cost: "16 Chakra", components: "HS, CM", duration: "Instant", description: "You create a massive cloud before using your chakra to mold it into the appearance of a large dragon of your description. The Dragon then expands in a cone attempting to engulf all those in its path. Each creature in a 60-foot cone, originating from you, must make a Dexterity saving throw, taking 7d6 Wind damage, gaining 2 ranks of bleed and chilled, and being knocked prone on a failed save. This jutsu deals double damage to objects and structures.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, Increase the cost of this jutsu by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "de3cad2ee6ffc5814e18e002", name: "Cloud Release: Swirling Discharge", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius Sphere)", chakra_cost: "15 Chakra", components: "HS, CM", duration: "Instant", description: "You summon a swirling cloud above your head that discharges chucks of hail in all directions. Each creature within 60 feet of you must make a Dexterity saving throw, taking 3d8 Wind damage and 3d8 Cold damage, gaining 2 ranks of bleed and 1 rank of chilled on a failed save, or half as much damage and no additonal effects on a succesful save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, Increase the cost of this jutsu by 3, the damage by 2d8, and increase the amount of ranks of either Chilled or Bleeding by 1. (Pick One)", created_at: NOW, updated_at: NOW },
  { _id: "120863c3117c6394e764f3fd", name: "Cloud Release: Razor Blade Rain", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (90-foot radius Sphere)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, Up to 1 Minute", description: "You summon a massive dark cloud to fill the sky above you, which begins to unleash an endless barrage of watery needles. Each creature of your choice within 90 feet of you must make a Dexterity saving throw, taking 6d10 Wind damage and gaining 2 ranks of the bleed and chilled on a failed save. Additionally,at the beginning of each of your turns, each creature in range of your choice must make a Dexterity saving throw, taking 4d10 Wind damage and gaining 1 rank of bleed and chilled on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage by 2d10, and the size of the Radius by 30 feet.  />  />  />  />", created_at: NOW, updated_at: NOW },
  { _id: "24de43cf16a08de60ecc245b", name: "Heat-seeking Missiles", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You fire three small missiles from your mechanical form. Each missile hits a target of your choice that you can see within range. A missile deals 1d4+1 fire damage to its target. The missiles all strike simultaneously, and you can direct them to hit one target or several.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and create one additional missile.", created_at: NOW, updated_at: NOW },
  { _id: "7c6c02692da46b735b674519", name: "Laser Vision", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "You fire two beams of hot energy from your optical lenses. This jutsu has two firing modes. You choose which firing mode to use when cast: Heat RayMake a ranged ninjutsu attack against either a single target or two adjacent targets within 5 feet of each other in range. On a hit, you deal 3d6 fire damage. If attacking two adjacent targets, the damage is split between both. A damaged creature must also succeed a Constitution save or gain 1 rank of Burned. Concussive RayMake a ranged ninjutsu attack against either a single target or two adjacent targets within 5 feet of each other in range. On a hit, you deal 3d6 force damage. If attacking two adjacent,the damage is split between both. This attack deals double damage to structures, constructs, and objects. A damaged creature must also succeed a Constitution save or gain 1 rank of Bruised.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage by 2d6. When you cast this jutsu at B-Rank or above, inflict 1 additional rank of either condition.", created_at: NOW, updated_at: NOW },
  { _id: "6ed26ce5cf70b95bf9ca5fe0", name: "Mecha-Mode: Terrain", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "CM", duration: "Concentration, up to 10 minutes", description: "Your mechanical form unfolds, adapting you into a configuration optimized for traversing any terrain. You can't lose concentration on this jutsu as a result of damage. While this jutsu is active, you gain the following benefits: - Increase your walking speed by 30 feet, and you ignore difficult terrain. - You can be mounted by up to two medium creatures. Creatures mounted this way occupy your space but are not encumbered. They are uneffected by jutsu you cast that damage an area surrounding you. - If you move at least 30 feet straight toward a target and hit it with a melee attack or taijutsu on the same turn, it must succeed on a Strength saving throw or be knocked prone.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, increase the speed by 5 feet and the medium creatures you can carry by 1.", created_at: NOW, updated_at: NOW },
  { _id: "a3e971ae4194554bc2ede24f", name: "Retractable Fists", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "You aim both fists as they rocket forth from your arms at a target in range while tethering cables back to you. If the target is a creature, on a hit, you deal your unarmed damage + 2d6, and the creature becomes grappled by you. Alternatively, you may target a fixed surface such as a ledge or wall, or a medium or smaller object within range. After a successful hit you can choose to retract your fists, which either moves you within 5 feet of the target or pulls the target within your reach (if applicable). If the target is a creature, it must succeed a Strength saving throw or be pulled 30 feet closer to you.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage increases by 1d6, and increase the jutsu's ranges by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "b75ae9012c10a18c8c2a94d4", name: "Mecha-Mode: Buzz Saw", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self (10-foot radius)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Your mechanical body steams open to reveal a roaring steel saw which expands to a radius of 10 feet centered on you. You can't lose concentration on this jutsu as a result of damage. All creatures within the area must make a Dexterity saving throw, taking 4d8 slashing damage and gains 1 rank of bleeding on a failed save or half as much and no other effect on a success. A creature takes the same damage when it enters the radius for the first time on a turn or begins its turn there. Non chakra-based objects or structures made of wood, plants, or similar material caught in the radius are destroyed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "2f001709e37981b06e578c0d", name: "Rapid Fire Handguns", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "120 feet (or 40-foot cone)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You blast a spray of bullets from your fingertips. This jutsu has two firing modes. You choose which firing mode to use when you cast it: Targeted ModeMake a ranged ninjutsu attack against a single target within 120 feet. On a hit, you deal 6d8 piercing damage. This attacks critical threat range increases by +1. On a critical hit, the target gains 1 rank of bleeding. Burst ModeAll creatures in a 40 foot cone originating from you must make a Dexterity saving throw, taking 8d4 piercing damage and gain 2 ranks of slowed on a failed save, or half as much damage on a success and 1 rank of slowed. These ranks last until the end of an affected creature's next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 2d8 and 2d4 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "261d5cd348f7c283dbf16e49", name: "Syphon Chakra", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "7 Chakra", components: "CM", duration: "1 minute", description: "You target a creature within range, syphoning its chakra to feed your internal chakra core. The target must make a Constitution saving throw. On a failure, it gains two ranks of weakened until the end of its next turn, and reduces its chakra point total by 4d6. On a successful save, it only reduces its chakra point total by half that amount. You gain temporary chakra by an equal amount which lasts for 1 min. While you have temporary chakra points from this jutsu, you cannot cast this jutsu again.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the target reduces its chakra point total by an additional 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "6f590d996fc5c2a80cbd6e4c", name: "Mecha-Mode: Flight", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "Your mechanical body unfolds, reconfiguring you into an airborne mode. You can't lose concentration on this jutsu as a result of damage. While this jutsu is active, you gain the following benefits: - You gain a fly speed of 120 feet. As part of casting this jutsu, you can move up to half this speed. - If you fly at least 60 feet straight toward a target(s) in range and hit it with a ranged attack or jutsu that deals damage in  an area of effect, increase that area by 10 feet in every direction. - As an action, you can make a ranged ninjutsu attack against a target within 60 feet, firing an explosive payload. On a hit, this attack deals 3d6 fire damage and 3d6 force damage. On a hit or miss, all targets within a 10 foot radius of the point of impact must make a Dexterity saving throw, taking half the damage on a failure and knocked back 10 feet and falling prone, or take 1/4th the damage on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and increase both damages by 2d6 and increase the speed by 30 feet.", created_at: NOW, updated_at: NOW },
  { _id: "35e5d8cee0261bcd0bdf7319", name: "Overclock", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you cast a Mecha-Nin clan jutsu", range: "Self", chakra_cost: "2 Mecha Dice (*Special*)", components: "HS, CM", duration: "*Special*", description: "For a moment you unlock the inhibitors directing the flow of power from your internal chakra core to your mechanical systems, amplifying your jutsu in one of the following ways: - *Damage Amp:* If the jutsu deals damage, the damage ignores resistance and cannot be reduced by more than half. A creature damaged by this jutsu must succeed a Constitution saving throw, being knocked back 10 feet and becoming weakened until its next rest on a failed save. - *Rechambered Amp:* You must use your action to cast the same jutsu next turn, but upcast up to A-Rank, for 0 chakra cost. This cannot be used to cast an A-rank clan jutsu. - *Chakra Core Amp:* You gain temporary hit points equal to 5 times your Constitution modifier. These temporary hit points last for 1 minute or until you cast this jutsu again. - *Targeting Amp:* If the jutsu requires an attack roll, gain advantage on that roll. If the jutsu instead requires a creature to make a saving throw, you may select an affected target to have disadvantage on their initial saving throw. - *Thruster Amp:* If the jutsu grants either an increase of speed or a fly speed, double that amount for its duration. While that jutsu remains active, your movement doesn't provoke attacks of opportunity.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f7a5d1364affda2b2ce8603c", name: "Chakra Cannon Buster", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Full-Turn-Action", range: "Self (1-mile line)", chakra_cost: "*Special*", components: "HS, CM", duration: "Concentration, 1 minute", description: "You drill both your arms and legs into the ground as a stabilizer. Meanwhile, your mechanical form elaborately opens as your body takes the shape of a powerful cannon. Your exposed internal chakra core -- the source of this attack -- hums with energy. You do not spend chakra to maintain concentration on this jutsu. For the duration, your speed becomes 0, and you cannot be knocked prone or moved against your will. Beginning at the start of your next turn, you can spend your action to fire a blinding surge of energy forming a line 1-mile long and 30 feet wide blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes Xd10 Force and Xd10 Fire damage on a failed save, or half as much damage on a successful one. \"X\" equals 1d10 for every 5 chakra points spent. Every chakra point consumed this way lowers your current and maximum hit points by an equal amount, if this amount would bring your hit point total below 0, you die. This jutsu then ends. The damage of this attack ignores damage reduction, resistance, and turns immunity into resistance.A creature, except adversaries with Elite Actions, reduced to 0 hit points by this attack are killed instantly. This attack deals double damage to constructs and structures. The blast obliterates any non chakra-enhanced objects in the area that aren’t being worn or carried. Hit points lowered by this jutsu can only be restored through spending downtime. 1 week of downtime spent restores one quarter of your hit point total. Once this jutsu has been cast, you cannot cast it again until you've completed a long rest.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "43ee56bca8e57bd25a8a23cb", name: "Mecha-Mode: Unite", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (5 feet)", chakra_cost: "15 Chakra (*Special*)", components: "HS, CM, M", duration: "Concentration, up to 1 minute", description: "Your mechanical body steams as it opens into a hollowed interior, allowing yourself to be worn and wielded by another medium-sized creature like a suit of armor. You can't lose concentration on this jutsu as a result of damage. Select a willing creature in 5 feet of you as the target of this jutsu. You unite with this creature and it becomes your designated pilot. For the duration you're united, you and the pilot benefit from the following; ___ Mecha-nin: - Your movement becomes 0 for the duration. - Your position in initiative is moved to the pilot's, where both turns are taken simultaniously. - You gain an additional reaction, which can be used to at any time to end this jutsu, ejecting the pilot and landing in the nearest unoccupied space from you. - Your current hit points exist as temporary hit points to the pilot. Any damage resistances or immunities you may have function normally with these temporary hit point. - Any physical or elemental condition or effect targeting you does not effect the pilot. Any mental condition or effect targeting you instead only effects the pilot. ___ Pilot: - Increase its movement speed by half of your movement speed. - Its Strength and Dexterity scores become 19. If they're already 19 or higher, they increase by +2 instead. - The pilot shares the same benefits from your Bionic Enhancements and active jutsu. The pilot can also cast any hijutsu you know, and doing so must spend your chakra. - The Pilot may expend chakra from your pool to cast jutsu or activate abilities. - The Pilot's AC becomes equal to your AC, or gains a +1 bonus to its AC, whichever is higher. - The Pilot is considered to have full cover and can't be targeted by attacks or jutsu, unless that jutsu has the genjutsu keyword or deals necrotic or psychic damage. Otherwise, such attacks instead target and effect the you. If your hit or chakra points are reduced to 0, this jutsu immediately ends and the pilot is ejected from you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f59f5dcdc3491ecf670ce6c1", name: "Blue: Attracting Strike", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "06427c7781895bb879c51b10"], elements: [], casting_time: "1 action", range: "15 feet", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "You coat a fist in Limitless Blue and target a creature within range. The target creature must make a Strength Saving Throw, being pulled to a spot adjacent to you. You may then make a Taijutsu attack against that creature so long as they are within 5 feet of you. If they failed the Strength Save, you make the attack at advantage. On a hit, you deal your Unarmed Damage + 3d6 Force damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3 and the additional damage by 2d6. At B-Rank, this jutsu gains a range of 20 feet. At S-Rank, its range becomes 25 feet.", created_at: NOW, updated_at: NOW },
  { _id: "8ea8b8981e587c44d958489e", name: "Infinite Space", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 reaction when you are targeted for an", range: "Self", chakra_cost: "5 Chakra", components: "HS", duration: "Instant", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c0e5fa8be47b5b26c05959d2", name: "Red: Blow Back", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "a9c9ccf4fcff33469ddd57d5"], elements: [], casting_time: "1 action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a small orb of bright red chakra, no larger than a golf ball, and shoot it at a creature in range. Make a Ranged Ninjutsu attack against the creature, dealing 3d8 Force damage on a hit. The target must then also make a Strength Saving Throw or be pushed directly back 15 feet. If they fail this Strength Save, the next attack to hit them also deals an additional die of damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 2d8 and the amount pushed back by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "1365f9421b4593c7cfed068d", name: "Infinite Steps", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 bonus action", range: "60 feet", chakra_cost: "4 Chakra", components: "CM", duration: "Instantaneous", description: "When you hit a creature with an attack or Mugen Hijutsu, you may cast this jutsu as a bonus action. When you do so, you intensify the infinity surrounding the creature. The creature must make a Constitution Saving Throw. On a failed save, they gain 1 rank of the Slowed condition as they find moving through this limitless space difficult and taxing. On a success, they instead just reduce their movement speed by 10 feet. Either effect lasts until the end of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c86f296e2a4e7b50822071af", name: "Blue: Crush", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "06427c7781895bb879c51b10"], elements: [], casting_time: "1 action", range: "30 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You surround a creature with nothing, leaving no matter around them. This causes the universe to quickly rush into that spot, crushing and disorientating the target. Choose a creature within range, they must make a Constitution Saving Throw. On a failed save, they take 6d8 Force damage and are Dazed until the end of their next turn. On a successful save, they take half damage and aren't dazed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "1f41e070d47c0ccdddf1a1c8", name: "Limitless Movement", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 action", range: "100 feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant", description: "You weave together two spots, where you are and a place within range, a small infinity of space between the two, and compress them. You must be able to see or are familiar with the chosen spot. Teleporting to that spot, as the sudden shift in space sends forth a shockwave of energy. Creatures of your choice within 10 feet of the spot you teleported to and from must make a Constitution Saving Throw, taking 6d4 Force damage on a fail, and half as much on a success. You can bring along object as long as their weight doesn’t exceed what you can carry. You can also teleport one willing creature of your size or smaller who is carrying gear up to it carrying capacity. The creature must be within 5 feet of you when you cast this jutsu, and there must be an unoccupied space within 5-feet of your destination space for the creature to appear in; otherwise, the creature is left behind. All attacks made against you, and the creature you brought with if you brought one, are made at disadvantage until the start of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3 and the damage by 1d4. When cast at B-Rank, the Range becomes 500 feet. When cast at A-Rank, the range becomes 1 mile. When cast at S-Rank, the range becomes ten miles.", created_at: NOW, updated_at: NOW },
  { _id: "a261efd5bca45ea0d9abf293", name: "Red: Repelling Coat", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "a9c9ccf4fcff33469ddd57d5"], elements: [], casting_time: "1 action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You coat your body in the crimson red of your repelling Limitless chakra, causing attacks to struggle to hit you and maintain their force. You reduce incoming damage by 2, and also gain a +2 bonus to AC, as well as Strength and Dexterity Saving Throws.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "264a7089051f7e2e7b7b9159", name: "Blue: Lapse", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "06427c7781895bb879c51b10"], elements: [], casting_time: "1 action", range: "80 feet (20-foot radius)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You send forth a large ball of blue to a space within range, which the sphere centers around in a 20-foot radius creating a dead zone of matter in the air. As you let this orb dissipate, matter rushes in, also causing creatures nearby to be dragged with it. Creatures in the radius, or within 5 feet of the radius, must make a Strength Saving Throw. On a failed save, they are knocked prone, pulled 30 feet toward the center of the radius and take 8d10 Force damage. On a successful save, they take half damage and aren't pulled. If they hit an object, structure, or creature from this forced movement, they take 1d4 bludgeoning damage for every 5 feet travelled.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f4e6c01e2bace71e65bedd5b", name: "Red: Reversal", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a", "a9c9ccf4fcff33469ddd57d5"], elements: [], casting_time: "1 action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You create a ball of crimson chakra and focus it to a fine point above your fingers, before launching it at a creature within range. Make a ninjutsu attack against the target creature. On a hit, the target takes 9d8 Force damage and is dazed until the end of their next turn. If you hit, the warbling ball explodes outward into a cone of mass trying to correct itself. Creatures in a 15-foot cone behind the target must make a Dexterity Save. On a failed save, they take 3d8 Force damage and are pushed back 20 feet. On a success, they take half damage and aren't knocked back.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9ff4daead840886a610fb8a8", name: "Unlimited Void", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 action", range: "30 feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You pull all those around you into a space of true infinity. All creatures within 30 feet of you are brought to this space, and cannot move more than 30 feet away from where you were when you casted this jutsu. Creatures on the outside can try and enter by making a Ninshou check against your Ninjutsu Save DC, being able to enter on a success. When you cast this jutsu, creatures of your choice within 30 feet of you must make a Wisdom Saving Throw. On a failed save, they are Incapacitated and take 2d8 Psychic damage at the start of each of their turns as they feel, see, hear, all of their senses overwhelmed with everything possible faster than they can process it. On a successful save, the creature is instead Dazed for the duration of this jutsu. A creature incapacitated or dazed by this jutsu remains as such until the end of the jutsu or they succeed the save. A creature incapacitated by this jutsu remakes the save at the end of each of it's turns, becoming Dazed on a success. A Dazed creature also remakes the save at the end of each of it's turns, losing the condition on a success. >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b121e39333dc225fb705c926", name: "Cat Chakra Claw", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "You flow chakra into your claws as they become  sharper than steel. While concentrating on this jutsu, unarmed attacks and taijutsu you cast using your *Claws* gain a +1 bonus to hit and benefit from the *Critical* and *Multiattack* properties.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "37243622420d7e1e3261ca6a", name: "Cat Eye Trick", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "One creature in range that can see you is selected as the target of this genjutsu. You appear as an unassuming, harmlessly adorable cat to a creature under this genjutsu. The target must make a Wisdom saving throw, and does so with advantage if you or your allies are fighting it. Creatures that fail against this jutsu can repeat the save at the end of each of its turns, ending the effects on itself on a success. Critical SuccessThis jutsu ends on the affected creature, removing all ranks of charm inflicted by this jutsu and is immune to the effects of this jutsu for 1 hour. SuccessAffected creature does not gain a rank of charmed. FailureAffected creature gains 1 rank of charmed against the caster until this jutsu ends. Critical FailureAffected creatures gains 2 ranks of charmed against the caster until this jutsu ends and have their movement reduced to 0 as they are overwhelmed with cuteness.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by 1.", created_at: NOW, updated_at: NOW },
  { _id: "275428d487707b4373070102", name: "Flea Shuriken", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "CM, M", duration: "1 minute", description: "As a ninja cat you can stretch out your body, rolling the joints of your neck to launch chakra-enhanced fleas at a target in range to inflict extreme irritation. Make a ranged taijutsu attack against a single creature in range. On a hit, a target takes 3d6 piercing damage, then must succeed a Constitution saving throw or become Confused on a failed save, falling prone and unable to stand. At the beginning of each of its turns the creature takes 2d4 piercing damage. At the start of each of its turns, or if another creature uses the help action on it, the affected target can reattempt the save, ending the effects on itself on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage dealt by 1d6 and the number of targets hit by 1.", created_at: NOW, updated_at: NOW },
  { _id: "e278708a731936fdc7e04133", name: "Paw Swipe", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You mischievously steal away with your opponent's items in the cover of your attack. Make a melee &emsp;&emsp;taijutsu attack dealing your unarmed damage + 2d8. &emsp;&emsp;&emsp;On a hit, &emsp;&emsp;you can attempt to disarm or &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;steal one item on the target's body. Make a &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;Sleight of Hand check contested against the &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;target's AC, on a success you take the chosen &emsp;&emsp;&emsp;&emsp;&emsp;item. If the target's passive perception is lower &emsp;&emsp;&emsp;&emsp;&emsp;than your check, it's unaware the item has been &emsp;&emsp;&emsp;&emsp;&emsp;stolen.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "297a6c1cfe7e155f92e89bef", name: "Cat Food Clone", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "*Special* (8 Chakra)", components: "HS, CM, NT (1 lb of cat food)", duration: "Instant", description: "You create an identical clone of yourself made of cat food. The rules for this clone are the same as a shadow clone, except it has no chakra. The clone can cast any Ninneko clan jutsu with the Ninjutsu or Taijutsu keyword of C-Rank or lower you know twice without expending chakra. After the second casting, the clone disappears. You can only have one Cat Food Clone at a time. Creating another clone causes an existing clone to disappear. As an action, you can see through your clone's eyes and hear what it hears until the start of your next turn. During this time, you are deaf and blind with regard to your own senses. As a bonus action on your turn, or a reaction before taking damage or making a saving throw, you can swap places with your clone if you are within 30 feet of it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3c6df83b7dcf4a56b1f5f85e", name: "Cat Scratch Fever", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "You spring into the air with a flurry of swipes, unleashing your feline fury. Make three melee taijutsu attacks against any target(s) within range. On each hit, deal your unarmed damage + 1d4 slashing damage. If at least two attacks hit a single target, it gains one rank of bleeding. If all three attacks hit a single target, it gains one rank of lacerated. Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of attacks by 1.", created_at: NOW, updated_at: NOW },
  { _id: "cdc21d71ba4b799badcce0a1", name: "Catslumber", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "10 minutes", description: "This is an advanced version of the 'Catnap' jutsu. You lace your enchanting purs with revitalizing chakra to encourage a cat-like sleep in those around you. Up to four willing creatures of your choice within range fall unconscious for the jutsu’s duration. The jutsu ends on a target early if it takes damage or someone uses an action to awaken it. If a creature remains unconscious for the full duration, it gains the benefit of a short rest and temporary hit and chakra points equal to double your Genjutsu modifier, and it can’t be affected by this jutsu again until it finishes a long rest. Alternatively, you can cast this jutsu on a single creature in range that can hear you, sending that target into a deep slumber. The creature makes a Wisdom saving throw. Creatures that fail against this jutsu can repeat the save at the end of each of its turns, ending the effects on itself on a success. Critical SuccessThis jutsu ends on the affected creature, removing all conditions inflicted by this jutsu and is immune to the effects of this jutsu for 1 hour. SuccessThe creature is unaffected. FailureThe affected creature gains three ranks of slowed and it is unable to speak due to uncontrollable yawning until this jutsu ends. Critical FailureAffected creatures gains three ranks of slowed and it falls unconscious until this jutsu ends. An unconscious creature awakens if it takes damage or an action is used to wake it.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target by 1.", created_at: NOW, updated_at: NOW },
  { _id: "ed219ef8c18dc363e4a67e6c", name: "Cat Call", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Concentration, up to 1 hour", description: "Using a combination of wit, charm, and looks empowered by illusive genjutsu, you sway a creature to your side. When you cast this jutsu, choose one creature within range that can see and hear you. The creature must make a Wisdom saving throw: SuccessThe creature is unaffected. FailureAffected creature gains two ranks of Charmed until this jutsu ends. While the creature is charmed this way, as a bonus action on subsequent turns, you can command the creature to perform any task you ask of it in a friendly manner, to the best of its ability. If the task might cause harm to the creature, or if it conflicts with the creature's normal activities and desires, the target can make another Wisdom saving throw to try to end the effect. If the task would result in physical harm or death obvious to the creature, the jutsu ends. Critical FailureAffected creatures gains the same as *Failure* except now has disadvantage on its Wisdom saving throw to end the jutsu on itself.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target with this jutsu by 1.", created_at: NOW, updated_at: NOW },
  { _id: "a5808b08f8fbb5db8683c4c3", name: "Powerful Paw", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "CM, M", duration: "Instant", description: "You blitz toward an enemy with feline ferocity. Make a single melee taijutsu attack, dealing your unarmed damage + 6d6 bludgeoning damage against the target on a hit.", at_higher_ranks: "For each rank you cast this jutsu above &emsp;B-Rank, increase the cost of this jutsu by 3 and any d6 &emsp; &emsp;damage rolled from this jutsu increases its damage die size &emsp;by 1.", created_at: NOW, updated_at: NOW },
  { _id: "7f550d4a6d832c2447a90c55", name: "Purrrgatory", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "15 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You trap a creature in range within a perceived illusion of a cat-themed purgatory of your design. For the duration of the genjutsu, you alter the appearance of the environment surrounding the target. Select a creature in range. That target must make a Wisdom saving throw. SuccessThe creature breaks the illusion and this jutsu ends. FailureThe affected creature is trapped within a perceived illusion of a cat-themed purgatory of your design. For the duration of the genjutsu, you alter the appearance of the environment surrounding the target. The target becomes otherwise blind to their surroundings. In the illusory area created by the jutsu, three Shadow Cats appear, occupying a space within 60 feet of the target. Refer to the Shadow Cat stat block. On your turn, you can use a bonus action to command each Shadow Cat to move up to 60 feet and make a single attack. Critical FailureIn addition to *Failure*, an affected creature also gains 1 rank of Fear and is stunned until the beginning of its next turn. At the beginning of your turn while concentrating on this jutsu, you can choose to spend the chakra cost once more to create three additional Shadow Cats to a maximum of six (6). An affected target can make a Wisdom saving throw at the end of each of its turns. On a successful save it breaks free and the effects of the jutsu end on that target. If a target breaks out of this jutsu early, you can target another creature within range as an action. ___ >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "582ccf05e98fabaa46061af4", name: "Sound Release: Interference", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Reaction, which you take when you would take damage", range: "Self (10-foot sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 round", description: "You shroud yourself in a static field of vibrations that absorbs incoming attacks and disorients enemies. You create a 10-foot sphere of interfering vibrations centered on you that reduces the damage you would receive by 3d10, except wind damage. If this damage is either bludgeoning or earth, reduce it by twice as much. Then until the beginning of your next turn, all damage except wind dealt in this sphere is reduced by -3. Creatures that enter the sphere for the first time on a turn or begin their turn within it must succeed a Wisdom saving throw or gain 1 rank of concussed until their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage reduction by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "6bad8fcac8a915ae4b1b68f2", name: "Sound Release: Reverberating Sphere", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You hurl a spherical orb of compressed, vibrating wind at a target in range. On a hit, you deal 4d4 force damage and the target must succeed a Constitution saving throw or gain 1 rank of concussed until the end of its next turn. When you roll a 10 on at least two damage dice, the target also becomes deafened for as long as it remains concussed. On a failed save, the target takes another 2d4 force damage at the beginning of its next turn as the vibrations continue to shake it.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, also increase the damage dealt by 2d4, and the repeating damage by 1d4. When you cast this jutsu at B-Rank or above, the target also becomes dazed on a failed save.", created_at: NOW, updated_at: NOW },
  { _id: "ee1b080666f1f6f8beeccc01", name: "Sound Release: Sonic Burst", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Self (20-foot cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You gather your chakra forming it into soundwaves at the palm of your hands, building it up into a concussive boom. All creatures 20-foot cone originating from you on you must make a Constitution saving throw. On a failed save, a creature takes 4d6 force damage, and is pushed back 10 feet and becomes deafened for the next minute, repeating the save at the end of each of its turns. On a successful save, a creature takes half damage. In addition, unsecured objects that are completely within the area of effect are automatically pushed 10 feet away from you by the jutsu's effect, and the blast emits a concussive boom audible out to 300 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, also increase the damage dealt by 1d6 and cone's area increases by 5 feet. When you cast this jutsu at B-Rank or above, creatures that fail their saving throw are also knocked prone.", created_at: NOW, updated_at: NOW },
  { _id: "70fd6c4f0a8d9acf0b8d4b44", name: "Sound Release: Slicing Soundwaves", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "00ca3f040aa5aa24f905202a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "This is an advanced version of the 'Slicing Airwaves' jutsu. You channel compressed air through both of your arms as you knead chakra into it, causing that air to vibrate intensely. Make two ranged ninjutsu attacks against up to two targets. On each hit, you deal 2d8 force damage, and the target gains one rank of bleeding.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, also increase the damage dealt from each attack by 1d8 and the ranks of bleeding by +1.", created_at: NOW, updated_at: NOW },
  { _id: "d8adafe009e266a6f190cec1", name: "Sound Release: Extreme Slicing Soundwaves", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "7 Chakra", components: "CM", duration: "Instant", description: "You must have cast Slicing Soundwaves this turn as an action. You boost the cutting power of your soundwaves with a concussive boom. Double the range of the jutsu, increase the critical threat range of each ranged Ninjutsu attack you make with Slicing Soundwaves by +1 (to a maximum of +3), increase the damage die increases by 1 step, and on a critical hit the target becomes lacerated. In addition, unsecured objects that are within 5 feet of the target are automatically pushed 10 feet away from the target by the jutsu's effect, and the attack emits a concussive boom audible out to 300 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a899f5c2b1bfcd74290cef92", name: "Sound Release: Hypnotic Chime", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You utilize your wind chakra to produce a droning sound within a 20-foot sphere centered on point you can see in range. The sound it makes distracts and disorients creatures within its space. When you cast this jutsu, and whenever a creature enters the sphere for the first time on a turn, it must make a Wisdom saving throw. Creatures that fail against this jutsu can repeat the save at the end of each of its turns, ending the effects on itself on a success. SuccessAffected target does not become deafened. FailureAffected targets take 2d6 force damage and become deafened as all it hears is the chime and you become duplicated by the soundwaves it produces, causing the target to have disadvantage on attacks made against you while it remains deafened. Critical FailureSame as failure but affected targets now are dazed for as long as they remain deafened.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, increase the damage by 2d6 and the size of the sphere by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "7e787e5c57b93366fd977bf6", name: "Sound Release: Vibrating Echo Tremor", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "7 Chakra", components: "HS, CM, M", duration: "Instant", description: "You gather vibrating chakra into your fists or feet, slamming it down to create a devestating effect. Make a melee ninjutsu attack. On a hit, you deal 5d8 force damage and the target becomes concussed and dazed for 1 minute. The target can make a Constitution saving throw at the end of each of its turns to end this effect on itself with a success. The vibrating force of the attack ripples out from the target, causing the ground within 30-feet of it to become difficult terrain and all creatures except you within the radius must make a Constitution saving throw. On a failed save they take half the force damage and gain one rank of concussed. On a success, the take no effect. In addition, unsecured objects that are completely within the area of effect are automatically pushed 30 feet away from its center by the jutsu's effect, and the blast emits a concussive boom audible out to 300 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, increase the damage by 1d8 and the number of ranks of concussed inflicted by +1. If cast to A-Rank or higher, you can make 1 additional melee ninjutsu attack.", created_at: NOW, updated_at: NOW },
  { _id: "5bd034a81b31a36bafc627f7", name: "Sound Release: Echo Chamber", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You weave a spiral of vibrating wind, creating a 20-foot sphere centered on a point within range. Creatures inside the sphere are deafened to all sounds outside of the sphere, and vice versa, creatures outside the sphere are deafened to all sounds within the sphere. A creature that attempts to move through the space of the sphere must make a Constitution saving throw, taking 6d6 force damage, is knocked back 10 feet, gains two ranks of concussed, and be unable to move through it on a failed save. On a successful save, it takes half as much damage and can move through the sphere as if it were difficult terrain. Sound is hypnotically amplified while inside the sphere which causes creatures to take additional damage when they would take wind, psychic, damage dice per equal to the rank of the jutsu damaging them (D-Rank1, C-Rank2, B-Rank3, A-Rank4, S-Rank5).", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, increase the damage by 2d6 and the size of the sphere by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "865753190c6431ef0491ee72", name: "Sound Release: Resonating Blast", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Self (100-foot line)", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You compress air into a vibrating wave of sound as your send it roaring in a 100-foot line that is 10 feet wide. Each creature within the line must make a Constitution saving throw. On a failed save a target takes 6d10 force damage and becomes concussed and bleeding, and is pushed away from the line. A creature pushed away from the line is knocked back 20 feet on a failed save, but if it failed its save by 10 or more, it is instead knocked back the entire 100-foot length of the line. This jutsu deals double damage to objects and structures. Objects and structures reduced to 0 hit points by this jutsu are destroyed. In addition, unsecured objects that are completely within the area of effect are automatically pushed the full 100 feet away from you by the jutsu's effect, and the blast emits a concussive boom audible out to 300 feet.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, increase the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "0e32d4fbaeb07e4bcfa524d6", name: "Sound Release: Whisper / Bang", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Self (300-foot radius sphere)", chakra_cost: "15 Chakra", components: "HS, CM", duration: "*Special*", description: "When you cast this jutsu, you choose whether to *Whisper* or to *Bang*, either option having its own effect: Whisper. You create a low tone frequency which barely registers to most creatures. You must concentrate on this jutsu and it can last for up to 1 minute. This jutsu gains the Unaware Keyword. Each creature within 300 feet of you that can hear you must make on a Constitution saving throw. Choose two of the following effects. Each creature that fails suffers the chosen effects: - Gains two ranks of concussed, while concussed it also has one rank of charm or fear against you (your choice). - Gains two ranks of bleeding, while bleeding it also has one rank of charm or fear against you (your choice). - Takes 3d10 force damage at the start of each of its turns for the next minute. - Becomes deafened, while deafened you are considered invisible to that creature. On a successful save, a creature only suffers one of these effects. Bang. You gather your chakra into a swirling mass of resonating wind that grows more compressed and vibrating before it explodes in a massive boom. Each creature other than you within 300 feet of you must make a Constitution saving throw. On a failed save, a creature takes 10d10 force damage and deafened and dazed for 1 minute. On a successful save, a creature takes half damage and is only deafened for 1 minute. Creatures that fail this save by 5 or more also become concussed for 1 minute, suffering 1 rank of bleeding for each rank of concussed it has. The ground within this radius becomes difficult terrain.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "73906b35882f2cde03e206a5", name: "Guiding Eye", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 minute", range: "5 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 8 hours", description: "You create a Tiny incorporeal eye of shimmering light in an unoccupied space you can see within range. The eye exists for the duration, but it disappears if you teleport or travel to another dimension. When the eye appears, you name one major landmark, such as a city, mountain, castle, or battlefield on the same dimension as you. Someone in history must have visited the site and mapped it. If the landmark appears on no map in existence, the jutsu fails. Otherwise, whenever you move toward the eye, it moves away from you at the same speed you moved, and it moves in the direction of the landmark, always remaining 5 feet away from you. If you don't move toward the eye, it remains in place until you do and flashes to have you follow it once every 1d4 minutes.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3e387ed2fbd10a95f82ef5b6", name: "Locate", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "Describe or name an object that is familiar to you. You sense the direction to the object's location, as long as that object is within 1,000 feet of you. If the object is in motion, you know the direction of its movement. This jutsu can locate a specific object known to you, as long as you have seen it up close—within 30 feet—at least once. Alternatively, the jutsu can locate the nearest object of a particular kind, such as a certain kind of apparel, jewelry, furniture, tool, or weapon. This jutsu can't locate an object if any thickness of lead, even a thin sheet, blocks a direct </brpath>path between you and the object.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the chakra cost of this jutsu by 3 and the range the object can be from you by 500 feet. If this jutsu is cast at B-Rank or higher, you can describe or name a creature instead of an object for this jutsu to locate.", created_at: NOW, updated_at: NOW },
  { _id: "e47fa2a65ded89b5c70120ac", name: "Open Eyes", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (10 feet)", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 minutes", description: "You focus your chakra through your visual senses, protecting yourself and any allies within 10 feet of you from blindness and visual illusions. For the duration, affected creatures are immune to the blinded condition and have advantage on saving throws against genjutsu with the Visual keyword. You do not need to spend chakra to concentrate on this jutsu if your Junsugan is active.", at_higher_ranks: "For each rank you cast this jutsu above D- Rank, increase the cost of this jutsu by 3 and the radius by 5 feet. If you cast this jutsu at B-Rank, it instead lasts for up to 1 hour. If you cast this jutsu at S-Rank, it no longer requires concentration to maintain.", created_at: NOW, updated_at: NOW },
  { _id: "023fe0519c71a1885de92c3a", name: "Redirect", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 reaction, which you take when you would be", range: "Self", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "You must have your Junsugan active in order to cast this jutsu. To avoid any pain, you attempt to change the trajectory of the triggering effect to exclude you. The triggering creature must succeed on a Wisdom saving throw. On a failed save, the creature must change the target of all their attacks to another creature, or move their area of effect so that you are no longer in it. If they cannot target another creature, their attacks fail.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3a288328b858da9df407e488", name: "Clairvoyance", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "10 minutes", range: "1 mile", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 minutes.", description: "You create an invisible sensor within range </brin> &nbsp;  &nbsp;  &nbsp;  &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; in a location familiar to you (a place you </brhave>&nbsp;  &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; have visited or seen before) or in an obvious  &nbsp;  &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; </brlocation>location that is unfamiliar to you (such as behind a &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; door, around a corner, or in a grove of trees). The sensor &nbsp; &nbsp; remains in place for the duration, and it can't be attacked &nbsp; &nbsp; or otherwise interacted with. You can see through the  &nbsp; sensor as if you were in its space. If a creature's mouth is &nbsp; visible, anything they say is displayed to you as floating &nbsp; &nbsp; words above their head. A creature that can see the sensor (such as a creature with true sight or chakra sight) sees a luminous, intangible orb about the size of your fist.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2d5426c0320eef2366c1411c", name: "Mystic Eye", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 hour", description: "You create an eye within range that hovers in the air for the duration. The eye can be invisible if you choose. You mentally receive visual information from the eye, which has your visual senses. The eye can look in every direction. As an action, you can move the eye up to 30 feet in any direction. There is no limit to how far away from you the eye can move, but it can't enter another dimension. A solid barrier blocks the eye's movement, but the eye can pass through an opening as small as 1 inch in diameter. While your Junsugan is active, you do not need to spend chakra to maintain concentration on this jutsu, and you can move the eye as a bonus action instead of an action.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "055c69943b6291ac7ca9c206", name: "Overload", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You must have your Junsugan active in order to cast this jutsu. Locking eyes with a creature you can see within range, you send all of the visual information you have towards them, attempting to overwhelm their senses. The target must make an Intelligence saving throw, taking 6d6 psychic damage on a failed save and half as much damage on a successful save. On a failed save, a creature must also make a Wisdom saving throw. On a failed save, they are stunned until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 2d6. If this jutsu is cast at A-Rank or higher, you can target an additional creature.", created_at: NOW, updated_at: NOW },
  { _id: "ce9ea9e7e42c68d2fb5b98f9", name: "Scrying", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "10 minutes", range: "Self", chakra_cost: "13 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 minutes", description: "You can see and hear a particular creature you choose that is in the same dimension as you. The target must make a Wisdom saving throw, which is modified by how well you know the target and the sort of physical connection you have to it. If a target knows you're casting this jutsu, it can fail the saving throw voluntarily if it wants to be observed. On a successful save, the target isn't affected, and you can't use this jutsu against them again for 24 hours. On a failed save, the jutsu creates an invisible sensor within 10 feet of the target. You can see and hear through the sensor as if you were there. The sensor moves with the target, remaining within 10 feet of them for the Duration. A creature that can see invisible objects sees the sensor as a luminous orb about the size of your fist. Instead of targeting a creature, you can choose a location you have seen before as the target of this jutsu. When you do, the sensor appears at that location and doesn't move. | Knowledge | Save Modifier | |:---|:------------| | Secondhand (you have heard of the target)  | +5 | | Firsthand (you have met the target)  | +0| |  Familiar (you know the target well) | -5| | Connection | Save Modifier | |:---|:------------| |  Likeness of picture  | -2    | |  Possession or garment  | -4      | |  Body part, lock of hair, bit of nail, or the like  | -10     | </div>", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4d4d3f3d9d0905114f75b8ef", name: "True Seeing", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "1 hour", description: "You must have your Junsugan active in order to cast this jutsu. For the Duration of the jutsu, you imbue yourself with true sight. You can also notice secret doors hidden by chakra, and can see ethereal beings, all out to a Range of 120 feet. Additionally, you ignore any effects that might make a creature immune to being found by jutsu with the Sensory keyword. Finally, your Junsugan's passive bonuses persist while this jutsu is active, and any visual ranges are extended to 120 feet. However, you cannot use any features that require you to take any actions of any kind without first activating your Junsugan again.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "98c6abf1b63417bf49141e3d", name: "Teleport", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "10 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You must have your Junsugan active to cast this jutsu. This jutsu instantly transports you and up to eight willing creatures of your choice that you can see within range, or a single object that you can see within range, to a destination you select. If you target an object, it must be able to fit entirely inside a 10-foot cube, and it can't be held or carried by an unwilling creature. The destination you choose must have been seen by you, and it must be in the same dimension as you. Your familiarity with the destination determines whether you arrive there successfully. The DM roll 1d100 and consults the table. *Familiarity.* \"Associated object\" means that you possess an object taken from the desired destination within the last six months, such as a book from a village's library, bed linen from a royal suite, or a branch from a tree in a sage's grove. \"Very familiar\" is a place you have been very often, a place you have carefully studied, or a place you can clearly visualize when you cast this jutsu. \"Seen casually\" is someplace you have seen more than once but with which you aren't very familiar. \"Viewed once\" is a place you have seen once, possibly using a jutsu. *On Target.* You and your group (or the target object) appear where you want to. *Off Target.* You and your group (or the target object) appear a random distance away from the destination in a random direction. Distance off target is 1d10 x 1d10 percent of the distance that was to be traveled. For example, if you tried to travel 120 miles, landed off target, and rolled a 5 and 3 on the two d10s, then you would be off target by 15 percent, or 18 miles. The DM determines the direction off target randomly by rolling a d8 and designating 1 as north, 2 as northeast, 3 as east, and so on around the points of the compass. If you were teleporting to a coastal city and wound up 18 miles out at sea, you could be in trouble. *Similar Area.* You and your group (or the target object) wind up in a different area that's visually or thematically similar to the target area. If you are heading to your home laboratory, for example, you might wind up in another scientist's laboratory or in an alchemical supply shop that has many of the same tool and implements as your laboratory. Generally, you appear in the closest similar place, but since the jutsu has no range limit, you could conceivably wind up anywhere in the same dimension. *Mishap.* The jutsu's unpredictable chakra results in a difficult journey. Each teleporting creature (or the target object) takes 3d10 force damage, and the DM rerolls on the table to see where you wind up (multiple mishaps can occur, dealing damage each time). <div class='wide'>", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ce3c5f69d2e979ae04036456", name: "Atlesian Blade Rush", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 bonus action", range: "Weapon Range", chakra_cost: "6 Chakra", components: "CM, M, W (Two or more Light weapons)", duration: "Instantaneous", description: "(This Jutsu Cannot Score a Critical Hit) You make a flurry of attacks with your blades, using nigh- invisible Chakra Strings to speed your movements along. Make two melee taijutsu attack against one creature you can see within range with different weapons. On a hit, you deal your weapons damage + 1d6, but you do not add your ability modifier to your weapons damage. If at least two hit, make one more attack with any weapon used, that deals your weapon damage but does not add your ability modifier.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. At B-Rank you make one more attack on both the primary and secondary attacks. At S-Rank you make an additional attack on both the primary and secondary attacks.", created_at: NOW, updated_at: NOW },
  { _id: "94e35a0cc50482ae1082e1af", name: "Atlesian Defense Matrix", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 reaction, in response to being hit with an", range: "Self", chakra_cost: "3 Chakra", components: "CM, M, W (Two or more Light weapons)", duration: "Instantaneous", description: "You analyze your enemies' strikes as they come, pinpointing the exact way to counter everyone. When you would be hit by an attack roll, you can roll the damage die for one of your weapons and subtract that from the attack roll, potentially causing it to miss. You gain an additional reaction which you can only use to cast this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7e2dc9d620cb6b23a42ada6c", name: "Atlesian Evasion", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 bonus action", range: "30 feet", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instantaneous", description: "You utilize your physiology to its fullest, ejecting Chakra strings from your back unit to pull yourself away from oncoming danger. Target a surface within range. You extend Chakra strings toward it, embedding them inside, and retract, pulling yourself towards it at high speeds. Attacks of opportunity made during this movement are made at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and its range by 10 feet. When casting this jutsu at B-Rank or higher, it can be cast as a reaction.", created_at: NOW, updated_at: NOW },
  { _id: "6768379c50df9f47896b494f", name: "Atlesian Laser Targeting", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 action", range: "60 feet", chakra_cost: "Special ( 1 Chakra per beam)", components: "CM, M, W (Floating Array)", duration: "Instantaneous", description: "You learn to focus your chakra through your weaponry, and into unerring beams of raw force. You create a beam of force for each weapon you are wielding in your Floating Array, which hit a target within range. A beam deals 1d4+1 force damage to its target. The beams all strike simultaneously, and you can direct them to hit one creature or several.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7d93224dde4b13d615bde689", name: "Atlesian Blade Dance", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 action", range: "Weapon range", chakra_cost: "8 Chakra", components: "CM, M, W (Floating Array)", duration: "Instantaneous", description: "You twirl blades around your body at high speed, hitting all enemies around you. Target all enemies in the radius of your lowest range weapon. They must make a Dexterity saving throw or take 6d6 damage of one of your Floating Array's damage types, or half as much on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and increase the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "98298e82489ceb9896babc90", name: "Atlesian Cable Binding", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 action", range: "30 feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "You extend your Chakra Strings toward up to two targets in range, and force them to make a dexterity saving throw. On a failure, they are grappled in place, and restrained while grappled in this way. At the end of each of the grappled creatures' turns, they can make a strength saving throw, breaking free on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and target 1 additional creature.", created_at: NOW, updated_at: NOW },
  { _id: "41c75f1a2b71034cfbe2d571", name: "Atlesian Sensory Matrix", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "4ca66bf77ffa28385682255c", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 action", range: "Self", chakra_cost: "9 Chakra", components: "CM", duration: "Concentration, up to 1 hour", description: "You activate your chakra-enhanced eyes, simulating the effects of a Dojutsu. You do not spend chakra to maintain concentration of this jutsu. For the duration, you have 300 feet of darkvision, 120 feet of chakra sight, and advantage on Perception and Investigation checks.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bbfd5b8bd6760833814bcf3b", name: "Atlesian Blade Binding", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 action", range: "60 feet", chakra_cost: "13 Chakra", components: "CM, M, W (Floating Array)", duration: "Concentration, up to 10 minutes", description: "You gain the ability to move or manipulate creatures or objects stabbing into them and gripping them with your blades. When you cast the jutsu, and as your action each round for the duration, you can exert your blades on one creature or object that you can see within range, causing the appropriate effect below. You can affect the same target round after round, or choose a new one at any time. If you switch targets, the prior target is no longer affected by the jutsu. Creature. You can try to move a Huge or smaller creature. Make an ability check with your Taijutsu ability contested by the creature's Strength check. If you win the contest, you move the creature up to 30 feet in any direction, including upward but not beyond the range of this jutsu. Until the end of your next turn, the creature is restrained by your blades. A creature lifted upward is suspended in mid-air. On subsequent rounds, you can use your action to attempt to maintain your telekinetic grip on the creature by repeating the contest. Object. You can try to move an object that weighs up to 1,000 pounds. If the object isn't being worn or carried, you automatically move it up to 30 feet in any direction, but not beyond the range of this jutsu. If the object is worn or carried by a creature, you must make an ability check with your Taijutsu ability contested by that creature's Strength check. If you succeed, you pull the object away from that creature and can move it up to 30 feet in any direction but not beyond the range of this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4821124b1fa14a472302a7bd", name: "Atlesian Laser Volley", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["2f6189c677ac38c9ac5435cf", "4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 action", range: "Self", chakra_cost: "13 Chakra", components: "CM, M, W (Floating Array)", duration: "Concentration, up to 1 minute", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f2be4d0ae7a8873fc752e807", name: "Atlesian Artillery Cannon Mk. 5", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 full turn action", range: "100 feet", chakra_cost: "20 Chakra", components: "CM, W (Floating Array)", duration: "Concentration, up to 1 minute", description: "You compose your Floating Array into a circle formation in front of you, spinning it into a You unleash a beam of pure chakra when you cast this jutsu and blast it outward in a line that is 100 feet long and 15 feet wide that persists until the start of your next turn. Any creature that starts their turn in this beam must make a Dexterity saving throw. On a failed save they take 10d12 force damage, or taking half as much on a successful save. This jutsu deals double damage to structures and constructs. While you are concentrating on this jutsu, your movement speed is 5 ft. At the start of each of your turns, you can use your action to maintain the beam or redirect it, rotating it up to 90 degrees in any direction. Any creature the beam passes through while rotating (if the beam passes completely through them and they will not start their turn inside of it) must make a Dexterity saving throw or, take 5d12 force damage on a failed save, and taking no damage on a successful save. Each turn you use your action to maintain the jutsu, the damage die decreases by 1 step (min d4). If you do not use your action to maintain or redirect it, the jutsu ends early.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank increase the cost of this jutsu by 3, and increase the damage by 2d12.", created_at: NOW, updated_at: NOW },
  { _id: "27960a73f16f3a75bf1bac7c", name: "Power Sledgehammer", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "You perform a potential three piece combo to lock an opponent down. Make two melee taijutsu attacks, dealing your unarmed damage + 1d4. On each hit, the creature must succeed a Constitution saving throw or become Dazed. If both attacks were successful, you can follow up with a 3rd melee taijutsu attack, dealing your unarmed damage and knocking the creature prone on a hit. This third attack scores a critical hit on a 19-20. These attacks do not add your ability modifier. Danger AmplificationBy using Danger Points, you can improve this jutsu's effect. When you impose a Constitution saving throw with this jutsu, you can spend 2 Danger Points to cause the creature to become Weakened until the end of your next turn on a failure. You must declare you are spending Danger Points for this purpose before you attack.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and both instances of damage by 1d4. If cast to B-Rank or higher, increase the damage die by 1 step, and you can now add half your ability modifier to each attack. If cast to S-Rank or higher, increase the damage die by 1 step, and you now add your full ability modifier to each attack.", created_at: NOW, updated_at: NOW },
  { _id: "70f4365eb4867b74b9c6e85d", name: "Crimson Blaster", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "Instant", description: "You rapidly form a hand sign and then jump high into the air and channel chakra into your legs, forming it into a sphere in front of you which you then kick towards a creature within range. Make a ranged ninjutsu attack, dealing 2d8 + your Ninjutsu ability modifier in  force damage. Danger AmplificationBy using Danger Points, you can improve this jutsu's effect. You can spend 3 Danger Points. When you do,  until the end of your turn, you can target one affected creature with a  Jutsu with the *Finisher* keyword regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to B-Rank, increase the number of attacks made by +1. If cast to S-Rank, increase the number of attacks made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "848bab40c65cfaef8bcb86c5", name: "Venomous Breath", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Reaction, which you take when a creature would miss you with an attack.", range: "*Special*", chakra_cost: "3 Chakra", components: "CM, M", duration: "Instant", description: "You employ a dirty tactic to catch your foes off guard. When a creature misses you with an attack, you can leap over the creature and land in a space behind them that can hold you, simultaneously  exhaling a breath of purple mist at them. The target must succeed a Constitution saving throw, or become Blinded until the end of their next turn. If the target is Poisoned or Envenomed, they roll with a -1d4 penalty, and gains the blinded condition for the duration of their Poisoned or Envenomed condition on a failure (whichever lasts longer).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f6cc68ff05f771a569c23e5f", name: "Sankaku Style: Hypebeast", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action or 1 Reaction, when you would roll for initiative", range: "Self (20-foot radius)", chakra_cost: "*Special* (28 Chakra)", components: "HS, CM", duration: "5 Rounds", description: "You boast a claim of victory, of determination, or anything you can think of to boost your allies morale. You raise your fist to the air and create a pulse of clear chakra to empower allied creatures within 20 feet. All allied creatures gain the following benefits for the duration; - All creatures gain a +1 bonus to AC. - All creatures gain a bonus to initiative checks equal to your Strength modifier. - Once per turn, an affected creature can give themselves a +1d4 bonus to a single skill check, attack roll, saving throw, or damage roll. - All creatures, other than you, can spend and roll up to 2 hit die and 2 chakra die. The creatures gain temporary hit points equal to the result of their hit die and temporary chakra equal to the result of their chakra die. - All creatures know of any conditions affecting each other. - All creatures are aware of each other's exact location. Combination*If this jutsu is cast as a Combination jutsu, increase the duration of this jutsu by 1 round per additional caster, excluding yourself.* *Any creature who assists in casting this jutsu as a combination jutsu increases this jutsu's supportive abilities based on the highest Charisma modifier within the group of casters. (+0-1No change. +2Increase the bonus to AC gained by +1. +3Affected creatures increase their movement speed by 15 feet and ignore difficult terrain. +4Affected creatures reduce the first instance of damage they take per round by -5. +5Affected creatures can now roll up to 4  hit die and 4 chakra die.) *", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c35a9da88f49fb989e14d3d2", name: "Crimson Pressure", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant", description: "A more powerful, altered  version of the *\"Crimson Blaster\"* hijutsu. Using the same technique as Crimson Blaster, you amplify one sphere further, making it huge. Make a ranged taijutsu  attack against a creature within range, dealing your 4d10 force damage as you create a large explosion. The creature must make a Strength saving throw, becoming Deafened until the end of their next turn due to the sound of the explosion and being knocked prone on a failed save. If this jutsu is cast as a *Finisher*, you instead deal 6d10 force damage on hit. Regardless of a hit or miss, the area within a 15-foot radius of the creature becomes difficult terrain, and  all creatures other than the target within this radius must succeed a Dexterity saving throw or take half damage. Danger AmplificationBy using Danger Points, you can improve this jutsu's effect. You can increase the radius of this jutsu when used as a *Finisher* by 5ft per Danger Point spent, up a maximum increase of 15ft. If you spend 3 Danger Points this way, all affected creatures must make the Strength saving throw to avoid becoming Deafened.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "c945931fbe7b013c3799532e", name: "Power Crusher", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you would take damage from an attack", range: "Self", chakra_cost: "*Special* (6 Chakra)", components: "CM, M", duration: "1 Round", description: "A powerful taijutsu of the Sankaku Clan where the user channels chakra within their muscles to absorb and redirect the negative feedback of attacks received. This jutsu cannot be cast while wearing  heavy armor. When you would be damaged by an attack, you contest the attack roll with a Constitution (Chakra Control) check. If you have expertise in Chakra Control, you instead add a +1d4 bonus in place of expertise. Critical hits cause you to always roll at disadvantage unless the critical hit can be negated. If you succeed this contest, you reduce the damage dealt by half and you gain 1 stack of Feedback until the end of the next turn. When you would make an unarmed attack, or cast a Taijutsu or Sankaku Hijutsu, you can convert any stacks of Feedback you have into 1 extra damage die. You also gain an extra reaction until the end of the turn, which you can use to cast this jutsu again at half cost. If you fail this contest, you reduce the damage by 2d8, and can't use this reaction again until the start of your next turn. Danger AmplificationBy using Danger Points, you can improve this jutsu's effect. When you would be critically hit while gaining this jutsu's benefits, you can spend 2 Danger Points to treat the critical hit as a normal hit.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "39f6b99bc1fa0727eed595a4", name: "Venomous Fists", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "7 Chakra", components: "CM, M", duration: "1 Minute", description: "You take in a big gulp of air and use medical chakra to isolate the toxic carbon dioxide within the atmosphere. You exhale this mixture onto your fists, causing them to be surrounded in a purple smog of poisonous chakra for the duration. This jutsu ends early if you reach 0 hit points. For the duration, your unarmed damage becomes poison and increases by 1 step. If this would cause your unarmed damage to go beyond a d12, your unarmed damage instead increases by +2. Twice per turn, when you hit a creature with an unarmed or taijutsu attack using your fists, they must succeed a Constitution saving throw or become Envenomed for the duration of this jutsu. If you score a critical hit, the creature makes this saving throw at disadvantage, and is also Poisoned on a failed save for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "40ce78e07dec24d5df5ae3ff", name: "Sankaku Style: Wombo Combo", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "*Special* (49 Chakra)", components: "CM, M", duration: "Instant", description: "This jutsu can only be cast if you have one or two other casters within 30 feet of you. You dash towards a creature within range and go for a punch to knock the wind out of them, followed by a grapple into a throw, placing trust within your allies to finish the combo. Make a melee taijutsu attack, dealing your unarmed damage on hit and imposing a Constitution saving throw. On a failed save, the creature gains 1 rank of Bruised. You then make a grappling contest against the creature, at advantage if the creature failed their Constitution saving throw. If you succeed, you grab the creature and spin them around rapidly. You then throw the creature a space within 30 feet and the other casters of this jutsu  can target them with a Taijutsu or Bukijutsu *Finisher*, with a casting time of 1 action or bonus action, once per turn, regardless of range, ignoring listed casting time. CombinationWhen this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between all casters. -        +0-1No Change. -        +2-3The target makes their Constitution saving throw with a -1d4 penalty. -        +4-5The creature cannot take reactions against Finishers cast against them until the end of the turn if you succeeded your grapple contest.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e9db1aaefc1305f42561cafb", name: "Crimson Comet Crash", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "13 Chakra", components: "CM, M", duration: "Instant", description: "You generate a large amount of chakra in your legs, causing them to be surrounded in blazing red energy. Select a creature within 60 feet. You teleport to this creature and immediately make two melee taijutsu attacks as you strike them with two kicks, dealing your unarmed damage + 1d8. For every two attacks made, the target must succeed a Strength saving throw, with a -2 penalty per attack that hits, or be knocked 30 feet in any direction of your choice. You can only knock a creature upwards once. On a failed save, if you would make more attacks with this jutsu, you teleport to them again to continue your assault. If you score a critical hit with this jutsu, instead of doubling the damage die, increase the damage die of this jutsu to 1d12s for the attack that crits. Danger AmplificationBy using Danger Points, you can improve this jutsu's effect. When you teleport to a creature using this jutsu, you can spend 2 Danger Points to make an Athletics check contested by the target's passive perception. If you succeed this check, the target is surprised for the next two attacks you make against them this turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the number of attacks made by +2.", created_at: NOW, updated_at: NOW },
  { _id: "3e1506910e6d5d69fb5fde4d", name: "Sankaku Penatrator", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a red aura which cause the ground to quake and dberis to disperse. You make a fist, shifting your aura into it, causing your hand to radiate with a burning red glow. Make a ranged Ninjutsu attack against a target in range as you fire a piercing beam of chakra. On a hit, you deal 9d6 force damage, which ignores cover, damage reduction, and temporary hit points. All creatures, between you and the target, must make a Dexterity save, taking half damage on a failure. Damage AmplificationBy using Danger Points, you can improve this jutsu's effect. For each Danger Point you spend, increase the damage die of this jutsu by 1 step. If you spend at least 2 Danger Points on this jutsu, this jutsu ignores resistance and treats immunity as resistance (If you spend 4, this jutsu ignores resistance and immunity).", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3, and gain a +2 to Clash checks. <div class='artist' style='bottom:30px;left:60px;'>", created_at: NOW, updated_at: NOW },
  { _id: "95195a649a552dca8807bba4", name: "Sankaku Style: Dangerous Geometry", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Full Turn Action", range: "*Special*", chakra_cost: "*Special* (77 Chakra, 9 Danger Points)", components: "CM, M", duration: "Instant", description: "This jutsu can only be cast if you have 3 to 5 casters within 30 feet of you. You release a gargantuan amount of chakra, emitting 30-foot bright light from yourself, which gathers and forms into a bestial effigy of your design that can be seen by onlookers. Your potent energy spreads to allied creatures within 30 feet of you, exciting their blood and intensifying their strength as they manifest their own bestial effigy. Select a creature within 120 feet of you. You and all allied creatures assisting this jutsu begin circling the creature from a 15-foot distance with immense, unquantifiable speed, forming a shape with a number of corners equal to how many creatures are performing this jutsu (For example, 3 casters create a triangle, 5 casters create a pentagon.) Each creature then, one by one, makes a melee taijutsu attack as they go in for a punch, kick, or headbutt, dealing their unarmed damage + 9d4 and knocking the creature 10 feet in a direction as the next creature in order goes in for their own attack. If any creature scores a critical hit, instead of doubling the damage, add twice their ability modifier to the damage roll. If 2 or more casters successfully hit their attacks, you teleport back to where you were initially standing, all other casters  teleporting next you in the closest space that can hold them, abreast each other facing the target. All creatures then cast a Ninjutsu of C-Rank or lower that makes a single attack roll or imposes a saving throw across an area of effect that is a line or cone at the creature, ignoring range. All Ninjutsu cast combine into one epic blast. Make a Ninjutsu attack roll using the highest Ninjutsu attack roll amongst all casters, affecting the creature with all Ninjutsu used on a hit that required an attack roll. This attack roll cannot score a critical hit. For jutsu that required a saving throw, the creature must make a single Constitution saving throw, suffering the damage and effects of all jutsu used that impose a saving throw on a failed save, or half damage on a success. Once this jutsu concludes, all casters gain 1 rank of Weakened, and you gain 1 rank of Exhaustion for 1d4+2 rounds. This exhaustion cannot be removed by any means and must run its course.  You cannot cast this jutsu again until you lose this rank of exhaustion. CombinationWhen this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between both casters. - +0-1No Change - +2-3The damage of this jutsu increases by 1 step. - +4-5All creatures gain a +1d4 bonus to hit with their taijutsu attack rolls.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "da4265ebbecd4c643d8ffdf2", name: "Ego Shift", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "CM, W (Ego Weapon)", duration: "Special", description: "You alter the properties of your Ego Weapon to better suit your situation, melding your Spirit's potential to your will. When you cast this jutsu, you can select a number of weapon properties equal to half your Ninjutsu Ability Modifier. These weapon properties must be present on other weapons that match the same type of weapon as your Ego Weapon. (Melee weapons can only gain properties found on melee weapons, and ranged weapons can only gain those that are found on ranged weapons) For the remaining duration of your Ego Weapon's existence, it gains the chosen weapon properties in addition to any others it possesses.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the number of properties by +1. If this jutsu is cast at B-Rank or higher, you can remove up to two weapon properties your Ego Weapon possesses when you cast this jutsu, and you can choose to have the chosen weapon properties apply to Seol Hijutsu with the Bukijutsu or Taijutsu keywords that you cast.", created_at: NOW, updated_at: NOW },
  { _id: "b344f5cc52f8f3c5cfaec78b", name: "Expel Soul", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "Special", range: "Special", chakra_cost: "4 Chakra", components: "CM, W (Ego Weapon)", duration: "Instant", description: "Once per round, when you would hit a creature with a weapon attack or a Taijutsu attack you can choose to attempt to drive your Ego Weapon into their soul, temporarily forcing it from their body to throw them into disorder. The target creature takes your Ninjutsu Ability modifier in Force damage and must make a Charisma saving throw, gaining Dazed on a failure. Until the end of the current turn, you can target one affected creature with a *Finisher*, regardless of range, once per turn, using either an Action, Bonus Action, or Reaction, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3, and the damage by your Ninjutsu Ability modifier.", created_at: NOW, updated_at: NOW },
  { _id: "cb1d834e97f33b0f6a3aa565", name: "Spiritual Arrest", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Special", chakra_cost: "5 Chakra", components: "CM, W (Any)", duration: "Concentration, up to 1 minute", description: "Your Spirit flares up its energy within your weapon, causing it to blaze with power for a short time. The next time you hit a creature with an attack that uses this weapon you deal an additional 2d8 damage, the damage type being determined by the type you selected in your Shared Power feature. If this jutsu is cast on your Ego Weapon, on a successful hit ethereal chains explode outwards from the weapon, and the target creature must make a Strength Saving Throw, becoming Restrained on a failure. At the end of each of their turns that they remain Restrained, a creature must make a Strength Saving Throw to break the chains and end this jutsu's effects on them.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 1d8.  If this jutsu is cast at A-Rank or higher, you can choose to cause a creature that fails their saving throw to become Stunned instead of Restrained. If you do, they instead remake their saving throw at the start of each of their turns.", created_at: NOW, updated_at: NOW },
  { _id: "1f869d4403cef3739a9e4803", name: "Spirit Tether", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "b5e8ac06ada0310dcd377049", "33ab3a61f3027398cd08f131", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "5 Chakra", components: "CM, M, W (Any)", duration: "Concentration, up to 1 minute", description: "You perform a deadly strike against an enemy that makes it seem like you looked into their soul to see their weakness. This jutsu can only be cast as a *Finisher*. Make a melee or ranged Taijutsu attack against a creature within range. On a successful hit, they take your weapon's damage + 2d8 and gain 2 ranks of Bleed. Damage dealt by the Bleeding condition inflicted by this jutsu is Force damage. If this jutsu is used with your Ego Weapon as a component, the initial attack is made at advantage, and on a successful hit the creature's soul is marked with an tether that is only visible to those with chakra sight or true sight. The tether extends to the edge of this jutsu's range, and a creature that the tether is attached to has disadvantage on checks made to conceal themselves from you. If a creature would leave the range of this jutsu the tether snaps and ends the effects of this jutsu on them, but their movement speed is halved until the end of your next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the range by 15 feet, and the damage by 2d8. If this jutsu is cast at B-Rank or higher, a creature must make a Charisma Saving Throw at the start of each of their turns the tether remains on them, having their movement speed halved on a failure.", created_at: NOW, updated_at: NOW },
  { _id: "2182a3c3c871bbdc06bc7f14", name: "Memento Mori", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "8 Chakra", components: "CM, M, W (Ego Weapon)", duration: "Concentration, up to 1 minute", description: "You carve into your opponent's soul, allowing your Spirit to summon forth vestiges from its world to assail your enemies. This jutsu can only be cast as a *Finisher.* Make a melee or ranged Taijutsu attack, dealing your weapon's damage + 4d8 on a hit. A creature hit by this jutsu must then make a Wisdom Saving Throw as spirits begin to tear into them. On a failure, they become Dazed, and are marked for death by the otherworldly spirits. At the start of each of their turns, they take 1d10 + your Ninjutsu Ability Modifier in Psychic damage. If you roll a 10 on at least 1 of the d10s, the target also gains 1 rank of Slowed that remains for the duration. At the end of each of their turn that they remain under the effects of this jutsu, the creature can remake their Wisdom Saving Throw to end its effects on them. On a success, any ranks of Slowed they gained are also lost.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the initial damage by 1d8, and the Psychic damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "7132b4b305674ff671fb9b69", name: "Multifold Exorcism", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "7 Chakra", components: "CM, M, W (Any)", duration: "Instant", description: "You tear open a rift to your Spirit's world, drawing forth a storm of blades that seek to excise the weak. Select a number of creatures within range equal to half your Ninjutsu Ability Modifier rounded up. Those creatures must make Dexterity Saving Throws, taking your weapon's damage + 3d10 Force Damage and being knocked Prone on a failure, or half as much damage and no effects on a success. If this jutsu is cast using your Ego Weapon as a component, creatures knocked Prone by this jutsu also become Restrained for the duration that they remain prone, as the swords that rain down nail them to the ground. On each of their turns that they remain Restrained, they can use an Action or Bonus Action to make a Strength Saving Throw, ending this jutsu's effects on them on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the range by +15 and the  damage by 1d10. If this jutsu is cast at B-Rank or higher, you can instead select a number of targets equal to your full Ninjutsu Ability Modifier. If this jutsu is cast at A-Rank or higher, if you use your Ego Weapon to cast this jutsu, a creature can only attempt to break free once per turn.", created_at: NOW, updated_at: NOW },
  { _id: "053b4726dbbcfd9f66caaabe", name: "Soul Read", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction, when a hostile creature make an attack or force allied creatures within range to make a saving throw", range: "Self (15 feet radius)", chakra_cost: "7 Chakra", components: "CM, W (Ego Weapon)", duration: "1 Round", description: "You fully link your mind with your Spirit's, attaining a limited amount of extrasensory perception from the bond. You both then spring into action, expelling your energy to form a stalwart shield that protects those close by from harm. When you cast this jutsu, all allied creatures in range gain a +5 bonus to their AC against the triggering attack or gain advantage on the triggering saving throw. Then, until the start of your next turn, while allied creatures remain within range of this jutsu they gain a +3 bonus to their AC or a +2 bonus to all saving throws for this jutsu's duration.  Allies cannot gain the benefit of this jutsu if they are already gaining bonuses to their AC or Saving Throws from a jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "55e365ceae75cd9e25de9bed", name: "Earthbound Impermanence", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "13 Chakra", components: "CM, M, W (Any)", duration: "Concentration, up to 1 minute", description: "You strike a creature with your chosen weapon, attempting to sever the ties that bind them to this world and send them partially to the next one. This jutsu can only be cast as a *Finisher.* Make a melee or ranged Taijutsu attack, dealing your weapon's damage + 5d10 on a hit. A creature hit by this jutsu must make a Charisma Saving Throw, having their mind, body, and spirit all thrown into disarray at once on a failure. A creature who failed their saving throw is Incapacitated, Blinded, and unable to move for this jutsu's duration. At the start of each of their turns, the target makes a Charisma Saving Throw. On a success this jutsu's effects end, but on a failure you roll 1d20. On a roll of 11 or higher, that creature's body and soul vanish into the other world, disappearing from their location until the start of their next turn. On a roll of 10 or lower, they remain in their position as usual.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3 and the damage by 1d10. If this jutsu is cast at A-Rank or higher, a number of times equal to your Ninjutsu Ability Modifier per casting of this jutsu, you can choose to treat the result of the d20 as if it rolled an 11.", created_at: NOW, updated_at: NOW },
  { _id: "da9ff1bab570d04b6ca92fc2", name: "Ego Death", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "*Special* (14 Chakra)", components: "CM, M, W (Ego Weapon)", duration: "Concentration, up to 1 minute", description: "You drive your Ego Weapon deep within a creature's core, flooding their psyche in an attempt to overwrite it with your Spirit's will. This jutsu can only be cast as a *Finisher.* Make a melee or ranged Taijutsu attack against a creature within range. On a success, you deal your weapon's damage + 6d6 in Psychic damage. You can force an affected creature to make a Charisma saving throw, becoming subsumed by your Spirit's consciousness on a failure. Also on a failure, your Spirit's remaining time of Physical Manifestation is reduced to 0 and your Spirit leaves your Ego Weapon temporarily. A creature that failed their saving throw is possessed by your Spirit. They control the speech, actions, movement, and all other aspects of the creature whose body they possessed for the duration of this jutsu. However, you cannot make them hurt themself. At the end of each of their turns that they remain possessed and each time they are damaged while they are possessed, they can make a Charisma saving throw to end this jutsu's effects on them, sending your Spirit back to you in its incorporeal form.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3 and the damage by 2d6. If this jutsu is cast at S-Rank, Charisma Saving Throws made against this jutsu cannot gain the benefit of dice-based bonuses to them, including advantage.", created_at: NOW, updated_at: NOW },
  { _id: "c8fba1c4b3aa9c1ed900ae6b", name: "Last Rites", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Full Turn Action", range: "Self", chakra_cost: "25 Chakra", components: "CM, W (Ego Weapon)", duration: "Up to 1 minute", description: "You call the true name of your Spirit aloud, flaring up both of your energies to their highest extent and allowing you both to wreak havoc on the battlefield. For the duration of this jutsu, you gain the following benefits: - You gain resistance to Physical and Mental conditions, and you cannot be Incapacitated or be made unable to move by any means unless you are Unconscious. - You can gain the benefits of any number of Soul Invocations you possess per casting of a jutsu that uses your Ego Weapon as a component. - Your ability scores use the higher values present between you and your Spirit Companion. - You add your Ego Weapon's base damage die to Clash checks you make. - You cannot make attacks, ability checks, skill checks, or saving throws at disadvantage. At the conclusion of this jutsu your Ego weapon dissipates, your Spirit Companion is reduced to 0 hit points, and you become unable to mold chakra until you complete a Long Rest. You also gain 5 ranks of Weakened and 3 ranks of Slowed until you complete a rest of any type.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost by 3. If this jutsu is cast at S-Rank, increase its duration to 10 minutes, and twice during its duration, if you would become Unconscious or die instantly, you can instead negate the triggering damage or effect and remain alive and conscious. Additionally, if this jutsu is cast at S-Rank, once per Long Rest, neither you nor your Spirit Companion suffer the usual detriments that would normally take effect when this jutsu ends.", created_at: NOW, updated_at: NOW },
  { _id: "c27df1309a2bcf80bd265300", name: "Chakra Draining Seal", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "CM, HS, CS", duration: "1 minute", description: "You attempt to place a seal on a creature to exhaust one's chakra. Make a melee ninjutsu attack against a creature in reach. On a hit, you deal your unarmed damage + 2d4 Chakra damage. Then for the next minute, that creature takes 1d4 Chakra damage at the start of its turns. At the end of the target's turns it makes a Chakra Control check against your Ninjutsu save DC, ending the jutsu's effects on a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the chakra damage by 1d4 and 1d4 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "ed91b192969326f569807872", name: "Flash-Bang Seal", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "97a529e82067b359e2044cea", "3d4ef417aa13fb1eaec5abc1", "c6bdd886dad791b51fa36b06"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "CM. HS, CS", duration: "1 hour", description: "As part of the action to cast this jutsu you place a seal on a surface, object, or body part of your choosing within range.  After this effect has been triggered the jutsu ends. The effectiveness of the Shimura clan in combat hinges upon careful preparation, often involving the strategic placement of certain Shimura hijutsu. The Shimura clan has designed jutsus that allow the seal to be placed before its activated. These jutsu are given a new keyword, \"Placement\". A jutsu with the placement keyword must be placed using the listed casting time, and then activated by fufilling the requirements listed after*Activation:*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "edbc11c78334ee9b9449187b", name: "Updraft Seal", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "c6bdd886dad791b51fa36b06"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "CM, CS", duration: "1 hour", description: "You place a seal on the ground. The seal then conceals itself and is invisible to all creatures without chakra sight.  &emsp; *Activation:* As a bonus action on subsequent turns, you can trigger this seal's activation. When activated the seal releases a massive gust of force sending anything within range flying upward. Creatures within a 10 foot radius of the seal must make a Strength saving throw, taking 2d6 Force damage and being lifted 10 feet in the air on a failed save. Targets lifted by this jutsu remain that way until the end of the start of your next turn. After this effect has been triggered the jutsu ends. Alternatively, this jutsu can deal no damage and instead lift willing creatures up to 30 feet in the air, but you must declare this during the casting of this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8fd84358f914977a0c91b20a", name: "Shimmering Mirage Seal", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131", "3d4ef417aa13fb1eaec5abc1", "c6bdd886dad791b51fa36b06"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "CM, CS", duration: "Special", description: "*As part of casting this jutsu, you may pick up to 4 creatures who will not be effected by the jutsu.* You place a seal on a surface of your choosing. The seal then conceals itself and is invisible to all creatures without chakra sight.  As a bonus action on subsequent turns, you can trigger this seal's activation. Once activated, the seal conjures a lifelike mirage of the caster's choosing, manifesting within a 10-foot radius around the seal. This illusionary display remains for one minute before gradually dissipating. All creatures who can see the mirage must make a Wisdom saving throw against your genjutsu save DC. A creature can only be affected by the mirage if it can see it, and the effect can only occur once per casting. Critical SuccessAffected creature is able to resist this jutsu’s effect, becoming immune to further castings of this jutsu until 3 turns have passed. SuccessAffected creature is uneffected by the Genjutsu FailureAffected creatures are fully convinced that what they are seeing is real. They gain 1 rank of fear or confused (your choice, but should be reflected in the mirage) Critical FailureSame as failure, but it gains an extra rank of the applied condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1d56aeeb72556fce7575eb18", name: "Advanced Explosive Seal", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "c6bdd886dad791b51fa36b06"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "CM, HS, CS", duration: "Instant", description: "As part of the action to cast this jutsu you place a seal on a surface, object, or body part of your choosing within range. When you place this seal you choose a single nature release keyword that you can cast and it’s damage type becomes the corresponding type. If you do not have a nature release this jutsu instead deals Force damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "f3cdea631cd42be3818a22a8", name: "Drag Wire", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "c6bdd886dad791b51fa36b06"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "CM, CS", duration: "Instant", description: "As part of the action to cast this jutsu you place a seal on a surface, object, or body part of your choosing within range. The seal then conceals itself and is invisible to all creatures without chakra sight. Once placed the seal shoots an invisible line that extends 30 feet or anchors to the nearest surface parallel of it.  ___", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "07094e5a31181900d4e3a488", name: "Fūinjutsu Trap", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "c6bdd886dad791b51fa36b06"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "CM, HS, CS", duration: "Instant", description: "*A jutsu designed to be like Advanced Explosive Seal, but it sacrifices the damage to disorientate enemys over larger areas. *You place this seal on a surface within reach, and this seal expands into a 20 foot cube.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "3c93915bbc183f27af519f37", name: "Absorption Seal", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "c6bdd886dad791b51fa36b06"], elements: [], casting_time: "1 Hour", range: "Touch", chakra_cost: "14 Chakra", components: "CM, CS", duration: "24 hours", description: "As part of the action to cast this jutsu you place a seal on a surface, object, or willing creature within range. You can only have a maximum of one Absorption Seal placed at one time. Casting this jutsu again while one Absorption Seal is currently paced causes the first placed seal to vanish.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, damage reduction by 2d10, and the casting time by 2 hours.", created_at: NOW, updated_at: NOW },
  { _id: "60162184ea7f8b3c6c9f0650", name: "Self-Cursing Seal", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "13 Chakra", components: "CM, HS, CS", duration: "Instant", description: "Make a melee ninjutsu attack against a target in range. On a hit, you place a crippling seal on the target. The seal then conceals itself and is invisible to all creatures without Chakra Sight. Then, as a bonus action after the seal is placed, you can activate this seal. When activated, the seal spreads across the target's body, siezing its muscles in place. The target must succeed a Constitution saving throw, becoming paralyzed on a failed save, or no effect on a success. At the end of the target's turns it makes a Chakra Control check against your Ninjutsu save DC, ending the jutsu's effects on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1f58dd74e04c9feef5c11cb3", name: "Reverse Four Symbols Sealing", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Week", range: "Touch", chakra_cost: "*Special* (45 Chakra)", components: "CM, CS", duration: "Special", description: "During an entire week of  downtime, you  inscribe the Mother of All Seals onto your chest. Once the seal is completed, you gain the ability to activate it as an Action. By doing so, you can select a target within 10 feet of you who is either Prone or Dazed. When the seal activates, it releases a  black hole that engulfs the chosen target, imprisoning them within your body. This sealing process is irrevocable, permanently containing the target. Once this has happened, the target becomes sealed away permenantly, and you fall to 0 hit points and die. When you die this way, you cannot be revived by normal means.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3e6260af8f213855993ecfc0", name: "Kido Technique: Hado 1: Sho", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You point at your target with your index finger, as a small amount of chakra is dispelled from the tip of the index finger with enough force to thrust a considerable amount of kinetic energy at a target. Select a target creature in range. They must succeed a Strength saving throw or be knocked back by an amount equal to 5 times your ninjutsu modifier. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage as if they had fallen an equal distance.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the range by 10 feet, and the knockback by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "f6ea7ab55ef0412e4c49be0c", name: "Kido Technique: Hado 4: Byakurai", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You gather high-density spiritual energy, which you discharge as you point at a creature, and generate a concentrated bolt of chakra. Make a ranged ninjutsu attack against a creature in range, dealing 3d6 lightning damage on a hit. All creatures in between you and the target must all make a Dexterity saving throw, taking half damage on a failed saving throw.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "421a8361357da2a69c65b997", name: "Hohou Technique: Sky Step", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "Instant", description: "A highly advanced, secret form of the water walking and wall walking technique most shinobi learn, you gather the chakra beneath your feet to run on air. Until the end of your turn, you gain a flying speed equal to your walking speed. At the end of this jutsu's duration, if you have not landed, the residual chakra slows you and brings you safely to the nearest surface.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3. If you cast this jutsu at C-Rank you no longer must pay chakra to concentrate on this jutsu. If you cast this Jutsu at A-Rank its duration becomes 10 minutes, no longer requiring concentration.", created_at: NOW, updated_at: NOW },
  { _id: "62eb1e967b57944f59528db7", name: "Kido Technique: Hado 33: Sokatsui", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You aim the palm of your hand at a creature in range and generate a torrent of blue chakra at them. Make a ranged ninjutsu attack against a creature in range. On a hit, you deal 6d6 Force damage and the creature must succeed a Constitution saving throw, becoming dazed on a failed save. If the target is restrained you can forgo gaining advantage to your attack roll and instead impose disadvantage on the creature's Constitution saving throw.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "969de8493323b9fa0bd80478", name: "Kido Technique: Bakudo 39: Enkosen", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Reaction, which you take when you are", range: "Self", chakra_cost: "8 chakra", components: "HS, CM", duration: "1 Round", description: "Using either both hands or their Zanpakutō in a blocking motion, the practitioner generates a dull yellow energy, which takes the form of a large spinning disk of condensed chakra, in front of themselves, blocking an opponent's attack. When you are targeted with an attack, or forced to make a saving throw from a line or cone area of effect, you can summon this disk, giving yourself 2d10 temporary hit points and advantage on Strength and Dexterity saving throws, until the start of your next turn. If you succeed on either saving throw, you take no damage or effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Disk’s Hit Points by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "b0ebe7d8eb2cb897cc7312eb", name: "Kido Technique: Hado 58: Tenran", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30-foot Cone)", chakra_cost: "9 Chakra", components: "HS, W (Zanpakutō), CM", duration: "Instant", description: "As part of casting this jutsu you must have 1 free hand for hand seals, or your Zanpakutō. Levitating your sheathed Zanpakutō in front of them, the practitioner lightly hits one of its ends, causing it to spin like a fan. Stopping it, the practitioner fires a widening tornado-like blast. All creatures in a 30-foot cone in front of you must make a Strength save, taking 4d10 Wind damage and falling prone on a failed save, or half damage and no effects on a success. For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the length of the cone by 10 feet, and the damage by 1d10.", at_higher_ranks: "At Higher RanksFor each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the length of the cone by 10 feet, and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "53959a6ffa463898d4c4ce2d", name: "Kido Technique: Bakudo 61: Rikujokoro", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute.", description: "Pointing your index finger at a creature in range, you generate a spark of yellow chakra, which summons six thin, wide beams of seals that slam into their midsection and hold them in place. The target must make a Dexterity saving throw. On a failed save, they are unable to move any part of their body, including the parts not struck by the beams. They are restrained and incapacitated for the duration. At the end of their turn, they can remake the save to end both conditions.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1f764d43514d8cfe47ff9fca", name: "Kido Technique: Hado 73: Soren Sokatsui", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Instant", description: "An advanced form of Hado", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c58da8fbb278a69a90261e42", name: "Hakuda Technique: Shunko", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Full Turn Action", range: "Self", chakra_cost: "Special (14 Chakra)", components: "CM, M", duration: "Concentration, up to 1 minute.", description: "Your chakra explodes from your back, manifesting in a bestial form of your choice around you. Each creature within 15 feet of you must make a Dexterity saving throw, taking 5d8 force damage on a failed save, or half as much on a successful one. For the jutsu's duration, you gain the following benefits; You have advantage on concentration checks to maintain concentration of this jutsu. - Your movement Speed is doubled. - You gain resistance to force damage. - All Shinigami Hijutsu have their damage die increased by 1 step. As an action, you can forcefully end this jutsu in an explosion of energy. Choose either a cylinder, line or sphere. - CylinderChoose a point within 60 feet of you. Each creature in a cylinder 50 feet high, with a 20-foot radius must make a Dexterity saving throw. On a failed save, they take 6d10 force damage and are dazed. On a successful save, they take half as much damage and no other effects. - LineEach creature in a line 15 feet wide and 60 feet long must make a Dexterity saving throw. On a failed save, they take 10d6 force damage and are knocked prone. On a successful save, they take half as much damage and no other effects. - SphereEach creature in a 25-foot radius around you must make a Dexterity saving throw. On a failed save, they take 8d8 force damage and are knocked to the edge of the area. On a successful save, they take half as much damage and no other effects.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fc63d3923762fbb1a161850a", name: "Kido Technique: Hado 90: Kurohitsugi", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "120 feet (40-foot cube)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 30 seconds.", description: "Kurohitsugi is a high-level Kidō which seals its target in a black spiritual coffin. You generate purple and black chakra, which envelops the target with a powerful torrent of gravity before taking the form of a box of black energy, covered in several spear-like protrusions which pierce the box, lacerating the one inside from head to toe. Select a point in range to summon the coffin. All creatures inside when it appears must make a Strength saving throw and Dexterity saving throw. On a failed Strength save, the creature becomes restrained. On a failed Dexterity save, the creature takes 8d10 Necrotic damage, or half as much on a success. At the start of each creature's turn, they remake the Strength and Dexterity saving throws, continuing to be restrained on a failed Strength save and taking 8d10 necrotic damage on a failed Dexterity saving throw, or half as much on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0c927c3bc4616952a2a1c795", name: "Kido Technique: Bakudo 99: Bankin", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "26 Chakra", components: "HS, CM", duration: "Concentration, up to 1 hour.", description: "You hold your palms away from yourself, with your arms extended out to the sides, before clasping your hands together, with the fingers intertwined intricately, causing your target's arms to be bound to their back with spiritual fabric and iron shafts. Select a target creature in range. They must succeed 3 saving throws in the following order; Strength SaveOn a failed save, the creature is restrained and cannot weave hand seals. Dexterity SaveOn a failed save, the creature takes 8d8 Piercing Damage as they are nailed to the ground. On a success, creatures take half damage. Constitution SaveOn a failed save, creatures gain two ranks of Weakened and gain disadvantage on all attack rolls, as their body is out of sync.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0e89b801e545d3d8865dd7bd", name: "Live Stage: First Chord", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "97a529e82067b359e2044cea", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Reaction, which you take as part of rolling for initative, or 1 bonus action", range: "Self (30ft)", chakra_cost: "4 Chakra", components: "HS, CM, NT (Instrument)", duration: "Concentration, up to 1 Minute", description: "You begin a melodious tune, getting your allies prepared for combat as the music begins to thump in the background. When you cast this Jutsu, choose between *Ballad* or *Punk*, your choice remains the same through all Jutsu with the “Live Stage:” name. - *Ballad:* For the Duration of this Jutsu, whenever an allied creature within 30ft of you that can hear you would make an Attack Roll, Saving Throw or Skill Check, they add +2 to that roll. - *Punk:* For the duration of this Jutsu, on your turn as an action you can unleash a blast of sound. Each creature within a 30ft cone that can hear you must make a Constitution saving throw, taking 2d8 Force damage, and being Concussed and Deafened until the end of their next turn on a failed save. Creatures deafened this way are still able to hear jutsu you cast with the Auditory keyword as your chords directly strike their soul. >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d3c9ee9438e1fff7eac07af1", name: "Headbanger", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "b5e8ac06ada0310dcd377049", "29e5ab0a1fdab5fce4104456"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM, NT (Instrument)", duration: "Instant", description: "You play a melodious tune, restoring life and energy to a creature that can both hear and see you. Choose one willing creature within range, that creature gains 2d6 + your Genjutsu ability modifier as Temporary hit points. For as long as they have these temporary hit points, they gain  a +4 bonus to the next three damage rolls they make. *Melodic Vice.* As part of casting this jutsu, you may spend up to 3 Vice Points. For each Vice Point spent, increase the temporary hit points by 1 step (up a d12), and the damage bonus by +1.", at_higher_ranks: "For each rank above D-Rank, this Jutsu costs 3 more chakra, increases it’s temporary hit points by 1d8, and may target one additional creature.", created_at: NOW, updated_at: NOW },
  { _id: "645b8cebb2e1147e21bd95fa", name: "Rockerboy's Battle Cry", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "b5e8ac06ada0310dcd377049", "c204701e083cfd21465f6b94"], elements: [], casting_time: "1 Action", range: "Self (10-foot radius)", chakra_cost: "5 Chakra", components: "HS, CM, V", duration: "Instant", description: "You unleash a scream of hatred and violence against all those who have wronged you. Each creature of your choosing within 10ft of you  must make a Wisdom saving throw, on a failed save they become Dazed, Deafened and gain 1 rank of Fear. *Violent Vice.* As part of casting this jutsu, you may spend up to 1 Vice Point. If you do, creatures within 5 feet of you roll at disadvantage.", at_higher_ranks: "For each rank above D-Rank, this Jutsu costs 3 more chakra, and increases its range by 10ft.", created_at: NOW, updated_at: NOW },
  { _id: "6c25f73c7f4e2539b38bb8e1", name: "Off the Record", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "97a529e82067b359e2044cea", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, NT (Instrument)", duration: "Instant", description: "Though you spend a lot time around a bunch of people, you hate it when your personal space is violated and these haters are pushing you to your limit. Make three melee Taijutsu attacks with your Instrument. On each hit, you deal your [Weapon's Damage Die]. If you hit with at least two of these attacks, the target must make a Strength saving throw or be knocked prone. This jutsu's effects changed based on your chosen branch. - MelodyThe target makes their saving throw at disadvantage, and on a failed save, they are also knocked back 30 feet as you play a smooth tune that produces a strong shockwave. - ViolenceYour melee attacks gain a +1 bonus to critical threat range, and add half your ability modifier to your damage rolls, as opposed to none.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to B-Rank or higher, increase the damage die by +1. If cast to S-Rank, increase the damage die by +1.", created_at: NOW, updated_at: NOW },
  { _id: "53617971dbd0fa938e815206", name: "Live Stage: A Thing of Beauty", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "97a529e82067b359e2044cea", "b5e8ac06ada0310dcd377049", "aaeecd12fb6a8f889a26ab97", "29e5ab0a1fdab5fce4104456"], elements: [], casting_time: "1 Action", range: "Self (30ft)", chakra_cost: "6 Chakra", components: "HS, CM, NT (Instrument)", duration: "Concentration, up to 1 Minute", description: "As a requirement to activate this Jutsu, you must have the *Live StageFirst Chord* Jutsu active. You end your concentration on that Jutsu and this one takes its place, maintaining the same duration limitation and Jutsu casting restrictions. You keep all the effects of that Jutsu, stacking them with this Jutsu’s effects. You continue your riff, opening into a deeper, more thoughtful tune as your song continues. You gain one of the following abilities, chosen by your choice between Ballad or Punk. -        *Ballad*For the duration of this Jutsu, whenever an allied creature that can hear you would start their turn that isn’t Dying or Incapacitated within 30ft of you, that creature heals 1d4 hit points. -        *Punk*Whenever you would unleash your blast of sound, you may choose any number of creatures within the area of effect to be unaffected by it.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7d3d3cb21b3fe044551bd6de", name: "Live Stage: Chippin' In", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "97a529e82067b359e2044cea", "b5e8ac06ada0310dcd377049", "00ca3f040aa5aa24f905202a", "c204701e083cfd21465f6b94"], elements: [], casting_time: "1 Action", range: "Self (30ft)", chakra_cost: "9 Chakra", components: "HS, CM, NT (Instrument)", duration: "Concentration, up to 1 Minute", description: "As a requirement to activate this Jutsu, you must have the *Live StageFirst Chord* Jutsu active. You end your concentration on that Jutsu and this one takes its place, maintaining the same duration limitation and Jutsu casting restrictions. You keep all the effects of that Jutsu, stacking them with this Jutsu’s effects. You fill your song with anger and hatred, raging against the machine that shackles you, you gain one of the following abilities, chosen by your choice between *Ballad* or *Punk*. -        *Ballad:* Each ally currently gaining a bonus to attack and damage rolls also gains a +1 bonus to their Critical Threat range with attacks made against constructs, or creatures with temporary hit points or damage reduction. They ignore any damage resistances or reduction that objects, structures and constructs would have. - *Punk:* Your blast of sound increases to a 60ft cone, and it’s damage becomes 5d12. Additionally, the saving throw is made at disadvantage, and whenever a creature fails it, they are knocked pone. Damage dealt by this ignores damage resistance or reduction that structures, objects or constructs would have.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cab02eb4a7de9dd94ab1eee9", name: "Never Fade Away", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Reaction, when you would be targeted by an attack roll or saving throw", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM, NT (Instrument)", duration: "Instant", description: "You produce a melancholy chord, and create a shield of sound and power that surrounds you. You gain an effect depending on your chosen *Branch*, if you would quality for both, you instead choose one: - *Melody:* Your aura of music is filled with restorative and protective Chakra. You gain damage resistance against the triggering damage type equal to 2d12 + your Ninjutsu or Genjutsu ability modifier until the start of your next turn. If the effect does not deal damage, you instead gain 1d12 + your Ninjutsu or Genjutsu ability modifier temporary hit points. - *Violence:* Your Aura of Music is filled with the will to never give in. You gain a +4 to your AC until the start of your next turn, or advantage on saving throws of the same type until the start of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "857b8916985ce3efa225b67b", name: "Crown of Rock", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM, NT (Instrument), V", duration: "Concentration, up to 1 Minute", description: "You string together sound and chakra into a red, metallic crown that floats above your head, producing music that everyone can hear. This music can sound as you wish, but if you begin playing music, it will change to whatever you are playing, adding a backing track to your performance. For the duration of this Jutsu, you can cause loud booms of sound to echo out from it. At the beginning of your turn, you can cause it to create this sound. Each creature within 20ft of you must make a Strength and Constitution saving throw. On a failed Strength save, they are knocked prone, and thrown back 20ft, if they hit an object, they take 2d8 force damage for each 5ft they travel. On a failed Constitution save they take 2d12 Psychic damage, and are Dazed", at_higher_ranks: "For each rank above C-Rank, this Justu costs 3 more chakra, and increases it’s area of effect by 10ft, and it’s damage on a failed Constitution save by 2 die.", created_at: NOW, updated_at: NOW },
  { _id: "75f31cb8932128c6171ec1b4", name: "Legendary Set", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "b5e8ac06ada0310dcd377049", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "Self (45-foot radius)", chakra_cost: "Special *(77 Chakra)*", components: "HS, CM, NT (Instrument), V", duration: "Concentration, up to 10 Minutes", description: "*(Any creature may assist you in the casting of this jutsu, regardless of clan, if they have an Instrument.)* An advanced, and more energetic version of *Song of War*, you unleash a legendary riff to empower your allies. Each creature of your choice within 45 feet of you begins to feel the pounding music, giving them the energy and power to fight. At the beginning of their turns, they may select one of the following bonuses, gaining it until the start of their next turn. -        +5 bonus to checks to maintain concentration, or to clash with opposing Jutsu. -        +4 bonus to a saving throw of their choice. -        +3 bonus to weapon attack and damage rolls within a specific weapon type -        +3 bonus to Ninjutsu, Genjutsu or Taijutsu attack rolls. -        +2 to Ninjutsu, Genjutsu or Taijutsu save DC -        +1 to Critical Threat range for all attack types. Combination*If this Jutsu is cast as a Combination with two or more casters, increase its range by 20ft. Any creature who assists in casting this Jutsu as a combination Jutsu increases the range of this Jutsu by one step based on the highest Charisma Modifier within the group of casters. (+0-1No change, +2Increase the range by 40ft, +3-4Increase the range by 60ft, +5Increase the range by 100ft)*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "12c8c1222ef8a6905cbad9a6", name: "Live Stage: Legendary Performance", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "12 Chakra", components: "HS, CM, NT (Instrument), V", duration: "Concentration, up to 1 Minute", description: "As a requirement to activate this Jutsu, you must have the *Live StageFirst Chord* and either *Live StageA Thing of Beauty* or *Live StageChippin’ In* Jutsu active. You end your concentration on that Jutsu and this one takes its place, maintaining the same duration limitation and Jutsu casting restrictions. You keep all the effects of that Jutsu, stacking them with this Jutsu’s effects. You turn up the volume, crank up the intensity, and let out everything you have inside of you, enhancing your performance even further. You gain one of the following abilities, chosen by your choice between *Ballad* or *Punk*. - *Ballad:* On your turn, as a bonus action you may gift an ally within range that can hear you a *Boon of Metal* , this Boon of Metal can be expended by them at any time to grant themselves advantage on any D20 roll.&emsp;For each additional *Boon of Metal* expended on a single roll, they add another d20, and may choose which one they keep. Creatures can have any number of Boons, and lose all of them at the end of a minute, or whenever this Jutsu ends. If a creature has a *Boon of Metal* from the *Ballad* mode of this Jutsu , and you switch to *Punk*, all boons they have swap their type to the type granted by the Punk mode of this Jutsu. - *Punk:* On your turn, as a bonus action, you may gift an ally within range a *Boon of Metal*, this Boon of metal can be expended on their turn at any time to grant a Jutsu they cast an additional 2 die of damage. Creatures can have any number of Boons, and lose all of them at the end of a minute, or whenever this Jutsu ends. If a creature has a *Boon of Metal* from the *Punk* mode of this Jutsu , and you switch to *Ballad*, all boons they have swap their type to the type granted by the Punk mode of this Jutsu.", at_higher_ranks: "For each rank above B-Rank, this Jutsu costs 3 more chakra. At S-Rank, you instead grant your allies 1d4 *Boons of Metal*.", created_at: NOW, updated_at: NOW },
  { _id: "857aa1b6574dbd15151f57a7", name: "Metal Soul of Rage and Fear", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Full Turn Action", range: "Self", chakra_cost: "Special *(20 Chakra)*", components: "HS, CM, CS, NT (Instrument), V", duration: "Concentration, up to 1 minute", description: "You unleash the rage, pain and sorrow that lies deep within your metal heart. Creating a creature that is formed from the pure, metallic style. This creature can take whatever form you wish – most Silverhand members of the Violence branch create this image as a giant Samurai, most from the Melody create a giant dragon. You summon forth a *Metal Soul*, the Metal Soul has the following in game statistics, and uses your Ninjutsu or Genjutsu ability modifier for its attack roll and Save DC; You may command the Metal Soul on your turn as a Bonus action or Reaction to take its Action and move. The Metal Soul may take a bonus action as part of taking its Action once per round. Your Metal Soul may take a Reaction without any input from you. If you cast this jutsu while concentrating on at least 2 Silverhand Hijutsu with the Auditory keyword, this jutsu does not count against your concentration limit, and its chakra cost is halved. ___ ___ >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7d80b566b704d185623491a3", name: "Sōzō Art: Dragonfly Cutter", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "An alternate version of the chakra scalpel technique designed to inflict molecular-level damage through intense vibrations. For the duration, your unarmed attacks deal 2d4 + your ninjutsu modifier in necrotic damage and gain the Deadly property. You can use your Ninjutsu ability modifier for the attack and damage rolls for these attacks. This jutsu can also be applied to infuse chakra into a weapon or blade, causing the weapon to deal an extra 1d8 necrotic damage, once per turn. Jutsu you cast that use your unarmed attack or weapon attack while this jutsu is active gain the Medical keyword.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the damage by 2d4 and 1d8. If this jutsu is cast at S-Rank, increase the damage by 2d4 and 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "f99e417b6823e117409904c3", name: "Casualty Palm Technique", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "Originally created for non-invasive procedures, it enables the caster's hands to pass through solid objects and was later adapted for combat. You perform one of the following effects: - HarmMake a melee Taijutsu or Ninjutsu attack against a target within range. This attack ignores any cover the target may have and treats the target's AC as 1 lower. On a hit, you deal your unarmed damage + 2d10 necrotic damage. If the target is a creature, it must then succeed on a Constitution saving throw or begin bleeding. - AidYou can use this jutsu to stabilize a creature. As part of casting this jutsu, you automatically stabilize a creature, removing any failed death saves.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d10. For every two ranks you cast this jutsu above D-Rank, treat the target's AC as 1 lower.", created_at: NOW, updated_at: NOW },
  { _id: "42e7b2601e0d91e0c4e4928a", name: "X-Ray Technique", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "4 Chakra", components: "CM, M", duration: "Round", description: "As part of the requirements of this jutsu, you must have the *Naibugan* clan feature active. By focusing the Interior Vision granted by your Naibugan, you create an x-ray scan of a creature within range, revealing its vital weak points. Until the end of your turn, the next jutsu you cast or attack you make against the target increases its critical threat range by +1. If the jutsu has the Medical keyword or the attack deals necrotic damage, the critical threat range increases by an additional +1. When you cast *Casualty Palm Technique* after this jutsu, its damage cannot be reduced. Alternatively, if used to stabilize a creature, that creature regains hit points equal to the jutsu's damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f9eaf7bf3f4889223a899cc6", name: "Cellular Alteration", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Concentration, up to 1 Minute", description: "As part of the requirements of this jutsu, you must have the *Naibugan* clan feature active. You combine your Interior Vision and Restorative Power to alter the cellular composition of a creature. Choose a creature within range that you can see. The target must succeed on a Constitution saving throw. On a failed save, you can select one resistance or immunity that the creature has. The creature then loses the chosen resistance or has the selected immunity reduced to a resistance for the duration of this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d0a103b2a9e71ef58e570c75", name: "Occipital Restoration", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "M, CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must have the *Naibugan* clan feature active. You mold medical chakra, injecting it directly into the occipital lobe -- the part of the brain responsible for sight. You perform one of the following effects: - CleanseYou target a creature, restoring its eyesight and enhancing it. The creature removes the blinded condition and can see up to 500 away with no difficulty for 1 minute. - BlindMake a melee Taijutsu or Ninjutsu attack against a creature within range. On a hit, you deal your unarmed damage, and the creature must succeed on a Constitution saving throw or be blinded for 1 minute. The creature can repeat the saving throw at the end of each of its turns, ending the blindness on a success. On a critical hit, the creature makes the saving throw at disadvantage. If it fails the saving throw, it also falls prone and is incapacitated while blinded, suffering from violent seizures.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If this jutsu is casted at A-Rank, creatures you target with Cleanse gain immunity to the blinded condition for 1 minute.", created_at: NOW, updated_at: NOW },
  { _id: "7fbca8b56847f4cfb056f12e", name: "Medical Haze: Vol. 1.", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 feet (20-foot Cloud)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 minute", description: "An advanced version of *Poison Mist Technique*, the user is capable of creating various toxins and their counterparts. You perform one of the following effects: -        AntidoteYou mold your medical chakra in order to form various compounds with the active capability of nullifying poisons. Creatures that inhale this mist end any condition imposed by a poison, disease, or jutsu with the Medical keyword. -        PoisonThe user releases a darkened indigo colored vapor into the atmosphere, when a creature enters the area for the first time on a turn or starts its turn there, the creature must make a Constitution saving throw, taking 3d12 poison damage and gaining one rank of envenomed on a failed save, or half as much damage and no further effect on a successful one. Creatures are affected even if they hold their breath or don’t need to breathe.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b4df95997f7337795d49b7f6", name: "Spontaneous Recovery Fever", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "b7c3bde363176d05f69f793a", "aaeecd12fb6a8f889a26ab97", "52254addcf8df274fe8214cc", "79eaf0305561cf512f55ad70", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "8 Chakra", components: "CM", duration: "Concentration, up to 1 minute.", description: "As part of the requirements of this jutsu, you must have the *Naibugan* clan feature active. This Genjutsu ensnares the target in a potent illusion with a unique effectspontaneous self-repair. Under its influence, the target's body enters a temporary state of constant healing, using its own chakra to repair damage even when none is present. A target creature you can see within range must succeed on a Constitution saving throw. On a failed save, it regains 2d4 hit points but reduces its current chakra points by an equal amount. While you maintain concentration, at the start of each of the creature's subsequent turns, it regains additional hit points equal to 2d4, plus an extra 1d4 for each turn beyond the initial turn, and reduces its current chakra points by an equal amount.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, increase the jutsu's die size by one step (d4<d6<d8<d10). <div class='artist' style='bottom:110px;left:5px;'>", created_at: NOW, updated_at: NOW },
  { _id: "300ed3b567b42355e9cf5efa", name: "Medical Haze: Vol. 2.", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 feet (30-foot cloud)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "1 minute", description: "The advanced version of the *Medical Haze* jutsu, capable of creating chemicals compounds that affects various systems. You perform one of the following effects: -        AnesthesiaYou release a transparent vapor into the air that slowly induces a sleep-like state. A creature that enters the area for the first time on a turn or starts its turn there must make a constitution saving throw. On a failed save, the creature gains 3 ranks of slowed. On a second failed save, the creature gains equal ranks of weakened. On a third failed save, the creature falls unconscious for the remaining duration of the jutsu. When the creature awakens, it has no memory of any events within the last 10 minutes. -        NumbingYou release a transparent vapor into the air, creatures coming into contact with this haze have all physical sensations numbed. While inside the area of the jutsu, all instance of damage forms except Psychic and Chakra damage is reduced by half.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a909b736f8007833b4f3453d", name: "Sōzō Art: Hasshōdō", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You channel a spiral of medical chakra into a volatile sphere. When this sphere strikes a target, it disrupts the immune system through amnesia, causing the creature's body to \"forget\" how to heal. Make a melee Ninjutsu attack against a creature within range. On a hit, you deal 8d8 necrotic damage, and the target must make a Constitution saving throw. On a failed save, the target's maximum hit points are reduced by an amount equal to the damage taken. Additionally, for 1 minute, the target becomes vulnerable to the envenomed condition. Damage from this jutsu cannot be healed until the creature completes a rest.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, increasing its damage by 2d8. If this jutsu is casted at S-Rank it gains a range of 60 feet.", created_at: NOW, updated_at: NOW },
  { _id: "4b4b0f63df95c616402990a1", name: "Sōzō Art: God Sculpting Technique", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "33ab3a61f3027398cd08f131", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Minute", range: "120 feet", chakra_cost: "20 Chakra", components: "CM", duration: "Instant", description: "As part of the requirements of this jutsu, you must have the *Naibugan* clan feature active. This technique allows you to focus the full power of your Naibugan on specific cells within the body, enabling you to recall cellular memory and force them to replicate. This process allows you to sculpt and form new body parts for a creature that has suffered severe damage. This technique can even revitalize those who have recently died or are on the brink of death, reconstructing, repairing, and reattaching organs and limbs. Select one creature within range. The target creature recovers one limb or organ that has been damaged or missing. If the target of this jutsu is a creature that has been dead no longer than 1 hour, the creature is restored to life with half its hit points. This jutsu closes all wounds, neutralizes any poison, cures all diseases, and lifts any jutsu affecting the creature when it died. The jutsu replaces damaged or missing organs and limbs. If the creature was undead, it is restored to its non-undead form. Coming back from the dead is an ordeal. The target takes a −4 penalty to all attack rolls, saving throws, and ability checks. Every time the target finishes a long rest, the penalty is reduced by 1 until it disappears. After using this jutsu, you gain four ranks of exhaustion that cannot be removed, and you are unable to cast this jutsu again until you complete a full rest. When you complete a full rest, you remove the ranks of exhaustion and regain the ability to cast this jutsu. Each subsequent casting of this jutsu beyond the first increases its chakra cost by 10. <div class='artist' style='top:110px;right:400px;'>", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c3e466be33de5dd9e542faa8", name: "Beast Tongue", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "3 Chakra", components: "CM, HS", duration: "10 minutes", description: "You gain the ability to comprehend and verbally communicate with beasts for the duration. You have advantage on all Charisma checks you make to influence beasts for the duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5841b8d77abc647a763084e8", name: "Bestial Art: Predator Sense", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1  Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, HS", duration: "Concentration, up to 10 minutes", description: "*As a part of casting this jutsu, you must be gaining the benefits of your* *Bestial Transformation* *feature*. Your chakra-enhanced instincts sharpen acutely as you pool chakra into your bestial snout. You know the general location of all creatures with chakra in a 1-mile radius of you. For the duration while tracking individuals or groups of creatures with chakra, you also learn their exact number, sizes, a general threat level (DM discretion), and how long ago they passed through an area. When you deal damage to a creature with an unarmed attack or taijutsu, that creature becomes Marked for the duration of this jutsu. You always know the general direction of a Marked creature if it is within 1 mile of you. You can sense the exact location of a Marked creature within 100 feet of you, and it cannot benefit from being hidden from you. Alternatively, as a bonus action for the duration you can touch an item, such as a scrap of clothing, a weapon, or trace amounts of blood, and learn the general direction of the creature the item  belonged to up to a 1 mile away from you", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3 and the sensing distances increase by 1 mile and 50 feet respectively.", created_at: NOW, updated_at: NOW },
  { _id: "14fe06f84e45a9084b36c9b7", name: "Cornered Savagery", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when a hostile creature ends its turn within 10 feet of you", range: "Self (10-foot radius)", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "Adrenaline surges within as you lash out in a frenzied whirlwind. All creatures of your choice within a 10-foot radius from you must make a Dexterity saving throw. On a failure, a creature takes 3d6 bludgeoning or slashing damage (your choice) and gains either 1 rank of Bruised (if bludgeoning damage) or Bleeding (slashing damage). *If this jutsu is cast while gaining the benefits of your* *Bestial Transformation* *feature, the damage die becomes a d10 and creatures that fail the save by 5 or more also gain 1 rank of fear against you.*", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "91fb74abc824514fe017b1c2", name: "Primal Rush", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "*As a part of casting this jutsu, you must be gaining the benefits of the Primal Fist Stance.* You let your primal instincts take over, rushing forward to a target in range as you attempt to maul them. You move up to your full walking speed to a creature you can sense in range. This does not provoke opportunity attacks. Then make one melee taijutsu attack against the target. On a hit, you deal your unarmed damage + 2d6, and the creature must make a strength saving throw be knocked prone. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3 and the additional damage by 1d6. When you cast this jutsu at B-Rank or above, you instead make two melee taijutsu attacks.", created_at: NOW, updated_at: NOW },
  { _id: "c2491ec7c7aef3a4eab860ad", name: "Barborous Kicks", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "*As a part of casting this jutsu, you must be gaining the benefits of the Primal Fist Stance.* Your claws tear into the ground as you leap to strike with three deadly kicks. Make three melee taijutsu attacks against a target in range. On a hit, you deal your unarmed damage + 1d4. Then you may force the target to make a Strength saving throw, being knocked back 5 feet for each  hit on a failure. If two or more attacks hit, the target gains one rank of bruised. *If this jutsu is cast while gaining the benefits of your* *Bestial Transformation* *feature, if three or more attacks hit, the target is also knocked prone*.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the bonus damage die increases by one step. When you cast this jutsu at A-Rank or above, you make one additional melee taijutsu attack.", created_at: NOW, updated_at: NOW },
  { _id: "ca15a0fcf8ef38ebd8d04f99", name: "Bestial Art: Static Hide", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "CM, HS", duration: "Concentration, up to 1 minute", description: "*As a part of casting and maintaining this jutsu, you must be gaining the benefits of your* *Bestial Transformation* *feature*. You cannot lose concentration on this jutsu as a result of taking damage. You saturate your bestial hide with chakra, causing the fur to stand up on its end. For the duration, you have resistance to both the bruised and bleeding conditions, and you reduce all incoming damage except psychic by 5. Additionally, twice per turn, when you would deal your unarmed damage, you may deal an additional 1d4 force damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3 and increase both the damage reduction die and the additional damage die by 1 step. When you cast this jutsu at S-Rank, you are immune to the bruised and bleeding conditions for the duration.", created_at: NOW, updated_at: NOW },
  { _id: "fd50e9ad93432bc2a092c549", name: "Omega Howl", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "7 Chakra", components: "CM", duration: "Instant", description: "Gathering chakra in your lungs, you release a concussive howl to stagger your foes. When you cast this jutsu, you may use either your Ninjutsu or Taijutsu for its  &emsp;&emsp;casting ability. All creatures in a 30-foot cone must make &emsp;&emsp;a Constitution saving throw. On a failed save, a creature &emsp;&emsp;takes 5d8 force damage and is knocked back 10 feet, or &emsp;&emsp;half as much damage and is not knocked back on a A creatures that fails this save that can hear you also &emsp;&emsp;&emsp;&emsp;&emsp;&emsp; &emsp; &emsp; becomes deafened for 1 minute, &emsp;&emsp;&emsp;&emsp;&emsp;&emsp; &emsp; &emsp; repeating the save at the end of each of &emsp;&emsp;&emsp;&emsp;&emsp; its turns to end the effect on itself. When you cast &emsp;&emsp;&emsp; the jutsu, your howl is audible from as far away as &emsp;&emsp;300 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "144a573c314db7cfe47b1d13", name: "Savage Slash", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "13 Chakra", components: "CM, M", duration: "Instant", description: "*As a part of casting this jutsu, you must be gaining the benefits of the Primal Fist Stance.* You channel chakra through one of your limbs, forming terrific claws of visible chakra coating your hand. Make a melee Taijutsu attack against a target in range. On a hit, you deal your unarmed damage + 8d8 slashing damage. The creature must then make a Constitution, saving throw gaining 2 ranks of bleeding on a failed save, or only 1 rank of the bleeding on a success. This attack ignores resistance to slashing damage and the bleeding condition. If this jutsu is used as a *Finisher*, you deal your unarmed damage + 8d10 slashing damage. The creature must then make a Constitution, saving throw gaining 2 ranks of bleeding on a failed save, or only 1 rank of the bleeding on a success. A creature suffers the Weakened condition for as long as it has these ranks of bleeding.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3, the damage by 2d8 and 2d12 respectively. When you cast this jutsu at S-Rank, instead of the bleeding condition, you inflict lacerated instead.", created_at: NOW, updated_at: NOW },
  { _id: "12659cb675bb8cea0dcadf28", name: "Bestial Art: Beast-Blood Regeneration", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "*Special*", components: "CM", duration: "Instant", description: "*As a part of casting this jutsu, you must be gaining the benefits of your* *Bestial Transformation* *feature*. You channel a spike chakra through your heightened bloodflow granted by your bestial form, allowing you to recover wounds. As part of casting this jutsu, you may spend any number of hit dice, regaining the result in hit points. For every five hit dice spent this way, increase your walking speed and jump distance by 30 feet, gain a +2 bonus to AC, and add +5 to the next attack roll, saving throw, or ability check you make until the end of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d4b3d60a2b2d14214a765c1d", name: "Bestial Art: Massacre", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "*Special*", chakra_cost: "20 Chakra", components: "M", duration: "Instant", description: "*As a part of casting this jutsu, you must be gaining the benefits of your* *Bestial Transformation* *feature*. For a moment, you unshackle the true beast inside, reimagining what ferocity truly looks like. You unleash an unfettered howl that chills the spine of all that hear it. All creatures of your choice in a 150-foot radius of you must make a Wisdom saving throw, gaining two ranks of fear against you for the next minute on a failed save, or 1 rank of fear on a success which lasts until the end of its next turn. Then at the conclusion of this jutsu, you may choose to gain 10 temporary hit points for each creature reduced to 0 hit points by this jutsu, which last until your next rest or until you cast this jutsu again. While you have these temporary hit points, you are considered *Frenzied*. While Frenzied, you suffer the Berserk condition, and all unarmed attacks and taijutsu you cast gain the Deadly and Lethal weapon properties.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "21746dd6ce90f54da50ce17d", name: "Light Release: Blinding Strikes", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a chakra construct of light of your own description (a giant fist, a sword, an arrow, etc.), striking your foes with it. Make a ranged ninjutsu attack against a creature you can see within range. On a hit, you deal 3d10 + your ninjutsu modifier in force damage. A creature hit with an attack must make a wisdom saving throw, becoming dazzled on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, starting at B-rank, you can make two attacks, which can be directed to the same or different creatures. Starting at S-rank, you make 3 attacks.", created_at: NOW, updated_at: NOW },
  { _id: "7272e3964573441da872aa39", name: "Light Release: Star Burst", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Special", description: "You emit a radiant light that illuminates everything nearby. This light extends 15 feet around you as bright light and an additional 15 feet as dim light. Choose between instant and lasting effects: InstantThis jutsu lasts until the end of the current turn. All creatures within the bright light must make a Wisdom saving throw. Those that fail end concentration on one jutsu they are concentrating on and become blinded until the end of their next turn. LastingThis jutsu lasts for 10 minutes. Jutsu that create darkness of the same rank or lower cannot produce darkness within this light.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3, the dim light by 5 feet and the bright light by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "c742ab01cadbdc32eeb12adc", name: "Light Release: Light's Undoing", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (15ft Radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You expell your radiant chakra in an aura, undoing the binds around others. Choose a number of creatures within 15 feet of you. They regain a number of hit points equal to 2d6 + your ninjutsu modifier. Additionally, if they are prone, grappled, or restrained, the condition ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of hit points each target regains by 2d6. If cast at B-Rank or higher, you can instead cast this jutsu as a Reaction, when a creature within 15 feet of you would be restrained, grappled or fall prone. If cast at S-Rank, you can also end the stunned, paralyzed, or incapacitated condition on affected creatures.", created_at: NOW, updated_at: NOW },
  { _id: "97d03c29acb5c00e7191b5c1", name: "Light Release: Searing Light", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "5 Chakra", components: "W (Any), CM", duration: "Concentration, up to 1 minute", description: "(You cannot lose concentration on this jutsu as a result of damage.) You mold your chakra onto a creature you touch, coating it in burning light, turning it into a radiant beacon. Once per turn, weapon attacks made by the creature deal an additional 1d8 force damage. A creature damaged this way must succeed a Constitution saving throw, gaining one rank of burned on a failed save. For the duration, the creature emits bright light to a 10-foot radius and dim light for an additional 10 feet. A creature can set this light on or off as a bonus action.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "9e63254e34ba7010fa8aaa19", name: "Light Release: Radiant Shield", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "Reaction, when taking damage", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "1 Round", description: "Before taking damage, you form a shield of pure white chakra to float in front of you. You increase your AC by +4 until the start of your next turn. In addition, this shield disperses attacks that hit it head-on. It has advantage on clash checks against jutsu with an area of line or cone. If this jutsu as a reaction to a line or cone, it starts a clash, regardless of keywords.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "52e58724c638fa32c55bd9e3", name: "Light Release: Rekindle Soul", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "Reaction to a creature within range taking damage", range: "30 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "When a creature within range would be damaged, you may use your reaction cover them in a splendid light which closes their wounds. The target creature regains hitpoints equal to 3d8 + your Ninjutsu Ability modifier, and until the start of your next turn, they heal 1d8 + your Ninjutsu Ability modifier whenever they would take damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3 and the initial healing by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "5a2237fc020e6aee9a81e21a", name: "Light Release: Swords of Light", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You use your chakra to create four chakra constructs of light of your own description (traditionally they are swords, but they can be anything from swords, to fish, to even giant confections) that hover in your space. When all of the constructs are expended, this jutsu ends. While you have at least one of these constucts around you, you can use any of the following effects, using the proper actions. 1 ActionYou make a melee ninjutsu attack, swinging one of the constructs at a creature within 5 feet of you, dealing 5d6 + your ninjutsu modifier force damage. If you have at least two of these weapons active, you can use your bonus action to make another of these melee ninjutsu attacks. If you score a critical hit with any of these attacks, you add an additional die to the critical hit damage. 1 ActionYou make a ranged ninjutsu attack against a target you can see within 90 feet of you, dealing 4d8 + your ninjutsu modifier force damage. Regardless of a hit or miss, each creature within 10 feet of the target must make a Dexterity saving throw, taking 4d6 force damage and being dazed on a failed save. This expends one of the constructs. 1 Bonus ActionYou put your construct in a defensive stance. You gain a bonus to AC equal to half the amount of Construct you have. If you would take a critical hit, you lose 2 constructs and threat it as a normal hit. Full Turn ActionYou expend all of your constructs, compressing them into a small bead of power, which you then unleash in a giant beam. Each creature in a 90-foot cone &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp; originating from you must make a &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp; &emsp; Constitution saving throw, taking 4d8 + &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;a number of additional d8s equal to &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp; the number of constructs &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;remaining. A creature who fails &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp; this saving throw also becomes &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp; blinded.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "26507dcc5d799bffebc342f4", name: "Light Release: Armor of Light", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "self (30 feet radius)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "(You cannot lose concentration on this jutsu as a result of damage.) You form your chakra into a suit of armor that radiates light. For the duration, you gain the following: - DR against non-psychic damage equal to your ninjutsu modifier. - Resistance to force and necrotic damage - You radiate bright light out to 30 feet, and dim light for an additional 30 feet. In addition, allied creatures, other than yourself, within 30ft of you gain the following: - Resistance to force and necrotic damage - Regain 2d8 hit points at the start of each of their turns.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c86e7033d43ab46b991f7be3", name: "Light Release: Wall of Radiance", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "12 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "Using a chakra seal as its base, you conjure a wall of brilliant light at a point you can see within range. The wall appears in any orientation you choosehorizontally, vertically, or diagonally. It can be free floating, or it can rest on a solid surface. The wall can be up to 60 feet long, 10 feet high, and 5 feet thick. The wall blocks line of sight, but creatures and objects can pass through it. It emits bright lightout to 120 feet and dim light for an additional 120 feet. You do not need to spend chakra to maintain concentration on this jutsu. When the wall appears, each creature in its area must make a Constitution saving throw. On a failed save, a creature takes 5d10 force damage and gains 1 rank of the burned condition. A creature that ends its turns in the wall's area takes 5d10 force damage. Until the jutsu ends, you can use an action to fire a beam of light from the wall at one creature you can see within 60 feet of it. Make a ranged ninjutsu attack. On a hit, the target takes 5d10 force damage and gains a rank of burned. Whether you hit or miss, reduce the length of the wall by 10 feet. If the wall's length drops to 0 feet, the jutsu ends.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the initial damage by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "8ef0382a83d562a3398b3947", name: "Light Release: Aura of Radiance", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30 feet)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Brilliant light washes out from you and coalesces in a soft radiance in a 30-foot radius around you. Creatures of your choice in that radius when you cast this jutsu shed dim light in a 5-foot radius and have advantage on all saving throws, and other creatures have disadvantage on all attacks against them until the jutsu ends. Additionally, once per turn, when an affected creature is hits by an attack, the light flares and the attacker must make a Wisdom saving throw, taking 6d6 force damage and being blinded on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "57aa9652d11bb098b5dc0e4f", name: "Fan the Flames", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "Fueled by your blazing chakra and hot headedness you turn fear and doubt into unbridled passion. When you cast this jutsu, choose one type of *Mental* condition you are inflicted with as a result of a jutsu of equal rank or lower, removing all ranks of the selected condition. The next Vermillion Hijutsu you cast deals an additional 1d6 damage for each rank of a condition removed. You can spend *Flame Die* as part of the casting of this jutsu choosing an additional condition for each die spent.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3, and the rank of condition you can remove by 1.", created_at: NOW, updated_at: NOW },
  { _id: "45747486afb502642a3d2440", name: "Flame Vent", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Bonus Action", range: "Self (15 feet)", chakra_cost: "3 Chakra", components: "CM, M", duration: "Instant", description: "You vent some of the excess heat you produce in an attempt to try and damage those surrounding you. All creatures of your choice within range must attempt a Dexterity saving throw, taking 2d6 + your Taijutsu modifier and gaining 1 rank of burned on a failed save or half as much damage and no other effects on a success. You can spend 1 *Flame Die* to change the range of this jutsu to a 15-foot cone, or a 30-foot long 5-foot-wide line.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3, the range by 5 feet, and the damage by 2d6+2.", created_at: NOW, updated_at: NOW },
  { _id: "5abee01209a27585a65157d4", name: "Blaze Blitz", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "You unleash a salvo of flaming blows on an opponent. Make a melee Taijutsu attack against a creature within range. On a hit you deal your unarmed damage + 2d6 Fire damage. You can spend 2 *Flame Die* to make an additional attack, up to 4 times. Additional attacks do not add your modifier to damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3, and the damage by 1d6+1", created_at: NOW, updated_at: NOW },
  { _id: "e1833f5f83ee61ff199315d3", name: "Kindle the Mind", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "You funnel your blazing chakra into your brain, increasing your concentration and awareness as your eyes become ablaze. For the duration of this jutsu you gain a +2 to your AC, you cannot lose concentration on jutsu with the Fire Release keyword as a result of taking damage, and all Vermillion clan Hijutsu you cast reduce their cost by 1. (min 1) When you cast this jutsu you can spend 2 *Flame Die* to immediately cast *Smolder the Body* as a Bonus Action if it is on your Known Jutsu List.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "307760d2fdb32545188a274d", name: "Cinder Lord Strike", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant", description: "You store a massive amount of chakra into your fist igniting it in vermillion flames, before slamming it into your opponent. Make a melee Taijutsu attack, dealing your unarmed damage + 3d8. On a successful hit you funnel your chakra into your opponent’s body causing flames to spew forth from within. All creatures within a 60 foot long 5 feet wide line must make a Dexterity saving throw taking 5d4+5 fire damage on a failed save, or half as much on a success. You can spend up to 4 Flame Die to increase the size of the line by 10 feet in length and 5 feet in width per Flame Die spent.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3, and the damage by 2d8+2 and 1d4+1.", created_at: NOW, updated_at: NOW },
  { _id: "9baf569a168246fd8c5a6e90", name: "Combustion Combo", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "7 Chakra", components: "CM, M", duration: "Instant", description: "You ignite your fist and consume yourself in flame, teleporting to your targets. Make two melee Taijutsu attacks on creatures of your choice within range dealing your Unarmed Damage + 2d8 and the target must make a Constitution saving throw, gaining 1 rank of burned on a failure, you then end this action in an adjacent space to the final target of the jutsu. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time. You can spend 3 Flame Die to instead target a 30-foot cone, instead making a melee Taijutsu attack on each creature of your choice in the cone, and choosing to appear in any unoccupied space in the cone at the conclusion of the jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3, and the damage by 1d8+1", created_at: NOW, updated_at: NOW },
  { _id: "0ae625a5272c6f5091e0da3d", name: "Smolder the Body", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "8 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "You send blazing chakra evenly throughout your chakra pathways, increasing the strength of your muscle and bone as your body becomes hot to the touch, letting off cinders. For the duration of this jutsu you gain a +30-foot bonus to your movement speed, and when you cast a Vermillion clan Hijutsu you deal an additional 2d8+2 damage up to twice per casting. If you cast this jutsu while gaining the benefits of Kindle the Mind, you no longer need to maintain concentration on that jutsu instead gaining all the benefits for the duration of this jutsu, and increase the chakra cost reduction by 1. When you cast this jutsu as a Bonus Action you can spend 2 Flame Die to immediately cast Ignite the Soul as a Reaction if it is on your Known Jutsu List.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8f012d6d4d19cf23eca6aff1", name: "Pyro's Finish", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You grab a target in range by their face, igniting their body in flame and slamming them into the ground. Make a melee Taijutsu attack against a creature in range, dealing your Unarmed Damage + 5d8, inflicting 1 rank of burn and knocking them prone on a hit. If this jutsu is used as a *Finisher* after slamming the  target into the ground, a pillar of  </brflame>flame rises from the crater. All  creatures in a 15-foot wide, </br60-foot-tall>60-foot-tall cylinder other than </bryourself>yourself must make a Dexterity saving throw, taking 4d6 Fire </brdamage>damage on a failure or half as </brmuch>much on a success. The initial </brtarget>target has disadvantage on this saving  throw. You can spend 2 Flame Die when you </brcast>cast this jutsu as a finisher to instead </brcause>cause the secondary effect to target all creatures in a </br30-foot>30-foot radius other than yourself.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3, and the damage by 2d8+2 and 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "75be4f35f143ea7528e8c7cc", name: "Ignite the Soul", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "12 Chakra", components: "CM, M", duration: "Concentration, up to 1 minute", description: "You ignite your soul, causing your chakra </brto>to become visible outside of your body consuming you </brin>in a raging inferno. For the duration of this jutsu, you </brignore>ignore resistance to Fire and treat Immunity as Resistance. Also due to the intensity of the flames, whenever you would inflict a rank of burned you inflict an additional rank. If you cast this jutsu while gaining the benefits of Kindle the Mind and Smolder the Body, you no longer need to maintain concentration on those jutsu instead gaining all the benefits for the duration of this jutsu, and increase the chakra cost reduction by 1. When you cast this jutsu as a Reaction, you can spend 2 Flame Die to immediately cast Cremate the Self as a free action if it is on your Known Jutsu List.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7866a116ea94f9373575d465", name: "Cremate the Self", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "18 Chakra", components: "CM, M", duration: "1 minute", description: "You invoke the forbidden jutsu of the Vermillion clan, becoming the inferno itself. You can only cast this jutsu if you are currently benefiting from the Kindle the Mind, Smolder the Body, and Ignite the Soul Hijutsu. Those jutsu immediately end and you gain the following benefits for the duration of this jutsu: - You gain a +5 bonus to your AC - You cannot lose concentration on jutsu with the Fire Release keyword, and can concentrate on an additional jutsu so long as all jutsu you are concentrating on have the Fire Release keyword. - When you deal damage with a Vermillion clan Hijutsu, you deal an additional 4d10+4 damage. - You ignore resistance and immunity to Fire damage. - When you would inflict the Burn condition, you inflict an additional 2 ranks. - Vermillion clan Hijutsu reduce their cost by 5, to a minimum of 1. - You gain resistance to all damage except cold. When this jutsu ends you die, leaving nothing behind and being unable to be revived as the flames scatter into the wind. At the end of every turn, you can choose to spend 1 Flame Die to extend the duration of this jutsu by 1 round, to a maximum of 10 minutes. You cannot gain the benefits of Kindle the Mind, Smolder the Body, or Ignite the Soul while under the effects of this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5db37d7767a0f43b99a11990", name: "Chakra Recharge", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c"], elements: [], casting_time: "1 Full Turn Action", range: "Self", chakra_cost: "*Special*", components: "HS, CM", duration: "Instant", description: "You take in a deep breath and pull chakra from the environment, generating an aura of chakra around you of your chakra color. You may spend a number of Chakra Die up to half your level. For each chakra die spent, roll 2 Adaptability Die (this does not spend any). You gain the result of all die rolled + 1 for each Adaptability Die rolled, as chakra. If regaining chakra this way goes beyond your maximum, the difference becomes temporary chakra.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8a1664f9364df28ecd30c01e", name: "Meteor Smackdown", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "You launch a flurry of punches and kicks at an opponent within range. Make 3 melee taijutsu attacks. On each hit, you deal your unarmed damage + 1d4, but you do not add your ability modifier to the damage rolls. If you hit with at least 2 of your attacks the target must succeed a Constitution saving throw or become unable to take reactions until the end of the turn. If you hit with all 3 attacks, this  save is made at disadvantage. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage die by 1 step (d4<d6<d8<d10<d12), and ignore 2 DR that the target may have on each hit. If cast to  B-Rank or higher, this jutsu deals an additional die of damage on each hit.", created_at: NOW, updated_at: NOW },
  { _id: "0a095db8f3d2a3396020259d", name: "Primal Chakra Wave", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You take a charging stance, cupping both your hands together and bringing them behind you at your side. Chakra collects between your palms, generating a powerful sphere in between them. While concentrating on this jutsu, both your hands are occupied and cannot form hand signs. You do not need to expend chakra to maintain concentration of this jutsu, and can stop concentrating on it at any point. Starting from your next turn, you may use your action to fire a 30-foot long, 5-foot wide beam of chakra at a target. Make a ranged ninjutsu attack against a target within range, dealing 5d6 force damage on hit. All creatures whose space your line passes through become a target of this jutsu, comparing their AC vs your attack result. If you score a critical hit with this jutsu, only your original target suffers the effects of the critical hit. ChargeAt the start of consecutive turns after casting this jutsu, you can choose to delay attacking with this jutsu, instead spending your action to continue charging the attack. For each turn you spend charging this jutsu, it deals an additional die of damage, and increases the damage dealt by 1 step. You can charge this jutsu a number of times equal to half your proficiency bonus before this jutsu ends early.", at_higher_ranks: "For each rank above D-Rank, increase the cost of this jutsu by 3, the damage by 2d6, and the length by 10 feet. If upcast to at least C-Rank, you can attack with this jutsu the turn you cast it. If upcast to B-Rank, increase the width of the line by 5 feet. If upcast to  S-Rank, increase the width of the line by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "cf667d40c8946089132c2952", name: "Solar Flare", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self (15-foot radius)", chakra_cost: "3 Chakra", components: "HS, CM", duration: "Instant", description: "You quickly put your hands to generating an incredibly bright light. Each creature within range in all directions that throw or become Blinded and Dazzled until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of the jutsu by 3. For each rank upcast, choose between one of the following options; Increase the radius by 15ft, or impose a -1 penalty on creatures who make the Wisdom saving throw.", created_at: NOW, updated_at: NOW },
  { _id: "7c8ada25036b83cf5ac6552d", name: "Primal Chakra Disc", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (60 feet)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "An iconic technique of the Low-Class Wukong, rumored to have been developed to counter a mythical power of the Elite Wukong.  You channel chakra into your hand and raise it high, forming a large razor-sharp disc of energy. Make a ranged Ninjutsu attack against a creature within range. On hit, you deal 7d6 Slashing damage, which ignores temporary hit points. The target must also make a Constitution saving throw, gaining 2 ranks of bleeding on a failed save as the jutsu goes straight through them. Additionally, if you aim this jutsu at an extraneous appendage the target may have, such as a horn, tail, or tentacles, and deal at least 25 damage with this jutsu, the creature must make a Strength saving throw, losing said extraneous appendage on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 2d6. If upcast to A-Rank or higher, you can alternatively choose to command the Primal Chakra Disc like a drone, giving this jutsu a duration of Concentration, up to 1 minute. The drone has an AC equal to your Ninjutsu or Taijutsu Save DC, whichever is higher, and 1 hit point. As a bonus action on your turn, you can command the disc to move up to 60 feet and attack one creature as if you cast this jutsu at C-Rank. If the disc reaches 0 hit points, this jutsu immediately ends. You can also turn this jutsu into a drone upon missing a creature with the jutsu by spending 4 chakra.", created_at: NOW, updated_at: NOW },
  { _id: "7d9863ef7f5d5e9be81d616b", name: "Spirit Shot", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action or 1 Reaction, which you take when you would be targeted by or take damage from an attack", range: "Self (10-foot radius)", chakra_cost: "8 Chakra", components: "CM", duration: "Instant", description: "You concentrate chakra all around your body, extending out your arms as you send this energy outward all around you. If cast as an action, each creature within range must make a Dexterity saving throw, taking 6d6 force damage and being knocked back 20 feet on failure, or half as much damage and knockback on a success. If cast as a reaction,  your energy becomes so potent that it forms a dense barrier around you. You gain resistance to the triggering damage type until the end of the attacking creature's turn and all creatures who are within 5 feet of you are knocked back 5 feet. For this duration, you are also immune to non-chakra enhanced damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 2d6 or the knockback by 10 feet (pick one) if used as an action, or the knockback by 5 feet if used as a reaction. If upcast to A-Rank as a reaction, the resistance and immunity granted by this reaction lasts until the start of your next turn.", created_at: NOW, updated_at: NOW },
  { _id: "bfb9088c1c2b0a665cede176", name: "Realm King Fist", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "10 Chakra", components: "CM, M", duration: "Concentration, up to 1 Minute", description: "You focus and briefly awaken the latent primal strength in your blood, dramatically increasing your heart rate and generating a prominent red aura around yourself. You cannot lose concentration of this jutsu as a result of taking damage, and you cannot concentrate on any jutsu other than Wukong hijutsu while this jutsu is active. Once per round, as a bonus action or reaction, you can upcast this jutsu by 1 rank by paying its upcast cost, up to a rank you are able to cast this jutsu to. This jutsu ends early if used in tandem with the *Eight Inner-Gates*. For the duration you increase your movement speed by half, your Strength and Dexterity scores increase by +2 and your unarmed damage die becomes a 1d6 if it is not already or you do not possess unarmed damage die. If your unarmed damage is higher than a 1d6, increase your unarmed damage die by 1 step (1d6>1d8>1d10>1d12>2d6>2d8>2d10).", at_higher_ranks: "For each rank this jutsu is cast above C-Rank, increase the cost by 3. If this jutsu is cast at B-Rank or higher, you instead double your movement speed and increase your unarmed damage die by another step. If this jutsu is cast at A-Rank or higher, you instead triple your movement speed, your Strength and Dexterity increase by +4 instead, and increase your unarmed damage die by another step. At this level and beyond, the intense strain of this jutsu begins to damage you. Lose 5 hit points at the start of each of your turns which cannot be reduced in any way. Once this jutsu ends, you become Weakened. If this jutsu is cast at S-Rank, quadruple your movement speed, increase your Strength and Dexterity scores by +6 instead, and your unarmed damage die by another step, and your unarmed critical threat range by +1. Once this jutsu ends, you gain the Weakened condition, which can only be removed by taking a long rest.", created_at: NOW, updated_at: NOW },
  { _id: "374d587967d33c096f07ddd1", name: "Wild Sense", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Reaction, which you take when an attack misses you, or you succeed a Strength, Dexterity, or Constitution saving throw.", range: "*Special*", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "As part of the requirements for casting this jutsu, the triggering creature must be within range of half of your movement speed. Faster than the eye can see, when an enemy is shocked by your agility, you quickly seize the opportunity for a counterattack. You teleport to a creature within range of half your movement and make a melee taijutsu attack at advantage as you punch or kick them away. On a hit, the creature takes your unarmed damage and must make a Dexterity saving throw. On a failed save, the creature is knocked back 30 feet and is Bruised. On a success a creature is knocked back 5 feet. If you score a critical hit, the creature automatically fails their saving throw. Until the end of your next turn, you can target one affected creature with a Taijutsu *Finisher*, regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "67c96a2a7954475803269959", name: "Meteor Dragon Strike", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You begin charging forward up to 60 feet, channeling an immense amount of radiant chakra within your fist which explodes into a golden dragon of your description. Make a melee Taijutsu attack on up to 3 creatures of your choice that you would pass with your movement. On a hit, you deal your unarmed damage + 7d6 force damage as you strike and pass through each creature. If this jutsu is cast as a *Finisher*, you target a single creature and make a melee taijutsu attack dealing your unarmed damage + 10d8 force damage on hit, ignoring resistance and treating immunity as resistance.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage die by one step. (d4<d6<d8<d10<d12). If upcast to S-Rank or higher as a *Finisher*, this jutsu ignores both resistance and immunity.", created_at: NOW, updated_at: NOW },
  { _id: "d8d8843b9ed193930045c52f", name: "Realm King Binding", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "15 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You close your eyes and take in a deep breath as you channel chakra into your palms. You then quickly open your eyes and make an expanding circle of energy with your hands, forming a ring around a creature. Select one target within range. That target must make a Charisma saving throw. If the target is under the effects of the Berserk condition, they make their saving throw at disadvantage. On a failed saving throw, the target creature has their movement speed reduced to 0 and loses the ability to take actions for the duration of this jutsu. At the end of each of the creature's turns, they can make a Strength or Charisma saving throw, using their physical strength or force of spirit to break free, ending this jutsu on a successful saving throw. A creature under the effects of this jutsu has all status conditions they possess suspended for the duration of this jutsu, their effects not triggering. Additionally, you and all allied creatures gain a +1d6 bonus to skill checks that you would roll in an attempt to decieve or persuade the creature. If an affected creature would take damage from a creature hostile to them, or be forced to make a saving throw against an obviously harmful effect, this jutsu immediately ends once they take damage or make the saving throw, gaining an additional reaction which they can use to move up to their movement speed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fbe72e3904dc32b5cf56a3ce", name: "Forced Spirit Fission", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "20 Chakra", components: "CM, M", duration: "Instant", description: "You channel chakra into your hands and instead of condensing it, you reverse the process, while in contact with another creature. Make a melee Taijutsu or Ninjutsu attack. On hit, you deal 12d8 force damage to the creature's hit points and half the result to their chakra. If the affected creature is currently benefitting from a jutsu, they must make a concentration check with a penalty equal to Xd4, where X equals how many jutsu they are benefitting from. This check must be rolled regardless of whether the jutsu requires concentration, and even if they are not the original caster of the jutsu. If the jutsu does require concentration, they make their concentration check at disadvantage. If the target is unable to lose concentration as the result of a jutsu, trait, or feature, they still must roll, but the Xd4 penalty given by this jutsu is halved. If the target is not benefitting from any jutsu, they must succeed a Constitution saving throw or lose the ability to concentrate on jutsu for 2d4 rounds. Additionally, if the creature has stolen any form of chakra or energy from other creatures and still possesses it, they must make a Constitution saving throw. On a failed save, these chakras/energies are immediately expelled in their entirety and returned to their original owner(s). If having these chakras/energies returned would go beyond the owner(s) maximums, the difference becomes temporary chakra or a temporary form of whatever the energy may be.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "64513ebbf6e1b6d154262ca8", name: "Gatecrash", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "30ft", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, Up to one Minute.", description: "You create a small tear in the fabric of space-time in a place within range that you can see. For the duration, you can activate again this Jutsu using either your Bonus Action or your Reaction, ending this jutsu. As a Bonus ActionOn your turn, you can activate this Jutsu again, teleporting you back to the marked place, no matter how far away you were from it, if you do so, the next attack roll you make before the end of your turn is made at advantage. As a ReactionAs a reaction to begin hit with an attack, and while you are within casting range of your Mark, you can spend the Chakra Cost of this Jutsu again, teleporting you back to the Marked Place, avoiding the attack.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the range by 10ft.", created_at: NOW, updated_at: NOW },
  { _id: "c1148a8188d39508b596e32b", name: "Repetition", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra, 1 *Fate*", components: "HS, CM", duration: "Instant", description: "*As a requirement for casting this Jutsu, you must have already taken your action to cast a jutsu.* You are able to see diferent outcomes from the same actions, allowing you to alter the space-time arround you to walk the same path twice. After casting this Jutsu, all the effects from your previous Jutsu are nullify, damage dealt is healed, conditions applied are removed and features with limited uses are regain, but chakra spent by you, and reactions taken from any creatures between the casting from your fist Jutsu, and this Hijutsu, are not regained. Until the end of your current turn you gain an aditional Action, that you must use to cast the same Jutsu that you used before this Hijutsu, targeting the same Area or Creature, having to roll again the Attack Rolls, Saving Throws and Damage dice involved, you must spent chakra again to cast the jutsu that triggered this Hijutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c4959225fe535593534cb69b", name: "Fakeout", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Minute", description: "You generate an echo on the space-time arround you, coating yourself in a mirror image of your person that moves in slighly diferent maner. For the duration of this Jutsu, the next time you suffer damage dealt by another creature, the echo expands in a violent matter, showing visions of alternate realities to the creature that attacked you. The creature must succed a Wisdom Saving throw, being Blinded until the end of their next turn. If the damage dealt to you was from a Melee Attack, the Saving Throw is made at Disadvantage. After this, this jutsu ends. Creatures already under the Blinded condition within range must perform this save anyways. Creatures with True Sight are immune to this Jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "27d84e4cfb06b9c55b50eb62", name: "Agresive Rift", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "4 Chakra", components: "HS, CM", duration: "instant", description: "You create a small wormhole near an oponent, allowing you to conect two points in the universe. Until the end of your turn, the next Attack Roll you make gain an alternate range of 30ft, and can count as both an Melee and Ranged Attack Roll, for the purpose of captializing on benefits, advantages or feature interaction.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a48b101b192e390327b274ca", name: "Mark of Fate", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30ft", chakra_cost: "9 Chakra, 1 *Fate*", components: "HS, CM, CS", duration: "Concentration, Up to one Minute.", description: "*In order to cast this Jutsu, you must Spend one Fate charge from your Alternate Fates Clan feature per creature marked.* You generate a seal inside a hostile creature within range, altering their tether to this timeline. Select one creature within range, for the duration, creatures Marked with this Jutsu roll their Damage Dice at disadvantage", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the number of creatures that you can mark by 1.", created_at: NOW, updated_at: NOW },
  { _id: "8962a454b33ac42fca2e1b01", name: "Rift Mark", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "30ft", chakra_cost: "7 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You impact your target, generating an echo on the space-time arround him, and molding it to your advantage Select a creature within range, the target must succeed a Charisma Saving Throw. On a Failure, the next instance of damage the target suffer from a Hostile Creature is rolled at advantage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1c52ffe5dd5624cc67a3505a", name: "Blindside", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30ft", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You rip an unstable dimensional fragment from reality. Holding it in your hand for a brief moment before throwing it away to a place within range, exploding mid-air, and showing visions of alternate realities to creatures near it. Select a point within range, this Jutsu can bend arround corners and structures on a 90º once during its movement. All the creatures within 30ft of the fragment that have a direct line of sight of it must succed a Wisdom Saving throw, being Blinded until the end of their next turn. Creatures standing within 5ft of it make this save at disadvantage. Creatures already under the Blinded condition within range must perform this save anyways. Creatures with True Sight are immune to this Jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "eba55d515be0f91fa7afaacf", name: "Dimensional Rift", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM, M", duration: "Concentration, Up to one Minute.", description: "You upen a tear your pocket dimension large enough for you to step in. For the duration of this Jutsu, you become unable to be damaged or affected by normal means or jutsu that lack the Fuinjutsu Keyword. Creatures who's passive perception is 5 or higher than your Save DC are able to catch glimpses of your essence as you move, allowing them to target you with diferent kind of Fuinjutsu, at disadvantage. If the Fuinjutsu would require the user to target you to make a Saving Throw, you gain advantage on the save. You can still hear and see whats happening on the materal realm, but you are unable to interact with it. At any point, you can as a Bonus Action step out of the pocket dimension, ending this Jutsu, if you do so, the next attack roll you make before the end of your turn is made at advantage, and has its critical range increased by 2. If you run out of chakra, end concentration, or loose the ability to mold chakra, this Jutsu ends abrtuplty and you return to the material plane, falling prone on the last position you were in. Creatures with Chakra Sight, Chakra Sensing or True Sight are able to see and/or sense you while this Jutsu is active.", at_higher_ranks: "For each rank you  cast this jutsu above B-Rank, increase the  cost of this jutsu by 3 and increase the  duration to Concentration, Up to one Hour.", created_at: NOW, updated_at: NOW },
  { _id: "1e90840a210039146d980d40", name: "Dimensional Lock", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action or 1 Reaction which you take when a creature within range is about to Teleport or access a Pocket Dimension.", range: "Self (60-foot radius sphere) / 60ft", chakra_cost: "12 Chakra", components: "HS, CM, CS", duration: "Special (Instant)", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ef2520ddad85aea63659eaca", name: "Controlled Fate", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction to falling to 0 Hit Points, or seeing a creature within range fall to 0 Hit Points", range: "60ft", chakra_cost: "*Special* (1 Hit Die)", components: "HS, CM", duration: "Instant.", description: "*In order to cast this Jutsu, you must Spend two Fates charges from your Alternate Fates Clan feature, in addition to this Jutsu Cost.* When you, or a creature within range that you can see would fall to 0 hit points, you may as a reaction, open a rift big enough to connect two timelines, breaking the boundaries of this universe as it collides with another one. As you do, you automatically move into another alternate timeline, on which the thing that would have killed you or them, instead does not. The hit points of the creature target of this Jutsu are restored back to its value before they took the triggering damage. When this Jutsu ends, you permanently lose the Hit Dice used to cast this Jutsu and your Maximum Hit Points are reduced equal to the maximum value of the die, as you leave a piece of you on the other universe. <!-- Full page stain -->", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6f1aa656f4e23f8c05e9e51b", name: "Timestamp", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Day", range: "Self", chakra_cost: "*Special* (13 Chakra, 1 Hit Die)", components: "HS, CM, CS", duration: "Special.", description: "You perform a ritual in order to connect two points in the same timeline, stretching the boundaries of the universe and allowing you to move, not from here to there, but from now to then. After casting this Jutsu, roll 1d4 and record the result, you and a numbers of creatures equal to your Proficiency Bonus that you can see and touch, travel back in time a number of days up to the result of the dice, to the exact location you where at that point in time. When using this Jutsu, creatures take the place of their previous selves, retaining knowledge, items, stats, Hit Points, Chakra Points and conditions. Additionally, when casting this Jutsu, you can spend any numbers of Fate charges from your Alternate Fates Clan feature, when doing so, increase the number of dice rolled by one, per each fate spent. When you cast this Jutsu, you permanently lose the Hit Dice used to cast this Jutsu and your Maximum Hit Points are reduced equal to the maximum value of the die, as you leave a piece of you on the other timeline.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the size of the dice by two steps. (D4>D8>D12)", created_at: NOW, updated_at: NOW },
  { _id: "7163dc87ee0378f543ac826a", name: "Butan's Calm", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "2 Chakra", components: "CM", duration: "8 Hours", description: "This medical ninjutsu was implemented by the Funato, in order to fight without limitations on the sea. A creature targeted by this Ninjutsu, is cured of sea seasickness instantly, additionally, for the duration, the creature cannot lose concentration due to environmental phenomena, such as sea turbulence on a ship.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3b9a20ff3b07df87d444fb58", name: "Chakra Gun: Transformation", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Full Turn Action", range: "60 Feet", chakra_cost: "1 Chakra", components: "CM, HS", duration: "10 minutes", description: "You focus your chakra into a singular point on one or more of your hands, spending 1 Chakra for each hand this jutsu is cast on. For the duration of this jutsu, you can spend 1 Chakra as a Bonus Action to shoot a condensed bullet of chakra at a creature within range. If this jutsu was cast on multiple hands, you may spend 1 chakra for each hand to shoot an additional bullet at a creature within range using the same bonus action. Make a ranged Ninjutsu attack for each bullet fired, on a hit you deal 1d6 + your Ninjutsu ability modifier Force damage. If you have another “Chakra Gun” jutsu active you may instead fire using your reaction, bullets shot this way do not add your ability modifier to damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "063339d9ae49981b819e3dec", name: "Finger Carving Seal", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "1 Chakra", components: "CM, CS", duration: "Concentration, up to 1 minute", description: "You concentrate chakra into your finger and using the heat from that, can apply writing of whatever you want to a surface. If you were to apply it to the flesh of a living creature, they take 1 Fire damage and are left with a scar. If a creature is unwilling you must make a melee ninjutsu attack roll.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f8f92e602713249bc08eb79d", name: "Hair Camouflage", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "1 Chakra", components: "CS, HS", duration: "Concentration, up to 1 hour", description: "Using this technique, your hair can grow to any desired length. It can even completely cover the your body. Your hair returns to its normal length at the conclusion of this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "73499384fe1d395c10a829c3", name: "Aurora", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 Feet (20-foot cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create an array of light encapsulating everything in sight. Each object in a 20-foot cube within range is illuminated in blue, green, or violet light (your choice). Any creature in the area when this jutsu is cast must make a Dexterity saving throw, becoming illuminated on a failed save. For the duration, objects and affected creatures shed dim light in a 10-foot radius. Any attack roll against an affected creature or object has advantage if the attacker can see it, and the affected creature or object can't benefit from being invisible.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2b94971821574e2ab8b6b84e", name: "Beast Imitating Art: Fish", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "Up to 10 minutes", range: "Self", chakra_cost: "13 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "24 Hours", description: "You take your scroll and begin to write a message of any length that you can conceivably write within a 10 minute or less time span. Once complete, the writings manifest into the form of a fish of your description and now carry themselves. You can also cast this jutsu targeting a message already written of 25 words or less. The fish you create has 1 hit point and an AC of 15. Specify a location that you have previously visited and a recipient who matches a general description. You then let the fish swallow the scroll, tag, or similarly small object to deliver to this creature. The construct travels for the duration of the jutsu towards the location, covering no more than 50 miles per 24 hours. When the fish arrives, it turns back into the message when provided a scroll to be placed on and delivers any packages to the creature you described. The fish will only release the object to the creature you specified or if killed. The creature dissipates into non-staining ink when the message is delivered or it is killed.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and duration increases by 24 hours. When casting this jutsu at B-Rank or Higher, the fish becomes large in size and is capable of carrying two medium size creatures on its back.", created_at: NOW, updated_at: NOW },
  { _id: "079ae8943e6f36aeeb0d73ba", name: "Bestial Art: Cub", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You infuse chakra into a chakra seal as you mark yourself with the seal of an animal with great potential. Your smell and hearing have surpassed what normal humans can hope to accomplish and your hands grow razor sharp claws for nails. For this jutsu’s duration, you gain the following benefits; - Your Strength score becomes 18. - Your unarmed attacks now deal 1d8 + Strength Modifier slashing damage. - You gain a +10 bonus to movement speed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "954776aeaacebba8d3cd4343", name: "Chakra Gun: Assault", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1  Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "As part of casting this jutsu, you must have Chakra GunTransformation active. You cannot lose concentration on this jutsu as a result of taking damage. You extend the focus point of your chakra to cover your entire arm. For the duration of this jutsu, as an Action, you can make a ranged Ninjutsu attack on a creature within range. On a hit you deal 1d10 + your Ninjutsu modifier Force damage. If you cast this jutsu and then drop Concentration, within the next minute you may recast it as a Bonus Action at half the chakra cost (rounded down), using the remaining duration.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7de6323a63ed528806949163", name: "Chakra Signal Flare", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "120 Feet", chakra_cost: "3 Chakra", components: "HS, CM", duration: "1 Round", description: "After forming the necessary hand signs, you point your hands towards the sky and shoot out a flare of chakra that shines bright 120 feet into the sky, able to be seen and heard for 5 miles. If you have a nature release affinity you can modify the flare with that element for 1 additional chakra. The chosen element will change the color of the flare. If you have more than 1 chakra affinity you can add as many as you have increasing the cost by 1 chakra for each affinity. | Element | Color | |:----:|:-------------| | Non-Elemental   | White | | Earth  | Brown | | Wind  | Green | | Fire | Red | | Water | Blue | | Lightning | Yellow | | Medical | Purple |", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bea22087c7064bbb49e9c582", name: "Crazy Hair Technique", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "5 feet", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "You can only cast this jutsu after you hit with an unarmed or melee weapon attack. After hitting an enemy, you extend your hair in order to hit two more times. Make two melee ninjutsu attacks, dealing 1d6 + your Ninjutsu modifier Piercing damage on a hit.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9290165f3d614f8a3800bc20", name: "Demonic Culling: Koketsu Arrow", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure nearly invisible arrows made of chakra and manipulate them by pointing your finger in the direction they're to go. These arrows interact with by interacting with related vectors forcing any it passes through to move in the desired direction. Make a ranged ninjutsu attack, dealing 2d8 force damage on a hit. They must also make a Strength saving throw on a hit, being forced 15 feet into your desired direction on a failure and not moving any feet on a success. If they are knocked into a solid surface, they take double falling damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost by 3 and the number of attacks by +1. At A-Rank increase the damage this jutsu does to 3d8.", created_at: NOW, updated_at: NOW },
  { _id: "e165dd5278b4b3261585ca72", name: "Fabricate Clothing", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, CS, NT (A medium sized thread of twine  or scrap of cloth)", duration: "*Special*", description: "You hold a thread of twine or scrap of cloth in hand and outstretch your hand to a willing creature you can touch. The material you hold  begins to glow with a radiant white before soon disapearing as the hand you are outstretching towards the creature releases a white light which completely obscures the creature. As the light fades, the creature stands in a brand new set of clothing of your design. Clothes you create with this feature, no matter how illustrious to the eye, always appear cheaply made when inspected, giving your clothes a value of 1 Ryo. If another creature attempts to wear clothes created with this jutsu, the clothes immediately disapear.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "17aadd57df88f7256ed62031", name: "Hair Trap Technique", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (20-foot Line)", chakra_cost: "5 Chakra", components: "CM, W/NT (Any Cutting object)", duration: "Concentration, up to 1 minute", description: "After cutting your hair, you infuse the strands with chakra, throwing it in a straight line, trapping the first person that comes into contact with it. The creature makes a Dexterity saving throw, being restrained and unable to take actions on a failed save, a restrained creature can make a Strength saving throw at the start of each of its turns, ending the effects on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "58b86fb696bcdda9d93a8f85", name: "Howling Hair Technique", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30 Foot Line)", chakra_cost: "5 Chakra", components: "CM", duration: "Instant", description: "By whipping around locks of your hair, you generate high-frequency sound waves that are capable of simultaneously disorienting the foe by overwhelming their hearing e able to slice at the target. Every creature in the range of this ninjutsu must make a Constitution saving throw, gaining the Dazed condition, and taking 2d6 Slashing damage on a failed save. On a success, they only take half the damage and suffer no additional effects.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "385e3d59bbafc79653315585", name: "Hunter's Instinct", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "3 Chakra", components: "CM", duration: "Concentration, up to 1 hour", description: "A jutsu which numbs the sporatic nature of the thoughts of the mind to allow one to focus and utilize all of their senses. For the duration of this jutsu, your passive perception and passive insight scores cannot be lowered by any effects of a rank equal to or lower than the rank of this jutsu. Additionally, you gain a +1d4 bonus to Investigation, Perception, and Survial checks for the duration and cannot make checks with these skills at disadvantage as the result of a hostile effect of a rank equal to or lower than this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast  to B-Rank or  higher, the bonus becomes a 1d6. If cast to S-Rank or higher, the bonus becomes a 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "0ab360af98d612f613ce859f", name: "Medical Release: Medical Fist", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b4a1e426130addb319cec760", name: "Medical Release: Sapping Strike", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "Action", range: "5 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f6b017b7a602c3b9336715a3", name: "Needle Senbon", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (25 Foot Cone)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You harden the hair on your head and shoot a multitude of hair Senbon to the enemies in front of you. All creatures in a 25-foot cone originating from you must succeed on a Dexterity saving throw, taking 4d4 Piercing damage on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "50685357e7be811e6d8069c9", name: "Refraction Array", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You rapidly refract light infusing your chakra with the water vapor in the air to create a burning scintillating glow in the form of a thin wire. Make three ranged ninjutsu attacks against a creature you can see within range, on a hit the target takes 1d8 force damage. If you hit with at least 3 of these attacks the creature is blinded until the start of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "5a9ef3c93847f8941451a41a", name: "Bestial Art: Alpha", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You infuse chakra into a chakra seal as you mark yourself with the seal of an alpha. Your senses get sharper, and you begin to notice things far more quickly than you are used to. You grow fur on your forearms, and long claws form at the edge of your fingertips. For this jutsu’s duration, you gain the following benefits; - Your Strength score becomes 18 if it is not already higher. If it is 18 or higher already, you instead increase your Strength Score by +2. - Your unarmed damage becomes 2d6 and deals slashing damage. - You gain a +15 bonus to movement speed. - Attacks of Opportunity you make are at advantage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dfda381286f40e68f18f616e", name: "Beast Imitating Art: Jellyfish (Changed)", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, up to 1 minute", description: "You draw a picture of a jellyfish. Infusing chakra into it as it exits your scroll and stands next to you. You summon a construct Ink Jellyfish. The construct jellyfish has the following Statistics; You may command the Ink Jellyfish as a bonus action on your turn. The Ink Jellyfish may take an appropriate reaction if able. The Ink Jellyfish uses your Ninjutsu Attack bonus for all of its attacks.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the Ink Jellyfish's Hit points by 15 (2d8+5).", created_at: NOW, updated_at: NOW },
  { _id: "a3c19b47cd5c76d9850bef80", name: "Body Elimination Technique", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "10 minutes", range: "Self", chakra_cost: "8 Chakra", components: "CM, HS", duration: "Until Deactivated", description: "A shinobi's corpse is a treasure trove of information. You put a seal on your chest that keeps track of your heart beat, if your heart would stop beating the seal destroys your body completely turning it to dust stopping others from gaining access to your corpse. This jutsu activates when you would fail your 3rd death saving throw. You can deactivate this jutsu by spending 1 minute removing the seal from your chest.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c5f6fa1ae2b4d84d9bcb6521", name: "Compression Rasengan", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "As part of the requirements for casting this jutsu you must have Rasengan on your jutsu known list. You collect chakra into your hand generating a powerful sphere of spiraling chakra to strike an enemy with. By overlapping the Rasengan as it is formed in the dominant hand with the other hand, the user compresses and condenses it to its limit. In this state, it can penetrate targets with little resistance. This jutsu does not cost any additional chakra while concentrating. Starting next turn, you can spend your Action to make a melee ninjutsu attack against a creature within range. On a hit, the target takes 4d8 Force damage and makes a Constitution Saving throw. On a failed save they are knocked back 30 feet, gaining the Dazed Condition. This jutsu then ends. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage as if they had fallen an equal distance. This jutsu ignore any DR a creature may have as well as their resistances, and treats immunity as resistance. At the conclusion of this jutsu, the user of this takes 1d8 force damage.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3, the damage by 3d8, and the knockback by 10 feet. If this jutsu is cast at A-Rank or higher, you can make the melee ninjutsu attack the turn you cast it. ___ >", created_at: NOW, updated_at: NOW },
  { _id: "94d1ad29a008d9b83b26fa50", name: "Flash", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self (30-foot Radius)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You holds up your palms into a bird sign formation, emitting a dazzling bright light. All creatures other than yourself within a 30-foot radius must make a Constitution saving throw. Creatures within 10 feet roll their save at disadvantage, creatures more than 20 feet away roll their save at advantage. On a failed save, the creature is blinded for 1 minute. They may repeat the save at the end of each of their turns ending the effects on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "337ad4dd22ed61bab7867663", name: "Medical Release: Acidic Eruption", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure a surge of acidic chakra between your hands, before launching it out in front of you. Each creature in a 30-foot cone must make a Dexterity saving throw, or take 6d6 acid damage and become corroded on a failed save. On a successful save, a creature takes half as much damage and no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "6bc277545e09d3b09946baa7", name: "Medical Release: Bile Blast", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You spew out a stream of bile, infused with poisonous chakra that seeps through everything it touches. All creatures within a 30-foot-long, 5 feet wide line must make a Constitution saving throw, taking 4d12 Poison damage and becoming poisoned on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "31df89b3cd25baeb0bb92b1e", name: "Medical Release: Blood Mist Plume", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Reaction, when you would take damage from a melee attack", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM, NT (Blood Vial)", duration: "Instant", description: "You excrete a mist of acidic blood from a vial that disorients and confuses opponents. When cast, the triggering attack rolls an additional d20, taking the lower result. For the duration, until the beginning of your next turn, hostile creatures have disadvantage on melee attacks against you. When a creature hits you with a melee attack they must succeed a Constitution saving throw or take 3d6 acid damage and be blinded until the start of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "51840275065a685e7b293a50", name: "Medical Release: Defensive Cloak", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1  Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You cover your entire body in a vile cloak of medical jutsu, that harms any who touch you. When a creature hits you with a melee attack, they take 2d6 Necrotic damage and you gain temporary hit points equal to half the damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of the jutsu by 3 and increase the damage die by 1 step. (d6>d8>d10>d12) If you cast this jutsu at A-Rank or higher you instead gain temporary hit points equal to the full damage dealt.", created_at: NOW, updated_at: NOW },
  { _id: "09e881ae78006b02724e9604", name: "Medical Release: Healing Cloak", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1  Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Your entire body is covered in soothing medical chakra as you begin to glow a soft pink. When you cast this jutsu you regain 2d8 hit points. For the duration of this jutsu you regain 1d8 hit points at the start of your turn. You may as a bonus action on your turn heal 2d8, when you do this jutsu immediately ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b8451870fda701cd1d2d8b19", name: "Medical Release: Malice", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM, M", duration: "Instant", description: "You generate smoldering red and black energy within your hand manifesting all the offensive power of medical release. Make a melee ninjutsu attack against a target within range. On hit, you deal 10d4 acid, poison, or necrotic  damage and the target must make a Constitution saving throw, becoming either Corroded, Envenomed, or gaining 1 rank of Bleeding (pick the condition which corresponds the the damage type chosen). Due to the stress of manifesting all of the power of offensive medical chakra, you lose hit points equal to your Ninjutsu ability modifier when you cast this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1 step or the number of conditions gained on a failed save by +1, picking between Corroded, Bleeding, or Envenomed (Pick one).", created_at: NOW, updated_at: NOW },
  { _id: "fda78e270c07b5c6147b257d", name: "Needle Spear", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (20-Foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You extend your hair and harden it to be as sharp as a spear. Each creature in a 20-foot-radius sphere centered on you, other than you, must make a Dexterity saving Throw, taking 4d8 piercing damage on a failed save, or half asmuch on a successful one", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d8, and the radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "9af5751d30df987ce6d62967", name: "Probe Barrier", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "Self (250-Foot radius sphere)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "This technique allows the user to create a 5-foot spherical detection barrier with the user at the center. At the user's command, and as a bonus action, the detection barrier can expand up to 250-feet grasping everything in the surroundings, ending the jutsu when it reaches the limit. This jutsu work in the same way as the 'Sensing Technique.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f86b40ce51f49212cb09ac79", name: "Sealing Art: Release", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Minute", range: "Touch", chakra_cost: "8 Chakra", components: "HS, CM, CS", duration: "8 Hours", description: "You infuse chakra into a chakra seal and attempt to mark  a willing creature with a seal of protection. When a marked creature would be the target of, or would be force to make a saving throw or ability check against a jutsu with the Fuinjutsu or genjutsu keyword you enact a defensive ward meant to protect, granting the following benefits until the beginning of your next turn; This jutsu then ends. - They gain a bonus to their AC equal to the your Ninjutsu ability modifier against jutsu with the Fuinjutsu or Genjutsu keyword. - When they would make a saving throw or ability check vs a jutsu with the Fuinjutsu or genjutsu keyword, they instead may use half of your Intelligence (Ninshou) skill bonus.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of creatures you can target with this jutsu by +1", created_at: NOW, updated_at: NOW },
  { _id: "06b0c7a91bf374ffc8001e0d", name: "Soul Echo: Blessed Weapon", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "9 Chakra", components: "CM, CS, W (Any Melee)", duration: "Concentration, up to 1 Minute", description: "You begin to channel medical chakra within your palm as you think of happy memories. Kind words said over the years, hospitality, and better times. The echoes of your soul empower this jutsu as you bathe the weapon with your chakra. For the duration, your weapon begins to glow with a holy white lighting, gaining the following benefits; - At the start of each of your turns, you recover hit points equal to your Ninjutsu ability modifier. - Your weapon's damage die increases by 1 step, up to a d12. This weapon  cannot be targeted by another jutsu that would change its damage type, die, or add extra damage dice. - Your weapon emits 15 feet of bright light and 15 feet of dim light. The wielder of this weapon can use this light to see through chakra enhanced darkness from a jutsu of equal rank or lower. - For each hit you land with this weapon, whether it is part of a Bukijutsu or the attack action, the creature takes 1d6 chakra damage. Beasts, Undead, and Monstrosities take double the chakra damage.", at_higher_ranks: "For each rank above C-Rank, increase the cost by 3, the radius of both light sources by 10 feet, and the healing by +1. If cast to A-Rank or higher, you deal double chakra damage against Aberrations, Demons, and Mutants as well, and you ignore resistance and treat immunity as resistance when damaging an adversary type that would take double damage.", created_at: NOW, updated_at: NOW },
  { _id: "abda526cb495782e8fd8248e", name: "Yaco's Oasis", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Bonus Action", range: "Self (1 Mile radius)", chakra_cost: "6 Chakra", components: "HS, CM", duration: "1 Minute", description: "A variation of the *Sensing Technique* made to help locate sources of drinkable fluid. You make the \"Tori\" hand sign and briefly shut your eyes as you release a field of chakra in a 1 mile radius. Sources of drinkable water or other fluid safe for consimption begin to glow in a faint blue sparkly light that only you can see, even through walls. You can also locate sufficient sources of water, which glow in a green light. If any fluid sources you detect are chakra enhanced, the colors you see occasionally shift to yellow. If any fluid source contains poison or hostile chakra, it occassionaly shifts red. This jutsu cannot detect creatures, unless the creature is classified as a suffiecient source of water, in which case they glow a bright blue color if friendly, or bright red if hostile.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a25895ef51895e8b2bad5048", name: "Advanced Hair Binding Technique", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "This technique is a more complex version of the  Hair Binding technique, giving the user a variety of options once the target is captured. Choose one creature within range, the target must make a Dexterity saving throw, gaining the restrained and incapacitated condition on a failed save, and must make a Strength saving throw at the start of each of his turns to end the conditions and free themself. You can freely move the creature during the duration. You can only target creatures up to one size larger that you. Once captured, you can choose to do any of the following as a Bonus Action. -  *Strangle:* You deal 4d8 bludgeoning damage. -  *Suffocate:* You wrap your hair around the neck of your creature, and start suffocating it. - *Throw:* You launch the target, send it hurtling 60 feet away at high speed. The creature takes double the usual fall damage if they hit a solid surface like a tree, wall, or floor.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "be8a71350f26b098af623d34", name: "Beast Imitating Art: Wolf Pack (Changed)", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "13 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, up to 1 minute", description: "You draw a picture depicting 3 wolves. Infusing chakra into it as they exits your scroll and stand next to you. You summon 3 construct Ink Wolves. An Ink Wolf has the following Statistics; You may command the Ink wolves as a bonus action on your turn. When you command them, all wolves currently active act at the same time, and attempt to perform the same actions against either the same creature or different creatures determined by you. The Ink Wolves use your Ninjutsu Attack bonus for all of its attacks.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the hit points of the Ink Wolves by 10 (1d8+5). ___ >", created_at: NOW, updated_at: NOW },
  { _id: "f702e58380e6cefbe78f3ecd", name: "Dual Rasengan (Changed)", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "As part of the requirements for casting this jutsu you must have Rasengan on your jutsu known list. You collect chakra into both of your hands generating two powerful spheres of spiraling chakra to strike an enemy with. *This jutsu does not cost any additional chakra while concentrating.* Starting next turn, You can make two melee ninjutsu attacks against a creature within range as an Action. Both of these attacks are made at the exact same time. On a hit, the target takes 5d8 force damage and must succeed a Strength saving throw, being knocked back 30 feet and gaining the dazed condition on a failed save. This jutsu then ends. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage as if they had fallen an equal distance.", at_higher_ranks: "For each rank above B-Rank, increase the cost of this jutsu by 3, the damage by 2d8 and the knock back by 10 feet. If this Jutsu is cast at A-Rank or higher you may make the attacks as part of the same action as casting the jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "6dd6a7104bde76dd0f9b17a5", name: "Long Lasting Shadow Clone", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "Special *(10 Chakra)*", components: "HS, CM", duration: "Special", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dc26cd13a6ed363e510af813", name: "Magical Telescope", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Minute", range: "10 Miles", chakra_cost: "14 Chakra", components: "HS, CM, CS, NT (Crystal Ball)", duration: "Concentration, up to 1 minute", description: "You pour your chakra into a crystal ball over the course of a minute. Afterwards if you think of a creature or location that you know of within 10 miles of your current location the crystal ball shows you everything within 15 feet of the creature or a 15-foot cube in an area of your choosing.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 5 and the range of the jutsu is increased by 10 times.", created_at: NOW, updated_at: NOW },
  { _id: "293274ba3beeb82717fda9d8", name: "Medical Release: Withering", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Bonus Action", range: "Self (45-foot radius)", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You emit a dark aura of decay against creatures within 45 feet of you. For the duration, hostile creatures within range of this jutsu who gain the Envenomed condition have the duration of their condition extended until this jutsu ends, unless the duration is already higher. The envenomed condition now always deals its maximum damage and has its damage type changed to necrotic. You do not need to spend chakra to maintain concentration of this jutsu. Once per turn, when you affect a hostile creature with a jutsu with the medical keyword that deals necrotic damage, the creature must make a Constitution saving throw, becoming poisoned and envenomed on a failure. If the medical jutsu used already imposes a saving throw, they gain the envenomed condition upon failing the jutsu's innate saving throw instead.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the radius by 5 feet. If cast to A-Rank or higher, creatures are unable to remove the envenomed condition with a medical jutsu of a rank less than the rank that this jutsu was cast at.", created_at: NOW, updated_at: NOW },
  { _id: "9a648aca1705540abc2583f5", name: "Penance", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Full Turn Action", range: "Touch", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You burden yourself with another creature's pain, taking it on yourself. You touch a creature with a balance of yin-yang chakra to accept debilitating effects. You take all the negative effects the target is currently suffering from, removing them from the target. This includes reductions to ability scores, reductions to hit point maximum, curses that do not target the soul, and all conditions. You are cleared of all these effects after 1 hour, as your body naturally dissipates them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f964d3e3ef7d3e9522517f4", name: "Super Compression Rasengan (Changed)", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "13 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "As part of the requirements for casting this jutsu you must have Compression Rasengan on your jutsu known list. You collect chakra into your hand generating a powerful sphere of spiraling chakra to strike an enemy with. By overlapping the Rasengan as it is formed in the dominant hand with the other hand, the user compresses and condenses it to its limit. In this state, it can penetrate targets with little resistance. This jutsu does not cost any additional chakra while concentrating. Starting next turn, you can spend your Action to make a Melee Ninjutsu Attack against a creature within range. On a Hit, the target takes 6d8 Force Damage and makes a Strength Saving throw. On a failed save they are knocked back 30 feet, gaining the Dazed Condition. This jutsu then ends. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage as if they had fallen an equal distance. This jutsu ignores DR, resistance and immunity. If the target does not have resistance or immunity to Force damage, it takes double damage. At the conclusion of this jutsu, the user of this takes 2d6 force damage", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost by 3, the damage by 2d8, and the knockback by 20 feet. If this jutsu is cast at A-Rank or higher, you can make the melee ninjutsu attack the turn you cast it.", created_at: NOW, updated_at: NOW },
  { _id: "a534557e6b74f3b53423664e", name: "Beast Imitating Art: Giant Crab (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "18 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, up to 1 minute", description: "You draw a picture of a giant crab. Infusing chakra into it as it exits your scroll and stands next to you. You summon a construct Ink Giant Crab. The construct crab has the following Statistics; You may command the Ink Giant Crab as a bonus action on your turn. The Ink Giant Crab may take an appropriate reaction if able. The Ink Giant Crab uses your Ninjutsu Attack bonus for all of its attacks.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the hit points by 15 (3d8).", created_at: NOW, updated_at: NOW },
  { _id: "04c8cc44e03f53554c975601", name: "Grind", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Reaction, when you would be forced to make a saving throw against a ninjutsu that forms a range that is either a line or cone", range: "Self", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You create a pure ball of chakra and attempt to ride the source of energy directed at you, towards the caster. Make a melee ninjutsu attack against the save DC of the jutsu. On a success, you grind on the emitted energy, moving to the caster and avoid the jutsu entirely. Once your movement ends you may choose to make an attack roll against them, using the initial attack roll of this jutsu, dealing 7d10 force damage on a hit. This movement does not provoke an attack of opportunity.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "844793f9c3e17482f8acc100", name: "Medical Release: Poison Mist Dragon", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "20 Chakra", components: "CM, HS", duration: "Instant", description: "You open your mouth unleashing a near endless supply of poisonous gas in the shape of a dragon. The dragon then attempts to ram its target. Make a Ranged ninjutsu attack on a creature in range, on a hit the target creature takes 14d6 Poison damage. Afterwards the smoke dragon dissipates leaving behind a poisonous smoke cloud. All creatures including the target creature within 30 feet of the original target location must make a constitution saving throw or gain the poisoned condition for 1 minute. This jutsu rolls clash checks at disadvantage when clashing against a jutsu with the wind release jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8e20c13435ed0c9992170d74", name: "Medical Release: Scarlet Aeonia", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "20 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You gracefully jump into the air and begin forming scarlet chakra throughout your body, which gradually takes the appearence of a budding flower. Select a space within 60 feet. You elegantly move to your desired space, moving creatures that would be in your way to the side in a space that can hold them. All creatures within 15 feet of you when you land must succeed a Dexterity saving throw or take 2d10 acid and 2d10 poison damage and gain 1 rank of Corroded and Envenomed. Soon after you land, the flower fully blossoms, taking up a 30-foot sphere centered on you. All creatures with this radius, other than you, must make a Constitution saving throw, at disadvantage if they failed the Dexterity saving throw, taking 2d10 acid and 2d10 poison damage and gaining 2 ranks of Corroded and Envenomed on a failed save, or half as much damage and no further effects on a success. Creatures who would start their turn or enter this radius before the start of your next turn must make this Constitution saving throw, taking 2d10 acid and 2d10 poison damage and gaining 1 rank of Corroded and Envenomed on a failed save. ___ >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7b094f7ccb3268938b61e635", name: "Rasendan (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "17 Chakra", components: "HS, CM", duration: "Instant", description: "As part of the requirements for casting this jutsu you must have Rasengan on your jutsu known list. You conjure a mass of chakra with two fingers and then condense it into an inch wide swirling sphere of pure chakra and you fire it at creature you can see within range. The target creature cannot take reactions until the conclusion of this jutsu. Make a ranged ninjutsu attack. On a hit, the target takes 8d8 Force damage and must make a Strength saving throw. On a failed save they are knocked back 30 feet and gain the dazed condition until the end of their next turn. This jutsu ignores half and three quarters cover.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 3d8.", created_at: NOW, updated_at: NOW },
  { _id: "35be5a545486af793db68a96", name: "Rasen-Shuriken (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Weapons Range", chakra_cost: "20 Chakra", components: "CM, W (Any Shuriken)", duration: "Instant", description: "As part of the requirements for casting this jutsu you must have Rasengan on your jutsu known list. You take a shuriken in hand and begin collecting chakra within the center of it, forming a sphere of spiraling chakra which causes the weapon to vibrate and twirl faster than the eye can see. Make a ranged ninjutsu attack against a creature within range. On hit, you deal your weapon's damage + 8d8 Force damage and the creature must make a Strength saving throw, being knocked back 30 feet and gaining the dazed condition on a failed save. This jutsu scores a critical hit on a 19-20. After colliding with the creature, the shuriken returns to your hand.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "eec848dc98b9da05c6023b5b", name: "Ultra-Big Ball Rasengan (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "10 feet", chakra_cost: "20 Chakra", components: "CM", duration: "Instant", description: "As part of the requirements for casting this jutsu you must have either Compression Rasengan or Super Compression Rasengan, or Dual Rasengan on your jutsu known list. You collect chakra into your hand generating a powerful giant sphere of spiraling chakra to strike an enemy with. Make a Melee Ninjutsu Attack against a creature within range. On a Hit, the target takes 14d6 Force Damage and must succeed a Constitution saving throw. On a failed save they are knocked back 100 feet, gaining the Dazed Condition. This jutsu then ends. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage as if they had fallen an equal distance.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 5 and the damage by 2d6. If this jutsu is cast at S-Rank.  If this Jutsu is cast at S-Rank or higher, you  may also add a nature release keyword & change this jutsu’s damage type to match the nature release you currently can use.  You gain the following benefits depending on the Nature Release chosen: -  *Earth:* On a failed save the target creature also loses the ability to Mold Chakra for 1d4 Rounds and gains the weakened and restrained conditions until the end of their next turn. -  *Wind:* The Rasengan gains a range of 120 Feet, and you can instead make a Ranged Ninjutsu attack at a creature within range. On a Hit, the target creature takes wind damage and the Rasengan expands. All Creatures, except the original target, in a 30-foot radius sphere centered on the original target of this jutsu must make a Dexterity saving throw, taking the full damage of this jutsu on a failure or half as much on a success. - *Fire:* The target creature and all creatures in a 60-foot cone behind the target creature  must also make the saving throw, gaining 3 ranks of Burned. - *Water:* Target creature makes their Saving throw at Disadvantage. On a Failed save, target creature is knocked back twice the distance they normally would be, taking double falling damage if they hit a solid surface. After the jutsu ends you are counted as being near a source of water for 1 minute. -  *Lightning:* Target creature gains the Shocked and slowed condition for 1d6 rounds on a failed save. This Jutsu now scores a critical hit on a roll of 18-20.", created_at: NOW, updated_at: NOW },
  { _id: "52b689326ec893dfd790ee1a", name: "Bestial Art: Apex", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (*28 Chakra*)", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You infuse chakra into a chakra seal as you attempt to mark yourself with the seal of an apex creature. You cannot reduce the cost of this jutsu by any means. Your body grows and claws begin to form where your nails used to be. You grow a thick coat of fur that covers your entire body. Your senses are heightened until nothing can hide from you. For this jutsu’s duration, you gain the following benefits; -  Your Strength, Dexterity, Constitution and Wisdom scores become 20 if they are not already 20 or higher. If a score is 20 or higher already, you instead increase it by +4. - If your Constitution increases as a result of this jutsu you do not increase your maximum hit points and chakra, you instead gain temporary hit points and chakra equal to what the increase would've gave you, but this temporary chakra can't be used to pay concentration costs for this jutsu. - Your size becomes Large - You cannot lose concentration on this jutsu as a result of failing a concentration check. - You gain a +5 to Acrobatics, Athletics, Stealth and Perception checks. - You cannot be seen with Chakra Sight. - You gain a bonus to movement speed equal to 10 times your proficiency bonus. - Your jump distance and height are tripled. - You gain resistance to bludgeoning, piercing, and slashing damage. - Your unarmed damage becomes 3d12, deals Slashing damage, and you add both your Strength and Dexterity modifier to damage rolls. - Attacks of Opportunity you make are at advantage. - When you make an unarmed attack, you can make two attacks instead of one, if you cannot already. If you can, then you instead make one additional unarmed attack.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "47782980412975175413b708", name: "Beast Imitating Art: Dragon", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "26 Chakra", components: "HS, CM, CS, NT (Empty Scroll)", duration: "Concentration, up to 1 minute", description: "You draw a picture of a Dragon, a legendary creature of your description. Infusing chakra into it as it exits your scroll and stands next to you. You summon a construct Ink Dragon. You may command the Ink Dragon as a bonus action on your turn. The Ink Dragon may take an appropriate bonus action if able. The Ink Dragon’s has the following Statistics using your Ninjutsu attack bonus and Save DC for anything that requires an attack or saving throw; ___ >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f097f823f0bf7f031e638831", name: "Comet Azur", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Full Turn Action", range: "Self (120-foot long, 10-foot wide line)", chakra_cost: "28 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "You slowly move your hand in a spiral in front you, gathering immense chakra in your palm as your hand travels before firing a 120-foot long, 10-foot long line in  a sudden burst of crystaline blue energy. You have a +1d4 bonus to clash checks with this jutsu. All creatures within range must make a Dexterity saving throw, taking 15d10 force damage and halving their movement speed until the end of their next turn on a failed save, or only half damage and no further effects on a successful save. Creatures who fail this saving throw by 5 or more become Dazed. After this jutsu's casting, you can choose to maintain concentration. If you do, your speed is permenently reduced to 0 until this jutsu ends. You can only end concentration of this jutsu on your turn. A creature who enters this jutsu's area while you are concentration on this jutsu, takes 7d10 force damage, while a creature who starts their turn in it, takes 4d10 force damage. At the start of each of your turns while concentrating on this jutsu, if you choose not to end this jutsu, you spend your full turn action again to impose another Dexterity saving throw, dealing the same affects as the prior Dexterity saving throw on a success or failure respectively. Once this jutsu ends, the affected area becomes difficult terrain.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a66f992507674f1e2c63209b", name: "Medical Release: Divine Tree Heal", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (60-foot radius)", chakra_cost: "*Special* (55 Chakra)", components: "HS, CM, CS", duration: "1 Minute", description: "You stick a finger forward and release a beacon of golden medical chakra in front of you. From this stream, a ghostly gargantuan golden tree of medical chakra emerges, emitting a great rejuvinating golden aura to allied within range. For the duration, allied creatures within 60 feet of this tree recover 2d6+8 hit points and gain half as many temporary hit points at the start of each of their turns (the temporary hit points do not stack). They also ignore difficult terrain, and have advantage on saving throws against jutsu that would give a *Physical* or *Elemental* condition. This tree's space can be passed through by any creature. If a creature ends its turn in the tree's space, it is pushed outside of it in a space that can hold it. Creatures can target this tree in an attempt to destroy it. This tree has an AC equal to your Ninjutsu Save DC and 150 hit points, immunity to Acid, Necrotic, Psychic, and Poison damage, and uses the casters proficiency bonus for all saving throws. If this tree is destroyed, it releases a final parting gift of healing for your allies. Each allied creature within range recovers 50 hit points and gains 50 temporary hit points (these temporary hit points stack with other sources of temporary hit points). This jutsu then ends early.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a5b3a4489605e053fd1c8a26", name: "Medical Release: Heydays Delight", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action or Reaction", range: "Touch", chakra_cost: "*Special* (35 Chakra)", components: "HS, CM", duration: "1 Hour", description: "You send a wave of medical chakra throughout your body to counteract the effects of old age, poisons, and harmful techniques. For the duration of this jutsu your ability scores can not be lowered by features, jutsu, or poisons. You become immune to *Physical* conditions other than grappled and restrained for the duration. Additionally your ability scores cannot be lowered by any means, including permenent effects you may already possesses as the result of a critical injury, sickness, or old age.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "db770c435f0c3f85851bd0c9", name: "Medical Release: Grim Harvest", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (60-foot cone)", chakra_cost: "*Special* (30 Chakra), 10 Hit Die", components: "HS, CM", duration: "Instant", description: "As a part of casting this jutsu, you must be gaining the benefits of *Grim Reality*. You coat the Reaper's blade in a coat of dark chakra. The energy resonates within the air, the aura of death being all but tangible. All creatures in a 60-foot cone must make a Constitution saving throw at disadvantage or take 20d12 necrotic damage and gain 5 ranks of the weakened and fear conditions. Additionally, if a creature fails this saving throw they lose 5 hit die. The destruction left in your wake is palpable, and all plant life in the area shrivels and dies. This area becomes permanent difficult terrain and no life can grow in that area for the next 100 years. Conditions inflicted by this jutsu cannot be ignored in any way and cannot be healed or dispelled unless by the means of an S-Rank jutsu. If a creature dies or is reduced to 0 hit points by the means of this jutsu their body and soul withers away, not being able to be revived by any means.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c1c43918b408741fa3cc624e", name: "Meteoroid Blast", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Full Turn Action", range: "200 feet (60-foot radius sphere)", chakra_cost: "50 Chakra", components: "HS, CM", duration: "Instant", description: "You begin to form a giant ball of chakra in the sky, with the intent to obliterate any opponents who dare stand against you. You cannot reduce the cost of this jutsu by more than half. Select a space you can see in range, all creatures within a 60-foot radius centered on that space, must make a Dexterity saving throw, taking 20d10 damage on a failed save, or half as much on a success. If you have access to a Nature Release keyword, you can infuse this chakra with your elemental release, granting it increased benefits; You can only infuse one nature release; - EarthThe damage type becomes Earth and target creatures who fail their save gain the incapacitated and restrained condition for 1 minute as they are incased in rock, they can make a Strength saving throw at the end of each of their turns, breaking free on a success. If they do not succeed this saving throw before the minute elapses they become Petrified. Additionally, the area of this jutsu permanently counts as difficult terrain. - WindThe damage type becomes Wind and target creatures who fail their save gain 10 ranks of the Lacerated condition. Creatures who would fail their saving throw, spreads all Elemental conditions currently affecting them around to all creatures, excluding the caster within 60 feet of  them. Hostile creatures within 60 feet of the failing one gain 1 rank of all elemental conditions currently affecting it. - FireThe damage type becomes Fire and target creatures who fail their save gain 5 Ranks of the Burned condition, if this jutsu reduces a creature to 0 Hit Points, they cannot be revived as their body is burnt to ashes. - WaterThe damage type becomes Cold and target creatures who fail their save gain 5 ranks of the chilled condition. For the next minute creatures who remain in the area, or enter the jutsu area, begin to suffocate as the Water stays in the area in a stasis like state. - LightningThe damage type becomes Lightning and target creatures who fail their save gain 5 ranks of shocked and become paralyzed until the end of your next turn. - ForceIf you do not infuse this jutsu with a nature release keyword it instead deals 20d12 and deals Force damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "534d2ba299e2cd4e7a907395", name: "Stardust Fall (Changed)", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "300 feet (60-foot radius)", chakra_cost: "25 Chakra", components: "HS, CM, CS", duration: "Instant", description: "As part of the requirements to cast this jutsu, you must know the *Shining Stars, Soaring Strike* jutsu, and must currently be concentrating on *Shining Stars, Soaring Strike*. You channel chakra into your legs and backflip yourself 300 feet into the air. You raise both your hands above yourself and begin charging an incredible amount of chakra. Each star you possess from the *Shining Stars, Soaring Strike* jutsu shoots towards the center of your palms like a comet, merging together with all other stars forming a prismatic orb of pure energy which perspires an aura of radiant chakra. Creatures from below can see a bright light from where you are in the sky from a mile away. You aim the orb down at a space within 300 feet and hundreds of stars erupt from the orb like meteors, targeting the space you select and affecting creatures within a 60-foot radius. For each star you had remaining from the *Shining Stars, Soaring Strike* jutsu, you cast the *Hollow Stars* jutsu at A-Rank, raising the damage die by 1 step. Each star from Hollow Stars affects this area, dealing its damage and conditional effects to all creatures within range, in one instance. The affected area permanently becomes difficult terrain. You then quickly fall down back to the Earth, using your chakra to prevent you from taking fall damage. This jutsu immediately ends your concentration of the *Shining Stars, Soaring Strike* jutsu upon conclusion.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7240cfc4345ff65611ff6c44", name: "Summoning: Triple Rashomon (Changed)", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction", range: "60 Feet", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Instant", description: "As part of the requirements for casting this jutsu you must have *SummoningRashomon* on your jutsu known list. You bite your finger drawing blood before using it as a catalyst to summon a series of 3 Rashomon, 60 feet tall, 30 Feet wide, and 5 feet thick gates made of iron, brick, chakra and other materials. These walls are erected standing straight upward. The 3 walls are separated by 20 feet from each other. If you are in an area that cannot fit the 3 Rashomon’s, this jutsu will fail. Each Rashomon has an AC equal to your Ninjutsu save DC, 50 Hit points, and is resistant to all damage. Each Rashomon will remain summoned until the jutsu ends or its Hit points are reduced to 0. When all the Rashomon’s Hit points are reduced to 0, they are unsummoned. The design of each Rashomon is up to the user as well as the color and imagery on the wall itself.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "dee411b45d47d97ffe0fef6e", name: "Torii Seal", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1   Action", range: "120 Feet", chakra_cost: "Special (*24 Chakra*)", components: "HS, CM, CS", duration: "1 Minute", description: "You conjure a Summoning circle hundreds of feet in the sky above a target you can see within range. You conjure 3  torii that fall down from the summoning circle slamming down around and on top of the target creature. The &emsp;&emsp;&emsp;&emsp;&emsp;target creature must make a Strength saving", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "339673fcb602ac5d403e903c", name: "Earth Release: Compressed Earth", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You condense a mass of earth into a small ball, before throwing it as hard as you can. Make a ranged ninjutsu attack against a target you can see within range. On a hit, the target takes 2d8 earth damage and must make a Strength saving throw, being knocked back 10 feet and concussed on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "48f26fe4ff059864c7568d26", name: "Earth Style: Dung Pie Projectile", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You summon a small sphere made of earth release chakra that has a noxious odor. You then throw the sphere at a creature or object within range. Make a Ranged Ninjutsu Attack against the target. On a hit, the target takes 2d6 Earth damage and must succeed a Constitution saving throw gaining 1 rank of envenomed for 1 minute on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "48b9ccde360a65ace073bfb2", name: "Earth Release: Earth Palm", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You cover your hand with earth release chakra before delivering a single palm strike in the center of your opponent's mass. Make a melee ninjutsu attack against a target you can see within range. On a hit, the target takes 4d4 + your ninjutsu ability modifier earth damage and must make a Strength saving throw, being knocked back 15 feet on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "33799e0866c90f3111239d46", name: "Earth Release: Earth Spear", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a spear made out of earth to pierce through your enemies. This spear shares all the properties as a normal spear and can be used in Bukijutsu. Weapon attacks using this spear use your ninjutsu attack bonus. The spear deals 1d8 + your ninjutsu modifier in earth damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at B-Rank or higher, increase the damage by 1d8. If this jutsu is cast at S-Rank  increase the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "19f786c312ae2dc74d1346e3", name: "Earth Release: Graviton: Well", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a massive amount of purple chakra which allows you to manipulate the earth and its gravitational force. You fire a projectile of earth with a tremendous pulling force. Make a ranged ninjutsu attack, dealing 1d10 earth and 1d10 force damage and pulling the target 20 feet closer to you on a hit.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the damage of both damage types by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "7d0b6173ce85955b69ef66c3", name: "Earth Release: Muddy the Water", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 reaction, which you take when targeted by a jutsu with the Water Release keyword", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You sow fragments of rock sediment and debris to dilute the effectiveness of an enemy's water jutsu. Reduce the jutsu's damage by half.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3b04056fd48eca3c58691808", name: "Earth Release: Pillar Spring", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You focus chakra in 5-foot cube of earth you can see in range, creating a pillar that launches any willing creature above it to a point 30 feet in the air. If this jutsu would affect a non-willing creature then it must succeed a Dexterity saving throw. On a failed saving throw it is launched in the air.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the cube of affected earth by 5 feet and the distance launched in the air by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "a1e34be26245107d7a5037d6", name: "Earth Release: Aftershock", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 reaction, which you take after you cast a justu with the Earth Release keyword that deals damage", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 Round", description: "You make use of the crushing waves that still ripple in the ground from your previous jutsu. The target of your jutsu as well as any creature within 10 feet of its original damaging range must make a Strength saving throw. On a failed save, a target takes two damage dice of the previous jutsu cast and is knocked prone. On a success, the target takes half damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase damage dealt by 1 of the previous jutsu's damage dice and increase the aftershock area by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "a7e672569ba1275858b975a2", name: "Earth Style: Earth Launch", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You force the earth below you to rocket up, launching yourself into the air. You jump 60 feet in any direction of your choice. All creatures within 5 feet of your landing location must make a Constitution saving throw taking 1d8 Earth damage and being knocked back 10 feet on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, the movement range by 10 feet, and the range that enemies would be knocked back by an additional 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "b53a2fb2d5f5f406dec0b0df", name: "Earth Release: Gaia's Grasp", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "Special (*50 Chakra*)", components: "HS, CM,", duration: "1 Minute", description: "You select a 30-foot cube of unoccupied space on the ground that you can see within range. The entire surrounding area transforms into a giant hand attempting to crush all in in its palm. All creatures in the area must make a Strength saving throw. On a failed save, the target takes 4d6 earth damage and is grappled, restrained, and unable to mold chakra for the jutsu's duration. A creature grappled in this way is unable to form hand seals or use chakra seals. As an Action you can empower Gaia's Grasp increasing the DC by your Ninjutsu Casting Modifier until the start of your next turn. As an action on their turn, the restrained target can remake the saving throw. On a success, the target escapes and is no longer restrained by the hand. *Combination:* * If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 2d6.* *Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's area of effect size based on the highest Charisma Modifier within the group of casters. (+0-1No Change, +2Increase the area of effect by +10 feet, +3Increase the area of effect by +15 feet, +4Increase the area of effect by +20 feet, +5Increase the area of effect by +30 feet). *", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "99f13163070f656854564539", name: "Earth Release: Graviton: Sling", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 Minute", description: "You generate a massive amount of purple chakra which allows you to manipulate the earth and its gravitational force. You summon forth 3 large clumps of earth that statically hover above you. As part of casting this jutsu, and as a bonus action on subsequent turns, you can launch any number of clumps you have remaining at a creature within 90 feet. Once all of these clumps have been used, this jutsu ends. Make a ranged ninjutsu attack for each clump you fire. On a hit the target takes 2d6 + your Ninjutsu ability modifier in earth damage and becomes Bruised until the end of their next turn. As a reaction, on other creature's turns, you can send out all remaining clumps remaining at a creature.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of clumps created by +1.", created_at: NOW, updated_at: NOW },
  { _id: "890d6abc72831b8585aa979f", name: "Earth Release: Limestone Pillar", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You create a pillar of limestone that violently rises from the ground displacing everything around it. Each creature in a 15-foot radius, 60-foot-high cylinder centered on a point within range must make a Dexterity saving throw taking 6d6 earth damage and failing prone on a failed save. Pass or fail, all creatures are pushed to the edge of this cylinder. This pillar is an earthen construct and crumbles into dust after 1 minute.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 radius by 5 feet, and damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "680424d7f3d481f522a25cf4", name: "Earth Release: Stalactite Spear", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You create a column of earth before stomping the ground and kicking it towards your target. Make a ranged ninjutsu attack dealing 3d12 earth damage and creating a 10-foot radius sphere of difficult terrain on the point of contact. This stalactite spear remains as an earthen construct and crumbles into dust after 1 minute.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "21e7758b13753dfc934b41f9", name: "Earth Release: Terrashards", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 reaction, which you take when you or a creature within range would take damage", range: "40 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "Slamming your open palm toward the ground, you strike each of your fingers into the earth to mold a series of 5-foot tall, 5-foot wide, and 1-foot thick walls to shield you and your allies. In addition to yourself, choose up to four creatures in range. Each wall grants half cover and acts as an earthen construct occupying a space of your choice within 5 feet of all selected creatures, appearing right before an attack or jutsu would hit or harm it. It has 2d6 Hit points, Resistance to bludgeoning, piercing, slashing and Cold damage and vulnerability to Lightning damage. If the damage the wall receives would exceed its hit points, when you initially conjure it. Any remaining damage is dealt as normal to targets and the wall is destroyed. The wall acts as a structure otherwise. It does not dissolve or vanish instead remaining until destroyed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the hit points of each wall by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "c3f5a4ca862af07467b36414", name: "Earth Release: Third Eye", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "10 Feet", chakra_cost: "8 Chakra", components: "CM, HS", duration: "10 Minutes", description: "You form a small sphere out of mud or sand, before pouring chakra into it to grant it the appearance of an eye. You may use your bonus action to have the eye move up to 20 feet. Your earthen eye will disintegrate if it goes more than 100 feet away from you. Creatures must pass a perception skill check against your Ninjutsu save DC to be able to see the earthen Eye. While this jutsu is active you are able to see what the earthen eye is able to see.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of the jutsu and the range before the eye disintegrates by 50 feet.", created_at: NOW, updated_at: NOW },
  { _id: "ce8279ec0ea7c5cffaa3abad", name: "Earth Release: Buckshot", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a massive amount of small pebbles before firing them of in front of you. All creatures within range must make a Dexterity saving throw or take 6d8 earth damage or half as much on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "3df8b6a05ae1c7dc4812b480", name: "Earth Release: Cascade", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You create a pillar of condensed suffering in the form of falling rocks on your enemies, in the hope they all die. Choose a point you can see within range. All creatures within a 15-foot-radius, 60-foot-high cylinder centered on that point must make a Dexterity saving throw or take 6d6 earth damage and be knocked prone on a failed save. On a successful save a creature takes half as much damage and no additional effects.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "d876c1d57f2f83e6c7a3ab11", name: "Earth Release: Graviton: Shower", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a massive amount of purple chakra which allows you to manipulate the earth and its gravitational force. You form a highly condensed sphere of earth at a point above a creature you select within 60 feet, which explodes into hundreds of small comets of earth. The target creature must make a Dexterity saving throw, taking 4d8 earth and 4d8 force damage, being knocked prone, dazed, and gaining 2 ranks of Bruised on a failed save, or taking half as much damage and gaining only 1 rank of Bruised and no further effects on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and either increase the damage of both damage types by 1d8 or the number of targets by +1 (Pick one).", created_at: NOW, updated_at: NOW },
  { _id: "f207a490ce80579d3c6ddf67", name: "Earth Release: Iron Maiden", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create 6 giant spears made of earth surrounding your opponent, before collapsing them all onto one point. The target must make a Dexterity saving throw taking 6d12 damage and being restrained on a failed save, or half as much damage and no additional effects on a successful save. Creatures restrained by this jutsu cannot make hand signs. A creature restrained by this jutsu makes a Strength saving throw at the end of each of their turns to attempt to break out of this jutsu, escaping on a success.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "fb56132b43c305d8253c048b", name: "Earth Release: Multi-Layered Earth-Style Wall", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action, 1 Reaction, which you take when you would take damage.", range: "60 feet", chakra_cost: "Special (*77 Chakra*)", components: "HS, CM", duration: "10 Minutes", description: "You convert chakra into earth and spit it from your mouth, or use earth that’s already present to quickly generate a  series of 5 large walls. The walls take up an area 25 Feet Thick, 60 Feet Long and 50 Feet High and if the walls are generated within a creature's space, the creature is pushed to either side of the walls (Your choice). The walls can have any designs or shape you decide. The Walls AC is equal to your Ninjutsu Save DC and each wall has 6d8 Hit Points. The walls have vulnerable to Lightning Damage, resistant to cold damage and counts as an Earthen Construct. *Combination:* *If this jutsu is cast as a Combination jutsu with 2 or more casters increase the hp of each wall by 2d8.* *Any creature who assists in casting this jutsu as a combination jutsu increases the damage based on the highest Charisma Modifier within the group of casters. (+0- 1No Change, +2+2 to the Walls AC, +3+3 to the Walls AC, +4+4 to the Walls AC, +5+5 to the Walls AC and the wall instead has resistance to all damage types excluding Lightning and Psychic damage).*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ac5de493e9282e19d220bf40", name: "Earth Release: Concrete Rings", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "17 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create 8 rotating rings of earth around your arms that allow you to utilize a new fighting style focused on close range combat. Each ring can only be used once and you may recast this jutsu to regain the lost rings. While wielding these rings you gain the following options using the corresponding actions; ActionMake a melee ninjutsu attack dealing 5d8 + your ninjutsu ability modifier in earth damage and the target becoming dazed on a hit. ActionMake 2 ranged ninjutsu attacks against creatures within 30 feet. You can fire at at the same target or different ones. Dealing 3d8 + your ninjutsu ability modifier in earth damage on each successful hit. Bonus ActionMake a ranged ninjutsu attack against a creature within 30 feet. On a hit, the creature is restrained and cannot make hand signs. A restrained creature can make a Strength saving throw at the start of their turn to break out. Bonus ActionMake a melee ninjutsu attack dealing 2d8 + your ninjutsu ability modifier in earth damage and knocking them back 15 feet. ReactionWhen you would take damage that isn't psychic you can use any number of rings you have left to protect yourself. Each ring reduces the damage you take by 2d8. If you reduce the damage to 0 this way, you suffer no effects that would trigger if you failed the save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the number of rings created increases by 2.", created_at: NOW, updated_at: NOW },
  { _id: "9105ef74036fb64e2493c380", name: "Earth Release: Desert Suspension", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1   Action", range: "Self", chakra_cost: "20 Chakra", components: "CM, HS", duration: "Concentration, 1 Minute", description: "You create a platform of sand, mud, or rock that you suspend into the air that you use grant yourself a fly speed of 45 feet. Alternatively, you can cast this jutsu as a  Full turn action. If you do so you select 2 allied creatures within 60 feet of you commanding the earth below them to take flight. The allied creatures you selected gain a fly speed of 45. All creatures granted a fly speed by this jutsu can also hover.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3. Select 2 allied creatures within 60 feet of you. You command the earth below them forcing it to take flight. The allied creatures you selected gain a fly speed of 45.", created_at: NOW, updated_at: NOW },
  { _id: "2fa18edc0ac76f54843d8fd1", name: "Earth Release: Earth Fortress", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Reaction, which you take when you or a creature you can see within range are targeted for an attack, would take damage, or make a Strength, Constitution or Dexterity saving throw", range: "60 Feet (30-foot cube)", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You quickly create a fortress of earth that is designed to completely protect attacks from any manner of harm. This fortress takes up a 30-foot cube and has a design of your choice. If fortress is summoned in a creature's space the fortress has the creature is pushed to either side of the fortress (Your choice). The fortress can have any designs or shape you decide. The fortress' AC is equal to your Ninjutsu Save DC and has 12d10 hit points. This fortress is vulnerable to Lightning Damage, resistant to bludgeoning, piercing, slashing and cold damage and counts as an Earthen Construct. Any exccess damage does not pass over to any creatures inside as the fortress is completely destroyed.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the hit points by 2d10.", created_at: NOW, updated_at: NOW },
  { _id: "83cacd3caa3caf0e49c7f32c", name: "Earth Release: Graviton: Collapse", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self (60-foot cone)", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a massive amount of purple chakra which allows you to manipulate the earth and its gravitational force. You create a massive orb of earth in front of you, which collapses into a small void and sends out large orbs of gravitional force at targets within a 60-foot cone. Each creature within range of your choice must make a Dexterity saving throw, taking 12d6 force damage, being pulled towards 30 feet towards you, and becoming Weakened and Bruised on a failed save, or half as much damage and only being moved 10 feet towards you on  a successful save. If a creature affected by this jutsu was affected by an Earth Release Ninjutsu with *Gravition* in the name that you cast within the previous round, that was not this jutsu, the make their saving throw with a -1d6 penalty.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the damage of this jutsu by 2d6 and the length of the cone by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "2d5bbda24ed10d2fec224eb9", name: "Earth Release: Particle Assimilation Cone", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "30-feet Cone", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You form a 30-foot cone by using chakra to generate molecule sized particles. Anyone in the cone will begin to be deconstructed on a molecular level. Creatures in its path must succeed a Dexterity saving throw. On a failure a creature takes 12d6 force damage. If a creature is reduced to less than ½ of their hit points. The user decides on which appendage the target creature lost. (Arm or Leg). If a creature is reduced to 0 hit points, they are turned to dust and are immediately killed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4f0af2c59399ae836b6faeae", name: "Earth Release: Soul Echo: Crystalize (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "16 Chakra", components: "CM, CS, W (Any)", duration: "Concentration, up to 1 Minute", description: "You begin to channel earth release chakra into your palm as you begin to think of the day where the fighting ends. Memories of battle, feelings of resolve and perseverance. The echoes of your soul empower this jutsu as you bathe the weapon in your chakra. For the duration, your weapon is surrounded  with hard rock like stalagmites,  gaining the following benefits; - Your weapon's damage is increased by your Ninjutsu ability modifier, in Earth damage. - At the start of each of your turns, you gain a number of temporary hit points equal to your weapon's damage (If your weapon's damage die is greater than 2 dice, you only roll 2 die's worth). While you have these temporary hit points, you gain a +2 bonus to Strength and Constitution saving throws. - For hit you land with your weapon, you ignore 3 DR. This bonus can stack up to two times against a single target with consecutive attacks (up to ignore 9 DR total). This ability resets to 0 at the start of your next turn. - Once per turn, when you cast a Jutsu with the Earth Release keyword, you may add your weapon as a component. If you do, the jutsu's area of effect is increase by 5 feet in all directions (if applicable), its range is increased by +15 feet, and the jutsu ignores all temporary hit points. Jutsu that would already use your weapon as a component always gain the benefits, disregarding the once per turn limitation. You cannot lose concentration of this jutsu as the result of failing a concentration check and it does not cost chakra to maintain. This jutsu ends early if you let go of your weapon.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "06e93d98281d717a05e641f1", name: "Earth Release: Quartz Bullet", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "17 Chakra", components: "HS, CM", duration: "Instant", description: "You create a chunk of quartz and fire it at your enemy at blistering speed. Make a ranged ninjutsu attack dealing 7d12 earth damage and forcing the creature to make a Strength saving throw. On a failed save the creature is knocked prone and gains a rank of bruised.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "82c057913bfdea642b3bced4", name: "Earth Release: Air Sand Protective Ceiling", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when you or a creature within range", range: "300 Feet", chakra_cost: "30 Chakra", components: "CM, HS", duration: "10 Minutes", description: "You summon a grand pillar of earth, mud, or sand that is 10 feet wide, 10 feet long, and 50 feet tall to support a massive shield of the same material of the pillar that that has a radius of 100 feet.  The structure can have any shape of your choice. The structure's AC is equal to your Ninjutsu Save DC and has 30d8 Hit Points. This structure is  immune to cold damage and counts as an Earthen Construct.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "61bfb0d9bb3d408118e00b80", name: "Earth Release: Compressed Rock Bullets", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Action", range: "Self (120-foot cone)", chakra_cost: "32 Chakra", components: "HS, CM", duration: "Instant", description: "You create an innumerable amount of boulders before crushing them down into pebbles and firing them in a cone destroying everything in its path. Each creature in a 120-foot cone must make a Dexterity saving throw, taking 18d8 earth damage and being dazed for the next minute on a failed save, or half as much damage and no additional effects on a successful one. This jutsu does double damage to structures, constructs and objects.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "27780cac36788ca1964d37ba", name: "Earth Release: Earth Golem", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1  Action", range: "Self", chakra_cost: "30 Chakra", components: "CM, HS", duration: "Concentration, up to 1 minute", description: "You conjure a ginormous stone construct made of earth, dust, soil, and sand forming a gargantuan goldem that acts at the end of your turn (no action required), and uses your Ninjutsu attack bonus and  Save DC for effects that require it. Additionally, if you cast Earth ReleaseStone Dragon while this jutsu is active, instead of the normal effects of Stone Dragon occuring, you can choose for the following to happen; The Stone Dragon grows out of your Earth Golem and wraps its body around it, granting the Earth Goldem 125 Temporary Hit Points and the following new attack; As part of casting Earth ReleaseEarth Golem, you can spend 5 chakra to cast Earth ReleaseStone Dragon as a bonus action, paying its chakra cost as normal. Dust Breath (Recharge 7-8)The Dragon exhales dust in a 30- foot cone. Each creature in that cone must make a Dexterity saving throw, taking 66 (12d10) Earth damage on a failed save, or half as much damage on a successful one. ___ >", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4c7e0cb614ceeca67d26e55d", name: "Earth Release: Earthquake", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Full Turn Action", range: "500 Feet", chakra_cost: "27 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a seismic disturbance at a point on the ground that you can see within range. For the duration, an intense tremor rips through the ground in a 100-foot-radius circle centered on that point and shakes creatures and structures in contact with the ground in that area. For the duration, you do not spend chakra to maintain this jutsu, instead you must spend a bonus action on subsequent turns to maintain it. The ground in the area becomes difficult terrain and creatures cannot dash while within this area. When you cast this jutsu and at the end of each turn you spend concentrating on it, each creature on the ground in the area must make a Dexterity saving throw. On a failed save, the creature is knocked prone. Each creature on the ground must make a Constitution saving throw, being concussed on a failed save. *Fissures.* Fissures open throughout the jutsu's area at the start of your next turn after you cast the jutsu. A total of 1d6 such fissures open in locations chosen by the player. Each fissure is 2d10 × 10 feet deep, 20 feet wide, and extends from one edge of the jutsu's area to the opposite side. A creature standing on a spot where a fissure opens must succeed on a Dexterity saving throw or fall in. A creature that successfully saves moves with the fissure's edge as it opens. A fissure that opens beneath a structure causes it to automatically collapse (see below). *Structures.* The tremor deals 60 bludgeoning damage to any structure in contact with the ground in the area when you cast the jutsu and at the start of each of your turns until the jutsu ends. If a structure drops to 0 hit points, it collapses and potentially damages nearby creatures. A creature within half the distance of a structure's height must make a Dexterity saving throw. On a failed save, the creature takes 10d6 bludgeoning damage, is knocked prone, and is buried in the rubble, requiring a Strength (Athletics) check vs your Ninjutsu Save DC as an action to escape. On a successful save, the creature takes half as much damage and doesn't fall prone or become buried.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c066fdcd06e0c9841b10c4c6", name: "Earth Release: Graviton: Meteorite", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Full Turn Action", range: "1 Mile (300-foot radius)", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a massive amount of purple chakra which allows you to manipulate the earth and its gravitational force. Throughout the sky above, you form a gargantuan ball of pure gravity, which begins sucking up earthen material and forming large meteors all around itself. These meteors then rain down upon a 300-foot radius, ravaging the land and bringing forth pure destruction. Select a number of creatures within 120 feet equal to your proficiency bonus. You form a small aegis of gravity around them, allowing them to avoid this jutsu's effects. All creatures within range must make a Dexterity saving throw, taking 15d12 damage, gaining 3 ranks of Bruised, being knocked prone, becoming dazed,  and blown back 60 feet in any direction of your choosing on a failed save. Creatures who fail their saving throw by 10 or more also become Staggered for 1 minute. On a successful save, creatures take half as much damage and no further effects, as they are able to dodge and weave through most of the metoerites. At the conclusion of this jutsu, the area affected permenently becomes difficult terrain and for 1 minute, the area is magnfied with residual gravitional force, reducing the cost of Earth Release Ninjutsu with *Graviton* in the name by -2.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "20db8c9e8c62d7bfca8c7fd9", name: "Earth Release: Gravition: Extinction", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Full Turn Action", range: "120 feet", chakra_cost: "Special *(25 Chakra)*", components: "HS, CM, CS", duration: "Concentration, up to 1 minute", description: "As part of the requirements for casting this jutsu, you must have the following Earth ReleaseGraviton jutsu on your jutsu known list (Well, Sling, Shower, Collapse, and Meteorite). You generate a massive amount of purple chakra which allows you to manipulate the earth and its gravitational force. You generate a massive void at a space you can see, gathering forth various different earthen materials, or just about anything that you seem to be beneficial. You collect these components and create a Gargantuan construct known as a *Falling Star Beast*, which you control. This construct uses your Ninjutsu attack bonus and Save DC for effects that require it. The Falling Star Beast rolls its own initative as it has its own turns, using your Ninjutsu ability modifier + proficiency as its initative bonus.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a09cdebdc4281065ba96f22b", name: "Particle Style: Particle Assimilation Sphere", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "587205fc5e2f018201761d63"], elements: [], casting_time: "1 Full Turn Action", range: "90 feet", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You raise your hand high and form a small sphere just above your palm using chakra to generate molecule sized earth particles, which glow white. The strongest of all particle techniques, this sphere, once fully charged, with utterally atomize an opponent on a sub-atomic level. You do not spend chakra to maintain concentration of this jutsu. Starting from your next turn after casting this jutsu, make a ranged Ninjutsu attack at advantage as you throw the sphere at a target within range. This sphere travels in a straight line starting from you, and as such, if there is a creature in between yourself and the target caught within this line, that creature instead becomes the target of this jutsu. On a hit, the sphere gently enters the target's body before erupting violently, dealing 25d12 Force damage, which cannot be reduced. If a creature is reduced to less than ½ of their hit points, the user decides on which appendage the target creature lost. (Arm or Leg). If a creature is reduced to 0 hit points, they are turned to dust and are immediately killed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a0c19aadc4d3f6cf84ac6c3a", name: "Earth Release: Tectonic Movement", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["587205fc5e2f018201761d63", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "10 Minutes.", range: "100 Miles", chakra_cost: "Special (*138 Chakra*)", components: "HS, CM", duration: "10 Minutes", description: "You mold and send Earth Release Chakra deep into the earth directly into one of the planets tectonic plates. You and all casters designate a single target you can see within range. Upon casting the jutsu you force the tectonic plate to move causing a massive earth quake to below your target. You force all Creatures, objects and Structures within 1 mile of your target including your target to make a Constitution saving throw at disadvantage, taking 50d10 earth damage  on a failed save and hald as much on a successful save. Structures and Objects take double damage. Creatures who failed the constitution saving throw are knocked prone and gain the Dazed condition for 10 minutes. *Combination:* * If this jutsu is cast as a Combination jutsu with 2 or more casters reduce the cost by -2.* *Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's offensive abilities based on the highest Charisma Modifier within the group of casters. (+0-1No Change, +2Increase damage by 5d10  +3Increase damage by 10d10 +4Increase the damage by 15d10. +5Increase damage  by 25d10.*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "111f0855cadd0b4077f7e047", name: "Wind Release: Erupting Gale", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30-foot cone)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You create a powerful gust of wind in front of you, that blows back your foes. Each creature in a 30-foot cone must make a Strength saving throw being knocked back 30 feet on a failed save, or half the distance on a successful one. Creatures who collide with a solid object, have their movement stopped, taking falling damage equal to the distance they would have fallen.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the length of the cone and the length of the knockback by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "e1c636844dc4ae0cb639279a", name: "Wind Release: Galeful Strikes", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "Wind chakra flows freely around your body, guiding your strikes with speed and precision. Your unarmed and melee taijutsu attacks gain a 1d4 bonus to attack and damage rolls. The extra damage is Wind damage. When you take the attack action, the first attack you make against a creature cannot be reacted to, and you gain a +10 bonus to your speed which lasts until the end of the turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5ef0be831548f4a5c9054e4e", name: "Wind Release: Inverted Gale Palm", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "Instant", description: "You clasp your hands together coating your open palms in a powerful Vaccum. Make a ranged ninjutsu attack on a creature or object in range. On a hit they take 3d6 Wind Damage and must make a Strength saving throw, on a failed save they are pulled towards you and end their movement within 5 feet of you.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d6", created_at: NOW, updated_at: NOW },
  { _id: "16eedafef34ea832db6078aa", name: "Wind Release: Sky Drop", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action or Reaction", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "This jutsu must target an airborne creature. Target creature within must succeed a Strength saving throw against your Ninjutsu Save DC at disadvantage or be knocked back down with a strong force of wind, taking double the usual fall damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range of the jutsu by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "8d55849c1026c3cf161e7180", name: "Wind Release: Vortex", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "Choose a space within range, You create a small mote of wind that attempts to pull in all things.  Each creature within 15-feet of the mote must make a Strength saving throw or be pulled 10 feet towards it. A creature can willingly fail this saving throw.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. When cast at C-Rank, you can pull a creature up to 15 feet towards the vortex. When cast at B-Rank, you can create a second vortex within range. If a creature is in the radius of multiple vortexes, they are pulled towards the closest mote. When cast at A-Rank, All creatures within 20 feet of the vortex must now do the save throw. When cast at S-Rank, you can create a third vortex within range.", created_at: NOW, updated_at: NOW },
  { _id: "8615008cfb6b9fc5859d3d76", name: "Wind Release: Air Ball", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration up to 1 minute", description: "You form a ball of air below you and sit on top of it. While sitting on top of the ball your  movement speed is doubled, you have advantage on Dexterity saving throws, you gain a +2 bonus to AC, can dash or disengage as a bonus action, and you gain a climbing speed equal to your normal movement speed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e8cbf0a570bbcdae2ac3a759", name: "Wind Release: Deflective Gust", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Reaction, which you take when you are targeted by an attack or jutsu", range: "Self", chakra_cost: "7 Chakra", components: "CM", duration: "Instant", description: "You swiftly arc a powerful gust to deflect an incoming attack. Increase your AC by half of 1d6 (minimum 1). If the attack still hits you after this increase then you halve its damage. If this would cause the attack to miss you instead, you can redirect that attack to a creature within 15 feet, disarming the attacker if it was a melee weapon attack. The redirected target must succeed a Dexterity saving throw or suffer half the damage of the attack.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and you gain a +1 bonus to AC.", created_at: NOW, updated_at: NOW },
  { _id: "7d2ea5e5364ed6d42e99aaf0", name: "Wind Release: Dusty Whirlwind", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (20-foot cone)", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a powerful wind within your palm and send it spiraling outwards towards creatures within a 20-foot cone from you. As your wind travels, it picks up dust, dirt, and other loose debris, making the wind denser. Creatures who are in the affected range must make a Wisdom saving throw, becoming blinded until the end of their next turn on failure or no effects on a success. The affected creatures must also make a strength saving throw, being knocked back 30 feet on a failed save. This save is made at disadvantage if they failed their initial save. On a successful save, they are only pushed back 5 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c5aaeb0290868b1fdae2937a", name: "Wind Release: Erosion Stream", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (60-foot line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You release a precision stream of wind so powerful it can reduce stone to dust in an instant. The wind stream is a 100 feet long and 5 foot wide line that blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 8d8 Wind damage on a failed save, or half as much damage on a successful one. The stream of wind deals double damage to objects, structures, and earthen constructs, and any temporary hit points granted by jutsu with the Earth Release keyword.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage dealt by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "4ebe645bb75f01389facfa55", name: "Wind Release: Galewind Constitution", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM", duration: "1 Minute", description: "You generate an orb of soothing wind and press it against your body, causing an aura of healing wind to surround you. If you possess the bleeding and/or chilled conditions, they are immediately removed. For the duration, you recover 1d4+1 hit points at the start of each of your turns, and have advantage on saving throws to resist the bleeding and chilled conditions. Additionally, effects that would give you either listed condition without a saving throw, instead enable you to make a Constitution saving throw, resisting gaining the condition(s) on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "2bb23e0ad42514d7b29a2551", name: "Wind Release: Howling Gale", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You imbue the air passing through your vocal chords with wind chakra to release a maddening screech. All creatures within a 30-foot radius of you that can hear you must make a Constitution saving throw. On a failed save, a target takes 3d8 Wind damage + 2d6 Force damage and becomes defeaned for 1 minute. On a successful save, a target takes half damage. If this save is failed by 5 or more, a target also gains 1 rank of fear for 1 minute. A target can repeat its saving throw at the end of each of its turns, ending either effect on itself with a success.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage dealt by 1d8 Wind and 1d6 Force respectively.", created_at: NOW, updated_at: NOW },
  { _id: "3d8291047a1e693b3676a30a", name: "Wind Release: Pulse", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1  Action", range: "30 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You create a massive wave of wind, unleashing it in a 30-foot cone, and decide whether the force pulls or pushes creatures and objects. Each creature in that cone must make a Constitution saving throw. A creature takes 4d6 wind damage on a failed save, or half as much damage on a successful one. Each creature that fails the save is either pulled 15 feet toward you or pushed 15 feet away from you, depending on the choice you made for the jutsu. In addition, unsecured objects that are completely within the cone are likewise pulled or pushed 15 feet.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d6, and the distance pulled or pushed by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "676d551df5ba394306d8b519", name: "Wind Release: Severing Wind", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "You create two rotating discs of wind that whir a distinct sound, almost calming the heat of battle. Make two ranged ninjutsu attacks. You can target one or more creatures. On a hit, the target creature takes 2d6 + your ninjutsu ability modifier wind damage and gains 1 rank of bleed.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "55220e419090eefe7584dc26", name: "Wind Release: Air Claw", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (60-foot cone)", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You coat your hand in wind chakra in the shape of claws and then swipe your hand in a wide arc, devastating the battlefield.  Each creature in a 60-foot cone must make a Dexterity saving throw or take 9d4 wind damage and gain 1 rank of lacerated on a failed save, or half as much damage and no additional effects on a successful save. This jutsu cuts up the ground in its wake, leaving an area of difficult terrain.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage die by 1 step. (d4>d6>d8>d10>d12)", created_at: NOW, updated_at: NOW },
  { _id: "c46e6ed4335aa2e181416af3", name: "Wind Release: Beast Claw", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You bring your hand behind you generating a torrent of wind before slashing upward, sending three vertical slashes of wind. You create 3 30-foot long, 5-foot wide lines in wind chakra from 180° in front of you. These lines may go in any direction you like along the ground, but they cannot intersect and must have 5 feet of space between them after they are launched from the space in front of you. Each creature within range of a line must make a Dexterity saving throw, taking 7d8 in wind damage and becoming Lacerated on a failed save, or half as much damage and only 1 rank of bleeding on a success. The affected area becomes difficult terrain.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the damage die by 1 step (d8<d10<d12).", created_at: NOW, updated_at: NOW },
  { _id: "36e199d638b07af0e7bceb6d", name: "Wind Release: Heavy Blow", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1  Action", range: "Self (60-Foot line)", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You let out a strong highly condensed line of air from the palm of your hand. All creatures in a 5-foot wide  60-foot-long line must succeed a Dexterity saving throw.  Taking 8d6 Wind damage on a failed save, or half as much on a successful one.  Additionally, You may choose to move yourself backwards up to 30 feet as the strength of the wind is enough to carry you backwards.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, increase the damage by 1d6, and feet you may move yourself backwards is increased by 10.", created_at: NOW, updated_at: NOW },
  { _id: "bde474fed43b68c553e0dd3e", name: "Wind Release: Skyscraping Burst", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "60 Feet", chakra_cost: "11 Chakra", components: "HS, CM", duration: "Instant", description: "You flick your wrist and shoot a burst of wind from under your enemies. Each creature in a 30-foot-radius, 60-foot-high cylinder centered on that point must make a Strength saving throw being knocked up 60 feet, taking falling damage and being knocked prone on a failed save. A creature who fails the initial saving throw must also make a Constitution saving throw becoming weakened until the end of their next turn on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "571227640be0fc4dc4f37d46", name: "Wind Release: Wind Clone", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "dc2837c0a3446d09da7edaf6"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "Special (12 Chakra)", components: "HS, CM", duration: "Concentration, up to 10 minutes", description: "You conjure a clone made of wind similar to the Shadow Clone Technique. *Wind Clones* have no discernable weight. You can create up to three *Wind Clones* when casting this jutsu, each costing 12 chakra to conjure. *Wind Clones* can cast ninjutsu with the *Wind Release* keyword that you know of C-Rank, following normal Clone keyword restrictions. *Wind Clones* have immunity to Genjutsu, psychic, and poison damage, resistance to piercing, wind, and lightning damage, and vulnerability to fire damage. *Wind Clones* have a flying speed equal to their walking speed. Additionally, if a damaging jutsu the *Wind Clone* casts would use a damage die larger than a d6, the damage die the clone uses becomes a d8 instead. If a *Wind Clone* uses a weapon or unarmed attack, regardless of the weapon the clone uses, it deals 1d8 wind damage. If a *Wind Clone* moves through an area of dust, vapor, or gas, you can choose whether they disperse it or disseminate it. Dispersing it leaves an open area of the clone's size within the particulate's space, safe for others to move through until the end of your next turn. Disseminating it brings the particulate out behind the clone, increasing its size in a line behind them until they stop. This line is the same width as the clone's size. If a *Wind Clone* is destroyed or unsummoned after disseminating a particulate, the same particulate is blasted out in a 5-foot radius around the clone. If a *Wind Clone* casts a jutsu that requires more than 1 attack roll upon casting, it only makes one attack. If multiple *Wind Clones* attack the same creature, you do not make multiple attack rolls. You instead choose a lead clone and it gains a +1d8 bonus to its damage roll(s), for each additional clone that is aiding it.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3. If this jutsu is cast at S-Rank, increase the rank of jutsu water clones can cast to B-Rank.", created_at: NOW, updated_at: NOW },
  { _id: "697e68ca8727d821a4243d81", name: "Wind Release: Bladestorm", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You coalesce 5 kunai made of wind, that circle around your body. You cannot lose concentration of this jutsu as a result of damage. You can use an action to shoot two kunai toward the same or different creatures within 90 Feet of you. When you do, make a ranged ninjutsu attack. On a hit the target takes 6d4 + your ninjutsu ability modifier in wind damage. This jutsu scores a critical hit on 19-20. Whether you hit or miss you spend the kunais vanishes after use. The jutsu ends early if you expend all your kunai. As a full turn action, you can shoot all your kunai at a single creature", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "8b5c1f7ec397f980cfce889c", name: "Wind Release: Dark Moon", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "120 feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You form a large sphere of frigid air that resembles the moon on a misty dark night. Make a ranged Ninjutsu attack. On a hit, the target takes 14d6 wind damage and must make a Strength saving throw. This jutsu overwhelms the target with freezing wind, for every 6 rolled on this jutsu's damage dice, the target suffers a -1 penalty to their strength saving throw. On a failed save, the target gains 2 ranks of Weakened and Chilled. *Swirl.* Creatures who would fail their saving throw, spreads all *Elemental* conditions currently affecting them around to all creatures, excluding the caster within 5 feet of them. Hostile creatures within 5 feet of the failing one gains 1 rank of all elemental conditions currently affecting it.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the range by 30 feet, and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "a5da260089e06598d02516e4", name: "Wind Release: Liger Fang", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "90 Feet (30-foot cone)", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You kick out an invisible wave of wind that rides the air currents before it expands and cuts everything around it like a fang. Choose a point you can see within range to send the fang to. A jarring gash of wind creates a cone in that space and all creatures within a 30-foot cone centered on that point must make a Dexterity saving throw or take 6d12 wind damage and gain 3 ranks of lacerated on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "e81368a086b42b65ec4add21", name: "Wind Release: Sonic Snap", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (5-Foot radius Sphere)", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Instant", description: "You snap your fingers and amplify the vibrations in the air over a hundred times to attempt to overload the senses. All creatures in range other than you must make a Constitution saving throw or become incapacitated, deafened, and gain 5 ranks of bleeding on a failed save, as you rupture their eardrums. A creature who fails this save is incapacitated for 1 minute, they can remake the saving throw at the end of each of their turns removing the effect on a success. The snap can be heard up to a mile away. A creature is deafened until they are targeted by a jutsu that removes deafened at A-Rank or higher.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "7ac436d4d6e9202b1d5eb4d0", name: "Wind Release: Soul Echo: Gale (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "16 Chakra", components: "CM, CS, W (Any)", duration: "Concentration, up to 1 Minute", description: "You begin to channel wind release chakra within your palm as you begin to think of your desires and aspirations. Visions of freedom, a future where you and your allies can rest in peace. The echoes of your soul empower this jutsu as you bathe the weapon in your chakra. For the duration, your weapon is surrounded by spiraling green winds and gains the following benefits; - Your weapon's damage is increased by your Ninjutsu ability modifier, in Wind damage. - On a hit with your weapon, the target must succeed a Dexterity saving throw or have their AC reduced  by half the result of a 1d4 until the start of their next turn (Min. 1). Once the target fails, they no longer make these saving throws until the start of their next turn. - On each successful hit with your weapon, your attack bonus when using the weapon increases by +1, up to a maximum of +2. This resets at the end of the current turn. - You gain a +2 bonus to Dexterity skill checks and saving throws. You cannot lose concentration of this jutsu as the result of failing a concentration check and it does not cost chakra to maintain. This jutsu ends early if you let go of your weapon.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "eeb9cb64031c2231c7227b90", name: "Wind Release: Vacuum Prison", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a cube void of air around a creature, depraving them of any ways to breathe. Choose a creature you can see within range. When you cast this jutsu, that creature is surrounded by a wall of air, which can suspend them midair. A creature inside this prison has a movement speed of 0, cannot speak, and cannot make hand seals. Creatures trapped inside this prison cannot target creatures outside of it and vice versa. At the start of each of their turns they must make a Constitution saving throw, gaining 1 rank of weakened and losing concentration on all jutsu they were concentrating on, on a failed save. All ranks of weakened gained by this jutsu are removed when this jutsu ends. If a creature inside or out of the prison attempts to attack the prison they take must make a Dexterity saving throw or take 8d8 wind damage. This prison has 100 hit points, has an AC equal to your Ninjutsu save DC, and is resistant to bludgeoning, piercing, and slashing damage, and has immunity to wind and lightning damage and vulnerability to fire damage. A creature who does not need to breath is immune to the effects of being trapped inside the prison.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e8e7a0ca386ce655cd6b023f", name: "Wind Release: Wind Scythe", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "10 Foot Cone", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You mold wind release chakra into the shape of a scythe before quickly swiping out attacking all within range. All creatures in a 10-foot cone must make a Dexterity saving throw, taking 8d10 Wind damage on a failed save and gaining 3 ranks of bleeding, or half as much damage on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage by 2d10, and increase the ranks of bleed by +1.", created_at: NOW, updated_at: NOW },
  { _id: "32622a52c75901276dfd5f8f", name: "Wind Release: Gale Explosion", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "be25cd280a254892a04b3a6b"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "35 Chakra", components: "CM, M", duration: "Instant", description: "You take in a large gulp of air, allowing wind chakra to flow throughout your entire body, elevating your strength for your next strike. Make a melee ninjutsu or taijutsu attack against a creature within range. On the first attack, you punch a creature straight in its chest with such immense force that it creates a shockwave of pure wind chakra. The creature takes your unarmed damage + 4d10 + your Ninjutsu modifier in force damage, and each creature within 15-feet other than yourself and the triggering creature must make a Dexterity saving throw against your Ninjutsu or Taijutsu Save DC, whichever is higher. On a failed save, creatures take half the damage you dealt to the triggering creature as force damage. If your first attack successfully hit, you make a second attack, kicking the creature 60 feet into the air and dealing your unarmed damage + 3d10 + your Ninjutsu ability modifier in Bludgeoning damage. If both attacks of this jutsu were successful, you raise both your arms in with a loud battle cry, expel the wind chakra within your body and launch it at the creature, surrounding them in a 30-foot sphere of wind before exploding in a spectacular fashion. The creature must make a Constitution saving throw, taking 15d4 Wind damage and gaining 5 ranks &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;of Bleeding and 1 rank of Exhaustion until the end of &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;their next turn on a failed save, or half as much &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; damage and only 2 ranks of bleeding on a &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;failed save. The pressure of the wind &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;surrounding the creature slows their &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;descent, causing them not to take fall &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "038b659f60e310bd78bea901", name: "Wind Release: Rasenshuriken", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["be25cd280a254892a04b3a6b", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "35 Chakra", components: "CM", duration: "Instant", description: "As part of the requirements for casting this jutsu you must have Rasengan on your jutsu known list. You create a Rasengan before adding a rotating wind of chakra shaped like a shuriken that can even shred cells. Make a ranged ninjutsu attack against a target you can see within range, dealing 18d12 Force damage on a hit. A creature who is targeted by this jutsu, cannot gain the benefit of bonuses to AC or Temporary hit points as a result of Armor, Jutsu, features, or traits against you until the conclusion of this jutsu. Hit or miss, all creatures, except the original target, in a 15-foot radius sphere centered on the original target must make a Dexterity saving throw, taking half the damage of this jutsu as well on a failed save. A creature who is reduced to 0 hit points by this jutsu instantly dies and cannot be revived as their chakra network is destroyed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d5d1b0d2a543591a40666d4c", name: "Wind Release: Vacuum Grenade", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "be25cd280a254892a04b3a6b", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "500 feet (100-foot sphere)", chakra_cost: "30 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You take a small object such as a rock and begin infusing your wind release chakra into it. You fill the object with so much chakra that the slightest touch could cause it to explode in massive explosion. Choose a space within 500 feet. You hurl the object at this space. The object then explodes, sending a wild burst of wind chakra and shrapnel in 100-foot sphere. Each creature within range must make a Strength saving throw, taking 7d10 Bludgeoning and 7d10 Wind damage, and become weakened, as they are bombarded with debris and a force of wind so strong that it causes the air to be ripped from their lungs. Creatures that take more than 60 damage from this jutsu also become Slowed. Creatures that reach 0 hit points as a result of this jutsu are immediately killed as their lungs are torn to shreds. Structures, Objects, and Constructs take triple damage from this jutsu, crumbling to dust if they reach 0 hit points as the air is sucked out of them.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "27be17099129786ed67db6b6", name: "Fire Release: Crimson Despair", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (5-foot-Radius)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You encircle yourself in a rotating ring of flames to deter anyone from getting too close. Creatures caught in the radius when this jutsu is cast or begins their turns there must make a Dexterity saving throw or take 1d12+1 fire damage. Creatures who fail this saving throw must also make a Constitution saving throw or gain a rank of burned for the duration of this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the radius by 5 feet. If this jutsu is cast at B-Rank or higher, a creature must also make a Dexterity saving throw when they enter the radius for the first time on any turn.", created_at: NOW, updated_at: NOW },
  { _id: "f9537942cdb721b6e8f094e7", name: "Fire Release: Fire Beads", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You produce two quick lines of fire that streak toward a target in range. Make two ranged ninjutsu attacks. On each hit, you deal 3d4+3 Fire damage and the target's speed is reduced by 10 feet.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage dealt by 1d4+1.", created_at: NOW, updated_at: NOW },
  { _id: "5bccbf794f97aa83686cac65", name: "Fire Release: Flame Whirl", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (15-foot line)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You twirl your hand in front of you forming a whip of fire release chakra that strikes all creatures within a 15-foot long, 5-foot wide line in front of you. Each creature within range must make a Strength saving throw, taking 4d4+4 fire damage on a failed save, or half as much damage on a success. Creatures who fail this saving throw by 5 or  more become Burned. This jutsu leaves behind a trail of fire on the ground.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage by 2d4+2. If cast to B-Rank or higher, increase the width of this line by 5 feet. If cast to S-Rank or higher, increase the width of this line by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "c2e608429297d41aab451094", name: "Fire Release: Haunting Flame", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a ball of flames that tethers itself to an unsuspecting enemy, following them wherever they go. You do not need to spend chakra to maintain concentration on this jutsu. A creature who is being followed by this flame is always considered to be seen by you, for the purposes of targeting them with Ninjutsu with the Fire Release Keyword, as the jutsu can be originated from the flame following them. They cannot benefit from cover or be hidden from you. A creature who is doused with a gallon of water or is hit with a Water Release jutsu of equal rank or higher may clear this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the amount of creatures you can target by +1.", created_at: NOW, updated_at: NOW },
  { _id: "4d02db94d63526c9b09f643b", name: "Fire Release: Hiding in Fire Technique", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "5 Chakra", components: "CM, HS", duration: "1 Minute", description: "The user of this jutsu becomes able to both take on the appearance of fire and be immune to any damage caused by natural fires. While hiding in a natural fire the caster of this jutsu gains a +5 to stealth checks and is unable to be seen with chakra sight.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If this jutsu is casted at C-Rank increase the Duration to 10 minutes. If this jutsu is casted at B-Rank increase the Duration to 1 hour. If this jutsu is casted at A-Rank increase the Duration to 1 day. If this jutsu is casted at S-Rank increase the Duration to 1 week.", created_at: NOW, updated_at: NOW },
  { _id: "18bb36482de191e302358c8e", name: "Fire Release: Pyre Fist", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You coat your fist in flames and deliver a single punch almost igniting the air itself. Make a melee ninjutsu attack against a target you can see within range. On a hit, the target takes 4d4+4 fire damage.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d4+2 and the die step by 1.", created_at: NOW, updated_at: NOW },
  { _id: "4443a0f36d44e26d3decde97", name: "Fire Release: Rocket Palm", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "Instant", description: "You gather a fuming amount of fire chakra in each hand before striking your opponent in a burst of flame. Make a melee ninjutsu or taijutsu attack, dealing your unarmed damage + 2d6+2 Fire damage. A target hit by this attack must make a Strength saving throw, being pushed back 20 feet on a failed save, or half as much on a success. Alternatively, you can forgo the knock back dealt to the target and instead push yourself directly back 20 feet. This movement does not trigger an opportunity attack from the target.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and increase the damage by 1d6+1 and increase the knock back distance by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "c47821eb883c027179d603d2", name: "Fire Release: Demon Lantern Swarm", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minutes", description: "You Create 4 Demon Masks made of fire, that float around you. You can use a bonus action to send one of the globes streaking toward one creature or object within 60 Feet of you. When you do, make a ranged Ninjutsu attack. On a hit the target takes 2d6+2 fire damage. Whether you hit or miss you spend one Demon Mask and it vanishes after use. The Jutsu ends early if you expend the last Demon Mask or fall unconscious. If you have 3 or more globes, they shed a bright light in a 30-foot radius and dim light for an additional 30 feet. If you have less than 3, the remaining globes shed dim light in a 30-foot radius.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the number of motes created increases by 1. If this jutsu is casted at B-Rank or higher the damage die size is increased by 1. If this jutsu is casted at A-Rank or higher the damage is increased by 1d8. If this jutsu is casted at S-Rank or higher the damage die size is increased by 1.", created_at: NOW, updated_at: NOW },
  { _id: "c392a8c47df40189aa383d84", name: "Fire Release: Flash Fire", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Reaction", range: "Self", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Instant", description: "You brightly intensify the flames of a fire jutsu you've cast. When you used your action this turn to cast a ninjutsu with the Fire Release keyword that deals damage to a target, that target must also make a Constitution saving throw, taking 2d4+2 Fire damage and becoming blind until the end of its next turn on a failed save, or half as much damage and not blind on a success.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and increase the damage by 2d4+2.", created_at: NOW, updated_at: NOW },
  { _id: "bd00fbcad30427debdd0f760", name: "Fire Release: Fusillade Butterflies", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30 feet)", chakra_cost: "8 Chakra", components: "HS, CM, M, W (Any Shuriken)", duration: "Instant", description: "You ready your shuriken in hand and coat it in a layer of fire release chakra. Make a ranged ninjutsu attack against a creature within 30 feet, dealing your weapon's damage in fire damage. As the shuriken leaves your hand, the fire coating is agitated and small will-o-wisps perspire off the weapon, forming into 3 small glowing butterflies of fire. These butterflies emit 10 feet of bright light and immediately fly to the creature, each butterfly dealing 1d8+1 fire damage. These butterflies ignore cover.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the amount of butterflies created by +1.", created_at: NOW, updated_at: NOW },
  { _id: "f98a665d8668867b702be3ca", name: "Fire Release: Merciful Agony", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You cover your palm in fire before grabbing your opponent’s face and unleashing an explosion. Make a melee ninjutsu attack against a target you can see within range. On a hit, the target takes 4d12+4 fire damage. A creature hit by this jutsu must also make a Constitution saving throw, becoming blinded on a failed save. A creature can repeat the saving throw at the end of each of its turns, ending the blinded condition on a success. If a creature is reduced to 0 hit points, their head explodes, but killing them painlessly.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d12+2.", created_at: NOW, updated_at: NOW },
  { _id: "344e40e8af7a82d327af6e17", name: "Fire Release: Queso", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "30 feet (10-foot radius Sphere)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Concentration, up to 1 Minute", description: "You mold Fire release in your stomach creating a thick vicous lava like substance with a peculiar smell. Pick a spot within 30 feet of you, creatures within a 10-foot sphere of that spot must make a Constitution saving throw, taking 2d8 Fire damage and gaining 1 rank of burned on a failed save, or half as much and no conditions on a success. The 10-foot sphere then lingers, any creature who starts their turn or steps in the area gains 1 rank of burned.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fcce4c10011a6e922e9ce7f5", name: "Fire Release: Thruster Jets", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You concentrate fire chakra in the soles of your feet and the palms of your hands, creating jets of exhaust that lift you up. While concentrating on this jutsu you have a flying speed of 40 feet and can hover. When you use your action to cast a jutsu with the Fire Release keyword, you can dash or disengage as a bonus action.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and increase your flying speed by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "d20839f050cff1ab1e337f62", name: "Fire Release: Wild Ballet", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1  Action", range: "Self (30-foot Cone)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You breathe a stream of fire that expands into a long spiral engulfing all in its range. Each creature in a 30-foot cone must make a Dexterity saving throw. Creatures that are in the center of the cone make the saving throw at disadvantage. Creatures are counted as being in the center of the cone if they would still be in the area of the jutsu if it's area was instead a 5-foot wide 30-foot long line. A creature takes 5d8+5 fire damage on a failed save, or half as much damage on a successful one. This fire ignites any flammable objects in the area that aren’t being worn or carried.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, increase the damage by 1d10+1, and the range by 5ft. If this jutsu is casted at A-Rank or higher creatures are counted as being in the center of the cone if they would still be in the area of the jutsu if it's area was instead a 15 feet wide 30 feet long line.", created_at: NOW, updated_at: NOW },
  { _id: "da9b9b6906eae5fc64799ff3", name: "Fire Release: Black Flame", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "14 Chakra", components: "CM, CS", duration: "Instant", description: "This jutsu can only be cast after casting a Ninjutsu with the *Fire Release* keyword that makes an attack roll, or after landing an unarmed attack, or melee weapon attack with a weapon with the light property. You generate a super-hot flame in your hand that absorbs all light, which then combusts. Make a melee ninjutsu attack at a creature within range. On hit, the creature takes 3d8+3 fire damage which ignores resistance and treats immunity as resistance.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage die by one step (d8>d10>d12). If cast to  S-Rank, you can make two attacks with this jutsu as opposed to one.", created_at: NOW, updated_at: NOW },
  { _id: "26e67a61437dc7af3b72bbc3", name: "Fire Release: Black Orb", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "12 Chakra", components: "CM, CS", duration: "Instant", description: "You generate a super-hot flame in your hand which absorbs all light, forming into an orb which you throw at a creature within range. Make a ranged ninjutsu attack against a creature within range, dealing 6d12+6 fire damage which ignores resistance and treats immunity as resistance on hit. The next saving throw the creature makes against a Ninjutsu with the fire release keyword is made with a -2 penalty.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, the damage of this jutsu by 1d12, and the range by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "65d7ae4ea3d63ea0cc717faa", name: "Fire Release: Black Serpent", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "*Special*", chakra_cost: "14 Chakra", components: "CM, CS", duration: "Instant", description: "You generate a super-hot flame in your hand which absorbs all light. You then slam the flame into ground, causing the fire to erupt into a line of fire that moves and tracks a creature like a snake. Select one creature within 30 feet. The serpent-like flame follows this creature up to 30 feet (You can control how this flame moves.) The flame follows the target, even if they would move, unless the target moves outside of this jutsu's range. All creatures within the flame's path must make a Dexterity saving throw, taking 10d6+10 fire damage which ignores resistance on a failed save. The target of this jutsu makes this saving throw at disadvantage. A creature can be affected by this jutsu no more than once per turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and the amount of flame serpents\" by +1. ___ >", created_at: NOW, updated_at: NOW },
  { _id: "e1698331a80b5989aaf84cc8", name: "Fire Release: Crimson Serpent", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "14 Chakra", components: "HS, CM, CM", duration: "Concentration, up to 1 minute", description: "You spew a great line a fire into a space within 60 feet of you. This fire collects into a huge-sized Flame Serpent. This Flame Serpent can be commanded as a bonus action on your turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cdd579517f748f89ab0a1f85", name: "Fire Release:  Fire Lightning", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1  Action", range: "Self (10-foot radius)", chakra_cost: "14 Chakra", components: "CM, HS", duration: "Instant", description: "You shoot out dozens of spears of fire attempting to skewer all those around you.  Each creature within 10 feet of you must make a Dexterity saving throw taking 8d8+8 fire damage on a failed save or half as much damage on a success. Objects within 10 feet of the stream of fire ignite if they are not being worn or held.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d8+2. If this jutsu is casted at A-Rank or Higher, you may cast this jutsu as a bonus Action.", created_at: NOW, updated_at: NOW },
  { _id: "c2bafabc8990ba729bb68044", name: "Fire Release: Fire Seeking Chains", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "15 Chakra", components: "HS, CM, CS", duration: "Instant", description: "Striking both palms to the ground, chain-like flames crackles around you as five streaks of fire rapidly snake along the ground toward up to five targets standing on the same surface as you within range, leaping towards their target and exploding into a column of flame upon reaching them. This jutsu ignores all cover. Each creature must make a Dexterity saving throw, taking 8d6+8 fire damage on a failed save, or half as much damage on a successful one. A target that fails this save also becomes grappled in place by the flames. A creature grappled this way can make a Strength saving throw at the end of each of its turns, escaping on a success. A target gains 1 rank of Burned at the start of each turn it is grappled. If a single creature is targeted by all five streaks of fire, this jutsu instead deals 12d6+12 fire damage on a failed save, or half as much damage on a successful one. The fire can travel over obstacles up to 10 feet high, and ignites flammable objects along its path that aren't being worn or carried.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and increase the damage by 2d6+2 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "cda043528300f2e7753e749f", name: "Fire Release: Plague-Bearing Fireball", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "60 Feet (15-foot radius)", chakra_cost: "14 Chakra", components: "HS, CM, M", duration: "Instant", description: "You focus a large amount of medical chakra within your mouth and quickly spit it outward towards a space up to 60ft away. As you fire this blast of chakra, you simultaneously change the nature release of the chakra to fire. Each creature within a 15-foot radius must make a Dexterity saving throw, taking 5d10+5 Fire damage, or half damage and no further effects on a success. After the blast collides with the ground, a poisonous fog emerges that covers the area for 1 minute unless dispelled. Each creature within the radius after the blast has hit must also make a constitution saving throw, gaining the envenomed and poisoned conditions on failure. Creatures who were hit by this jutsu must make the Constitution save at disadvantage and creatures who failed their Constitution save that begin their turns in this jutsu's area take additional poison damage as if they had another rank of the envenomed condition. If a creature ends or starts their turn in this jutsu's space, they must make the constitution save. A creature can repeat the constitution save at the start of each of their turns.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bd0d361d000ce44b4f54dec3", name: "Fire Release: Baelfire", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "16 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You invoke the fire of demons within your lungs, allowing you to spew it out like one. Until the jutsu ends, you can use an action to exhale fire in a 45-foot cone. Each creature in that area must make a Dexterity saving throw, taking 8d6+8 fire damage and inflicting a rank of burned on a failed save, or half as much damage and no additional effects on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6+1.", created_at: NOW, updated_at: NOW },
  { _id: "70feb8bc4bccfdaefb5c499d", name: "Fire Release: Bloodflame", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Action", range: "Self (30-foot Cone)", chakra_cost: "17 Chakra", components: "HS, CM", duration: "Instant", description: "As part of casting this jutsu you must possess at least one ounce of blood, or sacrifice 2d4 of your hit points. You generate a flame in hand and infuse it with blood before sending the flame in a 30-foot cone in front of you. All creatures within range must make a Dexterity saving throw to avoid the sanguine flame. On a failed save, creatures take 5d8+5 fire and 5d8+5 necrotic damage, and gains 1 rank of Bleeding and Burned. On a successful save, creatures take half damage and no further effects. After casting this jutsu, the affected area remains bathed in bloody fire for the next minute, causing creatures that enter or start their turns in it to take 10 fire and 10 necrotic damage. These flames can be dispersed early by affecting the area with a jutsu with the  Water Release keyword and a  jutsu with the Medical keyword.  If this occurs, this area cannot  be affected by this jutsu again for 1 minute.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, both instances  of damage by 1d8, and the affected area damage by 5 for both instances.", created_at: NOW, updated_at: NOW },
  { _id: "e0001ea5d1b96752f5658bf2", name: "Fire Release: Chaos Bed Vestiges", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "Action", range: "90 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You form a ball of fire in your hands that has the appearance of a small sun and throw it at a target within range. Make a ranged ninjutsu attack on a target creature within range. On a Hit, the target creature takes 10d10+10 fire Damage and the target must make a constitution saving throw, gaining 2 ranks of burned on a failed save. Compare the result of your attack roll against the AC of all creatures within 5 feet of the creature you hit. If your attack is greater than their AC, they take half the damage the original target took and must make a constitution saving throw, gaining 1 rank of burned on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage die by 2d10+2.", created_at: NOW, updated_at: NOW },
  { _id: "30e57aad7473f22cd5f8d5d1", name: "Fire Release:  Flame Control Hedgehog", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "90 Feet (15-foot radius Sphere)", chakra_cost: "20 Chakra", components: "CM, HS", duration: "Instant", description: "You summon a sphere of fire that shoots out dozens of pillars of fire. Each creature within range must make a Dexterity saving throw taking 10d8+10 Fire damage and gaining 2 ranks of the burned condition on a failed save or half as much damage and no additonal effects on a success.  Creatures within 5 feet of the center of the sphere must make the Dexterity saving throw at disadvantage. Objects within 10 feet of the stream of fire ignite if they are not being worn or held.", at_higher_ranks: "For each rank you cast this jutsu above &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp; A-Rank, increase the cost of this jutsu &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;by 3 and the size of this &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;jutsu by 5 feet and &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp; Creatures within 10 &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;feet of the center &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;of the sphere must make the &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;Dexterity saving &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;throw at &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp;disadvantage.", created_at: NOW, updated_at: NOW },
  { _id: "05ede1a46ad41aea9c5a8a68", name: "Fire Release: Heavenly Prison Fire Sword", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minutes", description: "The user brings up a large flame in his right hand, which soon after takes the form of a sword. If someone is hit by the sword, they will be engulfed in flames.  For the duration of this jutsu, when you take the attack action, you make a weapon attack dealing 4d10+4 Fire damage and your target must make a Constitution saving throw or gain 2 ranks of burned up to a total of 4 ranks of burned. Additionally, as a Bonus Action you may choose to ignite a creature who has ranks of burned, when you choose to do this the target creature takes 2d8+2 fire damage for each rank of burned they had and loses all ranks of burned. For the duration of this jutsu one of your hands are occupied and cannot be used to make Hand Signs (HS).", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage by 1d10+1, and the amount of burned ranks a creature can gain from this jutsu by 2.", created_at: NOW, updated_at: NOW },
  { _id: "52fc724688dde83a9745f934", name: "Fire Release: Immolation Pulse", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "20 Chakra", components: "CM", duration: "Instant", description: "As a prerequisite to casting this jutsu, your target must be restrained, incapacitated, or prone. You create an orb of vibrant fire release chakra in your hand and blast it at a vulnerable creature within 10 feet of you. Make  a melee ninjutsu attack if within 5 feet, or a ranged ninjutsu attack if further. On a hit, you deal 7d10+7 Fire damage. The ground beneath the creature begins to crack and boil, until a 5-foot wide, 40-foot-wide cylinder of flame and magma erupts from where they are struck. The creature must make a Dexterity saving throw.  On a failed save, they are caught by the cylinder, taking 3d12+3 fire damage and being knocked to the top of the cylinder on a failed save. On a successful save, the creature avoids the cylinder, moving to a space that can hold it within 5 feet.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost by 3, the damage by 1d10+1 and 1d12+1 respectively, and the height of the cylinder by 20 feet.", created_at: NOW, updated_at: NOW },
  { _id: "9c270ee71b1ee9ee3673bb23", name: "Fire Release: Ghostflame", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "15 Chakra", components: "HS, CM, CS", duration: "Instant", description: "You create a ball of silver and black flame that strangely burns cold. It is said that this jutsu possesses the ability to quell the persistance of the undead to cling to this world. Make a ranged ninjutsu attack against the target within range, dealing 10d4+10 necrotic damage and imposing a Constitution saving throw. On a failed save, the target feels a deep cold swathe over their very core, becoming Chilled for the next minute. Fire damage from this jutsu does not end the Chilled condition on a creature. If this jutsu is used on an undead, the damage die of this jutsu become d10s and you ignore reistance and immunity to necrotic damage against them. Additionally, if the undead target possesses the ability to resurrect and you reduce them to 0 hit points with this jutsu, you sever their ties to this world, immediately killing them, unable to be revived again.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b826f377d891b0773be640a1", name: "Fire Release: Sacred Flame", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "5 feet", chakra_cost: "16 Chakra", components: "HS, CM", duration: "Instant", description: "You throw your hand out to grab your opponent’s faces and let out a fiery explosion. Make a melee ninjutsu attack on a creature within range. On a successful Hit, the target creature takes 10d10+10 Fire damage and the must make a Constitution saving throw gaining the dazed condition and 1 rank of burned on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage die by 2d10+2. In addition, a creature who fails the saving throw also is knocked back 50 feet. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage as if they had fallen an equal distance.", created_at: NOW, updated_at: NOW },
  { _id: "b1f212fa59010daf38abd8c6", name: "Fire Release: Soul Echo: Ember (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "ea399ace196c0070d6371c26"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "16 Chakra", components: "CM, CS, W (Any Melee)", duration: "Concentration, up to 1 Minute", description: "You begin to channel fire release chakra within your palm as begin to focus on the Will of Fire within you. You picture you and your comrades in the distant future being written as legendary shinobi, and the thought of this excites you. The echoes of your soul empower this  jutsu as you bathe the weapon in your chakra. For the duration, your weapon is surrounded in black and blue fire, like that of a fabled beast. You gain the following benefits; - Your weapon's damage is increased by your Ninjutsu ability modifier, in Fire damage. - Your weapon's critical threat range increases by +1 and on a critical hit, you reroll all 1s and 2s. If you *Bloodied* (Under 50  hit points), the bonus to critical threat range becomes a +2 and on a critical hit, the target is Burned. - For each hit you land with your weapon, you become surrounded in an aura of fire emits bright light up to 30 feet. Until the start of your next turn, melee attacks that hit you cause the attacker to take 5 fire damage. The damage increases by 2 for each additional attack you make after the first. - Your movement speed is increased +30 feet, and you always considered as gaining the benefits of the Disengage action for the duration. You cannot lose concentration of this jutsu as the result of failing a concentration check and it does not cost chakra to maintain. This jutsu ends early if you let go of your weapon.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "136d0370c780605eaf1b9607", name: "Fire Release: Warm Body Technique", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Minute", range: "Self", chakra_cost: "15 Chakra", components: "HS, CM", duration: "10 Hours", description: "You fill your body with Fire Release chakra to keep yourself warm. For the next 10 hours you are immune to any negative effects caused by extreme cold temperatures and the burned condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a8fedc21381a51b20239991d", name: "Fire Release:  Amon's Beheading Sword", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (120 foot line)", chakra_cost: "32 Chakra", components: "CM, HS", duration: "Instant", description: "You summon forth the greatest power from Amon, the Flame Minister, molding your chakra into the form of a giant flaming swordsman, who dashes forward for a finishing strike. You shoot out a 10-foot wide 120-foot-long line forcing each creature within the line to  make a Dexterity saving throw. On a failed save, a creature takes 20d6+20 fire damage. A creature who is brought to 0 hit points by failing this saving throw is immediately turned to ash, as Amon's blade cuts through their very soul. On a successful save, a creature takes only half damage and cannot be turned to ash. This jutsu ignores resistance and treats immunity as resistance. Additionally, if you win a Clash with this jutsu, it deals double damage to the creature that lost.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "29013f96393913c55c7126c2", name: "Fire Release: Comet Dash", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Full Turn Action", range: "60 Feet", chakra_cost: "24 Chakra", components: "CM, M", duration: "Instant", description: "You create a ball of fire similar to a comet in the palm of your hand, before rushing forward and slamming it down with a powerful explosion erupting from your hand. You move up to 60 feet in a straight line ignoring all difficult terrain or obstructions in your path as you crash through them effortlessly. This movement does not provoke attacks of opportunity. Make a melee ninjutsu attack on a creature within 5 feet after your movement, dealing 10d10+10 fire damage on a hit. Hit or miss, all creatures in a 30-foot cone in front of you the target creature must make a Dexterity saving throw, taking 10d8+10 fire damage and gaining 3 ranks of the burned condition on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "29d4362f3db1c78292b9f9c5", name: "Fire Release: Inferno Dance", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "32 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure a ring of fire rotating around your body and propel 5 streams of flames that ignite the air itself. You can select up to five creatures within range that you can see. Make a ranged ninjutsu attack against the selected creatures. On a hit, the target creature takes 7d10+7 + your ninjutsu ability modifier Fire damage. This jutsu ignores half and three fourths cover.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c2d161b0bffeaa58f6b16f11", name: "Fire Release: Phoenix Screech", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "146f92dbec13f8ccb9d843cb"], elements: [], casting_time: "1 Action", range: "Self (60-foot cone)", chakra_cost: "21 Chakra", components: "HS, CM", duration: "Instant", description: "You take in a big breath and cross your arms in an X pattern and then unleash a mighty scream that reaches even the heavens. You make 3 60-foot cones that spread out in different directions. The cones cannot overlap. Each creature in one of the cones must make a Dexterity saving throw taking 10d12+10 fire damage on a failed save or half as much damage on a successful one.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3e5a845f062c0b4b41171f1c", name: "Fire Release: Quasar", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131", "9991cc726431e53e17c4a8fa", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "10 Minutes", range: "100 Miles", chakra_cost: "Special *(138 Chakra)*", components: "HS, CM, CS", duration: "Instant", description: "You harness the power of a black hole and bring down the power of a celestial body down upon your enemies. The ambient temperature of the air rises and the sky opens its maw to bring forth death and destruction. All creatures objects and structures within a 100-foot-radius, 500-foot-high cylinder must make a Dexterity saving throw or take 100d4+100 fire damage and become immolated and blinded on a failed save. If this would reduce a creature, structure, or object to 0 hit points it is turned to ash and atomized. on a failed save and half as much on a successful save. Structures and Objects take double damage. A creature immolated by this jutsu cannot extinguish the flames on their own and can only have either the burned condition or the Blinded condition ended by a Jutsu that removes conditions casted at no less than S-Rank. *Combination:* *If this jutsu is cast as a Combination jutsu with 2 or more casters reduce the cost by -2.* *Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's offensive abilities based on the highest Charisma Modifier within the group of casters. (+0-1No Change, +2Increase damage by 10d4+10, +3Increase damage by 15d4+15, +4Increase damage by 25d4+25, +5Increase damage die by 1 step.*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "30b633b3113e29d59ffcafda", name: "Water Release: Torrential Flow", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You create a torrent of rushing rotating water that drags enemies closer together, by any means. Each creature in a 15-foot radius, 60-foot-high cylinder centered on a point within range must make a Strength saving throw or be pulled toward the center of the radius and take 3d6 cold damage on a failed save, or half as much damage and no additional effects on a successful save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "8e0a4140b1d492dadb67a7a5", name: "Water Release: Surging Strikes", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "ed3184ccd83030d0ec4106a9", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "Instant", description: "Water flows around your arms and legs to guide your strikes. Make three ninjutsu or taijutsu attacks, adding a 1d4 to the attack roll of each strike (this jutsu cannot crit). On each hit, deal your unarmed damage + 1d4 Cold damage. If all three attacks hit, the target takes an extra 2d4 Cold. *Saturation.* If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can force the affected target to make a Constitution saving throw, gaining 1 rank of Chilled on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage by 1d4", created_at: NOW, updated_at: NOW },
  { _id: "494a0163fd0961e5d646c680", name: "Water Release: Water Ball", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "30 Feet (10-foot radius sphere)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "You conjure an expanding ball of water that quickly pops splashing on everything in sight. Each creature in a range must succeed a Dexterity saving throw or take 3d6 cold damage and gain 1 rank of Chilled. *Saturation.* If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or on a successful saving throw, creatures take half damage from this jutsu and are chilled until the start of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "1d2e94b41338eb3b2a703017", name: "Water Release: Aqua Cutter", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You line the edge of your hands and arms with pressurized water chakra. For the duration of this jutsu, as an action you can make two melee ninjutsu attacks dealing 2d10 Cold damage. These attacks have a critical threat range of 19~20.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and increase damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "17e09afd41af216275f333bf", name: "Water Release: Bubble Handcuffs", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "Action", range: "30 feet", chakra_cost: "6 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create bubbles that fly towards a creature of your choice within range, attempting to stop that creature from using hand signs. The target creature must make a Dexterity saving throw. On a failed save that creature loses the ability to use hand signs or hold anything in their hands.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the range by 10 feet. At A-Rank the amount of creatures that you can target with this jutsu by 1.", created_at: NOW, updated_at: NOW },
  { _id: "8545e09140cad0a178c35701", name: "Water Release: Coral Palm", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "7 Chakra", components: "HS, CM", duration: "Instant", description: "Make a melee ninjutsu attack on a creature within range. On a hit, coral starts growing over your target quickly restraining them. The target creature must succeed a Strength saving throw or become restrained for 1 minute. A restrained creature may attempt a Strength saving throw at the beginning of each of their turns, ending the restrained condition on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5788e1847f151636f2a76800", name: "Water Release: Double Tsunami", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet (30ft Cube)", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b9aa83f74cac708842136102", name: "Water Release: Hail Storm", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Full Turn Action", range: "120 Feet", chakra_cost: "Special *(50 Chakra)*", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create a cloud of cold water that forms ice cubes that fall like hail. A 250- foot cloud forms centered on a point you can see. Creatures of your choice under this cloud must succeed a Dexterity saving throw at the start of each of its turns taking 6d8 cold damage and being bruised and chilled on a failed save or half as much damage and no additional effects on a successful one. *Combination:* *If this jutsu is cast as a Combination jutsu with 2 or more casters increase the radius of the cloud by 50 feet.* *Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's offensive abilities based on the highest Charisma Modifier within the group of casters. (+0-1No Change, +2Increase damage by 3d8, +3creatures who fail a saving throw also gain a rank of chilled, +4Increase damage die by 1 step, +5 Increase damage by 3d10.*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0008ca4804aae9c68c5ddb32", name: "Water Release: Heavenly Weeping", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "A technique in which chakra is kneaded in the user's body, transformed into water and then shaped into Senbon in the mouth before finally being expelled at a high velocity.  Make a Ranged Ninjutsu attack against a creature you can see within range, dealing 2d8 Cold damage+ 2d8 Piercing damage. If your Ninjutsu Save DC is higher than your target's passive perception by 5 or more you gain advantage on your attack targeting them with this jutsu. *Saturation.* If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to instead make an additional attack targeting another creature within range.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8 for each damage type.", created_at: NOW, updated_at: NOW },
  { _id: "722ea4514097265c436196c3", name: "Water Release: Misty Step", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "Using the water around you, you convert it into a short-range chakra network that only you can use to translocate. You teleport to a space you can see within 60 feet of you. *Saturation.* If used near a sufficient source of water, reduce the cost by 2 or increase the range you can teleport by 30 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "661d83b1b698817324dbda3a", name: "Water Release: Rising Water Slicer", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (60-foot line)", chakra_cost: "9 Chakra", components: "CM, HS", duration: "Instant", description: "You summon a strong thin linear wave of water that shoots outward from the ground at high speeds to its target. Creatures in a 5- foot wide, 60-feet-long line must succeed a Dexterity saving throw. Creatures take 4d8 Water damage and gain 1 rank of the bleeding condition on a failed save. On a success they take half damage and no further effects. *Saturation.* If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or increase the size of the damage die by 1 step.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "719af936b78a43e71dace53b", name: "Water Release: Scrub", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "8 Chakra", components: "HS, CM", duration: "Instant", description: "You manifest a cube of water at a space within range to scrub out the competition. Choose a space within range that you can see. You create a 10 by 10 foot cube originating from this space, which then travels 15 feet from its outer edge before dispesing. Each creature within range must make a Dexterity saving throw, taking 3d10 cold damage and gaining 1 rank of chilled on a failed save, or half as much damage on a success. The affected area is scrubbed clean of grime and flith. Affected creatures who are benefitting from a jutsu with a range of self or touch cause the original caster of the jutsu to make their concentration check with a -1d4 penalty as the waters of this jutsu scrub the chakra off of them.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10. If cast to B-Rank or higher, increase the distance the cube travels to 20 feet. If cast to S-Rank or higher, increase the distance the cube travels to 25 feet.", created_at: NOW, updated_at: NOW },
  { _id: "8f1cf08205311c70bd3b6393", name: "Water Release: Aqua Mallet", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action, which you take while falling", range: "15 feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "*(This jutsu cannot score a critical hit.)*  As a prerequsite to casting this jutsu you must currently be falling from a height of 10 feet or higher. As you fall, you weave signs and take the molecules of water within the air and form it into a comically large hammer. Make a melee ninjutsu attack against a creature within 15 feet of you as you aim to strike transferring all of your momentum. On a hit, you deal 3d10+your ninjutsu ability modifier in cold damage. You also deal an additional amount of falling damage equal to the falling damage you would've taken. If this damage reduces a creature to 0 hit points, they are immediately killed as their body explodes from the impact. On a hit, you land safely on the ground, taking no fall damage. On a miss, you take half your falling damage. *Saturation:* If this jutsu is used near a sufficient source of water, reduce the cost of this jutsu by 2 or force all creatures within 5 feet of the target, other than you and the original target, to make a Dexterity saving throw, taking half this jutsu's damage on a failure.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e08bc816ca63a282554103be", name: "Water Release: Bubble Transport System", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Minute", range: "Touch", chakra_cost: "13 Chakra", components: "HS, CM", duration: "1 Hour", description: "You create a bubble that may carry 2 medium creatures. Upon casting this jutsu you are immediately placed within the bubble and if there is a friendly creature within 5 feet of you they may choose to also be immediately placed within the bubble. Otherwise, a friendly creature can walk into the bubble. You control where the bubble moves as a free action and the bubble has a flying movement speed of 500 feet. The Bubble has an AC of 12 and 10 hit points. You must repay the cost of this jutsu at the end of each hour.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the amount of medium sized creatures the bubble can carry.", created_at: NOW, updated_at: NOW },
  { _id: "9de76d0ee28c28e9a116d5f6", name: "Water Release: Dehydration", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "13 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You forceful take water from a creature's body, instantly dehydrating them. Make a melee ninjutsu attack, on a hit the target takes 7d6 Necrotic damage and are slowed for the duration. A creature with ranks of slowed granted by this jutsu must make a Constitution saving throw at the end of each of their turns gaining another rank of slowed on a failed save or removing all ranks of slowed on a successful one.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "28de110f931433585490f897", name: "Water Style: Distortion Technique", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["4ca66bf77ffa28385682255c", "87db194b8f9f4fe2140fb4c3", "b3b9a80a8acefa31d6905369"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "13 Chakra", components: "CM, HS", duration: "Concentration, up to 1 minute", description: "The user of this technique targets any item up to Medium size within range, cloaking it in a variation of the Water Blending jutsu.  This thin layer of Water chakra does not harm the object or interfere with attacks (if a weapon).  If the object is a weapon, any weapon attacks made with the weapon are made with advantage for the duration as the refractory cloak of water makes it difficult to track the weapon's exact position.  If the object is an armor, it grants an extra +2 AC as the water makes it difficult to aim for unprotected areas.  If the object is a consumable or other item, the object is considered hidden unless a creature makes a Wisdom (Perception) check against your Ninjutsu Save DC.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the size of objects you can target with this jutsu. (A-Rank = Large, S-Rank = Huge).", created_at: NOW, updated_at: NOW },
  { _id: "59298179e3cdacc540e49c41", name: "Water Style: Exploding Water Shuriken", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "90 Feet (20-foot radius Sphere)", chakra_cost: "15 Chakra", components: "CM, HS", duration: "Instant", description: "An advanced version of Water Shuriken, the user compresses an enormous amount of water into a single shuriken, engulfing everything in its range. creatures in range must succeed on a Dexterity saving throw or take 5d10 Cold Damage and gain 2 ranks of the chilled condition or half as much damage on a failed save. *Saturation.* If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or increase the amount of damage die by 2.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d10 and radius by 5ft. page", created_at: NOW, updated_at: NOW },
  { _id: "b2b0348d1a1824cb8561a453", name: "Water Release: Painful Gasp", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You create pools of water in the lungs of a creature, attempting to forcefully drown them. The creature must make a Constitution saving throw or gain a rank of weakened and become incapacitated on a failed save. A creature becomes incapacitated until the start of their next turn, they must then make another saving throw or be subjected to this jutsu's affect again. A creature who has passed a subsequent saving throw may spend their action to end this jutsu by forcefully expelling the water in their lungs. Creatures who do not need to breathe air or can breathe in water are immune to this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5838f373c27146828c4f7388", name: "Water Release: Torrential Blades", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fc7547ed9254d4697efeccd4", name: "Water Release: Water Formation: Lake", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1  Action", range: "30 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Instant", description: "You generate a Large lake of water from your stomach and expel it onto the ground in front of you. This lake holds no more than 1000 gallons of water. You can use this lake as a source of drinking water, lay a trap, or use it as a source for more complex Water Ninjutsu. You may use the water this Jutsu Produces as a Source  of Water for no more than 5  water release ninjutsu of A-Rank  or Lower.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "50495c4d61485fe26aa020d3", name: "Water Release: Blood Bending", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "17 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You attempt to take subjugate a creature by taking control of the water in their blood flowing in their body. A creature you can see within range must make a Constitution saving throw at disadvantage or their body is taken over by you. You now control this creature, using their body at will. A creature may attempt to break out of this jutsu by making a Constitution saving throw at the end of their turns. While under the effects of this jutsu a creature is incapacitated and has a movement speed of 0, but you can control them as an action on your turn. You can make the creature move, and you can make them take any action, bonus action, or reaction they could normally take. You have access to any features or jutsu you saw them use and can cast them using their chakra. If this jutsu is used during a full moon it does not require chakra to maintain concentration on. Creatures who do not have blood or are not made primarily of water are immune to this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f6cbaf124ba2b2c771072290", name: "Water Release: Heaven's Tears", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Full Turn Action", range: "120 Feet", chakra_cost: "Special *(110 Chakra)*", components: "HS, CM", duration: "1 minute", description: "You create a torrential downpour of water that seeps into one creature, greatly enhancing their capabilities. Choose a creature a caster can see within range. For the duration, they gain the following benefits: - Immunity to cold damage. - Vulnerability to earth damage. - All damage you deal is cold damage that cannot be resisted. - Advantage on Constitution saving throws. - You always count as being near a sufficient source of water. - Increase the DC of all jutsu with the water release keyword by +2. - Increase the number of damage dice rolled by 2 of all jutsu with the water release keyword. *Combination:* *If this jutsu is cast as a Combination jutsu with 2 or more casters reduce the cost by -2.* *Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's offensive abilities based on the highest Charisma Modifier within the group of casters. (+0-1No Change, +2-3Increase the number of creatures that can be affected by +1. +4-5Increase the number of creatures that can be affected by +2.*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4079b1c5d7949f0a93d33f48", name: "Water Release: Hydrosnipe (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "300 feet", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Instant", description: "You take aim at your target as you use water chakra to pressurize a single spout of water to deadly levels. You launch this pressurized jet of water at a target in range, making a ranged ninjutsu attack. This attack has a critical threat range of 17~20, and ignores three-quarters cover. On a hit, this deals 10d10 Cold damage and the target gains 2 ranks of Chilled. If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can force the affected target to make a Constitution saving throw, gaining 2 ranks of Bleeding on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and increase the damage dealt by 3d10, and the critical threat range increase by +1.", created_at: NOW, updated_at: NOW },
  { _id: "271d685309f37eea04a6f5ee", name: "Water Release: Self-Hydrating Technique", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Minute", range: "Self", chakra_cost: "15 Chakra", components: "HS, CM", duration: "10 Hours", description: "Using Water Release Chakra you make sure that your sweat glands are constantly fill to keep your body at a healthy temperature even in the most extreme heats. For the next 10 hours you are immune to any negative effects caused by extreme hot temperatures and the chilled condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "458a722a51e52fafac838ebd", name: "Water Release: Soul Echo: Tide (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "16 Chakra", components: "CM, CS, W (Any Melee)", duration: "Concentration, up to 1 Minute", description: "You begin to channel water release chakra within your palm as you begin to think of peace and tranquility. Soothing oceans, gentle tides, the thought of retiring someday on a peaceful Warf. The echoes of your soul empower this jutsu as you bathe the weapon in your chakra. For the duration, your weapon is surrounded in rushing sparkling water, gaining the following benefits; - Your weapon's damage is increased by your Ninjutsu ability modifier, in Cold damage. - You ignore difficult terrain. You also gain a water walking and swim speed equal to double your movement speed. - When you a hit target with your weapon, consecutive hits on the same target an additional die of cold damage, equal to your weapon's damage die. The effect stacks up 2 times before it resets to 0 bonus damage die, after which you can build the damage die bonus again by hitting the target as before. At the end current turn, this bonus damage die resets to 0 for all targets that were hit by you. - Once per round, when you would reduce damage in any way, increase the amount of damage reduced by your weapon's damage. If you use a jutsu with the Water Release keyword to reduced damage, increase the damage reduction further by your proficiency bonus. You cannot lose concentration of this jutsu as the result of failing a concentration check and it does not cost chakra to maintain. This jutsu ends early if you let go of your weapon.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0d3dd573001dd69c098c6ff5", name: "Water Release: Water Formation: Ocean", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1  Action", range: "60 Feet", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Instant", description: "You generate an ocean of water from your stomach and expel it onto the ground in front of you. This ocean holds no more than 10000 gallons of water. You can use this ocean as a source of drinking water, lay a trap, or use it as a source for more complex Water Ninjutsu. You may use the water this Jutsu Produces as a Source of Water for no more than 5 water release ninjutsu of S-Rank or Lower.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 5, increase the amount of water created by 10000, and the amount of times the source of water can be used as a source of water by 5.", created_at: NOW, updated_at: NOW },
  { _id: "84ef2657e8fab0093004af6a", name: "Water Release: Aquatic Obliteration", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Instant", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8fecc78acc6c4e87bb4a002a", name: "Water Release: Eight Headed Water Hydra", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1  Action", range: "120 Feet", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Instant", description: "You expel a massive quantity of water or pull from a nearby source, conjuring a Giant eight headed Hydra of your description from water. The Hydra attempts to ram its target. Make a Ranged ninjutsu attack, on a hit the target creature takes 20d10 Cold damage and must make a Constitution saving throw, being stunned and knocked prone on a failed save until the end of the creature’s next turn. *Saturation.* If used near a sufficient source of water, reduce the chakra cost of this jutsu by 2 or you can choose to increase the damage die to a d12.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "18b852732932efdf763886bf", name: "Water Release: Origin Pulse", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "b816b9a2e7670f7792937f0e"], elements: [], casting_time: "1 Action", range: "Self (120-foot sphere)", chakra_cost: "24 Chakra", components: "HS, CM", duration: "Instant", description: "All water in the air and earth within range collect and swirl around you before dispersing in a powerful blast. All creatures in a 120-foot sphere centered on you must make a Strength saving throw, taking 12d10 Cold damage and 12d10 Bludgeoning damage on a failed save or half as much on a success. In addition, on a failed save, a target also gains two ranks of both Bruised and Chilled, and is knocked back 60 feet away from the center of the sphere. On a successful save, a target is only knocked back 30 feet. Any surfaces caught in this sphere are now difficult terrain until 1 hour passes.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3feb13482ef986ee49bf44a6", name: "Lightning Release: Shocking Step", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (30-Foot radius)", chakra_cost: "4 Chakra", components: "HS, CM, M", duration: "Instant", description: "You generate a field of lightning chakra as you perform a graceful dance. All creatures in your range must make a constitution saving throw, becoming shocked on a failed save until the end of their next turn. If you have *Lightning ReleaseElectric Boogaloo* on your jutsu known list, you can target 1 of the creatures who failed their saving throw with this jutsu, casting it as a bonus action.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "33d6c4304dd768bf95953463", name: "Lightning Release: Thunderwave", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Self (15-foot cube)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a Constitution saving throw. On a failed save, a creature takes 2d8 Lightning damage and is knocked back 10 feet away from you. On a successful save, the creature takes half as much damage and no additional effects. In addition, unsecured objects that are completely within the area of effect are automatically pushed 10 feet away from you by the jutsu's effect, and the jutsu emits a thunderous boom audible out to 300 feet. *Overcharge.* When you cast this jutsu, as a bonus action or reaction, you can overcharge its effects. When you do, a creature who fails their saving throw is shocked until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "14a1286a3c156ad0590552b1", name: "Lightning Release: Booming Strike", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Weapon's Range", chakra_cost: "8 Chakra", components: "HS, CM, W (Any)", duration: "1 Round", description: "You brandish a weapon in lightning and make a taijutsu attack against a creature within range. On a hit, the creature takes your weapon's damage + 1d10 lightning damage and becomes sheathed in booming electricity until the start of your next turn. If the target willingly moves 5 feet or more before the start of your next turn, they take 2d8 lightning damage, being struck by a bolt of lightning as they move. This jutsu then ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the damage by 1d10 and 1d8 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "1eca9f1733a2f954ef26baca", name: "Lightning Release: Electric Boogaloo", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (40-Foot radius)", chakra_cost: "8 Chakra", components: "HS, CM, M", duration: "Instant", description: "You pull off some groovy dance moves while simultaneously radiating highly volatile lightning. All creatures within range must make a dexterity saving throw, on a failed save the creature takes 4d8 lightning damage. If a creature making this saving throw has the shocked condition due to *Lightning ReleaseShocking Step*, the creature also becomes dazed until the end of their next turn on a failed save. You can only effect 1 creature who failed their saving throw with this special effect. 0n a successful save, creatures takes half damage and suffers no additional effects. If you have *Lightning ReleaseFlashy Finale* on your jutsu known list, you can target 1 of the creatures who failed their saving throw with this jutsu, casting it as a reaction.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "91cf1ea10d117382ffe62ffb", name: "Lightning Release: Lightning Bolt", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (120-foot line)", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one. The lightning ignites flammable objects in the area that aren’t being worn or carried.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "6aa2d3997a0824c7d7dd127c", name: "Lightning Release: Nerve Boost", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "8 Chakra", components: "HS, CM, M", duration: "1 minute", description: "The mental aspect of the perfected Lightning Chakra Mode created so that the user's body can keep up with the speed granted by enhancing your body with Lightning Chakra. By speeding up the rate at which your neurons send signals through your body you slow your perception of time, making both hitting and dodging easier. For the duration, when you would make a melee attack, add a d4 to the roll. Additionally, when you would be the target of a melee or ranged attack, add a d4 to you AC against the attack. This causes immense stress on your neurons. After this Jutsu ends, decrease all of your attack rolls by a d4 and your AC by 1 for 1 minute.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "94ae7e1f795d5c6555a43241", name: "Lightning Release: Rejuvenating Spark", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1  Action", range: "30 feet", chakra_cost: "7 Chakra", components: "CM, HS", duration: "Instant", description: "You conjure your lightning release chakra to generate a spark of willpower from a creature within range. A Creature gains 1 Hit point and a number of temporary hit points equal to 2d6 + Your Ninjutsu ability Modifier. These Temporary hit points last for 1 minute. Additionally, the creature gains resistance to Lightning damage so long as they have Temporary hit points granted by this jutsu. *Overcharge.* When you cast this jutsu, as a bonus action or a reaction, you can overcharge its effects. When you do, the first time your target would take lightning damage while benefiting from temporary hit points (thp) as a result of this jutsu, you instead gain bonus thp equal to half the damage dealt.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the healing die by 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "c8dcbd3da87e4f491b9ebb25", name: "Lightning Release: Vanishing Rasengan", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "9 Chakra", components: "CM", duration: "Instant", description: "You collect chakra into your hand generating a powerful sphere of spiraling chakra, then the user adds Lightning Release to it before throwing it. As it glides, the nature transformation abruptly kicks in, resulting in the technique disappearing from sight. This adds an element of surprise to the attack, as an opponent may lower their guard, assuming that the technique has dispersed, only to find themselves struck by the invisible attack. Make a ranged ninjutsu attack against a creature within range, your target must make a Perception check opposed by your Ninjutsu save DC, on a failure this attack is made at advantaged. Creatures with chakra sight have advantage on the Perception check. On a Hit, the target takes 4d8 force damage and makes a Constitution saving throw. On a failed save they gain the prone condition.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of this jutsu by 3, the damage by 2d8, and the range by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "7899f086c9539033e6ab571e", name: "Lightning Release: Discharge", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "Self (150-foot cube)", chakra_cost: "Special *(77 Chakra)*", components: "HS, CM", duration: "Instant", description: "You clap your hands together and discharge a giant wave of electrical energy to destroy your foes. Each creature in a 150-foot cube originating from you must make a Constitution saving throw. On a failed save, a creature takes 12d10 lightning damage and become shocked, weakened, and slowed. On a successful save, the creature takes half as much damage and no additional effects. After casting this jutsu you cannot cast a jutsu with the lightning release keyword until the end of your next turn. *Combination:* *If this jutsu is cast as a Combination jutsu with 2 or more casters reduce the cost by -2.* *Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's offensive abilities based on the highest Charisma Modifier within the group of casters. (+0-1No Change, +2-3Increase damage by 5d10 and inflict another rank of shocked. +4-5Increase damage by 5d10 and inflict another rank of weakened.*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "972061d790a95d9782653591", name: "Lightning Release: Flashy Finale", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self (50-Foot radius)", chakra_cost: "11 Chakra", components: "HS, CM, M", duration: "Instant", description: "You bust out a spectacular move that ends in a dazzling finish. All creatures within range must make a Dexterity saving throw, on a failed save they take 7d8 lightning damage, or half as much on a successful one. If a creature making this saving throw has the dazed condition as a result of the jutsu *Lightning ReleaseElectric Boogaloo*, the affected creature instead takes 7d12 lightning damage on a failed save and must make also Constitution saving throw. This saving throw is made at disadvantage if they failed their Dexterity saving throw. On a failed Constitution save, the creature becomes stunned until the end of their next turn. You can only target 2 creatures that failed their saving throw against Electric Boogaloo with this special effect.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e2d6849ac5b2d29b220d8d66", name: "Lightning Release: Lightning Charged Neurons (Changed)", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "14 Chakra", components: "HS, CM", duration: "1 minute", description: "You send lightning chakra through your central nervous system to massively speed up your body's response time and perceptive abilities. Your movement speed is increased by 15 feet, you gain advantage in Dexterity Saves, Dexterity and Wisdom ability checks, and at the beginning of each of your turns you gain either an additional bonus action or reaction. At the conclusion of this jutsu you gain 1 rank of Weakened and gain the Shocked condition for 1 hour and cannot benefit from this jutsu again until they take a full rest. This jutsu ends early if the target is incapacitated.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "564f6eeb4ba057ea4b22d0e6", name: "Lightning Release: Lightning Floor", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "14 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 1 Minute", description: "You inscribe a large seal on the ground of your design, encompassing a 30-foot radius from where you stand before dissipating. The seal imbeds lightning release chakra into random spots of the ground below, creating an efficient but unassuming trap. For the duration, this jutsu's area is considered difficult terrain. Hostile creatures, even if they are flying that move a space or are knocked into a space within this jutsu's radius must make a Dexterity saving throw. Creatures that do not have either Chakra Sight, True Sight, or Tremor Sense must make this saving throw at disadvantage. On a failed save, the creature takes 5d4+ your Ninjutsu modifier in lightning damage, is knocked prone and gains the Shocked condition until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d4.", created_at: NOW, updated_at: NOW },
  { _id: "66c68aeb5a26c26e4cde79b2", name: "Lightning Release: Weaved Defense", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Reaction, which you take when targeted by a jutsu or forced to make a saving throw as a result of one.", range: "5 feet", chakra_cost: "10 Chakra", components: "HS, CM", duration: "1 Round", description: "You weave hand signs at the speed of light to summon a net made of dozens of lines of thick lightning  chakra. The lightning net then creates a barrier protecting you and anyone within 5 feet of you from damage. The barrier has an AC is equal to your Ninjutsu Save DC, has 10d8 hit points, and is vulnerable to Wind Damage. The barrier disappears at the beginning of your next turn.  Creatures benefitting from this jutsu gain the  benefits of half cover.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 5 and the hit points of the barrier by 2d8. If this jutsu is cast at A-Rank or higher, it now protects anyone within 10 feet of you.", created_at: NOW, updated_at: NOW },
  { _id: "907ea284884d6b5ca39f994d", name: "Lightning Release: Raikiri", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1  Action", range: "Touch", chakra_cost: "20 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "As part of the requirements for casting this jutsu you must have Chidori on your jutsu known list. A more complete version of Chidori. This jutsu forms lightning chakra into a small lightning blade surrounding one of your hands, which will be unable to hold items while charged, but can still be used to make hand seals without harm. As a part of casting this jutsu you make a melee Ninjutsu attack. On a Hit, the target creature takes 10d10 Lightning Damage. On later turns you may use your action to make this attack again. This Jutsu has a critical threat range of 17-20.", at_higher_ranks: "For each rank above A-Rank, increase the cost by 3, increasing the damage done by 2d10 and Critical threat range by +1.", created_at: NOW, updated_at: NOW },
  { _id: "8043a6bfdd7845cb5624e91b", name: "Lightning Release: Soul Echo: Thunder (Changed)", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "16 Chakra", components: "CM, CS, W (Any Melee)", duration: "Concentration, up to 1 Minute", description: "You begin to channel lightning release chakra within your palm as think of justice. The determination to strike down those who oppose the safety of those you love, one by one, until your  friends and family can walk this earth safely. The echoes of your soul empower this jutsu as you bathe the weapon in your chakra. For the duration, your weapon perspires golden lightning, gaining the following benefits; - Your weapon's damage is increased by your Ninjutsu ability modifier, in Lightning damage. - You form an electric link with your weapon, allowing you to call your weapon back to you on or outside of your turn (no action required), if it is within 60 feet of you. When you attack with your weapon, on each attack you are able to go beyond the attack's normal range and throw the weapon up to an additional 30 feet away, calling the weapon back to you after each attack. - When you hit a target with your weapon you mark them with static elecricity. At the start of their next turn, they must succeed a Dexterity saving throw, with a -1 penalty for each attack they were hit with on their turn. On a failure, they struck by lightning, taking your weapon's damage in lightning damage, and being Shocked and knocked prone. - Reduce the cost of all jutsu with the Lightning Release keyword that you cast by -2 (Min. half). Allies within 60 feet of you also reduce the cost of such jutsu by -1 (Min. half). You cannot lose concentration of this jutsu as the result of failing a concentration check and it does not cost chakra to maintain. This jutsu ends early if you let go of your weapon.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ffceb4fff0a743395e133b97", name: "Lightning Release: Zapple", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "300 feet", chakra_cost: "*Special* (110 Chakra)", components: "HS, CM", duration: "Instant", description: "You prepare to summon forth lightning that brings forth the wrath of the sky. You, or allied creature(s) assisting you in casting this jutsu, shoot a beam of light high into the stratosphere. From the light, black thunderclouds form stretching a 1 mile area. You then raise your hand into the sky, calling for the lightning to strike as you throw your hand down pointing a creature you can see within 300 feet. Make a ranged Ninjutsu attack at the target. This attack ignores cover. This jutsu also ignores armor based effects that  would resist this jutsu in any way, such as damage reduction or saving throw bonuses. On a hit, the creature takes 40d6 lightning damage and gains 2 ranks of Shocked. The creature must also make a Strength saving throw, becoming Incapacitated for 1d4 rounds on a failed save. If this jutsu scores a critical hit, instead of doubling the damage die, increase the damage die of this jutsu by 2 steps, and this jutsu ignores resistance and treats immunity as resistance. Lastly, if this jutsu reduces a creature to 0 hit points, the creature falls unconscious, but is stable. *Combination:* *If this jutsu is cast as a Combination jutsu with 2 or more casters increase the damage by 5d6 and gain a +1 bonus to critical threat range.* *Any creature who assists in casting this jutsu as a combination jutsu increases this Jutsu's damage potential based on the highest Charisma Modifier within the group of casters. (+0-2No Change, +3-4The attack roll of this jutsu is always rolled at advantage, regardless of the circumstance, and gains a +1 to critical threat range +5Increase the damage die of this jutsu to d8s, and gain a +1 to critical threat range. This jutsu also gains the benefits of having a +3-4 modifier.)*", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "1b9c40ca48c15e320eac05a7", name: "Dragon Lightning", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["a76452ff37e678bdca89c3ea", "87db194b8f9f4fe2140fb4c3"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "35 Chakra", components: "HS, CM", duration: "Instant", description: "As part of casting this jutsu you must have a sky above you. You gather golden red lightning in your palm and thrust it into the sky, summoning forth 4 great pillars of golden red lighting capable of ravaging even the strongest mythical beasts. When you cast this jutsu, 4 huge strikes of lighting appear in front and behind you, and at your sides. These strikes of lighting travel in a 30-foot straight line moving away from you, passing through creatures. Each creature that this lighting would pass through must make a Dexterity saving throw, taking 14d10 Lightning damage and gaining 1 rank of Shocked until the end of their next turn on a failed save, or half as much damage and no further effects on a success. A creature can be affected by this jutsu a maximum of twice. If there is a creature that within 300 feet above you that would be within range of one or more strikes of lightning when they first appear, the lightning strikes them instead, never hitting the ground next to you and imposing a -1d4 penalty on the creature's saving throw(s).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a067145a8d1ef408c99ebec0", name: "Lightning Release: Electric  Body", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You temporarily transform your body into living lightning bolt. You and your equipment are immune to lightning damage. When you would take lightning damage or suffer an effect cause by a jutsu with only the lightning release keyword, you instead regain hit points equal to half the amount of damage it would normally deal. You gain immunity to blindness, deafness, poison, slashing, piercing or bludgeoning damage. You gain vulnerability to earth damage from Earth or Earth Release Jutsu. Your unarmed melee attacks deal 4d8 Lightning damage. If you would cast a Jutsu that would allow you to deal your unarmed damage that is under the effects of this jutsu, you only deal this jutsu’s damage once, after which you default to your original unarmed damage. Due to your being made of pure lightning your speed is tripled and you have advantage on all Dexterity Saving throws. Jutsu you cast that have the Lightning Release Keyword have their save DC’s increase by +1. If you enter an area that has strong winds you take 4d6 wind damage each round you remain in the area afflicted by the winds.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4360e4428923fc1a5c1b16a8", name: "Lightning Release: Lightning Rain", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "Self (1 Mile Radius)", chakra_cost: "80 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "An advanced form of the Thunderstorm Ninjutsu. A turbulent cloud forms made of lightning; it surges with energy almost breathing lightning. *This jutsu does not cost any additional chakra while concentrating.* For the duration, creatures of your choice under this cloud must succeed a Dexterity saving throw at the end of each of its turns taking 12d8 Lightning damage and being stunned on a failed save or half as much damage and no additional effects on a successful one. Creatures who attempt to cast a Ninjutsu without the Lightning Release Keyword must make a Constitution saving throw or their jutsu is disrupted and failed, as the ambient lightning chakra disrupts their chakra flow. Additionally, jutsu with the Lightning Release Keyword have their cost reduced by 2, and have their damage die increase by 1 step. (d4>d6>d8>d10>d12)", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7b493da6e21ff90941b8786e", name: "Lightning Release: Rolling Thunder", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["87db194b8f9f4fe2140fb4c3", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "25 Chakra", components: "HS, CM", duration: "Instant", description: "You create an enormous ball of lightning in the sky, that festers and rotates producing a destructive wave of thunder that tears the ground asunder. Choose a point within range. The bolts of lightning expand from that point in a 60-foot cube and all creatures in the area must make a Dexterity and Constitution saving throw. Creatures who fail the Dexterity saving throw take 10d10 Lightning damage and become stunned until the end of their next turn, or take half as much damage and no additional effects on a successful save. On a failed Constitution saving throw they become dazed and shocked for 1 minute.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9f0248714d5e7e140597ffbe", name: "Sound Barrier", jutsu_rank_id: "dc532b2f11a7307a387d188c", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 bonus Action", range: "30 feet (5-foot cube)", chakra_cost: "2 Chakra", components: "CS, HS, CM", duration: "Concentration, Up to 1 minute", description: "For the duration, anything within the area of the genjutsu does not produce sound at all. At Higher LevelsThis jutsu’s range increases by 5 feet die when you reach 5th level (10-foot Cube), 11th level (15-foot Cube), 17th level (20-foot Cube).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "87bde642cc5bf3defc2fd833", name: "Amnesia", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "5 Chakra", components: "CM", duration: "1 round", description: "You vibrate your vocal cords and augment them to a distracting hymn, temporarily inflicting amnesia. The target must succeed on a Wisdom saving throw or lose concentration on any jutsu or features that require concentration. A creature cannot begin concentrating on anything until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the duration of this jutsu by 1 round.", created_at: NOW, updated_at: NOW },
  { _id: "686eb9c05e2144db9ffbf669", name: "Charming Pose", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Reaction, which you take when you would be damaged by a creature within range.", range: "10 feet", chakra_cost: "5 Chakra", components: "HS, CM", duration: "Instant", description: "In response to a creature's attack, you attempt to cast a genjutsu to confuse and disarm your opponent in a rather embrassing fashion. The triggering creature must make a Charisma saving throw.  Critical SuccessThe creature is immune to this jutsu's effects for 1d4 rounds.  SuccessThe creature is able to resist this jutsu's effects.  FailureThe creature, in their mind, sees you break out into a dance, emitting an aura of pink dazzling chakra just before their attack connects. The creature gains 1 rank of Charmed until the start of their next turn against you, causing their attack to fail.  Critical FailureSame affects as a failure, but the creature becomes flustered. The creature drops whatever items it may be holding and has their movement speed reduced to 0 until the end of the current turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the range by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "3ae663a2b0243c1f46275181", name: "Headache", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (10-foot radius sphere)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You propose such an idiotic idea to your enemies they take damage just because of how awful it is. All hostile creatures within range must make an Intelligence saving throw or take 2d8 psychic damage and be unable to cast a jutsu that requires concentration until the end of their next turn as their mind is still struggling with the idea.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f91d3e64c9bea8a5b63112ef", name: "Mirror Wall", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "30 feet (20-foot line)", chakra_cost: "5 Chakra", components: "HS, CM", duration: "1 Hour", description: "For the duration you attempt to trick all around you into believing that there is a wall where one is not. All creatures that would see the wall must make a Wisdom saving throw. On a failed save, the creature sees the wall and believes it to be real, treating it as if it were a real indestructable wall. The illusory wall may show whatever the caster desires. The wall has 10 hit points and an AC equal to your Genjutsu Save DC. The wall is 20-foot wide and 10-foot tall, and has no discernable edges. The user can choose to project onto the wall anything they desire, such as animated images, though this effect is purely illusory.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "e22f7460c1cf1374bb2400dc", name: "Sovreign Battle Roar", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Bonus Action", range: "Self (15-foot radius)", chakra_cost: "4 Chakra", components: "HS, CM", duration: "Instant", description: "You take in a large breath, secretly  releasing an wave of invasive chakra at hostile creatures within 15 feet of you. You then make a loud battle cry, and affected hostile creatures hear the cry of a primordial beast, such as a dinosaur, acompany your warcry, echoing throughout the land and reverberating their bodies. Each affected creature must succeed a Charisma saving throw. Creatures under the effects of a Genjutsu you cast, or within 5 feet of you, roll at disadvantage.   Critical SuccessThe affected creature cannot be affected by this jutsu for 1d4 turns.  SuccessThe affected creature feels a chill run down their spine, but is able to resist this jutsu's effects.  FailureThe affected creature is Frightened until the end of your next turn, and on its turn must use half its movement speed to move away from you.  Critical FailureThe affected creature suffers the effect of a failure, and also falls prone.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3c3a5784e1ffcfe6938cd1ba", name: "Suigetsu's Aggressive Minor Illusion", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Bonus Action", range: "60 feet", chakra_cost: "5 Chakra", components: "HS, CM, M", duration: "Instant", description: "Using a modified version of Minor Illusion, you create a doppelganger illusion and erase yourself from the field of view of your target. Allowing you to move  without being noticed. You select a target within 60 feet of you to make a Wisdom saving throw. On a failed they see an illusion of you that acts in a manner of your choice while staying still and can no longer see the real you. Additionally, until the end of your turn your first attack against the target is made at advantage. Either at the end of your turn or when your target takes damage, your illusion fades away and your target is able to see you again.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of this jutsu by 3 and increase the number of targets by +2.", created_at: NOW, updated_at: NOW },
  { _id: "9066a34d91d86fbbac98a3c6", name: "Collapse", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You utter a single word that overpowers and dominates a foe's psyche. Choose one creature that you can see and that can hear you within range. The target creature must make a Wisdom saving throw or take 6d6 psychic damage and fall prone. While a creature is prone in this way they must make a Wisdom saving throw if they attempt to stand, staying prone on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "5d37e555fa84cd8f980c3ef7", name: "Mass Release", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1  Action", range: "Self (15-foot Radius)", chakra_cost: "7 Chakra", components: "HS, CS", duration: "Instant", description: "You take the Release technique and apply it to the area in front of you. You create an aura of forceful chakra to dispel genjutsu from those in front of you. You must first be aware that the targets in the area are under the effects of a genjutsu. As part of the casting of this jutsu, make an Illusions skill check at advantage against the saving throw DC of the genjutsu the targets are being affected by. On a success, you free the targets from the genjutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "996321753e770aa427720c53", name: "Mental Flashbang", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You create a depraved visual, almost making sight itself seem like a curse. All creatures in a 15-foot radius sphere centered on a point you can see within range, must succeed a Wisdom saving throw.  Critical SuccessThis creature ignore the effects of this jutsu.  SuccessAffected creature gain 1 rank of dazzled.  FailureAffected creatures Blinded until the end of their next turn.  Critical FailureAffected creatures becomes blinded and concussed and must remake the Wisdom saving throw at the end of each of its turns to end the blinded condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6561f72ce8624d09612ddd4d", name: "Rewire", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "9 Chakra", components: "HS, CM", duration: "Instant", description: "You temporarily rewrite the neural pathways of a creature hampering their ability to fight effectively. One creature you can see within range must make an Intelligence saving throw.  Critical SuccessAffected creature is able to resist this Jutsu's effects becoming immune to it for the next minute cast from the same creature. SuccessAffected creature is able to resist this jutsu’s effects. FailureAffected creature gains 1 rank of confused. Critical FailureAffected creatures gains 3 ranks of confused.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7f6b76c56e80f6bfd7685108", name: "Demonic Culling: Sleep Inducement", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "This genjutsu targets a single target, forcing a wave of drowsiness to overtake them and knock them out. They then enter a dream like state, experiencing joys that they'll never want to leave. Select one creature you can see within range. The selected creature must make a Wisdom Saving throw. If the creature has already awoken from this jutsu they remake future saves at advanatge. Critical SuccessAffected creature is able to resist this jutsu's effects and always has advantage against this jutsu for the remainder of combat.  SuccessAffected creature is able to resist this jutsu's effects.  FailureAffected creature becomes unconscious. At the beginning of each of their turns they may remake the save, waking up on a success and staying asleep on a failure. If the target takes damage while asleep they instantly wake up.  Critical FailureAffected creature becomes unconscious. At the end of each of their turns they may remake the save, waking up on a success and staying asleep on a failure. Whenever the target takes damage while asleep they make another save at advantage to wake up.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by and the number of targets by +1.", created_at: NOW, updated_at: NOW },
  { _id: "e16fae96ecf60bc930fed8e3", name: "Greyoll's Roar", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 feet (20-foot radius)", chakra_cost: "12 Chakra", components: "HS, CM, NT (Poison Kit)", duration: "Instant", description: "You manifest a scarlet colored poison meant to create mass hysteria and horrific illusions at creatures within range. Each creature within range must make a Wisdom saving throw, taking 5d10 psychic damage on failed save plus additional effects depending on their results.  SuccessOn a successful save the affected creature takes half damage and is able to resist this jutsu's other effects.  FailureThe creature's vision briefly darkens and from this darkness, the head of fearsome dragon appears and emits a roar that disturbs the creature to its very core. The creature takes this jutsu's damage is knocked back 15 feet, falls prone, and gains 1 rank of Fear.  Critical FailureSame affects as a failure and the next damage roll the creature deals to another creature while it possesses this rank of fear is halved, as they are so caught up in shock and paranoia that they cannot fight properly.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, the range by 15 feet, and the radius by 5 feet.", created_at: NOW, updated_at: NOW },
  { _id: "070b1b62c23e8dcfeb25fedb", name: "Numbness", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70", "aaeecd12fb6a8f889a26ab97"], elements: [], casting_time: "1 Reaction when you or an allied creature", range: "30 feet", chakra_cost: "13 Chakra", components: "HS, CM", duration: "1 Round", description: "When you or an allied creature in range would take damage, you may use your telekinetic abilities to enter their mind and numb their ability to feel pain. The target creature gains resistance to all damage until the start of your next turn and gains temporary hit points equal to your genjutsu ability modifier until the end of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "cbf761059482d79680a0c450", name: "Psychic Torment", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "Self (20-foot radius sphere)", chakra_cost: "14 Chakra", components: "HS, CM", duration: "Instant", description: "You shoot out a burst of psychic energy to terrorize and torment all who would oppose you. All creatures you can see within range must make a Wisdom saving throw.  Critical SuccessThis creature ignore the effects of this jutsu.  SuccessAffected creature take 3d10 psychic damage and 1 rank of dazzled.  FailureAffected creatures take 4d10 psychic damage and become concussed until the end of their next turn.  Critical FailureAffected creatures take 6d10 psychic damage and become blinded and gain 1 rank of concussed. A creature who has a condition as a result of this jutsu remakes the saving throw at the end of each of their turns, ending the condtion(s) on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bee2a3fc0afc3de101e959d0", name: "Refract", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "11 Chakra", components: "CM, HS", duration: "Concentration, up to 1 minute", description: "You create 3 false clones of yourself that trail behind you them making it much more difficult for attackers to determine who they need to attack. You gain a +4 to their AC for the duration of the jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6c5a5467b0d83b972ca7c2ea", name: "Suspicious Calm", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "12 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You utter words that come out as a soft calming whisper, ensuring them that everything will be ok. A creature you can see in range must make a Wisdom saving throw. A creature charmed by this jutsu repeats their saving throw once per round when they take damage, or at the end of each of their turns, ending this jutsu's effects on a success. Critical SuccessThe target is able to resist this jutsu's effects and is immune to it for 1 minute.  SuccessThe target gains 1 rank of charmed until the start of their next turn and suffers no additional effects.  FailureThe target gains 2 ranks of charmed, and reduces their movement speed by half while they are charmed by this jutsu.   Critical FailureThe target gains 3 ranks of charmed, drops any items they may be holding, and is slowed while they possess ranks of charmed from this jutsu.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and number of creatures you can affect with this jutsu by +1.", created_at: NOW, updated_at: NOW },
  { _id: "09d1f29f26bbe777ac1d1a9d", name: "Demonic Illusion: Tree Binding Death Explosion", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Bonus Action or Reaction, which you can take when you have any number of targets caught under the effects of Tree Binding Death, cast by you.", range: "90 Feet", chakra_cost: "15 Chakra", components: "CM, HS", duration: "Instant", description: "To cast this jutsu you must have  *Tree binding Death* as a part of your known jutsu list. As you finish tree binding you quickly enhance the jutsu with a genjutsu, trapping the target in their own mind trapped by a cherry blossom tree as paper tags litter it detonating causing the Tree Binding Death Genjutsu to end early, The targets take 8d10 Psychic damage, and must make a Charisma saving throw. On a failed save,  they are convinced that all trees around them will explode must immediately at the start of each of their turns move as far away as they can away from all types of  trees. Creatures who failed can repeat the saving throw at the end of their turns, ending this effect on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6258b3c1a1490a0076db72ae", name: "Chorus of Screams", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea"], elements: [], casting_time: "1 Action", range: "30 feet (15-foot radius)", chakra_cost: "18 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You throw your voice and envelope your opponent’s cacophonous screech disorienting them. All creatures of your choice within range must make a Wisdom saving throw reducing their movement to 0 and becoming incapacitated on a failed save. A creature who fails this saving throw increases the area by 5 feet and any creatures who previously passed the initial saving throw must repeat the saving throw again. An affected creature repeats this saving throw at the end of each of their turns for the duration. This jutsu has a maximum area of effect of 30 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "093ccd7fbc774cd71b324156", name: "Mark of Calamity", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Full-Turn Action", range: "Self (15-foot Radius)", chakra_cost: "20 Chakra", components: "HS, CM", duration: "1 Round", description: "You focus your chakra inward and channel chakra to the middle of your forehead, opening your mind's eye. Each creature of your choice within 15 feet must make an Intelligence saving throw as they hear  a piercing sound. A creature can fail this saving throw twice before they become immune to this jutsu until they take a short rest. Critical SuccessThe target is able to resist this jutsu's effects and becomes immune to it for the next minute.  SuccessThe target takes half the result of an 8d6 as psychic damage and suffers no additional effects.  FailureThe target takes 8d6 psychic damage and is marked with the *Mark of Calamity* until the end of their next turn, which only you and affected creatures can see. The *Mark* *of Calamity* appears as a red demonic eye floating above the creature's head. When a creature with this mark next takes damage, they an additional amount of psychic damage equal to half the damage dealt (this does not stack with vulnerability. This jutsu's effects then end on them.  Critical FailureSame effects as a failure, however, the damage becomes 8d8 and the target is painfully levitated 30 feet above the ground and then released (fall damage received does not trigger the *Mark of Calamity*).", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "5dc04e3558cf800f37f62fea", name: "Psionics: Guard Swap", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc", "b5e8ac06ada0310dcd377049"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "19 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "*As part of the requirements for casting this jutsu you must have at least 1 vulnerability, resistance, or immunity to a damage type as the result of a jutsu, feat, or feature.* You outstretch your hand and select a target within range. You attempt to analyze the creature's chakra network to override their senses with your own, whilst simultaneously mimicking theirs. The creature must make an Intelligence saving throw.  SuccessThis jutsu ends and the target is able to resist this jutsu's effects.  FailureAny vulnerabilities, resistances, or immunities that the target may possess as the result of a jutsu, feat, feature, or trait, are swapped with your own. If their vulnerabilities, resistances, or immunities comes from a jutsu that has a duration, they become unable to end the jutsu(s) providing these statistics to them as you take control of it. Once this jutsu ends, both you and the creature have your statistics returned to normal. The target can use their action to remake the saving throw, ending this jutsu's effects on a success.  Critical FailureSame affects as a failure, however, the target cannot reattempt the saving throw.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "582efa7df264a292065a7459", name: "Sudden Doubts", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b7c3bde363176d05f69f793a", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Reaction, when you see a creature make an attack roll or cast a Ninjutsu, Taijutsu, or Bukijutsu that would negatively affect you or an ally.", range: "60 Feet", chakra_cost: "15 Chakra &emsp;", components: "HS, CM", duration: "Instant", description: "You generate feels of doubt and dread within a creature causing them to think twice about their attack. The creature must make a Charisma saving throw. &emsp;&emsp;&emsp; Critical SuccessThe creature is immune to this jutsu's effects and remains immune for the next minute. &emsp;&emsp;&emsp; SuccessThe creature carries through with their action as normal, but hesistates, dealing half damage and granting creatures a +1d4 bonus to any saving throws they make. &emsp;&emsp;&emsp;&emsp;&emsp;&emsp; FailureThe creature doesn't go through with their action, wasting it. &emsp;&emsp;&emsp;&emsp;&emsp;&emsp;&emsp; Critical FailureSame affects as a failure, but the creature feels so concerned that they use their action to cast a jutsu or use an ability to benefit the creature's they would've harmed.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "471c4f671ba26f6cdce8a218", name: "Fall", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "30 Chakra", components: "CM", duration: "Concentration, up to 1 minute", description: "You utter a single word of absolute dread, dredging up the innate fears of a creature. Choose up to three creatures you can see within range. The target(s) must make a Charisma saving throw. On a failed the target(s) are incapacitated, blinded, and knocked prone, as the weight of their soul crushes them. A prone creature struggles to even stand and must make a Charisma saving throw to do so. On a failed save, they remain prone and immediately end their turn. On a successful save, the target can stand up and take one action before falling prone and ending their turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "19d02cffb60e3419b246d6e7", name: "Infinite Abyss", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "3d4ef417aa13fb1eaec5abc1", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "28 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "You convince a creature they are falling forever and that there is no escape, this fear swallowing them whole. A creature you can see within range must make a Wisdom saving throw or gain 5 ranks of fear and they begin falling in a dark abyss in their minds. For each turn this jutsu is active they take psychic damage as if they had fallen 100 feet. This damage does not trigger until the jutsu ends. If a creature takes psychic damage as a result of this jutsu the fall prone.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0c22947aba9db1fd0eea9779", name: "Insufferable Pain", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "90 Feet", chakra_cost: "30 Chakra", components: "HS, CM", duration: "Concentration, up to 1 minute", description: "As a part of the requirements to cast this jutsu, you must target a creature currently under the effects of *Pain*, *Doubled Pain* or *Unlimited Pain.* You end your concentration on that jutsu and this one takes its place. You retain all the effects of that jutsu and add this jutsu’s effects to them. You magnify the suffering of a creature, bringing creatures to even writhe in agony at even the thought of being subjected to this jutsu. One creature you can see within range must succeed an Intelligence saving throw. On a failed save, for the duration, each time a creature takes damage, as a result of this jutsu are vulnerable to its damage. Additionally, they have disadvantage on attack rolls, ability checks, and saving throws.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b5cab47f84c93ba295623d43", name: "Psychic Scream", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "90 feet", chakra_cost: "28 Chakra", components: "HS, CM", duration: "Instant", description: "You unleash the power of your mind to blast the intellect of up to ten creatures of your choice that you can see within range. Creatures that have an Intelligence score of 2 or lower are unaffected. Each target must make an Intelligence saving throw. On a failed save, a target takes 14d6 psychic damage and is stunned. On a successful save, a target takes half as much damage and isn't stunned. If a target is killed by this damage, its head explodes, assuming it has one. A stunned target can make an Intelligence saving throw at the end of each of its turns. On a successful save, the stunning effect ends.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ec6dbabdad63914c6243945e", name: "Squid Game", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "52254addcf8df274fe8214cc", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "90 feet (30-foot radius)", chakra_cost: "45 Chakra", components: "HS, CM, CS", duration: "Concentration, up to 10 Minutes", description: "You invade the minds of creatures causing them to become maddened with rage and turn against each other. Select up to 3 creatures within 30 feet of each other that are no more than 90 feet away from you. These creatures must make a Charisma saving throw, becoming Berserk on a failed save. This jutsu's effects change depending on how many targets fail this saving throw. The eyes of affected targets glow a noticable bright red. You do not spend chakra to concentrate on this jutsu, however, you cannot benefit from effects that would grant you advantage on concentration checks or allow you automatically succeed them for the duration. If an affected creature would be targeted by the Genjutsu *Release*, the caster cannot gain advantage on the chakra control check, and rolls at disadvantage if the target it not bloodied. If all three targets fail this saving throw, the creatures gain a bonus to attack and damage rolls equal to your Genjutsu ability modifier, and only attack each other on their turns. These creatures cannot deal non-lethal damage. If a non-affected creature attacks or makes a loud distraction at one or more of these creatures, they will begin attacking them, going back to killing each other if they successfully kill the distractor. If only one or two creatures fail this saving throw, the affected creatures gain 100 temporary hit points and gain a bonus to attack and damage rolls equal to half your Genjutsu ability modifier, rounded up. These creatures then begin attacking the creature(s) that succeeded to the death. If an affected creature would take damage while Bloodied (under 50  of their maximum hit points) from a creature not being affected by this jutsu, they can begin remaking the Charisma saving throw, ending this jutsu's effects on them on a success and becoming immune to it for 1 week.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a24f6224629fd62355922d67", name: "The Farthest Star", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "97a529e82067b359e2044cea", "79eaf0305561cf512f55ad70", "52254addcf8df274fe8214cc"], elements: [], casting_time: "1 Action", range: "60 Feet", chakra_cost: "30 Chakra", components: "CM", duration: "Instant", description: "You fill a creature's thoughts with esoteric knowledge not fit for the living. Choose a creature you can see within range. The target must succeed on an Intelligence saving throw or take 8d12 psychic damage and gain 5 ranks of fear. A creature that has ranks of fear granted by this jutsu makes another Intelligence saving throw at the start of each of their turns, ending the fear condition on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "4475cd08696b22a894536a01", name: "Thought Bomb", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["b7c3bde363176d05f69f793a", "79eaf0305561cf512f55ad70"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "30 Chakra", components: "CM, HS", duration: "Instant", description: "A jutsu created for the purpose of destroying the higher functions of the brain, and those that could use them better. Choose one target within range, the target must make a Intelligence saving throw, taking xd10 (x=the intelligence score of the target) on a failed save and no damage on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "59ed7617b659e76ce07ab883", name: "Blooming Cherry Blossom", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "Action", range: "5 feet", chakra_cost: "5 chakra", components: "M, CM", duration: "Instant", description: "You rush towards a target before unleashing a volley of attacks. Make two taijutsu attacks on a creature within range. On a hit you deal your unarmed damage + 1d6. If you hit with two or more of these attacks the target is knocked prone.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank increase the cost of the jutsu by 3 and increase the damage by 1d6. If this jutsu is cast at B- Rank of higher increase the number of attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "11bf7ecf0d5ad64093730567", name: "Bearic Maul", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 action", range: "15 feet", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu,  you must currently be in the *Bear Fist Stance*. You do not add your ability modifier to your unarmed damage with this jutsu. Primal fury consumes your mind in the moment as you make a mad dash at your prey. As part of casting this jutsu you can move up to 20 feet then make three melee taijutsu attacks against a target in reach. On each hit, you deal your unarmed damage + 1d4 slashing. If at least one of these attacks hit then the target must make a Constitution saving throw, gaining 1 rank of Bleeding on a failed save. If the creature you target with this jutsu is also the target for your *Bear Fist Stance's* *Apex Might* or *Predator's Pride* feature, on each hit, you instead deal your unarmed damage + 1d6 slashing and the target must make a Constitution saving throw for each successful hit, gaining 1 rank of Bleeding on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the number of taijutsu attacks by +1.", created_at: NOW, updated_at: NOW },
  { _id: "2d415183fa9230fc4445a22c", name: "Deflect Missiles", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you would be damaged by a ranged weapon attack.", range: "Self", chakra_cost: "5 Chakra", components: "M", duration: "Instant", description: "When you would be damaged by a ranged weapon attack, you attempt to catch and deflect the attack back at the attacker with grace. Reduce the damage dealt to you by your unarmed damage die + 2d8. If you reduce the damage to 0, you can choose  to deflect the ranged attack back at the target if they are within 60 feet of you. You make the attack as a ranged taijutsu attack, regardless of the attack’s properties.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage reduction by 1d8+3. If cast to B-Rank or higher, this jutsu can be used on any type ranged attack from a weapon.", created_at: NOW, updated_at: NOW },
  { _id: "6a26eeb76d3531b9b96fe18a", name: "Ripple of Earth: Mole Claws", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of earth release chakra throughout your entire body. You form earth chakra over your hands in the shape of claws as you slash at an enemy, trying to break them. Make a melee taijutsu attack, dealing your unarmed damage + 2d8 Earth damage. The affected creature must succeed a Constitution saving throw or gain a rank of Bruised. If there are any non-sentient earthen constructs within 30 feet created by an allied creature, you can choose to quickly dig and cast this jutsu as if you were in the constructs space, increasing the damage dealt by 1 step.  You then exit the construct, appearing in a space within 5 feet of it.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "96968e498029d8411c44eb9a", name: "Ripple of Earth: Tectonic Shift", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["587205fc5e2f018201761d63", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "You stomp the ground with incredible force causing a boulder to be chinked from the ground in front of you. You then make a frontflip, channeling earth release chakra to increase your strength, grab the boulder and throw it at a creature within range. Make a ranged taijutsu attack, dealing your unarmed damage + 3d6 Earth damage and the creature must make a Constitution saving throw, becoming Dazed on a failure.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost by 3, the damage by 2d6, and the range by 15ft.", created_at: NOW, updated_at: NOW },
  { _id: "3bdb1fe2cd91fe5918d891fa", name: "Ripple of Wind: Air Whip", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of wind release chakra throughout your entire body. You whip your body around violently and strike a creature within range. Make a melee taijutsu attack. On a hit, you deal your unarmed damage and the target gains 1 rank of bleeding. The target must also make a Constitution saving throw, becoming Dazed and being knocked back 15 feet on a failed save. *Swirl.* Creatures who would fail their saving throw, spreads all Elemental conditions currently affecting them around to all creatures, excluding the caster within 5 feet of them. Hostile creatures within 5 feet of the failing one gains 1 rank of all elemental conditions currently affecting it.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to B-Rank, multiply your unarmed damage by 2 when dealing damage with this jutsu. If cast to S-Rank, multiply your unarmed damage by 3 when dealing damage with this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "d93d98061e90d7aff06c0690", name: "Ripple of Wind: Sonic Boom", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["be25cd280a254892a04b3a6b", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of wind release chakra throughout your entire body. You punch the air in front of you with the force to create a small scale sonic boom. Make a melee taijutsu attack against a target within range, dealing your unarmed damage + 2d6 and imposing a Constitution saving throw, where failure causes the creature to become Deafened until the end of their next turn. *Swirl.* Creatures who would fail their saving throw, spreads all Elemental conditions currently affecting them around to all creatures, excluding the caster within 5 feet of them. Hostile creatures within 5 feet of the failing one gains 1 rank of all elemental conditions currently affecting it.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to  B-Rank or higher, increase the number of attacks made by +1. If cast to S-Rank or higher, increase the number of attacks made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "90cc00154f4029a85ee1ba92", name: "Ripple of Fire: Hell Port", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1  Action", range: "30 feet", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of fire release chakra throughout your entire body. You instantly teleport in a burst of flames, reappearing in another location within range. When you reappear, you use the opportunity to make a single strike. Make a melee taijutsu attack, dealing your unarmed damage+1d10+1 fire damage. This jutsu nor its damage can be reacted to. You leave behind a trail of fire from where you once stood to where you appear.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage by 1d10+1.", created_at: NOW, updated_at: NOW },
  { _id: "707cc90f47ce2f0b0c113ac3", name: "Ripple of Fire: Incinerating Revenge", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["146f92dbec13f8ccb9d843cb", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you would be damaged by an attack roll", range: "Self", chakra_cost: "5 Chakra", components: "CM, M", duration: "1 Minute", description: "You inhale and take a charging stance, manifesting ripples of fire release chakra throughout your entire body. In response to recieving damage from an attack you coat your body in flames of revenge. Reduce the damage recieved by 3d6. This damage reduction is doubled against fire damage, and halved against cold damage. For 1 minute, the next taijutsu attack you make gains the effects of *Blaze*, dealing an additional amount of fire damage equal to the number of damage die used. If the taijutsu attack is perfomed with a Taijutsu with the fire release keyword, double the damage bonus of Blaze.  Once this damage triggers, this jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and the damage reduction by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "904e283c92ce1aae74c28650", name: "Ripple of Water: River Kunai", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of water release chakra throughout your entire body. You form two kunai made completely out of water in both of your hands and slash at a creature within range. Make two melee taijutsu attacks, dealing your unarmed damage + 1d10 on each hit. These attacks do not add your ability modifier to the damage roll. A creature hit by 2 attacks from this jutsu must make a Strength saving throw, gaining  1 rank of Chilled on a failed save. *Saturation.* If this jutsu is used near a sufficient source of water, reduce the cost of this jutsu by -2 or add your ability modifier to this jutsu's damage rolls.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3. If cast to B-Rank or higher, increase the number of attacks made by +1. If cast to S-Rank or higher, increase the number of attacks made by +1.", created_at: NOW, updated_at: NOW },
  { _id: "5c7b2d699349a9fd4cacca83", name: "Ripple of Water: Tidal Palm", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["b816b9a2e7670f7792937f0e", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Touch", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of water release chakra throughout your entire body. The user solidly plants both hands directly onto a creature's torso within range, then fires a short high-pressure burst of water that can shatter steel.  Make a melee taijutsu attack, dealing your unarmed damage + 2d4 Cold damage. The target must make a Strength saving throw, being knocked back 10 feet and becoming Dazed on a failed save. *Saturation.* If this jutsu is used near a sufficient source of water, increase the knockback of this jutsu by 10 feet or the damage by 1d6.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the knockback by 10 feet, the total damage dice by 1, and the damage die by 1 step (1d4<1d6<1d8<1d10<1d12).", created_at: NOW, updated_at: NOW },
  { _id: "a9f116f686bdf9f0560a767e", name: "Ripple of Lightning: Flash Punch", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["a76452ff37e678bdca89c3ea", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "15ft", chakra_cost: "4 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of lightning release chakra throughout your entire body. You rear your hand back and coat it in a controlled lighting as you dislocate your bones and keep them together with no pain thanks to the lightning, striking at an enemy unexpectedly. Make a melee taijutsu attack dealing your unarmed damage + 2d6 Lightning damage, the creature must then make a constitution saving throw, gaining shocked on a failed save. OverchargeWhen you cast this jutsu, as a bonus action or reaction, you can overcharge its effects. When you do this jutsu becomes unreactable", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d6 and increase the range by 5ft", created_at: NOW, updated_at: NOW },
  { _id: "9edb287538875ebcb00c5a4e", name: "Ripple of Lightning: Wave Kick", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a76452ff37e678bdca89c3ea"], elements: [], casting_time: "1 Action", range: "5ft", chakra_cost: "5 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of lightning release chakra throughout your entire body. You coat your knee in a sharp coat of lightning and rapidly strike and an creature with it, hitting them directly in the stomach. Make a melee taijutsu attack, dealing your unarmed damage + 3d4 Lightning damage, this jutsu ignores half of a creatures damage reduction. OverchargeWhen you cast this jutsu, as a bonus action or reaction, you can overcharge its effects. When you do this the affected creature must make a constitution save gaining a rank of slowed on a fail.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d4, if this jutsu is cast at B-Rank or higher you ignore damage reduction entirely.", created_at: NOW, updated_at: NOW },
  { _id: "233c2298fcbfe836dc1562b5", name: "Wave Dash", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you would be targeted with an attack of opportunity.", range: "Self", chakra_cost: "4 Chakra", components: "M", duration: "Instant", description: "In response to a creature aiming to take advantage of your supposed poor decision to move, you showcase that their counterattack was part of your plan, and move to make your own counter to their counter. Increase your AC by +3 against the triggering attack, after the triggering attack hits or misses, you move to a space within 15 feet. Regardless of whether the triggering creature hits you, you make one melee taijutsu attack against them as you move, dealing your unarmed damage on hit and reducing their movement speed by 5 feet until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above D-Rank, increase the cost of this jutsu by 3, and the distance you can move by 10 feet. If cast to B-Rank or higher, you make an additional attack. If cast to S-Rank or higher, you make an additional attack.", created_at: NOW, updated_at: NOW },
  { _id: "7890d23e9862badd689df535", name: "Youth Style Stance", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "5 Chakra", components: "M", duration: "1 minute", description: "You put one arm behind your back and your other Infront of you. Entering the signature stance of the hidden leaf village. If combat begins within the next minute, you gain the following benefits: - During the first 3 rounds of combat you may switch your taijutsu stance as a free action once per turn. - You add a +5 bonus to your initiative roll. - During the first round of combat you may take the dash action as a free action. - In the first round of combat, you have advantage on all unarmed attacks, and deal an additional amount of damage equal to your proficiency modifier. This jutsu can only be used while you are not concentrating on any jutsu. If no combat begins within 1 minute, the jutsu fizzles out.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "ab0a42951e3e498bf532f50c", name: "Cherry Blossom Clash", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1  Action", range: "5 ft.", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "You throw your fist forwards attempting to strike your opponent with a mighty blow. Make a melee Taijutsu attack, on a hit you deal your unarmed damage + 4d8 and the target makes a constitution saving throw. On a failed save they are knocked back 30ft. This jutsu then ends. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage as if they had fallen an equal distance. If this jutsu is used as a *Finisher*, the creature gains the dazed condition until the end of their next turn ,the knock back is increased by 30 ft, and the initial damage die size is increased to d10s.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of the jutsu by 3, increase the damage by 1d8, and the knock back by 10ft.", created_at: NOW, updated_at: NOW },
  { _id: "c3f9726da866bb1aa7194f1b", name: "Colossal Impact", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1  Action", range: "5 ft. (30 ft. Radius)", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "You drive your fist into the stomach of a creature with enough power to lift them off their feet, you then slam them into the ground with a massive amount of force. Make a melee Taijutsu attack, on a hit you deal your unarmed damage + 3d8 and each creature (excluding you) within 30 ft. must make a dexterity saving throw as you slam the creature into the ground taking 3d6 bludgeoning damage on a failed save or half as much on a success. The creature you initially attacked automatically fails this saving throw and is knocked prone.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank increase the cost of the jutsu by 3 and increase the damage by 1d8 and 1d6.", created_at: NOW, updated_at: NOW },
  { _id: "9e975f18cd157b34f00fd393", name: "Fearful Fist", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "5 Feet", chakra_cost: "9 Chakra", components: "M", duration: "Instant", description: "You punch in a maniacal fashion, only a psychopath would enjoy a fight this much. Make a melee taijutsu attack dealing your unarmed damage + 3d10 and forcing the target to make a Wisdom saving throw, inflicting 1 rank of fear on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "dabb0d2a71aa83f5e703d362", name: "Finger Breaker", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, when you see a creature cast a jutsu using hand signs", range: "5 Feet", chakra_cost: "9 Chakra", components: "M", duration: "Instant", description: "You see a creature weaving hand signs and attempt to stop them by disrupting their hands. Make a melee taijutsu attack contested by the creature's Intelligence (Ninshou) check if Ninjutsu, or Wisdom (Illusions) check if Genjutsu. roll. If your roll is higher than your opponent’s the jutsu fails and you may make an unarmed attack against the creature dealing your unarmed damage and using the same attack roll you used to disrupt this jutsu. If the hostile creature rolls higher, their jutsu proceeds as normal.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "34f7e276147911c24a1c507f", name: "Iron Throw", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Bonus Action", range: "60 feet", chakra_cost: "5 Chakra", components: "M, W (Blocking, Light)", duration: "Instant", description: "You ready a weapon in hand and throw it at a creature with such precision to have notable impact whilst also having the perfect trajectory to fly back to you. Make a ranged taijutsu attack. On a hit, you deal twice your unarmed damage, and the next melee attack you make against the creature before the end of the turn is made at advantage. Regardless of a hit or miss, your weapon returns to you.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6b68001c05e5152fc5cd2c8e", name: "Protest", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "8 Chakra", components: "M, W (2x Tonfas)", duration: "Concentration, up to 1 Minute", description: "As a requirement to activate this jutsu, you must currently be in the *Ryukyu Fist Stance*. When this jutsu is cast, and once on each of your turns, you can as a bonus action make a 2 melee taijutsu attacks against a creature within range, dealing your unarmed damage on each hit, but do not add your ability modifier to the damage dealt. These attacks score a critical hit on a 19-20. If you score a critical hit with these attacks you can activate the critical hit based effects of the *Ryukyu Fist Stance*, without expending your use limit of these effects.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3. If cast to  B-Rank or higher, increase the bonus to critical threat range by +1. If cast to A-Rank or higher, increase the number of attacks by +1. If cast to S-Rank or higher, you may now add your ability modifier to the damage dealt.", created_at: NOW, updated_at: NOW },
  { _id: "775e2d523e00ad34236957ee", name: "Leaf Rising Wind (Changed)", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "This technique uses the entire body as a spring, by amassing power through taking a posture where the back of the body falls down. With this powerful taijutsu, the user kicks just above the head. Because the power of the kick from the ground is instantly converted into a blow, the enemy hit with this attack will be launched high into the sky. Make a melee Taijutsu attack, on a hit the target takes 4d10 bludgeoning damage, and is launched into the air 15 feet. If this jutsu is cast as a *Finisher*, you instead deal your unarmed damage + 5d10 bludgeoning and knock the creature 30 feet into the air.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the damage by 1d10, and the knockback by 10 feet.", created_at: NOW, updated_at: NOW },
  { _id: "38970a9ce673f9e9c1fd6f87", name: "Overbearing Crush", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action, while you are grappling or restraining a creature", range: "Touch", chakra_cost: "7 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu,  you must currently be in the *Bear Fist Stance*. You bear all your crushing strength into squeezing the life out of a creature you have grappled or restrained. The target automatically takes your unarmed damage in bludgeoning damage, and the creature must make a Strength saving throw. On a failed save, the target gains 1 rank of Bruised. If the save was failed by 5 or more, it is also Weakened until the end of its next turn. If the creature you target with this jutsu is also the target for your *Bear Fist Stance's* *Apex Might* or *Predator's Pride* feature, it suffers a penalty to this saving throw equal to half the result of 1 die's worth of your unarmed damage die.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the ranks of Bruised inflicted by +1.", created_at: NOW, updated_at: NOW },
  { _id: "9f433c899d16b4f3312abcab", name: "Red Rush", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "6 Chakra", components: "CM, M", duration: "Instant", description: "You flood your body with intense chakra, doubling your heart rate and speed for a moment, giving you a momentary red aura that radiates like fire around your body. Move to a space within your movement speed. This jutsu allows you to move within the air as if you were flying, ignoring difficult terrain and hostile speed reducing effects. If there is a creature within your path, you make one melee taijutsu attack against them, dealing your unarmed damage and knocking them back 40 feet. If you score a critical hit with this attack, double the knockback. If you a hit a creature this way, your movement  stops and this jutsu ends early.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, the distance you can move by 30 feet, and the knockback by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "0f71b71899c1b1f9b7a86206", name: "Ripple of Earth: Concrete Run", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "8 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of earth release chakra throughout your entire body. You flood earth chakra through your feet to turn the ground below you into a partially solid liquid akin to semi-hardened concrete. You begin to glide along this substance, moving to a space within reach of your movement speed, ignoring land based difficult terrain. Make a melee taijutsu attack against each creature you pass by, dealing your unarmed damage on hit and imposing a Constitution saving throw, where failure causes the creature to gain 1 rank of Bruised. Some of the transformed earth sticks to your body as you move, granting you the benefits of the jutsu *Earth ReleaseBedrock Skin* cast at D-Rank until the start of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "87216f75b63066764e2a9ce4", name: "Ripple of Earth: Richter Scale", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["587205fc5e2f018201761d63", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Bonus Action", range: "30 feet", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of earth release chakra throughout your entire body. You stomp the ground with incredible force, causing the battlefield to quake and the ground in front of you to split in a 30-foot long, 5-foot wide line. Each creature within range must make Dexterity saving throw, falling prone on a failure. Select one creature that failed their saving throw. You channel earth release chakra through the crack in the earth at the space they have fallen, causing a large pillar of rock to emerge and strike the creature. The creature takes 2d10 Earth damage and is knocked up 30 feet into the air. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost by 3 and the damage by 1d10. If cast to A-Rank or higher, add your unarmed damage to the damage of this jutsu.", created_at: NOW, updated_at: NOW },
  { _id: "fc850a5f4aae1e0e36c8fc47", name: "Ripple of Wind: Gale Barrier", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "Self", chakra_cost: "7 Chakra", components: "CM, M", duration: "1 minute", description: "You inhale and take a charging stance, manifesting ripples of wind release chakra throughout your entire body. You form a barrier of wind release chakra around yourself which acts like a barrier that cushions any attack. The barrier is only as strong as you. For the duration, you gain a number of temporary hit points equal to your unarmed damage + 15. These temporary hit points have resistance to Bludgeoning, Slashing, and Lightning damage, and vulnerability to Piercing and Fire damage. Once the temporary hit points of this jutsu becomes 0, this jutsu immediately ends.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the temporary hit points by 10.", created_at: NOW, updated_at: NOW },
  { _id: "87985a99ffefc7b1cd725b51", name: "Ripple of Wind: Sweeping Gale", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["be25cd280a254892a04b3a6b", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Self (20-foot sphere)", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of wind release chakra throughout your entire body. You take in a deep breath and exhale a large quantity of golden wind from your lungs. With open palms, you use your arms to disperse the wind in a 20-foot sphere. Each creature within range must make a Dexterity saving throw, being pushed up to 5 feet of you on a failed save. You then make a spinning roundhouse kick against each creature. Make one melee taijutsu attack against each creature of your choice within 5 feet of you, dealing your unarmed damage + 4d4 and knocking the creature prone and back 15 feet on each hit. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "03c04a6f22d3c3e25aec8738", name: "Ripple of Fire: Falcon Kick", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "8 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of fire release chakra throughout your entire body. You coat your body in a flames and dash forward unleashing a devastating kick. Make a melee taijutsu attack against the creature dealing unarmed damage + 4d8 fire damage on a hit. Regardless if you hit or miss, you end your movement within 5 feet of the original target. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3d7eda7c29ae6556be936f7c", name: "Ripple of Fire: Raptor Boost", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["146f92dbec13f8ccb9d843cb", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Bonus Action", range: "15 Feet", chakra_cost: "8 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of fire release chakra throughout your entire body. You boost yourself towards your target being aided by your flames before executing a powerful uppercut. Make a melee taijutsu attack against the creature dealing unarmed damage + 4d6 fire damage on a hit and knocking them up 10 feet. A creature hit by this jutsu make a Constitution saving throw, gaining the burned condition on a failed save. Regardless if you hit or miss, you end your movement within 5 feet of the original target.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "11f6e9a518469be659432b07", name: "Ripple of Water: Rain Squall", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action, which you can only take while airborne.", range: "Self (10-foot sphere)", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of water release chakra throughout your entire body. As you jump, you clasp your hands together forming a burst of water in a 10-foot sphere centered on yourself. All creatures within range, excluding you, must make a Strength saving throw. On a failed save, creatures take 5d6 cold damage and are knocked upwards 10 feet and knocked back 5 feet away from you. On a success, creatures take half damage and no further effects. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "b496ae87cbbd8b778ba7927e", name: "Ripple of Water: Torrential Fist", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["b816b9a2e7670f7792937f0e", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1  Action", range: "Touch", chakra_cost: "9 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of water release chakra throughout your entire body. You generate a water  chakra within your palm and close your fist, causing it to shake due to the building pressure of the water. Make a melee taijutsu attack against a target within range. On a hit you deal your unarmed damage + 4d6. Upon hitting the creature, you upon your palm, releasing a torrent of water in a 20-foot cone originating from the creature. The target, and all creatures within range must make a Dexterity saving throw, taking 2d10 cold damage, being knocked back to the edge of the line, and gaining 1 rank of Chilled on  a failed save.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and the damage by 1d6 and 1d10 respectively. If cast to A-Rank or higher, creatures take half damage on a successful save.", created_at: NOW, updated_at: NOW },
  { _id: "3835784dd9666d28c75e3ee5", name: "Ripple of Lightning: Hamon Beat", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "5ft", chakra_cost: "8 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of lightning release chakra throughout your entire body. You charge your hand in Lightning release chakra and then chop at an enemy disorienting them. Make a melee taijutsu attack dealing your unarmed damage + 2d12 Lightning damage, a creature you affect with this jutsu must make a constitution saving throw or else become unable to react until the start of your next turn Until the end of your turn, you can target one affected creature with a Taijutsu Finisher regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 1d12.", created_at: NOW, updated_at: NOW },
  { _id: "ea30455b4091685136542c3b", name: "Ripple of Lightning: Sendo Overdrive", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["a76452ff37e678bdca89c3ea", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5ft", chakra_cost: "8 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of lightning release chakra throughout your entire body. You coat your arm in a spread lightning pattern, meant to evade obstacles and hit the target, almost as if it had a mind of its own. Make a melee taijutsu attack dealing your unarmed damage + 3d6 Lightning damage, if you were to target a creature that is behind a wall at any point of this jutsu casting your may ignore any cover benefits it may give and treat it as if it wasn’t there in the first place.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "4beb6a2bbf4a03fc0804d815", name: "Vanish", jutsu_rank_id: "e8cb106a7c700a15e96dde71", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you see a creature take any reaction against a jutsu cast by another allied creature (other than yourself) within range.", range: "30 feet", chakra_cost: "8 Chakra", components: "M", duration: "Instant", description: "A daring jutsu to prevent a creature from escaping demise at the cost of your own safety.  You teleport to  a space within 5 feet of the creature that can hold you and make a melee taijutsu attack against them. On a hit, you deal your unarmed damage and the creature must make a Constitution saving throw, their reaction failing on a failed save. If you score a critical hit with this attack, the creature makes their saving throw at disadvantage. You then move yourself out of harms way of your ally's jutsu, up to moving a maximum distance away of 30 feet.", at_higher_ranks: "For each rank you cast this jutsu above C-Rank, increase the cost of this jutsu by 3, and the range of this jutsu by 10 feet. If cast to B-Rank or higher, your attack scores a critical hit on a 19-20. If cast to S-Rank or higher, your attack scores a critical hit on a 18-20.", created_at: NOW, updated_at: NOW },
  { _id: "50d1f339c80d959fbcf25913", name: "Airforce (Changed)", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "9991cc726431e53e17c4a8fa"], elements: [], casting_time: "1 Action", range: "Touch (30-foot radius)", chakra_cost: "*Special* (49 Chakra)", components: "M, W (Weapon with  the Unarmed property)", duration: "Instant", description: "This jutsu can only be cast if there is at least one other caster within 30 feet of you. You target a creature within range and whistle towards your comrades to come and attack the creature in succession. Make two melee taijutsu attacks, dealing your unarmed damage + 2d8. Each ally that assists you in casting this jutsu makes two melee taijutsu attacks, dealing their unarmed damage + 1d8. If any creature scores a critical hit on these attacks, the damage cannot be reduced by more than 5, and the creature gains 1 rank of Bruised and is knocked prone. CombinationWhen this jutsu is cast, it gains additional effects based on who has the highest Charisma modifier between all casters. - +0-1No change. - +2-3All casters increase their critical threat range by +1. - +5All casters increase their critical threat range by +2, and on a critical hit, the creature gains 1 rank of Fear against all casters until the end of their next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "9684cc77e8d8202272a7a4bf", name: "Cherry Blossom Finale", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (60-foot Radius)", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "This jutsu can only be cast as a *Finisher*. You slam your fist into the ground creating a giant shockwave. Each creature in range must make a Dexterity saving throw, taking your unarmed damage + 8d8 on a failure, or half as much on a success. If a creature is prone, they have disadvantage on saving throw. After the conclusion of this jutsu, the area is counted as difficult terrain.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank increase the cost of the jutsu by 3 and increase the damage by 2d8.", created_at: NOW, updated_at: NOW },
  { _id: "d6fc4ee586b38ad3f159163c", name: "Grizzly Charge", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "12 Chakra", components: "CM, M", duration: "Instant", description: "As a requirement to activate this jutsu,  you must currently be in the *Bear Fist Stance*. Glowing bear claws of chakra manifest over your hands and feet as as you snarl wickedly. As part of casting this jutsu, you can move up to 30 feet in the direction of your target. The target makes a Strength saving throw, falling prone on a failure, on a success it is not knocked prone. Then make two melee taijutsu attacks against the same target. On each hit, you deal your unarmed damage + 3d8 slashing. If you reduce the target to 0 hit points, you can move up to half your speed and make a one more taijutsu attack against a target in reach. If the creature you target with this jutsu is also the target for your *Bear Fist Stance's* *Apex Might*, *Tremble in Fear*, *Predator's* *Pride* feature, on each hit, you instead deal your unarmed damage + 3d10 slashing and the target must make a Wisdom saving throw, gaining 1 rank of Fear against you on a failed save.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, and increase the damage of each attack by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "5e55fc0926ef503c3e17ee7a", name: "Heaven's Judgement", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "This jutsu can only be used as a *Finisher*, on a creature who is currently airborne or falling. You lock eyes with a creature who is in the air that you could reach with your movement speed if they were on the ground. You give them a menacing glare and in a flash, you zip up to right above the creature, so fast that an afterimage of yourself can be seen where you last stood. Make a melee taijutsu attack at advantage. On hit, you slam the creature down to the earth with incredible force, dealing your unarmed damage + 6d10. As the creature collides with the earth, they take the fall damage they would've taken as normal, and a small shockwave forms from where they hit the ground, carrying debris and smoke. The radius of this shockwave depends on how high the creature fell from, detailed below. Creatures within the range of this shockwave must make a Strength saving throw, becoming blinded and falling prone on a failed save. - 10-30ft in the air10-foot radius shockwave - 31-60ft in the air15-foot radius shockwave - 61-90ft in the air20-foot radius shockwave - 91ft+ in the air25-foot radius shockwave You then land back down to the ground gracefully, taking no fall damage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d10.", created_at: NOW, updated_at: NOW },
  { _id: "4f85451fd677710148b6b95c", name: "Heaven Shaking Supreme Fang", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 reaction, when you would be knocked prone", range: "10 feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "In reaction to being knocked prone, you twist your body in mid-air, spinning and creating a huge amount of force. If a creature is within range, you can drive your elbow into them. Make a melee taijutsu attack, dealing your unarmed damage + 6d4 bludgeoning damage. The creature must then succeed on a Strength saving throw or be knocked prone and stunned until the start of their next turn. If this jutsu is used as a *Finisher*, you instead deal your unarmed damage + 8d8 bludgeoning damage and the target must then succeed on a Constitution saving throw or be knocked prone and paralyzed until the start of their next turn. Regardless of if you hit or miss with your attack, you land on your feet, avoiding the prone condition.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "bbf187f771e880728d00d4cd", name: "Leaf Spinning Kick", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "10 Feet", chakra_cost: "13 Chakra", components: "M", duration: "Instant", description: "You jump forward, doing an innumerable number of flips before crashing down onto your opponent's head with your momentum. Make a taijutsu attack dealing your unarmed damage + 4d10 on a hit. The target creature must also succeed on a Constitution saving throw, being stunned until the end of their next turn on a failed save. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 1d8.", created_at: NOW, updated_at: NOW },
  { _id: "99e3ecb8f16a4c3d37411bda", name: "Mighty Throw", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "120 Feet", chakra_cost: "13 Chakra", components: "M", duration: "Instant", description: "You grab a medium or smaller object and throw it at a target creature within range. Make a single ranged Taijutsu attack against a target creature within range. On a hit, the you deal 8d6 bludgeoning damage and the target makes a constitution saving throw. On a failed save they again the dazed condition until the end of their next turn.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, the range by 15 ft, and the amount of damage by 1d6. If this jutsu is cast to S-Rank or higher, you may grab and throw a large or smaller object. Additionally, if you throw a large object the damage die size is increased by 1.", created_at: NOW, updated_at: NOW },
  { _id: "9be9c24122dc9aca26705a28", name: "Mind Phase", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Reaction, which you take when you would be targeted with a Genjutsu", range: "*Special*", chakra_cost: "11 Chakra", components: "CM, CS, M", duration: "Instant", description: "The very microsecond you feel your chakra network under attack from a Genjutsu, your muscles instinctually work to avoid losing full control and launch a counterattack. Make a Martial Arts check contested by the creature's Illusions skill. If the triggering Genjutsu is above B-Rank, you make your skill check with a -1d4 penalty. If you succeed this check, you gain a +5 bonus to AC and saving throws to resist Genjutsu attacks and saving throws only until the start of your next turn. Additionally, the next unarmed or Taijutsu attack made against the creature before the end of your next turn gains a +1d6 to its attack and damage roll. If you fail this check, genjutsu attacks made against you have advantage and you have disadvantage on saving throws against Genjutsu. These effects last until the start of your next turn.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "011b64225f45095e01df7fce", name: "Ripple of Earth: Grand Canyon", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["587205fc5e2f018201761d63", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (30-foot wide, 10-foot long Line)", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of earth release chakra throughout your entire body. You slam your fist on the ground as you crack the floor beneath someone, trying to make them fall as you strike. All creatures within a 30ft long, 10ft wide line must make a Dexterity saving throw, if they fail they cannot gain the benefits of a reaction for this jutsu. Regardless of a success or fail, make a ranged taijutsu attack roll against the AC of all creatures within range, dealing your unarmed damage + 5d6 earth damage on a hit. If you score a critical hit with this attack, instead of doubling the damage dice, all creatures hit by this jutsu gain 1 rank of Bruised. If this jutsu is cast as a *Finisher* creatures must make their Dexterity save at disadvantage and instead take your unarmed damage + 5d8 earth damage. Additionally, when this jutsu is used as a *Finisher*, if there are any non-sentient earthen constructs within 20 feet of the fissure, the creator of said construct may sacrifice up to 20 hit points to increase one damage instance on an affected creature by an amount equal to hit points sacrificed. They may sacrifice up to 20 hit points per creature that is damaged to increase the damage dealt this way, but the bonus to damage cannot exceed 20 even if multiple different constructs are used.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3b5d40788e8b602ceb9dbc0c", name: "Ripple of Earth: Seismic Smash", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["587205fc5e2f018201761d63", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of earth release chakra throughout your entire body. You build up a seismic amount of Earth Release chakra within your arms and strike the ground with two open palms, causing several fractures to form throughout a 30-foot radius originating from yourself. All creatures within this radius, other than you, are treated as being within difficult terrain for the duration. Soon after the fractures form, large rocks burst out from the cracks. Each creature within range, other than you, must make a Dexterity saving throw. On a failed save, the creature takes your unarmed damage + 7d6 earth damage and becomes Bruised. On a success, the creature takes half damage and no effects.", at_higher_ranks: "For each rank you cast above B-Rank, increase the cost of this jutsu by 3. If cast to S-Rank, the rocks you create from this jutsu fall back down after they shoot up from the ground. At the start of each affected creature's turn, they must make a 2nd Dexterity saving throw, at disadvantage if they failed the prior save. On a failed save, the creature suffers the same effects as a failure as the previous saving throw and is knocked prone.", created_at: NOW, updated_at: NOW },
  { _id: "b7bf93938f11649e991cf643", name: "Ripple of Wind: Spiraling Storm", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "90 feet (10-foot radius)", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of wind release chakra throughout your entire body. You begin to dash in circle around a space in front of you. As you dash you punch and send a gust of air into the space you are moving around. As you continue to do this, a momentus storm begins to form, and as you end your dash you jump upwards and kick the storm towards a space within 90 feet. The storm is 10 feet long and 10 feet wide. Each creature within range of the storm as it travels must make a Dexterity saving throw, gaining 1 rank of bleeding, and being knocked upward 50 feet on a failure. Once your storm reaches the designate space, it expands and bursts. All creatures within 20 feet of the storm on its sides or that are above the storm must make a Strength saving throw to resist the wind, taking your unarmed damage + 4d6 wind damage on a failed save. Once per casting, if the storm passes over a source of water, electricity, or fire, the storm absorbs  some the energy of the source, incoporating it into itself, giving 1 rank of Chilled, Shocked, or Burned respectively until the end of the creature's next turn on a failed Strength saving throw.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "3454771ba5aa00388bcb469b", name: "Ripple of Wind: Zephyr Tunnel", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["be25cd280a254892a04b3a6b", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Self (30-foot line)", chakra_cost: "12 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of wind release chakra throughout your entire body. You gather wind chakra behind you, blasting yourself forward at tremendous speed. You move in a straight line directly towards a creature you can see within range and make a melee taijutsu attack against them. On a hit, you deal your unarmed damage + 4d8 wind damage and the target is knocked back 30 feet. If this jutsu is cast as a *Finisher*, you instead deal your unarmed damage + 6d8 wind damage and the target is knocked back 30 feet and is Dazed.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, the damage by 1d8, and the distance you can move by 15 feet.", created_at: NOW, updated_at: NOW },
  { _id: "fd8438b52ce4d71dcfcb4920", name: "Ripple of Fire: Blazing Lariat", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of fire release chakra throughout your entire body. You pull your arm back, twisting your whole body as you prepare to spin to space you can see within 30 feet in one clean swing in the blink of an eye. Fire erupts on your hands as you begin to move, burning all creatures you touch. Move to a space  within 30 feet in a straight line. All creatures within range must make a Dexterity saving throw, taking your unarmed damage + 5d10 fire damage, and becoming burned and being knocked back 15 feet on a failed save, or half damage and no further effects on a success. Creatures within 5 feet of your initial space when you cast this jutsu make this saving throw at disadvantage, and are knocked back an additional 15 feet on a failure. You leave a trail of fire from where you originated.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3, the damage by 1d12 or the distance you can move by 10 feet (Pick one).", created_at: NOW, updated_at: NOW },
  { _id: "9a3fcf3235f86ce6b1517095", name: "Ripple of Fire: Knee of Justice", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["146f92dbec13f8ccb9d843cb", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action, which you can only take while", range: "5 Feet", chakra_cost: "14 Chakra", components: "M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of fire release chakra throughout your entire body. You perform a powerful strike with your knee meant to send opponents flying. Make a melee taijutsu attack against the creature dealing unarmed damage + 4d10 bludgeoning damage and knocking them back 15 feet on a hit. If this jutsu is used as a *Finisher,* you instead make a melee taijutsu attack against the target, dealing your unarmed damage + 6d12 and knocking them back 60 feet on a hit. This attack has a +1 bonus to its critical threat range.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "223018ea01492c06ae76410c", name: "Ripple of Water: Loch Substitution", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Reaction, which you take when you would take damage from a melee attack roll.", range: "Self", chakra_cost: "12 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of water release chakra throughout your entire body. In response to a creature striking you with a melee attack, make a Martial Arts check vs.  the attack roll of the triggering creature. On a success, you avoid the attack in its entirety, vanishing into a pool of water and moving to a space within 15 feet and making a melee taijutsu attack against a creature within your unarmed range. If the target is the triggering creature, make your attack roll at advantage. On a hit, you deal your unarmed damage + 3d8 cold damage and knocking the creature back 15 feet on hit.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f53a062e5e8116fd2e4681d0", name: "Ripple of Water: Resivour Shuriken", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["b816b9a2e7670f7792937f0e", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "*Special*", range: "60 feet", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of water release chakra throughout your entire body. You begin charging a medium sized shuriken between both of your palms as an action. Make a ranged taijutsu attack against a target within range as you throw the shuriken with all your might at the creature. On a hit, you deal your unarmed damage + 7d6 cold damage and the target must make a Strength saving throw, becoming Chilled on a failed save. You can spend your bonus action and/or reaction to elevate the power of this jutsu further, giving additional effects and making the Shuriken larger. - Bonus ActionIncrease the damage of this jutsu by 2d6. - ReactionAll creatures within 5 feet of the target must succeed a Dexterity saving throw, taking half the damage of this jutsu on a failed save. If this jutsu is used as a *Finisher*, it automatically gains the benefits as if you used your bonus action to  enhance this jutsu effects, and the damage of this jutsu is increased by 1 step.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f12a887974d8ee59d3ba1ae9", name: "Ripple of Lightning: Hamon Overdrive", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["a76452ff37e678bdca89c3ea", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (15-foot radius)", chakra_cost: "12 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of lightning release chakra throughout your entire body. You coat your hand in a compact Lightning chakra, punching the ground as you spread it over an area. All hostile creatures within 15ft of you must make a dexterity saving throw, suffering 6d6 Lightning damage or half as much on a successful save, if a creature has a rank of shocked they must make this save at disadvantage.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d6.", created_at: NOW, updated_at: NOW },
  { _id: "631df5d9a66bb2bd8819f0ca", name: "Ripple of Lightning: Tornado Overdrive", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a76452ff37e678bdca89c3ea", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5ft", chakra_cost: "12 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of lightning release chakra throughout your entire body. You jump into the sky and coat your legs in lightning chakra as your spin like a tornado, slamming down on a creature. Make a melee taijutsu attack dealing your unarmed damage + 3d10 Lightning damage. If this jutsu is cast a *Finisher* change the damage to unarmed damage + 5d10 and the creature must succeed a Constitution saving throw or else gain a rank of shocked. Regardless of whether this jutsu is cast normally or as a *Finisher*, you gain a +1 to your attack rolls for each rank of shocked the target has.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and increase the damage by 2d10 and 2d12 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "f4646b89c0dc6bd0dbe2ebd3", name: "Shattered Earth", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (10-foot radius)", chakra_cost: "12 Chakra", components: "M", duration: "Instant", description: "You hit the ground and create a shockwave that destroys and shatters all around. All creatures within 10 feet of you, other than you must make a Strength saving throw or take your unarmed damage + 8d4 bludgeoning damage and be knocked prone and weakened, on a failed save. On a successful save, a creature takes half as much damage and no additional effects. This area remains as difficult terrain.", at_higher_ranks: "For each rank you cast this jutsu above B-Rank, increase the cost of this jutsu by 3 and the damage by 2d4.", created_at: NOW, updated_at: NOW },
  { _id: "9f8c6b555c15e86da87bcb2c", name: "Shattering Star: Bash", jutsu_rank_id: "5b66927a43f65331bc68018d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "14 Chakra", components: "M, CM", duration: "Instant", description: "You deliver 4 quick strikes, disrupting your opponents guard, leaving them open for more devastating attacks. Make 4 melee taijutsu attacks each dealing your unarmed damage. These attacks do not add your ability modifier and cannot score a critical hit. For every 2 successful attacks their lowers their AC by -1 until the start of your next turn. If all 4 attacks hit the creature, the creature is staggered until the end of the current turn. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "87c3d8a4a1ffe638a459acb3", name: "Cherry Blossom Bomb", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "45 ft. (Cone)", chakra_cost: "18 Chakra", components: "M", duration: "Instant", description: "You send your fist into the ground sending a controlled shockwave ahead of you. Creatures in a 45-footcone in front of you must succeed a Dexterity saving throw as the surface is destroyed and pieces of the ground shoot out in random directions. On a failed save you deal your 10d10 bludgeoning Damage on a  failed save or half as much on a successful one. The affected area is counted as difficult terrain and creatures that are greater than 10 feet from each other are heavily obscured from one  another.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "da96c4910d3ac01887a177f7", name: "Disaster", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "a353e375646b20ac8f642370"], elements: [], casting_time: "1 Action", range: "30 Feet", chakra_cost: "19 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the *Death Fist Stance*. You ready your fists with an explosive amount of chakra, and either on the ground or air punch your fists into the space between you and your opponent. Make three ranged taijutsu attacks, dealing your unarmed damage + 3d6 force damage. This jutsu cannot crit. On a hit the target is forced to make a Strength saving throw, being pushed back 5 feet and reducing their AC by -1 until the start of their next turn on a failure and nothing on a success. Until the end of your turn, you can target one affected creature with a Taijutsu *Finisher* regardless of range, once per turn, using either an Action or Bonus action, ignoring its listed casting time.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "39fa891dd599875e3957b824", name: "Disorder", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you are", range: "Self", chakra_cost: "18 Chakra", components: "M", duration: "1 Round", description: "As a requirement to activate this jutsu, you must currently be in the *Death Fist Stance*. You load chakra into your fists and launch an unrelenting barrage of explosive punches against whatever attack is heading your way, destroying it before it can reach you. When an opponent targets you with an attack, up to a number of time equal to half of your proficiency modifier, reduce incoming attack rolls by half of your taijutsu ability modifier (rounded up). If you are instead targeted by a Strength or Dexterity saving throw you may, up to a number of times equal to half of your taijutsu ability modifier add your taijutsu attack modifier in place of your normal saving throw modifier.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "a8450382830a86f3243c7f8d", name: "Flying Thunder God: Downpour of Thunder", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "2f6189c677ac38c9ac5435cf", "33ab3a61f3027398cd08f131"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "17 Chakra", components: "CM, CS, M, NT, W (Kunai or Shuriken)", duration: "Instant", description: "*(This jutsu cannot score a critical hit)* You take from a stack of shuriken or kunai and mark them with a chakra seal reminiscent of the seal used in the *Flying Thunder God* technique. This jutsu can be used without breaking stealth. Roll a 1d6 and add half your proficiency bonus. This is how many targets you can affect with this jutsu in range. You throw your kunai or shuriken into the air, deliberately with different speeds and at different times, to land within 5 feet of a creature. You can target one creature with multiple shuriken or kunai. After throwing your last kunai or shuriken, you throw one final one high into the sky above you. As your weapons descend, just before they hit the ground, you teleport to each one and make an unarmed attack against a creature you targeted when you threw your weapon. The first attack you make on this jutsu, per target, is made at advantage and cannot be reacted to. On hit, you deal your unarmed damage + 2d8. Teleportation from this jutsu does not provoke attacks of opportunity, and after making your final attack, you teleport to the extra kunai or shuriken you threw above yourself earlier just as it hits the ground. You do not add your ability modifier to your unarmed damage.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage by 1d8, and the 1d6 by 1 step (1d8).", created_at: NOW, updated_at: NOW },
  { _id: "44e6380467102714243c3652", name: "Ripple of Earth: Gravity Supplex", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["587205fc5e2f018201761d63", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "16 Chakra", components: "CM, M", duration: "Instant", description: "You make a series of melee attacks against a target, kicking up dirt, sand, and other debris into the air around the two you as you move. Using your control of earth release, you mold the remnants of the ground into weights  that you place on the target with each successful strike. Make 3 melee taijutsu attacks, dealing your unarmed damage + 2d10 earth damage on each hit. On your first successful attack, the creature must make a Strength saving throw. On a failed save, you place a small but heavy mound of earth on their body, making the creature Weakened until the start of their next turn. On a second successful attack, the creature must make another Strength saving throw, at disadvantage if they failed their first Strength save. On a failed save, you place another mound of earth causing the creature to become Slowed until the start of their next turn from the immense weight. On a third successful attack, you grab the creature by the waist and Supplex them into the ground, imbedding them into the ground as a large crack forms. The creature must make a Strength saving throw, at disadvantage if they failed one Strength saving throw from this jutsu, or automatically failing if they failed two. On a failed save, the creature becomes incapacitated until the end of their next turn, and all conditions gained from this jutsu last for the duration that they are incapacitated.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "c59e7f55329784ae1002eb13", name: "Ripple of Earth: Terraforming Force", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: [], elements: [], casting_time: "1 Action", range: "30 feet", chakra_cost: "16 Chakra", components: "CM, M", duration: "Instant", description: "This jutsu can only be used as a finisher. You summon the upmost force as you will the ground itself to aid you in combat, allowing it to meld with other forces in order to attack, as you then make a construct that rears its arm back and slams its fist into your enemy. Make a melee taijutsu attack, dealing your unarmed damage + 6d10 Earth Damage, the affected creature must also make a constitution saving throw or else become staggered. If you have a nature release, this jutsu gains another nature release keyword that you can cast, and additional effects base on the Nature release. If you only have earth release the damage die increases by a step. - WaterWater coats the rock and turns it into clay, slowing your target after you strike. The affected creature gains a rank of slowed if they fail the constitution saving throw. - FireFire solidifies within your earth as it turns to magma, increasing your damage output. Add 1 damage for every damage die you roll. - WindWind flows around your earth making sharp, sharpening your attack. The creature also gains a rank of lacerated if they fail the constitution saving throw. - LightningLightning coats your earth as it increases its speed, making your attack as quick as thunder. The targeted creature cannot gain the benefits of a reaction to this jutsu.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "77ef9ab3406b038cc5b69197", name: "Ripple of Wind: Great Disaster", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self (30-foot radius)", chakra_cost: "20 Chakra", components: "CM, M", duration: "Instant", description: "*(This jutsu cannot score a critical hit)*  You inhale and take a charging stance, manifesting ripples of wind release chakra throughout your entire body. You take in a large breath of air and slam your leg against the ground with incredible force. Several cracks form all throughout a 30-foot radius and from those cracks wind release chakra floods through. Each creature within range must make a Dexterity saving throw, being thrown up 60 feet and becoming suspended in midair, restraining them,  as the wind chakra pools into a sphere of gale energy. You then exhale, creating cloud-like boots at your feet from wind release chakra and begin teleporting to each creature suspended in the air and attack. Make one melee Taijutsu attack against each creature within the sphere. dealing your unarmed damage + 11d4 wind damage and knocking the target 30 feet away in a direction opposite to your attack on a hit, causing them to fall if they go outside of the sphere. You then return back to your original position and the cloud disperses, releasing all creatures and causing them to fall.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8901fb9151fd2320a73b4028", name: "Ripple of Wind: Wind Sheer", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["be25cd280a254892a04b3a6b", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "17 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of wind release chakra throughout your entire body. You grab a creature, using wind chakra together with your grip strength to tear your target apart. Make a Strength (Athletics) check against your target's AC. On a successful check, the target must make a Strength saving throw. If you already have the target grappled, they make this save at disadvantage. On a failed save, the target takes your unarmed damage + 5d10 wind damage, and gain 3 ranks of the bleeding condition. If cast as a *Finisher*, the target takes your unarmed damage + 7d10 wind damage and the target gains 2 ranks of lacerated and weakened until the end of their next turn, as you tear apart their body.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3, the damage by 1d8 and the ranks of bleeding or lacerated by +1.", created_at: NOW, updated_at: NOW },
  { _id: "3a57bbc9e93e05821665ef24", name: "Ripple of Fire: Bolero Whip", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "15 feet", chakra_cost: "19 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of fire release chakra throughout your entire body. You generate flames all throughout your body as you dash towards a creature within range. Make a melee taijutsu attack. On a hit, you grapple the creature. On a miss, this jutsu fails. If you succeed, you grab the creature and move into their space as you throw them back to your original space. The creature can no longer take reactions against this jutsu. The flames covering your body detach from you and fly past the creature, spiraling behind them and exploding, causing the creature to be sent flying back towards you. You step to side and stick out your arm, covering it flame as you attempt to catch the creature as they are flying towards you with a lethal blow. Make a melee taijutsu attack, dealing your unarmed damage + 9d8 fire damage and knocking the creature back 30 feet behind you. Succeeding the creature's AC by 10 or more scores an automatic critical hit. If you score a critical hit, the knockback of this jutsu is doubled and the creature gains 1 rank of Burned.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "f99916e0673cdcfc7793f816", name: "Ripple of Fire: Falcon Punch", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["146f92dbec13f8ccb9d843cb", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "17 Chakra", components: "CM, M", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu *Finisher*. You inhale and take a charging stance, manifesting ripples of fire release chakra throughout your entire body. You cover your fist in flames and then release it as it explodes in the shape of a falcon. Make a melee taijutsu attack against the creature dealing unarmed damage + 10d10 fire damage and knocking them back 30 feet on a hit. If a creature knocked back by this jutsu collides with a solid object, their movement is stopped, taking falling damage equal to the distance they would have fallen. Regardless of a hit or miss, all creatures excluding you and your original target, within 5 feet must make a Dexterity saving throw taking 8d6 fire damage on a failed save.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "534765ebf689d372eb6e4016", name: "Ripple of Water: Aqua Crossguard", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Reaction, which you take when you or an ally within 30 feet would be targeted by an attack, take damage, or make a Strength, Dexterity, or Constitution saving throw.", range: "Self (15-foot line)", chakra_cost: "20 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of water release chakra throughout your entire body. Before you or an allied creature within 30-feet would be subject to an enemy's assault, you quickly gather a massive amount of water release chakra and jump in front of the allied creature to impose the attack. You take a cross guard stance, expelling a water barrier in two 15-foot lines at your sides. You and each creature within 10 feet of you or these lines gains double your unarmed damage + 50 temporary hit points until the end of the turn. Each allied creature, other than yourself, gaining the benefits of this jutsu is also considered behind three-fourths cover until the end of the turn, and the bonus from this cover applies to Strength and Constitution saving throws as well.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "470fec044a7263cef3cc8c25", name: "Ripple of Water: Water Drake", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["b816b9a2e7670f7792937f0e", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "20 Chakra", components: "CM, M", duration: "Instant", description: "This jutsu can only be used as a Taijutsu *Finisher*. You inhale and take a charging stance, manifesting ripples of water release chakra throughout your entire body. A variation of the *Water ReleaseWater Dragon* Ninjutsu adapted for more martial fighters. This jutsu cannot be used without a source of water nearby deep enough to fit a medium sized creature. You pull from a source of water and form a large wingless dragon of your description around yourself. You charge at a target within range as the water begins to boil. Move up to your movement speed at a creature within range and make a melee taijutsu attack. On a hit you deal your unarmed damage + 12d6 cold damage. The creature must make a Strength saving throw, becoming Dazed, Incapacitated, and Slowed until the end of its next turn.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and the damage die by 1 step.", created_at: NOW, updated_at: NOW },
  { _id: "be8b4ae4db7bcbc77e1ec781", name: "Ripple of Lightning: Sunlight Overdrive", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "5ft", chakra_cost: "15 Chakra", components: "CM, M", duration: "Instant", description: "You may only cast this jutsu as a *Finisher*. You coat your entire body in glorious sparks of lightning, shining so bright they turn yellow as your rear your arms back and unleash a flurry of blows in an overdrive of speed! Make four taijutsu attacks each dealing your unarmed damage + 3d8 Lightning damage. If you land at least two attacks the affected creature is knocked back 60ft, if they would crash into a surface you may make one final taijutsu attack against them, dealing your unarmed damage + 3d10 Lightning damage. If you were to score a critical hit with this jutsu you roll an additional die for each crit instead of doubling your dice.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and make an additional attack for both the original attack flurry and if they get knocked back.", created_at: NOW, updated_at: NOW },
  { _id: "530e28488766dd4f62f0f4e2", name: "Ripple of Lightning: Volt Tackle", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["a76452ff37e678bdca89c3ea", "ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action", range: "Movement Speed", chakra_cost: "14 Chakra", components: "CM, M", duration: "Instant", description: "You inhale and take a charging stance, manifesting ripples of lightning release chakra throughout your entire body. You take a prowling stance and begin charging wrathful jolts of energy around your entirebody of golden lightning. Select a creature you could reach within your full movement. You dash towards the creature within range in a zig-zag line with incredible speed. Make a melee taijutsu attack. On a hit the creature takes your unarmed damage + 11d6 lightning damage and must succeed a Constitution saving throw. On a failed save, the creature becomes Dazed and gains 2 ranks of shocked. This attack scores a critical hit on a 19-20. As part of casting this jutsu, you can sacrifice increments of 5 hit points to increase this jutsu's critical threat range by +1 and the damage die by 1 step. You can do this up to 3 times.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "402671387e776f0da401de53", name: "Shattering Star: Break", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f"], elements: [], casting_time: "1 Action", range: "Touch", chakra_cost: "18 Chakra", components: "M, CM", duration: "Instant", description: "This jutsu can only be cast as a Taijutsu *Finisher*. You rush forward in a flurry of attacks devasting your foe, before unleashing an explosion that tears the world asunder. Make 3 melee taijutsu attacks each dealing your unarmed damage. Each attack knocks them back 10 feet as the force of your blows are staggering. Then make a ranged taijutsu attack as you throw a ball of pure chakra at your enemy, dealing 10d10 force damage and forcing them to make a Constitution saving throw or gain 1 rank of weakened for 1 minute. For every successful melee attack that hit the target creature they take a -1 penalty to their saving throw.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "6bfe540662f4b4c9ea34c9c9", name: "Straight", jutsu_rank_id: "ddb90764cacd7cc1ef326463", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 Feet (60-foot line)", chakra_cost: "18 Chakra", components: "M", duration: "Instant", description: "You plant your feet twist your body and punch with all your might in perfect form. Make a melee taijutsu attack against a target. On a hit you deal your unarmed damage + 8d10 and the force of the impact sends a  shockwave that affects all creatures in a 15-foot wide, 60-foot-long line behind your initial target creature. All creatures behind the target creature must make a Dexterity saving throw taking 6d8 bludgeoning damage on a failed save or half as much on a successful one.", at_higher_ranks: "For each rank you cast this jutsu above A-Rank, increase the cost of this jutsu by 3 and damage by 1d10 and 1d8 respectively.", created_at: NOW, updated_at: NOW },
  { _id: "b30e8ca33173df71f5ae8d4c", name: "Annihilation", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "981b128eaf7210e3da4dfa9f", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Action or 1 Reaction, which you take when", range: "Movement Speed", chakra_cost: "25 Chakra", components: "M", duration: "Instant", description: "As a requirement to activate this jutsu, you must currently be in the *Death Fist Stance*. This jutsu can only be cast as a *Finisher*. You ready your chakra into your arms as you crouch down with both your arms at the sides of your body, poised for a strike. You then lunge forward, creating two destructive shockwaves blasting off from your hand, demolishing anyone or anything that was hit by it. Make a single melee taijutsu attack, dealing your unarmed damage + 12d12 force damage. On a hit they must make a Constitution saving throw, becoming paralyzed until the start of their next turn on a failed save and nothing on a success. If you initiate a Clash with this jutsu you do half of this jutsu’s damage on a failed check and deal double the jutsu’s damage on a success.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8f12583864410a4fa8c4ab55", name: "Compass Needle", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Self", chakra_cost: "*(Special)* 35 Chakra", components: "CM, M", duration: "1 minute", description: "As a requirement to activate this jutsu, you must currently be in the *Death Fist Stance*. You manifest a light blue snowflake-shaped compass underneath yourself, as chakra begins to seep into the air from it and derive information from the surroundings. The compass needle points then light up in accordance with your opponent’s strength, the stronger they are the more that light up. Finally, after gauging their strength your technique focuses your body to sense their battle spirit, allowing you to target their vitals easier and adapt to their fighting style. While you are under the effects of this jutsu you gain the following; - Once per turn you may reroll a melee attack roll. - For the duration, whenever you hit with a melee attack you increase your melee attack rolls by +1 when hitting that same target, until the start of your next turn. - You gain blindsight in a 60-foot sphere originating from you. - As a reaction to being targeted by a melee attack you can subtract their melee attack rolls by an amount equal to half your proficiency bonus, until the beginning of your next turn. - For the duration, your melee attack rolls cannot suffer any penalties.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "893c6368987ffcb0b08cee2d", name: "Final Blow", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "60 ft. (120 ft. radius)", chakra_cost: "26 Chakra", components: "M, CM", duration: "Instant", description: "You leap into the air before crashing down on a spot within range creating a devastating shockwave and leaving a mark on the earth. Each creature within 120 feet must make a Dexterity saving throw taking 14d10 Bludgeoning damage and being thrown back a number of feet equal to 5 times your strength score on a failed save, or half as much damage on a successful save and no additional effects. This jutsu deals quadruple damage to structures and the area is permanently difficult terrain.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "7880665f19ade8978289a1bd", name: "Galactic Impact", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "23 Chakra", components: "M", duration: "Instant", description: "You launch yourself into the air using all your might and then crash down in a mighty slam shattering the world beneath you. You jump up to ten times your strength score in the air and fall to earth forcing in an area equal to double your strength score to make a Dexterity saving throw or take your unarmed damage + the falling damage you would've taken in bludgeoning damage and being knocked prone on a failed save. On a successful save, they take half as much damage and are still knocked prone. You leave a crater a number of feet deep equal to strength score. An area of difficult terrain is left in your wake that has a radius of three times your strength score.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "834f7359e2126cb14ab167a9", name: "One Thousand Meter Punch", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "5 Feet", chakra_cost: "25 Chakra", components: "CM, M", duration: "Instant", description: "Moving your arm faster than lightning you punch a creature with more force than even the bijuu possess. Make a melee taijutsu attack dealing your unarmed damage +10d8. On a hit, the target creature takes must make a Constitution saving throw. On a failed save the target creature is knocked back 1 mile. If they strike a solid surface that’s less than 5 feet thick, they tear through it, taking 6d6 bludgeoning damage for each surface they go through. If they strike a solid surface that’s more than 5 feet thick, their movement stops and they take 6d6 bludgeoning damage. it, taking 6d6 bludgeoning damage. If the creature would be fully stopped before they have been knocked back half a mile they instead take 10d6 bludgeoning damage for the final instance of damage.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "8aaf3bf19d75147b23bdcc34", name: "Shattering Star: Burst", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "60 feet", chakra_cost: "*Special* (28 Chakra)", components: "M", duration: "Instant", description: "Your muscles all over your body tense up and grow in size as you intend to wreak as much havok on a creature as possible. Select on creature within range. You move faster than the eye can see,  teleporting to a space 30 feet above the creature. Make a melee taijutsu attack, striking the creature directly in the head. On a hit, you deal your unarmed damage + 3d6. If you hit with this attack, you then move at hypersonic speeds once more, striking the creature with punches and kicks faster than the eye can see. Make a number of melee taijutsu attacks equal to your taijutsu ability modifier, dealing your unarmed damage on each hit. Also on each hit, you knock the creature 15 feet in the direction of your attack, teleporting next to them to make your next attack, until you make all of your attacks. For every attack you land, the target must make a Strength saving throw, becoming weakened and unable to take reactions until the end of the turn. With each additional attack you land after the 2nd, the target suffers a -1 to this saving throw. If you hit with at least 5 attacks this way, the target automatically fails their saving throw. If the creature you attacked failed their saving throw against this jutsu, as they are disoriented from your assault, you can target them with one Ninjutsu of C-Rank or lower, that requires a melee ninjutsu attack and only effects one creature, at no extra cost. This ninjutsu automatically hits the creature, and in addition, the jutsu generates a powerful explosion that knocks the creature back 30 feet.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "d1114dd6f62fe10fb8b94b6a", name: "Ripple of the Stars", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9", "00ca3f040aa5aa24f905202a"], elements: [], casting_time: "1 Full Turn Action", range: "Movement Speed", chakra_cost: "*Special* (40 Chakra)", components: "CM, M", duration: "Instant", description: "As part of the requirements for casting this jutsu, you must have access to two or more nature releases. You inhale and take a charging stance, manifesting ripples of elemental chakra throughout your entire body. Casting this jutsu causes your body to radiate with awesomely bright light in a 120 feet radius that dispels darkness, chakra enhanced or natural. Choose two different nature releases you possess. You raise both your arms to your sides, channeling the chakra of two different nature releases chosen between them in ripples of chakra that travel down arms and coalesce in your hands. The energy you produce causes the earth to shake and the sky to briefly turn dark. You then dash towards a creature within range, absolutely ravaging the landscape in your wake turning it into difficult terrain and destroying any non-chakra enhanced structures and objects. Make a single melee taijutsu attack against a creature within range at advantage, striking them with both of your fists at the same time, dealing your unarmed damage + 14d12 in the damage types of the two releases you choose (Water=Cold). The creature must then make a Constitution saving throw, suffering a designated effect depending on the two releases chosen on a failed save, as shown on the *Ripple of the Stars Effect Table*. Regardless of a hit or miss, you produce a 120-foot shockwave, causing all creatures within range other than you and the target to make a Dexterity saving throw or be knocked back 60 feet. Once this jutsu is cast, you become unable to mold chakra until the end of your next turn, and gain 1 rank of Exhaustion and Weakened as the sheer pressure of manifesting two nature releases has ravaged your body and chakra network.", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "10916cc31b5aca6700aa8144", name: "Triple Tiger Sashay", jutsu_rank_id: "5f339e6048462aafae180c0d", keyword_ids: ["ed3184ccd83030d0ec4106a9"], elements: [], casting_time: "1 Action", range: "Special", chakra_cost: "24 Chakra", components: "M", duration: "Instant", description: "As a requirement for activating this jutsu, there must be three hostile creatures within 30 feet of you. You execute a masterful technique that combines all of your taijutsu expertise into a flawless move that almost looks like a dance. You dart forward and jump into the air and make a single melee taijutsu attack against each creature dealing your unarmed damage + 14d6. If you hit each creature with this attack you land at a point you can land at a point within 15 feet of the last creature hit and they must all make a Constitution saving throw or be stunned until the end of their next turn on a failed save. <div class='wide'>", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "0952aaab44d11cb95e145beb", name: "Lightning Straight", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: [], elements: [], casting_time: "1 Action", range: "", chakra_cost: "", components: "", duration: "", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
  { _id: "fd8977501aefd2c5289f0cf4", name: "Guillotine Drop", jutsu_rank_id: "b7c4bb8d8a7ea05b5574913a", keyword_ids: [], elements: [], casting_time: "1 Action", range: "", chakra_cost: "", components: "", duration: "", description: "", at_higher_ranks: null, created_at: NOW, updated_at: NOW },
];
